INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  1,
  'Bleeding In Pregnancy',
  'Gynaecology & Women''s Health',
  'Video Consultation',
  false,
  'Rachel Pemberton',
  '31-year-old female',
  ARRAY['Normal vaginal delivery 4 years ago','Lower Segment Caesarean Section (LSCS) 2 years ago'],
  ARRAY['Not currently taking any regular medication.','No known drug allergies'],
  'No significant recent consultations',
  'Patient booked an urgent video appointment to discuss vaginal bleeding in early pregnancy.',
  'Hello doctor, I''ve been having some bleeding from down below for the past couple of days and I''m worried I might be losing the baby.',
  'You noticed some light vaginal bleeding a couple of days ago, and it has left you feeling very anxious given that you are pregnant.',
  ARRAY['Your last menstrual period was 10 weeks ago. You did a pregnancy test 5 weeks ago after missing your period and it was positive.','You feel well in yourself otherwise — no fever, no tummy pain, and no other symptoms.','You are mainly concerned that something might be wrong and want reassurance that everything is okay.','You have not yet arranged your antenatal care or had any scans, as you have been caught up with running your business.','If asked about the previous Caesarean section, explain it was your personal preference, as you did not wish to go through a vaginal delivery again.'],
  'You live with your husband, who is very supportive. You do not smoke or drink alcohol. You have two children — a 4-year-old son and an 18-month-old daughter. You run an online business selling handmade homewares.',
  'You are wondering whether the bleeding could mean you are miscarrying.',
  'You are worried about having a miscarriage.',
  'You would like the GP to advise you on what you need to do next.',
  ARRAY['If the doctor suggests going to hospital today, explain that arranging childcare is difficult right now. You have two young children, and your husband is currently in France on a business trip and is not due back for another three days. You do not have nearby family who can step in at short notice.','If the doctor suggests coming to the GP surgery for an assessment, agree and ask whether you are able to bring your toddler along with you.'],
  'Ask whether you need to let your husband know and whether he should come back early from his trip.',
  'Decline to answer any questions or report any symptoms beyond the information already provided above.',
  ARRAY['Ask about the onset and volume of bleeding — whether it is light, moderate, or heavy, and whether there are any clots.','Confirm the date of the last menstrual period.','Ask whether she has repeated a pregnancy test since the bleeding began.','Ask about any associated abdominal pain. Note that ectopic pregnancy typically causes unilateral or localised pain, whereas miscarriage more commonly presents with generalised, crampy pain.','Ask about other red flag features suggestive of ectopic pregnancy, including shoulder tip pain, dizziness, fainting, palpitations, or breathlessness.','Ask whether there is any other vaginal discharge.','Ask if she has registered for antenatal care and whether any scans have been arranged.','Ask about any recent abdominal trauma.','Ask about urinary symptoms such as frequency, urgency, or dysuria.','Ask about nausea or vomiting.','Ask whether the pregnancy was planned and whether she was using any contraception, in particular an intrauterine device, which carries an increased risk of ectopic pregnancy.','Ask about any previous ectopic pregnancy or miscarriage.','Explore social history including smoking, alcohol use, occupation, home circumstances, and screen sensitively for domestic violence.','Explore the patient''s ideas, concerns, and expectations.','Arrive at a working diagnosis of bleeding in early pregnancy — most likely threatened miscarriage — while keeping ectopic pregnancy as an important differential to exclude.'],
  ARRAY['Acknowledge her anxiety and reassure her that light bleeding can occur in early pregnancy and does not always indicate a miscarriage.','Offer an urgent same-day referral to the Early Pregnancy Assessment Unit (EPAU) for review. Explain that this is to arrange an ultrasound scan to confirm the pregnancy is located in the womb and to check beta-hCG levels.','If she is unable to attend the EPAU today, offer a same-day appointment at the GP surgery to assess her, check observations, examine her abdomen, and repeat a pregnancy test, with the EPAU scan arranged for the following day to allow time to organise childcare.','Advise her to rest and to avoid heavy lifting or strenuous activity until she has been assessed.','Recommend she registers for antenatal care to ensure appropriate monitoring going forward.','Prescribe folic acid 400 micrograms daily until 12 weeks of gestation or until after the dating scan.','Prescribe vitamin D 10 micrograms daily throughout the pregnancy.','Advise that based on her current mild symptoms, there is no urgent need for her husband to cut his trip short, but encourage her to keep him informed so he is aware and can provide support if the situation changes.','Provide clear safety-netting advice: if the bleeding becomes heavier, if she develops abdominal pain or shoulder tip pain, or if she feels dizzy, faint, or generally unwell, she should seek urgent medical attention by calling 999 or attending A&E immediately.'],
  'Thank you for getting in touch today, and I can completely understand how worrying the past couple of days must have been for you. Vaginal bleeding in early pregnancy is understandably frightening, and I want to reassure you that you have done exactly the right thing by coming to speak with us today.

Rachel, the most important thing we need to do right now is to make sure we find out where the pregnancy is and that you and the baby are safe. Light bleeding in early pregnancy is actually quite common and does not always mean something serious is happening — it can occur as the pregnancy settles in. However, because bleeding can sometimes be associated with a condition called an ectopic pregnancy — where the pregnancy has begun to develop outside the womb — it is essential that we arrange a scan promptly to check everything is in the right place.

The best place for you to be seen today is the Early Pregnancy Assessment Unit, often called the EPAU. This is a specialist unit that deals with exactly this kind of situation. They will perform an ultrasound scan to confirm the pregnancy is in your womb and check your hormone levels, which will give us a much clearer picture of what is happening. I will arrange an urgent referral for you to be seen there today.

I completely understand that getting there today with your little ones and your husband away in France is not straightforward. If it truly is not possible to get to the EPAU today, I would like you to come into the surgery instead so we can check your observations, examine your tummy, and repeat a pregnancy test here. We can then book you into the EPAU first thing tomorrow, which should give you a little time to arrange things at home.

In the meantime, please take things easy — rest where you can, and avoid any heavy lifting or strenuous activity. It would also be a good idea to let your husband know what is going on, even if he does not need to come home straight away. Based on what you have described, your symptoms are mild and there is no immediate reason for him to cut his trip short, but having his support and keeping him in the loop is important.

Once we have the scan results and know everything is well, I would like to get your antenatal care started. I will also prescribe folic acid 400 micrograms daily, which helps to protect the baby''s development, and vitamin D 10 micrograms daily throughout the pregnancy.

Finally, I want to make sure you know what to look out for. If your bleeding becomes heavier, if you develop any pain in your tummy or in your shoulder tip, or if you feel dizzy, faint, or generally very unwell, please do not wait — call 999 or go straight to A&E. These can be signs that something needs immediate attention. We are here to support you through this, so please do not hesitate to get back in touch.',
  ARRAY['Bleeding in early pregnancy requires prompt exclusion of ectopic pregnancy, even when symptoms appear mild — always refer to the EPAU for same-day ultrasound and beta-hCG.','A previous LSCS is relevant obstetric history and should be recorded, though it does not alter the acute management of bleeding in early pregnancy.','Key red flags for ectopic pregnancy include unilateral abdominal pain, shoulder tip pain, dizziness, syncope, and haemodynamic instability — these warrant emergency referral.','Folic acid 400 micrograms daily should be recommended from conception until at least 12 weeks; vitamin D 10 micrograms daily is advised throughout pregnancy.','Safety-netting must be explicit: advise the patient to call 999 or attend A&E if bleeding worsens, pain develops, or she feels faint — do not rely on generic advice.','If same-day EPAU attendance is not possible due to social circumstances, a GP review with deferred EPAU referral is an acceptable and safe alternative.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  2,
  'Abnormal Liver Function Test',
  'Gastroenterology & Haematology',
  'Telephone Consultation',
  false,
  'Stuart Mackenzie',
  '40-year-old male',
  ARRAY[]::text[],
  ARRAY['Not currently on any regular medication'],
  'Patient was invited for a routine NHS Health Check after recently turning 40. Seen by HCA 2 days ago — Diane Parsons (Healthcare Assistant role). BP 135/85, Pulse 98 bpm, BMI 35.2. Bloods taken and sent. Blood Test Results Summary: CRP, U&Es, Thyroid Function Test, FBC, HbA1c — reviewed and filed as normal by Dr. Priya Nair (Clinical Practitioner role). Liver Function Tests (LFTs) — filed as abnormal by Dr. Priya Nair. Patient notified by text message and advised to book a GP appointment for further discussion. Test Result Reference Range: ALT 91 U/L (ref: 10–45 U/L); ALP 49 U/L (ref: 30–130 U/L); Bilirubin 11 μmol/L (ref: <21 μmol/L); GGT 98 U/L (ref: <60 U/L)',
  'Patient booked a routine appointment to discuss his blood test results.',
  '',
  '',
  ARRAY[]::text[],
  'You drink alcohol occasionally — perhaps once a month or so, and you would not consider yourself a heavy drinker. You do not smoke. You work as an IT consultant and work from home most of the week. You are not in a relationship and tend to eat convenience food as you find cooking after a long day quite difficult.',
  'You were simply sent a text asking you to book in to go through your blood results — you were not particularly expecting anything to be wrong.',
  'You feel perfectly well in yourself, so you are not especially concerned — just curious about what the results mean.',
  'You just want to understand what the results show and whether there is anything you need to do about them.',
  ARRAY[]::text[],
  NULL,
  'Say no to any symptoms asked about.',
  ARRAY['Take a thorough symptom history from head to toe.','Ask about any yellowing of the skin or whites of the eyes.','Ask about any itching of the skin.','Ask about right-sided abdominal pain or discomfort.','Ask about tiredness or fatigue.','Ask about any change in the colour of stools or urine.','Ask about recent travel abroad.','Ask about any fever or unintentional weight loss.','Ask about risk factors for hepatitis, including tattoos, blood transfusions, or intravenous drug use.','Ask about use of any over-the-counter, herbal, or supplement preparations.','Explore psychosocial history including diet, weight, smoking, and alcohol intake in detail.','Ask about his home situation and relationship status, including how long he has been with any current partner, to assess hepatitis B transmission risk.','Offer a working diagnosis of fatty liver disease (hepatic steatosis), likely related to raised BMI and obesity.'],
  ARRAY['Arrange further investigations: Hepatitis B and C screen, autoimmune liver screen, AST (to enable NAFLD scoring), and a full lipid profile.','Arrange an abdominal ultrasound scan to look for evidence of fatty liver or other underlying causes.','Explain that you will calculate his risk of significant liver damage using a validated medical calculator called the NAFLD score.','Offer to calculate his cardiovascular risk using Q-Risk.','If no blood pressure reading or BMI was available from the recent assessment, arrange a face-to-face appointment to examine the abdomen, recheck blood pressure, and discuss weight management support.','Provide lifestyle advice: aim for gradual weight loss through a combination of improved diet and regular physical activity; reduce intake of processed and fatty foods; keep alcohol intake low, even if current consumption is minimal.','Suggest accessible and convenient healthy eating options — for example, a meal kit service such as HelloFresh — for patients who struggle with cooking after work.','Safety-net for signs of liver complications: advise him to seek urgent medical review if he develops yellowing of the skin or eyes, persistent itching, abdominal pain, changes in stool or urine colour, or tremors.','Arrange a follow-up appointment in one week to review investigation results and plan next steps.'],
  'Thank you for calling in today. I know it can feel a little unsettling to receive a text asking you to get in touch about blood results — so I appreciate you booking in, and I''m glad we have the chance to go through everything together.

The good news is that most of your results came back completely normal — your kidney function, thyroid, blood count, and blood sugar are all looking fine. What we did notice, though, is that two of the liver markers in your blood tests are slightly raised. The ALT, which is one measure of liver activity, came back at 91 — the normal range goes up to 45. And the GGT, another liver marker, was 98, where the upper limit of normal is 60. The other liver values were within the expected range.

Now, Stuart, I want to be clear that slightly raised liver tests like these are actually quite common, and they do not necessarily mean there is anything seriously wrong. One of the most frequent causes we see, particularly in someone with a BMI in the range that yours is, is a condition called fatty liver disease — or hepatic steatosis. This happens when fat builds up in the liver, often linked to diet and weight, even in people who drink very little alcohol. It does not usually cause symptoms, which is why blood tests like yours are so useful for picking it up early.

To understand things better and make sure we are not missing anything else, I would like to arrange a few more tests. These include a screen for hepatitis B and C — not because I think you have been doing anything risky, but because it is part of thorough routine care in this situation. I will also check for autoimmune causes of liver inflammation, and we will arrange an abdominal ultrasound scan so we can actually look at the liver directly. I will also run a cholesterol check at the same time, as this often goes hand in hand with fatty liver, and I will calculate your overall cardiovascular risk while we are at it.

Alongside those investigations, the most effective thing you can do right now is to look at your diet and activity levels. Even modest weight loss of five to ten percent of body weight can make a real difference to liver health. I appreciate that cooking after a long day of working from home is not always appealing — but it might be worth exploring some of the meal kit delivery services that take the planning out of it and tend to be healthier than ready meals.

I would like to catch up with you in about a week, once the results are back, to go through everything and decide on next steps together.

In the meantime, please keep an eye out for any new symptoms — if you notice any yellowing of your skin or the whites of your eyes, any persistent itching, pain in your abdomen, or any changes in the colour of your urine or stools, please get back in touch with us promptly. Those kinds of changes would need a quicker review.',
  ARRAY['An isolated elevation in ALT and GGT with normal bilirubin and ALP is a common pattern in fatty liver disease (NAFLD/MASLD) and should prompt investigation rather than reassurance alone.','Always screen for secondary causes of abnormal LFTs before attributing findings to NAFLD: hepatitis B and C, autoimmune liver disease, alcohol use, and hepatotoxic medications including herbal supplements.','BMI and metabolic risk factors are the most important clinical context for interpreting mild LFT derangement — always document them and calculate the NAFLD score where relevant.','An abdominal ultrasound is the first-line imaging investigation for suspected fatty liver disease.','Lifestyle modification — particularly weight loss through dietary change and increased physical activity — is the cornerstone of management for NAFLD and should be actively encouraged even in the absence of heavy alcohol use.','Safety-netting should include specific symptoms of liver decompensation: jaundice, pruritus, right upper quadrant pain, dark urine, pale stools, and tremor or confusion.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  3,
  'Ear Discharge in a Child',
  'ENT & Eye',
  'Telephone Consultation',
  false,
  'Callum Brady',
  '4-years, 5 months-old male',
  ARRAY[]::text[],
  ARRAY['No known drug allergies','Not currently on any medication'],
  'Missed routine appointment with the Practice Nurse for MMR vaccine (2nd dose) and 4-in-1 pre-school booster, scheduled over 9 months ago — two text message reminders sent. Seen by Paula Simmons (Nurse Access role) 3 weeks ago: MMR vaccine (2nd dose) administered. Advised to book a separate appointment for the 4-in-1 pre-school booster. Letter from Child Therapy Unit — did not attend paediatric physiotherapy appointment for in-toeing, scheduled 2 weeks ago. Patient discharged back to GP — GP to re-send referral if still required.',
  'Mother, Karen Doyle, has booked the appointment to discuss her son Callum''s ear symptoms.',
  '',
  '',
  ARRAY[]::text[],
  '',
  'You think it sounds like an ear infection.',
  'You are worried because his symptoms do not seem to be getting any better, and the health visitor suggested he might need antibiotics.',
  'You are hoping the GP will be able to prescribe antibiotics. You are happy to follow whatever advice the doctor gives.',
  ARRAY['If the doctor asks why Callum is behind on his vaccinations, explain that you are doing your best, but it can be tricky to fit in appointments around your work commitments and coordinating with your mum, who helps out with childcare.'],
  NULL,
  NULL,
  ARRAY['Ask whether the pain is in one ear or both.','Ask if the pain is worse when the outer part of the ear is pulled or pressed, which might suggest otitis externa rather than a middle ear infection.','Ask about the onset and how long the symptoms have been present.','Ask whether there has been any discharge from the ear.','Ask about any swelling or redness behind the ear, to rule out mastoiditis.','Ask whether Callum has had a fever.','Ask about any change in his hearing or whether he seems to be responding less well to sound.','Ask about associated cold-like symptoms such as a runny nose, blocked nose, or sore throat.','Ask whether Callum has been swimming recently or had prolonged exposure to bath water, which can predispose to otitis externa.','Ask if Callum has had recurrent ear infections in the past.','Ask about red flag symptoms including neck stiffness, unsteadiness, or severe headache, to exclude more serious complications.','Ask whether Callum is passing urine normally or, if still in nappies, whether wet nappies are as expected.','Ask sensitively about the reason for missing the physiotherapy appointment and the outstanding vaccination.','Ask whether there are any other children at home and whether they are well.','Ask whether the caregiver is coping and managing day to day.','Explore the mother''s ideas, concerns, and expectations regarding Callum''s condition.','Reach a working diagnosis of acute otitis media — a common childhood infection that frequently follows a viral upper respiratory tract infection.'],
  ARRAY['Offer a face-to-face appointment to examine Callum''s ears, check his temperature, and assess his overall condition.','If the mother is unable to bring Callum in due to her circumstances, provide appropriate telephone advice and arrange a follow-up option that works for her.','As Callum has had ear pain and now ear discharge for more than 48 hours with signs of infection, an immediate antibiotic prescription is appropriate. Alternatively, if symptoms are not worsening but have not improved, a delayed prescription with clear instructions to begin antibiotics if there is no improvement within 24 hours, or if things worsen at any point, is also a reasonable approach.','Advise regular fluid intake and the use of paracetamol or ibuprofen as appropriate to manage fever and pain.','Let the mother know that you will re-send the physiotherapy referral for Callum''s in-toeing and help her arrange his outstanding vaccination.','Acknowledge her situation as a busy parent and gently emphasise the importance of attending health appointments for Callum''s wellbeing. Explain that if attendance is not possible, it is always best to call and rearrange as early as possible.','Reassure her that the practice is there to support her, but explain that if further appointments continue to be missed, the practice may need to consider a safeguarding referral, simply to make sure Callum''s health needs are being properly met.','Encourage her to let the practice know if she is struggling and to make use of any available support, whether through the GP team, local family support services, or social care.','Safety-netting advice: advise her to seek urgent help if Callum develops any of the following — swelling or redness behind the ear, neck stiffness or severe headache, unusual drowsiness or difficulty rousing, or a significant reduction in wet nappies or urine output.','Arrange a follow-up review in two to three days to check on Callum''s progress.'],
  'Thank you so much for calling in today, and I can hear how concerned you are about Callum. It is always worrying when a little one has been unwell for a few days and things do not seem to be settling, so you have absolutely done the right thing by getting in touch.

From what you have described — ear pain that has now been going on for a couple of days and has developed into a discharge — this sounds very much like acute otitis media, which is a middle ear infection. This is one of the most common childhood illnesses we see, particularly in children around Callum''s age, and it most often follows a cold or viral infection. The discharge you are seeing can actually happen when the pressure builds up behind the eardrum and it releases — it can look alarming, but it often means the worst of the pressure is beginning to ease.

Ideally, I would love to have a proper look in Callum''s ears in person, and I would encourage you to come in if you are able to. However, I completely understand that getting in today may not be straightforward. Given that his symptoms have now been present for more than 48 hours and he has developed discharge, I think it is appropriate to prescribe antibiotics to help clear the infection rather than simply waiting and watching.

I will arrange a prescription for him, and I would like you to use paracetamol or ibuprofen regularly in the doses appropriate for his age and weight to keep him comfortable and bring any fever down. Please also make sure he is drinking well throughout the day.

There are a couple of other things I want to pick up with you today — I can see from our records that Callum''s 4-in-1 pre-school booster is still outstanding, and he also missed his physiotherapy appointment for his in-toeing a couple of weeks back. I completely understand that life gets busy, especially when you are juggling work and childcare, and I am not here to make you feel judged at all. What I would ask is that if an appointment is not possible, please give us a call so we can rearrange — it really does help us make sure Callum gets everything he needs. I will re-send the physiotherapy referral for you so that one does not fall through the cracks.

I do want to be transparent with you: if we find that appointments continue to be missed, we may at some point need to flag this with our safeguarding team — not because we think anything is wrong, but simply because it is our responsibility to make sure every child''s health needs are being met. Please know that this is always done with care and never as a punishment. We are here to help.

Please keep a close eye on Callum over the next day or two. If you notice any swelling or redness appearing behind his ear, if he develops a very stiff neck or a severe headache, if he becomes unusually sleepy or you cannot rouse him, or if he stops drinking or passing urine, please do not wait — take him straight to A&E or call 999. I would like to give you a call in two to three days to check in and see how he is getting on.',
  ARRAY['Acute otitis media presenting with ear pain and discharge for more than 48 hours in a young child warrants antibiotic treatment; a delayed prescription approach is appropriate if symptoms are present but not worsening.','Red flags requiring urgent review include post-auricular swelling or erythema (mastoiditis), neck stiffness, severe headache, and significant drowsiness — these may indicate serious complications.','Missed health appointments in children should be addressed sensitively but directly; safeguarding concerns should be raised transparently and proportionately if a pattern of non-attendance emerges.','Always address outstanding vaccination and referral tasks identified in the records during a consultation, even if they are not the primary reason for the call.','Safety-netting for a child with otitis media should include specific signs of deterioration: worsening fever, reduced urine output, post-auricular changes, neck stiffness, and altered consciousness.','A face-to-face review is preferable for a young child with ear symptoms but remote management with appropriate follow-up is a safe and acceptable alternative when attendance is genuinely difficult.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  4,
  'Back Pain With Abnormal Blood Test',
  'Elderly Medicine & Palliative Care',
  'Telephone Consultation',
  false,
  'George Hartley',
  '75-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'Patient booked an appointment to discuss his blood test results.',
  '',
  '',
  ARRAY[]::text[],
  'You live alone. You are a non-smoker and do not drink alcohol. You are a retired airline pilot.',
  'You have wondered whether the back pain is simply wear and tear from years of sitting for long periods during long-haul flights.',
  'You are worried because you have been losing weight and feeling tired, and these symptoms are starting to have a real impact on your day-to-day life.',
  'You want the GP to explain what the blood results mean.',
  ARRAY[]::text[],
  NULL,
  'Accept all advice and offers from the doctor.',
  ARRAY['Ask about the nature of the back pain — its location, character, and how severe it is.','Ask whether the pain radiates anywhere, such as down the legs.','Ask whether the pain is getting worse, improving, or staying the same over time.','Ask whether the pain disturbs sleep or wakes the patient during the night.','Ask about any weakness, numbness, or tingling in the legs.','Ask whether the patient has normal bladder and bowel control, to rule out spinal cord compression.','Ask about any unintentional weight loss.','Ask about fever or night sweats.','Ask about loss of appetite, fatigue, or a general sense of feeling unwell.','Ask about symptoms that could suggest hypercalcaemia, including abdominal pain, constipation, excessive thirst or urination, muscle weakness, confusion, or drowsiness.','Ask about any family history of cancer, blood disorders, or other relevant conditions.','Ask about symptoms of anaemia, such as headaches, dizziness, palpitations, shortness of breath, or chest pain.','Ask how the patient is managing at home, both physically and emotionally.','Explore social history including smoking, alcohol use, and home situation.','Break the news of a likely diagnosis of multiple myeloma sensitively and clearly.'],
  ARRAY['Arrange an urgent urine test for Bence Jones protein and a blood test for serum protein electrophoresis to look for signs of myeloma.','Explain that if these results come back positive, an urgent referral will be made to a haematologist under the 2-week suspected cancer pathway for further assessment. The specialist will arrange additional investigations and, where appropriate, discuss the case at a multidisciplinary team (MDT) meeting involving cancer specialists.','Arrange an urgent X-ray of the lower back to look for signs of bone damage or fracture.','If offering an NSAID for pain relief, co-prescribe a proton pump inhibitor such as omeprazole to protect the stomach lining.','Arrange a follow-up call in two days to review the results and check on the patient''s symptoms.','Safety-netting: advise the patient to seek immediate medical attention if he develops numbness in the perianal area, difficulty passing urine or controlling his bowels, or sudden weakness in the legs, as these could be signs of cauda equina syndrome, a medical emergency.','Also advise him to be alert to symptoms of raised calcium levels, such as increased thirst, constipation, or passing more urine than usual.','Inform the patient that if he has not heard from the GP practice or the hospital within two weeks, he should contact the surgery to follow up.'],
  'Thank you for ringing in today, and I really appreciate your patience in waiting to go through these results with me. Before I explain what we have found, I want to acknowledge that what I am about to share may come as a shock, and I want you to know that I will be here to support you every step of the way.

Your blood tests have shown some results that are not consistent with normal aging or with simple mechanical back pain. In particular, the pattern of results we are seeing — which includes changes to your protein levels in the blood — raises the possibility of a condition called multiple myeloma. I want to be clear that we have not confirmed this diagnosis yet, but it is important enough that we need to investigate it thoroughly and quickly.

Multiple myeloma is a condition that affects the plasma cells in the bone marrow — the cells that normally help your body fight infection. When these cells become abnormal, they can cause problems including bone pain, particularly in the spine, as well as tiredness, unintentional weight loss, and changes to the blood and kidneys. These are symptoms you have been experiencing, which is why this possibility has come to our attention.

George, I want to be straightforward with you: this is something we need to take seriously and act on quickly. I am going to arrange two urgent tests today. The first is a urine test to look for something called Bence Jones protein, which is a marker associated with myeloma. The second is a blood test called serum protein electrophoresis, which looks at the types of protein circulating in your blood. I will also arrange an urgent X-ray of your lower back to look for any changes to the bones.

If these results point in the direction I am concerned about, I will refer you immediately to a blood specialist — a haematologist — under the two-week suspected cancer pathway. This does not mean we are certain you have cancer, but it means you will be seen by the right specialist quickly so we can get answers and a proper plan in place. They may wish to run further tests and will likely discuss your case at a team meeting with other specialists.

In the meantime, if your back pain is troubling you, we can look at appropriate pain relief. I would be cautious about certain painkillers given your age and the situation, but we can find something suitable. I will give you a call in two days once I have had a chance to review the early results.

Please do get in touch sooner if anything changes. In particular, if you develop any numbness around your back passage or groin, any difficulty passing urine or controlling your bowels, or any sudden weakness in your legs, please do not wait — call 999 immediately, as these can be signs of a spinal emergency that needs urgent treatment. Similarly, if you notice you are feeling very thirsty, more confused than usual, very constipated, or passing much more urine than normal, please let us know promptly as this could indicate high calcium levels. I will be thinking of you, and we will get through this process together.',
  ARRAY['Back pain in an older patient accompanied by constitutional symptoms such as weight loss, fatigue, and night sweats should raise strong suspicion of an underlying malignancy, including multiple myeloma.','Key investigations for suspected myeloma include serum protein electrophoresis, urine Bence Jones protein, and urgent plain X-ray of symptomatic bones; do not delay these pending further history.','The 2-week suspected cancer referral pathway should be activated if myeloma is suspected — early haematology involvement is essential.','If prescribing NSAIDs for pain in an older patient, always co-prescribe a proton pump inhibitor such as omeprazole for gastric protection.','Safety-netting for myeloma-related complications must address two key emergencies: cauda equina syndrome (perianal numbness, urinary/bowel dysfunction, leg weakness) and hypercalcaemia (thirst, confusion, constipation, polyuria).','Breaking serious or unexpected news over the telephone requires particular care — introduce the concern clearly but sensitively, check understanding, and always arrange prompt follow-up.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  5,
  'COPD Flare-Up in a Smoker',
  'Respiratory',
  'Video Consultation',
  false,
  'Peter Donnelly',
  '65-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'Patient booked an urgent appointment to discuss worsening respiratory symptoms.',
  '',
  '',
  ARRAY[]::text[],
  'You smoke around 40 cigarettes a day and do not drink alcohol. You live alone — your wife sadly passed away from breast cancer three years ago. You are currently in a relationship with a girlfriend. You had a COPD flare-up around six months ago and needed a course of steroids at that time. You believe you may need antibiotics and have booked this appointment to get some help. You are currently staying with a friend who lives about nine miles from the surgery, so attending a face-to-face appointment would be difficult at the moment.',
  'You think this could be another flare-up of your COPD, similar to the episode you had six months ago.',
  'You are worried that the symptoms are not settling on their own and may get worse if nothing is done.',
  'You are hoping to be prescribed antibiotics and possibly steroids to manage the flare-up remotely, and you would feel reassured knowing that something can be done without having to come in. When the doctor explains the diagnosis, volunteer the following: tell the doctor that your girlfriend, who also has COPD, lent you a finger pulse oximeter to check your oxygen levels. You used it this morning and it read 90%.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY['Ask about the cough — when it started, whether it is dry or producing sputum, and whether there is any blood in the sputum.','Ask about breathlessness — whether it is constant, worse with activity, or occurring even at rest.','Ask about breathlessness when lying flat (orthopnoea) or waking at night feeling short of breath (paroxysmal nocturnal dyspnoea).','Ask about any fever, chills, or recent infections.','Ask about any bluish discolouration of the lips or fingertips, which could suggest low oxygen levels.','Ask whether anyone has noticed the patient seeming more confused or muddled than usual.','Ask about any chest pain or palpitations.','Ask about swelling of the neck veins or any signs of fluid retention.','Ask about medication use — whether inhalers and other prescribed treatments are being taken as directed.','Ask about any recent travel, including long journeys, which can increase the risk of blood clots.','Ask whether the patient has had his flu vaccine, pneumococcal vaccine, and COVID-19 booster.','Ask about previous flare-ups and whether they have required antibiotics, steroids, or hospital admission.','Explore social history — smoking history and amount, alcohol use, living situation, and whether there is support at home.','Arrive at a working diagnosis of a COPD exacerbation.'],
  ARRAY['Offer a face-to-face review to examine his chest, check oxygen saturation directly, and confirm the clinical picture.','As the patient is unable to attend, remote management is appropriate provided he remains clinically stable.','Prescribe Doxycycline (or Clarithromycin if Doxycycline is not suitable), given his allergy to penicillin. Confirm any further allergies before prescribing.','Prescribe Prednisolone 30mg once daily for five days to reduce airway inflammation.','Arrange a follow-up call in three to four days to reassess symptoms and ensure he is improving.','Refer to the COPD nurse for review, including a discussion about setting up a rescue pack containing antibiotics and steroids, and developing a personalised COPD self-management plan.','Offer to arrange outstanding vaccinations if not already up to date — Pneumococcal, Influenza, and COVID-19 vaccines.','Safety-net: advise him to call 111 or seek urgent medical attention if he develops worsening breathlessness, chest pain, a high fever, confusion, or if his oxygen levels drop.','Explain that an oxygen saturation reading of 92% is acceptable for now, but that if it falls below 90%, this would indicate a need for hospital assessment and he should not delay in seeking help.'],
  'Thank you for getting in touch today and for not putting this off — respiratory symptoms that are not settling deserve prompt attention, and I''m glad you''ve called in.

From what you''ve described, this does sound very much like another flare-up of your COPD. An exacerbation — which is what we call these flare-ups — typically causes your cough to worsen, your breathlessness to increase, and often produces more or thicker mucus than usual. It is very common for these to be triggered by a respiratory infection, and given your symptoms and your previous episode six months ago, I think that is what is happening here.

I would normally want to examine you in person to listen to your chest and check your oxygen levels directly, and I do think that if you are able to get in at any point over the next day or two, it would be worth doing. However, I completely understand that it is difficult right now, and I am satisfied that we can manage this safely from a distance, provided things stay as they are and do not get worse.

You mentioned that you checked your oxygen level this morning with the finger monitor your girlfriend lent you, and it came back at 90%. I want to be honest with you — 90% is on the lower end of acceptable for someone with COPD. We would generally prefer levels of 92% or above. It''s not at a level that requires you to rush to hospital right now, but it is something I want you to keep a close eye on. If it drops below 90%, please do not wait — call 111 or go straight to A&E.

I am going to prescribe two things for you today. The first is a course of Prednisolone 30mg, taken once a day for five days — these are steroid tablets that will help reduce the inflammation in your airways and get them working better more quickly. The second is an antibiotic called Doxycycline, which will help tackle any infection that may be contributing. I''ll need to check that you have no other allergies before I send the prescription through.

I''d also like to refer you to our COPD nurse. She can review how you''re getting on, talk through your inhaler technique, and set you up with what''s called a rescue pack — essentially a supply of antibiotics and steroids kept at home so that if you ever have another flare-up in future, you can start treatment straight away without waiting for a GP appointment. She can also help you put together a written self-management plan so you feel more in control when these episodes happen.

I will give you a call in three to four days to see how you are getting on. If at any point before then your breathlessness gets significantly worse, you develop chest pain, a high fever, feel confused, or that oxygen reading drops below 90%, please seek help urgently — call 111 or 999 depending on how serious it feels.

One last thing, Peter — I do want to gently raise the subject of smoking. I know it''s not always easy to hear, and I''m not here to lecture you. But I think you know as well as I do that smoking 40 cigarettes a day is a very significant driver of your COPD and these flare-ups. When you are feeling better, I would really like to talk about what support might be available to help you cut down or stop. There is a lot more we can offer these days than there used to be, and even a reduction makes a meaningful difference.',
  ARRAY['A COPD exacerbation presenting with increased breathlessness, worsening cough, and change in sputum should be treated with Prednisolone 30mg once daily for five days; add an antibiotic if there are signs of infection.','In penicillin-allergic patients, Doxycycline is the preferred antibiotic for a COPD exacerbation; Clarithromycin is an alternative if Doxycycline is not tolerated.','An oxygen saturation of 90% in a COPD patient warrants close monitoring; if it falls below 90%, hospital assessment is required and the patient should be advised accordingly.','Remote management of a COPD flare is acceptable when the patient is clinically stable and unable to attend in person, but face-to-face review should be offered and arranged where possible.','All COPD patients benefit from a personalised self-management plan and a rescue pack (pre-prescribed antibiotics and steroids); refer to the COPD nurse to set this up.','Smoking cessation support should be raised at every appropriate opportunity in patients with COPD, and vaccinations (Influenza, Pneumococcal, COVID-19) should be kept up to date.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  6,
  'Insulin Management in Type 2 Diabetes',
  'Endocrine & Nephrology',
  'Video Consultation',
  false,
  'Tariq Hassan',
  '51-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'Patient booked an appointment to discuss his diabetes management.',
  '',
  '',
  ARRAY[]::text[],
  'You do not smoke or drink alcohol. Your diet is not ideal — your meals are mostly home-cooked by your wife but tend to be high in carbohydrates.',
  'You suspect that your high blood sugar levels are contributing to your symptoms.',
  'You are worried about developing serious complications — your uncle lost a leg as a result of his diabetes, and you are frightened the same could happen to you.',
  'You want your diabetes to be better controlled, but you would strongly prefer another tablet rather than going onto insulin.',
  ARRAY[]::text[],
  NULL,
  'Say no to any symptoms not specified in the station.',
  ARRAY['Ask about any changes in vision, including blurring.','Ask whether the patient has noticed increased thirst, more frequent urination, or feeling hungrier than usual.','Ask about any chest pain or breathlessness, particularly given the cardiovascular risks associated with poorly controlled diabetes.','Ask about any tingling, numbness, or pain in the legs or feet, or any slow-healing sores or wounds on the feet.','Ask about any unintentional weight loss or gain.','Review medication compliance — explore whether any doses have been missed or medications stopped, and ask why if so.','Explore psychosocial factors including smoking and alcohol use, dietary habits and activity levels, home environment and support, and occupation — particularly whether the patient is a driver, given potential implications for licensing.','Arrive at a working diagnosis of poorly controlled type 2 diabetes based on the patient''s symptoms and test results.'],
  ARRAY['Request a urine albumin-to-creatinine ratio (ACR), lipid profile, and calculate Q-Risk to fully assess cardiovascular and kidney health. Note: chronic kidney disease (CKD) can develop even when eGFR remains within the normal range, particularly in people with uncontrolled type 2 diabetes — this is why checking the ACR is essential even when kidney function appears normal on standard tests.','Offer an SGLT2 inhibitor such as Empagliflozin as the next step in treatment.','Counsel the patient about the side effects of SGLT2 inhibitors, including an increased risk of urinary tract infections and, on rare occasions, a serious infection of the genital or perineal area called Fournier''s gangrene (necrotising fasciitis).','Advise the patient about sick day rules: if he becomes unwell with diarrhoea or vomiting, he should temporarily stop metformin and his SGLT2 inhibitor (for example empagliflozin or dapagliflozin) and restart them only once he has recovered and has been eating and drinking normally for 24 to 48 hours.','GLP-1-based therapies such as oral or injectable semaglutide (Wegovy) and dual GIP/GLP-1 receptor agonists such as tirzepatide (Mounjaro) are the next-line options if glycaemic control is not achieved after introducing an SGLT2 inhibitor, in line with the updated NICE 2026 diabetes guidelines for patients with obesity. If the patient prefers not to take an SGLT2 inhibitor, GLP-1 or dual GIP/GLP-1 therapies can be offered at this stage as an alternative. Emphasise the importance of lifestyle measures: weight loss, a balanced diet reducing processed carbohydrates and sugary foods, and regular physical activity.','Offer routine vaccinations: Pneumococcal, Influenza, and COVID-19.','Arrange annual diabetic screening, including a retinal eye check and foot examination.','Advise on driving regulations: as a Group 2 driver (HGV or lorry), the patient is legally required to notify the DVLA about his diabetes diagnosis, regardless of whether he is on insulin, to ensure fitness to drive and for review of his licensing conditions.','Arrange a follow-up appointment in three months to review blood sugar control and response to treatment.','Safety-net regarding DKA symptoms — feeling very unwell, stomach pain, breathlessness, or a fruity smell on the breath — and advise him to seek urgent help if these occur. Also counsel on the side effects of Empagliflozin.'],
  'Thank you for coming on today, and I can hear that you have been worried about your diabetes for some time. I want to use this consultation to go through where things stand and to put together a clear plan to get your blood sugar under better control.

From what you have described — the symptoms you have been noticing and the results we have on file — it is clear that your diabetes is not as well managed as we would like at the moment. This is not about blame; it happens, and the important thing is that we address it now before it causes any of the complications that you are understandably concerned about.

Tariq, I hear you when you say you would much rather try another tablet than go onto insulin. That is completely understandable, and the good news is that there are effective tablet options we have not yet tried that can make a real difference. I would like to start you on a type of medication called an SGLT2 inhibitor — specifically a drug called Empagliflozin. This works by helping your kidneys remove excess sugar from the body through your urine. It has been shown to improve blood sugar control and also has benefits for the heart and kidneys, which is particularly important in someone with type 2 diabetes.

I do want to make sure you know about the possible side effects. The most common one is an increased risk of urine infections or infections around the genital area, so it is important to keep yourself clean and dry and to let us know promptly if you develop any unusual discomfort in that area. There is also a rare but serious infection of the skin in the genital or perineal region called Fournier''s gangrene — it is very uncommon, but I want you to be aware of it so you can seek help quickly if you ever notice severe pain or swelling in that area.

There is also something very important I need to tell you about what to do if you become unwell. If you develop a stomach bug with diarrhoea or vomiting and are not able to eat or drink properly, you should temporarily stop both your metformin and the Empagliflozin until you have recovered and have been eating and drinking normally again for at least 24 to 48 hours. This is what we call sick day rules, and it helps prevent a rare but serious complication.

I also want to tell you about some additional options further down the line. If Empagliflozin alone does not bring your blood sugar into the target range, the current NICE guidelines — updated in 2026 — recommend medications called GLP-1 therapies, such as semaglutide, or a newer dual-acting medication called tirzepatide, which also helps with weight loss. So there are still further steps we can take before ever needing to consider insulin.

On that note, diet and lifestyle changes genuinely do make a difference and are worth pursuing alongside the new medication. Reducing high-carbohydrate foods — particularly white rice, bread, and sugary drinks — and building in some regular physical activity, even gentle walking, can meaningfully improve your blood sugar levels over time.

There are a few housekeeping things I also want to address. I would like to arrange some routine checks — a urine test, a cholesterol test, and a check of your cardiovascular risk — to make sure we have a complete picture of your health. I would also like to confirm that you are up to date with your vaccinations, and I want to make sure you have your annual diabetic eye and foot checks arranged if they are not already.

One important practical matter: I understand you drive a large goods vehicle for work. As a Group 2 driver with diabetes, you are legally required to inform the DVLA about your condition, if you have not already done so. This applies regardless of whether you are on insulin or not, and the DVLA will assess your fitness to drive and your licence conditions. Please do make sure this is in order.

I will see you again in about three months to review your blood sugars and see how you are getting on with the new medication. In the meantime, if you feel very unwell — particularly if you notice stomach pain, feel very sick, are struggling to breathe, or notice a fruity or unusual smell on your breath — please seek urgent medical attention as these can be signs of a serious complication called DKA. We are going to get on top of this together.',
  ARRAY['Poorly controlled type 2 diabetes with obesity should prompt consideration of SGLT2 inhibitors as next-line therapy, followed by GLP-1 receptor agonists or dual GIP/GLP-1 agonists (e.g. semaglutide, tirzepatide) in line with NICE 2026 guidelines.','Patients starting SGLT2 inhibitors must be counselled on sick day rules: temporarily stop metformin and the SGLT2 inhibitor during acute illness with vomiting or diarrhoea, and restart once eating and drinking normally for 24–48 hours.','Urine ACR should be checked in all patients with type 2 diabetes even when eGFR is normal, as CKD can develop early without a detectable fall in eGFR.','Group 2 (HGV/lorry) drivers with diabetes have a legal obligation to notify the DVLA regardless of treatment type; this is a mandatory disclosure, not optional.','Annual diabetic screening (retinal photography and foot examination) and up-to-date vaccinations (Influenza, Pneumococcal, COVID-19) are part of routine diabetes care and should be proactively offered.','Safety-netting for DKA must be clear and specific: advise patients to seek urgent help for vomiting, abdominal pain, breathlessness, or a fruity smell on the breath.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  7,
  'Abnormal Thyroid Function',
  'Endocrine & Nephrology',
  'Video consultation',
  false,
  'Helen Cartwright',
  '53-year-old female',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'Patient booked a routine appointment to discuss recent blood test results.',
  '',
  '',
  ARRAY[]::text[],
  'You don''t smoke or drink alcohol. You''re married with two teenage children at home. If asked: you''ve recently started taking over-the-counter multivitamins, thinking you might be low in something like B12 or iron.',
  'You think your tiredness is probably down to a vitamin deficiency.',
  'You''re worried because the fatigue is starting to affect your performance at work.',
  'You''d like to understand what''s behind it and get it sorted.',
  ARRAY[]::text[],
  NULL,
  'Decline any questions not covered by the details already provided. Accept all advice offered.',
  ARRAY[
    'Begin by asking how long she has been feeling tired.',
    'Explore the pattern — is the tiredness getting better, worse, or staying the same over time?',
    'Ask whether she had any recent illness, particularly a viral infection, before the fatigue began.',
    'Ask about hypothyroid symptoms: enquire whether she feels colder than those around her.',
    'Ask about skin changes — has it become noticeably drier than usual?',
    'Ask about hair changes — any thinning or increased shedding?',
    'Ask whether she has noticed any puffiness or swelling around the eyes (periorbital oedema).',
    'Enquire about unexplained weight gain.',
    'Ask about swelling or discomfort in the neck area.',
    'Check for difficulties with concentration or brain fog.',
    'Ask about bowel habits — specifically whether she has been constipated.',
    'Ask about her menstrual cycle — regularity, and whether she has any fertility concerns.',
    'Explore mood — any feelings of low mood or emotional changes?',
    'Take a social history: smoking, alcohol, home life, and the impact of symptoms on work and relationships.',
    'Explore specifically how the tiredness is affecting her job and day-to-day life.',
    'Arrive at a working diagnosis of subclinical hypothyroidism with post-viral fatigue.'
  ],
  ARRAY[
    'Offer to repeat thyroid function tests in 3 months, or sooner if symptoms worsen or significantly impact daily life.',
    'Encourage the patient to keep a daily symptom diary to identify patterns or triggers for fatigue, which can help plan activities and manage energy more effectively.',
    'Introduce the concept of pacing and energy management: explain that this involves balancing activity with rest. Suggest listing daily tasks, prioritising the most important ones, breaking them into manageable steps, and spreading them out to avoid overexertion.',
    'Advise against pushing through fatigue. Recommend resting when tiredness sets in and encourage asking for help or delegating tasks to family where possible.',
    'Promote gentle, regular physical activity such as short walks to maintain stamina. If fatigue persists or worsens, consider a referral to physiotherapy for a tailored activity plan.',
    'Discuss work support — if symptoms are affecting performance, offer a fit note for amended duties or a phased return. For example, starting with reduced hours (e.g. 2–4 hours per day) and building up gradually.',
    'Safety net: advise the patient to get in touch if symptoms worsen, new symptoms develop, or the tiredness becomes overwhelming or disabling.',
    'Arrange a follow-up in 3 months to review symptoms and repeat blood results, with the option to bring this forward if needed.'
  ],
  'Thank you for calling in today, Helen — I''m glad we have the chance to go through your blood results together and try to make sense of what''s been going on with your energy levels.

I''ve had a careful look at everything, and I want to start by reassuring you that most of your tests have come back completely normal. Your full blood count, blood sugar, liver and kidney function, and vitamin levels are all within the expected range. So there''s no sign of anaemia, a vitamin deficiency, or anything worrying in those areas.

There is, however, one result that sits slightly outside the normal range — your thyroid function. Specifically, your TSH level is a little higher than it should be, though your T4 level is still sitting within the normal range. What this tells us is that your thyroid — the gland in your neck that helps regulate your energy levels and metabolism — may be working slightly harder than it needs to, but it hasn''t yet dropped into a state where we''d need to start treatment. This is called subclinical hypothyroidism, and it''s actually quite common.

One thing worth knowing is that a recent viral illness can sometimes cause temporary changes to thyroid function, and it''s possible that''s played a role here. Because of that, the standard approach is to monitor it over time rather than jump straight to medication, since it often settles back on its own as the body recovers.

What I''d like to do is repeat your thyroid blood test in around three months to see whether things have returned to normal or whether they''re persisting. In the meantime, your tiredness is most likely a combination of the post-viral fatigue and the slightly borderline thyroid level working together.

To help manage your energy while we wait, there''s a technique called pacing that many people find really useful. The idea is to recognise your personal energy limits and plan your day around them, rather than pushing through and then crashing. Keeping a simple daily diary — noting when you feel most tired and when you have more energy — can help you identify patterns and schedule your most important tasks at the times when you feel your best.

It''s also worth incorporating some gentle activity, such as a short walk each day, which can gradually help rebuild your stamina over time. If things don''t improve, we can look at referring you to physiotherapy for a more structured programme.

I understand this has been affecting your work, and I want to make sure you''re supported. If it would be helpful, I can issue a fit note — whether that''s for a short period of reduced duties or a phased return, we can tailor it to what suits you best.

Finally, please do get back in touch sooner if things feel worse — for example if you notice unexplained weight gain, constipation, low mood, or feeling unusually cold. Those would be signs that we should take another look before the three-month mark. I''m happy to send a summary of all of this in writing if that would be useful.',
  ARRAY[
    'Subclinical hypothyroidism is defined by a raised TSH with a normal T4; it often requires monitoring rather than immediate treatment, as it can resolve spontaneously — particularly after a viral illness.',
    'Post-viral fatigue is a common and underrecognised cause of persistent tiredness; a careful history of preceding illness is essential.',
    'Pacing and energy management are evidence-based, non-pharmacological strategies for fatigue and should be offered alongside clinical follow-up.',
    'Repeat thyroid function tests at 3 months is the appropriate next step in subclinical hypothyroidism; treatment is generally considered when TSH remains elevated on repeated testing.',
    'A fit note can be offered to support work adjustments; GPs should actively discuss occupational impact and not wait for patients to request this.',
    'Safety-netting should include specific symptoms to watch for — weight gain, constipation, periorbital oedema, low mood, and feeling cold — that may indicate progression to overt hypothyroidism.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  8,
  'Hair Loss in Young Female',
  'Dermatology',
  'Video consultation',
  false,
  'Priya Sharma',
  '26-year-old female',
  ARRAY[]::text[],
  ARRAY[]::text[],
  'Patient booked a routine consultation to discuss concerns about her hair. You are Priya Sharma, 26 years old. You have been noticing increased hair loss over the past 2–3 months. Hair falls out easily in the shower and when combing, and you find strands on your pillow in the morning. The shedding is spread across the whole scalp. It is not yet obvious to others, but you are worried and want to address it before it becomes visible. There is no scalp scarring or patchy loss. No family history of hair loss. You have not changed hair products or introduced any new ones. No recent significant stress. If asked: you get tired easily and noticed this around the same time the hair loss started, about 2–3 months ago. Say no to any other questions asked. Only say this if asked — your periods have been quite heavy for the past 6 months or so. You are currently on your period, which is heavy, and it lasts 7 days. Your cycle is normally 28 days. Your first period was at age 12. You do not bleed between periods. You are not using any contraceptives — your partner uses condoms.',
  'Patient booked a routine appointment to discuss hair loss.',
  'I''ve been losing quite a lot of hair recently and I''m getting worried about it.',
  'The hair loss has been going on for about two to three months. It comes out mostly in the shower and when I brush my hair, and I notice some on my pillow too.',
  ARRAY[]::text[],
  'You live with your partner, and you have been together for five years. You have no other sexual partners. You do not smoke. You drink alcohol occasionally.',
  'You''re not sure what could be causing it.',
  'The hair loss is affecting your confidence — you work as a beauty therapist and your appearance matters to you professionally.',
  'You would like something to stop the hair loss, or to be referred to a specialist who can help.',
  ARRAY[]::text[],
  NULL,
  'Decline any questions not covered by the details already provided. Accept all advice that is offered.',
  ARRAY[
    'Take a detailed history of the hair loss — clarify whether it is thinning or shedding. Thinning often starts at the parting line, sides, or crown and presents gradually with finer, more brittle strands, as seen in PCOS or androgenetic alopecia. Shedding tends to be more sudden and diffuse, and is often linked to stress, nutritional deficiencies such as iron deficiency, or telogen effluvium.',
    'Ask whether there are any bald patches, visible scarring, redness, or rashes on the scalp.',
    'Enquire about the patient''s hair care routine and whether she has made any recent changes — such as new products, tight hairstyles, or heat treatments.',
    'Ask about any family history of hair loss.',
    'Ask about medications known to affect hair growth, such as antidepressants, carbimazole, or chemotherapy, and about any recent dieting or nutritional concerns.',
    'Take a menstrual history and specifically ask whether her periods are heavy. Recognise that heavy periods can cause iron-deficiency anaemia. If confirmed, ask about symptoms of anaemia such as dizziness, light-headedness, tiredness, palpitations, chest pain, or breathlessness.',
    'Rule out other contributing causes such as PCOS or hypothyroidism — ask about acne, hirsutism, recent weight changes, or skin changes.',
    'Explore the emotional and functional impact of the hair loss — whether it has affected her confidence, daily life, or work.',
    'Ask whether she has experienced any recent stress or significant life changes.',
    'Ask whether there is any chance she could be pregnant or has recently given birth, as postnatal telogen effluvium is a common and self-limiting cause of hair shedding.',
    'Arrive at a working diagnosis of hair loss most likely secondary to heavy menstrual blood loss causing iron deficiency.'
  ],
  ARRAY[
    'Arrange blood tests to investigate possible causes of hair loss and heavy periods, including ferritin, full blood count (FBC), thyroid function tests, vitamin B12, folate, vitamin D, liver function tests (LFTs), urea and electrolytes (U+Es), and coagulation profile to assess for bleeding tendencies.',
    'Offer a face-to-face appointment to examine the scalp and hair, including a hair pull test to determine the pattern and type of hair loss, and to check blood pressure and pulse to ensure haemodynamic stability.',
    'Advise that during the face-to-face appointment, an abdominal and speculum examination will be carried out to assess for pelvic causes of heavy menstrual bleeding, which may guide whether a pelvic ultrasound is needed.',
    'Acknowledge the patient''s concerns and interest in a dermatology referral or medication: explain that it is completely understandable to want to address this quickly, and suggest waiting for blood test results first. If iron deficiency is found and treated, the hair loss may resolve without the need for referral.',
    'Discuss temporary options for managing hair appearance if this is distressing — such as styling adjustments, hairpieces, or cosmetic products.',
    'To manage heavy menstrual bleeding in the short term, consider starting tranexamic acid, mefenamic acid, or norethisterone while awaiting full assessment and results — after checking for contraindications.',
    'Provide safety-netting for signs of worsening anaemia such as palpitations, fainting, or breathlessness, and advise her to seek medical attention if any of these occur.',
    'Book a follow-up in one week to review blood test results and agree on a tailored treatment plan.'
  ],
  'Thank you for coming to speak with me today — it sounds like this has been worrying you for a little while, and I''m glad you''ve raised it so we can look into it properly.

Based on what you''ve described, Priya — hair shedding diffusely across the scalp, getting worse in the shower and on your pillow, alongside feeling more tired than usual — I think the most likely explanation is something called telogen effluvium. This is a condition where hair enters a resting phase and sheds more than normal, usually triggered by something happening in the body, rather than a problem with the scalp itself.

One of the most common causes of this in women your age is iron deficiency, particularly when periods are heavy. When the body loses iron through blood loss each month, there may not be enough left to support normal hair growth, and the hair starts to shed more readily. The fact that your periods have been heavy for the past six months or so, alongside the fatigue and the timing of when the hair loss started, does make me think this could be the underlying reason.

To find out for certain, I''d like to arrange some blood tests for you. These will include a check on your iron stores (ferritin), a full blood count, thyroid function, vitamin B12, folate, vitamin D, and a couple of other checks to make sure nothing else is contributing. I''d also like to check whether your blood has any tendency to clot more slowly than normal, which can sometimes be a cause of heavier periods.

I''d also like to see you in person so I can have a proper look at your scalp and do a simple hair pull test, which helps me understand the pattern and type of hair loss. At that appointment I''ll also check your blood pressure and pulse, and I''d like to examine your tummy and do a brief internal examination to make sure there''s no pelvic cause for the heavy bleeding.

I completely understand that you''d like something done about the hair loss now, and I haven''t dismissed the idea of a referral to a dermatologist. But if this turns out to be iron deficiency, then treating it may be enough to stop the shedding and allow your hair to grow back naturally — so let''s get the results first before going down that route, as it could save you a lot of unnecessary steps.

In the meantime, to manage the heavy periods while we wait for results, I can consider starting a short course of medication such as tranexamic acid, which helps reduce bleeding, so that will be worth discussing at your face-to-face appointment.

Please do get in touch sooner if you start to feel faint, have palpitations, or feel breathless — those could be signs that your iron levels have dropped quite low and you would need to be seen more urgently. I''ll book a follow-up for next week to go through the blood results with you and put together a proper plan.',
  ARRAY[
    'Telogen effluvium is diffuse hair shedding caused by a physiological stressor — iron deficiency from heavy periods is one of the most common reversible causes in young women.',
    'Distinguish between hair thinning (often hormonal, as in PCOS or androgenetic alopecia) and hair shedding (more likely nutritional deficiency, stress, or post-partum) as this guides investigation.',
    'A comprehensive blood panel including ferritin, FBC, TFTs, B12, folate, vitamin D, LFTs, U+Es, and coagulation profile is appropriate when hair loss coincides with heavy menstrual bleeding.',
    'Heavy menstrual bleeding can be managed in the short term with tranexamic acid, mefenamic acid, or norethisterone while awaiting full assessment.',
    'A face-to-face review should include a hair pull test, haemodynamic assessment, and abdominal/speculum examination to assess for pelvic pathology.',
    'Acknowledge the psychosocial impact of hair loss — particularly in patients whose work or identity is linked to their appearance — and validate the request for referral before explaining a stepwise approach.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  9,
  'Drug Abuse in Teenager',
  'Mental Health',
  'Telephone consultation',
  false,
  'Jade Mercer',
  '15-year-old female',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication', 'No known drug allergy'],
  NULL,
  'Patient booked a routine appointment to discuss a personal concern.',
  'Hi. I need to talk to someone but I want to make sure this stays private first.',
  'Once reassured about confidentiality, the patient explains that she took a drug for the first time two days ago while spending an evening with her boyfriend, Ryan, who is also 15 and a classmate. She was at a friend''s house and Ryan gave her a drink mixed with something — she thinks it might have been MDMA, also known as ecstasy, though she''s not certain. After drinking it she felt dizzy and disorientated. She remembers dancing but soon felt overwhelmed and blacked out. She has vague memories of Ryan and others being around her, but cannot recall what happened over the next two to three hours. When she came round, Ryan said she had just fallen asleep. She feels uneasy about this. She has had headaches since, though these are now improving. She does not suspect sexual assault — there is no pain or bleeding down below. She recently became sexually active with Ryan and is not using any contraceptives. Her last menstrual period started yesterday and she is still on it.',
  ARRAY[]::text[],
  'She does not smoke or drink alcohol and does not normally use drugs. She lives with her parents but does not want them to find out — she says they are always busy with work and she feels emotionally distant from them. She rarely talks to them about personal matters.',
  'She is here for advice. She is not sure whether something might have gone wrong in her body.',
  'She is worried something may have happened to her that she cannot remember, and she is unsure whether she needs any medical treatment.',
  'She just wants to know whether she needs to take anything to clear the drug from her system.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Ask about the incident: where she was, who was present, what she took, and how it was given to her.',
    'Ask what drug she took — was she aware it was MDMA/ecstasy, or did she think it was something else?',
    'Ask whether she felt pressured or uncomfortable when her boyfriend offered her the drink.',
    'Ask how much she took and how long after taking it she lost consciousness.',
    'Ask whether others present also took the drug and whether they were similarly affected.',
    'Ask what she remembers from before she passed out.',
    'Ask how long she was unconscious and where she woke up.',
    'Explore whether she has any memory gaps — note that GHB, sometimes used as a date-rape drug, can cause blackouts and memory loss.',
    'Ask what happened when she came round — in particular whether she noticed any injuries, pain down below, or any bleeding or discharge — to assess for the possibility of sexual assault.',
    'Ask directly but sensitively whether she is worried that something sexual or harmful may have happened while she was unconscious.',
    'Ask about the boyfriend — how old is he, how does she feel about the relationship, and does she feel safe with him?',
    'Ask whether her boyfriend has ever pressured her into doing things she didn''t want to do, such as taking drugs or anything else.',
    'Ask whether she is sexually active, whether she uses any contraceptives, and if not, ask for her last menstrual period and whether there is any chance she could be pregnant.',
    'Ask whether this is the first time she has taken drugs.',
    'Ask how she feels about having taken the drug — whether she regrets it or feels it was a mistake.',
    'Ask about smoking, alcohol, and other substances.',
    'Ask about school and whether there are any difficulties there.',
    'Ask about her home situation — who she lives with and whether she has spoken to anyone about this.'
  ],
  ARRAY[
    'Thank the patient for coming forward and reassure her that she is not in trouble and that you are here to support her.',
    'Recognise that the combination of passing out after suspected drug use and limited parental involvement significantly heightens this young person''s vulnerability — a safeguarding referral is required.',
    'Explain calmly and without judgement: acknowledge what she has shared, reassure her she is not in trouble, and make clear that your primary concern is her safety. Explain that street drugs are dangerous and that you want to make sure she is protected both physically and emotionally.',
    'Explain the safeguarding process clearly: because she is young and the circumstances involve passing out and lost memory, you are required to involve a specialist team whose role is to support and protect young people in vulnerable situations — not to get anyone into trouble.',
    'Offer a face-to-face appointment if she has any concerns about what may have happened physically or is worried about sexual assault. If she has no concerns and no symptoms, this is not immediately required.',
    'Offer signposting to a sexual health clinic for STI screening, and arrange a separate appointment to discuss contraception. Provide leaflets on contraceptive options.',
    'Arrange a follow-up in 2–4 weeks to check how she is doing and ensure she feels supported.'
  ],
  'Thank you for calling in today, and I want you to know straight away that I''m really glad you did. I can hear that it took some courage to reach out, and you''ve done the right thing by talking to someone.

I want to be clear that this conversation is confidential. That means what you tell me stays between us in the vast majority of cases. There are some situations where I might need to share information with another team — but only if I''m genuinely worried about your safety, and if that were ever the case, I would tell you first and explain why. So please speak as openly as you feel able to.

Based on what you''ve told me, Jade, I''m not going to judge you at all. What happened to you — taking a substance and then losing several hours of memory — is something I take very seriously, and I want to make sure you''re okay.

In terms of your physical health, it sounds like the drug may well have been MDMA, though we can''t be completely certain, and there''s also a possibility that something called GHB was involved — this is a drug that can cause blackouts and memory loss when mixed into drinks, and it''s sometimes used without people knowing. The good news is that your headaches are settling and you''re feeling physically better now, which is reassuring.

In terms of what happened while you were unconscious — I''m glad you feel there was no physical assault, and I believe you. But I want you to know that if you ever change your mind about that, or feel worried, you can always come back and I will arrange a proper examination in a safe and supportive way.

There is something important I do need to explain. Because of what happened — the blackout, the lost time, the fact that this was given to you by someone else, and the fact that home isn''t always an easy place to talk — I have a responsibility to involve a specialist team called the safeguarding team. I want to be really clear that this is not about getting anyone into trouble, including you or Ryan. It''s about making sure you have the right support around you, especially given what you''ve been through. They work with young people all the time and they''re there to help.

I''d also like to arrange for you to have a check-up at a sexual health clinic — they can do a quick screen for infections and help with contraception advice too, all completely confidentially. I''ll also book a follow-up with me in the next few weeks so I can see how you''re getting on. You''re not going to be left on your own with this.',
  ARRAY[
    'Any young person who presents with blackout or memory loss after suspected drug use must trigger a safeguarding assessment — do not wait for confirmed abuse to act.',
    'GHB is a date-rape drug that causes rapid loss of consciousness and retrograde amnesia; it should be considered when a teenager''s drink may have been spiked.',
    'Confidentiality in young people has limits — explain these clearly at the outset using Fraser/Gillick principles, and always inform the young person before sharing information where possible.',
    'Limited parental involvement is an independent vulnerability factor and should be considered when assessing safeguarding risk.',
    'STI screening and contraception counselling are essential components of the management plan for a sexually active teenager who has experienced this type of incident.',
    'A non-judgemental, calm, and empathetic consultation style is critical to building enough trust for the young person to disclose fully — this directly affects the quality of the safeguarding assessment.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  10,
  'Depression And Firearms',
  'Mental Health',
  'Video consultation',
  false,
  'Gordon Whitfield',
  '54-year-old male',
  ARRAY[]::text[],
  ARRAY['Sertraline 200mg once daily', 'No known drug allergy'],
  'Seen by Dr Karen Reynolds (Clinical Practitioner Access Role) — 4 weeks ago. Presenting complaint: Known history of depression, currently on sertraline for the past six months. The patient reports ongoing low mood but notes some improvement since starting sertraline. He describes previous suicidal thoughts but denies any current suicidal ideation. He is otherwise well. Mental state examination: Calm, appropriately dressed, normal speech, low mood, no psychotic symptoms, no current suicidal ideation, insight and judgement preserved. Plan: Increase sertraline from 150 mg to 200 mg once daily. Arrange follow-up in four weeks. Safety-netting advice provided, including advice to seek urgent help should suicidal thoughts return.',
  'Patient booked a routine follow-up to review his mental health and discuss his medication.',
  'Hello doctor. I''m feeling a lot better now and I''d like to come off the sertraline.',
  'You have been dealing with depression for around six to seven months. You saw a GP four weeks ago who increased your sertraline dose. You have felt significantly better since then and would like to stop the medication. You are planning to apply for a firearms licence for use on your farm and are concerned that being on antidepressants might need to be declared during the application process and could affect your chances of being granted one.',
  ARRAY[
    'If asked about your mood: your mood is currently good. Your sleep and appetite are normal. You have not noticed any changes in your weight. You have no current thoughts of suicide or self-harm.'
  ],
  'You do not smoke, drink alcohol, or use illicit drugs. You live with your wife, who is very supportive. You work as a sheep and arable farmer. The farm was going through a difficult period financially, which contributed to your depression. Things have since improved, and you are hoping to apply for a firearms licence for pest and predator control — managing rabbits and foxes that damage your crops and protecting your livestock.',
  'You feel your depression has fully resolved.',
  'You are worried that remaining on sertraline will need to be declared on the firearms licence application and may prevent you from being approved.',
  'You would like the GP to stop your antidepressant medication.',
  ARRAY[]::text[],
  NULL,
  'Decline any questions or symptoms not covered by the details already provided.',
  ARRAY[
    'Ask why he wants to stop sertraline at this point and clarify when he started feeling better.',
    'Check whether he has been taking sertraline as prescribed and ask about any side effects.',
    'Ask about his current mood.',
    'Ask about sleep, appetite, and energy levels.',
    'Ask directly whether he has any current thoughts of suicide or self-harm.',
    'Explore his social history, including smoking, alcohol, recreational drug use, and occupation.',
    'Ask how his depression has affected his daily life and functioning.',
    'Ask about his home situation and whether he has adequate support.',
    'Ask whether he currently has access to firearms or plans to obtain them.',
    'Arrive at a working diagnosis of stable depression.'
  ],
  ARRAY[
    'Explain that antidepressants are generally continued for at least six months after symptoms have improved in order to reduce the risk of relapse.',
    'Advise that stopping sertraline too early significantly increases the risk of depression returning, particularly given his history of suicidal thoughts.',
    'Explain that sertraline must not be stopped abruptly — any reduction would need to be done gradually after a period of stability on the medication.',
    'Acknowledge how important obtaining a firearms licence is to him, but explain the need to ensure he remains mentally stable before any licence is granted, both for his own wellbeing and for reasons of public safety.',
    'Offer psychological support, such as talking therapies, if he feels this would be helpful alongside or in addition to medication.',
    'Provide safety-netting advice: advise him to contact the GP urgent line or emergency services without delay if suicidal thoughts return or his mood deteriorates.'
  ],
  'Thank you for coming today, and I''m really pleased to hear that you''ve been feeling so much better over these past few weeks — that''s genuinely good news, and the change in your sertraline dose does seem to have made a real difference.

I completely understand why you want to stop the medication. When you''re feeling well again, it''s natural to wonder whether you still need it. And I also hear that you have a very practical reason for wanting to come off it — the firearms licence application — which is entirely understandable given how important that is to the running of the farm.

That said, Gordon, I do need to be honest with you about the risks, because I think it''s important you have the full picture before making this decision. Antidepressants like sertraline work not just by lifting your mood, but by helping to stabilise it over a longer period. The general guidance is that once someone''s symptoms have improved, they should stay on the medication for at least six months before we consider reducing the dose — and you''re only a few weeks into that window.

The reason for this is that stopping too early significantly increases the chances of the depression returning, sometimes quite quickly. Given that you had thoughts of ending your life earlier in this illness, I have to weigh that risk very carefully. A relapse would not only be very difficult for you and your family, but it would also likely delay any firearms application far more than staying on the medication would.

There''s also something important to know about how sertraline is stopped — it should never be done suddenly. A gradual dose reduction is much safer and minimises the risk of withdrawal effects. That''s something we can plan together when the time is right.

In the meantime, I want to support you in every way I can. If you feel that talking to someone — a therapist or counsellor — would help alongside the medication, that''s something I can arrange. Many people find that combining medication with talking therapy gives the best long-term results.

Please do keep the line of communication open. If your mood dips, you feel you''re struggling, or you have any thoughts of harming yourself, I need you to contact us straight away — call the surgery urgent line, or if you feel unsafe, please ring 999 or go to your nearest A&E. Your safety always comes first.',
  ARRAY[
    'Antidepressants should be continued for a minimum of six months after symptom remission to reduce the risk of relapse; premature cessation is one of the most common management errors in depression.',
    'A history of suicidal ideation raises the stakes when a patient requests early cessation of antidepressants — this must be clearly explained and documented.',
    'Sertraline must be tapered gradually rather than stopped abruptly to avoid discontinuation syndrome.',
    'When a patient with depression seeks access to firearms, GPs must carefully balance the patient''s occupational needs with the clinical and public safety implications of granting a licence during a period of unstable mental health.',
    'Offering talking therapies such as CBT alongside or in place of medication should be raised as an option, particularly for patients motivated to reduce reliance on medication.',
    'Clear safety-netting — including contact details for urgent help and crisis services — is essential at every appointment for a patient with a history of suicidal ideation.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  11,
  'Hypercalcaemia in Older Female with Cancer History',
  'Endocrine & Nephrology',
  'Video consultation',
  false,
  'Patricia Hollingsworth',
  '64-year-old female',
  ARRAY[]::text[],
  ARRAY['Sertraline 50mg once daily', 'Ramipril 5mg once daily', 'Letrozole 2.5mg once daily', 'Alendronic acid 70mg once weekly on Tuesdays', 'No known drug allergy'],
  'Seen by Dr Anna Clarke (Clinical Practitioner Access Role) — 1 week ago. Presenting complaint: Reports persistent fatigue and noticed unintentional weight loss. No recent viral illness. Examination: BP 100/76 mmHg, pulse 75 bpm. Plan: Bloods arranged; review with results. Seen by Rebecca Thornton (Other healthcare professional access role) — yesterday. Blood samples taken with no complications. Results of bloods done yesterday: Na+ (Sodium) 139 mmol/L [ref 135–145 mmol/L; previous result 10 weeks ago: 131 mmol/L]. K+ (Potassium) 3.7 mmol/L [ref 3.5–5.3 mmol/L; previous: N/A]. Ca2+ (Adjusted) 2.9 mmol/L [ref 2.2–2.6 mmol/L; previous: N/A]. Phosphate 0.78 mmol/L [ref 0.74–1.4 mmol/L; previous: N/A]. Urea 2.7 mmol/L [ref 2.5–7.8 mmol/L; previous: N/A]. Creatinine 61 µmol/L [ref 59–104 µmol/L; previous: N/A]. eGFR >90 [ref >90, normal; previous: N/A]. Additional tests: thyroid function, HbA1c, CRP, and liver function tests — all within normal limits. Patient has booked a video consultation to discuss results.',
  'Patient has booked a video consultation to review her recent blood test results.',
  'Hello. I''ve had my blood tests done and I''m hoping you can go through the results with me.',
  'You had the blood tests because you''ve been exhausted for the past three weeks and have lost some weight. The fatigue is really starting to get you down and you wanted to find out what''s going on.',
  ARRAY[
    'Weight loss: you previously weighed 70 kg but now weigh 65 kg. You believe this has happened over the last 3–4 weeks.',
    'Medications: you take vitamin D tablets (10 micrograms / 400 IU — a low dose). Mention the dose if the doctor asks.',
    'If asked about calcium-rich food: explain that you eat yoghurt and milk regularly and that the hospital consultant advised you to do this, along with taking vitamin D, because of the medication letrozole which you take for breast cancer. Ask the doctor whether you should continue the vitamin D tablets.'
  ],
  'You do not smoke and do not drink alcohol. You live with your husband. You are a retired primary school teacher.',
  'You are not sure what is causing your symptoms.',
  'The tiredness is really affecting your daily life and you want to get it sorted.',
  'You are hoping the doctor will explain what the blood test results mean.',
  ARRAY[]::text[],
  NULL,
  'If asked anything outside of the details provided, say no. Keep your responses natural and conversational. Show mild concern but let the doctor lead the discussion.',
  ARRAY[
    'Take a symptom history from head to toe.',
    'Ask whether the patient feels confused, muddled, or unusually drowsy.',
    'Ask about nausea or vomiting.',
    'Ask about increased thirst or excessive fluid intake (polydipsia).',
    'Ask about palpitations or chest pain.',
    'Ask about abdominal pain or constipation.',
    'Ask about urinary frequency or any blood in the urine.',
    'Ask about weight loss or reduced appetite.',
    'Ask whether she has noticed any new lumps in the breast or armpit, given her history of breast cancer.',
    'Ask about bone pain, which may suggest bony metastases.',
    'Ask whether she takes any over-the-counter medications, particularly vitamin D supplements.',
    'Ask about smoking and alcohol intake.',
    'Explore ideas, concerns, and expectations.',
    'Ask about her home situation and level of support.',
    'Based on her symptoms and blood results, form a working diagnosis of hypercalcaemia, likely secondary to recurrence of breast cancer.'
  ],
  ARRAY[
    'This is a mild case of hypercalcaemia with no significant acute symptoms, so hospital admission is not required at this stage.',
    'Offer a face-to-face appointment to examine the breasts and armpits.',
    'Arrange an urgent 2-week-wait referral to the breast clinic — provide immediate safety-netting advice that if she has not heard from the clinic within 2 weeks, she should contact the surgery straight away.',
    'Arrange further blood tests for PTH (parathyroid hormone) and vitamin D levels.',
    'Advise the patient to keep well hydrated by drinking plenty of fluids.',
    'Reassure the patient that she can continue eating calcium-rich foods such as milk and yoghurt — dietary calcium is unlikely to have caused this elevation.',
    'Advise the patient to stop her vitamin D supplements for now as a precautionary measure.',
    'Safety-net: advise the patient to seek help if symptoms of hypercalcaemia worsen, including increasing confusion, nausea, constipation, or more frequent urination.'
  ],
  'Thank you so much for calling in today, and thank you for getting those blood tests done — I know it''s not always easy to organise, especially when you''re not feeling well.

I can hear that the tiredness has been really getting to you, and I want to make sure we get to the bottom of it. Let me go through your results with you carefully.

The good news is that most of your blood tests have come back completely normal — your thyroid, blood sugar, inflammatory markers, and liver function are all fine. Your kidney function and blood counts are also reassuring. So there''s a lot here that we can take some comfort from.

However, Patricia, there is one result that has come back slightly above the expected range, and I want to be open with you about what that means. Your calcium level is a little high — it''s 2.9, where we''d expect it to be between 2.2 and 2.6. Now, there are several possible explanations for this. Sometimes it''s related to the parathyroid glands in the neck working a little too hard. And vitamin D supplements can occasionally push calcium levels up too, though at the low dose you''re taking — 400 IU — that''s quite unlikely to be the main cause.

I want to be honest with you, because I think you deserve a straight answer. Given your history of breast cancer and the fact that you''ve also lost weight recently, I think it''s important that we consider whether the cancer could be playing a role here. I want to be clear — this isn''t a definite diagnosis, and I''m not telling you the cancer has definitely come back. But it would not be right for me to ignore the possibility, and I don''t want to give you false reassurance.

What I''d like to do is refer you urgently to the breast clinic. This is called a two-week-wait referral, which means the team should be in touch with you within two weeks to be examined and for further tests. If you don''t hear from them within that time, please call us straight away and we will chase it up for you — don''t wait.

I''d also like to do a couple of additional blood tests — specifically to check your parathyroid hormone levels and your vitamin D, which will give us a clearer picture of what''s driving the calcium result.

In the meantime, I''d ask you to stop taking your vitamin D tablets for now, just as a precaution. You can absolutely continue eating calcium-rich foods like yoghurt and milk — the calcium in your diet is very unlikely to be causing this level of elevation, so there is no need to change that.

Please make sure you''re drinking plenty of fluids, and if you notice that things get worse — more confusion, nausea, constipation, or needing to pass water more often than usual — please don''t wait for your next appointment. Call us or ring 111, as those could be signs that the calcium is rising further and needs prompt attention.

I''m sorry this isn''t the straightforward reassurance you were hoping for today. But I want to make sure we act quickly and get you seen by the right team. Please don''t hesitate to call if you have any questions in the meantime.',
  ARRAY[
    'Hypercalcaemia in a patient with a history of breast cancer should raise immediate concern about malignant recurrence with bony metastases until proven otherwise — a 2-week-wait referral to the breast clinic is appropriate.',
    'Mild hypercalcaemia (Ca2+ 2.9 mmol/L) without acute symptoms does not require emergency admission, but does require prompt investigation and safety-netting for worsening features.',
    'A differential for hypercalcaemia includes primary hyperparathyroidism, malignancy (most common), excess vitamin D, and granulomatous conditions — take a thorough medication and supplement history.',
    'PTH and vitamin D levels are the key additional investigations to help differentiate the cause of hypercalcaemia.',
    'Non-specific symptoms such as fatigue and unintentional weight loss in a patient with a cancer history should always prompt consideration of recurrence, even in the absence of an obvious localising symptom.',
    'Patients on aromatase inhibitors such as letrozole are sometimes advised to take calcium and vitamin D supplementation; the GP should review whether this is still appropriate when hypercalcaemia is identified.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  12,
  'Polycystic Kidney Disease in a Young Adult',
  'Genetics',
  'Video consultation',
  false,
  'Daniel Ashworth',
  '36-year-old male',
  ARRAY[]::text[],
  ARRAY['Indapamide 2.5mg once daily', 'No known drug allergy'],
  'Telephone consultation with Dr Louise Briggs (Clinical Practitioner Access Role) — 4 weeks ago. Presenting complaint: Patient attended following a routine occupational health check in which elevated blood pressure was identified. He was advised to see his GP for further assessment. Ambulatory blood pressure monitoring (ABPM) was arranged and confirmed hypertension, with an average reading of 150/100 mmHg. Impression: Hypertension. Plan: Commence ramipril 5mg once daily. Arrange blood tests in one week including urea and electrolytes. Send urine for albumin-to-creatinine ratio. Review blood pressure in one to two weeks. Safety-netting advice provided. Face-to-face consultation with Dr Sophie Alderton (Clinical Practitioner Access Role) — 3 weeks ago. Blood results filed: Na+ (Sodium) 139 mmol/L [ref 135–145 mmol/L]. K+ (Potassium) 3.7 mmol/L [ref 3.5–5.3 mmol/L]. Ca2+ (Adjusted) 2.3 mmol/L [ref 2.2–2.6 mmol/L]. Phosphate 0.78 mmol/L [ref 0.74–1.4 mmol/L]. Urea 2.7 mmol/L [ref 2.5–7.8 mmol/L]. Creatinine 104 µmol/L [ref 59–104 µmol/L]. eGFR 61 mL/min/1.73m² [ref >90 mL/min/1.73m²]. Other bloods: thyroid function, HbA1c, cholesterol, CRP, LFTs — all within normal limits. Urine ACR: normal. Impression: Poorly controlled hypertension with concern about renal function following initiation of ACE inhibitor. Examination: blood pressure 165/100 mmHg; Q-risk 3%. Plan: Switch ramipril to indapamide due to concern about deterioration in renal function and possible renal artery stenosis. Arrange urgent renal ultrasound scan. Follow up with scan results. Safety-netting advice given. Renal ultrasound scan — performed yesterday. Findings: Both kidneys are enlarged with numerous bilateral cortical and medullary cysts of varying sizes. The largest cyst in the right kidney measures 4.5 cm and in the left kidney 3.8 cm. No solid masses or suspicious lesions identified. No hydronephrosis. Renal parenchyma: cortical thinning noted bilaterally. No calcification or nephrolithiasis. Bladder appears normal. No abnormal findings in surrounding abdominal organs. Conclusion: Ultrasound findings are consistent with polycystic kidney disease (PKD). No evidence of renal artery stenosis.',
  'Patient has booked a video appointment to discuss the results of his renal ultrasound scan.',
  'Hello doctor, I''m here to find out what the scan showed.',
  'You had a kidney scan because recent blood tests raised concern about your kidney function. The doctor explained at the time that this could be related to the blood pressure medication, the high blood pressure itself, or some other underlying cause, and that a scan was needed to check. You had no symptoms and felt completely well, which is why the high blood pressure came as such a shock.',
  ARRAY[
    'You are not taking any over-the-counter or herbal medications.'
  ],
  'You do not smoke or drink alcohol. You live with your wife and two children — an 11-year-old daughter and an 8-year-old son. You work as a software engineer. You enjoy your job and do not find it stressful. Family history: you were adopted. You know that your biological father died from a kidney-related condition, but you do not know the specific diagnosis.',
  'You don''t understand why your blood pressure is high — you feel completely well.',
  'You are worried after being told there may be a problem with your kidneys, as you know kidney conditions can be serious.',
  'You would like the doctor to explain what the scan results mean and what happens next.',
  ARRAY[]::text[],
  NULL,
  'Decline any questions or symptoms not covered by the details already provided.',
  ARRAY[
    'Ask about symptoms of kidney disease, including flank pain, blood in the urine (haematuria), a sense of abdominal fullness or lumps due to enlarged kidneys, ankle or leg swelling, and recurrent urinary tract infections — all of which are common features of polycystic kidney disease.',
    'Ask about potential complications of polycystic kidney disease: intracranial berry aneurysms (presenting with sudden severe headache, neck stiffness, or visual changes suggesting subarachnoid haemorrhage) and aortic dissection (presenting with severe chest pain or breathlessness).',
    'Ask about a family history of kidney disease or sudden unexplained death, which may have been caused by an aortic dissection or berry aneurysm rupture.',
    'Ask about lifestyle factors including smoking and alcohol consumption.',
    'Ask about occupation, hobbies, and whether he participates in any contact sports — patients with polycystic kidney disease should avoid contact sports such as rugby or boxing due to the risk of cyst rupture.',
    'Ask about use of over-the-counter medications or herbal remedies, particularly NSAIDs such as ibuprofen, which can worsen kidney function.',
    'Ask about family circumstances, including whether he has children, as this is relevant to the discussion about genetic implications.',
    'Explore the patient''s ideas, concerns, and expectations.',
    'Break bad news sensitively and explain the diagnosis of polycystic kidney disease.'
  ],
  ARRAY[
    'Arrange a routine referral to nephrology for specialist assessment and long-term management.',
    'Advise the patient to stop indapamide and switch back to ramipril. Explain that ramipril is unlikely to have been responsible for the deterioration in kidney function and that it provides important renal protection as well as blood pressure control.',
    'Explain that blood pressure will need to be monitored regularly, and emphasise the critical importance of good control to slow the progression of kidney disease. Arrange regular reviews and suggest home blood pressure monitoring.',
    'Advise the patient to avoid over-the-counter NSAIDs such as ibuprofen, which can accelerate kidney damage in polycystic kidney disease.',
    'Discuss screening in his children and explain the risks and benefits. Routine screening in asymptomatic children is not generally recommended because of the potential psychological impact, the fact that many will remain asymptomatic for years, and the risk of future difficulties with insurance or employment. However, early detection of raised blood pressure allows earlier treatment and may reduce disease progression. Explain that some families opt for ultrasound and blood pressure screening, and that the decision should be made on an individual basis after full discussion.',
    'Offer a referral to clinical genetics to clarify whether this is autosomal dominant polycystic kidney disease and to provide genetic counselling for the patient and his family.',
    'Advise the patient to avoid contact sports such as rugby or boxing due to the risk of cyst rupture and serious internal bleeding.',
    'Provide clear safety-netting: advise the patient to seek emergency help immediately if he develops a sudden severe headache, neck stiffness, or visual disturbance (suggesting subarachnoid haemorrhage from a berry aneurysm), or sudden severe abdominal pain or dizziness (suggesting cyst rupture or internal bleeding).'
  ],
  'Thank you for coming in today — I know you''ve been waiting for the results of the scan, and I appreciate your patience. Before I go through the findings, I just want to check how you''ve been feeling generally since we last spoke.

I need to be honest with you about what the scan has shown, because it''s significant, and I think you deserve a clear explanation. The scan of your kidneys has identified something that we didn''t previously know about. Both of your kidneys are enlarged, and they contain a large number of fluid-filled sacs called cysts — on both sides, and of varying sizes. The largest on the right measures 4.5 centimetres, and the largest on the left is 3.8 centimetres. The scan also shows some thinning of the kidney tissue itself, which ties in with the slightly reduced kidney function we saw in your blood tests.

The conclusion from the scan is that this is consistent with a condition called polycystic kidney disease, or PKD. I want to take a moment to explain what that means, because I appreciate this is a lot to take in, Daniel.

Polycystic kidney disease is an inherited condition where cysts gradually develop within the kidneys over time. For many people, it doesn''t cause noticeable symptoms for years, which is why you''ve felt completely well up to this point. The fact that we''ve picked this up now — before you had any symptoms — is actually a real advantage, because it gives us the opportunity to manage it proactively and protect your kidney function for as long as possible.

I also want you to know that this very likely explains why your biological father died from a kidney-related condition. The most common form of PKD is passed down through families in what''s called an autosomal dominant pattern, meaning that each of your children has a roughly 50% chance of having inherited the gene. I know that''s a difficult thing to hear when it comes to your daughter and son, and we''ll talk through what that means for them carefully.

In terms of managing this going forward — the single most important thing we can do right now is ensure your blood pressure is well controlled, as high blood pressure accelerates damage to the kidneys. I want to switch your medication back from indapamide to ramipril. I know a concern was raised about ramipril and your kidney function, but on reflection we believe ramipril is unlikely to have caused that and it actually provides important protection for kidneys with this condition, so it''s the right choice for you.

I''d also like to refer you to the kidney specialists — the nephrology team — who will become your long-term partners in looking after this. They''ll monitor your kidney function closely and advise on management as things develop.

A couple of other important points: please avoid taking ibuprofen or similar anti-inflammatory painkillers — these can harm the kidneys and should be avoided from now on. And because the kidneys are enlarged, I''d ask you to avoid contact sports like rugby or boxing, as a knock to the abdomen could cause a cyst to rupture, which would be a medical emergency.

I''d also like to refer you to our genetics team, who can formally assess what type of polycystic kidney disease this is and provide you with proper genetic counselling — including guidance on whether and when your children should be tested.

Finally, please know the warning signs to watch out for: if you ever develop a sudden, severe headache unlike anything you''ve had before, especially with a stiff neck or blurred vision — go to A&E immediately, as this could indicate a bleed in the brain. Similarly, if you develop sudden severe abdominal pain or feel faint, please call 999. These are rare but serious complications of the condition that we want you to be aware of.

I know this is a lot to process. Please don''t hesitate to ask any questions today, and we can arrange a further appointment once you''ve had time to take this in.',
  ARRAY[
    'Autosomal dominant polycystic kidney disease (ADPKD) is the most common inherited kidney disease; it should be considered in any patient with bilateral renal cysts on imaging, especially with a family history of renal disease or unexplained early death.',
    'ACE inhibitors such as ramipril are the preferred antihypertensive in ADPKD because they provide both blood pressure control and direct renal protection; they should not be withheld based on a modest early rise in creatinine alone.',
    'NSAIDs are contraindicated in polycystic kidney disease as they can precipitate further deterioration in renal function.',
    'Contact sports should be avoided in ADPKD due to the risk of traumatic cyst rupture and internal haemorrhage from enlarged kidneys.',
    'Genetic counselling and referral to clinical genetics is essential — offspring of an affected parent have a 50% chance of inheriting the condition, and decisions about childhood screening require careful, individualised discussion.',
    'Safety-netting must include the symptoms of subarachnoid haemorrhage from berry aneurysm rupture (sudden severe headache, neck stiffness, visual disturbance) and cyst rupture (sudden abdominal pain, dizziness, haemodynamic compromise), both of which are recognised complications of ADPKD.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  13,
  'Jaundice in Returning Traveller',
  'Travel Health & Infectious Disease',
  'Video consultation',
  false,
  'Daniel Okafor',
  '28-year-old male',
  ARRAY[]::text[],
  ARRAY['No known drug allergies'],
  NULL,
  'Patient has booked an urgent appointment to discuss feeling unwell following recent travel abroad.',
  'Hi doctor, I''ve been feeling really under the weather for the past couple of weeks. It started after I got back from a trip to Sri Lanka.',
  'The fever and flu-like symptoms have settled now, but you''ve noticed your urine has gone very dark, your stools look pale and loose, and you''ve been itching all over. You still feel very tired.',
  ARRAY['Your mum noticed your eyes looked yellow, which made her push you to come and see a doctor.','You did eat street food while you were away in Sri Lanka.'],
  'You are not currently sexually active, have no tattoos, and are not taking any medications. You do not smoke or drink alcohol. You work as a sous chef at a local restaurant and live at home with your parents.',
  'You''re wondering whether this could be malaria. You did take your antimalarial tablets before travelling and don''t remember being bitten by mosquitoes.',
  'You are worried about whether you are safe to go back to work, particularly given that you work in a kitchen handling food.',
  'You''re hoping the doctor can tell you what is wrong and put your mind at rest.',
  ARRAY[]::text[],
  'Can I go back to work? When will I be able to return? If the doctor mentions hepatitis A, ask: "Will I need to have the hepatitis A vaccine before I travel again in future?"',
  'Decline any questions about symptoms not covered above. Accept all advice offered.',
  ARRAY['Ask about the onset and duration of symptoms','Ask whether the initial flu-like symptoms and fever have now resolved or are still ongoing','Ask about the fever pattern: in malaria, fever is typically swinging (swinging pyrexia) — worse at night, better during the day, and does not settle unless properly treated. In hepatitis A, fever tends to be continuous and usually lasts 5–7 days, occurring in the prodromal (pre-jaundice) phase','Carry out a systematic liver symptoms review, including jaundice, headache or confusion (which may suggest hepatic decompensation), nausea or vomiting, generalised itching, tremors (again suggesting hepatic decompensation), right upper quadrant abdominal pain, and any change in stool or urine colour','Ask about recent consumption of street food or untreated water during travel','Ask about use of illicit substances or over-the-counter medications','Ask about tattoos or recent blood transfusions','Ask whether anyone close to the patient has had similar symptoms','Take a brief sexual history','Ask whether malaria prophylaxis or hepatitis A vaccination was taken prior to travel','Ask about social history including smoking and alcohol use','Ask about occupation, as this is relevant for public health risk assessment','Elicit the patient''s ideas, concerns, and expectations','Arrive at a working diagnosis of hepatitis A infection, given recent travel history and consumption of street food'],
  ARRAY['Arrange a face-to-face appointment for blood tests including hepatitis serology, liver function tests (LFTs), renal function (U+Es), full blood count (FBC), C-reactive protein (CRP), and a malaria screen','Advise maintaining a cool, well-ventilated environment, wearing loose clothing, and avoiding hot baths or showers to help manage itching','Consider prescribing chlorphenamine at night if itching is particularly troublesome','Advise that ibuprofen can be used for pain relief if there are no contraindications','Notify the Health Protection Unit (HPU) immediately — do not wait for test confirmation. This is especially important given his role as a food handler. The HPU will arrange contact tracing and advise on further steps to prevent spread','Advise that any close contacts, particularly household members who work in food-handling roles, should stay away from work and await HPU guidance, even if they are currently well','Advise the patient to remain off work until he is no longer infectious — typically 7 days after the onset of jaundice, or 7 days after symptoms such as fatigue, nausea, or fever begin if no jaundice develops','Reinforce thorough handwashing after using the toilet','If the patient is or becomes sexually active, advise against unprotected sexual contact (including oro-anal and oro-genital contact) until at least 7 days after the onset of jaundice or 7 days after symptoms begin if there is no jaundice','Advise the patient to seek urgent medical attention if symptoms worsen, signs of dehydration occur, or any new symptoms develop','Arrange follow-up in 1–2 weeks; consider repeating LFTs at that point if initial results are abnormal','Reassure the patient that hepatitis A vaccination will not be needed in future, as he will have developed natural lifelong immunity following this infection'],
  'It''s really good that you came in today, Daniel, and I can understand why you''ve been worried. Let me explain what I think is going on and what we''re going to do about it.

Based on everything you''ve told me — the flu-like illness that started after eating street food in Sri Lanka, the dark urine, pale stools, itching, and the yellowing your mum noticed in your eyes — this really does sound like a condition called hepatitis A. Hepatitis A is a viral infection that affects the liver. It spreads through contaminated food or water, particularly in areas where hygiene standards may vary, and the virus is passed on through the stools of infected individuals. The combination of your recent travel, the street food you ate, and the pattern of your symptoms all point strongly in this direction.

I know you''ve been wondering about malaria, and it''s a very sensible thought given you''ve been to Sri Lanka. The thing is, malaria typically causes a persistent or cyclical fever with rigors and chills, and it does not settle on its own without treatment. In your case, the fever has now resolved, and the yellowing, dark urine, and pale stools that followed are much more typical of hepatitis A. That said, I do want to rule malaria out properly, so we''ll include a malaria screen in your blood tests.

I''d like to arrange a face-to-face appointment so we can take blood samples to look at your liver function, kidney function, a full blood count, and hepatitis markers, as well as that malaria screen. This will help us confirm the diagnosis and make sure everything is being monitored properly.

In the meantime, there are a few things that will help you feel more comfortable. If you''re in pain, ibuprofen is fine to take. For the itching — which can be really irritating — try to keep the room cool and well-ventilated, wear loose clothing, and avoid hot baths or showers. If the itching is particularly bad at night, I can prescribe an antihistamine called chlorphenamine to help you sleep more comfortably.

Regarding work — I know this is a real concern for you. Because hepatitis A can spread to others, particularly through poor hand hygiene or contaminated food, you will need to stay off work until you are no longer infectious. That is generally 7 days after the yellowing of your eyes started, or 7 days after your other symptoms began if you haven''t developed jaundice. I will also need to notify the Health Protection Unit, which is a routine public health step — you don''t need to worry about this. They will help with contact tracing and advise on whether anyone else at home or in close contact needs to be assessed, especially any family members who also work with food.

The good news about going forward is that once you have had hepatitis A, your body builds natural lifelong immunity, so you will not need the hepatitis A vaccine before future travel. Most people recover fully, and we will follow up with you in one to two weeks to check how you are getting on and review the blood results.',
  ARRAY['Hepatitis A should be considered in any returning traveller presenting with jaundice, particularly where there has been consumption of street food or untreated water in an area with lower sanitation standards','Distinguishing hepatitis A from malaria is important: hepatitis A typically causes a self-resolving fever in the prodromal phase followed by jaundice, dark urine, and pale stools; malaria causes a persistent or cyclical fever with rigors that does not settle without treatment','Hepatitis A is a notifiable condition — the Health Protection Unit must be informed promptly and without waiting for laboratory confirmation, particularly when the patient works as a food handler','Patients should be advised to stay away from food-handling work for at least 7 days after the onset of jaundice or 7 days after other symptoms begin if no jaundice develops','Chlorphenamine at night can help manage troublesome itching; ibuprofen is appropriate for pain relief in the absence of contraindications','Natural immunity develops after hepatitis A infection, so future vaccination is not required — this is an important point to communicate clearly to patients who travel regularly'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  14,
  'Insomnia In A Child',
  'Mental Health',
  'Telephone consultation',
  false,
  'Connor Fitzpatrick',
  '4-years, 4 months-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  'Nine months ago — seen by Nurse Elaine Hargreaves (Nurse Access role): Caller: Mother — Niamh Fitzpatrick. Reason for appointment: Booked to discuss ongoing concerns regarding Connor.',
  'Mother calling to discuss ongoing sleep difficulties in her young son.',
  'Hello, I''m calling about my son Connor. He''s been having a really hard time getting to sleep, and it''s starting to affect all of us at home.',
  'Connor has been struggling with sleep for the past 4–5 weeks. He has difficulty falling asleep and regularly wakes during the night, coming into your room. This is disrupting your sleep too, which is now becoming a real problem.',
  ARRAY['Connor used to have a reliable bedtime of 7pm, but now he isn''t settling until 10 or even 11 at night. He often uses his tablet to watch cartoons late into the evening. He also has fizzy drinks sometimes in the evenings.','You were recently promoted at work, which has meant longer hours and more pressure. Your mum helps with childcare — she collects Connor from nursery, and you pick him up from hers on your way home from work. Connor has just started nursery.','The main change in recent weeks has been your increased work commitments, with earlier starts and later finishes. You are a single parent and you are doing your best to give Connor a good life.'],
  'You live at home with Connor — it is just the two of you in the household.',
  'You believe Connor has insomnia.',
  'You are worried because his disturbed sleep is affecting your own ability to function, and you are exhausted.',
  'You would like Connor to be prescribed sleeping tablets. If asked directly about your own wellbeing, mention that you feel stressed, anxious, and low in mood.',
  ARRAY[]::text[],
  'If the doctor declines to prescribe sleeping tablets, ask: "What about Piriton? My friend''s child was given it for eczema and it helped them sleep."',
  'Decline any questions about symptoms not covered above. Accept all advice offered.',
  ARRAY['Ask when the sleep difficulty first started, to establish duration and assess for chronic insomnia','Ask whether Connor has difficulty falling asleep, staying asleep, or both, to characterise the sleep problem clearly','Ask how many nights per week the problem occurs — a frequency of three or more nights per week for three or more months supports a diagnosis of childhood insomnia','Ask whether Connor''s sleep was normal before the difficulties began, to determine whether this is a new or longer-standing issue','Ask whether there have been any recent changes in the family situation — for example, bereavement, parental separation, a house move, or a change in nursery or childcare arrangements, to assess for psychological or environmental triggers','Ask whether Connor has any fears about being alone at night, to screen for separation anxiety or nighttime fears','Ask whether Connor sleeps during the day, as excessive daytime sleep can reduce night-time sleep drive','Ask how many total hours of sleep Connor gets across a 24-hour period, to assess whether overall sleep is adequate','Ask about possible sleep disorders — for example, whether Connor wakes suddenly shouting or crying at night (screening for night terrors or nightmares), or whether he has ever sleepwalked (important for safety and differential diagnosis)','Ask whether Connor shows signs of hyperactivity, poor concentration, or impulsive behaviour, to screen for ADHD, which is strongly associated with sleep disturbance in children','Ask whether Connor has any difficulty interacting or communicating with others, to screen for autism spectrum disorder, which is also linked with poor sleep','Ask whether Connor snores or has any episodes of choking or gasping during sleep, which may indicate sleep-disordered breathing or obstructive sleep apnoea','Ask about the bedroom environment, including noise, light levels, and comfort, to identify environmental factors','Ask whether anyone shares a room with Connor, as this may affect his sleep','Ask whether Connor uses a tablet or other electronic device before bed, as screen time is a major contributor to delayed sleep onset in children','Ask whether Connor has fizzy or caffeinated drinks in the evening, as caffeine can significantly impair sleep in children','Take a pregnancy, birth, immunisation, nutrition, and developmental (PBIND) history, to check for any underlying developmental or health concerns','Ask how the mother is feeling — whether she feels stressed, low in mood, or anxious — as parental wellbeing directly affects the child','Ask whether any strategies have already been tried at home, to guide further management','Offer a working diagnosis of likely poor sleep hygiene causing sleep disturbance'],
  ARRAY['Advise on good sleep hygiene: encourage Connor to go to bed and wake up at a consistent time each day, including at weekends','Help mum establish a calm and predictable bedtime routine — this might include quiet time, a warm bath, and a short bedtime story, ending with Connor falling asleep independently without needing mum in the room','If Connor wakes and comes into mum''s room during the night, advise her to gently and calmly return him to his own bed, offer brief reassurance such as a goodnight kiss and a promise to check in shortly, then leave the room','If Connor is afraid of the dark, suggest using a small night light to help him feel more comfortable','Advise to avoid screens — including tablets, televisions, and phones — for at least 30–60 minutes before bedtime, as screen light interferes with the brain''s natural sleep signals','Advise to avoid fizzy drinks or anything caffeinated, particularly in the evening hours','If sleep hygiene measures have already been tried, ask specifically what has been attempted, reinforce what is working, and advise on any steps not yet implemented','Suggest keeping a sleep diary to help track patterns, identify possible triggers, and guide any adjustments to the plan','Explain clearly that sleeping tablets are not appropriate for children with sleep problems and can actually make sleep quality worse over time','Advise against long daytime naps, particularly in the late afternoon, and encourage regular physical activity during the day to build natural tiredness by the evening','Recommend a mindfulness or relaxation app — such as Headspace — for mum to help her manage her own stress and develop healthy coping strategies','Advise mum to book a separate appointment to discuss her anxiety and low mood, as her own wellbeing may be contributing to the situation at home','Arrange a follow-up appointment in four weeks to review progress and adjust the plan as needed'],
  'Thank you so much for calling today, and for being so open about what''s been happening with Connor. It really does sound as though you''ve been carrying a lot — managing a demanding new role while raising Connor on your own is no small thing, and I can hear how tiring this has all been.

From what you''ve described, the very late bedtimes, the tablet use in the evenings, and the fizzy drinks, this sounds very much like a case of poor sleep hygiene. This is actually extremely common in young children, especially when daily routines are disrupted or life gets busier. The good news is that this is very manageable with the right approach.

I want to address the question about sleeping tablets and Piriton directly, because I know that might seem like a quick fix. Unfortunately, sleeping tablets are not recommended for children, and antihistamines like Piriton are not suitable for sleep problems in this age group either. Rather than helping Connor learn to fall asleep on his own, they can actually make things harder in the long run and may cause other unwanted effects. What genuinely works is re-establishing a consistent sleep routine, and I''d like to walk you through exactly how to do that.

The most important thing is getting Connor back to a regular, earlier bedtime, ideally the same time each evening including weekends. Before bed, build in a calm wind-down period — something like a warm bath followed by a short story — and then have him settle in his own bed without needing you in the room. If he wakes in the night and comes to you, walk him gently back to his room, offer a brief reassurance, and then leave. It can take a few nights of being consistent, but most children respond well once the routine is established. A small night light can also be really helpful if he''s unsettled in the dark.

It''s also worth turning screens off at least half an hour before bed — the light from tablets can actually suppress the brain''s natural sleep signal, which makes it much harder for children to wind down. And try to avoid fizzy drinks in the evenings, as the caffeine and sugar can keep him alert for much longer than you might expect.

One more thing I''d like to mention — and please don''t feel I''m prying — you mentioned feeling stressed and low in mood yourself. That matters too, and it can have a real knock-on effect for both of you. I''d really encourage you to book a separate appointment so we can talk about how you''re doing. In the meantime, something like the Headspace app can be a helpful way to build in a little calm for yourself each day. Let''s also start a sleep diary for Connor so we can track what''s changing, and I''ll book you both in for a follow-up in four weeks to see how things are progressing.',
  ARRAY['Sleep difficulties in young children are most commonly related to poor sleep hygiene — including excessive screen time, caffeine intake, disrupted routines, and inconsistent bedtimes — rather than an underlying medical condition','A structured history should explore duration, frequency, and pattern of sleep difficulties, as well as potential contributing factors including environmental, psychological, and developmental ones','Sedating antihistamines such as chlorphenamine (Piriton) are not recommended for sleep problems in children and should not be prescribed for this purpose','ADHD and autism spectrum disorder are both strongly associated with sleep disturbances in children, and should be screened for when taking the history','If behavioural sleep hygiene measures have been tried without success in a child with a neurodevelopmental condition, referral for specialist input — including possible consideration of melatonin — may be appropriate','A sleep diary is a practical and valuable tool to track patterns, identify triggers, and monitor progress over time','Parental wellbeing is an important part of the assessment — maternal stress, anxiety, and low mood can contribute to the child''s difficulties and should be addressed alongside the child''s management'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  15,
  'Hyponatraemia in Older Male',
  'Endocrine & Nephrology',
  'Telephone Consultation',
  false,
  'Geoffrey Barton',
  '74-year-old male',
  ARRAY['Hypertension'],
  ARRAY['Ramipril 10 mg once daily','Amlodipine 10 mg once daily','Bendroflumethiazide 2.5 mg once daily','No known drug allergies'],
  'Urgent Primary Care Letter — 2 weeks ago

Dear GP,

Re: Geoffrey Barton, 74-year-old male

Geoffrey presented with a 5-day history of muscle cramps, tiredness, and generalised muscle weakness. He reported no red flag symptoms. On examination, his observations were stable: blood pressure 135/79 mmHg, pulse 75 bpm, respiratory rate 18 breaths per minute, oxygen saturations 99% on air, and temperature 36.5°C. Urgent blood tests demonstrated a low sodium level of 126 mmol/L (reference range 134 to 145 mmol/L), consistent with moderate hyponatraemia. He has been advised to suspend his bendroflumethiazide. He was safety-netted regarding symptoms of worsening hyponatraemia and understands to seek urgent medical attention if these occur. I would be grateful if you could arrange repeat sodium levels in 2 weeks to reassess.

Kind regards,
Dr Patricia Svensson
Locum Out of Hours GP

Seen yesterday by Donna Blackwood (Nurse Access Role)
Patient attended for repeat blood tests.
Observations: Blood pressure 177/98 mmHg, Pulse 70 bpm.
Blood tests were taken, and the procedure was well tolerated.

Blood test results
Test               Result          Reference Range
Sodium             134 mmol/L      134–145 mmol/L
Potassium          4.1 mmol/L      3.5–5.3 mmol/L
Urea               5.0 mmol/L      2.5–7.8 mmol/L
Creatinine         78 µmol/L       60–110 µmol/L
eGFR               70 mL/min/1.73m²   >90 mL/min/1.73m²',
  'Patient has booked a video consultation to discuss his recent blood test results.',
  'Good morning doctor, I''d like to go over my blood test results and find out if I can restart my blood pressure tablet.',
  'Two weeks ago, you felt unwell with muscle cramps, tiredness, and weakness. You were unable to get a GP appointment, so you called 111 and were directed to an urgent primary care service. The doctor there ran blood tests and told you your salt level was low. You were advised to stop the bendroflumethiazide and to have a repeat blood test after two weeks.',
  ARRAY['You have been taking bendroflumethiazide for around 15 years. It was added because your blood pressure was not well controlled on just two tablets.','You feel well now and have no symptoms at present.'],
  'You do not smoke or drink alcohol. You are a retired civil engineer. You eat a balanced diet and stay active by walking with your wife in the evenings. You live with your wife.',
  'You think the low sodium might have been caused by a stomach bug. Around the same time as the cramps, you had a bout of diarrhoea. The diarrhoea and weakness settled, but the cramps lingered, which is what made you seek help.',
  'You are worried because your blood pressure was checked yesterday and appears to be raised. You know that high blood pressure can cause a stroke, and this concerns you greatly, as your father suffered a fatal stroke.',
  'You would like to understand your blood test results and to know whether it is safe to restart bendroflumethiazide.',
  ARRAY[]::text[],
  NULL,
  'Say no to any other questions or symptoms asked about outside of the details already provided.',
  ARRAY['Acknowledge that you have reviewed the out-of-hours letter and understand the background to his low sodium. Then ask him, in his own words, to describe what happened and what brought him to seek urgent care','Ask whether he is still experiencing any symptoms such as muscle cramps, tiredness, or generalised weakness','Ask about any recent diarrhoea, vomiting, or reduced food and fluid intake','Screen for red flag symptoms of severe hyponatraemia, including confusion, falls, seizures, or any reduction in level of consciousness','Screen for red flag symptoms that may suggest an underlying malignancy, including unintentional weight loss, night sweats, a persistent cough, or any new lumps or masses — noting that small cell lung cancer is the primary cause of cancer-related SIADH, accounting for up to 70% of cases, with other causes including non-small cell lung cancer, head and neck cancers, and certain lymphomas','Ask how long he has been taking his current medications and whether there have been any recent dose changes','Ask about any over-the-counter or additional medications','Ask whether he has had any previous episodes of low sodium','Explore social history including smoking, alcohol intake, diet, and home circumstances','Explore the patient''s ideas, concerns, and expectations','Arrive at a diagnosis of thiazide-induced hyponatraemia, likely exacerbated by a recent episode of diarrhoeal illness','Recognise that his blood pressure is currently uncontrolled following the cessation of bendroflumethiazide'],
  ARRAY['Explain that thiazide diuretics are a well-recognised cause of low sodium, and that restarting bendroflumethiazide carries a significant risk of it happening again. Make clear that hyponatraemia can be dangerous, potentially causing confusion, seizures, and in severe cases, death','Offer alternative blood pressure medications to replace bendroflumethiazide — options include an alpha blocker such as doxazosin or a beta blocker such as bisoprolol','Arrange follow-up in 1–2 weeks to recheck blood pressure and assess response to the new medication','Encourage him to continue his healthy lifestyle, including a balanced diet and regular exercise','Safety-net: advise that while you do not anticipate any immediate problems, he should call 999 or seek urgent care immediately if he develops chest pain, shortness of breath, blurred vision, weakness in any part of the body, or slurred speech'],
  'Good morning, Geoffrey. Thank you for coming in today, and I''m glad you''ve had the repeat blood test done. Let me walk you through the results and explain what I think has been going on.

Looking back at what happened two weeks ago, the out-of-hours doctor found that your sodium level — which is essentially the salt level in your blood — had dropped to 126 mmol/L. The normal range is 134 to 145 mmol/L, so it was meaningfully below where it should be, and that level of drop is enough to cause symptoms like the cramps, tiredness, and weakness you experienced. This is called hyponatraemia.

The good news is that your repeat blood test yesterday shows your sodium has come back up to 134 mmol/L, which is right at the lower end of the normal range. That is a reassuring improvement. Your potassium, kidney function, and other markers all look satisfactory too. So from a sodium perspective, stopping the bendroflumethiazide has clearly helped.

Now, the reason I need to be careful about restarting bendroflumethiazide is that this type of medication — known as a thiazide diuretic — is actually a well-recognised cause of low sodium levels. In your case, it had likely been causing a gradual reduction in your sodium over time, and the diarrhoeal illness you had around the same time tipped things over the edge. If we were to restart it, there is a real risk of your sodium dropping again, which could be dangerous — low sodium can cause confusion, falls, seizures, and in severe cases, it can be life-threatening.

I understand you are concerned about your blood pressure, and you are absolutely right to be — it was 177/98 mmHg when the nurse checked it yesterday, which is higher than we would want. Given your family history of stroke, I completely understand why that worries you. What I would like to do is offer you an alternative blood pressure tablet to replace the bendroflumethiazide. Depending on what suits you best, options include a tablet called doxazosin, which is an alpha blocker, or bisoprolol, which is a beta blocker. Both work in different ways to help bring blood pressure down without the same risk to your sodium levels.

I would like to see you again in one to two weeks to check how your blood pressure is responding to the new medication. In the meantime, please do continue your evening walks and healthy eating — those habits genuinely make a difference. And if at any point you develop chest pain, blurred vision, shortness of breath, weakness in your arms or legs, or slurred speech, please call 999 straight away.',
  ARRAY['Thiazide diuretics such as bendroflumethiazide are a common and well-recognised cause of hyponatraemia, and the risk of recurrence if restarted is high — the medication should not be resumed after a significant hyponatraemic episode','Hyponatraemia can be exacerbated by concurrent diarrhoea, vomiting, or reduced fluid intake — a concurrent illness should always be considered as a contributing factor','Red flags for severe hyponatraemia include confusion, seizures, falls, and reduced level of consciousness — these require urgent escalation','Small cell lung cancer is the most common cancer-related cause of SIADH (accounting for up to 70% of cases) and should be considered when screening for a secondary cause of hyponatraemia, particularly in older patients','When a thiazide diuretic must be withdrawn, suitable alternatives for blood pressure control include an alpha blocker such as doxazosin or a beta blocker such as bisoprolol','Follow-up within 1–2 weeks is appropriate after changing a blood pressure medication to assess response and ensure sodium remains within normal limits'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  16,
  'Rectal Bleeding in Adult with Learning Disability',
  'Gastroenterology & Haematology',
  'Telephone consultation',
  false,
  'Raymond Ashworth',
  '70-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'Carer calling on behalf of a resident at a care home to discuss new rectal bleeding.',
  'Hello doctor, I''m calling from Meadow View Care Home. I look after Raymond, and we''ve been quite worried about him over the past few weeks. He''s been passing blood from his back passage and we''re not sure what to do.',
  'Raymond has been having rectal bleeding for around three to four weeks. There has also been some unintentional weight loss over that time, though it is difficult to quantify precisely. His stools have been loose and more frequent than usual.',
  ARRAY[]::text[],
  'Raymond lives in the care home and has a severe learning disability. He is non-verbal. He does not smoke or drink alcohol.',
  'You are not sure what is causing this, but the senior nurse at the care home is worried it could be bowel cancer.',
  'You cared for a close friend who was diagnosed with bowel cancer, and you witnessed the toll that surgery, chemotherapy, and radiotherapy took on him. It was an incredibly distressing experience, and you would not want Raymond to go through anything invasive or aggressive if it can be avoided.',
  'You would like to understand what might be going on and to have a conversation about the options available going forward. If asked about any other symptoms, respond: "No, there''s nothing else I''m aware of."',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY['Ask how long the rectal bleeding has been occurring','Ask about the amount of bleeding and how quickly it seems to have developed, quantifying if possible','Ask whether Raymond has any abdominal pain, and if so, whether carers have noticed any signs of discomfort such as guarding his abdomen or appearing distressed','Ask whether his stools have been loose or whether there has been any noticeable change in bowel habit','Ask about nausea or vomiting','Ask whether any masses or lumps have been felt in the abdomen by carers during personal care','Ask about symptoms that might suggest anaemia, such as dizziness, light-headedness, fainting, or shortness of breath','Ask whether any recent observations have been taken, including blood pressure and pulse','Ask whether Raymond has been more tired or less active than usual, which may suggest anaemia or general decline','Ask about his appetite and whether there has been any change','Ask about any family history of bowel cancer or bowel disease, if known from records','Ask whether Raymond has ever smoked, or whether this is documented anywhere','Ask about Raymond''s general health and baseline function before these symptoms began, to assess fitness for any potential investigations or interventions','Arrive at a working diagnosis of possible bowel cancer'],
  ARRAY['Offer a care home visit for a face-to-face clinical assessment to see whether Raymond will tolerate an examination in his familiar environment','Offer a FIT (faecal immunochemical test) and stool culture — explain to the carer that a stool sample can be collected from Raymond''s pad or commode when he next opens his bowels','Explain to the LPA or next of kin that if the FIT test returns positive, further referral under the two-week-wait pathway and investigations such as CT colonography or colonoscopy may be required, but that any such decision would first be discussed at a formal best interest meeting involving: the LPA, care home staff and the senior nurse, the GP, and a learning disability nurse','Explain what the best interest meeting would consider: Raymond''s baseline health and quality of life, whether further investigation is clinically necessary and safe, whether it can be carried out with the least possible distress, and what benefit further testing or treatment would realistically bring','Explain that light sedation or a short general anaesthetic may be options for certain investigations, but these would only be considered if absolutely necessary and only with agreement from everyone involved in the best interest process','Reassure the carer that if the team, including the LPA, concludes that further investigations or treatment would cause more harm or distress than benefit, the plan may instead be refocused on comfort care and symptom management','Emphasise that all decisions will be guided by Raymond''s best interests, that nothing will be done against his will or forced upon him, and that the process will be taken one step at a time with the LPA fully involved throughout','If a two-week-wait referral is made, advise the care home to contact the surgery if there has been no hospital contact within two weeks','If investigations are declined or deferred, offer symptom management such as analgesia for abdominal discomfort','Advise care home staff to contact the GP surgery promptly if Raymond''s condition deteriorates, he appears unwell, or they have any new concerns about his health'],
  'Thank you so much for calling, and for advocating so clearly for Raymond. It is clear you know him well and care about his welfare, and that means a great deal. Let me talk you through what I think we should do.

The symptoms you''ve described — the rectal bleeding, the looser stools, the weight loss over several weeks — are ones we need to take seriously and investigate properly. The honest answer is that we cannot tell from a phone call what is causing this, but these symptoms do need to be assessed carefully, and I want to reassure you that we will manage this in a way that keeps Raymond''s comfort and dignity at the centre of everything.

The first thing I''d like to do is arrange a visit to the care home so that I, or one of my colleagues, can see Raymond face-to-face. Sometimes a gentle clinical review can give us useful information even without formal examination, depending on what Raymond will tolerate on the day.

I''d also like to arrange a test called a FIT test, which stands for faecal immunochemical test. This is a stool sample test that checks for traces of blood that might not be visible to the eye. Your team can collect the sample from Raymond''s pad or commode when he next opens his bowels — it''s straightforward and does not require anything difficult from Raymond himself. We would also send a stool sample for culture to check for any infection that might be contributing.

If the FIT test comes back positive, we would need to think carefully about the next steps together. Any further investigations — such as a scan or a camera test of the bowel — would not be decided by one person. We would hold a formal best interest meeting involving you, the care home team, Raymond''s legal proxy or next of kin, and a learning disability nurse, to talk through what is realistically in Raymond''s best interests given his health, his quality of life, and what he would likely tolerate.

I have heard what you said about your friend''s experience, and I want you to know that nothing invasive will ever be pushed on Raymond. If the team agrees that further tests or treatment would cause more harm than good, we would absolutely shift the focus to keeping Raymond comfortable and managing his symptoms. His wellbeing — not just his medical condition — is what guides every decision here.',
  ARRAY['In patients with learning disabilities who are non-verbal, a collateral history from carers or the LPA (Lasting Power of Attorney) is essential — it is the primary source of clinical information','Rectal bleeding combined with weight loss and a change in bowel habit in an older patient warrants urgent assessment for possible colorectal malignancy, even when the patient cannot self-report symptoms','A FIT (faecal immunochemical test) is a practical first-line investigation that can be collected non-invasively from a pad or commode in a care home setting','Any decision about further investigation or treatment in a patient who lacks capacity must be made through a formal best interest meeting under the Mental Capacity Act, involving the LPA, care home staff, GP, and a learning disability nurse','If further investigation is felt to be more harmful than beneficial, management should be redirected towards comfort care and symptom control — this is a valid and appropriate outcome of the best interest process','If a two-week-wait referral is made, the care home should be advised to contact the surgery if no hospital appointment is received within two weeks'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  17,
  'Severe Leg Pain in Palliative Patient',
  'Elderly Medicine & Palliative Care',
  'Telephone consultation',
  false,
  'Trevor Hollingsworth',
  '79-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'District nurse calling on behalf of a palliative patient at home who is experiencing severe leg pain.',
  'Good morning doctor, I''m calling about Mr Hollingsworth. I''m his district nurse. He''s in a lot of pain in his left foot and calf and I''m very worried about him.',
  'The pain came on over the past day or so. It is in the left foot and lower leg. The foot looks pale and feels cold to the touch compared to the other leg. There is no obvious swelling or redness in the calf. He has no sensation in the foot and is completely unable to weight-bear or use the leg at all.',
  ARRAY[]::text[],
  'Trevor lives at home with his wife, who is his primary carer. She appears visibly distressed and there are concerns about whether she is managing adequately with his increasing care needs. He is now largely bed-bound. He does not smoke or drink alcohol. Trevor is aware of the nature of his illness and appears to be preparing for the end of life.',
  'You are worried this could be a DVT or some kind of vascular problem.',
  'Trevor is now bed-bound because of the pain, and you are uncertain whether his morphine dose can safely be increased.',
  'You are calling to get guidance from the GP on the best next steps for managing this situation.',
  ARRAY[]::text[],
  NULL,
  'Say no to any other questions asked outside of the details already provided in the brief.',
  ARRAY['Ask about the onset of the pain in the foot and calf — when it started and how quickly it developed','Ask whether the pain is on one side or both sides','Ask whether the affected foot feels cold compared to the rest of the body and the other limb','Ask whether there is any numbness, tingling, or pins and needles in the foot or leg','Ask whether the patient is able to bear weight on or use the affected leg at all','Ask whether there is any swelling, redness, or prominent veins visible in the leg, to help assess for possible DVT','Ask about any associated shortness of breath, chest pain, or palpitations, to consider a possible pulmonary embolism','Ask about the home situation and what carer support is currently in place','Ask the district nurse about her observations, any clinical findings from her examination, and what her concerns are','Ask what pain relief Trevor has taken so far, including drug names, doses, frequency, and how effective they have been','Ask about the timing of his last Oramorph and Zomorph doses','Ask whether his pain is currently controlled or whether breakthrough pain is persisting','Ask about the patient''s own wishes and preferences regarding hospital admission and escalation of care','Arrive at a working diagnosis of likely critical limb ischaemia based on the reported symptoms and clinical findings'],
  ARRAY['Respect Trevor''s decision to decline hospital admission and direct management towards keeping him comfortable at home in line with his expressed wishes','Arrange an urgent face-to-face clinical review today to assess his pain, examine the affected limb, and review his current opioid regimen','For immediate symptom relief, consider prescribing NSAIDs alongside paracetamol after confirming there are no allergies or contraindications','If adequate pain control cannot be achieved with current oral medications, escalate promptly to the specialist palliative care team for further support and consideration of a syringe driver if clinically appropriate','Offer to discuss and formally document an advance care plan, including the prescription of just-in-case medications for symptom management at home','Complete and submit an SR1 form (formerly DS1500) to support Trevor''s access to appropriate financial benefits and fast-tracked services; also involve the social prescriber to help coordinate additional support for his wife, who appears to be struggling with the caring role','Provide Trevor, his wife, and the district nursing team with the Daffodil Line contact details — a dedicated palliative care phone line that allows patients and families to access rapid support without the delays of standard routes; the name of this line may vary locally, but the core purpose is to ensure prioritised and timely care for palliative patients','Thank the district nurse for her dedication and continued care for Trevor and his family','Safety-net by advising the nurse and the family to contact the surgery or the out-of-hours team urgently if there is any worsening pain, new confusion, signs of distress, or any other concerns'],
  'Thank you for calling, and well done for being so observant and proactive — your clinical concerns about Trevor are absolutely right to take seriously.

From what you''ve described, the cold, pale, insensate foot with complete loss of power, combined with the sudden onset, paints a picture that is very concerning for critical limb ischaemia. This means the blood supply to the lower part of the leg has likely been severely compromised or interrupted. Under other circumstances this would be a surgical emergency, but given that Trevor is a palliative patient who is bed-bound, aware of his prognosis, and has clearly indicated he does not wish to go into hospital, we need to approach this very differently — with his dignity, comfort, and wishes at the forefront.

I will come out today to review Trevor in person. I want to assess the limb, review his current opioid dosing, and make sure we have the most effective pain management in place. In the meantime, if there are any oral NSAIDs available that are not contraindicated for him, we can try those alongside his regular paracetamol as a first step. If we find that his pain is not adequately controlled on oral medications alone, I will contact the specialist palliative care team to discuss escalation — including the possibility of setting up a syringe driver, which would allow us to give continuous medication under the skin for consistent comfort.

I would also like to take the time today to sit with Trevor and his wife to talk through an advance care plan, if that hasn''t already been documented formally. This includes making sure we have just-in-case medications prescribed so that the team can act quickly if his symptoms change overnight or at the weekend. I will also complete an SR1 form today, which unlocks access to certain financial benefits and faster community support — and I think it''s really important that we get the social prescriber involved to find some additional help for his wife. It is clear she is doing a remarkable job, but she should not have to carry this alone.

Please do share the Daffodil Line number with both Trevor and his wife — this is a dedicated palliative care line that means they can get direct support quickly, without having to go through standard routes. And please do not hesitate to call us back at any point today — if anything changes, his pain worsens, or there is any new confusion or distress, contact us or the out-of-hours team straight away.',
  ARRAY['Critical limb ischaemia should be considered in any palliative patient presenting with a sudden-onset cold, pale, pulseless, or insensate limb — even when the context is end-of-life care, the diagnosis guides symptom management','In palliative patients who decline hospital admission, management must be redirected towards comfort and symptom control in the home setting, fully aligned with the patient''s wishes','Just-in-case medications should be prescribed proactively in palliative patients with worsening symptoms to allow rapid symptom relief without delays at night or over the weekend','If oral analgesia is insufficient, early escalation to the specialist palliative care team is appropriate, including consideration of a syringe driver for continuous subcutaneous infusion','The SR1 form (formerly DS1500) should be completed promptly for patients approaching end of life, as it unlocks fast-tracked financial benefits and access to additional services','Carer wellbeing must not be overlooked — visible distress in a carer warrants referral to the social prescriber and involvement of community support services alongside clinical management','The Daffodil Line (or equivalent local palliative care rapid access line) provides patients and families with direct, prioritised access to palliative support — clinicians should ensure this is shared proactively'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  18,
  'Domestic Violence In A Young Female',
  'Ethics',
  'Video consultation',
  false,
  'Natasha Varga',
  '20-year-old female',
  ARRAY[]::text[],
  ARRAY['Not currently taking any medications','No known drug allergies'],
  NULL,
  'Patient has booked a routine appointment to discuss some concerns she has.',
  'Hi doctor. I''m a bit worried about my boyfriend actually. I wanted to talk to someone about him.',
  'Speak slowly and appear anxious and hesitant throughout. Your boyfriend is 41 years old. He lost his job three months ago, and since then he has been coming home drunk most evenings. He becomes physically violent when you ask him to stop drinking, and he has hit you on several occasions. He also has access to your bank account and regularly takes money to gamble.',
  ARRAY[]::text[],
  'You are not pregnant and have no children. You do not smoke or drink alcohol. You work as a hotel housekeeper and have been feeling overwhelmed by the situation at home. When asked about your own wellbeing, explain that while your mood is generally okay, you do not feel happy or safe at home.',
  'You think your boyfriend may be depressed and you''ve come today hoping the doctor can help him. You wonder if the doctor can prescribe him antidepressants or something to help him stop drinking.',
  'You are not looking for help for yourself — you are worried about him and want him to get better.',
  'You would like the doctor to explain what can be done to help your boyfriend, and what options are available.',
  ARRAY['If the doctor raises the possibility of involving safeguarding or social services, respond: "No please, don''t do that. He told me if I ever told anyone or reported him, he would kill me." You should not volunteer any further information unless directly and specifically asked.'],
  NULL,
  'Say no to any other questions asked outside of the details already provided in the scenario. If the doctor is kind and supportive, accept any plan they offer.',
  ARRAY['Ask how long the current situation with her partner has been going on','Recognise the possibility of domestic violence early in the consultation and respond with sensitivity','Ask about other forms of abuse the patient may be experiencing, including physical abuse (such as hitting, pushing, or kicking), emotional abuse (such as insults, controlling behaviour, or isolation from friends and family), and economic or financial abuse (such as control of her bank account or finances)','Ask whether there have been any threats or intimidation, particularly any threats to kill, which indicate a very serious level of risk','Ask whether any weapons have been used or threatened, such as belts, knives, or attempts to strangle','Ask whether her partner uses alcohol or drugs, and how frequently','Note the significant age gap between the patient and her partner, as this may be relevant to possible coercion or exploitation','Ask whether the partner has any known history of mental health problems','Take a social history — ask about her occupation and whether the abuse has affected her ability to work or manage day to day; ask sensitively about her own use of alcohol, drugs, or cigarettes as possible coping mechanisms','Ask whether there are any children in the household, and if so, whether they have witnessed any of the abuse, whether their behaviour or school attendance has been affected, or whether any concerns have been raised by teachers or others','Ask whether she feels safe speaking openly during the consultation at this moment','Explore her mood and emotional wellbeing, and how the current situation has been affecting her mental health','Arrive at a working diagnosis of domestic abuse, encompassing physical, emotional, and financial elements'],
  ARRAY['Gently and compassionately explain that what she is describing is likely domestic abuse, and affirm clearly that this is not safe or acceptable under any circumstances, regardless of what her partner is going through','Reassure her that she does not have to face this alone, and that support is available whenever she is ready to access it','Offer a referral to an Independent Domestic Violence Advisor (IDVA) if she feels comfortable — an IDVA can help her think through her options, develop a safety plan, and offer ongoing practical and emotional support','Given that she has received a direct threat to her life, advise that contacting the police by dialling 999 is an important step in keeping her safe; reassure her that if she prefers, you can help facilitate this contact to ensure she is supported throughout the process','If she is considering leaving the relationship but is worried about where she would go or how she would manage, offer a referral to Women''s Aid or the Samaritans, who can provide assistance with safe accommodation, emotional support, and practical guidance around employment','Provide the contact details for a local or national domestic abuse helpline, so she has access to confidential support at any time of day or night','Offer a referral to talking therapy, as the psychological impact of domestic abuse — including effects on mood, self-esteem, and sense of safety — can be significant and lasting','Advise that if she ever feels it would be safe to do so, she might consider encouraging her partner to seek help for his own mental health and drinking, for example through a trusted friend or by text, rather than in a direct conversation that could put her at risk','Safety-net clearly: if at any point she feels her life is in immediate danger, she must call 999 without hesitation','Reassure her throughout that her concerns are valid, that none of this is her fault, and that her safety is the priority','Offer a follow-up appointment within one week to check in on her wellbeing, confirm she is still safe, and revisit any decisions at a pace she is comfortable with'],
  'Natasha, thank you so much for coming today. I can see that this has taken a lot of courage, and I want you to know that you have done exactly the right thing by talking to someone. I''m going to listen carefully and I''m not going to judge you.

I hear how much you care about your boyfriend and how worried you are about him. That speaks to how kind you are. But I also want to be honest with you about something important. From what you''ve shared with me — the physical violence, the control over your finances, the threats — what you are describing sounds like domestic abuse. I want to be very clear: none of this is your fault. No one has the right to hurt you, regardless of what they are going through themselves.

Your safety has to come first. The threat he has made — that he would hurt you if you told anyone — is something I have to take very seriously, and so should you. A threat to kill is not something we can set aside. I want you to know that I am here to support you, not to do anything that would put you in more danger. Everything we discuss today is about what you are comfortable with and what feels safe.

One of the things I would like to offer you is a referral to someone called an Independent Domestic Violence Advisor, or IDVA. These are specialist professionals who work entirely confidentially with people in situations like yours. They can help you think through your options, make a safety plan that fits your circumstances, and walk alongside you at whatever pace feels right for you. You would not have to do anything you are not ready for.

Because of the threat that has been made, I also want to gently raise the option of contacting the police. I am not saying you must do this today, but I do want you to know it is available to you, and if you would find it helpful, I can help make that contact in a way that keeps you as safe as possible. If you were thinking about leaving at any point and were worried about where you would go, organisations like Women''s Aid can help with safe housing, and the Samaritans offer round-the-clock emotional support and practical guidance.

I would also like to offer you some talking therapy. What you have been going through has a real impact on how a person feels about themselves, and having a safe space to process all of this can make a real difference. I''d like to book you in for a follow-up appointment in one week — not to pressure you into any decisions, but just so I can check in and make sure you are safe. And please, if at any point you feel you are in immediate danger, do not wait — call 999 straight away.',
  ARRAY['Domestic abuse may present indirectly, with the patient expressing concern for the abuser rather than themselves — clinicians must recognise this pattern and respond with sensitivity and a trauma-informed approach','Domestic abuse encompasses multiple forms of harm: physical, emotional, psychological, and financial — a thorough history should explore all of these, not just the presenting concern','A direct threat to kill represents a serious escalation of risk and must be taken seriously; safety planning and discussion of police involvement are appropriate responses','Patients who are over 18 and have capacity have the legal right to make their own decisions, including declining safeguarding interventions — this must be respected, but does not remove the clinician''s duty to safety-net clearly and offer ongoing support','An IDVA (Independent Domestic Violence Advisor) referral should be offered when domestic abuse is identified — IDVAs provide specialist, confidential support tailored to the individual''s circumstances and readiness','Safety-netting is essential: the patient must be clearly advised to call 999 immediately if she is ever in immediate danger, and should be encouraged to keep key documents and emergency funds accessible so she can leave quickly if needed','Talking therapy should be offered proactively, as the psychological impact of domestic abuse on mood, self-esteem, and wellbeing can be profound and long-lasting'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  19,
  'Type 2 Diabetes in a Gypsy Traveller',
  'General Practice',
  'Telephone consultation',
  false,
  'Patrick Donnelly',
  '54-year-old male',
  ARRAY[]::text[],
  ARRAY['No regular medication', 'No known drug allergies'],
  'One week ago – Seen by a Clinical Practitioner (Access Role)
Presenting complaints: Patient is a traveller and temporarily registered. Reports a 3-month history of tiredness, increased thirst, and unintentional weight gain (no baseline weight recorded).
Examination: Blood Pressure: 138/88 mmHg. General condition satisfactory.
Impression: Fatigue and unintentional weight gain — underlying cause to be determined.
Plan: Blood investigations requested; to be reviewed with results.

Blood Test Results:
Test | Result | Reference Range
HbA1c | 69 mmol/mol | 20–42 mmol/mol
TSH | 2.1 mU/L | 0.4–4.0 mU/L
CRP | 4 mg/L | <5 mg/L
ALT | 28 IU/L | 10–50 IU/L
AST | 22 IU/L | 10–40 IU/L
ALP | 85 IU/L | 30–130 IU/L
Bilirubin | 12 µmol/L | 0–21 µmol/L
Albumin | 42 g/L | 35–50 g/L
Full Blood Count | Normal | —
Urea and Electrolytes | Normal | —
eGFR | >90 mL/min/1.73 m² | >90 mL/min/1.73 m²
Bone Profile including Calcium | Normal | —',
  'Patient has booked a telephone consultation to discuss recent blood test results.',
  'Hello, I''m ringing about my blood results — the doctor said to call once they were back.',
  'I had the tests because I''ve been feeling worn out and I''ve put on a bit of weight. Apart from that I feel alright in myself.',
  ARRAY['Does not smoke and does not drink alcohol', 'Lives in a caravan as a Gypsy Traveller; temporarily registered with the practice and moving out of the area tomorrow', 'Diet is poor — relies heavily on fast food and rarely cooks due to his mobile lifestyle', 'Family history: father had diabetes and has since passed away'],
  'Patrick does not smoke and does not drink alcohol. He is a Gypsy Traveller living in a caravan and is currently temporarily registered with the practice. He is moving out of the area tomorrow and is not yet sure where he will be settling. His diet is poor — he mostly relies on fast food and rarely cooks, due to the nature of living on the road. His father had diabetes and has since passed away.',
  'The previous doctor thought it could be a thyroid problem or possibly something like diabetes.',
  'He is more concerned about diabetes because a close friend lost his foot as a result of the condition.',
  'He wants to know what the test results show and what needs to happen next.',
  ARRAY['If the doctor offers a face-to-face appointment today, explain that you are unable to attend as you are leaving the area very soon. You live in a caravan and will be moving to another part of the UK with a friend, and you are not yet sure where you will settle. If the doctor advises contacting the new practice within 24 to 48 hours of settling so records can be transferred, agree and confirm you will do so.', 'If the doctor offers referral to a social prescriber for housing or accommodation support, politely decline. Explain that you are happy with your current lifestyle — you live in a caravan by choice and do not feel you need additional housing support at this time.'],
  NULL,
  'Decline to answer questions not covered in the information provided above. Accept all advice and management offered.',
  ARRAY['Take a focused history covering key symptoms from head to toe', 'Ask about blurry vision (may suggest hyperglycaemia-related complications)', 'Ask about increased thirst and changes in appetite (polydipsia and polyphagia)', 'Ask about chest pain or breathlessness (to screen for cardiovascular risk)', 'Ask about urinary frequency or blood in urine (polyuria and UTI symptoms)', 'Ask about tingling or numbness in the legs, non-healing wounds, or foot problems (peripheral neuropathy and early diabetic foot signs)', 'Ask about unintentional weight change', 'Explore psychosocial factors: smoking, alcohol use, and dietary habits (including reliance on fast food)', 'Ask if the patient has any housing difficulties or would benefit from support with social needs', 'Clarify how long he will remain in the area, to help plan ongoing care and follow-up', 'Deliver a clear diagnosis of Type 2 Diabetes Mellitus based on his symptoms and an HbA1c of 69 mmol/mol'],
  ARRAY['Advise on lifestyle modification: begin by exploring whether there are any realistic ways to improve his diet and activity level given his mobile lifestyle. Advise him to avoid sugary drinks and processed foods. Encourage a diet rich in high-fibre, low-GI foods such as fruits, vegetables, wholegrains, and pulses, along with low-fat dairy and oily fish.', 'Recommend regular physical activity such as walking or simple daily exercises.', 'Offer referral to a social prescriber who can provide support with housing options and access to local services, if he would find this helpful.', 'Prescribe modified-release Metformin 500mg once daily.', 'Advise that Metformin may cause stomach upset or diarrhoea, and to contact the surgery or any healthcare provider if symptoms become troublesome.', 'Explain sick day rules: if he becomes unwell with vomiting or diarrhoea, he should temporarily stop Metformin and restart it once he has recovered and has been eating and drinking normally for 24 to 48 hours.', 'Explain that an additional medication will also be needed — an SGLT2 inhibitor (such as dapagliflozin or empagliflozin) — but that this will be started at least 2 weeks after Metformin to ensure it is tolerated first.', 'Provide a Diabetic Passport containing his recent HbA1c result, current medications, and guidance on recognising high and low blood sugar, along with advice on when to seek help.', 'Offer pneumococcal, influenza, and COVID vaccinations, as diabetes increases infection risk, and document these in his Diabetic Passport.', 'Advise him to register with a new GP as soon as he settles in a new location and to let the current practice know so medical records can be transferred electronically to ensure continuity of care.', 'Advise on annual diabetic foot checks to prevent ulcers and complications — this can be arranged at his new GP surgery.', 'Advise on annual diabetic eye screening to detect early signs of retinopathy.', 'Safety net on signs of hypoglycaemia such as shakiness, sweating, and confusion, and advise on what to do if they occur.', 'Safety net on symptoms of diabetic ketoacidosis such as vomiting, abdominal pain, and rapid breathing, and advise to seek urgent medical attention if they develop.'],
  'Thank you for getting in touch today, Patrick — I''m glad you called to discuss your results. Having looked at your blood tests carefully, and taking into account what you''ve described — the tiredness, the increased thirst, and the weight gain — I can now tell you what we''ve found. Your results show that you have a condition called type 2 diabetes. Have you heard much about diabetes before?

Diabetes is a long-term condition where the level of sugar in your blood becomes higher than it should be. Over time, if it isn''t well managed, it can affect different parts of the body including the heart, kidneys, eyes, and nerves — even when you feel perfectly well in yourself. That''s why it''s so important we get on top of this early and put a plan in place. Are you with me so far?

I know you mentioned your worry about your friend who lost his foot, and I completely understand why that''s been weighing on you. I want to reassure you that with good blood sugar control, regular monitoring, and routine foot checks, those kinds of complications can usually be prevented. We are very much going to work together to keep you safe.

In terms of treatment, we''re going to start you on a medication called Metformin — 500mg once a day to begin with. This is the most commonly used first medication for type 2 diabetes and it helps to bring your blood sugar down. Most people tolerate it well, but some people experience mild stomach upset or loose stools in the early weeks. If that happens and it''s really bothering you, please do let a doctor or pharmacist know.

It''s also important to be aware of what we call sick day rules. If you ever become unwell with vomiting or diarrhoea, you should stop Metformin temporarily and only restart it once you''re eating and drinking normally again — usually after about 24 to 48 hours. This is to protect your kidneys during times of illness.

We''ll also need to start a second medication called an SGLT2 inhibitor — for example dapagliflozin — which works alongside Metformin to improve blood sugar control and also offers extra protection for your heart and kidneys. However, we''ll hold off on that for at least two weeks to make sure you''re settling well onto the Metformin first. Your new GP can help arrange that when you''ve registered with a practice in your new area.

I understand you''ll be moving on tomorrow, so it''s really important that you register with a new GP as soon as you''ve settled. Please also let us know where you''ve registered so we can arrange for your full medical records to be transferred electronically to your new surgery. This is the safest way to make sure nothing gets lost.

To help you in the meantime, we''ll give you a Diabetic Passport today. This is a small document that contains your HbA1c result, your current medication, and guidance on recognising if your blood sugar is running too high or too low and what to do about it. It''s worth keeping this with you at all times, especially while you''re on the move.

Because diabetes can make it harder for your body to fight infections, I would also like to offer you your flu jab, the pneumococcal vaccine, and a COVID booster if you haven''t had one recently — all of which we can record in your Passport. Finally, I want to make sure you''re aware of the signs of a rare but serious complication called diabetic ketoacidosis. If you ever feel very unwell, are vomiting, have tummy pain, or notice your breathing becoming unusually fast or deep, please go to the nearest A&E or call 999. I''m not expecting this to happen, but it''s important you know what to watch for.',
  ARRAY['A new diagnosis of Type 2 Diabetes Mellitus is confirmed by a single HbA1c of 48 mmol/mol or above in a symptomatic patient; in this case the HbA1c was 69 mmol/mol, well above threshold.', 'First-line treatment is modified-release Metformin 500mg once daily; an SGLT2 inhibitor (e.g. dapagliflozin or empagliflozin) should be added after at least 2 weeks once Metformin is tolerated.', 'Sick day rules are essential: Metformin should be temporarily stopped during illness causing vomiting or diarrhoea and restarted only after 24–48 hours of normal eating and drinking.', 'For a patient who is moving out of the area, a Diabetic Passport (containing HbA1c, medications, and self-care guidance) and electronic record transfer between GP practices are key tools for ensuring safe continuity of care.', 'Annual diabetic foot checks and annual eye screening for retinopathy are important components of ongoing diabetes management and should be arranged at the patient''s new GP surgery.', 'Pneumococcal, influenza, and COVID vaccinations should be offered and documented, as diabetes increases susceptibility to serious infections.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  20,
  'Young Man With Hand Lesion',
  'Dermatology',
  'Telephone consultation',
  false,
  'Ryan Chambers',
  '26-year-old male',
  ARRAY[]::text[],
  ARRAY['No regular medication', 'No known drug allergies'],
  NULL,
  'Patient has sent in a photo of a skin lesion for remote review and would like to discuss it.',
  'Hi, I sent in a photo of something on my hand. I''ve had this bump for a few weeks and I''m not sure what it is.',
  'I first noticed it on my right index finger about seven weeks ago. It''s grown a little bit since then. It''s not painful or itchy, but it feels a bit rough and raised.',
  ARRAY['The lesion is not present anywhere else on the body', 'No contact with anyone who has had a similar rash or skin lesion'],
  'Ryan is a non-smoker and does not drink alcohol. He lives with his parents and a younger brother. He works as a chef at a local Italian restaurant.',
  'He is not sure what is causing it.',
  'He is worried the lesion might be infectious, particularly because he works as a chef handling food and wants to return to work.',
  'He would like the doctor to identify what the lesion is and advise whether it is safe for him to continue working.',
  ARRAY[]::text[],
  'Can this skin condition spread? Can I still work as a chef?',
  NULL,
  ARRAY['Ask about the onset of the lesion and how long it has been present', 'Ask about the exact location of the lesion and whether it is present anywhere else on the body', 'Ask whether the lesion is getting better, worse, or staying the same size over time', 'Ask whether it is itchy or painful', 'Ask whether there has been any bleeding, cracking, or discharge from the lesion', 'Ask if the patient has been in contact with anyone who has had a similar rash', 'Ask if the patient has been unwell recently — for example with flu-like symptoms, a sore throat, or fever — prior to the lesion appearing', 'Ask if the patient has had this type of lesion before', 'Ask if the patient has a history of eczema or other skin conditions', 'Ask if any new medications have been started recently', 'Explore the patient''s ideas, concerns, and expectations', 'Ask about occupation and social history — particularly any roles involving food handling', 'Make a working diagnosis of a viral wart'],
  ARRAY['Offer a face-to-face review with a dermatoscope for a closer look if there is any diagnostic uncertainty about the nature of the lesion.', 'If confident in the diagnosis from the photo and history, reassure the patient that a face-to-face appointment may not be necessary.', 'Explain that warts are harmless and typically resolve on their own, although this may take several months.', 'Inform the patient that warts spread mainly through direct skin-to-skin contact or by touching contaminated surfaces — for example, floors in communal changing rooms, swimming pools, or shared shower areas.', 'Suggest trying an over-the-counter salicylic acid preparation, available from most pharmacies, which can be applied for up to 12 weeks.', 'Advise that warts can spread and that certain precautions are needed to reduce this risk.', 'Advise that he can continue working as a chef, provided the wart is kept covered at all times with a clean, waterproof dressing to prevent direct contact with food, utensils, or kitchen surfaces.', 'Recommend wearing disposable hygienic gloves over the dressing for an additional layer of protection while working.', 'Reassure that transmission of the virus through food is very unlikely, but that good hand hygiene remains important.', 'Advise the patient not to scratch or pick at the wart, as doing so can cause the virus to spread to other areas of his body or to other people.', 'Signpost to the NHS website or send an information leaflet about warts.', 'Advise the patient to contact the surgery if the wart becomes painful, bleeds, spreads further, or does not improve over time — if so, referral for cryotherapy may be considered.'],
  'Ryan, thank you for sending in that photo and for getting in touch today. It''s really helpful to have a clear image to look at alongside everything you''ve described.

Based on what I can see and what you''ve told me — a small, slightly raised, rough-surfaced bump on your right index finger that''s been there for around seven weeks and has grown slowly — this looks very much like a wart. A wart is a small, harmless growth on the skin caused by a common virus called human papillomavirus, or HPV.

You can pick up the virus through direct contact with someone who has a wart, or by touching contaminated surfaces such as floors in communal changing rooms or shared shower areas. Sometimes there''s no obvious source, because it can take several weeks from the point of exposure before a wart actually appears — so it can be quite difficult to trace back to where or when you came into contact with it.

The good news is that warts are completely harmless and do not cause any serious health problems. They very commonly clear up on their own, but I should be honest with you — it can take a few months for that to happen. In the meantime, if you''d like to try to speed things along, you can pick up an over-the-counter salicylic acid cream or gel from any pharmacy. These work by gradually breaking down the wart tissue and are used for up to twelve weeks. The pharmacist there will be happy to show you the right product and explain how to use it.

I completely understand your concern about work. The reassuring news is that you can continue working as a chef, provided you take a couple of straightforward precautions. The most important thing is to keep the wart covered at all times with a clean, waterproof dressing — this creates a barrier between the wart and anything it might touch in the kitchen. On top of that, I''d suggest wearing a pair of disposable gloves over the dressing while you''re doing food preparation, just for that extra layer of protection. Transmission of the virus through food is actually very unlikely, but taking these steps means you can work confidently and hygienically.

One thing to be mindful of: please try not to scratch or pick at the wart. Doing so can spread the virus to other parts of your own skin or, in theory, to others.

If the wart isn''t improving after a few months of pharmacy treatment, or if it starts to cause pain, bleeds, or spreads, do come back and we can discuss referral for cryotherapy — that''s where a cold spray is used to freeze and destroy the wart tissue. But for now, things are very manageable, and I''m happy to support you with whatever next steps you''d like to take.',
  ARRAY['Warts are caused by human papillomavirus (HPV) and spread through direct skin contact or via contaminated surfaces such as communal shower floors; they are harmless and self-limiting but can take several months to resolve.', 'Remote diagnosis can be made with confidence when the history and photo quality are clear; if there is any diagnostic uncertainty, a face-to-face review with a dermatoscope is appropriate.', 'First-line treatment is an over-the-counter salicylic acid preparation, applied for up to 12 weeks; if this fails, referral for cryotherapy should be considered.', 'Patients with warts on the hands who work as food handlers can continue working, provided the wart is covered with a waterproof dressing at all times and disposable gloves are worn over the top during food preparation.', 'Patients should be advised not to scratch or pick at the wart, as this risks spreading the virus to other sites on the body or to other people.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  21,
  'Young Adult With Blood In Semen',
  'General Practice',
  'Video consultation',
  false,
  'Daniel Pryce',
  '29-year-old male',
  ARRAY[]::text[],
  ARRAY['Not on any regular prescribed medication', 'No known drug allergies'],
  NULL,
  'Patient has booked a video consultation to discuss a personal health concern.',
  'Hello doctor, I wanted to talk to you about something that''s been worrying me. I''ve noticed some blood in my semen, and I''m not sure what to make of it.',
  'This has happened four times in the past month. The blood is bright red and mixed in with the semen. It came as quite a shock and I''ve been worried about what might be causing it.',
  ARRAY['Takes ibuprofen for migraines and sometimes uses it preventatively even when not in pain', 'Already had a full STI screen at a sexual health clinic — testing for gonorrhoea, chlamydia, syphilis, and HIV — all results came back negative', 'The clinic advised him to see his GP if the bleeding continued'],
  'Daniel is a non-smoker and does not drink alcohol. He lives with his partner of three years and has no other sexual partners. He works as a software engineer.',
  'A pharmacist suggested an STI screen, which has already been done and came back negative. He is now wondering whether this could be cancer.',
  'He is worried this could be cancer.',
  'He would like the doctor to help work out what is causing the bleeding.',
  ARRAY[]::text[],
  'Could this affect my fertility? My partner and I are hoping to start a family in the near future.',
  'Decline to answer questions not covered in the information provided above. Accept all advice and management offered.',
  ARRAY['Signpost sensitively before starting — let the patient know you will be asking some personal and intimate questions in order to understand the problem properly', 'Ask how long the symptom has been present', 'Ask whether the blood has been noticed on just one occasion or on multiple occasions (a single episode of haematospermia in a young, otherwise healthy man is often benign and self-limiting; recurrent or persistent haematospermia increases the index of suspicion for more serious causes)', 'Ask about the colour of the blood in the semen — is it bright red or brownish? Bright red blood suggests fresh bleeding, whereas brown or rust-coloured blood indicates older blood that has had time to break down', 'Ask whether there is any pain during ejaculation (this can suggest prostatitis, urethritis, orchitis, epididymitis, or seminal vesicle stones)', 'Ask about urinary symptoms: pain passing urine, urgency, frequency, or getting up at night to urinate (these may point to a urinary tract infection or prostatitis)', 'Ask whether there is any blood in the urine (haematuria — this could indicate a urinary tract malignancy, infection, or kidney/bladder stones)', 'Ask about pain in the perineum, testicles, or lower abdomen (associated with prostatitis, epididymitis, or pelvic infections)', 'Take a sexual history: number of partners, use of barrier contraception, history of STIs, and whether STI screening has been carried out (to rule out chlamydia or gonorrhoea, which can cause haematospermia)', 'Ask about any trauma to the groin or pelvic area (trauma can cause local bleeding into the seminal tract)', 'Ask about bleeding from any other sites such as gums, nose, or rectum (to help rule out a bleeding disorder)', 'Ask about regular or over-the-counter medications — particularly NSAIDs or anticoagulants (NSAIDs like ibuprofen and blood-thinning medications can increase bleeding risk)', 'Ask about alcohol use, smoking, and recreational drug use', 'Ask about high-risk physical activities such as frequent cycling or horse riding (which can cause repetitive trauma to the perineal area)', 'Screen for red flags: fever, chills, general malaise (suggesting infection), and unexplained weight loss or night sweats (possible malignancy)', 'Ask about family history of prostate, testicular, or urinary tract cancer', 'Ask about anaemia symptoms if bleeding is heavy: headaches, dizziness, light-headedness, palpitations, chest pain, or breathlessness', 'Make a working diagnosis of haematospermia (blood in the semen)'],
  ARRAY['Offer a face-to-face appointment to check blood pressure, examine the abdomen, genital area, and perform a prostate examination.', 'Offer to send a semen sample for culture to exclude infection not detected by the initial STI screen; there is no need to repeat the urine culture as this was already done and was normal.', 'Arrange blood tests including full blood count (FBC), clotting profile, urea and electrolytes (U+Es), and liver function tests (LFTs).', 'Although PSA testing is generally reserved for men over 40 with haematospermia, discuss and offer it given the patient''s concern about cancer and for thoroughness.', 'Advise him to stop taking ibuprofen regularly, as it can increase bleeding tendency; offer a follow-up appointment to review his migraine management separately, and suggest paracetamol in the meantime for headache relief.', 'If all investigations return normal but haematospermia continues, refer to urology for further specialist assessment.', 'Reassure him that in the majority of cases haematospermia resolves spontaneously and does not indicate anything serious.', 'Reassure him that haematospermia alone is unlikely to affect fertility unless other symptoms or underlying conditions are present.', 'Safety net: advise him to return if symptoms persist, worsen, or if any new symptoms develop.', 'Arrange follow-up to review investigation results.'],
  'I can completely understand how alarming it must have been to notice blood in your semen, Daniel — it''s not something anyone expects, and it''s absolutely right that you''ve come forward to discuss it. The medical term for this is haematospermia, which simply means blood present in the semen. While it sounds frightening, the reassuring news is that in most cases — particularly in men your age — it isn''t caused by anything serious.

Let me take you through some of the possible explanations. One thing that stands out from what you''ve told me is your use of ibuprofen for migraines, particularly using it regularly and sometimes even preventatively when you''re not in pain. Ibuprofen belongs to a group of medications called NSAIDs, and while it is generally safe when used occasionally, taking it frequently can subtly affect the way your blood clots. It does this by interfering with platelets — the tiny cells that help stop bleeding — and this can make small blood vessels in the reproductive system more prone to minor bleeds. It''s not a very common side effect, but it is a recognised one, and it could well be playing a role in what you''ve been experiencing.

Another possible cause is infection, but since your STI tests and urine culture came back completely clear, that is much less likely in your case. To be thorough, I would still like to arrange a semen culture — a test on a semen sample — to check for any less common infections that would not be picked up by the standard sexual health screen.

You mentioned you''re worried this could be cancer, and I completely understand why that thought would cross your mind. I want to be honest with you: from everything you''ve described, with no other concerning symptoms and at your age, cancer is genuinely unlikely. That said, I would like to arrange a face-to-face appointment so I can examine you properly — checking your abdomen, the genital area, and your prostate — just to make sure we''re not missing anything. I think you''d feel more reassured knowing we''ve been thorough.

I''d also like to arrange some blood tests: a full blood count to check for signs of infection or anaemia, a clotting profile to assess how your blood is clotting, and kidney and liver function tests as part of a baseline health check. Although a PSA test — which gives us information about prostate function — is usually reserved for men over 40, given your concerns I''d like to offer it to you as well, just for completeness.

You asked about your fertility, which is a very understandable concern given that you and your partner are thinking about starting a family. The reassuring thing is that haematospermia on its own is very unlikely to affect fertility, particularly when there are no other associated symptoms or underlying conditions. Once we''ve reviewed all the test results, we''ll have a much clearer picture.

In the meantime, I''d like you to stop using ibuprofen regularly. I know it has been helpful for your migraines, and we will absolutely look at better ways to manage those at a separate appointment — but for now, paracetamol is a safer option to switch to.

Most cases of haematospermia do settle down on their own. If yours continues despite all investigations coming back normal, we would then refer you to a urologist for further specialist input. Please do get back in touch if things worsen, or if you develop any new symptoms such as pain, fever, or unintentional weight loss.',
  ARRAY['Haematospermia (blood in the semen) is most commonly benign and self-limiting in men under 40 with no red flag features; a structured history is essential to exclude serious causes such as infection, malignancy, or a bleeding disorder.', 'Always signpost sensitively before asking intimate questions about sexual health; a thorough sexual history should include number of partners, condom use, STI history, and results of any prior screening.', 'Regular use of NSAIDs such as ibuprofen is a recognised cause of haematospermia due to their antiplatelet effect; medication history must always be explored.', 'Initial investigations include face-to-face examination (blood pressure, abdomen, genitalia, prostate), FBC, clotting profile, U+Es, LFTs, semen culture, and consideration of PSA (particularly if the patient has concerns about cancer or is over 40).', 'Haematospermia alone is unlikely to affect fertility; however, STIs such as chlamydia or gonorrhoea must be excluded as these can impact reproductive health if left untreated.', 'Referral to urology is indicated if haematospermia persists despite normal investigations, if there are features suggesting malignancy, or if the patient is over 40 with no identified cause.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  22,
  'Teenager Seeking Abortion',
  'Gynaecology & Women''s Health',
  'Telephone consultation',
  false,
  'Jade Okonkwo',
  '16-year-old female',
  ARRAY[]::text[],
  ARRAY['No regular medication', 'No known drug allergies'],
  NULL,
  'Patient has booked an urgent appointment to discuss a personal concern.',
  'Doctor, I would like to get an abortion.',
  'I found out I was pregnant three days ago using a home urine pregnancy test. I repeated the test again today and it''s still positive. I don''t want to continue with the pregnancy — I''m worried it would affect my studies, and I''m also scared about what my parents would think, especially with our family''s religious background.',
  ARRAY['This is her first pregnancy; she has never been pregnant before', 'Her last menstrual period was 7 weeks ago', 'She has never used any form of contraception', 'She is in a relationship with her boyfriend, who is 17 and in the same college class', 'She lives at home with her parents and two brothers', 'She does not feel able to tell her parents about this situation', 'If asked whether there is anyone she can confide in, she says her 22-year-old sister, whom she trusts'],
  'Jade is a 16-year-old student studying health and science at college. She lives at home with her parents and two brothers. She is in a relationship with her 17-year-old boyfriend, who is in the same class. She does not smoke, drink alcohol, or use recreational drugs.',
  'She has had time to think and feels certain she does not want to continue the pregnancy. She believes this is not the right time in her life to have a child.',
  'She is worried that continuing the pregnancy will seriously disrupt her education and future plans. She is also concerned about how her parents would react, particularly given the family''s strong religious beliefs, and does not feel ready to involve them.',
  'She would like the doctor to explain her options, including how to access an abortion safely and confidentially, and to understand what the next steps would be.',
  ARRAY[]::text[],
  NULL,
  'Decline to answer questions not covered in the information provided above. Accept all advice and management offered by the doctor.',
  ARRAY['Clarify the reason the patient is seeking an abortion and explore how she is feeling about the situation', 'Ask about her last menstrual period (LMP) to estimate the gestational age', 'Ask how she confirmed the pregnancy (e.g. home urine test, private ultrasound)', 'Explore whether she has spoken to anyone about the pregnancy — family, friends, or partner', 'Given her age, ask about her partner: confirm his age, the nature of the relationship, and whether he is known to her', 'Ask sensitively whether she feels safe in the relationship and whether the sexual intercourse was consensual (screen carefully for any coercion or pressure)', 'Screen for symptoms that could suggest an STI or ectopic pregnancy: vaginal discharge, unusual bleeding, pelvic or lower abdominal pain, shoulder tip pain, or pain between periods', 'Ask about contraceptive use; if she was using contraception, explore what type and any possible reasons for failure', 'Ask whether she has ever been pregnant before (in a 16-year-old, a previous pregnancy may raise safeguarding concerns and inform the level of support needed)', 'Explore lifestyle factors: smoking, alcohol use, and recreational drug use', 'Ask about her home situation and who she lives with', 'Ask what she already knows about abortion and whether she has looked into it herself', 'Ask whether she has considered any alternatives, such as continuing the pregnancy or adoption, and whether she would be open to discussing these'],
  ARRAY['Explain that there are two main types of abortion: medical abortion using tablets, and surgical abortion which is a brief procedure carried out in a clinic.', 'As she is approximately 7 weeks pregnant, medical abortion is a safe and effective option. It involves taking two types of medication, usually a couple of days apart.', 'Reassure her that it is normal to experience some bleeding and cramping after taking the medication, usually beginning within the first few days, as the body passes the pregnancy. Pain relief such as ibuprofen or paracetamol can help to manage discomfort.', 'Explain that in a small number of cases the abortion may not be fully complete, and some people may need a surgical procedure to remove any remaining tissue; however, this is uncommon and she will be fully supported throughout.', 'Gently let her know that continuing the pregnancy and considering adoption is also an option, if she would like to discuss that further.', 'Encourage her to consider involving a trusted adult for support — such as her older sister if she does not feel ready to speak to her parents. Having someone who knows what is happening can be very important for her safety and wellbeing, particularly if any complications arise at home.', 'Arrange a referral to a specialist abortion service — for example BPAS (British Pregnancy Advisory Service), MSI Reproductive Choices UK, or NUPAS (National Unplanned Pregnancy Advisory Service) — where she will receive further information, counselling, and access to the appropriate service.', 'Recommend STI screening at a sexual health clinic, as this is routinely offered alongside abortion care.', 'Offer to discuss contraceptive options to help prevent an unplanned pregnancy in the future; this can include daily pills or long-acting reversible contraceptives (LARC) such as the implant or the intrauterine device (coil).', 'Provide leaflets or links to trusted websites so she can read about her options in her own time.', 'Reassure her that you are here to support her without judgement, and that she is not alone.', 'Advise that if she proceeds with a medical abortion, she should seek urgent medical help if she experiences very heavy bleeding (soaking two or more full-size sanitary pads per hour for more than two hours), severe abdominal pain not relieved by painkillers, a high temperature or chills, or symptoms such as fainting, dizziness, or confusion.', 'Emphasise the importance of completing a follow-up pregnancy test three weeks after the procedure (usually provided by the clinic) to confirm the abortion is complete.'],
  'Thank you for calling today, and for having the courage to talk about this — I know this can''t have been an easy call to make. I want you to know that this is a completely safe space, and everything we discuss is confidential. I''m here to support you, not to judge you.

You''ve told me you''re around seven weeks pregnant, based on your last period, and that you''ve confirmed this with two separate home pregnancy tests. I can hear that you''ve already given this careful thought and you know what you would like to do. I want to make sure you have all the information you need so that you can move forward feeling as informed and supported as possible.

In terms of your options, Jade, there are two main types of abortion. The first is a medical abortion. Because you are around seven weeks pregnant, this is a suitable option for you. It involves taking two different types of medication — the first is a tablet you swallow, and the second, taken a couple of days later, is either placed inside the vagina or tucked between your cheek and gum. After the second medication, most people experience cramping and bleeding, a bit like a heavy period, as the body passes the pregnancy. This usually begins within a few hours and can continue for several days. Taking paracetamol or ibuprofen regularly can help to keep the pain manageable.

In a small number of cases — and I want to be honest with you about this — the abortion may not be fully complete, and some people do need a brief surgical procedure to remove any remaining tissue. This is not common, but if it did happen, you would be fully supported throughout.

The second option is a surgical abortion. This is a short procedure carried out in a clinic where the pregnancy is removed using gentle suction or surgical instruments. It is usually offered after ten weeks, though it can sometimes be done earlier. The procedure itself typically takes only a few minutes, and a local anaesthetic or light sedation is used to keep you comfortable. Like any procedure, there are small risks such as infection, incomplete removal, or minor injury to the womb, but it is considered very safe overall.

I also want to gently mention that there is a third option — continuing the pregnancy and, if you felt it was right for you, considering adoption. I raise this not to pressure you at all, but simply to make sure you are aware of all the possibilities. If it''s not something you''d like to think about, that is absolutely fine.

What I would encourage you to do is think about whether there is a trusted adult who could support you through this process — you mentioned your sister, and that sounds like a wonderful first step. The reason I raise this is not to put pressure on you, but for your safety: after a medical abortion, there is usually some bleeding at home, and while things almost always go smoothly, it is much safer to have someone nearby who knows what is happening and can help if you need it. You don''t have to tell your parents if you don''t feel ready to — having your sister with you may be enough.

I''m going to refer you to a specialist service — BPAS, MSI Reproductive Choices, or a similar organisation — where you will be able to speak with a counsellor, have an ultrasound scan to confirm your dates, and access whichever type of abortion is right for you. They are very experienced at supporting young people through this, and everything will remain completely confidential.

Once this is all behind you, I would love for us to meet again to talk about contraception — just so we can make sure you have the right protection going forward, in whatever form suits your lifestyle best. There are lots of options including daily pills, or longer-acting methods such as the implant or the coil, which you don''t have to think about every day. There''s no pressure to decide anything today — I''ll send you a leaflet so you can have a read in your own time.

And finally, if at any point during or after a medical abortion you experience very heavy bleeding, severe pain that paracetamol or ibuprofen isn''t touching, a high temperature, or you feel faint or confused, please call 999 or go straight to your nearest A&E. I''m not expecting any of that to happen, but I want to make sure you know what to do just in case. I''m here to support you every step of the way.',
  ARRAY['Fraser guidelines apply when providing contraceptive or sexual health advice to patients under 16; Gillick competency must also be assessed to confirm the young person has sufficient maturity and understanding to consent to treatment independently.', 'Safeguarding must be actively considered: confirm the patient is in a consensual relationship, screen sensitively for coercion, and ask about the age and nature of the relationship with the partner.', 'Medical abortion using two medications taken a couple of days apart is appropriate for pregnancies up to 10 weeks; at 7 weeks gestation it is a safe and effective first-line option.', 'Referral to a specialist service such as BPAS, MSI Reproductive Choices, or NUPAS is the appropriate next step; these services provide counselling, ultrasound, and access to both medical and surgical abortion.', 'Safety netting after medical abortion includes advising the patient to seek urgent help if she soaks two or more full-size sanitary pads per hour for over two hours, has severe unrelieved pain, develops a high temperature, or feels faint or confused; a follow-up pregnancy test at 3 weeks confirms completion.', 'Discussions about contraception and STI screening should be offered as part of holistic care, and long-acting reversible contraceptives (LARC) are particularly worth highlighting for young people who may find daily pill adherence challenging.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  23,
  'Obesity in a Child',
  'Endocrine & Nephrology',
  'Video consultation',
  false,
  'Oliver Brennan',
  '11-year-old male',
  ARRAY[]::text[],
  ARRAY['No regular medication', 'No known drug allergies'],
  'Seen 3 days ago by a Healthcare Assistant
Presenting complaint: Mother brought Oliver in for a routine weight check.
Examination findings: BMI: 31 — this plots between the 98th and 99.6th centile on the UK 1990 growth chart.
Plan: Mother advised to book a follow-up appointment with a GP to discuss concerns about Oliver''s weight.',
  'Mother has booked a routine appointment to discuss concerns about her son''s weight.',
  'Hello, I''m calling about my son Oliver. We saw the nurse a few days ago about his weight, and she suggested I speak to a GP about it.',
  'I''ve noticed he''s been putting on quite a lot of weight over the past few months and it''s becoming a real worry.',
  ARRAY['Mother believes the weight gain is largely due to an unhealthy diet: Oliver regularly has fizzy drinks, enjoys fast food including McDonald''s, and snacks on chocolate in the evenings. She feels partly responsible, as a new job has made home life very busy and left little time for cooking, so meals have become more convenience-based. However, she has recently started ordering balanced meal kits through Hello Fresh in an effort to improve the family''s eating habits.', 'She is worried not just about his physical health but also the emotional impact — Oliver has been bullied at school because of his weight and has become reluctant to attend. His general mood seems okay, but he has become more withdrawn and less socially engaged than before.', 'She is hoping the doctor might prescribe something to help with weight loss. She uses Orlistat herself and has found it effective, and wonders whether something similar could help Oliver.'],
  'The whole family has a history of being overweight — mother is overweight, Oliver''s 20-year-old brother is overweight, and so is his father. They all live together. Oliver currently does no regular exercise and spends a lot of time on his games console. He says he enjoys swimming but has stopped going because he feels self-conscious. Mother has tried cutting down on fizzy drinks, but his weight continues to be a concern.',
  'Mother believes Oliver''s weight gain is largely due to an unhealthy diet — he regularly has fizzy drinks, fast food, and evening snacks. She feels partly responsible due to a busy new job leaving less time for cooking, though she has started ordering balanced meal kits to try to improve things.',
  'She is worried about his physical health but also the emotional toll — he has been bullied at school because of his weight, which has made him reluctant to attend, and he seems more withdrawn than before.',
  'She is hoping the doctor can prescribe something to help him lose weight. She uses Orlistat herself and wonders whether something similar might be suitable for Oliver.',
  ARRAY[]::text[],
  NULL,
  'Decline to answer questions not covered in the information provided above. Accept all advice and management offered.',
  ARRAY['Explore the reason for seeking help at this point in time — what has prompted the concern now?', 'Ask about the psychological impact of the weight gain, including any experiences of bullying or teasing, changes in self-esteem or confidence, signs of low mood, reduced school attendance or academic engagement, and withdrawal from friendships or social activities', 'Ask about potential physical effects of excess weight, such as joint or back pain, snoring or suspected sleep apnoea, breathing difficulties, or reduced ability to exercise', 'Explore contributing lifestyle factors: sedentary behaviours such as screen time, diet patterns including frequency of takeaways and sugary drinks, level and type of physical activity, family history and home environment (studies show obese children are more likely to have obese parents, suggesting a genetic link), and sleep habits (sleep deprivation is recognised as a contributing factor to weight gain in children)', 'Screen for symptoms of possible underlying medical causes — hypothyroidism (constipation, feeling cold, dry skin), growth hormone deficiency (weight gain with signs of delayed puberty), and in females, polycystic ovarian syndrome (irregular periods, excessive hair growth)', 'Ask what has already been tried to manage the weight and whether any approaches have been successful', 'Ask about any over-the-counter medications or other medical conditions', 'Take a brief developmental history: pregnancy and birth history, immunisation history, nutrition, and developmental milestones', 'Make a diagnosis of childhood obesity'],
  ARRAY['Explain to the mother that Orlistat is not recommended for children, as it can interfere with the absorption of fat-soluble vitamins A, D, E, and K, which are essential for a growing child''s development. It can also cause gastrointestinal side effects including oily stools, flatulence, and faecal urgency, which may be particularly distressing and difficult for a child to tolerate.', 'Offer a face-to-face appointment to measure blood pressure and arrange blood tests including thyroid function, HbA1c, and a fasting lipid profile, to screen for any underlying conditions or complications related to his weight.', 'Provide practical dietary advice: encourage plenty of fruit and vegetables, healthy snacks, and balanced meals. Reassure the mother that carbohydrates do not need to be eliminated entirely, but that choosing wholegrains and minimising processed foods is helpful. A food diary can be a useful starting point, and referral to a dietitian can be offered for more tailored support.', 'Recommend regular physical activity — children should aim for at least 60 minutes of moderate-intensity exercise each day. This could include walking, cycling, dancing, or taking part in sports. Reducing screen time and time spent on video games can also make a meaningful difference. It is important to explore activities that Oliver actually enjoys, so that exercise becomes an achievable and enjoyable part of his routine.', 'Consider referral to a local family wellbeing or lifestyle service, which can support the whole household with practical guidance on nutrition, shopping, meal planning, and physical activity tailored to the family''s needs. Note that while family-based programmes have traditionally been recommended, recent evidence suggests their effectiveness can vary, so support should be individually tailored.', 'Encourage the mother to contact the school regarding the bullying, to ensure Oliver receives emotional support and any impact on his attendance is addressed. Suggest the school counsellor as a first point of contact, and offer a referral for CBT (cognitive behavioural therapy) if further support is needed to help Oliver manage the emotional effects of bullying and concerns about his weight.', 'Arrange a follow-up appointment in 4 weeks to review progress, offer encouragement, and adjust the management plan as needed.'],
  'Thank you so much for getting in touch today and for sharing your concerns about Oliver — it''s clear how much you care about his health and wellbeing, and taking this step to speak with us is really the right thing to do.

I''ve had a look at the results from his recent weight check with the healthcare assistant. When we plot his BMI of 31 onto the growth chart we use for children, it falls between the 98th and 99.6th centile for his age. That means his weight is higher than we would expect, and it does fall into the category of obesity for a child his age. I know that''s not easy to hear, but I want to reassure you that this is something we can absolutely work on together, and there is a lot of support available.

I understand you''ve been using Orlistat yourself and wondered whether it might help Oliver in the same way. It''s a completely reasonable thought, and I appreciate you raising it. However, Orlistat isn''t suitable for children. The reason is that it works by blocking the absorption of fat from food — but fat is also the way the body absorbs certain essential vitamins, particularly vitamins A, D, E, and K. These vitamins are especially important during childhood for healthy bone development, immune function, and growth, so blocking their absorption at this stage could cause real harm. Orlistat can also cause some uncomfortable side effects such as oily stools, wind, and an urgent need to go to the toilet, which can be quite distressing for an 11-year-old. So while it works well for adults in the right circumstances, it''s not the right option here.

What we can do is focus on some practical and achievable changes that will make a real difference over time. In terms of diet, the good news is that Oliver doesn''t need to follow a strict or complicated plan. Encouraging more fruit and vegetables, choosing wholegrain options over processed foods, cutting back on sugary drinks, and reducing evening snacking are all really positive steps. The meal kits you''ve been trying sound like a great idea — getting involved in preparing food can also help children develop a healthier relationship with eating. A referral to a dietitian might also be helpful if you''d like more personalised guidance.

When it comes to physical activity, the aim for children Oliver''s age is around 60 minutes of moderate exercise each day. It doesn''t have to be structured sport — walking, cycling, dancing, or even playing active games all count. You mentioned he likes swimming, so that could be worth revisiting when he feels more confident. Finding something he genuinely enjoys is key, because it''s much easier to keep going with activities that feel fun rather than like a chore. Reducing the time spent on screens and gaming can also make a noticeable difference.

I also want to acknowledge what you said about the bullying at school — that must be very hard for Oliver, and for you as his mum. The emotional side of this is just as important as the physical, and I don''t want us to overlook it. I would encourage you to contact the school if you haven''t already — schools are generally experienced at handling these situations sensitively, and they can put support in place through pastoral staff or a school counsellor. If Oliver seems to be struggling emotionally beyond what the school can offer, we can also arrange a referral for CBT — cognitive behavioural therapy — which is a talking therapy that can help children build resilience and develop healthier ways of thinking about themselves and their situation.

I''d also like to arrange some blood tests — including thyroid function, a blood sugar check, and a lipid profile — just to make sure there are no underlying medical conditions contributing to his weight, and to check whether any health complications have started to develop. We''ll do this at a face-to-face appointment where we can also check his blood pressure properly.

Let''s plan to catch up in four weeks to see how things are going. We''re very much in this together, and I want to make sure Oliver and your whole family feel supported every step of the way.',
  ARRAY['Childhood obesity is defined using UK 1990 BMI centile charts; a BMI at or above the 98th centile for age and sex indicates obesity in children.', 'Orlistat is not recommended for children under 12 and should only be considered in adolescents over 12 under specialist supervision after lifestyle interventions have been trialled; it impairs absorption of fat-soluble vitamins A, D, E, and K and commonly causes gastrointestinal side effects.', 'Assessment should be holistic and explore diet, physical activity, screen time, sleep, family history and environment, psychological impact (including bullying and low self-esteem), and any symptoms suggesting an underlying medical cause such as hypothyroidism or growth hormone deficiency.', 'Blood tests including thyroid function, HbA1c, and fasting lipids should be arranged to screen for underlying causes and complications of obesity; blood pressure should be checked at a face-to-face appointment.', 'Children should aim for at least 60 minutes of moderate-intensity physical activity daily; dietary advice should focus on increasing fruit, vegetables, and wholegrains while reducing sugary drinks and processed snacks — carbohydrates do not need to be eliminated entirely.', 'The emotional impact of childhood obesity, including bullying and social withdrawal, must be actively addressed; school liaison, pastoral support, and referral for CBT should be considered where appropriate.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  24,
  'Middle-Aged Man With Chronic Cough',
  'Respiratory',
  'Video consultation',
  false,
  'Graham Hallett',
  '44-year-old male',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication', 'No known drug allergies'],
  'Seen by a Nurse Practitioner 5 weeks ago
Presenting complaint: Persistent dry cough lasting 3 weeks.
Examination findings:
- Chest clear on auscultation
- Oxygen saturation: 98% on room air
- Respiratory rate: 18 breaths per minute
- Blood pressure: 145/90 mmHg
Impression: Likely chest infection.
Plan: Amoxicillin 500mg three times daily for 5 days (oral). Safety netting and worsening advice provided.',
  'Patient has booked an appointment to discuss ongoing concerns about a persistent cough that has not resolved despite a course of antibiotics.',
  'Doctor, I''ve had this cough for a while now — it''s been going on for about 8 weeks and just doesn''t seem to be getting any better. I thought the antibiotics would clear it up, but it''s still there and it''s really bothering me.',
  'The cough is dry and happens throughout the day, but it seems worse at night and sometimes after eating. I haven''t had any shortness of breath, chest pain, fever, or palpitations.',
  ARRAY['Occasionally notices an unpleasant sour taste in his mouth when lying down at night', 'Sometimes experiences heartburn, though he did not think it was significant', 'Feels tired most of the time, but attributes this to stress from a new senior role at work'],
  'Graham is a former smoker — he smoked 20 cigarettes a day for 15 years but stopped 3 years ago. He lives with his wife and two children. He works as a regional manager for a logistics company. There is no family history of cancer or significant illness.',
  'He thinks this is probably a stubborn chest infection that has not fully cleared up.',
  'The ongoing cough is causing him significant distress and embarrassment, particularly in professional settings.',
  'He is hoping the doctor will prescribe another course of antibiotics.',
  ARRAY[]::text[],
  NULL,
  'Decline to answer questions not covered in the information provided above. Accept all advice and management offered.',
  ARRAY['Ask about the onset and total duration of the cough', 'Ask whether the cough is productive (bringing up mucus) or dry — this can help distinguish infective causes from non-infective causes such as reflux or post-nasal drip', 'Ask about haemoptysis (coughing up blood) — a red flag for lung malignancy, TB, or severe infection', 'Ask whether there is any wheeze or noisy breathing (to assess for asthma, COPD, or other airways disease)', 'Ask about associated shortness of breath, chest pain, or palpitations (to assess for cardiac or pulmonary involvement)', 'Ask whether the cough worsens at night or after meals (suggestive of gastro-oesophageal reflux disease, though asthma-type cough can also worsen at night)', 'Ask about reflux symptoms: heartburn, epigastric discomfort, feeling full or bloated, nausea, vomiting, or a sour taste in the mouth (note that a sour taste can be a feature of both acid reflux and post-nasal drip)', 'Ask about upper respiratory symptoms: nasal congestion, throat clearing, or a sensation of mucus dripping down the back of the throat (post-nasal drip)', 'Ask about voice changes or hoarseness (associated with laryngopharyngeal reflux, malignancy, or chronic irritation)', 'Ask about red flag symptoms: unexplained weight loss, night sweats, fatigue, or loss of appetite (to screen for underlying malignancy or systemic illness)', 'Ask about current and past smoking history', 'Ask about occupation and any potential exposure to dust, fumes, or chemicals at work (to rule out occupational lung disease)', 'Ask about a personal or family history of allergies, asthma, or atopic conditions', 'Ask about over-the-counter medications and any recently started or changed prescribed medications — particularly ACE inhibitors, which are a well-recognised cause of persistent dry cough', 'Ask about family history of lung cancer or atopic disease', 'Make a working diagnosis of chronic cough, most likely triggered by gastro-oesophageal reflux, while explaining the need to rule out more serious underlying causes such as malignancy'],
  ARRAY['Offer a face-to-face appointment to examine the chest, abdomen, and throat in more detail.', 'Arrange a chest X-ray within 2 weeks, given the persistent cough, unexplained fatigue, and significant smoking history.', 'Start a 4-week trial of omeprazole 20mg once daily, as the symptom pattern is consistent with acid reflux contributing to the cough.', 'Advise avoiding known reflux triggers such as spicy foods, coffee, fatty meals, and alcohol.', 'Advise not eating within 3–4 hours before going to bed, to help reduce nocturnal reflux symptoms.', 'Recommend stress management strategies such as mindfulness apps, practising breathing exercises, or trying yoga, as stress can exacerbate physical symptoms.', 'Note that his blood pressure reading from the previous consultation was mildly elevated at 145/90 mmHg; advise booking a follow-up to monitor this, and recheck it at the face-to-face appointment.', 'Provide safety netting advice: if he develops any new or worsening symptoms such as shortness of breath, coughing up blood, unexplained weight loss, chest pain, or palpitations, he should seek medical attention promptly.'],
  'Thank you for joining the video call today, Graham, and for taking the time to talk me through everything. I can completely understand why you''re frustrated — eight weeks is a long time to be dealing with a cough, and it''s natural to want answers.

Let me reassure you about something first: based on what you''ve described and the fact that you''ve already completed a course of antibiotics, I don''t think this is still an active infection. Infections that require antibiotics usually come hand in hand with other symptoms — things like a fever, feeling run down and unwell, chest pain when breathing, or coughing up discoloured mucus. You haven''t had any of those, and when you were examined a few weeks ago your chest was completely clear. So another course of antibiotics is unlikely to be the answer here.

What I do think is very possibly going on is something called acid reflux, or gastro-oesophageal reflux disease. This is where acid from the stomach travels upwards into the oesophagus and throat, and it can irritate the airway and trigger a cough. You mentioned having heartburn and occasionally noticing a sour taste in your mouth when you''re lying down — and importantly, your cough tends to be worse at night and after eating. All of those details fit together very well with a reflux picture.

However, because your cough has been going on for more than eight weeks and you''ve also been feeling persistently tired — and given that you have a significant past smoking history — I think it would be irresponsible of me not to arrange some further investigations to make sure we''re not missing anything more serious. I''d like to arrange a chest X-ray within the next two weeks. I want to be straightforward with you: this is partly to rule out lung cancer. I''m not saying I think that''s what this is — at this stage it''s much more likely to be reflux — but given your smoking history and the length of time this has been going on, it would be the right thing to do. Most of the time, chest X-rays like this come back clear, and that in itself is really reassuring.

I''d also like to bring you in for a face-to-face appointment so I can listen to your chest again, check your abdomen, and have a look at your throat. This will give us a much fuller picture.

In the meantime, I''d like to start you on a medication called omeprazole — 20mg once a day. This reduces the amount of acid your stomach produces and should help settle the reflux. We''ll give it a four-week trial and see how you respond. Alongside the medication, there are some straightforward lifestyle changes that can make a real difference: avoiding spicy foods, coffee, and large meals, and trying not to eat for at least three to four hours before you go to bed, so your stomach has time to empty before you lie down.

You mentioned that work has been quite stressful lately with the new role, and I don''t want to dismiss that. Stress doesn''t directly cause reflux, but it can certainly make physical symptoms feel worse. Some people find mindfulness or breathing exercises genuinely helpful for managing stress — there are apps such as Headspace that can be a good starting point, and things like yoga or even a short walk at lunchtime can make a real difference.

One more thing I want to mention: when you were seen five weeks ago, your blood pressure was recorded at 145/90 mmHg, which is slightly above the normal range. That''s something we should keep an eye on, so when you come in for the face-to-face appointment we will recheck it and go from there.

And finally, if at any point before we next speak you develop anything new or more worrying — such as coughing up blood, chest pain, breathlessness, or if you notice you''re losing weight without trying — please don''t wait for your appointment. Contact us straight away or go to A&E if needed. I don''t expect that to happen, but I want you to know what to look out for.',
  ARRAY['Cough lasting more than 8 weeks is classified as chronic; a structured history should cover infective, reflux, post-nasal drip, and respiratory causes, as well as red flag features that may indicate malignancy.', 'A chest X-ray within 2 weeks is indicated for patients aged 40 or over with a history of smoking who present with a persistent unexplained cough; fatigue in this context should not be dismissed as it may represent a red flag symptom rather than stress alone.', 'Gastro-oesophageal reflux disease (GORD) is a common cause of chronic dry cough; key features include nocturnal and post-prandial worsening, heartburn, and a sour taste in the mouth. First-line treatment is omeprazole 20mg once daily for a 4-week trial.', 'ACE inhibitors are a well-recognised cause of persistent dry cough and should always be asked about in the medication history, even if the patient does not volunteer this information.', 'Lifestyle advice for reflux includes avoiding known dietary triggers (spicy food, coffee, fatty meals), not eating within 3–4 hours of bedtime, and stress management strategies such as mindfulness or yoga.', 'Mildly elevated blood pressure noted at a previous consultation (145/90 mmHg) should be flagged, rechecked at the face-to-face appointment, and monitored appropriately — it should not be overlooked in the context of another presenting complaint.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  25,
  'Duty of Candour',
  'Ethics',
  'Telephone Consultation',
  false,
  'Sandra',
  '32-year-old female',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'A practice nurse is calling to seek advice after realising she administered the wrong injection to a patient.',
  'Hi doctor, I''ve made a terrible mistake with a patient and I really need your advice on what to do.',
  'You were rushing through a busy clinic when you accidentally gave a patient a vitamin B12 injection instead of the pneumococcal vaccine they were due. You only realised the error after the patient had left the building.',
  ARRAY[
    'You believe the error happened because you were overwhelmed and not following the correct checking procedure at the time.',
    'You are terrified that you might lose your job as a result of this mistake.',
    'You are hoping the GP will tell you what to do next and offer support throughout the process. You are open to all suggestions and support offered.'
  ],
  'You are a practice nurse working at the surgery. You have been under significant personal and professional stress recently, including financial difficulties related to your mortgage.',
  'You believe the error occurred because you were feeling overwhelmed and did not follow the proper checking procedure.',
  'You are terrified you might lose your job over this mistake.',
  'You are hoping the GP will advise you on what to do next and support you through the process. You are open to any suggestions or support offered.',
  ARRAY[]::text[],
  NULL,
  'Decline to answer any questions not covered in the details provided above. Accept all advice offered.',
  ARRAY[
    'Ask how the incident occurred — to understand the sequence of events and whether any safety steps were missed',
    'Ask how she became aware of the mistake — to assess her level of insight, whether the error was self-identified or flagged by someone else, and to understand her accountability in clinical practice',
    'Ask whether the patient had any reaction after receiving the wrong injection — to evaluate immediate clinical risk and patient safety',
    'Ask whether she has informed the patient yet — to assess her understanding of the duty of candour and professional responsibilities',
    'Ask if the patient has any known allergies — to identify potential complications or risks arising from the incorrect medication',
    'Ask what she thinks contributed to the error — to explore factors such as fatigue, cognitive overload, or a breach of protocol',
    'Ask what her main concerns are — to explore fears such as disciplinary action, harm to the patient, or job security',
    'Ask whether there is anything else she was hoping to get from this conversation — to clarify expectations and support needs',
    'Ask how she usually verifies medications before administration — to understand her normal safety practices and identify any lapses',
    'Ask whether any other medication errors occurred during that same session — to ensure other patients are safe and rule out a wider pattern or systemic problem',
    'Ask how she is feeling about the incident — is she experiencing any emotional distress or guilt?',
    'Ask whether she has completed an incident report form',
    'Ask whether she is currently experiencing any personal or professional stressors — to identify external factors contributing to the error',
    'Ask what her thoughts are on how such errors can be prevented in future — to encourage reflection and quality improvement',
    'Ask whether she feels she needs any support from colleagues or the wider team — to assess wellbeing and the need for a supportive workplace response'
  ],
  ARRAY[
    'Reassure Sandra that mistakes can and do happen in healthcare settings; what matters most is acknowledging them, taking responsibility, and learning from the experience to improve future safety.',
    'Acknowledge and commend her for recognising the error, and thank her for having the courage to come forward and speak up.',
    'Advise her to contact the patient as soon as possible to explain the mistake, discuss any potential consequences, and offer a sincere apology — in keeping with the duty of candour.',
    'Ensure the patient is offered appropriate follow-up care, including rebooking the pneumococcal vaccination with another clinician.',
    'Reassure Sandra that vitamin B12 injections are generally safe, but advise her to inform the patient of possible side effects from excess B12, such as mild diarrhoea, headache, or flushing, and to monitor accordingly.',
    'Ensure the incident is documented both in the patient''s medical record and in the practice''s clinical incident reporting system.',
    'Emphasise that the purpose of incident reporting is not to assign blame, but to allow the practice to reflect, learn, and prevent similar errors from occurring in the future.',
    'Reassure her that such incidents rarely lead to dismissal, especially when handled transparently; however, if she has concerns, she may contact her professional defence organisation, such as the RCN (Royal College of Nursing) or the MDU (Medical Defence Union).',
    'Advise that if she is feeling emotionally overwhelmed or burned out, she should consider taking time off work for the sake of her own wellbeing and for patient safety.',
    'Recommend the Headspace app as a resource that can support her with mindfulness and stress-reduction techniques.',
    'Suggest she makes an appointment to see her own GP if she is experiencing symptoms of anxiety, depression, or other mental health concerns.',
    'Let her know that the MoneyHelper service, provided through the NHS, offers free, impartial, and confidential financial advice — including help with mortgage difficulties.'
  ],
  'Thank you for calling, Sandra, and for having the courage to speak up straight away — that in itself takes real integrity, and it''s exactly the right thing to do.

I want to start by reassuring you that errors do happen in clinical practice, even when we care deeply about our patients and take our work seriously. What defines us as professionals is how we respond when they occur. The fact that you recognised the mistake and sought help immediately is a very positive sign.

To explain what happened in straightforward terms: your patient was due to receive the pneumococcal vaccine, but received a vitamin B12 injection instead. The good news is that vitamin B12 is a naturally occurring substance and is generally very well tolerated. There is no cause to expect serious harm, though it is possible your patient may experience a minor side effect such as a mild headache, some flushing, or loose stools. These would be temporary and should resolve without treatment.

In terms of what needs to happen next, I would encourage you to contact the patient as soon as possible today. You should explain clearly and honestly that an error occurred, what they received instead of what was planned, what the potential effects might be, and offer a sincere apology. This is in keeping with our professional duty of candour — both as an ethical obligation and a professional requirement. The patient also needs to be rebooked for the pneumococcal vaccine they were originally due.

The incident will need to be documented in the patient''s medical record and recorded through the practice''s clinical incident reporting system. I want to emphasise that this process is not about blame — it is about creating a safe environment where errors can be examined, understood, and used to improve systems and prevent future mistakes.

Regarding any concern about your job, I want to be honest with you: incidents of this nature are handled seriously but do not typically lead to dismissal, particularly when they are disclosed openly and dealt with professionally. If you are worried about your position, I would encourage you to get in touch with your professional defence organisation — either the RCN or the MDU — who can offer confidential guidance and support.

On a personal note, it sounds as though you have been under considerable strain recently. If you are struggling emotionally, please do consider speaking to your own GP. There are also some useful resources — the Headspace app can be helpful for managing stress day to day, and if you are experiencing financial pressures around your mortgage, the MoneyHelper service offers free and confidential financial advice through the NHS. You don''t have to manage all of this alone.',
  ARRAY[
    'The duty of candour requires healthcare professionals to be open and honest with patients when things go wrong — including offering a sincere apology and explaining what happened and what will be done next.',
    'Vitamin B12 is generally safe even when given inadvertently; however, the patient should be informed of possible temporary side effects such as flushing, headache, or mild diarrhoea, and rebooked for the intended pneumococcal vaccine.',
    'All clinical incidents must be documented in the patient record and reported through the practice''s incident reporting system — the purpose is learning and system improvement, not blame.',
    'Nurses and other healthcare professionals can seek confidential support from professional defence organisations such as the RCN or MDU when concerned about disciplinary consequences.',
    'GPs should explore contributing factors such as fatigue, workload pressure, and personal stressors when supporting a colleague following a clinical error, and signpost appropriate wellbeing resources including occupational health and the Headspace app.',
    'The MoneyHelper service provides free, impartial, confidential financial advice for NHS staff, including guidance on mortgage difficulties.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  26,
  'Mental Health Concerns in Military Veteran',
  'Mental Health',
  'Telephone Consultation',
  false,
  'Nathan Whitmore',
  '29-year-old male',
  ARRAY[]::text[],
  ARRAY['No known drug allergies'],
  'Patient booked a telephone appointment with the GP to discuss some concerns.',
  'A serving Royal Navy officer is calling to request sleeping tablets due to severe and worsening sleep problems.',
  'Hi doctor, I just can''t sleep anymore. It''s getting unbearable. Can I have a sleeping tablet, please?',
  'You returned from active duty in Afghanistan around 4 months ago, where your closest friend was killed in combat. Since then, you have been experiencing increasing psychological distress. You are having severe sleep difficulties, particularly over the last 2 months. You struggle to fall asleep and wake frequently with intense nightmares and flashbacks related to your experiences during the deployment. These symptoms are affecting your ability to function both at work and in your personal life.',
  ARRAY[
    'You feel constantly on edge, hypervigilant, and emotionally numb. You find it very difficult to connect with others, particularly your partner, and feel guilty for not being able to show her the affection you used to. Your mood has been persistently low because of everything you have been through.',
    'Due to your deteriorating mental state, you have voluntarily handed in your firearm, as you no longer feel mentally fit to handle it. You do not have any suicidal thoughts.'
  ],
  'You do not smoke, do not drink alcohol, and do not use recreational drugs. You drive regularly and do not experience drowsiness while driving. You live with your partner, who has been very supportive throughout.',
  'You suspect these problems are connected to your time on active duty and what you witnessed out there.',
  'You feel distraught and are struggling to carry out your duties in the Royal Navy due to poor sleep and low mood.',
  'You are hoping the GP can prescribe sleeping tablets to help you get some rest.',
  ARRAY[]::text[],
  NULL,
  'Decline to answer any questions not covered in the details provided above. Accept anything offered by the doctor.',
  ARRAY[
    'Ask about his current sleeping pattern — to understand the nature and severity of his sleep difficulties',
    'Ask whether he has difficulty falling asleep, staying asleep, or both — to characterise his insomnia',
    'Ask about daytime sleepiness or fatigue — to assess the functional impact of his sleep problems',
    'Recognise that the symptoms described are suggestive of Post-Traumatic Stress Disorder (PTSD)',
    'Ask about any triggers or thoughts that prevent him from sleeping — to identify associations with trauma or anxiety',
    'Ask about flashbacks or intrusive thoughts related to the traumatic event',
    'Ask if he experiences nightmares linked to his time in combat',
    'Ask whether he avoids situations, places, or reminders connected to his traumatic experience',
    'Ask if he feels emotionally numb or detached from the people around him',
    'Ask about guilt or self-blame, particularly in relation to the death of his friend — to explore trauma-related beliefs',
    'Ask about his overall mood — to assess for comorbid depression',
    'Ask if he still has interest or pleasure in activities he used to enjoy',
    'Ask if he has experienced any suicidal thoughts or thoughts of self-harm',
    'Ask how these symptoms are affecting his life, including his work and relationships',
    'Ask if he drives and whether his sleep problems affect his ability to do so safely — for safety and DVLA implications',
    'Since he serves in the armed forces, ask if he currently has access to a firearm and whether he has voluntarily returned it — patients with mental health concerns should not have access to firearms, as this has legal and safeguarding implications',
    'Ask about smoking, alcohol, and recreational drug use',
    'Ask what strategies or remedies he has already tried to improve his sleep',
    'Arrive at a working diagnosis of Post-Traumatic Stress Disorder (PTSD)'
  ],
  ARRAY[
    'Offer screening using the Trauma Screening Questionnaire (TSQ) to support a working diagnosis of PTSD.',
    'Advise on sleep hygiene measures, including maintaining a comfortable sleep environment, going to bed only when sleepy, waking at the same time each day including weekends, doing relaxation exercises in the evening, avoiding screens before bed, and avoiding vigorous exercise close to bedtime while encouraging it earlier in the day.',
    'Offer a short course of zopiclone, prescribing 7 tablets to be taken on alternate nights over a two-week period. Explain that this is for short-term relief only and that prolonged use is not recommended due to the risk of dependence and tolerance.',
    'Inform him that zopiclone can cause dizziness, and if this occurs he should not drive.',
    'Refer him under the veterans'' priority scheme to a specialist for assessment and trauma-focused cognitive behavioural therapy (CBT).',
    'While awaiting specialist input, offer drug treatment if he is open to it, including an SSRI or venlafaxine.',
    'If medication is started, warn him about the possible risk of increased suicidal thoughts in the early phase of treatment. Arrange to review him in one week and continue with weekly reviews throughout the first month.',
    'Offer support with work-related difficulties, which may include providing a fit note outlining amended duties, reduced hours, or recommending a period of sick leave if needed.',
    'Provide the contact number for the local crisis team in case he experiences a deterioration in his mental health or needs urgent support.',
    'Inform him about veteran-specific support services, including Combat Stress and Veterans UK, which can provide practical and emotional assistance.',
    'Safety net by asking about suicidal thoughts before ending the consultation, and arrange follow-up in 1–2 weeks to monitor progress and review ongoing needs.'
  ],
  'Thank you so much for calling today, and for trusting me with what you''ve been going through. I can only imagine how exhausting and distressing this period has been for you, and I want you to know that what you''re experiencing makes complete sense given everything that happened in Afghanistan.

Nathan, based on everything you''ve shared with me — the nightmares, the flashbacks, feeling constantly on edge, the emotional numbness, and the way your sleep has completely broken down since returning from duty — I believe you may be experiencing a condition called Post-Traumatic Stress Disorder, which we often refer to as PTSD. This is a recognised mental health condition that can develop after living through or witnessing deeply traumatic events, such as combat and the loss of someone close to you. These are not signs of weakness — they are the mind''s natural response to an extraordinary and terrible experience.

I want to reassure you that PTSD is a treatable condition, and seeking help at this stage is exactly the right thing to do.

In terms of your sleep, I''d like to start with some sleep hygiene strategies — practical steps such as keeping a regular wake time, avoiding screens before bed, winding down with relaxation exercises in the evening, and only going to bed when you actually feel sleepy. These can help retrain your sleep patterns over time. If your sleep remains unmanageable despite these measures, I can offer a short course of zopiclone — a sleeping tablet — for up to 7 tablets, taken on alternate nights over two weeks. This is a short-term measure only, as zopiclone can become habit-forming if used regularly, and may actually worsen nightmares with prolonged use. Please also be aware that it can cause dizziness, so you should not drive if you feel this effect.

I''d also like to refer you to a specialist mental health service through the veterans'' priority pathway, which means you are likely to be seen more quickly than through the standard route. The main treatment offered for PTSD is Trauma-Focused Cognitive Behavioural Therapy — a structured talking therapy with strong evidence behind it. Eye Movement Desensitisation and Reprocessing, known as EMDR, is another effective option your specialist may discuss with you.

While we wait for that referral, it may be worth considering an antidepressant to help stabilise your mood and reduce anxiety. Options include an SSRI or venlafaxine. If we go down that route, I want to be transparent with you: there is a small risk of increased suicidal thoughts in the early weeks of starting these medications, particularly in people under 30. Because of this, I would want to review you in one week after starting, and then weekly throughout the first month to make sure you are safe and tolerating it well.

I can also provide a supporting letter for your commanding officer to help facilitate adjustments to your duties, or to support some time off if that would help. You should not feel pressured to perform at full capacity while you are recovering. Finally, I would strongly encourage you to explore veteran-specific support services such as Combat Stress and Veterans UK — both organisations offer tailored emotional and practical support for people with exactly your kind of experience. You are not alone in this.',
  ARRAY[
    'PTSD should be considered in anyone presenting with sleep disturbance, flashbacks, emotional numbing, hypervigilance, or avoidance behaviours following a traumatic event — it may not be volunteered by the patient without sensitive, structured questioning.',
    'Armed forces veterans with service-related PTSD are eligible for expedited referral to secondary care under the veterans'' priority scheme; specialist treatment typically involves trauma-focused CBT or EMDR.',
    'Zopiclone may be offered short-term for sleep disturbance in PTSD (maximum 7 tablets, on alternate nights); long-term use risks dependence, tolerance, and worsening of nightmares — it should be stopped immediately if nightmares worsen.',
    'SSRIs or venlafaxine may be offered for PTSD in adults; patients under 30 have an increased risk of suicidal ideation in the early treatment phase and must be reviewed within one week of starting medication, then weekly for the first month.',
    'Patients with mental health concerns who have access to firearms must be sensitively asked whether they still hold weapons; if they do, they should be encouraged to contact the police about their licence, and military personnel should inform their superior officers.',
    'Veteran-specific services including Combat Stress and Veterans UK provide tailored emotional and practical support and should be routinely signposted in consultations with serving or former military personnel.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  27,
  'Painful Swollen Toe in Diabetic Patient',
  'General Practice',
  'Telephone Consultation',
  false,
  'Rachel Hobbs',
  '41-year-old female',
  ARRAY[]::text[],
  ARRAY['Metformin 1g BD', 'Sitagliptin 100mg OD', 'Sertraline 100mg OD', 'No known drug allergies'],
  'Seen 3 months ago by the Diabetic Nurse Practitioner for a routine diabetes review. Blood tests showed HbA1c level of 52 mmol/mol. Examination: BP 130/80 mmHg. Feet check satisfactory. Plan: continue current medication, reinforce lifestyle measures, and review in 3 months.',
  'A patient with type 2 diabetes and depression is calling about swelling and pain around her left big toenail that has been worsening over the past five days.',
  'Hi doctor, I''ve had some swelling and pain around my left big toenail for about five days now and it''s getting worse. I''m quite worried — if asked what you are worried about, reply: you''re worried because you have diabetes and you remember being told that foot problems can become really serious, and it''s also starting to affect your work as a delivery driver.',
  '',
  ARRAY[
    'The swelling is painful and appears to be spreading slightly towards the tip of the foot. This is a new symptom and you have never experienced anything like this before.',
    'You accidentally knocked your toe against a door frame at home around five days ago.',
    'You have no other associated symptoms — no fever, no discharge, and no other trauma beyond the knock.',
    'Your blood sugar control has not been great recently, but you are now actively trying to improve your diet.'
  ],
  'You do not smoke or drink alcohol. You live with your partner and work as a delivery driver. The foot problem is making it increasingly difficult for you to walk and carry out your deliveries.',
  'You wonder whether this might be gout, though you are not entirely sure.',
  'You work as a delivery driver and the pain is stopping you from walking properly and doing your job. You are also worried because you are diabetic and you know that foot problems can become serious.',
  'You want the doctor to explain what is going on and to offer some guidance or treatment. You cannot attend an in-person appointment because you are about to leave for the airport — you have a flight to Portugal in three hours and will be away for two weeks. You are open to any suggestions or safety-netting advice the doctor offers.',
  ARRAY[]::text[],
  NULL,
  'Decline to answer any questions not covered in the details provided above. Accept any suggestions offered by the doctor.',
  ARRAY[
    'Ask about the exact location of the swelling — whether it is around the toenail itself or involves the whole toe joint — to help differentiate between paronychia and gout; paronychia affects the nail fold, whereas gout typically involves the joint',
    'Ask about the presence and extent of redness — to assess for localised infection or inflammation',
    'Ask about the nature and severity of the pain — to assess functional impact and the likelihood of infection',
    'Ask if there is any pus or discharge from the area — to identify signs of bacterial infection such as paronychia or abscess',
    'Ask if she has had any fever or systemic symptoms',
    'Ask if she can move the toe joint — restricted movement may indicate joint involvement as seen in gout or septic arthritis',
    'Ask if any other toes are affected — to check for spreading infection or multi-joint involvement',
    'Ask about any recent trauma to the area — paronychia commonly follows minor injury to the nail fold',
    'Ask if this has happened before — recurrent episodes are more characteristic of gout than paronychia',
    'Ask how the symptoms are affecting her daily life and work — to assess functional impact',
    'Ask about diabetes control, recent HbA1c, and self-monitoring — poor glycaemic control increases the risk of foot infections and delays healing',
    'Ask about any family history of similar joint or foot problems — gout can run in families',
    'Ask about smoking, alcohol intake, and diet — modifiable risk factors for gout and delayed wound healing in people with diabetes',
    'Ask if she is up to date with her diabetic foot checks — important for risk assessment and prevention of complications',
    'Arrive at a working diagnosis of paronychia, based on localised swelling and redness around the nail fold, a history of minor trauma, and the absence of joint involvement'
  ],
  ARRAY[
    'Offer a face-to-face appointment to examine the affected foot. If the patient is unable to attend in person, ask her to send clear photographs of the foot to support remote assessment.',
    'Prescribe antibiotics based on clinical suspicion of paronychia. Confirm allergy status before prescribing. If no allergies are present, prescribe Flucloxacillin; if the patient is allergic to penicillin, consider Clarithromycin.',
    'Advise the patient to apply warm moist soaks to the affected toe for 10–15 minutes, three to four times daily, to help reduce pain and swelling.',
    'Instruct the patient to keep the area clean and dry to promote healing and reduce the risk of further infection. Advise her to avoid manipulating or injuring the nail.',
    'Offer NSAIDs or paracetamol for pain relief, depending on patient preference and any contraindications.',
    'If the infection is affecting her ability to work as a delivery driver, offer a fit note for time off or suggest amended duties where appropriate.',
    'Advise follow-up with the podiatrist for a comprehensive diabetic foot review once she returns from travel.',
    'Recommend she ensures she has valid travel insurance for her Portugal trip, particularly given her underlying diabetes and the current foot infection.',
    'Safety net: advise the patient to seek urgent medical attention if she experiences worsening symptoms, such as increasing pain, swelling, redness, pus, or fever. In the UK she can call 111 or contact the surgery; if abroad, she should seek help from local urgent medical services.'
  ],
  'Thank you for calling today, and I completely understand why you''re worried — especially with diabetes in the background and a trip coming up very soon.

You mentioned gout as a possibility, and that''s a really reasonable thought — gout can absolutely cause pain and swelling in the big toe. However, based on what you''ve described, Rachel, I think what you''re actually dealing with is something called paronychia. That''s an infection of the skin around the nail, rather than the joint itself. The clue here is that the swelling and redness are focused around the nail area rather than the joint, and importantly, you told me that you knocked your toe against a door frame around five days ago — that kind of minor knock can create a tiny break in the skin, which is all bacteria need to get in and start an infection.

In people with diabetes, infections in the feet do need to be taken seriously and treated promptly. Diabetes can affect the body''s ability to fight infection and can slow down healing, so early treatment really does make a difference.

Ideally I would want to examine the toe in person, or at least see a clear photograph. I understand that''s not possible today given your travel plans, so we''ll do our best remotely. Looking at your records, I can see you have no allergies to medication — is that still correct? If so, I''d like to prescribe a course of Flucloxacillin to treat the likely bacterial infection. You would take this four times a day for seven days, and it''s important to complete the full course even if the toe starts to feel better.

While you are away, please soak the toe in warm water for 10 to 15 minutes three or four times each day to help reduce the swelling and ease the discomfort. Keep the area clean and dry between soaks, and try not to knock or aggravate it. If things are not improving, or if you notice the redness spreading, the area becoming more swollen, any pus appearing, or if you develop a fever, please do not wait — seek medical attention locally wherever you are in Portugal. Most travel insurers can help you find local healthcare, which is another reason I would strongly encourage you to double-check your travel insurance covers your diabetes before you fly.

When you return in two weeks, I would like you to come in for a proper diabetic foot review with our podiatrist, just to make sure everything has healed properly. Have a good trip, and please don''t hesitate to contact local medical services if anything concerns you while you''re away.',
  ARRAY[
    'Paronychia presents with localised pain, swelling, and redness around the nail fold, often following minor trauma; it should be distinguished from gout, which typically involves the joint and presents with acute severe pain and swelling at the metatarsophalangeal joint.',
    'Patients with type 2 diabetes are at increased risk of foot infections, impaired healing, and complications — even minor foot injuries or infections require prompt assessment and early treatment.',
    'First-line antibiotic treatment for paronychia is Flucloxacillin; if the patient has a penicillin allergy, Clarithromycin is an appropriate alternative.',
    'When a face-to-face examination is not possible, requesting a clear photograph of the affected area can support remote clinical assessment and treatment decisions.',
    'Safety-netting in diabetic foot infections should include advice to seek urgent medical attention for worsening redness, spreading cellulitis, pus, or fever — and patients travelling abroad should be advised to ensure adequate travel insurance.',
    'Patients whose foot condition affects their ability to work should be offered a fit note, and a diabetic foot review with the podiatrist should be arranged following resolution of the acute infection.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  28,
  'Persistent Fatigue in Young Adult',
  'Elderly Medicine & Palliative Care',
  'Video Consultation',
  false,
  'Laura Simmons',
  '27-year-old female',
  ARRAY[]::text[],
  ARRAY['Salbutamol PRN', 'Clenil Modulite 200mcg, 2 puffs twice daily', 'No known drug allergies'],
  'Patient booked a routine video appointment to discuss some concerns.',
  'A young woman is attending a routine video appointment to discuss persistent and worsening tiredness that has been present for the past eight weeks.',
  'Hi doctor, I''ve been completely exhausted for weeks now and I just don''t seem to be getting any better. I''m not sure what''s going on but I''m really struggling.',
  'You have been feeling constantly tired for the past 8 weeks and it does not seem to be improving. The fatigue began suddenly around 10 weeks ago, shortly after a flu-like illness. Even minimal physical activity — whether at home or at work — makes the tiredness significantly worse.',
  ARRAY[
    'You often wake up feeling unrefreshed, flu-like, and stiff, despite sleeping for many hours. Your mood is fine — you have no symptoms of low mood or any other mental health concerns.'
  ],
  'You are a non-smoker and do not drink alcohol. You live with your fiancé and your two young children. You work as a financial analyst.',
  'You are not sure what is causing this but wonder whether a vitamin deficiency could be behind it.',
  'You are struggling to keep on top of things at work because of the constant tiredness.',
  'You would like help understanding what is causing your fatigue and some guidance on what to do next.',
  ARRAY[]::text[],
  NULL,
  'Decline to answer any questions not covered in the details provided above. Accept anything offered by the doctor.',
  ARRAY[
    'Ask about the onset, duration, and progression of the tiredness — when it started and whether it is getting better, worse, or staying the same',
    'Ask whether the tiredness is worsened by even light activity, and whether a flu-like illness preceded the start of symptoms — to explore possible post-viral fatigue',
    'Ask whether she wakes feeling refreshed and whether she is sleeping more than usual',
    'Ask about difficulty concentrating or experiencing "brain fog"',
    'Ask about generalised body aches or joint stiffness, particularly in the mornings',
    'Explore mood carefully, asking about low mood, loss of motivation, and screen for suicidal thoughts or self-harm — to exclude depression presenting as fatigue',
    'Ask about cold intolerance, skin changes, and constipation — to screen for hypothyroidism',
    'Ask about urinary frequency, thirst, and weight changes — to rule out diabetes',
    'Ask whether her menstrual periods are regular',
    'Ask about smoking, alcohol, and drug use',
    'Ask about her work and home situation and whether she feels able to cope with her day-to-day responsibilities',
    'Ask if she drives and whether her tiredness has affected her ability to drive safely — important for DVLA fitness-to-drive implications',
    'Arrive at a diagnosis of chronic fatigue syndrome'
  ],
  ARRAY[
    'Arrange a comprehensive set of blood tests to investigate underlying causes of fatigue. These should include: FBC, U&Es, ESR, CRP, TFTs, HbA1c, Vitamin D, B12, Ferritin, Folate, Coeliac Screen, and Creatine Kinase — to rule out neuromuscular causes. If the patient were over 60, consider adding a myeloma screen.',
    'Inform the patient that if all blood tests return normal, you would consider referral to a specialist chronic fatigue service, which offers energy management programmes and access to specialist physiotherapists to support with symptom management.',
    'Offer a fit note for time off work or suggest amended duties, depending on how the fatigue is affecting her daily functioning and personal preference.',
    'Recommend talking therapy, such as counselling or CBT, which may help improve coping strategies and overall functioning, even if her mood is currently stable.',
    'Introduce the concept of pacing — a self-management technique that involves recognising energy limits, breaking tasks down into manageable chunks, prioritising essential activities, and balancing rest and activity to avoid overexertion.',
    'Advise that while her mood appears stable at present, fatigue can sometimes begin to affect mental health over time, and she should seek help promptly if she notices changes in mood, motivation, or emotional wellbeing.',
    'Offer written information and leaflets about fatigue and chronic fatigue syndrome, and direct her to relevant support groups for peer support and further guidance.'
  ],
  'Thank you for coming today, and I''m really glad you booked this appointment — eight weeks of exhaustion that isn''t improving is absolutely something we need to take seriously and get to the bottom of.

You mentioned wondering whether a vitamin deficiency might be to blame, and that''s a really valid thought. We will definitely check for that. However, based on what you''ve described — the tiredness coming on suddenly after a flu-like illness, waking up feeling unrefreshed despite long hours of sleep, and the way even minor activity makes things worse — I think we may also need to consider something called chronic fatigue syndrome, sometimes abbreviated to CFS. This is a recognised long-term condition that often follows a viral illness and causes profound fatigue that does not improve with rest and can flare after activity.

I want to be clear that we are not jumping to any conclusions yet. First, Laura, I am going to arrange a full set of blood tests to make sure we are not missing a treatable underlying cause. These will check things like your thyroid function, iron levels, vitamin B12 and D, folate, blood sugar, inflammation markers, a coeliac screen, and a muscle enzyme called creatine kinase. These tests will help us rule out conditions such as anaemia, thyroid problems, diabetes, or vitamin deficiencies before we consider other explanations.

If all of those tests come back normal, I would want to refer you to a specialist chronic fatigue service. These are multidisciplinary teams that include clinical psychologists and specialist physiotherapists who can offer a structured programme of support. This includes something called energy management, which is about understanding your individual energy limits across all types of activity — not just physical, but mental, emotional, and social activity too.

A central part of energy management is a technique called pacing. Rather than pushing through on good days and crashing afterwards, pacing means planning your day carefully — breaking tasks into smaller chunks, building in regular rest periods, and gradually increasing what you do in a way your body can sustain. This approach helps avoid what we call post-exertional malaise, which is the significant worsening of symptoms that can follow overexertion.

Alongside this, I would encourage you to keep a symptom and activity diary. Writing down what you do and how you feel afterwards can help identify patterns, spot triggers, and give both you and any specialist a much clearer picture of what is happening.

In terms of work, if things are becoming unmanageable as a financial analyst at the moment, I can provide a fit note for amended duties or time off — whichever works best for your situation. I would also suggest considering a talking therapy such as CBT. This is not because your mood seems low right now, but because it can be very effective at helping people adjust to living with a long-term condition and finding different ways to cope. Finally, I will share some leaflets with you and point you toward some support groups, as many people find it helpful to connect with others who are going through something similar. Let''s take this one step at a time.',
  ARRAY[
    'Chronic fatigue syndrome (CFS) should be considered when fatigue has persisted for six or more weeks, is significantly impacting daily functioning, is unexplained by another condition, and is accompanied by post-exertional malaise and unrefreshing sleep.',
    'A comprehensive set of investigations must be completed before diagnosing CFS, including FBC, U&Es, ESR, CRP, TFTs, HbA1c, Vitamin D, B12, Ferritin, Folate, Coeliac Screen, and Creatine Kinase — to exclude other treatable causes of fatigue.',
    'If investigations are normal and symptoms have persisted for three months, referral to a specialist CFS service should be arranged per NICE guidelines; however, early referral may be appropriate if symptoms are severe or debilitating.',
    'Pacing is the cornerstone of self-management in CFS — patients should be guided to recognise their energy limits, break tasks into smaller steps, and avoid post-exertional malaise by not overexerting on good days.',
    'Unstructured exercise such as gym sessions or "pushing through" fatigue should not be recommended, as this may significantly worsen symptoms in CFS.',
    'Talking therapy such as CBT may be beneficial for coping with the emotional impact of CFS, even when mood appears stable; a fit note should be offered where work is being affected.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  29,
  'Microcytic Anaemia in an Older Adult',
  'Gastroenterology & Haematology',
  'Video Consultation',
  false,
  'Fatima Hussain',
  '69-year-old female',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'An older woman is attending a video appointment to receive and discuss the results of recent blood tests.',
  'Hello doctor. I''ve come to hear about my blood test results. I''m not quite sure what to expect.',
  'You came for blood tests as part of a routine check-up arranged by the practice.',
  ARRAY[]::text[],
  'You do not smoke or drink alcohol, and you live alone since your husband passed away from prostate cancer. Your diet has become less varied since his death — cooking was something you always did for him, and you have lost much of the motivation to prepare proper meals. You now mostly eat pre-packaged vegetarian ready meals from a local supermarket.',
  'You are not sure what to expect from the results and have no particular ideas about what might be wrong.',
  'You do not have any specific concerns but would like to understand what was found in your blood tests.',
  'You want to hear and understand the outcome of your blood tests and be given clear guidance on what happens next.',
  ARRAY[]::text[],
  NULL,
  'Decline to answer any questions not covered in the details provided above. Accept anything offered by the doctor.',
  ARRAY[
    'Ask why the patient originally had the blood tests done in the first place',
    'Ask if there has been any bleeding from any site: nosebleeds, bleeding gums, vomiting blood (haematemesis), coughing up blood (haemoptysis), unexplained bruising, blood in stools or black tarry stools, vaginal bleeding, or blood in the urine',
    'Ask about any new or recent heartburn symptoms — to help rule out a bleeding peptic ulcer or upper gastrointestinal malignancy',
    'Ask if the patient is experiencing abdominal pain, vomiting, or difficulty swallowing — bearing in mind the possibility of upper GI malignancy',
    'Screen for anaemia red flags using the "3 head" pattern: light-headedness, headaches, dizziness; and the "3 chest" pattern: shortness of breath, chest pain, palpitations',
    'Ask about other symptoms of anaemia: fatigue, dry skin, changes in hair or nails, mouth ulcers at the corners of the mouth, or generalised weakness',
    'Ask about systemic symptoms: unexplained weight loss, loss of appetite, or any recent changes in bowel habit including diarrhoea or constipation',
    'Ask about dietary habits, particularly iron intake, and any recent changes',
    'Ask about smoking and alcohol use',
    'Clarify her home situation and whether there have been any recent changes in social support or daily routine',
    'Ask if she has recently travelled abroad — to rule out parasitic infection or other travel-related nutritional deficiencies',
    'Explain that the blood test results indicate anaemia, most likely due to iron deficiency'
  ],
  ARRAY[
    'Arrange further investigations including ferritin and other haematinics (vitamin B12 and folate), a coeliac screen, urinalysis to check for blood in the urine, and a FIT test to look for hidden blood in the stool.',
    'Do not start iron tablets at this stage — iron deficiency anaemia must be confirmed before treatment is commenced.',
    'Inform the patient that if iron deficiency is confirmed, treatment will involve iron tablets, and she may be referred to a specialist for further testing, which could include gastroscopy with or without colonoscopy.',
    'Explain that iron tablets can sometimes cause constipation or dark stools, and if she experiences this or has difficulty tolerating them, she should let the practice know.',
    'Ask if she has considered ways to improve her diet, as this may be contributing to her anaemia. Advise her about iron-rich foods such as dark green vegetables, fortified breakfast cereals, apricots, and prunes.',
    'Consider referring the patient to a dietitian for personalised advice on nutrition and incorporating iron-rich foods, if she is open to it.',
    'Safety net: advise her to seek urgent medical attention if she notices any bleeding — such as in urine, in her stools, or from the gums — or if she develops new symptoms such as chest pain, shortness of breath, dizziness, light-headedness, or a racing heart.',
    'Arrange follow-up in 2–3 days to review the results of the additional tests and discuss next steps.'
  ],
  'Thank you for joining me today, and I''m glad we have the chance to go through these results together. I want to explain everything clearly so you leave this appointment with a good understanding of what we found and what we''ll do about it.

Your blood tests have shown that you have anaemia. Anaemia means that the number of red blood cells in your blood is lower than it should be, or that those cells are smaller than normal. Red blood cells are the cells that carry oxygen around your body, so when there are fewer of them, or they''re not functioning properly, it can cause symptoms such as tiredness, dizziness, breathlessness, or a general sense of feeling run down. The particular pattern in your results suggests this is most likely due to iron deficiency — in other words, your body may not have enough iron to make healthy red blood cells.

Now, I want to be careful here, Fatima — before we start any treatment, we need to do a little more detective work to understand why your iron might be low. It can sometimes be due to a lack of iron in the diet, but it can also occasionally be a sign that there is some bleeding going on somewhere in the body that we are not yet aware of. That''s why it''s important we investigate further rather than simply starting iron tablets right away.

I''d like to arrange a few additional tests. We will check your ferritin level — that''s a specific iron store marker — along with your vitamin B12 and folate levels. We''ll also do a coeliac screen, which checks whether your gut might be preventing you from absorbing iron properly. I''d like a urine test to check for any hidden blood, and a stool test called a FIT test, which can detect tiny traces of blood in the bowel that you wouldn''t be able to see with the naked eye.

Once those results are back — which I''d hope to have within a few days — we can talk again and plan the next steps. If the tests confirm iron deficiency, we will start you on iron tablets. I want to mention in advance that iron tablets can sometimes cause your stools to turn dark or cause a little constipation; that''s normal and not a cause for alarm, but please do let us know if you''re struggling to tolerate them.

I also noticed that you mentioned your diet has changed since losing your husband. I am truly sorry for your loss. It''s very understandable that cooking has felt harder without him. But improving your diet could genuinely help your iron levels — foods like dark green vegetables, fortified cereals, dried apricots, and prunes are all good sources of iron. I can refer you to our dietitian if you would like some personalised support with this, and that is absolutely something I''d encourage you to consider.

In the meantime, if you notice any signs of bleeding — blood in your urine or stools, bleeding gums, or if you develop chest pain, breathlessness, severe dizziness, or a very fast heartbeat — please do not wait; seek medical attention straight away.',
  ARRAY[
    'Microcytic anaemia in an older adult should prompt investigation for iron deficiency as the most likely cause, but crucially, the underlying reason for iron deficiency must be established before treatment is started — particularly to exclude gastrointestinal bleeding or malignancy.',
    'Initial investigations for suspected iron deficiency anaemia should include ferritin, vitamin B12, folate, a coeliac screen, urinalysis for blood, and a FIT test to detect occult gastrointestinal bleeding.',
    'Iron tablets should not be prescribed before iron deficiency is confirmed on blood tests; if initiated, patients should be warned about common side effects including dark stools and constipation.',
    'If iron deficiency anaemia is confirmed, specialist referral may be required for upper and/or lower GI endoscopy to identify a bleeding source, particularly in older patients where malignancy must be excluded.',
    'Dietary assessment is an important part of management — iron-rich foods including dark green vegetables, fortified cereals, apricots, and prunes should be recommended, with referral to a dietitian for patients who would benefit from personalised nutritional support.',
    'Safety-netting in iron deficiency anaemia should include clear instructions to seek urgent review if the patient develops new bleeding, worsening systemic symptoms, or cardiovascular symptoms such as chest pain, palpitations, or severe breathlessness.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  30,
  'Sudden-Onset Vertigo in Adult Female',
  'ENT & Eye',
  'Telephone Consultation',
  false,
  'Adaeze Okonkwo',
  '35-year-old female',
  ARRAY[]::text[],
  ARRAY['No known drug allergies'],
  'Patient has booked an urgent telephone consultation to discuss ongoing concerns.',
  'A young woman is calling urgently about episodes of dizziness that have been going on for the past four days and are not improving.',
  'Hi doctor, I''ve been feeling really dizzy for the past few days — it''s like I''m drunk or the room is spinning. It''s not getting better, and I just don''t know what''s going on.',
  '',
  ARRAY[
    'The dizziness feels like a spinning sensation — a true vertigo. The dizziness started spontaneously and is present constantly, even when your head is completely still. However, it is not as severe when you remain still; symptoms are worsened by head movement but not triggered by it — the dizziness is already ongoing, and changes in head position simply make it worse. You experienced flu-like symptoms approximately three days before the dizziness began. You feel nauseous and have vomited several times. You do not have any hearing loss or tinnitus.'
  ],
  'You are a single parent with two young children — one aged 9 months and one aged 2 and a half years — both of whom are fully dependent on you. You are finding it very difficult to care for them because of the constant dizziness. You moved to the UK from Nigeria around two years ago and do not have close family or social support nearby. You work as a software developer but are currently on maternity leave. You drive but are not currently driving because of the dizziness.',
  'You have never experienced this type of dizziness before and have no idea what might be causing it.',
  'You are worried that this could be a brain tumour, as your aunt had very similar symptoms and was later found to have one. You are also very worried about your ability to care for your children, especially as you have no one to help you at home.',
  'You would like the doctor to prescribe something to help with the dizziness and to arrange a brain scan to rule out anything serious.',
  ARRAY['If the doctor offers an anti-sickness medication, ask: "Will this affect my baby?"'],
  NULL,
  'Decline to answer any questions not covered in the details provided above. Accept anything offered by the doctor.',
  ARRAY[
    'Clarify the nature of the dizziness — whether it is a light-headed feeling or a spinning sensation — to differentiate between vertigo and presyncope',
    'Ask when the symptoms first started',
    'Ask whether the dizziness is constant or comes and goes — constant vertigo may suggest central causes such as stroke, or peripheral causes like vestibular neuronitis or labyrinthitis; intermittent vertigo is more typical of BPPV',
    'Ask how long each episode lasts — BPPV typically causes brief episodes lasting less than one minute, often triggered by specific head movements, with complete resolution between episodes',
    'Ask about associated nausea and vomiting',
    'Ask if the dizziness is made worse by head movement — in vestibular neuronitis and labyrinthitis, dizziness is already present but becomes worse with movement; in BPPV, dizziness is directly triggered by specific head movements and resolves between episodes',
    'Ask about tinnitus and hearing loss — hearing loss is a feature of Meniere''s disease and labyrinthitis',
    'Ask about any recent viral illness or flu-like symptoms — a common trigger for vestibular neuronitis and labyrinthitis',
    'Screen for neurological red flags: persistent headache, blurred vision, slurred speech, weakness or numbness anywhere in the body — to rule out central causes such as stroke, TIA, or a space-occupying lesion',
    'Ask whether she has experienced any falls as a result of the dizziness — to assess safety and risk of injury',
    'Explore how she is coping at home, particularly with caring for her young children',
    'Ask about lifestyle and social history, including smoking, alcohol intake, and her current circumstances',
    'Ask whether she drives or operates machinery, to assess risk related to safety and fitness to drive',
    'Arrive at a working diagnosis of vestibular neuronitis'
  ],
  ARRAY[
    'Offer a face-to-face appointment to examine the ears, check blood pressure, assess cranial and peripheral nerves, and perform the head impulse test — ensure there are no neck problems before performing this.',
    'Prescribe a short course of antiemetics such as cinnarizine or cyclizine to relieve nausea and vomiting.',
    'Advise that antiemetics should be used for a maximum of 3 days to avoid interfering with the body''s natural vestibular compensation.',
    'Explain that cyclizine and cinnarizine pass into breast milk in small amounts but are not known to be harmful.',
    'Advise her to monitor the baby for signs of unusual drowsiness or lethargy and to seek urgent medical advice if any concerns arise.',
    'Suggest expressing breast milk before starting the medication as a precaution if she is worried.',
    'Encourage adequate fluid intake to prevent dehydration and support recovery.',
    'Ask whether she has any friends, relatives, or neighbours who can assist with childcare while she is unwell.',
    'If no informal support is available, offer the option of arranging paid childminders or referring to the social prescriber to explore additional local support services.',
    'Advise avoiding driving or operating any machinery while experiencing dizziness.',
    'Offer a follow-up review in one week to monitor progress and recovery.',
    'Provide safety-netting advice: if symptoms worsen, persist beyond one week, or if new symptoms such as visual changes, weakness, or severe headache develop, she should seek urgent medical attention.'
  ],
  'Thank you for calling and for telling me everything that''s been going on. I can hear how frightening and exhausting this has been — especially with two young children relying entirely on you.

Based on everything you''ve described, Adaeze — the constant spinning sensation that came on suddenly, the fact that it started a few days after a flu-like illness, the nausea and vomiting, and the absence of any hearing loss or tinnitus — this sounds very much like a condition called vestibular neuronitis. What that means, in simple terms, is that the vestibular nerve — a nerve inside your inner ear that helps your brain understand where your body is in space and helps you balance — has become inflamed. This usually happens following a viral infection, which fits perfectly with the flu-like symptoms you had just before the dizziness began. The good news is that vestibular neuronitis is not dangerous, and in most cases it gets better on its own over the course of a few weeks, even though it can feel very debilitating in the meantime.

I completely understand why you''re worried about something more serious like a brain tumour, especially given what happened with your aunt. That''s an entirely natural fear. However, I want to reassure you that a brain tumour is very unlikely based on what you''ve described. When we think about more serious causes of dizziness, we look for additional warning signs such as persistent severe headaches, blurred vision, slurred speech, weakness on one side of the body, or numbness. You''ve not mentioned any of those things, which is genuinely reassuring.

That said, I would like to arrange for you to come in for a face-to-face appointment today so I can examine you properly. I would check your blood pressure, look inside your ears, test your eye movements, and carry out a simple head movement test called the head impulse test, which can help confirm whether this is coming from your inner ear. This will help us rule out anything else and make sure you''re getting the right care.

In the meantime, I would like to prescribe a short course of cyclizine to help with the nausea and dizziness. You would take this up to three times a day, and I want to emphasise that this should only be taken for a maximum of three days. That might sound strange, but it is actually important — your inner ear needs to go through a natural process of recalibration to recover, and if you rely on the medication for too long, it can slow that process down and prolong your symptoms overall.

You asked about your baby, and it''s a really important question. Cyclizine can pass into breast milk, but only in very small amounts, and it is not known to cause harm. That said, I would ask you to keep a close eye on your baby over the coming days — if you notice anything unusual such as excessive sleepiness or unusual lethargy, please get in touch or seek medical advice straight away. If it would give you peace of mind, you could express some breast milk before your first dose so you have a supply ready while you see how your baby responds.

Please make sure you are drinking plenty of fluids and resting as much as you possibly can — I know that is a big ask with a nine-month-old and a toddler at home. Is there anyone at all — a neighbour, a friend, anyone — who might be able to come and help you for a few days? If not, please let me know and I will look into whether we can connect you with our social prescriber, who can help explore local support options, including paid childminders or community services.

Finally, please do not drive while you are feeling like this. And if your symptoms worsen, if you develop a new headache, any weakness, blurred vision, or if you have not started to improve within a week, please seek urgent medical attention immediately.',
  ARRAY[
    'Vestibular neuronitis presents with sudden-onset, constant vertigo — worsened by head movement but not triggered by it — typically following a viral illness, without hearing loss or tinnitus; labyrinthitis is similar but includes hearing loss and/or tinnitus due to cochlear involvement.',
    'BPPV should be distinguished from vestibular neuronitis: in BPPV, dizziness is episodic and brief (under one minute), directly triggered by specific head movements, with complete resolution between episodes.',
    'Central causes of vertigo (stroke, TIA, space-occupying lesion) must be excluded by screening for neurological red flags: persistent headache, blurred vision, diplopia, dysarthria, dysphagia, facial numbness, or limb weakness.',
    'Antiemetics such as cyclizine or cinnarizine should be prescribed for a maximum of three days only — prolonged use interferes with the brain''s natural vestibular compensation and can delay recovery.',
    'Cyclizine and cinnarizine pass into breast milk in small amounts and are not known to be harmful; however, the baby should be monitored for drowsiness or lethargy, and expressing breast milk prior to the first dose can be offered as a precaution.',
    'Safeguarding and social considerations should be addressed in patients with young dependants and limited support networks — referral to a social prescriber or signposting to childcare support services may be appropriate.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  31,
  'Sick Note Request for Skin Condition',
  'General Practice',
  'Telephone consultation',
  false,
  'Laura Bennett',
  '31-year-old female',
  ARRAY[]::text[],
  ARRAY['Oilatum cream','Mometasone furoate 0.1% cream apply once daily (Acute prescription)','Symbicort 100/6 Turbohaler – 1 puff as needed, may be increased up to 6 puffs as required (maximum 8 puffs per day)'],
  'Letter from Bristol Royal Infirmary Dermatology Clinic 4 months ago
Laura Bennett | 31 years old | Female
Dear GP,
Thank you for your referral of this 31-year-old woman with a background history of eczema and asthma, referred with a query of contact dermatitis or occupationally related eczema. Ms Bennett works as a nail technician and beauty therapist, with intermittent exposure to substances such as hair products and nail polishes. She reports no history of immediate skin reactions to these products and is not currently experiencing an active eczema flare. Patch testing was performed prior to this appointment and revealed no positive reactions. I have advised her that her eczema is unlikely to be of occupational origin. She has been encouraged to maintain a symptom diary to help identify and avoid potential triggers. No further dermatology input is required at this stage and she has been discharged from our clinic.
Yours sincerely,
Dr Fatima Okonkwo, MBChB, FRCP
Consultant Dermatologist

Seen 2 weeks ago by Dr Sarah Brennan (General Practitioner).
Presenting complaint: Patient attended with a recurrent eczema flare affecting both upper limbs, particularly the elbows and hands. She identifies psychological stress as a possible trigger but felt her mood was currently stable and was not keen to explore emotional factors further, feeling confident in managing that herself.
Examination: Erythema and scaling noted over the elbows and dorsal aspect of both hands. All observations stable.
Impression: Eczema flare.
Plan: Mometasone furoate 0.1% cream prescribed for once daily use; liberal emollient use advised. Safety-netting and worsening advice given. Routine telephone appointment booked to discuss concerns.',
  'Patient is calling to request a sick note due to her eczema flare-ups making it difficult for her to continue working.',
  'Hi doctor, I was hoping you could help me with a sick note today.',
  'You work as a nail technician and beauty therapist at a salon. About 3 months ago, a client refused your service and made a hurtful remark about the appearance of your hands and elbows. This left you feeling self-conscious and embarrassed. Since then you have become increasingly anxious about your flares, and the condition has started to weigh on you emotionally. You find yourself constantly worrying about when the next flare will come — it is always in the back of your mind.

You are currently having a flare that is beginning to settle, but you still feel unable to face work and would like some time off to recover. You are not entirely sure what brings on your eczema flares, but you have noticed they tend to happen when you are under emotional pressure. Stress seems to be followed shortly after by a flare.

If asked about the frequency of your flares: you typically get around one flare every two months.

You have not identified any other specific triggers and do not believe your work directly causes your eczema. If asked about emollient use: you tend to use them consistently only during a flare, but stop once your skin settles.',
  ARRAY[]::text[],
  'Non-smoker. No alcohol or illicit drug use. You live with your partner, who has also made comments about your eczema. Your relationship has been affected — you tend to withdraw and pull back from intimacy and social situations during flares.',
  'You are not sure what is likely causing your flare.',
  'You are worried about having visible flares at work, as they affect your confidence and your ability to do your job well.',
  'You would like the GP to issue a sick note so you can take some time off while your eczema settles.',
  ARRAY[]::text[],
  NULL,
  'Decline any questions not covered by the scenario details above. Accept all advice and support offered by the doctor.',
  ARRAY[
    'Ask why she is requesting a sick note today',
    'Ask about her current eczema flare — whether the recent treatment has helped and whether symptoms have improved or worsened since her last consultation',
    'Ask whether she has any itching, cracking, weeping, or signs of skin infection such as fever or yellow crusting',
    'Ask about the pattern of her flares — how often they occur, how long they last, and whether any particular triggers have been identified (e.g. work-related irritants, soaps, detergents, food, stress, pets)',
    'Ask how frequently she uses her topical steroid and how often she applies emollients',
    'Ask how she manages her skin when not in a flare, including whether she uses emollients regularly as maintenance',
    'Ask about the emotional impact of her experience at work — how the client''s comment made her feel',
    'Ask about her mood — whether she feels low, whether she still enjoys activities she used to, and whether she has noticed any changes in sleep or appetite',
    'Ask if she has had any thoughts of self-harm or suicide',
    'Ask about her job role and how her eczema has affected her ability to work, particularly regarding confidence, client interaction, and manual tasks',
    'Ask about her home and relationship situation, especially how the flares have affected things with her partner',
    'Ask about smoking, alcohol, and recreational drug use to complete the social history',
    'Reach a working diagnosis of recurrent eczema flare with significant psychological impact, likely exacerbated by emotional stress or anxiety'
  ],
  ARRAY[
    'Provide a sick note to allow her time off work while the current eczema flare settles.',
    'Reinforce the importance of using emollients regularly, even when the skin is clear, to maintain the skin barrier and reduce the risk of future flares.',
    'Advise using an emollient as a soap substitute to minimise irritation from standard soaps and cleansers.',
    'Recommend wearing cotton-lined rubber or plastic gloves at work where appropriate, with regular removal to prevent sweating, which can aggravate eczema.',
    'Suggest wearing long sleeves where practical to protect affected areas and reduce self-consciousness.',
    'Encourage keeping a symptom diary to identify potential triggers such as stress, environmental exposures, or specific products.',
    'Discuss the psychological impact of her eczema and offer referral to talking therapy to support stress and anxiety management.',
    'Recommend self-help strategies such as breathing exercises and mindfulness apps (e.g. Headspace) for independent stress management.',
    'Explain that medication (e.g. antidepressants) could be considered in future if symptoms persist or worsen, based on her preference.',
    'Offer leaflets or information for her partner to help him better understand the impact of eczema on her daily life.',
    'Suggest relationship support services such as Relate if the condition is placing strain on the relationship.',
    'Book a follow-up appointment in 3–4 weeks to review her skin, emotional wellbeing, and overall progress.',
    'Safety-netting: advise her to seek medical attention promptly if symptoms worsen, the skin becomes weeping or infected, she develops a fever, or her mood deteriorates.'
  ],
  'Thank you for getting in touch today. It sounds like things have been really tough lately, and I want you to know that I can hear how much your eczema has been affecting both your work and your sense of self.

From everything you''ve shared, Laura, it does seem that emotional stress may be playing a significant role in triggering your flares. We know that psychological stress is a well-recognised aggravating factor in eczema, and when we are anxious or under pressure, the skin can respond. It also sounds like your emollient use tends to drop off once a flare settles, and keeping the skin well hydrated between episodes is really important for preventing the next one.

The good news is that there is a lot we can do to support you. Firstly, I am happy to provide a sick note today so that you can take some time off to rest and let this current flare settle. That is completely appropriate given what you have described.

Alongside the sick note, I would also like us to look at ways to help prevent this cycle from continuing. One option I would recommend is a referral to talking therapy. Many people find this really helpful when stress or anxiety start to affect their physical health. I can also suggest some self-help strategies you can use in your own time, such as breathing exercises and mindfulness apps like Headspace, which offer guided relaxation sessions.

If things become more difficult to manage, medication such as antidepressants can be considered, though that would be a joint decision and something we would only explore if you felt comfortable with it.

In terms of looking after your skin, it is really important to use your emollient regularly — even when your skin is completely clear. Think of it as maintenance rather than treatment. Using it as a soap substitute is also recommended to reduce irritation from conventional cleansers.

At work, wearing cotton-lined rubber or plastic gloves when handling products can help protect your skin and reduce irritation. Do make sure to remove them regularly though, as sweating inside gloves can actually worsen eczema. Wearing longer sleeves may also help you feel more confident around clients.

Keeping a symptom diary can be a really useful tool — noting what is happening around the time of each flare in terms of stress levels, skincare routine, diet, or product exposure. This can help us identify patterns and fine-tune your management plan over time.

I also wanted to mention your relationship. It can be hard for partners to fully understand how difficult eczema can be to live with. If you are comfortable, I can provide some information or a leaflet that you could share with him to help him understand what you are going through. If the condition is putting strain on your relationship, services such as Relate offer specialist couples support.

I would like to check in with you again in around 3–4 weeks to see how you are getting on — both physically and emotionally. In the meantime, please do not hesitate to contact us if things worsen. If your skin becomes weeping, very painful, develops yellow crusting, or if you develop a fever, please get in touch promptly as that could indicate a skin infection. Equally, if your mood drops or you feel overwhelmed, we want to know about that too.',
  ARRAY[
    'Emotional stress is a well-recognised trigger for eczema flares and should be actively explored in consultations, particularly in young adults with public-facing roles.',
    'Emollients should be used regularly as maintenance even when the skin is clear — stopping between flares significantly increases the risk of recurrence.',
    'A holistic approach to eczema management includes addressing the psychological burden: screen for anxiety, low mood, and impact on relationships, work, and sleep.',
    'Referring to talking therapy and recommending mindfulness or breathing techniques are first-line non-pharmacological options for stress-related eczema exacerbations.',
    'When eczema significantly impacts work, issuing a sick note is appropriate alongside a broader management plan — addressing only the skin without the psychological context is insufficient.',
    'Safety-net for signs of secondary skin infection (weeping, fever, yellow crusting) and for deteriorating mood, as unaddressed psychological distress can perpetuate the eczema-anxiety cycle.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  32,
  'Prescription Request After Release from Prison',
  'Ethics',
  'Telephone consultation',
  false,
  'Ryan Fletcher',
  '30-year-old male',
  ARRAY[]::text[],
  ARRAY['Salbutamol inhaler (PRN use)'],
  'Discharge Letter from HMP – 2 months ago
HMP Healthcare Services
His Majesty''s Prison

Re: Ryan Fletcher, 30-year-old male

I am writing in my capacity as a General Practitioner working within His Majesty''s Prison healthcare services to summarise the above patient''s medical history and treatment during his period of incarceration.

Mr Fletcher was under our care for approximately two years prior to his recent release. During this time he was managed for chronic lower back pain, for which pregabalin was prescribed with good symptomatic effect. He remained stable on this medication throughout his time in custody. He also carries a background diagnosis of asthma, managed with a salbutamol inhaler on an as-required basis. His asthma symptoms were intermittent and well controlled with this approach.

There were no acute medical concerns at the time of his release. It is recommended that his community GP reviews his current medications and continues appropriate management.

Please do not hesitate to contact us if further information is required.

Yours sincerely,
Dr Priya Nair, MBBS, MRCGP
General Practitioner, HMP Healthcare Services

Patient was advised by the pharmacist to contact his GP for medication reconciliation.',
  'Patient has contacted the surgery requesting prescriptions for multiple medications following recent release from prison.',
  'Hi doctor, I''d like prescriptions for pregabalin, tramadol, and zopiclone please.',
  'While you were in prison, the prison GP prescribed pregabalin for your back pain. However, you were also obtaining tramadol and zopiclone illegally inside prison. Since your release two months ago, you have continued to source these medications online and from the street. You are about to run out and would like the GP to prescribe them for you.',
  ARRAY[
    'While in prison you developed persistent lower back pain and also began struggling significantly with sleep. The prison doctor prescribed pregabalin, but a fellow prisoner also supplied you with tramadol and zopiclone, which you have taken regularly ever since. You feel these medications are essential — without them your back pain becomes severe and you cannot sleep without the zopiclone. You have been taking them for approximately one year.',
    'You now have only one tablet of each medication remaining and have been trying to see a GP since your release. A pharmacist recently told you that only a GP can review and prescribe these in the community.',
    'You do not feel low in mood and deny any symptoms of depression.',
    'You were taking pregabalin 50 mg three times a day, tramadol 100 mg four times a day, and zopiclone 7.5 mg at night.'
  ],
  'You are currently staying with a friend in a static caravan as you have no fixed address. You are not working at present, as you believe no employer will take on someone with a criminal record. You are not in contact with your family, who have distanced themselves since your imprisonment. You were imprisoned for assaulting a former partner. You do not smoke, do not drink alcohol, and do not use illicit drugs.',
  'You believe you need these medications to control your pain and to be able to sleep.',
  'You are worried about going into withdrawal — you already feel shaky, sweaty, and on edge when you miss doses.',
  'You are hoping the doctor will restart all your previous prescriptions.',
  ARRAY[]::text[],
  NULL,
  'Decline any questions outside of the details provided in the scenario. Accept anything appropriate offered by the doctor. If the doctor declines to prescribe the medications, say you will try to obtain them from the street as you are worried about withdrawal.',
  ARRAY[
    'Ask how long he has been taking pregabalin, tramadol, and zopiclone (to assess potential dependence and whether a gradual wean is more appropriate than abrupt discontinuation)',
    'Ask what the original reason was for each medication being started',
    'Ask what happens when he misses or does not take the medications (to screen for withdrawal symptoms such as sweating, agitation, pain, or confusion — suggestive of physical dependence)',
    'Ask if he is taking any over-the-counter medications or supplements (to identify potential interactions or undisclosed use)',
    'Ask about his lower back pain in detail: Has it changed or worsened? Is there any numbness around the back passage (saddle anaesthesia)? Any leg weakness? Any problems with bladder or bowel control? (to screen for red flag features of cauda equina syndrome)',
    'Ask whether he has previously tried physiotherapy or any non-pharmacological approaches for managing his back pain',
    'Ask about his sleep difficulties — whether he has trouble falling asleep or staying asleep, and whether nightmares, past trauma, or poor sleep hygiene may be contributing',
    'Ask about his bedtime routine and whether he has tried any sleep hygiene measures such as a regular schedule, reducing screen time before bed, or limiting caffeine',
    'Ask about red flag symptoms including constipation, unexplained weight loss, nausea, or vomiting',
    'Ask about his history of illicit drug use, including any past or current use (to guide screening for blood-borne viruses and to assess misuse risk)',
    'Ask whether he has obtained any medications through non-medical sources while in prison or since release',
    'Ask about his employment status and current financial situation',
    'Ask about his housing and social support network',
    'Screen for low mood or thoughts of self-harm'
  ],
  ARRAY[
    'Prescribe a short-term supply of pregabalin, tramadol, and zopiclone with a clear and structured plan to gradually wean off each medication under close supervision.',
    'Arrange 1–2 weekly prescriptions with regular reviews to monitor withdrawal symptoms, adherence, and safety, coordinating with the pharmacist where appropriate.',
    'Book a same-day face-to-face appointment to examine his lower back and screen for any red flag features of cauda equina syndrome.',
    'Refer to physiotherapy for chronic lower back pain management and evidence-based exercise guidance.',
    'Recommend paracetamol or ibuprofen as simple analgesia during pain flare-ups, provided there are no contraindications.',
    'Offer referral to talking therapy to help address chronic pain, sleep difficulties, anxiety, and emotional wellbeing.',
    'Provide education on sleep hygiene, including maintaining a consistent bedtime routine, avoiding screens before bed, reducing daytime naps, and increasing daytime physical activity.',
    'Refer to the social prescriber to support housing applications and access to social care services.',
    'Signpost to charities supporting people recently released from prison, such as Nacro (National Association for the Care and Resettlement of Offenders), Prison Reform Trust, The Hardman Directory, Shelter, and Unlock, which can assist with accommodation and employment.',
    'Arrange a follow-up review in 2 weeks to assess progress with medication reduction, back pain management, housing, and psychological wellbeing.',
    'Safety-netting: advise him to contact the practice urgently if he experiences worsening pain, withdrawal symptoms, thoughts of self-harm, or a housing crisis.'
  ],
  'Thank you for calling today. I really appreciate you reaching out and being open about what has been going on — I can hear that things have been difficult since your release, and I want to make sure we support you properly.

I want to talk with you honestly about the medications you have requested. Pregabalin and tramadol are both powerful medications, and while they can be helpful in the short term, using them regularly over a long period carries real risks. Over time, your body can adapt to them — this is called tolerance — meaning you may need higher doses to achieve the same effect. This can lead to dependence, which is when your body comes to rely on the medication to function normally. The feelings of shakiness and sweating you described when you miss doses suggest that this process has already begun.

Because of this, it would not be safe to simply stop these medications abruptly — that could cause significant and distressing withdrawal symptoms. What I would like to do instead is provide you with a short supply now, and then we work together on a gradual reduction plan, reducing your dose steadily over time in a way that keeps you safe and comfortable. I will arrange for prescriptions to be issued every one to two weeks so we can keep a close eye on how you are doing, and the pharmacist will be involved in supporting this process.

I would also like to see you face to face today so that I can examine your back properly. I want to make sure there are no concerning features that need further investigation. For the longer-term management of your back pain, I would like to refer you to physiotherapy, where you can be guided through exercises tailored to your condition. In the meantime, straightforward pain relief such as paracetamol or ibuprofen can help during flare-ups. Many people with persistent pain also find talking therapy very beneficial — it does not mean the pain is not real, but it can help you develop better coping strategies and reduce the day-to-day impact of the pain on your life.

In terms of your sleep, I understand it has been really hard. Sleeping tablets such as zopiclone are not safe for long-term use, and part of our plan will be to reduce these gradually too. In the meantime, there are some practical things that can make a real difference — keeping a regular bedtime, avoiding screens in the hour before sleep, cutting out caffeine in the afternoon and evening, and trying to stay active during the day to help your body feel more ready to rest at night.

Ryan, I also want you to know that there is help available for your housing situation. We have a social prescriber here at the practice who is very approachable and experienced in connecting people with housing support through the council and local services. There are also charities specifically for people leaving prison — organisations like Nacro, Shelter, and Unlock can help with accommodation, employment, and practical support. I would very much like to help you access those.

Let''s arrange a face-to-face appointment for later today to examine your back and put this plan in place together. We can then check in again in two weeks to see how things are going. If anything changes in the meantime — worsening pain, severe withdrawal symptoms, weakness in your legs, numbness around your back passage, or any concerns at all — please do not hesitate to get in touch straight away. How does that all sound?',
  ARRAY[
    'Patients recently released from prison often present with complex physical, psychological, and social needs — a trauma-informed, structured approach is essential.',
    'Abrupt discontinuation of pregabalin, tramadol, or zopiclone risks significant and potentially dangerous withdrawal; always plan a gradual supervised wean rather than stopping suddenly.',
    'Medications obtained illegally (e.g. from fellow prisoners or online) should not simply be continued as prescribed — a careful review of indication, dose, and risk is required before prescribing.',
    'Screen for red flag features of cauda equina syndrome in any patient with chronic lower back pain: saddle anaesthesia, leg weakness, and bladder or bowel dysfunction require urgent assessment.',
    'Signpost patients leaving prison to specialist charities (Nacro, Shelter, Unlock, Prison Reform Trust) alongside social prescribing referrals — housing instability compounds medical and psychiatric risk.',
    'Do not prescribe methadone or other opioid substitution therapy in primary care on an unplanned basis; if illicit opioid dependence is identified, refer urgently to drug and alcohol services for supervised opioid substitution therapy.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  33,
  'Patient-Initiated DNACPR Request',
  'Elderly Medicine & Palliative Care',
  'Telephone consultation',
  false,
  'Graham Sutton',
  '66-year-old male',
  ARRAY[]::text[],
  ARRAY['Ramipril 5mg OD','Nil known drug allergy'],
  NULL,
  'Patient has booked a telephone consultation to discuss a DNACPR decision following a distressing personal experience with a family member.',
  'Good morning doctor. I''d like to talk to you about something I''ve been thinking about for a while — I want to discuss a do-not-resuscitate form.',
  'You have been thinking about this carefully since witnessing what happened to your brother. He suffered a cardiac arrest, was resuscitated, but sustained a severe brain injury and is now in a persistent vegetative state. You describe him as "like a vegetable." Watching his prolonged suffering has been deeply traumatic. You feel very clearly that if something similar happened to you, you would not want resuscitation attempted.',
  ARRAY[]::text[],
  'You do not smoke or drink alcohol. You run your own small catering business and find your work fulfilling and enjoyable. You live with your wife, and you have two adult sons who visit every couple of weeks. You have not yet discussed your thoughts about a DNACPR with your wife or sons.',
  'You understand that CPR involves chest compressions and electric shocks, and that it does not always result in a meaningful recovery.',
  'You are worried about surviving a cardiac arrest only to be left with a severely diminished quality of life, particularly ending up in a similar state to your brother.',
  'You would like the doctor to complete a DNACPR form for you today.',
  ARRAY[]::text[],
  'Is a DNACPR legally binding? If I sign this form, can another doctor override it? If I have a DNACPR, does that mean I won''t be admitted to hospital for other problems?',
  'If the doctor guides the conversation calmly and sensitively and suggests involving family, be open to discussion and accept their recommendation. If the doctor seems uncertain or does not lead the conversation, say you have already made up your mind and would like to proceed with signing the form. Decline any questions not covered in the scenario above.',
  ARRAY[
    'Ask what has prompted him to consider a DNACPR decision at this particular time (to explore his motivation and ensure the request is well-informed)',
    'Ask how he is coping emotionally following his brother''s experience (to show empathy and assess his emotional readiness)',
    'Ask about his main concerns or fears relating to resuscitation (to explore underlying motivations such as fear of suffering, poor quality of life, or the impact of witnessing his brother''s situation)',
    'Ask whether he has any concerns about his own health deteriorating over time',
    'Ask whether he has had any previous hospital admissions or significant health scares that may have influenced his thinking',
    'Ask whether he is taking any regular medications or has any medical conditions not listed in his records',
    'Ask about his social history including smoking, alcohol use, recreational drug use, and occupation',
    'Ask whether he understands what CPR involves, including both its potential benefits and limitations, such as the possibility of survival with significant brain injury or poor functional outcome (to support informed decision-making)',
    'Ask whether he is aware that a DNACPR applies only to cardiopulmonary resuscitation and does not affect access to any other treatment, including antibiotics, oxygen, fluids, pain relief, or hospital admission (to address common misconceptions)',
    'Ask whether he feels he has had sufficient time and information to make this decision',
    'Ask whether he has discussed his wishes with any family members or other healthcare professionals',
    'Ask whether he has considered completing an Advance Care Plan or Advance Decision to Refuse Treatment to formalise his wishes more comprehensively'
  ],
  ARRAY[
    'Acknowledge and sensitively explore the patient''s DNACPR request, confirming he has capacity and understands the implications of his decision.',
    'Provide a clear explanation of what DNACPR means — that it applies solely to CPR and does not restrict access to any other treatments, including antibiotics, fluids, hospital admission, or pain relief.',
    'Clarify that a DNACPR form is not legally binding, but is a clinically respected decision that guides healthcare professionals in an emergency.',
    'Reassure the patient that his wishes will be fully documented and respected, and that the form can always be reviewed or cancelled if he changes his mind.',
    'Encourage him to discuss his wishes with his wife and family, while making clear that the final decision rests with him, to help avoid confusion or distress in the event of a future emergency.',
    'Offer a face-to-face appointment to complete the DNACPR form formally, ensuring it is clearly documented, signed, and added to both his GP record and his Summary Care Record.',
    'Offer written information or a leaflet to support his understanding of DNACPR and advance care planning.',
    'Explore broader future planning, such as completing an Advance Decision to Refuse Treatment (ADRT) or an Advance Care Plan, if he wishes to make his preferences legally enforceable or more comprehensive.',
    'Advise the patient to contact the surgery at any time if he wishes to review or change his decision.'
  ],
  'Thank you for calling today, and for trusting me with something so personal and important. I want you to know that I take this kind of conversation very seriously, and I am glad you reached out.

I am truly sorry to hear about what has happened with your brother. Watching someone you love go through something like that — surviving a cardiac arrest but being left in a condition where they cannot communicate or interact with the world — must have been incredibly painful to witness. It is completely understandable that this experience has made you think carefully about your own wishes, and it speaks to how much you value your quality of life.

Graham, before we go any further, I want to make sure you have all the information you need to make this decision confidently. DNACPR stands for Do Not Attempt Cardiopulmonary Resuscitation. CPR is an emergency procedure — it involves chest compressions, sometimes electric shocks, and occasionally breathing support — used to try to restart the heart when it stops. The outcomes of CPR can vary considerably. In some situations it can be lifesaving, but in others, particularly where someone has underlying health conditions or where the organs were already under significant strain, the chances of a meaningful recovery are much lower, and complications such as brain injury can occur.

A DNACPR form records your wish that, in the event your heart stops, the medical team would not attempt CPR. Importantly, it applies only to that one intervention. It does not affect any other care you would receive — you would still be given antibiotics if you had an infection, pain relief if you were in discomfort, oxygen, fluids, or hospital admission if you needed them. Your overall care continues exactly as before.

I do want to be transparent with you about one important point: a DNACPR form is not a legally binding document. Healthcare professionals are expected to respect it as far as reasonably possible, but in an emergency, if the form is not available or if there is uncertainty about your circumstances, a clinician may use their professional judgment about what is in your best interests at that moment. If you would like your wishes to be legally enforceable, you can complete what is called an Advance Decision to Refuse Treatment — this is a legal document that, once properly completed, signed, and witnessed, and provided it specifically addresses resuscitation, cannot be overridden.

If we go ahead and complete a DNACPR form for you, I will ensure it is added to your GP record, shared with the out-of-hours service, and flagged with the ambulance service. I would also encourage you to keep a copy somewhere accessible at home — beside your bed or in your wallet — so that it is available if ever needed.

I would also gently encourage you to consider speaking with your wife and sons about this. It can be a difficult conversation, but helping your family understand your wishes now can prevent a great deal of confusion and distress at a very difficult time. The final decision is entirely yours — I simply want to make sure the people who love you are not left in doubt about what you would want.

Please also know that this decision is not set in stone. You can change your mind at any time and we will update or cancel the form accordingly. I can arrange a face-to-face appointment for you to complete the form formally, and I am happy to send you some written information to take away and reflect on at your own pace. How does all of that sound to you?',
  ARRAY[
    'A DNACPR form is not legally binding — it is a clinically respected document guiding healthcare professionals, but clinical judgment may override it in emergency situations where the form is unavailable.',
    'If a patient wishes to make their refusal of resuscitation legally enforceable, they should be advised to complete an Advance Decision to Refuse Treatment (ADRT) under the Mental Capacity Act 2005, which must be written, signed, witnessed, and explicitly state it applies even if life is at risk.',
    'Always confirm the patient has capacity, is making the decision voluntarily and without undue influence, and understands what CPR involves and what a DNACPR does and does not affect.',
    'A DNACPR applies only to cardiopulmonary resuscitation — it does not restrict access to any other treatment and this must be clearly explained to avoid common misconceptions.',
    'Encourage family involvement sensitively while reinforcing patient autonomy — the final decision rests with the patient, but family awareness reduces distress at the time of a crisis.',
    'Discuss broader advance care planning options including Lasting Power of Attorney for health and welfare, and Advance Care Plans, to support long-term documentation of the patient''s preferences.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  34,
  'Medication Request in Patient with Epilepsy',
  'General Practice',
  'Telephone consultation',
  false,
  'Charlotte Davies',
  '25-year-old female',
  ARRAY[]::text[],
  ARRAY['Tegretol PR 400mg BD (Last requested 7 months ago)','No known drug allergy'],
  'Letter from Neurology Clinic 7 months ago
Re: Charlotte Davies | 25 years old | Female

Dear GP,

I am writing to advise you that Charlotte Davies did not attend her scheduled neurology clinic appointment. She has now failed to attend on three separate occasions and no further appointments have been arranged at this stage. We hope Charlotte is well. Should she wish to rebook or require further support, please do not hesitate to contact us.

Kind regards,
Dr Yusuf Adeyemi, MBBS, MRCP (UK)
Consultant Neurologist

Patient has booked an urgent telephone appointment to discuss concerns.',
  'Patient is calling following a suspected seizure episode overnight and is requesting to restart her epilepsy medication.',
  'Doctor, I think I''ve had a seizure — I''d like to restart my epilepsy medication please.',
  'You think you had a seizure during the night because when you woke up this morning you had wet yourself and bitten your tongue — these are things that only happen to you after a seizure. There was no one else at home to witness the episode.',
  ARRAY[
    'Your last seizure was approximately 9 months ago. Your seizures are typically generalised tonic-clonic in nature — your whole body jerks and you lose consciousness during an episode. You usually experience a brief aura of light-headedness before a seizure, which gives you just enough time to lower yourself to the floor or sofa to avoid injury. Last night''s episode was not typical — it happened during sleep with no warning.',
    'You are not aware of any specific triggers for your seizures.',
    'Medication history: You made your own decision to stop taking Tegretol (carbamazepine) around 7 months ago. You felt the condition was under control as you had been seizure-free for a period, and you did not experience any side effects from the medication.'
  ],
  'You do not drink alcohol and do not smoke. You work as an IT consultant and drive to work each day. You are in a new relationship and have been with your partner for about four weeks. You are sexually active and the two of you have recently started talking about moving in together.',
  'You are not entirely sure why you have had another seizure after being fine for so long.',
  'You are worried about what this means for your seizures going forward — you had hoped they were behind you.',
  'You would like the doctor to issue a prescription to restart your epilepsy medication today.',
  ARRAY[]::text[],
  NULL,
  'Decline any questions not covered by the details in the scenario. Accept all advice offered by the doctor.',
  ARRAY[
    'Ask the patient to describe the seizure episode in detail, including whether there was anyone present to witness it',
    'Ask about the type of seizure — whether there was an aura, loss of consciousness, and any post-ictal features such as confusion, incontinence, tongue biting, or sleepiness afterwards',
    'Ask about potential triggers for the seizure, including sleep deprivation, recent illness or infection (e.g. flu-like symptoms or urinary tract infection), emotional stress, sensitivity to flashing lights, or alcohol use',
    'Ask screening questions to rule out red flag causes: features of a brain tumour (e.g. persistent headache, visual changes, progressive focal weakness) or intracranial infection (e.g. fever, neck stiffness, photophobia, feeling generally unwell)',
    'Ask about social history including smoking, alcohol intake, recreational drug use, and occupation, particularly whether she works in a high-risk environment such as operating machinery, working at heights, or driving',
    'Ask whether she is sexually active, as carbamazepine has important implications for contraceptive efficacy and pregnancy',
    'Ask whether she drives, as this has significant medicolegal and safety implications',
    'Explore the reason for stopping her medication and for missing her neurology follow-up appointments',
    'Reach a working diagnosis of breakthrough seizure due to self-discontinuation of antiepileptic medication in a patient with known epilepsy'
  ],
  ARRAY[
    'Restart antiepileptic medication at the previously effective dose (Tegretol 400 mg BD), as she has had a breakthrough seizure most likely caused by self-discontinuation.',
    'Send an urgent referral to the Neurology team for specialist assessment and follow-up.',
    'Offer a face-to-face appointment for neurological examination, vital signs assessment, and blood tests including electrolytes, FBC, CRP, LFTs, and TFTs.',
    'Educate the patient on medication adherence, emphasising clearly that antiepileptic medication must not be stopped without medical advice, as sudden withdrawal significantly increases the risk of further seizures and serious complications.',
    'Advise immediate cessation of driving and the legal requirement to notify the DVLA following any seizure, including nocturnal seizures. Explain the safety rationale and legal obligations clearly.',
    'Arrange a follow-up appointment to discuss contraceptive options in detail, as carbamazepine can reduce the effectiveness of hormonal contraception including the combined oral contraceptive pill, and carries a small risk of congenital abnormalities if pregnancy occurs. In the interim, advise consistent use of condoms.',
    'Recommend wearing a medical alert bracelet so that bystanders and emergency responders are aware of her diagnosis and can respond appropriately in the event of a seizure in a public place.',
    'If she lives alone, suggest considering an epilepsy seizure alarm — a device that detects unusual movements during sleep or while awake and can alert a designated emergency contact.',
    'Encourage her to inform close contacts — including her partner, friends, and colleagues — about her epilepsy, so they know how to respond safely during a seizure, including placing her in the recovery position and, if prescribed by a specialist, administering rescue medication such as buccal midazolam or rectal diazepam.',
    'Safety-netting: advise her to seek urgent medical attention if she experiences any further seizures, blurry vision, persistent headache, focal weakness, or any other concerning new symptoms.'
  ],
  'Thank you for calling this morning. I''m glad you got in touch, and I can hear that this has been frightening — waking up to find you''ve wet yourself and bitten your tongue during the night is very unsettling, especially when you thought things had been under control.

Based on what you have described, Charlotte, it does sound like you may well have had a seizure during your sleep. The combination of urinary incontinence and a bitten tongue without any recollection of the episode is very consistent with a generalised seizure, and these types of nocturnal seizures can occur without any warning aura beforehand.

I want to explain something really important about what has likely happened here. When you stopped your Tegretol seven months ago, the protective effect of the medication gradually wore off, and this left your brain more vulnerable to having a seizure. I completely understand why you made that decision — if things have been going well for a while it can feel logical to wonder whether you still need the medication. But in epilepsy, it is really important to discuss any changes to your medication with your GP or neurologist before stopping, because the risk of breakthrough seizures increases significantly when antiepileptic drugs are withdrawn, even after a long seizure-free period.

What I would like to do today is restart your Tegretol at your previous dose of 400 mg twice a day, as this is the medication that was keeping your seizures under control. I will also arrange an urgent referral back to the neurology team so they can assess you properly and take over your longer-term management. In addition, I''d like to arrange a face-to-face appointment for a full neurological check, a blood pressure and temperature reading, and some blood tests — these will include things like electrolytes, a full blood count, liver function tests, and thyroid function, just to rule out any other contributing factors.

There is something very important I also need to mention regarding driving. I know this may be difficult to hear, but following any seizure — including one during sleep — you are legally required to stop driving and to inform the DVLA. This is a legal obligation rather than a choice, and it is about protecting both you and other people on the road. The DVLA will guide you on when and under what conditions you may be able to drive again, once your seizures are well controlled.

I also want to talk about contraception. Tegretol can reduce the effectiveness of certain types of hormonal contraception, including the combined pill, which means there is a risk of unintended pregnancy if you rely on that alone. It also carries a small risk of harm to a developing baby if pregnancy were to occur. For now, I would advise using condoms consistently, and I''d like us to arrange a follow-up appointment soon to discuss the most appropriate long-term contraceptive options for you.

Given that you were alone during last night''s episode, it is worth thinking about a seizure alarm for home use — these are devices that detect unusual movement during sleep and alert a designated contact, which can be really reassuring if you are on your own. A medical alert bracelet is also worth considering, so that if a seizure ever happens in public, people around you and emergency responders will immediately know what is happening and how to help.

I''ll send you some information leaflets, and I''d encourage you to share details of your epilepsy with your new partner and anyone else close to you, so they know what to do in an emergency.

Please do get back in touch urgently if you have any further seizures, develop a bad headache, blurry vision, weakness in your face or limbs, or anything else that concerns you. How does all of that sound? Do you have any questions?',
  ARRAY[
    'Breakthrough seizures in known epilepsy are commonly caused by self-discontinuation of antiepileptic medication — always explore adherence before assuming disease progression.',
    'Restart antiepileptic medication at the previously effective dose (Tegretol 400 mg BD) following a breakthrough seizure due to self-discontinuation, and arrange urgent neurology review.',
    'Any seizure — including nocturnal ones — legally requires the patient to stop driving and notify the DVLA; this is a mandatory obligation the GP must clearly communicate.',
    'Carbamazepine is an enzyme inducer that reduces the efficacy of hormonal contraception including the COCP, and carries a small risk of congenital abnormalities; contraceptive counselling is essential before restarting.',
    'SUDEP (Sudden Unexpected Death in Epilepsy) is the leading cause of epilepsy-related death in young adults with uncontrolled seizures — effective medication adherence and specialist follow-up are key risk-reduction strategies.',
    'Patients living alone with epilepsy should be offered practical safety advice including epilepsy seizure alarms, medical alert bracelets, and guidance for close contacts on how to respond during a seizure.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  35,
  'Low Platelet Count in a Young Adult',
  'Gastroenterology & Haematology',
  'Telephone consultation',
  false,
  'Daniel Ashworth',
  '41-year-old male',
  ARRAY[]::text[],
  ARRAY['Not on any medication','No known drug allergy'],
  'Seen by Dr Camille Osei (General Practitioner) 8 days ago in Urgent Primary Care (Out of Hours).
Presenting complaint: Patient reported spontaneous bruising, persistent tiredness, and fatigue.
Examination: Abdomen soft and non-tender with no palpable masses. Bruising noted on both forearms and hands. Blood pressure 115/80 mmHg, pulse 89 bpm, temperature 36.5°C.
Plan: Urgent full blood count requested. Review with results.

Further review: Urea and electrolytes, C-reactive protein, liver function tests, and bone profile all within normal limits. Full blood count showed a platelet count of 90 × 10⁹/L, with all other parameters within normal range.
Plan: Reassured and discharged home. Advised to follow up with own GP for repeat full blood count in one week.

Repeat full blood count done yesterday
Parameter              Result            Reference Range
Haemoglobin (Hb)      14 g/dL           13.8 – 17.2 g/dL
Haematocrit (Hct)     41%               40 – 52%
White Blood Cells      5.5 x 10⁹/L      4.0 – 11.0 x 10⁹/L
Neutrophils            3.0 x 10⁹/L      2.0 – 7.5 x 10⁹/L
Lymphocytes            1.8 x 10⁹/L      1.5 – 4.0 x 10⁹/L
Platelets              86 x 10⁹/L       150 – 450 x 10⁹/L
Mean Corpuscular Vol   82 fL            80 – 100 fL',
  'Patient has called to discuss his recent blood test results.',
  'Hi doctor, I''d like to go over my recent blood test results if that''s okay.',
  'You rang 111 and were directed to the out-of-hours GP 8 days ago because you were exhausted and had noticed unexplained bruising appearing on your body. The doctor examined you and ran some blood tests. He told you that the part of your blood responsible for clotting was slightly low — at 90 — and asked you to have a repeat test with your own GP in one week, which you have now done.',
  ARRAY[
    'For the past 5 weeks you have been feeling persistently tired and have been noticing unexplained bruising coming up in different places, particularly on your arms and hands. This is completely new for you and has never happened before, which has been making you feel quite anxious.',
    'You also recall having a sore throat around 7 weeks ago, but this cleared up on its own. You have not had any weight loss or other symptoms.'
  ],
  'You are married with two children and live with your family in Bristol. You are a non-smoker, do not drink alcohol, and work as a software developer.',
  'You are worried this might be leukaemia, particularly because your older brother had similar symptoms when he was in his twenties, was eventually diagnosed with leukaemia, and sadly died from it.',
  'You are frightened this could also be leukaemia.',
  'You want the doctor to explain your blood test results clearly and tell you what happens next.',
  ARRAY[]::text[],
  NULL,
  'Decline any questions outside of the details already provided in the scenario. Accept all advice offered by the doctor.',
  ARRAY[
    'Ask why the blood test was arranged originally (to understand the initial presenting symptoms)',
    'Ask when the patient first noticed the bruising, where the bruises have appeared, and whether they are getting better, worse, or staying the same',
    'Ask about any abnormal bleeding, including nosebleeds, bleeding gums, vomiting blood, dark or tarry stools, rectal bleeding, or blood in the urine',
    'Screen for systemic symptoms that may suggest a haematological malignancy, such as unintentional weight loss, drenching night sweats, fevers, or bone pain',
    'Ask about any abdominal symptoms including pain, swelling, or any lumps or bumps the patient has noticed',
    'Ask about any recent or preceding infections, such as a flu-like illness, sore throat, or gastrointestinal illness',
    'Ask about use of over-the-counter medications, particularly NSAIDs, which can contribute to drug-induced thrombocytopenia',
    'Ask about any family history of bleeding disorders or blood cancers',
    'Ask about social history including smoking, alcohol use, and occupation',
    'Explore the patient''s ideas, concerns, and expectations',
    'Provide a working diagnosis of thrombocytopenia, likely following a recent viral illness (e.g. the preceding sore throat), consistent with immune thrombocytopenic purpura (ITP)'
  ],
  ARRAY[
    'Arrange an urgent peripheral blood smear (blood film), along with additional investigations including Liver Function Tests (LFTs), clotting profile, Urea and Electrolytes (U&Es), vitamin B12, folate, ferritin, and an HIV and hepatitis screen if there is clinical suspicion of an infectious trigger.',
    'Advise the patient to minimise the risk of injury or trauma given the increased bleeding risk associated with a low platelet count.',
    'Book a follow-up appointment in 1–2 weeks to review results and discuss next steps.',
    'Explain that if platelet levels continue to fall or the blood film result is inconclusive, the case will be discussed with a haematologist for further guidance — reassure the patient that specialist input is not needed at this stage until initial investigations are reviewed.',
    'Safety-netting: advise the patient to contact the surgery promptly or seek urgent medical attention if symptoms worsen — for example, increasing bruising or bleeding, or symptoms that could suggest anaemia such as dizziness, worsening fatigue, breathlessness, chest pain, or palpitations.'
  ],
  'Thank you for calling in today, and for coming back to get these results checked as requested. I can hear that this has been worrying you, and I want to make sure I explain things clearly so you know exactly where we stand.

Looking at your latest blood test, the result I want to focus on is your platelet count. Platelets are tiny cells in the blood whose job is to help with clotting — they gather at the site of a cut or injury to stop bleeding. In your repeat test, your platelet count has come back at 86 × 10⁹/L, which is below the normal range of 150 to 450. This is slightly lower than the reading of 90 we got a week ago, which tells us this needs to be looked into further.

The reassuring part is that all your other blood count results — your red cells, white cells, and haemoglobin — are completely normal. That is genuinely important, because it tells us that your bone marrow appears to be functioning well in all other respects. This pattern — where only the platelet count is low — is something we see in a number of conditions, and one of the most common in someone your age, particularly after a recent viral illness such as a sore throat, is a condition called immune thrombocytopenic purpura, or ITP. In ITP, the immune system mistakenly produces antibodies that attack and destroy the body''s own platelets. It is not a cancer, and in many adults it resolves on its own or responds well to treatment.

Daniel, I understand you are worried about leukaemia because of what happened with your brother, and I want to acknowledge how frightening that experience must have been. I can see why this situation has brought those fears back. I want to be honest with you — while I cannot completely rule anything out at this stage, what we are seeing so far is not typical of leukaemia. In leukaemia, we would usually expect to see abnormalities across multiple blood parameters, not just the platelets, and often symptoms such as significant weight loss, drenching night sweats, or persistent fevers. None of those are present here.

That said, I want to be thorough. The next step I would like to arrange is a blood film — this involves a pathologist looking at your blood cells directly under a microscope, which gives us much more detail about the shape and appearance of your platelets and other cells. I would also like to arrange some additional blood tests, including liver function, clotting studies, vitamin levels, and if appropriate, checks for viral infections such as HIV or hepatitis, which can sometimes affect platelet counts.

In the meantime, because your platelet level is low, I would ask you to be careful about the risk of injury — avoid activities where you might sustain a knock or bruise, and steer clear of anti-inflammatory medications such as ibuprofen, which can affect platelet function further.

I will book you in for a follow-up appointment in one to two weeks once all the results are back so we can go through everything together. If your symptoms change before then — particularly if you notice heavier bruising, any bleeding that is hard to stop, dizziness, significant breathlessness, or chest pain — please do not wait for your appointment. Contact us or go to A&E if you feel very unwell. How does that all sound? Do you have any questions?',
  ARRAY[
    'Isolated thrombocytopenia following a recent viral illness in an otherwise well young adult is suggestive of immune thrombocytopenic purpura (ITP) — a common, often self-limiting immune-mediated cause of low platelets.',
    'A peripheral blood film is a key investigation in thrombocytopenia: it allows direct assessment of platelet morphology and helps distinguish ITP from other causes such as thrombotic thrombocytopenic purpura (TTP) or haematological malignancy.',
    'Normal haemoglobin, white cell count, and all other FBC parameters alongside isolated thrombocytopenia make haematological malignancy less likely — but a blood film and follow-up are still essential.',
    'Additional investigations in unexplained thrombocytopenia should include LFTs, clotting profile, U&Es, vitamin B12, folate, ferritin, and where clinically indicated, HIV and hepatitis B/C screen.',
    'Advise patients with low platelet counts to avoid NSAIDs and minimise injury risk; safety-net for worsening bruising, bleeding, or symptoms of anaemia such as breathlessness, dizziness, or palpitations.',
    'Acknowledge and address patient concerns directly — in this case, fear of leukaemia prompted by family bereavement — and explain clearly why current findings do or do not support that diagnosis.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  36,
  'Enuresis',
  'Paediatrics',
  'Telephone consultation',
  false,
  'Ethan Holbrook',
  '7-year-old male',
  ARRAY[]::text[],
  ARRAY['No known drug allergy','Movicol – 2 sachets daily for constipation (Acute prescription)'],
  'Seen by Mrs Patricia Dunmore (Nurse Practitioner) 6 months ago.
Presenting complaint: Mother reports constipation in child.
Examination: Abdomen soft, non-tender, no masses palpable. Heart rate 109 bpm, Temperature 36.5°C.
Plan: Trial of Movicol 2 sachets daily. Encourage increased fibre in diet. Worsening advice given.

Mother, Karen Holbrook, has booked a telephone appointment to discuss concerns regarding her son.',
  'Mother is calling to discuss her son''s bedwetting, which has started over the past 3 months.',
  'Hello doctor, I''m ringing because my son Ethan has started wetting the bed and I''m not sure what''s going on.',
  'You''ve noticed over the past 3 months that Ethan has been wetting the bed regularly, which was not something he was doing before. This has started to worry you.',
  ARRAY[]::text[],
  'Ethan lives at home with you, his father, and his older sister. He shares a room with his 9-year-old sister, sleeping in separate bunk beds, and the bathroom is just down the corridor. There are no concerns at school, no signs of bullying, and no significant changes at home. Ethan is a happy, sociable child who plays well with others. You are not blaming him for the bedwetting, but you feel something must be causing it. His birth and developmental history are unremarkable: normal pregnancy, normal vaginal delivery, and immunisations are fully up to date.',
  '',
  'If asked what you think might be causing the bedwetting, you are worried it could be diabetes, especially as Ethan''s father was diagnosed with Type 1 diabetes as a child and had very similar symptoms at the time.',
  'You would like the doctor to test Ethan for diabetes.',
  ARRAY[]::text[],
  NULL,
  'Decline any questions or symptoms outside of those covered by the scenario details. Accept anything offered by the doctor.',
  ARRAY[
    'Ask whether Ethan has ever been consistently dry at night, and clarify when the bedwetting started (secondary enuresis refers to the return of nighttime wetting after a child has been dry for more than 6 months)',
    'Ask about the frequency of bedwetting — whether it happens every night or only some nights, and whether Ethan wakes up after wetting the bed',
    'Ask whether Ethan has any daytime urinary symptoms and explore the following: daytime wetting or urgency (may suggest UTI or overactive bladder); increased urinary frequency (could indicate diabetes or UTI); infrequent urination of fewer than four times a day (may suggest retention or obstruction)',
    'Ask about symptoms that might suggest diabetes, including excessive thirst (polydipsia), increased hunger (polyphagia), and any changes in weight',
    'Ask whether Ethan is fully toilet trained; if not, explore the reason',
    'Ask about fluid intake, including whether the parents restrict fluids in the evening to try to manage bedwetting, and whether Ethan has fizzy drinks or caffeine-containing beverages',
    'Ask about bowel habits, specifically constipation, as faecal loading can contribute to urinary incontinence by pressing on the bladder',
    'Ask about any psychological or emotional factors, such as recent changes at home (e.g. new school, house move, bereavement, parental separation) or concerns about bullying or stress',
    'Ask about the home environment, including whether Ethan shares a room and whether there is easy access to the toilet at night',
    'Ask about any family history of bedwetting',
    'Ask how the bedwetting is affecting Ethan''s confidence and emotional wellbeing, and the impact it has had on the family',
    'Ask about birth history, developmental milestones, immunisation status, nutrition, and growth (PBIND)',
    'Reach a diagnosis of secondary enuresis'
  ],
  ARRAY[
    'Offer a face-to-face appointment to examine Ethan''s abdomen, assess for signs of constipation or faecal impaction, and evaluate his general wellbeing.',
    'Arrange investigations including urinalysis to check for signs of urinary tract infection or the presence of glucose, which may raise concern for diabetes.',
    'Offer a blood glucose test to screen for diabetes, particularly given parental concern and a relevant family history of Type 1 diabetes.',
    'Advise the parent to keep a 2-week diary recording Ethan''s fluid intake, toileting pattern, and bedwetting episodes, to identify any patterns and help guide management.',
    'Continue managing constipation, which may include adjusting the dose of Movicol to achieve regular, soft, well-formed stools. Provide dietary advice to increase fibre and fluid intake, and advise limiting fizzy drinks as they can irritate the bladder and worsen symptoms.',
    'Advise using a positive reward system appropriate for Ethan''s age to encourage engagement with bedwetting management. Rewards should be given for specific behaviours such as having a dry night, drinking an appropriate amount during the day, using the toilet before bed, or actively participating in management tasks. Emphasise clearly that punitive approaches or withdrawing earned rewards are not recommended, as these can damage the child''s self-esteem.',
    'Reassure the mother that with consistent constipation management, encouragement, and a reward-based approach, secondary enuresis often improves; if it persists despite these measures, escalation to an enuresis alarm or desmopressin can be considered.',
    'Provide a leaflet on bedwetting and signpost to reliable online resources such as the ERIC website for further information and support.',
    'Arrange a follow-up in 2–3 weeks to review progress with constipation management and assess the effectiveness of behavioural strategies.'
  ],
  'Thank you for calling today. I can hear that this has been worrying you, and you are absolutely right to get in touch. Let me try to explain what might be going on and what we can do about it.

From what you have described, it sounds like Ethan has a condition called enuresis — which is simply the medical term for bedwetting. Because he was previously dry at night and has now started wetting the bed again, this is called secondary enuresis. I want to reassure you straight away that this is not Ethan''s fault, and it is more common than many parents realise.

Bedwetting happens because during the night, the bladder sometimes cannot hold the volume of urine being produced, and in some children, the signal from the bladder to the brain that says "wake up and go to the toilet" does not come through strongly enough. There are several things that can contribute to this — and in Ethan''s case, I think his constipation may well be playing an important role. When there is a build-up of stool in the bowel, it can press against the bladder and make it harder to hold urine, particularly during the night. Treating the constipation effectively can make a really significant difference to the bedwetting.

Karen, you mentioned you are worried this could be diabetes, and I think that is a completely understandable concern given that Ethan''s father was diagnosed with Type 1 diabetes as a child. You are right that diabetes can cause children to pass urine more frequently, which can sometimes contribute to bedwetting. Based on what you''ve told me, Ethan does not seem to have some of the other typical symptoms of diabetes, such as urinating frequently during the day, losing weight, or feeling unusually thirsty or hungry. That is reassuring. However, given your family history, I think it is absolutely right to check — I would like to arrange a urine test and a blood glucose test to put your mind at rest.

I would also like to see Ethan in person so I can examine his tummy and make sure there are no signs of significant constipation or any other concerns.

In terms of what we can do to help at home, one of the most effective things is to keep a diary for the next couple of weeks — recording how much Ethan drinks during the day, when he uses the toilet, and on which nights he wets the bed. This helps us spot patterns and gives us really useful information for guiding his management.

On the dietary side, it is worth encouraging more fibre-rich foods and making sure Ethan is drinking enough water during the day. It is also worth knowing that fizzy drinks can irritate the bladder, so reducing these may help. We will continue his Movicol for now to keep his bowel moving regularly.

A reward chart can also be a really helpful tool at this age — not just for dry nights, but also for positive behaviours like using the toilet before bed, drinking the right amount during the day, or taking his medication. The important thing is to keep it positive and encouraging. Punishing him or taking away rewards he has already earned is not recommended, as it can knock his confidence and make things harder.

If things do not improve after we have addressed the constipation and tried these approaches, there are further options we can explore such as an enuresis alarm or medication called desmopressin. But let''s start with the steps that are most likely to help first.

I will send you some information and point you towards a website called ERIC, which has excellent resources on bedwetting for families. Let''s plan to speak again in two to three weeks to see how Ethan is getting on. Does that sound okay? Do you have any other questions for me?',
  ARRAY[
    'Secondary enuresis — defined as the return of nighttime wetting after at least 6 months of dryness — should prompt a search for an underlying cause, including constipation, UTI, diabetes, and psychological stressors.',
    'Constipation is a common and frequently overlooked contributor to secondary enuresis: faecal loading puts pressure on the bladder, impairing its capacity and control; treating constipation often significantly improves bedwetting.',
    'Urinalysis should be arranged in all children with new-onset enuresis to exclude a UTI and to check for glycosuria, which would raise concern for diabetes mellitus.',
    'A positive reward system focused on achievable behaviours (drinking well during the day, using the toilet before bed, participating in management) is an evidence-based first-line behavioural intervention; punitive approaches should be explicitly discouraged.',
    'Enuresis alarms and desmopressin are second-line options if enuresis persists despite management of any underlying cause and an adequate trial of behavioural strategies.',
    'Family history of Type 1 diabetes in a parent presenting with a child with new-onset secondary enuresis warrants a blood glucose check to screen for diabetes, even in the absence of classic polyuria, polydipsia, and weight loss.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  37,
  'Uncontrolled Asthma in a Young Adult',
  'Respiratory',
  'Telephone consultation',
  false,
  'Zoe Mitchell',
  '17-year-old female',
  ARRAY[]::text[],
  ARRAY['Clenil® Modulite 200 mcg MDI, 1 puff twice daily','Salamol inhaler, used as needed (PRN)'],
  NULL,
  'Patient booked a routine telephone consultation to discuss ongoing concerns about her asthma.',
  'Hi, I just wanted to talk about my asthma. I keep having trouble when I''m playing sport and I''m not sure what to do about it.',
  'You have been getting breathless and wheezy during football matches and training sessions. Sport is really important to you and you train and compete regularly. You often need to use your blue inhaler during a match because your symptoms become quite bad — it usually takes around 30 minutes before you feel better. You take your inhalers as prescribed: the brown inhaler (Clenil) 2 puffs twice daily, and the blue inhaler (Salamol) whenever you get breathless or wheezy. Outside of sport you generally feel fine, although you occasionally wake at night with a cough. You have no known triggers at home such as pets or mould.',
  ARRAY['You experience shortness of breath and wheezing during football but feel well outside of exercise, apart from an occasional night-time cough.','You have no known environmental triggers such as pets or mould at home.','You take your inhalers exactly as prescribed: Clenil 2 puffs twice daily and Salamol as needed for symptoms.','Symptoms during football typically take about 30 minutes to settle after using the blue inhaler.'],
  'You live at home with your parents and a 14-year-old brother. Nobody in the house smokes and you do not smoke yourself. You are currently in sixth form studying for your A-levels and doing well academically.',
  'You are not sure why you keep having these symptoms during football despite using your inhalers.',
  'Your breathlessness and wheezing during football are affecting your performance. Your coaches are beginning to question your fitness, and you are worried this might hold back your chances of progressing in the sport.',
  'You want to find an approach that lets you manage your symptoms properly so that nothing holds you back when you play football.',
  ARRAY[]::text[],
  NULL,
  'Decline any questions that fall outside the details already provided in the scenario. Accept all advice offered by the doctor.',
  ARRAY['Clarify whether asthma symptoms occur only during exercise or whether there are other triggers.','Ask whether the patient experiences night-time cough, wheeze, or breathlessness.','Ask about associated symptoms including palpitations, chest pain, and whether any cough is productive of phlegm.','Ask about the number of previous asthma attacks, use of oral corticosteroids, and any hospital or ICU admissions related to asthma.','Confirm whether the patient takes her inhalers as prescribed and how frequently she uses her reliever.','Ask about tobacco smoke exposure — whether she smokes or lives with anyone who does.','Ask about exposure to mould or pets at home.','Ask about a history of eczema, hay fever, or other medical conditions.','Ask whether she takes NSAIDs, any over-the-counter medications, or has known allergies.','Assess the impact of asthma on her education, sports participation, and overall quality of life.','Check whether she is up to date with flu and COVID-19 vaccinations.','Offer a working diagnosis of poorly controlled asthma and/or exercise-induced asthma.'],
  ARRAY['Offer a face-to-face appointment to examine her chest and check vital signs including oxygen saturation, respiratory rate, and peak flow measurement.','Switch from her current inhaler regimen (SABA + ICS) to a low-dose MART regimen in line with current asthma guidelines. Offer low-dose MART such as Symbicort 100/6 or Fostair 100/6: 1 puff twice daily for maintenance and 1 puff as needed for symptom relief, with a maximum of 8 puffs per day. Explain that this replaces her current two inhalers with a single combination inhaler.','Advise her to take one puff of the MART inhaler before exercise such as football to help prevent exercise-induced asthma symptoms.','If prescribing a pMDI such as Fostair pMDI, prescribe with a spacer device; note that a spacer is not required for dry powder inhalers such as Symbicort Turbuhaler or Fostair Nexthaler.','Encourage her to stay up to date with influenza and COVID-19 vaccinations, as viral infections can trigger asthma flare-ups.','Provide a personalised asthma action plan (PAAP) if she does not already have one, covering daily medication use, inhaler technique, how to recognise worsening symptoms, what to do in an asthma attack, and when to seek help.','If she already has a PAAP, update it to reflect her new MART treatment plan.','Advise her to always carry her inhaler and ensure those around her — including family, teachers, and coaches — know her asthma management plan and what to do in an emergency.','Arrange follow-up in 4–8 weeks with yourself or the asthma nurse to review her response to the MART regimen and adjust treatment if needed.','Provide safety-netting advice: if symptoms worsen despite using the MART inhaler, or she experiences severe breathlessness, she should seek urgent medical attention via the GP, out-of-hours services, or by calling 999 or attending A&E if severe.'],
  'Thank you so much for calling today, Zoe — it''s really helpful that you''ve explained what''s been happening so clearly. Based on what you''ve told me, it sounds as though your asthma is not fully under control at the moment, particularly when you''re playing football. The fact that you need your blue inhaler during a match, and that it takes around half an hour to feel better, tells me that your current treatment may not be keeping your airways as calm as we''d like.

What you''re experiencing is often called exercise-induced asthma. Physical activity causes the airways to narrow, which leads to that familiar feeling of breathlessness, tightness, and wheeze. For someone as active as you — training regularly and aiming to play at a high level — it''s really important we get this sorted so it doesn''t hold you back.

The good news is that asthma guidelines have evolved, and there''s now a simpler, more effective approach for someone in your situation. Rather than using two separate inhalers — your brown preventer and blue reliever — we can move you on to a single combination inhaler called Symbicort or Fostair. This is used in a way called MART, which stands for Maintenance and Reliever Therapy.

With MART, you take one puff of this inhaler twice a day every day to prevent symptoms, and then use the same inhaler for quick relief whenever symptoms come on — just as you''ve been using your blue inhaler. You can also take one puff before football training or a match to help stop symptoms before they start. The maximum you can take in a day is eight puffs in total. Having one inhaler to do everything is much more straightforward, and evidence shows it works very well.

I''d also like to see you face to face today so I can listen to your chest, check your oxygen levels and peak flow, and make sure your inhaler technique is right. If it''s a dry powder inhaler like Symbicort Turbuhaler, you won''t need a spacer, but we''ll go through exactly how to use it. I''ll also put together or update a personalised asthma action plan for you — a written guide that covers your daily medications, how to recognise if things are getting worse, and what to do if you have an asthma attack.

Please make sure you always have your inhaler with you, and let your coaches and family know about your plan in case they ever need to help in an emergency. I''d also encourage you to keep up with your flu and COVID-19 jabs, as viral infections are one of the most common triggers for asthma flare-ups.

We''ll book a follow-up in four to eight weeks — with me or our asthma nurse — to check how you''re getting on with the new inhaler. And in the meantime, if your breathing gets significantly worse despite using the inhaler, please don''t wait — contact us, call 111, or call 999 if it''s severe. Does that all make sense?',
  ARRAY['Exercise-induced asthma in an active young person suggests poorly controlled asthma; the need for a reliever during activity and prolonged recovery time are red flags for step-up of treatment.','Current NICE/BTS asthma guidelines support switching from a separate ICS and SABA to a low-dose MART regimen (e.g. Symbicort 100/6 or Fostair 100/6: 1 puff twice daily plus 1 puff as needed, maximum 8 puffs per day).','Taking one puff of the MART inhaler before exercise can help prevent exercise-induced bronchospasm.','A spacer is required with pMDI formulations (e.g. Fostair pMDI) but is not needed for dry powder inhalers (e.g. Symbicort Turbuhaler or Fostair Nexthaler).','All patients with asthma should have a personalised asthma action plan (PAAP) and be up to date with flu and COVID-19 vaccinations.','Asthma reviews should assess inhaler technique, trigger avoidance, vaccination status, and the impact of asthma on daily life and education.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  38,
  'Visible haematuria in Older Adult',
  'General Practice',
  'Telephone consultation',
  false,
  'Raymond Clarke',
  '69-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  'Patient was seen yesterday at an out-of-hours service.

Letter from Riverside Out of Hours Service:

Dear GP,
RE: Raymond Clarke | 69 years old | Male

The above-named patient was seen at the out-of-hours service yesterday with a five-day history of blood in his urine. He was clinically well, with no dysuria, abdominal pain, or systemic symptoms. Urine dipstick showed 4+ blood, with no leucocytes or nitrites. No treatment was required at the time. He was advised to follow up with his GP for further assessment.

Seen by: Patricia Owen, Advanced Nurse Practitioner',
  'Patient booked an urgent appointment today following advice from the out-of-hours team to see his GP.',
  'Hello doctor, the nurse I saw at the out-of-hours service yesterday asked me to book in with you today.',
  'You had three episodes of blood in your urine, which you first noticed six days ago. You have not seen it since the day before yesterday. You are following up because the out-of-hours nurse practitioner advised you to see your GP.',
  ARRAY['You feel otherwise well — no pain when passing urine, no fever, and no abdominal or back pain. You do not feel unwell. You have not had any weight loss, changes in appetite, and your bowels are normal.','You were quite shaken when you noticed the blood in your urine, as this has never happened before.','You are not on any regular medication apart from occasional co-codamol for joint pain.'],
  'You do not smoke or drink alcohol. You are a retired postman. You live with your wife of 32 years and have no other sexual partners. There is no family history of bowel cancer, and you have never seen blood in your urine before.',
  'You wonder whether this might be connected to the yellow fever vaccination you received eight days ago at a private travel clinic, as you are preparing for a trip to Kenya.',
  'The experience frightened you and you are worried it could be a sign of something serious such as cancer.',
  'You would like the doctor to explain what might be causing this and to advise you whether it is safe to travel to Kenya next week for your 32nd wedding anniversary trip with your wife. You will be away for three weeks.',
  ARRAY['If the doctor suggests cancelling or postponing your trip, explain that this is not possible — you have been planning it for over a year and it marks a very significant milestone anniversary. Make it clear how important this trip is to you, but remain polite and open to advice.'],
  NULL,
  'Decline any questions not covered by the details already provided in the scenario. Accept all advice offered by the doctor.',
  ARRAY['Clarify the onset, duration, and recurrence of the haematuria.','Ask whether the haematuria was painful or painless — painless visible haematuria is more suspicious for malignancy.','Ask about other urinary symptoms such as dysuria or urinary frequency and urgency, to help rule out a UTI.','Ask about other lower urinary tract symptoms including nocturia, weak stream, hesitancy, and terminal dribbling.','Ask about fever, chills, or rigors to assess for systemic infection, UTI, or prostatitis.','Ask about perineal, rectal, suprapubic, or testicular pain.','Ask about flank pain or abdominal discomfort, keeping renal stones and UTI in mind.','Ask about recent strenuous exercise or trauma, which can occasionally cause transient haematuria.','Ask about bleeding from other sites — gums, bruising, or nosebleeds — to screen for coagulopathy or thrombocytopenia.','Ask about red flag symptoms suggestive of malignancy: weight loss, reduced appetite, night sweats, or palpable lumps or masses.','Ask about use of prescribed or over-the-counter medications, particularly NSAIDs or anticoagulants.','Clarify any previous urological history including haematuria, infections, stones, or prostate problems.','Take a brief sexual history including recent partners or unprotected intercourse, to assess for STI risk.','Ask about symptoms of anaemia such as light-headedness, dizziness, headache, breathlessness, chest pain, or palpitations.','Explore social history including smoking status, alcohol use, and occupational history — particularly exposure to dyes, rubber, aromatic amines, or industrial chemicals, which are risk factors for bladder cancer.','Ask about any family history of urological malignancy.','Explore the patient''s ideas, concerns, and expectations.','Offer a working diagnosis of unexplained visible haematuria, which may be transient in nature, but differentials include urinary tract infection or underlying malignancy such as bladder or renal cancer.'],
  ARRAY['Offer a face-to-face appointment for further assessment, including examination of the abdomen and flanks for tenderness or palpable masses, and a digital rectal examination to assess prostate size and texture.','Offer a repeat urine dipstick and send a midstream urine sample for microscopy and culture to rule out infection.','Arrange blood tests including PSA, urea and electrolytes, liver function tests, C-reactive protein, coagulation profile, and bone profile.','Explain that if the urine culture returns without identifying a clear cause, he will be referred urgently to urology under the two-week wait pathway for further investigations including cystoscopy and imaging of the urinary tract.','Advise the patient that blood in the urine is not a recognised side effect of the yellow fever vaccine, but that you will check this and update him if needed.','Discuss his upcoming travel and gently explore whether it can be postponed to allow timely investigations.','If travel cannot be delayed, advise him to remain contactable so that results can be communicated promptly and next steps discussed.','Advise the patient to obtain comprehensive travel insurance in case medical care is needed while abroad.','Provide safety-netting advice to seek urgent medical attention if haematuria recurs, or if he develops pain, fever, or feels unwell while travelling.','Arrange a follow-up telephone appointment to discuss blood and urine results and plan next steps once investigations are available.'],
  'Thank you for calling in today, Raymond, and I''m really glad the out-of-hours team directed you to us. I can completely understand why seeing blood in your urine would be frightening — it''s not something anyone expects, and it''s absolutely right that we take this seriously.

I want to reassure you that there are several possible explanations for what you''ve experienced, and many of them are not sinister. That said, we have a responsibility to investigate this properly, because visible blood in the urine — what we call haematuria — always warrants a thorough assessment to make sure we''re not missing anything important.

Regarding the yellow fever vaccination: blood in the urine is not a recognised side effect of that vaccine. I''ll look into this further and let you know if I find anything to suggest a link, but I wouldn''t expect that to be the cause.

What I''d like to do first is ask you to come in today so we can examine you — I''d want to feel your abdomen and check your back for any tenderness, and I''d also like to do a brief rectal examination to assess your prostate, which is a routine part of the assessment for any man in your situation. We''ll also repeat a urine dipstick test and send a sample to the laboratory to check for any infection.

I''ll arrange a set of blood tests as well, including a PSA — which is a prostate-related marker — along with kidney function tests, inflammatory markers, and a clotting screen. This gives us a much clearer picture of what might be going on.

If all these tests come back without identifying a clear cause, the next step would be a referral to the urology team under what we call the two-week wait pathway. This is a priority referral route that ensures you''re seen quickly, and it would involve a camera examination of the bladder — called a cystoscopy — as well as imaging of the kidneys and urinary tract.

I understand your trip to Kenya is enormously important to you, and I don''t want to take that away. If travel genuinely cannot be postponed, please make sure you have comprehensive travel insurance in place before you go, so that if anything comes up while you''re abroad, you''re covered. I''d also ask that you keep your phone accessible so we can reach you once results are back. And please — if the bleeding returns, or you develop pain, a fever, or feel generally unwell while you''re away, seek medical attention straightaway without delay. We can then follow up properly on your return.',
  ARRAY['Painless visible haematuria in an older adult must be investigated urgently for underlying malignancy, including bladder cancer and renal cell carcinoma, even if haematuria is transient or has resolved.','Initial assessment should include urine dipstick, midstream urine culture, blood tests (PSA, U&Es, LFTs, CRP, coagulation, bone profile), abdominal examination, and a digital rectal examination to assess the prostate.','Patients with unexplained visible haematuria and no obvious benign cause should be referred urgently via the two-week wait pathway to urology for cystoscopy and upper tract imaging.','Occupational exposure to aromatic amines, rubber, and dyes is a recognised risk factor for bladder cancer and should be explored in the social history.','Yellow fever vaccine does not cause haematuria; however, patient-held beliefs about causation should be acknowledged and addressed respectfully.','If a patient cannot postpone travel during investigation, advise comprehensive travel insurance and ensure they remain contactable for results; safety-net clearly regarding recurrence of symptoms abroad.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  39,
  'Recurrent Fracture in Female Athlete',
  'Rheumatology & Musculoskeletal',
  'Telephone consultation',
  false,
  'Hannah Reid',
  '22-year-old female',
  ARRAY[]::text[],
  ARRAY['No known drug allergies'],
  'Letter from Orthopaedics

Dear GP,
Hannah Reid, a 22-year-old gymnast and competitive athlete, was admitted following a fall resulting in a left wrist fracture. She underwent open reduction and internal fixation (ORIF) of the left wrist. Hannah is now 6 weeks post-ORIF and has made a good recovery. The surgical wound is well-healed, and radiographic imaging shows satisfactory alignment and healing of the fracture. She has regained near-full range of motion in the left wrist and is currently pain-free. She has completed her postoperative physiotherapy programme and no longer requires specialist follow-up in the orthopaedic clinic. Given her history of multiple fractures within the past year, I recommend a review with her GP to discuss the possibility of an underlying condition contributing to these recurrent fractures. I have now discharged her back to your care.

Regards,
Mr Jonathan Hale, FRCS(Ortho), MCh
Consultant Trauma and Orthopaedic Surgeon',
  'Patient has booked a telephone consultation to discuss the orthopaedic discharge letter and her history of recurrent fractures.',
  'Hello, I was asked to book in with my GP by the bone surgeon who operated on my wrist. I''ve had a few fractures recently and they want someone to look into why.',
  'You are a 22-year-old gymnast calling because your orthopaedic surgeon recommended a GP follow-up to explore the reasons behind your recurrent fractures. Seven weeks ago you fractured your left wrist after a minor fall during gymnastics training. You had surgery and have recovered well, with good wrist movement and no ongoing pain. However, this is now your third fracture in the past year — you previously fractured your right elbow nine months ago and your right shoulder seven months ago.',
  ARRAY['You have not had a period for the past 6–7 months and are unsure why. You are not pregnant — you took a pregnancy test three days ago which was negative, as expected, since you have not been sexually active for well over a year.','You believe you eat and drink well. You are not preoccupied with your weight or afraid of gaining weight. Your diet is mainly high in protein and you deliberately avoid carbohydrates to maintain a physique suited to gymnastics. You are aware that you are slim but you are not obsessed with your weight.','You have never used laxatives or made yourself vomit after eating.','You exercise 3–4 hours daily as part of your training programme, with the aim of qualifying for the Olympics.'],
  'You do not smoke and do not drink alcohol. You currently live with your parents. You work part time at a local garden centre.',
  'You are starting to wonder whether you might have weak bones or some underlying condition that makes you prone to fractures.',
  'You are worried that these repeated fractures could affect your ability to return to high-level gymnastics and compete professionally.',
  'You would like the GP to investigate what is causing these fractures and advise you on how to prevent further injury.',
  ARRAY[]::text[],
  'How can I prevent future fractures?',
  'Decline any questions not covered by the details already provided in the scenario. Accept all advice offered by the doctor.',
  ARRAY['Ask about the nature of the fall that caused the wrist fracture — clarify whether it was a high-impact injury or a minor fall.','Ask whether the patient has experienced any other recent falls or similar incidents.','Ask about hand dominance and confirm whether the patient is right-handed, and explore how she is coping functionally now that her dominant hand is affected.','Ask when the previous fractures occurred and whether they were caused by significant trauma or minor accidents.','Ask about her daily diet, including whether she consumes adequate calcium and vitamin D, and whether she follows any dietary restrictions.','Ask about concerns around weight and dietary behaviours, including whether she restricts food for appearance or performance reasons, and screen for disordered eating using key questions such as: "Do you ever make yourself sick because you feel uncomfortably full?", "Do you worry that you have lost control over how much you eat?", "Have you recently lost more than one stone in a 3-month period?", "Do you believe yourself to be fat when others say you are too thin?", and "Would you say that food dominates your life?"','Ask about her menstrual cycle — whether her periods are regular, if she has had any recent changes or missed periods, and whether there is any possibility of pregnancy.','Ask about her training routine, including how many hours per day she exercises and the intensity of her sessions.','Ask whether any professional has advised her to reduce or modify her activity levels following the fractures.','Ask about the use of any over-the-counter medications, particularly steroids or supplements.','Ask about family history of osteoporosis or other bone conditions.','Ask about other health concerns including unexplained weight loss, fatigue, or systemic symptoms.','Make a working diagnosis of Relative Energy Deficiency in Sport (RED-S).'],
  ARRAY['Arrange blood tests to investigate underlying causes: Full Blood Count (FBC), Urea and Electrolytes (U&Es), Liver Function Tests (LFTs), Thyroid Function Tests, HbA1c, Calcium and Bone Profile, Vitamin D level, and a full hormone profile including FSH, LH, Oestradiol, and Prolactin.','Refer for a DEXA scan immediately without calculating a FRAX score, given her BMI being below 18.5 and a history of multiple fractures, which already places her at high risk for osteoporosis.','Advise that depending on DEXA results, if there is evidence of low bone density or osteoporosis, liaison with a rheumatologist may be necessary for further specialist input.','If hormone levels are abnormal, refer to endocrinology for assessment. Inform the patient that hormone replacement therapy may be considered by the endocrinologist depending on findings.','Assess for calcium and vitamin D deficiency by asking about dietary intake and sun exposure, and use a calcium calculator to estimate her intake.','Advise that supplementation will be started if calcium or vitamin D levels are found to be low.','Refer her to a dietitian to help optimise her nutrition and ensure she is meeting her body''s energy and nutrient needs to support bone health and overall wellbeing.','Advise on modifying exercise levels by recommending a reduction in high-intensity training to support healthy weight restoration and reduce fracture risk, and suggest involving a sports physiotherapist to create a safe and balanced plan that supports her athletic goals without compromising bone health.','Encourage weight-bearing and resistance exercises, as tolerated, to help build bone and muscle strength.','Safety net: advise Hannah to recontact the surgery if she experiences another fracture, significant pain, or worsening symptoms.','Arrange a follow-up appointment to review blood test and DEXA scan results, discuss the diagnosis in more detail, and plan further management.'],
  'Thank you for calling today, Hannah — and for explaining your situation so clearly. I''m really glad your orthopaedic surgeon flagged this, because three fractures in one year is something we do need to look into carefully, especially when the injuries have occurred following relatively minor falls.

What you''ve described gives me quite an important picture. You train intensely for several hours every day, you follow a high-protein, low-carbohydrate diet to maintain your physique, and your periods have stopped over the past six to seven months. Taken together, these things point strongly towards a condition called Relative Energy Deficiency in Sport — or RED-S for short.

RED-S occurs when the body doesn''t have enough energy coming in to meet both the demands of intense exercise and the needs of normal bodily functions. Even though you feel you eat well, when carbohydrates are significantly reduced and training load is high, the body can fall into what we call a state of low energy availability. To protect its vital organs, the body starts to shut down less immediately essential functions — including the menstrual cycle and bone maintenance. Over time, this leads to bones becoming thinner and more fragile, which explains why they are fracturing after what would normally be minor incidents.

This isn''t about your weight, and it isn''t about eating disorders — many highly dedicated athletes develop RED-S without realising it, simply because the demands they place on their bodies outpace the energy they take in.

The good news is that with the right support, we can address this and work towards protecting your bones and your long-term sporting career. I''d like to start by arranging some blood tests — to check your hormone levels, bone markers, vitamin D, calcium, kidney and liver function, and thyroid. I also want to arrange a DEXA scan, which is a specialised X-ray that measures your bone density. Given your age and the number of fractures you''ve had, this is something we''ll arrange directly without needing to calculate a risk score first.

Depending on your results, I may also refer you to an endocrinologist — a specialist in hormones — who can consider whether hormone replacement therapy might be appropriate as a short-term measure to protect your bones while we address the underlying energy imbalance. I''d also like to refer you to a dietitian, who can help you optimise your nutrition in a way that actually supports your training and bone health rather than working against it. And I''ll suggest involving a sports physiotherapist who can help you adapt your training in a safe and sustainable way.

For now, Hannah, I''d really encourage you to speak with your coach or training team about what you''ve learned today. The goal here is not to stop you competing — it''s to make sure your body is strong enough to support the ambitions you have.',
  ARRAY['Relative Energy Deficiency in Sport (RED-S) — formerly known as the Female Athlete Triad — occurs when energy intake is insufficient to meet the combined demands of exercise and normal physiology, leading to amenorrhoea, low bone density, and recurrent fractures.','RED-S is common in sports that prioritise low body weight or aesthetics (e.g. gymnastics, long-distance running, dance) and can occur without a formal eating disorder.','Key investigations include FBC, U&Es, LFTs, TFTs, HbA1c, calcium and bone profile, vitamin D, and a full hormone profile (FSH, LH, Oestradiol, Prolactin). A DEXA scan should be arranged directly if BMI is below 18.5 or there is a history of multiple fragility fractures.','Do not use the combined oral contraceptive pill (COCP) to regulate periods in RED-S — it masks the true hormonal status and can worsen bone health. Hormone replacement therapy under specialist guidance is preferred.','Management requires a multidisciplinary team: dietitian, sports physiotherapist, endocrinologist (for hormone assessment), rheumatologist (if osteoporosis is confirmed), and a psychologist if disordered eating is suspected.','Amenorrhoea in an athlete should never be dismissed as normal or desirable — it is a clinical red flag for low energy availability and bone loss.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  40,
  'Pregnant Woman With Epilepsy',
  'Gynaecology & Women''s Health',
  'Telephone consultation',
  false,
  'Michelle Harper',
  '26-year-old female',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'Patient has booked a telephone consultation to discuss her epilepsy management now that she has found out she is pregnant.',
  'Hi doctor, I''ve just found out I''m pregnant and I''m really not sure what I should do about my epilepsy medications. I''m quite worried.',
  'You found out you are pregnant a few days ago using a home pregnancy test. You are not sure how far along you are. You have been on antiepileptic medications for your epilepsy and you are concerned about whether they are safe for the baby.',
  ARRAY['You are worried about whether your epilepsy medications could harm your baby''s development.','You are wondering whether you should stop your medications straight away to protect the baby.','You are not sure how to access antenatal care or who will look after you during the pregnancy.'],
  'You do not smoke or use alcohol or recreational drugs. You work as a sales assistant in a clothing shop. You live with your partner. You do not drive.',
  'You are unsure what the correct next steps are regarding managing your epilepsy during the pregnancy.',
  'You are particularly worried about the impact of your antiepileptic medications on your baby''s health and development.',
  'You are wondering whether you should stop your medications immediately to protect the baby.',
  ARRAY[]::text[],
  NULL,
  'Decline any questions not covered by the details already provided in the scenario. Accept all advice offered by the doctor.',
  ARRAY['Ask when and how the patient confirmed the pregnancy — for example, by urine pregnancy test, home test, or scan.','Ask about the last menstrual period and whether the patient has any idea how far along she might be.','Ask whether the pregnancy was planned or unplanned.','Ask about her epilepsy history — frequency of seizures, when the last seizure occurred, and any recent changes in seizure control.','Ask whether the patient drives.','Ask whether she is currently taking any over-the-counter medications or supplements.','Ask about smoking, alcohol, or recreational drug use.','Ask if she has been pregnant before, and if so, inquire about any complications or relevant issues in previous pregnancies.','Ask about her home environment — who she lives with, whether she has adequate support, and her general living situation. Screen for safeguarding concerns by asking whether she feels safe in her relationship and whether anyone is pressuring her to make decisions against her will.','Ask whether there have been any symptoms in this pregnancy so far, such as abdominal pain, vaginal bleeding, or cramping.','Explore her ideas, concerns, and expectations.'],
  ARRAY['Reassure the patient and advise her clearly not to stop her antiepileptic medications. Explain that poorly controlled seizures during pregnancy can pose a greater risk to both mother and baby than the medications themselves.','Discuss the potential risks to the fetus from antiseizure medications, including an increased risk of congenital malformations, neurodevelopmental disorders, and fetal growth restriction. However, make clear that abruptly stopping epilepsy medication carries a greater risk, as uncontrolled seizures can lead to trauma, miscarriage, or harm to both mother and baby.','Arrange an urgent referral to a neurologist so that her antiepileptic regimen can be reviewed and an individualised management plan developed.','Encourage her to register for antenatal care as soon as possible. This can be done via the NHS Badger Notes app — offer to text her the link for easy access. Explain that she will likely be under the care of a specialist team throughout her pregnancy.','Explain that the midwife will carry out initial assessments including blood tests, urine checks, blood pressure monitoring, and height and weight measurements, and will arrange an ultrasound scan to help accurately date the pregnancy.','Prescribe folic acid 5mg daily — the recommended high-dose supplement for women taking antiepileptic drugs. Advise her to take this until her dating scan confirms gestational age, and then continue until 12 weeks gestation.','Recommend a daily vitamin D supplement of 10 micrograms throughout the pregnancy to support bone and immune health.','Encourage her to notify her pregnancy to the UK Epilepsy and Pregnancy Register, which monitors outcomes and contributes to national guidance on epilepsy in pregnancy.','Offer appropriate vaccinations: influenza and COVID-19 vaccines may be given at any stage of pregnancy; pertussis (whooping cough) vaccine from 16 weeks gestation; and RSV (Respiratory Syncytial Virus) vaccine from 28 weeks gestation.','Arrange a follow-up call in 2 weeks to check whether she has registered with antenatal services and whether she has been seen by a specialist.','Safety net: advise her to contact the practice or seek urgent medical help if she has any concerns, seizure activity, or new pregnancy-related problems.'],
  'Thank you so much for calling today, and congratulations on your pregnancy — even though I can completely understand that this news brings with it a lot of questions and worries, especially when you have epilepsy to manage at the same time.

I want to address your most pressing concern straight away, Michelle, and that is the question of your epilepsy medications. Please do not stop them. I know it feels like the right instinct — to protect your baby by removing any medication from the equation — but stopping antiepileptic drugs suddenly during pregnancy can actually be far more dangerous than continuing them. If your seizures become poorly controlled, there is a real risk of falls, trauma, reduced oxygen to the baby, and in rare cases, serious harm to you or your pregnancy. The medications themselves do carry some risks, but these are best managed with specialist support, not by stopping treatment.

What I''d like to do is refer you urgently to a neurologist who specialises in epilepsy. They will review your current medications, discuss the specific risks associated with whichever drug you are on, and help tailor a plan that keeps both you and your baby as safe as possible throughout the pregnancy.

In the meantime, I would like to start you on a higher-dose folic acid supplement — 5mg daily. This is different from the standard dose people take and is specifically recommended for women on antiepileptic medication, as it helps reduce the risk of certain birth defects. I would also like you to take vitamin D — 10 micrograms a day — throughout the pregnancy to support your bone health and your baby''s development.

The next important step is to register with your midwife for antenatal care as soon as you can. You can do this through the NHS Badger Notes app — I can text you the link if that would help. Because of your epilepsy, you will likely be cared for by a specialist team, so it''s important to get this in place quickly. The midwife will see you for your first appointment, carry out some initial blood tests and checks, and arrange a dating scan to confirm how far along you are.

I''d also strongly encourage you to register your pregnancy with the UK Epilepsy and Pregnancy Register. This is a national database that helps improve understanding of epilepsy in pregnancy and can also be a helpful source of support.

Finally, I''d like to make sure your vaccinations are up to date. The flu and COVID jabs are safe at any stage of pregnancy, the whooping cough vaccine is offered from 16 weeks, and the RSV vaccine from 28 weeks. We''ll go through all of these with you as the pregnancy progresses.

I''ll book a follow-up call for you in two weeks to check that everything is in motion. And please — if you experience a seizure, any pain, bleeding, or anything else that worries you, contact us straight away or call 999 if it''s urgent.',
  ARRAY['Women with epilepsy who are or may become pregnant must not stop antiepileptic medications without specialist review — uncontrolled seizures in pregnancy pose a greater risk to mother and fetus than the medications themselves.','All women with epilepsy of childbearing potential should be prescribed folic acid 5mg daily (not the standard 400 micrograms) before conception and throughout the first trimester, to reduce the risk of neural tube defects.','Urgent referral to neurology is required to review the antiepileptic regimen and develop an individualised management plan for the pregnancy.','Daily vitamin D 10 micrograms should be recommended throughout pregnancy for all women, including those with epilepsy.','Women should be encouraged to register with their midwife promptly (via NHS Badger Notes), notify the UK Epilepsy and Pregnancy Register, and receive pregnancy-specific vaccinations (flu/COVID at any stage; pertussis from 16 weeks; RSV from 28 weeks).','Safeguarding and social history are important in any unplanned or newly discovered pregnancy — always explore home circumstances, support structures, and whether the patient feels safe.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  41,
  'Advanced COPD',
  'Respiratory',
  'Telephone consultation',
  false,
  'Graham Norris',
  '70-year-old male',
  ARRAY[]::text[],
  ARRAY['Trimbow® NEXThaler 87/5/9 mcg – 2 inhalations twice daily','Co-codamol – 1–2 tablets every 4–6 hours PRN; maximum 8 tablets/day','Amlodipine 10 mg once daily','Ramipril 5 mg once daily','Atorvastatin 20 mg at night','Sensitivity to Azithromycin (GI side effects)'],
  'Letter from Respiratory Specialty

RE: Mr Graham Norris | 70 years | Male

Dear GP,

I am writing to update you regarding the above-named patient, who was recently discharged from our care following a two-week hospital admission for an infective exacerbation of chronic obstructive pulmonary disease (COPD).

Mr Norris has a history of frequent exacerbations despite maximal inhaled therapy. He had previously been trialled on Roflumilast 500 micrograms once daily, which was discontinued after two months due to lack of clinical benefit. In view of persistent exacerbations, we commenced Azithromycin 500 mg three times per week for a trial period of six months. Unfortunately, this produced no significant reduction in exacerbation frequency, and the patient experienced gastrointestinal side effects including abdominal discomfort and loose stools. We held a detailed discussion with Mr Norris regarding the options of either reducing the dose to 250 mg three times per week for a further six months or stopping the medication altogether. After careful consideration, he chose to discontinue Azithromycin.

Mr Norris remains under your care in the community. Should he require further specialist input or support from our team, please do not hesitate to get in touch.

Yours sincerely,
Dr Caroline Obi, MBBS FRCP
Consultant Respiratory Physician',
  'Patient has booked a routine telephone consultation to discuss his concerns about his COPD.',
  'Hi doctor, I''d like to talk about my COPD. It''s been getting steadily worse and I really don''t know what to do anymore.',
  'You feel your COPD has been progressively worsening. Your main symptom is severe breathlessness. You now become breathless after walking less than 100 metres. You do not have chest pain, palpitations, leg swelling, waking at night gasping for air (paroxysmal nocturnal dyspnoea), or difficulty lying flat. You have been using your inhalers regularly as prescribed and have always attended your follow-up appointments. You were recently discharged from the respiratory clinic and do not wish to return for further hospital-based treatment or specialist reviews. You are mostly bedbound and rely heavily on your wife for daily support. Unfortunately, she has chronic back pain and struggles to manage. You are exhausted by repeated hospital admissions and do not want to try further medications that are likely to cause side effects without offering much benefit.',
  ARRAY[]::text[],
  'You are an ex-smoker and do not drink alcohol. You live at home with your wife. You are a retired lorry driver. Your son comes every fortnight to do the shopping.',
  'You believe your COPD is clearly deteriorating. You want to avoid further hospital admissions or specialist referrals and would prefer all your care to be managed through your GP.',
  'You are beginning to feel like a burden to your wife, who is already dealing with her own health problems — chronic back pain — which limit what she can do to help you.',
  'You would like the GP to help improve your breathing and to explain clearly what options and next steps are available given your current situation.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY['Ask about breathlessness — how severe it is, how far the patient can walk, whether it occurs at rest, and whether there is any associated wheeze.','Ask whether he becomes breathless when lying flat (orthopnoea) or wakes at night gasping for air (paroxysmal nocturnal dyspnoea), to help rule out heart failure.','Ask about cough — if present, ask about sputum production including colour and quantity, and about any blood in the sputum (haemoptysis).','Ask about chest pain, palpitations, or chest tightness to consider possible cardiac causes.','Ask about fever or chills to identify possible signs of infection.','Ask about fatigue, weight loss, or night sweats to explore constitutional symptoms or possible malignancy.','Ask about current inhaler use — how often he uses them and whether he is confident with the correct technique.','Ask whether he has ever been considered for home oxygen.','Ask about the impact on daily life — washing, dressing, toileting, and moving around the house.','Ask about the home situation — who lives with him, what support is available, how his wife is coping, and whether any carers are involved or a social care needs assessment has been done.','Ask how many exacerbations and hospital admissions he has had in the past year and whether he has recently needed antibiotics or oral steroids.','Ask about mood — whether he has been feeling low, anxious, or overwhelmed, as patients with chronic disease and recent admissions are at higher risk of depression and emotional distress.','Ask about smoking history, alcohol use, and previous occupation.','Ask about flu, pneumococcal, and COVID-19 vaccination status.','Ask whether there have been any previous discussions about ceilings of care, advance care planning, or DNACPR.','Make a working diagnosis of Advanced (End-Stage) COPD.'],
  ARRAY['Acknowledge and validate the patient''s concerns. Gently explain that COPD is a progressive, long-term condition and that, based on what he has described, he appears to be in the advanced or end-stage phase. The current goal of care is to maximise comfort and quality of life through a palliative approach rather than to cure the disease.','Address breathlessness using both non-pharmacological and pharmacological strategies.','Non-pharmacological approaches include advising on simple measures to relieve breathlessness such as keeping the room cool and improving air circulation with a fan or open window. Refer to a physiotherapist who can offer home visits and support with breathing techniques and appropriately tailored physical activity.','Advise the patient that any physical activity recommended by the physiotherapist will not be strenuous and will be tailored to his individual level of ability — this may include simple movements such as standing up briefly once an hour.','For pharmacological management, consider switching the patient from co-codamol to a low-dose oral morphine preparation, carefully titrated, to help reduce the sensation of breathlessness. Opioids should be prescribed alongside regular laxatives and consideration of an anti-emetic to manage side effects.','Consider a home nebuliser trial if symptoms remain poorly controlled or if the patient has difficulty using inhalers.','Offer a trial of benzodiazepines if anxiety or agitation is contributing to breathlessness: Lorazepam may be used for acute relief (short-acting); diazepam for ongoing anxiety (longer-acting); and midazolam can be considered for intractable breathlessness, either as needed or via syringe driver in a palliative care setting.','Advise the patient that if the above measures do not adequately control his breathlessness, oxygen therapy may be considered — but this would require referral to a specialist and would depend on whether he meets specific eligibility criteria.','Offer a home visit to discuss Advance Care Planning: explore the patient''s values, preferences, and concerns regarding future care; discuss advance decisions; preferred place of care; ceiling of treatment options; and DNACPR.','Refer to the frailty or occupational therapy team for a home assessment to determine what additional support is needed, and to explore carer options given that his wife is struggling.','Advise that you will complete the SR1 form to support access to benefits and involve the social prescriber to explore additional financial entitlements and community support.','Arrange a structured medication review with the clinical pharmacist to evaluate current medications, deprescribe where appropriate, and ensure the patient is not burdened by unnecessary treatments.','Safety net: advise the patient to seek urgent medical advice if his condition worsens or he has any concerns.','Arrange a follow-up telephone call in 2 weeks to review how things are going.'],
  'Thank you for calling today, Graham, and for being so open about how things have been. I can hear how exhausting and disheartening this has been for you, and I want you to know that I''m here to support you — not to push you towards anything you''ve already decided isn''t right for you.

Based on everything you''ve told me, it does sound as though your COPD has reached what we call an advanced or end-stage phase. I know those words can sound alarming, but what they really mean is that we need to shift our focus. Rather than continuing to pursue treatments aimed at slowing the disease, our goal now is to make sure every day is as comfortable as possible, that your breathing is managed as well as it can be, and that you feel in control of what happens next. This is called palliative care — and it is very much about living well, not giving up.

For your breathlessness, there are several things we can try. On the practical side, keeping a window open or having a small fan directed towards your face can genuinely make a difference to how breathless you feel — it''s a simple trick but many people find it helps. I''d also like to arrange for a physiotherapist to visit you at home. They can guide you through very gentle breathing techniques and small movements — nothing demanding, just things like standing briefly every hour — which can help your body cope better over time even when you''re mostly resting.

On the medication side, I''d like to talk to you about switching from co-codamol to a low-dose liquid morphine preparation called Oramorph. In very small doses, morphine is actually one of the most effective treatments we have for the sensation of breathlessness — it takes the edge off that feeling of air hunger. I''d start you on a low dose a few times a day and adjust it carefully depending on how you respond. We''d also give you something to prevent constipation, as that''s a common side effect of morphine. If anxiety is adding to your breathlessness — which it very often does — there are medications we can try for that as well.

If your inhalers are becoming difficult to use, we could also look at a nebuliser — a machine that turns your medication into a fine mist that''s much easier to breathe in. And if, after all of this, your breathlessness is still not well controlled, oxygen is something we can explore further — though it would need to be assessed properly by a specialist first.

I''d very much like to arrange a home visit, Graham — not just to see you, but so we can have a proper conversation with you and your wife about what you''d both like going forward. This includes things like where you''d most like to be cared for, what treatments you do and don''t want, and the question of resuscitation. I know these are not easy conversations, but having them means we can make sure your wishes are always respected, whatever happens.

I can also see that your wife is under a lot of pressure, and I don''t want that to continue without proper support in place. I''ll ask our occupational therapy and frailty teams to visit and assess what help is available — whether that''s a package of care, equipment at home, or additional carers coming in. I''ll also complete an SR1 form, which can help you access certain financial benefits more quickly, and ask our social prescriber to be in touch about any other support you might be entitled to. Finally, I''ll ask our clinical pharmacist to go through your medications and see whether anything can be safely stopped — there''s no point taking things you don''t need.

I''ll call you again in two weeks to see how things are going. And please — if anything gets significantly worse before then, don''t wait. Call us, and we''ll do everything we can.',
  ARRAY['End-stage COPD is characterised by severe functional limitation, frequent exacerbations despite maximal therapy, and breathlessness at minimal exertion or at rest; management shifts from disease modification to a palliative, symptom-focused approach.','Non-pharmacological strategies for breathlessness include cool air (fan or open window) directed at the face and physiotherapy-led breathing techniques and graded activity adapted to the patient''s capabilities, including bedbound patients.','Low-dose oral morphine, carefully titrated, is an evidence-based treatment for refractory breathlessness in advanced COPD; it must be co-prescribed with regular laxatives and consideration of an anti-emetic.','Benzodiazepines (Lorazepam for acute relief, diazepam for ongoing anxiety, midazolam via syringe driver for intractable breathlessness in the palliative setting) can be used when anxiety or agitation contributes to breathlessness.','Advance Care Planning in advanced COPD should cover preferred place of care, ceiling of treatment, DNACPR, and advance decisions; the SR1 form facilitates faster access to certain financial benefits.','Home assessment by occupational therapy or frailty teams, involvement of a social prescriber, and structured medication review (with deprescribing where appropriate) are all important components of holistic end-of-life care in the community.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  42,
  'Elevated Blood Pressure in Middle-Aged Man',
  'Cardiology',
  'Telephone consultation',
  false,
  'Martin Pearce',
  '52-year-old male',
  ARRAY[]::text[],
  ARRAY['No known drug allergies'],
  'A&E Clinical Summary:

Dear GP,
RE: Martin Pearce | 52 years old | Male

The above-named patient presented to A&E with a right wrist laceration, which was managed appropriately. During the visit, elevated blood pressure readings were noted: 160/100 mmHg and 162/98 mmHg. He was advised to follow up with his GP to discuss possible initiation of antihypertensive treatment.

Report signed by: Dr Helen Marsh, MBBS, FRCEM
Emergency Medicine Consultant',
  'Patient has booked a telephone appointment following advice from the A&E team to discuss his blood pressure readings.',
  'Hello doctor, I''d like to talk about starting blood pressure tablets. The A&E team told me my blood pressure was high when I was seen for my wrist.',
  'You are Martin Pearce, a 52-year-old man. You attended A&E after cutting your right wrist at work. While you were there, the team noticed your blood pressure was raised. Your wrist is healing well and you have an appointment with the hand surgery team in two days for suture removal and a check-up. You are fit and well with no known medical conditions. You are worried about the risk high blood pressure can pose and want to discuss starting medication.',
  ARRAY[]::text[],
  'You are a non-smoker and do not drink alcohol. You live with your wife and two teenage children. You work as a landscape gardener. Your diet is not great — you tend to rely on fast food and takeaways most days. Your paternal grandmother had hypertension and died of a stroke.',
  'You think you probably do have high blood pressure.',
  'Your paternal grandmother had hypertension and died of a stroke. You are worried the same thing could happen to you.',
  'You would like to start antihypertensive medication now.',
  ARRAY['If the doctor suggests waiting before starting treatment, politely ask: "Can I ask why we wouldn''t start medication now, given how serious high blood pressure can be?"'],
  NULL,
  'Decline any questions not covered by the details already provided in the scenario. Accept all advice offered by the doctor.',
  ARRAY['Ask about symptoms that may suggest end-organ damage: headache, blurry vision (hypertensive retinopathy), chest pain (acute coronary syndrome or hypertensive heart disease), shortness of breath (heart failure), palpitations, ankle swelling (heart failure), blood in the urine (hypertensive nephropathy), or stroke symptoms such as unilateral weakness or slurred speech.','Explore lifestyle factors including diet, physical activity, smoking, alcohol, and recreational drug use.','Ask about any family history of hypertension or cardiovascular disease.','Ask about the wrist injury — whether there is ongoing pain, swelling, signs of infection, or further follow-up planned.','Make a working diagnosis of probable essential hypertension, explaining that a confirmed diagnosis cannot be made on the basis of a single set of elevated readings.'],
  ARRAY['Offer ambulatory blood pressure monitoring (ABPM) or home blood pressure monitoring (HBPM) to confirm the diagnosis.','Offer a face-to-face appointment to repeat blood pressure, perform a cardiovascular examination and fundoscopy, and arrange further investigations including HbA1c, cholesterol, U&Es, urine ACR, and ECG.','If fundoscopy cannot be performed in clinic, advise the patient to book a comprehensive eye examination with a high street optician.','Offer to calculate a QRISK score to assess overall cardiovascular risk.','Provide lifestyle advice: encourage increased physical activity, reduce salt and caffeine intake, and adopt a healthier diet.','Explain that if hypertension is confirmed, treatment will be started with Ramipril 1.25–2.5 mg, and outline possible side effects including cough.','Inform the patient of blood pressure targets: clinic BP below 140/90 mmHg, or home BP below 135/85 mmHg.','Arrange follow-up in 24 hours (ABPM) or 4–7 days (HBPM) to review blood results and discuss monitoring findings.','Safety net by advising the patient to seek urgent medical attention if he develops any concerning symptoms such as sudden weakness (which may suggest a stroke), blurred vision, chest pain, or breathlessness.'],
  'Thank you for calling today, Martin — and I''m really glad you followed up as the A&E team advised. It''s completely understandable to feel concerned after being told your blood pressure was high, especially with your family history in mind.

I want to explain something important first. When your blood pressure was checked in A&E, you had just been through a stressful and painful experience — a laceration to your wrist. Pain and stress can temporarily push blood pressure up significantly, and the readings taken at that time may not reflect what your blood pressure is like day to day. That said, I''m not dismissing those numbers — they are in a range that we need to take seriously and investigate properly.

The key thing is that we cannot make a diagnosis of high blood pressure, which we call hypertension, based on two readings taken in an emergency setting. National guidelines are very clear on this: before we start any treatment, we need to confirm that the blood pressure is consistently elevated over time and in different circumstances.

The best way to do that is either with a 24-hour blood pressure monitor — a small device worn on your upper arm that takes readings automatically throughout the day and night while you go about your normal life — or by using a home blood pressure machine, checking your readings twice a day, morning and evening, for at least four to seven days. We''d ask you to write those readings down, and then we''d review them together. I''d recommend the 24-hour monitor as the gold standard, but home monitoring is a very good alternative.

While we''re setting that up, I''d also like you to come in for an appointment so I can check your blood pressure myself, listen to your heart, and look at the back of your eyes for any early signs of blood pressure-related changes. I''ll also arrange some blood tests — to check your blood sugar, cholesterol, and kidney function — along with a urine test and a heart tracing called an ECG. If I can''t get a good look at the back of your eyes in the clinic, I''ll ask you to see a high street optician for a full eye check.

If the monitoring confirms that your blood pressure is genuinely elevated, we would then talk about starting treatment. The first-line medication we would likely consider is Ramipril, starting at a low dose of 1.25 to 2.5 mg. It is generally well tolerated, though a small number of people develop a dry cough on it — if that happens, there are alternatives we can switch to.

In the meantime, there are things you can do straight away that make a real difference to blood pressure: cutting back on salt, reducing caffeine, eating more fruit and vegetables and fewer takeaways, and increasing your physical activity even in small ways.

And Martin — I want you to keep an eye out for any concerning symptoms between now and when we next speak. If you develop sudden weakness in your arm or leg, notice your speech becoming slurred, experience chest pain, blurred vision, or feel significantly breathless, please call 999 straight away. Those are warning signs we would want to act on urgently. Otherwise, I''ll be in touch once your monitoring results and blood tests are back.',
  ARRAY['Elevated blood pressure readings taken in an acute setting such as A&E should not be used to diagnose hypertension — pain, stress, and anxiety can transiently raise blood pressure significantly.','NICE guidance states that if clinic blood pressure is between 140/90 mmHg and 180/120 mmHg, diagnosis must be confirmed with ambulatory blood pressure monitoring (ABPM) or home blood pressure monitoring (HBPM) before treatment is initiated.','If blood pressure is 180/120 mmHg or above, same-day referral is required if there are signs of retinal haemorrhage, papilloedema, or life-threatening symptoms such as confusion, chest pain, signs of heart failure, or acute kidney injury.','Investigation for target organ damage should include HbA1c, cholesterol, U&Es, urine ACR, ECG, and fundoscopy (or optician referral if fundoscopy is unavailable in clinic).','If hypertension is confirmed and no contraindications exist, first-line treatment for a patient under 55 is an ACE inhibitor such as Ramipril 1.25–2.5 mg; blood pressure targets are clinic BP below 140/90 mmHg or home BP below 135/85 mmHg.','Lifestyle modification — increased physical activity, reduced salt and caffeine intake, and a healthier diet — should be recommended alongside or prior to pharmacological treatment.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  43,
  'Safeguarding Concerns in a Child',
  'Ethics',
  'Telephone consultation',
  false,
  'Dylan Carter',
  '5-year-old male',
  ARRAY[]::text[],
  ARRAY['Nil known. Alerts and QOFs up to date. Immunisations current. Caller: Sandra Mitchell (mother), calling to raise concerns about her son Dylan.'],
  NULL,
  'Mother calling to discuss worries about her son''s wellbeing following a recent contact visit with his father.',
  'Hello, I''m calling because I''m really worried about my son Dylan. Something doesn''t feel right after his last visit to his dad''s house.',
  'Two weeks ago Dylan spent the weekend with his father, Martin Carter, as part of a court-ordered joint custody arrangement. When he came back I noticed a bruise on his left arm. The bruise has healed now but I''m still very worried. He also seems upset every time he comes back from there.',
  ARRAY[
    'If asked whether Dylan has said anything specific: He hasn''t directly said anyone hurt him, but he becomes very quiet and withdrawn after visits.',
    'If asked about the father''s household: Dylan''s father has recently remarried and Dylan stays with his father and his new wife.',
    'If asked about school: His teachers haven''t raised any concerns, and Dylan is attending regularly.',
    'If asked about development and immunisations: There were no problems in pregnancy or birth. Dylan is up to date with his immunisations, eating well, growing normally, and meeting all his developmental milestones.',
    'If asked about other types of abuse: No signs of physical injuries elsewhere, no UTIs or genital complaints, no obvious neglect — he is clothed and fed appropriately.'
  ],
  'Sandra lives alone with Dylan. He attends primary school and his teachers have not raised any safeguarding concerns. Dylan''s pregnancy, birth history, and immunisations are all unremarkable. He is developing normally and meeting all milestones.',
  'Sandra believes Dylan may be being mistreated, possibly by his father''s new wife rather than his father directly.',
  'Dylan is due to visit his father again tomorrow, and Sandra does not want him to go — but she feels she cannot stop the visit because of the court-ordered co-parenting arrangement.',
  'Sandra wants the GP to write a letter or report that would prevent Dylan from attending the contact visit, as she believes the visits are distressing and potentially harmful to him.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any questions asked outside of the details already provided. Accept anything offered by the doctor.',
  ARRAY[
    'Elicit detailed facts about the incident — ask whether Dylan has specifically said that someone hurt him, hit him, or described an abusive experience, to explore the possibility of direct disclosure.',
    'Ask whether Dylan has any bruises or injuries currently, or whether he has had similar injuries in the past, to identify patterns that may suggest repeated or non-accidental harm.',
    'Ask whether Dylan is currently unwell — including symptoms such as fever, bruises elsewhere on the body, lumps or bumps in the abdomen, nausea, vomiting, or signs of a recent viral illness, to rule out other causes of bruising such as leukaemia or immune thrombocytopenic purpura (ITP).',
    'Ask about the home environment — who lives in the household and where Dylan stays when not with his mother.',
    'Ask about other forms of abuse: sexual abuse (e.g. unexplained genital injuries, urinary tract infections, pain on touching), emotional abuse (e.g. becoming withdrawn, tearful, not speaking up), and neglect (e.g. frequent illness, poor school attendance, poor peer relationships) to screen for wider safeguarding concerns.',
    'Ask about pregnancy, birth, immunisation history, nutrition, and developmental milestones.'
  ],
  ARRAY[
    'Offer an urgent face-to-face appointment today to examine Dylan — explain that although the bruise has healed, this will allow you to check for any other marks, old injuries, or signs of harm, and to assess his general health and overall wellbeing.',
    'Inform the mother that you will make an urgent referral to the child safeguarding team today, clearly documenting the urgency — and that they will normally review within 24 hours.',
    'Reassure her that the safeguarding team treats cases like this as a priority and will take the necessary steps to ensure Dylan''s safety while investigations are ongoing.',
    'Advise that GPs cannot write letters to override or prevent a court-ordered custody arrangement — this falls outside our legal role. However, reassure her that concerns like this are taken very seriously and will be referred promptly to the appropriate safeguarding services.',
    'Advise the mother that if she believes Dylan''s safety is in immediate danger, she should contact the police without delay.',
    'Arrange a follow-up phone call in 3–5 days to ensure that support services are involved and that the safeguarding process has been properly initiated.'
  ],
  'It takes real courage to make this call, and you were absolutely right to do so. When a child shows signs of distress after contact visits — even if the physical injury has healed — that is exactly the kind of thing a GP needs to hear about. I want you to know that I am taking what you have told me very seriously.

The first thing I would like to do is bring Dylan in today for a face-to-face appointment. I know the bruise has healed, but seeing him in person allows me to check him over properly — to look for any other marks or signs that might not be obvious, and to get a sense of how he is doing more broadly. Sometimes small things that seem insignificant can be important in building a full picture of a child''s wellbeing.

Sandra, after our conversation today I will be making an urgent referral to the child safeguarding team. This is not something I take lightly — it is part of my duty of care to Dylan, and it is the right thing to do based on what you have shared with me. The team is experienced in situations like this and will carry out a proper assessment. They typically aim to review cases within 24 hours, and they have the authority to take protective steps if they believe there is a risk of harm.

Regarding the letter you were hoping for — I understand why you want something to prevent Dylan from going tomorrow, and I can see how desperate that must feel. However, writing a letter to override a court order is not within my legal powers as a GP. What I can do is document everything you have told me in detail and make sure the safeguarding team is aware of the urgency of the situation. They are the appropriate authority to act on this.

In the meantime, if at any point today you genuinely believe Dylan is in immediate danger, please do not wait — contact the police straight away. They can act quickly when a child''s safety is at risk.

You are doing exactly the right thing by speaking up. Let''s get Dylan seen today, and I will make sure the right people are involved without delay.',
  ARRAY[
    'A GP has a duty to act on safeguarding concerns even when the physical signs have resolved — parental concern and a child''s behavioural changes alone can be sufficient grounds to trigger a safeguarding referral.',
    'Always screen for multiple forms of abuse: physical, sexual, emotional, and neglect, rather than focusing solely on the presenting injury.',
    'In children with unexplained bruising, consider non-abusive differential diagnoses such as leukaemia or immune thrombocytopenic purpura (ITP), particularly if the child is systemically unwell.',
    'GPs cannot write letters to override court-ordered custody arrangements — this falls outside their legal role, and the appropriate referral pathway is to the child safeguarding team or social services.',
    'An urgent face-to-face review of the child should be offered even when injuries have healed, to allow proper clinical assessment and documentation.',
    'Always advise the parent to contact the police immediately if they believe the child is in immediate danger, and arrange follow-up to ensure safeguarding processes have been initiated.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  44,
  'Sudden-Onset Neurological Symptoms in Older',
  'Neurology',
  'Telephone consultation',
  false,
  'Tariq Hussain',
  '61-year-old male',
  ARRAY[]::text[],
  ARRAY['Amlodipine 10mg once daily', 'Atorvastatin 20mg once daily'],
  NULL,
  'Patient has booked an urgent appointment to discuss some neurological symptoms that came on suddenly earlier today and have since resolved.',
  'I had something very strange happen this morning — my face went droopy on one side, my arm felt weak, and my speech came out slurred. It only lasted about 20 minutes and then it all went back to normal. It gave me a real fright.',
  'The symptoms came on suddenly about three hours ago. My left side of my face went numb and drooped, my left arm felt very weak, and my speech was slurred and jumbled. After about 20 minutes everything went back to normal. I have never had anything like this before.',
  ARRAY[
    'If asked about vision: No vision changes or loss during the episode.',
    'If asked about balance or dizziness: There was some unsteadiness on my feet during the episode but it has completely resolved.',
    'If asked about chest pain or palpitations: No chest pain. I did notice my heart felt like it was racing a little during the episode.',
    'If asked about medication compliance: I take my tablets regularly and I had my blood pressure checked about three months ago — it was a bit high at 150/90.',
    'If asked about family history: My father had a stroke in his late 60s.',
    'If asked about driving: I drive for work — I am a taxi driver.'
  ],
  'Tariq lives with his wife and does not smoke or drink alcohol. He works full-time as a taxi driver and is the main financial provider for the household, as his wife does not work outside the home.',
  'Tariq thinks the episode may have been a stroke or something similarly serious.',
  'He is anxious because a close friend had very similar symptoms before dying from a stroke in hospital, and he is worried the same could happen to him.',
  'Tariq wants the doctor to explain what happened and to tell him what needs to be done to prevent it from happening again.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Ask about the time of onset and whether all symptoms have fully resolved or whether any are still present.',
    'Ask about unilateral weakness or sensory loss — for example, numbness or tingling down one side of the body.',
    'Ask about slurred speech or difficulty finding or understanding words during the episode.',
    'Ask about loss of balance or any vertigo.',
    'Ask about sudden, temporary loss of vision in one eye, which may suggest amaurosis fugax.',
    'Ask about associated symptoms that might point to atrial fibrillation — including chest pain, palpitations, and shortness of breath.',
    'Ask about compliance with current medications and whether blood pressure has been well controlled recently.',
    'Ask about social history, including occupation, as this is directly relevant to driving and safety advice.',
    'Ask about any family history of TIA or stroke.',
    'Give a working diagnosis of Transient Ischaemic Attack (TIA) based on the history of resolved focal neurological symptoms.'
  ],
  ARRAY[
    'Offer aspirin 300 mg immediately and advise the patient to take this daily until they are reviewed by a specialist.',
    'Refer urgently to the TIA clinic for specialist assessment and investigations — this should ideally take place within 24 hours of symptom onset.',
    'Advise the patient not to drive and to arrange for someone else to take him to the hospital or clinic.',
    'Inform the patient that he must not drive until he has been assessed by a specialist and declared fit to do so.',
    'Explain that most taxi drivers hold a Group 1 licence, and according to DVLA guidance, they must not drive for at least 4 weeks following a confirmed TIA.',
    'Advise that taxi licensing is regulated by the local council, and the patient should contact his local licensing authority for further guidance about returning to professional driving.',
    'Explain what to expect in secondary care — likely investigations include a CT head scan, carotid Doppler ultrasound (a neck ''jelly scan''), ECG, and blood tests.',
    'Arrange a follow-up consultation to review the findings and outcome of the TIA clinic assessment.',
    'Safety-net: advise the patient to call 999 immediately if any symptoms return, such as sudden weakness, difficulty with speech, or loss of vision.'
  ],
  'Thank you for calling in so promptly — you were absolutely right to seek advice straight away. What you have described this morning sounds like it could be a TIA, which stands for Transient Ischaemic Attack. Most people call it a mini-stroke. It happens when the blood supply to part of the brain is briefly interrupted, causing neurological symptoms that then resolve completely, usually within minutes to hours, which is exactly what you experienced.

I want to be honest with you, Tariq — a TIA is a warning sign that needs to be taken seriously and acted on urgently. It does not mean a full stroke has occurred, but it does mean the risk of one is elevated in the coming days, which is why we need to move quickly. I understand that hearing the word "stroke" is frightening, especially given what happened to your friend, and I want to reassure you that we are doing everything we can to reduce that risk right now.

The first thing I would like you to do is take 300 mg of aspirin immediately — you can take a standard tablet with water. This helps reduce the chance of a clot forming and will need to be taken daily until you are seen by a specialist. I am also arranging an urgent referral to the TIA clinic, which should assess you within 24 hours. They will carry out further investigations including a scan of your head, an ultrasound of the arteries in your neck, an ECG to check your heart rhythm, and some blood tests.

There is something important I need to raise with you about your work as a taxi driver. Following a possible TIA, you must not drive until you have been assessed by a specialist and declared fit to do so. Under DVLA guidance, if the TIA is confirmed, you would not be permitted to drive for at least 4 weeks. I know this is difficult given your role, and I would encourage you to contact your local taxi licensing authority for specific guidance about returning to professional driving, as they regulate licensing separately from the DVLA.

Please arrange for someone — your wife or a family member — to take you to the TIA clinic today. Do not drive yourself. And importantly, if any of your symptoms return at any point — weakness on one side, difficulty speaking, or sudden loss of vision — please call 999 immediately and do not wait to see if they pass. I will follow up with you after your clinic appointment to go through the findings together.',
  ARRAY[
    'Transient Ischaemic Attack (TIA) presents with focal neurological symptoms that resolve completely, typically within 24 hours — urgent assessment within 24 hours of symptom onset is essential to reduce stroke risk.',
    'First-line management includes immediate aspirin 300 mg, urgent TIA clinic referral, and strict advice not to drive pending specialist review.',
    'Under DVLA guidance, patients with a Group 1 licence (including taxi drivers) must not drive for at least 4 weeks following a confirmed TIA — taxi licensing is additionally regulated by the local council.',
    'Always ask about occupation in TIA consultations, as driving restrictions have major occupational and financial implications for the patient.',
    'Expected secondary care investigations include CT head, carotid Doppler ultrasound, ECG, and blood tests.',
    'Safety-net clearly: if symptoms recur, the patient must call 999 immediately rather than waiting for outpatient review.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  45,
  'Vitamin B12 Deficiency',
  'Gastroenterology & Haematology',
  'Telephone consultation',
  false,
  'Rachel Forsythe',
  '34-year-old female',
  ARRAY[]::text[],
  ARRAY['Nil'],
  'Seen 2 days ago by Dr Christine Okafor (Clinical practitioner access role). Presenting complaint: Patient reports feeling tired all the time. No red flags identified. Note previous B12 deficiency documented. Examination findings: BP 120/65 mmHg, Pulse 68 bpm, no lymphadenopathy noted. Plan: Bloods, review with results. Results of patient''s bloods — yet to be filed. Test | Result | Reference Range. HB (Haemoglobin): 113 g/L (ref: 120–170 g/L). MCV (Mean Cell Volume): 105 fL (ref: 80–100 fL). B12: 94 ng/L (ref: 180–1000 ng/L). Folate: 3 ng/L (ref: >7 ng/L). Other tests: Thyroid function test, Coeliac screen, U&Es, LFTs, HbA1c, CRP, and Vitamin D — all within normal range. Patient has booked a follow-up telephone consultation to discuss blood test results.',
  'Patient calling to discuss the results of recent blood tests arranged at a previous appointment, having been experiencing persistent tiredness for the past six months.',
  'Hello, I''m calling to get my blood test results back. I''ve been exhausted for months now and I was really hoping the tests might show what''s going on.',
  'I have been feeling tired all the time for about six months and it''s not getting any better. I''ve had low B12 before and had injections at my old GP surgery. Since joining this practice I''ve been managing with over-the-counter B12 and folate tablets, which I''ve been taking every day for about five months. I''ve also been eating plenty of B12-rich foods but nothing seems to be helping.',
  ARRAY[
    'If asked about concentration or memory: I do feel a bit foggy sometimes and struggle to keep track of things at work.',
    'If asked about tingling or numbness: No tingling or numbness in my hands or feet.',
    'If asked about blurred vision or headaches: No headaches or vision changes.',
    'If asked about mouth ulcers: No mouth ulcers.',
    'If asked about palpitations or breathlessness: No chest pain or palpitations, no shortness of breath.',
    'If asked about bowel symptoms: Bowels are completely normal — no diarrhoea, constipation, bloating, or vomiting.',
    'If asked about diet: I am not vegan or vegetarian. I eat meat and dairy regularly.',
    'If asked about family history: I was adopted so I do not know my family medical history.',
    'If asked about recreational drugs: No recreational drug use, including no nitrous oxide.',
    'If asked about prescribed medications or PPIs: Not on any prescribed medications and not taking any over-the-counter PPIs.',
    'If asked how tiredness affects daily life: It is starting to affect my work — I am a legal secretary and I am struggling to stay on top of tasks.'
  ],
  'Rachel lives with her partner. She does not smoke or drink alcohol. Her menstrual cycles are regular.',
  'Rachel thinks her B12 levels are low again, as she has experienced this before.',
  'The tiredness is now beginning to affect her work performance — she is struggling to keep up with her responsibilities as a legal secretary.',
  'Rachel wants to discuss her blood test results and understand what is causing her symptoms.',
  ARRAY[
    'If the doctor offers B12 injections: Ask — "How long would I need to keep having the injections? Is this something I''ll need for the rest of my life?"'
  ],
  NULL,
  'Say NO to any questions asked outside of the details already provided. Accept anything offered by the doctor.',
  ARRAY[
    'Ask about the tiredness — whether it has changed or worsened since the previous consultation.',
    'Ask about associated symptoms of B12 deficiency: memory problems or difficulty concentrating (possible cognitive changes), headache, blurred vision (possible optic neuropathy), mouth ulcers or angular cheilitis, tingling or numbness in the hands or feet or elsewhere (peripheral neuropathy), palpitations, chest pain, or shortness of breath (anaemia-related symptoms).',
    'Ask about gastrointestinal symptoms that may suggest malabsorption — including diarrhoea, bloating, and vomiting — particularly given that the patient has been taking oral supplements without improvement.',
    'Ask about any personal or family history of autoimmune conditions, including pernicious anaemia.',
    'Ask about dietary habits — whether the patient is vegan or vegetarian.',
    'Ask how the tiredness is affecting her daily life, including work, function, and overall wellbeing.',
    'Ask about social history, including smoking, alcohol use, recreational drug use (particularly nitrous oxide, which can inactivate B12), and occupation.',
    'Ask about any prescribed medications not listed in the notes (e.g. metformin, PPIs) or over-the-counter medications (e.g. OTC esomeprazole) that could impair B12 absorption.',
    'Give a diagnosis of anaemia caused by B12 and folate deficiency.'
  ],
  ARRAY[
    'Offer a blood test for intrinsic factor antibodies to assess for pernicious anaemia. If this is normal, refer to gastroenterology for further investigation including gastroscopy and colonoscopy to check for gut-related causes of malabsorption. If those are also normal, refer to haematology for further specialist evaluation.',
    'Start treatment with Vitamin B12 (Hydroxocobalamin) injections at a dose of 1 mg intramuscularly three times a week for 2 weeks. Folate replacement can be initiated after B12 treatment has started, typically 24 to 48 hours later.',
    'Arrange a full blood count and reticulocyte count within 7–10 days of starting treatment to check for response, and repeat again after 8 weeks to confirm ongoing improvement.',
    'Explain that if no reversible cause is found, treatment with B12 injections may need to be lifelong.',
    'Advise her to continue eating foods rich in B12 and folate as part of good dietary habits.',
    'Offer a Fit Note with amended duties or workplace adjustments, as the patient''s symptoms are currently affecting her ability to work.',
    'Safety-net and advise the patient to seek urgent medical attention if she develops new symptoms such as tingling in the hands or feet, balance problems, or changes in memory or mood, as these may indicate nerve involvement.'
  ],
  'Thank you for calling back, and I am glad we have the results to go through with you today. I can see from looking at them that we have found something important, and I think it helps explain why you have been feeling so exhausted.

Your haemoglobin — the part of your blood that carries oxygen around your body — is a little low at 113 g/L, when the normal range is 120 to 170. This is called anaemia, and it can certainly cause the kind of persistent tiredness you have been describing. Now, the likely reason your haemoglobin is low is that both your vitamin B12 and your folate levels are very low — your B12 is 94 ng/L, well below the normal lower limit of 180, and your folate is 3 ng/L, when it should be above 7.

What is particularly interesting, Rachel, is that you have been taking B12 and folate supplements for five months and eating well, yet your levels are still low. This tells us that the tablets are not working, which strongly suggests your body is struggling to absorb B12 through the gut. One of the most common causes of this is a condition called pernicious anaemia, where the immune system interferes with a protein in the stomach needed to absorb B12. We cannot diagnose this from today''s conversation alone, but it is something we need to investigate.

To look into this, I am going to arrange a blood test called an intrinsic factor antibody test. This will help us understand whether pernicious anaemia is the underlying cause. Depending on those results, we may also arrange a gastroscopy and colonoscopy to check for other gut-related causes of malabsorption, and if needed, a referral to the haematology team.

In the meantime, because your B12 is very low and you are clearly symptomatic, I would like to start you on B12 injections straight away. These bypass the gut entirely, so they will work regardless of any absorption problem. The plan is to give you an injection of Hydroxocobalamin 1 mg intramuscularly, three times a week for two weeks, to build your levels back up. After a day or two of starting B12, we will also add in folate tablets. It is important to start B12 first before folate, as treating folate alone when B12 is very low can occasionally worsen any nerve-related effects.

If we find that the absorption problem is permanent — as is the case with pernicious anaemia — then yes, you may need B12 injections long-term. We will discuss that further once we have the results of your tests. I will arrange a blood count check about 7 to 10 days after starting the injections to see how you are responding, and again at 8 weeks. I would also like to offer you a fit note if the fatigue is affecting your ability to work, so please let me know if that would help. Finally, please seek urgent advice if you develop any tingling in your hands or feet, problems with your balance, or changes in your memory, as these can occasionally be signs that the nerves are being affected.',
  ARRAY[
    'B12 and folate deficiency is the most common cause of megaloblastic anaemia — a raised MCV alongside low B12 and folate and a low haemoglobin is the classic picture.',
    'When a patient remains deficient despite oral supplementation, suspect malabsorption — arrange intrinsic factor antibody testing to assess for pernicious anaemia, the leading cause of B12 deficiency in the UK.',
    'Treatment of symptomatic B12 deficiency is with Hydroxocobalamin 1 mg intramuscularly three times a week for 2 weeks; folate replacement should begin 24–48 hours after B12 has been started, not before.',
    'If no reversible cause is identified, B12 injections may need to be lifelong — this is particularly important to communicate clearly to patients.',
    'Always screen for neurological complications of B12 deficiency including peripheral neuropathy, ataxia, optic neuropathy, and cognitive changes — if present, seek urgent specialist input.',
    'Safety-netting should include advice to seek urgent review if new neurological symptoms develop, and a follow-up blood count at 7–10 days and 8 weeks to confirm treatment response.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  46,
  'Electrolyte Abnormalities in Unwell Young',
  'General Practice',
  'Telephone consultation',
  false,
  'Claire Jennings',
  '27-year-old female',
  ARRAY[]::text[],
  ARRAY['Nil'],
  'Seen by Dr Priya Sharma (Clinical practitioner access role) 2 days ago. Presenting complaint: Patient reports feeling tired all the time, associated with malaise and weight loss. No red flags identified. Examination: BP 90/59 mmHg. Pulse 99 bpm. Weight 57 kg (previously 63 kg). Plan: Bloods, review with results. Results of patient''s bloods — yet to be filed. Test | Result | Normal Range. Potassium: 5.8 mmol/L (ref: 3.5–5.0 mmol/L). Sodium: 130 mmol/L (ref: 135–145 mmol/L). Blood Urea Nitrogen (BUN): 12 mg/dL (ref: 7–20 mg/dL). Creatinine: 1.0 mg/dL (ref: 0.6–1.2 mg/dL). Glomerular Filtration Rate (GFR): >90 mL/min (normal: >60 mL/min). Other tests: TFTs, FBC, Ferritin, Coeliac screen, LFTs, HbA1c, CRP, Vitamin D — all within normal range. Patient has booked a follow-up telephone consultation to discuss her blood test results.',
  'Patient calling to discuss recent blood test results, arranged at a previous appointment where she presented with fatigue, weight loss, and general malaise.',
  'Hello, I''m calling to get my blood results. I have been feeling dreadful for a couple of weeks now — exhausted, dizzy, and my muscles just feel so weak. I''ve also noticed my skin looks darker than it used to, which is really strange.',
  'Over the past two weeks I''ve been feeling very tired, my muscles feel weak, and I keep getting dizzy spells — like I might faint. I''ve also completely lost my appetite and I''ve noticed my clothes are much looser than they used to be, even though I haven''t weighed myself. And the change in my skin colour — it''s noticeably darker, which is really not normal for me.',
  ARRAY[
    'If asked about when the fatigue started and whether it is improving: It started about two weeks ago and it is not getting better — if anything, it feels a bit worse.',
    'If asked about nausea, vomiting, or abdominal symptoms: No vomiting, no abdominal pain.',
    'If asked about salt cravings: Yes, actually — I have been craving salty things a lot lately, which is unusual for me.',
    'If asked about chest pain or palpitations: No chest pain, but I have noticed some occasional fluttering in my chest.',
    'If asked about existing medical conditions: None that I know of.',
    'If asked about current medications or supplements: I am not taking any prescribed medications, supplements, or herbal remedies.',
    'If asked about family history: No family history of Addison''s disease or autoimmune conditions that I know of.',
    'If asked about mood or stress: My mood is fine. I''ve been a bit worried about how I feel, but I''m not depressed.',
    'If asked about how symptoms affect daily life: I am currently off work because I feel too unwell to carry out my duties.'
  ],
  'Claire works as a traffic officer but is currently off sick due to her symptoms. She lives with her boyfriend, who is present during the call. She does not smoke, drink alcohol, or use recreational drugs.',
  'Claire suspects the tiredness might be due to low iron, as this is common in women.',
  'Her symptoms are now significantly affecting her ability to work.',
  'Claire wants the doctor to explain her blood test results and tell her what is going on.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any questions asked outside of the details already provided. Accept anything offered by the doctor.',
  ARRAY[
    'Ask about when the fatigue started and whether it is improving, worsening, or staying the same.',
    'Ask about associated symptoms such as muscle weakness, dizziness, or light-headedness, to assess impact and possible electrolyte-related effects.',
    'Ask about nausea, vomiting, or abdominal symptoms, which may be signs of adrenal insufficiency or systemic illness.',
    'Ask about any changes in appetite and whether there has been unintentional weight loss.',
    'Ask about any darkening or changes in skin colour, as this can be a sign of Addison''s disease.',
    'Ask about chest pain or palpitations, to assess for possible complications of hyperkalaemia.',
    'Ask about salt cravings or an increased desire for salty foods, which is an important feature in the context of suspected adrenal insufficiency.',
    'Ask about any known medical conditions not listed in the notes.',
    'Ask about current medications, over-the-counter supplements, or herbal remedies.',
    'Ask about any recent changes to diet or exercise routine.',
    'Ask about family history of Addison''s disease or autoimmune conditions.',
    'Ask about social history including occupation, smoking, alcohol, and recreational drug use.',
    'Ask about mood and emotional wellbeing, and any recent stress at work or at home.',
    'Ask how the condition has affected her at work and at home, to assess impact on daily functioning.',
    'Explain that the results show hyperkalaemia and hyponatraemia — a combination that raises suspicion for Addison''s disease.'
  ],
  ARRAY[
    'Offer same-day admission via the Acute Medical Unit or Emergency Department, given the previously low blood pressure and abnormal electrolyte results.',
    'Ask whether she has someone who can take her to hospital safely, such as her boyfriend or a family member. Advise her not to go alone, and to make sure the person with her knows what is happening. If anything changes on the way, they should stop and call 999 immediately.',
    'Inform her that in hospital she will be given fluids through a drip to help stabilise her sodium and potassium levels.',
    'Explain that further tests will be done in hospital to confirm whether she has Addison''s disease. If confirmed, she will be started on lifelong steroid treatment to replace the hormones her body is not producing.',
    'Advise her to book a follow-up appointment after discharge from hospital to review what happened, go through any new medications that were started, and discuss the diagnosis and ongoing management.',
    'Safety-net by advising that if she feels worse or has any new concerns while on her way to hospital, she should contact the practice or call 111 or 999 depending on the severity of her symptoms.'
  ],
  'Thank you for calling back, and I am glad you are at home with your boyfriend right now, because what I am about to tell you is going to require some action today. I have looked carefully at your blood results, and there are some important abnormalities that we need to address urgently.

Your potassium level is raised at 5.8 mmol/L, when the normal range is 3.5 to 5.0, and your sodium is low at 130 mmol/L, when it should be between 135 and 145. When we see this combination of high potassium and low sodium — especially alongside low blood pressure, weight loss, fatigue, muscle weakness, and the skin darkening you mentioned — it can point to a condition called Addison''s disease.

Addison''s disease is a condition where small glands that sit on top of your kidneys — called the adrenal glands — are not producing enough of certain essential hormones. These hormones help control your blood pressure, energy levels, and the balance of salts in your body. Without enough of them, the body struggles to maintain normal function, which can explain everything you have been experiencing.

Because of these results and your symptoms, Claire, I think it is safest for you to be assessed in hospital today. They will be able to give you fluids through a drip to help correct your salt levels and will run further tests to confirm what is going on. I will be in contact with the admissions team so they know to expect you and are aware of the background.

Please ask your boyfriend to take you in — do not go alone. Make sure he is with you and knows the situation. If you feel worse or develop any new symptoms on the way, stop and call 999. Do not drive yourself.

If Addison''s disease is confirmed in hospital, you will likely be started on lifelong steroid medication to replace the hormones your body is not producing. This is a very effective treatment, and most people feel significantly better once they are on it. Once you are discharged, please book a follow-up appointment here so we can go through everything together — your diagnosis, your new medications, and what it means for you going forward.',
  ARRAY[
    'Hyperkalaemia combined with hyponatraemia alongside hypotension, weight loss, fatigue, and skin hyperpigmentation is the classic biochemical and clinical picture of Addison''s disease (primary adrenal insufficiency).',
    'Addison''s disease results from destruction or dysfunction of the adrenal cortex, leading to deficiency of cortisol and aldosterone — the most common cause in developed countries is autoimmune disease.',
    'This presentation requires same-day hospital admission for IV fluid resuscitation, electrolyte correction, and further investigation including serum cortisol (ideally taken at 8–9 a.m.) in a stable patient.',
    'If there is clinical suspicion of an impending adrenal crisis, do not delay treatment for investigations — untreated adrenal crisis is rapidly life-threatening.',
    'Always ask about salt cravings in patients with suspected adrenal insufficiency — this is a useful and often overlooked symptom of aldosterone deficiency.',
    'If Addison''s disease is confirmed, lifelong steroid replacement will be required — patients should be educated on sick-day rules and the need for dose increases during illness or surgery.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  47,
  'Confusion And Dehydration In Palliative Patient',
  'Elderly Medicine & Palliative Care',
  'Telephone consultation',
  false,
  'Norman Walsh',
  '66-year-old male',
  ARRAY[]::text[],
  ARRAY['Oramorph 10mg/5ml — 2.5 ml every 4 hours as needed', 'Lactulose 15 ml once daily', 'Senna 15 mg at night', 'No known drug allergy. Caller: Paramedic Steven Clarke, calling on behalf of the patient.'],
  NULL,
  'Paramedic calling on behalf of a palliative care patient who has become confused and has not opened his bowels for three days despite regular laxatives.',
  'Hello, this is Steven Clarke calling — I''m a paramedic and I''m at the home of Norman Walsh, who I believe is registered with your practice. I''ve been called out because his neighbour contacted us after speaking to Norman''s wife. She was worried because Norman seems confused this morning and hasn''t opened his bowels for three days even though he''s been taking his laxatives regularly.',
  'I''ve done a full set of observations. His temperature is 36.0 degrees, blood pressure 120/75, pulse 99, and oxygen sats are 98% on air. He looks mildly dehydrated. His abdomen is soft, non-tender, and mildly distended — bowel sounds are reduced but present. No vomiting and no obvious signs of obstruction. Norman mentioned some bone pain in both legs but no back pain. He is fluctuating in and out of confusion. His wife is upstairs with him but she is hard of hearing and is not able to speak on the phone.',
  ARRAY[
    'If asked about when the confusion started: His wife noticed it this morning — it appears to be new but is fluctuating.',
    'If asked whether Norman can speak on the phone: He is going in and out of confusion and would not be able to engage meaningfully in a telephone call.',
    'If asked about bowel habits more specifically: He hasn''t opened his bowels for three days. His normal pattern is once daily. He has been taking both his prescribed laxatives regularly.',
    'If asked about vomiting or obstruction: No vomiting. No signs of obstruction on examination.',
    'If asked about thirst and urine output: Norman has mentioned increased thirst and he has been urinating more frequently than usual.',
    'If asked about bone pain: He has reported bone pain in both legs — no back pain.',
    'If asked about the wife''s ability to cope: She appears to be struggling with his care needs at home.',
    'If asked about Norman''s wishes regarding hospital: Both Norman and his wife have said they are comfortable with healthcare professionals making decisions on their behalf.'
  ],
  'Norman lives at home with his wife. She appears to be struggling to cope with his care needs. He is a retired lorry driver. He does not smoke or drink alcohol.',
  'The paramedic suspects that Norman''s symptoms could represent a progression of his metastatic cancer.',
  'The paramedic is particularly concerned about the confusion, abdominal discomfort despite no tenderness, and the failure of regular laxatives to produce a bowel movement for three days.',
  'The paramedic is uncertain whether hospital admission is appropriate given that Norman is under palliative care, and is seeking clinical advice on whether to manage him at home or to escalate.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any questions asked outside of the details already provided. Accept anything offered by the doctor.',
  ARRAY[
    'Ask about the confusion: when it started, whether it is new or fluctuating, and how it is affecting Norman''s orientation, communication, and level of alertness.',
    'Ask about bowel habits: last bowel movement, usual pattern, straining, incomplete emptying, and adherence to laxatives.',
    'Ask about red flags for bowel obstruction: vomiting, abdominal distension, the nature of any abdominal pain, and whether bowel sounds are present or absent.',
    'Ask about symptoms of hypercalcaemia: bone pain, increased thirst, polyuria, palpitations, nausea, or fatigue.',
    'Ask the paramedic whether any examinations have been performed and request the findings — including temperature, pulse, blood pressure, oxygen saturations, hydration status, and abdominal examination findings (tenderness, distension, bowel sounds).',
    'Ask about social history including the home situation, whether any carers are in place, and whether Norman''s wife appears to be managing his care needs.',
    'Ask about Norman''s wishes or preferences regarding treatment and hospital admission, if known, and whether any advance care plan is in place.',
    'Make a diagnosis of hypercalcaemia secondary to bone metastases.'
  ],
  ARRAY[
    'Advise hospital admission for possible hypercalcaemia, as Norman is symptomatic, fluctuating in and out of confusion, and has no advance care plan or documented wishes against hospital admission in place.',
    'Explain that treatment in hospital may include IV fluids and possibly bisphosphonates, with the goal of stabilising him and improving his comfort rather than curative intent.',
    'Ask the paramedic to kindly inform Norman and his wife about what to expect in hospital.',
    'Request that the ambulance crew initiate IV normal saline en route to hospital if this is feasible and within their scope of practice.',
    'Offer to contact the hospital — the acute medical or oncology team — in advance to alert them to Norman''s arrival and clinical background.',
    'Offer to arrange a home visit after discharge to discuss advance care planning with Norman and his wife.',
    'Propose involving the community palliative care team or Macmillan nurses for ongoing support at home.',
    'Suggest assessment of care needs including referral to occupational therapy and a social prescriber, given that Norman''s wife appears to be struggling.',
    'Offer to complete the SR1 form (formerly DS1500) to support access to benefits and assist with care planning.',
    'Thank the paramedic sincerely for their efforts and compassionate care.'
  ],
  'Thank you so much, Steven — that is a really comprehensive handover and it is clear you have done a thorough job on scene. I want to work through this with you carefully.

From everything you have described, I think what we are likely dealing with here is hypercalcaemia — high calcium in the blood — which is a recognised complication of advanced cancer, particularly when there are bone metastases. The constellation of symptoms — the confusion, the constipation despite regular laxatives, the increased thirst, the more frequent urination, and the generalised bone pain — all fit with this diagnosis. The dehydration will also be making things worse.

Given that Norman is symptomatic, fluctuating in and out of confusion, and does not appear to have an advance care plan or any documented preference against hospital admission in place, I think the right decision here is to admit him today. The aim of admission is not to pursue any curative treatment — it is to stabilise him, manage his symptoms, and ensure he is as comfortable as possible. In hospital they will be able to give him fluids through a drip to address the dehydration and start correcting the calcium, and they may also consider bisphosphonate treatment depending on how things look.

If it is within your scope and you carry the equipment, would you be able to start some IV normal saline en route? Even a small amount could help with his dehydration and comfort on the journey. I will ring ahead to the acute medical team right now so they are expecting him and have the background.

Before you leave, please make sure his wife is aware of what is happening and what to expect at the hospital. She should not be left without support. I want to acknowledge what you mentioned about her struggling — that is really important, and I will make sure we address it. Once Norman is discharged, I will arrange a home visit to sit down with both of them together. We will discuss his wishes, begin putting an advance care plan in place, and look at what additional support is available for his wife. I will also involve the community palliative care team and Macmillan nurses, and refer to occupational therapy and a social prescriber to look at practical support at home.

There is also a form called the SR1 — previously known as the DS1500 — which helps patients with progressive illness access benefits more quickly. I will make sure that is completed and coordinated through our social prescriber for the family.

Steven, thank you again — genuinely. You have managed a complex situation with real skill and compassion. Please do not hesitate to ring us any time you need support with one of our patients.',
  ARRAY[
    'Hypercalcaemia of malignancy should be suspected in palliative patients who present with confusion, constipation, increased thirst, polyuria, and fatigue — it is a recognised complication of bone metastases.',
    'Hospital admission is appropriate in palliative patients with symptomatic hypercalcaemia, particularly when no advance care plan is in place and when the goal is symptom relief and comfort rather than cure.',
    'Treatment of hypercalcaemia of malignancy typically involves IV fluids and bisphosphonates — however, NICE advises that treatment may not be appropriate if the patient is approaching the end of life, making clinical judgement and patient wishes central to the decision.',
    'The SR1 form (formerly DS1500) should be offered to patients with progressive life-limiting illness to support timely access to benefits — this can be coordinated through a social prescriber.',
    'Advance care planning should be initiated early in the palliative journey — in its absence, hospital admission may be the appropriate default when a patient lacks capacity and has no documented preferences.',
    'Always assess the wellbeing and coping capacity of the main carer — referral to occupational therapy, community palliative care, and social prescribing may all be appropriate to support the family at home.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  48,
  'Excessive Sweating in a Young Adult',
  'Endocrine & Nephrology',
  'Video consultation',
  false,
  'Gemma Whitfield',
  '27-year-old female',
  ARRAY[]::text[],
  ARRAY['Nil'],
  NULL,
  'Patient has booked a routine video consultation to discuss concerns about excessive sweating that has been affecting her for two years.',
  'I sweat excessively under both armpits. It''s been going on for about two years now and it''s really starting to get on top of me. I find it really embarrassing.',
  'The sweating is only in my armpits — not anywhere else on my body. It happens pretty much every day but it completely stops when I''m asleep at night. I''ve tried lots of different antiperspirants but none of them have made any difference.',
  ARRAY[
    'If asked about other areas of the body: It is only under my armpits — nowhere else.',
    'If asked about frequency: It happens almost every day.',
    'If asked about night sweating: No — it stops completely when I''m asleep. That''s actually one of the strange things about it.',
    'If asked about triggers: I can''t pinpoint a clear trigger, but I have noticed it seems worse during periods when I''m drinking more coffee. I currently drink about three to five cups a day.',
    'If asked about weight loss, lumps or bumps, or other symptoms: No weight loss, no lumps, no other symptoms.',
    'If asked about mood: My mood is generally fine. I''m not depressed or anxious. It does affect my confidence though.',
    'If asked about palpitations or fever: No palpitations, no fever.',
    'If asked about family history: No family history of similar problems.',
    'If asked about previous treatments: I''ve tried various commercial antiperspirants — Dove, Sure, that sort of thing — but they haven''t helped.'
  ],
  'Gemma does not smoke, drink alcohol, or use recreational drugs. She has been in a stable relationship with her partner for four years and they live together. She works as a make-up artist.',
  'Gemma wonders whether the sweating might be linked to her caffeine intake.',
  'Gemma works as a make-up artist and the sweating causes visible patches on her clothing, which is embarrassing and affects her confidence during work. She is not depressed or anxious.',
  'Gemma has heard about a treatment called iontophoresis from a friend and would like to know whether she can be referred for it, and what it involves.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any questions asked outside of the details already provided. Accept anything offered by the doctor.',
  ARRAY[
    'Ask how long the excessive sweating has been present.',
    'Ask whether the excessive sweating is limited to the armpits or also occurs in other areas of the body.',
    'Ask whether the sweating is bilateral — if unilateral, consider secondary causes.',
    'Ask how often episodes of excessive sweating occur each week — primary hyperhidrosis typically occurs at least once per week.',
    'Ask whether symptoms occur during sleep — primary hyperhidrosis does not usually cause night-time sweating; if present, consider systemic disease or malignancy.',
    'Ask about potential triggers: stress, anxiety, caffeine, alcohol, spicy or hot food, sweets, chocolate, citrus, smoking, or exercise.',
    'Screen for red flags or associated symptoms: fever, weight loss, anorexia, palpitations, or night sweats, to rule out systemic disease or malignancy.',
    'Ask how the sweating affects her daily life and confidence, and check for depression and anxiety.',
    'Ask about occupation, stress levels, and social history including smoking, alcohol, and recreational drug use.',
    'Ask about any family history of similar symptoms.',
    'Give a diagnosis of primary focal hyperhidrosis (axillary).'
  ],
  ARRAY[
    'Offer investigations including FBC, thyroid function tests, HbA1c, ESR/CRP, U&Es, and liver function tests to rule out secondary causes.',
    'Advise the patient to avoid identified triggers, particularly caffeine, as part of lifestyle modification and health promotion.',
    'If no obvious trigger is identified, advise the patient to keep a symptom diary to help identify any potential patterns or triggers over time.',
    'Recommend self-care strategies including frequent use of commercial antiperspirants rather than deodorants, avoiding tight clothing and synthetic fabrics, wearing white or black clothing to reduce visible sweat patches, and using underarm pads to protect clothing.',
    'Advise on the use of 20% aluminium chloride hexahydrate topical preparations, explaining they should be applied to clean, dry skin at night before bed, washed off in the morning, and used every 1–2 days until symptoms improve, then as required — up to every 6 weeks — noting that skin irritation may occur.',
    'Address the patient''s ideas, concerns, and expectations by explaining iontophoresis, how it works, and when it is considered appropriate.',
    'Explain that iontophoresis is a treatment where a weak electrical current is passed through water to block nerve signals to the sweat glands; for the underarms, special pads are connected to water trays; if effective it can reduce sweating short-term but requires regular maintenance and is usually initiated by a specialist, with machines available for home use.',
    'Offer conservative treatment and aluminium salt preparations as first-line before referring for iontophoresis.',
    'Mention other second-line options such as botulinum toxin injections, which may be considered if conservative treatments fail.',
    'Offer follow-up to monitor response, provide ongoing support, and adjust the management plan as needed.'
  ],
  'Thank you for bringing this to me today, and I can hear how much this has been affecting you. What you have described — localised sweating in both armpits, present most days but not at night, without any other symptoms — fits very well with a condition called primary focal hyperhidrosis. This simply means excessive sweating that is confined to a specific area of the body without any underlying medical cause.

It is more common than many people realise, particularly in younger adults, and it happens when the nerves that control the sweat glands become overactive. It is not dangerous, but I completely understand how distressing it is — especially in a role like yours where you are working closely with people and your appearance matters. You should not have to just live with it, and we have several things we can offer.

You mentioned noticing a link with caffeine, Gemma, and that is worth paying attention to. Caffeine stimulates the nervous system and can act as a trigger for sweating, so reducing or cutting it out could make a meaningful difference. If you are not sure what your triggers are more broadly, I would suggest keeping a symptom diary over the next few weeks — noting what you ate, drank, and were doing when the sweating was at its worst. This can be really helpful in identifying patterns.

In terms of what you can do straight away: the commercial antiperspirants you have been using are deodorants rather than true antiperspirants, and the active ingredients are not concentrated enough to be therapeutic. I would like you to try a prescription-strength preparation containing 20% aluminium chloride hexahydrate. The way to use it is to apply it to completely clean, dry skin under your arms at night before bed, wash it off in the morning, and repeat every one to two days until your symptoms improve. After that you can reduce to using it as needed, up to every six weeks. The skin can sometimes become a little irritated, which is normal and usually settles.

You mentioned iontophoresis, and I want to address that directly because it is a valid and well-recognised treatment. It works by passing a very mild electrical current through water, which temporarily blocks the nerve signals to the sweat glands. For the underarms, special electrode pads are connected to trays of water, and it can produce a significant reduction in sweating. However, it does need regular maintenance sessions to keep working, and it is a treatment that is usually initiated through a dermatology specialist. So the pathway would be: try the aluminium chloride first, and if that does not provide sufficient benefit, I will refer you to dermatology for consideration of iontophoresis. If that does not work either, botulinum toxin injections are another option available through secondary care.

Before we start any of this, I would also like to arrange some basic blood tests — a full blood count, thyroid function, blood sugar, inflammatory markers, kidney and liver tests — just to make sure there is nothing underlying that we have missed. I am not expecting to find anything, but it is good practice. I will arrange a follow-up once the results are back, and we can check how you are getting on with the aluminium chloride as well.',
  ARRAY[
    'Primary focal hyperhidrosis is the most common type of excessive sweating — it is bilateral, affects specific sites (commonly axillae, palms, or soles), occurs at least once a week, and does not cause night-time sweating; absence of night sweats helps distinguish it from secondary causes.',
    'The absence of systemic symptoms such as weight loss, fever, palpitations, or night sweats is important in ruling out malignancy, thyroid disease, or other secondary causes — baseline blood tests (FBC, TFTs, HbA1c, ESR/CRP, U&Es, LFTs) should be arranged.',
    'First-line treatment is 20% aluminium chloride hexahydrate applied to clean, dry skin at night before bed and washed off in the morning — used every 1–2 days until improvement, then as required up to every 6 weeks.',
    'Iontophoresis uses a weak electrical current passed through water to block sweat gland nerve signals — it is effective for axillary hyperhidrosis but is specialist-initiated and requires regular maintenance; refer to dermatology if first-line treatments fail.',
    'Lifestyle advice should include avoiding known triggers such as caffeine, tight or synthetic clothing, and hot foods; keeping a symptom diary can help identify individual triggers.',
    'Botulinum toxin injections are a recognised second-line option for primary focal hyperhidrosis when conservative measures and iontophoresis have not been sufficient — this is arranged via dermatology.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  49,
  'Accidental Overdose in Patient with Memory',
  'Mental Health',
  'Telephone consultation',
  false,
  'George Hartley',
  '80-year-old male',
  ARRAY[]::text[],
  ARRAY['Ramipril 2.5mg OD','Clopidogrel 75mg OD','Atorvastatin 80mg OD','Tamsulosin 400mcg OD'],
  'Seen by clinical practitioner 1 week ago. Presenting complaint: recent fall and confusion. Examination: BP 100/76, pulse 75 bpm. Patient intermittently confused; difficult to determine if this is acute given he lives alone without carers or family available for collateral history. Plan: admit to hospital. Emergency Department discharge letter — Patient admitted following fall and confusion; fall described as mechanical. Blood tests (CRP, U+Es, thyroid function, LFTs, FBC) and CT head all satisfactory. No bony injury. Carers attend twice daily for meals and household support. Minor laceration to right leg — cleaned and referred to district nurse for regular dressing. Plan: discharge home; physio and OT assessment recommended. GP review if further deterioration. District nurse Janet Moorfield has visited the patient and is calling to discuss his condition.',
  'District nurse calling to discuss an elderly patient she has just assessed at home.',
  'I''m calling because I''ve just seen Mr George Hartley and I''m worried he may have taken double the amount of his regular medications.',
  'During my home visit I noticed that his blister pack had several tablets missing and he isn''t due a new supply for another two days. This suggests he may have taken two days'' worth of medication in a single day. When I asked him about it, he said he might have done so accidentally because he hates missing his tablets. His medications are Ramipril 2.5mg OD, Clopidogrel 75mg OD, Atorvastatin 80mg OD, and Tamsulosin 400mcg OD. He appears physically well at the moment, but the carers have mentioned he has seemed increasingly muddled over the past few months and often forgets things. I did a urine dip which was negative. His leg wound looks clean with no signs of infection.',
  ARRAY['Observations if asked: BP 128/80 mmHg, pulse 75 bpm, oxygen saturation 96% on air. Chest clear. Mobilises with a Zimmer frame.','He lives alone and is housebound due to reduced mobility. His next of kin is his son, William, who visits twice a week and handles his shopping. He does not smoke or drink alcohol. Carers attend twice a day to help with meals, cleaning, and personal care.'],
  'He lives alone and is housebound due to reduced mobility. His next of kin is his son, William, who visits twice a week and does his shopping. He does not smoke or drink alcohol. Carers attend twice daily and assist with meals and household tasks.',
  'I suspect he may have taken his medications incorrectly by mistake.',
  'I''m worried this may reflect an underlying problem with his memory or early dementia.',
  'I''d like the GP to consider a further assessment for dementia and to advise whether it''s safe for him to skip his clopidogrel and other medications for 24 hours to avoid any further overdosage. I will ask: can he skip his clopidogrel and other medications today?',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Ask which medications are included in the blister pack and clarify which may have been double-dosed','Ask whether the patient has reported any new or current symptoms','Ask about gastrointestinal symptoms such as nausea, abdominal pain, or an upset stomach, as all of these medications are taken orally','Ask about any bruising or bleeding, including blood in the urine or from the back passage, as a potential side effect of Clopidogrel','Ask about dizziness or recent falls, which may be side effects of Ramipril or Tamsulosin','Ask about muscle cramps or aches, which may be a side effect of Atorvastatin','Ask about headaches, a known side effect of Tamsulosin','Ask about the onset and duration of any memory difficulties','Ask about any recent changes in personality or behaviour','Ask about gait abnormalities and whether the patient uses a walking aid, is bed-bound, or requires support with mobility','Ask about associated symptoms such as tremors or urinary incontinence, which could suggest conditions such as normal pressure hydrocephalus or Parkinson''s disease','Ask about the patient''s nutritional status, including whether he is eating and drinking adequately and who is responsible for shopping and meal preparation','Ask about bowel habits and whether the patient is experiencing any difficulties','Ask about lifestyle factors, particularly alcohol intake and smoking history','Ask about mood and screen for signs of low mood or emotional changes','Ask about the patient''s home situation, including who he lives with, whether there is a next of kin or lasting power of attorney in place','Ask how frequently carers attend and what support they provide','Ask whether the district nurse has taken recent observations, and check for any abnormal vital signs including blood pressure, heart rate, and oxygen saturation','Establish a working diagnosis of possible early dementia with accidental medication overdose'],
  ARRAY['Offer a home visit to assess the patient in person for possible cognitive decline and early dementia','Arrange further blood tests as part of a confusion screen, including B12, folate, and ferritin; no need to repeat FBC, U&Es, CRP, or LFTs as these were done one week ago and were all normal','Refer the patient to the memory clinic for formal cognitive assessment','Reassure the district nurse that the patient''s regular medications can be resumed the following day, as the medications involved are not typically harmful in the context of minor accidental double dosing and the patient is currently asymptomatic; however, carers should monitor for any concerning symptoms and seek medical advice if they arise','Advise that carers and next of kin should be provided with clear written instructions on potential side effects to watch for, including bleeding, bruising, muscle cramps, abdominal discomfort, dizziness, or seizures, and should seek urgent medical attention if any occur; the next of kin should also be encouraged to check in regularly and escalate any concerns promptly','If uncertain about the safety of continuing medications following overdose, advise that you will consult TOXBASE (www.toxbase.org) and the BNF and will call the nurse back with further guidance','Note that according to NICE guidance, patients who exceed the daily dose of two or more cardiotoxic agents, such as beta blockers or calcium channel blockers, should be referred for hospital assessment — though this does not apply in this case, awareness of the principle is important','Suggest carer-supervised administration of his medications; carers should be provided with clear written instructions and asked to assist with administration if trained and willing; if not, request district nursing support to provide daily medication administration visits, particularly given these are once-daily medications','Consider advising that his medications be kept locked away as an interim safety measure; discuss this with the patient to explain it is for his safety and to obtain his agreement','Liaise with the dispensing pharmacy to arrange an early replacement supply and ensure there is no interruption to treatment','Refer to the frailty team or occupational therapy for a home visit to assess whether the current care package is adequate or needs to be increased','Offer to contact the next of kin, William, to inform him of the situation including concerns about medication safety and possible cognitive impairment, with the patient''s consent','Offer practical safety measures such as a personal falls alarm given his history of falls and reduced mobility','Thank the district nurse for her thorough assessment and for escalating her concerns appropriately'],
  'Thank you so much for calling, Janet, and for the thoroughness of your assessment today — it''s exactly the kind of proactive approach that makes such a difference for patients like George. Based on what you''ve described, I do share your concern that Mr Hartley may be showing early signs of cognitive decline or dementia. The missing tablets from the blister pack, combined with the carer reports of increasing forgetfulness and confusion over recent months, paint a consistent picture that warrants further investigation.

In terms of the accidental overdose, I want to reassure you that the medications involved — Ramipril, Clopidogrel, Atorvastatin, and Tamsulosin — are not typically dangerous in the context of a single episode of minor accidental double dosing, particularly as he is currently well and asymptomatic. On that basis, I''m happy for him to resume his usual medications from tomorrow as normal. That said, I would ask the carers and his son William to keep a close eye on him over the next 24 to 48 hours and to watch for any new symptoms such as unusual bruising, bleeding, muscle cramps, abdominal discomfort, dizziness, or confusion. If anything like that develops, they should contact us or seek urgent medical attention straight away.

I won''t repeat the recent blood tests as they were all satisfactory just a week ago, but I will arrange some additional screening to look for reversible causes of confusion. Specifically, I''d like to check his B12, folate, and ferritin levels. I''ll also arrange a home visit to assess George in person and will make a referral to the memory clinic for a formal cognitive assessment.

To help reduce the risk of this happening again, I think it would be sensible for the carers to take a more active role in supervising his medication administration. I can provide clear written instructions to make this as straightforward as possible. If the carers are not comfortable or trained to do this, I''d ask the district nursing team to consider adding a daily medication visit, especially given these are all once-daily tablets. As an additional safety measure, it may be worth discussing with George whether he''d be happy for his medications to be kept securely stored — I''d want to explain that this is purely for his safety and make sure he is agreeable to it.

I''d also like to liaise with the pharmacy to arrange an early replacement supply so there is no gap in his treatment. And with George''s consent, I''ll contact his son William to make him aware of the situation, including the concern about his memory and the steps we''re putting in place. Given his history of falls and limited mobility, I''ll also arrange for him to have a personal falls alarm. Finally, I think a referral to the frailty team or occupational therapy for a home assessment would be worthwhile to make sure his care package remains appropriate. Thank you again, Janet — your prompt escalation has been really valuable.',
  ARRAY['In cases of minor accidental double dosing in an elderly patient, hospital admission is not always necessary if the medications are not highly toxic and the patient remains asymptomatic; use TOXBASE and the BNF if uncertain about specific drug safety','A confusion screen for reversible causes should include B12, folate, and ferritin; recent normal FBC, U&Es, CRP, and LFTs do not need to be repeated','Accidental medication errors in older adults with memory difficulties should prompt referral to a memory clinic and consideration of carer-supervised medication administration','Clopidogrel, Ramipril, Atorvastatin, and Tamsulosin are not typically dangerous in minor accidental overdose when the patient is well, but monitoring for drug-specific side effects is essential','NICE guidance advises hospital admission if a patient exceeds the daily dose of two or more cardiotoxic agents such as beta blockers or calcium channel blockers — awareness of this threshold is important even when it does not apply','Safeguarding and frailty referrals, personal falls alarms, and next-of-kin communication are all important components of holistic management in vulnerable elderly patients'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  50,
  'Headaches in a Woman on the Pill',
  'Gynaecology & Women''s Health',
  'Telephone consultation',
  false,
  'Claire Donovan',
  '28-year-old female',
  ARRAY[]::text[],
  ARRAY['Microgynon','No known drug allergies'],
  'Letter from sexual health clinic (2 years ago). Re: Claire Donovan | 28 years old | Female. Claire was reviewed in our sexual health clinic. A full sexually transmitted infection screen was carried out, all results negative. A pregnancy test at the time was also negative. Background history includes migraine without aura. Following counselling, she was commenced on the combined oral contraceptive pill, Microgynon. Repeat prescriptions to be obtained from her GP. She was counselled on missed pill rules and sick day rules.',
  'Patient has booked a telephone consultation to discuss worsening migraines over the last six months.',
  'My migraines have been getting worse over the last six months and I''m not sure what''s causing it or what I should be taking for them.',
  'The headache tends to be on the right side, towards the front of my head. It''s a throbbing pain and bright light makes it worse. It feels just like my usual migraines. But I''ve noticed they only seem to happen during the week I stop taking my pill.',
  ARRAY['You do not experience any aura symptoms such as zigzag lines, flashing lights, or sensory changes like numbness or tingling. You have no blurred vision and no weakness anywhere in your body.','You have a history of migraines and paracetamol and ibuprofen used to help, but they are no longer providing relief. You currently take paracetamol and ibuprofen when headaches occur but with limited effect.','You use paracetamol and ibuprofen approximately five to six times per month.','You started Microgynon for contraception around two years ago and had migraines before starting the pill.'],
  'You do not smoke, drink alcohol, or use recreational drugs. You live with your long-term partner. You work as an estate agent and have no significant work-related stress. You are sexually active with one partner only.',
  'You are not sure what is causing your headaches.',
  'The headaches are becoming more frequent and this is starting to worry you.',
  'You would like the GP to explain what is causing the headaches and whether anything further needs to be done. If the GP suggests stopping the combined oral contraceptive pill, say that you do not want to stop it and that you are very happy using it and wish to continue.',
  ARRAY['If the GP offers to stop your combined oral contraceptive pill: state that you do not wish to stop it. Say you are very happy with the pill and would like to continue using it.'],
  NULL,
  'Say NO to any questions outside the details already provided in this scenario.',
  ARRAY['Ask about the location, onset, and character of the headache, for example whether it is throbbing, stabbing, dull, or sharp','Ask whether the headache radiates and whether it is improving, worsening, or remaining the same','Ask whether the headache is constant or intermittent, how long each episode lasts, and how frequently episodes occur','Ask whether the headache occurs only during the pill-free interval or at other times as well — if it occurs only during the pill-free interval this suggests oestrogen withdrawal headache; if it occurs while taking the pill this may suggest worsening migraine and could require stopping the pill','Ask about aura symptoms prior to the headache, such as visual disturbances including zigzag lines or flashing lights, or sensory changes such as numbness or tingling','Ask about associated symptoms including nausea, vomiting, photophobia, visual disturbance, fever, rash, and neck stiffness','Explore potential triggers such as stress, emotional distress, or menstrual cycle timing','Ask whether the headache wakes the patient from sleep, which may be a red flag','Screen for neurological symptoms including unilateral weakness, numbness, or slurred speech','Ask about any recent head trauma within the last three months to help exclude subdural haematoma','Ask what medications the patient is using for headache relief and how frequently they are used, in order to explore the possibility of medication overuse headache — for example using NSAIDs or paracetamol 15 or more days per month, or triptans or opioids 10 or more days per month','Ask about the impact on daily activities and quality of life','Ask about lifestyle factors including smoking, alcohol, and recreational drug use','Explore the patient''s ideas, concerns, and expectations','Make a diagnosis of oestrogen withdrawal headache'],
  ARRAY['Offer a face-to-face appointment to perform a full neurological examination, blood pressure check, and fundoscopy','Recommend keeping a headache diary to monitor frequency, duration, triggers, and response to treatment','Advise that as the headaches occur only during the pill-free interval, several options are available: (1) Continue the combined oral contraceptive pill without a break for three months at a time — the tricycling regimen — which reduces headache frequency to approximately four to five episodes per year; (2) Consider switching to a progesterone-only contraceptive method; (3) Offer short-term perimenstrual prophylaxis with a triptan such as frovatriptan 2.5 mg twice daily or zolmitriptan 2.5 mg twice daily, starting two days before the expected onset and continuing for five to six days; (4) Use oestrogen supplementation during the pill-free interval, for example an oestrogen patch 100 micrograms applied twice during the hormone-free week, oestrogen gel 1.5 mg daily during the pill-free interval, or oral oestradiol valerate 2 mg daily during the pill-free interval','Provide lifestyle advice including stress management, reducing screen time, maintaining good hydration, ensuring adequate sleep, and engaging in regular physical activity','Provide clear safety-netting advice to seek urgent medical attention if headaches suddenly worsen, change in character, are associated with neurological symptoms, or become unresponsive to treatment','Provide stroke safety-netting advice to call emergency services immediately if she develops slurred speech, weakness, numbness or tingling in any part of the body, or visual disturbance','Arrange follow-up in four to six weeks to review progress'],
  'Thank you so much for getting in touch today, Claire — it sounds like these headaches have been quite disruptive, and I can understand why you''re keen to get to the bottom of them. From everything you''ve described, the headaches themselves sound very typical of your usual migraines — the throbbing quality, the right-sided frontal location, and the sensitivity to light all fit that pattern well. What stands out here, though, is that they are now happening specifically during the week you stop taking your pill. That is a really important clue.

What I think is happening is something called an oestrogen withdrawal headache. When you stop Microgynon for that seven-day break each month, the level of oestrogen in your body drops. In some people — particularly those with a history of migraines — that hormonal drop can act as a trigger. So it''s not that your migraines are becoming more dangerous, but rather that the monthly dip in hormone levels is setting them off. Does that make sense?

The reassuring news is that there are several ways we can manage this without stopping the pill, especially as you''re happy to continue with it. One option is to change the way you take your pill. Rather than taking it for three weeks and then having a seven-day break every month, you could take it continuously for three months and only then have a short break. This is sometimes called the tricycling regimen, and by reducing the number of hormone-free intervals, you can cut down the number of migraine episodes to roughly four or five times a year instead of every month. How does that sound?

Another approach would be to use a short course of medication during the pill-free week to prevent the headaches from starting. One option is a medication called frovatriptan 2.5 mg taken twice daily, starting two days before your pill-free interval and continuing for around five to six days. There is also the option of using a small amount of oestrogen during the pill-free week to smooth out the hormonal drop — this can be done with an oestrogen patch, gel, or tablet taken during that week. Alternatively, if none of those options suit you, switching to a progesterone-only contraceptive, which does not contain oestrogen, would avoid the hormonal fluctuation altogether.

Alongside whichever option we agree on, it''s worth keeping a headache diary to track when they occur, how long they last, and what helps. This will be really useful when we review how things are going. General measures like staying well hydrated, getting good sleep, managing stress, and reducing screen time can also help reduce migraine frequency over time.

I''d like to arrange a face-to-face appointment so I can check your blood pressure, carry out a neurological examination, and take a look at the back of your eyes — all just to make sure there''s nothing else contributing. I''ll arrange a follow-up in four to six weeks to see how you''re getting on. In the meantime, if your headaches suddenly become much worse, feel different from your usual migraines, or are accompanied by any neurological symptoms such as slurred speech, weakness, numbness, or changes in your vision, please seek urgent medical attention — or call 999 if those symptoms come on suddenly.',
  ARRAY['Headaches occurring exclusively during the pill-free interval in a woman taking a combined oral contraceptive are characteristic of oestrogen withdrawal headache, not worsening migraine','The tricycling regimen — taking the combined pill continuously for three months before a break — reduces oestrogen withdrawal headaches to approximately four to five episodes per year','Perimenstrual triptan prophylaxis, such as frovatriptan 2.5 mg twice daily or zolmitriptan 2.5 mg twice daily, started two days before the pill-free interval and continued for five to six days, is an effective alternative','Oestrogen supplementation during the pill-free week, using a patch (100 micrograms), gel (1.5 mg daily), or oral oestradiol valerate (2 mg daily), can smooth the hormonal drop that triggers migraines','Medication overuse headache should be considered in any patient using analgesics such as paracetamol or NSAIDs on 15 or more days per month, or triptans on 10 or more days per month','Safety-netting for stroke is essential — patients should call 999 immediately if they develop slurred speech, focal weakness, numbness, or sudden visual disturbance'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  51,
  'PSA Blood Test Results',
  'Men''s Health',
  'Video consultation',
  false,
  'Kwame Asante',
  '58-year-old male',
  ARRAY[]::text[],
  ARRAY['Amlodipine 10 mg once daily','Atorvastatin 20 mg at night','Tamsulosin 400 mcg once daily','No known drug allergies'],
  'Seen in clinic 1 week ago. Presenting complaint: worsening lower urinary tract symptoms (LUTS) despite being on tamsulosin. Examination: PR examination — enlarged prostate, no masses, no tenderness. Urinalysis — clear. Plan: PSA, HbA1c, U+Es, urine culture. Discuss results at follow-up. Results now available: PSA (Prostate-Specific Antigen) 45 ng/mL (reference range < 3.5 ng/mL). Patient has booked a follow-up appointment to discuss results.',
  'Patient has booked a follow-up video consultation to discuss his recent blood test results.',
  'Hello Doctor, I''ve come back to hear about my blood tests. I''m hoping to find out what''s going on.',
  'Over the past month or so my waterworks symptoms have been getting worse. I''ve been getting up several times at night to pass urine, sometimes there''s dribbling into my underwear afterwards, and I never quite feel like I''ve fully emptied my bladder. The doctor I saw last week examined me and said my prostate felt enlarged, which might be the cause. He suggested some blood tests to investigate.',
  ARRAY['You prefer to be called Kwame.','You do not smoke, drink alcohol, or use recreational drugs. You are married with children. You work as a civil engineer.'],
  'You are a non-smoker, do not drink alcohol, and do not use recreational drugs. You are married with children. You work as a civil engineer.',
  'You believe your symptoms are likely caused by your prostate.',
  'You are mainly concerned about the discomfort — your symptoms are becoming increasingly difficult to manage and are affecting your daily life.',
  'You would like to be given medication to help shrink the prostate and improve your symptoms. If the doctor suggests an urgent referral to a specialist, ask: "Can''t you just prescribe something first to shrink the prostate and see if that helps?"',
  ARRAY['If the doctor suggests an urgent referral to a specialist, respond by asking: "Can''t you just prescribe something first to shrink the prostate and see if that helps?"'],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Ask the patient why the blood tests were arranged','Ask about current urinary symptoms including nocturia, frequency, urgency, poor stream, intermittency, straining, post-void dribbling, incomplete emptying, and any accidental leakage','Ask if there has been any visible blood in the urine (haematuria)','Ask about any associated back pain','Ask if the patient has experienced fever, abdominal pain, or discomfort in the rectal or pelvic area, to help rule out prostatitis','Ask about red flag symptoms such as night sweats or unintentional weight loss','Ask about family history of prostate cancer','Ask about lifestyle factors including smoking, alcohol intake, and occupation','Ask whether the patient followed pre-test instructions before the PSA blood test, for example avoiding ejaculation or vigorous exercise such as cycling in the 48 hours prior','Explain the raised PSA result clearly and in plain language'],
  ARRAY['Offer a referral to the two-week wait (2WW) urology pathway and explain that this is necessary given the significantly raised PSA result, which could indicate a possibility of prostate cancer','Explain that the urologist may carry out further investigations such as an MRI scan of the prostate and possibly a biopsy — a small tissue sample — to help make a clear diagnosis','Provide cancer safety-netting advice: if the patient has not heard anything or been seen within two weeks, advise him to contact the GP surgery immediately so that the referral can be followed up','Do not prescribe finasteride at this stage, as it can artificially lower PSA levels and interfere with the interpretation of future diagnostic tests; gently explain that although it may help with symptoms, it is important to wait until the specialist has assessed the situation before starting it','Offer a follow-up appointment after the urology consultation to review the outcome, provide ongoing support, and discuss next steps in management based on the urologist''s findings'],
  'Thank you for coming back to discuss your results today, Kwame — I know it can feel unsettling waiting for news, and I appreciate your patience. I can see that the urinary symptoms have been really interfering with your daily life, particularly being woken up at night and that sensation of not fully emptying your bladder. That is genuinely uncomfortable and I want to make sure we take the right steps to help you.

The blood test we did to check your prostate — called the PSA test, which stands for prostate-specific antigen — has come back at 45 ng/mL. The normal range for someone your age is below 3.5 ng/mL, so this result is considerably higher than we would expect. Now, I want to be straightforward with you about what this means, while also being careful not to jump to conclusions.

A raised PSA can sometimes be explained by having an enlarged prostate on its own, which we already know you have. However, a result this significantly elevated also raises the possibility that something more serious may be happening, such as prostate cancer. I am not telling you that you have cancer — that can only be determined by further specialist tests — but it would not be right for me to simply ignore a result like this. The most important thing is that we act promptly so that we can find out exactly what is going on.

What I would like to do is refer you urgently to a specialist called a urologist. This is done through a pathway specifically designed to ensure you are seen within two weeks. The urologist will be able to arrange more detailed tests, which may include an MRI scan of the prostate and possibly a small tissue sample called a biopsy. These investigations will give us a much clearer picture.

I can hear that you were hoping for a prescription to help shrink the prostate, and I completely understand that — you want your symptoms to improve and that is entirely reasonable. However, certain medications used for that purpose, such as finasteride, can actually lower PSA levels and may interfere with the accuracy of the specialist''s investigations. Starting it now could make it harder to get a clear result, so I would strongly recommend we hold off on that until after the urologist has assessed you.

If you have not heard from the urology team within two weeks, please contact us straight away and we will chase the referral on your behalf. In the meantime, if you develop any new symptoms such as blood in your urine, significant pain, or if you are unable to pass urine at all, please get in touch with us promptly. Once we have the specialist''s findings, I will arrange a follow-up with you so we can go through everything together and plan the next steps.',
  ARRAY['A PSA of 45 ng/mL in a 58-year-old man is significantly above the age-specific threshold of 3.5 ng/mL and warrants an urgent two-week wait urology referral to exclude prostate cancer','Finasteride must not be prescribed before specialist assessment as it can artificially lower PSA levels and interfere with diagnostic test interpretation','The urologist will likely arrange an MRI scan of the prostate and potentially a biopsy to establish a clear diagnosis','Pre-test instructions matter: ejaculation or vigorous exercise such as cycling within 48 hours of PSA testing can raise the result falsely — always ask whether these were avoided','Benign prostatic hyperplasia and prostate cancer can coexist; an enlarged prostate on examination does not exclude malignancy','Safety-netting for a two-week wait referral should include advice to contact the surgery if not seen within two weeks so the referral can be chased'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  52,
  'Acute Chest Pain',
  'Cardiology',
  'Telephone consultation',
  false,
  'Adrian Norris',
  '53-year-old male',
  ARRAY[]::text[],
  ARRAY['Ramipril 10 mg once daily','Atorvastatin 20 mg at night','No known drug allergies'],
  'Patient has booked an urgent telephone appointment to discuss ongoing concerns.',
  'Patient has booked an urgent telephone appointment due to recent episodes of chest pain.',
  'Hi Doctor, thanks for calling. I''ve been having some chest pain since yesterday — it started about 11 hours ago. It felt a bit like heartburn at first but then turned into a dull ache. It lasted around 30 minutes and has happened again today while I was helping my line manager at work move some boxes and rearrange some furniture.',
  'The first episode started approximately 11 hours ago. It initially felt like heartburn before developing into a dull ache in my chest. That episode lasted around 30 minutes and came on while I was sitting at home watching television. It was also accompanied by shortness of breath and palpitations — my heart felt like it was racing. I''m currently at work and had another similar episode about 40 minutes ago when I was helping move some boxes. That one also lasted around 30 minutes. I''m not in any pain right now — it has settled. My partner urged me to call because she was worried, though I thought it might just be a pulled muscle.',
  ARRAY[]::text[],
  'I don''t smoke or drink alcohol. My diet is fairly poor — mostly convenience food — and my job is quite sedentary. I don''t really exercise. Family history: my father had a heart attack at age 55.',
  'I think the chest pain might be a pulled muscle or indigestion, especially since it came on while I was moving things around.',
  'I''m a bit worried because it keeps coming back, and my partner is particularly anxious given that my father had a heart attack at 55.',
  'I''d like to know whether this is anything serious and whether I need any tests or something for the pain.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered by the doctor. If the doctor advises hospital admission, politely ask: "Would it be okay if I drive myself to the hospital?"',
  ARRAY['Ask about the character of the pain — whether it is dull, sharp, pressure-like, or crushing','Ask about the location of the pain and whether it is central, left-sided, or in another area','Ask whether the patient is currently experiencing chest pain and when the last episode occurred','Ask how long each episode of chest pain has lasted','Ask about relieving factors, for example whether the pain improves with rest or with changes in position','Ask whether the pain radiates to the jaw, neck, shoulders, arms, or back','Ask about associated symptoms including shortness of breath, palpitations, dizziness or lightheadedness, nausea, or sweating','Ask about fever to help rule out infective or inflammatory causes such as pericarditis or pneumonia','Ask about any family history of heart attack, stroke, or sudden cardiac death, particularly in relatives under the age of 60','Ask about lifestyle factors including smoking, alcohol consumption, dietary habits, occupation, and stress levels','Establish a working diagnosis of acute coronary syndrome'],
  ARRAY['Arrange emergency admission to hospital via 999 — clearly advise the patient that you will arrange an ambulance and that he must not drive or make his own way to hospital','Advise that if another episode of chest pain occurs while waiting for the ambulance, he or someone with him should call 999 immediately','Ask whether there is someone with him at work and advise that person to be made aware of the situation and to remain with the patient in case his condition deteriorates','Request the postcode or address of the patient''s workplace as he is currently there — this is essential information for ambulance dispatch','Explain that once in hospital, the team will perform an ECG, which is an electrical recording of the heart, and a blood test to check for troponin, a chemical released when the heart muscle is under stress; if these suggest a heart attack the specialist team will offer treatment to restore blood flow to the affected artery','Advise the patient to book a follow-up appointment after discharge to review the hospital findings, discuss any new medications prescribed, and explore lifestyle changes including improving diet, increasing physical activity, and managing stress'],
  'Thank you for calling in today — it''s really good that you got in touch, and I want to make sure we deal with this safely and promptly. I can hear that you were hoping this might just be a muscle strain or indigestion, and I understand that, but I have to be honest with you about what your symptoms suggest.

The pattern you''ve described — a dull aching chest pain that came on at rest last night, lasted around 30 minutes, was accompanied by shortness of breath and a racing heart, and then happened again today during physical activity — is something I take very seriously. These features are consistent with what we call acute coronary syndrome, which is when the blood supply to the heart is partially or fully reduced, often due to a narrowing or blockage in one of the heart''s blood vessels. If that''s what''s happening, it''s a medical emergency and time matters greatly.

I know you mentioned that your partner thought it might be serious, and given your father''s heart attack at 55, you were right to make this call. I want to act quickly to make sure you get the right assessment and care.

What I''m going to do right now is arrange for an ambulance to come to you. I need to be clear about this — please do not drive yourself to hospital and please do not travel alone. If another episode of chest pain starts before the ambulance arrives, call 999 immediately. Is there anyone with you at work at the moment? If so, please let them know what''s happening and ask them to stay with you.

Could you also give me the postcode or address of your workplace? That''s essential for me to pass on to the ambulance service so they can find you quickly.

Once you are at hospital, the team there will carry out an ECG — that''s an electrical tracing of your heart — and a blood test to check for a substance called troponin, which rises in the bloodstream when the heart muscle is under stress or has been damaged. If those tests confirm a problem with blood flow to your heart, the specialist team will have treatments available to help restore it.

Once you''ve been assessed and discharged, please book a follow-up with us. We can then talk through the hospital findings together, review any new medications, and look at some lifestyle changes — things like improving your diet, building in some regular physical activity, and managing stress — which can all make a real difference for your heart health going forward.',
  ARRAY['Chest pain at rest lasting 30 minutes or more, accompanied by shortness of breath and palpitations, is a red flag presentation consistent with acute coronary syndrome and requires immediate 999 ambulance transfer','Never advise a patient with suspected ACS to drive themselves to hospital or travel unaccompanied','The postcode or address of the patient''s current location is essential information to obtain for ambulance dispatch, particularly if they are not at their registered address','In hospital, an ECG and troponin blood test are the key initial investigations for suspected acute coronary syndrome','Troponin is a cardiac biomarker released into the bloodstream when myocardial cells are damaged or under significant stress','Family history of myocardial infarction, particularly under the age of 60, is an independent cardiovascular risk factor and should always be explored in chest pain consultations'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  53,
  'Psychosis in a Teenager',
  'Mental Health',
  'Telephone consultation',
  false,
  'Nathan Fowler',
  '16-year-old male',
  ARRAY[]::text[],
  ARRAY['Oilatum cream','Eumovate cream (used during flares)','No known drug allergies'],
  'Caller: Karen Fowler (mother), calling to discuss her son''s condition.',
  'Mother calling on behalf of her 16-year-old son who has been displaying unusual and concerning behaviour over the past two to three weeks.',
  'Hello, I''m calling because I''m very worried about my son Nathan. He''s been acting very strangely over the last few weeks and I don''t know what to do.',
  'Nathan has been saying that people are following him and watching what he does. I''ve heard him talking to himself as though he''s having a full conversation with someone who isn''t there. He says he hears two voices. Sometimes the voices tell him to do inappropriate things like take his clothes off, and at other times they tell him he is royalty from a country he''s never been to and has no connection with. He''s also become really irritable — he loses his temper easily, shouts at us for no reason, and has threatened to hurt me and his younger sister who is 13.',
  ARRAY['He has no fever and hasn''t been physically unwell in any way.','You found out he has been drinking alcohol and smoking. You''re not certain about drug use but have smelled cannabis coming from his room.','He is in Year 11 preparing for his GCSE exams.','There is a family history of mental illness — schizophrenia in his cousins on your side of the family, and bipolar disorder in his father, which is currently well controlled.'],
  'You have found out he has been drinking alcohol and smoking. You are not certain about drug use but have smelled cannabis in his room. He is in Year 11 and preparing for his GCSE exams. There is a family history of mental illness — schizophrenia in his cousins, and bipolar disorder in his father, which is currently well controlled.',
  'You suspect this is a mental health problem.',
  'You are scared he might harm himself or his younger sister.',
  'You want help and urgent advice on what can be done.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Ask about the onset and duration of the hallucinations','If one type of hallucination is reported, ask about others — for example if the patient is described as seeing things that others cannot see (visual hallucinations), ask whether he also hears voices others cannot hear (auditory hallucinations) or experiences unusual physical sensations such as feeling something crawling on his skin (tactile hallucinations)','If auditory hallucinations are reported, ask what the voices say or instruct the patient to do','Ask about paranoid ideation, such as a belief that people are talking about or watching him','Ask about unusual thought experiences that may suggest psychosis, including feeling that thoughts are being removed from his mind (thought withdrawal), that thoughts are being placed into his mind (thought insertion), that others can hear or know his thoughts (thought broadcasting), or giving unusual personal meaning to ordinary events (delusional perception)','Ask directly about any thoughts of self-harm, suicide, or intention to harm others','Ask about any previous personal history of mental health difficulties','Screen for red flags such as headache, fever, or neck stiffness to help rule out viral encephalitis or meningitis','Ask whether the patient was physically unwell in the period before these symptoms began, for example with a cough or urinary symptoms, to exclude an infective cause or delirium','Ask about substance use including alcohol, cannabis, and other drugs','Ask about his home and school life and explore how these behavioural changes may be affecting his daily routine, studies, and relationships with family and classmates','Ask about any previous diagnosis of depression, psychosis, or personality disorder','Ask about family history of schizophrenia or other mental health conditions','Establish a working diagnosis of acute psychosis'],
  ARRAY['Urgently refer the patient same day to the local CAMHS (Child and Adolescent Mental Health Services) crisis team for assessment of possible first-episode psychosis','Inform the mother that the CAMHS crisis team will arrange to visit Nathan at home to assess him and offer support; if admission is felt to be necessary for his safety or the safety of others, they will recommend this; if Nathan refuses and is deemed to be at significant risk, they may proceed with compulsory admission under the Mental Health Act','Advise that during any admission, further investigations including blood tests will be carried out to rule out physical causes of his symptoms, and medication may be offered; if cannabis use is confirmed, a drug and alcohol support service may also be involved to support reduction or cessation','Encourage the mother to keep Nathan safe at home and ensure that sharp objects, medications, and any substances are kept out of his reach','Make a safeguarding referral due to concerns about Nathan''s threatening behaviour at home, particularly the risk he may pose to his younger sister; the safeguarding team will assess the situation holistically, offer support to the whole family, and help ensure everyone''s safety, including monitoring the wellbeing of the younger sibling','Offer the mother a follow-up appointment to check in and provide ongoing support, including signposting to young person mental health charities and parent support groups','Reassure the mother that she has done the right thing by calling and that early intervention gives the best outcomes','Advise the mother to call 999 or go to A&E if Nathan becomes aggressive, appears suicidal, or seems to be in immediate danger'],
  'Thank you so much for calling today — I can hear how frightening this has been for you, and I want you to know that you have absolutely done the right thing by getting in touch. What you have described about Nathan is serious, and I want to be as helpful and as honest with you as I can.

From what you''ve told me — the voices he''s hearing, the belief that people are watching him, the things the voices are telling him to do, and the threatening behaviour towards you and his sister — these are symptoms that we associate with a condition called psychosis. Psychosis is a state in which a person loses touch with reality. It can involve hearing or seeing things that others cannot, holding unusual beliefs, and experiencing confused or disorganised thinking. I want to reassure you that this can happen to young people, and it is treatable, particularly when it is picked up early.

There are a few possible causes that we need to explore. One is that Nathan may be developing a mental health condition such as schizophrenia, which given your family history is something we do need to consider. Another possibility is that the cannabis you''ve noticed, or other substances, may be contributing to or triggering these symptoms. Cannabis in particular, especially in young people whose brains are still developing, can sometimes cause exactly this kind of presentation. It''s also important for the specialist team to check that there is no underlying physical cause — infections affecting the brain, for example, can occasionally produce similar symptoms.

The most important step right now is to get Nathan seen urgently by the right team today. I''m going to refer him to the CAMHS crisis team — that stands for Child and Adolescent Mental Health Services. They are trained specifically to support young people in situations like this, and they will arrange to come to your home to assess Nathan directly. I know he has been reluctant to seek help, but the team are experienced in engaging young people sensitively, even when they don''t want to engage initially. If Nathan''s symptoms pose a serious risk to himself or others and he refuses help, the team do have the legal authority to arrange an assessment and, if necessary, an admission even without his consent. This is what some people refer to as being sectioned under the Mental Health Act, and it is used only when there is no other way to keep everyone safe.

In the meantime, I want you to take some precautions at home. Please make sure that any sharp objects, medications, or substances are stored safely out of his reach. And if at any point Nathan becomes physically aggressive, you believe someone is in immediate danger, or you are genuinely frightened for his or your own safety, please call 999 straight away or take him to A&E.

I also want to flag something important. Given what you''ve described — particularly the threats towards his younger sister — I do need to make a safeguarding referral to ensure she is protected and that the right support is in place for your whole family. The safeguarding team will work alongside the CAMHS team and can help with family support and making sure everyone is safe. I''d also like to arrange a follow-up for you, because I know how hard this is as a parent. There are also some really good organisations that offer support to families going through exactly this kind of situation, and I can point you towards those as well. You are not alone in this.',
  ARRAY['New-onset psychosis in a teenager warrants same-day CAMHS crisis referral for assessment of first-episode psychosis — do not delay this','Cannabis misuse is a recognised trigger for psychotic episodes in young people, particularly in those with a family history of psychotic illness, and substance use history must always be explored','Red flags including headache, fever, and neck stiffness must be screened for to exclude viral encephalitis or meningitis as a physical cause of acute psychosis','If a young person refuses assessment and poses a significant risk to themselves or others, compulsory assessment and admission under the Mental Health Act can be arranged by the CAMHS crisis team','A safeguarding referral is essential when there are credible threats of harm towards siblings or other household members — do not omit this step even when the primary focus is psychiatric','Early intervention in first-episode psychosis is associated with significantly better long-term outcomes — reassuring the family and supporting engagement with services is a key part of the GP''s role'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  54,
  'Deteriorating Patient with Alcohol History',
  'Gastroenterology & Haematology',
  'Video consultation',
  false,
  'Stephen Carver',
  '54-year-old male',
  ARRAY[]::text[],
  ARRAY['Ramipril 10 mg once daily','Atorvastatin 20 mg at night','Tamsulosin 400 mcg once daily','No known drug allergies','Smoker: 20 cigarettes per day for the past 15 years (last update: 6 weeks ago)'],
  'Seen in clinic 6 weeks ago. Presenting complaint: episodes of rectal bleeding and unintentional weight loss. Examination: rectal examination revealed a palpable rectal mass. Patient noted to smell strongly of alcohol at the time of assessment. Plan: blood tests including FBC and liver function, FIT (Faecal Immunochemical Test). Referral made under the 2WW colorectal cancer pathway due to red flags (bleeding, weight loss, rectal mass). Note (3 weeks ago): patient missed two appointments for blood tests — advised to call and reschedule if unable to attend. Letter from colorectal team: "You referred Stephen on account of PR bleeding, weight loss, and a rectal mass. He has missed two appointments and has not responded to our calls. There will be no further appointments sent. If clinical concerns remain, please re-refer and we will be happy to see him." Signed: Mr Richard Holt, MCh FRCS(Colorectal), Consultant Colorectal Surgeon. Caller: Ms Sandra Webb, Adult Social Worker, calling to discuss Stephen Carver''s case with a GP.',
  'Adult social worker calling to discuss a patient known to the practice who has been found at home in a concerning condition.',
  'Hello, I''m Sandra Webb, a social worker. I''m calling because I''ve been contacted about one of your patients, Stephen Carver, and I''m very worried about him. I was hoping to speak with the GP.',
  'One of Mr Carver''s neighbours — who happens to be a nurse — contacted adult social services this morning because she hadn''t seen him walking his dogs for over a week, and she''d noticed his dog appeared to be in poor condition. Suspecting he might be in difficulty, she entered his flat and found him on the floor, heavily intoxicated. She recorded his observations: blood pressure 90/58 mmHg, pulse 109 bpm, oxygen saturation 96% on air. She wanted to call an ambulance but he refused. When I arrived, I found him lying on the floor surrounded by empty vodka bottles. He smelled strongly of alcohol. He was conscious but very drowsy, confused, and seemed to be making up details to fill in gaps in what he was saying. I''m very worried about his physical health.',
  ARRAY['His hands were shaking visibly when I arrived.','He was conscious but confused, sweating, and said his heart felt like it was racing.','Hospital letters were scattered by the front door — he says he hasn''t attended his appointments because he didn''t want to leave his dog unattended.','He lives alone and has no family contact. He has a son in France, but they are not in contact.'],
  'He lives alone and has no family contact. He has a son in France but they are not in contact. He is a smoker and has significant alcohol misuse.',
  'You believe he may be physically unwell, likely due to complications related to his alcohol use.',
  'You are very worried about his physical health, his level of self-neglect, and his mental state.',
  'You would like a GP assessment and hope that urgent support can be put in place to ensure his safety and health are prioritised.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Begin by thanking the social worker for escalating her concerns and for taking the time to call','Ask whether the patient is alert and orientated, or if he appears confused or drowsy','Ask about any signs of shakiness or tremors','Ask whether the patient has complained of a racing heartbeat or palpitations','Explore whether the patient has mentioned feeling unwell, including fever, vomiting, or nausea','Ask whether the neighbour or social worker has witnessed any seizures','Ask whether the patient has reported any visual disturbances, such as double or blurred vision, which could suggest ophthalmoplegia','Ask whether there is still ongoing or worsening rectal bleeding and, if so, assess for symptoms of possible anaemia such as fatigue, dizziness, or breathlessness','Ask about the home environment, including whether the property appears unkempt, and confirm whether the patient lives alone','Explore whether the patient has shown signs of low mood or depression','Ask whether the patient has been taking his prescribed medications and whether there is any concern about accidental or intentional overdose','Ask whether the patient has any next of kin or family contact and whether they are aware of the current situation','Inform the social worker that based on what has been described, the patient may be experiencing alcohol withdrawal symptoms and will likely require urgent hospital admission for further assessment and management'],
  ARRAY['Arrange an ambulance for urgent hospital admission to enable medical stabilisation, alcohol detoxification, and further investigation of the suspected colorectal pathology while under inpatient care','Advise the social worker that you will inform the hospital team in advance about his physical condition and social circumstances to support appropriate discharge planning from the outset','Advise that following discharge, an assessment will be arranged to determine whether a short-term placement in a respite or supported care facility is needed to prevent future self-neglect','Acknowledge that this constitutes a safeguarding concern due to self-neglect and confirm that the social worker will take this forward as part of her professional role — a separate GP safeguarding referral is not required as the social worker is already part of the adult safeguarding team','Ask whether the social worker can assist in contacting relevant pet welfare organisations such as The Cinnamon Trust or the PDSA Vet Charity to arrange short-term care for his dog during the admission; if this cannot be arranged, advise that you can escalate this to your in-house social prescriber for urgent support','Once the patient is more stable and alert, seek his consent before contacting his next of kin so that a relative can be kept informed in the event of future emergencies','Thank the social worker for her involvement and assure her that you will keep her updated following the patient''s discharge from hospital'],
  'Thank you so much for calling, Sandra, and for everything you''ve done to escalate this so quickly — it''s clear that without the neighbour''s intervention and your response today, Stephen could have been in a very serious situation for a lot longer. I really do appreciate it.

Based on what you''ve described — the confusion, the shaking, the fast heart rate, the sweating, and the heavy alcohol use — I''m concerned that Stephen may be experiencing alcohol withdrawal. This can be a life-threatening condition if it is not treated properly and in a timely way. The confusion and the way he seems to be filling in memory gaps with things that aren''t real are also worrying signs that his brain may be under significant stress, possibly from prolonged heavy alcohol use.

On top of that, I can see from his notes that six weeks ago we identified some very concerning findings — rectal bleeding, unintentional weight loss, and a palpable rectal mass on examination. He was referred urgently to the colorectal team, but he has since missed all of his appointments and has not been responding to their attempts to contact him. The fact that hospital letters were piling up unopened at his front door suggests he has been struggling for some time. These findings need to be investigated urgently, and being admitted to hospital gives us the best opportunity to do that while also addressing the acute alcohol problem.

The safest and most appropriate step right now is for Stephen to be admitted to hospital urgently via ambulance. I will arrange that straight away. I''ll also make sure to contact the hospital team before he arrives to give them the full picture — both the acute presentation and his background of missed investigations — so they can start planning appropriately from the outset. Once he is more settled, the team can think about what support he will need on discharge, whether that is a period in a respite or supported care facility, or additional community support to prevent him from ending up back in this situation.

In terms of his dog — I can hear that this has been part of why he has been reluctant to leave home and attend appointments. Would you be able to make contact with The Cinnamon Trust or the PDSA Vet Charity to arrange short-term animal care during his admission? If that''s not something you''re able to arrange from your side, I can flag this to our in-house social prescriber and ask them to look into it urgently, because I think removing that barrier could make a real difference to his willingness to engage.

What you''ve described also constitutes a clear safeguarding concern — the self-neglect, the alcohol misuse, and the missed urgent cancer investigations all point to a vulnerable adult who needs coordinated support. I know that as a social worker you will be taking this forward through the appropriate safeguarding channels, so I won''t duplicate that referral. But please do keep me informed and I''ll make sure to update you once he has been assessed and a discharge plan is in place. Together I think we can make sure Stephen gets the support he needs.',
  ARRAY['Confusion, tremors, tachycardia, and sweating in a patient with known heavy alcohol use are cardinal features of alcohol withdrawal syndrome, which can be life-threatening and requires urgent hospital admission','Alcohol withdrawal can be complicated by Wernicke''s encephalopathy — confusion and confabulation are red flag features; the hospital team should be made aware','When a patient has missed urgent cancer investigations, these must be re-referred or flagged to the inpatient team so that investigations can be picked up during the admission','When a social worker is already involved and is part of the adult safeguarding team, a separate GP safeguarding referral is not required — the GP should acknowledge the safeguarding concern and confirm that the social worker will lead on this','Pet welfare concerns, such as The Cinnamon Trust or PDSA Vet Charity, can be raised as a practical barrier to hospital engagement and addressed via a social prescriber','Early communication with the receiving hospital team about a patient''s social and clinical background supports better discharge planning and reduces the risk of re-admission'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  55,
  'Transgender Health',
  'Ethics',
  'Telephone consultation',
  false,
  'Emma Thornton (previously known as Adam Thornton)',
  '30-year-old female',
  ARRAY[]::text[],
  ARRAY['Not on any regular medications','No Known Drug Allergies'],
  'Patient booked a routine telephone appointment to discuss concerns. You are Emma Thornton, a 30-year-old transgender woman. You have been feeling low in mood and anxious for the past 2–3 months, particularly after recently undergoing gender reassignment surgery abroad. You would like a sick note, as you have already been off work for over a week. You recently travelled to Thailand to undergo gender reassignment surgery, as you were unable to wait for the two-year social gender role transition required under the NHS pathway. You have now returned to the UK having had breast augmentation, vaginoplasty (creation of a neo-vagina), and orchidectomy (removal of testicles). You are currently on oestrogen and progesterone hormone replacement therapy, which was prescribed by the gender clinic, and they monitor you with regular blood tests. Since returning to work, you''ve been feeling increasingly distressed. You have the impression that some colleagues may be talking about you behind your back, and you don''t feel accepted in the workplace. One colleague recently addressed you by your former name, "Adam," despite your request to be called "Emma." You are also unsure about which toilet you should use at work, as you are now socially female. You feel very low in mood, anxious, and overwhelmed. You have no thoughts of suicide or self-harm. Although you love your job, you do not feel emotionally or mentally ready to return due to the current workplace environment. You would like a Fit Note (sick note), as you do not believe you can cope with work under these circumstances.',
  '',
  'Doctor, I''ve been really struggling since going back to work, and I was hoping to get some support today.',
  'I had surgery abroad a few months ago and things have been very difficult since I returned. I''m feeling low and anxious, and I just don''t feel safe or accepted at work. I''d like a sick note so I can have some time off to focus on my wellbeing.',
  ARRAY[]::text[],
  'You do not smoke, drink alcohol, or use recreational drugs. You live alone but are well supported by your family.',
  'You believe your low mood and anxiety are directly linked to the difficult experience of returning to work after surgery. You feel the social transition has been emotionally challenging as you settle into your identity as a transgender woman.',
  'You are worried that colleagues are talking about you behind your back and treating you differently, making you feel isolated and unwelcome. You are also uncertain about which toilet facilities you are entitled to use at work.',
  'You would like a sick note to take time off work. If offered antidepressants: you do not want medication; your preference is for talking therapy or counselling.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario.',
  ARRAY['Begin by expressing genuine empathy and acknowledging how difficult and upsetting it must be to feel unsupported and singled out at work','Ask how long her mood has been low and whether she feels low all the time','Ask if she has lost interest or enjoyment in activities she would usually do','Ask about changes in appetite and any associated weight loss or gain','Ask about sleep disturbances and feelings of tiredness or low energy','Ask about any thoughts of suicide or self-harm','Ask about lifestyle factors, including smoking, alcohol consumption, and illicit drug use','Ask about physical activity levels','Ask how her symptoms have affected daily life and functioning','Ask about her support system, including family, friends, or anyone at home','Make a working diagnosis of work-related anxiety and depression'],
  ARRAY['Offer the PHQ-9 questionnaire to assess the severity of depressive symptoms','Offer a referral for talking therapy (e.g. counselling or CBT) as a first-line treatment','Offer antidepressant medication as an option','Provide a sick note to support time off work, but explain that this is a temporary solution. Encourage her to speak with her line manager about the discrimination, and if it remains unresolved, to escalate the matter to occupational health (if available) or to her union representative','Advise that her workplace should ideally provide gender-neutral toilets. Explain that, according to the most recent Supreme Court ruling and Equality and Human Rights Commission (EHRC) guidance, access to male or female toilets may be restricted based on biological sex, even for individuals who have transitioned. However, reassure her that the law still protects her from discrimination, and she must never be left without access to a toilet. The workplace has a duty to ensure she has a safe, appropriate facility she can use comfortably.','Signpost to supportive organisations such as Stonewall, TransUnite, and MindOut for additional mental health and LGBTQ+ support','Arrange follow up in 2–3 weeks to review how things are going','Safety net and advise her to seek urgent help if she develops thoughts of suicide or self-harm, including contacting 111, crisis services, or 999 if at immediate risk'],
  'Thank you so much for calling today, Emma, and for being so open about what you''ve been going through. It takes real courage to reach out, and I want you to know that everything you''re feeling makes complete sense given the circumstances.

From what you''ve described, it sounds like you''re experiencing symptoms of work-related anxiety and low mood. This is a very understandable response to the stress of returning to work after major surgery in an environment where you haven''t felt accepted or supported. What you''re describing — colleagues talking behind your back, being addressed by your previous name despite having made your wishes clear — is not something you should have to put up with, and I''m truly sorry you''ve been through that.

In terms of practical support, I can issue you a sick note today so that you can take some time away from work to focus on your mental health. I want to be clear that this is a short-term measure, and that we should also look at addressing the root cause of the problem. I would strongly encourage you to speak with your line manager or a senior colleague about what has been happening. If those concerns are not taken seriously, the next step would be to involve occupational health or your union representative, who can advocate on your behalf.

On the question of which toilet facilities you can use at work, I know this has been a source of worry for you. Under the most recent Supreme Court ruling and Equality and Human Rights Commission (EHRC) guidance, some organisations may restrict access to gendered spaces based on biological sex. However, the law is clear that you must never be left without access to a suitable facility. Your employer has a duty to ensure you have a safe and appropriate option — ideally, this would mean gender-neutral toilets being available.

In terms of support for your wellbeing, I''d like to refer you for talking therapy. Counselling or CBT can provide a confidential space to work through how you''re feeling and develop strategies for coping. I''m also offering antidepressant medication as an option, though I understand from what you''ve said today that you''d prefer to explore talking therapies first — and that is absolutely a valid and reasonable choice.

I''ll also signpost you to some additional organisations that may be helpful, including Stonewall, TransUnite, and MindOut, which offer mental health support specifically for LGBTQ+ individuals. Let''s arrange a follow-up in two to three weeks so I can see how you''re getting on. And please remember — if at any point you find yourself having thoughts of harming yourself, do not hesitate to contact 111, a crisis service, or 999 in an emergency. You are not alone in this.',
  ARRAY['Transgender patients presenting with low mood and anxiety following gender-affirming surgery should be assessed with the PHQ-9 and offered first-line talking therapies such as CBT or counselling','Hormone replacement therapy prescribed by a recognised gender identity clinic should be continued; ask specifically where hormones are being sourced, as unmonitored online prescriptions require urgent specialist review','Under the UK Supreme Court ruling and EHRC guidance, access to single-sex spaces may be restricted based on biological sex, but employers must always ensure transgender individuals have access to a safe and suitable toilet facility — they cannot be left without provision','A sick note is appropriate as a short-term measure, but should be accompanied by advice to engage with line management, occupational health, or a union representative to address underlying workplace discrimination','Signposting to LGBTQ+-specific mental health organisations (Stonewall, TransUnite, MindOut) is an important part of holistic management for transgender patients experiencing social difficulties','Safety-netting regarding suicidal ideation is essential: advise the patient to contact 111, crisis services, or 999 if they experience thoughts of self-harm or suicide'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  56,
  'Knee X-ray results',
  'Rheumatology & Musculoskeletal',
  'Video consultation',
  false,
  'Tariq Hussain',
  '58-year-old male',
  ARRAY[]::text[],
  ARRAY['Symbicort 100/6: 1 puff twice daily for maintenance, plus 1 puff as needed for symptom relief, up to a maximum of 8 inhalations per day (includes both maintenance and reliever use)','No known drug allergy'],
  'Seen by a clinical practitioner 4 weeks ago. Presenting complaint: Patient reports worsening bilateral knee pain, known to have osteoarthritis. No red flags. Examination findings: Crepitus on both knee joint movements, no lumps or bumps noted, normal systemic examination. Plan: Referred for physiotherapy, repeat knee X-rays arranged, safety netting and worsening advice given.

X-ray Report – Bilateral Knees
Findings:
Right Knee: There is worsening narrowing of the medial joint space compared to previous X-ray, consistent with severe osteoarthritis. Subchondral sclerosis is noted in the medial compartment. Osteophyte formation is observed along the joint margins. There is evidence of mild patellofemoral joint involvement with small osteophytes noted at the patellar margins. No acute fracture or dislocation is seen.
Left Knee: Similar to the right knee, there is narrowing of the medial joint space. Subchondral sclerosis is present in the medial compartment. Osteophyte formation is also seen along the joint margins. The patellofemoral joint shows severe osteoarthritic changes with osteophyte formation at the patellar margins. No acute fracture or dislocation is seen.
Conclusion: Bilateral severe knee osteoarthritis is noted, more prominent in the medial compartments of both knees. The patellofemoral joints also show involvement. No evidence of acute bony injury.

Recent investigations done 2 weeks ago: Blood tests including FBC, LFTs, CRP, ESR, and Rheumatoid screen – all within normal limits. eGFR: 55 mL/min/1.73 m² – filed as satisfactory.

Patient booked routine appointment to discuss results. You are Tariq Hussain, a 58-year-old self-employed tradesman. You recently saw the GP because your knee pain has been getting worse. The GP arranged a knee X-ray which you are now calling to discuss. The pain is interfering with your work. As the sole breadwinner for your household, taking time off is financially very difficult. There is no swelling, redness, or fever and no other joints are affected. You have been managing the pain with ibuprofen, which gives some relief. Paracetamol alone does not take the pain away. Your asthma is well controlled and you haven''t had a flare-up in over three years. You have not experienced any allergic reactions to ibuprofen in the past.',
  '',
  'Hello doctor, I''m calling to get the results of my knee X-ray. I''ve been really struggling with the pain and I''m hoping you can help me with something that will keep me going.',
  '',
  ARRAY[]::text[],
  'Self-employed tradesman working on construction sites; non-smoker; you do not drink alcohol; you live with your wife and three children.',
  'You suspect there may be a fracture or something serious going on, even though you haven''t had any trauma.',
  'You are worried the pain will impact your ability to work, which would affect your income and your family''s finances.',
  'You want to know the results of the X-ray and what is causing the pain. You hope for a treatment option that will allow you to keep working. If the doctor discusses referral for a knee replacement, say you''re not ready at this time due to ongoing work commitments.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything else offered to you by the doctor.',
  ARRAY['Ask where the pain is located','Ask if the pain has gotten worse, better, or remained the same','Ask if there is any swelling, redness, stiffness, or fever','Ask if the joint can be moved or if he is able to weight bear','Ask about night pain or whether it wakes him from sleep','Ask if any other joints are affected (e.g. joint above or below)','Ask about psychosocial history including occupation, smoking status, alcohol intake, and activity level','Ask how this has affected daily activities and functioning','Ask if the patient has ever experienced asthma symptoms after taking ibuprofen','Explain knee X-ray results that show worsening osteoarthritis'],
  ARRAY['Advise that oral ibuprofen may worsen both asthma and kidney function; recommend switching to topical ibuprofen gel as a safer alternative. Explain that although the gel is generally better tolerated, it can still trigger asthma symptoms if used in large amounts. Ensure renal function is monitored regularly, and advise the patient to stop using the gel and seek medical advice if any asthma symptoms occur.','Offer a short course of co-codamol (codeine with paracetamol) if additional pain relief is needed','Discuss the option of a steroid joint injection for symptom relief and discuss risks associated with it such as temporary pain and swelling at the injection site, skin changes at the injection site, and rare complications like infection','Explain the option of referral to orthopaedics to assess suitability for knee replacement, and discuss risks associated with the operation, including infection, blood clots, persistent pain or stiffness, and implant failure','Refer to physiotherapy for tailored exercise advice, including low-impact activities such as swimming, walking, and strength training','As he is self-employed and symptoms are impacting his ability to work, advise referral to the Department for Work and Pensions under the "Access to Work" scheme. Explain that this scheme may support workplace adaptations, mobility aids, equipment, or other forms of allowance; refer to the social prescriber for further assistance with this','Safety net regarding red flag symptoms such as worsening pain, inability to weight bear, or signs suggestive of septic arthritis','Arrange follow-up in 4 weeks to reassess symptoms and review progress'],
  'Thank you for coming back today to go over those results, and I appreciate you explaining how much this pain has been affecting your work. Let me go through what the X-ray has shown.

The scan confirms that the pain you''ve been experiencing is due to worsening osteoarthritis in both knees. The good news is that there is no fracture or break in any of the bones, which I know was something you were worried about. Osteoarthritis means that the smooth cartilage cushioning between your joints is gradually wearing away, leading to the pain, stiffness, and difficulty moving that you''ve been describing — and that is understandably much more noticeable when you''re doing physical work.

I can see you''ve been relying on ibuprofen tablets to manage the pain, and I''m glad they''ve been giving you some relief. However, there are a couple of things I need to flag. Your recent blood tests show that your kidneys are not quite working at full capacity, and ibuprofen tablets can put extra strain on the kidneys over time. There''s also your asthma to consider — oral ibuprofen can sometimes worsen asthma symptoms, even if that hasn''t happened to you so far. For these reasons, I''d like to suggest switching to ibuprofen gel that you rub directly onto your knees. It works locally, so it''s much less likely to affect your kidneys or lungs, while still providing meaningful pain relief. That said, even the gel can occasionally cause asthma symptoms if used in large quantities, so if you notice any breathing changes, please stop using it straight away and get in touch.

If the gel alone isn''t sufficient, we can also try a short course of co-codamol — that''s a combination of codeine and paracetamol — to give you some additional relief. Another option worth considering is a steroid injection directly into the knee joint. This can reduce inflammation and provide relief for several months. Like any procedure, it does carry some small risks, including temporary soreness at the site, minor skin changes, and very rarely an infection, but it''s generally well tolerated.

Longer-term, an orthopaedic referral to assess whether you might be suitable for a knee replacement is something we can discuss. I completely understand that now isn''t the right time for you given your work situation, and that is entirely your decision. We can revisit that option whenever you feel ready. In the meantime, physiotherapy can help strengthen the muscles around your knees and improve your mobility — activities like swimming and walking are particularly good as they''re easy on the joints.

Finally, because your knee pain is making it harder for you to continue working, I''d like to refer you to our social prescriber, who can help you access the "Access to Work" scheme through the Department for Work and Pensions. This can provide support with workplace adaptations, equipment, or other allowances to help you stay in work safely. Please do get back in touch urgently if the pain becomes much worse, if you can''t bear weight on your leg, or if you develop any heat, redness, or swelling in the joint, as those would need urgent assessment. Let''s plan to speak again in four weeks to see how you''re getting on.',
  ARRAY['Topical ibuprofen gel is preferred over oral ibuprofen in patients with comorbid asthma and reduced kidney function (eGFR 55 mL/min/1.73 m²); topical NSAIDs should be avoided altogether when eGFR is below 30 mL/min/1.73 m²','Even topical ibuprofen can cause systemic effects including asthma exacerbation when used in large amounts; it should be avoided in patients with known NSAID hypersensitivity or nasal polyps, and used with caution in those with asthma who have not previously taken NSAIDs','Management of osteoarthritis should be individualised and stepwise: analgesia optimisation, physiotherapy, intra-articular steroid injection, and surgical referral — always respecting patient preferences around timing of intervention','A steroid joint injection can provide several months of symptom relief; patients should be counselled on risks including post-injection pain flare, skin changes, and rare infection','The "Access to Work" scheme (DWP) is an important resource for patients whose musculoskeletal condition is affecting their ability to work; social prescribers can assist with the referral process','Red flag features requiring urgent review in osteoarthritis include inability to weight bear, significant swelling, warmth, or fever — these may indicate septic arthritis'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  57,
  'Sexual Headache',
  'Neurology',
  'Video consultation',
  false,
  'Daniel Fletcher',
  '34-year-old male',
  ARRAY[]::text[],
  ARRAY['Naproxen 500mg TDS (Last issued 2 years ago)','No known drug allergy'],
  'Patient booked routine video consultation to discuss a private matter. You are Daniel Fletcher, a 34-year-old male. You would like to discuss something private. You have recently developed headaches that occur during sexual activity. These began around 2–3 weeks ago. The pain is described as a pressure-like sensation that sometimes becomes a severe pounding headache, building up quickly as sexual activity progresses. It occurs just before or at the point of orgasm and subsides within 30–60 minutes, leaving a mild lingering sensation for a few hours. It occurs with nearly every sexual encounter, both with your partner and during masturbation. No nausea, vomiting, visual disturbances, or sensitivity to light and sound — symptoms you usually associate with your migraines. You have tried ibuprofen and paracetamol but they do not reliably take the headache away.',
  '',
  'Doctor, I''ve booked this appointment because I''ve been having some, well, private health concerns that I''m a little embarrassed to bring up, but I feel I need to get checked out.',
  'I''ve been getting really bad headaches during, um, intimate moments. It''s been happening for the last few weeks and it''s starting to worry me.',
  ARRAY[]::text[],
  'You work as a financial analyst in the City. You love your job and there is no significant work-related stress. You live with your girlfriend of two years. You do not smoke or drink alcohol. You are currently calling from home.',
  'You suspect your migraines may be getting worse and would like another prescription for naproxen.',
  'The headaches are starting to affect your intimate relationship as you have been avoiding sexual activity because of them.',
  'You would like the GP to prescribe naproxen again.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor.',
  ARRAY['Ask about the onset of the headache','Ask about the location of the headache (e.g. frontal, parietal, generalised)','Ask about the nature of the headache (e.g. pounding, thunderclap, dull ache)','Ask whether the headache radiates anywhere','Ask about the severity, relieving or aggravating factors, and known triggers','Specifically explore red flag triggers such as headaches brought on by coughing, sneezing, or physical exertion, neck stiffness, visual changes, neurological symptoms (e.g. weakness), and sensitivity to light or sound','Ask about associated symptoms including nausea, vomiting, and autonomic features such as eye redness or watering, nasal congestion or runny nose, and facial flushing, which may suggest a cluster headache','Ask if he has experienced this type of headache before and whether it feels similar to his usual migraines','Ask how the headache is affecting his day-to-day life, particularly his sexual activity','Ask about social history including smoking, alcohol intake, and occupation','Explore the patient''s ideas, concerns, and expectations (ICE)','Make a diagnosis of sexual headache'],
  ARRAY['Offer referral to the acute medical unit or emergency department for urgent CT head to rule out subarachnoid haemorrhage, as this is a first presentation of sexual headache','Advise the patient that this is a precautionary step to ensure there is no serious underlying cause','Explain that once serious causes are ruled out, preventive treatment can be considered','Consider starting prophylactic medication such as propranolol (40–240 mg daily)','Indometacin, taken at a dose of 25–75 mg either regularly or approximately 60 minutes before planned sexual activity, may help prevent the onset of headache','Triptans may offer benefit for individuals who cannot tolerate indometacin, particularly when taken 60 minutes prior to sexual activity','Advise on general lifestyle measures including weight loss if overweight, regular physical activity, and taking a more passive role during intercourse, which may help reduce symptom frequency','Offer follow-up after discharge from the acute medical unit or emergency department to review the outcome of hospital assessment and initiate prophylactic treatment as appropriate','Provide safety net advice: if symptoms worsen on the way to hospital or new symptoms develop, advise the patient to stop and call emergency services; recommend that he avoid driving himself and arrange for someone else to take him to hospital'],
  'Thank you for sharing that with me, Daniel, and please don''t feel embarrassed — this is exactly the kind of thing we''re here to help with, and you''ve done the right thing by getting it checked out.

The type of headache you''re describing — one that comes on during or just before orgasm, building to a severe, pounding sensation — is known as a primary sexual headache. These are more common than many people realise, and in many cases they are entirely harmless, often related to changes in blood pressure and muscle tension that occur during sexual activity. However, because this is the first time you''ve experienced this and it came on quite suddenly, we do need to rule out something more serious before we can say that with confidence.

One condition we need to exclude is a subarachnoid haemorrhage — that''s a type of bleeding that can occur around the brain. While it is uncommon, it can occasionally present as a sudden severe headache during exertion or sexual activity. I want to reassure you that this is a precautionary step, and the majority of people with headaches like yours do not have anything dangerous going on. But given this is a new and sudden-onset presentation, it''s the right and safe thing to do.

For that reason, I''d like to refer you to the acute medical unit at the hospital today. Please do not drive yourself — ask your girlfriend or arrange another way to get there. While you''re travelling, if the headache comes on again or you develop any new symptoms such as neck stiffness, weakness, or visual changes, stop immediately and call 999. At the hospital, they will arrange a brain scan, and if needed, a lumbar puncture — that''s a procedure where a small sample of fluid is taken from your lower back to look for any signs of bleeding around the brain.

If all the tests come back clear, which is often the case, we can then look at options to prevent these headaches from happening in the future. One option is propranolol, a medication taken daily that can reduce the frequency of episodes. Another is indometacin, which can be taken at a dose of 25–75 mg roughly 60 minutes before planned sexual activity and is often effective at preventing the headache from occurring. There are also some general lifestyle measures that may help, such as staying active and, during intimate moments, taking a more passive role, which can reduce the physical exertion involved.

We''ll arrange a follow-up appointment after your hospital visit so we can review the results together and discuss next steps.',
  ARRAY['Primary sexual headache is triggered by sexual activity, typically starting as a dull bilateral ache that intensifies at orgasm; it is approximately three times more common in males and occurs in the absence of intracranial pathology','Even without red flag features, a first presentation of sexual headache requires urgent exclusion of subarachnoid haemorrhage with CT head and, if negative, lumbar puncture','Risk factors for primary sexual headache include a personal history of migraine or exertional headache, obesity, stress, and intensity of sexual excitement','Prophylactic options include propranolol 40–240 mg daily (regular prevention) and indometacin 25–75 mg taken approximately 60 minutes before sexual activity (situational prevention)','Triptans taken 60 minutes prior to sexual activity may benefit patients who cannot tolerate indometacin','Safety-netting for this presentation is critical: advise the patient not to drive to hospital and to call 999 if symptoms worsen or new neurological symptoms develop en route'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  58,
  'Syncopal Episodes in Young Adult',
  'Cardiology',
  'Video consultation',
  false,
  'Rachel Brennan',
  '26-year-old female',
  ARRAY[]::text[],
  ARRAY['Fostair Nexthaler 100/6: 1 inhalation twice daily for maintenance, plus 1 inhalation as needed for symptom relief; maximum of 8 inhalations per day','No known drug allergy'],
  'Patient booked routine video consultation to discuss some concerns. You are Rachel Brennan, a 26-year-old woman. You booked this consultation to discuss two episodes of collapse you have experienced recently.

First Episode (Witnessed): Happened 3 weeks ago at home. You were told by your partner that you suddenly fell to the floor, were shaking, and were unresponsive for about 3–4 minutes. When you regained consciousness, you noticed you had wet yourself.

Second Episode (Unwitnessed): Happened 10 days ago while getting ready for work in the morning. You found yourself on the floor without any recollection of how you got there. Again, you noticed you had wet yourself.

Associated symptoms: No warning signs such as dizziness, palpitations (heart racing), or chest pain before either episode. No confusion or prolonged drowsiness after waking up. No tongue biting, visual disturbances, or headache. Say ''no'' to any additional symptoms asked by the doctor.',
  '',
  'Hi doctor, thank you for seeing me. I''ve had a couple of worrying episodes recently where I''ve collapsed, and I''m really anxious about what might be going on.',
  '',
  ARRAY[]::text[],
  'You are a healthcare assistant in a hospital. You enjoy your work and generally feel healthy. You drive to work daily (only say this if asked). You do not smoke or drink. You are in a stable relationship for 5 years with your female partner.',
  'You are unsure what might be causing the episodes.',
  'You''re worried about having further episodes, especially while at work.',
  'You would like the doctor to investigate and help find out what''s going on.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY['Ask about the onset and timing of the first collapse episode','Ask the patient for a detailed description of what happened during each incident','Ask if anyone witnessed either episode','Ask how long the patient was unconscious for','Ask about symptoms prior to the collapse, including dizziness, light-headedness, nausea, vomiting, weakness, or visual disturbance','Ask whether the episode occurred during exercise, while lying down, or when sitting or standing','Ask if there were any palpitations, chest pain, or shortness of breath','Ask what happened during the recovery phase, including incontinence, amnesia, drowsiness, dizziness, sleepiness, or tongue biting','Ask if the patient has experienced similar episodes in the past','Ask if the patient had been feeling unwell prior to the event, such as with flu-like symptoms, sore throat, or fever','Ask about headache or any recent head injury','Ask if there have been any new medications started recently','Ask about smoking history and alcohol intake','Ask about driving status and occupation, particularly if the job involves operating machinery or poses safety risks','Ask about family history of epilepsy','Make a working diagnosis of possible seizure activity (epilepsy). Since there have been two episodes, this raises the possibility of epilepsy.'],
  ARRAY['Offer a face-to-face appointment to perform a full neurological examination and cardiovascular examination (e.g. listen to heart sounds, check blood pressure and pulse)','Arrange an ECG and routine blood tests','Refer to the "First Fit Clinic" or "First Seizure Clinic"; explain that the clinic may offer a brain scan and an EEG (electrical tracing of brain activity) to investigate further. They typically aim to see patients within two weeks.','Advise the patient to stop driving until seen by a specialist and a diagnosis is confirmed, and that they should inform the DVLA','Advise informing her employer and arranging an occupational health assessment for potential adjustments at work','Inform her that you will send some leaflets with emergency precautions that those around her can follow to help keep her safe in the event of another seizure. Emphasise the importance of educating her colleagues at work about her condition, so they are prepared to assist her appropriately if an episode occurs.','Recommend avoiding high-risk situations where a seizure episode could lead to harm, such as working at heights or swimming alone','Suggest that she consider wearing a medical alert bracelet, so that if she has a seizure in a public place where people may not know her, they will be aware of her condition and able to get help quickly','Safety net: advise that if another seizure occurs and lasts more than 5 minutes, anyone present should call 999 immediately'],
  'Thank you for telling me about those episodes, Rachel — I can completely understand why they''ve been worrying you, and you were absolutely right to get in touch.

Based on everything you''ve described, I think it''s possible that you may have been having seizures. A seizure happens when there''s a sudden, temporary change in the electrical activity in the brain, and this can cause someone to collapse, shake, and lose control of their bladder — which is exactly what you and your partner have noticed. Because this has now happened on two separate occasions, it raises the possibility of epilepsy, which is a condition where seizures can recur. I want to be clear that we are not confirming a diagnosis today — what we are doing is making sure you get the right specialist input as quickly as possible.

I''d like to refer you to a specialist clinic called the First Seizure Clinic, sometimes also called the First Fit Clinic. The aim is to see patients within two weeks. At the clinic, they will likely arrange a brain scan and an EEG — that''s a painless test that records the electrical activity in your brain — to help us understand what is happening and guide next steps. In the meantime, I''d like to see you in person today so I can examine your nervous system and heart, and we''ll arrange some blood tests and an ECG as well.

There is one important thing I need to ask you about — you mentioned that you drive to work. I''m afraid that, for safety reasons, I need to advise you to stop driving for now. This is not a permanent situation, but until a specialist has assessed you and we have a clearer picture, it would not be safe for you or other road users. You will also need to inform the DVLA about these episodes.

Regarding your job as a healthcare assistant, I''d encourage you to let your manager know what''s been happening so that an occupational health referral can be arranged. They can look at what reasonable adjustments might need to be in place to keep you safe at work. It would also be very helpful to make sure your colleagues know what to do if you ever have an episode at work — I can send you some leaflets covering seizure first aid so they feel prepared.

In the meantime, it''s important to avoid situations where a seizure could put you at risk — things like swimming alone or working at heights. You might also want to consider wearing a medical alert bracelet so that anyone who is nearby in a public place would know to get help. And finally, if you or anyone with you notices another seizure that lasts more than five minutes, they should call 999 immediately.',
  ARRAY['When assessing collapse, take a structured history covering three phases: before (warning symptoms), during (duration, characteristics), and after (recovery features including incontinence, confusion, amnesia, tongue biting)','Vasovagal syncope typically lasts under 30 seconds with rapid, complete recovery; epileptic seizures usually last over one minute and are followed by post-ictal features such as confusion, drowsiness, incontinence, and amnesia','Two or more unexplained seizure-like episodes raises the working diagnosis of epilepsy and requires urgent referral to a First Seizure Clinic, with a target of being seen within two weeks','All patients with a suspected first seizure must be advised to stop driving immediately and to notify the DVLA — this is a legal requirement regardless of whether a diagnosis has been confirmed','Investigations at the First Seizure Clinic typically include brain imaging (MRI or CT) and an EEG to assess for underlying neurological causes','Education of the patient, family members, and workplace colleagues about seizure first aid and when to call 999 (seizure lasting more than 5 minutes) is an essential component of management'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  59,
  'Itching in Pregnancy',
  'Gynaecology & Women''s Health',
  'Telephone consultation',
  false,
  'Priya Sharma',
  '32-year-old female',
  ARRAY[]::text[],
  ARRAY['Nil','No known drug allergy'],
  'Patient booked urgent telephone consultation to discuss some concerns. You are Priya Sharma, a 32-year-old woman currently 33 weeks pregnant with your first child. You are calling for an urgent telephone consultation because you have developed widespread itching over the past two days, and it seems to be getting worse. The itching is particularly bothersome at night and has begun to disturb your sleep. You have tried using regular moisturisers but they have not helped. You have no rash, have not been in contact with anyone else experiencing similar symptoms, and your pregnancy has been uneventful so far. You are up to date with all midwife appointments and you continue to feel normal baby movements.',
  '',
  'Doctor, I''ve been itching all over my body for the last couple of days and it''s getting really uncomfortable. I was hoping you could prescribe something to help.',
  'The itching is really bad at night and it''s been disturbing my sleep. I''ve tried moisturiser but it hasn''t made any difference. There''s no rash that I can see.',
  ARRAY[]::text[],
  'This is your first pregnancy; you are a non-smoker; you do not drink alcohol; you work as a beauty therapist; you live with your supportive husband; you are due to travel to Greece for a holiday tomorrow.',
  'You''ve heard that itching can be common in pregnancy.',
  'You are worried the itching might affect your sleep and your upcoming holiday to Greece.',
  'You would like the GP to prescribe a safe medication to stop the itching.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor.',
  ARRAY['Ask how many weeks pregnant she is (gestational age), as conditions like obstetric cholestasis and polymorphic eruption typically begin after 28 weeks','Ask when the itching started and how it has changed','Ask if the itch is localised or generalised','Ask if there is a rash','Ask about associated symptoms suggesting obstetric cholestasis: jaundice, dark urine, pale stools, right upper quadrant abdominal pain, and malaise','Ask if the itch is worse at night (obstetric cholestasis causes night-time itch)','Ask about recent contact with anyone else who is also itching, to rule out scabies','Ask about any triggers (e.g. heat, hot showers, sweating)','Ask about any prescribed or over-the-counter medications, especially opioids, as they can cause itching','Ask if she feels her baby move normally (foetal movements are usually noticed between 16 and 24 weeks)','Ask about red flag symptoms such as night sweats, unexplained weight loss, or lumps, which could suggest more serious pathology such as lymphoma','Ask about lifestyle factors: smoking, alcohol, illicit drug use','Ask if she is attending antenatal care and whether the pregnancy has been progressing normally','Ask how the itching is affecting her daily life and sleep quality','Ask about her home situation and whether she has adequate support at home','Give a diagnosis of itching in pregnancy, and explain the need to rule out obstetric cholestasis'],
  ARRAY['Arrange same-day assessment/admission to the maternity assessment unit for urgent blood tests, including liver function tests and bile acids, to rule out obstetric cholestasis','Explain that at the hospital, they will carry out blood tests and also monitor the baby''s wellbeing through appropriate foetal assessments','If obstetric cholestasis is diagnosed, inform the patient that an individualised care plan will be developed based on her results and clinical situation; this may include regular blood tests to monitor liver function and bile acid levels, possible early delivery depending on severity and gestational age, or treatment with ursodeoxycholic acid (UDCA) to relieve itching and reduce bile acid levels','Advise against travelling to Greece at this time, as it is important to complete investigations and ensure the safety of both mother and baby','Inform her that if she has travel insurance, she may be able to make a claim based on medical advice not to travel','Advise that if investigations return as normal, she should book a follow-up appointment to consider treatment options such as menthol 0.5% or 1% in aqueous cream to relieve the itch, and a sedating antihistamine at night (e.g. chlorphenamine or promethazine) to improve sleep — noting that this is an off-label use in pregnancy','Provide safety netting advice: if symptoms worsen, new symptoms develop, or if there are any concerns about baby movements or general wellbeing before or after attending hospital today, seek urgent medical attention without delay'],
  'Thank you for calling today, Priya, and for letting us know about this so promptly. I''m really glad you got in touch rather than waiting.

You''re right that itching is not uncommon in pregnancy, and for many women it''s simply due to the skin stretching or becoming drier. However, because you are 33 weeks pregnant, the itching is getting worse, and it is particularly bad at night, I do need to make sure we rule out a specific pregnancy-related condition before we can reassure you.

The condition I want to exclude is called obstetric cholestasis. This is a liver condition that can develop during pregnancy, where the liver doesn''t process bile acids as efficiently as normal. When bile acids build up, they can cause itching — often without any visible rash, and typically worse at night — which is very similar to what you''ve been describing. It''s important that we investigate this promptly because, while the itching itself is very uncomfortable for you, obstetric cholestasis can also carry risks for the baby if it isn''t properly monitored and managed.

For that reason, I''d like you to go to the maternity assessment unit at the hospital today — not the emergency department, but the specialist maternity team. They will take some blood tests, including liver function tests and bile acid levels, and they will also check on how your baby is doing with appropriate monitoring. I know this isn''t what you were expecting when you called today, but it''s really the safest and most important thing we can do right now.

I also need to advise you strongly against travelling to Greece tomorrow. I completely understand how disappointing that is, especially if it''s something you''ve been looking forward to. But until we have these results and know everything is okay with you and your baby, it wouldn''t be safe to travel abroad. If you have travel insurance, it is likely you''ll be able to make a claim given that you''ve been advised not to travel on medical grounds.

If the blood tests come back completely normal, we can then look at ways to manage the itch more comfortably. Options would include menthol 0.5% or 1% in aqueous cream applied to the skin to soothe the itching, and a sedating antihistamine such as chlorphenamine or promethazine taken at night to help you sleep. These are used off-label in pregnancy but are generally considered safe.

If you notice that your baby''s movements change or slow down at any point, or if you develop any new symptoms before you get to the hospital, please seek urgent medical attention straight away. You can call 999 or go directly to your nearest maternity unit.',
  ARRAY['Generalised itching in pregnancy after 28 weeks without a rash — especially when worse at night — should raise the possibility of obstetric cholestasis until proven otherwise','Obstetric cholestasis is a pregnancy-specific liver condition characterised by impaired bile acid clearance; it requires same-day assessment with liver function tests and serum bile acid levels at the maternity assessment unit','If obstetric cholestasis is confirmed, management options include regular monitoring of liver function and bile acids, ursodeoxycholic acid (UDCA) to reduce itching and bile acid levels, and consideration of early delivery depending on severity and gestational age','Other causes of itching in pregnancy include polymorphic eruption of pregnancy, atopic eruption of pregnancy, pemphigoid gestationis (all typically present with a rash), and non-pregnancy causes such as scabies or eczema — the presence or absence of a rash is a key differentiator','Travel should be strongly discouraged until obstetric cholestasis has been excluded; patients should be advised to check their travel insurance for medical cancellation cover','If investigations are normal, symptomatic relief can be offered with menthol 0.5–1% in aqueous cream and a sedating antihistamine at night (chlorphenamine or promethazine), both used off-label in pregnancy'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  60,
  'Abnormal Liver Function and Vitamin D Levels',
  'Gastroenterology & Haematology',
  'Video consultation',
  false,
  'Emmanuel Okafor',
  '54-year-old male',
  ARRAY[]::text[],
  ARRAY['Amlodipine 10 mg once daily','Atorvastatin 20 mg once daily','Eumovate cream (used as needed for eczema flares)','No known drug allergies'],
  'Seen by a clinical practitioner 2 weeks ago. Presenting complaint: Patient reports widespread joint aches and feeling tired all the time for the last 4 weeks. No red flags, no recent flu symptoms. Examination findings: BP 135/85 mmHg, Pulse 68 bpm. No generalised lymphadenopathy. Plan: Blood tests arranged; advice given regarding worsening symptoms. Follow-up with results.

Investigation Results:
HbA1c, U+E, calcium, CRP, ESR, Thyroid function test – all filed as normal.

Liver Function Tests:
Alanine Aminotransferase (ALT): 22 U/L (ref 7–56 U/L)
Aspartate Aminotransferase (AST): 18 U/L (ref 10–40 U/L)
Alkaline Phosphatase (ALP): 198 U/L (ref 40–130 U/L)
Bilirubin (Total): 0.8 mg/dL (ref 0.1–1.2 mg/dL)
Albumin: 4.5 g/dL (ref 3.5–5.0 g/dL)
Gamma-Glutamyl Transferase (GGT): 30 U/L (ref 8–61 U/L)
Prothrombin Time (PT): within normal range (ref 11–14 seconds)
Vitamin D (25-hydroxyvitamin D): 11 ng/mL (ref 30–100 ng/mL)

Patient has booked a follow-up video consultation to discuss the results of his blood tests. You are Emmanuel Okafor, a 54-year-old man. You feel tired throughout the day despite getting a good night''s sleep. You have generalised joint aches, particularly in your lower back and legs. There is no joint swelling, redness, or deformity. Say ''no'' to any other symptoms asked by the doctor.',
  '',
  'Good morning doctor. I''ve come back to get my blood results and hopefully find out what''s been causing all this tiredness and joint aching.',
  '',
  ARRAY[]::text[],
  'You work as an IT consultant. You smoke 30 cigarettes per day and have done so for the last 30 years. You spend very little time outdoors, particularly in winter. You do not drink alcohol.',
  'You suspect the joint aches and tiredness could be due to your age or possibly a side effect of your medications, particularly the cholesterol tablet — though you''ve been on it for 3 years without any problems.',
  'The fatigue and joint aches are starting to affect your work and your ability to concentrate.',
  'You want a clear explanation of what''s causing the symptoms and would like advice and treatment to improve your energy and reduce joint aches. If offered vitamin D treatment, ask: "Will I need to take vitamin D tablets for life?"',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY['Begin by acknowledging the reason for today''s consultation and referring to the previous appointment: acknowledge that the patient is returning to discuss blood test results arranged after presenting with tiredness and joint aches, and ask how the symptoms have been since then — whether they have improved or worsened. This demonstrates appropriate use of available clinical information and engagement with the patient''s ongoing journey. Failure to do so may be marked negatively by the examiner.','Ask specifically about bone pain (e.g. in skull, pelvis, spine, or long bones), as this may suggest Paget''s disease','Ask about red flag symptoms such as weight loss and night sweats','Ask whether the patient has had any previous fractures or falls','Ask about sunlight exposure, particularly during winter months','Ask about jaundice, abdominal pain, dark urine, or pale stools (to screen for liver causes of raised ALP)','Ask how long the patient has been on statin therapy, and whether any side effects have previously been noticed','Explore social history, including smoking and alcohol intake, and ask about dietary habits, especially calcium and vitamin D intake','Ask about the patient''s occupation, and explore how the symptoms of fatigue and joint pain have impacted their daily functioning and quality of life'],
  ARRAY['Offer to start vitamin D supplementation using a suitable loading dose regimen: for example, 800 IU five times daily for 10 weeks (total 280,000 IU), or 50,000 IU once weekly for 6 weeks (total 300,000 IU)','After completing the loading regimen, start on a maintenance dose of 800 IU daily','Advise that blood tests will be repeated in 6 to 10 weeks, depending on the chosen loading regimen, to monitor calcium, vitamin D levels, and ALP','Assess dietary calcium intake using the calcium calculator; advise that this will include questions about foods like milk, cheese, and yoghurt to estimate daily intake','Provide lifestyle advice to improve diet and increase safe sun exposure; recommend incorporating vitamin D-rich foods such as oily fish, eggs, and fortified cereals','Explain that lifelong supplementation is not always necessary; with improved diet and sun exposure, many people maintain adequate vitamin D levels. However, due to his risk factors (darker skin, limited sun exposure), long-term low-dose supplementation may be needed, and future decisions will be guided by blood tests','Offer smoking cessation support in a non-judgemental manner and, if he is open to it, offer self-referral to local smoking cessation services','Safety net: advise him to contact the surgery urgently if his symptoms worsen or do not improve, or if he develops any new concerning symptoms'],
  'Thank you for coming back today, Emmanuel, and for your patience in waiting for these results. I can see you''ve been feeling quite drained and uncomfortable with the joint aching, so let''s go through everything together and I''ll explain what we''ve found.

The good news is that the vast majority of your blood tests have come back completely normal — your blood sugar, thyroid, kidney function, inflammation markers, and most of your liver results are all within the healthy range. However, there are two results that stand out and that I think are very likely connected to the symptoms you''ve been experiencing.

The first is your vitamin D level, which is significantly low at 11 ng/mL — the normal range is 30 to 100 ng/mL. Vitamin D plays a really important role in maintaining healthy bones, muscles, and energy levels. When it''s very low, it commonly causes symptoms like persistent tiredness and widespread joint or muscle aching, which is exactly what you''ve been dealing with. This is almost certainly the main explanation for how you''ve been feeling.

The second result is your ALP — one of your liver and bone enzyme markers — which is slightly elevated at 198 U/L against a normal upper limit of 130 U/L. This particular enzyme can rise when vitamin D levels are very low, so it''s very likely that these two findings are related. I''m not concerned about your liver itself, since all the other liver markers are normal. It''s also worth mentioning that I don''t think your statin — the atorvastatin — is responsible. You''ve been on it for three years without any problems, and it would typically affect different liver markers if it were causing a problem.

To address this, we''re going to start you on a course of vitamin D tablets. One option is to take 800 IU five times a week for ten weeks, which gives your body a good loading dose to replenish your stores. Once the loading course is complete, we''ll move you onto a maintenance dose of 800 IU daily. You asked whether you''ll need to take vitamin D for the rest of your life — that''s a great question and completely understandable. For many people, once their levels recover and they make some dietary and lifestyle changes, they can maintain their levels without long-term supplements. However, given that you have darker skin — which naturally produces less vitamin D from sunlight — and that you spend limited time outdoors, especially in winter, there is a good chance you may benefit from a lower maintenance dose long-term. We''ll review this once we''ve repeated your blood tests in around six to ten weeks.

In terms of lifestyle changes, eating more vitamin D-rich foods such as oily fish, eggs, and fortified cereals can help, as can making the most of sunny days when possible. I''ll also send you a short dietary questionnaire to check your calcium intake, since calcium and vitamin D work hand in hand for bone health.

Finally, I do want to gently raise the topic of your smoking. I understand it''s been part of your life for a long time, and I won''t lecture you. But given that you also have blood pressure and cholesterol to manage, smoking does significantly increase the risk of heart disease and stroke. If you''ve ever considered cutting down or giving up, I would genuinely love to help — there are free local services and a range of support options available, and we can go at your pace entirely. What are your thoughts?

We''ll plan to repeat your vitamin D, ALP, and calcium in around six to ten weeks to check that your levels are improving. In the meantime, please do get back to us promptly if your symptoms worsen, you develop any new problems, or you feel your energy levels are getting significantly worse rather than better.',
  ARRAY['An isolated raised ALP with normal ALT, AST, GGT, bilirubin, and albumin — in the context of severe vitamin D deficiency — is most likely attributable to vitamin D deficiency itself, rather than intrinsic liver disease or statin toxicity','Vitamin D deficiency (25-hydroxyvitamin D < 30 ng/mL) is a common and treatable cause of fatigue, generalised muscle aching, and joint pain; risk factors include darker skin pigmentation and limited sun exposure','Loading dose regimens for vitamin D deficiency include 800 IU five times daily for 10 weeks (total 280,000 IU) or 50,000 IU once weekly for 6 weeks (total 300,000 IU), followed by a maintenance dose of 800 IU daily','Blood tests including calcium, vitamin D levels, and ALP should be repeated 6–10 weeks after commencing treatment to confirm an adequate response','Paget''s disease of bone is a differential for isolated raised ALP; however, it typically causes localised bone pain (particularly skull, spine, or pelvis) and is less likely when there is a clear alternative explanation such as vitamin D deficiency — if ALP fails to normalise with treatment, further investigation for Paget''s disease is warranted','Statins can cause myalgia but are less likely to be the cause when the patient has tolerated the medication for several years without problems and other liver markers are normal; stopping a statin unnecessarily risks losing cardiovascular protection'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  61,
  'Unexplained Weight Loss And Sweating In A',
  'General Practice',
  'Telephone consultation',
  false,
  'Helen Marsh',
  '44-year-old female',
  ARRAY[]::text[],
  ARRAY['Rigevidon (combined oral contraceptive pill)'],
  'Patient has booked a routine telephone consultation to discuss new concerns. You are Helen, aged 44. You have arranged this consultation to discuss some symptoms that have developed over the past two months. You have been experiencing excessive sweating, particularly noticeable at night, alongside persistent fatigue and unintended weight loss. The sweating happens both during the day and most nights, often soaking through your clothes and bed sheets. The fatigue is constant and does not improve with rest. You have lost approximately 5 kg over the last two months without any changes to your diet or exercise. You have had intermittent episodes of a racing heartbeat during this time, which you put down to your anxiety, even though you have not felt particularly anxious recently. You are currently taking the combined oral contraceptive pill (Rigevidon) and your periods remain regular and controlled. You have not experienced hot flushes, vaginal dryness, or any changes in your menstrual flow. You work full-time as an estate agent. You do not smoke or drink alcohol. Your mother went through an early menopause. There is no family history of cancer or other significant medical conditions.',
  'Routine telephone consultation to discuss new symptoms including excessive sweating, fatigue, and unintended weight loss over the past two months.',
  'Hello, I''ve been getting these really bad sweats, especially at night, and I''ve also been feeling exhausted all the time. I''ve lost quite a bit of weight recently without trying, and I''m not sure what''s going on.',
  'The sweating occurs both during the day and most nights, often soaking through clothes and bed sheets. The fatigue is constant and not relieved by rest or sleep. Approximately 5 kg of weight has been lost over two months without dietary changes. There have been intermittent episodes of a racing heartbeat, attributed to anxiety, though she has not felt particularly anxious of late.',
  ARRAY[]::text[],
  'Helen works full-time as an estate agent and enjoys her role but has been feeling increasingly fatigued during the day. She does not smoke or drink alcohol. Her mother experienced an early menopause. There is no family history of cancer or other significant medical conditions.',
  'She thinks her symptoms might be related to the menopause.',
  'She is worried about the possibility of early menopause like her mother experienced, and the symptoms are beginning to affect her work as she feels tired all the time.',
  'She would like some blood tests to check whether she is going through the menopause.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY[
    'Ask about the onset of symptoms and how long they have been present',
    'Clarify whether the sweats occur during the day or just at night',
    'Ask about fever, to rule out an infectious cause',
    'Ask about fatigue — whether it worsens with activity and whether symptoms are improving, worsening, or remaining unchanged',
    'Ask about any potential triggers for the fatigue and night sweats',
    'Ask about joint pains or the presence of lumps or swellings, to rule out possible malignancy such as lymphoma',
    'Ask about weight loss and quantify it — how much has been lost and over what period',
    'Ask about menstrual history and whether periods are regular; explore menopausal symptoms such as hot flushes, vaginal dryness, irritability, and reduced sex drive',
    'Ask about palpitations, feeling hot when others are not, diarrhoea, and neck swelling or discomfort to explore the possibility of hyperthyroidism',
    'Ask about any family history of medical conditions including cancer, thyroid disorders, or early menopause',
    'Explore the impact of symptoms on daily functioning',
    'Take a social history including smoking and alcohol use',
    'Make a working diagnosis of likely hyperthyroidism while considering other differentials such as malignancy, including lymphoma'
  ],
  ARRAY[
    'Offer a face-to-face appointment to allow for physical examination, including assessment for lymphadenopathy, measurement of pulse and blood pressure, and consideration of an ECG to evaluate for arrhythmias, particularly in view of her palpitations and the suspicion of hyperthyroidism. This is especially important to rule out atrial fibrillation, which may be associated with Graves'' disease or thyrotoxicosis.',
    'Request urgent blood tests including FBC, U&Es, thyroid function tests, LFTs, HbA1c, CRP, and ESR.',
    'Explain that if blood results suggest an overactive thyroid, treatment would typically involve starting medication and referring to an endocrinologist (hormone specialist) for further management.',
    'Advise keeping a symptom diary to help identify patterns or potential triggers for the sweats.',
    'Recommend lifestyle strategies to manage fatigue, including pacing activities and maintaining good sleep hygiene.',
    'Arrange follow-up within 24 to 48 hours to review blood results and plan next steps.',
    'Advise seeking urgent medical attention if symptoms worsen or she becomes more unwell in the meantime.'
  ],
  'Thank you for calling today and for telling me about what you''ve been going through. I can see how much these symptoms — the sweating, the tiredness, and the weight loss — have been affecting you, and it''s absolutely right that we look into this properly.

Helen, I can understand why you might be thinking about the menopause, especially given your mum''s history. However, because you''re currently taking the combined oral contraceptive pill, it''s worth knowing that the pill contains synthetic hormones that keep your hormone levels stable. This means it can actually mask the signs of menopause, so it becomes less likely that menopause alone is causing these symptoms. In fact, for this reason, we would not usually rely on a standard hormone blood test to check for menopause in someone taking the pill, as the results would not be reliable.

What I''d like us to consider instead is whether your thyroid gland might be a little overactive. The thyroid is a small gland in the front of your neck that helps control your body''s energy levels. If it becomes overactive, it can cause exactly the kinds of symptoms you''ve been describing — weight loss without trying, sweating, feeling constantly tired, and that racing heartbeat. Does that sound like it could fit with what you''ve been experiencing?

That said, while I think an overactive thyroid is the most likely explanation here, I also want to be open with you and mention that we do need to consider other causes as well. One of these is a type of cancer called lymphoma, which can sometimes cause similar symptoms including night sweats, fatigue, and weight loss. I want to be very clear that I am not saying this is what you have — but it is important that we investigate thoroughly so we can either confirm it or rule it out with confidence.

With that in mind, I''d like to arrange two things. First, I''d like you to come in for a face-to-face appointment so I can examine you — feel for any gland swellings in your neck, armpits, or groin, check your pulse and blood pressure, and possibly arrange a heart tracing. Second, I''d like to request an urgent set of blood tests, including a thyroid function test, a full blood count, liver tests, inflammatory markers, and a few others.

In the meantime, it would be helpful if you could keep a brief diary of when the sweats occur and any other symptoms you notice. And please do not hesitate to contact us sooner if you feel significantly more unwell before your appointment. We will be in touch quickly once the results are back.',
  ARRAY[
    'The combined oral contraceptive pill (COCP) suppresses natural hormone fluctuations and can mask menopausal symptoms; FSH testing is unreliable in women taking the COCP and should not be used to diagnose menopause in this context, as per NICE guidance.',
    'Unexplained weight loss, night sweats, and fatigue in a middle-aged woman on the COCP should prompt consideration of hyperthyroidism as the primary differential, alongside exclusion of malignancy such as lymphoma.',
    'Key investigations include thyroid function tests, FBC, U&Es, LFTs, HbA1c, CRP, and ESR; face-to-face examination should assess for lymphadenopathy, pulse irregularity, and consideration of ECG to exclude atrial fibrillation.',
    'Graves'' disease and thyrotoxicosis can cause atrial fibrillation; palpitations in the context of suspected hyperthyroidism should prompt ECG assessment.',
    'Safety-netting is essential: follow-up within 24 to 48 hours of blood results, with clear advice to seek urgent help if symptoms worsen before then.',
    'Managing clinical uncertainty is a core GP skill — a structured approach exploring multiple differentials, appropriate investigation, and clear communication is key when the diagnosis is not immediately clear.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  62,
  'Postherpetic Neuralgia',
  'Neurology',
  'Video consultation',
  false,
  'Gary Barlow',
  '61-year-old male',
  ARRAY[]::text[],
  ARRAY['Ramipril 10mg once daily', 'No known drug allergy'],
  'Seen 3 months ago by Dr Priya Mehta (Clinical practitioner access role). Presenting complaint: Patient developed painful rashes over the right anterior abdomen, extending towards the posterior region. Examination: Findings consistent with shingles. Plan: Treat with acyclovir 800 mg five times daily (at approximately 4-hour intervals) for 7 days. Analgesia with co-codamol (1 to 2 tablets every 4 to 6 hours as required; maximum 8 tablets per day). Safety-netting and worsening advice given. Patient has booked a routine video consultation to discuss ongoing concerns.',
  'Video consultation to discuss a 3-month history of persistent burning pain in the right lower back and anterior abdomen following a previous episode of shingles.',
  'Hello Doctor, I''ve had this burning pain in my lower right back for about three months now. It wraps around to the front of my stomach, and it''s really starting to get to me, especially at night when I''m trying to sleep.',
  'The pain is burning in character and has been disturbing sleep. It is not made worse by movement or physical activity, and rest does not significantly relieve it. Occasionally the pain can be triggered by touch. Paracetamol and ibuprofen gel have both been tried without meaningful relief. There is no history of trauma. He had shingles affecting the right side of his body three months ago, treated with antiviral medication, and the rash has since fully resolved. There are no new rashes or blisters, but the pain persists.',
  ARRAY[]::text[],
  'He works as a warehouse supervisor. His role involves moderate physical activity including regular walking and occasional lifting. He does not smoke or drink alcohol. He lives at home with his wife and adult son.',
  'He is unsure what is causing the pain, although it feels similar to when he had shingles — but this time there is no rash.',
  'The pain is disrupting his sleep and causing increasing worry.',
  'He would like the GP to provide effective pain relief and, if possible, identify the cause of the ongoing discomfort.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY[
    'Ask about the onset, nature, and radiation of the pain, as well as relieving or aggravating factors. It is important to ask specifically about triggers, as in post-herpetic neuralgia the pain may be provoked by light touch or pressure, known as allodynia.',
    'Ask about associated symptoms such as the presence of any rash, and any urinary symptoms particularly haematuria, to help rule out differential diagnoses such as kidney stones.',
    'Ask about systemic symptoms including fever, nausea, or vomiting, which may indicate pyelonephritis or renal colic.',
    'Ask about any history of recent injury or trauma.',
    'Ask about constitutional symptoms such as weight loss or night sweats to exclude malignancy.',
    'Explore the impact of the pain on daily life and quality of life.',
    'Assess the patient''s mood, recognising that chronic pain may be associated with low mood or depression.',
    'Take a relevant social history including occupation, smoking, and alcohol use.',
    'Give a diagnosis of post-herpetic neuralgia.'
  ],
  ARRAY[
    'Offer a face-to-face appointment to examine the affected area and assess for nerve-related tenderness or changes, to support a clinical diagnosis of postherpetic neuralgia.',
    'Recommend simple self-care measures that may reduce irritation, such as wearing soft cotton or silk fabrics. Advise protecting sensitive skin by applying a barrier, such as a firm bandage, compression clothing, cling film, or a clear plastic dressing (e.g. Opsite®).',
    'Offer neuropathic pain relief. Options include amitriptyline, duloxetine, gabapentin, or pregabalin. In this case, as sleep is being disrupted, amitriptyline may be a suitable first choice.',
    'Another alternative is topical lidocaine 5% plasters. Advise that the plaster can be applied once daily over the painful area and kept on for up to 12 hours within a 24-hour period. Discuss the potential for skin irritation but reassure that many patients tolerate it well and find it effective.',
    'Arrange follow-up in 2 to 4 weeks to review response to treatment and adjust management as needed.',
    'Provide safety-netting advice, including to seek medical help if symptoms worsen, become more widespread, or significantly affect daily life.'
  ],
  'Thank you for coming to see me today and for describing what you''ve been going through. Three months of burning pain that keeps you awake at night is genuinely difficult to live with, and I want you to know that what you''re experiencing is very real.

Gary, from everything you''ve told me, I believe you have a condition called postherpetic neuralgia. This is what can happen after someone has had shingles. Even though the rash has completely healed and disappeared, the virus can leave the affected nerves in a sensitised or irritated state. As a result, those nerves continue to send pain signals to the brain, even when there is nothing on the surface of the skin to explain it. That is why you are feeling this burning sensation in the same area where the shingles was, without any new rash being present. You are not imagining it — the nerve itself is simply misfiring.

I''d like to arrange for you to come in so I can have a look at the area and gently examine it. Sometimes the skin can be very sensitive to even a light touch in postherpetic neuralgia — this is called allodynia — and examining the area helps confirm the diagnosis and guides treatment.

In terms of what we can do to help, the standard painkillers like paracetamol and ibuprofen unfortunately do not work well for this type of nerve pain. What does tend to help is a group of medications specifically designed to calm irritated nerves. One option is amitriptyline — this is a medication that at low doses is very effective at settling nerve pain, and given that your sleep is being affected, it may be a particularly good choice as it can also help with sleep quality. Other options include gabapentin, pregabalin, or duloxetine. We can discuss which feels right for you.

Another option worth knowing about is a lidocaine 5% skin plaster, which you apply directly over the painful area for up to 12 hours at a time. Many people find this helpful for localised nerve pain, and it is well tolerated by most patients.

On a practical note, wearing loose, soft fabrics — cotton or silk where possible — can help reduce irritation to the sensitive skin. Some people also find that a protective dressing or light bandage over the area helps to reduce discomfort from clothing rubbing against it.

I would like to review how you are getting on in two to four weeks. If the pain is not improving, we can look at adjusting the dose or switching to a different option. Please do get back in touch sooner if things get significantly worse or if you develop any new symptoms.',
  ARRAY[
    'Postherpetic neuralgia (PHN) is defined as pain persisting for more than three months after an episode of shingles and commonly presents with burning or stabbing pain, allodynia (pain triggered by light touch), and sleep disturbance.',
    'Standard analgesics such as paracetamol and ibuprofen are not effective for neuropathic pain; first-line treatments include amitriptyline, duloxetine, gabapentin, or pregabalin, with the choice guided by the patient''s symptoms and comorbidities.',
    'Topical lidocaine 5% plasters are an effective alternative for localised postherpetic neuralgia, applied once daily for up to 12 hours; clinicians should note that topical capsaicin 0.075% cream (Axsain®) is currently unavailable in the UK until at least mid-2026.',
    'Risk factors for PHN include older age, severe initial shingles rash or pain, prodromal pain, and immunocompromise; all increase the likelihood of persistent nerve pain after the rash resolves.',
    'Practical self-care such as wearing soft cotton or silk clothing and applying a protective barrier dressing can reduce allodynia and improve comfort.',
    'Follow-up within 2 to 4 weeks is recommended to review treatment response, with safety-netting advice to seek help if symptoms worsen or significantly affect daily life.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  63,
  'Dizzy Episodes in Older Adult',
  'Elderly Medicine & Palliative Care',
  'Telephone consultation',
  false,
  'George Whitfield',
  '75-year-old male',
  ARRAY[]::text[],
  ARRAY['Amlodipine 10 mg once daily', 'Ramipril 10 mg once daily', 'Bisoprolol 1.25 mg once daily', 'Atorvastatin 20 mg once daily', 'No Known Drug Allergy'],
  'A&E Discharge Summary 4 weeks ago: Mr George Whitfield presented to the Emergency Department with complaints of recurrent palpitations over the preceding week. On examination, he was haemodynamically stable. Cardiovascular examination revealed normal heart sounds with no audible murmurs. Initial investigations including 12-lead ECG, blood tests, and bedside echocardiography were unremarkable. During cardiac monitoring, the patient had brief runs of sinus tachycardia (heart rate reaching 110 to 115 bpm) temporally associated with the sensation of palpitations. These were self-limiting with no haemodynamic compromise. He was commenced on bisoprolol 1.25 mg once daily for symptom control and referred to the cardiology outpatient clinic. Seen and discharged by: Dr Luke Palmer, MBBS, FRCEM, Emergency Medicine ST6 Registrar. Cardiology Clinic Letter 3 weeks ago: Re: Mr George Whitfield (Age: 75). Dear Colleague, Mr Whitfield was reviewed in the cardiology clinic following his recent presentation with palpitations. He reported no associated symptoms such as chest pain, syncope, or breathlessness, and confirmed symptoms had fully resolved by the time of the appointment. He underwent a 7-day Holter monitor and transthoracic echocardiogram, both of which were entirely normal, with no evidence of arrhythmia or structural heart disease. No further cardiology follow-up is required. Bisoprolol 1.25 mg once daily may be continued at your discretion if he remains well and tolerates it. Discharged back to your care. Kind regards, Dr Kelechi Peters MBBS, MRCP (UK), Consultant Cardiologist. Seen 2 days ago by Practice Nurse: Mr George Whitfield attended for his routine influenza vaccination. Blood pressure recorded as 100/60 mmHg. The vaccine was administered without issue and tolerated well. Patient has booked an urgent telephone consultation to discuss concerns.',
  'Urgent telephone consultation to discuss a 2-week history of light-headedness and dizzy episodes, particularly on standing.',
  'Hello Doctor, I''ve been getting these dizzy spells for the past couple of weeks. It happens when I stand up quickly, and sometimes when I''ve been on my feet for a while. It nearly makes me feel like I''m going to pass out, though I haven''t actually fallen.',
  'The dizziness feels like light-headedness rather than a spinning sensation. Each episode is brief, lasting around 30 seconds, and tends to happen on standing up quickly or after prolonged standing such as when doing household chores or working in the garden. He has not experienced any blackouts, falls, or injuries. There is no chest pain, breathlessness, or palpitations associated with the dizziness. The palpitations that brought him to A&E have fully resolved. He has not noticed headaches, blurred vision, or weakness in his limbs.',
  ARRAY[]::text[],
  'He lives alone. His wife passed away from ovarian cancer three years ago. He does not smoke or drink alcohol. He usually has tea in the mornings but sometimes forgets to drink enough water throughout the day. There is no family history of heart disease. He does not drive.',
  'He is unsure what could be causing the dizziness.',
  'He is worried it could be something serious that might affect his independence, particularly his ability to manage his garden and household tasks.',
  'He would like the doctor to explain what might be causing the dizziness and help him manage it so he can carry on with the things he enjoys.',
  ARRAY[]::text[],
  'Can I still carry on with my gardening?',
  NULL,
  ARRAY[
    'Ask about the onset of dizziness and how long it has been present',
    'Clarify the nature of the dizziness — is it a feeling of light-headedness or a spinning, vertigo-type sensation?',
    'Ask how long each episode of dizziness lasts',
    'Ask about potential triggers — does it occur on standing up, during exertion, or after prolonged standing?',
    'Ask how often it happens and whether it is getting worse, to determine severity and impact on the patient',
    'Ask about associated symptoms, including palpitations, chest pain, or breathlessness during the episodes',
    'Ask if the patient has experienced any falls — if so, how many and whether any injuries were sustained',
    'Ask about any history of recent head trauma, viral illness, or ear symptoms to rule out alternative causes',
    'Explore the impact of symptoms on daily activities and quality of life',
    'Ask if the patient drives, and if so, whether symptoms are affecting driving',
    'Enquire about hydration and dietary intake, particularly fluid consumption',
    'Take a psychosocial history — including who the patient lives with, smoking, and alcohol history',
    'Provide a working diagnosis of possible orthostatic (postural) hypotension'
  ],
  ARRAY[
    'Offer a face-to-face consultation to assess postural blood pressure (measured lying and standing) and to check pulse rate and rhythm.',
    'Consider offering blood tests including FBC (to check for anaemia), U&Es (to assess electrolytes and renal function), and blood glucose. However, if recent bloods are available these should be reviewed first, and clinical judgement used to decide whether repeat testing is necessary.',
    'Offer a medication review: stop bisoprolol, as it was initially prescribed for palpitations that have since resolved and were confirmed as benign by cardiology. It is likely no longer necessary. If palpitations recur, it can be restarted based on clinical need.',
    'Consider reducing or stopping amlodipine, or alternatively adjusting the dose of ramipril, as both may contribute to postural hypotension. Use clinical judgement based on blood pressure readings and overall tolerability.',
    'Advise on lifestyle measures to support independence and allow continued gardening: rise slowly from sitting or kneeling, stay well-hydrated, avoid skipping meals, take breaks when doing household tasks, and have a light snack before physical activity.',
    'Discuss falls prevention as the patient lives alone; suggest a falls alarm device, which can be arranged through the frailty practitioner, community occupational therapist (OT), or social prescriber.',
    'Offer a review of blood pressure again in 2 weeks following any medication adjustments.',
    'Provide safety-netting: advise the patient to seek urgent medical help if symptoms worsen, or if he experiences chest pain, palpitations, or any episode of collapse.'
  ],
  'Thank you for getting in touch today. From what you''ve described, I can understand why this has been worrying you, and it''s exactly the right thing to call about.

George, based on what you''ve told me — the dizziness coming on when you stand up quickly or when you''ve been on your feet for a while, the episodes lasting only a short time and then settling — I think what you may be experiencing is something called postural hypotension. This is a condition where your blood pressure drops slightly when you stand up, which briefly reduces the blood flow to your brain and causes that light-headed, almost-going-to-faint feeling. It is particularly common in older adults and in people taking blood pressure medications.

To confirm this and make sure we are not missing anything else, I would like you to come in so we can check your blood pressure both sitting and standing, and also check your pulse. We may also look at some recent blood tests, or arrange new ones if needed, to check things like your kidney function, salt levels, and whether you might be slightly anaemic.

Now, I also want to mention something about your current medications. You were started on bisoprolol a little while ago for the palpitations, but as you know, those have since settled completely, and the heart specialists confirmed everything was normal. That means bisoprolol is probably no longer necessary, and we can look at stopping it. This could actually help with the dizziness too, as bisoprolol can lower your blood pressure and heart rate. Similarly, your amlodipine and ramipril — both of which you take for blood pressure — can sometimes contribute to this kind of dizziness, so depending on your readings when you come in, we may look at adjusting the dose of one of them.

You mentioned you were worried about whether this might stop you from gardening — and the honest answer is, it should not have to. Most people with postural hypotension can manage very well with a few simple adjustments. These include standing up slowly rather than jumping to your feet, making sure you are drinking enough fluids throughout the day (not just tea in the morning), avoiding long periods on your feet without a break, and having a small snack before doing physical tasks. Those small changes can make a real difference.

One more thing I want to mention is that because you live on your own, it would be worth considering a falls alarm. This is a small device you wear that can call for help automatically if you have a fall. We can organise this through our community team. It is not because I think you are at high risk right now, but rather to give you — and perhaps your family — some peace of mind.

We will arrange a review in about two weeks after any medication changes to see how you are doing. In the meantime, please call us straight away if the dizziness gets significantly worse, if you have chest pain, or if you feel like you actually collapse.',
  ARRAY[
    'Orthostatic (postural) hypotension is defined as a sustained drop in systolic BP of ≥20 mmHg or diastolic BP of ≥10 mmHg within three minutes of standing, and is especially common in older adults on antihypertensive medications.',
    'A thorough medication review is essential; bisoprolol started for benign palpitations that have since resolved and been cleared by cardiology should be stopped, as it is no longer indicated and may be contributing to hypotension.',
    'Both amlodipine and ramipril can contribute to postural hypotension; clinical judgement guided by lying and standing BP readings should determine whether dose reduction or cessation of either is appropriate.',
    'Lifestyle advice including slow positional changes, adequate hydration, avoiding prolonged standing, and eating before physical activity are effective and practical first-line measures for postural hypotension.',
    'Falls risk must be assessed in older patients living alone; a falls alarm device can be arranged via the frailty team, community OT, or social prescriber to support independence and safety.',
    'Clinicians must consider fitness to drive in patients with orthostatic symptoms; if there is concern, the patient should be advised to contact the DVLA directly for guidance.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  64,
  'Dizzy Episodes in Teenager',
  'Neurology',
  'Telephone consultation',
  false,
  'Chloe Bennett',
  '16-year-old female',
  ARRAY[]::text[],
  ARRAY['Not currently taking any regular medications', 'No known drug allergy'],
  'Patient has booked a routine telephone consultation to discuss ongoing concerns.',
  'Telephone consultation to discuss episodes of dizziness, fainting, and a fast heartbeat on standing that have been occurring over the past six months.',
  'Hi Doctor, I''ve been getting really dizzy spells lately and I''ve even fainted a few times. It''s been going on for several months now, and I''ve noticed my heart starts racing whenever I stand up. I''m getting quite worried about it.',
  'The dizziness tends to happen after standing up from sitting for a long time, or when standing still for extended periods such as during school assemblies. On standing, the heart starts to race and she feels light-headed, which usually settles on sitting back down. She has fainted on six occasions; each episode lasted only a few seconds and she recovered quickly without confusion. Her parents recently bought her a smartwatch and she has noticed her heart rate sometimes goes up to 125 beats per minute. She does not experience chest pain or shortness of breath. The palpitations occur only on standing up suddenly. Symptoms seem worse during periods of stress, particularly with A-level preparation.',
  ARRAY[]::text[],
  'She does not smoke, drink alcohol, or use recreational drugs. Her last menstrual period was one week ago. She is not sexually active and is certain there is no chance of pregnancy.',
  'She is not sure what is causing this, but her mum thinks it might be related to anxiety.',
  'She is worried these episodes might interfere with her ability to sit her A-level exams or affect her day-to-day life.',
  'She would like to understand what is causing her symptoms and whether anything can be done to manage or stop them.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY[
    'Ask about the onset and duration of dizziness',
    'Clarify the nature of the dizziness — is it light-headedness or a spinning sensation (vertigo)?',
    'Ask how long each episode lasts',
    'Ask about triggers — does it occur when standing from sitting, during prolonged standing, or with exertion?',
    'Ask about frequency and whether symptoms are worsening',
    'Ask about associated symptoms including palpitations — clarify exactly when they occur, particularly in relation to standing, to assess for Postural Orthostatic Tachycardia Syndrome (PoTS)',
    'Ask about chest pain or shortness of breath during episodes',
    'Ask if any episodes of syncope or collapse have occurred — if so, how many and whether any injuries were sustained',
    'Ask if symptoms occur during exercise — if yes, this is a red flag and should prompt urgent referral to cardiology',
    'Ask about other symptoms such as nausea, vomiting, bowel or urinary changes, and general wellbeing',
    'Ask about menstrual history and whether there is any chance of pregnancy',
    'Explore the impact of symptoms on daily life and school performance',
    'Ask about hydration, diet, and fluid intake',
    'Take a psychosocial history including who she lives with, smoking, alcohol, and any recreational drug use',
    'Give a working diagnosis of possible postural orthostatic tachycardia syndrome (PoTS)'
  ],
  ARRAY[
    'Offer a face-to-face appointment to examine the patient, check pulse and blood pressure sitting and standing, and listen to the heart for any murmurs.',
    'Postural Orthostatic Tachycardia Syndrome (PoTS) is more likely if there is a sustained rise in heart rate of ≥30 bpm (or ≥40 bpm in those aged 12 to 19) within 10 minutes of standing, in the absence of orthostatic hypotension.',
    'Offer blood tests including thyroid function, U&Es, LFTs, FBC, cortisol, and ferritin.',
    'Offer a 12-lead ECG to rule out arrhythmia or structural abnormalities.',
    'Advise the patient to keep a symptom diary to identify potential triggers.',
    'Recommend increasing fluid intake to 2 to 2.5 litres per day, avoiding prolonged standing, and rising slowly from sitting or lying down.',
    'Suggest compression stockings if symptoms are significant or persistent.',
    'Encourage gentle, regular exercise such as walking, but advise stopping immediately if symptoms arise during activity.',
    'Offer to refer the patient to a paediatric cardiologist for further evaluation and management after baseline investigations are completed — they may consider medications such as fludrocortisone or SSRIs.',
    'Offer a letter of support for the school to facilitate reasonable adjustments during A-level preparation, helping to reduce anxiety and avoid symptom triggers.',
    'Safety-net: advise the patient to seek urgent medical attention if symptoms worsen, if chest pain develops, or if dizziness occurs during exercise.'
  ],
  'Thank you for speaking with me today, and thank you for describing everything so clearly — that really does help. It is completely understandable that you''ve been worried about this, especially with exams coming up.

Chloe, from what you''ve told me, I think you may have a condition called Postural Orthostatic Tachycardia Syndrome — or PoTS for short. This is a condition where your heart beats much faster than normal when you stand up. When you change position from sitting or lying to standing, your body has to work to keep the blood pumping up to your brain. In PoTS, this adjustment does not happen as smoothly as it should, which causes your heart to race and makes you feel dizzy or light-headed. Sometimes, as you have experienced, it can even cause a brief faint. The good news is that it is not dangerous or life-threatening, but it can certainly affect your daily life, and that is why it is important we get on top of it.

The next step is to come in so I can check your blood pressure and heart rate both sitting and standing, and have a listen to your heart. I will also arrange some blood tests and an ECG — that is a simple painless tracing of your heart — to make sure we rule out anything else. Would that be okay?

If the results point towards PoTS, I will refer you to a heart specialist called a paediatric cardiologist, who has particular experience managing this in young people. They may recommend medications if needed, but very often the most effective approach involves lifestyle changes, which I can tell you about now.

Drinking more fluids — aiming for around 2 to 2.5 litres a day — is one of the most helpful things. Avoiding standing still for long periods, getting up slowly from sitting or lying, and wearing compression stockings if needed can all make a real difference. Light, regular exercise like walking is also beneficial, though if you ever feel dizzy during activity, stop straight away and sit or lie down.

I also want to help with your school situation. I can write a letter to your school explaining what is happening, so they can put some reasonable adjustments in place — things like being allowed to sit during assemblies, or having a bit of extra support around exam time. I know stress can make symptoms worse, so making sure you feel supported at school is just as important as any medical treatment.

Please do get in touch urgently if things get worse, if you develop any chest pain, or if you feel dizzy while exercising. Otherwise, let''s get you booked in for that face-to-face appointment as soon as possible.',
  ARRAY[
    'Postural Orthostatic Tachycardia Syndrome (PoTS) is an important cause of recurrent dizziness, palpitations, and syncope in adolescents, particularly females; it is defined by a sustained rise in heart rate of ≥30 bpm (or ≥40 bpm in those aged 12 to 19) within 10 minutes of standing, without orthostatic hypotension.',
    'Symptoms occurring during exercise are a red flag in a young person with palpitations and syncope and should prompt urgent referral to cardiology to exclude serious cardiac causes.',
    'Baseline investigations include ECG, thyroid function, FBC, U&Es, LFTs, cortisol, and ferritin; postural BP and heart rate measurements are essential to support a clinical diagnosis of PoTS.',
    'First-line management is non-pharmacological: increased fluid intake (2 to 2.5 litres per day), gradual positional changes, compression stockings, and regular gentle exercise; pharmacological options such as fludrocortisone or SSRIs may be considered by the specialist.',
    'The impact on education and wellbeing must be considered; a school support letter facilitating reasonable adjustments can reduce anxiety and help the young person manage symptom triggers.',
    'Referral to a paediatric cardiologist is appropriate after baseline investigations for further evaluation and management of confirmed or suspected PoTS.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  65,
  'Abdominal Migraine',
  'Gastroenterology & Haematology',
  'Telephone consultation',
  false,
  'Lily Forsythe',
  '9-year-old female',
  ARRAY[]::text[],
  ARRAY['Not currently on any regular medications', 'No known drug allergy'],
  'Seen 3 months ago by Dr Adaeze Okonkwo (Clinical practitioner access role). Presenting complaint: Patient seen with her mother. She reports intermittent abdominal pain on and off for 2 to 3 months. No change in bowel habits, no PR bleeding, no vomiting or diarrhoea, no weight loss. Examination: Abdomen soft and non-tender, no masses. Plan: Bloods including TFTs, LFTs, FBC, U&Es, ferritin, coeliac screen, and stool for calprotectin. Review in 2 weeks. Investigation outcome: Blood and stool calprotectin results reviewed and found to be within normal limits. Results filed by Dr Adaeze Okonkwo. Recent A&E Attendance 4 days ago — A&E Letter: Dear Colleague, Lily Forsythe, a 9-year-old female, was seen in the Emergency Department for episodic abdominal pain. She reported recurrent episodes of cramping abdominal pain over the last 6 months which suddenly worsened the previous day. There are no associated vomiting, diarrhoea, or fever. On review, she was otherwise well with no signs of acute illness. Investigations: urinalysis normal; blood tests (including thyroid function, FBC, U&Es, LFTs, ferritin, folate, CRP) normal; bedside abdominal ultrasound normal. Based on her clinical presentation and normal investigation findings, abdominal migraine is the most likely diagnosis. Recommendations: if symptoms recur, follow up with GP for further evaluation and management. If symptoms change in nature or become more severe, advise immediate re-assessment. Kind regards, Dr Chika Cubana, MBBS FRCEM, ST6 Emergency Medicine Specialist Registrar. Patient''s mother — Claire Forsythe — has booked a routine telephone consultation to discuss ongoing concerns.',
  'Routine telephone consultation for mother to discuss ongoing abdominal pain episodes in her 9-year-old daughter, following a recent A&E attendance and a provisional diagnosis of abdominal migraine.',
  'Hello Doctor, I''m calling about my daughter Lily. She''s been having these tummy pains on and off for about six months now. She was just at A&E the other day and they mentioned something about abdominal migraine. I wanted to call and get a bit more clarity on what that means and what we should be doing.',
  'Lily experiences episodes of abdominal pain every 2 to 3 weeks. Each episode typically lasts a few hours to a full day. The pain is located in the centre of her tummy and feels cramping or aching. She sometimes feels slightly nauseous during episodes but has never vomited. The episodes seem to happen after Lily eats dark chocolate, which she loves. Lily is otherwise well, happy at home, and doing well at school. She has not missed any school because of the pain.',
  ARRAY[]::text[],
  'Lily lives at home with her mother Claire, her father, and her younger brother who is 5 years old and also well. Family history: Claire (her mother) has a history of migraine headaches.',
  'A doctor at A&E recently mentioned abdominal migraine as a possible cause, and her mother is wondering if that is indeed the diagnosis.',
  'She is concerned about Lily being in pain and wants to know if any treatment is needed.',
  'She would like to confirm the diagnosis of abdominal migraine and understand how best to manage it going forward. She also wants to know whether Lily will go on to develop migraine headaches in the future, and whether this could be irritable bowel syndrome (IBS).',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY[
    'Ask about the onset of symptoms',
    'Ask about the nature of the abdominal pain, including location, duration, and whether anything relieves or worsens it, such as stress or certain foods including chocolate',
    'Ask about associated symptoms such as nausea, vomiting, change in bowel habits (diarrhoea or constipation), or PR bleeding',
    'Ask about the presence or absence of headaches during episodes',
    'Ask if the patient has started her periods (menarche) to rule out menstrual-related causes such as dysmenorrhoea',
    'Ask about any weight loss, changes in appetite, or concerns around growth, to assess the nutritional impact of symptoms and exclude malignancy',
    'Ask about family history of migraines',
    'Ask how symptoms have affected the child''s day-to-day life, including school attendance and activities',
    'Take a social history, including who lives at home',
    'Give a diagnosis of possible abdominal migraine, given that all other investigations have been reported as normal'
  ],
  ARRAY[
    'There is no need for an immediate face-to-face appointment to assess this child, as she has already been evaluated twice with the most recent assessment occurring just four days ago.',
    'Advise keeping a symptom diary to help identify potential triggers, monitor the frequency and pattern of episodes, and guide future management.',
    'Advise avoiding dark chocolate, as this appears to be a possible trigger for her symptoms.',
    'Recommend paracetamol or ibuprofen during acute episodes to manage pain.',
    'If episodes become more frequent, start to interfere with school attendance, or significantly affect her day-to-day life, consider referral to a paediatrician for further evaluation and possible preventative treatments.',
    'Advise the mother to seek urgent medical advice if Lily develops new symptoms such as constant or worsening pain, fever, vomiting, weight loss, or if the nature of the pain changes.',
    'Offer a follow-up review in 4 to 6 weeks to assess progress, discuss the symptom diary, and adjust the plan if needed.',
    'Inform the mother that abdominal migraines can sometimes be a sign that a child may be more likely to develop regular migraines later in life, especially with a family history. However, not every child with abdominal migraines will go on to develop them, and some children grow out of it altogether.',
    'Reassure the mother that this is unlikely to be irritable bowel syndrome (IBS), as IBS usually involves ongoing bowel symptoms such as diarrhoea or constipation, which Lily does not have.'
  ],
  'Thank you so much for calling today, and for taking the time to explain what''s been happening with Lily. I can understand how unsettling it must be to watch your daughter go through these painful episodes without a clear explanation.

You mentioned that the A&E doctor raised the possibility of abdominal migraine, and having reviewed Lily''s history, her symptoms, and all the test results that have come back completely normal, I do agree that abdominal migraine is the most likely explanation for what she has been experiencing. Before I go any further, has anyone explained to you what abdominal migraine actually is, or have you had a chance to look it up?

Abdominal migraine is a condition that we do see in children, and it can be a little surprising because when most people hear the word migraine, they think of a headache. In this form, however, the pain is felt in the tummy rather than the head. It tends to come in episodes, usually every few weeks, and each episode can last anywhere from a few hours to a whole day. During an episode, children often feel nauseous, and the pain is typically felt in the centre of the abdomen. Between episodes, they are completely well — which fits exactly with what you have described about Lily.

One helpful observation you have made is that the episodes seem to follow eating dark chocolate. That is a really useful clue, because certain foods can be triggers for abdominal migraine — much as they can be for head migraines. Other common triggers include stress, disrupted sleep, and irregular meals.

One of the most useful things you can do at home is to keep a symptom diary — noting when each episode happens, what Lily has eaten beforehand, how long it lasts, and whether anything seems to help. This will help us identify clear patterns and guide any future decisions. For now, it would also be worth trying to avoid dark chocolate to see if that reduces the frequency of episodes.

During an episode itself, simple pain relief such as paracetamol or ibuprofen is perfectly appropriate to use and should help make Lily more comfortable. There is no need for specialist medication at this stage.

You asked about whether Lily will develop migraine headaches when she gets older. That is a really sensible question. Children with abdominal migraine do have a higher chance of developing typical migraines later, particularly with a family history like yours. However, not every child goes on to develop them — and some children grow out of the abdominal episodes entirely as they get older.

You also asked about IBS. I want to reassure you that this does not sound like IBS. IBS typically involves ongoing changes in bowel habits — things like regular diarrhoea or constipation — and Lily has not had any of those symptoms.

I would like to review Lily again in about four to six weeks to see how she has been getting on and to look at the symptom diary together. In the meantime, please do not hesitate to call sooner if the pain becomes constant or much worse, if she develops a fever, starts vomiting, loses weight, or if anything else about the symptoms changes.',
  ARRAY[
    'Abdominal migraine is a recognised functional gastrointestinal disorder in children, presenting with episodic central abdominal pain, often with nausea, in the absence of structural or biochemical abnormality; it is more common in children with a personal or family history of migraine.',
    'The diagnosis of abdominal migraine is clinical and is made when thorough investigation (including FBC, TFTs, LFTs, U&Es, ferritin, coeliac screen, urinalysis, abdominal ultrasound, and stool calprotectin) is normal and the episodic pattern fits.',
    'Trigger identification via a symptom diary is a key first step in management; common triggers include certain foods (including chocolate), stress, and irregular sleep or meals.',
    'Acute episode management involves paracetamol or ibuprofen; if episodes are frequent or significantly disruptive, referral to a paediatrician for consideration of preventative therapy is appropriate.',
    'Children with abdominal migraine may go on to develop typical migraine headaches in adolescence, particularly where there is a family history; parents should be counselled about this possibility while being reassured that not all children follow this trajectory.',
    'Red flags warranting urgent reassessment include constant or worsening pain, fever, vomiting, weight loss, or change in the pattern of symptoms; safety-netting on these points is essential.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  66,
  'Request to Amend Medical Records',
  'Ethics',
  'Telephone consultation',
  false,
  'Dev Sharma',
  '51-year-old male',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication', 'No known drug allergies'],
  'Recently re-registered with the practice. Patient has booked a routine telephone consultation to discuss concerns.',
  'Routine telephone consultation. Patient has recently re-registered with the practice and is calling to request removal of a previous Hepatitis C diagnosis from his medical records following a new job requirement.',
  'Hi Doctor, I''ve just started a new job and had to fill in a medical history form. I noticed that Hepatitis C is still showing on my records, and I''d really like that removed if possible.',
  'Dev was diagnosed with Hepatitis C and treated successfully with antiviral medication 7 years ago. At the time he was under the care of a hospital specialist, but he relocated to Canada to work as a property developer and missed some of his follow-up appointments. He has recently returned to the UK and started a new job as a catering manager. As part of his employment, he was asked to complete a medical history form, which led to concerns about Hepatitis C still being on his record and whether this might affect his employment. He feels completely well and has had no symptoms.',
  ARRAY[]::text[],
  'He does not smoke, drink alcohol, or use recreational drugs. He lives alone but has recently started a new relationship with a man.',
  'He believes that since his Hepatitis C was treated years ago and he has had no symptoms since, it should no longer appear on his medical records.',
  'He is worried that having Hepatitis C recorded in his medical history might affect his ability to work, particularly in his new role in the catering industry.',
  'He wants to know whether the Hepatitis C entry can be removed from his records now that he has completed treatment. He has also recently started a new relationship and wants to know if it is safe to have unprotected sex. He additionally wants to know whether, if Hepatitis C is still active, this would prevent him from working as a catering manager.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY[
    'Ask when he was diagnosed with Hepatitis C and for details about his treatment 7 years ago, including why he disengaged from gastroenterology follow-up',
    'Ask about his current general health — any ongoing symptoms or concerns',
    'Ask if he has experienced any symptoms suggestive of liver disease, such as jaundice, abdominal pain, pale stools, dark urine, or generalised itching',
    'Ask if he has had any recent blood tests, liver function monitoring, or follow-up for Hepatitis C since completing treatment',
    'Ask about his alcohol intake, smoking habits, and any history of intravenous drug use',
    'Clarify his current relationship status and any relevant sexual health concerns',
    'Ask whether his employer''s medical form is requesting confirmation of Hepatitis C resolution, or simply asking for a general medical history'
  ],
  ARRAY[
    'Explain that it would not be appropriate or safe to remove the Hepatitis C diagnosis from his medical records.',
    'Inform the patient that medical records are kept accurately to protect his health and to ensure that any future healthcare professional involved in his care has the full information needed to make safe and effective decisions; if Hepatitis C were relevant to a future treatment or condition, missing this information could lead to inappropriate or delayed care.',
    'Inform the patient that even if Hepatitis C is still present, it should not prevent him from working in a catering role. Hepatitis C is a blood-borne virus and is not transmitted through food or casual contact. As long as he has no open wounds or cuts, there is no risk to others. If the employer has concerns, they can be directed to occupational health for further guidance.',
    'Arrange blood tests to check for active Hepatitis C infection, liver function tests, and other baseline bloods.',
    'Regardless of test results, refer the patient back to gastroenterology or hepatology for specialist follow-up, as he was previously treated but lost to follow-up.',
    'Advise on practising safe sex, especially in the context of a new relationship, until his current Hepatitis C status is confirmed.',
    'Safety-net: advise the patient to seek medical attention if he develops symptoms such as jaundice, unusual fatigue, abdominal pain, or dark urine.'
  ],
  'Thank you for calling today, and I can completely understand why you want to move on from something that feels like it belongs in the past. Being asked to put Hepatitis C on a medical form for a new job is understandably uncomfortable, especially when you feel so well.

Dev, I want to be honest with you about why we are not able to remove the entry from your records. Medical records are meant to be a complete and accurate account of your health history — not just for administrative purposes, but to keep you safe. If you were ever seen by another doctor in the future — say, for a liver-related problem, or before being given a new medication — having that history available could help them make the right decisions quickly. Removing a genuine past diagnosis would not be in your best interests, and it would not be ethically or legally appropriate for us to do so.

That said, I want to reassure you about your concerns regarding work. Having Hepatitis C in your past, or even if it turns out to still be active, does not prevent you from working in a catering environment. Hepatitis C is a blood-borne virus. It is not passed on through food, cooking, or everyday contact with other people. As long as you do not have open cuts or wounds, there is genuinely no risk to your colleagues or customers. If your employer has any concerns, they can seek advice from occupational health, who will be able to confirm this for them.

What I do think is important is that we find out where things stand with the virus. You completed treatment seven years ago, but you were not able to attend all of your follow-up appointments, so we do not have confirmation that the virus cleared completely. I would like to arrange some blood tests — this will include a check for active Hepatitis C infection as well as your liver function and some baseline bloods. I would also like to refer you back to the liver specialists, because regardless of the result, they should review you properly given the gap in follow-up.

You also asked about your new relationship and whether it is safe to have unprotected sex. That is a very important question, and I am glad you raised it. If the treatment was successful and the virus is no longer present in your blood, then there is no risk of passing it on, even without a condom. However, until we have confirmed that through a blood test, I would recommend using condoms in the meantime — just to be safe. Once we have the results, we can have a clearer conversation about this.

Please do contact us sooner if you develop any new symptoms in the meantime — in particular, yellowing of the skin or eyes, unusual tiredness, tummy pain, or dark urine. These are things we would want to know about promptly.',
  ARRAY[
    'Medical records are a legal and ethical record of a patient''s health history and cannot be altered or deleted simply because the patient requests it; a diagnosis can only be corrected if it was a factual error, and the original entry must still be retained with an annotation of what changed, who made the change, and when.',
    'Under GDPR, patients may request correction of factual errors in their records, but they cannot require removal of a clinician''s confirmed diagnosis simply because they disagree with it or because treatment has been completed.',
    'Hepatitis C is a blood-borne virus and is not transmitted through food or casual contact; a diagnosis of Hepatitis C, even if still active, does not preclude employment in the food industry, and employers with concerns should be directed to occupational health.',
    'Patients who have completed Hepatitis C treatment but were lost to specialist follow-up should be referred back to gastroenterology or hepatology for review, regardless of whether virological cure can be assumed.',
    'Safe sex advice is an important component of management in a patient with known or suspected active Hepatitis C who is in a new sexual relationship; advise condom use until treatment status is confirmed with blood tests.',
    'Baseline investigations should include a test for active Hepatitis C infection, liver function tests, and other relevant bloods to assess current hepatic status and guide onward management.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  67,
  'Medically Unexplained Symptoms',
  'General Practice',
  'Telephone Consultation',
  false,
  'Patricia Norwood',
  '71-year-old female',
  ARRAY['Hypertension','Osteoarthritis'],
  ARRAY['Amlodipine 5 mg once daily','Paracetamol as required','No known drug allergies'],
  'Seen by Dr Fiona Okafor (Clinical practitioner access role) 4 weeks ago. Presenting complaint: Patient reported multiple symptoms including feeling generally unwell, with ongoing tiredness, a brief episode of sharp pain in her right knee that settled quickly, persistent lower back discomfort, hair thinning, and occasional abdominal pain. Examination: BP 125/60 mmHg, Pulse 65 bpm, abdomen soft, non-tender, no masses, chest clinically clear with normal heart sounds. Impression: Medically unexplained symptoms. Plan: Bloods including TFTs, LFTs, FBC, U+Es, Ferritin, Ca-125, Coeliac screen and stool for calprotectin and FIT. Review in 2 weeks. Investigation Outcome: All results returned within normal limits. Patient informed via standard text message. Advised to recontact if symptoms persisted or worsened. Patient booked routine telephone appointment to discuss concerns.',
  'Patient called to discuss ongoing physical symptoms following normal blood and stool test results.',
  'I''ve been having all these different symptoms and I''m not really sure what to make of them. Everything came back normal on the tests but I still don''t feel right.',
  'You have been experiencing ridges appearing on your nails, a single episode of knee pain, lower back pain, hair thinning, occasional abdominal discomfort, and a vague feeling that something isn''t right. These symptoms have made you feel quite overwhelmed and anxious. All recent blood and stool tests came back normal, but you still feel unsettled.',
  ARRAY[]::text[],
  'You live alone in Bristol. Your husband passed away six months ago from pancreatic cancer. You do not smoke and have no family history of cancer. Your mood is generally okay — you would not say you are depressed, but you miss your husband deeply. You have supportive friends and family nearby, but since your husband died you have not been going out much. You have experienced some health worries and moments of panic during this time. You have two adult daughters who live in Canada.',
  'You are worried that your symptoms could be linked to something serious like pancreatic cancer, which your husband had.',
  'You are frightened that something is being missed, and you feel anxious about your general health.',
  'You want the doctor to take your symptoms seriously, help you understand what might be going on, and advise you on what you can do to improve your health and wellbeing.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Ask specific follow-up questions for each of the patient''s reported symptoms.',
    'Nails: When did the ridges start? Any changes in colour, texture, or shape of the nails?',
    'Knee pain: Was the pain related to any activity or injury? Any swelling, redness, or stiffness?',
    'Abdominal discomfort: Where exactly is the pain? Is it getting worse? Any change in bowel habits or PR bleeding?',
    'Back pain: Does it improve or worsen with rest or movement? Any bowel or bladder changes?',
    'Hair thinning: When did this begin? Any recent stress, illness, dietary change, or new medication?',
    'Ask about cancer red flags: unintentional weight loss, night sweats, loss of appetite (Note: loss of appetite may also relate to grief or low mood).',
    'Explore social history: how she is coping emotionally since her husband''s death, availability of family or social support, impact on daily life.',
    'Ask about sleep, and whether symptoms are affecting her routine or functioning.',
    'Ask if she has accessed any form of bereavement counselling or emotional support.',
    'Explore ICE (ideas, concerns, expectations) to better understand her fears and what she hopes to achieve from the consultation.',
    'Give a working diagnosis of grief-related anxiety with somatic symptoms, or health anxiety following bereavement.'
  ],
  ARRAY[
    'Reassure the patient that her symptoms are not concerning based on recent normal investigations, and take a symptom-specific approach.',
    'Nail ridges: Reassure that these are common with age or can be stress-related; ferritin levels were normal, which helps rule out iron deficiency.',
    'Knee pain: Likely mechanical or linked to osteoarthritis; advise gentle movement, regular activity, and consider paracetamol as needed.',
    'Abdominal discomfort: Reassure her that both FIT and calprotectin were normal and there are no red flag symptoms; continue to monitor.',
    'Back pain: Likely mechanical in nature; recommend gentle stretching, pacing of activities, and maintaining mobility.',
    'Hair thinning: Reassure that this may be stress-related (telogen effluvium); advise monitoring and offer review if it persists or worsens.',
    'Explore and offer support for bereavement, such as local bereavement counselling services, support groups, or referral for CBT if symptoms of health anxiety persist.',
    'Encourage gentle re-engagement with activities she enjoys, such as gardening or community groups; consider referral to the social prescriber for additional local support.',
    'Safety net: Advise her to contact the practice urgently if she develops new or worsening abdominal symptoms (e.g. persistent pain, a lump, diarrhoea, PR bleeding), sudden worsening of back pain, or visual changes such as an increase in floaters or flashes of light.'
  ],
  'It''s clear from our conversation today, Patricia, that you have been through an enormous amount over the past several months, and it makes complete sense that your body and mind are feeling the strain of that. Losing your husband so recently — and to pancreatic cancer — would understandably make anyone more alert to changes in their own health. I want you to know that your concerns are entirely valid and I am taking them seriously.

The good news is that the tests we arranged were thorough and covered a wide range of potential causes, and everything came back reassuringly normal. That includes your blood count, thyroid function, liver tests, iron stores, markers for coeliac disease, and even the bowel cancer screening stool tests. There was nothing there to suggest anything sinister is going on.

That said, I want to go through each of your symptoms individually so nothing gets overlooked. The ridges on your nails are very common and can appear with age or during periods of stress or illness — your iron levels were checked and are normal, which is reassuring as low iron is one of the things that can contribute to nail changes. The brief episode of knee pain you had is most likely related to wear and tear in the joint, which is common with a background of osteoarthritis. The fact that it settled quickly on its own is a positive sign, and gentle activity along with paracetamol when needed should help with any recurrence.

Your back discomfort is also most likely mechanical in nature — related to posture, reduced activity, or the way tension tends to settle in the body during stressful times. Keeping gently mobile, doing some light stretching, and using paracetamol if needed often makes a real difference. As for the abdominal discomfort, both the FIT test and the calprotectin came back normal, which is very reassuring and helps to rule out inflammation or anything more serious in the bowel.

Regarding your hair thinning — this is something we call telogen effluvium, and it happens when the body goes through a significant physical or emotional stress, which causes more hairs than usual to enter a resting and then shedding phase. It can be quite distressing to notice, but the good news is that it usually settles down on its own over time as things stabilise.

So while each of these symptoms taken on its own is not worrying, and together they are not pointing towards anything dangerous, I do think what we might be seeing is your body''s way of processing grief and the emotional weight of what you have been through. This is genuinely very common, and it does not mean these symptoms are any less real — they absolutely are real. It is simply that grief and anxiety can have very tangible physical effects.

I would love to offer you some support with that side of things. There are bereavement counselling services we could refer you to, and our social prescriber can also help you gently find your way back into activities and social connection when you feel ready. We will keep a close eye on things, and if anything changes or you notice any new symptoms — particularly anything to do with your tummy, bowel, or eyesight — please do not hesitate to get in touch straight away. You are absolutely not alone in this.',
  ARRAY[
    'Grief following bereavement can manifest as multiple vague physical symptoms (somatic symptoms), including fatigue, pain, hair thinning, and gastrointestinal discomfort — this is a recognised grief reaction and should not be prematurely dismissed.',
    'Appropriate investigation is essential before attributing symptoms to psychological causes; relevant tests include TFTs, FBC, LFTs, U+Es, ferritin, Ca-125, coeliac screen, calprotectin, and FIT.',
    'Telogen effluvium is a stress- or illness-related form of hair thinning that typically resolves spontaneously as the underlying trigger settles.',
    'Management should address both physical symptoms individually and the underlying emotional cause; options include bereavement counselling, CBT for health anxiety, and referral to social prescribing.',
    'Safety-netting in this presentation should include advice to return urgently for new or worsening abdominal symptoms (pain, PR bleeding, a lump), sudden back pain, or visual disturbance.',
    'Nail ridges (onychorrhexis) are common with ageing and stress; normal ferritin helps exclude iron deficiency as a contributory cause.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  68,
  'Teenager with Gender Dysphoria',
  'General Practice',
  'Telephone Consultation',
  false,
  'Sophie Hargreaves (previously known as Nathan Hargreaves)',
  '15-year-old female (assigned male at birth)',
  ARRAY['No known medical conditions'],
  ARRAY['Not currently taking any medications','No known drug allergy'],
  'The patient''s mother booked a routine telephone appointment for Sophie to discuss some concerns.',
  'Appointment booked by patient''s mother to discuss difficulties Sophie has been experiencing at school and concerns about her emotional wellbeing.',
  'Hi doctor… I''ve been struggling at school recently. I just don''t feel like I belong there, and my mum thought it would be helpful for me to speak to the GP about it.',
  'You are Sophie, a 15-year-old girl. You were assigned male at birth but have been socially transitioning to female over the past year. You now identify and present as female and sometimes wear female clothing. You have recently been feeling increasingly uncomfortable at school. Although you have not experienced direct bullying, you feel out of place and unable to connect with your peers. There is no one else like you at school, and you often feel isolated or out of place. Attending school has become emotionally draining and you have become reluctant to go. You mentioned to your mum that homeschooling might suit you better — a safer and more understanding environment. This is what prompted her to book this appointment. You are not low in mood but feel slightly anxious about going to school.',
  ARRAY[]::text[],
  'You live at home with your mum and older brother, both of whom are supportive. You do not smoke, drink alcohol, or use any drugs. You are not taking any hormones, either from a clinic or sourced online.',
  'You feel your reluctance to attend school is mainly due to feeling misunderstood and disconnected from other students. You believe homeschooling could offer you more comfort and emotional security.',
  'You are worried that staying in your current school environment might affect your emotional wellbeing and make it harder to focus on learning. You also worry about expressing your identity openly without drawing unwanted attention.',
  'You are hoping for support from the GP to better understand your feelings and to explore whether homeschooling is a suitable option. Ask: "Am I allowed to use the girls'' toilets at school?"',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Ask why she feels reluctant or uncomfortable about going to school.',
    'Ask whether she has experienced any bullying or if anyone at school is making her feel unsafe or excluded.',
    'Ask about her relationships with peers and teachers, and whether she feels supported or isolated.',
    'Ask if she is struggling academically or finding lessons harder to manage.',
    'Assess her emotional wellbeing: mood, sleep, appetite. If any of these are low, sensitively ask about suicidal thoughts or self-harm.',
    'Ask if she feels anxious, particularly in school settings or socially.',
    'Ask if she has had any recent physical health concerns or bodily changes that are worrying her.',
    'Ask whether she has spoken to anyone at school — such as a teacher, school nurse, or pastoral lead — about how she has been feeling or what support might be available.',
    'Ask whether she is taking any medications, including hormones or other gender-affirming treatments, or if she is considering starting them.',
    'Ask how her transition journey has been so far, including how she feels about her identity and how others have responded.',
    'Explore the home environment — who she lives with and whether there are any issues or conflicts at home.',
    'Ask about lifestyle: smoking, alcohol, or use of illicit substances.',
    'Explore what she hopes homeschooling will offer and how it might feel different or better than school.',
    'Ask whether she has explored other options such as moving schools or accessing additional pastoral or emotional support within her current school.'
  ],
  ARRAY[
    'Acknowledge her interest in homeschooling and explain that while it may offer short-term relief and help improve her mental wellbeing, there are potential long-term downsides, such as cost, reduced social interaction, and it may not fully address underlying feelings of not being accepted or confident in society. Emphasise that building self-confidence and feeling included now is important for long-term wellbeing and development.',
    'Encourage her to speak with a trusted adult at school, such as a teacher, head of year, or pastoral lead, about how she has been feeling, and to explore what support the school might be able to offer.',
    'In the meantime, offer information about online support groups for transgender and gender-diverse young people, such as Mermaids, which offers peer support, youth groups, and counselling.',
    'Suggest organisations such as Stonewall, which provide resources and can connect her with counsellors or psychologists experienced in supporting LGBTQ+ youth.',
    'Offer a referral to the social prescriber, who can help explore local community support, youth groups, and discuss homeschooling as a short-term option if appropriate.',
    'Regarding school toilets: Advise that the school should ideally provide gender-neutral toilets. Explain that, according to the most recent Supreme Court ruling and Equality and Human Rights Commission (EHRC) guidance, access to male or female toilets may be restricted based on biological sex, even for individuals who have transitioned. However, reassure her that the law still protects her from discrimination, and she must never be left without access to a toilet. The school has a duty to ensure she has a safe, appropriate facility she can use comfortably.',
    'If she has not yet been seen by anyone regarding her transition or gender dysphoria, offer a referral to CAMHS or the community paediatric team for emotional wellbeing support and to initiate onward referral to a gender identity clinic, as referrals for young people under 16 must go through one of these services.',
    'Arrange a follow-up in 4–6 weeks to review how she is doing emotionally and socially, and whether she has accessed any of the support offered.',
    'Safety net: Advise her (and her mother) to seek help urgently if her mood worsens, if she feels unsafe, or if she starts having thoughts of self-harm or suicide.'
  ],
  'Sophie, thank you so much for feeling able to talk to me today — I know it isn''t always easy to put these kinds of feelings into words, and I really appreciate your honesty. It''s completely understandable to find school difficult when you feel like you don''t quite fit in or connect with the people around you. Even without direct bullying, that sense of isolation can be genuinely exhausting, and I want you to know that your feelings make complete sense.

I can hear why homeschooling is appealing — the idea of a space where you feel safer and more comfortable, without the pressure of navigating a school environment that can feel unwelcoming, is entirely reasonable. In the short term, it could give you some valuable breathing room. However, I want to be honest with you about some of the longer-term considerations, because I think you deserve a full picture.

Homeschooling can sometimes be costly, and while it might reduce day-to-day stress, it doesn''t always address the deeper challenge of building confidence and a sense of belonging around others. Those are skills that will really matter as you grow and move into the wider world, and ideally we want to find ways to help you develop them in a supported and safe way, rather than stepping away from that opportunity altogether.

Before making any big decisions, there are several other avenues we can explore together. Speaking to someone you trust at school — whether that''s a form tutor, head of year, or a pastoral lead — could open up support that you might not yet know is available. There are also some excellent organisations specifically for young people like yourself. Mermaids is one — they offer peer support, youth groups, and counselling for transgender and gender-diverse young people. Stonewall is another that can connect you with experienced counsellors. Our social prescriber can also help you explore local community options.

Regarding your question about toilets at school — that is a really important one and I am glad you asked. Ideally, your school should have gender-neutral toilet facilities so that you have access to a space where you feel safe and comfortable. According to the most recent Supreme Court ruling and guidance from the Equality and Human Rights Commission, access to single-sex toilets may in some circumstances be restricted based on biological sex. However — and this is important — the law still protects you from discrimination, and the school has a clear duty to ensure you always have access to a safe and appropriate facility. You should never be left without somewhere to go. If this is a concern, I can help support that conversation with the school if that would be useful.

Finally, I would also like to offer you a referral to CAMHS or the community paediatric team — not because anything is wrong, but because they can provide proper emotional wellbeing support and, when the time is right, help with onward referral to a gender identity clinic. For young people under 16, that pathway needs to go through one of those services. I would like us to check in again in about four to six weeks. And please — if at any point you or your mum feel things are getting harder, or if you have any thoughts of hurting yourself, reach out to us straight away.',
  ARRAY[
    'Young people under 16 with gender dysphoria should be referred to CAMHS or a community paediatric team for emotional wellbeing support and onward referral to a gender identity clinic — direct GP referral to a gender identity clinic is not appropriate for this age group.',
    'Homeschooling may offer short-term emotional relief but carries long-term risks including reduced social development and cost; explore school-based pastoral support and community organisations (Mermaids, Stonewall) before recommending homeschooling.',
    'According to the UK Supreme Court ruling and EHRC guidance, access to single-sex toilet facilities may be restricted based on biological sex even for individuals who have socially transitioned; however, schools must ensure every student has access to a safe and appropriate toilet and cannot leave a student without provision.',
    'Always ask transgender young people whether they are taking any hormones, and if so, where these are sourced — unsupervised or online-sourced hormones require referral for appropriate specialist oversight.',
    'Sensitively screen for low mood, self-harm, and suicidal ideation in any young person presenting with social isolation or gender-related distress.',
    'Safety-netting must include clear advice to the patient and parent/guardian to seek urgent help if mood deteriorates or thoughts of self-harm arise.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  69,
  'Unexplained Rash',
  'Dermatology',
  'Telephone Consultation',
  false,
  'Karen Mitchell',
  '37-year-old female',
  ARRAY['None recorded'],
  ARRAY['Not currently on any regular medication','No known drug allergy'],
  NULL,
  'Patient booked a routine telephone appointment to discuss a recurring rash that has been coming and going for the past two months.',
  'Doctor, I''ve had this rash that keeps coming and going for the last couple of months and I''m not really sure what''s causing it.',
  'For the past two months, you have been getting a red, raised, itchy rash that usually appears around your neck and arms. The rash comes and goes, and each episode lasts about one to two days. You take cetirizine 10 mg, which sometimes helps. The rash is not present today — the last episode was yesterday and it settled this morning. You otherwise feel well with no fever, weight loss, or other symptoms.',
  ARRAY[]::text[],
  'You live with your partner and three children. You work as a dental receptionist. You do not smoke or drink alcohol. You consider yourself generally fit and well.',
  'You think it might be some kind of allergic reaction, but you are not sure what is triggering it.',
  'You want to be sure it is not something serious.',
  'You would like to find out what is causing the rash and what you can take or do to stop it coming back.',
  ARRAY[]::text[],
  NULL,
  'Say no to any other questions or symptoms asked outside of the details already provided.',
  ARRAY[
    'Ask about the onset of the rash.',
    'Ask about the location of the rash and whether it has spread or changed over time.',
    'Ask the patient to describe the rash — whether it is raised, bumpy, flat, or blistering.',
    'Ask if the rash is getting worse, staying the same, or improving over time.',
    'Ask whether the rash is itchy, painful, or both.',
    'Ask about any possible triggers, such as food, stress, new fabrics, insect bites, or medications.',
    'Ask if there has been any recent change in environment, such as a new home, job, skincare product, or laundry detergent.',
    'Ask if she has experienced a similar rash before.',
    'Ask if she has started any new medications recently, including over-the-counter preparations or supplements.',
    'Ask if the rash appears minutes or hours after taking medications such as ibuprofen or codeine.',
    'Ask about any known allergies.',
    'Ask about any family history of allergic skin conditions, such as eczema, urticaria, hay fever, or asthma.',
    'Screen for red flag features of anaphylaxis, including lip or tongue swelling, difficulty breathing, or wheeze.',
    'Ask about smoking, alcohol use, and the impact of the rash on daily life and wellbeing.',
    'Give a working diagnosis of urticaria.'
  ],
  ARRAY[
    'No need for a face-to-face assessment at present as the patient is not currently experiencing the rash.',
    'Advise the patient to send a photo of the rash if she has one from a previous episode, or to take and send a photo if the rash occurs again.',
    'Recommend keeping a symptom diary for 2–4 weeks to help identify any potential triggers such as food, stress, environmental factors, or skincare products.',
    'Advise the patient to stop ibuprofen and codeine, as both may be triggering the rash, and recommend using paracetamol for pain relief instead. If she is unable to stop both and requires something stronger, codeine may be continued cautiously — but if the rash recurs after taking it, she should stop it as well.',
    'Safety net: Advise the patient to seek urgent medical attention by dialling 999 if she experiences signs of anaphylaxis, such as swelling of the lips or tongue, difficulty breathing, wheezing, or feeling faint.'
  ],
  'Thank you for getting in touch about this, and I''m glad you called. A rash that keeps coming and going like this is absolutely worth looking into, and from what you''ve described — a red, raised, itchy rash on your neck and arms that flares for a day or two and then settles — this fits a pattern that we call urticaria, which is sometimes referred to as hives. It''s actually a very common condition, and while it can feel uncomfortable and unsettling when it keeps recurring, it''s not something dangerous in itself.

Urticaria occurs when cells in the skin release a substance called histamine, which causes the characteristic raised, itchy welts. In many cases, there is a trigger involved, and working out what that trigger is can make a real difference in managing and preventing future episodes. That''s why I would like us to approach this in a structured way.

One of the things I want to look at carefully is your medication. Both ibuprofen and codeine are recognised triggers for urticaria in some people, and given that you have been experiencing these flares over the past couple of months, it is worth trialling a period without either of those to see whether that makes a difference. I would recommend switching to paracetamol for pain relief in the meantime, as this is much less likely to cause a reaction. If you find you really do need something stronger and continue codeine, please keep a note of whether the rash appears in the hours after taking it — and if it does, stop it and let us know.

I would also like you to start keeping a simple symptom diary over the next two to four weeks. It doesn''t need to be complicated — just jotting down when the rash appears, what you had eaten in the hours before, any products you had used on your skin, any stress or changes in routine, and whether you had taken any medications. That kind of information can really help us spot patterns.

If you have any photographs from previous episodes, please do send those through — and if it comes on again before we next speak, take a photo as soon as you can, as that will help me get a clearer picture of what we are dealing with.

The most important safety point I want to leave you with is this: if at any point you develop swelling of your lips or tongue, difficulty breathing, wheezing, or feel faint or dizzy at the same time as the rash, please call 999 immediately, as those would be signs of a more serious allergic reaction called anaphylaxis that needs emergency treatment. As long as it remains a skin rash with no other symptoms, there is no immediate cause for alarm, but please do not hesitate to contact us if things change or worsen.',
  ARRAY[
    'Recurring urticaria (hives) presenting as transient raised itchy welts lasting one to two days is a common presentation in general practice; common triggers include NSAIDs (e.g. ibuprofen), opioids (e.g. codeine), food, and environmental factors.',
    'Ibuprofen and codeine are recognised pharmacological triggers for urticaria and should be stopped if suspected; paracetamol is a safe alternative for pain relief.',
    'A symptom diary kept over 2–4 weeks is a useful tool for identifying individual triggers in recurrent urticaria.',
    'Urticaria does not require face-to-face assessment when the rash is not present at the time of the consultation; a photograph of the rash during a flare is helpful for clinical assessment.',
    'Safety-netting must include clear advice to call 999 for signs of anaphylaxis: lip or tongue swelling, difficulty breathing, wheeze, or feeling faint alongside the rash.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  70,
  'Abnormal Thyroid Function Test',
  'Endocrine & Nephrology',
  'Video Consultation',
  false,
  'Meera Sharma',
  '33-year-old female',
  ARRAY['Nil'],
  ARRAY['Not on any medications','No known drug allergy'],
  'Seen 4 days ago by Dr. Aisha Patel (General Practitioner). Presenting complaints: Palpitations, sweating, weight loss (5 kg in 2 months), and amenorrhoea for 3 months. Examination findings: Tremor, heart rate 98 bpm, BP 128/78 mmHg. Impression: Suspected thyroid disorder. Plan: Arrange blood tests and follow-up with results. Blood Test Results — Thyroid Stimulating Hormone (TSH): <0.01 mU/L (Normal range: 0.4–4.0 mU/L); Free T4: 26 pmol/L (Normal range: 9–20 pmol/L); Free T3: 6.5 pmol/L (Normal range: 3.5–6.0 pmol/L); Full Blood Count: Normal; Electrolytes: Normal; Bone profile: Normal; CRP: Normal; Ferritin, Folate, B12: Normal; FSH, LH, Testosterone and androgen index: Normal. Patient booked a video consultation to discuss blood test results.',
  'Patient attending video follow-up to discuss recent blood test results after presenting with palpitations, sweating, weight loss, and absent periods.',
  'Hello, thank you for seeing me again. I''ve been quite nervous about what these results might show — I''ve been feeling really unwell over the past few months.',
  'You are Meera, a 33-year-old woman attending a video follow-up to discuss recent blood test results. Four days ago you saw a GP because you had been experiencing palpitations, night sweats, unexplained weight loss, and no periods for the past three months. If asked: palpitations occur daily, especially when at rest; sweating is noticeable and worse at night; weight loss has been unintentional despite a normal appetite; the absence of periods is distressing because you recently got married and are hoping to start a family soon.',
  ARRAY[]::text[],
  'You recently got married and work as a secondary school science teacher. You do not smoke and drink only occasionally at social events. You do Pilates twice a week and report no significant stress aside from your current health concerns.',
  'You think it might be due to a hormonal imbalance — possibly something like PCOS.',
  'You are especially worried about the weight loss and missed periods, and how this might affect your chances of conceiving.',
  'You are hoping for a clear explanation of your symptoms and some treatment options to help restore hormonal balance and support your goal of starting a family.',
  ARRAY[]::text[],
  NULL,
  'Say no to any other questions asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY[
    'Acknowledge that the patient was reviewed by a colleague with symptoms of palpitations, sweating, weight loss, and menstrual irregularities, and was sent for blood tests.',
    'Ask whether her symptoms have worsened since the last consultation, then proceed with a structured head-to-toe review for hyperthyroidism.',
    'Ask about eye symptoms, including blurry vision, excessive tearing, or light sensitivity (photophobia).',
    'Ask about any neck swelling or visible enlargement of the thyroid gland.',
    'If neck swelling is present, ask about compression symptoms: difficulty breathing, hoarse voice, trouble swallowing (dysphagia), or a feeling of pressure in the neck.',
    'Ask about the palpitations — when they occur, how long they last, and whether they are getting worse.',
    'Ask about the presence of hand tremors and when they are most noticeable (e.g. at rest or during activity).',
    'Ask whether she feels hot when others are cold, suggestive of heat intolerance.',
    'Ask about any fever, which may suggest thyrotoxicosis.',
    'Ask about fatigue or tiredness.',
    'Ask about bowel symptoms, particularly diarrhoea.',
    'Ask about menstrual irregularities, including the current amenorrhoea.',
    'Ask about mood changes, irritability, or difficulty sleeping.',
    'Ask how the symptoms are affecting her daily life, including work and social function.',
    'Ask about social history, including work, home, and lifestyle.',
    'Ask whether she is on contraception or actively trying to conceive.',
    'Explore ICE — ideas, concerns, and expectations.',
    'Give a working diagnosis of hyperthyroidism.'
  ],
  ARRAY[
    'Offer propranolol (if no contraindications) to help relieve adrenergic symptoms such as palpitations, tremor, and agitation.',
    'Offer an ECG, especially in patients with cardiovascular symptoms such as palpitations, chest discomfort, dizziness, or shortness of breath, to screen for atrial fibrillation, a recognised complication of hyperthyroidism.',
    'Refer to endocrinology, as per NICE guidance, for all patients with newly diagnosed hyperthyroidism.',
    'Explain that you will liaise with endocrinology regarding starting carbimazole, a medication used to treat overactive thyroid.',
    'Counsel on carbimazole side effects: agranulocytosis — advise the patient to seek urgent medical advice if they develop a sore throat, fever, or flu-like symptoms, as this may indicate a drop in white blood cells. Pancreatitis — advise reporting any new or unexplained abdominal pain immediately.',
    'If eye symptoms (e.g. visual changes, discomfort, proptosis) are present, refer same day to ophthalmology.',
    'Arrange a repeat TSH and thyroid function test in 6 weeks, then every 3 months until stable.',
    'Advise the patient not to conceive until thyroid levels are stabilised (euthyroid), due to increased risks of miscarriage and fetal abnormalities.',
    'Recommend condoms as interim contraception, then offer a follow-up consultation to discuss more reliable contraceptive options.',
    'Refer to endocrinology not only for diagnosis but also to help with pre-pregnancy planning and ongoing management.',
    'Safety net: Advise the patient to seek urgent medical advice if they develop worsening symptoms such as chest pain, shortness of breath, severe palpitations, or signs of thyroid eye disease.'
  ],
  'Thank you so much for coming back to speak with me today, Meera, and I can imagine it has been quite an anxious wait for these results. Let me go through what we have found and explain what I think is going on. Having looked at your blood tests, they show that your thyroid gland is overactive — this is a condition called hyperthyroidism. Your TSH level, which is the pituitary hormone that signals the thyroid, came back very low at less than 0.01 mU/L, when the normal range is 0.4 to 4.0 mU/L. At the same time, your thyroid hormone levels — Free T4 at 26 pmol/L and Free T3 at 6.5 pmol/L — are both above their normal ranges. Taken together, this confirms that your thyroid is producing too much hormone.

The thyroid is a small butterfly-shaped gland at the front of your neck, and its job is to regulate your body''s energy use and many of its core functions. When it goes into overdrive, it creates exactly the picture you have been experiencing — a racing heart, unintentional weight loss despite eating normally, night sweats, and changes to your periods. It can also cause tremor, irritability, and a feeling of being unable to switch off. So in a sense, we now have a clear explanation for everything that has been troubling you, which I hope is at least some relief.

The good news is that this condition is very treatable. I would like to start you on a medication called propranolol relatively soon — this is a beta-blocker that helps to calm down some of the most uncomfortable symptoms like the palpitations and tremor while we work on the underlying thyroid issue. I would also like to arrange an ECG — a heart tracing — just to make sure the heart rhythm is normal, as an overactive thyroid can occasionally cause an irregular heartbeat.

I will be referring you to the endocrinology team — specialist hormone doctors — who will oversee your ongoing treatment. They are very likely to recommend starting a medication called carbimazole, which works by reducing the amount of thyroid hormone your body produces. There are two important things to know about carbimazole. First, in rare cases, it can reduce the white blood cells that help fight infection — so if at any point you develop a fever, sore throat, or feel like you are coming down with something while taking it, please contact us the same day rather than waiting. Second, in very rare cases it can affect the pancreas, so any unexplained abdominal pain should also be reported promptly.

I want to speak carefully about your plans to start a family, because I know that is close to your heart. While your thyroid is overactive and not yet controlled, it would be safer to avoid conceiving, as untreated hyperthyroidism can significantly increase the risks of miscarriage and problems with the baby''s development. Once your thyroid levels are back within the normal range and stable, those risks reduce considerably and we can have a much more positive conversation about pregnancy planning. In the meantime, I would suggest using condoms as a reliable and simple form of contraception, and I am very happy to arrange a separate appointment to talk through other options that might suit you better.

We will plan to recheck your thyroid function in around six weeks, and then every three months until things are stable. The endocrinology team will guide that process and will also be well placed to support your pre-pregnancy planning when the time is right. Please do not hesitate to get in touch at any point if your symptoms worsen significantly — particularly if you develop severe palpitations, chest pain, breathlessness, or any changes to your vision.',
  ARRAY[
    'Hyperthyroidism is confirmed by a suppressed TSH (<0.01 mU/L) alongside elevated Free T4 (>20 pmol/L) and elevated Free T3 (>6.0 pmol/L); all newly diagnosed cases should be referred to endocrinology per NICE guidance.',
    'Propranolol can be used early to manage adrenergic symptoms such as palpitations, tremor, and agitation while awaiting specialist review.',
    'Carbimazole is the main antithyroid drug used in the UK; key side effects to counsel on include agranulocytosis (urgent review for fever, sore throat) and pancreatitis (urgent review for unexplained abdominal pain).',
    'An ECG should be offered in patients with palpitations to screen for atrial fibrillation, a recognised complication of hyperthyroidism.',
    'Women of reproductive age with untreated hyperthyroidism should be advised to delay conception until euthyroid, as poorly controlled hyperthyroidism increases the risk of miscarriage, preterm birth, fetal growth restriction, and congenital abnormalities.',
    'Thyroid eye disease (proptosis, visual changes) requires same-day ophthalmology referral if present.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  71,
  'Chronic Cough in an Older Adult',
  'Respiratory',
  'Telephone Consultation',
  false,
  'Vera Hartley',
  '82-year-old female',
  ARRAY['Frailty','Learning disability','Hypertension (diagnosed 10 years ago)','Hypercholesterolaemia'],
  ARRAY['Ramipril 10 mg once daily','Amlodipine 5 mg once daily','No known drug allergy'],
  'Seen 2 months ago by Dr. Nina Osei (General Practitioner) — visit at nursing home. Presenting complaint: Nursing staff reported a persistent cough for 4 weeks with no red flags. Examination findings: Chest clear, BP 120/62 mmHg, Pulse 65 bpm, RR 18 cpm, SpO2 98% on air. Plan: As cough is persistent, treat with oral antibiotics; chest X-ray arranged. Chest X-Ray Report — Patient: Mrs Vera Hartley | Date: 2 months ago. Findings: Lungs are clear with no evidence of consolidation, mass, or pleural effusion. Cardiothoracic ratio within normal limits. No signs of pulmonary fibrosis or interstitial lung disease. No bony abnormalities detected. Conclusion: No acute abnormalities identified. Reported by: Mr Marcus Webb, Advanced Reporting Radiographer.',
  'A paramedic practitioner from the GP surgery is calling to discuss concerns about a care home patient with a persistent cough that has not resolved despite antibiotics and a normal chest X-ray.',
  'Hi Doctor, this is Tom — I''m one of the paramedic practitioners based at the surgery. I''m calling about one of our care home patients, Mrs Vera Hartley, and was hoping to get your advice if that''s alright?',
  'Mrs Hartley has had a persistent dry cough for 3 months. About 2 months ago she was reviewed by Dr. Nina Osei, who ordered a chest X-ray and prescribed oral antibiotics for suspected infection. Mrs Hartley completed the course, the chest X-ray came back normal, but the cough has persisted. Care staff have noticed the cough is worse after meals and more troublesome at night. There has been no improvement with the antibiotics.',
  ARRAY[
    'She has no history of smoking but has a background of reflux and occasionally uses Gaviscon to manage symptoms.',
    'The care staff are concerned about the impact of the cough on her quality of life, especially at night as it is disrupting her sleep. There is no reported fever, chest pain, or significant shortness of breath. Oral intake remains adequate, but staff have noticed she occasionally clears her throat after swallowing. No weight loss or haemoptysis.',
    'On examination: chest remains clear, BP 135/89 mmHg, Pulse 75 bpm, SpO2 97% on air, respiratory rate 17 cpm.',
    'SAY NO TO ANY OTHER SYMPTOMS ASKED.'
  ],
  '',
  'You suspect the cough might be related to her long-term use of Ramipril.',
  'Both the nursing team, the patient, and yourself are concerned about the ongoing cough and how it is disrupting her sleep and affecting her quality of life.',
  'You are hoping for guidance on whether trialling a change in medication or other treatment may help.',
  ARRAY[]::text[],
  NULL,
  'Say no to any other symptoms asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY[
    'Begin by thanking the paramedic practitioner for reviewing the patient at the care home.',
    'Ask about the onset and duration of the cough.',
    'Ask whether the cough is productive or dry.',
    'If the cough is productive, ask about the presence of haemoptysis.',
    'Ask if there has been any wheeze reported or heard on examination.',
    'Ask whether the patient has experienced any associated symptoms such as fever, shortness of breath, chest pain, or palpitations.',
    'Ask if there are any precipitating or aggravating factors.',
    'Ask whether the symptoms are worse at night (reflux cough tends to be worse at night and after meals).',
    'Ask about any symptoms of postnasal drip, including blocked or runny nose, or the sensation of mucus at the back of the throat.',
    'Ask specifically about reflux symptoms, such as heartburn or a sour taste in the mouth.',
    'Ask whether the patient has experienced hoarseness of voice.',
    'Screen for red flag features suggestive of malignancy, such as unexplained weight loss, night sweats, fatigue, or loss of appetite.',
    'Ask whether the patient currently smokes or has ever smoked.',
    'Give a working diagnosis of reflux-related cough.'
  ],
  ARRAY[
    'Advise a trial of omeprazole 20 mg once daily for 2 weeks to treat suspected reflux-related cough.',
    'Advise that nursing staff should be informed of lifestyle measures to help manage reflux symptoms, including offering smaller but more frequent meals; avoiding lying the patient flat after eating; slightly elevating the head of the bed at night; and avoiding known food triggers such as spicy meals if identified.',
    'Arrange a follow-up review after 2 weeks — this can be carried out either by the GP or by the paramedic practitioner if appropriate and agreeable.',
    'If symptoms persist despite PPI treatment, consider withdrawing ramipril, which is known to cause a dry cough, and switching to an alternative antihypertensive.',
    'Safety net: Ask the paramedic to inform care staff that if symptoms worsen, or if the patient develops new symptoms such as haemoptysis, shortness of breath, chest pain, or significant weight loss, they should contact the GP promptly for reassessment.'
  ],
  'Thank you very much, Tom, for assessing Mrs Hartley and giving such a clear and thorough handover — that is really helpful. You have painted a good picture of what''s been going on, and I think between your assessment and the information from the care home staff, we have some useful clinical leads to work with.

From what you have described — a persistent dry cough that is notably worse after meals and at night, set against a background of known reflux and normal chest X-ray findings — the most likely explanation here is a reflux-related cough, sometimes called a gastro-oesophageal reflux cough. The pattern of worsening after eating and at night is very characteristic, and the normal chest X-ray reassuringly rules out consolidation, malignancy, and other structural causes.

You were also right to flag Ramipril as a possible contributor — it is a well-known cause of a dry persistent cough in a proportion of patients who take it, and it is definitely worth keeping in mind. That said, I would suggest we take a stepwise approach. Before switching her antihypertensives, it makes good clinical sense to first trial a proton pump inhibitor and see whether that makes a difference, since the reflux history is quite prominent and the aggravating factors fit so well. I would recommend starting omeprazole 20 mg once daily for two weeks as a therapeutic trial.

Alongside that, it would be helpful if the care home team could implement some straightforward lifestyle measures to minimise reflux: offering Mrs Hartley smaller, more frequent meals rather than large portions; keeping her upright for at least thirty minutes after eating rather than lying her flat; and slightly raising the head of her bed at night. These can make a meaningful difference, particularly in someone who is mostly chair- or bed-bound.

Would you be happy to review her again in two weeks, Tom, to see whether the omeprazole has had any effect? If there is no improvement despite the PPI, that would be the point to revisit the Ramipril — and I would be very happy to discuss switching her to an alternative antihypertensive at that stage.

In the meantime, please do ask the care home staff to contact us promptly if anything changes — particularly if Mrs Hartley develops any haemoptysis, breathlessness, chest pain, or unexplained weight loss. Those would prompt us to escalate our investigations and review the plan sooner. Thank you again for managing this so well.',
  ARRAY[
    'Chronic cough in an older care home resident that is worse after meals and at night, with a background of reflux and a normal chest X-ray, should raise strong suspicion for gastro-oesophageal reflux-related cough.',
    'A stepwise approach is appropriate: trial omeprazole 20 mg once daily for 2 weeks before withdrawing Ramipril, as both reflux and ACE inhibitor use are plausible and treatable causes.',
    'Ramipril and other ACE inhibitors are a well-recognised cause of chronic dry cough; if a PPI trial fails to resolve the cough, switching to an angiotensin receptor blocker (ARB) is a reasonable next step.',
    'Lifestyle advice for reflux-related cough in care home residents includes smaller, more frequent meals; remaining upright after eating; and head-of-bed elevation at night.',
    'Collaborative working with allied healthcare professionals such as paramedic practitioners should be acknowledged and encouraged, with clear shared decision-making on the management plan.',
    'Safety-netting must include prompt GP review for haemoptysis, significant weight loss, breathlessness, or chest pain, which would warrant escalation of investigation.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  72,
  'Suspected Lyme Disease',
  'Travel Health & Infectious Disease',
  'Telephone Consultation',
  false,
  'Laura Simmons',
  '36-year-old female',
  ARRAY['Childhood eczema'],
  ARRAY['Not on any current medication','No known drug allergy'],
  NULL,
  'Patient has sent in a photograph of a rash on her hands and has booked an urgent telephone appointment to discuss her concerns.',
  'Hi, I''ve sent in a photo of this rash I''ve developed on my hands. I''m a bit worried it might be linked to a tick bite I had recently while I was away.',
  'You are Laura, a 36-year-old woman. You first noticed the rash two days ago, around a week after returning from a camping trip. You recall being bitten by a tick during the trip and are worried the rash may be related to Lyme disease, particularly as it seems to be spreading and is present on both hands. The rash is itchy, red, and scaly. You have not used any new soaps, detergents, fabrics, or skincare products recently. There is no other rash elsewhere on your body, and you have no additional symptoms such as fever, joint pain, headache, fatigue, or flu-like illness. You have a history of childhood eczema but have been free of any significant skin problems in recent years.',
  ARRAY[]::text[],
  'You work as an interior designer, mostly from a home studio. You have not recently travelled to areas known for Lyme disease outbreaks, other than the camping trip. You are a non-smoker and do not drink alcohol. You got married earlier this year and are hoping to start a family in the next couple of years.',
  'You are concerned this rash could be Lyme disease given the timing and the tick bite you noticed during the camping trip.',
  'You are worried that if it is Lyme disease it could become serious if left untreated, having read about it online.',
  'You would like the GP to confirm whether this is Lyme disease and, if so, to start antibiotics promptly. You are due to travel to Portugal tomorrow and would like to know whether it is safe to travel with this rash, or whether you should delay your trip.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Ask about the onset of the rash.',
    'Ask about the location of the rash — for example: "Thanks for sending the photo. Is the rash just on the hand shown, or is it affecting both hands or any other areas of your body?"',
    'Ask whether the rash is getting worse, improving, or staying the same.',
    'Ask if the rash is itchy or painful.',
    'Ask if the rash is scaly, cracked, or weeping.',
    'Ask whether the patient has noticed a bull''s-eye or expanding circular pattern typical of early Lyme disease.',
    'Ask how many ticks were noticed and whether they were attached for a prolonged period, and whether the tick was removed fully.',
    'Ask about any systemic symptoms that could suggest Lyme disease, such as fever, muscle or joint aches, headache, numbness or tingling, fatigue, or changes in vision.',
    'Acknowledge her history of childhood eczema and ask when she last had a flare-up, and whether this current rash feels or looks different from her usual eczema.',
    'Ask about any recent environmental changes — new job, stress, new skincare products, laundry detergents, or changes in living environment.',
    'Explore ICE — ideas, concerns, and expectations.',
    'Ask about smoking, alcohol intake, and how the rash is affecting daily life.',
    'Give a working diagnosis of likely hand dermatitis or eczema, with Lyme disease less likely based on history and clinical features.'
  ],
  ARRAY[
    'Reassure the patient that based on the current appearance, distribution, and absence of systemic symptoms, Lyme disease is unlikely.',
    'Offer emollients and a topical corticosteroid, such as a moderate potency steroid like Eumovate (clobetasone butyrate 0.05%) or a potent steroid such as Elocon (mometasone furoate 0.1%), to treat likely hand eczema.',
    'Advise keeping a symptom diary to help identify any potential triggers, including new products, materials, or environmental exposures.',
    'Reassure the patient that it is safe to proceed with her travel plans but recommend arranging travel health insurance in case any issues arise while she is away, so that she can access medical care if needed.',
    'Arrange a follow-up in 2–3 weeks to review progress and response to treatment.',
    'Safety net: Advise the patient to recontact the surgery sooner if symptoms worsen or if she develops new systemic symptoms such as fever, generalised body aches, fatigue, or joint pain, at which point blood tests and further investigations for Lyme disease may be considered.'
  ],
  'Thank you for sending in the photograph and for getting in touch so promptly, Laura — I can completely understand why the timing of this rash has made you think about Lyme disease, especially with the tick bite so fresh in your mind. That was absolutely the right thing to flag, and I want to take you through my thinking carefully.

Having looked at the photo and listened to everything you have described — a red, itchy, scaly rash affecting both hands, developing around a week after your camping trip — I think this is more likely to be a flare of hand eczema or contact dermatitis, rather than Lyme disease. I know that might feel surprising given the timing, but let me explain why I think that.

Lyme disease does cause a rash, but it tends to look quite different from what you have described. The classic Lyme rash — called erythema migrans — usually appears as a single, expanding, round or oval patch that may have a bull''s-eye pattern, and it typically develops at or near the site of the tick bite rather than across both hands symmetrically. It is also usually accompanied by feeling quite unwell — things like fatigue, muscle aches, joint pain, headache, or a fever. Because you have not had any of those symptoms and the rash is on both hands in a pattern more consistent with skin irritation, Lyme disease is much less likely in your case. That is genuinely reassuring.

Your history of childhood eczema is actually quite relevant here. Eczema can remain dormant for many years and then flare up again, particularly following environmental exposures — things like certain materials during camping, cold air, repeated hand washing, or even the stress of travel can all be enough to trigger it. The scaly, itchy quality you are describing on both hands fits this picture very well.

To help settle the rash, I would like to recommend a topical steroid cream. A good starting option is Eumovate — clobetasone butyrate 0.05% — which is a moderate-strength steroid that can help calm the inflammation. I would also suggest using a gentle, fragrance-free moisturiser regularly to protect the skin barrier. If the rash is quite severe, we might consider stepping up to a more potent steroid such as Elocon — mometasone furoate 0.1% — but let''s see how you respond first.

It would also be worth jotting down anything you notice seems to trigger or worsen the rash — soaps, detergents, fabrics, or environmental factors — as identifying triggers is one of the most useful things you can do for long-term management.

Regarding your plans to travel to Portugal tomorrow — from everything you have told me, I see no reason why this rash should stop you going. You are feeling otherwise well, and this is a manageable skin condition rather than anything that warrants delaying your trip. I would just strongly recommend getting travel health insurance before you go, so that if the rash spreads or you start to feel unwell while you are away, you can access medical care without any difficulty.

We will catch up when you are back — aim for two to three weeks'' time — to see how the skin is responding. In the meantime, if you develop a fever, joint or muscle aches, generalised fatigue, or the rash spreads beyond your hands or changes significantly in appearance, please do contact us promptly, as at that point we would want to do blood tests to check for Lyme disease and other causes.',
  ARRAY[
    'The classic Lyme disease rash (erythema migrans) presents as a single expanding round or oval patch, often with a bull''s-eye pattern, at or near the tick bite site — a bilateral symmetric scaly rash on both hands is not consistent with this pattern.',
    'Hand eczema or contact dermatitis is the more likely diagnosis when the rash is itchy, scaly, bilateral, and in the absence of systemic symptoms (fever, fatigue, myalgia, arthralgia), particularly in a patient with a background of eczema.',
    'Treatment of hand eczema: start with a moderate potency steroid such as Eumovate (clobetasone butyrate 0.05%) or a potent steroid such as Elocon (mometasone furoate 0.1%) combined with regular emollients; the Primary Care Dermatology Society recommends initiating with a potent or very potent steroid for more effective control.',
    'A symptom diary to identify environmental or contact triggers is valuable in recurrent or persistent hand eczema.',
    'Travel fitness: a localised skin rash without systemic features does not preclude travel; recommend travel health insurance as a safety measure.',
    'Safety-netting: if systemic symptoms develop (fever, joint pain, fatigue, spreading rash) after a tick bite, blood tests for Lyme disease should be arranged promptly, as early treatment with appropriate antibiotics is effective.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  73,
  'Poor Pain Control in Palliative Patient',
  'Elderly Medicine & Palliative Care',
  'Telephone Consultation',
  false,
  'George Ashworth',
  '77-year-old male',
  ARRAY['Hypertension','Hyperlipidaemia','Chronic Kidney Disease (CKD, Stage 3A)','Metastatic Prostate Cancer – for palliative','Has DNACPR in place'],
  ARRAY['Ramipril 5 mg OD','Atorvastatin 20 mg OD','Butec (Buprenorphine) 10 µg/hour Transdermal Patch: Apply one patch every 7 days','Paracetamol 1g QDS PRN','No known drug allergies QOF and alerts!!: Has no advance care plan in place'],
  'Recent notes from oncology Subject: Discharge Summary for Mr. George Ashworth Dear GP, As you may know, Mr. George Ashworth, aged 77, has been under our care for metastatic prostate cancer with bone involvement. He suffers significant chronic pain, particularly in his lower back and hips. He has been started on a Butec 10 µg/hour transdermal patch, to apply one patch every 7 days. Additionally, he remains on paracetamol as needed. If issues arise with the patch not adhering to the skin, we have advised the use of micropore tape to help secure it. Mr. Ashworth has been counselled regarding the advanced nature of his disease and his prognosis, including the limited time he has remaining. He is aware of the focus on symptom management and maintaining quality of life. He has now been discharged to the community for palliative management. Yours sincerely, Dr A. Narayanan, Consultant Oncologist

District Nurse Review (2 weeks ago)
Routine bloods taken to monitor renal function

Test                    Result              Reference Range
Serum Creatinine        103 µmol/L          64–104 µmol/L (male)
eGFR                    54 mL/min/1.73m²    >90 mL/min/1.73m²
Urea                    12 mmol/L           2.5–7.8 mmol/L
Potassium               4.8 mmol/L          3.5–5.1 mmol/L
Sodium                  138 mmol/L          135–145 mmol/L
Albumin                 35 g/L              35–50 g/L
Calcium (Corrected)     2.25 mmol/L         2.2–2.6 mmol/L
Phosphate               1.4 mmol/L          0.8–1.5 mmol/L

Patient booked routine telephone consultation to discuss his current concerns.',
  'Patient calling to discuss pain control and concerns about his buprenorphine patch.',
  'Hi doctor, I don''t feel my pain is being managed properly at the moment. The patch keeps coming off after just a couple of days, and I really need something that actually works.',
  '',
  ARRAY[]::text[],
  'George lives with his wife, who acts as his main carer at home. He is retired and enjoys reading historical biographies and watching wildlife programmes on television. He has become less active recently because of the pain. He does not smoke and has not drunk alcohol for many years. He says he is keeping his spirits up as best he can, but the constant pain and disrupted sleep are wearing him down.',
  'He believes the patch is not staying in place because he sweats heavily, and thinks this is why his pain has not been well controlled.',
  'He is particularly concerned that the pain is now disturbing his sleep and making daily life harder to manage.',
  'He would like to explore alternative pain relief options and receive practical guidance on how to better manage his symptoms going forward.',
  ARRAY['If the doctor offers a new tablet for pain relief, ask whether you should start taking it straight away or wait, given that you still have the patch on. A good way to ask: "Should I begin the tablets as soon as you prescribe them, or do I need to wait since the patch is still on?"'],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor.',
  ARRAY['Ask about the pain – its nature (burning, dull, throbbing), whether it radiates, and any relieving or aggravating factors','Ask whether the pain is worsening, improving, or staying the same','Ask about red flag symptoms for spinal cord compression – leg weakness, difficulty walking, numbness or tingling in the legs, inability to control the bladder or bowel, or numbness around the back passage','Ask how the pain is affecting his quality of life and sleep','Ask whether he is using the Butec patch as prescribed and confirm correct application technique (dry, non-irritated, hairless skin, rotating sites)','Ask whether the excessive sweating is a new symptom or something long-standing – to decide if further investigation is needed now or can wait','Ask if micropore tape has been tried as advised by the oncology team – for example: "I can see from your notes that the cancer specialist suggested using micropore tape to help keep the patch in place – have you been able to try that?"','Ask if he is eating and drinking well and whether he has any difficulty swallowing','Ask if he is passing urine and opening his bowels regularly, and check for constipation as a side effect of opioids','Ask how he is coping emotionally and whether he has been feeling low or anxious','Ask about his home situation and whether he has adequate support','Make a working diagnosis of uncontrolled pain due to buprenorphine patch displacement caused by long-standing excessive sweating'],
  ARRAY['Advise discontinuation of the buprenorphine patch and offer oral morphine for pain control','Inform the patient that you will calculate the appropriate dose conversion from buprenorphine to morphine to ensure adequate pain relief. Explain that a regular dose will be prescribed along with additional doses for breakthrough pain, and that the exact dosing will be clearly communicated to him','Advise the patient to wait 24 hours after removing the buprenorphine patch before taking the first dose of morphine. In the meantime, offer paracetamol for pain relief','If paracetamol alone is insufficient, offer a combination of paracetamol with a low dose opioid such as co-codamol 8/500 mg or 15/500 mg','Counsel the patient on common side effects of morphine, including drowsiness, nausea, and constipation','Prescribe an anti-emetic such as metoclopramide to be taken as required for nausea or vomiting','Prescribe a stimulant laxative such as senna 7.5 to 15 mg once daily or bisacodyl 5 to 10 mg once daily, alongside a stool softener such as Movicol, for example two sachets daily, to prevent opioid-induced constipation','Offer a follow-up telephone consultation or home visit to discuss advance care planning. Explain that this allows documentation of his wishes and preferences for future care, including decisions around resuscitation and care if he becomes unable to make decisions','Provide the patient with the local palliative care emergency contact number so he can access support from the district nurse or GP if symptoms worsen or concerns arise','Arrange review in two weeks to assess symptom control and tolerance of the new medication','Provide safety net advice to seek urgent medical attention if symptoms suggestive of spinal cord compression develop, such as new or worsening back pain, leg weakness, numbness, or difficulty controlling bladder or bowel function'],
  'Thank you so much for calling today, George. It''s clear that this period has been really difficult, especially when you''re trying to manage your pain day to day and struggling to get a good night''s sleep. I completely understand why this has been worrying and frustrating for you, and I want to make sure we come up with a much better plan today.

From what you''ve described, it sounds very much as though the buprenorphine patch is not staying in place long enough to provide consistent pain relief. Heavy sweating can prevent the patch from adhering properly to the skin, which means the medication may not be getting through at the level you need. Even with the micropore tape, if moisture is building up underneath, the drug delivery is likely being disrupted.

What I''d like to do is stop the patch altogether and switch you to oral morphine instead. Morphine is a very effective painkiller taken by mouth, and it avoids the issue of adhesion entirely. We will carefully work out the right starting dose based on the buprenorphine you have been taking, and we will prescribe both a regular dose and an extra dose you can take if your pain flares up between regular doses. The dose will be communicated clearly to you and to your district nurse.

Because the patch is still releasing medication into your system, I would ask you to remove it and then wait 24 hours before taking your first morphine tablet. This is to make sure the two medications do not overlap and cause unwanted effects. In the meantime, you can use paracetamol for some relief, and if that is not quite enough, co-codamol 15/500 mg up to four times a day is a safe option to bridge the gap.

Morphine can sometimes cause side effects, and I want to be upfront about those. The most common ones are constipation, nausea, and some drowsiness, especially in the first few days. To get ahead of this, I will prescribe a laxative – something like bisacodyl 5 to 10 mg once a day combined with Movicol sachets to keep things moving – as well as an anti-sickness tablet such as metoclopramide to take if you feel queasy.

I would also like to arrange a telephone call or home visit in the near future to talk through something called advance care planning. I want to be clear that there is absolutely no pressure – this is simply a way of making sure your wishes and preferences are recorded, so that if your situation changes and you are not able to speak for yourself, the people caring for you know exactly what you would want. We can do this at whatever pace feels right for you.

I will make sure you have the palliative care contact number so you or your wife can reach the district nursing team or our surgery at any point if something concerns you. We will also review how you are getting on with the morphine in about two weeks.

One important thing to watch out for: if you develop new or worsening back pain, weakness or numbness in your legs, or any difficulty controlling your bladder or bowels, please do not wait – seek urgent medical attention straight away, as these symptoms can occasionally indicate a complication called spinal cord compression that needs immediate assessment.',
  ARRAY['Poor adhesion of transdermal opioid patches in patients who sweat heavily is a practical and clinically significant problem – switching to an oral preparation such as morphine is appropriate when patch delivery is unreliable','When stopping buprenorphine patches and starting oral morphine, advise a 24-hour gap between patch removal and the first morphine dose to avoid opioid overlap and toxicity','Prescribe laxatives prophylactically whenever starting opioids – a stimulant such as senna 7.5–15 mg or bisacodyl 5–10 mg once daily combined with a stool softener such as Movicol is a standard regimen','Morphine should be used with caution in renal impairment and avoided when eGFR falls below 30; buprenorphine and fentanyl are safer alternatives in significant renal impairment','Advance care planning should be offered proactively in palliative patients, particularly where a DNACPR is already in place but no formal care plan exists','Always safety-net for signs of spinal cord compression in patients with metastatic bone disease – new back pain, leg weakness, numbness, or loss of bladder/bowel control require urgent assessment'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  74,
  'Chronic Cough in a Gypsy Traveller',
  'Respiratory',
  'Telephone Consultation',
  false,
  'Patrick Flynn',
  '52-year-old male',
  ARRAY['No known medical condition','Temporary registered at the practice'],
  ARRAY['Not currently on any medication','No Known Drug Allergy'],
  NULL,
  'Patient calling with concerns about a persistent cough and feeling generally unwell.',
  'Hi doctor, I''ve had this cough for about 6 weeks now and I just don''t feel right. I thought I should call and see if I need antibiotics.',
  '',
  ARRAY[]::text[],
  'Patrick smokes 20 cigarettes a day and has done so for the past 30 years. He is currently staying in the area with a friend in his caravan. He is a traveller and is planning to leave the area today, and is not sure exactly where he will end up, as he moves around with his friend.',
  'He thinks it is probably a chest infection that needs antibiotics to clear up.',
  'He is worried that it could get worse if left untreated.',
  'He is hoping to be prescribed antibiotics to deal with the cough.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Refuse to attend a face-to-face appointment if offered – explain that you are travelling out of the area today and cannot come in. Only accept a follow-up phone call in 2–3 days once you have arrived somewhere new. You can also agree to phone the surgery to let them know your new whereabouts. Request antibiotics. If the doctor does not prescribe them, politely ask why.',
  ARRAY['Ask about the onset of the cough and how long it has been present','Ask if the cough is productive; if so, ask about the colour of the sputum and whether there is any blood in it (haemoptysis)','Ask about associated symptoms – wheeze, fever, shortness of breath, chest pain, or palpitations – to assess for possible chest infection, pneumonia, or pulmonary embolism','Ask about contact with anyone with a similar cough or recent travel outside the UK, to assess the risk of tuberculosis','Ask about flu-like symptoms or post-nasal drip – blocked nose, runny nose, or a feeling of mucus draining down the back of the throat','Ask about reflux symptoms – heartburn or a sour taste in the mouth','Ask about any hoarse voice','Ask about possible precipitating factors, to identify triggers such as allergens, irritants, or exertion','Ask about red flag cancer symptoms – unexplained weight loss, night sweats, reduced appetite, or fatigue','Ask about smoking history','Ask if the patient has any medical problems the practice is not aware of','Give a working diagnosis of possible lung cancer'],
  ARRAY['Offer a face-to-face assessment to examine the patient in person','If the patient declines, explain your concern about possible lung cancer and outline the following options. If the patient knows where he is moving to: advise him to register with a GP in the new area without delay; offer to make a direct 2-week wait (2WW) referral to a respiratory specialist in that area while simultaneously arranging electronic transfer of his medical records to his new GP; advise that his new GP will be informed that the referral has already been made. If the patient does not yet know his new location: offer a follow-up telephone call in 2–3 days to confirm his new whereabouts; emphasise the importance of registering with a GP as soon as he settles; once the new location is known, arrange a direct 2WW referral to a respiratory specialist there; inform the new GP about the referral and arrange electronic transfer of records. Note: a 2WW referral can be made to any hospital in the UK regardless of current location, and medical records are transferred electronically in the UK','Stress that the referral should be treated as urgent given the concerning nature of his symptoms','Offer back-up antibiotics – for example, Amoxicillin 500 mg three times daily for five days – to be used only if symptoms worsen (e.g. if he develops a fever, his cough becomes worse, or he begins to feel unwell)','Offer advice and support on smoking cessation','Provide clear safety netting: advise him to seek urgent medical attention via 111 or A&E if he notices an increase in the amount of blood in his sputum, develops worsening shortness of breath, chest pain, difficulty breathing, or new symptoms such as persistent fever or significant weight loss','Arrange a follow-up telephone call in 2–3 days to confirm he has registered with a local GP and to assist with the referral process if needed'],
  'Thank you for calling today, Patrick. I''m glad you reached out, because what you''ve described needs to be taken seriously, and I want to be honest with you about my concerns.

You''ve had a cough for around six weeks, you''ve noticed some blood in your sputum, and you''ve been feeling unusually tired and think you may have lost some weight. On top of that, you have smoked 20 cigarettes a day for 30 years. Taken all together, these symptoms are concerning enough that I need to consider the possibility of something more serious than a simple chest infection – including, I have to be straightforward with you, the possibility of lung cancer. I want to be clear that I am not saying that is what this is, but it is something we must rule out urgently.

Ideally, I would want to see you face to face today so I could examine your chest and check your pulse, temperature, and oxygen levels. However, I completely understand that you are travelling and cannot come in. So here is what I would like to do instead.

I would like to arrange a follow-up call in two to three days once you have settled somewhere. As soon as I know your new location, I will make an urgent referral – called a two-week wait referral – directly to a chest specialist in that area. This type of referral can be sent to any hospital in the country, so wherever you end up, we can get the ball rolling. I will also arrange for your medical records to be transferred electronically to a new GP near you, so please make sure you register with one as soon as you arrive. If you do not hear from the specialist within two weeks of us making the referral, please chase it up yourself or ask your new GP to help.

Now, I know you were hoping for antibiotics, and I do understand why. The truth is that the most common cause of a prolonged cough is a viral infection, which antibiotics do not help with. However, given that you are leaving the area and cannot easily be reviewed if things deteriorate, I am going to give you a back-up prescription for Amoxicillin 500 mg three times a day for five days. Please only start taking these if you develop a high fever, your cough gets noticeably worse, or you start to feel generally unwell. They are a safety measure, not a first-line treatment.

I also want to take this opportunity to talk about your smoking. I know it can be very difficult to stop, but given everything we have discussed today, this would be one of the most important things you could do for your health. When you are settled again, please speak to your new GP about support to quit.

Please call us in a couple of days and let us know where you are. And if at any point before then you notice more blood in your sputum, you become very short of breath, you develop chest pain, or you feel seriously unwell, please call 111 or go to an A&E department straight away.',
  ARRAY['A persistent cough lasting more than three weeks in a smoker should always prompt consideration of lung cancer as a differential diagnosis, particularly when accompanied by haemoptysis, weight loss, or fatigue','A two-week wait (2WW) urgent referral to respiratory services can be made to any hospital in the UK, regardless of where the patient currently lives – this is especially relevant when managing patients from mobile or transient communities','Back-up antibiotics may be appropriate as a pragmatic safety measure when a patient cannot attend for face-to-face review and reliable follow-up cannot be guaranteed – they should only be taken if signs of bacterial infection develop','When a patient declines or cannot attend for in-person assessment, document clearly the clinical reasoning behind the management plan and the safety-netting advice given','Tuberculosis should be considered in patients with a prolonged productive cough, particularly in those with risk factors such as recent travel to high-prevalence areas or known exposure – though it is less likely in the absence of these factors','Smoking cessation advice should be offered at every appropriate opportunity, especially when a respiratory red flag presentation raises concerns about lung malignancy'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  75,
  'Vasectomy Counselling',
  'Gynaecology & Women''s Health',
  'Video Consultation',
  false,
  'Daniel Pearce',
  '34-year-old male',
  ARRAY['None recorded'],
  ARRAY['Not currently on any medication','No Known Drug Allergy'],
  NULL,
  'Patient requesting information and counselling regarding vasectomy.',
  'Hi doctor, I''ve been giving serious thought to having a vasectomy and wanted to talk it through with you.',
  '',
  ARRAY[]::text[],
  'Daniel does not smoke or drink alcohol. He works as a project manager in construction. He lives with his wife, with whom he has been married for three years.',
  'He believes a vasectomy is the most responsible and practical long-term contraceptive option, given that he and his wife have both agreed they do not want children.',
  'He is concerned because his wife, who takes the combined oral contraceptive pill, has recently missed a few doses, and he worries about the risk of an unintended pregnancy.',
  'He is hoping for clear and honest information about the vasectomy procedure, what the risks are, and how to go about getting it arranged.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor. If asked about external pressure: deny any pressure and confirm this is entirely your own decision.',
  ARRAY['Explore the reason behind the patient''s request for a vasectomy – establish whether the decision is based on personal conviction, mutual agreement with his partner, or external pressure','Ask whether he has discussed the vasectomy specifically with his partner and how she feels about it','Ask what he already knows about vasectomy and whether he understands the risks and the permanent nature of the procedure','Ask about the nature of his relationship with his wife and whether there are any current difficulties or conflicts','Ask whether other forms of contraception have been considered, and whether reversible options such as long-acting contraception for his wife have been discussed','Ask about long-term considerations – how confident he is that he will never want children, and how he might feel if his circumstances or relationship changed in the future','Ask about his occupation and whether there are any current pressures or stressors at work','Explore his ideas, concerns, and expectations (ICE)'],
  ARRAY['Explain that a vasectomy is a permanent form of male sterilisation involving cutting or sealing the vas deferens – the tubes that carry sperm from the testicles','Emphasise that reversal is complex, expensive, and not always successful, and that the NHS does not routinely fund reversal procedures','Inform the patient that vasectomy is not immediately effective; he will need to continue using effective contraception until a post-vasectomy semen analysis (PVSA) confirms azoospermia','Advise that PVSA is usually performed around 12 weeks after the procedure','Highlight the importance of involving his partner in the decision-making process','Explain that although the final decision rests with him, it is important to have an open and honest conversation with his wife given the permanent nature of the procedure','Inform the patient about alternative contraceptive options, including reversible methods such as condoms or long-acting reversible contraception (LARC) for his partner, for example intrauterine devices or contraceptive implants','Advise that if he decides to proceed, the procedure can be arranged through a local sexual health clinic or vasectomy service','Reassure him that he does not need to make a decision today and is welcome to return to discuss further','Offer a follow-up consultation to allow more time for reflection or to proceed with a referral if he is ready'],
  'Thank you for coming to discuss this today, Daniel. It''s really positive that you are thinking this through carefully rather than rushing into a decision, and I''m happy to talk through everything with you.

A vasectomy is a minor surgical procedure that cuts or seals the vas deferens – the two tubes that carry sperm from the testicles. It is done under local anaesthetic and usually takes around 15 to 30 minutes. Most men feel well enough to return to light activities within a few days, though some experience mild discomfort or swelling for a short while afterwards. Serious complications are uncommon, but as with any procedure, there are some risks to be aware of, including the possibility of infection, a small collection of blood called a haematoma, or in a minority of men, longer-term testicular discomfort known as post-vasectomy pain syndrome.

One very important point is that a vasectomy does not work straight away. You will need to continue using contraception until a special semen test – called a post-vasectomy semen analysis – confirms there are no sperm present. This test is usually done around 12 weeks after the operation.

I also want to be very clear that vasectomy is intended to be permanent. Reversal operations do exist, but they are technically complex, not reliably successful, and not routinely available on the NHS – so anyone considering reversal would need to pursue it privately, with no guarantee of success. It is important to go into this fully aware of that.

You mentioned that you and your wife have agreed you do not want children, and that is a really important foundation for this decision. I would gently encourage you to make sure you have also had a specific conversation with her about the vasectomy itself, just to confirm you are both fully aligned on this particular step. People''s feelings and circumstances can sometimes change – after a bereavement, a change in relationship, or simply with time – and it is worth reflecting on how you might feel in those situations.

I also want to make sure you are aware of the alternatives. There are effective reversible options that do not involve a permanent procedure – for example, long-acting reversible contraception for your wife, such as an intrauterine device or a contraceptive implant, which are highly effective and do not carry the same permanence. These are worth considering if there is any uncertainty.

If, after reflecting on all of this, you feel confident you would like to go ahead, I can refer you to a local sexual health clinic where you will receive more detailed counselling and they will arrange the procedure. There is absolutely no pressure to decide today – please take the time you need, and come back whenever you are ready.',
  ARRAY['Vasectomy counselling must cover permanence, the failure rate of reversal, and the fact that NHS reversal is not routinely funded – patients should have realistic expectations before proceeding','Post-vasectomy semen analysis (PVSA) is required to confirm success and is typically performed around 12 weeks after the procedure; couples must use contraception until azoospermia is confirmed','It is good practice to encourage an open discussion with the patient''s partner before proceeding, given the permanent nature of the decision – though the procedure cannot legally be withheld solely because a partner objects','Reversible alternatives such as long-acting reversible contraception (LARC) for the female partner should always be discussed as part of counselling','The procedure is minor, performed under local anaesthetic, and takes 15–30 minutes; potential complications include infection, haematoma, and post-vasectomy pain syndrome','Shared decision-making and ensuring the patient is free from external pressure are central ethical principles when counselling for permanent sterilisation'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  76,
  'Recurrent UTI In A Child',
  'Paediatrics',
  'Video Consultation',
  false,
  'Mia Clarke',
  '4-year-old female',
  ARRAY['None recorded'],
  ARRAY['Not currently on any medication','No Known Drug Allergy','Immunisations up to date'],
  'Seen face to face 6 months ago by Dr H. Okocha (Clinical Practitioner)
Presenting complaint: Mother reports frequency and dysuria.
Examination: Vitals stable. Urinalysis: Nitrites positive, Leucocytes 2+
Plan: Treat as UTI with trimethoprim. Urine sent for culture. Safety netting and worsening advice given.

Urine Culture Report (6 months ago)
Antibiotic Sensitivity:
Amoxicillin – Resistant
Nitrofurantoin – Sensitive
Cefalexin – Sensitive
Trimethoprim – Sensitive
Ciprofloxacin – Sensitive
Amoxicillin-Clavulanate – Resistant

Seen face to face 2 months ago by Dr B. Chopra (Clinical Practitioner)
Presenting complaint: Mother reports frequency and dysuria. 2nd episode within the past 3–4 months.
Examination: Vitals stable. Urinalysis: Leucocytes 2+ and nitrites positive.
Plan: Treat with trimethoprim as per previous sensitivity. Safety netting and worsening advice given.

Patient''s mother (Karen Clarke) booked urgent appointment to discuss ongoing concerns.',
  'Mother calling to discuss recurrent urinary tract infections in her 4-year-old daughter.',
  'Hi doctor, it seems like Mia has another water infection, and I''m really worried – this keeps happening and I just don''t understand why.',
  '',
  ARRAY[]::text[],
  'Karen lives with Mia and her biological father. There is no family history of kidney disease. No safeguarding concerns or suspicion of abuse. Mia attends nursery and there have been no concerns raised. Pregnancy, birth, immunisation, and developmental history are all normal.',
  'Karen thinks that Mia''s difficulty wiping herself properly after the toilet might be causing the infections to keep coming back.',
  'She is worried about long-term damage to Mia''s kidneys or bladder if the infections continue.',
  'She wants advice on how to prevent further infections, reassurance about Mia''s health, and guidance on whether investigations or a specialist referral are needed.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor.',
  ARRAY['Ask about Mia''s current symptoms and their onset – frequency, dysuria, haematuria, abdominal pain, fever','Ask how often UTI symptoms have occurred in the past and the overall pattern','Ask about any nausea or vomiting','Ask about bowel habits, specifically constipation, as this can contribute to recurrent UTIs in children','Ask about toilet habits – how often Mia passes urine and whether she empties her bladder fully','Ask about fluid intake, including whether she drinks fizzy or sugary drinks','Ask about toilet hygiene, specifically whether Mia wipes from front to back, as wiping back to front significantly increases the risk of UTIs in young girls','Ask about the home situation and who lives at home','Ask if Mia has shown any changes in behaviour, such as becoming withdrawn, fearful, irritable, or losing interest in usual activities, to rule out possible abuse','Ask sensitively about potential safeguarding concerns – for example: "I ask all parents this as a routine part of my assessment, and I hope you understand it comes from a place of care. Is there anything that has ever made you worry about anyone behaving inappropriately towards Mia?"','Ask about any family history of kidney or urinary tract conditions','Ask for PBIND history – pregnancy, birth, immunisation, nutrition, and development','Give a diagnosis of recurrent urinary tract infection (UTI)'],
  ARRAY['Offer a face-to-face appointment to clinically assess Mia and perform a urine dipstick; send a sample for urine culture','Explain that if today''s dipstick indicates signs of infection, antibiotic treatment will be started based on her previous sensitivity results','Provide lifestyle and hygiene advice to reduce the risk of recurrence: encourage adequate fluid intake, regular toileting and complete bladder emptying, and teach and support proper wiping technique from front to back','Advise use of cotton underwear and avoidance of synthetic fabrics. Advise against perfumed bubble baths and other potential irritants','Arrange an ultrasound scan of the urinary tract within 6 weeks in line with NICE guidance, and refer Mia to a paediatrician for specialist assessment','Inform the parent that the specialist will review the scan, may request further imaging such as DMSA or MCUG, and may consider prophylactic antibiotics if clinically appropriate','Provide clear safety netting: advise Karen to seek medical attention promptly if Mia''s symptoms worsen, if she develops a fever, if there is visible blood in the urine, or if UTI symptoms recur'],
  'Thank you so much for getting in touch today, Karen. I can hear how worried you are, and that is completely understandable – having a young child who keeps getting urine infections is distressing, and you are absolutely right to want answers.

Based on what you have described – Mia passing urine more frequently, finding it painful, and the urine having a strong smell – it does sound as though she may be having another urinary tract infection. I would like to see her in person today so we can test her urine properly. If the urine test points to an infection, we will start antibiotics straight away, using the one we know worked well for her before based on the previous culture results.

You mentioned that you think the way Mia wipes herself might be playing a role, and that is a really thoughtful observation. In young girls, wiping from back to front rather than front to back can carry bacteria from the bowel towards the urethra, which can trigger urinary infections. At Mia''s age, she is still learning, and that is completely normal. Encouraging her to wipe from front to back each time is one of the most practical things you can do. I can also send you some helpful tips and resources, including information from the ERIC website, which specialises in bladder and bowel health for children.

In terms of your concern about long-term harm to Mia''s kidneys – I can hear how much this is weighing on you. Because Mia has now had more than one confirmed urinary infection, I am going to arrange an ultrasound scan of her kidneys and urinary tract. This is a routine step recommended by NICE guidance for children with recurrent UTIs, and it simply checks whether there is any underlying structural issue that might be contributing. I will also refer her to a paediatrician, who will review the scan results and decide whether any further tests or treatment – such as a low-dose preventive antibiotic – might be appropriate.

In the meantime, there are a few things that can genuinely make a difference at home. Keeping Mia well hydrated, making sure she goes to the toilet regularly rather than holding on, encouraging her to fully empty her bladder each time, dressing her in cotton underwear rather than synthetic fabrics, and avoiding perfumed bubble baths or soaps in the bath area – all of these reduce the chance of further infections.

Please do watch out for any worsening of symptoms or a high fever, and contact us straight away if that happens. We will also make sure you are kept fully informed at every stage.',
  ARRAY['Recurrent UTI in a child is defined as any recurrence of confirmed UTIs, regardless of the time interval between episodes – unlike in adults, there is no minimum number of episodes required before investigation','All children with recurrent UTIs should be referred to a paediatrician and offered a renal ultrasound scan within 6 weeks, in line with NICE guidance, to exclude structural abnormalities or vesicoureteric reflux','Trimethoprim is a commonly used first-line antibiotic for UTIs in children, but treatment should always be guided by urine culture and sensitivity results from previous episodes','In young girls, incorrect wiping technique (back to front) is a recognised and modifiable risk factor for recurrent UTIs – education about front-to-back wiping is an important part of management','Constipation can contribute to recurrent UTIs in children by causing bladder dysfunction; asking about bowel habits is an essential part of the history','A sensitive but routine safeguarding enquiry should be made in any child presenting with recurrent UTIs to exclude the possibility of abuse'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  77,
  'Haematuria In A Young Man',
  'Men''s Health',
  'Video Consultation',
  false,
  'Ryan Holloway',
  '21-year-old male',
  ARRAY['None recorded'],
  ARRAY['Not currently on any medication','No Known Drug Allergy'],
  'Out-of-Hours Summary Letter
RE: Ryan Holloway | 21 years old | Male

Ryan was seen yesterday at the out-of-hours service reporting visible blood in his urine over the past two days. He denied any associated symptoms such as pain, dysuria, urinary frequency, or systemic symptoms. He is not sexually active. On examination, he was haemodynamically stable. A urine dipstick test was performed, which showed 1+ haematuria and 1+ protein. Nitrites and leucocytes were negative. The patient was advised to follow up with his GP for further assessment and investigation if symptoms do not settle.

Seen by: Angela Carter, Advanced Nurse Practitioner (RN, MSc Advanced Clinical Practice, Independent Prescriber)',
  'Patient following up after out-of-hours attendance with visible blood in his urine.',
  'Hi doctor, I''ve noticed blood in my urine for the past few days and I''m really worried about what it could mean.',
  '',
  ARRAY[]::text[],
  'Ryan does not smoke, drink alcohol, or use recreational drugs. He works as a labourer on building sites.',
  'He is not sure what is causing the blood in his urine and has been trying not to think about it too much.',
  'He was not initially very worried, but his mother suggested it could be something serious like cancer, which has made him anxious.',
  'He wants the GP to explain what is causing the blood and tell him what the next steps will be.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor. Only mention the recent sore throat if specifically asked about recent illnesses or infections.',
  ARRAY['Ask about the onset of symptoms and how many days the blood has been visible','Ask whether the blood appears bright red, pink, or dark and tea-coloured','Ask if there is any pain on urination or dysuria','Ask about urinary frequency and other lower urinary tract symptoms','Ask about other associated symptoms – fever, nausea, or vomiting','Ask about abdominal, loin, or back pain to help rule out renal stones','Ask about any previous episodes of blood in the urine','Ask about recent illnesses – specifically any recent sore throat or flu-like symptoms in the past two to three weeks','Ask about any swelling around the eyes, face, hands, or ankles, which might suggest glomerulonephritis','Ask about sexual history and any penile discharge to help rule out an STI-related cause','Ask about smoking, alcohol, and occupation','Ask about family history of kidney disease','Ask about red flag symptoms – unexplained weight loss, night sweats, or reduced appetite','Explore the patient''s ideas, concerns, and expectations (ICE)','Give a likely diagnosis of post-streptococcal glomerulonephritis'],
  ARRAY['Offer a face-to-face appointment for clinical assessment, including blood pressure measurement and repeat urinalysis','Send urine for culture and urine albumin:creatinine ratio (ACR)','Arrange blood tests: full blood count (FBC), C-reactive protein (CRP), erythrocyte sedimentation rate (ESR), urea and electrolytes (U+Es), and antistreptolysin O titre (ASOT)','If any sore throat symptoms are still present, send a throat swab to check for Group A Streptococcus','Arrange a renal ultrasound scan to assess kidney structure','Advise that haematuria will be monitored every 1–2 weeks to ensure resolution; referral to nephrology will be considered if haematuria persists or any abnormal findings arise from investigations','Provide safety netting: advise Ryan to seek urgent medical attention if he develops facial, hand, or ankle swelling, shortness of breath, or any other new or worsening symptoms','Arrange follow-up in 1–2 weeks to review test results and monitor progress'],
  'Thank you for coming to see me today, Ryan. I can understand why this has been worrying you, especially after your mum raised the possibility of something serious. I want to start by reassuring you that in someone your age, with no other symptoms and no family history of cancer, that is an extremely unlikely explanation. That said, blood in the urine is something we always take seriously and investigate properly, so it is absolutely the right thing to come and discuss it.

Let me explain what I think might be going on. You mentioned that you had a sore throat about two weeks ago, and when you were seen out of hours, your urine showed not just blood but also a small amount of protein. Taken together, these findings point towards a condition called post-streptococcal glomerulonephritis. That is quite a mouthful, so in simple terms – it means the kidneys have become temporarily inflamed as a reaction to a previous throat infection, most likely caused by a type of bacteria called streptococcus. This typically happens around one to two weeks after the infection, which fits with your timeline. It is more common in younger people, and in the vast majority of cases it settles on its own without any specific treatment.

That said, I want to make sure we confirm the diagnosis properly and rule out other causes, so here is what I would like to arrange. I would like to see you face to face today so I can check your blood pressure and examine your abdomen. I will then organise some blood tests – including tests to check how your kidneys are working, a test called an antistreptolysin O titre which looks for evidence of a recent streptococcal infection, and some general inflammation markers. We will also send a urine sample for more detailed analysis, including a test for protein leakage from the kidneys called an albumin:creatinine ratio.

I would also like to arrange an ultrasound scan of your kidneys. This is a painless scan that uses sound waves – a bit like the scans used in pregnancy – and will let us check the structure of the kidneys and rule out things like a kidney stone or any abnormality.

Once all the results are back, I will review them with you and we will take things from there. We will also keep a close eye on the blood in the urine over the next one to two weeks to make sure it is clearing up. If things are not improving, or if any of the tests come back with unexpected results, I would refer you to a kidney specialist.

In the meantime, please contact us straight away if you notice any swelling around your eyes, face, hands, or ankles, or if you become breathless. These can occasionally be signs of the kidneys not coping, and we would want to see you urgently if they develop.',
  ARRAY['Post-streptococcal glomerulonephritis (PSGN) should be a top differential in a young patient presenting with painless visible haematuria and proteinuria following a recent sore throat or skin infection','PSGN typically occurs 7–14 days after a Group A beta-haemolytic streptococcal throat infection, or up to 6 weeks after a streptococcal skin infection such as impetigo','Key investigations include urinalysis (with ACR), renal function tests (U+Es), FBC, CRP, ESR, and antistreptolysin O titre (ASOT); a renal ultrasound is also appropriate to assess structure','PSGN is usually self-limiting and managed with monitoring rather than specific treatment in most cases; however, nephrology referral is appropriate if haematuria persists or renal function deteriorates','Safety-netting should cover signs of nephrotic or nephritic syndrome: periorbital or peripheral oedema, shortness of breath, or worsening blood pressure – these require urgent review','Cancer is an important differential for haematuria in older patients but is extremely unlikely in an otherwise well young adult – communicating this clearly can provide significant reassurance'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  78,
  'Gastroenteritis',
  'Gastroenterology & Haematology',
  'Video Consultation',
  false,
  'Laura Bennett',
  '27-year-old female',
  ARRAY['None recorded'],
  ARRAY['Rigevidon','No Known Drug Allergy'],
  NULL,
  'Patient calling urgently about diarrhoea and vomiting since yesterday, wanting medication.',
  'Hi doctor, I''ve had diarrhoea and vomiting since yesterday and just wanted to get something to stop it.',
  '',
  ARRAY[]::text[],
  'Laura is a non-smoker and drinks alcohol occasionally at social events. She works as a marketing executive. She lives with her partner of three years.',
  'She suspects the symptoms are due to food poisoning from a Thai restaurant she visited two days ago.',
  'She wants to return to work as soon as possible and was unsure whether it would be safe to do so.',
  'She is hoping the doctor can prescribe something to stop the diarrhoea.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor. Only mention that you have not vomited your contraceptive pill if specifically asked.',
  ARRAY['Ask about the onset of symptoms and how they started','Ask about the number of episodes of diarrhoea and vomiting','Ask whether there is any blood in the stools or vomit','Ask about fever, abdominal pain, mucus, or pus in the stool','Ask about current fluid intake','Ask whether she is passing urine normally, or if there has been any reduction in how often she is going – to assess for dehydration, noting that adults typically pass urine 4 to 7 times per day','Ask about symptoms of dehydration – dry mouth, dizziness, or weakness','Ask whether she has been in contact with anyone else who has had similar symptoms','Ask about her occupation – working in food handling may require stool testing and exclusion from work','Ask about recent travel abroad','Ask about recent antibiotic use to help rule out Clostridioides difficile','Ask whether she is on any other medications and whether her ability to take her contraceptive pill has been affected by the vomiting or diarrhoea','Give a likely diagnosis of viral gastroenteritis'],
  ARRAY['Reassure the patient that this is likely a self-limiting case of viral gastroenteritis','Advise maintaining adequate hydration by sipping fluids regularly throughout the day','Explain that antibiotics and antidiarrhoeal (antimotility) medications are not routinely recommended, as the illness is usually self-limiting','Inform the patient that if she needs rapid symptom relief to manage essential activities, she may choose to purchase loperamide over the counter as an antimotility agent','Advise that loperamide should not be used if she has blood, mucus, or pus in the stools, or if she develops a high fever, as these may indicate a more serious infection such as dysentery requiring medical assessment','Advise that she should not return to work or attend any social or communal settings until at least 48 hours after the last episode of diarrhoea or vomiting','Emphasise hygiene measures to prevent spread: thorough handwashing with soap and water, cleaning the toilet with disinfectant after each use, and using a dedicated cloth for toilet cleaning','Advise that diarrhoea and vomiting can reduce the effectiveness of the combined oral contraceptive pill (COCP). She should use additional contraception such as condoms until 7 days after symptoms have fully resolved','Explain that if she was unwell with vomiting or diarrhoea for more than 24 hours while taking the last 7 pills before her pill-free break, she should skip the break and start her next pack straight away','Offer to send her a link to official NHS guidance on COCP use during gastrointestinal illness','Advise that she can self-certify for up to 7 days; a sick note will be required if she remains unwell beyond that point','Provide safety netting: advise her to seek medical attention if symptoms have not improved by day 7, are getting worse, or if she develops any red flags – blood in stools, significant abdominal pain, or signs of dehydration such as dizziness, dark urine, or markedly reduced urine output'],
  'Thank you for getting in touch today, Laura. It sounds as though you''ve had quite an unpleasant 24 hours, and I want to give you a clear picture of what I think is going on and what I would recommend.

From everything you''ve described – the sudden onset, around five episodes of diarrhoea and vomiting, starting yesterday – this sounds very much like a viral stomach bug, which we call viral gastroenteritis. It is one of the most common things we see, and the good news is that it almost always clears up on its own within a few days without needing specific treatment.

I know you thought it might be related to the meal you had at the restaurant two days ago, and that is a very understandable thought. However, the timing actually makes food poisoning less likely. Food poisoning tends to cause symptoms within just two to six hours of eating contaminated food. Your symptoms came on the following day, which fits better with a viral infection. It is also worth noting that your partner, who ate at the same restaurant, has been fine – which again points away from a food-related cause.

You mentioned you were hoping for something to stop the diarrhoea, and I completely understand why. In most cases, though, we would not recommend antibiotics, because this is almost certainly a viral illness and antibiotics simply do not work against viruses. We also tend not to prescribe anti-diarrhoea medications as a matter of routine, because they can slow down the body''s natural process of clearing the infection. That said, if you feel you genuinely need some relief to get through essential activities, you could pick up loperamide from a pharmacy over the counter. Please do not take it if you develop any blood or mucus in your stools, or if you run a high fever – those would be signs that something more is going on and you should contact us or call 111.

The most important things to focus on right now are keeping well hydrated – small, regular sips of water or diluted squash throughout the day – and resting. I know you want to get back to work, and I do not want to keep you off longer than necessary. The guidance is to stay away from work until at least 48 hours after your last episode of diarrhoea or vomiting, even if you are feeling much better before then. This protects your colleagues from picking up the bug.

There is one more important thing I want to mention. You are taking Rigevidon, which is the combined oral contraceptive pill, and episodes of diarrhoea and vomiting can affect how well it is absorbed. This means your contraceptive cover may be reduced while you are unwell. I would advise using condoms as additional protection and continuing with that extra precaution until seven days after your symptoms have fully stopped. If you happened to be ill during the last seven active pills of your packet before your pill-free break, you should skip the break entirely and start your next pack straight away. I will send you a link to the NHS guidance on this so you can read through it at your own pace.

If your symptoms are not improving by day seven, are getting worse at any point, or if you notice blood in your stools, significant abdominal pain, or signs of dehydration such as dizziness or very dark urine, please do not hesitate to contact us or call 111.',
  ARRAY['Viral gastroenteritis is the most common cause of acute diarrhoea and vomiting in otherwise well adults; it is self-limiting and does not routinely require antibiotics or antimotility agents','Food poisoning typically causes symptoms within 2–6 hours of eating contaminated food; symptoms appearing 24–48 hours after exposure are more consistent with a viral cause','Patients should be advised to remain off work and away from communal settings for at least 48 hours after the last episode of diarrhoea or vomiting to prevent onward transmission','Diarrhoea and vomiting can reduce absorption of the combined oral contraceptive pill (COCP); patients should be counselled to use additional contraception for 7 days after symptoms resolve, and to skip the pill-free break if illness occurred during the final 7 active pills of a pack','Stool culture is not routinely required for acute gastroenteritis but should be considered if: diarrhoea persists beyond 7 days, there is blood or mucus in the stool, there has been recent antibiotic use or hospital admission, the patient is a food handler, or there has been recent travel to a higher-risk region','Notification to the local Health Protection Team is required if a notifiable disease such as food poisoning, Shigella, enteric fever, or cholera is suspected – notification should be made even before laboratory confirmation'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  79,
  'Urinary Incontinence In Older Female',
  'Gynaecology & Women''s Health',
  'Video Consultation',
  false,
  'Claire Hartley',
  '48-year-old female',
  ARRAY['No significant past medical history','Normal cervical smear 3 months ago; next screening scheduled as per routine interval'],
  ARRAY['Not currently taking any regular medication','No known drug allergies','No recent consultations on record'],
  NULL,
  'Patient booked a routine video appointment to discuss urinary leakage that has been worsening over recent months.',
  'Hi doctor, I''ve been leaking urine for a while now — it''s been going on for years really, but over the past few months it''s gotten much worse and it''s really starting to affect my day-to-day life.',
  'You are Claire, a 48-year-old woman attending a video consultation to talk about urinary incontinence that began after the birth of your only child, eight years ago. The delivery was a forceps delivery. To begin with, you had occasional leakage when you coughed or sneezed, which you managed on your own without seeing a doctor. Over the last four months, however, the problem has become much more bothersome. You now wear urinary pads throughout the day. Over the last two to three months, you''ve also started getting a sudden, intense urge to pass urine and sometimes cannot make it to the toilet in time — though this happens less often than the leakage with physical activity. If asked which type of leakage is most frequent, say: "It''s usually when I cough or sneeze." You''ve started positioning yourself closer to the toilet at work to avoid accidents. You are now avoiding sex with your partner because you fear leaking during intercourse. This has knocked your confidence and affected your relationship, even though your partner has been understanding. You have no sensation of heaviness or dragging down below.',
  ARRAY['The incontinence started after a forceps delivery eight years ago and was initially occasional leakage only with coughing or sneezing','The leakage has become more frequent over the last four months and you now wear pads all the time','In the last two to three months you have also developed urgency — a sudden strong need to pass urine — and sometimes you do not reach the toilet in time, though this is less frequent than the stress leakage','You have started sitting closer to the toilet at work to avoid accidents','You are avoiding intimacy with your partner due to fear of leaking during sex, which has affected your confidence and your relationship — though your partner is supportive','You have no dragging or heaviness sensation in the vaginal area'],
  'You live with your partner. You do not smoke or drink alcohol, and you have been avoiding caffeine. You have been cutting back on your fluid intake to try to manage the leakage, but this seems to have made things worse. Your periods are regular, with your last period around two weeks ago. You are not using any contraception as your partner has had a vasectomy. Your bowels are normal. You have not sought medical help for this before, but you now feel frustrated and overwhelmed, and you are ready to get some support.',
  'You wonder whether a prolapse from the forceps delivery might be responsible for your symptoms.',
  'You are worried that you will have to rely on urinary pads for the rest of your life.',
  'You are hoping the doctor can help you understand what is going on and offer you treatment or support to help you regain control.',
  ARRAY[]::text[],
  NULL,
  'Say no to any other symptoms asked about. Accept anything offered by the doctor.',
  ARRAY['Ask when the patient first noticed urinary incontinence and how long it has been going on','Ask whether the leakage occurs during physical activities such as coughing, sneezing, laughing, or exertion — to assess for stress urinary incontinence','Ask whether she experiences a sudden, urgent need to pass urine and sometimes cannot reach the toilet in time — to assess for urge urinary incontinence','Ask which type of leakage is more frequent or troublesome for her, to identify the dominant component','Ask about other urinary symptoms including nocturia, dysuria, and haematuria','Ask about any lower abdominal or bladder pain','Ask whether she has noticed any sensation of heaviness, pressure, or dragging in the vaginal area, which would suggest prolapse','Ask about any recurrent urinary tract infections','Ask about bowel habits, particularly constipation, as this can worsen incontinence','Ask about her menstrual cycle and current contraception','Signpost sensitively before asking personal questions: ask about any vaginal discharge, whether she is sexually active, and whether she experiences pain during intercourse (dyspareunia)','Ask about her obstetric history, including the number and type of deliveries — particularly whether any were vaginal or instrument-assisted','Ask whether she has been restricting her fluid intake and why','Ask about caffeine consumption','Ask about symptoms that might suggest diabetes, such as increased thirst, frequent urination, or unexplained weight change','Explore the impact of incontinence on her quality of life, including sleep, confidence, intimacy, and self-esteem','Ask about smoking history, as a chronic cough from smoking can worsen stress incontinence','Ask what coping strategies she has tried so far, for example wearing pads or limiting fluids','Give a diagnosis of mixed urinary incontinence'],
  ARRAY['Offer a face-to-face appointment to allow for pelvic examination, including per vaginal (PV) assessment, urinalysis, and urine culture','Advise the patient to keep a bladder diary for at least 3 days, recording fluid intake, frequency and timing of urination, episodes of leakage, the type of leakage (stress or urge), and pad use','As stress incontinence appears to be the predominant type, offer referral to a pelvic floor physiotherapist or via the local bladder and bowel service for supervised pelvic floor muscle training for 3 months','Reassure the patient that long-term pad use is not inevitable. Many women experience significant improvement or resolution of symptoms with appropriate pelvic floor exercises and targeted support','Emphasise the importance of adequate fluid intake — explain that restricting fluids can lead to concentrated urine, which irritates the bladder and worsens urgency symptoms','Acknowledge the emotional and relational impact of the incontinence. Encourage open communication with her partner and consider referral to sexual health or relationship counselling if appropriate','If emotional distress or avoidance behaviour is contributing to low mood, consider offering or signposting to CBT (Cognitive Behavioural Therapy)','Suggest she speaks with her HR department about possible workplace adjustments, such as flexible rest breaks or easier access to toilet facilities','Safety net: advise the patient to seek urgent review if she develops haematuria, pain on urination, fever, or a significant worsening of symptoms','Arrange a review appointment in 3 months to assess symptom progression and response to pelvic floor training'],
  'Thank you so much for sharing all of that with me today — I can really see how much this has been affecting you, both physically and emotionally, and I want you to know that you are absolutely right to seek help. Based on everything you have described, Claire, it sounds like you are experiencing what we call mixed urinary incontinence. This means there are two things happening at the same time: stress incontinence, where urine leaks when you cough, sneeze, or move, and urge incontinence, where you sometimes get a sudden, strong need to pass urine and cannot always make it to the toilet in time.\n\nYou mentioned wondering whether this might be caused by a prolapse related to your forceps delivery, and that is a very reasonable thing to consider. However, from what you have described, your symptoms do not sound typical of a prolapse. Women with prolapse often report a feeling of pressure, heaviness, or dragging in the vaginal area — sometimes describing it as a sensation that something is coming down. You have not mentioned any of those feelings, which is reassuring. That said, because you have a history of a forceps delivery, I would still like to arrange a face-to-face examination to check everything properly and put your mind at rest.\n\nIn terms of your worry about wearing pads indefinitely, I want to genuinely reassure you that this is not the outlook for most women. With the right support — particularly supervised pelvic floor muscle exercises through a specialist physiotherapist or our local bladder and bowel service — many women see real and lasting improvement. The pads are there to keep you comfortable in the meantime while we work on the underlying problem together.\n\nI also want to acknowledge the impact this has had on your relationship and your confidence. That is completely understandable. We can discuss referral to a sexual health or relationship counsellor if you feel that would help, and in the meantime, simply being open with your partner about what you are going through can sometimes make a big difference.\n\nOne thing I would also like to mention: cutting back on fluids can actually make things worse rather than better. Concentrated urine irritates the bladder lining and can increase urgency, so we need to find the right balance — not too much, not too little — ideally around 1.5 to 2 litres of fluid per day.\n\nOne very helpful first step would be to keep a bladder diary for the next three days. This involves noting down what you drink, how often and how much you pass urine, any leaks you have, what you were doing at the time, and whether you used a pad and how wet it was. This gives us really valuable information to guide the best treatment for you. Is that something you would be willing to try?\n\nI will also arrange a follow-up in around three months to check how things are going and review your response to pelvic floor training. Please do not hesitate to contact us sooner if you notice any blood in your urine, pain when passing urine, a temperature, or if your symptoms get significantly worse.',
  ARRAY['Mixed urinary incontinence combines stress urinary incontinence (leakage with exertion) and urge urinary incontinence (leakage preceded by a sudden strong desire to void); management should target the dominant symptom','The first-line investigation is a bladder diary of at least 3 days, recording fluid intake, voiding frequency, leakage episodes, and pad use — this guides targeted treatment','When stress incontinence is predominant, supervised pelvic floor muscle training for a minimum of 3 months (via physiotherapy or a bladder and bowel service) is the first-line treatment','Fluid restriction worsens incontinence by producing concentrated urine that irritates the bladder; patients should be advised to maintain adequate hydration of approximately 1.5–2 litres per day','A history of instrumental delivery (e.g. forceps) raises the possibility of prolapse, but prolapse classically presents with pelvic heaviness or a dragging sensation — absence of these features is reassuring, though examination is still warranted','Urge urgent review for new haematuria, dysuria, fever, or rapidly worsening incontinence, as these may indicate an underlying pathology requiring further investigation'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  80,
  'HIV and Death Certificate',
  'Ethics',
  'Telephone Consultation',
  false,
  'Martin Davies',
  '46-year-old male',
  ARRAY['Metastatic anal squamous cell carcinoma (HPV-associated)','HIV positive','Generalised anxiety disorder','Alcohol misuse and IV drug use (heroin)','DNACPR in place'],
  ARRAY['Dolutegravir (50 mg) + Tenofovir disoproxil fumarate (300 mg) + Emtricitabine (200 mg): one tablet orally once daily','Morphine sulfate (Oramorph): 10 mg orally every 4 hours as needed','Senna: 15 mg orally at bedtime','Sertraline: 50 mg orally once daily','Metoclopramide: 10 mg orally three times daily as needed for nausea and vomiting','No known drug allergies'],
  'Oncology letter Re: Mr. Martin Davies (Age: 46 years old male)\n\nDear GP,\n\nI am writing to update you on the management and current status of our mutual patient, Mr. Martin Davies, who has been under the care of the Oncology Department for metastatic anal squamous cell carcinoma, associated with HPV infection and HIV-positive status.\n\nMr. Davies''s disease has progressed significantly, with confirmed metastases to liver, lungs, and various lymph nodes. He has undergone palliative radiotherapy and palliative chemotherapy for symptom control. Unfortunately, despite these interventions, his disease continues to advance, and it has been determined that there are no curative treatment options available.\n\nMr. Davies is aware of his prognosis and has consented to transition to community-based palliative care and end-of-life management. His primary goal is to prioritise comfort and maintain dignity during this period. He has expressed a preference to die at home, supported by community palliative services.\n\nWe have now discharged Mr. Davies from our care and referred him to the local hospice and palliative care teams. We would be grateful if you could oversee his ongoing management, including symptom control, psychosocial support, and coordination with community services. Should you require any further information about his oncology treatment or wish to discuss his case in more detail, please do not hesitate to contact me directly.\n\nYours sincerely,\nDr J. Okafor, MBBS, MRCP (UK), FRCR\nConsultant Oncologist',
  'Patient booked a telephone consultation to discuss advance care planning.',
  'Hi Doctor. I hope you don''t mind me raising this, but there''s something really important I wanted to talk to you about. When the time comes, I would prefer that my HIV status isn''t mentioned on my death certificate. I just don''t want my family to find out about it — even after I''m gone.',
  'You feel judged by your family for both your sexuality (you are gay) and your history of substance use. You have not disclosed your HIV status to them and do not want them to find out, even after your death. You are particularly anxious about your HIV status appearing on the death certificate or being revealed through any other means. You are currently in a hospice, which has been helpful in managing your pain. Your strong preference is to die at home rather than in a facility. You are otherwise fairly well, and the hospice is hoping to discharge you in around three days.',
  ARRAY[]::text[],
  'You are currently staying in a hospice and have no close family or carers directly involved in your care. You are being supported by the hospice team and are exploring the possibility of dying at home. You do not smoke or drink alcohol.',
  'You are thinking ahead and want to plan properly for the end of your life.',
  'You do not want your family to learn about your HIV status and want reassurance that this wish will be honoured, even after you have passed away.',
  'You would like help arranging a peaceful death at home, and you are hoping the GP can advise on how your personal wishes — particularly around confidentiality — can be respected.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY['Begin by exploring the patient''s primary concern with sensitivity: "I understand you''re worried about your HIV status appearing on your death certificate. Could you tell me a bit more about why this is so important to you?"','Ask what his specific worries are about how his family might react if his HIV status became known','Ask whether he has any other wishes or concerns beyond confidentiality around his HIV status','Ask about his current symptoms, including pain, constipation, nausea, breathlessness, or anxiety','Ask about his appetite','Explore his mood and emotional wellbeing','Ask about his current home environment and what practical support is available there','Ask whether he has any close friends or family members who could help provide care or support at home','Ask about the level of support currently provided by the hospice or palliative care team','Ask whether he understands what is involved in completing a death certificate and whether he would like an explanation of the process'],
  ARRAY['Sensitively explain that in the UK, the cause of death recorded on a death certificate must accurately reflect the medical facts that contributed to the person''s death. If HIV played a role in the progression of the terminal illness, it may need to be included','Explain that the death certificate is a legal and medical document required for the official registration of death and must be completed accurately','Inform the patient that in the UK, death certificates are public records — any individual with basic identifying details such as full name and date of death can request a copy, which means his family could potentially access the information recorded on it','Acknowledge the emotional weight of this news and reassure him that while the death certificate itself is not private, his wider medical records remain strictly confidential under the NHS and cannot be accessed by others without appropriate consent or legal authority','Offer support in helping him think through how he might wish to communicate his diagnosis to his family, if he chooses to do so. The palliative care team or a counsellor can help facilitate this sensitively','Inform the patient that once he is discharged from the hospice, a home visit can be arranged to review his needs in person','Explain that the district nurse will be involved to support his medical needs and symptom control at home, and that an occupational therapist may assess his home environment to recommend equipment, adaptations, and help with personal care','Explain that a form called the SR1 (formerly DS1500) can be completed to fast-track access to benefits related to terminal illness','Confirm that his wish to die at home will be documented in his clinical records and shared appropriately with the wider multidisciplinary team','Provide information about the Daffodil Line — a specialist palliative care phone line offering direct access to a GP or district nursing team for patients receiving end-of-life care at home, ensuring prompt support for urgent medical or symptom needs'],
  'Thank you for calling today, and thank you for trusting me with something so deeply personal. I can hear how important your privacy is to you, particularly regarding your HIV status and the fear of how your family might respond. I want you to know that I take this very seriously and I am here to support you through this.\n\nLet me first try to explain how death certificates work in the UK, Martin, because I know this is at the heart of your concern. A death certificate is a legal and medical document that must accurately record the cause of death and any conditions that contributed to it. If HIV played a role in the progression of your illness — which in your case it has — then it may need to be included on the certificate. I know that is difficult to hear, and I am genuinely sorry to be telling you that. But this is a legal requirement that I am bound by as your doctor.\n\nI also need to make you aware that in the UK, death certificates are classified as public records. This means that in principle, anyone who has basic details about you — your full name and date of death — can apply for a copy. So unfortunately, there is a possibility that members of your family could access that information in time. I wish I could give you a different answer, but I want to be honest with you. What I can reassure you of is that your wider medical records — everything else we hold about you — remain completely confidential and cannot be seen by anyone without your consent or a legal basis.\n\nIf you would like, we could talk about whether you might want to have any input into how this information is shared with your family, perhaps through a counsellor or the palliative care team. Sometimes having that conversation on your own terms, even in writing, can feel better than worrying about what might emerge later. There is no pressure at all — that is entirely your decision.\n\nIn terms of making your wish to die at home a reality, I am fully behind you on that. Once you are discharged from the hospice, I will arrange a home visit to assess your needs in person. We will get the district nursing team involved to support your comfort and any ongoing symptom management. I will also ask an occupational therapist to visit to look at your home environment and make sure you have everything you need in place — any equipment, adaptations, or help with personal care.\n\nI will also complete an SR1 form, which can fast-track access to benefits related to your terminal diagnosis, and I will make sure your preference for a home death is clearly recorded in your notes and shared with the team caring for you. You can also call the Daffodil Line at any time — it gives you direct access to a GP or district nurse for urgent support when you are at home.\n\nPlease know that you do not have to face any of this alone. We will do everything we can to honour your wishes and keep you as comfortable and supported as possible.',
  ARRAY['The Medical Certificate of Cause of Death (MCCD) must accurately reflect the cause of death and any contributing conditions — if HIV contributed to the terminal illness, it must be included as a legal requirement','Death certificates in the UK are public records; any person with basic identifying details (full name and date of death) can request a copy, which limits the GP''s ability to guarantee confidentiality for information recorded on the certificate','While the death certificate is a public document, the rest of a patient''s medical records remain strictly confidential and cannot be accessed by third parties without appropriate consent or legal authority','GPs must balance the legal obligation to complete death certificates accurately with compassionate, sensitive communication — particularly where stigma, sexuality, or substance use are involved','End-of-life care planning should include documentation of preferred place of death in the clinical record, coordination with district nurses and occupational therapists, and completion of an SR1 form to fast-track terminal illness benefits','The Daffodil Line provides patients receiving end-of-life care at home with direct access to a GP or district nurse for rapid support with urgent medical or symptom needs'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  81,
  'Elbow Pain In Young Adult',
  'Rheumatology & Musculoskeletal',
  'Video Consultation',
  false,
  'Daniel Osei',
  '36-year-old male',
  ARRAY['No significant past medical history'],
  ARRAY[]::text[],
  'Letter from Out-of-Hours Service (1 week ago)\n\nRe: Mr. Daniel Osei, 36-year-old male presenting with right elbow pain\n\nMr. Daniel Osei attended the out-of-hours service with a 2-week history of right elbow pain. He described the pain as localised to the outer aspect of the elbow, made worse by gripping and lifting. There was no history of trauma. Examination revealed tenderness over the lateral epicondyle with no swelling or deformity. Neurovascular assessment was normal. An X-ray of the right elbow was performed and showed no abnormalities. He was advised to use over-the-counter analgesia such as ibuprofen or paracetamol, to rest, apply ice, and avoid aggravating activities. He was advised to follow up with his GP if symptoms persisted beyond a few weeks or worsened.\n\nKind regards,\nOluwaseun Adeyemi\nAdvanced Nurse Practitioner',
  'Patient booked a routine appointment to discuss ongoing right elbow pain following a recent out-of-hours attendance.',
  'Hi doctor, I''ve had this pain on the outside of my right elbow for about three weeks now and it doesn''t seem to be going away. I saw someone at the out-of-hours service recently, but I wanted to follow it up with you.',
  'You are Daniel, a 36-year-old electrician. You have been having pain on the outer side of your right elbow for the past three weeks. The pain started gradually and you hoped it would settle on its own, but it has not. It seems to get worse when you are working — you do a lot of repetitive hand and wrist movements fitting cables and using tools, and this aggravates the pain. It is also worse at the end of a long working day, and you''ve noticed it is difficult to grip or straighten your arm fully at times. You visited the out-of-hours service recently and had an X-ray which came back normal. The pain has not got worse since that visit. You are here today because it is starting to interfere with your work and your daily activities.',
  ARRAY['The pain started gradually about three weeks ago and you hoped it would go away, but it has not','The pain is worse with repetitive gripping and twisting movements at work as an electrician','It tends to be worse at the end of a long day, and you find it difficult to fully grip or extend your arm at times','You had an X-ray at the out-of-hours service which was normal — the pain has not worsened since then','You are right-handed, and this is your dominant hand, which makes the problem more significant for your work','You have two children at home: a 7-year-old daughter and a 5-year-old son. You live with your partner','No other joints are affected. No numbness, tingling, or weakness in the hand. No swelling or redness at the elbow. No night pain waking you from sleep'],
  'You are a non-smoker and do not drink alcohol. You work as an electrician and are employed by a small local firm. You live with your partner and two children.',
  'You are not entirely sure what is causing the pain, though you think it might be related to your work.',
  'The pain is starting to interfere with your job as an electrician, and you are worried about how long it will last and whether it will affect your ability to keep working.',
  'You would like the GP to help you understand what is causing the pain and what can be done to treat it.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY['Ask about the location of the pain — lateral elbow pain suggests lateral epicondylitis (tennis elbow); medial elbow pain suggests medial epicondylitis (golfer''s elbow)','Ask about the onset and duration of symptoms','Ask the patient to describe the character and severity of the pain','Ask whether the pain is getting better, worse, or staying the same — if it has worsened since the out-of-hours visit, a face-to-face examination may be warranted','Ask about any history of trauma to the elbow or forearm','Ask about swelling, redness, warmth, or any lumps or bumps around the elbow','Ask about numbness, tingling, or weakness in the arm or hand','Ask whether any other joints are affected','Ask about night pain and whether it wakes him from sleep','Ask about his occupation — lateral epicondylitis is common in electricians, barbers, tennis players, and others who perform repetitive gripping or twisting movements','Ask whether he is right- or left-handed, to understand the functional impact on his dominant hand','Ask what the patient has already tried in terms of pain relief or self-management','Explore his ideas, concerns, and expectations, as well as any relevant psychosocial context','Explain the likely diagnosis of lateral epicondylitis (tennis elbow) and that the normal X-ray excludes bony injury, with the pain likely arising from tendon irritation at the lateral epicondyle'],
  ARRAY['Advise on a stepwise approach to analgesia: start with paracetamol and/or topical NSAIDs; if these are insufficient, consider oral NSAIDs such as ibuprofen. If ibuprofen does not provide adequate relief, naproxen may be used. Always check for contraindications before prescribing NSAIDs, including asthma, COPD, cardiovascular disease, and renal impairment','Refer for physiotherapy to aid recovery and prevent recurrence through guided stretching and strengthening exercises','Consider recommending an elbow brace (epicondyle strap), which applies counter-pressure to the forearm muscles and can reduce strain on the affected tendon','Provide advice on workplace adjustments — these may include varying work tasks to reduce repetitive strain, increasing the frequency of rest breaks, adjusting how tools are held or used, and considering ergonomic modifications to his working environment','If symptoms are significantly affecting his ability to work and his income is at risk, consider referral to a social prescriber who can advise on eligibility for benefits such as Employment and Support Allowance from the Department for Work and Pensions','Safety net: advise him to seek review if his symptoms worsen, if he develops swelling, redness, or stiffness of the joint, or if new neurological symptoms appear such as numbness or weakness','Arrange a follow-up appointment in 6 weeks to review his progress'],
  'Thank you for coming along today and for following up after your out-of-hours visit. I''ve had a look at the X-ray report and I''m glad to confirm it was completely normal — so there''s no evidence of any fracture, bone damage, or significant joint problem, which is really reassuring.\n\nBased on everything you have described, Daniel — the pain on the outer side of your right elbow, the fact that it is your dominant hand, and that it is worse with repetitive gripping and twisting at work — I think what you are dealing with is something called lateral epicondylitis, or what is more commonly known as tennis elbow. Despite the name, it has nothing to do with playing tennis. It affects lots of people who do repetitive hand and wrist movements as part of their job, and electricians are actually among the occupations where we see this quite commonly. What happens is that the tendons that attach the forearm muscles to the outer part of the elbow become irritated and inflamed through repeated use.\n\nThe good news is that tennis elbow does respond well to treatment, and most people make a full recovery — it just takes a little time and the right approach. I would like to start you on some pain relief to help manage things while you heal. Paracetamol and anti-inflammatory gels applied directly to the elbow are a good starting point. If those are not enough, we can try an anti-inflammatory tablet like ibuprofen or naproxen — though before we do that I''ll just want to check that you have no history of asthma, stomach problems, or heart or kidney issues, as those can affect whether it is safe to use.\n\nI would also like to refer you to physiotherapy. A physiotherapist can guide you through specific stretching and strengthening exercises for the forearm that are really effective for this condition and help prevent it coming back. An elbow brace — sometimes called an epicondyle strap — worn just below the elbow can also help take some of the strain off the tendon while you are working.\n\nIn terms of your job, I understand this is your livelihood and it is important. I would encourage you to talk to your employer about the possibility of varying your tasks a bit — spreading out the repetitive work, taking more frequent short breaks, and looking at whether there are any adjustments to how you hold or use your tools. These changes can make a real difference to how quickly you recover.\n\nIf at any point your symptoms worsen, if the elbow becomes swollen or red, or if you notice any numbness or weakness in your hand or fingers, please do come back and see us. I would like to see you again in six weeks to check how you are getting on.',
  ARRAY['Lateral epicondylitis (tennis elbow) presents with pain over the lateral epicondyle, typically worsened by gripping, lifting, or repetitive wrist extension — it is common in occupations involving repetitive hand movements such as electricians, barbers, and plumbers','A normal X-ray in the context of lateral epicondyle tenderness effectively excludes bony injury; the pain arises from tendon irritation or degeneration at the common extensor origin','First-line management includes analgesia (paracetamol, topical NSAIDs), physiotherapy with eccentric strengthening exercises, and an elbow brace (epicondyle strap) — always check for contraindications before prescribing systemic NSAIDs','Workplace adjustments are an important part of management: varying tasks, increasing rest breaks, and making ergonomic modifications can reduce ongoing strain and aid recovery','If income is affected due to inability to work, referral to a social prescriber can help assess eligibility for Employment and Support Allowance from the Department for Work and Pensions','Safety-net advice should include return if symptoms worsen, swelling or redness develops, or new neurological symptoms such as numbness or weakness appear; arrange follow-up at 6 weeks'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  82,
  'Recurrent Tinnitus In A Young Adult',
  'ENT & Eye',
  'Video Consultation',
  false,
  'Thomas Griffiths',
  '42-year-old male',
  ARRAY['Schizophrenia'],
  ARRAY[]::text[],
  'Letter from Occupational Health Nurse (1 week ago)\n\nDear GP,\n\nRe: Mr. Thomas Griffiths, 42 years old — Occupational Health Assessment\n\nI am writing following a recent occupational health review carried out for Mr. Thomas Griffiths, who is employed in the operations department at Meridian Distribution Services. This assessment formed part of the company''s routine workplace wellbeing programme.\n\nDuring the consultation, Mr. Griffiths reported experiencing a persistent ringing sensation in both ears (tinnitus) for approximately five weeks. He denied any recent upper respiratory tract infection, flu-like illness, or significant exposure to loud noise in the workplace. There were no associated red flag symptoms such as sudden hearing loss, vertigo, headache, or other neurological features. On examination, both tympanic membranes appeared clear and intact, with no evidence of impacted wax or other visible abnormalities.\n\nGiven the persistence of tinnitus and absence of identifiable occupational or acute causes, I have advised Mr. Griffiths to seek further assessment and management from his general practitioner.\n\nPlease do not hesitate to contact me should you require any further details from this assessment or wish to discuss any ongoing occupational health input.\n\nYours sincerely,\nNaomi Clarke, RN, BSc (Hons), DipOHPrac\nSenior Occupational Health Nurse',
  'Aripiprazole intramuscular depot injection 400 mg every month. No known drug allergies.',
  'Patient booked a routine video appointment following a referral from the occupational health nurse to discuss ongoing ringing in the ears.',
  'Hi doctor, I''ve been having a ringing sound in both my ears for about six weeks now. I saw the nurse at work recently and she suggested I book an appointment with you.',
  'The ringing actually started about six weeks ago. It began in my right ear first and then seemed to spread to the left as well. It sounds like a constant mechanical hum or machinery noise.',
  ARRAY['The tinnitus is always there, but it tends to be less noticeable when there is background noise around you','You remember going to a loud heavy metal concert about six weeks ago, and the ringing started shortly after that evening — the music was very loud','If asked about hearing loss, say you are not completely sure — it might just be that the ringing makes it harder to catch things clearly, but you cannot tell for certain','You have not noticed any ear discharge, dizziness, vertigo, balance problems, jaw pain or clicking, facial weakness, or sensitivity to loud sounds','You have not had any recent cold, flu, or other illness, headaches, visual changes, or unusual stress'],
  'You are a non-smoker and do not drink alcohol. You live alone and work as an operations manager at a large distribution company. You do not think you are exposed to significant noise levels in your day-to-day work.',
  'You are not sure what has caused the ringing in your ears.',
  'You want the ringing to stop — it is uncomfortable, distracting, and making it harder to concentrate at work.',
  'You would like the GP to explain what might be causing it and what can be done to make it go away.',
  ARRAY['If the doctor offers a face-to-face examination, ask: "What exactly will you be checking, doctor? The nurse at work already looked in my ears."'],
  NULL,
  'Say no to any other questions or symptoms not covered in the details already provided. Accept anything offered by the doctor.',
  ARRAY['Ask about the duration and onset of tinnitus and whether it came on gradually or suddenly','Ask whether the tinnitus affects one ear or both ears','Ask the patient to describe the sound and whether it is pulsatile — that is, whether it seems to pulse in time with the heartbeat. Note: sudden-onset pulsatile tinnitus requires same-day ENT referral as it may indicate a vascular abnormality','Ask whether the tinnitus is constant or comes and goes','Ask about any recent upper respiratory tract infection or cold','Ask about any ear discharge or ear pain','Ask whether there has been any recent head injury — tinnitus following head trauma requires an urgent same-day ENT referral as it may indicate a serious underlying cause such as traumatic brain injury','Ask about associated symptoms including hearing loss, dizziness, vertigo, balance problems, jaw pain or clicking, facial weakness, unilateral limb weakness, sensitivity to loud sounds, visual changes, headache, or stress','Ask about relieving or aggravating factors — for example, background noise may reduce tinnitus, while stress, poor sleep, caffeine, or certain head or jaw positions may worsen it','Ask about significant noise exposure, either at work or during leisure activities such as concerts or high-volume headphone use','Ask about use of any ototoxic medications, whether prescribed or over-the-counter, such as aspirin or NSAIDs','Ask about any family history of hearing loss or tinnitus','Explore the impact of the tinnitus on his sleep, mood, work performance, and daily activities','Ask about social history including smoking, alcohol, and stress levels','Explore his ideas, concerns, and expectations','Make a diagnosis of noise-induced tinnitus'],
  ARRAY['Offer a face-to-face appointment to perform basic hearing assessments (Weber and Rinne tuning fork tests) to check for sensorineural or conductive hearing loss, and to carry out a brief neurological examination','Refer to audiology for a formal hearing assessment to check for noise-induced hearing loss — the referral typically takes around four to five weeks','Explain that if hearing loss is identified, he may be offered hearing aids, which can also help reduce the perception of tinnitus','Reassure him that tinnitus frequently improves on its own, particularly when caused by short-term noise exposure, but that repeated exposure to loud sounds can lead to permanent hearing damage','Advise avoiding further exposure to loud noises such as concerts and high-volume headphone use; encourage the use of ear protection such as earplugs or noise-reducing headphones in loud environments','Suggest sound therapy as a self-help strategy — for example, having low-level background sounds such as soft music, a fan, or a white noise machine, particularly at night, to help distract attention away from the tinnitus','Encourage relaxation techniques, mindfulness, or tinnitus-focused CBT, as these can significantly reduce the distress associated with persistent tinnitus','Safety-net advice: advise him to seek urgent medical review if the tinnitus worsens, becomes one-sided, pulsatile, or is associated with hearing loss, weakness, headache, or balance problems. Advise him to seek help immediately if the tinnitus or associated distress causes him to feel anxious, low in mood, or if he develops any thoughts of self-harm or suicide','Offer a follow-up appointment after the audiology assessment to review results and plan next steps in management'],
  'Thank you for explaining all of that so clearly today — I can hear that the constant ringing is really getting in the way of your day-to-day life, and I completely understand why you want answers and some relief from it.\n\nFrom everything you have described, Thomas, it sounds like you are experiencing what we call tinnitus — which is the medical term for hearing a ringing, buzzing, or other sound when there is no external noise causing it. You mentioned that the ringing started shortly after attending a loud heavy metal concert about six weeks ago. That timing is actually very telling, and it suggests the most likely cause is noise-induced tinnitus — where the very loud music has temporarily overstimulated or irritated the delicate hair cells in the inner ear that are responsible for hearing. This is a well-recognised cause of tinnitus, and importantly, in many cases it does improve over time as the ears recover from that exposure.\n\nI would like to see you in person for a brief face-to-face appointment so I can carry out a hearing check using a tuning fork — this helps me assess whether there is any change in your hearing, and in what way. I will also do a quick neurological check. The main purpose of seeing you in person is to make sure there are no red flag signs that would need a more urgent referral. I know the nurse at work looked in your ears already, and that is really helpful — but the tuning fork tests assess hearing function rather than the appearance of the eardrum, so it is a slightly different assessment.\n\nI would also like to refer you to the audiology department for a formal hearing test. This will give us a much more detailed picture of whether your hearing has been affected at all. The waiting time for this referral is usually around four to five weeks, so it is worth getting that in motion now.\n\nIn the meantime, the most important thing is to give your ears a rest from loud noise. Please try to avoid further exposure — concerts, loud music through headphones, or prolonged use of earphones at high volume. If you cannot avoid noisy environments entirely, wearing earplugs or noise-reducing headphones will protect your hearing and reduce the risk of worsening the tinnitus.\n\nMany people find it helpful to have some gentle background sound around them, especially at night — things like a fan running quietly, soft music in the background, or a white noise machine. This gives the brain something else to focus on and reduces how much attention you notice the ringing. Relaxation techniques and mindfulness can also help, as stress and tiredness tend to make tinnitus feel more intense.\n\nPlease come back and see us straight away if the tinnitus becomes pulsatile — meaning it starts to beat in time with your heartbeat — or if it becomes only one-sided, or if you develop dizziness, weakness, headaches, or any other new symptoms. And if at any point the tinnitus or the disruption to your sleep is making you feel very low, anxious, or having any thoughts of harming yourself, please call us, contact NHS 111, or dial 999 if you feel unsafe. You do not have to manage that alone.',
  ARRAY['Tinnitus is the perception of sound in the absence of an external stimulus; noise-induced tinnitus is a common cause and occurs after exposure to excessive sound levels, such as concerts or prolonged headphone use at high volume','Key red flags requiring same-day ENT referral include sudden-onset pulsatile tinnitus (possible vascular abnormality), tinnitus following head trauma, sudden hearing loss within 30 days, and neurological features such as facial weakness or acute vertigo','All patients with tinnitus should be offered audiological assessment — a formal hearing test helps identify noise-induced hearing loss and guides management including hearing aids if appropriate','Ototoxic drugs that can cause or worsen tinnitus include aspirin and NSAIDs, loop diuretics (furosemide, bumetanide), aminoglycosides (gentamicin), macrolides (erythromycin), antimalarials (quinine, chloroquine), cytotoxic agents (cisplatin), and valproate','Self-management strategies include avoiding further loud noise exposure, using ear protection, sound therapy with low-level background noise, relaxation techniques, mindfulness, and tinnitus-focused CBT','Safety-net advice must include seeking urgent help if tinnitus worsens, becomes one-sided or pulsatile, or if associated distress leads to low mood or suicidal ideation — particularly important given this patient''s background of schizophrenia'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  83,
  'Acute Rash In An Unwell Child',
  'Paediatrics',
  'Telephone consultation',
  false,
  'Luca Marchetti',
  '5-year-old male',
  ARRAY[]::text[],
  ARRAY['No known drug allergies','Not on any regular medications','Patient is up to date with his immunisations'],
  'Seen by Hannah Stead (Paediatric Nurse Practitioner) 9 months ago. Patient presented with cough and fever of 3 days'' duration. No red flags. On examination: HR 112 bpm, SpO2 99% on air, Temp 36.6°C, RR 24 cpm. Chest clear. Impression: Viral URTI. Plan: Reassure, safety-netting and worsening advice given.',
  'Mother called urgently to discuss concerns about a rash that has appeared on her son''s body this morning.',
  'Hello doctor, it''s Luca''s mum here. I''m a bit worried — Luca woke up this morning with a rash on his chest and tummy, and I''m not sure what''s causing it.',
  'You are Francesca Marchetti, the mother of Luca. Yesterday he developed a fever and a runny nose. This morning you noticed a rash on his chest, tummy, and both arms. The rash is not itchy. If specifically asked about the glass test, say: you pressed a glass against the rash and it faded away completely.',
  ARRAY['Right now Luca is lying on the sofa watching cartoons and seems more settled than he was earlier','His temperature was 38.0°C about an hour ago but seems to have come down a little since then','He is eating, drinking, and doing wet nappies as normal','No one else at home is unwell and you have not heard of anyone at his school or nursery being poorly','He last went to school yesterday morning','You have two other children at home — an 8-year-old and a 3-year-old — neither of whom are unwell'],
  'You live at home with your two other children. You are a single parent. Your mother lives nearby and can sometimes help, but she is away visiting family in Italy this week and will not be back until the day after tomorrow. You do not have a car. You cannot afford a taxi at the moment as you are waiting for your wages to come through.',
  'You are not sure what has caused the rash.',
  'You are worried it could be something serious like meningitis. Your cousin''s child had meningitis a few years ago, which is why you are particularly anxious.',
  'You would like the doctor to explain what the rash might be and whether Luca needs antibiotics or any other treatment.',
  ARRAY['If the doctor asks you to bring Luca in today, explain that you cannot come in this evening. You do not have a car, you cannot afford a taxi right now, and you have no one to help you this evening as your mother is away in Italy. You have two other young children at home. Politely but firmly block any avenue for a face-to-face consultation today.'],
  '"What do you think has caused this rash?" and "I gave Luca some Calpol about twenty minutes ago but he was sick straight after — is it safe to give him another dose now?"',
  'Say no to any other questions not covered in the information already provided.',
  ARRAY['Ask when the rash first appeared — this helps assess acuteness and possible infectious causes','Ask where on the body the rash is located — localised versus widespread helps narrow the differentials','Ask whether anyone at home or at school has had a similar rash or any viral illness recently, to assess for a contagious cause','Ask whether the rash is itchy — helps distinguish viral from allergic causes','Ask whether Luca has had a fever — viral rashes are commonly accompanied by fever','Ask whether pressing on the rash makes it disappear — if it fades, it is blanching; if it stays, it is non-blanching. The glass test can be used: press a clear glass firmly onto the skin and observe','Ask where Luca is now and what he is doing — if the parent says he is asleep, ask whether he has been unusually drowsy','Ask how Luca is in general — is he eating, drinking, and passing urine normally?','Ask about associated symptoms: headache, neck stiffness, or sensitivity to light (red flags for meningitis); cough, sore throat, or runny nose (viral symptoms); vomiting or diarrhoea; abdominal pain; joint pain or swelling','Ask about the home situation — who is at home, whether anyone else is unwell, and about recent travel or school attendance','Ask about immunisation status and developmental history (PBIND)','Explore the parent''s ideas, concerns, and expectations — what do they think is going on, and what are they hoping will happen from this call?','Give a working diagnosis of a likely viral rash and explain this clearly to the mother, while acknowledging the anxiety around meningitis and describing what features would raise concern'],
  ARRAY['Offer a face-to-face appointment if the child is able to attend','If the mother is unable to bring the child in today, offer to book an appointment for the following morning and provide reassurance that, based on the description, this is most likely a viral rash — common in young children fighting off a mild infection and usually not serious','Advise the mother to monitor Luca closely and encourage him to drink plenty of fluids. Recommend paracetamol (Calpol) for fever or discomfort','Advise that if Luca vomited shortly after taking a dose of paracetamol, she should not repeat the dose — wait for the next scheduled time. Explain that it is impossible to know how much was absorbed, and repeating too soon risks overdose. Paracetamol has a narrow therapeutic window and excess can cause severe liver damage. Ibuprofen can be used as an alternative, but check there is no history of asthma. Both paracetamol and ibuprofen can be used together, but doses should be staggered — wait at least 1 hour after the first dose before giving the second, particularly if fever or discomfort persists','Reassure the parent that Luca can be safely observed at home overnight provided there are no red flags','Safety-net thoroughly: advise the mother to seek urgent help — call 999 or go to A&E immediately — if Luca develops a rash that does not fade when pressed with a glass, becomes very drowsy or impossible to wake, develops a high fever that does not settle with paracetamol or ibuprofen, has neck stiffness or sensitivity to light, develops fast or laboured breathing, has cold hands and feet or pale or mottled skin, refuses to drink, or is vomiting repeatedly','Offer a follow-up appointment the next day to reassess Luca in person'],
  'Thank you so much for calling in today — you are absolutely doing the right thing by getting in touch, and I completely understand why seeing a rash on Luca has made you anxious, especially given what happened with your cousin''s child.\n\nBased on everything you''ve described to me, the most likely explanation for what Luca has is something called a viral rash. These kinds of rashes are very common in young children when their immune system is fighting off a mild infection — they often appear alongside a fever and a runny nose, exactly as you''ve described. The rash tends to be widespread, it''s not itchy, and crucially, it fades when you press on it — which is exactly what you found with the glass test. That is a really important and reassuring sign.\n\nI know meningitis is at the front of your mind, and I want to take that concern seriously. In meningitis, children are typically very unwell — they are often very difficult to rouse, floppy, or drowsy, they may have a stiff neck, be very sensitive to light, or have a severe headache. And the key thing with meningitis is that the rash does not fade when pressed — it stays put even under a glass. From everything you''ve told me, Luca is watching cartoons, drinking normally, and his rash disappeared with the glass test. None of that fits with meningitis, which is genuinely reassuring.\n\nI would still like to see him in person tomorrow morning to have a proper look and make sure everything is as it should be. I''ll get that appointment booked for you now.\n\nIn the meantime, there are a few practical things. Keep encouraging him to drink — small amounts regularly is fine. For the fever and any discomfort, you can give him Calpol. Now, regarding the dose he just vomited — do not give another dose straight away. We cannot know how much he actually absorbed before he was sick, and paracetamol is very safe at the right dose but can damage the liver if too much is taken. Please wait until the next scheduled dose time. If you still need something for his fever in the meantime, ibuprofen is fine to use as an alternative as long as he has no history of asthma. You can actually use both paracetamol and ibuprofen together, but stagger them — wait at least an hour after giving one before trying the other.\n\nMost importantly, I need you to watch out for the following warning signs tonight. Please call 999 or go straight to A&E immediately if: the rash changes and no longer fades when you press a glass on it; Luca becomes very difficult to wake or seems floppy or unusually drowsy; his fever does not come down with medicine; he develops a stiff neck or seems very sensitive to light; his breathing becomes fast or laboured; his hands or feet feel cold or his skin looks pale or blotchy; or if he refuses to drink or keeps vomiting. I am going to send you a text message right now with all of these warning signs so you have them written down.\n\nOtherwise, I will see Luca tomorrow morning. Please do not hesitate to call back at any time tonight if you are worried.',
  ARRAY['A blanching rash — one that fades when a glass is pressed firmly against the skin — is generally reassuring and more consistent with a viral cause; a non-blanching rash is a red flag for meningococcal sepsis and requires immediate emergency referral','Viral rashes in children are common, typically accompany mild febrile illness, are often widespread and non-itchy, and resolve without treatment — reassurance and safety-netting are the cornerstones of management','If a child vomits a dose of paracetamol shortly after taking it, the dose should not be repeated immediately — the amount absorbed is unknown and repeating too soon risks overdose. Paracetamol has a narrow therapeutic window and excess intake can cause severe and delayed liver failure','Paracetamol and ibuprofen can be used together in children, but doses should be staggered by at least 1 hour. Ibuprofen should not be used in children with asthma','Red flag symptoms requiring immediate 999 or A&E attendance include a non-blanching rash, unusual drowsiness or difficulty rousing, persistent high fever, neck stiffness, light sensitivity, fast or laboured breathing, cold extremities, pale or mottled skin, refusal to drink, or repeated vomiting','This case highlights the importance of managing clinical uncertainty safely over the telephone: when a face-to-face review is not immediately possible, thorough safety-netting with written red flag advice and a booked follow-up appointment for the next day is an appropriate and safe approach'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  84,
  'Depression In A Teenager',
  'Mental Health',
  'Video Consultation',
  false,
  'Emma Bradley',
  '15-year-old female',
  ARRAY['No significant past medical history'],
  ARRAY[]::text[],
  'Routine video consultation booked by the patient''s mother on behalf of the patient. No previous consultations recorded.',
  'Consultation booked by patient''s mother to discuss concerns about her daughter''s emotional wellbeing.',
  'Hi. My mum booked this appointment. I''ve been struggling with some things for a few months and I wasn''t sure who to talk to.',
  'You are Emma, a 15-year-old student in Year 10. You have come today because you have been self-harming — cutting your arms and thighs — for the past three to four months. It started as a way to manage feelings of being overwhelmed. The cuts are getting deeper. You have been bullied at school for the past year and it has left you feeling worthless and isolated. You have not told your parents because you are scared they will be upset or angry with you.',
  ARRAY['You self-harm when you feel overwhelmed and do not know how else to cope. You have tried to stop but find it very hard','You have been sleeping poorly, not eating much, and feeling exhausted most days','You often feel very alone and anxious about school and social situations','You do not have any thoughts of wanting to end your life or hurt yourself in any way other than the cutting','You last self-harmed about a week ago and the injury has fully healed — there are no open wounds and no active bleeding'],
  'You live at home with your mum and your dad. You have a younger brother aged 12. You do not smoke, drink, or use any substances.',
  'You feel that self-harming is the only thing that makes the emotional pain bearable and you worry there is no other solution.',
  'You are frightened by how deep the cuts are getting and worried that one day you might go too far. You are scared your parents will find out and that they will not understand.',
  'You are hoping the doctor can offer you support and help you find other ways to cope without needing to hurt yourself.',
  ARRAY[]::text[],
  '"How can I stop self-harming?"',
  'Say no to any other questions not already covered in the scenario. Accept anything offered by the doctor.',
  ARRAY['Ask why Emma feels she has been self-harming and what tends to trigger it','Explore the bullying situation in more detail: ask how long it has been going on, how frequent it is, and what form it takes — for example, physical, verbal, social exclusion, or online bullying','Ask whether Emma has told anyone about the bullying — her parents, a teacher, or anyone else','Ask about her mood — how has she been feeling overall, and how has the bullying affected her emotionally?','Ask, sensitively and clearly, whether aside from self-harm she has ever had thoughts of harming herself in a more serious way, or any thoughts of ending her life','Ask how she feels after she has self-harmed — does it make her feel better, worse, or the same?','Ask when she last self-harmed and whether she currently has any active injuries, bleeding, or open wounds','Ask about her home situation — who does she live with and how are things at home?','Ask about school — has her attendance or her grades been affected?','Ask about smoking, alcohol, or any substance use','Explore her ideas, concerns, and expectations — what does she think is going on, what worries her most, and what is she hoping the doctor can help with?','Provide a working diagnosis of depression likely caused by persistent bullying, expressed through self-harming behaviour as a coping mechanism'],
  ARRAY['Reassure Emma that you understand self-harm is currently helping her manage overwhelming emotions, and that you are not here to judge her','Advise her to tell a trusted adult — ideally her parents — about the bullying, and encourage her parents to then report it to the school formally','Explain that bullying is never acceptable, and that once it is reported the school has a duty to put measures in place to keep her safe','Suggest distraction techniques and emotional release strategies as safer alternatives to self-harm — for example: writing feelings in a private journal or as unsent letters without worrying about grammar; creating a mood playlist; practising mindfulness. Offer to send links to resources that explain these techniques','Advise Emma and her parents to remove or secure sharp objects from her immediate environment at home','Refer Emma to CAMHS (Child and Adolescent Mental Health Services) and a children''s CBT service, who will also develop a tailored self-harm prevention strategy for her','Safety-net: discuss warning signs and advise her to seek urgent help if she has any thoughts of suicide or if she inflicts a serious or worsening injury on herself. Note: if she has any actively bleeding wound from self-harm, she should go directly to A&E. If there is an open but non-bleeding cut, it should be assessed and dressed at an urgent treatment centre or by the practice nurse','Arrange a follow-up appointment in 2 weeks to review progress — including whether the bullying has been reported to school and how she is getting on with distraction techniques'],
  'Thank you for coming today and for being so honest with me. I know it takes real courage to talk about something this personal, especially when you have been carrying it on your own for so long. I want you to know that you are not in trouble, and I am not here to judge you.\n\nFrom everything you have shared with me, Emma, it sounds like you have been going through an incredibly difficult time. Being bullied for a whole year, feeling isolated, not sleeping or eating properly, and feeling worthless — that is a lot for anyone to carry, let alone at your age. What you are describing, including the low mood, exhaustion, and withdrawing from things, sounds like depression. And the self-harm — the cutting — sounds like the way your mind has found to release some of that pain when it all gets too much to bear. That makes sense as a response to what you have been going through, even though I know it worries you that the cuts are getting deeper.\n\nThe fact that you are here today, talking about this, is really important. It means you want things to be different — and they can be. The self-harm is not something you have to manage on your own, and there are much safer ways I want to help you find to deal with these feelings.\n\nOne of the most important things we can do right now is to make sure that the bullying is dealt with properly. Bullying is not acceptable, and schools have a real responsibility to protect their students. I would really encourage you to tell your parents what has been happening — both the bullying and the self-harming. I understand that feels frightening, and I know you are worried about how they will react. But parents, when they understand what is going on, almost always want to help. Once they know, they can speak to the school and make sure proper action is taken to keep you safe.\n\nI would also like to refer you to a specialist team called CAMHS — the Child and Adolescent Mental Health Service. They are a group of professionals who specialise in helping young people with exactly what you are going through. They will also help put together a proper plan to support you in finding other ways to cope when things feel overwhelming. Some ideas to start trying in the meantime — when you feel the urge to cut, try writing down how you are feeling in a journal, even if it is messy and makes no sense. Or create a playlist of music that matches or lifts your mood. Mindfulness breathing exercises can also help your body calm down when emotions feel too big. I can send you some links with more ideas if that would be helpful.\n\nOne thing I would like to ask your parents to do is to put any sharp objects at home somewhere less accessible to you — not because you are being punished, but just to create a little more distance between you and the urge when it is strong.\n\nFinally, I want to make sure you know what to do if things ever feel much worse — particularly if you ever have any thoughts of ending your life or hurting yourself seriously. Please speak to a parent, a teacher, call NHS 111, or in an emergency dial 999. You do not have to manage a crisis alone. And if you ever have a cut that is actively bleeding, please go to A&E straight away.\n\nI would like to see you again in two weeks to see how things are going — whether the bullying has been reported, how you are getting on with the distraction techniques, and how you are feeling overall.',
  ARRAY['Self-harm in adolescents is often used as a coping mechanism for emotional overwhelm — it should be approached with non-judgement; understanding the triggers and function of the behaviour is essential before addressing management','A full risk assessment is essential: ask directly about suicidal ideation, the frequency and severity of self-harm, the depth of any injuries, and whether there are currently any open wounds. Active bleeding requires immediate A&E referral','Bullying-related depression in teenagers should prompt referral to CAMHS and a children''s CBT service; parents should be advised to formally report bullying to the school, which has a duty to ensure the student''s safety','Distraction and emotional regulation techniques — journalling, mood playlists, mindfulness — can offer safer alternatives to self-harm and should be offered as part of a practical safety plan alongside the CAMHS referral','Environmental safety advice is important: parents should be advised to secure or remove sharp objects from the home environment to reduce access during moments of impulse','Safety-net advice must cover three escalation pathways: active bleeding from self-harm goes to A&E; open but non-bleeding wounds go to an urgent treatment centre or practice nurse; any suicidal ideation should prompt immediate contact with crisis services, NHS 111, or 999'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  85,
  'Unexplained Weight Loss In A Young Adult',
  'Elderly Medicine & Palliative Care',
  'Telephone consultation',
  false,
  'Adam Clarke',
  '28-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  'Patient booked routine consultation to discuss concerns.',
  'Patient called to discuss symptoms he has been experiencing over the past couple of months.',
  'Hi doctor, thanks for calling. I''ve been feeling really run down for the past couple of months and I''m not sure what''s going on.',
  'I''ve just been exhausted no matter how much sleep I get — it''s been going on for about 8 to 10 weeks now. It''s really starting to affect my work.',
  ARRAY[
    'I''ve lost about 6 kilograms without changing my diet or doing anything differently.',
    'I''ve been waking up at night completely soaked in sweat, which is very unusual for me.',
    'My appetite has not been great lately — I just don''t feel like eating much.'
  ],
  'Adam works full-time at a technology company and usually copes well with day-to-day pressure, though this prolonged tiredness has begun to affect his output and his manager has noticed a drop in his performance. He has smoked 5 to 10 cigarettes a day for the past 5 years. He lives alone and is not currently in a relationship. Family history: His father died of cancer, though Adam does not know the type as his parents separated when he was young and he had little contact with his father.',
  'Not entirely sure — I just know something doesn''t feel right.',
  'I''m quite worried about the weight loss — it''s happened quite quickly without me trying.',
  'I''d like to understand what might be causing all of this and find out if there is something that can be done.',
  ARRAY[]::text[],
  'Ask the doctor what is causing these symptoms. Mention that you are due to travel to France for 3 weeks for a tech summit organised by your company and ask whether it would be sensible to postpone the trip.',
  'Decline to answer any questions outside the details already provided.',
  ARRAY[
    'Explore the presenting symptoms thoroughly — ask about the nature and duration of fatigue, whether it has worsened over time, and whether rest improves it.',
    'Ask directly about unintentional weight loss, including how much weight has been lost and over what time frame.',
    'Ask about night sweats — frequency, severity, and whether the patient wakes up drenched.',
    'Screen for other B symptoms: fevers, itching, or rashes.',
    'Ask about appetite and any change in bowel habit.',
    'Explore visual symptoms, lymph node swelling, or any lumps noticed by the patient.',
    'Ask about smoking history, alcohol use, recreational drug use, and sexual health.',
    'Explore family history of cancer or other serious illness.',
    'Ask about the patient''s ideas, concerns, and expectations.',
    'Acknowledge the patient''s concern about the upcoming travel and address this sensitively.',
    'Formulate a differential diagnosis including: lymphoma, hyperthyroidism, tuberculosis, HIV, and other malignancy.'
  ],
  ARRAY[
    'Offer a face-to-face appointment to examine for lymphadenopathy, assess for organomegaly, listen to the chest, and check for any other clinical signs.',
    'Arrange urgent blood tests including full blood count, erythrocyte sedimentation rate, CRP, LDH, uric acid, thyroid function tests, HIV test, liver function tests, and renal function.',
    'Advise the patient to try to maintain regular meals and adequate hydration.',
    'Offer a sick note or a supportive letter for his employer if needed.',
    'Arrange to review blood results within 48 hours and inform the patient that further investigations or onward referral will be guided by findings.',
    'Regarding travel: advise that given the need for urgent investigation, it would be wise to defer the trip until a clearer picture is established — offer to provide a letter for his employer or travel insurance if required.',
    'Safety net: advise Adam to seek urgent medical attention if he develops high fevers, difficulty breathing, severe pain, or any new or rapidly worsening symptoms.'
  ],
  'It sounds like you''ve been through quite a difficult few weeks, and it''s really good that you''ve called in today to talk about this. Adam, I want to be straightforward with you because I think that''s the most helpful thing I can do.

The combination of symptoms you''re describing — the persistent fatigue that doesn''t improve with sleep, the 6 kilograms of unintentional weight loss, and waking up drenched in sweat at night — are things we take very seriously in medicine and want to investigate promptly. These are sometimes called ''B symptoms'', and while they can have a number of causes, we need to rule out some important ones.

One possibility is an overactive thyroid gland — the thyroid sits in the neck and controls the body''s metabolism. When it becomes overactive, it can cause weight loss, fatigue, and sweating. This is treatable and relatively straightforward to pick up with a blood test.

Another possibility I want to be honest with you about is a type of cancer called lymphoma. Lymphoma affects the lymphatic system — part of the immune system — and the symptoms you''ve described can be associated with it. I want to stress that this is one of several possibilities, not a certainty, and many people with these symptoms turn out to have something less serious. However, given how important it is not to miss this if it is present, we need to investigate urgently.

What I''d like to do first is arrange an urgent set of blood tests today. These will look at a wide range of things including your blood cell counts, inflammation markers, thyroid function, and some other markers that can give us important clues. I''d also like to see you in person so I can carry out a physical examination — in particular, I''d like to feel for any swollen lymph nodes and check your chest and abdomen. I''ll review your results within 48 hours and contact you as soon as they are back.

Regarding your trip to France — I understand how significant this is professionally, and I don''t want to cause unnecessary disruption. However, given that we need to investigate these symptoms urgently, I would strongly advise deferring the travel until we have a clearer picture. If you need a letter for your employer or your travel insurance company, I''m very happy to provide one to support you.

In the meantime, please do try to eat regular meals, even small ones, and stay well hydrated. If at any point before we speak again you develop a high fever, difficulty breathing, severe pain, or any new and worrying symptoms, please don''t wait — go to A&E or call 999 straightaway. We''re going to get to the bottom of this, and I''ll be in touch very soon.',
  ARRAY[
    'Unintentional weight loss, drenching night sweats, and fatigue together constitute classic ''B symptoms'' and should always prompt urgent investigation to exclude lymphoma and other serious pathology.',
    'A broad differential for B symptoms includes lymphoma, hyperthyroidism, tuberculosis, HIV, and other malignancy — blood tests should be targeted accordingly (FBC, ESR, CRP, LDH, TFTs, HIV screen).',
    'Travel plans should be sensitively but firmly addressed when urgent investigation is pending — offer a supporting letter for employers or insurers.',
    'Offer both a face-to-face examination for lymphadenopathy and organomegaly alongside urgent bloods, rather than relying solely on telephone assessment.',
    'Safety-netting is essential: patients should be given clear criteria for seeking urgent care (high fever, breathlessness, severe pain, rapidly worsening symptoms) and a definite follow-up plan within 48 hours of results.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  86,
  'New Diagnosis Of Type 2 Diabetes',
  'Endocrine & Nephrology',
  'Video consultation',
  false,
  'Tariq Hassan',
  '58-year-old male',
  ARRAY['Hypertension'],
  ARRAY['Ramipril 5mg once daily','No Known Drug Allergy'],
  'Seen by Dr S. Patel (Clinical Practitioner role) 2 weeks ago. Presenting complaint: Patient reports feeling tired all the time and occasional urinary frequency for 3 months. No other lower urinary tract symptoms. No thirst. No weight changes. Examination: BP 135/85 mmHg, SpO₂ 99% on air, Temperature 36.5°C, Respiratory rate 16 breaths per minute. Urine dip showed glucose 2+ with other parameters normal. Prostate examination normal. BMI 34.5. Capillary glucose 12 mmol/L. Impression: Suspected diabetes. Plan: Blood tests requested. Safety net advice given. Blood Test Results (2 days ago): HbA1c: 53 mmol/mol. Total cholesterol: 6.08 mmol/L. QRISK: 13.5%. Urea and electrolytes, thyroid function tests, liver function tests, CRP, ESR, and full blood count all within normal limits.',
  'Patient has booked an appointment to discuss his recent blood test results.',
  'Hello doctor, I''ve come in today to go over my blood test results from last week.',
  'I''ve been exhausted for about three months and I''ve been passing urine more often than usual, though not constantly. I saw a doctor who checked my urine and found sugar in it and arranged some blood tests.',
  ARRAY[
    'You do not have any other symptoms.',
    'Your diet is not very healthy — you eat a lot of takeaway food because of how busy you are at work, and at home you tend to eat a lot of carbohydrate-rich meals.'
  ],
  'Tariq is married with four children. He does not smoke or drink alcohol. He works as a delivery driver. Family history: His father had diabetes and needed dialysis in later life.',
  'You suspect you may have diabetes.',
  'You are worried because your father had serious complications from diabetes and you do not want to end up in the same situation.',
  'You would like the GP to explain what the blood test results mean. If offered medication, you want to ask how you can manage your diabetes during Ramadan, particularly regarding whether and how to take your tablets while fasting, as you are a Muslim.',
  ARRAY[]::text[],
  NULL,
  'Decline to answer any questions or describe any symptoms outside the details already provided.',
  ARRAY[
    'Acknowledge that you can see from the records that the patient was recently seen by a colleague and had blood tests arranged, but before going through results, take a brief focused history of the symptoms that prompted the tests.',
    'Ask about symptoms suggestive of diabetes and its complications, including blurred vision, increased appetite, increased thirst, shortness of breath, chest pain, urinary frequency, blood in the urine, tingling or numbness particularly in the feet or legs, and any non-healing wounds or ulcers, especially on the feet.',
    'Ask about any unintentional weight loss or weight gain.',
    'Explore social history including smoking, alcohol intake, diet, weight, occupation, and home circumstances.',
    'Ask about the patient''s ideas, concerns, and expectations.',
    'Deliver the diagnosis of type 2 diabetes clearly and sensitively, linking it to the HbA1c result of 53 mmol/mol.'
  ],
  ARRAY[
    'Advise on lifestyle changes including regular physical activity, gradual weight loss, and a healthy balanced diet.',
    'Advise a diet low in saturated fat and refined carbohydrates, including more oily fish, low-fat dairy, fruit, and vegetables. Offer to send written dietary information and, if further support is needed, offer referral to the practice dietitian.',
    'Explain that some people manage type 2 diabetes with lifestyle changes alone, but given that he is symptomatic and his HbA1c indicates a moderate level of hyperglycaemia, recommend starting medication alongside lifestyle measures.',
    'Offer modified release metformin 500 mg once daily and dapagliflozin 10 mg once daily.',
    'Explain that metformin will be started first; after approximately two weeks, once he has confirmed he is tolerating it without significant side effects, dapagliflozin will be introduced.',
    'Inform him of side effects: metformin can cause gastrointestinal upset including diarrhoea and nausea. Dapagliflozin can increase the risk of urinary tract infections and, rarely, a serious infection called Fournier''s gangrene affecting the genital and perineal area.',
    'Explain sick day rules: if he develops vomiting or diarrhoea, he should temporarily stop both medications and restart them 24 to 48 hours after he is eating and drinking normally again.',
    'Discuss Ramadan: advise that fasting is possible in many cases but requires planning. If his blood sugar is well controlled and his risk of hypoglycaemia is low, fasting can be considered. Both medications are once daily and can be taken in the evening after breaking the fast. A dedicated pre-Ramadan review will be arranged to assess control and personalise advice.',
    'Address his cholesterol and cardiovascular risk: total cholesterol is raised and QRISK is 13.5%. Offer atorvastatin 20 mg once daily for cardiovascular risk reduction. This will not be started immediately — once he is tolerating metformin, it can be introduced to minimise the burden of new side effects.',
    'Advise on annual diabetic review: retinal screening, foot checks, HbA1c, renal function, blood pressure, and cholesterol monitoring.',
    'Request a urine albumin-to-creatinine ratio (ACR) sample to screen for early diabetic nephropathy.',
    'Offer vaccinations including pneumococcal, influenza, and COVID-19 vaccines.',
    'Arrange follow-up in 3 months to reassess HbA1c and response to treatment.',
    'Safety net: advise him to seek urgent medical attention if he develops symptoms of diabetic ketoacidosis — feeling very unwell, excessive thirst, passing large volumes of urine, nausea or vomiting, abdominal pain, deep or rapid breathing, confusion, or a fruity smell to the breath. He should contact the surgery or call NHS 111 out of hours.'
  ],
  'Thank you for coming in today to go over these results — I can see this may bring up quite a bit to think about, so please do feel free to stop me at any point if you have questions. Before I go through the numbers, I want to briefly check in about how you''ve been feeling, as I think it helps to make sense of everything together.

Tariq, based on your blood test results and the symptoms you''ve been experiencing — the persistent tiredness and passing urine more frequently — I do need to tell you that the results indicate you have type 2 diabetes. Your HbA1c, which is the key marker we use to diagnose diabetes, came back at 53 mmol/mol. A reading at this level confirms the diagnosis. I want to say straight away that this is something that can be managed well, and many people live very healthy lives with type 2 diabetes.

I understand your worry about what happened to your father, and I want to reassure you that the complications he experienced — such as problems with his kidneys — are not inevitable. They tend to develop when diabetes is poorly controlled over many years. Because we are picking this up now and starting treatment early, we have a real opportunity to protect your health going forward.

In terms of treatment, I''d like to start you on two medications. The first is modified release metformin 500 mg, taken once a day. Metformin is a well-established, first-line treatment for type 2 diabetes and helps your body use insulin more effectively. Some people notice loose stools or nausea when starting it, which is why the modified release formulation and a low starting dose help to minimise this. After about two weeks, once we know you''re tolerating it well, I''d like to add a second tablet called dapagliflozin 10 mg once daily. This works in a different way and has the added benefit of protecting the kidneys and heart. It does carry a small risk of urinary tract infections, so I''ll make you aware of what symptoms to look out for.

Regarding Ramadan — I''m really glad you raised this, and it''s something we can absolutely plan around. Both tablets are taken once a day, so they can be shifted to the evening and taken when you break your fast. I''d like to arrange a dedicated appointment before Ramadan begins so we can go through your blood sugar control in detail and give you personalised guidance.

Your cholesterol is also a little elevated and your cardiovascular risk score suggests it would be worth starting a cholesterol-lowering tablet called atorvastatin 20 mg. We will not start this immediately — once you are settled on metformin, we will add it in, to make it easier to tell if any side effects relate to which tablet.

Going forward, you''ll be invited for a yearly diabetic review where we check your eyes, feet, kidneys, blood pressure, and cholesterol. I''d also like you to bring in a urine sample today if possible, so we can check your kidneys are not being affected.

One important thing to be aware of: if you ever feel very unwell, extremely thirsty, are passing large amounts of urine, are vomiting, or notice a fruity smell on your breath, please contact us or call NHS 111 straight away as these could be signs of a serious complication. Otherwise, let''s arrange a follow-up appointment in three months to see how you''re getting on with the medication and recheck your HbA1c.',
  ARRAY[
    'An HbA1c of 53 mmol/mol or above on a symptomatic patient confirms a diagnosis of type 2 diabetes — explain this clearly and link it to the patient''s presenting symptoms.',
    'First-line pharmacological management of type 2 diabetes with cardiovascular risk factors includes modified release metformin 500 mg once daily, with dapagliflozin 10 mg once daily added once metformin is tolerated.',
    'Sick day rules apply to both metformin and dapagliflozin — both should be temporarily stopped during illness with vomiting or diarrhoea and restarted 24–48 hours after normal eating resumes.',
    'Ramadan fasting is often achievable with careful planning — once-daily medications can generally be shifted to evening doses after iftar, and a pre-Ramadan review should be offered.',
    'Atorvastatin 20 mg once daily is recommended for cardiovascular risk reduction when QRISK exceeds 10% — stagger introduction of new medications to make side effect attribution easier.',
    'Annual diabetic review should include retinal screening, foot checks, HbA1c, renal function (including urine ACR), blood pressure, and cholesterol — and vaccinations (pneumococcal, influenza, COVID-19) should be offered at diagnosis.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  87,
  'Reflux Disease',
  'Gastroenterology & Haematology',
  'Telephone consultation',
  false,
  'Karen Sutton',
  '37-year-old female',
  ARRAY[]::text[],
  ARRAY[]::text[],
  'Referred for OGD due to persistent reflux symptoms. OGD Report: Patient Name: Karen Sutton. Age: 37-year-old. Date of Procedure: 20th March 2023. Indication: Epigastric pain, dyspepsia. Procedure: Oesophagogastroduodenoscopy (OGD). Findings: Oesophagus: consistent with gastroesophageal reflux disease (GERD). Stomach: gastritis. Duodenum: normal appearance; no signs of inflammation, ulceration, or abnormal mucosal findings in the D1 and D2 segments. Diagnosis: Gastroesophageal Reflux Disease (GERD) and Mild Gastritis. Recommendations: Start proton pump inhibitor (PPI) therapy for symptomatic relief for 4 weeks. Lifestyle and dietary modifications (e.g., avoiding NSAIDs, alcohol, and spicy foods). Endoscopist: Dr A. Mensah, Consultant Gastroenterologist. Report Date: 20th March 2023. Patient has booked a routine consultation to discuss these findings.',
  'Patient called to discuss the results of her recent camera test and to talk through her ongoing symptoms.',
  'Hi doctor, I''ve been having heartburn and stomach pain for a few weeks now and I had a camera test done — I was hoping we could go through the results together.',
  'The discomfort has been coming and going for about three weeks. It''s worse at night and I''m not always sure what sets it off, though I know I''ve been under a lot of stress lately.',
  ARRAY[]::text[],
  'Karen is a non-smoker and does not drink alcohol. She works as a ward manager in an oncology unit. She went through a divorce earlier this year, and has recently taken on a more senior role at work, which has come with a great deal of additional responsibility.',
  'She wonders whether this could be something more serious, like cancer.',
  'Karen works in oncology and has seen patients with similar-sounding symptoms who turned out to have cancer — this has made her particularly anxious about her own situation.',
  'She would like to have a camera test to know for certain what is going on.',
  ARRAY[]::text[],
  NULL,
  'Decline to describe any symptoms not already mentioned.',
  ARRAY[
    'Ask about the location and character of the pain or discomfort — whether it is burning in nature, and whether it radiates anywhere.',
    'Ask about potential triggers such as spicy food, fatty meals, coffee, chocolate, or alcohol, and whether anything makes it better.',
    'Ask about associated symptoms including bloating, nausea, vomiting, and whether food or acid comes back up into the throat.',
    'Screen for red flag features: dysphagia, unintentional weight loss, night sweats, persistent vomiting, haematemesis, and loss of appetite.',
    'Ask about diet and eating habits — whether she eats late at night or skips meals.',
    'Ask about mood and explore the recent stressors in her life, as psychological stress is a recognised trigger for GORD.',
    'Ask about over-the-counter medications such as ibuprofen or aspirin, which can exacerbate gastritis.',
    'Ask about recent weight changes.',
    'Explore social history: smoking, alcohol, occupation, and family situation.',
    'Explain the OGD findings and make a diagnosis of GORD with mild gastritis, clearly addressing her concern about cancer and reassuring her that no red flag features or sinister findings were identified on the endoscopy.'
  ],
  ARRAY[
    'Offer a proton pump inhibitor (PPI) for 4 weeks, or offer Helicobacter pylori testing first and then a 4-week course of PPI if negative.',
    'Counsel the patient on common side effects of PPIs including headache, diarrhoea, and nausea.',
    'Advise that stress can trigger and worsen reflux symptoms — suggest the Headspace app, which is available free of charge to NHS employees. This includes guided meditations led by clinical experts to help with stress management.',
    'Suggest mindfulness as an additional strategy for managing stress.',
    'Advise dietary and lifestyle modifications: avoid spicy food, fatty food, and eating late in the evening; try to eat smaller meals and remain upright for at least two to three hours after eating.',
    'Advise on the benefits of weight loss if BMI is elevated.',
    'Safety net: advise the patient to seek urgent medical attention if she develops difficulty swallowing, vomiting blood, significant unexplained weight loss, or persistent vomiting.',
    'Arrange follow-up in 4 weeks to review symptom response to treatment.'
  ],
  'Thank you for calling in today — I can completely understand why you''ve been anxious about this, particularly given what you see at work every day. Let me go through the camera test results with you and hopefully put your mind at rest on the most important point first.

Karen, the good news is that the endoscopy did not find any signs of cancer. What it did show is something called gastroesophageal reflux disease — GORD for short — along with some mild gastritis, which is a little inflammation of the stomach lining. These are both common and treatable conditions, and I want to reassure you that there were no worrying or sinister findings.

GORD happens when the acid from your stomach travels back up into your oesophagus — the tube connecting your mouth to your stomach. This causes that burning sensation in the chest and the discomfort you''ve been noticing, particularly at night when you''re lying down. Gastritis simply means the stomach lining is a little irritated, and this often goes hand-in-hand with reflux.

I think it''s worth acknowledging that the stress you''ve been going through — the divorce, and the added pressures of your new role — can genuinely make reflux worse. Stress increases acid production and can affect gut motility, so it''s not just in your head; there is a real physical link. I''d like to tackle both the physical symptoms and the stress element together.

For the reflux and gastritis, the endoscopy team have recommended a four-week course of a medication called a proton pump inhibitor — a PPI — which works by reducing the amount of acid your stomach produces. This should significantly ease the heartburn and discomfort. I may also want to check first for a bug called Helicobacter pylori, which can contribute to gastritis, before starting the tablet.

Alongside the medication, a few changes to your routine can make a real difference: try to avoid spicy or very fatty foods, don''t eat too late in the evening, and try to stay upright for a couple of hours after meals. If you do take ibuprofen for any reason, it''s worth switching to paracetamol instead, as anti-inflammatories can aggravate the stomach lining.

For the stress side of things, I''d actually recommend the Headspace app — it''s available completely free for NHS staff and has some really well-regarded guided meditations and mindfulness exercises. Many people find it genuinely helpful.

I''d like to check in with you in four weeks to see how you''re getting on. If in the meantime you develop any difficulty swallowing, bring up blood, or have significant unintentional weight loss, please contact us straight away or go to A&E — though based on everything today, I have no reason to expect that.',
  ARRAY[
    'GORD and gastritis are common, treatable conditions — OGD is the gold standard for diagnosis and can provide important reassurance when red flag features such as dysphagia or haematemesis are absent.',
    'Stress is a recognised physiological trigger for GORD and should be addressed alongside pharmacological treatment; the Headspace app is available free to NHS staff as a mindfulness resource.',
    'First-line treatment for GORD is a 4-week course of a PPI; consider testing for Helicobacter pylori first and treating if positive before committing to long-term acid suppression.',
    'Advise patients to avoid NSAIDs, alcohol, spicy and fatty foods, and late-night eating — lifestyle modification is a key part of GORD management.',
    'Safety-netting must include red flag symptoms that warrant urgent reassessment: dysphagia, haematemesis, significant unintentional weight loss, and persistent vomiting.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  88,
  'Safeguarding Concern In Older Adult',
  'Ethics',
  'Telephone consultation',
  false,
  'Mrs. Janet Morris',
  '65-year-old female',
  ARRAY[]::text[],
  ARRAY[]::text[],
  'Caller is Mrs. Patricia Hughes, a neighbour of Mrs. Janet Morris, who she believes is a registered patient at this surgery. She is calling to report concerns about potential abuse.',
  'Neighbour calling to report a safeguarding concern about a patient she believes is registered at the practice.',
  'Hello, I hope I''m through to the right place. I''m calling because I''m worried about my neighbour, Janet Morris — I think she''s one of your patients. I''ve been seeing some things that have really been playing on my mind.',
  'I''ve been friends with Janet for a number of years and I''ve noticed some changes recently that are worrying me. It''s her husband — I''ve heard him shouting at her quite harshly on several occasions, and last week I saw him physically push her. She seems very anxious and withdrawn whenever he''s around.',
  ARRAY[]::text[],
  '',
  '',
  'You are worried that Janet may be experiencing emotional and physical abuse from her husband. You have already encouraged her to speak to her GP but she refused. You are unsure whether she feels safe enough to seek help independently, and you want to make sure your concerns are handled carefully without making things worse for her.',
  'You are hoping the GP can look into this discreetly and offer support to Janet. You want to know what you can do as a neighbour to help her, and you want her situation to be handled sensitively.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Thank the caller for contacting the surgery and acknowledge that it takes courage to raise these concerns about someone you care about.',
    'Gather details about the nature and frequency of the concerns — what has been seen and heard, and over what period of time.',
    'Ask whether the caller has spoken directly to Janet about her concerns and, if so, what Janet''s response was.',
    'Ask whether Janet appears to have freedom of movement and social contact, or whether she appears isolated or dependent.',
    'Explore whether there are any concerns about her physical health or any visible injuries.',
    'Clarify the caller''s relationship with Janet and how well she knows the household situation.',
    'Ask whether the caller has any reason to believe Janet is in immediate danger at the present time.',
    'Explain the limits of confidentiality clearly and sensitively: while you cannot discuss Janet''s medical records or confirm whether any action will be taken, her safety is the surgery''s priority and there are processes in place to follow up on concerns like this.',
    'Acknowledge and validate the neighbour''s concern throughout the conversation.'
  ],
  ARRAY[
    'Ask whether Mrs. Hughes feels she is able to gently encourage Janet to attend the surgery for a general health review — this can provide an opportunity to speak with her privately.',
    'Explain that in situations like this, the practice would normally contact the patient directly — for example, inviting her for a routine health check — which allows the GP to assess her wellbeing and create a safe space for a private conversation without alerting those who may be causing harm.',
    'If Janet does not respond to an invitation or attend, explain that the practice can follow up by telephone or letter, or arrange a home visit to assess the situation more directly.',
    'Explain that the practice works closely with social services, who can also visit the home independently to assess the situation and offer support.',
    'Thank the neighbour and acknowledge the value of her support: having a caring and attentive neighbour who continues to offer friendly check-ins and small acts of kindness can make a significant difference to someone in Janet''s position.',
    'Safety net: advise Mrs. Hughes that if at any point she believes Janet is in immediate danger, she should call 999 without hesitation — timely intervention by emergency services could be critical.'
  ],
  'Thank you so much for calling and for taking the time to share this — it''s clear that you care a great deal about Janet, and it really does matter that people like you speak up when something doesn''t feel right.

I want to be honest with you about one thing straight away: because of patient confidentiality, I''m not able to discuss Janet''s medical records with you or share information about any steps we might take. I hope you understand that this rule exists to protect patients, including Janet herself. What I can tell you is that we take concerns like the ones you''ve raised very seriously, and that her safety and wellbeing are our priority.

What you''ve described — the shouting, the physical push you witnessed, and the way Janet seems anxious and withdrawn around her husband — are all things that concern us too. Domestic abuse in older adults is unfortunately underreported, and it can be difficult for those experiencing it to reach out, particularly if they feel they have limited options or are worried about the consequences.

In situations like this, our usual approach would be to contact the patient — often by inviting her in for what looks like a routine health check or a general review. This gives us the chance to speak with her privately, away from home, in a safe environment where she can talk openly if she chooses to. We would never do this in a way that might alert or alarm her husband.

If she doesn''t respond to that kind of invitation, we can also arrange for someone to visit at home, or we can involve social services, who have their own powers to visit and assess independently. They are experienced in handling these situations with great sensitivity.

As for what you can do — honestly, having someone like you nearby who she trusts can make an enormous difference. Simply continuing to be a friendly presence, checking in on her, and making sure she knows you are there without putting pressure on her is genuinely valuable. People in difficult situations often need time before they feel ready to accept help.

Finally, if you ever believe Janet is in immediate danger — if you hear or see something that makes you fear for her safety in that moment — please call 999 straight away. Do not hesitate. Your instincts matter, and emergency services are there precisely for situations like that.',
  ARRAY[
    'Safeguarding concerns about older adults should always be taken seriously — physical, emotional, and financial abuse are underreported and may be difficult for the patient to disclose voluntarily.',
    'Confidentiality must be clearly explained to third-party callers: you cannot confirm whether the patient is registered, share records, or disclose planned actions — but reassure the caller that concerns will be taken seriously.',
    'A common and effective first step is inviting the patient for a routine health check, creating a safe, private opportunity for the GP to assess wellbeing and open a conversation without alerting the alleged abuser.',
    'Social services can be involved to carry out an independent home assessment — this is an important escalation pathway and does not require the patient''s consent when there is risk of significant harm.',
    'Neighbours and informal carers play a valuable role in safeguarding — validate their concern, thank them for calling, and advise them to call 999 immediately if they believe the patient is in imminent danger.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  89,
  'Allergic Reaction After Food Ingestion',
  'Dermatology',
  'Telephone consultation',
  false,
  'Raymond Okafor',
  '52-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  'Patient has booked an urgent appointment to discuss a recent allergic reaction.',
  'Patient calling to discuss an allergic reaction he experienced two days ago following a meal at a restaurant.',
  'Hi doctor, I''m calling because I had quite a bad reaction after eating out a couple of days ago and I''m still a bit shaken by it — I wanted to get some advice.',
  'Two days ago I went to a Thai restaurant and had a dish that I think contained shellfish. Shortly after eating, my lips and eyes started to swell up and I came out in a very itchy rash all over my body. I took some Cetirizine — an antihistamine I had at home — and the symptoms gradually improved. The rash hasn''t completely gone yet but I''m feeling a lot better.',
  ARRAY[]::text[],
  'Raymond is a non-smoker and drinks alcohol occasionally on social occasions. He lives with his partner. There are no pets at home. He works as a healthcare assistant in a respiratory ward.',
  'You know it was an allergic reaction of some kind, but you are unsure whether the food or one of your regular medications — Ramipril, which you have been taking for about three years without any problems — might have been responsible.',
  'You are wondering whether you now need to carry an EpiPen in case it happens again.',
  'You want the doctor to tell you what caused the reaction and what you should do going forward.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Take a detailed history of the allergic reaction — onset, duration, and progression of symptoms.',
    'Ask specifically about the symptoms experienced: swelling of the lips, tongue, and eyes; rash and its distribution; any breathlessness, wheeze, dizziness, or loss of consciousness.',
    'Ask about what was eaten in the hours before the reaction and clarify whether shellfish or other common allergens were definitely present.',
    'Ask whether any new medications, supplements, or products were used around the same time.',
    'Explore current regular medications — specifically ask about ACE inhibitors such as ramipril, which are a recognised cause of angioedema.',
    'Ask whether the patient has had similar reactions before.',
    'Screen for risk factors that would warrant an EpiPen: co-existing conditions such as asthma, COPD, or ischaemic heart disease; previous anaphylaxis; or inability to reliably avoid the trigger.',
    'Explore social history including occupation, smoking, and alcohol.',
    'Ask about the patient''s ideas, concerns, and expectations.',
    'Explain the likely diagnosis of angioedema with urticaria, and discuss the two probable contributing triggers — shellfish allergy and ramipril-induced angioedema.'
  ],
  ARRAY[
    'Advise the patient to continue taking cetirizine at the same dose, as it has been effective in managing symptoms. It can be continued for up to 6 weeks if needed.',
    'Advise stopping ramipril — explain that ACE inhibitors are a well-recognised cause of angioedema and must be discontinued. Offer to check his blood pressure and start indapamide if an additional antihypertensive is required.',
    'Explain that no specialist referral is immediately required, as the two likely triggers — shellfish and the ACE inhibitor — have been identified and can be avoided.',
    'Advise the patient to strictly avoid shellfish and any dishes that may contain it, including reading labels carefully and informing restaurants of his allergy when eating out.',
    'Regarding an EpiPen: explain that an adrenaline auto-injector is generally recommended for patients at high risk of severe anaphylaxis — for example, those with co-existing asthma, COPD, heart disease, or those who cannot reliably avoid their allergen. As Raymond does not have these risk factors and can avoid shellfish, an EpiPen would not typically be prescribed at this stage.',
    'Advise the patient to dial 999 or attend A&E immediately if symptoms progress rapidly or if features of anaphylaxis develop — including shortness of breath, wheeze, dizziness, swelling of the tongue or throat, or collapse.'
  ],
  'Thank you for calling in — it sounds like that reaction was very frightening, and it''s understandable that you''re still feeling unsettled by it. Let me explain what I think happened and what we should do about it.

Raymond, what you''ve described — the swelling of your lips and eyes, the generalised itchy rash — is a reaction called angioedema with urticaria. Angioedema is a type of swelling that happens just beneath the surface of the skin, often affecting the face and lips, and urticaria is the medical term for hives. This happens when the body''s immune system reacts to something it perceives as a threat, triggering the release of a chemical called histamine. The Cetirizine you took is an antihistamine, which is exactly the right first response, and it''s good to hear it worked.

Now, you mentioned two potential triggers, and I think you were quite right to consider both. The first is the shellfish in the meal — this is one of the most common food allergens and can cause exactly the kind of reaction you described. I would strongly advise you to avoid shellfish and any dishes that might contain it from now on, including letting restaurants know when you eat out.

The second factor is your ramipril. ACE inhibitors — which is the class of blood pressure medication that ramipril belongs to — are a well-known cause of angioedema. This can sometimes happen even after years of taking the medication without any problems, which is why it''s important we take it seriously now. I would like you to stop taking ramipril. I''ll check your blood pressure and, if it''s still elevated, I''ll start you on an alternative medication called indapamide, which works well for blood pressure but does not carry the same risk of causing angioedema.

In terms of whether you need an EpiPen — I completely understand why you''re wondering about this. An adrenaline auto-injector is recommended for people who are at high risk of a severe anaphylactic reaction, particularly those with conditions like asthma, COPD, or heart disease, or those who cannot easily avoid their allergen. Since you don''t have those risk factors and you can realistically avoid shellfish, we would not typically recommend an EpiPen at this stage. That said, you should remain alert to any future reactions.

If at any point you develop symptoms of a more serious reaction — difficulty breathing, a wheeze, dizziness, or swelling affecting your throat or tongue — please call 999 or get to A&E immediately without waiting. That is the most important safety message to take away from today. Otherwise, carry on with the cetirizine for now until the rash has fully settled, and please do stop the ramipril from today.',
  ARRAY[
    'Angioedema with urticaria following food ingestion should prompt consideration of two concurrent triggers: a food allergy (commonly shellfish, nuts, or peanuts) and ACE inhibitor use — ramipril is a well-recognised cause of angioedema even after years of use without problems.',
    'ACE inhibitor-induced angioedema requires cessation of the drug — switch to an alternative antihypertensive such as indapamide; no re-challenge should be attempted.',
    'An adrenaline auto-injector (EpiPen) is indicated for patients at high risk of anaphylaxis — specifically those with co-existing asthma, COPD, ischaemic heart disease, or who cannot reliably avoid their allergen trigger; it is not routinely prescribed for all allergic reactions.',
    'Antihistamines (e.g. cetirizine) are the first-line treatment for mild-to-moderate allergic reactions with urticaria and angioedema, and can be continued for up to 6 weeks if symptoms persist.',
    'Clear safety-netting is essential: patients must be advised to call 999 or attend A&E immediately if they develop breathlessness, wheeze, dizziness, tongue or throat swelling — features that indicate potentially life-threatening anaphylaxis.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  90,
  'Male Hair Loss',
  'Dermatology',
  'Telephone consultation',
  false,
  'Lucas Bennett',
  '33-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  'Patient has booked a routine appointment to discuss concerns about hair thinning.',
  'Patient calling to discuss hair thinning that has been bothering him over the past couple of months.',
  'Hi doctor, I''m calling because I''ve been noticing my hair getting thinner over the past few months and it''s really starting to worry me.',
  'I''ve noticed the hair thinning mainly at the front of my scalp and at both temples. It''s been happening gradually over about two months. My dad started losing his hair when he was in his early thirties as well.',
  ARRAY[]::text[],
  'Lucas does not smoke or drink alcohol. He lives with his partner. He works as a professional photographer, and his appearance is very important to him professionally. He has been checking his hairline in the mirror several times a day and says the anxiety about his appearance is starting to affect his confidence.',
  'He thinks he may be going bald, like his father did at a similar age.',
  'He is worried this will progress to complete hair loss.',
  'He wants the doctor to help him find a solution quickly. He has a professional photoshoot booked in two weeks'' time and is keen to know whether anything can be done before then. He also wants to ask about hair transplants and whether that would provide a rapid result.',
  ARRAY[]::text[],
  'Ask the doctor about hair transplants and whether they would provide a quick solution.',
  NULL,
  ARRAY[
    'Ask about the pattern of hair loss — where it started, whether it is diffuse or in a specific distribution, and whether it has progressed.',
    'Clarify the onset — gradual versus sudden hair loss has different differentials (androgenetic alopecia is gradual; telogen effluvium is often more acute).',
    'Ask whether there is any hair shedding — for example, finding large amounts of hair on the pillow, in the shower, or on a brush.',
    'Ask about associated scalp symptoms such as itching, scaling, or redness.',
    'Explore potential contributing factors: recent significant physical or emotional stress, recent illness, surgical procedures, or significant dietary change such as crash dieting or fasting.',
    'Ask about current and recent medications, including any that are known to cause hair loss (e.g. antidepressants, carbimazole, or other systemic medications).',
    'Explore diet and nutritional history — iron deficiency and poor nutrition can cause hair thinning.',
    'Ask about family history of hair loss on both the maternal and paternal side.',
    'Explore the psychological impact — how is this affecting his confidence, daily routine, and work?',
    'Ask about social history including smoking, alcohol, occupation, and relationship.',
    'Formulate a working diagnosis of androgenetic alopecia (male pattern hair loss) based on the distribution, gradual onset, and strong family history.'
  ],
  ARRAY[
    'Advise that a photograph can be sent via the online consultation system to help confirm the diagnosis, or offer a face-to-face appointment to examine the scalp directly.',
    'Discuss treatment options: minoxidil 5% solution is not available on the NHS but is available over the counter; minoxidil 5% foam (Regaine for Men) is available on the NHS.',
    'Advise that finasteride 1 mg tablets (Propecia®) are not prescribable on the NHS but can be issued on a private prescription.',
    'Inform the patient that continuous use for 2 to 4 months is required before any evidence of hair growth can be expected with topical treatment, and 3 to 6 months if using oral tablets.',
    'Advise that if treatment is stopped, beneficial effects begin to reverse within 3 to 6 months and return to baseline by 9 to 12 months for both topical and oral treatment.',
    'Address his photoshoot concern: explain that unfortunately no medical treatment will produce visible results within two weeks. However, good hair styling, aesthetic wigs, or hair camouflage products can provide the appearance he needs for the shoot in the short term.',
    'Address hair transplants: explain that transplants are not available on the NHS and are expensive. They also take longer to show results — while some initial growth may be seen within a few weeks, significant changes typically take several months.',
    'Arrange follow-up based on treatment chosen: 2 months if starting topical minoxidil, 3 months if starting oral finasteride.'
  ],
  'I can hear how much this has been playing on your mind, and it''s completely understandable — especially when your appearance is so important to your work. Let me reassure you that this is something we can discuss properly and put together a plan for.

Lucas, based on what you''ve described — the gradual thinning at the front and temples, the fact that it''s been coming on over a couple of months, and particularly the strong family history of your dad losing his hair at a similar age — this really does sound like androgenetic alopecia, which is the medical term for male pattern hair loss. It''s an extremely common condition and it does have a strong genetic basis. It tends to follow a characteristic pattern starting at the hairline and temples, which is exactly what you''re describing.

I want to be clear that it doesn''t necessarily mean you''ll lose all your hair. Male pattern hair loss varies a great deal in how far it progresses, and there are treatments available that can slow it down or in some cases partially reverse it, though they work best when started early — which is actually a reason it''s good you''ve come in now.

There are two main medical treatments I can tell you about. The first is minoxidil, which comes as a 5% foam called Regaine for Men and is available on the NHS. It''s applied directly to the scalp and works by stimulating hair follicles. The important thing to know is that you need to use it consistently for 2 to 4 months before you can expect to see any response — it doesn''t produce quick results. The second option is a tablet called finasteride 1 mg, which works by reducing the hormone responsible for follicle shrinkage. This isn''t available on the NHS but can be prescribed privately. It also takes 3 to 6 months of continuous use to show benefit. If either treatment is stopped, the effects begin to wear off within 3 to 6 months and hair typically returns to where it would have been without treatment by 9 to 12 months.

Regarding your photoshoot in two weeks — I want to be honest with you: no medical treatment will make a visible difference in that timeframe. However, there are some excellent hair styling products and hair camouflage sprays and fibres that can give the appearance of fuller hair for your shoot. Aesthetic hairpieces and wigs have also improved enormously in quality. These are genuinely effective short-term options.

On the question of a hair transplant — this is something some men do choose to pursue, and the results can be very good. However, it''s not available on the NHS, it is expensive, and it also takes time. You might see some early growth within a few weeks after a transplant, but meaningful, visible results typically take several months to develop. So it would not be the right solution for the next two weeks.

Would it be helpful to arrange a face-to-face appointment so I can take a proper look at your scalp and we can talk through which option you''d like to try? Alternatively, you could send in a photo through the online portal so I can have a look and confirm the diagnosis before we go ahead.',
  ARRAY[
    'Androgenetic alopecia (male pattern hair loss) is diagnosed clinically based on the characteristic bitemporal and frontal distribution, gradual onset, and positive family history — no investigations are routinely required unless an alternative cause is suspected.',
    'First-line treatment options include topical minoxidil 5% foam (Regaine for Men, available on NHS) and oral finasteride 1 mg (not available on NHS, private prescription only) — both require continuous use for 2–4 months (topical) or 3–6 months (oral) before benefit is seen.',
    'Stopping treatment leads to reversal of benefit: effects begin to diminish within 3–6 months and return to baseline by 9–12 months for both topical and oral preparations.',
    'Hair transplants and medical treatments do not offer rapid cosmetic results — for short-term appearance concerns, hair camouflage products, styling techniques, or aesthetic hairpieces are practical alternatives.',
    'Consider alternative causes of hair loss when the pattern is atypical or onset is sudden: telogen effluvium (triggered by stress, illness, or crash dieting), iron deficiency anaemia, thyroid disease, and drug-induced alopecia should be on the differential and excluded if there are any suspicious features.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  91,
  'Abortion Due To Sex Of Child',
  'Ethics',
  'Telephone consultation',
  false,
  'Fatima Hussain',
  '37-year-old female',
  ARRAY[]::text[],
  ARRAY[]::text[],
  'Patient booked routine appointment to discuss concerns.',
  'Patient has booked a routine appointment to discuss a personal concern.',
  'Hello doctor, I was hoping to speak to you about something quite private. I need some help with my pregnancy.',
  'I am 27 weeks pregnant and I would like to discuss ending the pregnancy. I already have three daughters and this baby is also a girl. My husband is very unhappy about this and has been putting a lot of pressure on me to terminate.',
  ARRAY[]::text[],
  'You are a stay-at-home mother and rely entirely on your husband for financial support. You live with your three daughters aged 11, 8, and 5. You do not smoke or drink alcohol.',
  'You believe that the pregnancy itself is at the root of the problems at home and that ending it might restore peace in the household.',
  'You are frightened about what will happen if the pregnancy continues. Your husband has threatened to stop providing money and food for you and the children if you do not terminate this pregnancy. Your mother-in-law also mistreats you, sometimes locking you out of the house. Your husband has said cruel things to you, though he has not physically harmed you. You feel trapped and do not see a way out.',
  'You hope the doctor will be able to arrange a termination of pregnancy for you. You feel conflicted and unsure deep down, but you feel desperate. Accept whatever the doctor offers if they are kind and empathetic. If they are unkind, decline.',
  ARRAY[]::text[],
  NULL,
  'Accept whatever the doctor offers if they are kind and empathetic. If they are not nice, decline.',
  ARRAY[
    'Explore her reason for requesting an abortion — ask openly what has led her to this decision.',
    'Explore the social and family pressures in detail, including who is putting pressure on her and in what way.',
    'Ask directly whether she feels safe at home.',
    'Ask about physical abuse.',
    'Ask about other forms of abuse, including emotional, verbal, and sexual abuse.',
    'Ask about the current pregnancy — whether there have been any complications or concerns.',
    'Ask whether her children are also affected by or exposed to the abuse at home.',
    'Ask whether she has any support from family or friends outside the home.',
    'Ask how all of this has been affecting her mood and mental wellbeing.',
    'Ask about smoking, alcohol use, recreational drugs, and over-the-counter medications.'
  ],
  ARRAY[
    'Explain empathetically that abortion is not permitted in the UK at 27 weeks solely on the basis of the baby''s sex. The law only permits termination at this stage in very specific circumstances, such as a serious risk to the mother''s health or a severe foetal condition.',
    'Acknowledge how much pressure she is under and validate how difficult her situation is.',
    'Explain that what she has described — being locked out, threatened with withdrawal of food and financial support, and being subjected to verbal abuse — constitutes domestic abuse, and that you have a duty to ensure her safety and the safety of her children.',
    'Explain that you will need to involve the safeguarding team and social services. Reassure her that this is not to cause further distress, but to ensure she and her daughters are protected and supported.',
    'Offer referral to domestic abuse counselling services and organisations such as Women''s Aid.',
    'Reassure her that there are systems in place — including housing support, financial assistance, and legal advice — that can help her and her children live safely and independently if needed.'
  ],
  'Thank you for trusting me with something so personal and difficult, Fatima — it takes real courage to speak about this, and I want you to know you are in a safe space here.

I can hear how much pressure you are under, and I am deeply sorry for everything you have been going through. I want to take what you have said very seriously. You have mentioned being locked out of your home, being threatened with the withdrawal of food and financial support, and being spoken to in a way that is hurtful and demeaning. I want to be honest with you — what you have described is domestic abuse. None of this is your fault, and you and your children do not deserve to be treated this way.

Regarding your request for a termination: I have to be honest with you about what the law allows. In the UK, a termination at 27 weeks is only legally permitted in very specific circumstances — for example, if continuing the pregnancy would pose a serious risk to your health, or if the baby has been found to have a severe medical condition. An abortion cannot be arranged on the basis of the baby''s sex alone, and I want to be transparent with you about that. I know this is not the answer you were hoping to hear, and I am truly sorry.

What concerns me most right now is your safety and the safety of your three daughters. Because of what you have shared, I have a professional duty to involve our safeguarding team and social services. I want to reassure you that this is not about causing you any more difficulty — it is about making sure that you and your children are protected and that you have access to the support you need.

There are services that can help you. Organisations like Women''s Aid offer confidential advice, practical help, and refuge if needed. Social services can also help connect you with housing support, legal advice, and financial assistance, so that you and your daughters are not left without options.

I know this feels overwhelming, and I do not want you to face any of this alone. I will be here to guide you through this step by step, and we will work together to make sure you and your children are as safe and supported as possible.',
  ARRAY[
    'Abortion in the UK at or beyond 24 weeks is only lawful in very restricted circumstances — serious risk to maternal health or severe foetal abnormality. Sex-selective abortion is not a lawful ground at any gestation.',
    'Always screen for domestic abuse in a non-judgmental, open manner when a patient presents with a request that may be driven by coercive control — threats, financial control, emotional cruelty, and isolation all constitute abuse.',
    'When domestic abuse is identified and children are in the household, the GP has a safeguarding duty to refer to social services and the safeguarding team, even if the patient is reluctant.',
    'Offer concrete signposting to domestic abuse support — Women''s Aid, the National Domestic Abuse Helpline, and local counselling services — alongside the formal safeguarding referral.',
    'Approach these consultations with empathy and a non-judgmental tone throughout; a patient who feels judged or dismissed is less likely to accept help and may not return.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  92,
  'Tremors In Young Adult',
  'Neurology',
  'Video consultation',
  false,
  'Helen Barker',
  '47-year-old female',
  ARRAY[]::text[],
  ARRAY[]::text[],
  'Patient booked routine appointment to discuss concerns.',
  'Patient has booked a routine appointment to discuss concerns about hand tremors.',
  'Hi doctor, I''ve been having problems with my hands shaking for the past few months and it''s really starting to get in the way of my work.',
  'The tremors have been going on for about three months now. They are worst when I am actually trying to hold or carry something — like when I''m carrying plates and glasses at work. I''ve noticed that oddly enough, having a small drink seems to settle them a little. They don''t happen when I''m resting or at night, which I found strange. My dad had something similar but I haven''t been in contact with him for years, so I''m not sure what his diagnosis was.',
  ARRAY[]::text[],
  'You do not smoke. You drink alcohol occasionally and only really when it is offered to you at work. You do not use recreational drugs. You are married and have two children. You have been feeling stressed recently as you have taken on extra shifts to help cover the mortgage.',
  'You wonder whether this could be related to Parkinson''s disease, as your father had similar-looking tremors, though you are not sure what he was diagnosed with.',
  'You are concerned that the tremors are getting worse and may affect your ability to continue in your job. They are already making things difficult at work and you worry about what happens if they do not improve.',
  'You would like the doctor to find out what is causing the tremors and discuss what can be done to manage or treat them.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Ask about the onset and duration of the tremors — how long have they been present and did anything seem to trigger them?',
    'Ask about the character of the tremors — do they occur at rest, with movement, or when trying to hold or reach for something (action or intention tremor)?',
    'Ask whether the tremors affect one or both hands, and whether any other parts of the body are affected.',
    'Ask whether the tremors improve with alcohol.',
    'Ask about any family history of tremors or neurological conditions.',
    'Ask about associated symptoms such as slowness of movement, stiffness, balance problems, or changes in handwriting — to help rule out Parkinson''s disease.',
    'Ask about thyroid symptoms such as weight loss, heat intolerance, palpitations, or anxiety.',
    'Ask about medication use and caffeine intake.',
    'Ask about sleep, mood, and current stressors.',
    'Ask about the impact on her daily activities, particularly her work.',
    'Ask about smoking, alcohol use, and recreational drug use.',
    'Ask about her ideas, concerns, and expectations.'
  ],
  ARRAY[
    'Offer a face-to-face appointment to carry out a full neurological examination and assess the tremor directly.',
    'Offer blood tests including thyroid function tests, FBC, LFTs, and U+Es to exclude secondary causes of tremor.',
    'Offer propranolol — check for allergy and contraindications first — starting at 40 mg two to three times daily. Inform her of common side effects such as dizziness and lightheadedness, but reassure her that most people tolerate this medication well.',
    'Discuss potential workplace accommodations, such as adjusting tasks or taking breaks, if the tremors are currently affecting her ability to work.',
    'Offer leaflets or reliable online resources so she can read more about essential tremor.',
    'Safety-net: advise her to recontact the surgery if symptoms worsen or any new symptoms develop.'
  ],
  'Thank you for getting in touch and for explaining what''s been happening, Helen — it sounds like these tremors have been causing you real worry, particularly given how much your work relies on steady hands.

Based on everything you''ve described, I think what you are most likely experiencing is something called essential tremor. This is a common neurological condition that causes shaking, particularly when you are actively using your hands — so when you are carrying plates or glasses, for example — rather than when you are at rest. The fact that a small amount of alcohol seems to ease the shaking is actually a well-recognised feature of essential tremor, and the fact that it does not happen during sleep or when your hands are completely still fits this picture well.

I understand that Parkinson''s disease has been on your mind, especially given what you remember about your father. Parkinson''s is a different condition and tends to cause tremor mainly at rest, along with other features such as slowness of movement, stiffness, and balance difficulties. From what you have described, none of those features seem to be present, which is reassuring.

I would like to arrange a face-to-face appointment so that I can examine you properly and assess the tremor in person. I will also arrange some blood tests — including a thyroid function test and a few other routine checks — to make sure there is no other underlying cause contributing to the tremors.

In the meantime, there is a medication called propranolol which is commonly used to help manage essential tremor. It works well for many people. I would start you on 40 mg two to three times a day. The most common side effects people notice are feeling a little lightheaded or dizzy, but most people get on with it very well. We will check beforehand that there are no reasons you should not take it.

I would also suggest having a conversation with your employer about whether any adjustments can be made at work while we get things under better control. And I will send you some information about essential tremor so you can read more at your own pace. Please do get back in touch if anything changes or worsens — we will keep a close eye on how you are getting on.',
  ARRAY[
    'Essential tremor is an action tremor — it occurs during voluntary movement or when maintaining a posture — and is characteristically absent at rest and during sleep. This distinguishes it from the resting tremor of Parkinson''s disease.',
    'Temporary improvement of tremor with alcohol is a well-recognised feature of essential tremor and supports the diagnosis, though patients should not be encouraged to use alcohol as a management strategy.',
    'A positive family history is common in essential tremor, as it is often inherited in an autosomal dominant pattern.',
    'First-line pharmacological treatment for essential tremor is propranolol, typically starting at 40 mg two to three times daily. Always check for contraindications (asthma, bradycardia, heart block) before prescribing.',
    'Initial investigations should include thyroid function tests, FBC, LFTs, and U+Es to exclude secondary causes such as hyperthyroidism or hepatic disease.',
    'Safety-netting is important — advise the patient to return if symptoms worsen or new neurological features develop, as the diagnosis may need to be reconsidered.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  93,
  'Unwell Patient On Lithium',
  'Mental Health',
  'Video consultation',
  false,
  'Janet Hughes',
  '54-year-old female',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'Patient has booked a routine appointment to discuss feeling unwell.',
  'Hello doctor, I''ve not been feeling well for the last couple of days and I''m a bit worried.',
  'I''ve been feeling dizzy and my hands have been shaking. I''ve also felt a bit sick and generally not right. I take lithium for my mood and I''ve been on it for a few years now. I''m embarrassed to say that I missed my last blood test appointment — things got busy and it slipped my mind.',
  ARRAY[]::text[],
  'You do not smoke or drink alcohol. You live alone. You work as a chef but have been off work for the past two days because you have been feeling unwell.',
  'You are not entirely sure what is wrong, but the tremors and dizziness are worrying you. You have heard that lithium can cause problems if levels get too high, but you did not think missing one blood test would matter.',
  'You are concerned that something serious might be happening. The tremors and dizziness are affecting your ability to work as a chef, which is your passion and main livelihood. You have been off work for two days already.',
  'You hope the doctor can work out what is going on and help you feel better quickly. You would like to be able to return to work as soon as possible. If asked why you missed your appointment, tell the doctor you were busy and forgot.',
  ARRAY[]::text[],
  NULL,
  'Say no to any other questions asked outside the details already provided and accept everything the doctor offers.',
  ARRAY[
    'Ask about the nature and onset of her symptoms — specifically tremor, dizziness, nausea, confusion, or muscle twitching.',
    'Ask about her lithium prescription — dose, how long she has been taking it, and when she last had her lithium levels checked.',
    'Ask whether she missed any recent blood monitoring appointments and explore why without being judgemental.',
    'Ask whether she has started any new medications, as some drugs can raise lithium levels (e.g. NSAIDs, ACE inhibitors, diuretics).',
    'Ask about her fluid intake — dehydration can increase lithium toxicity risk.',
    'Ask about her general health and any other symptoms.',
    'Ask about home circumstances — whether she lives alone and whether anyone can accompany her if needed.',
    'Ask about smoking, alcohol use, and recreational drugs.',
    'Ask about her ideas, concerns, and expectations.'
  ],
  ARRAY[
    'Offer admission via the acute medical unit for urgent lithium level measurement and clinical assessment. Find out whether she has anyone who can take her to hospital or whether she would need a taxi.',
    'Advise her that if she feels unwell or unsafe on the way to hospital, she should stop and call 999.',
    'Advise her in a non-judgmental and supportive way about the importance of regular lithium monitoring — for example: "Janet, I completely understand that life gets busy, but it''s really important to have your lithium levels checked every three months. This helps us make sure the medication is working safely and prevents side effects like the tremors and dizziness you''ve been experiencing. We want to support you in keeping on top of these checks — we can send you reminders, and you might find it helpful to set a reminder on your phone as well."',
    'If she is of reproductive age and sexually active, advise her about the importance of using contraception while on lithium, due to the risk of birth defects in children exposed to lithium in utero.',
    'Advise her that once she has been discharged from hospital, she should book a routine follow-up appointment to review what happened and to further optimise her health and medication management.',
    'Offer her a lithium treatment card if she does not already have one, so she has key safety information readily available.'
  ],
  'Thank you for getting in touch today, Janet, and I''m glad you called — the symptoms you''ve been describing are important and I want to make sure we get to the bottom of them quickly.

You mentioned that you take lithium and that you have been feeling dizzy, shaky, and generally unwell for the past couple of days. I want to be honest with you — these symptoms can sometimes be a sign that the level of lithium in your blood has gone too high. Lithium is a medication that works within a very narrow safe range, which is why regular blood monitoring is so essential. When the level drifts above that range, even slightly, it can cause exactly the sort of symptoms you are describing.

Because of this, I think the safest and most important thing right now is for you to go to hospital today so that we can check your lithium level urgently. The acute medical team there will be able to run the blood test and make sure you receive the right treatment as quickly as possible. I want to check — do you have someone who can take you in, or would you need a taxi? And please, if you feel worse at any point on the way there, do not hesitate to call 999.

I also want to say something about the blood test you missed, and I want to say it gently — I completely understand that life gets busy and things slip through the net. But regular lithium checks every three months are really important for your safety. They help us catch any problems early, before they become serious. Going forward, we can set up a system of reminders from the surgery, and it might also be worth putting a reminder on your phone so it does not get forgotten again.

One thing I would also like to give you, if you do not already have one, is a lithium treatment card. This card has key information about your medication and is really useful to have on you, especially in situations like today when you are going to hospital.

Once you have been seen and discharged, please do book a follow-up appointment here so we can review everything together, go over what happened, and make sure your ongoing care is as well-supported as possible. You are doing the right thing by calling today.',
  ARRAY[
    'Symptoms of lithium toxicity include tremor, nausea, dizziness, confusion, and muscle twitching — these should be taken seriously and prompt urgent measurement of serum lithium levels.',
    'Lithium has a narrow therapeutic index and requires regular monitoring (typically every three months for stable patients). Missed monitoring is a significant safety risk.',
    'Common precipitants of lithium toxicity include dehydration, new NSAID or ACE inhibitor use, diuretics, and intercurrent illness — always ask about these.',
    'A patient with suspected lithium toxicity who is symptomatic requires same-day assessment via the acute medical unit, not a routine outpatient review.',
    'All patients on lithium should carry a lithium treatment card and be counselled about the importance of adequate fluid intake, regular monitoring, and avoiding interacting drugs.',
    'Lithium is teratogenic (Ebstein''s anomaly risk) — ensure patients of reproductive potential are advised about appropriate contraception.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  94,
  'HRT Counselling',
  'Gynaecology & Women''s Health',
  'Telephone consultation',
  false,
  'Caroline Webb',
  '51-year-old female',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication', 'No known drug allergy'],
  NULL,
  'Patient booked a routine telephone appointment to discuss some concerns.',
  'Hi doctor, I''ve been wondering whether I might have ADHD and I was hoping to be assessed for it.',
  'Over the past six months or so I''ve become increasingly forgetful and I''ve been struggling to multitask the way I normally would. It''s very out of character for me. For example, last month I had a really important presentation at work for some external stakeholders, but after sorting out the children''s lunchboxes and my husband''s things in the morning, I realised I''d left my laptop at home. I have to do things one at a time now because if I try to juggle several things at once, something gets dropped. My short-term and long-term memory feel fine as long as I am focused, but if I lose concentration for a moment, things slip. I''ve also become noticeably more irritable — my husband has mentioned it too.',
  ARRAY[
    'Your periods have become irregular over the past six months. They were previously very regular, but now they come roughly once every two months and are lighter than they used to be. You occasionally get hot flushes. You also experience some vaginal dryness, which can make sexual intercourse with your husband uncomfortable at times.'
  ],
  'You do not smoke or drink alcohol. You are married with three children. Your husband had a vasectomy, so you are not using any contraception. Your last period was about two and a half weeks ago, and before that there had been a gap of around six to seven weeks. You thought you might have been pregnant and did a couple of pregnancy tests, both negative. You work in financial services as a senior compliance manager, and your role normally requires excellent multitasking and sharp attention to detail, which is why these recent changes are affecting you so much.',
  'You believe you may have ADHD, which would explain why you are finding it so hard to concentrate and multitask.',
  'You want to get on top of these symptoms before they affect your work performance any further or put strain on your relationship with your husband.',
  'You were hoping the GP would refer you for a formal ADHD assessment.',
  ARRAY[]::text[],
  NULL,
  'Say no to any other questions or symptoms asked outside of the details already provided.',
  ARRAY[
    'Ask about the onset of her forgetfulness and difficulty multitasking — when did it start and has it been progressive?',
    'Ask about symptoms of inattention, such as becoming easily distracted or struggling to complete tasks.',
    'Ask about symptoms of hyperactivity or impulsivity, including feeling restless, talking excessively, interrupting others, or difficulty waiting.',
    'Ask whether anyone around her has noticed changes in her personality, and explore whether the difficulties are with short-term memory, long-term memory, or both — to help rule out early-onset dementia.',
    'Ask about her menstrual cycle, including regularity, flow, her last period, and whether there is any chance she could be pregnant.',
    'Ask about menopausal symptoms, including hot flushes, night sweats, sleep disturbance, fatigue, vaginal dryness, and muscle aches.',
    'Ask about red flag symptoms such as unexplained weight loss, loss of appetite, drenching night sweats, or any new lumps or bumps.',
    'Ask about her mood.',
    'Ask how her symptoms are affecting her daily activities, work, and relationships.',
    'Ask about smoking, alcohol use, and occupation.',
    'Ask about her ideas, concerns, and expectations.',
    'Make a diagnosis of perimenopause.'
  ],
  ARRAY[
    'Explain to her that her symptoms are most likely due to perimenopause — the transition phase leading up to the menopause.',
    'Decline blood tests to confirm menopause and explain that menopause is a clinical diagnosis based on symptoms; hormone levels fluctuate significantly at this age and are not a reliable diagnostic tool.',
    'Explain the benefits and risks of hormone replacement therapy (HRT) and also discuss the benefits and risks of non-hormonal alternatives, so she can make an informed decision.',
    'If she wishes to proceed with HRT, ask about contraindications, including any new breast lump, abnormal vaginal bleeding, personal or family history of breast cancer, and personal or family history of thromboembolism (DVT or PE). Ask about migraine, which is not a strict contraindication but requires caution. Advise her to attend a face-to-face appointment to have her blood pressure measured before HRT can be prescribed.',
    'If she prefers not to take HRT, reassure her that symptoms can be managed without it. Offer non-hormonal options such as vaginal moisturisers and lubricants to help with vaginal dryness and reduce discomfort during intercourse.',
    'Offer menopause-specific cognitive behavioural therapy (CBT). Explain that this can help by addressing unhelpful thought patterns, teaching coping strategies for hot flushes, night sweats, and mood changes, and improving overall quality of life.',
    'If she raises the topic of herbal remedies, explain that some, such as isoflavones or black cohosh, may help with hot flushes, but the quality and safety of these products varies and their effects are not always predictable.',
    'Offer to send her reliable written information, such as leaflets from Menopause Matters, so she can read more and make an informed decision.',
    'Arrange a follow-up in two to four weeks to review her symptoms and discuss which treatment option she has decided on.'
  ],
  'Thank you for calling today, and I''m really glad you brought these concerns to me, Caroline — it takes self-awareness to notice these kinds of changes, and I can understand why they have been worrying you, especially given how demanding your role is.

I''ve been listening carefully to everything you''ve described — the forgetfulness, the difficulty multitasking, the irritability, and the fact that this has come on over the past six months. I''d also like to gently ask about something else: have your periods changed at all recently? The reason I ask is that I think the symptoms you are experiencing may actually have a different explanation to ADHD.

Based on what you''ve told me — the cognitive changes, the mood shifts, and the changes in your cycle — I think what you are most likely experiencing is perimenopause. This is the transitional phase that comes before the menopause, and it can begin in the mid-forties to early fifties. During this time, oestrogen levels start to fluctuate and gradually decline, and this can have a significant effect on concentration, memory, and mood. Many women describe exactly what you are describing — feeling as though their mental sharpness has changed in a way that feels very unlike them.

I want to reassure you that we do not need a blood test to confirm this. Hormone levels fluctuate so much at this stage of life that they can be misleading, and the diagnosis is really made based on symptoms — exactly as you have described them.

In terms of what we can do to help: the most effective treatment for perimenopausal symptoms is hormone replacement therapy, or HRT. It works by topping up the oestrogen your body is producing less of, and for many women it makes a very significant difference to cognitive symptoms, mood, hot flushes, and vaginal dryness. Before I could prescribe it, I would need to ask you a few safety questions and I would want you to come in to have your blood pressure checked. I would also want to go through the benefits and risks with you in detail so you can make a fully informed decision.

If you would rather not take HRT, there are other options too — including vaginal moisturisers for the dryness, and a type of therapy called cognitive behavioural therapy which has been adapted specifically for menopausal symptoms. I will send you some information from Menopause Matters so you can have a good read and think about what feels right for you. Let''s arrange a follow-up in the next two to four weeks to go through everything and put a plan in place.',
  ARRAY[
    'Perimenopause can present with cognitive symptoms such as difficulty concentrating and multitasking, mood changes, and irritability — symptoms that closely mimic ADHD or early dementia. Always consider the perimenopausal stage when these symptoms arise in women in their late forties to early fifties.',
    'Menopause is a clinical diagnosis based on symptoms in women over 45. Blood tests (FSH, oestradiol) are not recommended for diagnosis in this age group as hormone levels fluctuate and are unreliable.',
    'Before prescribing HRT, assess for contraindications including personal or family history of breast cancer, unexplained vaginal bleeding, active or recent thromboembolism, and uncontrolled hypertension. Blood pressure must be checked before initiation.',
    'Non-hormonal options for managing menopausal symptoms include vaginal moisturisers and lubricants for dryness, menopause-specific CBT, and (with caveats) herbal preparations such as isoflavones or black cohosh.',
    'Shared decision-making is central to HRT counselling — explain the benefits and risks clearly and provide written resources (e.g. Menopause Matters) to support an informed choice.',
    'Arrange follow-up in two to four weeks to review the patient''s decision and initiate a treatment plan.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  95,
  'Polymyalgia Rheumatica',
  'Rheumatology & Musculoskeletal',
  'Telephone consultation',
  false,
  'Dorothy Ashworth',
  '57-year-old female',
  ARRAY[
    'Amlodipine 5mg once daily',
    'Ramipril 10mg once daily',
    'Metformin 1g twice daily',
    'Dapagliflozin 10mg once daily',
    'Mirtazapine 30mg once daily'
  ],
  ARRAY[]::text[],
  'Seen by a clinical practitioner five days ago. Presenting complaint: bilateral shoulder pain with associated stiffness for the past three months. No history of trauma and no red flag symptoms. Examination: reduced range of motion due to stiffness, with no obvious tenderness, swelling, or joint warmth. No red flags identified. Impression: suspected rheumatoid arthritis versus polymyalgia rheumatica (PMR). Plan: blood tests arranged. For review once results available. Worsening advice given.

Blood Test Results:
White Cell Count (WBC): 6.2 × 10⁹/L (ref 4.0–11.0 × 10⁹/L)
Haemoglobin (Hb): 118 g/L (ref 120–160 g/L, female)
Platelets: 230 × 10⁹/L (ref 150–400 × 10⁹/L)
Mean Cell Volume (MCV): 82 fL (ref 80–96 fL)
MCHC: 330 g/L (ref 320–360 g/L)
Erythrocyte Sedimentation Rate (ESR): 60 mm/hr (ref 0–20 mm/hr)
C-Reactive Protein (CRP): 41 mg/L (ref 0–5 mg/L)
Rheumatoid Factor (RF): Negative (<20 IU/mL) (ref <20 IU/mL)
Creatine Kinase (CK): 120 U/L (ref 50–200 U/L)
Adjusted Calcium: 2.32 mmol/L (ref 2.2–2.6 mmol/L)
Alkaline Phosphatase (ALP): 85 U/L (ref 45–115 U/L)
Protein Electrophoresis: Normal
Liver Function Tests, Thyroid Function Tests, Electrolytes, Urea, Creatinine, eGFR: Normal',
  'Patient called to discuss her recent blood test results.',
  'Hello doctor, I''m ringing to go over my blood test results please.',
  'I came in five days ago because I''ve had pain and stiffness in both shoulders for about three months. The pain has been gradually getting worse and is pretty much always there, but it''s particularly bad in the mornings. The stiffness takes about an hour to ease off. I find it really hard to lift my arms, do my hair, or reach up for things. I''ve had to stop driving because of it. My son, who lives a few miles away, pops over every couple of weeks to help me with the shopping. I used to go bowls with my friends every fortnight but I haven''t been able to manage that recently.',
  ARRAY[]::text[],
  'You live alone. You do not smoke or drink alcohol. You run a small coffee shop, and although you oversee things, your staff handle most of the physical work, so your symptoms have not directly affected your business. You try to eat healthily because of your diabetes and you usually go for a walk each evening.',
  'You think you may have some form of arthritis.',
  'The symptoms have been going on for months and are increasingly limiting what you can do day to day.',
  'You would like to understand what the blood test results mean and were hoping the doctor might arrange a shoulder X-ray. You also want to ask about physiotherapy.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Start by acknowledging that you can see she recently had blood tests and confirm she is calling to discuss the results.',
    'Ask what led to the blood tests being arranged — invite her to describe what has been happening.',
    'Ask about the nature of the shoulder pain and stiffness, including onset, duration, severity, and the pattern of morning stiffness.',
    'Ask how long the morning stiffness lasts and whether it improves with movement. (In polymyalgia rheumatica, morning stiffness typically lasts at least 45 minutes; in osteoarthritis it is usually brief or under 30 minutes.)',
    'Ask whether any other joints are affected, particularly the hips or neck.',
    'Ask about associated muscle weakness or any lumps or bumps around the joints.',
    'Ask about systemic symptoms including fatigue, weight loss, fevers, or night sweats.',
    'Ask about night-time symptoms or whether the pain disturbs her sleep.',
    'Screen for symptoms of giant cell arteritis: ask about new headaches, scalp tenderness, jaw pain on chewing, or any visual changes.',
    'Screen for anaemia: confirm she is post-menopausal with no vaginal bleeding, ask about bowel habits, skin bruising, and symptoms such as breathlessness, dizziness, or palpitations.',
    'Ask how the symptoms have affected her daily activities, ability to drive, social life, and ability to manage at home independently.',
    'Ask about home circumstances and available support.',
    'Ask about smoking and alcohol use.',
    'Ask about her ideas, concerns, and expectations.',
    'Explain that the blood tests show significantly raised inflammatory markers and a mild anaemia, both of which are consistent with polymyalgia rheumatica.'
  ],
  ARRAY[
    'Offer prednisolone 15 mg once daily and arrange a review in one week.',
    'Inform her that if her symptoms improve with steroids, this would strongly support the diagnosis of polymyalgia rheumatica. Explain that steroid treatment would then need to continue long term, with the dose gradually reduced in line with her symptoms. Advise her that treatment typically lasts one to two years and that she will be closely monitored throughout.',
    'Inform her about the side effects of steroids, including the risk of raised blood glucose. Advise that you will check her HbA1c and monitor her blood sugar more closely during treatment — ideally every three months — given that she has diabetes. Encourage her to continue eating healthily and taking her evening walks, as these will help with glucose control. Reassure her that if her blood sugar does rise, her diabetes medications can be adjusted.',
    'Explain that long-term steroids can reduce bone density, so a bone scan will be arranged if she has been on treatment for around three months, and bone health will continue to be assessed throughout.',
    'Explain that steroids increase the risk of infection. Offer relevant vaccinations including pneumococcal, influenza, and COVID.',
    'Advise her to avoid close contact with anyone who has chickenpox, shingles, or measles, particularly if she has not had these illnesses, as she would not have natural immunity. Advise her to seek urgent medical advice immediately if she is exposed.',
    'Explain that steroids can cause stomach irritation, so you will prescribe a medication to protect her stomach lining, such as omeprazole 20 mg once daily.',
    'Explain that steroids must never be stopped suddenly and provide her with a blue steroid card.',
    'Explain that an X-ray of the shoulder is not required to confirm the diagnosis of polymyalgia rheumatica and would expose her to unnecessary radiation without adding diagnostic value.',
    'Explain that physiotherapy can be very helpful once she is stabilised on steroid treatment, to rebuild strength in the shoulders and help her return to her usual level of activity.',
    'Safety-net about giant cell arteritis: advise her to contact the urgent GP line or call 111 immediately if she develops a new headache, any visual disturbance, or jaw pain on chewing.',
    'Arrange a review in one week. For patients who decline steroids, options include NSAIDs for interim pain relief and referral to rheumatology to consider biologic agents such as methotrexate.'
  ],
  'Thank you for calling in, and I''m glad we can go through these results together today. I know it has been a worrying few months with the pain and stiffness, so I want to explain clearly what the tests are showing and what I think is going on.

Looking at your results, the most important findings are your inflammatory markers. Your ESR — a measure of inflammation in the blood — is 60 mm/hr, where the normal range is 0 to 20. Your CRP, another inflammation marker, is 41 mg/L against a normal of less than 5. Both of these are significantly elevated. You also have a very mildly low haemoglobin, which can be seen alongside inflammatory conditions. Reassuringly, your rheumatoid factor came back negative, and everything else — including your thyroid, liver, kidneys, and calcium — is all normal.

Putting these results together with everything you''ve described — the bilateral shoulder pain and stiffness, the morning stiffness that takes around an hour to ease, the difficulty lifting your arms and doing your hair, and the fact that it has been going on for three months — I think the most likely diagnosis is something called polymyalgia rheumatica, or PMR. This is a condition caused by inflammation affecting the muscles and the tissues around the shoulder and hip joints. It is actually one of the most common inflammatory conditions in women over 50, Dorothy, and while it can be very limiting, the good news is that it responds very well to treatment.

The treatment I would like to start you on is a steroid tablet called prednisolone, at a dose of 15 mg once a day. For most people, the improvement in symptoms within the first week or two is quite striking — many patients find they can lift their arms and do their hair again quite quickly. If your symptoms do improve significantly, that would confirm the diagnosis.

I do want to be upfront about the steroid side effects. Because you have diabetes, I will be monitoring your blood sugars more closely while you are on steroids — ideally every three months — and we will adjust your diabetes medications if needed. Steroids can also affect bone density over time, so we will arrange a bone scan after around three months. I will also prescribe omeprazole 20 mg once daily to protect your stomach lining. I will give you a blue steroid card, and it is very important that you do not stop the steroids suddenly — always check with me first before making any changes to the dose.

Regarding the X-ray — I know you were hoping for one, but I want to reassure you that an X-ray would not actually help us confirm this diagnosis and would not add anything useful at this stage. It is not something you need. Physiotherapy, however, is a great idea, and once you are settled on the steroid treatment and feeling more comfortable, we will get that arranged to help rebuild your shoulder strength.

One important safety point: if you ever develop a new headache, any change in your vision, or pain in your jaw when you are eating, please call us urgently or contact 111 straightaway. These could be signs of a related but more serious condition called giant cell arteritis, which needs prompt treatment. Let''s catch up in one week to see how you are getting on.',
  ARRAY[
    'Polymyalgia rheumatica (PMR) classically presents in women over 50 with bilateral proximal shoulder and/or hip girdle pain and stiffness, with morning stiffness lasting at least 45 minutes. ESR and CRP are characteristically elevated; rheumatoid factor is negative.',
    'First-line treatment for PMR is prednisolone 15 mg once daily. A dramatic symptomatic response within one to two weeks is both therapeutic and diagnostic.',
    'Steroid side effects are particularly relevant in patients with comorbidities: monitor HbA1c every three months in diabetic patients, prescribe gastric protection (e.g. omeprazole 20 mg), arrange a DEXA scan after approximately three months, offer relevant vaccinations, and provide a blue steroid card.',
    'Steroids must never be stopped abruptly — patients need clear advice about this and should carry a steroid card at all times.',
    'Giant cell arteritis (GCA) is a serious complication of PMR — screen at every consultation for new headache, scalp tenderness, jaw claudication, or visual symptoms, and advise the patient to seek urgent assessment if any of these arise.',
    'An X-ray is not required to diagnose PMR and should not be offered as a routine investigation; the diagnosis is clinical and biochemical.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  96,
  'Low Mood in Younger Adult',
  'Mental Health',
  'Telephone consultation',
  false,
  'Priya Sharma',
  '23-year-old female',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication', 'No known drug allergy'],
  'Patient booked a routine consultation to discuss some issues.',
  'Patient has booked a routine appointment to discuss some concerns about how she has been feeling.',
  'Hello doctor, I''ve been feeling a bit down recently and I wasn''t sure whether to call, but my brother encouraged me to.',
  'I moved from India to the UK about three months ago to start my university course in Business Management. Since arriving I''ve been feeling quite flat and low. I cry more easily than I used to. The feelings aren''t constant — they come and go — but they''re getting more frequent. I feel disconnected from my family back home and I don''t feel like I really fit in here. Most of the people I''ve met have very different backgrounds and it''s hard to find common ground. I don''t feel depressed exactly, but I don''t feel myself either.',
  ARRAY[]::text[],
  'You do not smoke or drink alcohol. You live in student accommodation on campus. You do not get to speak to your family back home very often because of the time difference. Your sleep and appetite are fine and you are still keeping up with your studies.',
  'You are not sure exactly what is wrong. Your brother, who is a doctor back in India, suggested you see your GP as he thought it might be depression or possibly vitamin D deficiency, given how little sunshine there is in the UK.',
  'You are worried that the low mood might get worse or develop into something more serious like depression.',
  'You are hoping the doctor can help you understand what is going on and offer some support. You would also like a blood test to check whether anything physical might be contributing to how you feel.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Ask about the onset of the low mood and what she thinks might have triggered it.',
    'Ask her to describe her mood — how does she feel day to day? Is it constant or does it come and go?',
    'Ask whether the low mood is affecting her daily activities, including her studies and social interactions.',
    'Screen for symptoms of depression: ask about sleep, appetite, energy levels, ability to concentrate, and loss of interest in things she previously enjoyed.',
    'Ask about suicidal thoughts or thoughts of self-harm in a sensitive, direct manner.',
    'Ask about the impact of moving to a new country — how has she found adjusting to life in the UK, and how is she finding the cultural differences?',
    'Ask about her support network — does she have friends here, and how often does she speak to her family?',
    'Ask about physical symptoms such as muscle or bone pain or general fatigue (to help rule out vitamin D deficiency).',
    'Ask about her social history, including smoking, alcohol use, and accommodation.',
    'Ask about her ideas, concerns, and expectations.'
  ],
  ARRAY[
    'Offer blood tests including vitamin D, thyroid function, LFTs, FBC, U+Es, bone profile, and CRP.',
    'Offer cognitive behavioural therapy (CBT).',
    'Recommend that she look into cultural or community groups in the area that might offer a sense of belonging and connection. Signpost her to a social prescriber who can help her find and access appropriate local support.',
    'Safety-net: explain that if her mood does not improve, or if she begins to experience more persistent feelings of hopelessness, guilt, or thoughts of self-harm or suicide, she should seek help straight away.',
    'Arrange a follow-up appointment in a few weeks to review how she is doing and discuss any results.'
  ],
  'Thank you so much for calling today, and please do pass on my thanks to your brother for encouraging you to get in touch — it was the right thing to do.

I''ve been listening carefully to everything you''ve described, Priya, and I want to start by saying that what you''re feeling makes a great deal of sense given everything you''ve been through. Moving to a new country, leaving your family behind, adjusting to a completely different culture and environment — these are enormous changes, and they are not easy for anyone. The fact that you''re feeling flat, tearful at times, and disconnected is a very understandable response to all of that.

Based on what you''ve shared with me, I think what you are experiencing is something called adjustment disorder. This is a recognised condition that happens when someone struggles to adapt to a significant life change or stressor — and moving countries on your own to start a new course is about as big a life change as it gets. It is different from clinical depression. In depression, the low mood tends to be persistent and pervasive, often affecting sleep and appetite and interest in daily activities, and it does not always have a clear trigger. What you are describing has a clear and understandable trigger, your mood is not constant, your sleep and appetite are fine, and you are still engaging with your studies. These are important distinctions.

I agree with your brother that it is worth checking a vitamin D level, along with a few other routine blood tests. Vitamin D deficiency is very common in the UK, particularly for people who have moved from sunnier climates, and it can contribute to low energy and mood. We will get those results back to you and go from there.

In terms of support, I would like to refer you for cognitive behavioural therapy — CBT — which is a very effective talking therapy that can help you develop practical strategies for managing these feelings and adjusting to your new environment. I would also strongly encourage you to explore whether there are any cultural or community groups near your university — meeting people with shared backgrounds and values can make a real difference to how connected and settled you feel. I can refer you to our social prescriber, who is wonderful at helping people find exactly these kinds of local opportunities.

Please do keep an eye on how you''re feeling. If your mood starts to get worse, or if you ever find yourself experiencing persistent hopelessness, feelings of guilt, or any thoughts of harming yourself, I want you to contact us immediately or call 111. You have done the right thing today and we will make sure you have the support you need. Let''s speak again in a few weeks to see how things are going.',
  ARRAY[
    'Adjustment disorder is characterised by emotional or behavioural symptoms arising in response to an identifiable stressor, such as moving country or starting a new life phase. Symptoms are time-limited and proportionate to the stressor.',
    'Key features distinguishing adjustment disorder from depression include: a clear precipitating stressor, intermittent rather than persistent low mood, preserved sleep and appetite, maintained functioning, and absence of pervasive hopelessness or anhedonia.',
    'Always screen sensitively but directly for suicidal ideation and self-harm in any patient presenting with low mood, regardless of how mild the presentation appears.',
    'Vitamin D deficiency is common in the UK, particularly in individuals who have relocated from sunnier countries, and can contribute to fatigue and mood symptoms — offer testing alongside other routine bloods (TFTs, FBC, U+Es, bone profile, CRP).',
    'Management of adjustment disorder should include psychological support such as CBT, social prescribing to address isolation and lack of community, and clear safety-netting with a follow-up plan.',
    'A warm, non-judgmental consultation style is essential — patients presenting with emotional or psychological concerns are more likely to engage with management if they feel genuinely heard and validated.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  97,
  'Haemoptysis In Palliative Care Patient',
  'Elderly Medicine & Palliative Care',
  'Telephone consultation',
  false,
  'George Alderton',
  '58-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'Paramedic calling on behalf of a palliative care patient who has started coughing up blood at home.',
  '',
  '',
  ARRAY[]::text[],
  'He lives at home with his wife, who is very supportive. He is not keen to go into hospital and wishes to be cared for at home.',
  'You suspect this may be a sign of his cancer getting worse.',
  'You are worried that the bleeding could deteriorate further and that his condition may worsen as a result.',
  'You want to ask the GP for guidance on what should be done now, and whether the team needs to encourage him to accept a hospital admission.',
  ARRAY['IF THE DOCTOR ASKS TO SPEAK WITH THE PATIENT — INFORM THEM THAT BOTH THE PATIENT AND HIS WIFE ARE HARD OF HEARING AND CANNOT TAKE CALLS, AND THAT THEY WOULD PREFER ALL INFORMATION TO BE RELAYED THROUGH YOU.'],
  NULL,
  'Say NO to any other symptoms asked about.',
  ARRAY[]::text[],
  ARRAY['Advise that the patient can continue morphine to help suppress the cough. The dose can be increased if needed, but before doing so, check for common side effects to assess whether the patient can tolerate an increment — these include excessive drowsiness, confusion, nausea, or shallow breathing. If the dose is increased, advise the patient''s wife and carers to monitor for these side effects closely.','Offer to prescribe tranexamic acid to help reduce the bleeding.','Offer a home visit to discuss advance care planning, prescribe anticipatory medications (also known as just-in-case medicines or end-of-life medications), complete an SR1 form for benefits, add the patient to the Gold Standards Framework (GSF) list, and provide the Daffodil Line number — a dedicated rapid-access line for patients to contact the GP surgery promptly.','Inform the district nursing team about the patient and the need for him to have midazolam available at home.','Advise the patient to lie on his side, or on the side of the affected lung, to reduce the risk of aspiration.','If the above measures are insufficient, discuss with the palliative care team regarding further options such as dexamethasone.','Safety-net regarding worsening symptoms.','Thank the paramedic for their call and involvement.'],
  'Thank you so much for calling about George — I can hear that this is a worrying situation for everyone involved, and I want to make sure we do everything we can to support him and his wife at home, in keeping with his wishes.

From what you''ve described, the haemoptysis — coughing up blood — is most likely related to his underlying cancer. This can happen when the tumour affects blood vessels in or around the lungs. While it is distressing to witness, I want to reassure you that there are things we can do to help manage this.

First, the morphine he is already taking is helpful not just for pain but also for suppressing the cough. We can consider increasing the dose if needed, though before doing that it''s important to check he isn''t already showing signs of being too drowsy, confused, nauseated, or having shallow breathing. If the dose is increased, please make sure his wife and any other carers know to watch closely for those side effects.

I am also going to prescribe tranexamic acid, which is a medicine that helps reduce bleeding. This should help with the haemoptysis and is straightforward to give at home.

I will arrange a home visit as soon as possible so that I can speak with George and his wife directly. During that visit, I''d like to have a gentle conversation about advance care planning — making sure we have a clear plan in place that reflects his wishes, and ensuring he has the right medications available at home in case his symptoms worsen. I will also complete the SR1 form to help with any benefits he may be entitled to, and I''ll add him to our Gold Standards Framework list so that our team is closely coordinating his care. I''ll give you the Daffodil Line number too, so his wife has a direct route to reach us quickly if things change.

It would also be helpful to let the district nursing team know about George, and specifically to ensure that midazolam is prescribed and available in the home. This is one of the anticipatory medicines we use in palliative care to help if someone becomes very distressed or agitated.

In the meantime, if the bleeding happens again, it may help to ask George to lie on his side — ideally on the side of the affected lung. This positioning can reduce the risk of any blood being inhaled into the airways.

If these measures aren''t enough, I will liaise with the specialist palliative care team, who may be able to suggest additional options such as dexamethasone to help reduce inflammation and pressure from the tumour.

Please do call back immediately if his symptoms worsen significantly, if the bleeding becomes heavy, or if you have any concerns about his breathing or conscious level. And thank you again for reaching out — it really does make a difference.',
  ARRAY['In palliative care patients with haemoptysis, the most likely cause is progression of the underlying malignancy affecting pulmonary blood vessels; management should be home-based where possible if that is the patient''s wish.','Morphine can be used to suppress cough in palliative settings and may be dose-escalated with careful monitoring for excessive drowsiness, confusion, nausea, and respiratory depression.','Tranexamic acid should be offered to help reduce haemoptysis in palliative patients.','Anticipatory prescribing (just-in-case medications including midazolam), Gold Standards Framework registration, and advance care planning are all key components of end-of-life care in primary care.','The Daffodil Line provides patients and carers with rapid GP access and should be offered to palliative patients managed at home.','Positional advice (lying on the affected side) can reduce aspiration risk during episodes of haemoptysis; if symptoms remain uncontrolled, escalation to the specialist palliative team for consideration of dexamethasone is appropriate.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  98,
  'Penile Curvature in Middle-Aged Man',
  'Men''s Health',
  'Telephone consultation',
  false,
  'Daniel Harper',
  '37-year-old male',
  ARRAY[]::text[],
  ARRAY['Not on any medication','No known drug allergy','No significant recent consultation — booked routine appointment to discuss private concerns'],
  NULL,
  'Patient booked a routine telephone consultation to discuss a private concern.',
  '',
  '',
  ARRAY[]::text[],
  '',
  '',
  '',
  'You would like the GP to explain what is going on and to discuss what treatment options might be available.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any questions outside of the details already provided in this scenario. Accept any treatment offered by the doctor.',
  ARRAY['Ask about the onset of symptoms — when he first noticed the curvature or change in the shape of the penis','Ask about any lumps, bands, or areas of scar tissue on the penis — ask the patient to describe the lump, including whether it is ulcerating, firm, hard, or mobile','Ask whether the curvature has been getting worse over time or has remained roughly stable','Ask whether there are any problems with erections, or any pain during sexual activity or during an erection','Ask about any history of trauma or injury to the penis','Ask about any urinary symptoms','Ask about any bloody penile discharge or blood during ejaculation','Ask how the symptoms have affected his sexual life and relationship','Ask about any family history of this condition','Explore the patient''s ideas, concerns, and expectations'],
  ARRAY['Reassure the patient that Peyronie''s disease is a relatively common condition and is not life-threatening','Offer a face-to-face appointment to examine the penis and ensure there is nothing sinister, which is unlikely but important to rule out','Explain that because the symptoms are affecting his erections, causing pain, and causing distress, a routine referral to urology is warranted','Advise that in many people with Peyronie''s disease, the condition resolves spontaneously over time','Offer appropriate analgesia such as ibuprofen to manage any pain and reduce inflammation','Offer psychosexual counselling for the patient and his partner if confidence or the relationship has been affected — a well-known service is RELATE','Safety-net: advise that if the curvature becomes more severe or begins to prevent intercourse, or if the pain does not improve, he should seek further medical advice'],
  'Thank you for coming forward with this — I appreciate it can feel like a difficult thing to discuss, and I want to reassure you that you''ve done absolutely the right thing by bringing it to us.

From what you''ve described, Daniel, with the gradual development of a curve over the past several months, the sensation of what feels like a firm lump or area of scar tissue along the shaft, pain during erections, and the impact on intercourse — this sounds very much like a condition called Peyronie''s disease. I want to be clear straightaway: this is not cancer, and although it is very uncomfortable and understandably worrying, it is not life-threatening.

Peyronie''s disease occurs when scar tissue — we call it a plaque — forms inside the penis, usually beneath the surface. This scar tissue can make the penis curve during an erection. We don''t always know exactly why this happens. Sometimes there has been an injury during intercourse or physical activity, but it can also develop without any obvious cause. Importantly, you are far from alone — it is more common than many people realise, and most men find it difficult to talk about, which is why it often goes unreported.

The positive news is that in a good number of cases, Peyronie''s disease does improve on its own over time. However, because your symptoms are affecting your erections, causing pain, and having an impact on your relationship, I think it is right that we get some specialist input. I will refer you routinely to a urologist, who will be able to assess you in more detail. They may discuss options such as vacuum devices to encourage blood flow, or in more significant cases, they may consider a procedure to correct the curve.

In the meantime, I would also like to arrange a face-to-face appointment to examine you — just to make sure there is nothing else going on. While I am not expecting anything sinister, it is the right thing to do.

For the pain, over-the-counter anti-inflammatory tablets such as ibuprofen can help — they are best taken with food, and you should avoid them if you have any stomach problems or kidney concerns.

Finally, I know that this kind of issue can take a real toll on confidence and on a relationship. There is no shame in that at all. If you feel it would be helpful, we can discuss a referral to a psychosexual counselling service. One well-known option is called RELATE, who work with both individuals and couples and are very experienced in exactly this kind of situation.

Please do come back to us if the curvature gets noticeably worse, if the pain increases, or if you find intercourse becomes impossible. We are here to support you through this.',
  ARRAY['Peyronie''s disease is caused by the formation of fibrous scar tissue (plaque) within the penis, leading to penile curvature, pain on erection, and possible erectile dysfunction; it is not malignant.','Key history points include onset and progression of curvature, presence and characteristics of any palpable lump, pain during erections or intercourse, history of penile trauma, urinary symptoms, and impact on sexual function and relationships.','Management includes face-to-face examination to exclude sinister pathology, routine urology referral when the condition is painful, progressive, or affecting erectile function, and analgesia such as ibuprofen for symptom relief.','Many cases of Peyronie''s disease resolve spontaneously, but specialist options include vacuum erection devices and surgical correction for severe or persistent cases.','Psychosexual counselling (e.g. RELATE) should be offered when symptoms are affecting the patient''s confidence or relationship.','Safety-netting should advise return if curvature worsens significantly, intercourse becomes impossible, or pain does not settle.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  99,
  'Hearing Loss',
  'ENT & Eye',
  'Video consultation',
  false,
  'Thomas Griffiths',
  '23-year-old male',
  ARRAY[]::text[],
  ARRAY['Not on any medication','No known drug allergy','No significant recent consultation — booked routine appointment to discuss concerns'],
  NULL,
  'Patient booked a routine video consultation to discuss gradual hearing loss in his right ear over the past month.',
  '',
  '',
  ARRAY['You had a cold with nasal congestion and a sore throat, which cleared up, but since then you have noticed a gradual decline in hearing in your right ear.','You are struggling to follow lectures clearly, and it is affecting your part-time work playing guitar in a band.','You have noticed difficulty making out sounds, particularly in noisy environments.','You sometimes notice a feeling of fullness in the ear along with mild ringing, but there is no pain. You have not had any dizziness or vertigo.','You are concerned that this might be connected to your regular exposure to loud music. You have been playing in loud environments for about a year, and although you occasionally wear earplugs, it is not consistent.','There is no family history of hearing loss.','Say NO to any other symptoms asked about.'],
  'Non-smoker. Lives in university halls of residence.',
  'You wonder whether the hearing loss might be caused by your exposure to loud music.',
  'You are worried it could be something serious or permanent, which might affect your ability to pursue a career in music.',
  'You are hoping for a diagnosis and some treatment that might help restore your hearing. You are also wondering whether you should stay away from loud music in the meantime.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other symptoms asked about.',
  ARRAY['Ask about the onset of the hearing loss and how long it has been present','Ask whether the hearing loss affects one ear or both','Ask whether the hearing loss came on suddenly or gradually — note that sudden-onset hearing loss developing within 72 hours, presenting within the past 30 days, and not explained by external or middle ear causes requires urgent ENT referral within 24 hours','Ask whether symptoms have improved, worsened, or stayed the same — worsening hearing loss warrants audiometry referral','Ask about any recent or preceding cold or flu symptoms, and if so, whether there was nasal congestion','Ask about any discharge from the ear','Ask about any pain in the ear','Ask about tinnitus, a feeling of popping sounds, or a sensation of fullness in the ear','Ask about dizziness or vertigo','Ask about noise exposure','Ask about any head trauma','Ask about personal or family history of hearing loss','Explore the impact of symptoms on the patient''s daily life and work','Ask about red flags including unilateral altered facial sensation or unilateral facial weakness','Ask about smoking, as this can contribute to Eustachian tube dysfunction','Explore the patient''s ideas, concerns, and expectations','Arrive at a working diagnosis of hearing loss due to Eustachian tube dysfunction secondary to a recent upper respiratory tract infection'],
  ARRAY['Offer a face-to-face appointment to examine the ear with an otoscope, assess the cranial nerves including the facial nerve, and perform bedside hearing tests (Rinne''s and Weber''s)','Offer referral to audiology for formal audiometry — alternatively, it is reasonable to review in two weeks first before referring, given the likely self-limiting cause','Advise limiting exposure to loud music where possible and encourage consistent use of noise-cancelling or musician''s earplugs during band practice to prevent further damage','Reassure that Eustachian tube dysfunction typically resolves within six weeks in most people','Safety-netting: advise return if the hearing loss does not improve within two to three weeks, or if it worsens','Advise the patient to seek urgent medical attention if he develops severe ear pain, dizziness, or discharge from the ear, as these could indicate an infection. Important clinical notes: sudden-onset (developing within 72 hours) unilateral or bilateral hearing loss, occurring within the past 30 days and not explained by external or middle ear causes, requires urgent ENT referral within 24 hours. If focal neurology is present, the same-day assessment is needed to exclude stroke. Hearing loss that is sudden-onset but developed more than 30 days ago, or rapidly progressive hearing loss over 4–90 days not explained by external or middle ear causes, requires ENT or audio-vestibular medicine referral to be seen within 2 weeks. Eustachian tube dysfunction is a common cause of post-viral hearing loss and can also be caused by altitude changes, smoking, sinusitis, rhinitis, hay fever, or glue ear. Symptoms include muffled hearing, a sensation of popping, ear pressure or mild pain, tinnitus, and occasionally mild dizziness.'],
  'Thank you for coming to see me today about this — I can understand how worrying it must be, especially with your studies and your work in the band.

Based on everything you have told me, Thomas, I think I have a good idea of what is going on. The pattern of your symptoms — the gradual decline in hearing in the right ear that started around the time you had a cold, the sense of fullness, and the mild ringing — all point towards a condition called Eustachian tube dysfunction. Let me explain what that means.

The Eustachian tube is a small channel that connects your middle ear to the back of your nose and throat. Its job is to equalise pressure in the ear. When you had your recent cold, the lining of that tube can become swollen or blocked, which prevents it from working properly. This can cause the ear to feel full and make sounds seem muffled or quieter than usual. The good news is that in the majority of people, this settles on its own once the tube starts working normally again — usually within about six weeks.

I do also want to acknowledge your concern about loud music. You have been playing in noisy environments for around a year, and while I think your current symptoms are most likely down to the cold rather than noise damage, it is absolutely worth protecting your hearing going forward. I would strongly encourage you to wear earplugs consistently during rehearsals and performances — ideally musician''s earplugs, which reduce volume without distorting sound quality.

I would like to arrange a face-to-face appointment so I can look inside your ear with an otoscope, check the nerve supply to your face, and do some simple hearing tests. I also want to refer you to audiology for a formal hearing test, which will give us a much clearer picture of exactly what is happening and whether there is any element of noise-related change.

If the hearing does not improve within the next two to three weeks, or if things get worse, please do come back to see us sooner. And if you ever develop severe pain, dizziness, or discharge from the ear, I would want you to seek medical attention promptly, as that could suggest an infection developing.

The outlook here is genuinely reassuring — most people with Eustachian tube dysfunction recover fully. With the right ear protection going forward, there is every reason to hope this won''t affect your music career in the long run.',
  ARRAY['Eustachian tube dysfunction is a common cause of hearing loss following a viral upper respiratory tract infection; it typically resolves within six weeks and does not usually require active treatment beyond reassurance and monitoring.','Sudden-onset hearing loss (developing within 72 hours) that is unexplained by external or middle ear causes and presents within 30 days requires urgent ENT referral within 24 hours for consideration of steroids — this is a key safety-net criterion.','If focal neurological signs are present alongside sudden hearing loss, same-day assessment is needed to exclude stroke.','Hearing loss that is sudden-onset but presented more than 30 days ago, or that is rapidly progressive over 4–90 days, warrants ENT or audio-vestibular medicine referral to be seen within 2 weeks.','Face-to-face assessment should include otoscopy, cranial nerve examination (particularly facial nerve), and bedside tests (Rinne''s and Weber''s); formal audiometry provides definitive assessment.','Noise exposure is an important risk factor for sensorineural hearing loss, and consistent use of appropriate ear protection should be strongly encouraged in patients regularly exposed to loud environments.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  100,
  'Chronic Cough In Young Adult',
  'Respiratory',
  'Video consultation',
  false,
  'Priya Nair',
  '26-year-old female',
  ARRAY[]::text[],
  ARRAY['Not on any medication','No known drug allergy','No significant recent consultation'],
  NULL,
  'Patient booked a routine video consultation to discuss a persistent cough with associated symptoms.',
  '',
  '',
  ARRAY[]::text[],
  'Born in India; moved to the UK three years ago to work in the technology sector. Previously worked in a factory producing construction and plumbing materials. Non-smoker and does not drink alcohol. Lives in a shared house with work colleagues. Was not vaccinated against TB.',
  'You are worried this could be lung cancer because of the haemoptysis and weight loss.',
  'You are embarrassed by the cough at work and anxious about the possibility of a serious diagnosis such as cancer.',
  'You would like the doctor to investigate what is causing your symptoms and advise on what to do next.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other symptoms asked about.',
  ARRAY[]::text[],
  ARRAY['Offer a face-to-face appointment to assess the patient and listen to the chest','Arrange urgent investigations including sputum culture for routine microbiological screen and TB, and blood tests — FBC, ESR, CRP, and U&Es','Arrange an urgent chest X-ray','Inform the patient that because TB is suspected, she will be referred urgently to a respiratory specialist who will confirm the diagnosis','Advise that if TB is confirmed, she will require a course of antibiotics lasting approximately six months to fully eradicate the infection','Explain that TB spreads from person to person through the air when someone with active pulmonary TB coughs, sneezes, or speaks. If TB is confirmed, public health officials will be notified and they will work to identify close contacts who will need to be tested and treated if necessary','Advise on interim infection control measures: wearing a protective face mask, covering the mouth and nose when coughing or sneezing, disposing of sputum and used tissues safely, and maintaining good hand hygiene','Advise the patient to avoid enclosed public spaces and crowded environments until a diagnosis has been established and specialist guidance has been received. This may mean she needs to avoid work, and a sick note can be provided if required','Safety-netting: advise that if she notices increased blood in her cough, significant chest pain, or increasing breathlessness, she should seek urgent medical attention'],
  'Thank you for coming to see me today — I can hear how worried you have been, and I want you to know that we take your concerns very seriously and we are going to get to the bottom of this together.

You have described a persistent cough, coughing up some blood, losing weight, and feeling generally unwell over a period of time. I can understand why your mind has gone to something like cancer, Priya, and I want to acknowledge that. However, I would like to explain what I think may actually be going on.

Given your background — moving to the UK from India relatively recently, your previous work in a factory environment, and the fact that you were not vaccinated against TB — I am concerned that we need to rule out a condition called tuberculosis, or TB. TB is a bacterial infection that most commonly affects the lungs. It can cause exactly the kind of symptoms you have been experiencing: a persistent cough, coughing up blood, night sweats, weight loss, and fatigue. It is important to say that this is not a reflection of anything you have done — TB can affect anyone, and it is simply something we need to investigate promptly.

To get a clear picture, I would like to start some urgent tests. I will arrange for you to come in for a face-to-face appointment so I can examine your chest. I will also arrange blood tests — including a full blood count, inflammatory markers, and kidney function — along with a sputum sample, which is a sample of the mucus from your cough, to look for the TB bacteria directly. And I will request an urgent chest X-ray.

Because of the clinical picture, I will also refer you urgently to a respiratory specialist. They will be best placed to confirm the diagnosis and guide your treatment. If TB is confirmed, the standard treatment is a course of antibiotics taken for around six months. It is a long course, but it is very effective when taken consistently.

I also want to be open with you about something important. TB is spread through the air when someone with active pulmonary TB coughs, sneezes, or speaks near others. If the diagnosis is confirmed, we will need to inform public health officials, who will then try to identify and test anyone who has been in close contact with you. This is a routine process and nothing to be alarmed about — it is simply about protecting others.

In the meantime, while we are waiting for the results, I would ask you to take some precautions: wearing a face mask when you are around others, covering your mouth and nose carefully when you cough or sneeze, disposing of tissues hygienically, and washing your hands regularly. I would also advise avoiding crowded, enclosed spaces for now. Depending on what the specialist advises, you may need to stay away from work temporarily, and I can provide a sick note to support you with that.

Please do come back to us urgently if the blood in your cough increases, if you develop chest pain, or if your breathing becomes more difficult. We are here to support you through this.',
  ARRAY['TB should be suspected in patients presenting with a chronic cough, haemoptysis, unintentional weight loss, night sweats, and risk factors such as birth or residence in a high-prevalence country, unvaccinated status, or occupational dust exposure (e.g. silica in construction materials, which also carries a risk of silicosis).','Urgent investigations for suspected TB include sputum culture (for routine microscopy, culture, and sensitivity, as well as TB-specific testing), FBC, ESR, CRP, U&Es, and an urgent chest X-ray.','Patients with suspected active pulmonary TB should be referred urgently to a respiratory specialist for confirmation and to initiate treatment, which typically consists of a six-month course of antibiotics.','TB is a notifiable disease; if confirmed, public health authorities must be informed so that contact tracing can be carried out to identify and test close contacts.','Interim infection control advice for suspected TB includes wearing a face mask, covering the mouth and nose when coughing or sneezing, safe disposal of sputum and tissues, good hand hygiene, and avoiding crowded enclosed spaces — which may necessitate absence from work.','Safety-netting should include advice to seek urgent attention if haemoptysis worsens, significant chest pain develops, or breathlessness increases.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  101,
  'Recurrent Finger Discolouration in Young Woman',
  'General Practice',
  'Telephone consultation',
  false,
  'Michelle Okafor',
  '30-year-old female',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No known drug allergy','No significant recent consultations — booked routine telephone consultation to discuss concerns'],
  NULL,
  'Patient calling to discuss recurring episodes of colour changes in her hands that have been worsening.',
  'Hi doctor, I am calling because I keep having problems with my hands. They keep changing colour and things have been getting worse.',
  'You have been noticing problems with your hands for about four years, but things have become worse over the last six months. Your hands first go white, then turn blue, and finally turn red. When they are white or blue, they feel numb. When they turn red, they become painful. You have noticed that the episodes tend to happen when you are playing the clarinet. You usually have to stop playing, and the symptoms settle after roughly fifteen minutes. You are a professional musician and perform at events such as weddings and corporate dinners.',
  ARRAY[]::text[],
  'You smoke around fifteen cigarettes a day and have done for the past five years. You live with your partner. You do not drink alcohol or use illicit drugs. Family history is unknown, as you were adopted.',
  'You are not sure what this condition might be.',
  'You have an important performance at a large venue in four weeks'' time and are worried that this problem will interfere with your ability to play.',
  'You would like to understand what might be causing this and what can be done to manage it.',
  ARRAY['If the doctor offers a face-to-face appointment to examine your hands, ask: "What will that actually show, since I don''t have the symptoms right now — it only happens when I''m playing the clarinet?"'],
  NULL,
  'Say NO to any other questions or symptoms outside of the details already provided in the scenario. Accept anything the doctor offers.',
  ARRAY['Ask about the onset and duration of symptoms','Ask whether the symptoms affect both hands or just one','Ask about the sequence of colour changes in the fingers (white, blue, red) and how long it takes for the fingers to return to normal','Ask whether there is any pain during episodes','Ask about abnormal sensations such as tingling, numbness, or pins and needles','Ask about known triggers, including cold exposure, repetitive finger movements such as clarinet playing, emotional stress, or the use of vibrating tools','Ask whether other areas are affected, such as the tip of the nose, earlobes, tongue, or nipples','Ask about any ulcers on the fingers or thickening or tightening of the skin (sclerodactyly), which may suggest secondary Raynaud''s','Ask about any weakness or reduced grip strength in the hands','Ask about itching, or red or purple swollen lesions on the fingers following cold exposure, which may suggest chilblains — noting that chilblains are triggered by cold alone, whereas Raynaud''s can also be triggered by stress, vibrating tools, or repetitive finger use','Ask about symptoms of CREST syndrome — a limited form of systemic sclerosis — including calcinosis (hard lumps under the skin), Raynaud''s phenomenon, oesophageal dysmotility (difficulty swallowing), sclerodactyly (skin tightening over the fingers), and telangiectasia (small visible blood vessels on the skin)','Ask about the impact of symptoms on daily life and musical performance','Ask about smoking, alcohol use, and occupational exposures such as cold environments or vibrating tools','Ask about family history of Raynaud''s or autoimmune conditions','Explore the patient''s ideas, concerns, and expectations','Arrive at a working diagnosis of Raynaud''s phenomenon'],
  ARRAY['Offer a face-to-face assessment to examine the hands for pulses, check for ulcers on the fingers, and measure blood pressure','Explain to the patient that even though she does not have symptoms right now, examination is important to assess blood flow by checking her pulse and to measure blood pressure before starting any medication','Advise the patient to take photographs of her fingers during an episode if possible, so that the colour changes can be documented','Arrange blood tests including an autoimmune screen, CRP, ESR, and FBC, to check for secondary Raynaud''s — noting that secondary Raynaud''s can be associated with occupational factors such as repetitive hand movements or vibrating tools, and is less likely to be associated with a family history than primary Raynaud''s','Offer Nifedipine (immediate release) 5 mg three times a day, explaining that this medication can lower blood pressure and may cause dizziness, but that most people tolerate it well; advise the patient to report any troublesome side effects','Strongly advise smoking cessation, as smoking impairs circulation and worsens Raynaud''s symptoms','Discuss practical strategies for managing symptoms during performances, such as taking short breaks, warming the hands between sessions, and exploring padded finger supports or ergonomic adjustments to the clarinet to reduce repetitive pressure','Advise that stress can be a trigger and encourage relaxation techniques such as deep breathing or mindfulness','Encourage the patient to keep hands warm before and during playing, for example by using gloves or hand warmers'],
  'Thank you so much for calling, and I''m really glad you decided to get in touch about this. What you''ve been describing sounds quite distressing, especially with such an important performance coming up.

From everything you''ve told me, Michelle, the pattern of colour changes you''re experiencing — hands turning white, then blue, then red, with numbness and pain — is very characteristic of a condition called Raynaud''s phenomenon. Let me explain what that means.

In Raynaud''s, the small blood vessels in the fingers temporarily narrow, which cuts off the blood supply briefly. That''s why the fingers turn white first — the blood drains away. They then turn blue as the oxygen in the remaining blood is used up, and finally red as the blood flow returns and the vessels open up again. The numbness happens when blood flow is reduced, and the pain you feel when they turn red is caused by the rush of blood coming back. It usually settles on its own within about ten to twenty minutes, which fits with what you''ve described.

I want to address something you asked, which is what a face-to-face appointment would actually show. Even though you don''t have symptoms right now, it is very important that I examine you before we consider starting any treatment. I need to check the blood flow in your hands by feeling the pulses, and I also need to measure your blood pressure, because one of the medications we use for Raynaud''s can lower it. I would not want to start treatment without checking that first.

I would also like to arrange some blood tests — these are to check whether there is an underlying autoimmune or inflammatory condition that might be contributing to your symptoms. This is what we call secondary Raynaud''s. In your case, the repetitive finger movements from playing the clarinet are likely acting as a trigger, which can be associated with secondary Raynaud''s. The blood tests will help us understand the full picture.

In terms of medication, there is a tablet called Nifedipine, taken at a dose of 5 mg three times a day. It works by relaxing and widening the small blood vessels, which improves circulation and reduces the frequency and severity of episodes. Most people tolerate it well. The main side effect to be aware of is that it can sometimes cause light-headedness or dizziness because it lowers blood pressure — which is exactly why I need to check your blood pressure first. Please let us know if you notice any troublesome effects.

I also want to have an honest conversation about smoking. Smoking narrows the blood vessels throughout the body, and it will make Raynaud''s significantly worse. I know it can be hard to stop, but this is genuinely one of the most important things you can do to improve your symptoms. We have excellent stop-smoking support services and I would be happy to refer you.

In terms of managing your performances, there are some practical steps that can really help. Warming your hands thoroughly before you start playing — using gloves, hand warmers, or even warm water — can reduce the likelihood of triggering an episode. Taking short breaks during practice and performance can also make a difference. It is also worth exploring whether padded finger supports or small cushions on the clarinet keys might help reduce the repetitive pressure on your fingers. And stress can sometimes be a trigger too, so simple relaxation techniques like deep breathing before you go on stage may be helpful.

With the right treatment and these adjustments, most people with Raynaud''s are able to continue doing the things they love. I very much hope we can help you get to that four-week performance feeling more confident.',
  ARRAY['Raynaud''s phenomenon is characterised by episodic vasospasm of small digital vessels causing a classic triphasic colour change: white (ischaemia) → blue (deoxygenation) → red (reperfusion); triggers include cold, stress, repetitive finger use, and vibrating tools.','Primary Raynaud''s (Raynaud''s disease) occurs without an identifiable cause, while secondary Raynaud''s is associated with connective tissue disease, occupational factors, or medications; secondary Raynaud''s is more likely when onset is after age 30, episodes are asymmetric or severe, or when features of CREST syndrome are present.','Investigations for possible secondary Raynaud''s should include FBC, CRP, ESR, and autoimmune screen (including ANA); referral to rheumatology is indicated if the autoimmune screen is positive or if there is evidence of an associated connective tissue disease.','First-line pharmacological treatment is Nifedipine (immediate release) 5 mg three times a day; blood pressure must be checked before initiation due to the hypotensive effect; in primary Raynaud''s, intermittent dosing (taken only before anticipated cold exposure) is also an option once secondary causes are excluded.','Smoking cessation is strongly advised as nicotine causes vasoconstriction and significantly worsens symptoms.','Non-pharmacological management includes hand warming strategies (gloves, hand warmers), taking regular breaks from repetitive finger use, ergonomic adjustments to instruments or tools, and stress management techniques; chilblains should be distinguished from Raynaud''s as they are triggered by cold alone.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  102,
  'Diazepam Request in Anxiety Patient',
  'Mental Health',
  'Video consultation',
  false,
  'Naomi Adeyemi',
  '31-year-old female',
  ARRAY[]::text[],
  ARRAY['Fostair 100/6 — one puff twice daily; one puff as required for symptom relief; maximum 8 puffs per day','No known drug allergy'],
  'Patient booked a routine video consultation to discuss concerns about ongoing anxiety and a request for diazepam.',
  'Hi doctor, I have been feeling really anxious for quite a long time now. My heart races, I worry constantly about all sorts of things, and I just feel like I am always on edge. This has been going on for about seven months, but it has become a lot worse over the last five days because of a big presentation I have coming up at work. I was given diazepam in the past and I would really like to have it again — it feels like the only thing that actually helps me.',
  'You recently started a new position in the finance industry. For the past seven months you have been experiencing persistent, daily anxiety and excessive worry about multiple things — work, money, your health, and letting people down. You feel constantly on edge and struggle to relax. You often notice your heart racing, become very tense, and at times feel so overwhelmed that it affects your concentration and ability to get things done. Although your anxiety is always present, it has become significantly worse over the past seven days in the lead-up to an important work presentation. No family history of heart disease or mental health conditions.',
  ARRAY[]::text[],
  'You do not smoke, drink alcohol, or use illicit drugs. You live with your partner. You work as a financial analyst.',
  'You suspect you may be experiencing anxiety.',
  'You are worried that these feelings of anxiety will affect your performance at work, especially with your upcoming presentation.',
  'You would like the GP to prescribe diazepam to help control your symptoms. You have already tried relaxation techniques but they have not made much difference. You are particularly worried about breaking down during the presentation, which could put your job at risk.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other symptoms asked about.',
  ARRAY['Ask about the onset of symptoms and how they have changed over time','Ask about the frequency and intensity of symptoms, and whether they are constant or linked to specific triggers such as upcoming presentations','Ask whether symptoms are present as persistent worry and tension throughout most of the day — pointing towards generalised anxiety disorder — or whether they come as sudden, intense episodes that peak quickly and then settle, which would point more towards panic disorder','Ask about associated symptoms including tingling around the lips or mouth, restlessness, shortness of breath, palpitations, or chest pain','Ask about the impact of symptoms on daily life and work performance','Ask about mood and general emotional wellbeing','Screen for suicidal ideation or self-harm risk','Ask about sleep quality and appetite','Ask about smoking, alcohol, and illicit drug use','Ask about any personal or family history of anxiety, panic attacks, or other mental health conditions','Explore the patient''s ideas, concerns, and expectations','Arrive at a working diagnosis of possible generalised anxiety disorder'],
  ARRAY['Offer a very short course of diazepam (for example, 2 mg three times daily for up to three days), making clear that this is for short-term use only during the acute crisis period and will not be re-prescribed, due to the risks of tolerance, dependence, and addiction','Explain the importance of long-term anxiety management rather than relying on diazepam','Offer Cognitive Behavioural Therapy (CBT) as the first-line talking therapy for generalised anxiety disorder','Discuss the option of starting an SSRI such as sertraline for long-term symptom control. Explain that it typically takes around four to six weeks to feel the full benefit of the medication, and that anxiety symptoms may temporarily worsen during the first week. Inform the patient about other common side effects including mild gastrointestinal upset.','If the patient is willing to start an SSRI, explain that because her presentation is in five days, it would be best to begin sertraline after the presentation, as SSRIs can sometimes make anxiety feel worse in the first week before improvement is noticed','Advise that there is a small increased risk of suicidal thinking in some people when starting SSRIs, and arrange a follow-up review within one week of starting the medication','Advise on self-help strategies including relaxation techniques, breathing exercises, mindfulness, and lifestyle adjustments such as regular sleep and physical exercise','Safety-net: advise the patient to seek urgent help if she develops suicidal thoughts, thoughts of self-harm, or experiences a significant worsening of symptoms'],
  'Thank you for being so open with me today — I know it takes courage to talk about these things, and I want to start by saying that what you are going through sounds genuinely exhausting.

From everything you have described, Naomi, I do agree with you that you are experiencing anxiety. More specifically, what you''re describing fits with something called generalised anxiety disorder, or GAD. This is where the mind becomes caught in a cycle of excessive worry about everyday things — work, finances, health, relationships — in a way that feels disproportionate to the actual risk, and that starts to interfere with daily life. The physical sensations you''ve noticed, like your heart racing and feeling constantly tense and on edge, are very typical of how anxiety affects the body. It''s not a sign of weakness — it''s the body''s alarm system being stuck in the ''on'' position.

I want to talk to you honestly about the diazepam, because I understand why you are asking for it and I do not want to dismiss that. Diazepam can take the edge off anxiety quickly, and I can see why that has felt helpful in the past. However, it is not a safe long-term solution. Over time, the body can become reliant on it, meaning you need more and more to get the same effect, and stopping it can actually cause the anxiety to feel worse than before. For these reasons, I am only able to offer you a very short course — something like 2 mg three times a day for up to three days — to help you get through this particularly difficult period before your presentation. I want to be clear that I would not be able to continue prescribing it beyond that. Does that seem reasonable to you?

Looking beyond this week, the most effective treatments for generalised anxiety disorder are ones that work over time. The first is a talking therapy called Cognitive Behavioural Therapy, or CBT. This helps people identify unhelpful thought patterns and develop practical strategies to manage worry. Most people find it genuinely transformative with a bit of time and practice.

The other option is a medication called sertraline. It is not addictive, and it works very well for many people with anxiety. The important thing to know is that it does not work straight away — it usually takes around four to six weeks to feel the full benefit. In the first week, some people actually notice their anxiety feels a little worse before it improves, which is why I would suggest you start it after your presentation rather than now. I''d also like you to know that, very occasionally, SSRIs like sertraline can be associated with an increase in suicidal thoughts when first started. Because of this, I would always arrange to review you one week after starting, and I want you to know that if you ever felt unsafe or had thoughts of harming yourself, I would want you to seek urgent help straightaway — whether that''s calling us, ringing 111, or going to A&E.

In the meantime, self-help strategies can make a real difference alongside any treatment. Things like structured breathing exercises, mindfulness practice, gentle regular exercise, and maintaining a consistent sleep routine all help to reduce the overall burden of anxiety. They won''t fix everything on their own, but they genuinely support recovery.

You are absolutely right to have sought help — this is very treatable, and with the right support in place, there is every reason to feel hopeful.',
  ARRAY['Generalised anxiety disorder (GAD) is characterised by persistent, excessive worry about multiple everyday topics present on most days for at least six months; it should be distinguished from panic disorder, in which anxiety occurs as discrete sudden episodes that peak within minutes.','Diazepam may be offered as a short-term measure during acute crises at a dose of 2 mg three times daily for a maximum of two to four weeks; it must not be prescribed long-term due to the significant risks of tolerance, dependence, and withdrawal-related worsening of anxiety.','First-line management of GAD includes Cognitive Behavioural Therapy (CBT) as talking therapy and an SSRI such as sertraline for pharmacological long-term control; NICE does not recommend propranolol for anxiety or panic disorder.','SSRIs typically take four to six weeks to reach full efficacy; anxiety symptoms may transiently worsen in the first week of treatment, and patients should be counselled about this before starting — in this scenario, starting after a known stressor (the presentation) is appropriate.','All patients started on SSRIs should be reviewed within one week due to the small but recognised risk of increased suicidal ideation on initiation; patients must be advised to seek urgent help if they develop suicidal thoughts or self-harm urges.','Self-help strategies including breathing exercises, mindfulness, regular physical activity, and good sleep hygiene should be recommended alongside formal treatment as part of a comprehensive management plan.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  103,
  'Haemochromatosis',
  'Gastroenterology & Haematology',
  'Video Consultation',
  false,
  'Martin Clarke',
  '57-year-old male',
  ARRAY[]::text[],
  ARRAY['Amlodipine 10mg OD','No known drug allergy'],
  'Letter from Haematology Dear GP, Re: Martin Clarke | 57 years old | male Thank you for your referral of Mr Martin Clarke, who presented with fatigue and joint pain. His initial blood tests revealed elevated serum ferritin and transferrin saturation levels. Genetic testing confirmed homozygosity for the HFE C282Y mutation, consistent with hereditary haemochromatosis. He has commenced therapeutic venesection, which has successfully reduced his ferritin levels into the target range. He reports some improvement in symptoms and has tolerated the procedure well, without complications. Mr Clarke will require regular venesection therapy to maintain ferritin levels between 50–100 µg/L and transferrin saturation below 50%. This will be arranged through the hospital phlebotomy service and haematology clinic. We have advised him to avoid iron-fortified foods, vitamin C supplements, and alcohol to reduce liver strain. Liver function tests and imaging (including a recent ultrasound) have shown no evidence of cirrhosis or hepatocellular carcinoma at this stage. However, ongoing monitoring will be necessary, and I have copied Dr Patel (Consultant Hepatologist) to this letter, who will ensure this monitoring. I have advised that he discusses family screening of his condition with his GP. Mr Clarke will continue to attend the haematology clinic for venesection and monitoring, and we will keep you updated on his progress. Should he develop new symptoms or if there are any concerns, please do not hesitate to contact us. Kind regards, Dr A. El-Masry MB BCh, MRCP (UK), FRCP (Edin) Consultant Haematologist. Patient has booked a video consultation to discuss concerns about his condition.',
  'Patient booked a video consultation to discuss concerns following his haemochromatosis diagnosis and ongoing treatment.',
  'Hi doctor, I was recently told I have something called haemochromatosis. I''ve been going to the hospital for treatment where they take blood out at regular intervals, and I am feeling better for it, but I am quite worried about what this all means for my family.',
  '',
  ARRAY[]::text[],
  'Martin lives with his wife. His two adult children live nearby but independently. He does not smoke. He drinks approximately two cans of lager at the weekend.',
  'Martin is unsure what exactly caused the condition and whether his lifestyle played a role.',
  'Martin has read online and was told by the hospital consultant that the condition is genetic. He is worried he may have passed it on to his children — a 26-year-old daughter and a 21-year-old son — and wants to know whether they should be screened. Neither child has any symptoms at present.',
  'Martin would like the GP to explain the condition more clearly and to advise whether his children need to be tested. He also wants guidance on whether he needs to completely avoid iron in his diet. Family history: Martin is adopted and has no information about his biological family. His wife is also adopted and does not know her biological family history.',
  ARRAY[]::text[],
  'I was told to avoid iron in my diet. Does that mean I need to cut out everything with iron in it, like red meat or spinach?',
  'Decline to answer questions or report symptoms outside of what is provided in the brief.',
  ARRAY['Ask about current symptoms: for example, the letter indicates your symptoms have improved — is that still the case? Any ongoing fatigue, joint pain, abdominal discomfort, erectile dysfunction, or skin changes?','Ask about family history of haemochromatosis or other iron-related conditions','Ask about the health of his children — any symptoms of fatigue, joint problems, or unexplained illness?','Ask about his partner''s health and any relevant family history on her side','Ask about lifestyle, including alcohol intake, smoking, red meat and iron-fortified food consumption, and occupation','Ask about mood and any anxiety related to the diagnosis','Explore the patient''s understanding of haemochromatosis','Explore the patient''s ideas, concerns, and expectations'],
  ARRAY['Explain haemochromatosis in plain terms, including the genetic basis and the mechanism by which iron accumulates in the body','Advise that his children should be tested via their own GP, who will arrange blood tests including serum ferritin and transferrin saturation, with genetic testing arranged if indicated','Advise keeping alcohol consumption within recommended limits to reduce the risk of liver damage','Explain that he does not need to avoid all foods containing natural iron — these are safe in moderation as venesection keeps iron levels controlled. The key is to avoid foods with added iron, such as iron-fortified breakfast cereals and iron supplements','Advise avoiding iron-fortified foods, iron-containing vitamin supplements, and vitamin C supplements, as these increase iron absorption','Advise him to monitor for and promptly report any new or worsening symptoms such as fatigue, joint pain, abdominal discomfort, or skin changes','Advise him to contact the GP promptly if any new concerns arise'],
  'Thank you for coming to speak with me today, Martin. It sounds like you have been managing your treatment really well, and it is great to hear that the venesection has been helping with your symptoms. I completely understand why you are anxious about what this diagnosis might mean for your family, and I want to take some time today to go through everything carefully with you.

Haemochromatosis is a condition where the body absorbs too much iron from food, and over time that excess iron builds up and gets stored in organs such as the liver, the heart, and the pancreas. If it is not kept under control, that accumulation can eventually cause damage to those organs. The good news is that with the treatment you are already receiving — the regular venesections — and careful monitoring, we can usually prevent serious complications from developing.

Now, regarding your children. This condition does run in families, and the way it is inherited is important to understand. Most people develop haemochromatosis when they inherit two copies of the faulty gene, one from each parent. Your children could inherit two copies, one copy, or no copies at all. If they inherit two copies, they may develop the condition as you have. If they inherit just one copy, they would typically be carriers and unlikely to have symptoms, though in some cases carriers can accumulate a modest excess of iron. Because neither you nor your wife have any background information from your biological families, we cannot easily estimate the risk from the other side, and this actually makes it more important that your children are screened.

The good news is that screening is straightforward. As haemochromatosis is an adult-onset condition, we generally recommend that family members are screened once they are over the age of 16, when they are old enough to understand the implications. Both your children are well above that age, so I would encourage you to ask them to book with their own GP. The initial assessment involves a simple blood test to check ferritin and transferrin saturation levels, with genetic testing arranged if anything is flagged. I would also suggest they inform their GP that you have a confirmed diagnosis.

On the question of your diet — you do not need to cut out foods that naturally contain iron, such as red meat, spinach, or lentils. These foods are part of a balanced diet and provide important nutrients. Making drastic dietary changes on top of your venesection treatment is unlikely to provide additional benefit. What does matter is avoiding foods and supplements that add extra iron to your intake — these include iron-fortified products like certain breakfast cereals, iron tablets, and vitamin C supplements, which enhance iron absorption in the gut. It is worth checking food labels when shopping, as many products clearly state whether they have been iron-fortified.

Finally, I want to make sure you are keeping an eye on how you feel day to day. If you notice any new or worsening symptoms — such as increased fatigue, joint pain, abdominal discomfort, or any changes to your skin — please do not wait for your next hospital appointment. Get in touch with us here so we can review things promptly. I am happy to answer any other questions you may have, and please do not hesitate to contact the surgery if anything concerns you.',
  ARRAY['Hereditary haemochromatosis is most commonly inherited in an autosomal recessive pattern (HFE C282Y homozygosity); type 4 is autosomal dominant. Screening of first-degree relatives over the age of 16 is recommended.','First-line screening in relatives involves serum ferritin and transferrin saturation; genetic testing is arranged if initial results are abnormal.','Carrier testing is not recommended in healthy children under 16, as the condition is adult-onset and young children are very unlikely to be clinically affected.','Patients do not need to eliminate naturally occurring dietary iron; the key advice is to avoid iron-fortified foods, iron supplements, and vitamin C supplements, which enhance absorption.','Target ferritin range during therapeutic venesection is 50–100 µg/L with transferrin saturation kept below 50%; alcohol should be kept within recommended limits to reduce hepatic risk.','Clinical features of haemochromatosis include fatigue, arthropathy, abdominal discomfort, erectile dysfunction, and bronzing of the skin; symptoms typically present between ages 40–60 in males.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  104,
  'Erectile Dysfunction In Gay Man',
  'Men''s Health',
  'Video Consultation',
  false,
  'Simon Bradley',
  '49-year-old male',
  ARRAY[]::text[],
  ARRAY['Metformin 1g twice daily','No Known Drug Allergy'],
  'Seen by Paula Hendricks (Diabetic Nurse Specialist) 2 months ago. Test results 2 months ago / Test results 5 months ago / Reference range: HbA1c 30–41 mmol/L; eGFR >90 mL/min/1.73m²; Urine Albumin Creatinine Ratio <30mg/g / <30mg/g / <30mg/g. Presenting complaint: Patient attended for a routine diabetic review. Blood results show good blood sugar control. Examination findings: BMI 32 kg/m², BP 125/75 mmHg, Pulse 73 bpm full volume and regular. Foot check is normal. Patient is up to date with vaccinations and has completed the annual eye check. Plan: Reinforced lifestyle advice; continue ongoing management; review in 3 months.',
  'Patient booked a routine video consultation to discuss a private matter.',
  'Hi doctor, I wanted to speak to you about something personal. Over the last few months I''ve been struggling to get and keep an erection, and it''s starting to put a strain on my relationship.',
  '',
  ARRAY[]::text[],
  'Simon is in a same-sex relationship with a male partner; they have been together for around two years. He is both a receptor and an insertive partner. He occasionally uses poppers (amyl nitrite) during sex to ease penetration — he has been doing this for the past six to seven months. He does not smoke. He does not use illicit drugs other than poppers. He drinks very little alcohol. Simon works as a graphic designer. If asked about poppers: he describes them as small bottles of liquid that he inhales during sex because they relax the muscles and make penetration more comfortable. He uses them only occasionally, not every time.',
  'Simon is not sure what is causing the problem and wonders whether his diabetes could be a factor.',
  'Simon is worried that the problem will affect his relationship and his confidence. He is keen to find a solution so that he can continue to enjoy a satisfying sex life.',
  'Simon would like a prescription for sildenafil or another effective treatment for erectile dysfunction.',
  ARRAY['If the doctor asks about poppers: Explain that these are small bottles of liquid, sometimes called amyl nitrite. You inhale them during sex because they relax the muscles and make penetration more comfortable. You use them only occasionally, not every time you have sex.'],
  NULL,
  'Decline to answer questions about symptoms not covered in the brief.',
  ARRAY['Ask about the onset and course of the erectile difficulties — did they come on gradually or suddenly? (Gradual onset suggests an organic cause; sudden onset suggests a psychogenic cause.)','Ask whether the difficulty is in achieving an erection, maintaining one, or both','Ask whether he still has early morning erections','Ask whether erections are ever painful','Ask about any problems with ejaculation','Ask whether his libido has changed','Ask about any penile curvature, foreskin problems, or lumps in the testes','Ask about urinary symptoms','Ask about his personal life and relationships, including whether he has male or female partners, the number of sexual partners, how the problem has affected the relationship, and whether he uses poppers during sex','Ask about any recent STIs or episodes of risky sexual contact','Ask about back pain, numbness, or weakness around the genital area (to rule out spinal or neurological causes)','Ask about breast changes such as enlargement or tenderness (to screen for endocrine causes such as hypogonadism)','Ask about recent life changes, new stressors, or significant events','Ask about any past surgery or procedures in the pelvic or genital area','Ask about smoking, alcohol, recreational drug use, over-the-counter medications, physical activity, weight, and occupation','Ask whether he has already tried any treatments for erectile dysfunction','Explore the patient''s ideas, concerns, and expectations','Provide a working diagnosis of erectile dysfunction'],
  ARRAY['Offer a face-to-face appointment to examine the genitalia (penis and testes) and perform a prostate examination, as the patient is over 50. At the same visit, check blood pressure and pulse.','Arrange blood tests including HbA1c, early-morning testosterone (between 9–11 am), lipid profile, prostate-specific antigen (PSA for men over 50), thyroid function tests (TFTs), and liver function tests (LFTs).','Offer to calculate QRISK score to assess cardiovascular risk, as an organic cause is suspected','Explain that using poppers can itself contribute to erectile difficulties, and inform the patient that sildenafil must not be used at the same time as poppers — the combination can cause a sudden and potentially life-threatening drop in blood pressure. If the patient agrees to stop using poppers, sildenafil may be safely offered.','Offer sildenafil 50 mg if the patient agrees to stop using poppers. Explain it can also be purchased over the counter without a prescription. Advise him to take it approximately one hour before sexual activity.','Before prescribing sildenafil, ask about any history of chest pain, shortness of breath, or reduced exercise tolerance, to quickly assess cardiac risk. Also enquire about any personal or family history of retinal disease such as retinitis pigmentosa.','Inform the patient about common side effects of sildenafil, including headache, flushing, and dizziness, and reassure him that most men tolerate the medication well.','Advise and safety-net regarding priapism: if he develops an erection lasting longer than 3 to 4 hours, he must seek urgent medical help immediately.','Offer a referral for psychosexual counselling if the patient feels this would be helpful.','Provide lifestyle advice including healthy eating, regular physical activity, and weight loss (BMI is raised).','Arrange follow-up in 6 weeks.'],
  'Thank you for trusting me with something so personal, Simon. I can hear that this has been weighing on you, and I want you to know that what you have described — difficulty getting and maintaining an erection — is very common, particularly in men with conditions such as type 2 diabetes. Diabetes can affect the blood vessels and nerves that are involved in erections, so your condition is quite likely to be playing a part here. There may also be other contributing factors, which is why I would like to investigate things properly.

To start with, I would like to arrange a face-to-face appointment so that I can examine you. This would include checking your penis and testes for any physical changes, and because you are close to 50, I would also recommend a prostate examination at the same visit. I would check your blood pressure and pulse at that appointment too. Would you be comfortable with that?

I would also like to arrange some blood tests. These will include your morning hormone level — testosterone — as well as your cholesterol, thyroid function, liver function, and a PSA test for your prostate. These tests help us identify any underlying causes and make sure nothing important is missed.

Now, you mentioned using poppers. I want to be honest with you about this for two reasons. First, poppers themselves can make erectile difficulties worse — they cause a rapid drop in blood pressure which can interfere with getting an erection. Second, and very importantly, poppers must never be combined with sildenafil, the medication commonly used for erectile dysfunction. When taken together, they can cause a sudden and very dangerous fall in blood pressure, which in some cases can be life-threatening. If you are able to stop using poppers, then sildenafil would be a safe option we could explore.

Sildenafil — sometimes known by the brand name Viagra — works by increasing blood flow to the penis. The usual starting dose is 50 mg, taken about an hour before sexual activity. Common side effects include headache, flushing, and a sense of warmth, but most men find it well tolerated. One important safety point: if you ever develop an erection lasting longer than three to four hours, you must seek urgent medical attention straightaway. I would also like to ask whether you have ever had chest pain, breathlessness on exertion, or any heart problems, as this helps me assess whether it is safe for you before prescribing.

Finally, I think it is also worth exploring the psychological side of things. Erectile difficulties often affect confidence and create a cycle of anxiety that makes the problem worse. If you feel that speaking to someone with specialist experience in this area might help, I would be happy to refer you for psychosexual counselling. In the meantime, small lifestyle changes — eating well, staying active, and working towards a healthier weight — can also make a meaningful difference over time. Let''s arrange that follow-up in about six weeks and see how things are going.',
  ARRAY['Erectile dysfunction is common in men with type 2 diabetes due to vascular and neurological changes; a gradual onset suggests an organic cause, while a sudden onset is more consistent with a psychogenic aetiology.','A full assessment includes examination of the genitalia and prostate (in men over 50), BP/pulse, QRISK calculation, and blood tests: early-morning testosterone (9–11 am), HbA1c, lipid profile, PSA, TFTs, and LFTs.','Poppers (amyl nitrite) are vasodilatory substances used recreationally that can worsen erectile function and must never be combined with sildenafil or other PDE5 inhibitors — the combination can cause a life-threatening drop in blood pressure.','Sildenafil 50 mg is the standard starting dose, taken approximately one hour before sexual activity; it can be purchased over the counter as well as on prescription.','Safety-net priapism: patients must seek urgent medical help for any erection lasting longer than 3–4 hours.','Psychosexual counselling should be offered alongside physical treatment, particularly when the problem is affecting the patient''s relationship and self-esteem.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  105,
  'Eczema Flare In A Child',
  'Dermatology',
  'Telephone Consultation',
  false,
  'Kofi Asante',
  '2-year-old male',
  ARRAY[]::text[],
  ARRAY['Oilatum','Eumovate – apply to affected areas twice daily (acute prescription)','No known drug allergy','Patient is up to date with his immunisations'],
  'Seen by Dr Priya Nair (Clinical Practitioner) 3 weeks ago. Presenting complaint: Recurrent eczema flare for the past 2–3 weeks. Mother is unaware of any clear triggers. Previously prescribed hydrocortisone cream, which did not fully resolve symptoms. Last flare prior to this episode was 5 weeks ago. On examination: Eczematous rash with areas of dry skin, erythema, and excoriation affecting the trunk and both upper limbs. No evidence of infection. No alteration in pigmentation. Impression: Moderate eczema. Plan: Commenced on Eumovate and emollients. Advised to keep a symptom diary to help identify potential triggers. Safety-netting advice and guidance on when to seek further review if symptoms worsen.',
  'Kofi''s mother, Adwoa Asante, has booked a routine telephone consultation to discuss concerns about her son''s ongoing eczema and a possible milk allergy.',
  '"Doctor, Kofi''s eczema keeps flaring up, and I''m starting to wonder whether it might be linked to cow''s milk. Could he have a milk allergy?" Kofi was diagnosed with eczema at around 6 months of age. He currently has flare-ups approximately twice a month. During the most recent flare, you applied Eumovate (clobetasone) cream, which improved the rash but did not clear it fully, although the skin is now beginning to settle. He usually goes about a week without symptoms before another flare develops. You have been very thorough with his skincare routine, moisturising his skin ten or more times a day and using the emollient as a soap substitute. You have noticed that when Kofi goes three to four days without any milk, his skin sometimes looks clearer compared to days when he does have cow''s milk.',
  '',
  ARRAY[]::text[],
  'Kofi is an only child and lives at home with both parents. His father has a history of asthma and eczema. There is no smoking in the household. He does not attend nursery. Kofi was born at term with no complications. He is developing well and is up to date with all his immunisations. He is on complementary feeding and eats a wide variety of foods, though he still has cow''s milk with his breakfast cereal. Your cousin''s son had similar skin problems, and they improved after he was switched to a milk-free formula.',
  'Adwoa believes that Kofi''s eczema may be triggered or worsened by cow''s milk.',
  'She is worried about how frequently the flares are occurring and would like a long-term solution to get his eczema under better control.',
  'She hopes the GP will prescribe a milk-free formula for Kofi. She would also like Eumovate to be placed on repeat prescription so that she does not need to book a new appointment every time he needs the steroid cream.',
  ARRAY[]::text[],
  NULL,
  'Decline to answer questions about symptoms not provided in the brief.',
  ARRAY['Ask about the eczema history: when it first started, how often flares occur, and what treatments have been tried','Ask whether Kofi is currently in a flare','Ask about potential triggers for flares, including specific foods, environmental factors, infections, soaps, or temperature changes','Explore symptoms that might suggest a milk allergy: any vomiting, diarrhoea, or abdominal pain after milk? Any hives, swelling, or raised rashes after consuming milk or other foods? Any wheezing or breathing difficulties?','Ask about Kofi''s current feeding and diet, including what milk he takes and what solid foods he eats','Ask about other atopic conditions in Kofi, such as asthma or hay fever','Ask about family history of atopic conditions including asthma, eczema, or hay fever','Ask about the impact of eczema on Kofi''s daily life, including sleep, feeding, and play','Ask about the home environment: who lives at home, any other children, and whether anyone else in the household has skin problems or milk allergy','Ask about pregnancy, birth, immunisation, and developmental history','Explore the mother''s ideas, concerns, and expectations','Give a diagnosis of recurrent eczema flare with possible cow''s milk protein allergy as a contributing factor'],
  ARRAY['Acknowledge the mother''s concerns and validate that milk allergy can sometimes be linked to eczema. Explain that eczema is very common in young children and often improves as they get older.','Inform her that specialist formula, such as extensively hydrolysed formula (EHF) or amino acid formula (AAF), would at this age usually only be prescribed on the advice of a paediatrician or paediatric dietitian.','Refer to paediatrics or a paediatric dietitian for further assessment and specialist support.','Advise that cow''s milk can be removed from Kofi''s diet while awaiting specialist review. As he is on complementary feeding, he will obtain sufficient nutrition from a varied diet, making temporary exclusion reasonable until specialist guidance is available.','Encourage Adwoa to keep a symptom diary to record when flares occur and note possible triggers such as foods, temperature changes, soap products, or detergents.','Encourage her to continue regular emollient use, as she is already doing well with this.','Advise that because Kofi''s flares are frequent, it is appropriate to commence long-term management with topical steroids using a weekend therapy regimen: apply the steroid thinly on two consecutive days each week (for example Saturday and Sunday) to the areas most prone to flare, even when the skin appears normal, to help prevent recurrence.','For this reason, the topical steroid can be placed on repeat prescription, with regular monitoring every three months.','Counsel on the potential long-term side effects of steroid creams, including skin thinning, mild depigmentation, temporary burning or stinging, and in rare cases permanent stretch marks. Reassure her that not all children develop these effects, and that by reducing flare frequency, the amount of steroid needed — and therefore the risk — will also be reduced.','Safety-netting: advise to seek medical review if the eczema worsens, fails to respond to treatment, or shows signs of infection such as weeping, crusting, a spreading rash, or fever.'],
  'Thank you for calling today, and I want you to know that I completely understand how worrying it is to see Kofi''s skin keep flaring up. You are clearly doing a wonderful job with his skincare routine — moisturising that frequently and using the emollient as a soap substitute takes real commitment, and it is making a difference.

You raise a really important point about cow''s milk. You are right that food allergies, including milk allergy, can sometimes be linked to eczema in young children. Looking at Kofi''s pattern, he does not appear to have the typical immediate signs of a milk allergy — things like vomiting, diarrhoea, tummy pain, raised hives, or breathing difficulties after drinking milk. However, there is a type of milk allergy that causes slower, delayed reactions, and given what you have noticed about his skin on milk-free days, it is certainly something we should look into properly.

For that reason, I would like to arrange a referral to a paediatrician and paediatric dietitian — a children''s specialist — who will be able to assess Kofi in much more detail. If they feel a specialist formula is appropriate, they will prescribe it and support you through the change. Managing this with a specialist is important at his age to make sure he continues to get all the nutrients he needs. Are you happy for me to arrange that referral?

In the meantime, it is reasonable to remove cow''s milk from Kofi''s diet while you are waiting for that appointment. Because he eats a good variety of solid foods, he will still be getting the nutrition he needs from his meals, so a temporary exclusion is safe for now. Please do continue keeping a diary of when his flares happen and what he has been eating, along with any other possible triggers like soaps, bubble baths, or changes in temperature — this information will be really valuable for the specialists.

Regarding the steroid cream — I completely understand why having it on repeat would make things easier. In general, we do not routinely put steroid creams on repeat without regular reviews, because eczema can change and the skin needs reassessing from time to time. However, because Kofi''s flares are happening so frequently, I think it is reasonable to put Eumovate on repeat in this case, alongside a structured plan called weekend therapy. This means applying a thin layer of the cream on just two days each week — for example Saturday and Sunday — to the areas most likely to flare, even when the skin looks clear. The aim is to keep the inflammation under control and reduce how often full flares develop. We would review him every three months to make sure the treatment is still appropriate.

I also want to briefly explain what can happen if steroid creams are used over a long period of time, so you have all the information you need. Potential side effects include slight thinning of the skin, mild changes in skin colour, a little burning or stinging when applied, and very occasionally stretch marks. I want to reassure you that not every child develops these, and by working to reduce the frequency of flares, we are also reducing how much steroid cream is needed overall, which keeps any risk very low. If at any point Kofi''s skin becomes weepy, crusted, or starts spreading, or if he develops a fever, please seek medical advice promptly.',
  ARRAY['Cow''s milk protein allergy can present with delayed eczema flares rather than immediate reactions; it is one of the most common food allergies in early childhood and should be considered when eczema does not respond adequately to standard treatment.','Specialist formula (EHF or AAF) for children over one year should only be prescribed on the advice of a paediatrician or paediatric dietitian; temporary cow''s milk exclusion while awaiting review is reasonable if the child is on complementary feeding.','Topical steroids are not routinely placed on repeat without regular review, but when flares are frequent, weekend therapy is an appropriate long-term strategy: apply the usual steroid thinly on two consecutive days per week to flare-prone areas, even when skin looks normal.','Long-term side effects of topical steroids include skin thinning, mild depigmentation, burning or stinging, and rarely permanent stretch marks; the risk is minimised by reducing flare frequency and therefore steroid use.','A symptom diary is a valuable tool to help identify dietary and environmental triggers for eczema flares.','Safety-netting criteria for eczema: seek review if the rash worsens, fails to respond to treatment, or shows signs of secondary infection (weeping, crusting, spreading, or fever).'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  106,
  'Recurrent Candida In A Child',
  'Paediatrics',
  'Telephone Consultation',
  false,
  'Sofia Marchetti',
  '11-year-old female',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No known drug allergy','Patient is up to date with her immunisations'],
  '8 months ago – Seen by Dr Aisha Khan (Clinical Practitioner): Presenting complaint: Patient was seen with her mother. Patient reported 4 days of vulval and vaginal itching with a burning sensation when passing urine. On examination: Vitals stable. External vulval inspection (with consent from mother and patient) revealed vulval redness and a small amount of whitish discharge. No ulceration seen. Urinalysis: Leucocytes 1+, nitrites negative. Impression: Vulvovaginal candidiasis, rule out UTI. Plan: Urine sent for culture. Topical clotrimazole 1% cream prescribed — instructed to apply 2–3 times daily to the affected genital area for 7 days. Worsening advice given. Urine culture result: Microscopy — no organisms isolated. Culture — no growth. Sensitivity testing: Not applicable. 3 months ago – Telephone consultation with Dr Fiona Mackay: Presenting complaint: Mother called reporting vaginal itching and redness. No urinary symptoms. She explained the symptoms were similar to a previous episode 5 months ago and requested clotrimazole cream, as it had helped before. Plan: Topical clotrimazole 2% cream TDS for 7 days prescribed; no examination performed. Worsening advice given. Sofia''s paternal grandmother (Mrs Rosa Conti) has booked an urgent telephone appointment to discuss concerns.',
  'Sofia''s grandmother has called on behalf of Sofia''s mother (who is at work) to report a recurrence of symptoms and request a prescription.',
  'Hello doctor, I am calling about my granddaughter Sofia. She has been complaining of itching and soreness down below again for the past four days, and I was hoping she could have the Canesten cream that helped her last time. Sofia has had vaginal itching and soreness when she passes urine for the last four days. She has also noticed a whitish discharge. She is passing urine and opening her bowels normally. She is otherwise well in herself.',
  '',
  ARRAY[]::text[],
  'Sofia lives at home with her mother and father. She is an only child and no one else lives in the household. You have no concerns about any form of abuse. She is performing well at school. You collect her from school each day and she is there at the moment.',
  'Mrs Conti believes this is another episode of thrush.',
  'She is worried that Sofia seems too young to be having these repeated episodes of thrush, and she would like to know how to prevent them from happening.',
  'She would like the GP to prescribe Canesten cream for Sofia.',
  ARRAY[]::text[],
  NULL,
  'Decline to answer any questions outside of what is provided in the brief.',
  ARRAY['Ask about the onset and duration of Sofia''s current symptoms','Ask how many episodes she has had in the last year — note that recurrent candida is defined as four or more episodes per year','Ask about the specific local symptoms: itching, redness, discharge, soreness, and pain on passing urine','Ask about urinary symptoms including frequency, dysuria, and haematuria','Explore hygiene practices, including use of soaps, shower gels, bubble baths, or perfumed products in the bath','Ask about symptoms that might suggest diabetes: excessive thirst, increased urination, or unexplained changes in weight','Ask about systemic symptoms such as fever or abdominal pain','Ask sensitively about any concerns regarding inappropriate contact or sexual abuse, including any changes in Sofia''s behaviour such as becoming withdrawn or avoiding social situations','Ask about the home situation: who lives at home and what family support is available','Ask about how Sofia is getting on at school and her general wellbeing','Ask about her general health, including nutrition and diet','Explore the grandmother''s ideas, concerns, and expectations','Give a working diagnosis of likely vulvovaginal candidiasis'],
  ARRAY['Offer a face-to-face assessment to examine the genital area and take a low vaginal swab (not a high vaginal swab, given her age) for culture to confirm candida','Arrange blood tests including FBC, ferritin, and a diabetes screen (HbA1c or fasting glucose)','Prescribe topical clotrimazole 2% cream, applied three times daily for 7 days','Provide hygiene advice: wear cotton underwear rather than synthetic fabrics, avoid tight clothing, use non-scented soaps and avoid perfumed bubble baths or products, keep vulval hygiene gentle, dry the genital area properly after washing, and avoid using wet wipes on the genital skin','Arrange follow-up in 7 days to review swab results and assess progress','Safety-netting: advise to seek urgent medical help if Sofia develops a fever, abdominal pain, spreading redness, or unusual discharge'],
  'Thank you so much for calling today, Mrs Conti, and for taking the time to look after Sofia. I am glad you got in touch, because I want to make sure we get to the bottom of what is going on.

From what you have described, I do agree with you that this sounds very much like another episode of thrush — the itching, redness, and whitish discharge are all consistent with that. I understand your concern that Sofia seems young to be having these episodes, and you are right to question it. Thrush is actually less common in girls before puberty because the hormone oestrogen, which plays a role in creating the conditions where the thrush fungus can grow, is not yet present in significant amounts. However, it can and does still occur, particularly when certain factors are at play — things like soap, bubble baths, perfumed products, or the type of underwear worn can all upset the natural balance in that area and make thrush more likely. Does that help to explain things a little?

Because this is now Sofia''s second episode that we know of, I think it is really important that we bring her in for a face-to-face review. This would allow me to gently examine the area and take a small swab from the outside — this is not invasive and will be done with Sofia''s comfort in mind — just to confirm that this is indeed thrush and not something else. I would also like to arrange some blood tests to rule out other possible underlying causes, such as diabetes or low iron, which can sometimes make children more prone to these infections. Would that be alright with you?

In the meantime, I can prescribe the Canesten cream, as it has helped before and should bring Sofia some relief from the itching and soreness. Alongside the cream, some simple changes can really help to prevent these episodes from returning. These include switching to plain cotton underwear, avoiding tight clothing, keeping away from scented soaps and bubble baths, making sure the area is dried gently and properly after washing, and avoiding wet wipes on the skin in that area. These small adjustments can make a significant difference over time.

I will arrange to see Sofia in about a week, once the swab results are back, so we can make sure she is improving and review the findings together. If at any point before then she develops a high temperature, tummy pain, or the discharge changes in any way, please do not hesitate to contact us or seek urgent medical help.',
  ARRAY['Thrush is uncommon in prepubescent girls because the low-oestrogen environment is less favourable for Candida growth; however, it can still occur, particularly with hygiene-related risk factors such as bubble baths, scented soaps, and synthetic underwear.','Recurrent vulvovaginal candidiasis is defined as four or more episodes per year and warrants further investigation including a low vaginal swab (not HVS due to the child''s age), FBC, ferritin, and a diabetes screen (HbA1c or fasting glucose).','When a child has recurrent or unusual episodes of vulvovaginal symptoms, safeguarding must always be considered and sensitively explored — this should never be omitted.','Topical clotrimazole 2% cream applied three times daily for 7 days is the treatment of choice for vulvovaginal candidiasis in this age group.','Hygiene advice is an important component of management: cotton underwear, avoidance of scented products and bubble baths, gentle drying, and no wet wipes to the genital skin.','Vulvovaginitis in prepubescent girls is more commonly caused by bacteria or irritants rather than Candida, as the thin, non-acidic vaginal tissue is more susceptible to bacterial growth.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  107,
  'Failure To Thrive',
  'Paediatrics',
  'Video Consultation',
  false,
  'Noah Fletcher',
  '1 year, 7-month-old male',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No known drug allergies','Patient is up to date with immunisations'],
  'Seen by Dr Ravi Sharma (Clinical Practitioner) – 6 weeks ago. Presenting complaint: Recurrent sore throat — 4 episodes in the last 6 months. Examination: Erythematous tonsils with white spots. Plan: Treat as tonsillitis with Penicillin V. Safety-netting and worsening advice given. Seen by Ms Claire Dixon (Paediatric Nurse Practitioner) – 5 weeks ago. Presenting complaint: Mother reports recurrent loose stools associated with weight loss for the past 14 months, since introducing solid foods at 6 months of age. Mother suspects a possible food allergy but is unsure which food. No red flags or anaphylaxis symptoms. Patient is up to date with immunisations. Examination: Normal vitals, no signs of dehydration. Abdomen soft and non-tender, no evidence of masses. Chest is clear with good air entry. Weight today: 9.5 kg. Weight plotted on growth chart is between 0.4th and 2nd centile (birth weight 3 kg). Plan: Mother advised to keep a food diary to help identify potential triggers. Weight to be checked again in 4 weeks. Safety-netting provided. Seen by Ms Janet Cole (Nurse Access) – 3 days ago. Presenting complaint: Patient attended for a health check. Examination: Weight 9.38 kg. Plan: Mother advised to book with GP to discuss.',
  'Noah''s mother, Katherine Fletcher, has booked a video consultation to discuss her son''s ongoing diarrhoea and failure to gain weight, following the nurse''s recommendation.',
  '"Hello doctor, I was asked to book this appointment after Noah''s weight was rechecked a few days ago. He''s been having diarrhoea for a long time now, and he just doesn''t seem to be putting on any weight." Noah has had diarrhoea for the past 14 months, since he started solid foods at 6 months. He passes 3–4 loose stools per week, which are non-bloody. His symptoms have remained the same since you last saw the nurse 5 weeks ago. You have read online that this could be a food allergy, and your brother''s child has a condition where certain foods need to be avoided, though you are not sure of the name. Noah eats cereals such as cornflakes and pasta-based meals. He has no difficulty swallowing or eating, no nausea, no vomiting, and no skin rashes.',
  '',
  ARRAY[]::text[],
  'Noah lives at home with his mother and father. He is their first and only child. He was born at term with no complications. He was born in the UK and all newborn screening results were negative. He is up to date with all his immunisations and is otherwise well, though he is not gaining weight as expected.',
  'Katherine believes Noah may have a food allergy and is waiting to find out more.',
  'Katherine is worried about his ongoing weight loss and that something serious might be being missed.',
  'She would like the GP to investigate further or refer Noah to a specialist. If the doctor suggests coeliac disease, she will ask whether she should stop giving him foods containing gluten.',
  ARRAY['If the doctor mentions coeliac disease, ask: "Should I stop giving him foods with gluten in them, like pasta and cereal?"'],
  NULL,
  'Decline to answer questions about symptoms or details not provided in the brief.',
  ARRAY['Ask when the diarrhoea and weight loss were first noticed','Ask about the frequency of loose stools per day and their characteristics — is there any blood or mucus in them?','Ask about other gastrointestinal symptoms such as vomiting, abdominal pain (for example, does he appear to be in pain, draw his legs up, or seem distressed?), and abdominal bloating','Ask about symptoms of allergy and anaphylaxis, including rash (particularly if it occurs immediately or within a few hours of feeding), shortness of breath, wheeze, or swelling of the mouth or tongue','Explore appetite: what foods Noah eats and how regularly','Ask about his fluid intake','Ask whether he is passing urine normally (wet nappies)','Ask whether his symptoms have changed since the last consultation 5 weeks ago — if unchanged, an immediate face-to-face review may not be urgent','Ask about recurrent infections such as sore throats, chest infections, or UTIs — recurrent chest infections in particular may point towards cystic fibrosis','Ask about family history of bowel conditions, especially coeliac disease','Ask about PBIND history: pregnancy, birth, immunisation, nutrition, and development — confirm newborn screening results to help rule out cystic fibrosis','Ask about other medical conditions such as asthma or eczema, to consider the possibility of a food allergy','Ask who lives at home, whether there are any siblings, and what support is available','Explore the mother''s ideas, concerns, and expectations — why she thinks it might be a food allergy, what she is most worried about, and what outcome she is hoping for','Give a working diagnosis of likely faltering growth with coeliac disease as a possible cause'],
  ARRAY['Arrange further blood tests: coeliac screen, U&Es, folate, vitamin B12, vitamin D, ferritin, FBC, thyroid function tests, and liver function tests','Request a stool sample for routine culture to rule out infective cause. Note: calprotectin testing is generally not recommended in children under 5, as IBD is less common in this age group and baseline faecal calprotectin levels are naturally elevated, making results harder to interpret. However, if coeliac screen and other investigations return normal, a calprotectin test may still be appropriate given the possibility of very early-onset IBD (VEO-IBD).','No face-to-face review is required at this stage, as symptoms have not changed since the last consultation','Advise the mother not to remove gluten from Noah''s diet until the investigations are complete, as doing so may produce a falsely negative coeliac test result','Explain that if the coeliac screen is positive, referral to a specialist (paediatric gastroenterologist) will be arranged. If the screen is negative, referral will still be made, as false negatives can occur.','If coeliac disease is confirmed, advise that the main treatment is a lifelong gluten-free diet. Explain that gluten-free products are available on prescription and that dietitians will provide ongoing support.','Encourage the mother to continue offering regular meals without forcing Noah to eat','Liaise with health visitors to ensure regular monitoring of weight and growth','Safety-netting: advise urgent review if signs of dehydration develop (no wet nappies, lethargy, or unwell appearance) or if blood appears in the stools','Arrange follow-up in 1 week to review test results and reassess progress'],
  'Thank you for getting in touch, Katherine, and I can see how worried you have been about Noah. It is absolutely right that you followed the nurse''s advice and booked in with me today. From everything you have told me, it sounds like Noah has what we call faltering growth — this means that the rate at which he is gaining weight is lower than we would expect for a child of his age, sex, and background. I want to reassure you that we are going to investigate this carefully together.

There are a number of possible reasons why this can happen. You mentioned reading about food allergies online, and that is a reasonable thing to consider. However, I am also concerned about another condition called coeliac disease, which I would like to explain. Coeliac disease is an autoimmune condition — this means the body''s immune system reacts to a protein called gluten, which is found in foods like bread, pasta, and most breakfast cereals. When someone with coeliac disease eats gluten, it causes inflammation in the lining of the small intestine, which stops nutrients from being properly absorbed. Over time, this can lead to problems like loose stools, poor weight gain, and the kind of growth difficulties we are seeing in Noah. Does that make sense so far?

I want to arrange some blood tests and a stool sample to investigate this. The blood tests will include a coeliac screen along with checks of his iron levels, vitamin levels, kidney and liver function, and thyroid function, all of which give us a much clearer picture of how Noah is doing overall. Does that sound all right to you?

I need to mention one really important thing regarding his diet. If coeliac disease turns out to be the cause, it can be very tempting to try removing gluten from his diet straight away. Please do not do this yet. If you remove gluten before the tests are done, the results may come back falsely normal, which means we could miss the diagnosis entirely. Please continue feeding Noah his usual foods — including pasta and cereal — until we have the test results back and have had a chance to discuss them with you.

Whatever the outcome of these tests, I want to reassure you that we will not leave things there. If the coeliac screen is positive, I will refer Noah to a specialist children''s gastroenterology team, who will guide you through the next steps. If the screen is negative, I will still arrange a referral, because false negatives are possible and Noah''s ongoing symptoms deserve a specialist opinion. I will also make sure our health visiting team is keeping a close eye on his weight in the meantime.

Finally, please do keep offering Noah his meals regularly, though there is no need to pressure him to eat. If at any point he seems very unwell, stops having wet nappies, becomes lethargic, or you notice any blood in his stools, please seek urgent medical help immediately. I would like to speak to you again in about a week, once the initial results are back.',
  ARRAY['Faltering growth (failure to thrive) describes a rate of weight gain lower than expected for a child''s age and sex, and has a wide differential including feeding difficulties, chronic infections, metabolic disorders, food allergies, and gastrointestinal conditions such as coeliac disease.','Coeliac disease is an autoimmune condition triggered by gluten; it causes small intestinal inflammation that impairs nutrient absorption, presenting with chronic diarrhoea, poor weight gain, and faltering growth.','It is essential that gluten is not removed from the diet before coeliac serology is completed — early withdrawal can cause false negative results and delay diagnosis.','Initial investigations include: coeliac screen, FBC, ferritin, folate, B12, vitamin D, U&Es, thyroid function, and liver function tests, plus a stool sample for culture.','Faecal calprotectin is generally not recommended in children under 5 due to naturally elevated baseline levels; however, it may be considered if coeliac and other screens return normal and VEO-IBD is suspected.','Referral to a paediatric gastroenterologist should be arranged regardless of coeliac screen result, as false negatives occur and specialist evaluation is warranted with persistent faltering growth.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  108,
  'Unexplained Bloody Nasal Discharge',
  'ENT & Eye',
  'Video Consultation',
  false,
  'Roy Gallagher',
  '71-year-old male',
  ARRAY[]::text[],
  ARRAY['Apixaban 5mg BD','Amlodipine 10mg OD','Ramipril 5mg OD','Bisoprolol 2.5mg OD','Tamsulosin 400mcg OD','No known drug allergy'],
  'Blood test done 7 months ago for routine monitoring of Apixaban. Creatinine clearance calculated: 89 mL/minute. Full Blood Count (FBC): Haemoglobin (Hb) 14.2 g/dL (normal range 13.0–17.0 g/dL); Haematocrit (HCT) 42% (normal range 38%–50%); White Blood Cell Count (WBC) 6.8 x 10^9/L (normal range 4.0–11.0 x 10^9/L); Platelet Count 250 x 10^9/L (normal range 150–450 x 10^9/L). Urea and Electrolytes (U&E): Sodium (Na) 140 mmol/L (normal range 135–145 mmol/L); Potassium (K) 4.3 mmol/L (normal range 3.5–5.1 mmol/L); Urea 5.2 mmol/L (normal range 2.5–7.8 mmol/L); Creatinine 85 µmol/L (normal range 60–110 µmol/L); eGFR 76 mL/min (normal range >90 mL/min). Patient has booked a routine video appointment to discuss concerns.',
  'Patient booked a video consultation to discuss blood-streaked mucus he has been noticing for the past couple of months.',
  '"Doctor, for the past couple of months I''ve been spitting up mucus with streaks of blood in it, and it''s getting more frequent. I''m worried it might be connected to the blood thinner I take."',
  'For the past 2–3 months, Roy has noticed mucus mixed with blood when he spits. It feels as though the mucus is draining down from the back of his throat, and when he spits it out he can see streaks of dark red blood. This is happening 2–3 times per week. The last episode was 2 days ago. He frequently finds himself needing to clear his throat. He has never had significant sinus infections, apart from the occasional cold.',
  ARRAY['In the last 6 months, Roy has also lost around 5 kg in weight without trying to.','He has not had any cough, chest pain, or shortness of breath.','He has been on Apixaban for 5 years without any problems until now, and he takes all of his regular medicines as prescribed.'],
  'Roy lives alone — his wife passed away eight years ago. He is a retired bus driver. He has smoked 25 cigarettes per day for the past 50 years. He drinks alcohol occasionally at family gatherings.',
  'Roy thinks the Apixaban may be thinning his blood too much, or that he might have a sinus infection.',
  'He is worried about seeing blood, especially given that Apixaban increases the risk of bleeding, and he is concerned something serious may be going on.',
  'Roy wants the GP to find out what is causing the bleeding and explain clearly what should happen next.',
  ARRAY[]::text[],
  'Should I stop my Apixaban?',
  'Decline to answer questions about symptoms not provided in the brief.',
  ARRAY['Ask about the onset of the bleeding and clarify the likely source — is it from the nose, from vomiting blood (haematemesis), or from coughing up blood (haemoptysis)?','Ask whether the blood is bright red or dark — bright red suggests a fresh bleed from the upper airway; darker blood may indicate older blood or a source further down the tract','Ask about the frequency of episodes, how often they occur, and the approximate volume of blood seen','Ask whether there is any active bleeding from the nostrils or mouth, and when the most recent episode occurred','Ask about symptoms of sinus infection: nasal dripping, blocked nose, recent colds or flu, or a previous history of sinus infections','Ask about associated symptoms: cough, difficulty swallowing, heartburn or abdominal pain, hoarse voice, neck lumps, changes in appetite, one-sided nasal blockage, or one-sided facial pain and visual changes (which may suggest sinonasal or nasopharyngeal cancer)','Ask about weight loss and night sweats','Ask how long he has been on Apixaban and whether he takes it regularly as prescribed','Ask about symptoms of significant blood loss or anaemia: palpitations, chest pain, breathlessness, dizziness, light-headedness, headaches, or tiredness','Ask about smoking and alcohol intake','Explore the patient''s ideas, concerns, and expectations','Give a working diagnosis of possible sinonasal cancer'],
  ARRAY['Offer a face-to-face appointment to examine the patient, including listening to his chest, inspecting the nostrils with an otoscope, and checking blood pressure and pulse','Arrange blood tests including renal function, full blood count, and clotting profile','Make a two-week wait referral to ENT for urgent further assessment','Inform the patient that the ENT specialists are likely to arrange further investigations such as nasal endoscopy to directly examine the back of the nose and throat, with possible biopsy if needed, and imaging such as a CT scan','Offer an urgent chest X-ray (within 2 weeks) to assess for lung cancer — NICE recommends this for anyone aged over 40 who has ever smoked and reports unexplained weight loss','Inform the patient that Apixaban should not be stopped at this stage, as the bleeding is only streaks and is not heavy or uncontrolled. Stopping Apixaban would significantly increase his stroke risk, and the benefits of continuing outweigh the risks at present.','Offer smoking cessation advice and support','Safety-netting: advise that if he has not heard from the specialist within two weeks, he should contact the surgery. If the bleeding worsens, or if he develops dizziness, light-headedness, or palpitations, he should seek urgent medical help immediately.'],
  'Thank you for getting in touch, Mr Gallagher. I am really glad you booked this appointment, because I want to make sure we take your symptoms seriously and investigate them properly. I can hear that this has been worrying you, and understandably so.

You are absolutely right that Apixaban can increase the risk of bleeding, and that could be playing a part in what you are experiencing. It is also possible that there is some irritation or a problem at the back of your nose or throat contributing to this. However, I want to be transparent with you — what concerns me in particular is the weight loss you mentioned alongside the blood-streaked mucus and your many years of smoking. Taken together, these symptoms mean we need to rule out a serious cause, including the possibility of a cancer developing in the nose, sinuses, or back of the throat. I am not telling you that this is what is happening — but it is important that we do not ignore the possibility. Are you following me so far?

To investigate this properly and without delay, I would like to refer you urgently to an ear, nose, and throat specialist — this is what is known as a two-week wait referral. They will see you within two weeks and will be able to look directly into your nose and throat using a small camera, and if anything needs to be sampled or biopsied, they will arrange that too. They are also likely to organise a CT scan to get a clearer picture. I would also like to arrange a chest X-ray at the same time — because of your smoking history and the weight loss, NICE guidelines recommend an urgent chest X-ray to make sure there is nothing concerning in the lungs. Are you happy for me to put all of this in motion?

I also want to arrange some blood tests, including a full blood count to check whether the bleeding is affecting your blood levels, a clotting profile to see how your blood is behaving, and a check on your kidney function. I would like to see you in person as soon as possible to listen to your chest and have a look inside your nostrils. Would you be able to come in today or tomorrow?

Now, to your question about whether you should stop Apixaban. I completely understand why you are asking, and it is a very sensible question. However, my advice is that you should continue taking it for now. The blood you are seeing is in streaks in the mucus — it is not a heavy or uncontrolled bleed, and you have shown no signs of significant blood loss such as dizziness, a racing heart, or passing black stools. Apixaban is protecting you against a stroke, which is a much more serious and immediate risk given your atrial fibrillation. Stopping it now could put you at serious risk of a stroke. The benefits of staying on it currently outweigh the risks. We will reassess this carefully as we get more information, and we will keep a close eye on things together.

If at any point the bleeding becomes heavier, you cough or vomit up a significant amount of blood, your stools turn black or tarry, or you feel faint or notice your heart racing, please seek urgent medical help immediately — either call 999 or go straight to your nearest emergency department. I will also be monitoring things closely on my end.',
  ARRAY['Blood-streaked mucus draining from the back of the throat in an elderly long-term smoker with unexplained weight loss requires urgent investigation to exclude sinonasal or nasopharyngeal cancer.','A two-week wait referral to ENT is indicated. Specialist investigations typically include nasal endoscopy with possible biopsy and CT imaging.','NICE recommends an urgent chest X-ray (within 2 weeks) for anyone over 40 who has ever smoked and presents with unexplained weight loss, to assess for lung cancer.','Apixaban should not be stopped when bleeding is mild and non-haemodynamically significant — the risk of stroke from stopping anticoagulation outweighs the current bleeding risk. Any decision to pause anticoagulation must carefully balance stroke risk.','A face-to-face assessment should include inspection of the nostrils with an otoscope, auscultation of the chest, and blood pressure and pulse measurement. Blood tests should include FBC, clotting profile, and renal function.','Clinical features of sinonasal cancer include blood-stained nasal discharge, persistent unilateral nasal blockage, reduced sense of smell, recurrent nosebleeds, unilateral facial pain or numbness, and visual symptoms.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  109,
  'Urinary Symptoms In Young Adult Male',
  'Men''s Health',
  'Telephone consultation',
  false,
  'Ryan Fletcher',
  '22-year-old male',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No known drug allergy'],
  'Patient booked urgent telephone appointment to discuss private issues.',
  'Patient booked urgent telephone appointment to discuss personal matters.',
  'Hi doctor, I''ve been having a burning feeling when I go to the toilet and some discomfort around my private area. I think I might have a water infection — could I get some antibiotics please?',
  'You have been experiencing a burning sensation when you urinate and some discomfort around your penis. This has been going on for about 3 days. You have no other symptoms and feel otherwise well. Sexual History: You had unprotected sex 8 days ago with a new female partner you met through a dating app. You have no other sexual partners. It was a one-off encounter, and you had not been with anyone for around 6 to 7 months before that.',
  ARRAY[]::text[],
  'You do not smoke, drink alcohol, or use illicit drugs. You work as a web designer and live on your own.',
  'You think the symptoms are probably down to a urine infection.',
  'You are flying to Singapore for two weeks today and are worried the infection could get worse if it is not treated before you leave.',
  'You are hoping the GP will prescribe antibiotics to clear things up.',
  ARRAY['If the doctor asks you to come in for a face-to-face appointment or drop off a urine sample, explain that you cannot attend. You are due to fly to Singapore for an important work project in the next couple of hours and are already on your way to the airport. You suggest that antibiotics could be sent to a nearby pharmacy for you to collect before your flight.'],
  NULL,
  'Decline any questions outside of the details provided. Accept anything offered by the doctor.',
  ARRAY['Ask about onset and duration of symptoms','Ask about other urinary symptoms including nocturia, dysuria, frequency, haematuria, urgency, hesitancy, straining, or weak stream','Ask about any penile discharge','Ask about rectal pain, testicular pain, pelvic pain, or low back pain (to screen for prostatitis)','Ask about fever or systemic features','Ask about joint pain or eye symptoms (to screen for reactive arthritis)','Ask about recent sexual history, including partners, protection, and timing of encounters','Ask about social history including smoking, alcohol, and drug use','Explore ideas, concerns, and expectations','Give a diagnosis of likely sexually transmitted infection (STI), particularly chlamydia, as this is the most common STI in the United Kingdom.'],
  ARRAY['Offer a face-to-face consultation for assessment, including urinalysis and a urine sample for nucleic acid amplification test (NAAT) for chlamydia.','If unable to attend, treat empirically with doxycycline 100 mg twice daily for 7 days','Inform the patient about common side effects of doxycycline, including diarrhoea, vomiting, and photosensitivity, which is particularly relevant as he is travelling to Singapore where it will be sunny.','As the patient is travelling abroad, advise that having health insurance is essential to enable access to medical care or testing overseas if required, and to seek help promptly if he becomes unwell while away.','Emphasise the importance of formal STI testing. Explain that this can be arranged while he is in Singapore or as soon as he returns to the United Kingdom.','On his return, advise attendance at a genitourinary medicine (GUM) clinic, where consultations are confidential, full STI screening will be provided, and partner notification can be arranged.','Advise that sexual intercourse, including oral sex, should be avoided until both the patient and partner(s) have completed treatment.','Provide non-judgemental education on the consistent use of condoms to reduce the risk of future infections.','Safety net by advising to seek urgent medical attention if symptoms worsen, such as fever, urethral discharge, or feeling generally unwell.','Arrange follow-up in 2 weeks to review resolution of symptoms and confirm attendance at the GUM clinic.'],
  'Thank you for telling me what has been going on, Ryan, and I can understand why this feels worrying, especially with your trip coming up so soon. Based on what you have described — the burning when you pass urine and the discomfort around your penis — I think there is a good chance this is a sexually transmitted infection rather than a straightforward water infection. In the UK, the most common one we see is chlamydia, though it could also be something like gonorrhoea. The reassuring news is that these infections are very treatable. Does that make sense so far?

Ideally, I would like you to come in today so we can do a urine test and a full STI screen. However, since you are on your way to the airport and cannot attend, the safest approach is to start you on an antibiotic called doxycycline — 100 mg twice a day for 7 days. This should treat the most likely infection and help your symptoms settle. Before I prescribe it, can I just confirm you have no allergies, as I have none documented?

Doxycycline can sometimes cause side effects such as tummy upset, loose stools, or increased sensitivity to sunlight. That last point is worth bearing in mind given you will be in Singapore. If you experience anything troublesome, please contact a doctor out there or let us know as soon as possible.

Even though we are starting treatment now, it is still really important that you have a full STI screen done. You could arrange this while you are in Singapore if that is convenient, or we can sort it as soon as you are back in the UK. Full screening is important both for your own health and to protect any current or future partner.

Until you and any partner have both completed treatment, please avoid sexual intercourse — including oral sex — as the infection can still be passed on even without symptoms. Looking ahead, using condoms consistently is one of the most reliable ways to protect against sexually transmitted infections. It is something I would encourage you to consider going forward. Please do not hesitate to seek medical advice urgently out there if you develop a fever, discharge, or feel generally unwell. We will arrange a follow-up appointment for when you return in two weeks.',
  ARRAY['In young sexually active men, an STI — particularly chlamydia — is far more likely than a urinary tract infection; UTIs are uncommon in young males due to the longer urethra.','When same-day testing is not possible, empirical treatment with doxycycline 100 mg twice daily for 7 days is appropriate for suspected chlamydia.','Doxycycline causes photosensitivity — this is an important counselling point for patients travelling to sunny destinations.','Full STI screening via a GUM clinic should be arranged on return; partner notification is an essential part of management.','Sexual intercourse (including oral sex) must be avoided until both the patient and all partners have completed treatment.','Health promotion — including condom use and GUM clinic attendance — is a key component of managing STIs in primary care.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  110,
  'Abnormal Thyroid Function Results',
  'Endocrine & Nephrology',
  'Telephone consultation',
  false,
  'Karen Whitfield',
  '41-year-old female',
  ARRAY[]::text[],
  ARRAY['Levothyroxine 125 micrograms once daily (adjusted from 100 micrograms, 3 months ago)','Mirena coil','No known drug allergies'],
  'Seen by clinical practitioner 3 months ago. Presenting complaint: Known hypothyroidism. Current TSH levels at 12.1 and patient still symptomatic. Examination: No neck swelling, no visual symptoms, BP 120/85 mmHg, weight 75 kg. Plan: Levothyroxine dose increased from 100 micrograms to 125 micrograms once daily. Review in 3 months. Worsening advice given.

Recent Tests (3 days ago):
TSH: 12 mU/L (Reference range: 0.4–4 mU/L) | Previous result (3 months ago): 12.1 mU/L
T4: 3 pmol/L (Reference range: 9–24 pmol/L) | Previous result (3 months ago): 2.9 pmol/L
Other tests including FBC, U+Es, eGFR, CRP, HbA1c, LFTs, ESR, folic acid, ferritin, B12: all normal.',
  'Patient booked a telephone appointment to discuss recent blood test results.',
  'Hi doctor, I had some blood tests done recently for my thyroid, and I''ve booked this appointment to go through the results with you — I hope that''s alright.',
  'You were told you had an underactive thyroid six months ago after feeling constantly tired, having very dry skin, and struggling with constipation. Since starting levothyroxine, the constipation and dry skin have improved a little, but the tiredness is still really getting to you. It is affecting your work as an office administrator. Three months ago your dose was put up from 100 to 125 micrograms, but you have not noticed much difference. You are worried something else might be going on. If asked specifically, you mention that you take your multivitamins at the same time as your thyroid tablet each morning, as you thought they might help with your energy levels.',
  ARRAY[]::text[],
  'You live with your partner and two children. Your partner is supportive and helps around the house. Your sleep is fine and your mood is okay. You work as an office administrator, but the ongoing tiredness is making it hard to concentrate and keep up with your workload. You do not smoke and do not drink alcohol. You have not had a period for the past 7 months, but were told this is likely due to your Mirena coil.',
  'You think your symptoms might be down to a vitamin deficiency, or that your levothyroxine dose may need to go up again.',
  'You are worried that your tiredness is starting to affect your ability to do your job properly and that this might continue.',
  'You would like the doctor to explain what your results mean and help you feel better.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY['Ask about hypothyroid symptoms: tiredness, cold intolerance, skin changes, hair loss, weight gain, neck swelling, neck pain, mood changes, menstrual irregularities, constipation','Ask about compliance with levothyroxine and how she is taking her medication','Ask about the use of other medications or supplements, including multivitamins','Ask about simultaneous intake of levothyroxine with other medications (e.g. multivitamins), food or drink such as milk, coffee, grapefruit juice, soya products, or papaya, which may impair absorption of levothyroxine.','Ask about gastrointestinal symptoms such as bloating, diarrhoea, abdominal pain, or vomiting, which may indicate malabsorption conditions such as coeliac disease, Helicobacter pylori gastritis, atrophic gastritis, or inflammatory bowel disease.','Ask about weight gain, which may increase levothyroxine requirements','Ask how her symptoms have affected her day-to-day activities, including her ability to carry out her job','Ask about her mood and any impact on psychological wellbeing','Ask about her sleep and any difficulties, as poor sleep can contribute to tiredness.','Ask about social history including smoking, alcohol intake, occupation, and home situation','Explore her ideas, concerns, and expectations','Give a diagnosis of uncontrolled hypothyroidism, likely due to poor absorption of levothyroxine from simultaneous intake of multivitamins.'],
  ARRAY['Advise the patient to take levothyroxine on an empty stomach, either at least 60 minutes before any meal or at least 4 hours before taking any other medication or supplement. This will improve absorption and may remove the need to increase the dose further at this stage.','Offer a blood test for lipid profile to support Q-Risk calculation, as part of health promotion in hypothyroid patients.','Offer a fit note with amended or lighter duties at work, which may help the employer understand her situation while symptoms remain troublesome.','Arrange follow-up in 6–10 weeks to review symptoms and repeat thyroid function tests. At that stage, the levothyroxine dose may be increased if symptoms have not improved, thyroid results remain abnormal, and she is taking the medication correctly. Additional blood tests for malabsorption, such as screening for coeliac disease, can also be considered at that point if there is still no improvement.','Provide a patient information leaflet on hypothyroidism to reinforce education and self-management.','Safety net by advising to seek urgent medical attention if symptoms significantly worsen, particularly if there is confusion, drowsiness, or seizures, which could indicate severe hypothyroidism (myxoedema coma).'],
  'Thank you for calling in today, Karen, and for being so open about how things have been going. I can hear how much the tiredness has been getting on top of you. Let me go through your results and I think we can work out together why things have not improved as we had hoped.

Your thyroid blood tests show that your thyroid is still underactive — the levels have barely changed from three months ago despite the dose increase. Your TSH is 12 mU/L, where we want it below 4, and your T4 remains low at 3 pmol/L against a normal range of 9 to 24. That explains why you are still feeling so tired. The other tests — including your blood count, kidney function, and B12 — are all completely normal, which is reassuring.

Here is what I think is happening. You mentioned you take your multivitamins at the same time as your levothyroxine each morning. Multivitamins — especially those containing calcium or iron — can significantly reduce how much levothyroxine your body absorbs. This is very likely to be the reason your levels have not improved, even after the dose was raised.

The good news is that this is straightforward to address. I would like you to take your levothyroxine on its own, on an empty stomach, ideally first thing in the morning, and then wait at least 4 hours before taking your multivitamins or any other tablets. You should also try to leave at least an hour before breakfast. Taking it with just a glass of water is ideal. Once you do this consistently, your levels should begin to improve without necessarily needing a further dose increase.

Because your thyroid is still not controlled and you are working with ongoing symptoms, I can also provide you with a fit note recommending lighter or amended duties. That might give your employer a better understanding of the situation and take some of the pressure off you for now. I would also like to arrange a cholesterol blood test as part of your routine health monitoring, since thyroid conditions can affect lipid levels.

We will recheck your thyroid function in 6 to 10 weeks. If your levels have improved and your symptoms are settling, then the current dose should be sufficient. If things have not moved, we can look at adjusting the dose or investigating for other causes of poor absorption such as coeliac disease. In the meantime, please seek urgent help if you ever feel confused, very drowsy, or have a seizure — these would be signs of the thyroid becoming very severely underactive.',
  ARRAY['Levothyroxine absorption can be significantly impaired by concurrent intake of multivitamins, calcium, iron, coffee, milk, grapefruit juice, soya products, or papaya — always ask about timing when results fail to improve.','Levothyroxine should be taken on an empty stomach, at least 60 minutes before food, or at least 4 hours before interacting medications or supplements.','When an absorption issue is identified, address the cause before simply increasing the levothyroxine dose — dose escalation without fixing the problem risks overtreatment once absorption is corrected.','If thyroid levels remain abnormal despite correct administration, investigate for malabsorption conditions including coeliac disease, Helicobacter pylori gastritis, and inflammatory bowel disease.','A lipid profile is recommended in hypothyroid patients as part of cardiovascular risk assessment; thyroid dysfunction can adversely affect cholesterol levels.','Severe hypothyroidism (myxoedema coma) is a medical emergency — safety-net patients to seek urgent help if confusion, drowsiness, or seizures develop.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  111,
  'Recurrent Falls In Elderly Female',
  'General Practice',
  'Telephone consultation',
  false,
  'Dorothy Henshaw',
  '82-year-old female',
  ARRAY['Hypertension','Hypercholesterolaemia','Bilateral total knee replacements 3 years ago for osteoarthritis','Type 2 diabetes (controlled with lifestyle modification)'],
  ARRAY['Amlodipine 10 mg once daily','Ramipril 5 mg once daily','Atorvastatin 20 mg at night','Aspirin 75 mg once daily','Furosemide 20 mg once daily'],
  'Ambulance Patient Report Form (2 days ago)
Dorothy Henshaw | 82 years old | Female
Presenting Complaint: Mechanical fall
History of Presenting Complaint: Patient reports a mechanical fall approximately 45 minutes prior to arrival. Incident occurred whilst stepping out of the bathroom. Patient states she may have tripped. She was able to move herself into a sitting position on the floor before calling 999. Denies any pre-fall symptoms (no chest pain, palpitations, dizziness or loss of consciousness) and no post-fall symptoms.
Observations: BP 110/70 mmHg, HR 69 bpm (regular), respiratory rate 17/min, SpO₂ 98% on air, temperature 36.3°C, GCS 15/15. Random blood sugar: 5.4 mmol/L.
Systemic examination: Heart sounds S1, S2, no added sounds. No obvious injuries observed.
12-lead ECG: Sinus rhythm, rate 69 bpm, normal axis, no ST-segment or T-wave abnormalities. No acute ischaemic changes.
Impression: Mechanical fall with no apparent injury.
Plan: Patient was advised to attend hospital for further assessment. She declined transfer and expressed a preference to follow up with her GP. Safety netting advice was provided.',
  'Patient booked a telephone appointment following advice from the ambulance crew after a recent fall.',
  'Hello doctor, I was advised by the paramedics to give you a ring after my fall the other day.',
  'You had a fall 2 days ago while stepping out of the bathroom. For the past 7 months, you have been passing urine very frequently since being started on your water tablet. Just before the fall, your legs felt very shaky and unsteady. You were unable to get up straight away but managed to pull yourself into a sitting position. Thankfully, your phone was nearby and you were able to call for an ambulance. You did not lose consciousness or feel dizzy, and you had no chest pain or palpitations. This is the first fall you have had. Regarding your diabetes: it is managed with diet and lifestyle only. You have a diabetic nurse review coming up in about a month and have blood tests every 3 months — your last result was satisfactory. You were started on the water tablet 7 months ago for swollen ankles, and the swelling has since gone away. Regarding the aspirin: you were prescribed it many years ago alongside your blood pressure tablets and believe it works together with them.',
  ARRAY[]::text[],
  'You live alone in a semi-detached two-bedroom house with stairs. You are a retired civil servant. Your daughter lives around 30 miles away and comes to visit every couple of weeks. You manage your own cooking, cleaning, and shopping independently.',
  'You feel you tripped because your legs felt shaky and unsteady at the time.',
  'You are worried about having another fall.',
  'You would like the GP to advise you on how to prevent this from happening again.',
  ARRAY[]::text[],
  NULL,
  'Decline any questions outside the details provided in the scenario.',
  ARRAY['Ask about the episode of the fall: when it happened, mechanism of the fall, whether it was witnessed, what led to it, and whether she was able to get herself up.','Ask about pre-fall symptoms such as dizziness, palpitations, chest pain, or weakness in any part of the body to suggest a stroke','Ask if any injury or fracture was sustained. Use the ambulance report in questioning, for example: "I can see from the ambulance records that there were no injuries, is that correct?" to demonstrate use of available information.','Ask if she lost consciousness during or after the fall.','Ask if she ever feels dizzy when standing up from a sitting position, to assess for postural hypotension.','Ask if anything is affecting her mobility, such as arthritis or joint pain, or symptoms suggestive of Parkinson''s disease (tremor, slow gait).','Ask if she has recently been more forgetful, or if anyone has noticed changes in her behaviour or concerns about her memory, to help rule out cognitive decline or dementia.','Ask about her eyesight and any visual problems that could contribute to falls.','Ask about urinary symptoms, including frequency, urgency or incontinence.','Ask about her bowel habits and whether there are any issues.','Ask about her diabetic control, whether she has any upcoming follow-ups, and when she last had a blood test.','Ask about hazards in the home that may have contributed to the fall, such as loose rugs, mats, poor lighting, wet bathroom floors, or unstable fittings like handrails.','Ask about her home situation, including whether she lives alone, how she is coping, and whether she has carers or family members who help with shopping, cooking, or daily activities.','Ask about her mood and whether the fall has affected her confidence or caused any feelings of low mood or anxiety.','Ask about diet and nutrition, as poor intake can lead to conditions such as hypoglycaemia or hyponatraemia, which can increase fall risk','Review her current medications, such as furosemide and aspirin, which do not have clear indications from her notes, and ask if she knows why she is taking them, to assess appropriateness.','Ask about social history, including alcohol use and smoking.','Explore her ideas, concerns, and expectations','Give a diagnosis of likely mechanical fall, possibly caused by polypharmacy and side effects of medications such as furosemide and antihypertensives.'],
  ARRAY['Offer discontinuation of furosemide, as it can lead to dehydration, contribute to feeling wobbly, and is no longer required since her leg swelling has resolved','Offer review and reduction of antihypertensives, for example discontinuing ramipril, to reduce the risk of postural hypotension','Stop aspirin, as she has no clear indication for it and it is not recommended for primary prevention of cardiovascular disease. Aspirin should only be continued if there is a clear secondary prevention indication, such as a previous TIA, stroke, myocardial infarction, or peripheral arterial disease.','No immediate need for a face-to-face assessment, as she has recently been reviewed by the ambulance crew with vital signs, ECG, and cardiovascular examination. Therefore, do not offer a face-to-face appointment or home visit at this stage.','You can offer bloods to check for electrolyte abnormality due to furosemide','Offer referral to occupational therapy to assess her home environment and identify adjustments that may reduce her risk of falls','Offer referral to community physiotherapy for strength and balance training, which can improve confidence and help prevent further falls.','Offer a falls alarm, which can be arranged through social prescribers, occupational therapy, community physiotherapy, or frailty practitioners. These devices use motion sensors to detect a fall and automatically alert a monitoring team, who can arrange emergency help if required.','Consider anti-fall stockings, which may provide better traction on smooth floors and reduce fall risk.','Encourage good fluid intake to prevent dehydration, which can contribute to falls.','Arrange follow-up in 1–2 weeks to recheck blood pressure and reassess overall progress.','Safety net by advising that if she develops dizziness, chest pain, weakness in any part of the body, another fall, or any other concerning symptoms, she should seek urgent medical advice immediately.'],
  'Thank you for calling in today, Dorothy, and for letting me know what happened. I am glad you were able to get help quickly and that the paramedics found no injuries. I have looked through their report carefully and it is very reassuring that your heart tracing, blood pressure, and blood sugar were all satisfactory on the day. I want to go through a few things with you so we can try to understand what caused this and, importantly, reduce the chances of it happening again.

From what you have described — the shakiness in your legs just before the fall, and the fact that you have been needing to pass urine much more frequently since starting your water tablet seven months ago — I think the water tablet, called furosemide, may well be contributing to the problem. Because the swelling in your ankles has now resolved, it appears you no longer need it. I would like to stop it, and I would also like to review your blood pressure tablets to see whether we can reduce them slightly, as some blood pressure medication can make you feel light-headed and unsteady, particularly when you first stand up. This is called postural hypotension, and it is a recognised cause of falls in older patients.

I also want to talk about the aspirin. Looking through your records, I cannot find a clear reason why it was started. Unless you have had a previous heart attack, stroke, or similar event, aspirin is not recommended as a preventive measure in someone who has not had one of these conditions, as the risks can outweigh the benefits. I would therefore like to stop the aspirin as well. I will order a blood test to check your electrolytes, as stopping the water tablet can occasionally cause imbalances.

In terms of practical steps to help keep you safe at home, I would like to refer you to our occupational therapist, who can visit the home and suggest adjustments — things like grab rails by the bath, better lighting, or removing any trip hazards. I would also like to refer you to community physiotherapy for some balance and strength exercises, which have very good evidence for reducing falls. We can also look into a personal falls alarm — a small device you wear which automatically alerts a monitoring team if you have a fall and cannot reach your phone. That would give you and your daughter greater peace of mind.

Please do make sure you are drinking enough fluids each day, as dehydration can make you feel unsteady. I will arrange a follow-up in the next week or two to recheck your blood pressure once the medication changes have settled. In the meantime, please call 999 or ask someone to help you urgently if you experience dizziness, chest pain, any weakness or numbness, or have another fall.',
  ARRAY['Polypharmacy is a leading modifiable risk factor for falls in older adults — medication review is an essential part of falls assessment, with particular attention to antihypertensives and diuretics.','Furosemide should be reviewed regularly; if the original indication (such as peripheral oedema) has resolved, it should be discontinued to reduce fall risk from dehydration and electrolyte disturbance.','Aspirin is not recommended for primary prevention of cardiovascular disease in the absence of a confirmed secondary prevention indication; prescribing it without clear indication increases bleeding risk without benefit.','A recent ambulance assessment (including ECG, vital signs, and cardiovascular examination) is a valid clinical review — a further face-to-face GP appointment is not always required immediately after such attendance.','Falls prevention in older adults should be multidisciplinary: occupational therapy for home assessment, physiotherapy for strength and balance training, and falls alarms for safety.','Always screen for postural hypotension in older patients on antihypertensive therapy — ask specifically whether the patient feels dizzy on standing.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  112,
  'Patient''s Complaints About Your Colleague',
  'Ethics',
  'Telephone consultation',
  false,
  'Caroline Sutton',
  '51-year-old female',
  ARRAY['Osteoarthritis','Asthma'],
  ARRAY['DuoResp Spiromax (MART) 1 puff twice daily'],
  'Seen by a clinical practitioner 2 weeks ago. History: Recent X-ray confirmed osteoarthritis of the right knee. Patient states pain is not controlled with topical ibuprofen and is sometimes disturbing her sleep at night. No red flags. Walking freely and not limping. Plan: Start amitriptyline 25 mg at night. Worsening advice given. Patient has booked a telephone consultation to discuss some concerns.',
  'Patient booked a telephone consultation to raise concerns about a recent appointment.',
  'Hi doctor, I wanted to call because I have some concerns about the consultation I had a couple of weeks ago, and I wasn''t sure who to speak to.',
  'You attended the surgery two weeks ago because the topical ibuprofen was not controlling your knee pain. During the consultation, you noticed that the doctor appeared exhausted — their eyes were red and they seemed as though they had barely slept. The appointment felt rushed, and the doctor did not examine your knee the way other doctors usually would. They prescribed amitriptyline. You later experienced dizziness as a side effect and were not warned about this beforehand. When you looked it up, you discovered amitriptyline is an antidepressant also used for nerve pain, and you were not happy with the decision. You bought some codeine from the pharmacy, which has been helping with the pain. The dizziness settled once you stopped the amitriptyline.',
  ARRAY[]::text[],
  '',
  'You feel the doctor may not have been fit to see patients on that day.',
  'You are concerned about the safety of other patients who were seen by that doctor on the same day.',
  'You would like to know how to make a formal complaint. You also want to know whether the decision to prescribe amitriptyline was appropriate.',
  ARRAY[]::text[],
  'Was the decision to prescribe amitriptyline the right thing to do?',
  NULL,
  ARRAY['Begin by acknowledging the patient''s concerns warmly and non-defensively. For example: "Thank you for reaching out — I''m sorry to hear about your experience. I want to assure you that we take concerns like this very seriously, and I''d like to understand what happened so we can address this properly. Could I ask you a few questions to help me get the full picture?"','Ask how her knee pain is currently — is it controlled? Does she need further analgesia?','Ask about the amitriptyline: did she experience any other reactions beyond dizziness? Has she stopped taking it? Has the dizziness fully resolved? Did it provide any pain relief before the side effects occurred?','Ask for more detail about how the doctor appeared during the consultation — what specifically made her feel concerned about their fitness to practise?','Ask whether the doctor''s behaviour affected the care she felt she received during the appointment.','Ask if she has any further concerns about the consultation or any other aspect of her care.','Explore what outcome she is hoping for — does she want a formal investigation, an apology, reassurance, or something else?'],
  ARRAY['Acknowledge her concern again sincerely: "Thank you for sharing this with me. I''m sorry you left that consultation feeling uncomfortable, and that the amitriptyline caused dizziness without prior warning. You were right to stop it, and I''d like to work with you now on a better plan for your knee pain."','If she is still in pain, offer alternative analgesic options and discuss physiotherapy or joint injections for the knee.','If dizziness persists, arrange a further appointment to assess this in more detail.','Explain the complaints process clearly: her concerns will be passed to the practice manager for review. The practice will acknowledge the complaint within three working days, and a full investigation will follow. She will be kept updated throughout the process.','Reassure her that if she wishes to remain anonymous while the concern is investigated, this can be arranged.','Explain that you will also speak with the doctor involved to hear their account of the consultation.','If further analgesia is prescribed, arrange a follow-up to review its effectiveness and tolerability.','Inform her that she will be kept informed of the outcome of the investigation.','If asked about whether amitriptyline was an appropriate prescription: explain that amitriptyline is a recognised treatment for certain types of chronic or nerve-related pain that does not respond to standard analgesics. You were not present during the consultation and are therefore not in a position to fully evaluate the clinical decision made at that time. However, you will ensure her current pain management is reviewed and optimised.'],
  'Thank you for calling today, and I''m really glad you did. It takes courage to raise a concern like this, and I want you to know that we take everything you''ve described very seriously. Before we go any further, I want to make sure you''re doing okay at the moment — how is your knee now, and are you managing with the codeine you picked up?

I''m sorry to hear that the appointment felt rushed, and that you weren''t warned about the side effects of amitriptyline. Dizziness is a recognised side effect, and you were absolutely right to stop it when it was causing problems. I''m pleased to hear that has now settled. In terms of your knee pain, we can certainly look at other options together — whether that''s a different painkiller, a referral for physiotherapy, or a discussion about joint injections. We will make sure your pain is better managed going forward.

You have asked about the prescription itself. Amitriptyline is sometimes used in managing chronic pain, including joint and nerve-related pain that does not respond well to standard painkillers. I wasn''t involved in your care on that day, and I wouldn''t want to comment on a clinical decision made without having all of the information available at the time. What I can do is make sure your current treatment is reviewed thoroughly today.

In terms of your concerns about the doctor''s fitness on the day — I want you to know that these will be taken seriously. I''d like to pass your concerns on to the practice manager, who will lead a formal review. You will receive an acknowledgement of your complaint within three working days, and you will be kept informed as the investigation progresses. If you would prefer for your identity to remain confidential during this process, we can arrange that. We will also speak with the doctor involved to understand their perspective on the consultation.

Your concerns about other patients seen that day reflect a real care for patient safety, and that matters. This kind of feedback is exactly what helps us to improve and to make sure every patient receives the standard of care they deserve.',
  ARRAY['When a patient raises a concern about a colleague, begin by acknowledging the complaint openly and non-defensively before gathering further information — this builds trust and demonstrates a patient-centred approach.','The NHS complaints process requires acknowledgement within three working days; the patient should be kept informed of progress and outcome throughout the investigation.','Patients have the right to raise concerns anonymously — if requested, this should be respected while the concern is still investigated.','When asked to comment on a colleague''s clinical decision, avoid either endorsing or criticising the decision without full context; instead, acknowledge the treatment rationale generally and offer to review the patient''s current management.','Always attend to the patient''s immediate clinical needs during a complaints consultation — in this case, ensuring adequate pain management for the knee is part of good care.','Concerns about a colleague''s fitness to practise — such as appearing unwell or impaired at work — have patient safety implications and should be escalated through the practice manager and, if serious, through appropriate professional channels.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  113,
  'Breathlessness in Known COPD',
  'Respiratory',
  'Telephone consultation',
  false,
  'Peter Marsden',
  '67-year-old male',
  ARRAY['COPD','Hypertension','High Cholesterol'],
  ARRAY['Trelegy Ellipta one puff daily','Salamol inhaler PRN','Amlodipine 10 mg once daily','Atorvastatin 20 mg once daily'],
  'Seen by respiratory nurse practitioner 5 weeks ago. History: Known COPD, well controlled, good inhaler technique. Reports some shortness of breath on exertion, although mild, no red flags, recent spirometry shows no decline. Not a smoker and no recent flare. Plan: Continue ongoing management. Advised to book appointment with GP to discuss shortness of breath.',
  'Patient booked a telephone appointment to discuss breathlessness that has been occurring on exertion.',
  'Hello doctor, I''ve been living with COPD for quite a few years and it''s generally been well controlled. But recently I''ve been getting breathless when I exert myself, and I wanted to speak to someone about it.',
  'You attended a routine COPD review with the nurse 5 weeks ago, where your spirometry and inhaler technique were both checked and no changes were made. Recently you have been noticing shortness of breath, but only when doing something active like climbing stairs or walking further than usual. You have also noticed some chest tightness during those episodes. You have no breathlessness at rest, and you are not woken at night by it.',
  ARRAY['Your blue inhaler does not seem to relieve the breathlessness — only resting makes it better.','You have no chest pain, palpitations, dizziness, or fainting during the episodes.','You do not have any increased cough, more phlegm than usual, or wheezing.','You are concerned because even though your COPD seems to be under control, this breathlessness on exertion feels new or slightly worse than it used to be. Decline any questions outside the details provided.'],
  'You live at home alone — your wife passed away two years ago. You stopped smoking 10 years ago and do not drink alcohol. You are a retired delivery driver. You are generally independent with daily activities but the breathlessness has been holding you back recently.',
  '',
  'You are worried that the breathlessness might mean your COPD is getting worse, and you are concerned about losing your independence.',
  'You would like the doctor to look into why you are getting breathless and to give you some guidance on what to do.',
  ARRAY[]::text[],
  NULL,
  'Decline any questions outside the details already provided.',
  ARRAY['Ask about the breathlessness — does it happen only on exertion or also at rest? Is there associated chest tightness? What brings it on, and what makes it better (rest, inhalers)?','Ask about orthopnoea (difficulty breathing when lying flat, or needing extra pillows) and paroxysmal nocturnal dyspnoea (waking gasping for air), and ankle swelling — to screen for heart failure','Ask about cough, sputum production, chest pain, and palpitations','Ask about red flag symptoms: unexplained weight loss, night sweats, fever','Ask about adherence to current inhalers and medications','Ask how the breathlessness has affected his daily life and independence','Ask about social history: smoking history, alcohol intake, and home situation','Explore ideas, concerns, and expectations','Give a diagnosis of likely stable angina — explaining that exertional breathlessness with chest tightness, relieved by rest but not by inhalers, points to a cardiac rather than respiratory cause'],
  ARRAY['Offer a face-to-face appointment to examine heart sounds, check chest, and measure blood pressure','Offer investigations: ECG, blood tests including BNP, FBC, and cholesterol, and chest X-ray','Offer GTN spray and aspirin 75 mg once daily — with thorough safety-netting: use GTN spray during an episode; take a second dose after 5 minutes if not eased; call 999 if not eased 5 minutes after the second dose, or sooner if pain is intensifying or the patient is unwell','Offer urgent referral to a rapid access chest pain clinic','Safety net regarding unstable angina: if breathlessness occurs at rest, or is accompanied by chest pain or palpitations, advise calling 999 immediately'],
  'Thank you for calling today, and for giving me such a clear account of what has been happening. I can completely understand why this is worrying you — you have had your COPD well managed for years, and now something seems to have changed. I want to reassure you that we are going to take this seriously and get to the bottom of it.

I have looked at the notes from your nurse review five weeks ago, Peter, and it is really helpful that your spirometry was stable and your inhaler technique was good. That actually gives us an important clue, because it suggests your COPD itself is not the likely cause of this new breathlessness. What you are describing — breathlessness on exertion with chest tightness, improving with rest but not with your blue inhaler — follows a different pattern to what we would expect from COPD, which tends to be persistent and relieved by inhalers.

What I am more concerned about is a condition called angina. Angina happens when the heart muscle is not receiving quite enough oxygen-rich blood, usually because of some narrowing in the blood vessels supplying the heart. It commonly causes breathlessness or chest tightness during activity that eases with rest — exactly what you are describing. Given that you have high blood pressure, high cholesterol, and a history of smoking, your heart health is something we need to assess carefully.

I would like you to come in so I can examine your heart and chest, check your blood pressure, and carry out a heart tracing called an ECG. I would also like to arrange some blood tests — including a marker called BNP which helps us assess heart function — along with a cholesterol check and a chest X-ray. I would also like to refer you urgently to a specialist chest pain clinic, where the team can carry out further assessment quickly.

In the meantime, I would like to prescribe a GTN spray and a daily aspirin 75 mg to start protecting your heart. If you get another episode of breathlessness or chest tightness, spray the GTN under your tongue. If it is not better after 5 minutes, take a second dose. If it has still not improved 5 minutes after that second dose, or if it is getting worse, please call 999 immediately. The same applies if you ever develop breathlessness at rest, severe chest pain, or palpitations — that would be a reason to call 999 straight away without waiting.',
  ARRAY['Exertional breathlessness in a patient with known COPD should not automatically be attributed to the COPD — always consider cardiac causes, particularly if inhalers do not provide relief and chest tightness is present.','Key clinical features distinguishing angina from COPD-related breathlessness: angina is exertional, relieved by rest, not relieved by bronchodilators, and may be accompanied by chest tightness; COPD breathlessness is persistent, relieved by inhalers, and accompanied by cough or wheeze.','When stable angina is suspected, refer urgently to a rapid access chest pain clinic and arrange ECG, BNP, FBC, cholesterol, and chest X-ray.','GTN spray and aspirin 75 mg once daily are first-line treatments for suspected stable angina in primary care; patients must be counselled on correct GTN use and the 999 threshold if two doses fail to relieve symptoms.','Safety-netting is critical: any rest pain, severe or worsening symptoms, or failure of GTN after two doses warrants immediate emergency services.','NICE does NOT recommend paracetamol, NSAIDs, opioids, or oral triptans for cluster headaches — sumatriptan nasal spray or subcutaneous injection and high-flow oxygen are the recommended acute treatments.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  114,
  'Severe Headache In A Young Male',
  'Neurology',
  'Telephone consultation',
  false,
  'Lucas Bennett',
  '28-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'Patient booked an urgent appointment to discuss a severe recurring headache.',
  'Hi doctor, I''ve been getting these absolutely terrible headaches for the past few days and I''m really worried about what might be causing them.',
  'For the past four days you have been getting intense, one-sided headaches around your left eye and temple. The pain is sharp and stabbing — you would describe it as the worst pain you''ve ever felt, almost like a hot poker being driven into your eye. Each episode lasts roughly 30 to 90 minutes and you can have up to 6 attacks in a single day. During the attacks, your left eye goes red and watery, your nose blocks up or runs on the same side, and you get facial sweating on that side too. You feel completely restless during an attack and find yourself pacing or moving around because you cannot stay still. You have had this exact pattern of headache once before, about 2 months ago, and it went away on its own. Paracetamol and ibuprofen have not helped at all.',
  ARRAY['Your blue inhaler does not apply here — if asked about inhalers, say you do not use any.','The headache does not improve with standard painkillers such as paracetamol or ibuprofen.','You have no weakness, speech problems, confusion, or visual disturbances.','You have no neck stiffness, fever, rash, or recent head injury.','Decline any questions outside the details provided.'],
  'You work as a graphic designer and spend long hours in front of screens. You are a non-smoker and drink alcohol only occasionally. You have no history of recent head trauma. You live with your partner.',
  'You are worried this could be a brain tumour or a bleed in the brain.',
  'You are frightened that something very serious is going on inside your head and that it might be dangerous.',
  'You would like the GP to prescribe something stronger for the pain and to arrange a scan of your head.',
  ARRAY[]::text[],
  NULL,
  'Decline any questions outside the details already provided.',
  ARRAY['Ask about the onset of the headaches — when they started and whether this is a new pattern','Ask about the characteristics of the headache: location, which side, duration of each attack, nature of the pain (stabbing, throbbing, pressure), frequency (how many attacks per day), and any identifiable triggers such as alcohol, sleep changes, or stress','Ask about associated autonomic symptoms: red or watering eye, blocked or running nose, facial sweating, drooping eyelid, on the same side as the headache','Ask about light sensitivity (photophobia) and nausea or vomiting, which would be more typical of migraine','Ask about red flag features: neck stiffness (meningitis or subarachnoid haemorrhage), fever (meningitis or encephalitis), rash, limb weakness or numbness, visual disturbance (stroke or tumour), recent head trauma (subdural haematoma), confusion','Ask how the headaches are affecting his daily life and work','Explore ideas, concerns, and expectations','Give a working diagnosis of cluster headache, explaining the characteristic features and reassuring the patient about serious causes while recommending specialist review'],
  ARRAY['Offer a face-to-face appointment to perform a neurological examination, fundoscopy, and blood pressure check','For acute attack: offer sumatriptan intranasal spray — advise the patient to start with a dose of 10–20 mg in one nostril; if the headache returns after at least 2 hours, a further 10–20 mg can be taken; do not take a second dose for the same headache if the first did not help; the maximum dose in one day is 40 mg','Sumatriptan subcutaneous injection can also be considered as an alternative for acute attacks','Short-burst high-flow oxygen therapy can also be considered for acute attacks','Refer urgently to neurology for confirmation of diagnosis, neuroimaging, and likely initiation of preventive treatment. An urgent advice and guidance request or urgent referral are both appropriate.','If severe or frequent, seek specialist advice regarding prophylaxis with verapamil','Advise the patient to keep a headache diary to identify potential triggers and avoid them','Safety net thoroughly on neurological red flag symptoms and any sudden worsening — advise to call 999 if new neurological symptoms develop. Note: NICE advises that paracetamol, NSAIDs, opioids, ergots, and oral triptans should NOT be offered for the acute treatment of cluster headache, as they act too slowly and are insufficiently effective for these brief, intense attacks.'],
  'I can hear how frightening these headaches have been, and I completely understand why you are worried. When pain is this severe and happening so frequently, it is natural to fear the worst. Let me explain what I think is going on and what we are going to do about it.

From everything you have described, Lucas — the one-sided pain around your left eye, the short intense attacks lasting 30 to 90 minutes, the watering eye, blocked nose, and facial sweating on the same side, and the fact that you feel restless and cannot keep still during an attack — this fits very closely with a condition called cluster headache. Cluster headaches are one of the most painful conditions known, and many people who have them describe the pain exactly as you have: like something being forced into the eye. They tend to come in bouts or clusters lasting several weeks, with multiple attacks per day, before going away on their own — which matches what you told me happened two months ago.

I want to address your worries about a brain bleed or a tumour directly. A subarachnoid haemorrhage, which is a bleed around the brain, typically presents as a sudden, explosive thunderclap headache — the worst headache of your life arriving in an instant. Your headaches are severe but come on as distinct episodes rather than a single catastrophic event, and you have no neck stiffness, confusion, or weakness. A brain tumour typically causes headaches that build progressively over weeks or months and are often worse in the morning, and would usually be accompanied by changes in vision, memory, or coordination. Your pattern does not match either of these, which is reassuring.

That said, because this is the first time you have had these symptoms formally assessed, guidelines recommend that you are seen by a neurologist to confirm the diagnosis. They will very likely arrange a brain scan — not because we think there is something dangerous, but to be thorough and to make sure we are treating the right condition. I will send an urgent referral today.

In the meantime, I would like you to come in for a face-to-face appointment so I can check your blood pressure, look at the back of your eyes, and examine your nervous system. For the attacks themselves, there are effective treatments available. The most important thing I can tell you is that paracetamol and ibuprofen will not work for cluster headache — the attacks are simply too short and too intense for tablets to kick in in time. Instead, I am going to prescribe a nasal spray called sumatriptan. You use 10 to 20 mg in one nostril at the start of an attack. If the headache comes back after at least 2 hours, you can take a second dose, but do not take a second dose for the same attack if the first one did not help. The maximum in one day is 40 mg. High-flow oxygen through a mask is another effective option that the specialist may arrange. I would also encourage you to start keeping a diary of your headaches — when they happen, how long they last, and anything that might have triggered them, such as alcohol or changes in sleep. This will help the specialist greatly.

Please seek emergency help immediately if you develop any new symptoms such as weakness down one side, slurred speech, sudden severe vision changes, confusion, or a headache that is completely different to what you have been experiencing.',
  ARRAY['Cluster headache is characterised by severe unilateral periorbital pain with ipsilateral autonomic features (lacrimation, rhinorrhoea, facial sweating, ptosis) and psychomotor restlessness; attacks last 15–180 minutes and can occur up to 8 times per day.','NICE advises that paracetamol, NSAIDs, opioids, ergots, and oral triptans should NOT be used for acute cluster headache — they are too slow-acting for these brief, intense attacks.','First-line acute treatments for cluster headache are sumatriptan nasal spray (10–20 mg per nostril, maximum 40 mg per day) or subcutaneous injection, and high-flow oxygen therapy.','A first presentation of cluster headache should prompt urgent neurology referral for confirmation of diagnosis, neuroimaging, and consideration of prophylaxis — verapamil is the usual preventive agent.','Red flag features that must be excluded include neck stiffness, fever, rash, confusion, limb weakness, sudden thunderclap onset, and progressive worsening — these suggest meningitis, subarachnoid haemorrhage, or intracranial pathology.','Psychomotor restlessness (pacing, inability to keep still during attacks) is a distinguishing feature of cluster headache and helps differentiate it from migraine, where patients typically prefer to lie still in a dark room.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  115,
  'Pregnant woman worried about Downs',
  'Genetics',
  'Telephone consultation',
  false,
  'Rachel Whitmore',
  '44-year-old female',
  ARRAY['No significant past medical history','No regular medications or allergies'],
  ARRAY[]::text[],
  NULL,
  'Patient has booked an urgent appointment to discuss concerns about her current pregnancy and Down syndrome screening options.',
  'Hello, I''m calling because I''ve just found out I''m pregnant again and I''m really worried. I had my last period about eight weeks ago. I have a 4-year-old son with Down syndrome and I want to know what tests I can have and when.',
  'My son was born when I was 39 and I wasn''t really told about all the risks beforehand. I love him so much but I don''t want to go through the uncertainty again without knowing what options are available. A friend of mine who works as a midwife told me I might be able to get tested earlier than 11 weeks because of my history and age. I''m not sure if that''s right.',
  ARRAY['If asked about her son: He was diagnosed with Down syndrome at birth. He is doing well at home and attends a specialist nursery.','If asked about symptoms: She has some nausea but no abdominal pain and no bleeding.','If asked about antenatal registration: She has not registered yet as she only found out recently. The pregnancy was confirmed with a home urine test.','If asked about family history: No one else in her family or her partner''s family has Down syndrome or a known chromosomal condition.','If asked about medications: She started taking folic acid 400 micrograms daily after finding out she was pregnant.'],
  'She lives with her partner in Bristol. Both are anxious but happy about the pregnancy. She is a non-smoker and does not drink alcohol. No history of diabetes, hypertension, or other conditions affecting pregnancy.',
  'She believes her age and the fact that her previous son has Down syndrome both increase her risk in this pregnancy, and that there may be earlier testing options available to her.',
  'She is worried about the chances of Down syndrome in this pregnancy and wants to know whether she can be tested earlier than 11 weeks rather than waiting.',
  'She expects the doctor to explain all the available tests clearly, including when they can be done and whether they are safe for the baby.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY['Ask about LMP and how the pregnancy was confirmed — urine test or scan','Ask about early pregnancy symptoms: nausea, vomiting, abdominal pain, any bleeding','Ask about the previous pregnancy and the diagnosis of Down syndrome in her son','Ask about family history of Down syndrome or other genetic conditions from both her and her partner','Ask whether she has registered for antenatal care','Ask about medications including over-the-counter preparations and folic acid','Ask about smoking and alcohol use','Ask about her home situation and whether she has support','Explore her anxiety about this pregnancy and what specifically worries her most','Ask more about what her midwife friend said about earlier testing','Ask what she already understands about Down syndrome and the available tests','Ask about her ideas, concerns, and expectations'],
  ARRAY['Explain what Down syndrome is: a condition where the baby is born with an extra copy of chromosome 21, affecting growth and development. It occurs naturally and is not caused by anything the parent did or did not do.','Explain that the risk of Down syndrome increases with maternal age, and at 44 the risk is higher than average. Having had a previous child with Down syndrome also slightly increases the risk compared to someone of the same age who has not.','Explain that there are two main types of tests: screening tests and diagnostic tests. Screening estimates the probability; diagnostic tests confirm the diagnosis.','Screening tests: Combined Screening (11–14 weeks) involves a nuchal translucency ultrasound scan plus a blood test. NIPT (Non-Invasive Prenatal Testing) is a blood test available from 10 weeks and gives a more accurate screening result. If the patient books later, the quadruple blood test can be offered at 14–20 weeks, though it is less accurate than earlier options.','Diagnostic tests (from 11 weeks onwards) include chorionic villus sampling (CVS) and amniocentesis. These confirm whether the baby has Down syndrome but carry a small risk of miscarriage.','If a diagnostic test confirms Down syndrome, the options include: continuing the pregnancy and preparing for the baby''s needs; continuing the pregnancy and considering adoption; or ending the pregnancy (termination). Full support will be provided whatever the decision.','Ensure she is taking folic acid 400 micrograms daily (or 5 mg daily if considered high risk) and vitamin D.','Advise her to register for antenatal care as soon as possible.','Offer pregnancy vaccinations: flu vaccine and COVID-19 vaccine at any time in pregnancy; whooping cough vaccine from 16 weeks; RSV vaccine from 28 weeks.','Offer written information and leaflets about Down syndrome screening.','Advise her to book a follow-up appointment after the screening results are available if she wishes to discuss them further.'],
  'Thank you for calling in today, Rachel. I can hear how much this pregnancy means to you, and I want you to know that everything you''re feeling right now — the worry, the uncertainty — is completely understandable. Let me take some time to go through everything with you properly.

Down syndrome is a condition where the baby is born with an extra copy of chromosome 21, which affects how they grow and develop. It happens naturally during the formation of the egg or sperm, and it is not caused by anything you did or didn''t do in this pregnancy or the last one. The important thing to understand is that the chance of having a baby with Down syndrome does increase as we get older, and at 44, your background risk is higher than it was in your previous pregnancy. Having already had a son with Down syndrome also slightly increases your risk compared to someone your age who hasn''t. This is exactly why we make sure to offer thorough screening early.

Your midwife friend is right that there are options available before the standard 11 to 14 week combined screening. A test called Non-Invasive Prenatal Testing, or NIPT, is a blood test that can be done from 10 weeks of pregnancy. It analyses tiny fragments of the baby''s DNA that are present in your bloodstream and gives a much more accurate screening result than the combined test alone. It is completely safe for you and the baby because it involves only a blood draw from you.

The NHS combined screening, which involves a scan to measure the fluid at the back of the baby''s neck along with a blood test, is offered between 11 and 14 weeks. If you are further along when you register, there is also a quadruple blood test available between 14 and 20 weeks, though this is less accurate than the earlier options. If your screening comes back showing a higher chance result, we would then offer you a diagnostic test — either a chorionic villus sample from 11 weeks or an amniocentesis a little later. These are more definitive and tell us for certain whether the baby has Down syndrome, but they do carry a small risk of miscarriage, which is why we tend to use screening to guide who needs them.

If a diagnostic test were to confirm Down syndrome, I want you to know that you would not be left to face that alone. We would support you fully in exploring all your options — whether that is continuing the pregnancy and preparing for your baby''s care, or considering other paths. Whatever you decide, the team around you would be there to guide you.

In the meantime, I''d like to make sure you''re taking folic acid at least 400 micrograms daily — and given your age and history, it''s worth us reviewing whether you should be on the higher dose of 5 milligrams. Please also ensure you''re taking vitamin D. When you register for antenatal care, which I''d encourage you to do as soon as possible, the team will go through all of this with you in detail and arrange your first dating scan and booking bloods.

Do please call us or go to the nearest maternity assessment unit if you develop any abdominal pain, bleeding, or anything that worries you before your next appointment. We''re here for you throughout this pregnancy, Rachel.',
  ARRAY['The risk of Down syndrome increases with maternal age, and a previous child with Down syndrome further slightly elevates risk — both factors together make early screening discussion essential.','NIPT (Non-Invasive Prenatal Testing) is a blood test available from 10 weeks that gives a more accurate screening result than the combined test and carries no risk of miscarriage; it is a screening, not a diagnostic, tool.','Combined screening (nuchal translucency scan plus blood test) is offered at 11–14 weeks; the quadruple test is available at 14–20 weeks but is less accurate and should only be offered if the patient presents late.','Diagnostic tests (CVS and amniocentesis) confirm the diagnosis of Down syndrome but carry a small risk of miscarriage; they are offered after a high-chance screening result.','All pregnant women should be taking folic acid 400 micrograms daily (5 mg if high risk) and vitamin D; pregnancy vaccinations (flu, COVID-19, whooping cough from 16 weeks, RSV from 28 weeks) should be offered at antenatal registration.','If a diagnostic test confirms Down syndrome, the GP should present all options non-judgementally: continuing the pregnancy with preparation, adoption, or termination, with full support offered for any decision.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  116,
  'Pregnancy and Subclinical Hypothyroidism',
  'Endocrine & Nephrology',
  'Telephone consultation',
  false,
  'Claire Bennett',
  '33-year-old female',
  ARRAY['Currently pregnant','No other significant past medical history'],
  ARRAY[]::text[],
  'Seen 3 days ago by Jane Pearson, Nurse Practitioner (Access Role). History: Patient is 9 weeks pregnant. Reports persistent tiredness over the past 6 weeks with no other associated symptoms. Examination: BP 110/70 mmHg, Weight 70 kg, BMI 24. Urinalysis: all negative. Impression: Likely pregnancy-associated tiredness. Plan: Bloods requested to exclude vitamin deficiency or other causes of tiredness. Advised to rest, stay hydrated, and start folic acid 400 micrograms once daily (available over the counter). Review with results.

Blood results available for review:
Test | Result | Reference Range | Previous Result
TSH | 5.8 mU/L | 0.4–4.0 mU/L | N/A
T4 | 11 pmol/L | 9–24 pmol/L | N/A
Hb | 12.2 g/dL | 11.5–16.5 g/dL | N/A
Ferritin | 50 µg/L | 15–150 µg/L | N/A
B12 | Normal | — | N/A',
  'Patient is calling to discuss her recent blood test results.',
  'Hello, I was asked to call in to go through my blood results. The nurse said she''d checked a few things and I''m a bit anxious to find out what they show.',
  'I''ve been exhausted for about six weeks now. I know tiredness is common in pregnancy but it feels like more than that — I can barely get through a day at work without struggling. I haven''t had any other symptoms though.',
  ARRAY['Say no to any other symptoms if asked — no cold intolerance, no constipation, no weight gain, no skin or hair changes, no mood changes beyond normal pregnancy worry.','If asked about medications: she started folic acid 400 micrograms daily as advised by the nurse but is not taking anything else.','If asked about family history: no family history of thyroid disease that she is aware of.','If asked about antenatal registration: she has registered and her booking appointment is in two weeks.'],
  'She works as a secondary school teacher and lives with her partner in Leeds. Non-smoker, does not drink alcohol. This is her first pregnancy and she is unsure what is normal to expect. She has good support at home from her partner.',
  'She thinks the tiredness is probably just part of being pregnant since the nurse mentioned that last time, but she is not entirely sure.',
  'She is worried the tiredness is affecting her ability to do her job properly and she does not want to have to take early maternity leave.',
  'She wants the doctor to explain her blood results clearly and offer a solution to help her feel better.',
  ARRAY[]::text[],
  NULL,
  'SAY NO TO ANY OTHER SYMPTOMS ASKED',
  ARRAY['Ask about symptoms of hypothyroidism: fatigue, cold intolerance, changes to skin or hair, weight gain, low mood, constipation','Ask whether symptoms have worsened since she last saw the nurse practitioner','Ask about her pregnancy: how many weeks, whether it was planned, whether all is going well so far','Ask about pregnancy symptoms: abdominal pain, bleeding, nausea, vomiting','Ask about family history of thyroid disease','Ask about medications including over-the-counter preparations, and confirm she has started folic acid','Ask about social history: occupation, smoking, alcohol, home situation, support at home','Ask about her ideas, concerns, and expectations','Explain the blood test results, including the diagnosis of subclinical hypothyroidism'],
  ARRAY['Request further bloods to check for thyroid peroxidase antibodies (TPOAbs). Pregnant women with positive TPOAbs will usually benefit most from treatment with levothyroxine.','Offer levothyroxine 50 micrograms once daily — but discuss with a specialist (Endocrinologist) first before initiating. NICE guidance notes that treating subclinical hypothyroidism in pregnancy with levothyroxine (LT4) may reduce the risk of pregnancy complications, particularly in those with positive TPOAbs, and recommends seeking specialist advice prior to starting treatment. Both TPOAb-positive and TPOAb-negative patients should be considered for levothyroxine as it may improve pregnancy outcomes; however, specialist input is required. Levothyroxine is safe in pregnancy.','Advise that levothyroxine should be taken on an empty stomach, at least 30–60 minutes before food, and at least 4 hours apart from iron or calcium supplements, which can reduce its absorption.','Arrange follow-up with repeat thyroid blood tests in 4 weeks to check whether TSH is within the pregnancy target range (less than 2.5 mU/L in the first trimester).','Ensure she is taking folic acid 400 micrograms daily (or 5 mg if high risk) and vitamin D.','Offer pregnancy vaccinations: flu vaccine and COVID-19 vaccine at any time in pregnancy; whooping cough vaccine from 16 weeks; RSV vaccine from 28 weeks.','Safety net: advise her to seek urgent medical attention if she develops worsening fatigue, weight gain, cold intolerance, or any new symptoms.'],
  'Thank you for calling in, and I''m glad you''ve been in touch because your blood results do give us something important to go through together. I can hear that the tiredness has been really weighing on you, so let me explain what we''ve found and what we''re going to do about it.

Your blood test shows that your thyroid function is on the borderline — slightly lower than we''d like to see. This is called subclinical hypothyroidism. Your thyroid is a small gland at the front of your neck that acts a bit like the engine regulator for your whole body: it controls your metabolism, your energy, and how efficiently your body converts food into fuel. When the thyroid is a little sluggish, even mildly so, it can cause exactly the kind of persistent tiredness you''ve been describing.

Now, in pregnancy this becomes particularly important. Claire, your thyroid has to work harder than usual because it is supporting not just you but your growing baby as well. Even a subtle reduction in thyroid hormone output can affect how you feel day to day, and if left unaddressed it could potentially affect the pregnancy. That''s why we''re taking this seriously and acting on it now rather than waiting.

What I''d like to do is arrange one further blood test to check for something called thyroid peroxidase antibodies — these are markers that can tell us whether your immune system is contributing to the thyroid underactivity, and the result helps guide exactly how we treat you. In the meantime, I want to discuss starting you on a medication called levothyroxine. This is a tablet that simply replaces the hormone your thyroid isn''t making in quite enough quantity. It is completely safe to take during pregnancy. Before I prescribe it, I''d like to have a brief conversation with one of our specialist endocrinology colleagues to make sure we get everything right for you. The dose we would likely start with is 50 micrograms once daily.

If we do start levothyroxine, there are a couple of important things to know about how to take it. It works best on an empty stomach — ideally at least 30 to 60 minutes before breakfast. You should also leave at least 4 hours between taking it and any iron or calcium supplements, as those can interfere with how well the tablet is absorbed. We''ll then repeat your thyroid blood test in 4 weeks to make sure your levels are coming down into the right range for pregnancy, which we aim to keep below 2.5 for the first trimester.

In the meantime, please keep taking your folic acid and make sure you''re also taking vitamin D daily — both are really important in pregnancy. When you attend your booking appointment, the midwife team will also make sure you''re offered your flu and COVID-19 vaccines, and your whooping cough vaccine from 16 weeks.

If at any point before we speak again you notice the tiredness getting significantly worse, or you develop symptoms like feeling unusually cold, gaining weight unexpectedly, or anything new that worries you, please do not hesitate to call us straight away or contact the maternity assessment unit.',
  ARRAY['Subclinical hypothyroidism in pregnancy is defined as a TSH above the trimester-specific reference range (target <2.5 mU/L in the first trimester) with a normal T4; it is clinically significant in pregnancy even without symptoms.','NICE recommends seeking specialist (endocrinologist) advice before initiating levothyroxine for subclinical hypothyroidism in pregnancy; both TPOAb-positive and TPOAb-negative patients may benefit, but TPOAb-positive patients are most likely to see improved outcomes.','Levothyroxine 50 micrograms once daily is the typical starting dose; it must be taken on an empty stomach at least 30–60 minutes before food and at least 4 hours apart from iron or calcium supplements.','Thyroid peroxidase antibody (TPOAb) testing should be requested alongside levothyroxine initiation to guide ongoing management and establish immune-mediated aetiology.','Repeat thyroid function tests should be arranged at 4 weeks to confirm TSH is within the pregnancy target range; ongoing monitoring throughout pregnancy is required.','All pregnant women should receive folic acid and vitamin D; pregnancy vaccinations (flu and COVID-19 at any time, whooping cough from 16 weeks, RSV from 28 weeks) should be offered.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  117,
  'Suspected Female Genital Mutilation',
  'Ethics',
  'Telephone consultation',
  false,
  'Nadia Al-Rashid',
  '34-year-old female',
  ARRAY['No significant past medical history'],
  ARRAY[]::text[],
  'Mother (Fatima Al-Rashid) booked a routine consultation to discuss concerns. Patient: Leila Al-Rashid, 8-year-old female.',
  'Mother has called to seek advice about a planned trip abroad and has expressed concerns she wishes to discuss with the doctor.',
  'Hello, I''m calling because I''m not sure this is the right thing to do, but I need some advice. I''m worried about my daughter and I didn''t know who else to turn to.',
  'My husband has arranged for us to fly to Morocco in four days for a family gathering. But I found out recently that the real reason for the trip is for my daughter Leila to have what the family calls a "purification ceremony" — what some people call female circumcision. I had this done to me when I was a little girl and I remember how painful it was. I don''t want Leila to go through the same thing, but my husband says it''s part of our culture and religion and that the whole extended family expects it.',
  ARRAY['If asked about why she is calling: She feels guilty and frightened, but she does not know where else to turn. She is relieved someone is listening.','If asked about other children: She has two children — Leila and an older brother, Tariq, who is 10. Both are doing well in school.','If asked about whether Leila knows: Leila has been told it is just a family holiday and is not aware of the planned procedure.','If asked about how the mother feels: She is frightened of opposing her husband and the family but deep down does not want this to happen to her daughter.','If asked about safety at home: She feels under pressure from her husband but says she is not physically harmed. She is emotionally distressed.','Say no if asked about any physical symptoms relating to herself.'],
  'She lives with her husband and two children in Birmingham. Both children attend local schools and are doing well. She describes the home situation as outwardly fine but says she feels controlled by her husband on this issue.',
  'She knows the procedure is painful and believes it caused her lasting harm, but she was raised to think it was necessary for a woman to be accepted within her community and family.',
  'She is worried about her daughter''s health and wellbeing. She feels helpless because her husband has made the decision, and she is conflicted between her love for her daughter and her fear of disobeying her husband and being judged by the extended family.',
  'She is hoping the doctor can prescribe strong painkillers for her daughter for after the procedure.',
  ARRAY[]::text[],
  NULL,
  'SAY NO TO ANY OTHER SYMPTOMS ASKED',
  ARRAY['Begin by thanking the mother for calling and acknowledging how difficult it must have been to reach out','Ask when the trip is planned and exactly where they are going','Ask what the father has said about why he wants Leila to have this procedure — is it presented as cultural or religious in nature?','Ask about family history of FGM — has the mother herself undergone it?','Ask whether there are any other female children at home and, if so, whether FGM has already been carried out on them (if FGM has been carried out on a child under 18, this must be reported to the police)','Ask whether Leila is aware of the planned procedure and how she is feeling about the trip','Ask how the mother herself feels about the situation','Ask about the home environment: does she feel safe? Is there any form of coercion, pressure, or violence at home?','Explain clearly and sensitively what FGM is and why the GP is required to act','Explore the mother''s ideas, concerns, and expectations'],
  ARRAY['Take immediate safeguarding action — inform the mother clearly that this is a serious child protection matter and that you are required by law to act.','Contact the safeguarding team immediately and initiate an urgent child protection referral. Do not delay this even if the consultation has not concluded.','Inform the mother that Leila may be placed under a Child Protection Order to prevent her from leaving the country. The authorities may apply for an FGM Protection Order to prevent the trip.','Explain that FGM is illegal in the UK under the Female Genital Mutilation Act 2003. If the father proceeds with the plan, he could face a criminal sentence of up to 14 years in prison.','Do not prescribe painkillers for the procedure. Explain clearly that prescribing medication to facilitate FGM would be aiding an illegal act.','Reassure the mother that she is doing the right thing by speaking up, and that both she and Leila will be protected throughout this process.','Offer the mother (Fatima) a referral to counselling to address her own trauma from FGM.','Advise the mother that if she feels threatened or unsafe at home, she should call 999 in an emergency or contact the police, and that support services including domestic abuse helplines are available.','Provide written information and leaflets about FGM and available support organisations.'],
  'I want to start by saying how much courage it took to make this call today. I can hear that you are in a very difficult position, and I want you to know that reaching out was absolutely the right thing to do. You are clearly a loving mother and your daughter is lucky to have someone looking out for her in the way you are.

I need to be honest with you about what I''m hearing, because I have an important duty to explain. What you''ve described — a planned procedure for your daughter involving the removal or alteration of her genitalia — is what we in medicine call female genital mutilation, or FGM. I know that in some cultures this is described using other terms and is considered a tradition, but I want you to understand that in the United Kingdom this procedure is illegal. It is treated as a serious form of child abuse, regardless of cultural or religious context.

FGM causes significant physical harm. It is extremely painful, carries serious risks of infection and bleeding, and leads to lasting health complications that can affect a woman for the rest of her life. You know this from your own experience, and I am truly sorry that you went through that. The fact that you do not want the same for your daughter speaks volumes about how much you love her.

Because of what you have told me today, I am legally required to take action to protect Leila. I will be contacting our safeguarding team immediately so that the right agencies can step in to keep her safe. The authorities have the power to put a Child Protection Order in place, which can prevent Leila from being taken out of the country, and they can also apply for what is called an FGM Protection Order specifically to stop this trip from going ahead. I want to be transparent with you about all of this so there are no surprises.

Regarding the painkillers you mentioned — I''m afraid I''m not able to prescribe those. Providing medication to make it easier to carry out FGM would mean I was participating in an illegal act, and that is something I cannot do. I hope you understand that this is not about judging you — it is about protecting Leila.

I also want to make sure you are supported through this. What you have described about feeling unable to oppose your husband is something I take seriously. If at any point you feel threatened or unsafe at home, please call 999 immediately. There are also specialist support organisations and helplines for women in your situation, and I would like to arrange a referral to counselling for you as well, to help you process your own experiences with this procedure.

Please know that you have done the right thing today. Both you and Leila will be looked after through this process.',
  ARRAY['FGM is illegal in the UK under the Female Genital Mutilation Act 2003; performing, arranging, or facilitating FGM carries a prison sentence of up to 14 years.','Any disclosure of a planned or completed FGM on a child under 18 requires immediate safeguarding referral and contact with the child protection team — this is a mandatory duty, not a discretionary one.','Authorities can apply for an FGM Protection Order and a Child Protection Order to prevent a child from being taken abroad for the procedure; acting quickly is essential when a trip is imminent.','Do not prescribe analgesics or any medication that would facilitate FGM — doing so constitutes aiding an illegal act and is a serious professional and legal breach.','If FGM has already been carried out on another child in the household who is under 18, this must be reported to the police.','The mother should also be offered counselling for her own FGM-related trauma, and domestic abuse support should be discussed if there is any indication of coercive control at home.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  118,
  'Abnormal Blood Pressure Readings',
  'Cardiology',
  'Video consultation',
  false,
  'David Mensah',
  '48-year-old male',
  ARRAY['No significant past medical history'],
  ARRAY[]::text[],
  'Patient booked appointment to discuss concerns.',
  'Hello doctor. I''ve been checking my blood pressure at work over the last couple of weeks and the readings have been coming back quite high. I wanted to get some advice.',
  'I work as a sports physiotherapist and we have a blood pressure machine at the clinic. I checked mine on three separate days when I was sitting quietly and the readings were: Day 1: 150/100 mmHg, Day 2: 155/98 mmHg, Day 3: 160/98 mmHg. I feel absolutely fine — no headaches or anything — but my dad is on blood pressure tablets and I know it runs in the family. I''m worried I''ve got hypertension and I want to start medication now.',
  ARRAY['Say no to any other symptoms if asked — no headaches, no visual disturbance, no chest pain, no palpitations, no breathlessness, no leg swelling, no blood in urine, no weakness.','If asked about diet: not great — he eats a lot of takeaways and ready meals and admits he probably has too much salt. He drinks about three coffees a day.','If asked about exercise: he is aware of the irony that he does not exercise himself despite being a physiotherapist. He is largely sedentary outside work.','If asked about stress: work is moderately busy but manageable. No significant life stressors at the moment.','If asked about alcohol: drinks about 10–12 units per week, mostly at weekends.'],
  'He lives with his wife and three children in Leicester. He works as a sports physiotherapist. He does not smoke. He drinks approximately 10–12 units of alcohol per week. His diet is high in salt and processed food and he takes little regular exercise outside of his working day.',
  'He believes he has hypertension based on the readings and his family history.',
  'He has read that hypertension is called a "silent killer" and is worried that if it goes untreated it could lead to a stroke, heart disease, or kidney problems.',
  'He wants the GP to start him on antihypertensive medication today.',
  ARRAY[]::text[],
  NULL,
  'SAY NO TO ANY OTHER SYMPTOMS ASKED',
  ARRAY['Ask about headaches','Ask about blurred or double vision','Ask about any weakness, facial drooping, or speech problems (symptoms of stroke)','Ask about chest pain, palpitations, shortness of breath (hypertensive heart disease)','Ask about urinary symptoms including any blood in the urine','Ask about ankle or leg swelling','Ask about family history of hypertension, heart attack, or stroke','Ask about smoking, alcohol, diet, caffeine intake, occupation, and stress levels','Explore the readings he has taken and the circumstances under which they were measured','Make a working diagnosis of possible hypertension and explain that formal confirmation is required before treatment can be started'],
  ARRAY['Arrange a face-to-face appointment to check blood pressure in clinic. Request blood investigations: FBC, U+E, HbA1c, and lipid profile.','Request additional investigations including urine ACR (first void, early morning sample), ECG, and fundoscopy.','Offer Ambulatory Blood Pressure Monitoring (ABPM) — a small device worn for 24 hours that takes repeated readings throughout the day. Alternatively, offer Home Blood Pressure Monitoring (HBPM) — checking blood pressure twice daily for 7 days and recording the results. Either of these is needed to formally confirm hypertension before any medication is started.','Inform the patient that if ABPM or HBPM confirms hypertension, medication will be discussed and initiated at that stage.','Provide strong lifestyle advice: reduce dietary salt intake, increase physical activity, improve diet, reduce alcohol, reduce caffeine, and manage stress.','Arrange follow-up in 1–2 weeks to review blood test results and ABPM or HBPM readings.','Safety net: advise him to seek urgent medical attention if he develops severe headaches, chest pain, breathlessness, visual disturbance, or significant leg swelling before his next appointment.'],
  'Thank you for coming in today, and I''m glad you''ve been keeping an eye on things. It''s sensible to take blood pressure readings seriously, particularly with your family history, and I want to make sure we approach this properly.

The readings you''ve described — around 150 to 160 over 98 to 100 — are elevated, and I completely understand why that''s caught your attention, David. However, I want to explain why we can''t diagnose hypertension and start medication based on those readings alone. Blood pressure fluctuates quite naturally throughout the day. It can be temporarily raised by stress, caffeine, physical activity, or simply the act of being in a medical setting or thinking about your health. Three readings taken at work, even when you were sitting quietly, don''t give us the full picture. Before we label this as hypertension and consider medication, we need to be certain that the readings are consistently elevated across a longer period of time and in different circumstances.

The way we confirm a diagnosis of high blood pressure is through one of two methods. The first is called Ambulatory Blood Pressure Monitoring, or ABPM — you wear a small cuff attached to a monitor for 24 hours, which takes automatic readings at regular intervals while you go about your normal day. The second option is Home Blood Pressure Monitoring, where you check your blood pressure twice a day for seven days and record the results. Either of these will give us a much more reliable picture than a small number of clinic or workplace readings.

I''d also like to arrange a face-to-face appointment to check your blood pressure here in the practice, and to run some blood tests. These would include a full blood count, kidney function and electrolytes, a cholesterol panel, and a blood sugar test. We''d also check a urine sample, do an ECG to look at the electrical activity of your heart, and arrange an examination of the back of your eyes, which can show early signs of blood pressure damage.

In the meantime, there are some lifestyle changes that can make a real difference. I know it''s somewhat ironic given your profession, but building in more physical activity — even a 30-minute brisk walk most days — has a proven effect on blood pressure. Reducing your salt intake is probably one of the single most impactful changes you can make. Cutting back on processed and takeaway foods, moderating your alcohol intake, and reducing your caffeine to no more than one or two cups a day would all help too.

If the monitoring and blood tests confirm hypertension, we will absolutely discuss medication at that point — you won''t be left without treatment. But I want us to be sure of the diagnosis before we commit to lifelong tablets. Please do come back to us before your follow-up if you develop a severe headache, any chest pain or breathlessness, changes to your vision, or significant swelling in your legs — those would need prompt attention.',
  ARRAY['Hypertension cannot be diagnosed from a small number of self-taken or clinic readings alone — formal confirmation using ABPM (preferred) or HBPM (twice daily for 7 days) is required before any treatment is started.','A full cardiovascular risk assessment should be completed at diagnosis: FBC, U+E, HbA1c, lipid profile, urine ACR (early morning sample), ECG, and fundoscopy.','Lifestyle modification should be offered alongside or before medication: salt reduction, increased physical activity, reduced alcohol and caffeine, and dietary improvement are all evidence-based interventions.','Antihypertensive medication should not be initiated until the diagnosis is confirmed; premature treatment can cause unnecessary harm including symptomatic hypotension.','Safety-net patients to seek urgent review for red flag symptoms: severe headache, visual disturbance, chest pain, breathlessness, focal neurological symptoms, or significant oedema.','Family history of hypertension increases the pre-test probability and should prompt thorough assessment, but does not justify bypassing the diagnostic process.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  119,
  'Skin Lump In African Lady',
  'Dermatology',
  'Telephone consultation',
  false,
  'Amara Osei',
  '27-year-old female',
  ARRAY['No significant past medical history'],
  ARRAY[]::text[],
  'Recently registered at the practice. Patient sent a photograph of the lump on her abdomen via the online consultation portal. Patient booked a routine telephone appointment to discuss concerns.',
  'Patient calling to discuss a lump on her abdomen that has been growing in size and is causing her distress.',
  'Hello, I''m calling about a lump on my tummy. I''ve had it for about two years now but it''s been getting bigger over the last few months and I wanted to get some advice.',
  'The lump first appeared around two to three months after I had a road traffic accident in Accra, Ghana, about two years ago. I had a deep cut to my abdomen which was stitched up in hospital at the time and I recovered well from the wound itself, but this lump gradually appeared and grew from that area. It''s rubbery and soft when I press it, and it''s not painful. But it''s definitely bigger than it was even six months ago.',
  ARRAY['Say no to any other symptoms if asked — no pain, no discharge, no redness or warmth over the lump, no weight loss, no loss of appetite, no night sweats, no other lumps elsewhere in the body.','If asked about family history: she thinks her mother has similar scarring tendencies — a scar on her mother''s shoulder after an operation has always been raised and lumpy.','If asked about occupation: she works as a commercial photographer. Appearance and confidence in front of clients matters to her.','If asked about impact on life: she finds the lump embarrassing and avoids wearing certain clothes. It is affecting her confidence both personally and professionally.','If asked about previous skin treatments: none. She has not tried any treatments for the lump.'],
  'She lives with her flatmate in Manchester. She works as a commercial photographer and does not smoke or drink alcohol. She moved to the UK from Ghana eighteen months ago.',
  'She is not sure exactly what the lump is but strongly suspects it is related to the injury she sustained in the accident in Ghana.',
  'She is a commercial photographer and her appearance matters to her professionally and personally. The lump is visible when she wears certain clothing and it makes her feel self-conscious and less confident.',
  'She is hoping for a solution — ideally surgical removal or another treatment that will restore the normal appearance of her abdomen.',
  ARRAY[]::text[],
  NULL,
  'SAY NO TO ANY OTHER SYMPTOMS ASKED',
  ARRAY['Ask about the onset of the lump and how long it has been present','Ask about any history of trauma or injury in the area prior to the lump appearing — this is a classical feature of keloid and hypertrophic scars','Ask whether the lump has increased in size since it first appeared','Ask whether the lump feels soft, firm, or hard','Ask about any associated tenderness or pain','Ask about any discharge, redness, warmth, or other skin changes over the lump','Ask about any unexplained weight loss or loss of appetite (to exclude sinister pathology)','Ask whether there are any other lumps or bumps elsewhere on the body','Ask about any family history of keloid scars or similar lumps','Ask how the lump has affected her life, including work and confidence','Ask about occupation and social history','Explore her ideas, concerns, and expectations','Offer a clinical diagnosis of keloid scar based on the history and photograph provided'],
  ARRAY['Offer a routine referral to Dermatology for assessment and treatment, including intralesional corticosteroid injections, typically administered every 2–6 weeks until improvement is seen.','Counsel the patient on the side effects of intralesional steroid injections, which can include temporary changes to the treated skin area such as lightening or darkening of the skin (pigmentation changes), which may be more noticeable in darker skin tones; the appearance of small visible surface blood vessels (telangiectasias); and thinning of the skin or mild denting (subcutaneous atrophy), which often improves over time.','Inform the patient about steroid-impregnated tape options: Haelen tape (fludroxycortide tape) and Betesil medicated plaster (betamethasone valerate 2.25 mg), applied for 12 hours per day, which can help flatten keloid scars over time.','If the patient asks about surgical excision: advise her that removing the keloid surgically alone carries a high risk of recurrence, and the new scar that forms may be larger than the original. Surgery is generally not recommended as a standalone treatment for keloids.','Explain cryotherapy as another option: liquid nitrogen is used to freeze and gradually shrink the keloid. This can be effective, particularly for smaller or earlier lesions.','Advise the patient to avoid body piercings, tattoos, or unnecessary cosmetic procedures, especially in areas prone to keloid formation such as the chest, shoulders, and earlobes.','Advise the patient to inform any future surgeon about her history of keloid formation so that appropriate precautions — such as special wound dressings or prophylactic steroid injections — can be taken to minimise the risk of keloid formation after any future surgery.','Safety net: advise her to seek urgent medical attention if the lump changes rapidly, becomes painful, red, warm, or if any new symptoms develop.','Offer leaflets and written information about keloid scars.'],
  'Thank you for sending in that photograph — it really helped me to see what you''re dealing with, and I''m glad you''ve called in to discuss it. Based on what you''ve described and from what I can see in the image, I think I have a good understanding of what this lump most likely is, and I want to go through that with you now.

What you have appears to be something called a keloid scar. Amara, when the body heals after an injury — a cut, a wound, or surgery — it produces a protein called collagen to repair the damaged tissue. Most of the time this forms a flat or slightly raised scar that gradually fades. In some people, however, the body produces too much collagen during healing, and the scar continues to grow beyond the edges of the original wound and keeps enlarging over time. That is what a keloid is. The fact that your lump appeared a few months after a sutured wound, is rubbery and soft, is not painful, and has been gradually growing is very typical of a keloid scar. They are more common in people with darker skin tones, and if your mother has a history of raised lumpy scars, that also fits — keloid formation does tend to run in families.

The good news is that keloids are not dangerous. They do not become cancerous, and they are not a sign that something is seriously wrong inside your body. However, I completely understand that for you — particularly given your work as a photographer where your appearance and confidence matter — this is a real concern and something you want addressed.

I''d like to refer you to a dermatology specialist who can assess you in person and discuss treatment. The main treatment for keloids is intralesional steroid injections, where a small amount of corticosteroid is injected directly into the scar every two to six weeks until it flattens and softens. This is the most commonly used and effective approach. I do want to mention that because of your skin tone, the injections can occasionally cause temporary changes to the colour of the skin in that area — it may lighten or darken slightly. This is usually reversible over time, but it is something to be aware of. There is also a very small chance of the skin becoming slightly thinned or dented in the treated area, which tends to improve.

Another option the dermatologist may discuss is a special medicated tape — either Haelen tape or a product called Betesil — which contains a steroid that is slowly released into the scar when worn for about 12 hours a day. This can gradually help flatten the keloid over weeks to months.

You mentioned hoping for surgical removal. I want to be honest with you that surgery alone is generally not recommended for keloids because there is a high risk of the keloid growing back after the operation — and unfortunately the new scar that forms can sometimes be even larger than the original. The dermatologist may discuss combining surgery with other treatments in selected cases, but this would be their decision based on examining the lump directly.

Going forward, I''d also ask you to avoid body piercings, tattoos, or any unnecessary cosmetic procedures in the areas where keloids tend to form most easily — particularly the chest, shoulders, and earlobes. And if you ever need surgery in the future for any reason, please make sure the surgical team is aware of your keloid history so they can take appropriate precautions from the outset.

If the lump becomes painful, starts growing very rapidly, turns red or warm, or if any new symptoms develop, please do not wait for the dermatology appointment — contact us promptly.',
  ARRAY['Keloid scars grow beyond the original wound boundary and continue to enlarge over time; they do not regress spontaneously and are more common in people with darker skin tones and in those with a family history of keloid formation.','Hypertrophic scars, by contrast, remain within the wound boundary, are smaller, tend to appear sooner after injury, may improve over time, and are often associated with high wound tension — distinguishing between the two is a key clinical teaching point.','First-line treatment for keloids is intralesional corticosteroid injections given every 2–6 weeks; side effects including pigmentation changes and skin thinning should be discussed, particularly in patients with darker skin tones.','Surgical excision alone is contraindicated for keloids due to the high risk of recurrence and the risk that the resulting scar may be larger than the original; surgery may be combined with adjuvant therapy in specialist settings.','Steroid-impregnated tapes — Haelen tape (fludroxycortide) and Betesil (betamethasone valerate 2.25 mg) — applied for 12 hours per day are a non-invasive adjunct that can help flatten keloids.','Patients with known keloid tendency should be advised to avoid piercings, tattoos, and elective cosmetic procedures, and to inform any future surgical teams of their history so prophylactic measures can be taken.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  120,
  'Chronic Kidney Disease',
  'Endocrine & Nephrology',
  'Telephone consultation',
  false,
  'Peter Okafor',
  '63-year-old male',
  ARRAY['Hypertension','Type 2 Diabetes','High Cholesterol'],
  ARRAY['Metformin 1 g twice daily','Amlodipine 10 mg once daily','Ramipril 10 mg once daily','Atorvastatin 20 mg once daily','No Known Drug Allergy'],
  'Seen 3 months ago by Karen Adeyemi (Diabetic Nurse Practitioner, Access Role). Presenting complaint: Attended for routine diabetic review with no symptoms. Bloods showed eGFR 27 and HbA1c 60. Patient is compliant with his medications and remains asymptomatic. Examination: Blood pressure 130/70 mmHg, pulse 65 bpm, BMI 27. Foot examination normal. Plan: Repeat blood tests in 3 months to reassess eGFR and perform urine ACR.

Blood Test Results — Yesterday:
Test | Current Result | Result 3 Months Ago | Reference Range
eGFR | 26 mL/min/1.73m² | 27 mL/min/1.73m² | >60 mL/min/1.73m²
Urine ACR | 6.5 mg/mmol | <3 mg/mmol | <3 mg/mmol
HbA1c | 55 mmol/mol | 60 mmol/mol | <48 mmol/mol
Total Cholesterol | 5.0 mmol/L | — | <5 mmol/L
Sodium | 140 mmol/L | — | 135–145 mmol/L
Potassium | 4.5 mmol/L | — | 3.5–5.1 mmol/L
Creatinine | 120 µmol/L | — | 60–110 µmol/L',
  'Patient booked appointment to discuss blood test results.',
  'Hello doctor, I''d like to go through my blood test results if possible. I had some done yesterday and I''ve been a bit worried since.',
  'About three months ago, when I had my routine diabetes check, the nurse mentioned that my kidney function wasn''t quite right. She said it might be connected to the diabetes and that she wanted to repeat the tests to check. She also wanted to keep an eye on my blood sugar levels.',
  ARRAY['You feel well and have no symptoms at present. Say no to any symptoms asked.'],
  'He does not smoke and drinks very little alcohol — perhaps a small glass of wine on a Sunday. He lives with his wife in Coventry. He is a retired lorry driver. He follows a healthy diet and tries to exercise most days — he goes for a walk every morning and attends a gentle exercise class twice a week.',
  'He is not entirely sure what to expect from today''s results and does not have a strong prior idea about what the outcome will be.',
  'He is worried about kidney failure and whether he might eventually need dialysis. A close friend of his was diagnosed with kidney failure, spent years on dialysis, and passed away, which has made him particularly anxious about this possibility.',
  'He would like to understand what his blood test results mean, how serious his situation is, and what steps can be taken to slow down or prevent his kidney function from getting any worse.',
  ARRAY[]::text[],
  NULL,
  'Say no to any symptoms asked.',
  ARRAY['Ask about symptoms of chronic kidney disease, including nausea, vomiting, shortness of breath, itching, fatigue, muscle cramps, blood in the urine, reduced urine output, and other urinary symptoms.','Ask about symptoms suggestive of diabetes and its complications, including blurred vision, increased thirst or appetite, urinary frequency, chest pain, tingling or numbness particularly in the legs, and any non-healing wounds or ulcers, especially on the feet.','Ask about medication use, including over-the-counter medications such as NSAIDs, and supplements such as creatine, which can affect kidney function.','Ask about family history of kidney disease, for example polycystic kidney disease.','Ask about social history including smoking, alcohol intake, diet, exercise, occupation, and stress levels.','Ask about adherence to current medications, including antidiabetic, antihypertensive, and cholesterol-lowering treatments.','Make a diagnosis of chronic kidney disease, likely secondary to a combination of longstanding diabetes and hypertension.'],
  ARRAY['Stop metformin and offer alternative antidiabetic medications. Metformin should not be used when eGFR falls below 30 due to the risk of lactic acidosis.','Offer to start an SGLT2 inhibitor such as dapagliflozin 10 mg once daily and a DPP-4 inhibitor such as linagliptin 5 mg once daily as alternative antidiabetic agents appropriate for use in CKD.','Explain that both medications will not be started simultaneously. Dapagliflozin will be initiated first, and once it is well tolerated, linagliptin will be introduced after one to two weeks.','Counsel on side effects. Dapagliflozin increases the risk of urinary tract infections and, in rare cases, a serious infection called Fournier''s gangrene affecting the genital and perineal area. Linagliptin may occasionally cause a cough, though most patients tolerate it well.','Explain sick day rules for dapagliflozin: if he develops vomiting or diarrhoea, he should temporarily stop the medication and restart it 24 to 48 hours after he is able to eat and drink normally again.','Calculate his 5-year risk of requiring renal replacement therapy using the 4-variable Kidney Failure Risk Equation. If the risk is greater than 5%, refer to a nephrologist. If the risk is below 5%, continue monitoring in primary care.','Offer vaccinations appropriate for CKD: pneumococcal, annual influenza, and COVID-19 vaccines.','Advise lifestyle measures: avoid NSAIDs and nephrotoxic medications, maintain regular exercise, follow a healthy balanced diet, and aim for good blood pressure and glucose control.','Provide safety net advice for diabetic ketoacidosis (DKA): advise him to seek urgent medical attention if he develops symptoms such as feeling very unwell, excessive thirst, passing large amounts of urine, nausea or vomiting, abdominal pain, fast or deep breathing, confusion, or a fruity smell to the breath. He should contact the practice or call NHS 111 if out of hours.','Advise him to seek urgent medical attention for symptoms suggesting acute deterioration of kidney function: severe swelling of the legs or face, very little or no urine output, severe fatigue, confusion, nausea, shortness of breath, or chest pain.','Arrange follow-up in 3 months to reassess symptoms, blood results, and response to new treatment.'],
  'Thank you for calling in, and I can tell from the way you said it that you''ve been carrying some worry about these results. I want to take the time to go through everything with you carefully today, because there is quite a lot to cover and I want to make sure you leave this call feeling clear about what''s happening and what we''re going to do.

Your blood tests confirm something we were already keeping a close eye on — your kidneys are not working at full capacity. The main measure we use is called eGFR, which tells us what percentage of normal kidney function remains. Your eGFR has come back at 26, which is very similar to the reading of 27 three months ago — so although the number is low, it has remained stable, which is reassuring. We also checked a urine test this time around called the ACR, which looks for protein leaking into the urine — a sign that the kidneys are under strain. That result came back at 6.5, which is slightly above the normal threshold. Together, these results place you in a category we call chronic kidney disease, or CKD. We believe this is most likely due to the long-term effects of your diabetes and high blood pressure on the small blood vessels within the kidneys. Both conditions, if not tightly controlled over many years, can gradually damage those delicate vessels.

I know the word "kidney disease" is frightening, Peter, and I understand why especially given what your friend went through. I want to be honest with you: your kidneys are working at a reduced level, and that is something we need to take seriously. But I also want to reassure you that your levels have been stable, your blood pressure is well controlled, your cholesterol is borderline but manageable, and your blood sugar has actually improved since three months ago. These are all positive signs that what we''re doing is making a difference.

Now, there is one change I need to make to your medications today. The tablet you are currently taking for your diabetes — metformin — should not be used when kidney function falls below a certain level, because there is a risk that it could build up in the body and cause a serious condition. I will be stopping the metformin and replacing it with two newer medications that are actually better suited to your situation.

The first is called dapagliflozin, 10 milligrams once a day. This medication is particularly well suited to people with diabetes and kidney disease because it has been shown to not only help control blood sugar but also protect the kidneys from further decline. The second medication is called linagliptin, 5 milligrams once a day, which also helps control blood sugar and is very safe to use in kidney disease. We won''t start them both at the same time — I''ll start the dapagliflozin first, and once you''ve had a week or two to settle on it, we''ll add the linagliptin.

There are a couple of things I need to make you aware of with dapagliflozin. It can increase the risk of urine infections, so if you notice any burning when you pass water, please let us know promptly. There is also a very rare but serious risk of infection in the genital and perineal area — if you ever notice redness, swelling, or pain in that region, treat it as urgent and seek medical attention the same day. If you ever become unwell with vomiting or diarrhoea and cannot eat or drink normally, you should stop the dapagliflozin temporarily and restart it once you have recovered for 24 to 48 hours. I''d also advise you to avoid anti-inflammatory tablets like ibuprofen entirely from now on, as these can be harmful to kidneys that are already under stress.

I''d also like to arrange for you to receive your pneumococcal vaccination if you haven''t had it recently, and to make sure you''re up to date with your flu and COVID-19 jabs — your kidneys mean your immune system may not be quite as robust, so keeping those vaccines current is important.

You''re already doing a lot of the right things with your lifestyle and I want to acknowledge that. The daily walks and the exercise class are genuinely beneficial. Keep those up. If anything feels different before your next appointment in three months — particularly any swelling in your legs or face, a significant drop in how much urine you''re passing, confusion, or chest pain or breathlessness — please contact us straight away or call NHS 111.',
  ARRAY['Metformin must be stopped when eGFR falls below 30 mL/min/1.73m² due to the risk of lactic acidosis; alternative antidiabetic agents should be initiated promptly.','Dapagliflozin 10 mg once daily (SGLT2 inhibitor) is the preferred replacement in CKD with type 2 diabetes as it provides both glycaemic control and proven nephroprotective and cardioprotective benefits.','Linagliptin 5 mg once daily (DPP-4 inhibitor) is safe in CKD at any stage of renal impairment without dose adjustment and can be added after dapagliflozin is established; both should not be started simultaneously.','Sick day rules for dapagliflozin are essential patient education: the medication should be temporarily stopped during illness with vomiting or diarrhoea (dehydration risk) and restarted once the patient is eating and drinking normally for 24–48 hours.','The 4-variable Kidney Failure Risk Equation should be used to calculate 5-year risk of renal replacement therapy; a risk above 5% triggers referral to nephrology, while those below 5% can be managed and monitored in primary care.','NSAIDs should be avoided in all patients with CKD as they reduce renal perfusion and accelerate decline in kidney function; patients should be counselled on this explicitly.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  121,
  'Heart Failure',
  'Cardiology',
  'Video Consultation',
  false,
  'Janet Williams',
  '78-year-old female',
  ARRAY['Hypertension','High Cholesterol','Osteoarthritis','Amlodipine 10mg OD','Ramipril 5mg OD','Atorvastatin 20mg OD','Paracetamol PRN'],
  ARRAY[]::text[],
  'Seen 7 days ago by Dr Susan Hargreaves (Clinical Practitioner Access Role). History: Patient reports worsening shortness of breath with cough ongoing for 2 months. Cough is worse at night and breathlessness is worse when lying flat, requiring up to 3 pillows to sleep. She has also noticed bilateral ankle swelling. No chest pain and no other red flag symptoms. Examination: BP 139/80mmHg, Pulse 65bpm, bilateral pedal oedema noted, heart sounds S1 and S2 with no added sounds, chest clear, no crepitations, no raised jugular venous pressure. Impression: Suspected heart failure. Plan: Bloods and chest X-ray; review with results. In the meantime, trial furosemide 20mg OD. Blood tests done yesterday — results ready to file. Test | Current Result | Reference Range | Units. NT-proBNP | 1,800 | <400 | pg/mL. Sodium | — | 135–145 | mmol/L. Potassium | 4.2 | 3.5–5.1 | mmol/L. Creatinine | — | 60–110 | µmol/L. eGFR | >60 | — | mL/min/1.73 m². HbA1c | — | <48 | mmol/mol. Total Cholesterol | 4.8 | <5 | mmol/L. Ferritin and full blood count: Normal. Chest X-ray Report — Indication: Shortness of breath, orthopnoea, ankle swelling. Suspected heart failure. Findings: Cardiomegaly noted, cardiothoracic ratio >50%. Pulmonary vasculature appears unremarkable. No focal consolidation to suggest pneumonia. No pleural effusion seen. Bony structures unremarkable. Conclusion: Cardiomegaly present; no other findings. Please correlate clinically. Reported by: Mr Phil Bateman, Reporting Radiographer.',
  'Patient booked appointment to discuss blood test results and chest X-ray findings.',
  'Hello doctor, I was asked to book in to go over my blood test and X-ray results from last week. I''ve been a bit anxious about what they might show.',
  'The water tablets the doctor gave me did seem to take some of the swelling down in my feet, but I''m still getting quite short of breath.',
  ARRAY['The diuretic tablets helped reduce the ankle swelling, though breathlessness is ongoing.','No fever, chest pain, or palpitations.'],
  'Retired librarian. Lives alone in a flat in Leicester; family are nearby and visit regularly. She is widowed.',
  'The last doctor mentioned it might be coming from the heart, but she also wanted to check my lungs, which is why she sent me for the chest X-ray.',
  'She is worried that the breathlessness is stopping her from doing the things she enjoys, such as tending to her garden. She values her independence greatly and is frightened of losing it.',
  'She wants the doctor to explain what is going on and offer a solution.',
  ARRAY[]::text[],
  'If the doctor mentions heart failure, express surprise and ask whether you are going to die, and ask what caused it.',
  'Decline any other symptoms if asked.',
  ARRAY['Ask about the nature of the breathlessness — is it on exertion, at rest, or when lying flat','Ask about orthopnoea — how many pillows does she sleep on','Ask about paroxysmal nocturnal dyspnoea — does she wake suddenly gasping for air','Ask about associated symptoms: cough, chest pain, palpitations, ankle swelling, distended neck veins, fatigue','Ask about family history of heart disease','Ask about smoking and alcohol history','Ask about her home situation and how she is managing day to day','Ask whether the furosemide prescribed by the previous doctor made any difference to her symptoms','Confirm whether she is taking her regular medications as prescribed'],
  ARRAY['Increase furosemide from 20mg to 40mg OD as symptoms have not fully resolved, and recheck renal function in 1–2 weeks','Refer to cardiology for echocardiography and formal confirmation of diagnosis. As per NICE guidance: NT-proBNP above 2000 ng/L (236 pmol/L) — refer urgently for specialist assessment and echocardiography within 2 weeks; NT-proBNP between 400–2000 ng/L (47–236 pmol/L) — refer for specialist assessment and echocardiography within 6 weeks. This patient''s NT-proBNP of 1,800 pg/mL falls in the 6-week referral window.','Advise that the cardiologist may initiate additional medications depending on echocardiography findings (reduced ejection fraction or preserved ejection fraction)','Advise on dietary salt restriction — adult daily intake should not exceed 5 g of salt per day','Offer vaccinations: pneumococcal, influenza, and COVID-19','Arrange follow-up after cardiology review','Safety netting: advise to seek urgent help if severe breathlessness preventing speech, chest pain, sudden worsening of leg or facial swelling, or onset of confusion or dizziness'],
  'It is entirely understandable to feel anxious when you are waiting for results, and I want to take some time to go through everything with you today. Janet, your blood test showed a raised level of a protein called NT-proBNP. This is a chemical released by the heart when it is under strain. When the level is higher than normal, it tells us the heart is having to work harder than it should. Your chest X-ray has also shown that your heart is slightly enlarged, which can happen when the heart is not pumping as efficiently as it might be. Together, these results paint a consistent picture. What you are experiencing — the breathlessness when lying flat, the cough at night, and the ankle swelling — are classic signs of a condition called heart failure. I want to reassure you straight away: heart failure does not mean the heart is about to stop. It simply means the heart is not pumping blood around the body as effectively as usual, and as a result, fluid can build up in the lungs and legs. In your case, the most likely underlying reason is the long-standing high blood pressure. When blood pressure is elevated over many years, the heart has to pump against extra resistance. Over time this can cause the heart muscle to become stiffer or weaker, which eventually leads to the symptoms you have been experiencing. Now that we know what is happening, we can take proper steps to support your heart. Because the water tablets do not appear to have fully settled your symptoms yet, I would like to increase the furosemide from 20mg to 40mg once daily. I will also arrange a blood test in the next week or two to make sure your kidneys are coping well with the higher dose. The next important step is a referral to the cardiology team, who will arrange an ultrasound scan of your heart called an echocardiogram. This will show us exactly how the heart is functioning and help the cardiologist decide on any further medication that might be helpful. Based on your results, this referral should happen within six weeks. While you are waiting for that appointment, please try to keep your salt intake low — ideally no more than five grams a day, which is roughly one teaspoon. I would also like to make sure you are up to date with your vaccinations, including the flu, pneumococcal, and COVID jabs, as chest infections can put additional strain on the heart. If at any point you feel significantly more breathless — so much that you cannot complete a sentence — or you develop chest pain, sudden marked swelling, or feel confused or dizzy, please do not wait for your next appointment. Seek urgent medical help straight away.',
  ARRAY['NT-proBNP is a key marker in the diagnosis of heart failure: levels above 400 pg/mL are abnormal, and NICE guidance mandates echocardiography referral within 6 weeks for values between 400–2000 ng/L, or within 2 weeks if above 2000 ng/L','Cardiomegaly on chest X-ray combined with an elevated NT-proBNP in the context of orthopnoea, nocturnal cough, and bilateral ankle oedema is strongly suggestive of heart failure','If a patient remains symptomatic on furosemide 20mg OD, the dose should be uptitrated (e.g. to 40mg OD) and renal function checked within 1–2 weeks','Long-standing hypertension is a leading cause of heart failure; patients should be counselled on this link as part of shared understanding','Dietary salt restriction to less than 5 g per day and up-to-date vaccinations (influenza, pneumococcal, COVID-19) are important components of heart failure management in primary care','Safety netting in heart failure must cover acute decompensation symptoms: severe breathlessness, chest pain, rapid worsening oedema, confusion, or dizziness'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  122,
  'Breathlessness In A Young Adult',
  'Respiratory',
  'Video Consultation',
  false,
  'Laura Mitchell',
  '26-year-old female',
  ARRAY['Asthma'],
  ARRAY['Symbicort 100/6 — 1 puff twice daily; also 1 puff as required for relief of symptoms, increased if necessary up to 6 puffs as required, maximum 8 puffs per day','Microgynon','No known drug allergy'],
  'Seen 6 months ago by Priya Nair (Asthma Specialist Nurse). Patient attended for routine asthma review. Inhaler technique confirmed as satisfactory; uses a spacer device. No complaints and no recent flare-ups. Impression: Good asthma control. Plan: Continue ongoing management, update personalised asthma plan, safety netting advice given.',
  'Patient booked urgent appointment to discuss new respiratory symptoms.',
  'Hi doctor, I''ve been getting really breathless over the past few days and I''m not sure what''s going on. My inhaler doesn''t seem to be helping at all.',
  'I''ve also noticed some chest pain that gets worse when I breathe in, and my heart feels like it''s racing.',
  ARRAY['Chest pain is present and worsens on inspiration.','Palpitations — awareness of a fast heartbeat.','Inhaler use has not improved symptoms.'],
  'Works as a cabin crew member for Emirates, currently on a week''s leave. Occasional smoker — around 5 to 10 cigarettes per day for the past three years. Does not drink alcohol. Lives with her partner. Takes Microgynon as her contraceptive.',
  'She thinks it might be a chest infection or possibly her asthma playing up.',
  'She is due back at work in four days and is worried that if she does not improve she will need a sick note to apply for early leave.',
  'She was hoping the GP would prescribe a course of steroids to clear the symptoms up.',
  ARRAY['If the doctor asks about chest pain: pain is present and worsens when breathing in. Patient has also noticed her heart rate feels elevated.'],
  NULL,
  'Deny any other symptoms if asked directly.',
  ARRAY['Ask about the onset and duration of breathlessness — was it sudden or gradual','Ask whether breathlessness is constant or intermittent, and whether it is worse with movement or activity','Ask whether it is worse lying flat (orthopnoea)','Ask about associated symptoms: chest pain (pleuritic or positional), cough (productive or dry), haemoptysis, wheeze, fever, or recent flu-like illness','Ask about recent travel — particularly long-haul flights','Ask about contraception — specifically use of combined oral contraceptive pill (COCP)','Ask about smoking history','Ask whether the reliever inhaler has provided any relief','Ask about red flags: palpitations, dizziness, or syncope'],
  ARRAY['Arrange same-day referral to the acute medical unit given high clinical suspicion of pulmonary embolism (PE)','Inform her that initial investigations will include a D-dimer blood test to assess the likelihood of PE, along with a chest X-ray and an ECG. If the D-dimer is elevated, she will be offered a CT pulmonary angiogram (CTPA) to look more closely at the lungs','Inform her that if PE is confirmed, she should not fly for at least 4 weeks — offer a fit note if required','Advise her to stop taking the combined oral contraceptive pill (Microgynon) for now. In the meantime, condoms can be used as an alternative. Following hospital discharge, she should arrange a follow-up appointment to discuss longer-term contraception options','Offer smoking cessation advice','For future flights, advise preventive measures to reduce the risk of blood clots: wearing class 2 compression stockings, staying well hydrated, moving around the cabin regularly especially on long-haul journeys, and performing seated leg exercises to maintain circulation'],
  'It sounds like this has come on quite suddenly and I can understand why it''s worrying you, especially with work on the horizon. Laura, I want to be upfront with you about what I think may be happening, because I think it is important we act quickly. You have developed sudden breathlessness that has not improved with your inhaler, along with chest pain that is worse when you breathe in and a racing heart. On their own, each of these symptoms could have a straightforward explanation — but together, and in the context of your recent long-haul flight and taking the combined pill, they raise a real concern about something called a pulmonary embolism. A pulmonary embolism, or PE, happens when a blood clot travels to the lungs and blocks blood flow. This makes breathing painful and difficult, and can place extra strain on the heart, which may explain why your heart feels like it is racing. There are several things about your situation that increase the risk of developing a clot: flying long distances, taking the oestrogen-containing contraceptive pill, and smoking all contribute independently, and having all three together is a significant combination. This is a serious condition and I want to stress that it needs urgent assessment today. I am going to arrange for you to be seen at the acute medical unit at the hospital this afternoon. There, they will do blood tests, a chest X-ray, and a heart tracing, and if the initial results point towards a clot, they will do a specialised scan of your lungs called a CTPA. If a clot is found, you will be started on blood-thinning medication straight away. Regarding your contraceptive pill, I would advise you to stop taking it for now, as it increases clot risk. Condoms would be a safe option in the short term, and once you have been discharged and everything has settled, we can have a proper conversation about alternative long-term contraception. In terms of flying, if a PE is confirmed you will need to avoid flying for at least four weeks, and I can provide a fit note to cover your absence from work. I know that is not what you were hoping to hear, but your safety has to come first. Please make sure you go straight to the hospital — do not wait to see if things improve on their own.',
  ARRAY['In a patient with sudden breathlessness, pleuritic chest pain, palpitations, and recent long-haul travel on the COCP who smokes, pulmonary embolism (PE) must be the leading diagnosis and requires same-day hospital admission','In primary care, when clinical suspicion for PE is high (e.g. multiple risk factors clearly pointing to PE), same-day referral to the acute medical unit is appropriate without the need for face-to-face Wells Score calculation first','The combined oral contraceptive pill, long-haul air travel, and smoking are all independent risk factors for venous thromboembolism — the combination significantly elevates risk','Initial investigations for suspected PE include D-dimer, chest X-ray, and ECG; if D-dimer is elevated, a CTPA should be arranged urgently','If PE is confirmed, patients should be advised not to fly for at least 4 weeks; the COCP should be stopped and alternative contraception discussed','Smoking cessation and education on in-flight preventive measures (class 2 compression stockings, hydration, mobility) are important components of ongoing management'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  123,
  'Recurrent Reflux In A Child',
  'General Practice',
  'Telephone Consultation',
  false,
  'Ethan Brooks',
  '11-week-old male',
  ARRAY['Born via vaginal delivery','Up to date with immunisations','Gaviscon Infant — 2 sachets as required, mixed with feeds; maximum 12 sachets per day','No known drug allergies'],
  ARRAY[]::text[],
  'Seen 2 weeks ago by Dr Ranjit Bains (Clinical Practitioner Role). Patient seen with mother. Mother reports that the baby brings up milk after feeds, appears uncomfortable during feeding, and occasionally cries during feeds. He is wetting nappies normally and no weight loss has been reported. No rashes noted. No red flags identified. Examination: weight 5.7 kg (previous weight 5.5 kg), vitals stable, abdomen soft and non-tender, no masses, no rashes. Impression: Reflux. Plan: Gaviscon Infant — 2 sachets as required, mixed with feeds; maximum 12 sachets per day. Worsening advice given.',
  'Mother (Karen Brooks) has booked a telephone consultation to discuss ongoing concerns about her son.',
  'Hello, I''m calling about my son Ethan. He was seen a couple of weeks ago for reflux and was started on Gaviscon, but I''m still really worried — his symptoms don''t seem to have improved much at all.',
  'He''s still bringing up milk after almost every feed and seems really unsettled. I''m just wondering if there''s something else going on.',
  ARRAY[]::text[],
  'Ethan is Karen''s first child. She lives with Ethan and her husband. No family history of eczema or asthma.',
  'She is not sure what is causing the symptoms but is worried there might be something else going on beyond straightforward reflux.',
  'She is concerned another condition might be responsible for the symptoms and feels the current treatment is not working.',
  'She would like the GP to carry out further investigations to find out exactly what is happening, and is wondering whether Ethan needs a referral to a specialist.',
  ARRAY[]::text[],
  NULL,
  'Deny any additional symptoms if asked directly.',
  ARRAY['Ask about the onset of symptoms — at what age did the vomiting, regurgitation, crying after feeds, or reflux symptoms first begin','Ask whether symptoms are getting worse, staying the same, or improving','Ask whether there are any factors that seem to help or relieve symptoms','Ask about feeding — is Ethan breastfed, formula-fed, or mixed? How much does he take and how often? Does he appear uncomfortable during or after feeds','Ask whether there has been any weight loss or difficulty with weight gain','Ask about the nature of vomiting — is it projectile (shooting forcefully across a distance, which might suggest pyloric stenosis)','Ask whether the vomit has ever been green or bile-stained (which would raise concern about bowel obstruction)','Ask whether there has ever been any blood in the vomit (possible upper GI bleed)','Ask about other associated symptoms: choking episodes, difficulty breathing, back arching during or after feeds, persistent hiccups, or excessive crying','Ask about bowels — loose stools, constipation (a known side effect of Gaviscon and also seen in cow''s milk protein allergy), or blood in the nappy','Ask whether Ethan is wetting nappies normally — to assess hydration status','Ask whether he is still willing to feed or has been refusing feeds','Ask about any rash appearing after feeds, lip or tongue swelling, or any signs of allergic reaction including breathing difficulty (possible anaphylaxis)','Ask about family history of atopy including eczema and asthma','Ask about pregnancy, birth, immunisation, nutrition and developmental history (PBIND)','Ask what feeding modifications the mother has already tried — for example, smaller but more frequent feeds'],
  ARRAY['If there are any new symptoms or clinical concerns not identified at the previous assessment, consider offering a face-to-face examination. Otherwise, if there are no red flags and the picture is consistent with the earlier consultation, a telephone review is appropriate','Offer a 1–2 week trial of smaller, more frequent feeds while maintaining an appropriate total daily feed volume','Offer a 1–2 week trial of thickened formula — either a pre-thickened formula or a feed thickener such as Instant Carobel added to the existing formula. Important: pre-thickened formula and feed thickeners should not be used alongside Gaviscon Infant, as combining them can make the feed excessively thick, increasing the risk of difficulty swallowing or choking. Additionally, both Gaviscon and thickeners independently increase the risk of constipation, and using them together worsens this risk.','If switching to a thickened formula or adding a thickener, discontinue Gaviscon Infant','Gaviscon Infant may be continued alongside a trial of smaller but more frequent feeds','If the mother has already tried smaller and more frequent feeds without success, or does not wish to try this, consider stopping Gaviscon Infant and starting a 4-week trial of omeprazole','Discuss the possibility of cow''s milk protein allergy (CMPA) with the mother, but explain that Ethan''s current symptoms are not fully consistent with this diagnosis at present — no persistent diarrhoea, no blood or mucus in stools, and no significant distress after feeds suggesting allergy','Advise keeping Ethan upright for at least 20–30 minutes after each feed','Review in 1–2 weeks','Safety netting: advise to seek urgent medical attention if any of the following occur — projectile vomiting (possible pyloric stenosis), blood in vomit or stool, signs of dehydration such as fewer wet nappies or a sunken fontanelle, refusal of feeds, or weight loss'],
  'Thank you so much for calling, and please know that it is completely natural to be worried when your baby is unsettled and not seeming to respond to treatment. Ethan is still very young, and reflux is extremely common in babies this age — it happens because the muscle at the top of the stomach is still developing and milk can easily come back up. The good news is that when we last examined him two weeks ago, he had actually gained weight, his tummy felt normal, and there were no worrying signs. That is genuinely reassuring. Karen, because the Gaviscon does not appear to have settled his symptoms, I would like to suggest we try a slightly different approach. Rather than adding to what he is already on, there are two things we could try. The first is to offer Ethan smaller feeds a little more often throughout the day. Keeping the total amount of milk the same but spreading it out can make it easier for the stomach to cope without pushing things back up. We could also try switching to a thickened formula, which is simply a milk that is slightly thicker in consistency and tends to stay down more easily. If we do try a thickener, it is important to stop the Gaviscon at the same time, because using both together can make the milk too thick, which could make it harder for Ethan to swallow comfortably. If we have already tried those approaches without success, another option would be to stop the Gaviscon and try a short four-week course of omeprazole instead, which is a medication that reduces the amount of acid in the stomach and can ease irritation. I also want to mention something called cow''s milk protein allergy, which can sometimes cause symptoms that look very similar to reflux. At the moment, Ethan''s symptoms do not strongly suggest this — he does not have blood in his nappies or persistent loose stools — but if things do not improve with the changes we are making, we would want to revisit that possibility. After each feed, try to keep him upright for around 20 to 30 minutes if you can, as this can help prevent milk coming back up. I would like to speak with you again in a week or two to see how he is getting on. In the meantime, please do not hesitate to seek urgent help if you notice Ethan vomiting with great force across the room, any blood in his sick or nappy, signs that he is becoming dehydrated such as fewer wet nappies or a soft spot on his head appearing sunken, or if he starts refusing feeds or losing weight. Those would need to be seen the same day.',
  ARRAY['Gaviscon Infant is a first-line treatment for infant reflux, but if symptoms persist, the next steps include trying smaller and more frequent feeds and/or switching to a thickened formula','Gaviscon Infant must not be used alongside feed thickeners such as Carobel or pre-thickened formulas, as combining them increases choking risk and significantly worsens constipation','If conservative feeding measures fail, a 4-week trial of omeprazole is an appropriate next step','Red flag features in infant vomiting that require urgent assessment include projectile vomiting (pyloric stenosis), bile-stained or bloody vomit, signs of dehydration, weight loss, and refusal of feeds','Cow''s milk protein allergy (CMPA) should be considered in infants with reflux-like symptoms, particularly if there is also blood or mucus in stools, persistent diarrhoea, or a family history of atopy','Keeping an infant upright for at least 20–30 minutes after feeds is a simple non-pharmacological measure that can reduce regurgitation'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  124,
  'Uncontrolled Asthma',
  'Respiratory',
  'Telephone Consultation',
  false,
  'Ryan Foster',
  '22-year-old male',
  ARRAY['Asthma','Salbutamol PRN','Clenil Modulite (200mcg) 2 puffs BD','No known drug allergies'],
  ARRAY[]::text[],
  NULL,
  'Patient booked a routine telephone consultation to discuss concerns about his asthma.',
  'Hi doctor, I''ve been struggling quite a bit with my asthma over the past month or so. I feel like it''s not under control any more and I''m having to use my blue inhaler a lot more than I used to.',
  'I''ve been waking up at night coughing three or four times a week, my chest feels tight quite often during the day, and I get a wheeze when I breathe sometimes. I don''t have chest pain, palpitations, or dizziness.',
  ARRAY[]::text[],
  'Does not smoke, drink alcohol, or use recreational drugs. Studies Civil Engineering at university and lives in student halls.',
  'He believes his asthma is not well controlled at the moment.',
  'He would like to join the university rugby team but is concerned that if his asthma remains uncontrolled, he will not be able to participate.',
  'He is expecting the GP to advise him on what to do and provide a treatment plan.',
  ARRAY['If the doctor asks about triggers or home environment: recently moved into university halls and his flatmate smokes indoors. He tries to avoid the smoke but it lingers throughout the flat.'],
  NULL,
  'Deny any other symptoms if asked directly.',
  ARRAY['Ask about shortness of breath — is it present at rest, on exertion, or both','Ask whether symptoms are getting better, worse, or staying the same','Ask about wheeze','Ask about cough — if present, is it productive? What colour is any phlegm? Any blood','Ask about night-time symptoms — how many nights per week is he waking due to asthma','Ask about frequency of SABA (salbutamol) use — how many times per week, including daytime use. If using reliever more than 3 times per week, step up treatment','Ask about red flags: chest pain, palpitations, fever, or recent viral illness','Ask about triggers: exercise, pets, mould, carpets, stress, cold air, emotional upset','Ask about over-the-counter medications such as ibuprofen or aspirin that can worsen asthma','Ask about personal or family history of atopy including eczema','Ask about smoking and whether anyone else in the home smokes','Ask about occupation or study environment as a potential trigger','Ask about any previous hospital or ITU admissions for asthma — ITU admission indicates high-risk asthma and a lower threshold for admission in future exacerbations','Ask whether he is taking his inhalers as prescribed and whether his inhaler technique has ever been formally checked','Ask about peak flow — what is his usual reading and what is his current reading'],
  ARRAY['Invite the patient for a face-to-face review to examine the chest, check weight and height, and record BP and pulse','Step up treatment in line with current asthma guidelines by switching to a MART (Maintenance and Reliever Therapy) inhaler such as Symbicort or Fostair — one inhaler that provides both preventer (inhaled corticosteroid) and reliever (long-acting beta-agonist) functions','Advise that second-hand smoke from his flatmate is a likely trigger — encourage him to speak with his flatmate directly or raise the issue with university accommodation services to request a smoke-free environment','Refer to the asthma nurse for a full asthma review','The asthma nurse review should include discussion of a personalised asthma plan covering: current medications, normal peak flow readings, known triggers, how to recognise a flare-up, and what steps to take during one','Offer vaccinations: influenza and COVID-19','Safety netting: advise to seek urgent help if symptoms worsen acutely or if he develops a severe exacerbation','Follow up in 4 weeks'],
  'It sounds like things have become quite difficult over the last few weeks, and I''m glad you called about this. Ryan, from what you have described, your asthma is not well controlled at the moment. Using your blue inhaler several times a day, waking up at night with coughing three or four times a week, and regularly experiencing chest tightness are all signs that the preventer inhaler you are currently on — Clenil — may not be providing enough protection. One factor that stands out is your living situation. Second-hand smoke is one of the most significant triggers for asthma, and if smoke from your flatmate is lingering in the shared space, it could be having a real impact on your symptoms even if you are not actively smoking yourself. It would be worth having a conversation with your flatmate about this, or speaking to your accommodation team about whether a room change or a smoke-free policy could be arranged. In terms of your treatment, I think it is time to step things up. Rather than continuing with the separate preventer and reliever inhalers, I would like to switch you to what is called a MART inhaler — that stands for Maintenance and Reliever Therapy. It is a single inhaler that contains both a steroid to reduce inflammation in the airways and a long-acting reliever to keep the airways open. Importantly, you can also use it as your quick reliever if symptoms come on, rather than reaching for the blue inhaler. Examples include Symbicort and Fostair. I would also like to bring you in face-to-face for a proper check — to listen to your chest, check your weight and height, and look at your peak flow readings. After that visit, I would like to refer you to our asthma nurse, who will do a thorough asthma review and help you put together a personalised asthma plan. That plan will outline your medications, your normal peak flow, your triggers, and exactly what to do if you feel a flare coming on. Please do also make sure you are up to date with your flu and COVID jabs. I would like to see you back in around four weeks to check how you are getting on with the new inhaler. If at any point before then your breathing becomes significantly worse, you are not responding to your inhaler, or you feel like you are having an acute attack, please seek urgent help the same day.',
  ARRAY['Asthma is considered uncontrolled if the patient is using their SABA reliever more than 3 times per week, waking at night with symptoms, or experiencing daytime limitations — step-up treatment is indicated','Current asthma guidelines recommend stepping up to a MART (Maintenance and Reliever Therapy) inhaler such as Symbicort or Fostair when asthma is poorly controlled on a preventer alone','Second-hand smoke is a well-recognised asthma trigger and should always be explored as part of the social and environmental history','A personalised asthma plan should be discussed at every asthma review — it should cover medications, normal peak flow, known triggers, how to recognise a flare, and action steps during an exacerbation','A history of ITU admission for asthma is an important risk stratifier — such patients have a lower threshold for hospital admission during exacerbations','Annual influenza vaccination is recommended for all patients with asthma'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  125,
  'Eating Disorder',
  'Mental Health',
  'Telephone Consultation',
  false,
  'Zoe Harper',
  '17-year-old female',
  ARRAY['Nil','No known drug allergies'],
  ARRAY[]::text[],
  'The patient''s mother scheduled a telephone consultation following advice from the pharmacist to discuss concerns about her daughter''s health.',
  'Patient''s mother booked appointment at the pharmacist''s recommendation following a low BMI reading.',
  'Hi, I''m only here because my mum and my teachers kept pushing me to come. Honestly, I don''t really think there''s anything wrong with me.',
  'I think it''s just exam pressure making me tired. I feel like everyone is overreacting.',
  ARRAY['If asked about weight or appetite: mother has noticed weight loss and reduced eating. Zoe has been restricting her food intake out of fear of gaining weight. She has been making herself sick after eating.','If asked how she came to see the pharmacist: she visited the pharmacy for antibiotics for a chest infection and her BMI was measured at 16.5. The pharmacist advised her to see a GP.'],
  'Does not smoke or drink alcohol. Currently in Year 12 at school and describes school as going well. Lives at home with her parents and two older brothers. Not in a romantic relationship and not sexually active.',
  'She thinks her missed periods are probably just down to exam stress and believes her parents and teachers are overreacting. She is not sure why the pharmacist was concerned about her BMI.',
  'She is worried that if she gains weight she will lose control of how she looks. She does not really want to be here and does not think there is anything wrong.',
  'She does not feel she needs treatment but wants to get the appointment over with. She hopes the doctor will not try to force her to gain weight.',
  ARRAY[]::text[],
  NULL,
  'Deny any symptoms beyond what is prompted. Only disclose weight restriction and purging behaviour if directly asked.',
  ARRAY['Ask the patient why she thinks her mother, teacher, and the pharmacist are concerned about her','Ask about menstrual periods — when was her last period, were they previously regular, has she missed periods before, any contraception use, any possibility of pregnancy','Ask about weight changes — any weight loss, how much, over what period, and whether it was intentional or unintentional','Ask whether she has a fear of gaining weight and how she perceives her own body — does she see herself as overweight even when others say she is slim','Ask about eating habits — what a typical day of eating looks like, any foods avoided, whether meals have become smaller or skipped, whether there is anxiety around eating','Ask about compensatory behaviours — self-induced vomiting, laxative use, excessive exercise, or other means of weight control','Ask about energy levels — fatigue, dizziness, weakness, or difficulty concentrating at school','Ask about mood — feeling low, anxious, irritable, or withdrawn, and whether friends or teachers have commented on any change','Ask about red flag symptoms — fainting, palpitations, chest pain, cold intolerance, thinning hair, or dry skin','Ask about family history of eating disorders, depression, anxiety, or menstrual problems','Ask about lifestyle stressors — exam pressure, social dynamics, bullying, or any significant recent life changes','Ask about personal questions — whether she is in a romantic relationship and whether she is sexually active','Ask about medical history — any known anaemia, thyroid problems, or digestive conditions, and any medications or supplements','Ask about smoking, alcohol, or substance use','Ask about any previous hospital admissions or emergency attendances relating to low weight, eating habits, or fainting','Ask about the BMI reading — whether she recalls previous weights and whether she has ever been told she was underweight before'],
  ARRAY['Offer an urgent face-to-face appointment to assess vital signs, weight, height, BMI, blood pressure, and pulse. Perform an ECG to evaluate cardiac function. Assess for clinical signs of malnutrition: bradycardia, cold peripheries, hair thinning, and muscle weakness.','Arrange urgent blood tests: FBC, U&E, LFTs, and TFTs to assess nutritional status and thyroid function. Include FSH, LH, oestradiol, and prolactin to evaluate hormonal function. Add iron studies, B12, and folate to screen for nutritional deficiencies.','Refer to a specialist eating disorder clinic. The multidisciplinary team will conduct a comprehensive assessment. A dietitian will create a structured meal plan to support safe and gradual weight restoration. A psychologist will offer cognitive behavioural therapy for eating disorders (CBT-E), targeting unhelpful thoughts and behaviours related to food, weight, and body image.','Explain that if examination or blood test findings reveal concerning abnormalities, hospital admission may be necessary to ensure her safety and support physical recovery. This should be communicated sensitively and without pressure.','Acknowledge that the conversation may feel overwhelming. Reassure her that she is not being judged, that she is not alone, and that the goal is to help her feel stronger and healthier.','Encourage family involvement with Zoe''s consent, as family support is important in recovery from eating disorders. Provide information about relevant support organisations and resources.','Safety netting: advise that if she experiences fainting, dizziness, palpitations, or feels very weak, she or her family should seek urgent medical attention immediately.','Arrange weekly or fortnightly follow-ups to monitor progress, review the care plan, and ensure she is receiving appropriate support from all involved services.'],
  'Thank you for coming along today — I know this might not have been your choice, and I really appreciate you giving me a few minutes to chat. This is a completely safe space, and nothing you tell me will be used against you. I just want to understand how you have been feeling and make sure you are okay. Zoe, I want to be honest with you about what I am noticing, and I also want to reassure you that what I am going to say comes from a place of care, not judgement. When the pharmacist measured your BMI, they found it was 16.5. For your age and height, that is lower than the healthy range. Our bodies need a certain amount of energy just to keep all our systems running — including our hormones. When energy intake is too low for too long, the body starts to shut down things it considers non-essential. That is almost certainly why your periods have stopped. It is also very likely why you have been feeling more tired than usual. I also want to gently mention something else. The things you have shared with me — being careful about what you eat, feeling worried about weight, and using some strategies to manage that — are patterns that can sometimes point towards an eating disorder. I know that might sound like a big label, and I am not saying this to alarm you, but because recognising it is the first step to feeling better. The next thing I would like to do is arrange for you to come in face-to-face so we can check your weight, do some blood tests, and carry out a heart tracing called an ECG. This is just a safety check, because when the body has been under this kind of strain for a while, it is important to make sure the heart is coping well. I would also like to refer you to a specialist team who work specifically with young people going through what you are experiencing. This team includes doctors, psychologists, and dietitians, and their job is to support you — not to force anything on you. Recovery from an eating disorder is absolutely possible, and many young people go on to feel much better with the right help. If at any point you feel faint, notice your heart racing or feel very weak, please seek urgent help that same day.',
  ARRAY['A BMI of 16.5 in a teenager warrants urgent assessment — red flags for medical compromise include bradycardia, hypotension, cold peripheries, muscle weakness, and hair thinning','Amenorrhoea in the context of low BMI and disordered eating is a sign of hypothalamic suppression due to energy deficit and should not be attributed solely to stress without proper evaluation','Cognitive behavioural therapy for eating disorders (CBT-E) is the recommended psychological intervention for anorexia nervosa and bulimia nervosa in young people','Urgent investigations in suspected eating disorders include FBC, U&E, LFTs, TFTs, FSH, LH, oestradiol, prolactin, iron studies, B12, folate, and ECG','Hospital admission should be considered if there are significant electrolyte abnormalities, cardiac compromise, or rapid weight loss — communicate this possibility sensitively','Family-based approaches and involvement of a multidisciplinary eating disorder team (doctor, dietitian, psychologist) are central to managing eating disorders in adolescents'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  126,
  'Post ICU Syndrome',
  'General Practice',
  'Video Consultation',
  false,
  'Graham Harrison',
  '67-year-old male',
  ARRAY['COPD','Osteoarthritis','Benign prostatic hyperplasia','Trelegy Ellipta 92/55/22 inhaler — one puff (inhalation) daily','Salamol inhaler PRN','Paracetamol 500mg QDS PRN','Tamsulosin 400mcg OD'],
  ARRAY[]::text[],
  'Hospital letter received. Dear GP, I am writing to inform you that your patient, Mr Graham Harrison (67 years old), has been discharged following a prolonged hospital admission for pneumonia complicated by sepsis. He was admitted via the Emergency Department and deteriorated despite initial treatment, requiring ICU admission for three weeks with mechanical ventilation and vasopressor support. He was subsequently stepped down to the respiratory ward for four weeks, where he made a steady recovery with physiotherapy and pulmonary rehabilitation. His past medical history includes COPD, osteoarthritis, and benign prostatic hyperplasia. He is now clinically stable, with oxygen saturations of 95% on room air and no significant breathlessness at rest. His discharge medications remain unchanged. I would appreciate your ongoing monitoring of his COPD and general recovery, continued compliance with inhaler therapy, and assessment for any further exacerbations. He has been referred for respiratory outpatient review in six weeks. Please do not hesitate to contact me if further information is required. Yours sincerely, Dr Rachel Fairweather, MRCP, PhD, Consultant Respiratory Physician.',
  'Patient has booked a routine consultation to discuss concerns following his recent hospital discharge.',
  'Hello doctor, I know this might sound a bit odd, but I''ve come to ask about getting something to help me sleep. I just can''t seem to get proper rest since I got home from the hospital.',
  'At night I keep hearing the beeping of the machines, even though I''m in my own bedroom. When I do manage to drop off, I have nightmares about being in the hospital — the tubes and everything. And sometimes I can smell the antiseptic. It''s been like this for the past four weeks since I was discharged.',
  ARRAY['Not entirely sure why he feels this way, but he finds himself going over and over his time in hospital.','Has lost interest in things he used to enjoy.','Feels more fatigued than he would expect at this stage of recovery.','Was in ICU for 3 weeks then on the step-down ward for 4 weeks — 7 weeks in hospital in total. The experience was very distressing with many lines and tubes.','Has been discharged 4 weeks ago but has not felt quite right since.','Has tried sleep hygiene measures without benefit. Is only getting around 1 hour of sleep a night and feels he needs medication to help.'],
  'Ex-smoker; does not drink alcohol. Lives with his wife in Bristol. His wife is concerned — she says he seems detached and not like his usual self.',
  'He does not understand why he still feels as though he is back in the hospital even though he has been home for a month.',
  'He is worried that his mood is deteriorating and that he is not getting nearly enough sleep.',
  'He is hoping the GP will prescribe sleeping tablets to help him get some rest.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY['Ask about sleep disturbances — difficulty falling asleep or staying asleep, frequent waking, nightmares, or intrusive thoughts about the hospital experience','Ask about mood — how low does he feel, has he been tearful, withdrawn, or lacking motivation; does he feel hopeless or guilty; has he lost interest in things he normally enjoys','Ask about flashbacks and sensory re-experiencing — hearing hospital beeping sounds, smelling antiseptic, and whether these remind him of distressing moments in ICU','Ask about the hospital stay itself — what he recalls of his time in ICU and how he felt during that period','Ask about hypervigilance and avoidance — does he feel constantly on edge, does he avoid anything that reminds him of hospital, does he feel detached from those around him','Ask about appetite — any weight loss, reduced appetite, or change in eating habits','Ask about energy levels — fatigue, lack of motivation, daytime drowsiness, any change in ability to carry out everyday activities','Ask about smoking, alcohol, or substance use','Ask about family history of mental health problems','Ask about red flags — any thoughts of suicide or self-harm, or thoughts of giving up','Ask about social support — who lives with him, is he feeling isolated, how his symptoms have affected his relationship and daily life','Ask whether he is experiencing any respiratory symptoms and whether he is taking his inhalers as prescribed'],
  ARRAY['Acknowledge his symptoms and validate his experience — explain that post-ICU symptoms such as these are a recognised consequence of the severe stress of a prolonged critical illness and are not a sign of weakness','Explain that what he is describing is consistent with post-ICU syndrome, which can include low mood, sleep disturbance, and intrusive memories of the hospital stay. Some patients also develop symptoms similar to PTSD following ICU admission.','Offer sleep hygiene advice: reduce screen time before bed, avoid caffeine in the afternoon and evening, establish a calming bedtime routine, and consider relaxation or breathing techniques','Offer a short course of zopiclone (3–7 days), a non-benzodiazepine hypnotic, to provide some short-term sleep relief. Explain that it carries a risk of dependence and should be used cautiously. Advise alternate-day dosing rather than daily use to reduce this risk.','Emphasise that for sustained improvement in sleep, good sleep hygiene practices are essential and that CBT for insomnia (CBT-I) has strong evidence and is highly effective','Refer to the community mental health team to confirm the diagnosis and initiate specialist management, which may include trauma-focused CBT or Eye Movement Desensitisation and Reprocessing (EMDR)','If he is open to medication for mood: offer Sertraline (SSRI) and explain that symptoms may temporarily worsen in the first week, with full therapeutic benefit typically seen after around four weeks','Signpost to ICUsteps — the intensive care patient support charity — which provides peer support and resources for ICU survivors and their families','Safety netting: advise that if he feels suicidal, severely distressed, or unable to cope, he should seek urgent medical help immediately'],
  'I want to start by saying how much you have been through — seven weeks in hospital, three of them in intensive care on a ventilator, is an enormous ordeal, and it would affect anyone. You have been home for four weeks now, but it sounds like your mind is still very much back in that ward. Graham, what you are describing — the beeping sounds at night, the smell of antiseptic, the nightmares, feeling detached, losing interest in things, and struggling to sleep — are all recognised symptoms that some people experience after a stay in intensive care. This is known as post-ICU syndrome, and it happens because the body and brain go through an extreme amount of stress during critical illness. For some people, it can also develop into something very similar to post-traumatic stress disorder, because being in ICU — surrounded by equipment, unable to move, not always sure what is happening — can be a genuinely traumatic experience, even if you were not always fully conscious at the time. I want to be clear that this is not weakness and it is not unusual. Your body has been recovering physically, but your mind is still processing what happened, and that takes time and the right support. I am absolutely willing to help with sleep. I would like to prescribe a short course of zopiclone — this is a sleeping tablet that is not in the same family as older sedatives and is generally safer for short-term use. However, it can cause dependence if taken every night, so I would suggest using it on alternate nights rather than every night, and only for a week or so while we get some other support in place. For the longer term, the most effective treatment for sleep problems is a talking therapy called CBT for insomnia, which helps to retrain the way the mind approaches sleep — and it works better than tablets in the long run. I am also going to refer you to the mental health team, who can formally assess what is happening and offer treatments such as trauma-focused CBT or a therapy called EMDR, which stands for Eye Movement Desensitisation and Reprocessing — both of these have good evidence for the kind of symptoms you are describing. There is also an organisation called ICUsteps, which is a charity specifically for people who have been through intensive care. Many people find it helpful to connect with others who truly understand what the experience is like. If at any point you feel unable to cope, have any thoughts of harming yourself, or feel that things are rapidly getting worse, please do not wait for a follow-up — seek urgent help straight away.',
  ARRAY['Post-ICU syndrome is a recognised constellation of physical, cognitive, and psychological problems following ICU admission — including symptoms consistent with PTSD, depression, and sleep disturbance','Flashbacks, hypervigilance, avoidance behaviours, emotional detachment, and intrusive sensory memories (such as hearing monitors or smelling antiseptic) in an ICU survivor are red flags for PTSD and should prompt specialist mental health referral','Zopiclone (a non-benzodiazepine hypnotic) can be offered as a short-term sleep aid (3–7 days) with alternate-day dosing to reduce dependence risk; benzodiazepines should be avoided as they can worsen nightmares','Trauma-focused CBT and EMDR are evidence-based treatments for PTSD and are the preferred specialist interventions following ICU-related trauma','Sertraline (SSRI) can be offered for mood symptoms, with the caveat that symptoms may temporarily worsen in the first week and full benefit is seen around four weeks after starting','ICUsteps is the key patient-facing charity supporting ICU survivors and their families in the UK — signposting to this resource is good practice'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  127,
  'Microcytic Anaemia In A Patient On Dual Antiplatelet Therapy',
  'Gastroenterology & Haematology',
  'Telephone consultation',
  false,
  'George Hartley',
  '71-year-old male',
  ARRAY['Hypertension','Type 2 Diabetes Mellitus','High Cholesterol','Recent Myocardial Infarction (MI) – 2 months ago','Amlodipine 5 mg OD','Ramipril 10mg OD','Bisoprolol 2.5mg OD','Aspirin 75mg OD','Clopidogrel 75mg OD','Atorvastatin 80mg OD','Lansoprazole 30mg OD'],
  ARRAY[]::text[],
  'Letter from Cardiology - 2 months ago. Dear GP, Re: Mr. George Hartley, 71-year-old male. I am writing to inform you that Mr. George Hartley was admitted with an acute non-ST elevation myocardial infarction (NSTEMI). Coronary angiography revealed a significant stenosis of the proximal left anterior descending (LAD) artery, for which he underwent percutaneous coronary intervention (PCI) with drug-eluting stent (DES) placement, achieving successful revascularization. He has been discharged on optimal secondary prevention therapy, including: Bisoprolol 2.5mg OD, Aspirin 75mg OD, Clopidogrel 75mg OD, Atorvastatin 80mg OD, Lansoprazole 30mg OD. He has been referred for Cardiac Rehabilitation and will be followed up in the cardiology outpatient clinic. Please continue to monitor his cardiovascular risk factors, medication adherence, and any potential side effects. Best regards, Dr. R. Chandrasekaran, MBChB, MRCP (UK), FACC (US), Consultant Interventional Cardiologist. Seen by Tracey Hollingsworth (Health Care Assistant) - 3 days ago. Patient attended for routine influenza and COVID vaccination. He reports feeling generally well but mentioned occasional tiredness and heartburn. This was discussed with the duty GP, who advised proceeding with the vaccinations. Routine blood tests were arranged and a GP appointment was booked in two days'' time. The patient agreed with the plan and tolerated both vaccinations well. Blood Test Results: Haemoglobin (Hb) 109g/L (ref 130–180 g/L); Mean Corpuscular Volume (MCV) 74 fL (ref 80–100 fL); Mean Corpuscular Haemoglobin (MCH) 24 pg (ref 27–32 pg); Red Blood Cell Count (RBC) 5.8 x10⁶/µL (ref 4.7–6.1 x10⁶/µL); Haematocrit (HCT) 34% (ref 38–50%); White Blood Cell Count (WBC) 6.5 x10⁹/L (ref 4.0–11.0 x10⁹/L); Platelets 250 x10⁹/L (ref 150–450 x10⁹/L); Urea & Electrolytes, Bone profile, eGFR – Normal; CRP – Normal; Thyroid Function Tests – Normal.',
  'Patient has booked a telephone consultation to discuss his blood test results and current symptoms.',
  'Hello doctor, I''ve been asked to ring in about some blood test results I had done recently.',
  'You had your blood tests done after mentioning to the healthcare assistant at the surgery that you''d been feeling tired and having heartburn for the past four weeks. The healthcare assistant arranged the tests and asked you to book an appointment to discuss the results.',
  ARRAY['The discomfort sits in your upper abdomen and tends to be worse in the evenings and at night. You''ve been taking Gaviscon, which helps a little. It sometimes comes on after meals, but your appetite is fine and you are eating normally.','You haven''t had any weight loss, night sweats, dark or tarry stools, or vomiting.','You feel quite worn out during the day, but you assumed it was just part of recovering from the heart attack, as the cardiac rehabilitation team mentioned fatigue is common.','You have had no chest pain, no breathlessness, and no palpitations. Decline to answer anything outside these details.'],
  'You eat a well-balanced diet with plenty of fruit and vegetables, and you do not smoke or drink alcohol. You live with your wife and are a retired head teacher.',
  'You suspect the blood thinning tablets — aspirin and clopidogrel — might be behind your symptoms, as you came across this when reading about them online.',
  'You are puzzled about why you need to take two blood thinners at once, and your wife has been asking you to raise this with the GP.',
  'You would like to understand what is causing your symptoms and what the doctor can do about them.',
  ARRAY[]::text[],
  NULL,
  'Say no to any symptoms or details not already provided in the scenario. Accept any management offered by the doctor.',
  ARRAY['Acknowledge that you have reviewed his notes and blood results, and invite him to describe in his own words what prompted the blood tests.','Ask about the heartburn or upper abdominal discomfort — including onset, location, duration, severity, radiation, relationship to food or lying down, and whether antacids provide relief.','Ask about the tiredness — how long it has been present, whether it is getting worse, how it is affecting his daily activities, and whether it is worse at any particular time of day.','Ask about red flag symptoms: unintentional weight loss, night sweats, early satiety, loss of appetite, dark or tarry stools, fresh rectal bleeding, vomiting, haematemesis, and dysphagia.','Ask if he has noticed any bleeding from any site.','Given his recent myocardial infarction, ask about chest pain, breathlessness, palpitations, dizziness, presyncope, reduced exercise tolerance, leg swelling, excessive sweating, nausea, or worsening fatigue, to help identify cardiac complications or symptoms of anaemia.','Ask about his diet, particularly whether he consumes iron-rich foods.','Ask about adherence to his current medications, specifically aspirin, clopidogrel, and lansoprazole.','Ask about any previous gastrointestinal history, including peptic ulcers, gastritis, reflux disease, or gastrointestinal bleeding.','Ask about social history including smoking, alcohol consumption, occupation, stress levels, and caffeine intake.','Ask how his symptoms are affecting his quality of life and day-to-day activities.','Explore his ideas, concerns, and expectations.','Arrive at a working diagnosis of microcytic anaemia, likely secondary to chronic low-grade gastrointestinal blood loss in the context of dual antiplatelet therapy with aspirin and clopidogrel.'],
  ARRAY['Offer a face-to-face appointment to examine the abdomen and check observations.','Arrange further investigations including a ferritin level to confirm iron deficiency and a coeliac screen.','Offer a faecal immunochemical test (FIT) and perform urinalysis to check for haematuria.','Explain that if the ferritin result confirms iron deficiency, iron replacement therapy will be initiated, and he will be referred to gastroenterology for upper gastrointestinal endoscopy — and possibly colonoscopy if the FIT test is positive — under the two-week wait pathway.','Increase lansoprazole to 30 mg twice daily for enhanced gastroprotection.','Inform the patient that an urgent advice and guidance request will be sent to the cardiology team to seek specialist input regarding dual antiplatelet therapy and to determine whether it is safe to stop one agent. Aspirin is often discontinued and the patient continues on clopidogrel alone, but this decision rests with the cardiology team.','Provide safety-netting advice: seek urgent medical attention if he develops black or tarry stools, vomiting blood, worsening fatigue, dizziness, chest pain, difficulty swallowing, or early satiety.','Arrange follow-up to review blood results and plan next steps.'],
  'Thank you for calling in today, George. I can see from your records that you''ve been feeling quite tired and have had some discomfort in your stomach, and your blood tests have come back showing something we need to discuss. The results reveal that your haemoglobin — the protein in your red blood cells that carries oxygen around the body — is lower than it should be. Your level is 109 g/L, where the normal range for a man your age is 130 to 180 g/L. On top of that, your red blood cells are smaller than usual, which is a pattern we associate with iron deficiency. That would certainly explain the tiredness you''ve been experiencing. I''d like to check a specific iron test called a ferritin level to confirm this is what''s going on.

Now, you mentioned you''ve been wondering whether aspirin and clopidogrel might be responsible. That''s a very sensible thought, and you''re right that these medications can sometimes cause low-level irritation to the stomach lining, which may lead to a small but ongoing loss of blood over time. Together, that can gradually deplete your iron stores. The heartburn you''ve been experiencing fits with this picture as well. I want to be transparent with you, though — in men of your age, when we find this type of blood result, we also have a duty to rule out other causes, including something more serious like a bowel problem or, in rare cases, cancer. I''m not suggesting that is what this is, but we do need to investigate properly so we can be certain.

The next step is for you to come in for a face-to-face appointment so I can examine your tummy and check your blood pressure and pulse. Alongside the ferritin test I mentioned, I''d also like to check for coeliac disease — a condition where the gut reacts to gluten — which can cause this kind of anaemia. We''ll also do a simple stool test to look for hidden traces of blood that wouldn''t be visible to the eye, and a urine test to check for any blood there too.

If the ferritin comes back low, we''ll start you on iron tablets to help restore your levels. We''ll also arrange for you to see a specialist who can perform a camera test to look inside your stomach and, if necessary, your bowel, to find the source of any bleeding and rule out anything more serious.

Regarding your two blood thinners — I completely understand the concern. Aspirin and clopidogrel are both essential at this stage to prevent another heart attack, particularly given the stent you had placed two months ago. However, I also appreciate that balancing that protection against the risk of bleeding is important. I''m going to write an urgent message to your cardiology team today asking for their guidance on whether it would be safe to stop one of the agents. Please do not stop either medication yourself until we have heard back from them.

In the meantime, I''m going to double your lansoprazole dose to 30 mg twice a day to give your stomach better protection. Finally, if at any point you notice black or tarry stools, vomit any blood, feel very dizzy, develop chest pain, find it hard to swallow, or feel full very quickly after eating, please do not wait — contact us straight away or call NHS 111 if we are closed. We''ll be in touch as soon as your test results are back.',
  ARRAY['Microcytic anaemia (low haemoglobin with low MCV and MCH) in a patient on dual antiplatelet therapy should raise suspicion of chronic gastrointestinal blood loss as the underlying cause.','In men and postmenopausal women, iron deficiency anaemia must be investigated as a potential malignancy until proven otherwise — this requires ferritin, coeliac screen, urinalysis, FIT testing, and referral for endoscopy under the two-week wait pathway.','Lansoprazole should be increased to 30 mg twice daily for gastroprotection in patients on dual antiplatelet therapy who develop gastrointestinal symptoms.','Never unilaterally stop dual antiplatelet therapy after PCI — always seek cardiology advice via urgent advice and guidance before making any changes. Aspirin is often the agent that is stopped while clopidogrel is continued long term.','Safety-netting in this scenario is critical: the patient must be advised to seek urgent attention for haematemesis, melaena, worsening dizziness, dysphagia, or early satiety.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  128,
  'Skin Discolouration on Hands in Adult Male',
  'Dermatology',
  'Telephone consultation',
  false,
  'Daniel Asante',
  '26-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  'Patient sent photographs via the online consultation portal and has booked a routine appointment to discuss concerns about the appearance of his hands.',
  'Patient has booked a telephone consultation to discuss changes to the skin on his hands noticed over the past several months.',
  'Hi doctor, I''ve booked this appointment because I''ve been getting some strange pale patches appearing on my hands and I''m not really sure what''s going on.',
  'You are Daniel Asante, a 26-year-old who works in a vehicle components manufacturing plant. You first noticed lighter areas of skin developing on your fingers around four months ago, and they have gradually spread towards your palms. The patches are not sore, not itchy, and do not feel rough or flaky, but the way they look has been making you anxious. At work, you are supposed to wear protective gloves but have occasionally worked with bare hands when handling parts or chemical solvents. You have been at this job for just over a year, and the skin changes appeared a few months after starting.',
  ARRAY['You have had no pain, itching, redness, blistering, or scaling in the affected areas.','You have no other skin problems and no skin changes anywhere else on your body.','You have not had any cuts, burns, or injuries to your hands.','There is no family history of skin conditions, including vitiligo, or autoimmune diseases such as thyroid problems or diabetes.','You have not applied any creams or treatments to the patches.','You have had no recent infections, illnesses, or vaccinations.'],
  'You do not smoke or drink alcohol. You live with a flatmate and are relatively sociable. You work full-time at the manufacturing plant and mostly enjoy the work.',
  'You think the chemical exposure at work is most likely responsible for the skin changes.',
  'Colleagues on the factory floor have started to notice and make comments about your hands, which is leaving you feeling self-conscious and uncomfortable at work. You are worried the patches might continue to spread or become a permanent feature.',
  'You want the GP to tell you what is causing the skin discolouration. You are also hoping there is a treatment that can restore your normal skin colour.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY['Ask when the skin changes were first noticed and how they have progressed over time.','Ask about any associated symptoms — pain, itching, irritation, dryness, scaling, or blistering.','Ask whether the affected patches have changed in size, shape, or number since they first appeared.','Ask whether any other areas of the body are affected, including the face, lips, arms, legs, or genital region.','Ask about any history of trauma, chemical burns, or direct contact with irritants on the affected areas.','Ask about workplace exposure — what substances are handled, whether gloves are consistently worn, and whether any colleagues have experienced similar changes.','Ask about family history of skin conditions, particularly vitiligo, eczema, or psoriasis, and of autoimmune diseases.','Ask about personal medical history, including any previous skin conditions, thyroid problems, diabetes, or other autoimmune conditions.','Ask about recent infections, illnesses, or vaccinations, as these can sometimes trigger vitiligo in susceptible individuals.','Ask about any treatments or products applied to the affected areas.','Ask about lifestyle factors including smoking, alcohol use, stress, and diet.','Explore the psychological impact of the skin changes — how they are affecting his confidence, social interactions, and daily wellbeing.','Ask about his ideas, concerns, and expectations regarding the skin changes.','Arrive at a working diagnosis of vitiligo.'],
  ARRAY['Arrange blood tests including thyroid function tests and thyroid autoantibodies. Offer testing for autoantibodies related to other autoimmune conditions only if the history, family history, or initial results suggest a broader autoimmune picture.','Advise the patient to apply a sunscreen with a 4-star or 5-star UVA rating and a sun protection factor of 50 to the affected patches and surrounding skin before any sun exposure.','Offer a vitamin D blood test if the patient is avoiding sun exposure entirely.','Offer a referral to a specialist camouflage team for guidance on covering affected areas. These are typically based in hospital outpatient departments; if unavailable locally, refer to the dermatology department or suggest contacting the charity Changing Faces. The patient may also use cosmetic products or fake tan to help blend the skin tone in the interim.','Offer a two-month trial of a potent topical corticosteroid, with a review at four weeks to assess any response.','Counsel the patient on the potential side effects of topical steroids, including skin thinning (atrophy), stretch marks (striae), increased hair growth (hypertrichosis), skin discolouration, acne or folliculitis, delayed wound healing, and with prolonged use over large areas, possible systemic effects including adrenal suppression (tachyphylaxis).','Explain that vitiligo can be unpredictable — some people have limited, stable patches while in others it spreads. Treatment response varies and will be reviewed and adjusted accordingly.','If the skin does not improve or worsens after the steroid trial, refer to dermatology for further management.','If the patient''s mental health is significantly affected, consider a referral for cognitive behavioural therapy (CBT).','Arrange a follow-up appointment in four weeks.','Safety-net: advise the patient to get in touch if he notices rapid spreading, new patches appearing elsewhere on the body, or any changes in general health.'],
  'Thank you for getting in touch today and for sending those photographs — that was really helpful. I can see from the pictures that there are some clearly defined areas of lighter skin on your fingers and palms, and I completely understand why this has been concerning you, particularly with people at work making comments about it.

Based on what you have described — the gradual appearance of these pale patches over several months, the fact that they are not painful or itchy, and the pattern of how they have spread — this looks most consistent with a condition called vitiligo. Daniel, vitiligo occurs when the immune system — which is normally there to protect us from infection — mistakenly targets the cells in the skin that produce pigment, called melanocytes. When these cells are damaged, that area of skin loses its colour, which is what creates the lighter patches you are seeing.

I know you have been wondering whether the chemicals you work with might be responsible. It''s a fair and logical thing to consider. Some chemicals can indeed bleach or lighten skin, but this typically happens at the precise spots where the chemical made contact and tends to be more uniform. What you are describing — patches that are gradually enlarging and appearing across a wider area of your hands — is more in keeping with vitiligo than a chemical-related skin change. That said, I would like to run some blood tests to make sure everything else is in order.

In terms of what we can do to help, I want to be upfront with you: there is no guaranteed cure for vitiligo, and the skin may not return fully to its original colour. However, treatment in the early stages does give us the best chance of slowing or halting the spread and, in some cases, restoring some pigment. I would like to start you on a course of a potent steroid cream, which you would apply once daily for up to two months. We would check in at four weeks to see how you are responding. I will also run some blood tests to check your thyroid and some other markers that can sometimes be associated with vitiligo.

In terms of sun protection, it is important to apply a high-factor sunscreen — SPF 50 with a 4- or 5-star UVA rating — to the affected areas before going outdoors, as the patches are more vulnerable to sunburn without their natural pigment. I can also refer you to a specialist camouflage team who are expert in helping people cover skin discolouration if you would find that useful while we work on the treatment side of things.

If the steroid cream does not make a meaningful difference after the trial, the next step would be a referral to a dermatologist who can consider other options including light therapy. If any of this is weighing on your mood or confidence, please do let me know — that is something we take seriously and there is support available. Please do get back in touch if you notice the patches spreading quickly or any new areas appearing elsewhere on your body.',
  ARRAY['Vitiligo results from autoimmune destruction of melanocytes, causing well-defined depigmented patches; it is bilateral and progressive in its non-segmental form and is associated with other autoimmune conditions such as thyroid disease.','Initial investigations should include thyroid function tests and thyroid autoantibodies; broader autoimmune screens are only warranted if the history or other results suggest it.','In primary care, a potent topical corticosteroid once daily for up to two months (off-label) can be offered to adults with non-segmental vitiligo affecting less than 10% of body surface area, provided the face is not involved, the patient is not pregnant, there are no contraindications, and the patient understands the risks — all five criteria must be met.','If the patient does not meet all criteria for topical steroid use in primary care, or fails to respond after the trial, refer routinely to dermatology.','Sun protection with SPF 50 and 4- or 5-star UVA-rated sunscreen is essential for all patients with vitiligo, and a referral to a camouflage team or Changing Faces should be offered to help manage the cosmetic impact.','The psychological burden of vitiligo can be significant — always screen for impact on mental health and consider CBT referral if needed.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  129,
  'Pleural Effusion on Chest X-Ray',
  'Respiratory',
  'Telephone Consultation',
  false,
  'Simon Bradshaw',
  '57-year-old male',
  ARRAY[]::text[],
  ARRAY['Amlodipine 10 mg once daily','Mirtazapine 15 mg once daily','Simvastatin 20 mg at night','No known drug allergies'],
  'Seen 2 days ago by Dr M. Okafor (Clinical Practitioner). Presenting complaint: Patient reports a persistent dry cough lasting 3 weeks. He was prescribed amoxicillin 500 mg TDS by an out-of-hours GP and completed the full course; however, symptoms have not resolved. Examination findings: Slightly diminished breath sounds at the left lung base. BP 135/85 mmHg, Pulse 89 bpm, SpO2 97% on air, RR 19 cpm. Plan: Urgent chest X-ray requested. Safety-netting and worsening advice provided. Chest X-ray Report — Simon Bradshaw | Male | 57 years old. Indication: Persistent cough for 3 weeks. Findings: There is a moderate left-sided pleural effusion demonstrated by blunting of the left costophrenic angle with associated meniscus sign. The left hemidiaphragm appears partially obscured. There is some reduction in lung volume at the left base, likely secondary to compressive atelectasis. No focal consolidation is seen within the visualised lung fields. The right lung is clear. The cardiomediastinal silhouette is within normal limits. No suspicious bony lesions identified. Conclusion: Left-sided pleural effusion. Clinical correlation advised. Recommend further assessment with chest ultrasound to evaluate for possible drainage or CT thorax if clinically indicated. Reported by: K. Osei, BSc (Hons) Diagnostic Radiography, PgCert Radiographic Reporting (Chest), Advanced Reporting Radiographer. Patient has booked a telephone appointment to discuss the X-ray result.',
  'Patient has booked a telephone consultation to discuss his chest X-ray result following a persistent cough.',
  'Good morning doctor, I''ve rung in because I was told to call and get the result of my chest X-ray. I''m still getting this cough and I''m a bit worried about it.',
  'You are Simon Bradshaw, a 57-year-old man. You had the chest X-ray arranged two days ago because of a dry cough that has been going on for three weeks. You were given amoxicillin 500 mg three times a day for five days by an out-of-hours GP about two weeks ago, but despite finishing the course, the cough has not improved at all. You have not brought up any phlegm and definitely no blood. You have not noticed any breathlessness.',
  ARRAY['You have had no fever, wheeze, or chest pain.','You have not noticed any ankle swelling or palpitations.','You have had no difficulty breathing when lying flat.','If asked about your cancer history (Non-Hodgkin''s Lymphoma): you were told everything was fine at your last review and you are under annual follow-up with the oncology team. Your last appointment was 9 months ago and your next is due in 3 months.','Decline to answer anything outside the details provided.'],
  'You are a non-smoker and do not drink alcohol. You work as a delivery driver and live with your partner.',
  'You think this is probably a lingering chest infection. You are not sure why the previous clinician did not prescribe a different or stronger antibiotic, as the ones you were given clearly did not help.',
  'The cough is starting to bother you because people keep commenting on it, which makes you feel embarrassed and self-conscious. That, combined with the fact it has been going on so long, is making you increasingly anxious.',
  'You would like the doctor to prescribe a different or stronger course of antibiotics so you can get back to work.',
  ARRAY[]::text[],
  'If the doctor does not explain what has caused the fluid in your chest, ask: "What has actually caused the fluid to build up there?" If the doctor raises the possibility of cancer, react with surprise and say: "I didn''t think this could be cancer — I don''t feel like I''ve got any cancer symptoms."',
  'Say no to any questions or details outside the information already provided. Accept any management offered by the doctor.',
  ARRAY['Begin by acknowledging that you are aware he was seen by a colleague two days ago regarding his cough, showing you have reviewed his notes and are up to date with his background. Ask whether his symptoms have improved, stayed the same, or worsened since that consultation.','Ask about the nature of the cough — how long it has been present, how frequent it is, and whether it is dry or productive. If productive, ask about the colour and consistency of any sputum.','Ask specifically about haemoptysis — whether he has coughed up any blood.','Ask about breathlessness — whether it is present at rest or only on exertion, and whether it is worsening. Ask about orthopnoea (breathlessness on lying flat) and paroxysmal nocturnal dyspnoea (waking at night feeling short of breath) to help exclude heart failure.','Ask about associated symptoms including fever, wheeze, palpitations, chest pain, pleuritic pain on inspiration, and ankle swelling or peripheral oedema to help rule out heart failure.','Ask about the patient''s cancer history — confirm the status of his Non-Hodgkin''s Lymphoma remission and the date of his last oncology review.','Ask whether he has noticed any symptoms that might suggest lymphoma recurrence, such as lumps, enlarged glands around the neck, armpits, or groin, or any new swellings.','Ask about other red flag symptoms including unexplained weight loss, reduced appetite, night sweats, and persistent fatigue.','Ask about any recent travel or prolonged periods of immobility, to help exclude pulmonary embolism.','Ask about any close contact with someone who has had a prolonged cough, to help rule out tuberculosis.','Ask about his occupation and any possible past or current exposure to asbestos, which could raise the risk of mesothelioma or benign asbestos-related pleural disease.','Ask about social and lifestyle history, including current and past smoking, and alcohol consumption.','Ask how the symptoms are affecting his daily life, ability to work, and general wellbeing.','Explain the chest X-ray findings clearly — that there is fluid around the left lung called a pleural effusion — and sensitively inform him that given his history of lymphoma, this may potentially be linked to a recurrence of his cancer, and that further tests are needed to establish the cause.'],
  ARRAY['Refer the patient urgently to the respiratory ambulatory pleural service to be assessed within 24 to 48 hours.','Explain that a CT scan will be arranged to obtain more detailed imaging of the chest and help identify the underlying cause of the effusion. Inform the patient that the respiratory team may also perform an ultrasound-guided diagnostic aspiration, which can both relieve symptoms and provide a fluid sample for laboratory analysis to help determine the cause.','Explain that the respiratory team may also recommend insertion of a chest drain depending on the size of the effusion and the patient''s clinical condition — this will be decided by the specialist following assessment.','Inform the patient that if the test results confirm a cancer-related cause, his case will be discussed at a multidisciplinary team (MDT) meeting, where specialists across different fields will review his results and agree on the most appropriate treatment plan.','Arrange baseline blood tests including FBC, U&Es, LFTs, and CRP.','Offer a sick note to support time away from work, given that his symptoms are currently affecting his ability to carry out his job safely.','Safety-net the patient: advise that if his breathlessness worsens — particularly if he becomes short of breath at rest — or if he develops any new or concerning symptoms, he should seek urgent medical attention or go directly to his nearest emergency department.','Advise the patient to let those close to him, such as his partner, know about his condition so they can support him and help him get prompt assistance if his symptoms suddenly deteriorate.'],
  'Thank you for calling in today, Simon. I have had a look at your chest X-ray result, and I do want to talk you through what it shows, so please stay with me as I explain. The X-ray has found that there is a collection of fluid sitting around your left lung. This is a condition called a pleural effusion. The fluid is collecting in the space between the lung and the chest wall, and this is likely what has been causing your persistent cough.

There are a number of things that can cause fluid to build up in this way. It can be due to an infection, inflammation, problems with the heart, or in some cases, other conditions that need further investigation. I want to be honest with you, because I think you deserve a straightforward conversation. Given your history of lymphoma, we do need to consider whether this could be connected to that — in other words, whether this might indicate that the lymphoma has returned. I want to be clear that I am not telling you this is the case, but it is something we have a responsibility to look into, and I would not be doing my job properly if I did not raise it with you today.

To find out what is causing the fluid, you need to be seen by a specialist respiratory team very quickly. I am going to refer you to the respiratory pleural service today, and the aim is for you to be seen within the next 24 to 48 hours. They will arrange a CT scan of your chest, which gives a much more detailed picture than a standard X-ray. They will also likely perform an ultrasound of the chest — similar to the type of scan used in pregnancy — which allows them to see the fluid clearly. As part of that, they may use a fine needle to draw off a small sample of the fluid. This is both helpful in relieving any pressure and allows the fluid to be sent to the laboratory so we can understand what is causing it.

Depending on what they find, the team may also recommend placing a small drain into the chest to remove the fluid — but that decision will be made by the respiratory specialists after they have seen you. If it does turn out that the cause is related to your lymphoma, your case would then be discussed at a multidisciplinary team meeting, where a group of specialists — including oncologists, respiratory physicians, and radiologists — would review everything together and agree on the best plan for you.

I am also going to arrange some blood tests today and I will provide you with a sick note, as I appreciate this is affecting your ability to do your job. In the meantime, please keep a close eye on how you are feeling. If at any point your breathing becomes significantly worse, especially if you are struggling to catch your breath while sitting still or resting, or if you develop any new symptoms that worry you, please go straight to your nearest emergency department or call 999. Please also let your partner know what is happening so they can support you.',
  ARRAY['A new pleural effusion in a patient with a history of cancer must always raise suspicion of malignancy or cancer recurrence until proven otherwise — this is a clinical red flag that requires urgent specialist referral.','Patients with a moderate pleural effusion who are clinically stable (not breathless at rest, normal observations) should be referred urgently to the respiratory ambulatory pleural service and seen within 24 to 48 hours — hospital admission is not always necessary.','Key investigations for pleural effusion include CT thorax and ultrasound-guided diagnostic aspiration; the fluid sample is sent for cytology, protein, LDH, glucose, and culture to help determine the underlying cause (Light''s criteria can help distinguish exudate from transudate).','If the effusion is large, the patient is breathless at rest, or observations are deteriorating, urgent hospital admission is required rather than ambulatory management.','Safety-netting in pleural effusion must be explicit: the patient should be instructed to go directly to hospital if breathlessness worsens at rest or new symptoms develop before the specialist appointment.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  130,
  'DEXA Scan Results',
  'Rheumatology & Musculoskeletal',
  'Telephone consultation',
  false,
  'Margaret Fielding',
  '72-year-old female',
  ARRAY['Osteoarthritis','Hypertension','Urge incontinence','Paracetamol PRN','Amlodipine 10mg OD','Mirabegron 50 mg once daily','Codeine phosphate 30–60 mg every 6 hours as required for pain'],
  ARRAY[]::text[],
  'Letter from Orthopaedics – 6 weeks ago. Dear GP, Ms. Margaret Fielding was admitted via the Emergency Department following a mechanical fall. Imaging including X-ray and CT scan confirmed a compression fracture of L2. She was assessed by the orthopaedic team and as there were no red flag symptoms, a decision was made for conservative management with analgesia and mobilisation. She was discharged with appropriate follow-up and advice. Given the nature of the injury, it is important to assess underlying bone health. We would be grateful if you could review her for potential osteoporosis and initiate appropriate management as indicated. Please do not hesitate to contact us if further information is required. Yours sincerely, Mr. D. Okafor MBBS, MS (Orth), FRCS (Tr & Orth), Consultant Orthopaedic Surgeon. Patient reviewed by locum GP 4 weeks ago: Patient attended for review following mechanical fall. Letter from orthopaedics noted. No red flag symptoms. Back pain well controlled. BMI 27. Plan: refer for DEXA scan. DEXA Scan Results: Lumbar Spine (L1–L4) T-score –0.9 — Normal; Left Hip (Total Hip) T-score –1.0 — Normal; Femoral Neck T-score –1.0 — Normal. Reference ranges: Normal bone density is defined as a T-score of –1.0 or above; Osteopenia is defined as a T-score between –1.0 and –2.5; Osteoporosis is defined as a T-score of –2.5 or lower. Patient has booked an appointment to discuss DEXA scan results.',
  'Patient has booked a telephone consultation to discuss the results of her DEXA scan following a vertebral fracture six weeks ago.',
  'Hello doctor, I''ve booked this call to find out what my bone scan results say. I had it done a couple of weeks ago after my fall.',
  'You are Margaret Fielding, a 72-year-old woman who sustained a vertebral fracture six weeks ago. You were told that fragile bones might have contributed to the injury, so your GP arranged a DEXA scan to look into this. You are calling today to hear the results. You slipped on a rug in your hallway and fell awkwardly. Your back pain is now largely under control and you have no weakness in your legs or problems with your bladder or bowel.',
  ARRAY['You went through the menopause at age 49 and did not take hormone replacement therapy.','You have not had any previous fractures other than this one.','You follow a reasonably balanced diet that includes dairy products and other calcium-containing foods.','You walk most days but do not do any strength or resistance training.','You are not on any long-term steroid tablets or any other regular over-the-counter medications.','You have no family history of osteoporosis or fragility fractures.'],
  'You live independently and manage well at home. You smoked 40 cigarettes a day for 40 years. You do not drink excessively. You keep yourself fairly active but do not do weight-bearing exercise regularly. You are a retired florist.',
  'You are not really sure what to expect from today''s conversation.',
  'Not particularly — you are just keen to understand the results.',
  'You would like the GP to explain your DEXA scan results and what they mean for you. If the doctor offers bisphosphonates, ask how long you would need to take them.',
  ARRAY[]::text[],
  'If the doctor offers bisphosphonate treatment, ask: "How long would I need to be on this medication for?"',
  NULL,
  ARRAY['Ask about her understanding of the DEXA scan and what she is hoping to find out from today''s discussion.','Ask about the circumstances of the vertebral fracture — how exactly did it happen, was there any significant trauma or force involved?','Ask about red flag symptoms from the vertebral fracture: any leg weakness or altered sensation, problems with bladder or bowel control, or worsening back pain since discharge.','Ask about risk factors for osteoporosis and fragility fractures including: family history of osteoporosis or fractures, current or past smoking, alcohol intake, long-term steroid use, and any other medications known to affect bone health (such as proton pump inhibitors or anticonvulsants).','Ask about any other unexplained or low-trauma fractures in the past.','Ask about her diet, in particular calcium and vitamin D intake, and her level of physical activity including any weight-bearing or resistance exercise.','Ask about any recent falls or concerns about her balance and mobility.','Ask about her home environment and whether she lives alone or with support.','Explain the DEXA scan results clearly and sensitively: while the bone mineral density falls within the normal range on the scan, the presence of a vertebral fracture in the absence of significant trauma indicates that her bones are more fragile than the scan suggests, and this itself is indicative of osteoporosis. Explain that treatment is therefore recommended.'],
  ARRAY['Arrange blood tests to assess TSH, vitamin D, calcium, FBC, and U&Es, to identify any underlying factors contributing to poor bone health.','Offer to calculate her daily calcium intake using a validated calcium calculator by sending her a dietary questionnaire, so that the need for supplementation can be determined accurately.','Refer to physiotherapy or occupational therapy to assess her home environment for fall hazards and to enrol her in a falls prevention programme with combined OT and physiotherapy input.','As she lives independently, discuss the option of a personal falls alarm or pendant alarm to ensure she can summon help quickly if she falls again.','Initiate bisphosphonate therapy, explaining that this medication helps to strengthen the bones and significantly reduces the risk of future fractures. Counsel her on potential side effects including upper gastrointestinal discomfort and, in rare cases, osteonecrosis of the jaw. Advise her to attend a dental check-up before starting treatment and to maintain good oral hygiene.','Explain that bisphosphonate treatment may continue for up to 10 years.','Inform her that vitamin D and calcium supplementation may also be recommended, but that the blood test results and calcium calculator will guide this decision.','Encourage regular weight-bearing exercise such as walking.','Offer smoking cessation support.','Arrange a review appointment in 3 months to assess blood results and medication tolerance.','Safety-net: advise her to seek urgent medical attention if she develops any new or significantly worsening back pain, weakness or altered sensation in her legs, loss of bladder or bowel control, or if she has any further falls.'],
  'Thank you for calling in today. I have got your DEXA scan results here and I would like to go through them with you carefully, as there are some important things for us to discuss. The scan itself shows that your bone density is technically within the normal range at all the sites measured — the spine, hip, and femoral neck all came back as normal by the standard scoring system. I imagine that might sound like good news, and in one sense it is, but I want to be honest with you because the full picture is a little more nuanced than that.

Margaret, the reason I say that is because of the fracture you had six weeks ago. You slipped on a rug — that is not a major impact or a high-energy injury — and yet it resulted in a fracture in your spine. When a bone breaks from a relatively minor fall or movement like that, it tells us that the bone was more fragile than it appeared on the density scan. In fact, the clinical guidelines we follow specifically recognise that a vertebral fracture occurring after a low-energy event is itself evidence of osteoporosis, regardless of what the DEXA numbers say. So while the scan numbers look reassuring, the fracture you have had is the more important piece of information here.

What this means in practice is that you are at increased risk of having further fractures in the future — and we want to do everything we can to prevent that from happening. The good news is that there are effective treatments and practical steps we can take together to help protect your bones going forward. I would like to start you on a group of medications called bisphosphonates. These work by slowing down the natural breakdown of bone tissue, which effectively makes the bones stronger and more resistant to fracturing. You might be wondering how long you would need to take them — the answer is that treatment typically continues for up to ten years, though we would review that together along the way.

Before starting the bisphosphonates, I would like to run some blood tests to check your vitamin D, calcium, thyroid function, and a few other markers that can affect bone health. I will also send you a short questionnaire about your diet so we can work out how much calcium you are getting from food — that will help us decide whether you need to take calcium and vitamin D supplements alongside the bisphosphonate. It is worth knowing that bisphosphonates can sometimes cause mild stomach discomfort, and very rarely a condition affecting the jaw bone, so I would also recommend booking a dental check-up before starting the medication.

Alongside the medication, there are some very practical things that can make a real difference. I would like to refer you to a physiotherapist and an occupational therapist who can assess your home for any trip hazards — things like that rug in the hallway — and help enrol you in a falls prevention programme. Given that you live on your own, it might also be worth considering a personal alarm you can wear, so you can call for help quickly if you ever fall again. Keeping up with regular walking is also helpful, as weight-bearing exercise supports bone strength. And I do want to mention smoking — I know you have smoked for many years, and I appreciate this is not always easy to change, but smoking significantly affects bone health, so support to stop would be genuinely worthwhile and available through us any time you are ready.

Please do get in touch if your back pain returns or gets worse, if you develop any weakness in your legs or any problems with your bladder or bowel, or if you have any further falls. We will touch base again in about three months to review the blood results and see how you are getting on with the new medication.',
  ARRAY['A vertebral fracture occurring after a low-energy event (e.g. a simple fall from standing height) indicates clinical osteoporosis regardless of DEXA T-score — this is based on SIGN guideline expert consensus and treatment should be initiated without waiting for a T-score of –2.5 or lower.','Bisphosphonate therapy is the first-line treatment for osteoporosis; potential side effects include gastrointestinal upset and, rarely, osteonecrosis of the jaw — a dental check-up should be recommended before starting treatment. Duration of treatment is typically up to 10 years.','Blood tests before initiating bisphosphonates should include vitamin D, calcium, TSH, FBC, and U&Es to identify reversible contributing factors.','Calcium intake should be assessed using a validated calcium calculator; supplementation with calcium and vitamin D may be needed depending on dietary intake and blood results.','Falls prevention is an essential part of management: physiotherapy, occupational therapy home assessment, and a falls prevention programme should all be offered; a personal falls alarm is important for patients who live alone.','Smoking is a significant risk factor for osteoporosis and smoking cessation support should always be offered as part of bone health management.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  131,
  'Confusion In A Nursing Home Resident',
  'Elderly Medicine & Palliative Care',
  'Telephone Consultation',
  false,
  'Dorothy Kenwright',
  '72-year-old female',
  ARRAY['Hypertension','High cholesterol','Osteoarthritis','Frailty','Dementia','Urinary incontinence','Ramipril 10mg OD','Co-codamol 15/500mg PRN (1–2 capsules every 4–6 hours as needed)','Donepezil 10mg OD','Oxybutynin IR 10mg OD (started 2 months ago for urinary incontinence by a locum GP during a nursing home visit)'],
  ARRAY[]::text[],
  'Seen by locum GP 2 months ago — Care Home Visit. Patient reports episodes of a sudden, compelling urge to pass urine that is difficult to defer, resulting in urinary incontinence. She would prefer to have treatment for this. Plan: commence Oxybutynin 5mg once daily, to be increased to 10mg if symptoms remain uncontrolled. Caller: Patricia Norwood (Carer at Care Home) — calling to discuss concerns about the patient.',
  'Carer at the nursing home is telephoning to seek advice regarding a change in the resident''s behaviour and urinary symptoms.',
  'Good morning, I''m Patricia Norwood, I work as a carer at Riverside Care Home. I''m ringing because I''m a bit worried about one of our residents, Dorothy Kenwright. She''s been getting more confused since last night and she''s also been needing the toilet a lot more than usual over the past week or two. I''m wondering if she might have a urine infection.',
  'You are Patricia Norwood, a carer at the care home. You arrived at the start of your shift this morning and the night staff handed over that Dorothy has been confused since the previous evening. You have also noticed that she has been going to the toilet much more frequently over the past one to two weeks. You are phoning the GP because you think she might have a UTI and you are hoping they will prescribe antibiotics.',
  ARRAY['Dorothy does not have a temperature.','She has not complained of any pain or burning when passing urine.','There is no visible blood in her urine and it does not smell offensive.','She normally manages to use the toilet herself and does not require pads.','Her bowels have been opening normally — she is not constipated.','She has been eating and drinking as usual.','She has not had any falls or head injuries recently.','You have not performed a urine dipstick test.','Observations this morning: BP 130/80 mmHg, pulse 75 bpm, temperature 36.2°C, respiratory rate 17 cpm, oxygen saturations 98% on room air.','The only recent medication change has been starting oxybutynin two months ago.'],
  'You work full-time at the care home and have a good relationship with the residents. Dorothy is usually cheerful and relatively settled in her routine.',
  'You believe Dorothy has a UTI, as you know that confusion and increased urinary frequency are common signs of a urine infection in elderly residents.',
  'You are worried that if the infection is not treated promptly it could deteriorate into something more serious. You are also concerned about the increase in her confusion, which is not like her baseline.',
  'You would like the GP to prescribe a course of antibiotics to treat the suspected UTI.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY['Ask when the confusion started and clarify whether it has been getting progressively worse, or fluctuating.','Ask about specific urinary symptoms — whether there is any pain or burning on passing urine, increased urgency, frequency, hesitancy, foul-smelling urine, or visible blood in the urine.','Ask about other symptoms that might suggest an infection or systemic illness, including fever, chills, nausea, vomiting, abdominal pain, back or loin pain, or new-onset urinary incontinence.','Ask about Dorothy''s bowel habits, as constipation in older adults can worsen urinary symptoms and contribute to confusion.','Ask about fluid intake and whether she has been drinking normally, as dehydration is a common and easily overlooked cause of confusion in elderly patients.','Ask about recent changes to Dorothy''s medications, particularly the introduction of oxybutynin two months ago.','Ask about any recent illnesses, infections elsewhere, or a known history of recurrent urinary tract infections.','Ask about any recent falls or head injuries, as acute confusion in a frail older patient can sometimes be the result of an unwitnessed injury.','Ask about Dorothy''s usual cognitive baseline — whether her dementia is stable, and whether this current confusion represents an acute change from her normal level of functioning.','Recognise that the most likely explanation in this clinical context is oxybutynin toxicity, and that other differentials include delirium secondary to dehydration, an infection of unknown source, or constipation. Arrive at a working diagnosis of oxybutynin-related confusion and urinary frequency.'],
  ARRAY['Offer to arrange a home visit to assess Dorothy in person. Explain to the carer that you would like to examine her abdomen and perform a general clinical assessment to look for any signs of infection or other underlying cause.','If infection is suspected following the assessment, she may require hospital admission for urgent blood tests, intravenous fluids, close monitoring, and further management.','However, based on the information provided, infection does not appear to be the most likely explanation for Dorothy''s symptoms. The clinical picture — increased urinary frequency and new-onset confusion in an older woman with dementia who was started on oxybutynin two months ago — is more consistent with anticholinergic side effects. Advise that oxybutynin should be discontinued and that a more appropriate alternative, such as mirabegron, should be considered.','Safety-net: advise the carer to ensure Dorothy is drinking sufficient fluids. If her condition deteriorates, she becomes unwell, develops a fever, or her confusion worsens suddenly, the carer should seek urgent medical assistance — including calling an ambulance to arrange hospital admission if necessary.'],
  'Thank you very much for calling, Patricia — I can hear that you are genuinely worried about Dorothy and I really appreciate you taking the time to ring. You are absolutely right that UTIs are common in older women and that confusion and increased trips to the toilet can sometimes be signs of one. That is a very reasonable thing to be thinking about. Let me talk through the information you have given me, because I think there may be another explanation that is worth exploring.

The thing is, Dorothy does not appear to have the typical features we would expect to see with a urinary tract infection. She has no burning or pain when she passes urine, no blood in her urine, no offensive smell, no fever, and her observations are reassuring. That does not completely rule out an infection, but it does make it less likely as the primary cause.

What I want to draw your attention to is a medication change that happened about two months ago. Dorothy was started on a tablet called oxybutynin for her urinary urgency and incontinence. Oxybutynin is a type of medication we call an anticholinergic, and while it can sometimes help with bladder control, it has a number of side effects that are particularly problematic in older adults — especially those living with dementia. One of those side effects is causing the bladder to go into a state of retention, where the muscle cannot empty properly, which paradoxically leads to the feeling of needing to go very frequently. Another significant side effect is confusion or delirium, which fits very closely with what you have described in Dorothy. In fact, NICE guidance specifically advises against using immediate-release oxybutynin in older women who are at risk of a sudden decline in their physical or mental health, precisely because of these risks.

So what I think is happening here is that Dorothy''s symptoms — both the increased urinary frequency and the confusion — may well be side effects of the oxybutynin rather than a urinary infection. I do not want to simply prescribe antibiotics without proper assessment, because using antibiotics when they are not needed can cause side effects and contributes to antibiotic resistance across the population.

What I would like to do is come and see Dorothy in person so I can examine her properly and make a thorough clinical assessment. If I find any signs of infection during that visit, we will act on it straightaway — and if needed, I will arrange hospital admission for blood tests and further monitoring. But if the picture remains consistent with what you have described, the plan would be to stop the oxybutynin and switch her to a better-tolerated alternative called mirabegron, which does not carry the same anticholinergic risks. In the meantime, please make sure Dorothy is having enough to drink, as dehydration alone can cause confusion in someone with her background. If her condition gets worse before I can get there, if she develops a high temperature, or her confusion deteriorates suddenly, please call 999 for an ambulance. Thank you again for looking out for her — you were absolutely right to call.',
  ARRAY['NICE guidance advises that immediate-release oxybutynin should not be offered to older women who are at risk of rapid deterioration in physical or mental health, due to its anticholinergic side effects including confusion, urinary retention, and delirium.','Oxybutynin can paradoxically worsen urinary frequency by causing bladder retention, and can precipitate acute confusion or delirium in patients with dementia — this is a key prescribing safety point.','Urine dipstick testing should not be used to diagnose a UTI in women aged over 65 years, as false positive rates are high in this age group. A midstream urine (MSU) sample sent for culture is required to confirm infection.','A diagnosis of UTI in women over 65 should only be considered if there is isolated new-onset dysuria, or two or more of: fever, new frequency or urgency, new incontinence, new suprapubic pain, visible haematuria, or new/worsening delirium — where no other cause has been identified.','Where oxybutynin side effects are suspected, discontinue the drug and consider switching to mirabegron, which has a more favourable side effect profile in older adults.','In frail elderly patients with acute confusion, always consider a broad range of causes including medication side effects, dehydration, constipation, infection, and unwitnessed falls before defaulting to antibiotic prescribing.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  132,
  'Medication Error In A Nursing Home Resident',
  'Elderly Medicine & Palliative Care',
  'Telephone Consultation',
  false,
  'Frederick Pemberton',
  '74-year-old male',
  ARRAY['Dementia','Chronic Obstructive Pulmonary Disease (COPD)','Hypertension','Atrial fibrillation','Donepezil 10mg OD','Trelegy Ellipta 92/55/22 mcg (Fluticasone/Umeclidinium/Vilanterol) OD','Amlodipine 5mg OD','Apixaban 5mg BD'],
  ARRAY[]::text[],
  'Caller: Robert Chalmers (Carer at Care Home). Carer''s account: During this morning''s medication round, Robert accidentally administered another resident''s medication — Amitriptyline 25mg — to Frederick Pemberton. This was reported to the care home supervisor, who asked Robert to telephone the GP for guidance. Frederick has not shown any side effects so far, but Robert is worried about what might happen.',
  'A carer at the nursing home is telephoning to seek urgent GP advice following an accidental medication error — the wrong resident was given Amitriptyline 25mg.',
  'Hello doctor, I''m Robert Chalmers, I''m a carer at Willowbrook Care Home. I need to speak to a doctor urgently because I''ve made a medication mistake this morning and I''m not sure what to do.',
  'You are Robert Chalmers, a carer at the care home. During the medication round this morning, you accidentally gave Frederick Pemberton a tablet belonging to another resident — Amitriptyline 25mg. You noticed the error shortly afterwards and reported it immediately to your supervisor, who has asked you to contact the GP for advice. Frederick has not shown any effects from the medication so far, but you are very worried.',
  ARRAY['The medication error occurred approximately one hour ago.','Frederick has not experienced any drowsiness, dizziness, dry mouth, confusion, or any other new symptoms since taking the tablet.','He has not yet received any of his regular medications today.','There is no known history of heart problems, seizures, or drug allergies.','The care home has carers only — there are no qualified nursing staff on site.','You can arrange a blood pressure check at the care home if the doctor requests one.'],
  'You work full-time at the care home and take your responsibilities seriously. You are visibly distressed about the error and keen to do the right thing.',
  'You are concerned about the potential side effects of amitriptyline and what harm it might cause Frederick.',
  'You are worried that the medication error might have put Frederick at risk of serious harm. You are also unsure whether you should give him his regular medications this morning.',
  'You would like the GP to tell you what needs to happen next and whether any further action is required to keep Frederick safe.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY['Ask when the medication was given and confirm the exact dose that was administered.','Ask whether Frederick has experienced any symptoms since taking the tablet, including drowsiness, confusion, dizziness, dry mouth, low blood pressure, or any change in his heart rhythm.','Ask about Frederick''s usual cognitive baseline and whether there has been any acute change in his confusion since the error occurred.','Ask about his food and fluid intake this morning, as dehydration can compound the effects of medication.','Ask about any history of falls, seizures, or pre-existing cardiac conditions, as amitriptyline can have significant effects on heart rhythm.','Ask whether Frederick has received any of his regular medications today and whether there have been any other concerns this morning.','Ask about the care home''s capacity to monitor Frederick if his condition changes — whether the home has protocols in place for responding to a deteriorating resident.','Ask in a supportive and non-blaming way about the care home''s processes for preventing medication errors, and whether this incident will be formally reviewed. For example: "I know these things can be incredibly stressful, and I really appreciate you acting so quickly. Do you think this is something that will be looked at by the home, or are there already processes in place to help prevent this from happening again?" OR "It''s really good that you picked this up promptly and escalated it. Are there any changes you think might help make the medication round safer in future?"'],
  ARRAY['Advise close monitoring of Frederick, as amitriptyline has a delayed onset of action and symptoms — if they occur — may develop over the next few hours rather than immediately.','Reassure the carer that a single low dose of 25mg is unlikely to cause serious harm, but that caution and observation are still essential given that older adults can be more sensitive to anticholinergic effects.','Explain that you will check the BNF and TOXBASE to confirm there are no clinically significant interactions between amitriptyline and his regular medications before advising on whether it is safe to proceed with his usual medication round.','Advise that a blood pressure check should be performed before giving the Amlodipine dose, as both Amlodipine and amitriptyline can lower blood pressure, and the combined effect could increase the risk of dizziness or falls.','Recommend that this incident be formally reported and reviewed within the care home — not to apportion blame, but to identify any improvements to the medication administration process that could prevent future errors.','Provide clear safety-netting: if Frederick develops a rapid or irregular heartbeat, significant dizziness, excessive drowsiness, new confusion, or very low blood pressure, the carer should call 999 immediately and arrange urgent hospital admission.'],
  'Thank you for ringing straight away, Robert — that was exactly the right thing to do, and I can hear that you are very concerned. The fact that you picked this up quickly and escalated it immediately is genuinely important, and it means we can manage this situation safely together. Let me go through things clearly with you.

The good news is that Frederick is not showing any symptoms at the moment, which is reassuring. The tablet he was given — amitriptyline 25mg — is a medication that is sometimes used for pain, depression, or sleep problems. A single dose at that level is relatively low, and in most cases is unlikely to cause serious harm. However, I want to be clear that amitriptyline can have what we call a delayed effect — meaning that any problems, if they do occur, might not appear immediately but could develop over the next hour or two. That is why we need to keep a close eye on him rather than assume everything will be fine just because he seems okay right now.

There are a couple of things I want to flag specifically. Amitriptyline can cause blood pressure to drop, and Frederick is already on amlodipine, which also lowers blood pressure. The combination is not necessarily dangerous, but it is something to watch. Before you give him his amlodipine tablet this morning, could you check his blood pressure first? If it is already on the lower side, I would want to know before that medication goes in. His other regular medications — the donepezil, the Trelegy Ellipta inhaler, and the apixaban — should generally be given as usual, but before I confirm that with you, I am going to quickly check the BNF and TOXBASE to make sure there are no interactions we need to be aware of. I will call you back shortly to confirm.

In the meantime, please make sure someone is with Frederick or checking on him regularly. If at any point he seems more drowsy than usual, becomes confused, says he feels dizzy or unsteady, or if his lips or face look unusual, please call 999 straight away — do not wait to call us back first.

I do also want to raise something gently, and I want to be clear I am absolutely not saying this to make you feel worse — I can see how distressed you are and I know this was a genuine mistake. It is standard practice for incidents like this to be formally recorded and reviewed within the care home. That is not about blame — it is about looking at what systems are in place and whether there is anything that could be adjusted to make the medication round even safer, especially given that the home does not have nursing staff on site. I am sure your supervisor will be taking that forward. Thank you again for acting so quickly — you have made a real difference here.',
  ARRAY['Amitriptyline is a tricyclic antidepressant with a delayed onset of action — symptoms of toxicity, including hypotension, confusion, drowsiness, and cardiac arrhythmia, may not appear immediately after ingestion and the patient must be closely monitored.','A single therapeutic dose of amitriptyline 25mg in a supervised care home setting does not meet NICE''s definition of poisoning (which requires an excessive dose), and hospital admission may not be necessary — safe management can include careful observation, blood pressure monitoring, and symptom review in situ.','NICE advises that patients who have ingested substances with delayed toxicity (including tricyclic antidepressants, aspirin, modified-release preparations, iron, and paracetamol) should normally be referred urgently to hospital if symptomatic; however, clinical judgement is required when the dose is sub-therapeutic.','Amlodipine and amitriptyline both lower blood pressure — check the blood pressure before administering amlodipine to reduce the risk of compounded hypotension and falls.','BNF and TOXBASE should always be consulted when there is uncertainty about drug interactions or toxicity thresholds following an accidental medication administration.','Medication errors in care homes should always be formally reported and reviewed — not punitively, but to identify system-level improvements and prevent recurrence, particularly in homes without qualified nursing staff.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  133,
  'Abnormal Calcium Levels In Young Adult',
  'Endocrine & Nephrology',
  'Video Consultation',
  false,
  'Daniel Okafor',
  '34-year-old male',
  ARRAY['No known medical history','No regular medications','No known drug allergies'],
  ARRAY[]::text[],
  'Patient booked routine consultation to discuss blood test results. No recent GP contacts on record.',
  'Reviewing results from hospital attendance abroad showing elevated calcium levels.',
  'Hi doctor, I''m here because I went to A&E while I was on holiday in Turkey about five days ago. I had really bad stomach pain, blood in my urine, and I was going to the toilet constantly and felt incredibly thirsty. They did blood tests and told me my calcium was high — 2.9 mmol/L — and told me to drink lots of water and see a GP when I got back. I''m still not feeling right and I want to understand what''s going on.',
  'The abdominal pain is still there but has eased somewhat compared to before. Initially it was around the right kidney area and radiated down toward the groin, but now it''s more central around the belly button. Urinary frequency and thirst are ongoing. No nausea or vomiting. No fever or chills. No prior history of kidney stones or parathyroid problems. Not taking any calcium or vitamin D supplements. No previous episodes of high calcium. No recent bone pain or fractures. No unintentional weight loss or night sweats. No family history of parathyroid disease or kidney problems.',
  ARRAY[
    'No history of kidney stones or parathyroid problems when directly asked.',
    'Not taking any calcium, vitamin D, or over-the-counter supplements.',
    'No previous episodes of elevated calcium.',
    'No recent bone pain, fractures, unintentional weight loss, or night sweats.',
    'No family history of parathyroid disease, kidney problems, or endocrine conditions.',
    'If the doctor recommends hospital admission, politely but firmly decline — explain that he has a critical business contract to sign in Northern Ireland worth a significant sum and will return in two days. He understands the risks but wants to manage this in primary care if possible.'
  ],
  'Works as a civil engineer in the UK. Non-smoker, does not drink alcohol. No unusual infections or exposures noted during the holiday in Turkey. No family history of calcium-related or endocrine conditions.',
  'He wonders whether eating a lot of dairy — cheese, milk, and yoghurt — while on holiday might have caused his calcium to go high.',
  'He is concerned about why these symptoms are still present and wants to know if they will settle.',
  'He would like the GP to prescribe something or give clear advice on how to manage this.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Ask about the timeline of symptoms — when the pain, urinary symptoms, and thirst started, and whether they are improving or worsening.',
    'Ask about the severity and nature of the abdominal pain — location, radiation, and any triggering or relieving factors.',
    'Ask about associated symptoms including nausea, vomiting, fever, fatigue, palpitations, weakness, confusion, constipation, or bone pain.',
    'Ask about any previous episodes of similar symptoms or known calcium issues.',
    'Ask about medication and supplement use, including calcium, vitamin D, or over-the-counter preparations.',
    'Ask about risk factors for hypercalcaemia: parathyroid disease (family history, neck pain, past calcium issues), malignancy (weight loss, night sweats), sarcoidosis or tuberculosis exposure (cough, lymphadenopathy, TB history), and kidney stones (flank pain, prior stone history).',
    'Ask about dietary habits and hydration during the trip abroad.',
    'Ask about family history of calcium disorders, kidney disease, or parathyroid conditions.',
    'Ask about travel-related factors — any unusual infections or environmental exposures.'
  ],
  ARRAY[
    'Offer a referral to the Acute Medical Unit (AMU) as he is symptomatic and requires urgent treatment.',
    'If he declines admission, assess his capacity to make this decision. If he has capacity and understands the risks, proceed with urgent investigations in primary care, including calcium, parathyroid hormone (PTH), vitamin D, U&Es, LFTs, CRP, ESR, and TFTs to determine the underlying cause.',
    'Advise him to drink plenty of fluids to help lower his calcium levels.',
    'Provide clear safety netting advice — if he develops confusion, palpitations, chest pain, worsening symptoms, or if the blood in his urine returns, he must go to A&E immediately.',
    'Encourage him to inform someone around him about his condition so they can help him seek urgent care if needed.'
  ],
  'Thank you for coming in today and for sharing all of that with me, Daniel. I can hear how unsettled you''ve been feeling since you returned from Turkey, and I want to make sure we get to the bottom of this properly.

From everything you''ve described — the abdominal pain, the frequent urination, the excessive thirst, and the blood in your urine — along with the blood test result showing a calcium level of 2.9 mmol/L, it''s clear that your calcium is elevated, and this is most likely what''s been driving your symptoms. The medical term for this is hypercalcaemia.

One of the most common reasons for this in someone your age is a condition called primary hyperparathyroidism. You have four tiny glands at the front of your neck called parathyroid glands, and their job is to keep your calcium levels balanced. Occasionally one of these glands can become overactive and produce too much parathyroid hormone, which causes calcium levels in the blood to rise. When calcium gets too high, it can cause exactly the symptoms you''ve been experiencing.

In an ideal world, the safest course of action right now would be for you to be admitted to an Acute Medical Unit — that''s a specialist ward in hospital — where your calcium could be brought down safely with IV fluids and you''d be monitored closely. I want to be honest with you that elevated calcium at this level, especially with ongoing symptoms, is something we take seriously.

I understand you''ve explained you cannot attend hospital right now, and I respect that this is your decision to make. What I''d like to do is organise some urgent blood tests for you today, including your current calcium level, parathyroid hormone, vitamin D, kidney function, liver function, and inflammatory markers, so we can start working out what is causing this.

In the meantime, I want to reassure you about one thing — your dairy intake, the cheese, milk, and yoghurt you mentioned — that is very unlikely to have caused this level of calcium rise. So please don''t worry about that.

The most important thing while you''re away is to keep drinking fluids regularly — water is best — as this helps your kidneys flush out excess calcium. However, if at any point you feel confused, your heart starts racing, you develop chest pain, your symptoms significantly worsen, or the blood in your urine returns, you must go straight to the nearest A&E without delay. Please also consider letting someone travelling with you or a family member know about your situation so they can support you if needed.

We''ll get the results back as quickly as possible and arrange an urgent follow-up. And please do not hesitate to change your mind about hospital if things get worse — there''s no judgment in that at all.',
  ARRAY[
    'Symptomatic hypercalcaemia (calcium 2.9 mmol/L) with loin-to-groin pain, haematuria, polyuria, and polydipsia warrants urgent referral to the Acute Medical Unit; primary hyperparathyroidism is the most common cause in young adults.',
    'If a capacitous patient declines hospital admission, document the discussion, proceed with urgent primary care investigations (calcium, PTH, vitamin D, U&Es, LFTs, CRP, ESR, TFTs), and provide explicit safety-netting advice.',
    'Red flag features of hypercalcaemia requiring immediate A&E attendance include confusion, palpitations, chest pain, worsening haematuria, or severe weakness.',
    'Dietary calcium intake (dairy products) does not cause clinically significant hypercalcaemia and can be reassuringly excluded as a cause.',
    'Adequate hydration is the key immediate self-management strategy for hypercalcaemia; advise generous fluid intake while awaiting investigation results.',
    'Always encourage the patient to inform a trusted person nearby about their condition in case urgent assistance is needed.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  134,
  'Recurrent Dyspepsia',
  'Gastroenterology & Haematology',
  'Telephone Consultation',
  false,
  'Simon Hartley',
  '54-year-old male',
  ARRAY['Dyspepsia — likely GORD'],
  ARRAY[]::text[],
  'Omeprazole 20mg once daily — last issued 7 months ago. Patient booked routine telephone appointment to discuss ongoing symptoms.',
  'Returning heartburn and dyspeptic symptoms over the past two months, requesting repeat prescription for omeprazole.',
  'Hello, I''m calling because I''ve been getting heartburn and indigestion again. It''s been on and off for around six or seven months, but it''s been worse over the past two months and it''s really getting to me. I''ve been using Gaviscon from the chemist which helps a little, but I really think I need the omeprazole back on prescription.',
  'The burning sensation is mainly behind the chest, worse after meals and when lying down. Gaviscon provides some relief but symptoms keep returning. No difficulty swallowing (dysphagia) and no pain on swallowing (odynophagia). No unexplained weight loss. No vomiting, haematemesis, or black stools. No loss of appetite. No smoking. Drinks alcohol only occasionally at social occasions. No family history of oesophageal or gastric cancer. No recent infections or other new symptoms. Believes stress and his current diet are making things worse but still wants medication to help.',
  ARRAY[
    'Only if asked about stress or lifestyle: he is going through a separation from his long-term partner, which has been very difficult. He has been comfort eating, ordering a lot of takeaway food — particularly Indian food — eating late at night, and has put on weight over recent months.',
    'Only if asked about diet: he has been relying heavily on takeaways and processed food and has not been eating regular home-cooked meals.',
    'Deny any other symptoms not already listed if asked.'
  ],
  'Non-smoker. Drinks alcohol occasionally at social events, not regularly. Lives alone following a recent separation. Works as an IT consultant.',
  'He thinks this is acid reflux, as he had the same symptoms before and omeprazole worked well for him.',
  'He does not want to keep buying omeprazole over the counter as it becomes expensive over time.',
  'He would like a prescription for omeprazole to get his symptoms back under control.',
  ARRAY[]::text[],
  NULL,
  'SAY NO TO ANY OTHER SYMPTOMS ASKED',
  ARRAY[
    'Ask about the nature of symptoms — onset, duration, triggers, and relieving factors.',
    'Ask whether symptoms are associated with food and whether they are worse at night or when lying down.',
    'Ask about red flag symptoms, including unexplained weight loss, difficulty swallowing (dysphagia), pain on swallowing (odynophagia), vomiting (particularly with blood — haematemesis), black stools (melaena), persistent nausea, or early satiety.',
    'Ask about his previous response to omeprazole and whether Gaviscon provides full relief.',
    'Ask about dietary and lifestyle triggers such as spicy and fatty foods, caffeine, alcohol, and stress.',
    'Ask about recent weight changes and eating habits, particularly late-night meals and takeaway consumption.',
    'Ask about family history of gastrointestinal cancers or significant GI conditions.',
    'Ask about psychosocial factors including stress, current life circumstances, sleep patterns, and emotional wellbeing.',
    'Establish a working diagnosis of dyspepsia — likely GORD.'
  ],
  ARRAY[
    'Offer a face-to-face appointment to examine the abdomen.',
    'Offer H. pylori stool testing.',
    'Offer Omeprazole 20mg once daily.',
    'Discuss lifestyle modifications to help reduce symptoms: reduce intake of takeaway and fatty or spicy foods, avoid eating late at night and allow 2–3 hours before lying down after meals, limit caffeine and alcohol as these can worsen reflux.',
    'Encourage stress-reducing activities such as exercise or relaxation techniques. The Headspace app is available free to NHS workers and can support stress management.',
    'Discuss exercise and consider weight management strategies.',
    'Safety net — if symptoms do not improve after 8 weeks of treatment, or if they worsen despite medication, further investigation will be needed.',
    'Advise that if he develops any red flag symptoms such as difficulty swallowing, unintentional weight loss, vomiting blood, or black stools, he must seek urgent medical attention.'
  ],
  'I''m glad you called in today, Simon, and I appreciate you going through all of that with me. It''s clear you''ve been struggling with these symptoms for a while, and I want to make sure we get the right plan in place for you.

From everything you''ve described — the burning sensation behind your chest, the fact it''s worse after eating and when you lie down, and that Gaviscon offers some relief — this sounds very much like acid reflux, also known as GORD, or gastro-oesophageal reflux disease. What happens is that acid from the stomach travels upward into the food pipe, causing that familiar burning discomfort. It sounds like this is a return of the same problem you''ve had before.

I can prescribe omeprazole 20mg once daily for you. This medication works by reducing the amount of acid your stomach produces, and based on your previous experience it should help bring your symptoms back under control.

Before we start the omeprazole, I''d also like to arrange a simple stool test to check for a bacterium called Helicobacter pylori — often called H. pylori. This bug can sometimes contribute to reflux-type symptoms, and if it''s present, the treatment approach would be slightly different. It''s just a precaution and nothing to worry about.

I''m reassured that you haven''t had any of the more concerning symptoms — no difficulty swallowing, no unintentional weight loss, and no blood in anything you''ve vomited or passed — which is all very good to hear.

That said, the lifestyle side of things is really important here. Things like eating late at night, having a lot of takeaway food, and weight gain can all put extra pressure on the valve at the bottom of the food pipe, making it easier for acid to escape upwards. I''d encourage trying to eat earlier in the evening, leave a couple of hours before lying down after meals, and where possible shift toward lighter home-cooked options. I know that can be harder when life is stressful, and I want you to know I''m mindful of what you''re going through at the moment.

If you''re not feeling significantly better after eight weeks on the omeprazole, or if things worsen, we''d need to look into this further. And please do get in touch promptly if you notice any difficulty swallowing, vomiting blood, blood in your stools, or any unintentional weight loss — those would need urgent attention.',
  ARRAY[
    'Recurrent dyspepsia consistent with GORD in a middle-aged male can be managed with omeprazole 20mg once daily; always test for H. pylori with a stool antigen test before or alongside starting a proton pump inhibitor.',
    'Red flag symptoms requiring urgent investigation include dysphagia, odynophagia, unexplained weight loss, haematemesis, and melaena — their absence is reassuring but must be actively enquired about.',
    'Lifestyle factors including late-night eating, fatty or spicy food, weight gain, caffeine, and alcohol all lower oesophageal sphincter pressure and worsen reflux; addressing these is essential alongside medication.',
    'Psychosocial stressors such as relationship breakdown can drive both symptom exacerbation and unhealthy eating behaviours — these should be sensitively explored as part of a holistic consultation.',
    'Safety net at 8 weeks — if symptoms persist or worsen despite treatment, further investigation such as endoscopy should be considered.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  135,
  'Emergency Contraception Request In Young Person',
  'General Practice',
  'Telephone Consultation',
  false,
  'Jasmine Osei',
  '14-year-old female',
  ARRAY['BMI: 27'],
  ARRAY[]::text[],
  'Patient booked urgent appointment to discuss a personal concern. No recent GP consultations on record.',
  'Urgent request for emergency contraception following unprotected sexual intercourse.',
  'Hi, I need to speak to a doctor today please. I had unprotected sex yesterday and I''m worried I might get pregnant. I want to know if I can get the morning-after pill.',
  'She had unprotected sex at a friend''s party the previous day with a 16-year-old male who is her older brother''s friend. The encounter was consensual. She has previously been sexually active with a 15-year-old boyfriend whom she has recently separated from. Her last menstrual period (LMP) was 3 weeks ago, and she has a regular 28-day cycle. No other episodes of unprotected sex since her LMP. She does not smoke, drink alcohol, or use any illicit substances. She lives with her parents and two older siblings and is currently in Year 10 at school, where things are going well.',
  ARRAY[
    'Only if asked: the sexual contact was with a 16-year-old who is her brother''s friend. The encounter was consensual and she felt she was not pressured.',
    'Only if asked: she has previously been sexually active with a 15-year-old boyfriend she has recently broken up with.',
    'Only if asked about her cycle: her last period was 3 weeks ago and she has a regular 28-day cycle.',
    'Deny any other symptoms or history if asked directly.'
  ],
  'Does not smoke, drink alcohol, or use illicit drugs. Lives at home with her parents and two older siblings. Currently in Year 10 at school and doing well.',
  'She thinks she needs the morning-after pill to prevent pregnancy.',
  'She is worried about getting pregnant and very keen that her parents do not find out she has come to the GP.',
  'She wants emergency contraception today.',
  ARRAY[]::text[],
  NULL,
  'SAY NO TO ANY OTHER QUESTIONS ASKED',
  ARRAY[
    'Establish Fraser competence — assess whether the patient understands the nature, risks, and implications of emergency contraception and sexual activity, and whether she is able to make an informed decision.',
    'Ask when the unprotected sex occurred and how many hours ago, as timing affects the choice of emergency contraception.',
    'Ask whether the sexual contact was consensual and whether there are any concerns about coercion, pressure, or signs of exploitation or abuse.',
    'Ask about her partner''s age to assess whether there are any legal safeguarding implications.',
    'Ask about previous sexual activity — whether this is her first time or if she has been sexually active before.',
    'Ask about her last menstrual period and whether her periods are regular — this is essential for assessing effectiveness of emergency contraception.',
    'Ask whether there have been any other episodes of unprotected sex since her last menstrual period, to ensure complete assessment.',
    'Ask about previous contraceptive use, including condoms or any other method.',
    'Ask about any previous pregnancies or prior use of emergency contraception.',
    'Ask about STI risk factors — whether a condom was used, number of partners, and whether she has ever had STI testing.',
    'Ask about medical history, including any contraindications to emergency contraception such as liver disease or hormone-sensitive conditions.',
    'Ask about any regular medications that may interact with emergency contraception.',
    'Ask about her home situation, relationship with parents, and whether there is a trusted adult she can speak to.',
    'Explore her expectations for the consultation — specifically what she is hoping to receive and any concerns about confidentiality.'
  ],
  ARRAY[
    'Explain the available emergency contraception options: tablets and the intrauterine device (IUD/coil). Tablets work by preventing ovulation, while the coil prevents implantation and can also serve as long-term contraception.',
    'If she chooses the tablet, inform her that it is less likely to be effective in her case given that her LMP was 3 weeks ago on a 28-day cycle, meaning ovulation has likely already occurred. The coil would be a more effective option. Advise her to take a pregnancy test if her period is delayed by more than seven days or is lighter than usual.',
    'Levonorgestrel 1.5mg is recommended for individuals weighing less than 70kg or with a BMI below 26.',
    'For those weighing more than 70kg or with a BMI over 26, a double dose (3mg) is required for optimal effectiveness.',
    'Emphasise the importance of ongoing contraception to prevent future unplanned pregnancies. Briefly outline available options (pill, implant, injection, coil, patch) and provide leaflets for her to read at home.',
    'Discuss the risk of sexually transmitted infections (STIs) following unprotected sex and offer sexual health screening.',
    'Encourage her to involve her parents in the discussion, but if she is not comfortable doing so, respect her decision while ensuring her safety is addressed.',
    'Arrange a follow-up appointment in 2–3 days to discuss ongoing contraception and address any further concerns.',
    'Remind her to take a pregnancy test if her period is delayed by more than seven days or lighter than normal.',
    'Offer a safeguarding referral — because she is under 16, any sexual activity must be assessed from a safeguarding perspective. Discuss with the safeguarding lead. If no concerns about coercion, exploitation, or risk are identified, the focus will be on supportive intervention. If concerns are present, further steps may be taken. Be transparent with her about this process in a kind and non-judgemental way.'
  ],
  'Thank you for getting in touch today, and I''m really glad you felt able to call us. I can hear that you''re worried, and I want you to know that you''ve done the right thing by reaching out. My priority here is to make sure you''re safe and that you get the right support.

You''ve told me you had unprotected sex yesterday and that you''re keen to do something to reduce the chance of pregnancy — that''s completely understandable. Let me explain what options are available to you, Jasmine.

There are two main types of emergency contraception. The first is a tablet, and there are two different types, but both work in a similar way — they delay the release of an egg from your ovary, which helps prevent pregnancy. The second option is a small device called a coil, or IUD, which is placed inside the womb by a nurse or doctor. The coil works differently — it stops a fertilised egg from implanting — and it can also be left in place afterwards as an ongoing method of contraception if you''d like that.

Now, looking at your situation — you mentioned your last period was about three weeks ago, and your cycle is normally 28 days. That means ovulation — when your ovary releases an egg — would typically happen around day 14, which has most likely already occurred. This means that the emergency contraceptive tablet is less likely to be effective for you at this point. The coil would be a much better option and would offer the best protection. I''d like to arrange for you to attend the sexual health clinic today if possible to have the coil fitted. If it cannot be done today, we can still offer you the tablet in the meantime as a bridging measure, and if you''d prefer not to have the coil, I can still prescribe the tablet for you — I just want you to know it may not work as well in your circumstances.

Because of your BMI, I would also prescribe the tablet at a double dose of 3mg rather than the standard 1.5mg, to give you the best chance of it working.

Beyond today, I''d encourage you to think about using contraception regularly going forward, whether that''s the pill, an implant, an injection, or the coil. I''ll send you some leaflets to look through and we can talk more about what might suit you at a follow-up in a couple of days.

I also want to mention the risk of sexually transmitted infections — unprotected sex does carry a risk of catching infections such as chlamydia or gonorrhoea, and I can arrange a check-up for you at the sexual health clinic at the same time.

There is one more thing I need to be open with you about, and I want to explain it in a way that I hope makes sense. Because you are 14, I have a responsibility to think about your safety and wellbeing as part of my role. Under UK law, sexual activity involving someone under 16 needs to be considered from a safeguarding perspective — not to get anyone into trouble, but to make sure you are safe and that nobody has taken advantage of you. I will need to speak to our safeguarding lead about your situation. They will look at things carefully and their main aim is to make sure you have the right support around you. If there are no concerns about pressure or harm, the focus will simply be on helping you stay safe and healthy going forward. I know this might feel a bit daunting, but please know that you are not in any trouble and I am here to help you.',
  ARRAY[
    'Fraser competence must be established before providing emergency contraception or any other treatment to a patient under 16 — assess understanding of the nature, risks, and implications of sexual activity and contraception.',
    'Sexual activity involving a 16-year-old and a 14-year-old is technically a criminal offence under UK law, even if consensual — a safeguarding referral or discussion with the safeguarding lead is mandatory.',
    'Timing of the last menstrual period is critical — with LMP 3 weeks ago on a 28-day cycle, ovulation has likely occurred and the emergency contraceptive tablet (levonorgestrel or ulipristal) is less effective; the IUD (copper coil) is the preferred option.',
    'Levonorgestrel dose must be adjusted for BMI: 1.5mg for those under 70kg or BMI below 26; double dose (3mg) for those over 70kg or BMI above 26.',
    'Offer STI screening, ongoing contraception discussion, and a follow-up appointment in 2–3 days as part of holistic care.',
    'Advise a pregnancy test if the next period is delayed by more than seven days or lighter than usual, regardless of which emergency contraception method is used.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  136,
  'Chronic Constipation in Child',
  'Paediatrics',
  'Telephone Consultation',
  false,
  'Ella Chambers',
  '4-year-old female',
  ARRAY[]::text[],
  ARRAY[]::text[],
  'Telephone consultation by Dr Priya Nair (Clinical Practitioner) one month ago. Mother reported child had not opened her bowels for 10 days. No red flags documented, no blood in stool. Eating and drinking satisfactorily. No examination performed at that appointment. Impression: constipation. Plan: encourage high-fibre diet and fluids, commence Movicol 2 sachets daily. Safety-netting and worsening advice given. Father (Tom Chambers) calling today to discuss ongoing concerns.',
  'Father calling to discuss his daughter''s ongoing bowel problems and brownish staining noted in her underwear.',
  'Hi, I''m calling about my daughter Ella. She''s been struggling with constipation for about five weeks now, and we started the Movicol the GP prescribed last month but I''m not really seeing much improvement. The thing that''s really worried me is that I''ve been noticing brownish stains in her knickers that look a bit like diarrhoea. I don''t know what''s going on — she was already constipated so this doesn''t make sense to me.',
  'Ella passes hard stools, often only every few days. The brown staining in her underwear is new and has appeared since starting the Movicol without significant improvement in bowel frequency. No vomiting, no blood in stools, no unexplained weight loss, no abdominal distension, no lethargy, no fever. She occasionally complains of tummy pain but plays normally afterwards. She is a picky eater and prefers processed and fast food. The family is busy and often relies on convenience meals and takeaways. She does not eat much fruit or vegetables. She drinks some water but generally prefers juice. Movicol 2 sachets daily has been prescribed but the father feels there has been little noticeable improvement.',
  ARRAY[
    'Only if asked about stool habits: Ella passes hard stools, sometimes only once every few days.',
    'Only if asked about symptoms: no vomiting, no blood in stools, no weight loss, no abdominal swelling, no lethargy, no fever.',
    'Only if asked about pain: she occasionally complains of tummy pain but plays normally afterwards.',
    'Only if asked about diet: she is a picky eater who prefers McDonald''s and processed foods. The family is often busy and relies on fast food. She eats little fruit or vegetables.',
    'Only if asked about fluids: she drinks some water but prefers juice.',
    'Only if asked about medication: she has been on Movicol 2 sachets daily since last month''s call, but the father has not noticed much improvement.',
    'Deny any other symptoms if asked directly.'
  ],
  'Ella lives with her father Tom, her mother, and two older siblings. She attends reception class and is doing well at school.',
  'The father is not sure what is going on — he expected the constipation to be improving, not for diarrhoea-like staining to appear.',
  'He is worried that something might be seriously wrong with her bowels.',
  'He wants to understand what is causing the staining and what else can be done to help Ella.',
  ARRAY[]::text[],
  NULL,
  'SAY NO TO ANY OTHER QUESTIONS ASKED',
  ARRAY[
    'Ask about the frequency of Ella''s bowel movements and how often the soiling episodes occur.',
    'Ask about the consistency of her stools — whether they are hard, soft, or loose — and whether she experiences straining or pain when passing stools.',
    'Ask about the nature of the staining in her underwear — colour, consistency, and whether it tends to occur at certain times of day.',
    'Ask about associated symptoms including abdominal pain, bloating, vomiting, blood in stools, weight loss, or lethargy.',
    'Ask about her diet — fruit, vegetable, fibre, and fluid intake.',
    'Ask about her fluid preferences and how much water she drinks each day.',
    'Ask about the Movicol — whether she is taking it consistently and at what dose, and whether the parents have noticed any change since starting it.',
    'Ask about family history of bowel problems or any relevant medical background.',
    'Explain the likely diagnosis of faecal impaction with overflow soiling.'
  ],
  ARRAY[
    'Offer a face-to-face appointment to examine the abdomen.',
    'Increase Movicol gradually to clear the impaction — four sachets daily for 2 days, then six sachets daily for 2 days, then eight sachets daily. Continue until impaction resolves.',
    'Encourage a high-fibre diet including fruit, vegetables, and whole grains.',
    'Advise increasing fluid intake, with more water and less juice.',
    'Advise reducing fast food and including home-cooked meals where possible.',
    'Encourage regular toilet time — sitting on the toilet after meals is particularly helpful to use the gastrocolic reflex.',
    'Offer resources on childhood constipation and diet advice — signpost to the ERIC website.',
    'Review in 1–2 weeks to check the response to the Movicol adjustment.',
    'Safety netting — advise the father to seek urgent review if Ella develops severe pain, vomiting, persistent bloating, or blood in her stools.'
  ],
  'Thank you for calling in today, Mr Chambers, and I''m glad you got in touch because what you''re describing is really helpful to understand.

I know it must seem confusing — and perhaps worrying — to see what looks like diarrhoea when Ella has actually been constipated. I want to reassure you that this is actually a recognised pattern, and it has a specific explanation.

What is most likely happening is something called overflow soiling, which is sometimes also referred to as faecal impaction. When a large, hard mass of stool becomes stuck in the lower part of the bowel, softer stool from higher up in the digestive system can leak around the blockage. That leakage is what''s appearing as the brownish staining in her underwear. It can look just like loose stool or diarrhoea, which is why it seems so puzzling at first.

This is actually a relatively common problem in young children, and the good news is that it is very treatable. The key is that we need to clear the blockage first, and to do that, we need to increase the dose of Movicol significantly for a period. Rather than staying at two sachets a day, the plan would be to increase it to four sachets daily for two days, then six sachets for two days, and then eight sachets each day until the impaction has fully cleared and her stools become soft and regular. Once that has happened, we can reduce the dose down to a maintenance level.

Alongside the Movicol, it would make a real difference to try to introduce more fibre into Ella''s diet — things like fruit, vegetables, and wholegrain foods. I completely understand that with a busy household this can feel like a challenge, especially if she''s a picky eater, but even small changes can make a meaningful difference over time. Encouraging her to drink more water rather than juice is also a very straightforward step that helps.

It is also worth encouraging her to sit on the toilet regularly, particularly after meals, as the digestive system is naturally more active at that time. This helps reinforce a healthy bowel habit.

I''d like to arrange for Ella to be seen face to face in the next day or two so we can examine her tummy and make sure there are no other concerns. I''ll also send you a link to a website called ERIC, which has brilliant resources and practical advice for parents managing childhood constipation. And I''d like to speak with you again in one to two weeks to see how she is getting on with the increased dose.

Please do call us sooner if she develops severe tummy pain, starts vomiting, becomes very bloated, or if you notice any blood in her stools — those would need to be seen promptly.',
  ARRAY[
    'Overflow soiling — the passage of loose stool around a faecal impaction — can mimic diarrhoea and must be recognised as a sign of impaction rather than a new problem; it is a common presentation in young children with chronic constipation.',
    'Faecal impaction in children is managed by escalating Movicol doses (four sachets daily for 2 days, then six for 2 days, then eight daily) until disimpaction occurs, before stepping down to a maintenance dose.',
    'Dietary interventions — increasing fibre, reducing juice and processed foods, and encouraging water intake — are essential adjuncts to laxative therapy and should be discussed with parents.',
    'Encouraging regular post-meal toilet sitting capitalises on the gastrocolic reflex and helps establish healthy bowel habit in children.',
    'Signpost to the ERIC (Education and Resources for Improving Childhood Continence) website as a trusted patient and family resource for childhood constipation.',
    'Safety net for urgent review if the child develops severe abdominal pain, vomiting, persistent bloating, or rectal bleeding.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  137,
  'Chronic Cough in Young Adult',
  'Respiratory',
  'Video Consultation',
  false,
  'Rachel Alderton',
  '37-year-old female',
  ARRAY['No known medical history','No regular medications'],
  ARRAY[]::text[],
  'No recent GP consultations on record. Patient booked routine appointment to discuss a persistent cough.',
  'Persistent dry cough lasting eight weeks with no sign of improvement.',
  'Hi, thanks for seeing me. I''ve had this dry cough now for about eight weeks and it just doesn''t seem to be getting any better. It''s really starting to frustrate me and I''m starting to wonder if something is actually wrong.',
  'Dry cough, worse at night. No shortness of breath, no chest tightness, no wheeze, no weight loss. She also describes a sensation of something dripping down the back of her throat, a need to clear her throat frequently, a persistent tickling sensation in the throat, and an occasional sour taste in her mouth. Symptoms are generally worse at night. No fever, no haemoptysis, no night sweats.',
  ARRAY[
    'Only if asked about cough characteristics: it is a dry cough, worst at night, and has been present for eight weeks without improvement.',
    'Only if asked about associated symptoms: she notices a sensation of fluid draining into the back of her throat, frequent throat clearing, a tickling feeling in the throat, and a sour taste in her mouth. Symptoms worse at night.',
    'Deny any other symptoms if asked directly.'
  ],
  'Non-smoker. Drinks alcohol occasionally at Christmas and on bank holidays only. Lives with her husband. Works as a customer services manager at a retail company.',
  'She is not sure what is causing the cough and cannot identify any obvious trigger.',
  'She is frustrated because the cough is persistent and disruptive. She is also worried it might be a sign of something more serious.',
  'She wants to understand what is causing the cough and would like something to help relieve it.',
  ARRAY[]::text[],
  NULL,
  'SAY NO TO ANY OTHER QUESTIONS ASKED',
  ARRAY[
    'Ask about the duration and progression of the cough — how long it has been present and whether it has improved, stayed the same, or worsened.',
    'Ask about cough characteristics — whether it is dry or productive, whether it is worse at a particular time of day, and whether anything triggers or relieves it.',
    'Ask about associated symptoms including recent viral illness, wheeze, fever, postnasal drip (sensation of mucus draining from the back of the nose into the throat), frequent throat clearing, nasal congestion, or changes in taste.',
    'Ask about reflux symptoms — heartburn, and whether the cough is worse during or after eating.',
    'Ask about red flag symptoms — unexplained weight loss, haemoptysis, and night sweats.',
    'Ask about a history of allergies or asthma.',
    'Ask about exposure to triggers such as cigarette smoke, pollen, dust mites, or mould.',
    'Ask about occupational exposures — for example, dust or chemical fumes.',
    'Ask about any recent new medications, particularly ACE inhibitors, which are a well-recognised cause of dry cough.',
    'Ask about smoking history and home circumstances.',
    'Elicit ICE — ideas, concerns, and expectations.',
    'Give a working diagnosis of postnasal drip as the likely cause of the cough.'
  ],
  ARRAY[
    'Offer a face-to-face appointment to examine the chest and nostrils.',
    'Offer a non-sedating antihistamine (e.g., loratadine or cetirizine) and decongestants (e.g., pseudoephedrine). These are available over the counter. Decongestants should be used for a short duration only (maximum 7 days) to avoid rhinitis medicamentosa.',
    'If sinus symptoms are present — nasal congestion, runny nose, or facial pain — consider prescribing an intranasal corticosteroid spray.',
    'Advise avoiding throat irritants such as strong perfumes and smoky environments.',
    'Review in 2 weeks — symptoms typically begin to improve within this timeframe.',
    'Safety net clearly — advise that if symptoms are worsening, she notices blood in her sputum, she feels generally unwell, develops breathlessness, or loses weight unexpectedly, she should seek urgent medical advice.',
    'Signpost to the NHS website for further patient information on postnasal drip.'
  ],
  'Thank you for coming in today, and I can completely understand why an eight-week cough is starting to concern you. Let me explain what I think is going on based on everything you''ve described.

The combination of symptoms you''re experiencing — that feeling of something trickling down the back of your throat, the sour taste in your mouth, frequently needing to clear your throat, and a dry cough that''s particularly troublesome at night — all points strongly towards a condition called postnasal drip. This is where the lining of the nose or sinuses produces excess mucus that, instead of coming out through the nostrils, drips down the back of the throat. That constant irritation is what triggers the cough and the need to keep clearing your throat. It''s often worse when you''re lying down, which fits with your symptoms being more bothersome at night.

Postnasal drip can be triggered by things like a lingering cold, sinus irritation, or mild allergic reactions to things in the environment. It sounds unpleasant, Rachel, but the reassuring news is that it is treatable and very rarely a sign of anything more serious.

To help manage this, I''d recommend starting with a non-sedating antihistamine — something like loratadine or cetirizine — which you can pick up over the counter at a pharmacy. I''d also suggest using a short course of a nasal decongestant, such as pseudoephedrine. It''s important not to use the decongestant for more than seven days at a time, as using it for longer can actually make nasal symptoms worse in the long run — this is known as rebound congestion.

If you find that nasal symptoms like a blocked or runny nose or any facial pressure become more prominent, it would be worth coming back to try a nasal steroid spray, which I can prescribe and which can be very effective for postnasal drip.

I''d also encourage you to avoid strong perfumes and smoky environments as these can irritate the nasal passages further.

It would be helpful for you to come in face to face so I can listen to your chest and have a look at your nose and throat as well. Let''s aim for a review in two weeks. If things are going in the right direction, that''s great. But if you notice any blood when you cough, you start feeling breathless, you feel generally unwell, or you lose any weight without trying, please don''t wait for the review — contact us promptly or seek urgent advice.',
  ARRAY[
    'A dry cough persisting for more than 8 weeks in a non-smoker without other respiratory symptoms is commonly caused by postnasal drip, GORD, or ACE inhibitor use — enquire about all three in the history.',
    'Postnasal drip presents with a sensation of mucus draining into the throat, frequent throat clearing, a tickling sensation, and cough worse at night or on lying down.',
    'First-line treatment for postnasal drip includes a non-sedating antihistamine (loratadine or cetirizine) and a short course of decongestant (pseudoephedrine — maximum 7 days to avoid rhinitis medicamentosa); intranasal corticosteroids can be added if sinus symptoms are prominent.',
    'Red flag symptoms requiring urgent assessment in a patient with cough include haemoptysis, unexplained weight loss, night sweats, new breathlessness, and persistent hoarseness.',
    'Always ask about ACE inhibitor use in any patient presenting with a new dry cough — this is a very common drug side effect and is dose-independent.',
    'Review at 2 weeks is appropriate; symptoms should begin to improve within this timeframe if postnasal drip is the cause.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  138,
  'Hirsutism',
  'Dermatology',
  'Telephone Consultation',
  false,
  'Chloe Baxter',
  '22-year-old female',
  ARRAY['BMI: 30'],
  ARRAY[]::text[],
  'Patient booked routine appointment to discuss concerns. No recent GP consultations on record.',
  'Excess facial hair growth over the past ten months, associated with irregular menstrual cycles and difficulty losing weight.',
  'Hi, I''ve booked this call because I''ve been getting a lot of unwanted hair on my face — mainly on my upper lip and chin — and it just seems to be growing really fast. It''s been going on for about ten months now and it''s really affecting my confidence. I was hoping you could help me understand why it''s happening.',
  'Excess hair growth on the face, particularly the upper lip and chin, present for approximately 10 months. She currently removes it using hair removal cream. She has also noticed irregular periods for over a year — cycles are sometimes 42 days or longer, and occasionally she goes two months or more without a period. Her first period was at age 14. She has difficulty losing weight despite trying. She feels she gains weight very easily. No other symptoms reported.',
  ARRAY[
    'Only if asked about hair growth: it affects the upper lip and chin primarily; she removes it with hair removal cream.',
    'Only if asked about her menstrual cycle: irregular periods for over a year, sometimes cycles are 42 days or longer, sometimes no period for over 2 months. First period at age 14.',
    'Only if asked about weight: difficulty losing weight despite efforts; she gains weight easily.',
    'Only if asked about other symptoms: nil other symptoms.',
    'Deny any other symptoms if asked directly.'
  ],
  'Non-smoker, does not drink alcohol. Works as a beauty therapist. In a relationship but not currently using any contraception.',
  'She has no idea what is causing the excess hair growth.',
  'She is worried about how quickly the hair is growing and the impact it is having on her appearance and confidence.',
  'She wants to understand what is going on and whether there is a treatment that can reduce the hair growth.',
  ARRAY[]::text[],
  NULL,
  'SAY NO TO ANY OTHER QUESTIONS ASKED',
  ARRAY[
    'Ask about the onset, progression, and distribution of excess hair growth — not just the face but also the chest, abdomen, lower back, upper arms, and thighs.',
    'Ask how the hair growth has affected her daily life, confidence, and emotional wellbeing.',
    'Ask what she has already tried for hair removal and whether any methods have helped.',
    'Ask about family history of similar symptoms, excess hair growth, or hormonal conditions.',
    'Ask about conditions associated with hirsutism, particularly PCOS — including menstrual irregularities (cycle length, missed periods), and note the importance of asking about the age at first period (menarche). An ultrasound scan should not be used to diagnose PCOS in individuals who are less than 8 years after menarche, as multi-follicular ovaries are common at this stage.',
    'Ask about weight changes and difficulty losing weight.',
    'Ask about other signs of hormonal imbalance such as acne, scalp hair thinning, or deepening of the voice.',
    'Ask about social history — smoking, alcohol, occupation, relationship status, and current contraceptive use.',
    'Ask about over-the-counter or supplementary medications, including anabolic steroids.',
    'Give a working diagnosis of hirsutism likely secondary to PCOS.'
  ],
  ARRAY[
    'Offer investigations — bloods including HbA1c, lipid profile, thyroid function, testosterone, LH, FSH, and free androgen index.',
    'Offer lifestyle advice — regular exercise and a healthy diet. Inform the patient that even modest weight loss can significantly improve symptoms. A healthy diet and regular physical activity can help rebalance hormones and regulate periods.',
    'For hirsutism — offer simple hair removal methods such as shaving or waxing initially. If these are already being used or are insufficient, offer topical eflornithine for facial hirsutism. Note that eflornithine is not licensed for use in those under 19 years of age or in pregnant women.',
    'Inform her that a combined oral contraceptive pill, if she is open to it, can help regulate her periods and reduce hair growth over time.',
    'Laser hair removal is an option that can provide longer-term results but is not routinely available on the NHS.',
    'Arrange a review following blood test results to discuss findings and further management.'
  ],
  'Thank you for calling today and for explaining what you''ve been going through. I can understand how distressing it must feel to notice changes in your body like this, especially when they are affecting how you feel about yourself day to day.

From everything you''ve described — the excess hair growth on your face, the irregular periods, and the difficulty managing your weight — I think it''s very likely that you have a condition called Polycystic Ovary Syndrome, or PCOS. I want to explain what that means in a way that hopefully makes sense.

PCOS is a common hormonal condition that affects the way the ovaries work. In women with PCOS, there tends to be a hormonal imbalance involving higher-than-normal levels of androgens — these are sometimes called male hormones, although all women have them in small amounts. When these levels are elevated, it can cause unwanted hair growth, particularly on the face, disrupt the regularity of your periods, and make it harder to lose weight. It''s actually much more common than people often realise, Chloe, and importantly, it can be managed.

The first thing I''d like to do is arrange some blood tests to get a clearer picture of what is happening with your hormones. These will include tests for testosterone, LH, FSH, and free androgen index — all of which help us understand the hormonal side of things. I''ll also check your thyroid function, HbA1c, and cholesterol levels, as these can be affected in women with PCOS.

While we wait for those results, there are some things that can genuinely help. Lifestyle measures — a balanced diet and regular exercise — can make a real difference with PCOS, even if it can feel frustrating when weight hasn''t been shifting. Even a modest reduction in weight can help bring hormones back into a better balance and improve both your periods and the hair growth.

For the hair itself, if hair removal cream has been your go-to method, that''s fine to continue. However, if you find you want something more effective, there is a prescription cream called eflornithine which can be applied directly to the face and works by slowing down the rate at which hair grows. It won''t remove existing hair but can reduce regrowth significantly over time.

Another option worth discussing is the combined contraceptive pill. If you are open to using contraception, certain combined pills can help regulate your periods and over time reduce the effects of the androgens on hair growth. This is something we can explore further once your blood results are back.

Laser hair removal is also an option for longer-term results, though this is generally something you would access privately rather than through the NHS.

Let''s get the blood tests sorted first and then we''ll have a much better basis for planning your care. I''ll arrange a follow-up once the results are in so we can go through them together and agree on next steps.',
  ARRAY[
    'Hirsutism in a young woman with irregular periods and difficulty losing weight is PCOS until proven otherwise — the combination of these three features forms the diagnostic triad used in PCOS assessment.',
    'An ultrasound should not be used to diagnose PCOS in individuals within 8 years of menarche, as multi-follicular ovaries are physiologically normal at this stage of life — always ask about age at first period.',
    'Initial investigations for suspected PCOS should include testosterone, LH, FSH, free androgen index, HbA1c, lipid profile, and thyroid function tests.',
    'Eflornithine topical cream can be offered for facial hirsutism in women who find standard hair removal methods inadequate; it is not licensed for use under the age of 19 or in pregnancy.',
    'The combined oral contraceptive pill can help regulate menstrual cycles and reduce androgen-driven symptoms such as hirsutism over time — offer this as part of the management discussion.',
    'Lifestyle modification — particularly weight loss and regular exercise — is the cornerstone of PCOS management and can significantly improve both hormonal balance and symptom burden, even with modest weight reduction.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  139,
  'Syncopal Episode In Young Adult',
  'Cardiology',
  'Video Consultation',
  false,
  'Hannah Clarke',
  '24-year-old female',
  ARRAY['Hay fever','No known drug allergies'],
  ARRAY[]::text[],
  'North West Ambulance Service To: General Practitioner Re: Hannah Clarke, 24-year-old female Dear Doctor, This is to inform you that the North West Ambulance Service attended Hannah Clarke following a transient loss of consciousness while volunteering at a local care home. She reported feeling lightheaded and dizzy before losing consciousness for approximately 2–3 minutes. Witnesses noted brief, mild shaking, but there was no tongue biting or urinary incontinence. On regaining consciousness, she felt tired but had no confusion or neurological symptoms. Examination Findings: Blood Pressure: 118/76 mmHg Pulse: 72 bpm, regular Neurological Examination: No focal deficits Hannah was advised to attend A&E for further assessment, but she declined, expressing her preference to book an appointment with her GP instead. Please review as appropriate. Best regards, Tom Whitfield – Attending Paramedic North West Ambulance Service',
  'Patient has booked an appointment following a witnessed collapse at a local care home while volunteering. She was reviewed by paramedics at the time but declined hospital transfer.',
  'Hi, I booked this appointment because I fainted at the care home where I volunteer. I felt really dizzy and then I just went. Apparently I was out for a couple of minutes.',
  'If asked about how she felt after waking up: she felt tired but recovered after a short while. No confusion, no memory loss, no difficulty speaking. The paramedics checked her over but she didn''t want to go to A&E as she didn''t feel it was necessary.',
  ARRAY[
    'If asked about what she was doing beforehand: she had been standing at the reception desk for about an hour, helping with paperwork and greeting visitors.',
    'If asked about warning signs: she felt lightheaded and a bit sick just before passing out. No sudden onset without warning.',
    'If asked about what happened during the episode: bystanders said she had some mild shaking but it was brief. No tongue biting, no loss of bladder control.',
    'If asked about previous episodes: this is the first time it has happened.',
    'If asked about recent illness: no recent infections, chest problems, or flu-like symptoms.',
    'If asked about chest pain or palpitations: none.',
    'If asked about family history: no family history of epilepsy, sudden death, or heart conditions. Her cousin does have epilepsy, which is why she is worried.',
    'If asked about last menstrual period: two weeks ago, regular cycles, no chance of pregnancy. Not sexually active.'
  ],
  'Non-smoker, does not drink alcohol. Lives with her parents and a younger brother. Not currently in employment – she is taking a gap year before starting university. Not sexually active.',
  'She is not sure why this happened. She is worried it could be a seizure because her cousin has epilepsy.',
  'She wants to know whether it is safe for her to drive, as she is planning to start work as a delivery driver over the summer.',
  'She would like a clear explanation of what happened and reassurance about whether she needs any tests or follow-up.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided.',
  ARRAY[
    'Ask about the syncopal episode itself – onset, duration, and any warning signs beforehand such as lightheadedness, nausea, sweating, or visual changes',
    'Ask what the patient was doing prior to the episode – for example, prolonged standing, heat exposure, or emotional stress',
    'Ask whether there was loss of consciousness and how long it lasted',
    'Ask whether there were any witnesses and what they observed – for example, shaking, jerky movements, cyanosis',
    'Ask about the post-ictal period – was there confusion, tongue biting, urinary incontinence, or injury?',
    'Ask about previous syncopal episodes',
    'Ask whether the patient had been unwell recently – for example, recent infections, dehydration, reduced oral intake',
    'Ask about associated symptoms: chest pain, palpitations, breathlessness',
    'Ask about social history including smoking, alcohol, occupation, and driving',
    'Ask about family history of syncope, epilepsy, or sudden unexplained death',
    'Ask about last menstrual period and confirm no possibility of pregnancy',
    'Make a diagnosis of likely vasovagal syncope'
  ],
  ARRAY[
    'Offer a face-to-face appointment to assess – check heart sounds, pulse, blood pressure, and perform a neurological examination',
    'Offer investigations including ECG to rule out arrhythmia, FBC, U+Es, LFTs, and TFTs',
    'Advise on potential triggers that may have caused the episode and suggest strategies to avoid them. If triggers are unclear, recommend keeping a symptom diary noting what she was doing and when episodes occur',
    'Advise staying well hydrated, avoiding prolonged standing, and if feeling faint, to lie down and raise her legs to improve blood flow to the brain',
    'As the patient is a Group 1 driver, driving is generally not restricted and there is no requirement to inform the DVLA, provided the episode occurred while standing. However, she should refrain from driving until a full assessment has confirmed this was a simple faint and not due to another underlying cause',
    'Safety-net – advise the patient to seek urgent medical attention if she experiences chest pain, palpitations, breathlessness, or if she has another episode unexpectedly'
  ],
  'Thank you for telling me what happened, Hannah – it sounds like quite a frightening experience, and I completely understand why you wanted to get it checked out. Based on everything you''ve described, I want to reassure you that what happened sounds very much like a simple faint, which we call vasovagal syncope, rather than a seizure.

Let me explain why. You mentioned feeling dizzy and lightheaded before you passed out, which is a very typical warning sign of a faint. The episode only lasted a couple of minutes, and when you came round, you felt tired but were not confused or disoriented. There was no tongue biting and no loss of bladder control. These features are all very reassuring and more in keeping with a faint than with epilepsy.

I know you mentioned your cousin has epilepsy, and it''s natural to worry about that. The key difference is that in a seizure, people usually feel very confused and drowsy for a prolonged period afterwards, and tongue biting or incontinence is more common. The mild shaking that bystanders noticed can actually happen with a faint too – it doesn''t necessarily mean it was a seizure.

Fainting happens when the body temporarily overreacts to a trigger – in your case, standing for a prolonged period at the reception desk. This causes a brief drop in blood pressure and a temporary reduction in blood flow to the brain. It''s actually very common and in most cases completely harmless.

In terms of what happens next, I''d like to bring you in for a face-to-face appointment so I can check your heart sounds, blood pressure, and do a brief neurological check. I''d also like to arrange a few blood tests and an ECG, which is a heart tracing, just to make sure there''s nothing else contributing to what happened.

Regarding driving – I can see this is important to you given the job you''re planning. Because your episode happened while you were standing, and provided our assessment confirms it was a simple faint, you would not normally need to inform the DVLA and would generally be safe to drive. However, I would ask you to hold off on starting that job until we''ve completed the assessment and I''ve given you the all-clear, just to be safe.

In the meantime, please make sure you stay well hydrated, try not to stand still for long periods, and if you ever feel that dizzy sensation coming on again, sit or lie down straight away and raise your legs. If you ever experience chest pain, palpitations, or have another collapse, please seek urgent medical attention.',
  ARRAY[
    'Vasovagal syncope is the most common cause of transient loss of consciousness in young adults and is characterised by prodromal symptoms (lightheadedness, nausea), brief duration, and rapid recovery without post-ictal confusion.',
    'Key features that help distinguish vasovagal syncope from a seizure include: absence of post-ictal confusion, no tongue biting, no urinary incontinence, and a clear precipitating trigger such as prolonged standing.',
    'Mild brief shaking can occur in vasovagal syncope (convulsive syncope) and does not confirm epilepsy – do not over-diagnose based on witnessed movements alone.',
    'Initial investigations for a first syncopal episode should include ECG (to exclude arrhythmia), FBC, U+Es, LFTs, and TFTs.',
    'For Group 1 drivers (car and motorcycle), typical vasovagal syncope while standing does not require DVLA notification and driving is generally not restricted, but the patient should avoid driving until a full assessment confirms the diagnosis.',
    'Safety-netting is essential: advise the patient to seek urgent review if chest pain, palpitations, breathlessness, or further unexpected episodes occur.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  140,
  'Amenorrhea In A Woman On Desogestrel',
  'Gynaecology & Women''s Health',
  'Telephone Consultation',
  false,
  'Karen Mitchell',
  '49-year-old female',
  ARRAY['Desogestrel (started 6 months ago)','Cervical screening up to date – last smear 5 months ago, reported as normal'],
  ARRAY[]::text[],
  'No recent entries. Patient booked a routine telephone consultation to discuss concerns.',
  'Patient is calling to discuss the absence of her periods over the past two to three months. She has never experienced this before and is unsure whether it is something to be concerned about.',
  'Hi Doctor, I just wanted to speak to someone because I haven''t had a period for the past two or three months, and I''m not really sure why. It''s never happened to me before, so I wanted to check whether it''s something I should be worried about.',
  'She started Desogestrel six months ago after beginning a new relationship. Her periods were initially regular for the first two months, became lighter and shorter during the third month, and then stopped completely over the past three months. Prior to starting the pill her periods were regular every 28 days with no history of menstrual problems.',
  ARRAY[
    'If asked about tiredness: she has occasionally felt more tired than usual, but it has not affected her ability to work or manage daily life.',
    'If asked about joint pains: she has noticed some generalised joint aches, though they are not severe and not limiting her daily activities.',
    'If asked about mood: mostly stable, but over the last three months she has noticed feeling more irritable on some days.',
    'If asked about night sweats or hot flushes: she occasionally has night sweats but is not sure whether these are hot flushes.',
    'If asked about weight, palpitations, or appetite: no weight loss, no palpitations, no changes in appetite.',
    'If asked about pill adherence: she has been taking Desogestrel consistently without missing any doses.'
  ],
  'She works as a project manager, a role that involves long hours and frequent travel between sites. No recent stressors or significant lifestyle changes. She does not smoke or drink alcohol. She lives with her new partner of seven months. She is sexually active and has unprotected intercourse. She has three children and does not wish to have more.',
  'She is not sure what is causing the absence of her periods. She wonders whether it could be the start of the menopause, especially since her older sister went through the menopause at 46. She has also read online that Desogestrel can cause periods to stop, though she is not certain.',
  'She is concerned about why her periods have stopped.',
  'She would like the GP to explain the possible causes of her symptoms and would also like a blood test to confirm whether she is going through the menopause.',
  ARRAY[]::text[],
  'If the doctor mentions menopause, ask: "If this might be the menopause, does that mean I can stop taking the pill?"',
  'SAY NO TO ANY OTHER QUESTIONS ASKED.',
  ARRAY[
    'Ask about menstrual history – when was her last menstrual period, was it regular previously, and whether there has been any spotting or bleeding in between',
    'Ask about contraceptive use (Desogestrel) – has she missed any pills, and has she noticed any side effects from the medication',
    'Signpost before asking personal questions – ask whether she is sexually active and how many partners she has',
    'Ask whether there is any chance she could be pregnant and whether she has done a pregnancy test',
    'Ask about any abdominal pain, particularly if pregnancy is being considered',
    'Ask about menopausal symptoms including hot flushes, mood changes, night sweats, vaginal dryness, tiredness, and joint aches',
    'Ask about systemic symptoms to help rule out thyroid disease, including weight loss, palpitations, and hair thinning',
    'Ask about social history including smoking, alcohol use, and occupation',
    'Explore the patient''s ideas, concerns, and expectations',
    'Give a diagnosis of potential Desogestrel side effects or perimenopause'
  ],
  ARRAY[
    'Do not offer a blood test to check FSH, as FSH levels fluctuate at this age (46–50) and are not a reliable indicator of menopause',
    'Advise a urine pregnancy test to rule out pregnancy, as she is having unprotected sex and no contraceptive method is 100% effective',
    'Inform her that contraception should be continued until two years after her last natural period if under 50, or one year if over 50',
    'Advise staying well hydrated and maintaining a balanced diet to support energy levels',
    'Explain that menopausal symptoms can be managed with both hormonal and non-hormonal options, and offer to discuss these further if she is interested',
    'Advise that if she develops new symptoms or has any concerns in the meantime, she should seek medical advice promptly'
  ],
  'Thank you for getting in touch about this, Karen – I completely understand why you''d want to check in when something like this changes. Let me take you through what I think could be going on.

There are two main reasons why your periods may have stopped. The first is the Desogestrel pill you started six months ago. This is a progestogen-only pill, and one of its well-known effects is that it can reduce or completely stop periods in some women, particularly after the first few months of use. This is not harmful – it''s simply how the medication works in many people. So the fact that your periods gradually became lighter and then stopped is actually a pattern we see quite commonly with this pill.

The second possibility is that your body may be going through the early stages of the perimenopause – that''s the transition phase leading up to the menopause, when hormone levels start to change. At 49, and with your sister having gone through the menopause at 46, it would be entirely plausible for you to be starting this transition now. The symptoms you''ve described – the occasional tiredness, the joint aches, feeling a little more irritable, and the night sweats – can all be early signs of perimenopause.

You mentioned you''d like a blood test to confirm whether you''re menopausal, and that''s a very understandable request. However, in women over the age of 45, we don''t routinely use hormone blood tests to diagnose menopause. This is because hormone levels – particularly FSH – fluctuate considerably during the perimenopausal years, which means a single result can be misleading. Instead, we tend to make the diagnosis based on your age, your symptoms, and the pattern of your periods, which in your case are all pointing in the same direction.

One thing we do need to rule out is pregnancy. I know you''ve been taking your pill consistently, but no method of contraception is 100% effective. Given that you''re having unprotected sex, I''d recommend doing a simple urine pregnancy test just to be safe.

On the question of stopping contraception – this is something I know can feel confusing, particularly if you suspect the menopause is underway. The guidance is that contraception should be continued until at least two years after your last natural period if you are under 50, or one year if you are over 50. So even if this is perimenopause, it would be important to continue the Desogestrel for now.

If you do develop any new or worsening symptoms, or if you have any further concerns, please don''t hesitate to get back in touch. We can also have a longer conversation about managing any menopausal symptoms whenever you feel ready.',
  ARRAY[
    'Desogestrel, a progestogen-only pill, frequently causes reduced or absent periods and may mask the menstrual changes typically associated with perimenopause – this is a common cause of secondary amenorrhoea in women in their late 40s.',
    'Routine FSH testing is not recommended for diagnosing menopause in women aged 46–50, as hormone levels fluctuate significantly during the perimenopausal transition, making results unreliable.',
    'FSH testing may be appropriate in women aged 40–45 with menopausal symptoms and cycle changes, women under 40 with suspected premature ovarian insufficiency, and women over 50 using progestogen-only contraception.',
    'Contraception should be continued for two years after the last natural period if under 50, or one year if over 50 – even if menopause is suspected.',
    'Pregnancy must always be excluded in women presenting with secondary amenorrhoea, regardless of contraceptive use, as no method is 100% effective.',
    'Early perimenopausal symptoms such as irritability, joint aches, and night sweats may precede complete cessation of periods and should be explored when assessing women in this age group.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  141,
  'Abnormal ECG',
  'Cardiology',
  'Telephone Consultation',
  false,
  'George Whitfield',
  '67-year-old male',
  ARRAY['Hypertension','Previous ischaemic stroke (8 months ago)'],
  ARRAY[]::text[],
  'Routine medication review with Clare Patel (Clinical Pharmacist). Patient attended for routine medication check and reconciliation. On examination: pulse felt irregular. Plan: Discussed with duty GP who requested an ECG and booked the patient a follow-up appointment with a GP. ECG performed by Jenny Hartley (Healthcare Assistant). BP: 135/85 mmHg, Pulse: 97 bpm (irregular). CHA₂DS₂-VASc Score: 4. ORBIT Score: 1 (bloods done 3 months ago used in this calculation). Patient booked a telephone appointment to discuss ECG results and further management. Current medications: Ramipril 5mg OD, Amlodipine 10mg OD, Atorvastatin 80mg OD, Clopidogrel 75mg OD.',
  'Patient has booked a telephone consultation to discuss his recent ECG result following detection of an irregular pulse during a routine medication review.',
  'Hello, I was asked to ring in about my ECG results. I had the heart tracing done a few days ago and I''m calling to find out what it shows.',
  'He is not sure what is going on. He has been feeling occasional racing of his heart, usually when he is sitting or resting, and this has been happening on and off for around five months. He did not think much of it and assumed it was nothing serious.',
  ARRAY[
    'If asked about associated symptoms: no chest pain, no breathlessness, no dizziness.',
    'If asked about recent illness: nothing of note recently.',
    'If asked about caffeine or stimulant intake: he drinks two or three cups of tea per day. He does not use over-the-counter medications.',
    'If asked about medication adherence: he takes all his medications as prescribed and has not missed any doses.'
  ],
  'Non-smoker, does not drink alcohol. He runs a small bakery and has a fairly active daily routine. He lives with his wife and one of his adult children.',
  'Nothing specific. He is unsure what the ECG shows.',
  'He just wants to know what the ECG means and whether there is anything to worry about.',
  'He would like the doctor to explain the results and let him know whether any treatment is needed.',
  ARRAY[]::text[],
  NULL,
  'SAY NO TO ANY OTHER QUESTIONS ASKED. Accept everything offered by the doctor.',
  ARRAY[
    'Ask whether the patient has been experiencing any palpitations – if so, clarify onset (sudden or gradual), frequency, and any identifiable triggers',
    'Ask about associated symptoms including dizziness, breathlessness, chest pain, and fatigue',
    'Ask whether the patient has been unwell recently',
    'Ask about social history including alcohol intake, smoking, diet, caffeine use, and any over-the-counter medications',
    'Ask about current medications and adherence',
    'Explore the patient''s ideas, concerns, and expectations',
    'Give a diagnosis of atrial fibrillation'
  ],
  ARRAY[
    'Offer a face-to-face appointment to listen to heart sounds – if a murmur is present, echocardiography will be required',
    'Arrange further blood tests including thyroid function tests, U+Es, LFTs, and FBC',
    'Offer rate control with a beta-blocker – for example Atenolol 50mg OD or Bisoprolol 1.25mg OD',
    'Offer Apixaban 5mg twice daily for stroke prevention given his CHA₂DS₂-VASc score of 4. Counsel about the risk of bleeding as a side effect, and advise that if he sustains any head injury he must attend the Emergency Department for a CT head scan even if he feels well',
    'Advise that the stroke team will be consulted regarding discontinuing Clopidogrel, as continuing it alongside Apixaban increases his bleeding risk. In the meantime, offer Lansoprazole for gastric protection',
    'Safety-net the patient – advise him to seek urgent medical help if he develops severe chest pain, sudden breathlessness, or weakness on one side of his body',
    'Arrange follow-up in 1–2 weeks to review his response to treatment'
  ],
  'Thank you for calling in about this, George. I want to start by reassuring you that it''s really good that we picked this up when we did, and I''m going to explain exactly what''s going on.

Based on the heart tracing we did and the irregular pulse that was noticed at your medication review, it looks like you have a condition called atrial fibrillation – we often call it AF for short. What this means is that the electrical system in your heart is not quite coordinating in the way it should be, which causes the heart to beat in an irregular and sometimes faster pattern. Does that make sense so far?

AF is actually quite a common condition, and it often develops alongside other health conditions such as high blood pressure, which you do have. Over time, raised blood pressure puts extra strain on the heart, which can increase the likelihood of AF developing.

The reason it''s really important to address this is that AF can increase the risk of a blood clot forming inside the heart. If a clot were to travel up to the brain, it could cause a stroke. Given that you''ve already had a stroke eight months ago, managing this carefully is a priority for us.

To assess your stroke risk, we used a scoring tool called the CHA₂DS₂-VASc score, which takes into account factors like your age, your blood pressure, and the fact that you''ve had a previous stroke. Your score came out at 4, which tells us your risk is elevated. Because of this, I''d like to start you on a blood-thinning tablet called Apixaban, 5mg twice a day. Apixaban works by reducing the chance of clots forming, which significantly lowers your risk of having another stroke.

I do want to be open with you about one important side effect – because Apixaban thins the blood, it does increase the risk of bleeding. Most people tolerate it very well, but you should be aware that things like easy bruising or minor nosebleeds can occur. If you ever notice blood in your urine or stools, cough up blood, or have any persistent or unusual bleeding, please seek medical attention. Most importantly, if you ever bang your head – even if you feel completely fine – please go straight to A&E for a CT scan to check for any internal bleeding.

I''d also like to start you on a medication called Bisoprolol, starting at a low dose of 1.25mg once a day. This helps to slow and regulate your heart rate, which should help with those palpitations you''ve been noticing.

There''s one more thing I want to mention. You''re currently on a medication called Clopidogrel, which you were started on after your stroke. Taking Clopidogrel alongside Apixaban can significantly increase your bleeding risk, so I''m going to speak to the stroke team about whether it''s safe to stop it. While we''re waiting to hear back from them, I''d like to add a tablet called Lansoprazole to help protect your stomach lining in the meantime.

I''d also like to arrange some additional blood tests and bring you in face-to-face to check your heart sounds. Let''s plan a follow-up in one to two weeks to see how you''re getting on with the new medication.',
  ARRAY[
    'Atrial fibrillation presenting with an irregular pulse should be confirmed with a 12-lead ECG and appropriate investigations including TFTs, FBC, U+Es, and LFTs to identify reversible causes.',
    'The CHA₂DS₂-VASc score guides anticoagulation decisions in AF; a score of 2 or more in males (or 3 or more in females) warrants anticoagulation – Apixaban 5mg twice daily is a commonly used direct oral anticoagulant.',
    'Patients starting anticoagulation must be counselled about bleeding risk and advised to attend A&E immediately following any head injury for a CT head scan, even if asymptomatic.',
    'Rate control with a beta-blocker (e.g. Bisoprolol 1.25mg OD or Atenolol 50mg OD) is first-line in most patients with AF who are not acutely unwell.',
    'Concurrent use of antiplatelet agents (e.g. Clopidogrel) and anticoagulants significantly increases bleeding risk; specialist input from the relevant team (e.g. stroke team) should be sought before discontinuing antiplatelet therapy.',
    'Safety-netting in AF should include urgent review if the patient develops chest pain, acute breathlessness, or new focal neurological symptoms suggestive of stroke.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  142,
  'Restarting Antipsychotic',
  'Mental Health',
  'Telephone Consultation',
  false,
  'Stefan Kowalski',
  '39-year-old male',
  ARRAY['Schizophrenia (diagnosed 18 months ago)'],
  ARRAY['Aripiprazole 15mg daily (last requested and issued from GP surgery 5 months ago)'],
  'Patient booked urgent telephone consultation to discuss concerns.',
  'Patient is calling urgently to discuss his mental health. He stopped his antipsychotic medication five months ago and is now experiencing a return of symptoms. He is also due to fly abroad tomorrow to visit a seriously ill family member.',
  'Hi, I need to speak to a doctor urgently. My symptoms have started coming back and I''m not sure what to do. I''m also flying to France tomorrow to see my father, who is very unwell, and I''m really worried about how I''m going to manage.',
  'He was diagnosed with schizophrenia 18 months ago and was taking Aripiprazole 15mg daily until five months ago, when he stopped it on his own because he felt well. He is now calling because symptoms have been returning over the past three weeks. His father is dying of bowel cancer and doctors in France have said he has only a few days left. He has already booked his flight and is not sure when he would return – he plans to stay until his father passes.',
  ARRAY[
    'If asked about psychotic symptoms: he has been feeling paranoid, believing that strangers are watching him or talking about him. He also sometimes hears his name being called when no one is around, and a voice telling him to undress in public.',
    'If asked about other symptoms: no thoughts of self-harm or of harming others. No low mood or elevated mood. He is sleeping reasonably well and his appetite is normal.',
    'If asked about why he stopped his medication: he felt well and thought he no longer needed it. He was not experiencing any side effects at the time.',
    'If asked about whether he told anyone before stopping: he did not speak to his GP or psychiatrist before stopping the medication.'
  ],
  'Non-smoker, does not drink alcohol. He works remotely as a software developer for a technology company. He lives alone but stays in regular contact with friends and extended family.',
  'He believes his symptoms are coming back and that he needs help to get them under control before travelling.',
  'He is worried that his symptoms will worsen while he is in France and that he will not be mentally stable enough to support his father during his final days.',
  'He wants the GP to restart his Aripiprazole so that he can manage his symptoms during this very difficult time.',
  ARRAY[]::text[],
  NULL,
  'SAY NO TO ANY OTHER QUESTIONS ASKED.',
  ARRAY[
    'Ask about the nature of the returning symptoms – specifically whether he is experiencing any hallucinations, what the voices are saying, and whether they are instructing him to do anything. Also ask about delusional thoughts and any recent changes in his mood',
    'Ask about risk assessment – any thoughts of self-harm, suicide, or thoughts of harming others',
    'Ask about why he stopped his medication and whether he experienced any side effects or withdrawal symptoms when stopping',
    'Ask about the current family situation – acknowledge that his father is terminally ill and explore how he is personally coping with this, and how the family is managing during this difficult time',
    'Ask about social history including smoking, alcohol, occupation, and support network'
  ],
  ARRAY[
    'Do not restart Aripiprazole in primary care without specialist input',
    'Offer urgent referral to the local Crisis Resolution and Home Treatment Team (CRHTT), or contact the on-call psychiatrist directly for advice',
    'Explain that restarting at the full previous dose after a prolonged break may lead to side effects, and that starting too low may delay symptom control; specialist input is therefore essential to ensure safe and effective management',
    'Educate the patient that psychiatric medication should never be stopped without first discussing it with a healthcare professional',
    'Ask whether he is able to delay his travel temporarily, even by a short period, to allow for urgent specialist review and a safe management plan to be put in place',
    'If he is unable to delay travel, advise that you will contact the mental health team immediately after the call to obtain advice and relay a plan back to him',
    'Recommend that while in France he identifies local emergency mental health services and the nearest hospital or GP, so he can access help promptly if his symptoms worsen or he feels unsafe',
    'Safety-net: advise him to seek urgent medical attention if his symptoms worsen, including increasing paranoia, more frequent hallucinations, confusion, or any concerns about his own safety or behaviour'
  ],
  'Thank you for calling in today, Stefan, and I want to say first of all that I can hear how much you are carrying right now. What is happening with your father is incredibly difficult, and it makes complete sense that you want to be there for him. I also want to take your concerns about your mental health very seriously, because what you''re describing needs prompt attention.

From what you''ve told me, it does sound like some of the symptoms you experienced when you were first diagnosed are returning. The paranoid feelings, hearing your name being called, and hearing a voice giving you instructions are all symptoms that we need to take seriously and manage carefully.

I know you stopped your Aripiprazole around five months ago because you were feeling well, and that is a very understandable reason. However, stopping antipsychotic medication suddenly without guidance from a specialist often leads to symptoms returning, sometimes weeks or months later. That appears to be what has happened here, and it''s not your fault – it''s just something we need to address now in the right way.

I have to be honest with you about why I can''t simply restart the Aripiprazole today at the dose you were on before. After a break of this length, jumping straight back to the full dose can cause significant side effects, including problems with movement, sedation, and changes in heart rhythm. On the other hand, restarting at too low a dose might not bring the symptoms under control quickly enough. Getting this right really requires input from the specialist mental health team, and that is exactly who I want to contact on your behalf right away.

I want to ask you something – is there any possibility at all of delaying your flight, even by a day or two? I completely understand if that is not something you can do, given what is happening with your father. But even a very short delay might allow us to get a plan in place that keeps you safer while you travel and while you are over there.

If you genuinely cannot delay, I will contact the mental health crisis team immediately after this call and get advice on how best to support you in the short term. I will also ask them about any guidance we can pass on to you while you''re in France, and I would strongly encourage you to find out where the nearest hospital or emergency mental health service is near your father''s home in France, so you know exactly where to go if things become difficult.

While we are waiting to hear from the specialists, if at any point your symptoms get significantly worse – if the paranoia increases, the voices become more frequent or more distressing, or you feel confused or unsafe – please do not wait. Seek urgent medical help immediately. I am going to make this referral now.',
  ARRAY[
    'Antipsychotic medications should never be restarted in primary care after a prolonged break without specialist input – the GP should urgently contact the Crisis Resolution and Home Treatment Team (CRHTT) or the on-call psychiatrist for advice.',
    'Restarting antipsychotics at the previous full dose after more than a few weeks of discontinuation can cause serious adverse effects including extrapyramidal symptoms, sedation, and cardiovascular complications; dose re-titration is often required.',
    'Patients stopping antipsychotics without guidance is a common and important clinical scenario – always educate patients not to discontinue psychiatric medication without first speaking to their prescriber or mental health team.',
    'Risk assessment in returning psychosis should always include direct enquiry about command hallucinations, thoughts of self-harm, and thoughts of harming others.',
    'When a patient cannot access immediate specialist input (e.g. due to imminent travel), the GP should ensure the patient knows how to access emergency mental health support at their destination and provide clear safety-netting advice.',
    'Acute psychosocial stressors such as bereavement or family crisis can precipitate relapse of psychotic illness and should be acknowledged and explored as part of the consultation.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  143,
  'Sexual Health Swab Results',
  'Gynaecology & Women''s Health',
  'Video consultation',
  false,
  'Zoe Fletcher',
  '17-year-old female',
  ARRAY[]::text[],
  ARRAY['Rigevidon','No known drug allergy'],
  'Seen 3 days ago by Caitlin Barnes (Nurse Practitioner). Presenting complaint: Patient reported a 5-day history of foul-smelling vaginal discharge associated with dysuria. History of multiple sexual partners noted. Examination: Pelvic examination performed with verbal consent and chaperone present. Purulent vaginal discharge observed. High vaginal and endocervical swabs taken. Urinalysis: Leucocytes 2+, nitrites negative. Plan: Swabs and urine sent for culture. Follow-up appointment arranged to discuss results. Swab Results: Chlamydia trachomatis (NAAT): Positive. Neisseria gonorrhoeae (NAAT): Negative. Bacterial Vaginosis (Microscopy): Not detected. Candida species (Microscopy): Not detected. Trichomonas vaginalis (NAAT): Not detected. Midstream Urine Culture: No significant growth.',
  'Patient has booked a follow-up video consultation to discuss the results of her recent vaginal swabs and urine tests.',
  'Hi doctor, I''m here to go through my results from the tests I had done a few days ago.',
  'She has been experiencing unusual vaginal discharge for just over a week. The discharge has been foul-smelling and she has also noticed a burning sensation when passing urine. She is otherwise well. Her periods are regular and her last period was approximately two weeks ago. She is taking the contraceptive pill (Rigevidon) and has been consistent with it. She has had multiple sexual partners and believes she may have contracted something following unprotected sex with someone she met at a party around two weeks ago.',
  ARRAY[
    'If asked about whether symptoms have changed: they have not significantly improved since she was last seen.',
    'If asked about pelvic or abdominal pain: no lower abdominal pain or pelvic discomfort.',
    'If asked about fever or feeling unwell: no fever, no nausea, no general malaise.',
    'If asked about intermenstrual or postcoital bleeding: none.',
    'If asked about sexual partners: she has had more than one partner in recent months. The most recent contact was around two weeks ago and was unprotected.',
    'If asked about the age of her partners: they are all adults, over 18.',
    'If asked about coercion or abuse: she has not been forced or pressured into any sexual activity.',
    'If asked about smoking, alcohol, or drug use: she does not smoke, drink, or use recreational drugs.',
    'If asked about who she lives with: she lives at home with her parents. She does not want her parents to know about this consultation or her symptoms as she is worried about their reaction.',
    'If asked about college: she is studying for her A-levels and things are going well.'
  ],
  'She does not smoke, drink alcohol, or use recreational or illicit drugs. She is currently studying for her A-levels and attends college full-time. She lives at home with her parents and does not want them to be informed about this consultation or her symptoms, as she is worried about how they would react.',
  'She thinks this might be a sexually transmitted infection, but she also wondered whether it could be a urine infection.',
  'She is worried about what the results mean for her health.',
  'She would like to go through the results and understand what is causing her symptoms.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY[
    'Start by acknowledging that you can see from her records that she was seen three days ago by a colleague due to vaginal discharge, and that swabs and urine tests were taken at that time – this demonstrates to the examiner that you are making use of the information available to you',
    'Ask whether she is still experiencing the same symptoms, including dysuria and vaginal discharge',
    'Ask whether the symptoms have improved, worsened, or stayed the same',
    'Ask about any associated pelvic pain or lower abdominal discomfort',
    'Ask about systemic symptoms such as fever, nausea, or malaise to help rule out pelvic inflammatory disease',
    'Ask about menstrual history, including her last menstrual period, cycle regularity, and any intermenstrual or postcoital bleeding',
    'Signpost before asking personal questions about sexual history',
    'Ask about the number of sexual partners, the gender of partners, and condom use',
    'Ask about the timing of her most recent sexual contact',
    'Ask about the age of her sexual partners',
    'Ask whether she has ever been forced or coerced into sexual activity or experienced any form of abuse',
    'Ask about her current contraception and confirm whether she has been taking it consistently',
    'Ask about smoking, alcohol, and use of recreational or illicit drugs',
    'Ask about her home situation and who she lives with',
    'Ask about her studies and how things are going at college',
    'Explore her ideas, concerns, and expectations regarding the cause of her symptoms and what she hopes will happen today',
    'Explain the test results, confirming a positive result for Chlamydia infection'
  ],
  ARRAY[
    'Offer treatment with doxycycline 100mg twice daily for 7 days',
    'Advise that she should attend a sexual health clinic for a full sexual health screen to check for other STIs including HIV, hepatitis B, and syphilis. Inform her that this service is confidential and discreet',
    'Advise that sexual intercourse, including oral sex, should be avoided until she has completed the full course of treatment',
    'Explain the importance of informing recent sexual partners so they can also be tested and treated',
    'Advise that the local sexual health clinic can support with partner notification and contact tracing',
    'Note that a test of cure is not routinely recommended for uncomplicated genital chlamydia. However, for people under 25, repeat testing is recommended 3–6 months after treatment to check for re-infection',
    'Offer health promotion advice, including consistent use of condoms to reduce the risk of STIs in the future',
    'Safety-net: advise her to seek urgent medical attention if symptoms worsen, such as developing a fever, increasing lower abdominal pain, or new symptoms'
  ],
  'Thank you for coming back for your results today, Zoe. I know it can feel a little nerve-wracking waiting to find out, so I want to be straightforward with you. I''ve had a look at all the tests that were done when you were seen a few days ago, and I can see that most of the results have come back normal – the urine test did not grow anything, and the other swabs for bacterial infections and thrush were all negative.

However, one of the swabs has come back showing that you have tested positive for chlamydia. I want to say first of all – please try not to feel alarmed or embarrassed by this. Chlamydia is actually one of the most common sexually transmitted infections in the UK, and it''s very treatable with a short course of antibiotics. You did the right thing by coming forward when you noticed something wasn''t right.

Chlamydia is a bacterial infection that is passed on through unprotected sexual contact. It often causes no symptoms at all, which is one of the reasons it spreads so easily without people knowing. In your case, the unusual discharge and the burning sensation when passing urine were most likely caused by this infection.

In terms of treatment, the antibiotic we use for chlamydia is called doxycycline. You would take one 100mg tablet twice a day for seven days. I can arrange for this to be prescribed for you today. I can see from your records that you don''t have any known drug allergies – is that still correct? [Pause for confirmation.] Perfect.

While you are taking the antibiotics, it''s really important that you avoid any sexual contact – including oral sex – until you have finished the full seven-day course. This is to make sure the infection clears completely and to avoid passing it on to anyone else.

I also want to mention that it''s important that any recent sexual partners are informed, so they can get tested and treated too, even if they don''t have any symptoms. I know that conversation can feel difficult, but the sexual health clinic can actually help with this in a confidential way – they can contact people on your behalf if you''d prefer not to do it yourself. You don''t have to worry about anyone finding out anything you don''t want them to know.

Speaking of the sexual health clinic, I would really encourage you to book an appointment there for a full sexual health check. They can screen for a few other infections such as HIV, hepatitis B, and syphilis. Everything is completely confidential, and they are very experienced at making young people feel comfortable.

For the future, using condoms consistently with any new partner is one of the best ways to protect yourself from infections like chlamydia.

Because you are under 25, we would recommend coming back for a repeat chlamydia test in about three to six months' time, not because we doubt the treatment, but just to check you haven''t been re-exposed. If at any point before then your symptoms get worse – for example if you develop a high temperature, increasing lower tummy pain, or feel generally unwell – please seek help straight away, as that could indicate the infection has spread further.',
  ARRAY[
    'Chlamydia trachomatis (NAAT) positive results in a young person should be treated with doxycycline 100mg twice daily for 7 days as first-line therapy.',
    'A test of cure is not routinely recommended after treatment for uncomplicated genital chlamydia, but repeat testing 3–6 months after treatment is recommended in those under 25 years to detect re-infection.',
    'Partner notification and contact tracing are essential components of chlamydia management – the sexual health clinic can facilitate this confidentially, including anonymous notification if needed.',
    'When consulting with a minor (under 18), consider Gillick competence and confidentiality carefully – a 17-year-old can consent to treatment and has a right to confidentiality provided there are no safeguarding concerns.',
    'Safeguarding must always be considered in consultations involving sexually active young people – ask directly about the age of partners, consent, and any history of coercion or abuse.',
    'Full STI screening including HIV, hepatitis B, and syphilis should be recommended via the sexual health clinic, even when only one infection is identified.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  144,
  'Isolated Macrocytosis in a Middle-Aged Adult',
  'Gastroenterology & Haematology',
  'Telephone Consultation',
  false,
  'Priya Sharma',
  '52-year-old female',
  ARRAY['Irritable bowel syndrome','Hypothyroidism'],
  ARRAY['Levothyroxine 100 micrograms once daily','No known drug allergy'],
  'Seen by Rachel Norris (Nurse Access) – 1 week ago. Presenting complaint: Patient attended for routine thyroid function monitoring. She reported feeling tired all the time. The case was discussed with the duty GP – Dr Sarah Collins, who advised arranging additional routine blood tests alongside thyroid function tests and recommended booking a follow-up appointment with a GP once results were available. Plan: Blood tests arranged. Follow-up appointment with GP once results are available. Blood Test Results: Thyroid Function Tests – TSH 2.1 mU/L (ref 0.4–4.0 mU/L), Free T4 16 pmol/L (ref 12–22 pmol/L). Full Blood Count – Haemoglobin (Hb) 132 g/L (ref 115–160 g/L), Mean Corpuscular Volume (MCV) 104 fL (ref 80–100 fL), White Cell Count (WCC) 6.5 x10⁹/L (ref 4.0–11.0 x10⁹/L), Platelets 280 x10⁹/L (ref 150–400 x10⁹/L). Liver function tests, renal function tests, calcium, bone profile, and CRP – all normal and within reference range.',
  'Patient has booked a telephone appointment to discuss her recent blood test results following a routine thyroid monitoring appointment last week.',
  'Hi doctor, I booked this appointment to go through my blood test results, if that''s okay.',
  'She has been feeling tired all the time for over a year. She never mentioned it before, but when the nurse asked during her thyroid monitoring appointment she said yes. She assumed the tiredness might be related to her underactive thyroid.',
  ARRAY[
    'If asked about sleep and mood: her sleep is good and her mood is stable.',
    'If asked about menstrual history: she stopped having periods at the age of 47 and her menopausal symptoms have now settled.',
    'If asked about diet: she is vegetarian. She does not eat meat but does consume dairy products, eggs, and green vegetables.',
    'If asked about gluten or wheat intake: she stopped eating pasta and wheat-based foods over six months ago because she noticed they were triggering episodes of diarrhoea.',
    'If asked about weight loss: no unintentional weight loss.',
    'If asked about family history: she is adopted and does not know her biological family medical history.'
  ],
  'She lives with her husband and two teenage sons. She works as an accountant. The tiredness has not affected her work performance. There has been no recent stress. She does not smoke, drink alcohol, or use illicit drugs.',
  'She thinks her tiredness may be related to her thyroid condition.',
  'She does not have any specific concerns at present.',
  'She would like to understand the cause of her tiredness.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario.',
  ARRAY[
    'Ask about the onset and progression of her tiredness, including whether it has improved, worsened, or remained the same over time',
    'Ask about any triggers or factors that make the tiredness better or worse',
    'Ask about symptoms suggestive of vitamin B12 or folate deficiency, including numbness or tingling in the hands or feet, balance problems, memory changes, difficulty concentrating, shortness of breath, palpitations, dizziness, or reduced exercise tolerance',
    'Ask about gastrointestinal symptoms suggestive of coeliac disease or malabsorption, including diarrhoea, bloating, reflux, constipation, abdominal pain, steatorrhoea (stools that are pale, greasy, or difficult to flush), or unintentional weight loss',
    'Ask about her dietary intake, particularly sources of vitamin B12 and folate',
    'Ask how long she has been avoiding pasta and wheat, and whether she avoids other gluten-containing foods – this is important because coeliac serology requires the patient to be consuming gluten for a minimum of 6 weeks before testing',
    'Ask about mood, sleep, appetite, weight changes, and menstrual history',
    'Ask about social history including alcohol intake, smoking, illicit drug use, and occupation',
    'Ask about family history of gastrointestinal conditions, particularly coeliac disease',
    'Explore the patient''s ideas, concerns, and expectations',
    'Make a diagnosis of macrocytosis, most likely secondary to vitamin B12 deficiency given her vegetarian diet, with coeliac disease as an important differential given her symptoms triggered by pasta and wheat'
  ],
  ARRAY[
    'Arrange further blood tests including vitamin B12, folate levels, and coeliac serology (tissue transglutaminase IgA antibodies and total IgA)',
    'Explain that for coeliac testing to be accurate, she needs to be consuming gluten-containing foods for at least six weeks prior to the blood test. Ask whether she would be willing to temporarily reintroduce gluten so that the results will be meaningful',
    'Inform her that if vitamin B12 or folate deficiency is confirmed, this can be corrected with appropriate supplementation or injections',
    'Inform her that if coeliac disease is suggested on blood tests, she will be referred to a gastroenterologist for further assessment and confirmation of the diagnosis',
    'Provide advice on managing tiredness, including energy conservation techniques, pacing daily activities, and prioritising important tasks',
    'Encourage a regular sleep routine and good sleep hygiene practices',
    'Advise on ensuring adequate intake of vitamin B12 through vegetarian sources such as dairy products, eggs, and fortified cereals',
    'Provide safety-netting advice to seek urgent medical attention if symptoms worsen, or if she develops tingling in her hands or feet, balance problems, or memory difficulties',
    'Arrange follow-up once blood test results are available to review findings and adjust management accordingly'
  ],
  'Thank you for calling in, Priya, and for bearing with us while we arranged these tests. I want to go through the results with you and explain what we have found.

First, the good news. Your thyroid results are looking normal. Your TSH is 2.1, which sits comfortably within the normal range, and your free T4 is also normal. So the tiredness you have been experiencing is not being caused by your underactive thyroid at the moment.

However, I have noticed something on your full blood count that I would like to discuss with you. Your haemoglobin – the red cell count – is within the normal range, which is reassuring. But one of the measurements called the MCV, which tells us about the size of your red blood cells, is slightly elevated at 104. The normal range is 80 to 100, so yours is just a little above that. This is something we call macrocytosis, which simply means your red blood cells are slightly larger than they should be.

There are a few different things that can cause this. One of the most common causes, particularly in people who follow a vegetarian diet, is a deficiency in vitamin B12. B12 is found mainly in animal products such as meat, fish, and shellfish, but it is also present in dairy and eggs, which I understand you do eat. Even so, levels can sometimes fall over time. Another important cause I want to explore is a condition called coeliac disease, which is an immune reaction to gluten – the protein found in wheat, rye, and barley. Interestingly, you mentioned that you have been avoiding pasta and wheat for the past six months because they were causing diarrhoea. That is actually a very important piece of the puzzle.

I would like to arrange a couple more blood tests – one to check your vitamin B12 and folate levels, and another to test for coeliac disease. This is where I need to mention something important: for the coeliac blood test to give us an accurate result, you would need to be eating foods that contain gluten every day for at least six weeks before the test. I know that may feel uncomfortable given that wheat has been causing you symptoms, but without that, the test could come back falsely negative and we might miss the diagnosis. I want you to think about whether you would be willing to reintroduce some gluten-containing food for a few weeks so we can do this properly. We can have that conversation further once you''ve had a chance to consider it.

If the blood tests confirm a B12 or folate deficiency, this is very straightforward to treat – usually with supplements or, if needed, a course of injections. If the coeliac test is positive, I would refer you to a specialist in digestive conditions who can confirm the diagnosis and support you with a gluten-free diet going forward.

In the meantime, please make sure you are getting a good amount of B12 through your diet – dairy products, eggs, and fortified cereals are your best vegetarian sources.

Please do come back to us once we have these new results, and we can take it from there. In the meantime, if you notice any new or worsening symptoms – particularly tingling or numbness in your hands or feet, problems with your balance, or any changes in your memory or concentration – please do not wait for the follow-up appointment. Contact us straight away.',
  ARRAY[
    'Macrocytosis (MCV >100 fL) with a normal haemoglobin is an important incidental finding that requires further investigation; common causes include vitamin B12 deficiency, folate deficiency, hypothyroidism, alcohol excess, and coeliac disease.',
    'Vitamin B12 deficiency is a significant risk in vegetarians and vegans, as B12 is found predominantly in animal-derived foods; dietary sources for vegetarians include dairy, eggs, and fortified cereals.',
    'Coeliac disease can present with gastrointestinal symptoms triggered by wheat or gluten-containing foods, and macrocytosis caused by folate malabsorption – importantly, coeliac serology requires active gluten consumption for at least 6 weeks before testing to avoid a false negative result.',
    'Thyroid function should always be checked when investigating tiredness, and a normal TSH and free T4 effectively exclude hypothyroidism as a contributing cause.',
    'When macrocytosis is identified, initial further investigations should include serum vitamin B12, folate, and coeliac serology (tTG IgA and total IgA).',
    'Safety-netting in B12 deficiency should include advice to seek urgent review if neurological symptoms develop, such as peripheral tingling, balance disturbance, or cognitive changes, as subacute combined degeneration of the spinal cord is a serious complication.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  145,
  'Generalised Itching in a Young Adult',
  'Dermatology',
  'Video Consultation',
  false,
  'Simon Hartley',
  '39-year-old male',
  ARRAY['None Recorded'],
  ARRAY['Not on any regular medications','No known drug allergy'],
  'No significant recent consultations',
  'Patient booked a routine video consultation to discuss persistent generalised itching.',
  'Hi doctor, I''ve been itching all over my body for the past three to four weeks and it''s really getting me down. I was hoping you could help.',
  'You''ve been experiencing generalised itching for the past three to four weeks and it''s showing no signs of improving.',
  ARRAY['The itching is persistent and present throughout the day, and noticeably worse at night, often disturbing your sleep.','The itching is widespread with no single area more affected than any other.','There is no visible rash or skin changes, and no pain, burning, or swelling associated with the itching.','You have noticed that you have lost around 3 kg unintentionally over the past four weeks.','You have had no night sweats or fever.','There has been no change in your appetite.','You have no history of recent infections and no contact with anyone experiencing similar symptoms.','You have not been able to identify any triggers for the itching.'],
  'You work as a project manager. You do not smoke, drink alcohol, or use illicit drugs. There have been no recent changes in your work or lifestyle. Your mood is good and your mental health is stable. You live alone and currently have no partner.',
  'You are unsure what is causing the itching.',
  'You are worried about what might be behind these symptoms.',
  'You would like to understand the possible causes and receive advice or treatment to help relieve the itching.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided.',
  ARRAY[]::text[],
  ARRAY['Offer a face-to-face appointment to examine the skin, check for any lumps or swellings suggestive of lymphadenopathy, and perform an abdominal examination to assess for splenomegaly.','Advise the patient to keep a symptom diary to help identify any potential triggers or patterns associated with the itching.','Offer blood tests including full blood count, HbA1c, urea and electrolytes, liver function tests, CRP, ESR, thyroid function tests, and iron studies including ferritin.','Offer moisturisers. Note that for dry skin, ointments are generally more effective than creams.','Offer antihistamines. Start with a non-sedating antihistamine such as cetirizine as first line, and this can be increased gradually up to four times the standard dose if required.','If symptoms remain poorly controlled, particularly if sleep is affected, consider a sedating antihistamine such as chlorphenamine at night. In some cases, a non-sedating antihistamine can be used during the day and a sedating one at night, although this approach is more commonly used in conditions such as urticaria.','Provide safety-net advice. Although he will be reviewed face to face, advise that if symptoms worsen or if he develops new symptoms such as night sweats, lumps or swellings, or new skin changes, he should seek urgent medical attention.'],
  'Thank you for coming to see me today, Simon, and for describing your symptoms so clearly. I can understand how distressing persistent itching can be, especially when it is disturbing your sleep at night and you cannot identify a reason for it.

What you are describing — generalised itching with no visible rash and no obvious trigger, lasting several weeks — is something we take seriously in general practice. When itching occurs all over the body without a clear skin condition to explain it, we refer to this as pruritus, and it can occasionally be the first sign that something is happening internally, even before any other symptoms appear. The unintentional weight loss you mentioned alongside this is also something I want to make sure we investigate properly.

The most important next step is for you to come in so I can examine you in person. I would like to check your skin carefully, feel for any enlarged lymph nodes — which are small glands found in areas such as your neck, armpits, and groin — and examine your abdomen to check your liver and spleen. This physical examination will give us much more information than we can gather on a video call.

Alongside that, I would like to arrange a set of blood tests. These will include a full blood count to look at your blood cells, liver function tests, kidney function, thyroid function, blood sugar, inflammatory markers such as CRP and ESR, and iron studies including ferritin. These tests help us rule out a wide range of conditions that can sometimes cause generalised itching, including thyroid problems, liver or kidney issues, and blood conditions.

In the meantime, I would suggest applying a good moisturiser regularly, as dry skin can worsen itching even if it is not the underlying cause. Ointments tend to be more effective than creams for this purpose. For symptom relief, I would also like to start you on a non-sedating antihistamine called cetirizine. This can be taken once daily and, if needed, the dose can be gradually increased up to four times the standard amount. If the night-time itching is particularly troublesome and affecting your sleep significantly, we could also consider a sedating antihistamine such as chlorphenamine taken at night.

It would also be helpful if you could keep a symptom diary in the meantime — noting when the itching is at its worst, any foods, products, or activities that seem to make it better or worse, and any new symptoms that develop. This kind of information is very useful for building a clearer picture.

I want to reassure you that we are going to get to the bottom of this together. However, if before your face-to-face appointment you notice any new lumps or swellings, develop drenching night sweats, or feel significantly unwell, please do not wait — contact us urgently or go to A&E if needed.',
  ARRAY['Generalised pruritus without a visible rash in a young adult warrants a full systemic work-up to exclude underlying causes such as haematological malignancy, liver disease, renal disease, thyroid dysfunction, and iron deficiency.','Unintentional weight loss alongside pruritus is a red flag combination that must not be dismissed — it raises the possibility of lymphoma or other occult malignancy.','First-line blood investigations should include FBC, LFTs, U&Es, TFTs, HbA1c, CRP, ESR, and ferritin.','First-line antihistamine therapy is a non-sedating agent such as cetirizine, which can be titrated up to four times the standard dose; a sedating antihistamine such as chlorphenamine can be added at night if sleep is affected.','For dry or irritated skin, ointments are generally more effective than creams as a moisturiser.','Safety-net advice should specifically include warning the patient to seek urgent review if they develop lymphadenopathy, night sweats, or any new skin changes before their face-to-face appointment.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  146,
  'Recurrent Abdominal Pain in Middle Age',
  'Gastroenterology & Haematology',
  'Telephone Consultation',
  false,
  'Caroline Walsh',
  '51-year-old female',
  ARRAY['Open appendectomy in 2010','Laparoscopic excision of endometriosis lesions in 2022','Laparoscopic sigmoid resection with end-to-end anastomosis for deep infiltrating endometriosis in 2023','Depression','Perimenopause'],
  ARRAY['Sertraline 50mg daily','No Known Drug Allergy'],
  'Letter from Urgent Treatment Centre (UTC) Re: Caroline Walsh | 51 years old | Female I am writing to inform you about Caroline Walsh, who presented to the A&E for the third time in the last few months with recurrent abdominal pain, bloating, vomiting, and inability to pass wind. Each episode appears to resolve spontaneously after a period of time. During her visit, blood tests were performed, including CRP, ESR, U+Es, LFTs, and Thyroid Function, all of which returned normal results. A bedside ultrasound and abdominal X-ray were also carried out, and these were negative for any abnormalities. Following the investigations, Caroline was reviewed at the Urgent Treatment Centre. Upon explaining that all results were normal, her pain had settled without the need for intervention. I discussed the possibility that her symptoms may be IBS-related, but advised her that if symptoms persist she should follow up with her GP for further investigation and management. Please feel free to contact me should you require any further information. Kind regards, Patricia Simmons, Advanced Nurse Practitioner, Urgent Treatment Centre',
  'Patient booked a telephone consultation to discuss ongoing abdominal symptoms and a recent letter from the Urgent Treatment Centre.',
  '',
  '',
  ARRAY[]::text[],
  'You do not smoke or drink alcohol. You work as a nursing auxiliary at the local hospital. You have been calling in sick on multiple occasions due to these symptoms, which is affecting your job.',
  'You think it might be IBS because of the bloating and constipation.',
  'You want to get this sorted as it is affecting your work, and you are frustrated by the repeated hospital visits with no clear diagnosis.',
  'You want to know what is causing these symptoms and how they can be managed properly.',
  ARRAY[]::text[],
  NULL,
  'SAY NO TO ANY OTHER QUESTIONS ASKED',
  ARRAY[]::text[],
  ARRAY['Offer referral to surgical assessment unit or surgical rapid access clinic to be seen urgently, usually within a week (but can be seen sooner if needed).','No need for a face-to-face appointment as she is currently not symptomatic and was reviewed by a healthcare professional only two days ago.','Surgeons may consider CT abdomen and laparoscopy to directly visualise and treat adhesions (adhesiolysis).','Offer a sick note to help explain her situation to her employer and provide some support at work.','Strongly safety-net regarding symptoms of bowel obstruction — advise her to return to A&E immediately if she experiences any recurrence of symptoms, as this could indicate a developing or full-blown bowel obstruction.'],
  'Thank you for calling today, and I want to say straightaway that I completely understand how exhausting and frightening it must be to have gone to A&E three times now without getting a clear answer. That kind of uncertainty is genuinely distressing, and your frustration is very understandable.

I have read the letter from the Urgent Treatment Centre, and I can see that each time you have been seen, your blood tests, ultrasound, and X-ray have all come back normal, and your pain has settled on its own. That is actually quite helpful information, because it tells us what the problem is not — it is not an acute surgical emergency of the kind that would show up on those tests.

Given your surgical history — particularly the procedures you have had for endometriosis — one important possibility we need to consider is that adhesions, which are bands of scar tissue that can form internally after surgery, may be contributing to your episodes of pain, bloating, and difficulty passing wind. These can sometimes cause the bowel to become temporarily obstructed, and they would not be visible on a standard X-ray or ultrasound.

Because of this, I would like to arrange an urgent referral to the surgical team. This would typically be via a surgical assessment unit or a rapid access surgical clinic, and you would usually be seen within the week, or sooner if a slot is available. The surgical team can review your history in full and decide whether further investigations such as a CT scan of your abdomen, or even a laparoscopy to look directly inside and treat any adhesions, are warranted. This is called adhesiolysis.

I also want to help you with your work situation. I can provide you with a sick note to cover you during this period, which should take some pressure off and give your employer a clearer picture of what is going on.

Finally, I must give you some very important safety-netting advice. If at any point your symptoms come back — particularly if you have severe abdominal pain, cannot pass wind or open your bowels at all, start vomiting persistently, or your abdomen becomes very distended — please go straight to A&E without waiting. These could be signs of a more complete bowel obstruction that would need urgent treatment.',
  ARRAY['Recurrent episodic abdominal pain, bloating, and inability to pass wind in a patient with previous abdominal surgery should raise suspicion for adhesional small bowel obstruction, even when standard investigations are normal.','A history of multiple laparoscopic and open pelvic surgeries — particularly for endometriosis — significantly increases the risk of intra-abdominal adhesion formation.','Urgent surgical referral (surgical assessment unit or rapid access clinic) is appropriate when adhesional obstruction is suspected, as CT abdomen or diagnostic laparoscopy (adhesiolysis) may be required.','When a patient is currently asymptomatic and was reviewed by a clinician within the last 48 hours, a repeat face-to-face GP appointment adds little — the priority is onward surgical review.','Safety-netting for bowel obstruction must be explicit: patients should be advised to attend A&E immediately if pain returns, they cannot pass wind or stool, they vomit persistently, or their abdomen becomes distended.','A sick note should be considered proactively for patients whose recurrent admissions are affecting their employment.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  147,
  'Candida Swab Results in Male',
  'General Practice',
  'Telephone Consultation',
  false,
  'Ryan Cooper',
  '45-year-old male',
  ARRAY['Nil significant past medical history'],
  ARRAY[]::text[],
  'Face-to-face consultation with Sarah Drummond (Advanced Nurse Practitioner) one week ago. Patient reported whitish discharge from penile foreskin associated with redness and tightening of the foreskin. Third episode within the last 4-5 months. On examination: redness, whitish discharge with phimosis noted. Impression: Balanitis. Plan: Treat with Clotrimazole 1% cream — apply to the affected area 2 to 3 times daily. Swabs taken for culture. Safety-netting and worsening advice given. Follow up arranged for swab results. Swab Report — Patient: Ryan Cooper. Specimen: Penile discharge swab. Result: Candida albicans isolated. Sensitivity: Organism is sensitive to Fluconazole, Clotrimazole, Miconazole. Comment: Findings are consistent with a candidal infection.',
  'Patient booked a telephone consultation to discuss swab results following treatment for recurrent penile discharge.',
  'Hi, I''m calling about the swab results you said you''d ring me about. The cream has helped a bit but I''ve still got some discharge and a bit of itching.',
  'Your symptoms have improved slightly with the Clotrimazole cream, but you still have some discharge and intermittent itching or discomfort. You have no pain with urination and no urinary frequency.',
  ARRAY['You are sexually active, with a new female partner for the last four months. Your partner has no symptoms or discharge. You are not currently using condoms.','You have had three episodes of similar symptoms over the past five months despite good personal hygiene.','There is no pain on urination and no urinary frequency.','You have no history of STIs and have not had a recent sexual health screen.'],
  'You are a non-smoker and drink alcohol only occasionally. You work as a groundworker, which involves heavy physical outdoor work and long hours.',
  'You think your symptoms are probably Candida again and that you just need more Canesten cream.',
  'You do not understand why this keeps coming back. You have had three episodes in five months despite making efforts to improve your hygiene.',
  'You would like to know what the next step is and whether you need more treatment or a different approach.',
  ARRAY[]::text[],
  'Is Candida an STI (sexually transmitted infection)?',
  'SAY NO TO ANY OTHER QUESTIONS ASKED',
  ARRAY['Ask the patient about the symptoms that led to him having the swab taken.','Ask whether symptoms are getting better, worse, or staying the same.','Ask whether the discharge is coming from around the foreskin or directly from the urethra — urethral discharge is more commonly seen in STIs, whereas in balanitis the discharge typically collects under the foreskin.','Ask about bleeding and skin splitting of the foreskin.','Ask if there is any tightening of the foreskin or difficulty pulling it back, which could suggest phimosis, and whether the foreskin has ever become stuck after being retracted, which may indicate paraphimosis.','Ask about urinary symptoms — frequency, burning sensation, haematuria.','As symptoms are recurrent, screen for diabetes: ask about urinary frequency, excessive thirst, increased appetite, weight change, and family history of diabetes.','Ask about sexual history — any new partners, symptoms in current partner, any recent STI screen, any previous STIs, and whether this has affected his sexual life.','Explore the patient''s ideas, concerns, and expectations.'],
  ARRAY['Offer HbA1c test for diabetes, as recurrent candidal balanitis can be a presenting feature of undiagnosed diabetes mellitus.','Offer further Clotrimazole 1% cream to continue for another 7 days to complete a full 14-day treatment course, or until symptoms fully resolve.','Offer topical hydrocortisone 1% cream once daily for up to 14 days to reduce inflammation, or until symptoms settle.','Alternatively, prescribe combination cream — Canesten HC (clotrimazole 1% with hydrocortisone 1%) twice daily for 7 days.','Advise the patient to abstain from sexual activity until treatment is complete, or to use condoms if abstinence is not possible. Note that Clotrimazole can damage latex condoms.','Advise self-referral to a sexual health clinic for a full STI screen.','Advise that his partner should also be assessed, as there is a possibility of candidal infection being passed between sexual partners, even if she has no current symptoms.','Advise on good hygiene measures: wash the penile head area daily with lukewarm water and avoid harsh soaps; gently retract the foreskin where possible and ensure the glans penis is completely dry before replacing the foreskin; recommend an emollient as a soap substitute to reduce irritation.','Safety-net advice: advise the patient to seek urgent medical attention if he develops severe pain, blood in the discharge, skin ulceration, significant swelling, or problems with the foreskin such as difficulty retracting it (phimosis) or inability to return it to its normal position after retraction (paraphimosis).'],
  'Thank you for calling in, Ryan, and I''m glad the cream has given you some relief, even if things haven''t settled completely yet. I have your swab results here and I''d like to go through them with you and talk about what we do next.

Your swab has confirmed that you have a candidal infection — specifically a yeast called Candida albicans — and this is causing a condition called balanitis, which is an inflammation of the head of the penis. The good news is that the organism is sensitive to the treatments we have available, including the Clotrimazole cream you have already been using. However, because this is your third episode in five months, it is important that we think about why it keeps coming back rather than simply repeating the same treatment.

One of the most important things we need to look into is whether you might have diabetes. Raised blood sugar levels can create an environment where Candida thrives, and recurrent candidal infections are sometimes the first sign that diabetes is present. I would like to arrange a blood test called an HbA1c, which gives us a picture of your average blood sugar level over the past few months. It is a straightforward blood test and very much worth doing.

Regarding treatment, I would like to extend the Clotrimazole 1% cream for another seven days so that you complete a full fourteen days in total. I would also like to add a topical hydrocortisone 1% cream once daily alongside it for up to fourteen days to help settle the inflammation more quickly. Alternatively, we have a combination product called Canesten HC, which contains both clotrimazole and hydrocortisone in a single cream — that can be applied twice daily for seven days if you would prefer a simpler regimen.

I would also recommend that you and your partner both attend the sexual health clinic for a check-up. Even though your partner has no symptoms, Candida can be carried and passed between partners without causing obvious signs, and she may need treatment as well. In the meantime, please avoid unprotected sex until your symptoms have fully cleared and treatment is complete. If you do use condoms in the meantime, please be aware that Clotrimazole cream can weaken latex condoms.

Regarding your question about whether Candida is an STI — Candida is not classified as a typical sexually transmitted infection. It is a yeast that naturally lives in small amounts on the skin and in the body. However, it can be passed between partners during sexual contact, which is why it is sensible for your partner to be assessed too.

Finally, on hygiene: wash the area daily with lukewarm water rather than soap, gently retract the foreskin where you are able to, and make sure the skin is fully dry before replacing the foreskin. Using an unperfumed emollient as a soap substitute can also help reduce irritation. If at any point you develop severe pain, notice blood in any discharge, develop ulceration or significant swelling, or have trouble with the foreskin — either being unable to retract it or unable to return it to its normal position — please seek urgent medical attention.',
  ARRAY['Recurrent candidal balanitis — defined as three or more episodes — should always prompt investigation for undiagnosed type 2 diabetes mellitus; request HbA1c.','The swab result (Candida albicans sensitive to Fluconazole, Clotrimazole, and Miconazole) confirms the diagnosis of candidal balanitis; treatment should be extended to a full 14-day course of Clotrimazole 1% cream, with the option of Canesten HC (clotrimazole 1%/hydrocortisone 1%) twice daily for 7 days as a combination alternative.','Topical hydrocortisone 1% once daily for up to 14 days can be added to reduce inflammation alongside antifungal treatment.','Although Candida is not a classical STI, sexual transmission can perpetuate recurrent infection; partner screening and treatment is recommended even in the absence of symptoms.','Clotrimazole cream can degrade latex condoms — this must be communicated clearly when advising condom use during treatment.','Safety-netting should specifically cover phimosis and paraphimosis, as well as signs of complicated infection such as ulceration, haematuria, or severe swelling requiring urgent review.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  148,
  'Son Concerned About Mum''s Decline',
  'Elderly Medicine & Palliative Care',
  'Telephone consultation',
  false,
  'Dorothy Pearson',
  '84-year-old female',
  ARRAY['Hypertension','Osteoporosis','Alzheimer''s dementia','Amlodipine 5mg OD','Ramipril 10mg OD','Alendronic acid 70mg once weekly','Calcichew-D3 Forte 500mg/400IU chewable tablets, one tablet twice daily (for osteoporosis and vitamin D supplementation)','Donepezil 5mg OD','No known drug allergy','No Advance Care Plan in place','No Lasting Power of Attorney (LPA) for health or finances'],
  ARRAY[]::text[],
  'Nil. Patient''s son — Tom Pearson — calling to discuss the patient. Son''s account: You are Tom Pearson, Dorothy''s son, calling with some concerns. You visit your mother once every two weeks. On your most recent visit yesterday, you found her with an unkempt appearance, bins not taken out, and the house looking very untidy. Her dosette box appears full, suggesting she may not be taking her prescribed medications as directed. She has not reported feeling unwell or having a fever. You are unsure about her bowel and bladder function, but she has not mentioned any problems with either. Your mother does not know you have contacted the GP. She has not given you permission to discuss her health on her behalf, but you are her next of kin. Social: She lives alone and was usually independent, but you do not believe this is still the case. She is a non-smoker and does not drink alcohol. You purchase her food shopping and arrange for cleaners to deep clean the house every two to three weeks. Ideas: You suspect her memory is declining, but she denies having any memory problems. Concerns: You believe she is struggling to cope at home and may need nursing home care. Expectations: You would like the GP to arrange a nursing home placement and to explain what problems she may be having.',
  'The patient''s son has telephoned to discuss concerns about his mother''s ability to cope at home.',
  '',
  '',
  ARRAY[]::text[],
  '',
  'You suspect her memory is declining, but she denies having any memory problems.',
  'You believe she is struggling to cope at home and may need nursing home care. You feel that the situation will worsen if not addressed promptly.',
  'You would like the GP to arrange a nursing home placement and to be told what health problems his mother may be experiencing.',
  ARRAY[]::text[],
  'Can you tell me what medications my mum is taking and what they are for? Please do not tell her that I have called to discuss her health.',
  NULL,
  ARRAY['Confirm whether the son has the patient''s permission to speak about her health, and establish whether the patient is aware that he is contacting the GP on her behalf.','Ask when Tom last saw his mother, what he specifically noticed during that visit regarding her appearance and behaviour.','Ask whether he has noticed any changes in her ability to manage day-to-day tasks such as eating, dressing, or keeping the house tidy.','Ask whether there have been any recent incidents where Dorothy appeared confused or struggled with tasks she used to manage without difficulty.','Ask about any history of falls or unexplained bruising.','Ask about her usual mobility — does she move around independently or use a walking aid? — and whether there has been any recent change in her mobility.','Ask whether she has reported feeling unwell in any way, including fever, cough, urinary symptoms, or bowel problems including any incontinence.','Ask whether Tom has noticed any changes in her eating or drinking habits, and find out how her meals are prepared and who does her shopping.','Ask whether Dorothy has had any difficulty taking her medications and whether Tom has noticed whether the dosette box appears full or empty.','Ask whether there have been any recent changes in her sleeping patterns or daily routine, or whether she seems more withdrawn or agitated.','Ask about any recent hospital admissions.','Ask whether she smokes or drinks alcohol.','Explore whether Tom thinks Dorothy might benefit from more formal care such as home help or a residential placement.'],
  ARRAY['Explain to the son that without Dorothy''s consent, specific medical details — including her diagnoses, medications, and treatment plan — cannot be disclosed, in order to respect her confidentiality.','Offer a home visit as soon as possible to conduct a routine health examination and assess her overall wellbeing. Assess her home environment for safety, cleanliness, and her ability to manage daily tasks. Check for underlying physical health issues such as infection (chest, urine) or constipation, and treat appropriately if found.','Blood tests may be offered depending on the findings at the home visit.','Evaluate her ability to cope with daily activities and determine whether additional support — such as home care services or residential placement — is needed.','If she is not coping at home, involve the safeguarding team and the frailty team, including an occupational therapist and physiotherapist, to assess and support her needs.','Discuss the option of Lasting Power of Attorney (LPA) with Tom, to ensure appropriate legal arrangements are in place for future health and care decisions.','Provide support and information to Tom, including details of carer support groups and resources for people supporting someone with dementia.','Safety-net: advise Tom that while action is being taken following this call, if Dorothy''s memory deteriorates further or there are any concerning changes — such as a fall, increased agitation, or difficulty eating — he should contact the GP urgently or call 999 if there is an immediate risk.'],
  'Thank you so much for calling today. It is clear that you care very deeply about your mother, and it takes courage to reach out when you are worried about someone you love. I want to make sure we handle this conversation carefully and thoughtfully, because there are a few important things I need to address.

The first thing I want to be transparent about is that because Dorothy has not given her permission for her medical information to be shared with anyone at this stage, I am not able to give you specific details about her health, her diagnoses, or her medications. I know that may feel frustrating when you are so concerned about her, but this is to protect her right to confidentiality — a right that applies to every patient, regardless of who their next of kin is. I hope you understand that this is not a barrier to helping her; it is simply the right way for us to proceed.

What I can absolutely do is listen carefully to everything you have noticed, because the picture you are describing — the untidy home, the unkempt appearance, the dosette box appearing full — paints a very important picture that we need to take seriously. You are right to be concerned. These kinds of observations from a family member who knows someone well are invaluable.

The most important thing I can do right now is arrange a home visit for your mother as soon as possible. During that visit I would carry out a full health check, assess how she is managing in her home environment, and look for any medical issues that might be contributing to what you are seeing — for example, an infection, constipation, or other treatable causes of confusion or decline. These can sometimes look like worsening dementia when in fact they are entirely reversible.

If the visit confirms that she is struggling to cope safely at home, the appropriate next step would be to involve social services and the safeguarding team, as well as specialists in frailty medicine — including an occupational therapist and physiotherapist — who can carry out a full assessment of her needs and discuss with her what support is available. That conversation would happen with Dorothy, with her full involvement wherever possible.

I would also gently raise with you the topic of Lasting Power of Attorney, or LPA. If Dorothy has not yet set this up, now would be a good time to think about encouraging her to do so while she has the capacity to make that decision herself. LPA for health and welfare and for financial affairs can make a significant difference in being able to support her properly in the future.

In the meantime, if at any point before the home visit you are seriously concerned about her safety — for example if she falls, becomes very unwell, or seems in immediate danger — please do not hesitate to call 999 or contact us urgently.',
  ARRAY['A next of kin does not automatically have the right to receive medical information about a patient — explicit consent from the patient is required before specific diagnoses, medications, or treatment details can be shared.','You can take a full history from a third party (such as a family member) without breaching confidentiality, as this is gathering information rather than disclosing it.','An urgent home visit is the most appropriate initial response when a patient''s ability to cope at home is in question, to assess both health status and home environment.','Treatable medical causes of functional decline — including infection, constipation, and dehydration — must be excluded before attributing deterioration solely to dementia progression.','Safeguarding referral and frailty team involvement (OT, physiotherapist) should be considered if a patient is found to be struggling to cope safely at home.','Encouraging family members to discuss Lasting Power of Attorney (LPA) with the patient while capacity is retained is an important proactive step in dementia care.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  149,
  'Weight Management',
  'Endocrine & Nephrology',
  'Video consultation',
  false,
  'Martin Doyle',
  '41-year-old male',
  ARRAY['Obstructive sleep apnoea — currently managed with CPAP (diagnosed 3 months ago)','BMI 34 (last measured yesterday)'],
  ARRAY[]::text[],
  NULL,
  'Patient booked a routine video consultation to discuss weight management and to ask about options for weight loss.',
  'Hi doctor, I''ve been struggling with my weight for a few years now and I was hoping you could help me with some options, including possibly some medication to help me lose weight.',
  'You have been struggling with your weight for the past two to three years. Your BMI is 34. You were diagnosed with obstructive sleep apnoea three months ago and use a CPAP machine each night. You were told at the sleep clinic that losing weight would improve your symptoms and were advised to speak to your GP.',
  ARRAY['You have tried dieting in the past but find it difficult to maintain, and you still eat junk food from time to time.','You started doing daily walks about two weeks ago but are unsure what else you could be doing.','You are looking for medications to help with weight loss, as you find it hard to keep your weight down despite your efforts.','Your CPAP machine has helped improve your sleep quality.','You have a wife and two children at home.','You have a sedentary job as a software developer, which involves sitting for long periods.','You do not smoke or drink alcohol.'],
  'You are married with two children. You work as a software developer, which involves prolonged sitting at a desk. You do not smoke or drink alcohol.',
  'You feel that medication would help you lose weight more effectively than lifestyle changes alone.',
  'You are worried about the impact of your weight on your health, particularly in relation to your obstructive sleep apnoea.',
  'You would like the GP to provide options for weight loss medications and advice on improving your overall health.',
  ARRAY[]::text[],
  NULL,
  'SAY NO TO ANY OTHER QUESTIONS ASKED',
  ARRAY['Ask how long the patient has been struggling to lose weight.','Ask about previous weight loss efforts, including any specific diets or strategies tried in the past.','Ask about current diet, including typical food choices such as junk food, snacks, and portion sizes.','Ask about current level of physical activity.','Ask about the impact of weight on his health, particularly in relation to his sleep apnoea and any other conditions.','Ask whether he is experiencing any other effects of obesity such as joint pain, lower back pain, breathlessness, or difficulty with daily activities or mobility.','Ask about social history — occupation (to identify sedentary lifestyle), smoking, and alcohol.','Ask about family history of obesity, and also family history of diabetes, high blood pressure, or heart disease.'],
  ARRAY['Offer blood tests including thyroid function to rule out any underlying medical causes of weight gain.','Advise the patient to continue with current diet and lifestyle changes, as he is only two weeks into implementing an exercise routine.','Explain that if there is no significant improvement after two to three months, medication may be considered.','Discuss medication options such as Orlistat and GLP-1 receptor agonists (e.g., Mounjaro/tirzepatide).','Offer a referral to a dietitian for tailored nutritional support.','Offer referral to local weight management services for counselling and structured exercise support.','Cognitive Behavioural Therapy (CBT) for weight management or mindful eating programmes can also be offered to address emotional eating and support long-term behaviour change.','Arrange follow-up in 3 to 4 months to assess progress with weight loss and evaluate any changes in sleep quality or sleep apnoea symptoms.'],
  'Thank you for booking this appointment, and well done for taking this step — addressing weight proactively is one of the most important things you can do for your long-term health, and I am really pleased to be able to support you with this.

You have mentioned that your BMI is 34, which places you in the obese category. I know that label can feel disheartening, but I want to use it constructively — because it also means that even modest weight loss of five to ten percent of your body weight can make a meaningful difference to how you feel and to your sleep apnoea symptoms. The team at the sleep clinic were absolutely right to mention this to you.

Before we talk about treatment options, I would like to arrange a blood test — in particular to check your thyroid function. An underactive thyroid can make it genuinely much harder to lose weight, and it is worth excluding this before we assume the issue is purely lifestyle-related. We can also check a few other things at the same time.

In terms of your current approach: I want to genuinely commend you on starting the daily walks two weeks ago. That is a positive change and a really good foundation to build on. For sustainable weight loss, the general guidance is to work towards around 150 minutes of moderate-intensity activity per week — so roughly 30 minutes on five days. Walking, cycling, and swimming all count, and you do not need to do it all at once. Alongside the exercise, a balanced diet with reduced processed and high-calorie foods will make a significant difference. I would like to refer you to a dietitian, who can work with you one-to-one to create a realistic and sustainable eating plan that fits around your family and work life.

I would also like to refer you to our local weight management service, Martin. They offer a structured programme combining nutritional support, physical activity coaching, and sometimes counselling — and some people also find that a course of Cognitive Behavioural Therapy or mindful eating support helps them understand and change their relationship with food in a longer-term way.

Regarding medication: I want to be honest with you that we have good options available if they are needed. Orlistat works by reducing the amount of fat absorbed from food — it is effective but does come with side effects including oily stools, increased bowel movements, and abdominal discomfort. There is also a newer injection called Mounjaro, which is a tirzepatide-based GLP-1 receptor agonist — it works by reducing appetite and increasing the feeling of fullness, and it can be very effective. It can cause nausea, vomiting, and diarrhoea, particularly at the start.

However, given that you have only been making these lifestyle changes for two weeks, I would recommend we give diet and exercise a fair chance first — around two to three months. Many people make significant progress with structured support during this time, and it is important we give the lifestyle approach proper time to work. If after three to four months you have not made sufficient progress, we can absolutely revisit medication at that point.',
  ARRAY['For a patient with stage 1 obesity (BMI 30-34.9) and a comorbidity such as obstructive sleep apnoea, pharmacological treatment is clinically justified, but should be considered only after lifestyle interventions have been initiated and given adequate time — typically two to three months.','Weight loss of 5-10% of body weight can produce clinically significant improvements in obstructive sleep apnoea symptoms.','Thyroid function should be checked to exclude hypothyroidism as a reversible cause of weight gain before attributing difficulty with weight loss solely to lifestyle factors.','First-line lifestyle advice should target 150 minutes of moderate-intensity physical activity per week, alongside dietary modification; referral to a dietitian and local weight management services should be offered.','Orlistat reduces dietary fat absorption and is an established first-line weight loss medication; key side effects include steatorrhoea, faecal urgency, and abdominal cramps.','GLP-1 receptor agonists such as tirzepatide (Mounjaro) are increasingly used for weight management and can be considered if lifestyle interventions alone are insufficient; side effects include nausea, vomiting, and diarrhoea.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  150,
  'Request to Withhold Sensitive Information',
  'Ethics',
  'Telephone consultation',
  false,
  'Laura Sanderson',
  '35-year-old female',
  ARRAY['Temporary registration at the practice 2 days ago','Mirena coil (fitted 2 years ago)'],
  ARRAY[]::text[],
  NULL,
  'Patient booked an urgent appointment to discuss some private and personal concerns.',
  'Hi, I need to speak to a doctor about something quite sensitive. I hope you can help me — I''d like this to stay completely private.',
  'You are concerned about the possibility of having contracted a sexually transmitted infection following an unprotected sexual encounter with a male partner approximately two weeks ago. You are temporarily registered at this practice.',
  ARRAY['The sexual encounter took place at a leaving party for a colleague who was emigrating to Canada. The encounter was unprotected and consensual.','You currently have no symptoms of any STI but are still worried about the risk.','You are using the Mirena coil for contraception and have had no problems with it.','You are otherwise in good health and have used contraception during most sexual encounters not involving your husband.','You are married with two children.','You do not smoke and do not drink alcohol.'],
  'You are married with two children. You are a non-smoker and do not drink alcohol. You work as a radiographer at a local hospital.',
  'You are worried about the possibility of having an STI even though you have no symptoms at present. You are also concerned about your privacy — specifically, you do not want your sexual history to be shared with colleagues at the GP practice where you are permanently registered, which is where you work.',
  'You do not want the GP to transfer any information from this consultation or your sexual health history to your regular GP practice, which is the same practice where you work. You feel uncomfortable about colleagues potentially accessing your personal records.',
  'You expect this consultation to remain confidential and want a solution that avoids data being transferred to your regular practice. You want to rule out any STIs and receive clear guidance on the next steps for testing and management.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY['Signpost that you will be asking some personal questions and reassure her of confidentiality before proceeding.','Ask about the recent sexual encounter — when it took place, the setting, and how many partners were involved. Establish the timing clearly, as any encounter within the last 72 hours would make the patient eligible for post-exposure prophylaxis (PEP) for HIV.','Ask whether condoms were used.','Ask about STI symptoms — vaginal discharge, lower abdominal or pelvic pain, intermenstrual bleeding, or post-coital bleeding.','Ask about last menstrual period, confirm whether cervical screening is up to date, and confirm whether the Mirena coil is still in situ.','Ask about sexual health history — any previous STI tests, number of sexual partners, and prior STIs.','Ask about social history — smoking, alcohol, occupation.','Explore her concerns about privacy and confidentiality in relation to her regular GP practice.'],
  ARRAY['Offer a full STI screen including testing for chlamydia, gonorrhoea, syphilis, and HIV. This can be carried out using a urine sample, blood tests, and swabs. Advise that the HIV test will need to be repeated at three months.','Offer referral to a GUM (sexual health) clinic.','Address her privacy concerns by offering her a range of options: she can choose to permanently register at this practice, or she may prefer to attend a local sexual health clinic where records are kept confidential and are not routinely shared with the GP.','If she feels uncomfortable attending a local clinic, reassure her that she can attend a sexual health clinic in a different area — sexual health services are confidential and accessible regardless of location.','Reassure her that when records are transferred, they can be restricted so that only clinicians directly involved in her care have access to sensitive information.','Reassure her that all healthcare professionals are bound by data protection legislation and strict confidentiality obligations, and that records are not accessed unless directly necessary for patient care.','Discuss the importance of using condoms in future encounters to protect against STIs, even when using long-term contraception such as the Mirena coil.','Advise her to avoid unprotected sex with her husband until her results are confirmed — including the follow-up HIV test at three months — to reduce any risk of onward transmission.','If she wishes to have the tests carried out at this GP surgery, offer to arrange this and provide follow-up to discuss the results.'],
  'Thank you for calling and for trusting me with something so personal. I want to reassure you straightaway that everything you share with me in this consultation is confidential, and I will take your privacy concerns very seriously throughout our conversation.

I can hear that you are anxious, Laura, and I want you to know that your instinct to seek advice even without symptoms is absolutely the right one. Many sexually transmitted infections can be completely silent in the early stages — there may be no discharge, no pain, and no outward signs at all, yet the infection can still be present. So it is sensible and responsible to get tested even when you feel well.

Given that the unprotected encounter happened around two weeks ago, I would recommend a full STI screen. This would include testing for chlamydia, gonorrhoea, syphilis, and HIV. The tests themselves are straightforward — a urine sample, a few swabs, and a blood test. I want to mention one specific thing about HIV: the initial test we do now is a very good indicator, but guidelines recommend repeating the HIV test at three months to be certain, as it can sometimes take that long for the test to reliably detect the virus.

Now, regarding your concerns about privacy — I want to be very clear that I take this seriously and I understand exactly why it matters to you. In the NHS, medical information is stored electronically, and data can be shared between practices as part of standard care. However, you have options here, and I want to explain them all so you can make the choice that feels right for you.

One option is to permanently register with us at this practice, which would mean your records here would be your primary records. Alternatively, you could attend a sexual health or GUM clinic. Sexual health clinics operate under their own confidentiality framework and do not routinely share records with your GP unless you specifically consent to that. You can attend any clinic you choose — it does not have to be your local one; if you would feel more comfortable attending a clinic in a different part of the city or in another town entirely, that is completely fine, and many people in similar situations make that choice.

If you do choose to have testing done here, I can arrange for the relevant information to be marked as sensitive within your records, which restricts access to only the clinicians directly involved in your care. And I can reassure you that all healthcare professionals — including administrative staff — are bound by strict data protection laws and professional codes of conduct. Accessing a patient''s records without a legitimate clinical reason is a serious disciplinary and legal matter.

Finally, going forward, I would encourage you to consider using condoms in addition to your Mirena coil for any sexual encounters outside of your relationship. The coil is an excellent contraceptive but offers no protection against STIs, and condoms provide a simple and reliable additional layer of protection. In the meantime, I would also advise avoiding unprotected sex with your husband until your test results are back and confirmed — including the three-month HIV follow-up — just to be cautious.',
  ARRAY['A patient who is temporarily registered at a practice has the same rights to confidentiality as any permanently registered patient — being temporarily registered does not reduce privacy protections.','Sexual health clinics (GUM clinics) maintain their own confidentiality framework and do not routinely share records with a patient''s GP unless the patient explicitly consents to this — this should be clearly explained to patients with privacy concerns.','A full STI screen following unprotected intercourse should include chlamydia, gonorrhoea, syphilis, and HIV; the HIV test requires a repeat at three months, as the window period means an earlier test may not reliably detect infection.','If a sexual encounter occurred within the last 72 hours, eligibility for HIV post-exposure prophylaxis (PEP) must be assessed — this is a time-critical intervention.','Patients can be advised that records can be restricted or marked as sensitive to limit access to clinicians directly involved in their care, and that all NHS staff are bound by data protection law and professional confidentiality obligations.','The Mirena coil provides effective contraception but offers no protection against STIs — consistent use of condoms should be discussed for any encounters outside a mutually monogamous relationship.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  151,
  'Gambling Disorder',
  'Mental Health',
  'Video Consultation',
  false,
  'Adam Clarke',
  '38-year-old male',
  ARRAY['No significant past medical history','No known drug allergies'],
  ARRAY[]::text[],
  NULL,
  'Patient booked a routine appointment to discuss concerns about poor sleep and irritability, at the request of his wife.',
  'Doctor, my wife thinks I''ve been really irritable lately, and I''ve also been struggling to get to sleep at night. I was wondering if I could get something to help me sleep.',
  'You have been struggling to sleep and feeling irritable for around five to six weeks. You stay up most nights checking your phone — looking at the outcomes of your bets, working out where you can borrow more money from, and trying to figure out how to recover what you''ve lost. You get easily frustrated and angry when your bets don''t come in.',
  ARRAY[
    'You have been gambling online for over a year, but things have got significantly worse over the past six months.',
    'You often chase your losses, placing further bets in the hope of winning back money you have already lost.',
    'You have taken out loans, borrowed money from friends, and sold your motorbike, but told your wife it had been stolen.',
    'You feel ashamed and overwhelmed by the situation.',
    'You do not want your wife to find out — this must remain confidential.',
    'You are willing to seek help but feel scared and are not sure what the first steps would be.',
    'Your mood is not low all the time, mainly when you have lost money on a bet.'
  ],
  'You are married with two children. You work full-time as a logistics coordinator and your manager has recently commented that your performance has been slipping. You are a non-smoker and drink alcohol only occasionally.',
  'You feel you are simply under stress and that a good night''s sleep would sort things out.',
  'You are worried about losing control of the situation, the financial pressure building up, and the possibility of your wife discovering what has been going on.',
  'You would like sleeping tablets to help you through this difficult period, and possibly some general advice on managing stress. You would not necessarily bring up the gambling yourself unless the GP raised it in a non-judgmental way.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any unrelated medical questions.',
  ARRAY[
    'Ask how long the patient has been feeling irritable and experiencing sleep difficulties',
    'Ask about bedtime routine — what time he goes to bed, use of screens such as phones, tablets, or laptops, and the sleep environment',
    'Ask about possible triggers for poor sleep — such as stress, financial worries, shift work, or recent life changes',
    'Ask about any noticeable behaviours during sleep, including snoring, restless leg movements, or witnessed episodes of apnoea',
    'Clarify what is meant by irritability — for example, whether he is short-tempered, easily frustrated, or snapping at family members',
    'If the patient opens up about gambling, ask when it started and explore whether the behaviour has been persistent — typically over 12 months or more — and whether it occurs online or offline',
    'Ask whether he finds himself preoccupied with gambling or prioritising it over other responsibilities, relationships, or daily activities',
    'Ask how the symptoms have affected his relationship, work, and social life',
    'Ask about mood — screen for depression and anxiety',
    'Ask about any thoughts of self-harm or suicide',
    'Ask about social history: occupation, alcohol, smoking, family situation',
    'Make a diagnosis of gambling disorder causing insomnia and irritability'
  ],
  ARRAY[
    'Offer brief advice on sleep hygiene: reduce screen use before bed, establish a consistent bedtime routine, avoid naps during the day, and use stress reduction techniques',
    'Offer to provide written information or leaflets with further sleep hygiene strategies',
    'Advise against the routine use of sleeping tablets. If good sleep hygiene has been tried without success and insomnia is causing significant daytime impairment, a short course (3–7 days) of a non-benzodiazepine hypnotic such as zopiclone may be considered',
    'Offer referral to the National Gambling Helpline (run by GamCare)',
    'Offer referral to GambleAware',
    'Offer referral to the Primary Care Gambling Service',
    'Offer referral to GamLearn',
    'Offer referral to Gamblers Anonymous',
    'Offer referral to CBT (cognitive behavioural therapy)',
    'Provide safety-netting advice regarding suicide risk and worsening mental health',
    'Arrange follow-up in four weeks to assess progress and emotional wellbeing'
  ],
  'Thank you for trusting me with this today, Adam — I can see how much it has been weighing on you, and it takes real courage to speak openly about what''s been going on. You came in asking for something to help with your sleep, and I completely understand why that feels like the most pressing thing right now. However, based on what you''ve shared, I think the sleep difficulties and irritability are likely symptoms of something deeper — the stress and emotional burden that comes with the gambling, rather than a problem with sleep itself.

I''m not inclined to prescribe sleeping tablets as a first step, because they don''t address what''s driving the problem and can lead to dependency if used long-term. What I''d like to do instead is help you with some strategies that address the root cause and support your sleep in a more sustainable way.

In terms of sleep, there are some practical steps we call sleep hygiene measures that can make a real difference. These include avoiding screens — phones, tablets, laptops — for at least an hour before bed, as the blue light they emit suppresses melatonin, the hormone that helps you fall asleep. Trying to wake up at the same time every morning, even after a rough night or on weekends, helps to regulate your body clock. It''s also worth avoiding naps during the day, as even short ones can make it harder to drop off at night. Building a calming wind-down routine — whether that''s reading, a warm bath, or some gentle music — can help signal to your body that it''s time to sleep.

Alongside this, I think it''s really important that we also address the gambling itself. You do not have to go through this alone, and there are excellent, confidential services specifically designed to support people in exactly your situation. These include the National Gambling Helpline, run by GamCare, GambleAware, the Primary Care Gambling Service, GamLearn, and Gamblers Anonymous. Any of these can offer confidential support without judgement.

I''d also like to refer you for CBT — cognitive behavioural therapy — which is a talking therapy that has very good evidence behind it for managing gambling disorder. It can also help with the sleep difficulties and emotional regulation that you''re finding so hard at the moment.

I want to reassure you that everything you''ve told me today is confidential. I won''t share it with anyone, including your wife, unless I felt there was a serious risk of harm — and if that were ever the case, I would always speak to you first. I''d like to follow up with you in about four weeks to see how you''re getting on. How does that sound?',
  ARRAY[
    'Patients presenting with non-specific symptoms such as insomnia or irritability should be explored carefully for underlying causes, including behavioural addictions such as gambling disorder.',
    'Gambling disorder is a recognised behavioural addiction with significant mental, financial, and relationship consequences; persistent gambling over 12 months or more, chasing losses, and preoccupation with gambling are key diagnostic features.',
    'Sleeping tablets should not be offered as first-line treatment when the underlying cause of insomnia has not been addressed; sleep hygiene measures should be advised first.',
    'A short course (3–7 days) of a non-benzodiazepine hypnotic such as zopiclone may be appropriate if sleep hygiene has failed and insomnia is causing significant daytime impairment.',
    'Referral options for gambling disorder include the National Gambling Helpline (GamCare), GambleAware, the Primary Care Gambling Service, GamLearn, and Gamblers Anonymous; CBT is an effective psychological treatment.',
    'Confidentiality must be maintained and clearly communicated to the patient to build trust and encourage engagement with support services.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  152,
  'Bowel Issues In Young Adult',
  'Gastroenterology & Haematology',
  'Telephone Consultation',
  false,
  'Daniel Webb',
  '25-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'Patient has booked a routine telephone consultation following a recent attendance at the emergency department for left-sided abdominal pain.',
  'Hi doctor, I''ve been getting this pain in my lower left tummy, and the doctors in A&E said I should come and see my GP to talk about it.',
  'You went to A&E two days ago because the pain on the left side of your lower abdomen had come on again. The pain has actually been going on for around four to five months in total. You had been trying to get a GP appointment to discuss it but hadn''t managed to, and when it flared up again you decided to go straight to A&E. A doctor examined you and told you it was most likely constipation before discharging you. No blood tests were taken.',
  ARRAY[
    'The pain is crampy in nature and situated in the lower left abdomen. It tends to occur every one to two weeks.',
    'You have noticed it is often worse when you are feeling stressed.',
    'Your bowel habits have changed. You frequently feel constipated and it can take three to four days to pass a stool.',
    'You occasionally experience loose stools, though this happens far less often than the constipation.',
    'You have noticed mucus in your stool on a number of occasions, but you have never seen any blood.',
    'You have not had any weight loss, night sweats, or fevers.',
    'There is no family history of bowel conditions or cancer.'
  ],
  'You do not smoke, drink alcohol, or use recreational drugs. You live with your girlfriend of two years. You started working as a restaurant manager eight months ago — the role was quite demanding at first and you felt stressed, but you have gradually settled into it. Your mood is good and you are not currently under significant stress.',
  'You think this is most likely constipation.',
  'The episodes keep coming back almost every week and you want to get to the bottom of it.',
  'You would like the GP to offer you some treatment to help sort this out.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided.',
  ARRAY[
    'Ask about the onset, location, character, and frequency of the abdominal pain',
    'Ask about triggers such as stress, alcohol, caffeine, or spicy food, and any relieving factors such as opening the bowels',
    'Ask about changes in bowel habit, including constipation, diarrhoea, or an alternating pattern',
    'Ask about associated symptoms such as bloating, nausea or vomiting, mucus in the stool, or a feeling of incomplete evacuation',
    'Ask about red flag symptoms including rectal bleeding, unintentional weight loss, fever, night sweats, or persistent fatigue',
    'Ask about any recent changes to diet',
    'Ask about family history of inflammatory bowel disease, coeliac disease, or colorectal cancer',
    'Ask about social history including smoking, alcohol, diet, and occupation',
    'Ask about the impact of symptoms on daily life and work',
    'Ask about the patient''s ideas, concerns, and expectations',
    'Make a diagnosis of suspected irritable bowel syndrome'
  ],
  ARRAY[
    'Offer a face-to-face appointment to perform an abdominal examination and digital rectal examination',
    'Offer baseline investigations including full blood count, urea and electrolytes, C-reactive protein, coeliac serology, and faecal calprotectin to exclude alternative pathology',
    'Advise keeping a symptom diary to help identify triggers and guide avoidance strategies',
    'Discuss stress management and encourage relaxation techniques such as mindfulness, yoga, or talking therapy where appropriate',
    'Advise the patient to aim for at least 30 minutes of moderate-intensity physical activity on five days of the week, such as brisk walking, jogging, or cycling, as this can help improve IBS symptoms, reduce stress, and support overall health',
    'Provide lifestyle and dietary advice including regular meals, adequate hydration, and a gradual increase in dietary soluble fibre such as oats and linseed; note that increasing soluble fibre should be done gradually to avoid flatulence and bloating',
    'For abdominal cramping, offer an antispasmodic such as mebeverine to help relax gut smooth muscle',
    'Inform the patient that if symptoms do not improve, referral to a dietitian for a low FODMAP diet can be considered; this involves temporarily reducing specific hard-to-digest carbohydrates for two to six weeks, followed by gradual reintroduction to identify personal triggers',
    'If the low FODMAP approach is not effective, symptomatic medications available over the counter can be used, such as loperamide for diarrhoea and appropriate laxatives for constipation; note that lactulose should be avoided in IBS as it increases bloating and flatulence',
    'Provide clear safety-net advice to seek medical attention promptly if symptoms worsen or new features develop such as rectal bleeding, unintentional weight loss, or fever',
    'Arrange follow-up in four to six weeks to review symptoms and response to treatment'
  ],
  'Thank you for calling in today, Daniel. I''m glad you got checked over in A&E, and I can understand why these recurring episodes are frustrating, especially when they''ve been going on for several months now. Let me explain what I think might be going on and what we should do next.

Based on what you''ve described — the crampy pain in the lower left abdomen coming on every week or two, the mixture of constipation and occasional loose stools, the mucus in your stool, and the fact that stress seems to make things worse — this sounds very much like irritable bowel syndrome, often referred to as IBS. IBS is a common condition affecting the way the bowel works. It is not dangerous and does not increase your risk of bowel cancer, but it can cause very uncomfortable and persistent symptoms, so I completely understand why you want it sorted.

Before I can be confident in that diagnosis, I''d like to bring you in for a face-to-face appointment so I can examine your abdomen and do a short rectal examination. I''d also like to arrange some blood tests and a stool sample test — these include a full blood count, inflammation markers, tests for coeliac disease, and something called faecal calprotectin, which helps us check for bowel inflammation. These tests are really to make sure we''re not missing anything else, and if they come back normal alongside your story, IBS becomes the most likely diagnosis.

In the meantime, there are several things that can make a real difference. Keeping a symptom diary — noting what you ate, your stress levels, and what your bowels did each day — can be incredibly useful in spotting patterns and identifying personal triggers. Regular physical activity, ideally around 30 minutes on most days, has good evidence for improving IBS symptoms. In terms of diet, try to eat regular meals, drink plenty of fluids, and if you want to increase your fibre intake, make sure you do so gradually using soluble fibre such as oats or linseed, as sudden increases can make bloating worse.

For the cramping itself, I can prescribe a medication called mebeverine, which works by relaxing the smooth muscle in the gut wall and tends to be very well tolerated. If things don''t improve with these measures, we can look at a referral to a dietitian who specialises in something called the low FODMAP diet — this involves cutting out certain types of hard-to-digest carbohydrates for a few weeks and then reintroducing them one by one to work out which ones are causing you trouble.

I''d like to follow up with you in four to six weeks to see how you are getting on. In the meantime, please do contact the practice sooner if you notice any bleeding from your back passage, unintentional weight loss, fever, or any significant change in your symptoms. Does that all sound reasonable to you?',
  ARRAY[
    'IBS is the most likely diagnosis in a young adult presenting with recurrent crampy lower abdominal pain, altered bowel habit, mucus in stool, and a clear link to stress, in the absence of red flag features.',
    'Red flag symptoms that must be excluded include rectal bleeding, unintentional weight loss, fever, night sweats, and persistent fatigue; these would prompt urgent investigation.',
    'Baseline investigations for suspected IBS should include full blood count, CRP, urea and electrolytes, coeliac serology, and faecal calprotectin to exclude organic pathology.',
    'First-line management of IBS includes lifestyle advice, stress management, regular exercise, gradual increase in soluble fibre, and antispasmodics such as mebeverine for cramping.',
    'Lactulose should be avoided in IBS as it worsens bloating and flatulence; if a laxative is needed for constipation, an alternative agent should be chosen.',
    'If first-line measures fail, referral to a dietitian for a supervised low FODMAP diet is the next step; over-the-counter symptomatic treatments such as loperamide can also be considered.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  153,
  'Diabetic Complication in Type 2 DM',
  'Endocrine & Nephrology',
  'Video Consultation',
  false,
  'Patricia Griffiths',
  '59-year-old female',
  ARRAY[
    'Hypertension — diagnosed 9 years ago',
    'Type 2 Diabetes Mellitus — diagnosed 4 years ago',
    'Medications: Metformin 1g BD, Dapagliflozin 10mg OD, Ramipril 10mg OD'
  ],
  ARRAY['No known drug allergies'],
  'Seen 4 weeks ago by diabetic specialist nurse for routine annual diabetic review. History of previously uncontrolled diabetes with recent significant improvement in HbA1c. BP 135/88 mmHg, BMI 32. U&Es and urine ACR all normal. Foot examination: no ulcers or wounds, distal pulses palpable. Standard 10g monofilament applied bilaterally at plantar aspect of 1st, 3rd, and 5th metatarsal heads, plantar aspect of hallux and 3rd toe. Patient reported no sensation at 2 sites on left foot and 1 site on right foot — score 7/10, indicating some degree of neuropathy. Plan: patient educated on daily foot self-checks and footcare; advised to book appointment with GP to discuss further. Review in 3 months.',
  'Patient has booked a routine video consultation to discuss concerns following her recent diabetic review.',
  'Hello doctor, when I went for my diabetes check a few weeks ago, the nurse tested the feeling in my feet and mentioned I should come and speak to you. I''ve also been getting a burning sensation in both my feet and legs for a couple of months now.',
  'The burning started gradually about two months ago and has been getting steadily worse. It affects both feet and legs, particularly from the ankles downwards and around the calves. It is worse at night and is now beginning to affect your sleep. It has also caused you to walk slightly differently and you feel a little unsteady at times.',
  ARRAY[
    'The sensation is a burning and tingling feeling, sometimes like walking on pins and needles. It is most noticeable when resting or lying down.',
    'There is no history of injury or trauma to the feet or legs.',
    'No significant back pain.',
    'You are able to walk but move more slowly than before and feel unsteady at times, which makes you nervous when crossing the road or standing for long periods at work.',
    'No symptoms to suggest autonomic neuropathy such as dizziness on standing, nausea, vomiting, urinary incontinence, or sweating while eating.'
  ],
  'You work in a supermarket deli counter, which involves standing for long periods. You live with your husband. You do not smoke or drink alcohol.',
  'You are not entirely sure what is causing this. The diabetic nurse suggested you see the GP after she tested your feet, but she did not seem overly alarmed.',
  'You are worried the symptoms might get worse and that you may eventually struggle to walk properly.',
  'You would like the GP to explain what is going on and to let you know whether anything can be done to relieve the burning sensation.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked.',
  ARRAY[
    'Ask about the onset, duration, and progression of the leg symptoms',
    'Ask about the nature of the pain — burning, tingling, or pins and needles',
    'Ask about relieving or aggravating factors, and whether symptoms are worse at particular times of day, especially at night (typical of diabetic neuropathy)',
    'Ask whether the pain radiates anywhere',
    'Ask about any new back pain',
    'Ask about weakness, numbness, or balance difficulties in the lower limbs',
    'Ask whether the patient has noticed any ulcerations or changes in colour of the feet',
    'Ask about any recent trauma to the feet or legs',
    'Ask about symptoms of autonomic neuropathy — gastrointestinal symptoms (abdominal pain, nausea, vomiting, faecal incontinence), genitourinary symptoms (urinary incontinence), cardiac symptoms (postural hypotension), and gustatory sweating',
    'Ask about the impact of symptoms on mobility and sleep',
    'Ask about social history including occupation, alcohol, smoking, and diet',
    'Explore the patient''s ideas, concerns, and expectations',
    'Make a diagnosis of likely diabetic peripheral neuropathy'
  ],
  ARRAY[
    'Offer a face-to-face appointment to perform a neurological examination of the lower limbs',
    'Offer further blood tests including vitamin B12 and thyroid function tests to exclude other contributory causes of neuropathy',
    'Offer referral for nerve conduction studies and electromyography to diagnose and assess the extent of nerve damage',
    'Offer a choice of neuropathic pain medication: amitriptyline, duloxetine, gabapentin, or pregabalin',
    'Advise that once other potential causes such as B12 deficiency and thyroid dysfunction have been excluded, referral to the local Foot Protection Team will be arranged',
    'Advise on regular foot self-checks and to report any ulcerations, colour changes, worsening pain, or reduced sensation in the feet or legs',
    'Safety net and advise the patient to seek urgent medical attention if they notice any weakness in the lower limbs, worsening pain, changes in leg colour, or development of ulcers'
  ],
  'Thank you for coming to speak with me today, Patricia — and well done for attending your diabetic review and for making this follow-up appointment. I can hear that the burning sensation has been quite distressing, especially now that it is affecting your sleep and your confidence when walking.

Based on everything you''ve told me, and taking into account the results of the monofilament test from your recent diabetic review, I think you may be developing something called diabetic peripheral neuropathy. This is a condition where, over time, high blood sugar levels can cause damage to the small nerves — particularly in the feet and lower legs. It typically causes exactly the kind of burning, tingling, and pins-and-needles sensation that you''ve been describing, and it''s often worse at night, which fits with your experience.

The good news is that your recent blood sugar results have shown real improvement, and that is genuinely important. Keeping blood sugars well controlled is one of the most effective things we can do to slow down or prevent further nerve damage from progressing. The fact that we''ve picked this up relatively early through the monofilament test means we can act now.

However, before we settle on this diagnosis, I want to make sure we''re not missing any other cause for your symptoms. There are other conditions that can cause similar nerve pain — for example, vitamin B12 deficiency, which can actually occur as a side effect of long-term metformin use, and thyroid problems. I''d like to arrange blood tests to check for both of these, as well as any other relevant causes.

I''d also like to bring you in for a face-to-face appointment so I can examine the nerves in your legs more thoroughly. If needed, I can also refer you for a nerve conduction study — this is a specialist test that helps us understand exactly how severely the nerves are affected and guides our management.

In the meantime, regarding the burning pain itself, there are several medications that can help with this type of nerve pain. These include amitriptyline, duloxetine, gabapentin, and pregabalin. Your notes confirm you have no allergies, so we have options. I''d like to discuss these with you at your face-to-face appointment so we can choose what suits you best. Finally, please do continue your daily foot checks — look out for any ulcers, colour changes, or areas where the skin looks broken — and contact us promptly if anything new develops.',
  ARRAY[
    'Diabetic peripheral neuropathy should be suspected in patients with type 2 diabetes who present with bilateral burning, tingling, or pins-and-needles in the feet and lower legs, particularly when symptoms are worse at night.',
    'The 10g monofilament test is used to assess protective sensation in the feet; a score of 7/10 or below indicates reduced sensation and should prompt GP review.',
    'Other causes of peripheral neuropathy must be excluded, particularly vitamin B12 deficiency (which can be caused by long-term metformin use) and thyroid dysfunction.',
    'Further investigation should include vitamin B12, thyroid function tests, nerve conduction studies, and electromyography to assess the extent of nerve damage.',
    'First-line pharmacological options for diabetic neuropathic pain include amitriptyline, duloxetine, gabapentin, and pregabalin — the choice should be individualised.',
    'Once other causes have been excluded, referral to the local Foot Protection Team is appropriate; ongoing foot self-checks and safety-netting about ulcers and colour changes are essential.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  154,
  'Post-Partum Hair Loss',
  'Gynaecology & Women''s Health',
  'Video Consultation',
  false,
  'Claire Harrison',
  '32-year-old female',
  ARRAY[
    'Postpartum (four months)',
    'History of eclampsia requiring emergency caesarean section',
    'Hypertension'
  ],
  ARRAY['Ramipril 5mg once daily','No known drug allergies'],
  NULL,
  'Patient has booked a routine video consultation to discuss concerns about hair loss since having her baby.',
  'Doctor, I''ve been losing quite a lot of hair over the past few weeks and it''s really starting to worry me.',
  'You first noticed the hair shedding about a month ago. It started in the shower, then you began seeing a lot more hair on your brush, and more recently you''ve noticed it on your pillow as well. You are now quite concerned that you might be losing too much.',
  ARRAY[
    'The hair loss is spread across the whole scalp rather than in one particular area. There is no pain, itching, rash, or flaking of the scalp, and there are no bald patches.',
    'You gave birth nearly four months ago. Your pregnancy was complicated by pregnancy-induced hypertension, which led to seizures, and you required an emergency caesarean section. You subsequently developed sepsis and were admitted to hospital for six days and treated with antibiotics. You are now well and recovered.',
    'You have no other symptoms.',
    'You are not breastfeeding — your baby is formula fed.',
    'You were started on ramipril after delivery to help control your blood pressure.',
    'Your last menstrual period was five days ago. You are not pregnant, as you have not been sexually active since delivery and are not currently using contraception.',
    'There is no family history of hair loss.'
  ],
  'You do not smoke, drink alcohol, or use recreational drugs. You live with your partner and your four-month-old baby. You work as a nursery nurse but are currently on maternity leave. You are not experiencing significant stress at the moment. Your baby is doing well and you have no concerns about him.',
  'You have read in the information leaflet that came with ramipril that hair loss can be a side effect, so you think the medication may be causing it.',
  'You are worried the hair loss could continue to get worse and start to noticeably affect your appearance.',
  'You would like to know whether you should stop taking ramipril and whether you could be switched to a different medication.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided.',
  ARRAY[
    'Ask about the onset of hair loss, whether it was sudden or gradual, and which areas of the scalp are affected',
    'Ask whether the hair loss is due to shedding or thinning; note that shedding is more suggestive of telogen effluvium or iron deficiency anaemia, whereas thinning is more suggestive of female androgenetic alopecia, polycystic ovary syndrome, or hypothyroidism',
    'Ask about patches of hair loss, scarring, redness, rashes, or scaling of the scalp',
    'Ask about hair care routine and any recent changes in hairstyle, traction, heat treatments, or use of new hair products',
    'Ask about family history of hair loss',
    'Ask whether the patient has started any new prescribed medications or is using over-the-counter treatments or supplements',
    'Ask about recent stressors or significant life events, including the pregnancy, delivery, and whether the birth experience was traumatic',
    'Ask about dietary changes or significant weight loss or gain',
    'Ask about the menstrual cycle, whether periods have returned, and if they are heavy, as this may contribute to iron deficiency anaemia',
    'Ask about social history including smoking, alcohol intake, home circumstances, mood, and psychological wellbeing',
    'Ask about the impact of hair loss on confidence and daily life',
    'Explore the patient''s ideas, concerns, and expectations',
    'Make a diagnosis of likely postpartum telogen effluvium'
  ],
  ARRAY[
    'Reassure the patient that the presentation is most consistent with postpartum telogen effluvium, which is common and self-limiting',
    'Offer a face-to-face review to assess the hair and scalp and to perform a hair pull test',
    'Acknowledge that ramipril can be associated with hair loss; however, explain that in this case the hair loss is more likely due to telogen effluvium',
    'Advise a watch-and-wait approach, as symptoms often improve spontaneously over time',
    'Explain that if hair loss worsens or fails to improve, ramipril can be stopped and an alternative antihypertensive considered',
    'Offer blood tests to exclude other contributory causes, including full blood count, thyroid function tests, ferritin, vitamin B12, and vitamin D',
    'Discuss cosmetic and supportive measures to improve appearance and confidence, such as hairstyling techniques, colouring, hairsprays, hairpieces, or wigs',
    'Provide safety-net advice to recontact the practice if hair loss worsens, new symptoms develop, or she has ongoing concerns',
    'Arrange follow-up in two to three months to review progress'
  ],
  'Thank you for reaching out today, Claire, and I''m really glad you came to discuss this. Losing hair can feel very alarming, especially when you''ve already been through such a challenging few months with your delivery and recovery. Let me try to put your mind at ease and explain what I think is most likely going on.

What you''re describing — diffuse shedding across the whole scalp, starting about three to four months after giving birth — is a very well-recognised condition called postpartum telogen effluvium. During pregnancy, elevated hormone levels actually keep more hairs in the active growth phase for longer than usual, so you tend to lose less hair than normal. After delivery, those hormone levels drop suddenly, which causes a larger-than-usual number of hairs to shift into the resting and shedding phase all at once. The result is that noticeable shedding, which is often most obvious in the shower or on the hairbrush, tends to peak around three to four months after birth — which fits exactly with your timeline.

I noticed from your notes that you raised the possibility of ramipril causing this, and I want to acknowledge that you''re right that hair loss can occasionally be listed as a side effect of ramipril. However, given the timing of your symptoms and the postpartum context, I think telogen effluvium is a much more likely explanation in your case. We''ll keep ramipril in mind though — if your hair loss doesn''t improve in the coming months, stopping it and switching to an alternative blood pressure medication is absolutely something we can consider.

The reassuring news about postpartum telogen effluvium is that it is self-limiting, meaning it does resolve on its own. Most women see a significant improvement within six to twelve months of delivery without needing any specific treatment.

That said, I would like to run some blood tests to make sure there are no other factors contributing — for example, iron deficiency, thyroid problems, low vitamin B12, or low vitamin D are all things that can worsen hair shedding and are worth checking. I''d also like to bring you in for a face-to-face appointment so I can take a proper look at your scalp and hair.

In the meantime, for day-to-day confidence, there are some helpful cosmetic options worth knowing about — volumising sprays, certain styling techniques, or even clip-in hairpieces can make a real difference to how the hair looks while it recovers. Please do come back if the hair loss seems to be getting worse rather than better, or if any new symptoms develop. I''ll plan to follow up with you in around two to three months to see how things are progressing.',
  ARRAY[
    'Postpartum telogen effluvium is a common, self-limiting cause of diffuse hair shedding that typically peaks three to four months after delivery, driven by the sudden postpartum drop in oestrogen and progesterone.',
    'Key features pointing to telogen effluvium include diffuse scalp shedding (rather than patterned thinning or bald patches), absence of scalp inflammation, and a clear temporal relationship with a recent stressor such as childbirth.',
    'Ramipril can be associated with hair loss as a side effect, but in the postpartum context telogen effluvium is more likely; if hair loss fails to resolve, stopping ramipril and switching antihypertensive should be considered.',
    'Blood tests to exclude contributory causes should include full blood count, ferritin, thyroid function tests, vitamin B12, and vitamin D.',
    'A hair pull test at face-to-face review can help confirm the diagnosis and assess severity.',
    'Management is mainly reassurance and watchful waiting, with cosmetic measures to support confidence; follow-up in two to three months is appropriate.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  155,
  'Breathing Difficulties In A Child',
  'Paediatrics',
  'Telephone Consultation',
  false,
  'Lucas Bennett',
  '4-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'Mother has called to discuss her son''s recurrent episodes of coughing and breathing difficulty.',
  'Hi doctor, I''m calling about my son Lucas. He''s four years old and he keeps getting this cough and wheeze. It''s been happening on and off for a few months now and I''m not sure what''s going on.',
  'Lucas has been having episodes of coughing and wheezing for around three to four months. The episodes seem to come on particularly at night and in the early morning. The cough is dry and can be quite persistent. He has also had some episodes of shortness of breath. The symptoms seem to ease on their own after a while but keep coming back. He has not had a fever with these episodes.',
  ARRAY[
    'The cough and wheeze tend to be worse at night and early in the morning.',
    'The episodes have been happening on and off for around three to four months.',
    'There is no fever during these episodes, which makes a chest infection less likely.',
    'Lucas is otherwise well — eating, drinking, and growing normally.',
    'He lives at home with his mum and dad. There are no other children at home and no pets.',
    'There are no smokers in the household.',
    'He is due to start reception class soon.',
    'Family history: his father has eczema. There is no family history of asthma or hay fever (only say this if asked).'
  ],
  'Lucas lives at home with his mum and dad. There are no other children in the household and no pets. There are no smokers in the home. He is due to start reception class soon. He is eating, drinking, and growing well.',
  'You''re not sure — perhaps he keeps getting chest infections?',
  'You''re worried this isn''t going away and that it might be something more serious.',
  'You''re wondering whether he needs antibiotics or some other treatment to get on top of this.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked.',
  ARRAY[
    'Ask about the onset and duration of symptoms, and whether they have been getting better or worse over time',
    'Ask about the character of the cough — whether it is dry or productive — and about any associated wheeze or shortness of breath',
    'Ask whether symptoms are worse at particular times — especially at night or early morning, which is typical of asthma',
    'Ask about potential triggers such as exercise, cold air, allergens, or respiratory infections',
    'Ask about fever, as its absence during wheeze episodes makes infection less likely and asthma more likely',
    'Ask about any eczema or allergic rhinitis in the child',
    'Ask about family history of asthma, eczema, or hay fever (atopic triad)',
    'Ask about the home environment — pets, smokers in the household, damp or mould',
    'Ask about the child''s general health, including feeding, growth, and development',
    'Ask about the impact on the child''s sleep and daily activities',
    'Explore the parent''s ideas, concerns, and expectations',
    'Make a diagnosis of likely childhood asthma'
  ],
  ARRAY[
    'Offer a face-to-face appointment to assess the chest, including auscultation and observation of respiratory effort',
    'Offer an 8-week trial of paediatric low-dose inhaled corticosteroids (ICS) as maintenance therapy (e.g. Clenil Modulite MDI 100mcg, 2 puffs twice daily) alongside a short-acting beta-agonist (SABA) for symptom relief',
    'Offer a spacer device for delivery of inhaled medications',
    'Advise keeping a symptom diary to help identify potential triggers and guide avoidance strategies',
    'Review in 8 weeks to assess response to treatment',
    'Safety net and advise the mother: if Lucas''s symptoms do not improve after using the inhaler as directed, or if he needs the reliever inhaler (blue one) more than three times a week, or if he is still waking at night regularly with cough or breathing difficulty, to seek urgent medical advice',
    'Safety net for red flags: advise the mother that if Lucas becomes breathless at rest, struggles to speak or eat, his breathing looks laboured with his tummy drawing in, or his lips or face look pale or bluish, to seek emergency medical attention immediately'
  ],
  'Thank you for calling today. I can hear how worried you''ve been about Lucas, and I''m glad you got in touch. Recurrent episodes of coughing and wheezing that keep coming back over several months — particularly at night and first thing in the morning — are something we always take seriously in young children. Let me explain what I think is most likely going on.

The pattern of symptoms you''ve described — the dry cough, the wheeze, the fact that it keeps recurring and is worse at night — is very characteristic of childhood asthma. Asthma is actually the most common chronic respiratory condition in children, and it''s important to know that with the right treatment, the vast majority of children manage it very well and live completely normal, active lives.

I would like to see Lucas in person so I can listen to his chest and take a closer look at his breathing. This will help me confirm what''s going on and rule out any other causes.

If, as I suspect, this is asthma, the standard treatment for a child of his age is a small preventer inhaler — this is taken every day to reduce inflammation in the airways and prevent the episodes from happening in the first place. We would also give him a reliever inhaler — the blue one — to use when he has symptoms. The preventer would be something called Clenil Modulite, which contains an inhaled steroid at a low dose: 100 micrograms, two puffs in the morning and two puffs at night. We would give this as an eight-week trial to see whether his symptoms improve. Alongside this, I''d recommend using a device called a spacer, which makes it much easier for young children to get the medication into their lungs effectively.

It would also be really helpful to keep a brief diary of his symptoms — when the cough or wheeze happens, how long it lasts, and whether anything seems to set it off. This will help us spot any patterns and identify triggers such as cold air, exercise, or exposure to certain allergens.

I want to make sure you know when to seek help urgently. If Lucas is struggling to breathe even when he''s sitting still, can''t speak or eat because of his breathing, or if his tummy is visibly pulling in with each breath, or his lips or face look pale or bluish — please call 999 straight away. If his symptoms aren''t responding to the inhaler or he''s needing the blue reliever more than three times a week, please contact us promptly and don''t wait for the review appointment. We''ll plan to follow up in eight weeks to see how he''s responded to treatment.',
  ARRAY[
    'Childhood asthma should be suspected in a child with recurrent dry cough and wheeze, particularly when symptoms are worse at night and in the early morning, in the absence of fever.',
    'A positive family history of atopy (eczema, hay fever, or asthma) and an allergen-free, smoke-free home environment are important contextual factors to explore.',
    'First-line maintenance treatment for suspected asthma in a pre-school child is a low-dose inhaled corticosteroid such as Clenil Modulite MDI 100mcg, 2 puffs twice daily, alongside a SABA reliever inhaler, given as an 8-week trial.',
    'A spacer device must always be used with a metered-dose inhaler (MDI) in young children to ensure effective drug delivery.',
    'Safety-netting should cover both urgent red flags (cyanosis, inability to speak or eat, severe breathlessness at rest) and early review triggers (requiring reliever more than three times per week, or persistent nocturnal symptoms).',
    'A symptom diary helps identify triggers and monitor treatment response; review should be arranged at 8 weeks.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  156,
  'Acne in Young Adult Male',
  'Dermatology',
  'Telephone Consultation',
  false,
  'Marcus Osei',
  '17-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'Patient has booked a telephone consultation to discuss ongoing acne that has not responded to previous topical treatments.',
  'Hi doctor, I''ve been using the acne creams I was given before but they''re not really doing anything. My skin is still really bad and it''s getting me down.',
  'Your acne has been present for around two years and has been gradually getting worse despite using topical treatments. You were prescribed a topical cream some months ago but feel it has made little difference. You have been using it as directed but are frustrated that you haven''t seen any improvement.',
  ARRAY[
    'The acne affects your face, particularly the cheeks and chin. You also have some spots on your chest and back.',
    'There is some scarring and dark patches appearing in areas where spots have healed.',
    'You haven''t changed any face creams or washing routines recently.',
    'You have not taken any oral medications for your acne.',
    'The acne is having a significant impact on your confidence. You feel self-conscious in social situations and find it hard to look people in the eye.',
    'Your mood is low because of how your skin looks. You have not had any thoughts of self-harm or suicide.',
    'There is no fever or joint pain.',
    'There is a family history of acne — your father had it when he was a teenager.',
    'You do not want any more creams. You want a tablet — specifically Accutane.'
  ],
  'You do not drink, smoke, or use recreational drugs. You live with your parents at home. You are currently studying for your A-Levels at sixth form college. You have no history of mental illness. You are not in a relationship and have not experienced any bullying or self-harm. Housemates or classmates have not commented on your skin.',
  'You feel the creams aren''t working and that tablets would be more effective.',
  'You are worried the acne might not clear up and that your confidence will keep getting worse.',
  'You are hoping the GP can prescribe Accutane today. You do not want to use any more creams.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked.',
  ARRAY[
    'Ask about the onset, duration, and progression of the acne',
    'Ask about other sites involved apart from the face — such as the chest or back',
    'Ask about the presence of scarring or pigmentation changes, such as dark spots or patches in the affected areas',
    'Ask about potential triggers such as face creams, excessive face washing, or contraceptives and periods (in females)',
    'Ask about previous treatments tried and compliance, noting that acne treatments are usually assessed after at least three months of use',
    'Ask about the impact on mood, self-esteem, and social life',
    'Ask about mental health concerns — particularly low mood, self-harm, or suicidal ideation',
    'Ask about social history: smoking, alcohol, drug use, school or college life, and family and home circumstances',
    'Ask about family history of acne',
    'Rule out systemic involvement by asking about fever and joint pains',
    'Ask about ideas, concerns, and expectations',
    'Give a diagnosis of moderate acne'
  ],
  ARRAY[
    'Inform the patient of the next step in management: oral antibiotics for moderate acne (e.g. lymecycline 408mg once daily or doxycycline 100mg once daily for 3–6 months) in combination with a topical non-antibiotic agent such as Epiduo (benzoyl peroxide plus adapalene), topical azelaic acid 15%, or azelaic acid 20%',
    'Refer to dermatology for consideration of isotretinoin (Accutane) in line with NICE guidance — NICE recommends referring people to dermatology if their acne of any severity, or acne-related scarring, is causing or contributing to persistent psychological distress or a mental health disorder',
    'While awaiting dermatology referral, offer oral antibiotics plus a topical agent (Epiduo or azelaic acid) if the patient is willing',
    'Offer referral to CBT as the acne is having a significant impact on the patient''s mental health',
    'Advise against picking or squeezing spots',
    'Advise to avoid excessive face cleansing, which can cause dryness and skin irritation',
    'Safety net: advise the patient to return if acne worsens, mood deteriorates or thoughts of self-harm or suicide develop, or if side effects occur from medication',
    'Follow-up in 8–12 weeks to review response if the patient agrees to oral antibiotics plus a topical agent'
  ],
  'Thank you for calling in today. I can hear that this has been really difficult for you, and I want you to know that what you''re going through is completely understandable. Acne that doesn''t respond to treatment and affects the way you feel about yourself day-to-day is not something to brush aside — the impact on confidence and mood is real, and I take it seriously.

Let me explain where I think things stand. Based on what you''ve described — acne on the face, chest, and back that has been present for around two years, with some scarring and skin discolouration developing, and the clear impact on your mental wellbeing — I would classify this as moderate acne. The fact that topical treatments haven''t given you enough improvement is also important information.

I completely hear that you want a tablet rather than more creams, Marcus, and I think that''s a very reasonable position given what you''ve been through. The tablets used for acne at this stage are oral antibiotics — the main ones we use are lymecycline 408mg once a day or doxycycline 100mg once a day, taken for a course of three to six months. These work by targeting the bacteria involved in acne and also have an anti-inflammatory effect. However, there is an important rule with oral antibiotics for acne: they must always be used alongside a topical non-antibiotic treatment. This is because using antibiotics alone can lead to antibiotic resistance over time. So we would combine the antibiotic tablet with a topical gel — for example Epiduo, which contains benzoyl peroxide and adapalene, or an azelaic acid cream. I know you said you''re done with creams, and I completely understand that, but this combination is necessary for the treatment to work safely and effectively.

Now, I know you''ve specifically asked about Accutane — isotretinoin. This is a very effective medication for acne, but it can only be prescribed by a dermatologist, not by a GP, because it requires careful monitoring. The good news is that based on NICE guidelines, the fact that your acne is causing persistent psychological distress and affecting your mental health means I can refer you to dermatology right now — today — for consideration of isotretinoin. You do not need to have failed oral antibiotics first in order to qualify for this referral. I''ll get that referral in today.

While you''re waiting to be seen by dermatology, if you''d like to start oral antibiotics and the topical agent in the meantime, I''m happy to prescribe those — it may help bring things under control while you wait. I''d also like to offer you a referral for some talking therapy — CBT — to help with the impact this has been having on your confidence and mood, because that is just as important to address as the skin itself.

A couple of quick tips while we get things moving: please try to avoid picking or squeezing spots, as this makes scarring worse, and avoid washing your face too frequently or too vigorously, as over-cleansing can irritate the skin further. Please come back to us sooner if your mood dips significantly or if you ever have thoughts of harming yourself.',
  ARRAY[
    'Acne causing persistent psychological distress or a mental health disorder is an indication for dermatology referral for consideration of isotretinoin (Accutane) regardless of acne severity, in line with NICE guidance.',
    'Oral antibiotics for acne (e.g. lymecycline 408mg OD or doxycycline 100mg OD for 3–6 months) must always be combined with a topical non-antibiotic agent such as Epiduo (benzoyl peroxide plus adapalene) or azelaic acid 15–20%; oral antibiotic monotherapy must be avoided due to the risk of antibiotic resistance.',
    'Isotretinoin (Accutane) can only be initiated by a dermatologist and requires specialist monitoring; GPs should refer rather than prescribe.',
    'The psychological impact of acne — including low mood, reduced confidence, and social withdrawal — should be assessed at every consultation and addressed, with CBT referral considered when appropriate.',
    'Oral antibiotics for acne should be assessed after at least three months of use before concluding they are ineffective.',
    'Excessive face washing and picking or squeezing spots should be actively discouraged as they worsen skin irritation and scarring.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  157,
  'Woman Requesting Sick Note',
  'General Practice',
  'Telephone Consultation',
  false,
  'Donna Clarke',
  '38-year-old female',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'Patient calling to request a sick note from her GP.',
  'Hi, I''ve been off work for a few days and I need a sick note. I''ve hurt my hand and I really don''t think I''m able to go back just yet.',
  'I hurt my hand at home. I fell and landed awkwardly on it. It''s quite swollen and painful.',
  ARRAY[]::text[],
  'Works as a cleaner. Lives with her partner; no children at home. Does not smoke or drink alcohol. No known social services involvement.',
  'She hasn''t linked the injury to anything specific when first asked.',
  'She is worried about her finances if she leaves her partner.',
  'Initially wants a stronger painkiller as she is only on paracetamol. Once reassured and supported, she may hope the GP can guide her on next steps and how to get help safely.',
  ARRAY[]::text[],
  NULL,
  'SAY NO TO ANY OTHER SYMPTOMS OR QUESTIONS ASKED',
  ARRAY[]::text[],
  ARRAY[
    'Offer referral to safeguarding team or specialist domestic abuse worker if the patient wishes',
    'Offer referral to domestic abuse agencies such as Women''s Aid, which can help with emergency shelter, finances, and emotional support',
    'Advise patient that ibuprofen is available over the counter for managing pain',
    'Offer mental health support or talking therapy if appropriate',
    'Provide a fit note for an initial 2 weeks off work, then reassess',
    'Safety net: ensure the patient knows she can call back at any time and how to access urgent help in a crisis — including calling 999 if she feels she is in immediate danger, or contacting domestic abuse helplines',
    'Safety net regarding compartment syndrome — advise that if she notices numbness or tingling in her hand or fingers, colour changes such as the hand going pale or blue, worsening pain despite medication, or increasing swelling in the hand or arm, she should seek urgent medical attention immediately'
  ],
  'Thank you so much for calling in today, Donna, and for trusting me with what you''ve shared. I want you to know that everything you tell me is treated with care and in confidence.

I''ve listened to what you''ve told me about your hand, and I do want to make sure we look after that properly. For the pain, ibuprofen from a pharmacy should help more than paracetamol alone — it works well for soft tissue injuries, and you can take it with food. I''ll also arrange a fit note for the next two weeks so you don''t need to worry about work right now.

But I also want to check in about how things are at home more generally, because sometimes when someone has an injury like this, there can be more going on. You don''t have to share anything you''re not comfortable with, but I''m here to listen without any judgement at all.

If things at home are difficult, there is real support available. I can refer you to a specialist domestic abuse worker, in complete confidence, who can talk through your options with you — including practical things like finances and housing, which I know can feel like a barrier. Organisations like Women''s Aid are also there to help, and they can do so without any pressure to take a particular course of action. You would always be in control of any decisions.

I also want to make sure you know how to get help quickly if you ever need it urgently. If at any point you feel you''re in immediate danger, please call 999 without hesitation. There are also 24-hour domestic abuse helplines you can contact at any time.

One more thing I want to mention about your hand — please keep an eye on it over the coming days. If you notice any numbness, tingling, or pins and needles in your fingers, if your hand starts to look pale or bluish, if the pain gets worse even after taking pain relief, or if the swelling increases significantly, please seek urgent medical attention straight away, as these can occasionally be signs of a condition called compartment syndrome that needs to be assessed quickly.

Please do not hesitate to ring us again at any time. We are here for you.',
  ARRAY[
    'Domestic abuse may present indirectly — a patient calling for a sick note or pain relief following an injury at home warrants sensitive enquiry about home circumstances',
    'Offer referral to a specialist domestic abuse worker and to organisations such as Women''s Aid, which can support patients with safety planning, emergency shelter, and financial guidance',
    'Ibuprofen is appropriate for soft tissue hand injuries and is more effective than paracetamol alone; advise it can be purchased over the counter',
    'A fit note should be issued for an appropriate period (e.g. 2 weeks) with planned review, allowing time and space for the patient to consider her options',
    'Safety-net for compartment syndrome: advise the patient to seek urgent review if she develops numbness, tingling, colour changes, worsening pain, or increased swelling in the affected limb',
    'Always signpost urgent help — ensure the patient knows to call 999 in immediate danger and has access to domestic abuse helpline numbers'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  158,
  'Pregnant Lady With New Onset Headache',
  'Neurology',
  'Video Consultation',
  false,
  'Claire Hussain',
  '30-year-old female',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'Pregnant patient calling to discuss a new headache she has been experiencing.',
  'Hi doctor, I''ve had this headache for a couple of days now. It''s quite bad and I''m not sure if it''s just a migraine or something else. I''m pregnant and I didn''t want to take anything without checking first.',
  'The headache came on gradually. It''s mainly at the front of my head. I don''t have any visual problems or swelling that I''ve noticed.',
  ARRAY[]::text[],
  'Non-smoker, no alcohol, works as a teaching assistant, lives with her husband.',
  'She thinks it might be her usual migraine coming back.',
  'She is worried about the pain and recalls being told not to take anything stronger than paracetamol during pregnancy.',
  'She would like something stronger for the headache — perhaps codeine or a prescription migraine tablet.',
  ARRAY[]::text[],
  NULL,
  'SAY NO TO ANY OTHER QUESTIONS ASKED',
  ARRAY[]::text[],
  ARRAY[]::text[],
  'Thank you for getting in touch today, Claire, and well done for checking before taking any new medication during your pregnancy — that was exactly the right thing to do.

I can understand how uncomfortable a headache can be, especially when you''re pregnant and want to make sure both you and your baby are kept safe. Let me share a bit about what we need to consider here.

When a new headache comes on during pregnancy, we always want to make sure we''re not missing anything important. There is a condition called pre-eclampsia which can cause headaches along with other features such as visual disturbances, swelling of the face or hands, or high blood pressure, and we need to check for that. Because of this, I''d like to arrange for you to be seen and assessed, so we can check your blood pressure and urine, and make sure everything is as it should be.

In terms of pain relief during pregnancy, paracetamol remains the safest option and is what we would recommend in the first instance. Codeine is generally avoided in pregnancy, particularly in the third trimester, as it can affect the baby. Triptans and standard migraine medications are also not routinely recommended during pregnancy without specialist input.

If it does turn out to be a migraine, we can also talk through some practical strategies — things like staying well-hydrated, resting in a quiet and dark room, and using cold or warm compresses on the forehead, which some people find helpful.

Please do contact us or go to your maternity unit urgently if your headache becomes very sudden or severe, if you develop any changes in your vision such as blurring or seeing flashing lights, if you notice significant swelling of your face, hands, or feet, or if you experience any abdominal pain. These would all need prompt assessment on the same day. We want to keep a close eye on you and make sure you and your baby are both well.',
  ARRAY[
    'New onset headache in pregnancy must prompt assessment for pre-eclampsia — check blood pressure and urine for proteinuria urgently',
    'Paracetamol is the safest and recommended analgesic in pregnancy; codeine is generally avoided, particularly in the third trimester',
    'Triptans and standard migraine-specific treatments are not routinely recommended in pregnancy without specialist guidance',
    'Red flag features in pregnancy headache include sudden or severe onset, visual disturbances, facial or peripheral oedema, and upper abdominal pain — these require same-day urgent assessment',
    'Non-pharmacological measures such as hydration, rest, and cold compresses can be suggested as adjuncts for migraine management in pregnancy'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  159,
  'Flare of Ulcerative Colitis',
  'Gastroenterology & Haematology',
  'Video Consultation',
  false,
  'Thomas Hayward',
  '31-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  'Letter from gastroenterology 5 months ago. Dear Doctor, Mr. Thomas Hayward was recently admitted via the Acute Medical Unit with a 3-day history of bloody diarrhoea and crampy abdominal pain. He was initially resuscitated successfully with supportive care and intravenous fluids. A colonoscopy performed during admission revealed left-sided ulcerative colitis involving the descending colon and sigmoid. There was evidence of mucosal inflammation, friability, and contact bleeding consistent with a moderate flare of his known ulcerative colitis. He was commenced on intravenous corticosteroids, to which he responded well. Following clinical improvement, he was stepped down to oral prednisolone 40mg once daily, with instructions to taper the dose by no more than 5mg every 5 to 7 days, depending on clinical response and under outpatient supervision. He was also restarted on mesalazine (Salofalk®) 500mg three times daily for maintenance therapy. Mr. Hayward was provided with verbal and written information on medication adherence and the importance of attending follow-up. At discharge, he was given the contact details of the IBD Clinical Nurse Specialists and advised to get in touch should he experience worsening symptoms. He will be followed up in our gastroenterology outpatient clinic. Please do not hesitate to contact us if further information is required. Yours sincerely, Dr. A. Khan MBBS, MRCP (UK), Consultant Gastroenterologist. Patient booked urgent appointment to discuss concerns.',
  'Patient requesting review of worsening bowel symptoms in the context of known ulcerative colitis.',
  'Hi doctor. I''ve had ulcerative colitis for a few months now. I had a really bad flare a while back and was started on some tablets. Things settled down for a bit but over the last three days I''ve been getting bloody diarrhoea again — about five times a day — and some tummy cramps. I''m still taking my mesalazine. I was hoping I could get some steroids, as that''s what sorted me out last time.',
  'The cramps are not severe. I feel tired but I''m not dizzy or unwell in myself. I haven''t had a fever. I missed my hospital follow-up appointment about two weeks ago as things got busy.',
  ARRAY[]::text[],
  'Does not smoke. Does not drink alcohol or use illicit drugs. Lives alone and works as a plumber.',
  'He is certain this is another flare of his ulcerative colitis.',
  'He is worried it will escalate the same way it did last time if nothing is done quickly.',
  'He would like to be prescribed steroids, as that is what helped him previously.',
  ARRAY[
    'If the doctor asks him to come in for examination: inform the doctor that he is due to fly to Scotland in 2 hours for a 2-week job and cannot attend in person today'
  ],
  NULL,
  'SAY NO TO ANY OTHER SYMPTOMS ASKED',
  ARRAY[]::text[],
  ARRAY[
    'Offer face-to-face review to assess today if possible',
    'Offer blood tests (CRP, FBC, U+Es, LFTs, ESR) and stool tests for C. difficile and microscopy',
    'Based on history, previous response to steroids, and current stability with no red flag features, initiate a short course of oral prednisolone as a pragmatic and safe option given the upcoming travel',
    'Dose for management of a flare of ulcerative colitis as per BNF is 20–40mg once daily followed by reducing doses (reducing by 5mg every 5–7 days is based on clinical experience and commonly adopted practice; the tapering regimen is not specified in the BNF)',
    'Educate on steroid side effects and the importance of medication adherence',
    'Advise patient that you will inform the IBD nurse and gastroenterology team of the flare, missed follow-up appointment, and that oral steroids have been initiated',
    'Advise patient to continue mesalazine (Salofalk®) 500mg three times daily without interruption',
    'Safety netting — advise patient to seek urgent medical care if symptoms worsen while away (severe pain, fever, vomiting, or signs of dehydration)',
    'Arrange follow-up appointment for when the patient returns from his trip'
  ],
  'Thomas, thank you for explaining all of that so clearly. From what you''ve described — the return of bloody diarrhoea, the mild abdominal cramps, and your background of ulcerative colitis — this does sound very much like another flare. You''ve done exactly the right thing by continuing your mesalazine, and I completely understand why you''re asking about steroids, especially given how effective they were for you last time.

That said, before we start them, I want to make sure this flare isn''t more severe than it appears and that there''s no underlying infection or complication that would change how we manage things. Steroids are effective but they do have potential side effects, so we always want to be confident they''re appropriate and safe before starting.

Ideally, I would ask you to come in today for a brief examination, and we would also arrange some blood tests — a CRP, full blood count, kidney and liver function — as well as a stool sample to rule out infections like C. difficile. However, I understand that you have a commitment to travel shortly.

Given your clear diagnosis of ulcerative colitis, your previous good response to steroids, and the fact that you''re currently stable without any red flag features such as a high fever, severe pain, or signs of dehydration, I am prepared to start you on a short course of oral prednisolone. The usual dose for a flare is between 20 and 40mg once daily, followed by a gradual reduction — typically coming down by 5mg every five to seven days. I will send you written tapering instructions to make this clear.

I will also be contacting your IBD team today to make them aware of the flare, the missed appointment, and that we have started steroids in the community. Please do continue your mesalazine three times a day without any break.

While you are away, if your symptoms worsen at all — particularly if you develop a high temperature, severe abdominal pain, vomiting, or signs of dehydration — please seek urgent medical attention locally without delay. And once you are back, I would like to see you for a follow-up to check how things are progressing. Does that plan sound reasonable to you?',
  ARRAY[
    'Assess severity of an IBD flare before initiating treatment — six or more bloody stools per day plus systemic upset (fever, tachycardia, anaemia, or raised CRP/ESR) warrants hospital admission rather than community management',
    'In remote consultations, a detailed symptom history — stool frequency, presence of blood, systemic features, and ability to stay hydrated — guides the decision between community management and urgent referral',
    'Where a patient is stable, has no red flags, and cannot attend in person, it may be appropriate to initiate a short course of oral prednisolone (20–40mg once daily with tapering) in line with NICE guidance on shared-care IBD management',
    'Mesalazine (Salofalk®) 500mg three times daily should be continued without interruption during a flare',
    'Always inform the IBD nurse or gastroenterology team when initiating steroids in the community for a known IBD patient, and arrange timely follow-up',
    'Safety-net for deterioration: advise patients to seek urgent care for fever, severe pain, vomiting, or dehydration, especially if travelling away from their usual GP'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  160,
  'New Onset Facial Weakness',
  'Neurology',
  'Telephone Consultation',
  false,
  'Gary Thornton',
  '44-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  NULL,
  'Patient calling about new onset weakness affecting one side of his face, which started this morning.',
  'Hi doctor, I woke up this morning and the right side of my face just won''t move properly. My mouth is drooping a bit and I can''t fully close my eye on that side. It came on overnight as far as I can tell. I haven''t had a stroke, have I?',
  'It''s just on one side. There''s no arm or leg weakness, no slurred speech, no headache, no visual changes. I can''t close my right eye fully, and my mouth is a bit droopy on that side. It started when I woke up this morning.',
  ARRAY[]::text[],
  'Does not smoke. Drinks alcohol occasionally. Lives alone and works as a delivery driver for a haulage company.',
  'He is scared this might be a stroke.',
  'He is worried it could be something serious and permanent, and is unsure whether he is safe to drive or go to work.',
  'He wants to understand what is happening and whether it can be treated.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other symptoms asked',
  ARRAY[]::text[],
  ARRAY[
    'Arrange a face-to-face review to examine the facial muscles and check for any other concerning signs',
    'Start prednisolone 50mg once daily for 10 days, as the patient has presented within 72 hours of symptom onset',
    'Offer lubricating eye drops for frequent daytime use and eye ointment at night for corneal protection',
    'Advise the patient to tape the affected eye closed at night using microporous tape if it does not fully close',
    'Recommend wearing sunglasses outdoors to protect the eye from wind and bright light',
    'Reassure that he can continue to drive if his vision is not affected, but advise him to inform the DVLA for formal guidance',
    'Book a follow-up appointment in 2–3 weeks to assess recovery',
    'If no improvement after 3 weeks, arrange referral for further specialist assessment',
    'Provide clear safety-netting — advise that if symptoms suddenly worsen, or if he develops weakness in his arms or legs, slurred speech, or balance problems, he should seek urgent medical help by calling 111 or 999',
    'Advise that if his eye becomes red, painful, or his vision changes, he should seek urgent review'
  ],
  'Thank you for calling today, Gary, and I can hear how unsettling this must have felt to wake up to this morning. Let me try to reassure you as much as I can.

From what you''ve described — weakness affecting just one side of your face, difficulty closing your eye, a droopy mouth, but no arm or leg weakness, no slurred speech, and no other symptoms — this sounds most consistent with Bell''s palsy rather than a stroke. Bell''s palsy is caused by inflammation of the facial nerve, and while it can look quite alarming, it is not a stroke and in most cases the majority of people recover well with the right treatment.

What makes this important to treat promptly is that you''ve come to us within 72 hours of your symptoms starting, which is exactly the right window for us to start a course of steroids. I''d like to prescribe you prednisolone 50mg once daily for 10 days — this reduces the inflammation around the nerve and significantly improves the chances of a full recovery.

One thing I want to make sure we manage carefully is your eye. Because it''s not closing fully, the surface of the eye can become dry and vulnerable. I''ll arrange for you to have lubricating eye drops to use regularly during the day, and an eye ointment to use at night. If the eye still won''t close fully when you go to sleep, gently taping it shut with some microporous tape will protect it. Wearing sunglasses when you''re outdoors will also help.

I''d like to see you in person today so I can examine the facial muscles properly and make sure there''s nothing else we need to consider. I''ll also book you a follow-up in two to three weeks to check how the recovery is going.

Regarding driving — if your vision is not affected, there is no immediate reason you cannot drive. However, I would recommend letting the DVLA know about your symptoms so they can advise you formally.

Please do seek urgent help — call 111 or 999 — if you notice any sudden worsening, or if you develop any weakness in your arms or legs, problems with your speech, or difficulty with your balance, as those features would need to be assessed as an emergency. Similarly, if your eye becomes red, painful, or your vision changes at all, please get that checked urgently.',
  ARRAY[
    'Bell''s palsy causes unilateral lower motor neurone facial weakness affecting the whole side of the face including forehead — this distinguishes it from an upper motor neurone stroke, where forehead sparing is typical',
    'Prednisolone 50mg once daily for 10 days should be started within 72 hours of symptom onset to improve recovery outcomes',
    'Eye care is essential — prescribe lubricating eye drops for daytime use and eye ointment at night; advise taping the eye shut if it does not close fully, to prevent corneal damage',
    'Patients can generally continue to drive if vision is unaffected, but should be advised to notify the DVLA for formal guidance',
    'Safety-net: advise urgent review if the patient develops limb weakness, slurred speech, or balance problems, as these would suggest a central cause requiring emergency assessment',
    'If there is no improvement after 3 weeks, arrange specialist referral for further assessment'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  161,
  'Crushing Tablets for Elderly Relative',
  'Elderly Medicine & Palliative Care',
  'Telephone Consultation',
  false,
  'Mrs. Margaret Hollis',
  '88-year-old female',
  ARRAY[
    'Alzheimer''s disease',
    'Type 2 Diabetes Mellitus',
    'Hypertension',
    'Hyperlipidaemia',
    'Osteoporosis'
  ],
  ARRAY[
    'Donepezil 5mg once daily — stopped 6 months ago by consultant geriatrician at family''s request',
    'Metformin 1g twice daily',
    'Amlodipine 10mg once daily',
    'Ramipril 2.5mg once daily',
    'Alendronic acid 70mg weekly (Mondays)',
    'Calcichew D3 500mg/200 IU twice daily',
    'Aspirin 75mg once daily',
    'Omeprazole 20mg once daily',
    'Atorvastatin 20mg once daily',
    'No known drug allergy',
    'Next of Kin / LPA: Son — Philip Hollis',
    'No DNACPR or advance care plan in place'
  ],
  'Recent bloods done 5 days ago by frailty team: HbA1c within target. Cholesterol 4.3 mmol/L. U+Es, FBC, CRP, LFTs, TFTs: all normal.',
  'Son calling to seek advice about his mother''s difficulty taking her medications and whether crushing tablets is safe.',
  'Hi Doctor, I''m calling about my mum, Margaret Hollis. She''s been having a lot of trouble swallowing her tablets for the past couple of weeks. I''ve been crushing some of them and mixing them into her food to help, but a neighbour saw me doing it and said it might not be the right thing to do. I just wanted to get some proper advice.',
  'She is still eating and drinking, though she manages better with soft food and liquids. She sometimes holds food in her mouth for a while before she swallows it. There are no signs of choking, vomiting, infections, or confusion beyond her usual baseline. She does not appear to be in pain when swallowing. Her bowels and waterworks are normal. Her cognition has deteriorated further and she now prefers to stay in bed most of the day. She no longer recognises me, which has been really hard to come to terms with — she seems to recognise the neighbours more than she does me.',
  ARRAY[
    'Her blood pressure has been around 120/70 over the past week',
    'She has had no weight loss, chest pain, or abdominal pain',
    'Bowel and urinary habits are unchanged',
    'There is no DNACPR or advance care plan in place'
  ],
  'She does not smoke or drink alcohol. Her son Philip is her primary carer and lives with her full-time.',
  'He is not sure why she is refusing to take her medications.',
  'He is worried because he was told her medications are all important for her health, and he is unsure whether he has been doing the right thing.',
  'He would like advice on whether crushing the tablets was appropriate, and whether some of her medications need to be stopped or changed given how difficult it has become to administer them.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Ask about the duration and progression of swallowing difficulties',
    'Clarify whether she struggles more with solids or liquids, or both',
    'Ask about pain on swallowing, chest or abdominal pain, vomiting, or weight loss',
    'Ask about episodes of choking, coughing, respiratory infections, or recent illness',
    'Ask about any new limb weakness, facial weakness, or slurred speech that might suggest a stroke',
    'Ask about bowel and urinary habits',
    'Explore current dementia status: cognition, mood, behaviour changes, and level of function',
    'Ask about her current medication routine and whether she is now predominantly bedbound',
    'Confirm next of kin and whether a Lasting Power of Attorney (LPA) is in place',
    'Ask if the carer is aware of whether a DNACPR order or advance care plan has been discussed or put in place',
    'Explore the frequency and level of care support the patient receives, and whether the carer is coping or struggling',
    'Give a diagnosis of likely deterioration of Alzheimer''s dementia'
  ],
  ARRAY[
    'Arrange a home visit to assess Mrs. Hollis, including general physical examination and direct observation of swallowing',
    'Inform Philip that you will also aim to discuss advance care planning (ACP) and DNACPR during the home visit',
    'Inform the son that you will consider stopping non-essential medications, including the statin, aspirin, alendronic acid, omeprazole, and Calcichew D3',
    'Explain that metformin may be continued but can be switched to a liquid formulation or a safer alternative that is easier to administer',
    'Clarify that any medication changes will be discussed with the pharmacy team, and a full medication review will be completed before any final decisions are made',
    'Gently advise the son, in a non-judgemental and supportive way, not to crush or conceal medication without first seeking guidance from a GP or pharmacist',
    'Refer to adult safeguarding due to multiple concerns: the son is the sole carer and appears to be under significant strain; crushing and mixing medications without medical advice raises concern about carer burden and possible covert administration; the patient''s advanced cognitive decline and inability to recognise her son indicate a need to reassess her care needs and mental capacity',
    'Refer to the Speech and Language Therapy (SALT) team for a formal swallowing assessment',
    'Recommend continuing a soft or puréed diet in the meantime until the SALT assessment has been completed',
    'Safety-net: advise the carer to seek urgent medical attention if Mrs. Hollis becomes increasingly drowsy or confused, starts choking, stops eating or drinking, or develops any new symptoms'
  ],
  'Thank you so much for ringing today, Philip, and for everything you''re doing for your mum. I can hear how much you care for her, and I want you to know that you''re doing your very best in what is clearly a very difficult situation.

From everything you''ve shared with me, it does sound as though your mum''s dementia has progressed into a more advanced stage. The fact that she is mostly staying in bed now, finding it hard to manage her tablets, and is no longer recognising you even though you''ve been her closest support for so many years — these are all signs that her condition has moved on significantly. I know that is very painful to hear, and I want you to know that what you''re feeling is completely understandable.

I also wanted to say something about the tablets. I can see entirely that you started crushing them because you were trying to help — you wanted to make sure she was getting her medication. However, some tablets are not safe to crush, as it can change how the medication works or lead to side effects. So it''s really important that any changes to how medicines are given — including crushing or mixing with food — are only done after checking with the GP or pharmacist. That''s not a criticism at all; I just want to make sure we keep her as safe as possible going forward.

In terms of her medications, this is something I''d very much like to review carefully. Some of them may no longer be appropriate at this stage. For example, alendronic acid, which is the tablet for her bones, needs to be taken sitting upright for at least 30 minutes, and as she is mostly bedbound now, continuing it could cause irritation or harm to her food pipe. I would also look at stopping the cholesterol tablet, aspirin, the calcium supplement, and the stomach protection tablet, as these are less likely to be providing benefit at this stage. For her diabetes medication, metformin, we can explore whether a liquid form or an alternative might be easier to give. I''ll involve the pharmacy team in a thorough medication review before we make any changes.

I''d like to arrange a home visit to see your mum in person, examine her, and observe how she is managing with swallowing. I''ll also bring a referral to the Speech and Language Therapy team, who can do a proper swallowing assessment and advise us on the safest way to give her food and fluids in the meantime. Please continue offering soft or puréed foods until we have that assessment.

I also want to mention that I''d like to involve the adult safeguarding team. I want to be very clear — this is not because you have done anything wrong. It is simply to make sure that both you and your mum are getting the right level of support. Caring for someone with advanced dementia on your own is an enormous responsibility, and it can be overwhelming. The safeguarding team can look at what extra help and services might be available to ease things for you at home.

Finally, please do call us urgently if your mum becomes very drowsy, starts choking, stops eating or drinking, or develops any new symptoms. We are here for you both.',
  ARRAY[
    'Difficulty swallowing in advanced dementia reflects neurological dysfunction rather than mechanical obstruction; patients may struggle to initiate a swallow even without reporting pain',
    'Crushing medications without medical advice can alter drug pharmacokinetics and safety — carers must be educated in a non-judgemental way to seek GP or pharmacist guidance before modifying how medicines are administered',
    'Deprescribing is an essential part of managing advanced dementia — non-essential medications such as statins, aspirin, alendronic acid, omeprazole, and calcium supplements should be reviewed and stopped when they no longer offer meaningful benefit',
    'Alendronic acid is contraindicated in patients who cannot remain upright for 30 minutes after taking it — this is a specific reason to stop it in a bedbound patient, due to risk of oesophageal erosion',
    'A safeguarding referral is appropriate when a sole carer is under significant strain and clinical concerns exist about covert medication administration and the patient''s care needs — it is a supportive, not punitive, process',
    'Involve the MDT — refer to SALT for swallowing assessment, coordinate with pharmacy for medication review, and discuss advance care planning and DNACPR during the home visit'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  162,
  'Memory Screen in Older Adult',
  'Elderly Medicine & Palliative Care',
  'Video Consultation',
  false,
  'Peter Clifford',
  '66-year-old male',
  ARRAY[
    'Hypertension (diagnosed 10 years ago)'
  ],
  ARRAY[
    'Amlodipine 10mg once daily',
    'No known drug allergy'
  ],
  NULL,
  'Patient attending for a routine appointment to discuss increasing forgetfulness over the past several months.',
  'Hi doctor, I''ve booked this appointment because my memory has been getting worse over the last six months or so. It''s starting to affect my work now and I''m really worried about it.',
  'I work as a security officer at a large retail store. A few weeks ago I forgot to lock up properly before leaving, and some stock went missing. I''m being blamed for it and it''s been really stressful. My wife has also noticed that I keep forgetting recent things, like what we had for breakfast or important dates.',
  ARRAY[]::text[],
  'Non-smoker, drinks alcohol occasionally. Lives with his wife. Mood is fine and things are settled at home. Does not do the cooking or shopping. Still drives and the memory problems have not yet affected his driving.',
  'He suspects it may be dementia, as his father had it and started in a similar way.',
  'He is worried that if this is dementia, it could mean he has to stop working early.',
  'He would like the doctor to test his memory today. If a memory test is offered: Year — give correct answer; Month — give correct answer; Address phrase (e.g., Peter, Jones, 17, Maple Road, Derby) — repeats correctly; Time — gives correct time within one hour; Count backwards from 20 to 1 — makes an error; Months in reverse — makes an error; Recall address phrase — cannot recall it.',
  ARRAY[]::text[],
  NULL,
  'SAY NO TO ANY OTHER QUESTION ASKED',
  ARRAY[
    'Ask about onset and progression of symptoms — gradual or sudden',
    'Ask whether he has problems with short-term memory, long-term memory, or both',
    'Ask whether anyone close to him has noticed changes in his behaviour or personality',
    'Rule out normal pressure hydrocephalus and Parkinson''s disease — ask about changes in gait, recent falls, headaches, tremors, or urinary symptoms',
    'Ask about the impact of memory loss on activities of daily living (ADLs) — eating, dressing, shopping, managing medications',
    'Ask about mood: any signs of low mood or depression',
    'Check for safety issues — ask about any recent incidents at work or home, such as accidentally leaving the gas or electric cooker on, which could pose a fire risk',
    'Ask about driving: is he still driving, and has he noticed any difficulties?',
    'Ask whether he takes any over-the-counter or herbal medications',
    'Ask about alcohol or substance use',
    'Ask about family history of dementia',
    'Ask about support at home',
    'Perform 6CIT: What year is it? (Correct: 0 points; Incorrect: 4 points); What month is it? (Correct: 0 points; Incorrect: 3 points); Give address phrase to remember — 5 components, e.g. Peter, Jones, 17, Maple Road, Derby (Correct: 0 points; Incorrect: 3 points); About what time is it within one hour? (Correct: 0 points; Incorrect: 3 points); Count backwards from 20 to 1 (Correct: 0 points; 1 error: 2 points; More than 1 error: 4 points); Say the months of the year in reverse order (Correct: 0 points; 1 error: 2 points; More than 1 error: 4 points); Recall address phrase from earlier (All 5 correct: 0 points; 1 error: 2 points; 2 errors: 4 points; 3 errors: 6 points; 4 errors: 8 points; All wrong: 10 points). Score interpretation: 0–7 normal; 8–9 mild cognitive impairment; 10 or more suggests significant cognitive impairment or dementia and warrants further assessment. Note: a normal score on the 6CIT does not rule out dementia — if the clinical history is suggestive, refer for further assessment regardless of score',
    'Make a diagnosis of cognitive impairment and possible dementia'
  ],
  ARRAY[
    'Offer a memory screening test during the consultation (e.g. 6CIT or similar validated tool)',
    'Offer blood tests: FBC, CRP, ESR, U&Es, Calcium, HbA1c, LFTs, TFTs, B12, Folate',
    'Check blood pressure and review hypertension management',
    'Refer to memory clinic or community mental health team for a full cognitive assessment',
    'Explain that the memory clinic may arrange brain imaging such as MRI or CT scan',
    'Offer to write a GP letter or amended duties fit note for his employer to support a discussion about temporary adjustments to his role while investigations are ongoing, to reduce pressure on the patient',
    'Ask whether his workplace has occupational health services — if so, advise him to speak to his line manager or HR in confidence to request a referral; if not, encourage him to speak with his employer about any reasonable adjustments they can make',
    'Recommend lifestyle support: mental stimulation, regular exercise, using reminders, notes, and phone calendars to support daily memory',
    'Advise DVLA notification as dementia is suspected — he may still be able to drive, but should contact the DVLA for formal guidance',
    'Offer to write down everything discussed during the consultation, including next steps and referral information, to support the patient''s recall — this demonstrates awareness that memory difficulties may affect his ability to retain verbal information',
    'Offer a follow-up appointment after results or referral outcome are available'
  ],
  'Thank you for coming in today and for sharing all of that with me, Peter. I can hear how much this has been weighing on you, particularly with what happened at work, and I want you to know that you''ve absolutely done the right thing by coming in.

From what you''ve described, with your memory getting gradually worse over several months, your wife noticing changes, and it now affecting your work, this is something we need to take seriously and investigate properly. I''ve also done a brief memory test with you today, and while some answers were fine, there were a few areas — particularly recalling information and counting backwards — where I noticed some difficulties. This gives me a useful picture alongside everything else you''ve told me.

I want to be honest with you: there are a number of reasons why someone''s memory can change, and dementia is one possibility, but there are others too — things like thyroid problems, vitamin deficiencies, or even blood pressure — and we need to check for all of those. So I''d like to arrange some blood tests, looking at your thyroid function, vitamin B12, folate, blood count, kidney and liver function, and blood sugar levels. I''ll also check your blood pressure today, as that can sometimes affect memory and thinking.

I would like to refer you to a memory clinic. They are specialists in this area and will carry out a much more detailed assessment than we can do in a GP appointment. They may also arrange a brain scan, such as an MRI or CT, to look more closely at what''s happening. As a GP, my role is to make sure I refer you to the right people, and the memory clinic will be the ones to give you a formal diagnosis and a clear plan. You won''t be left waiting without support in the meantime.

I know you''re worried about work, and I''m sorry to hear about the situation at the store. While we''re still investigating, I''d be happy to write a GP letter for your employer explaining that you''ve been experiencing memory difficulties and are under investigation. This could support a conversation with HR about temporarily adjusting your duties to something that places less reliance on memory, just to take some of the pressure off while we work out what''s going on. If your workplace has an occupational health service, it would also be worth asking for a referral through your line manager.

Regarding driving — on the basis of what you''ve told me, your memory difficulties don''t appear to be affecting your driving right now. However, because we have concerns about your memory, it is important that you let the DVLA know. They will review things and give you proper guidance on whether it is safe for you to continue — that decision sits with them, not with us, and we''ll support you through that process.

I''m also going to write down everything we''ve discussed today — the next steps, who we''re referring you to, and the tests we''re arranging — so you can take it away and look back at it, or share it with your wife. You are not alone in this, and we will support you at every step along the way.',
  ARRAY[
    'The 6CIT is a validated GP screening tool for cognitive impairment — multiple errors in memory recall or reverse tasks (counting or months backwards) should raise suspicion of cognitive decline even if the total score is below the threshold',
    'A normal score on the 6CIT does not rule out dementia — NICE guidance states that if the clinical history suggests progressive memory loss or functional decline, referral for further assessment should proceed regardless of the cognitive test result',
    'GPs do not diagnose dementia — the role in primary care is to screen, arrange appropriate investigations, and refer to a memory clinic or older adults mental health team for formal assessment',
    'Blood tests to exclude reversible causes of cognitive decline include FBC, CRP, ESR, U&Es, Calcium, HbA1c, LFTs, TFTs, B12, and Folate',
    'Patients with suspected dementia should be advised to notify the DVLA — they may still be able to drive, but this is a formal decision made by the DVLA based on the information provided',
    'Address the practical impact on employment — a GP letter or fit note supporting temporary workplace adjustments can significantly reduce stress while investigations are ongoing, and occupational health referral should be offered where available'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  163,
  'Opioid Request',
  'Mental Health',
  'Video Consultation',
  false,
  'Adrian Kowalczyk',
  '37-year-old male',
  ARRAY['Recently moved from Romania; newly registered at the practice','No significant medical history','No known drug allergy','No previous consultations on record'],
  ARRAY[]::text[],
  NULL,
  'Patient booked routine appointment to discuss back pain and request pain relief.',
  'Hi doctor, I really need help with my back. I''ve been in pain for over a year now after a car accident, and I only have two tablets left. I''m worried I won''t be able to cope without them.',
  'The pain started after a road traffic accident about fourteen months ago. It''s in my lower back, constant and dull, sometimes sharp when I move. I take 7 to 10 tablets of codeine 30mg each day. I was last given a prescription three months ago back in Romania. I''ve had no problems with my legs or bladder, no weakness or numbness, and no fever. I tried physiotherapy back home but it didn''t make any difference. The pain hasn''t changed since the accident.',
  ARRAY['If asked about missing doses: I get very restless and anxious, the pain feels much worse and I can''t sleep or function','If asked about mood: I''m frustrated and low at times, especially because I can''t do my job properly','If asked about recreational drug use: No, I don''t use any drugs'],
  'You work at a car wash and live with a friend from back home. You don''t smoke and only drink occasionally. No illicit drug use.',
  'Believes codeine is the only thing keeping his back pain under control.',
  'Worried that without codeine the pain will become unbearable and he will not be able to cope.',
  'Wants the doctor to prescribe codeine on an ongoing basis.',
  ARRAY[]::text[],
  NULL,
  'If the doctor refuses the codeine request, remain persistent and reluctant to accept alternatives.',
  ARRAY[
    'Ask about onset, duration, location and character of the pain',
    'Ask about radiation of pain — does it travel down the leg (sciatica)?',
    'Ask for red flag symptoms that may indicate cauda equina syndrome: saddle anaesthesia, loss of bladder or bowel control, leg weakness',
    'Ask for red flag symptoms that may indicate malignancy or spinal infection: unexplained weight loss, fever, night sweats',
    'Ask about history of trauma or injury',
    'Ask about the impact of pain on work, daily life, sleep, and mood',
    'Ask about previous investigations or treatments for the back pain',
    'Clarify dose and frequency of codeine use — if the patient is on high doses or has been taking it for a long time, a gradual reduction plan will be needed to avoid withdrawal',
    'Ask what happens if he misses a dose of codeine',
    'Ask about social history: smoking, alcohol, and sensitively enquire about past or current recreational drug use, occupation, and living situation',
    'Ask about mental health: low mood, stress, anxiety',
    'Give a likely diagnosis of chronic mechanical low back pain with codeine dependence'
  ],
  ARRAY[
    'Offer a face-to-face review to examine the back, including reflexes, sensation, and power',
    'Consider using the STarT Back questionnaire to assess risk and tailor the treatment approach',
    'Prescribe a small supply of codeine today with a clear plan to gradually reduce and stop use over time',
    'Discuss the risks of long-term codeine use: dependence, tolerance, and harm to the liver, bowel, mood, and mental health',
    'Offer referral to physiotherapy, acknowledging his previous experience but encouraging a different, tailored approach',
    'Offer CBT (talking therapy) to help manage the emotional and psychological impact of living with long-term pain',
    'During the weaning phase, consider prescribing naproxen or ibuprofen PRN as a safer alternative — first check for a history of stomach problems or asthma, and add a PPI if needed',
    'Provide information on self-help resources (e.g. Versus Arthritis website for exercises and pain management advice)',
    'Refer to the social prescriber for support with understanding the NHS and accessing community resources, as the patient is new to the UK',
    'Arrange a follow-up appointment in 3 to 4 weeks to assess progress and adjust the plan as needed',
    'Safety-net: advise him to seek urgent help if he develops leg weakness, numbness, difficulty passing urine, or if the pain worsens suddenly'
  ],
  'Thank you for being so open with me today, and I can hear how difficult this past year has been. Living with long-term back pain following an accident is genuinely exhausting, and it makes complete sense that you want something to help you manage.

What you''re describing — pain that has persisted for well over a year, unchanged in character — is very consistent with what we call chronic mechanical low back pain. This is where the muscles, joints, and nerves in the back remain sensitised over time. It doesn''t mean something dangerous is happening, but the pain is very real and can have a significant impact on your daily life. Adrian, I want to be completely honest with you about the codeine, because I think it''s important.

I can prescribe you a small supply today, but I would like us to work together on a plan to gradually reduce and then stop it over time. The reason for this is that when codeine is taken regularly, especially at higher doses, the body begins to adapt to it. Over time it can stop working as effectively, and some people find they need more and more to get the same relief — which becomes risky. Long-term codeine use can also affect the liver, bowel, mood, sleep, and memory. The fact that you feel very unwell when you miss a dose tells me your body has become used to it, and that is something we need to address safely and carefully.

Coming off codeine too quickly can cause withdrawal symptoms, which is why we will reduce it slowly and support you through the process. You won''t be left without help during this time. We can look at other pain relief options — for example, ibuprofen or naproxen taken regularly can reduce inflammation and help with the pain. I would just need to check that you have no history of stomach problems or asthma before prescribing these, and I would likely add a tablet to protect your stomach.

I know you tried physiotherapy before and it didn''t help, and I completely understand why you''re sceptical. But sometimes a different physiotherapist with a different approach — one that is specifically tailored to your body, your work, and your lifestyle — can make a meaningful difference. I''d encourage you to give it another go if you''re willing.

Another option that has really good evidence behind it is CBT, or cognitive behavioural therapy. This is a type of talking therapy. It is not because the pain is in your head — far from it. But it can help you develop strategies to manage how the pain affects your mood, your sleep, and your sense of control over your life.

Because you are new to the UK and to the NHS, I would also like to refer you to our social prescriber. They can help connect you with local community services, support groups, and help you understand how things work here — which can make a real difference, especially when you are also dealing with something like this.

I''d like to see you again in three to four weeks to see how things are going and adjust the plan if needed. In the meantime, please come back to us urgently if you develop any weakness in your legs, numbness, or difficulty passing urine — those symptoms would need prompt assessment.',
  ARRAY[
    'Chronic low back pain lasting more than 12 weeks is termed chronic mechanical back pain; always screen for red flags including cauda equina symptoms and systemic features of malignancy or infection.',
    'When a patient is taking codeine 7 to 10 tablets of 30mg daily and reports feeling unwell when they miss a dose, codeine dependence should be recognised and addressed — abrupt cessation risks withdrawal and should be avoided.',
    'A gradual, supported opioid reduction plan is preferable to abrupt cessation; during the weaning phase, NSAIDs such as naproxen or ibuprofen (with gastroprotection) can be offered as adjuncts.',
    'The STarT Back questionnaire is a validated tool for stratifying patients with low back pain into low, medium, or high risk to guide appropriate management.',
    'CBT is an evidence-based psychological intervention for chronic pain and should be offered alongside physical treatments such as physiotherapy.',
    'Social prescribing is particularly valuable for newly registered patients who may be unfamiliar with the NHS and local support networks.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  164,
  'Methadone Request',
  'Mental Health',
  'Video Consultation',
  false,
  'Karen Walsh',
  '40-year-old female',
  ARRAY['Heroin addiction — intravenous drug use (IVDU)','Methadone hydrochloride oral solution 60mg once daily — prescription issued by drug and rehabilitation team'],
  ARRAY[]::text[],
  'Letter from Moorfield Drug and Rehabilitation Unit (received 4 months ago): Dear Colleague, I am writing to confirm that Ms Karen Walsh, a 40-year-old woman with a history of intravenous drug use, is currently under the care of our team at Moorfield Drug and Rehabilitation Unit. Ms Walsh has been engaged with our service for the past 4 months and has shown good compliance with her treatment plan. She is currently prescribed methadone hydrochloride 60mg once daily as part of her opioid substitution therapy (OST), dispensed via a local community pharmacy under supervised consumption. Screening for blood-borne viruses (HBV, HCV, and HIV) was carried out as part of her initial assessment and all results were negative. She is followed up regularly by our multidisciplinary drug and alcohol team, with psychosocial interventions forming part of her recovery pathway. Thank you for your continued support in her care. Yours sincerely, Dr M. Okafor, GP with Special Interest in Substance Misuse.',
  'Patient booked urgent appointment to discuss a problem with her methadone.',
  'Hi doctor, I''m in a bit of a difficult situation and I''m not sure what to do. I''m on methadone from the drug team and I''ve been doing really well, but this morning I accidentally spilled it. The bottle must not have been sealed properly, and while I was sorting out a mess my son had made in the kitchen, I must have knocked it over. By the time I realised, most of it had gone down the sink. I don''t have enough left for today''s dose and I''m worried I might start feeling unwell.',
  'The bottle was not properly closed. While clearing up a drink her son had spilled on the kitchen counter, she knocked the methadone bottle without realising. She only noticed later that most of it had drained into the sink. She normally stores it in a safe place out of reach of children. She has not had any withdrawal symptoms yet but knows how quickly they can come on if she misses a dose. She has not used heroin — she has been doing well on the programme and has not injected since starting. She tried contacting her keyworker but could not get through. This has never happened before.',
  ARRAY['If asked about other substance use: No — no heroin, no benzodiazepines, no alcohol, no cocaine','If asked about withdrawal symptoms: None yet, but she is anxious about them starting','If asked whether she has contacted the pharmacy: She rang but they said they couldn''t help without authorisation from the prescribing team'],
  'You smoke 20 cigarettes a day and have done for around 10 years. You do not drink alcohol. You live with your partner and your 8-year-old son, Callum. You are currently unemployed and receive universal credit. You and your partner share childcare responsibilities.',
  'Understands she needs methadone to prevent withdrawal symptoms.',
  'Anxious about missing her dose and the risk of relapse.',
  'Wants an urgent replacement prescription from the GP.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Explore the circumstances surrounding the methadone spill in detail — establish clearly what happened and when',
    'Ask when her last dose was taken and how many doses she has now missed',
    'Ask whether this has happened before — to identify if there is a pattern of losses or requests',
    'Ask whether she has been able to contact her rehabilitation team or her keyworker',
    'Ask whether she has contacted the dispensing pharmacy',
    'Ask if she is experiencing any symptoms of withdrawal',
    'Ask whether she has used heroin or any other substances since the incident — including benzodiazepines, alcohol, or cocaine',
    'Ask about her social history: smoking, home situation, and employment',
    'Ask about child safety — is the methadone usually stored somewhere secure and out of reach of her son?',
    'Ask about her support network — does she have a keyworker, social worker, or other key support?',
    'Elicit Ideas, Concerns, and Expectations'
  ],
  ARRAY[
    'Do not prescribe methadone from the GP practice — avoid being pressured into issuing controlled drug prescriptions in an unplanned or emergency manner',
    'Explain clearly that methadone must be prescribed by her specialist drug and alcohol recovery team, not the GP',
    'Advise the patient to contact her recovery team directly as soon as possible',
    'Offer to contact her named keyworker or the rehabilitation team on her behalf today to help facilitate a replacement prescription',
    'Offer smoking cessation advice and signpost to local stop smoking services',
    'If withdrawal symptoms develop, advise her not to attempt to self-manage with street drugs or opioids',
    'Warn explicitly about the risk of overdose if street opioids are used — her tolerance will be lower than before starting the programme, making even a small amount potentially fatal',
    'Advise her to attend the nearest A&E or call 111 urgently if withdrawal symptoms become severe (e.g. vomiting, agitation, tremors) or if she is at risk of relapse',
    'Check whether she has received harm reduction education, including guidance on dangers of injecting, overdose prevention, and naloxone access — if not, offer referral to a keyworker or recovery support worker for this',
    'Make a child safeguarding referral due to the methadone spill occurring in a household with a child present — explain this is a standard supportive step, not a punitive one; it is routine practice when a child lives in a home where controlled drugs are prescribed',
    'Safety-net: advise her to attend A&E or call 111 if she feels unwell, develops withdrawal symptoms, or is at risk of relapse'
  ],
  'Thank you for calling today, and thank you for being so honest about what happened. I can hear how worried you are, and I want you to know that you''ve done exactly the right thing by getting in touch straight away rather than trying to manage this on your own.

I can tell how committed you are to your recovery, Karen, and I can see from the information we have from your rehabilitation team that you have been doing really well. That matters, and it''s something to feel genuinely proud of. What happened this morning sounds like an unfortunate accident, and I do understand how stressful that is.

However, I have to be honest with you about what I can and cannot do from the GP practice. Methadone is a tightly controlled medication, and because you are under the care of the drug and rehabilitation team, it would not be safe or appropriate for me to issue a replacement prescription from here. This is not about doubt or mistrust — it is about making sure your treatment stays properly coordinated and safe. Your rehabilitation team holds your full clinical history and is best placed to manage this situation.

What I would like to do right now is try to contact your keyworker or the team at Moorfield directly on your behalf. Hopefully we can reach them today and get things moving quickly. If you can get through to them before I do, please do call them as well — the sooner they know, the sooner they can help.

In the meantime, it is really important that you do not try to manage any withdrawal symptoms yourself using street drugs or anything similar. I know that might feel like a solution in the moment, but please hear me on this — if your body has adjusted to the methadone programme, using heroin or other opioids now could be extremely dangerous, even a small amount. The risk of a serious overdose is very high. If you start to feel unwell — sweating, stomach cramps, shaking, feeling very agitated — please do not wait. Go to your nearest A&E or call 111 straight away and they can assess you and help keep you safe.

I also want to mention something briefly, and I hope you don''t mind. I noticed you mentioned that you smoke. I know now probably doesn''t feel like the right time to bring it up, and there''s absolutely no pressure. But when you feel ready, we do have excellent free stop smoking support locally, and it can make a real difference to your health and wellbeing — and to your recovery journey too.

Finally, because there was an accidental spill of methadone in your home and your son Callum is there, I do need to make a routine referral to our safeguarding team. I want to be very clear that this is not about blame — it is something we do as standard practice when controlled medications are involved in a household with a child. The purpose is to make sure both you and Callum have the right support around you. You are not in trouble. We are here to help, and we will do everything we can to support you through this.',
  ARRAY[
    'GPs should not prescribe methadone as a replacement in an emergency situation; opioid substitution therapy must be managed by the specialist drug and alcohol recovery team.',
    'When a patient on opioid substitution therapy reports a lost or spilled dose, the appropriate response is to liaise with or refer back to the prescribing specialist team, not to issue an ad hoc prescription.',
    'Patients who have been on opioid substitution therapy have reduced tolerance to street opioids; using heroin or other illicit opioids to self-manage withdrawal carries a very high risk of fatal overdose.',
    'Harm reduction should be offered or reinforced at every opportunity, including information on safer use, overdose prevention, and naloxone access.',
    'A child safeguarding referral is required as a matter of routine when a child lives in a household where a parent is prescribed or misuses controlled drugs — this is a supportive rather than punitive measure.',
    'Smoking cessation should be offered opportunistically during consultations, particularly in patients with complex social needs where health promotion can support overall recovery.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  165,
  'Behavioural Concerns in a Child',
  'Mental Health',
  'Telephone Consultation',
  false,
  'Noah Bennett',
  '6-year-old male',
  ARRAY['No significant medical history','Up to date with immunisations','No known drug allergies'],
  ARRAY[]::text[],
  NULL,
  'Mother (Claire Bennett) booked routine telephone consultation to discuss concerns about her son''s behaviour.',
  'Hi, I''m calling about my son Noah. I''ve been really worried about him lately — he is so hyperactive and just can''t seem to sit still. I keep wondering if he might have ADHD.',
  'Noah is 6 years old. He is constantly jumping around, moving about, and says he finds it hard to sit still at home. His older sister (Ella, age 8) is quite calm and settled by comparison, which makes Claire more concerned. No one at school, in nursery, or in the wider family has raised any concerns. Noah sleeps well at night, has no toileting issues, eats well, has good friendships, and plays happily with other children. There are no behavioural concerns from teachers. No significant difficulties with attention, learning, or following instructions in structured settings. No history of trauma, safeguarding concerns, or developmental delay.',
  ARRAY['If asked about attention at school: teachers say he pays attention and participates well in class','If asked about family history: no family history of ADHD or autism on either side','If asked about the home environment: things are settled at home, no stress or conflict'],
  'Noah lives with his mum Claire, his dad, and his older sister Ella. Things are well at home. No family history of ADHD or autism.',
  'Wonders whether Noah might have ADHD given how hyperactive and restless he is at home.',
  'Worried that if ADHD is not picked up now, Noah might struggle socially or academically as he gets older.',
  'Hopes the GP can assess Noah or refer him for a formal diagnosis and, if needed, get medication started.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Ask about the nature of the behaviour: when it happens, how often, and in which settings',
    'Ask about inattention symptoms — does Noah appear not to listen when spoken to, as if his mind is elsewhere? Does he have difficulty maintaining concentration during tasks or play activities?',
    'Ask about hyperactivity-impulsivity symptoms — does he fidget or tap his hands or feet when seated? Does he interrupt or intrude on others?',
    'Ask whether Noah has friends and whether he has any difficulties interacting with his peers',
    'Ask about the impact on daily life: sleep, learning, and social interactions',
    'Ask whether anyone else — teachers, nursery staff, or family members — has noticed or raised concerns about Noah''s behaviour',
    'Ask about family history of ADHD or autism',
    'Ask about the home environment — how communication is within the household and whether there are any difficulties or concerns at home',
    'Ask about PBIND history (pregnancy, birth, immunisation, nutrition, and development)',
    'Give a likely diagnosis of a normal energetic child — ADHD is unlikely based on the information provided'
  ],
  ARRAY[
    'Reassure the parent that Noah''s current behaviour is within the normal range for his age, particularly given the absence of concerns from school or any difficulties with social interaction',
    'Acknowledge and validate the comparison with his older sister, and gently explain that no two children develop in the same way or share the same temperament',
    'Offer a period of watchful waiting and suggest a follow-up review in 10 weeks to reassess whether any new concerns have emerged',
    'Offer a referral to a group-based parenting support programme (ADHD-focused or positive parenting group) if the parent would find this helpful',
    'Encourage Claire to maintain open communication with Noah''s school and ask them to flag any concerns if they arise',
    'Safety-net: advise Claire to come back sooner if concerns escalate, particularly if the school begins to notice learning difficulties, attention problems, or significant behavioural challenges'
  ],
  'Thank you so much for calling today, and for keeping such a close eye on how Noah is getting on. It''s completely understandable to have questions when you notice your child behaving differently from their sibling, and it shows how much you care about getting him the right support.

From everything you have described, Noah sounds like a bright, energetic, and social 6-year-old. It''s really reassuring to hear that he is sleeping well, eating well, getting along with his friends, and that his teacher hasn''t raised any concerns. Those are all very positive signs.

When we think about ADHD, Claire, one of the key things we look for is whether the difficulties are showing up across more than one setting — so both at home and at school — and whether they are having a meaningful impact on the child''s learning, friendships, or everyday functioning. Based on what you''ve told me, that picture isn''t quite there at the moment. The fact that Noah is settled in school and managing well socially is genuinely reassuring.

I also want to acknowledge what you said about Noah''s older sister. It''s very natural to compare children within the same family, and when one child seems more full of energy than another, it can feel worrying. But children are wonderfully different from one another, even when they grow up in the same home with the same parents. Some children are naturally more active and excitable, while others are quieter and more settled. That difference alone doesn''t indicate a problem — it is simply part of the wide range of normal childhood development.

What I''d like to suggest is a period of watchful waiting. We won''t dismiss your concerns, and we''ll keep a close eye on how things develop. I''d like to review Noah in around ten weeks, by which point we can reassess and see whether the picture has changed at all.

In the meantime, I can share some helpful resources on child development and behaviour, and we can talk through some simple strategies that might help channel Noah''s energy in a positive way at home. I can also refer you to a group-based parenting support programme — these are designed specifically for parents managing children with high energy levels, and many parents find them really practical and reassuring, not just for tips but for the sense of community and support they provide.

If anything changes before your next appointment — especially if school starts to notice things or if Noah''s behaviour becomes more challenging to manage — please don''t wait. Get back in touch with us and we will take a closer look together. You are doing all the right things by keeping us in the loop.',
  ARRAY[
    'A diagnosis of ADHD requires that symptoms are persistent, present in more than one setting (e.g. both home and school), and cause significant impairment to functioning — symptoms confined to one setting make ADHD unlikely.',
    'Comparing a child''s behaviour to a sibling is a common parental concern; it is important to validate this while explaining that temperament and development vary widely between children in the same family.',
    'Watchful waiting with a follow-up review in approximately 10 weeks is the appropriate first-line response when a child''s behaviour is within the normal range and no concerns have been raised by school.',
    'Referral to a group-based parenting support programme is a useful and low-risk intervention for parents of children with high energy levels or suspected ADHD traits.',
    'Safety-netting should include advising the parent to return sooner if school raises concerns or if difficulties with learning, attention, or social behaviour become apparent.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  166,
  'Sensation of Lump in Throat',
  'ENT & Eye',
  'Telephone consultation',
  false,
  'Michelle Turner',
  '41-year-old female',
  ARRAY[]::text[],
  ARRAY['No known drug allergy','Not currently on any medication'],
  'Patient booked routine appointment to discuss a throat symptom that has been present for several weeks.',
  'Patient calling with a persistent sensation of a lump in her throat lasting over four weeks.',
  'Hi doctor, I''ve had this strange feeling of a lump in my throat for a few weeks now and it''s really worrying me. I''m not sure what''s going on.',
  'She has been feeling a persistent lump sensation in her throat for over four weeks. It is not painful, and she has no difficulty swallowing. She has had no weight loss, no night sweats, no nausea, vomiting, or loss of appetite. No heartburn, abdominal pain, or changes in bowel or bladder habits. She frequently clears her throat and finds herself swallowing saliva even when she is not eating or drinking. If asked about stress: she has been under significant emotional strain recently because her husband was diagnosed with bowel cancer six weeks ago. He is currently awaiting chemotherapy. The situation has been overwhelming, and she is struggling to cope at work. She works as an estate agent and has made several errors at work recently due to distraction. Her manager has spoken to her about her performance, which has added further pressure.',
  ARRAY['If asked about lumps or swellings in the neck: she has not noticed anything and checked herself at home','If asked about voice changes or hoarseness: no changes to her voice','If asked about coughing up blood or vomiting blood: no'],
  'She does not smoke, drink alcohol, or use illicit drugs.',
  'Suspects the lump sensation in her throat could be a sign of cancer.',
  'Deeply worried this could be something serious, particularly given her husband''s recent diagnosis.',
  'Hoping the doctor can arrange scans or tests to rule out anything sinister.',
  ARRAY[]::text[],
  NULL,
  'Say no to any other questions asked outside of the details already provided in the scenario.',
  ARRAY[
    'Ask when the patient first noticed the sensation of a lump in the throat',
    'Ask whether the sensation is constant or intermittent — intermittent symptoms are more typical of globus sensation, while constant symptoms may suggest a structural or more serious cause including malignancy',
    'Ask whether there is any associated throat pain or pain on swallowing (odynophagia)',
    'Ask whether she has noticed any lumps or swellings in the neck',
    'Ask whether she has any difficulty swallowing (dysphagia)',
    'Ask whether she experiences heartburn or a sour taste in the mouth, which may suggest acid reflux or GORD',
    'Ask about symptoms of postnasal drip, such as a runny nose or mucus dripping down the back of the throat',
    'Ask about nausea or vomiting; if present, ask whether vomit has contained blood',
    'Ask about red flag symptoms: unintentional weight loss, night sweats, persistent hoarseness, or voice changes',
    'Ask about any particular triggers for the throat sensation, such as stress, certain foods, caffeine, or time of day',
    'Ask whether she frequently clears her throat or finds herself dry swallowing (swallowing without food or liquid)',
    'Ask about recent emotional stress or difficult life events',
    'Ask about smoking history, alcohol use, and any occupational exposures such as voice strain, dust, or fumes',
    'Give a likely diagnosis of globus sensation (globus pharyngeus)'
  ],
  ARRAY[
    'Offer a face-to-face appointment for further assessment, including examination of the neck and throat',
    'Acknowledge that stress and anxiety are likely contributing factors and recommend support strategies such as Cognitive Behavioural Therapy (CBT), mindfulness, yoga, regular exercise, or relaxation apps such as Headspace',
    'Provide vocal hygiene advice, including reducing caffeine intake, avoiding habitual throat clearing or dry swallowing, and suggesting sipping chilled carbonated water when the urge to clear the throat arises',
    'Offer a short-term fit note given that work-related stress is affecting her health and performance',
    'Reassure the patient that, given the absence of red flag symptoms, a scan or referral is not indicated at this stage',
    'Advise that if symptoms persist, worsen, or if anything concerning is found on examination, further investigation including referral to a specialist may be necessary',
    'Safety-netting advice: advise the patient to seek urgent medical attention if the throat sensation becomes constant or significantly worsens, or if she develops any new symptoms such as difficulty swallowing, voice changes, unexplained weight loss, pain, or any visible lumps or swellings',
    'Offer a follow-up appointment in 3 to 4 weeks to assess progress and review response to the management plan'
  ],
  'Thank you for calling today, and I really appreciate you sharing all of that with me. I can hear how distressing this has been, and particularly given everything happening with your husband at the moment, it makes complete sense that you would be feeling anxious and on edge about your own health too.

Let me start by saying something that I hope will be reassuring. From everything you have described — no difficulty swallowing, no weight loss, no changes to your voice, no lumps you have noticed yourself — nothing you have told me today points towards something serious or sinister. I know that is what you were worried about, Michelle, and I want to be open with you about that.

What you are describing actually fits very well with a condition called globus pharyngeus, sometimes just called globus sensation. This is where you feel as though there is something stuck or lodged in the throat, but when the area is examined properly, there is nothing there physically. It is a very common symptom, and importantly it is not dangerous. That said, I want to be clear — just because there is nothing harmful there does not mean the sensation is not real. It is absolutely real, and it can be very uncomfortable and distressing.

One of the things we know about globus sensation is that it is very commonly triggered or made worse by stress and emotional strain. Given what you have been going through over the past few weeks with your husband''s diagnosis and the pressures at work, it would be very understandable for your body to be responding in this way. Stress can have a surprisingly powerful effect on the throat and the muscles around it.

I would still like to invite you in for a face-to-face appointment so that I can examine your throat and neck properly. Even though I am not expecting to find anything, an examination allows us to be thorough and to make sure nothing has been missed.

I also want to support you more broadly during this very difficult time. One thing that can really help with globus sensation — and with the anxiety that often accompanies it — is talking therapy such as CBT, or Cognitive Behavioural Therapy. It teaches practical techniques to manage stress and reduce the physical symptoms it causes. Mindfulness, yoga, and even gentle exercise are also really effective for many people. If you feel that work has simply become unmanageable, I can provide you with a short-term fit note to give you some breathing space.

On a practical note, something that many people with this throat sensation find helpful is to resist the urge to constantly clear the throat or swallow — that habit can actually make the feeling more pronounced. One simple tip is to take small sips of cold sparkling water when the urge comes on, as this can help settle the reflex.

I will arrange a follow-up with you in three to four weeks to see how things are going. If anything changes before then — particularly if the sensation becomes constant, or you notice any difficulty swallowing, any voice changes, or any lumps appearing — please do come back to us straightaway. We are here to support you.',
  ARRAY[
    'Globus pharyngeus (globus sensation) is a subjective feeling of a lump or foreign body in the throat in the absence of any true obstruction; common causes include stress and anxiety, GORD, postnasal drip, and upper oesophageal sphincter dysfunction.',
    'Key red flag features that would prompt urgent ENT referral via the two-week wait pathway include constant (rather than intermittent) sensation, dysphagia, odynophagia, unexplained weight loss, voice changes, or a visible or palpable neck lump.',
    'In the absence of red flag features, globus sensation can be managed in primary care with reassurance, a face-to-face examination of the throat and neck, and appropriate safety-netting advice.',
    'Stress and emotional strain are recognised contributing factors to globus sensation; psychological support including CBT, mindfulness, and relaxation techniques should be offered as part of management.',
    'Vocal hygiene advice — including reducing caffeine, avoiding habitual throat clearing, and sipping cold carbonated water — can help reduce the frequency and intensity of the globus sensation.',
    'A short-term fit note may be appropriate when work-related stress is clearly contributing to symptoms and affecting occupational functioning.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  167,
  'Abnormal Cholesterol Results',
  'Cardiology',
  'Video consultation',
  false,
  'Ryan Fletcher',
  '39-year-old male',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No known drug allergy','Smoker — smoking cessation advice needed'],
  'Face-to-face consultation 3 weeks ago with Dr S. Patel (Clinical Practitioner Access Role). Presenting complaint: Patient booked appointment requesting routine blood tests, including cholesterol, after a home testing kit suggested a raised level. Examination: BP 130/80 mmHg, BMI 31. Plan: Arrange full lipid profile and routine blood tests. Schedule follow-up to discuss results.

Blood Test Results:
Lipid Profile | Result (mmol/L) | Reference Range
Total Cholesterol | 6.0 | < 5.0
HDL Cholesterol | 1.1 | > 1.0
LDL Cholesterol | 3.9 | < 3.0
Triglycerides | 1.7 | < 1.7
Total/HDL Ratio | 5.5 | < 4.0
QRISK3 Score: 4%
HbA1c, U&Es, LFTs, Thyroid Function Tests, Full Blood Count: all within normal reference ranges.',
  'Patient booked follow-up consultation to discuss blood test results, specifically cholesterol.',
  'Hi doctor, I''ve come to find out about my blood test results. I''m a bit nervous about what they might show.',
  'He is here to go through the results of his recent cholesterol blood tests. He had a home testing kit that flagged raised cholesterol, which prompted him to contact the surgery to request cholesterol tablets. The GP instead advised formal lab tests, which have now come back. He has been feeling well with no chest pain, shortness of breath, or other symptoms.',
  ARRAY['If asked about diet: unhealthy — relies heavily on takeaways and processed food','If asked about exercise: very little — he has a sedentary job working as a software developer','If asked about why he first checked his cholesterol: his brother-in-law, who is in his early 40s, recently died of a heart attack and the family attributed it to high cholesterol','If asked about family history: he was adopted as a child so has no knowledge of his biological family history'],
  'He smokes approximately 10 cigarettes a day and has done for around 10 years. He does not drink alcohol. He lives with his wife. His job involves sitting at a desk for most of the day as a software developer.',
  'Thinks his cholesterol is probably raised due to his diet — he eats a lot of processed and takeaway food.',
  'Worried about having a heart attack, especially following the death of his brother-in-law.',
  'Would like to be started on cholesterol-lowering tablets (statins) as soon as possible.',
  ARRAY[]::text[],
  NULL,
  'Say no to any other questions asked outside of the details already provided in the scenario.',
  ARRAY[
    'Clarify why the patient originally requested the cholesterol test — explore the background and what motivated him',
    'Ask about symptoms of cardiovascular disease: chest pain, shortness of breath, palpitations, dizziness, headaches, and any weakness or numbness affecting one side of the body that might suggest stroke or TIA',
    'Ask about lifestyle factors: diet, physical activity levels, and the nature of his occupation (sedentary work increases cardiovascular risk)',
    'Ask about smoking, alcohol use, and any other substance use',
    'Ask about personal or family history of cardiovascular disease, including heart attacks, strokes, high blood pressure, and diabetes',
    'Explore his understanding of cholesterol and cardiovascular risk — identify any misconceptions',
    'Explore Ideas, Concerns, and Expectations — particularly his fear of heart attack and his desire to start statins',
    'Give a diagnosis of raised cholesterol with a low QRISK3 score of 4%'
  ],
  ARRAY[
    'Reassure the patient that although cholesterol is raised, his QRISK3 score is low at 4%, and there is no current indication for statin therapy according to NICE guidelines',
    'Explain that a QRISK3 score of 4% means that out of 100 people with the same risk factors, approximately 4 are estimated to develop a heart attack or stroke over the next 10 years — this is considered a low risk, but still worth reducing through lifestyle change',
    'Offer lifestyle advice: refer for smoking cessation support (key modifiable risk factor), provide heart-healthy diet advice or refer to a dietitian if available, and encourage regular aerobic exercise — at least 150 minutes of moderate-intensity activity per week',
    'If the patient still wishes to proceed with statin treatment after lifestyle discussion, explain clearly what statins are, how they work, and their potential side effects — including muscle aches, gastrointestinal upset, and effects on liver function',
    'If, after a balanced and informed discussion, the patient expresses a clear preference to start statins and understands the risks and benefits, it would be reasonable to offer statin therapy',
    'According to NICE guidelines, even when QRISK3 is below 10%, statin treatment can still be considered if lifestyle change is ineffective or inappropriate, the patient expresses an informed preference for treatment, or there is concern that calculated risk may underestimate true cardiovascular risk — for example, due to an unknown family history such as adoption',
    'Arrange a repeat lipid profile in 3 months regardless of whether the patient starts statin therapy — this monitors either the response to lifestyle changes or the effect of medication',
    'Offer referral to a Health and Wellbeing Coach or local lifestyle support services if the patient is interested',
    'Provide written materials or links to trusted resources such as the NHS website or the British Heart Foundation',
    'Safety-net: advise him to seek urgent medical help if he develops chest pain, breathlessness, palpitations, or weakness or numbness affecting one side of the body',
    'Offer a follow-up appointment in 3 months to review progress'
  ],
  'Thank you for coming in today, and for being so proactive about your health. I know today''s appointment has felt quite significant, especially given what has happened with your brother-in-law, so I really appreciate you following this up.

I''ve had a good look at your blood test results and I want to talk you through what they show. Your total cholesterol is 6.0, which is above the recommended level of 5.0. Your LDL cholesterol — that''s often described as the ''bad'' cholesterol — is also raised at 3.9, where we''d ideally want it below 3.0. These results do confirm that your cholesterol is on the higher side and worth addressing.

However, Ryan, I want to give you the full picture. We use a tool called QRISK3 to calculate your overall risk of having a heart attack or stroke over the next 10 years. This takes into account your age, blood pressure, cholesterol, smoking status, and a range of other factors. Your score works out at 4%. What that means in practical terms is that, out of 100 people with the same profile as you, approximately 4 would be expected to develop a significant cardiovascular event over the next decade. That is actually considered a low-risk score.

Now, that doesn''t mean we should ignore it — I want to bring that risk down, and there is plenty we can do. The most effective first step is lifestyle change. The biggest single thing you can do is to stop smoking. Smoking significantly raises your cardiovascular risk, and quitting would have a powerful impact — not just on your cholesterol, but on your heart, lungs, and overall life expectancy. We have excellent free stop smoking services and I would be very happy to refer you.

Diet is also really important. You mentioned you rely quite a bit on processed food and takeaways. Reducing saturated fat, increasing your intake of oily fish, oats, and plenty of vegetables, and cutting down on processed food can all make a meaningful difference to your cholesterol over time. I can provide you with a leaflet on heart-healthy eating or refer you to a dietitian if you would find that helpful.

Physical activity is the third key area. The recommendation is at least 150 minutes of moderate activity per week — things like brisk walking, cycling, or swimming. Even small increases in daily movement, like walking more during your lunch break, can start to make a difference.

You mentioned that you would like to start cholesterol tablets. I understand why, particularly given your family experience. I want to be transparent with you — at your current risk level, NICE guidelines do not indicate that statins are routinely necessary right now. That said, if after our discussion today you feel strongly that you would like to try them, and you understand the potential benefits and the possible side effects — which can include muscle aches and effects on the liver — we can have a further conversation about starting them. Your adoption also means we don''t know your biological family history, and that is a factor worth acknowledging.

Regardless of what we decide today, I would like to repeat your blood tests in three months — this will allow us to see how any changes you make are affecting your cholesterol levels. I''ll arrange a follow-up at that point to review everything together.

Please come back to us urgently if you develop any chest pain, shortness of breath, palpitations, or any sudden weakness or numbness — particularly if it affects one side of your body. Those symptoms would need same-day assessment.',
  ARRAY[
    'Raised cholesterol alone does not automatically indicate statin therapy — the QRISK3 tool should be used to calculate 10-year cardiovascular risk, and statins are routinely recommended by NICE when QRISK3 is 10% or above.',
    'Even when QRISK3 is below 10%, statins may still be considered if the patient has an informed preference, if lifestyle changes are ineffective or inappropriate, or if there is reason to suspect the calculated risk underestimates true risk — for example, in a patient who was adopted and has no knowledge of their biological family history.',
    'Smoking is the most important modifiable cardiovascular risk factor and smoking cessation should be actively offered at every opportunity, with referral to structured stop smoking services.',
    'A repeat lipid profile should be arranged in 3 months regardless of whether statin therapy is started — to assess either the response to lifestyle intervention or the effectiveness of medication.',
    'Shared decision-making is central to this consultation: the patient should be fully informed about their risk level, the benefits and limitations of statins, and the role of lifestyle change before any treatment decision is made.',
    'Sedentary occupation, an unhealthy diet, smoking, and a BMI of 31 are all modifiable risk factors that should be addressed comprehensively in this consultation.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  168,
  'Methotrexate Request',
  'General Practice',
  'Video consultation',
  false,
  'Jonathan Harper',
  '41-year-old male',
  ARRAY[]::text[],
  ARRAY[]::text[],
  'Bloods done 7 months ago — filed as satisfactory:
FBC: Haemoglobin (Hb) 140 g/L (ref 130–180 g/L male); White Cell Count (WCC) 6.5 x10⁹/L (ref 4.0–11.0 x10⁹/L); Neutrophils 3.8 x10⁹/L (ref 2.0–7.5 x10⁹/L); Platelets 250 x10⁹/L (ref 150–400 x10⁹/L).
U&Es: Sodium 140 mmol/L (ref 135–145 mmol/L); Potassium 4.2 mmol/L (ref 3.5–5.0 mmol/L); Creatinine 80 µmol/L (ref 60–120 µmol/L male); eGFR >90 mL/min/1.73m² (ref >60 mL/min/1.73m²).
LFTs: ALT 22 U/L (ref 10–50 U/L); AST 18 U/L (ref 10–40 U/L); ALP 78 U/L (ref 30–130 U/L); Bilirubin 12 µmol/L (ref <21 µmol/L); Albumin 42 g/L (ref 35–50 g/L).
Inflammatory Markers: CRP 4 mg/L (ref <5 mg/L); ESR 8 mm/hr (ref <15 mm/hr male under 50).

Note entry (4 months ago) — by Mr P. Chandra (Pharmacist Access Role): Attempted to contact patient by phone on three occasions and sent a text message regarding a missed methotrexate monitoring appointment. No response received. Methotrexate withheld as per safety protocol. Notification letter sent to patient''s home address.',
  'Patient booked urgent appointment to discuss restarting methotrexate, which was stopped after missed blood monitoring.',
  'Hi doctor, I''m calling because my joints have been getting really bad over the past few days and I need to get my methotrexate restarted. It was stopped a few months ago and things have really gone downhill.',
  'Jonathan is here to discuss restarting methotrexate for rheumatoid arthritis (RA), which was stopped several months ago due to missed blood monitoring. Over the past 5 days he has noticed increasing pain, stiffness, and swelling in his hands, which is affecting his work and daily life. He works as a barrister and is struggling significantly to write, type, and manage case documents. Four months ago he missed his routine monitoring blood test because of an exceptionally busy period at work — he had several high-profile cases and court appearances. He received a letter from the practice warning that methotrexate would be stopped if bloods were not done, but did not find the time to act on it. His symptoms have worsened progressively and he now wants to restart methotrexate as it had previously controlled his RA well. He has been taking paracetamol regularly and only started ibuprofen the day before. He has not yet contacted his rheumatology team.',
  ARRAY['If asked about folic acid: he was taking it alongside methotrexate but has not had any since the methotrexate was stopped','If asked about side effects from methotrexate previously: no significant side effects experienced','If asked about infections: no cough, fever, sore throat, or urinary symptoms','If asked about other joints: it is mainly his hands and fingers, with some stiffness in his wrists'],
  'Non-smoker. Does not drink alcohol. Lives with his wife and two children. Works as a barrister and his symptoms are significantly affecting his ability to work.',
  'Believes his rheumatoid arthritis is flaring because methotrexate was stopped and wants to restart it as soon as possible.',
  'Worried that his symptoms will keep worsening and will affect his ability to work effectively as a barrister.',
  'Wants the GP to restart his methotrexate prescription today so that his symptoms can be brought back under control.',
  ARRAY[]::text[],
  NULL,
  'Say no to any other questions asked outside of the details already provided in the scenario.',
  ARRAY[
    'Clarify the reason for today''s call and confirm the nature and duration of worsening joint symptoms and their impact on function',
    'Ask about symptoms of an RA flare: morning stiffness, joint swelling, pain, and fatigue',
    'Ask which joints are currently affected and whether any other joints are involved',
    'Ask whether he is having difficulty moving the affected joints or is unable to move them at all; ask whether the joints are hot or swollen, and ask about systemic symptoms such as fever or feeling generally unwell — this helps exclude septic arthritis, which should be suspected if a single joint is hot, swollen, immobile, and accompanied by systemic features',
    'Ask about extra-articular features of rheumatoid arthritis, including: Eyes (redness or visual changes suggesting episcleritis or scleritis); Lungs (shortness of breath, persistent cough, or chest pain suggesting interstitial lung disease); Heart (chest pain, palpitations, or breathlessness suggesting pericarditis); Skin (unusual rashes, easy bruising, or painful red spots suggesting vasculitis)',
    'Ask about the functional impact of symptoms on activities of daily living, including the ability to work, write or type, and carry out domestic tasks such as cooking, cleaning, and self-care',
    'Confirm when the last dose of methotrexate was taken and whether any side effects were experienced',
    'Ask whether he is still taking folic acid',
    'Ask about other medications used in the interim (e.g. NSAIDs or paracetamol)',
    'Ask about any symptoms of infection: cough, fever, urinary symptoms, or sore throat — this is important as restarting methotrexate in the presence of active infection increases the risk of serious complications including sepsis',
    'Clarify why the monitoring blood tests were missed and explore his understanding of the monitoring requirements',
    'Ask about social history including occupation, smoking, and alcohol use',
    'Explore Ideas, Concerns, and Expectations',
    'Give a likely diagnosis of rheumatoid arthritis flare due to discontinuation of methotrexate'
  ],
  ARRAY[
    'Acknowledge that the patient is likely experiencing a flare of rheumatoid arthritis as a result of methotrexate being withheld',
    'Explain clearly that methotrexate cannot be restarted until up-to-date blood tests have been reviewed to confirm it is safe to do so',
    'Arrange urgent blood tests: full blood count, liver function tests, kidney function (U&Es), and CRP',
    'Reinforce the importance of regular monitoring for methotrexate given the risk of liver toxicity, renal impairment, and bone marrow suppression',
    'Prescribe anti-inflammatory treatment for symptom relief: advise taking ibuprofen regularly with food and prescribe omeprazole for gastric protection; alternatively, offer naproxen with omeprazole if stronger anti-inflammatory relief is needed or preferred',
    'Consider a short course of oral steroids if symptoms are severe or not adequately controlled with NSAIDs alone',
    'Send an update to the rheumatology team informing them of the current flare and the plan to restart methotrexate once blood results are back and within the normal reference range',
    'Discuss practical strategies to support future blood test compliance and avoid missed monitoring appointments — for example, setting phone reminders or booking tests well in advance',
    'Offer pneumococcal vaccination and annual influenza vaccination to reduce infection risk associated with immunosuppressive therapy',
    'Safety-net: advise the patient to seek urgent review if symptoms worsen significantly, especially if a joint becomes hot, swollen, and immobile, or if he develops a fever or feels systemically unwell',
    'Book a follow-up appointment or telephone review once blood results are available'
  ],
  'Thank you for getting in touch today, and thank you for being so open about what has been happening. I can hear how much your joints have been affecting you over the past few days, and I know how demanding your work is — being unable to write and manage documents as a barrister must be extremely frustrating on top of the physical discomfort.

I want to be straightforward with you. From what you''ve described — the increasing stiffness, swelling, and pain in your hands since the methotrexate was stopped — this does sound very much like a flare of your rheumatoid arthritis. That makes complete sense given that the methotrexate was keeping things under control, and stopping it has allowed the inflammation to return. You''re right to be concerned and right to get in touch.

However, Jonathan, I am not able to restart the methotrexate today, and I want to explain clearly why. Methotrexate is a medication that can affect your liver, kidneys, and blood cell production. These effects can build up silently without causing obvious symptoms, which is why the regular blood tests are so important. Our shared care agreement with Rheumatology — and national safety guidelines — require that we have up-to-date blood results before we can safely issue another prescription. Because the last set of results is now seven months old and the monitoring was missed, we need a fresh set before we can proceed. I know that is not what you were hoping to hear, and I genuinely understand the frustration given how busy things were at work when the appointment was missed.

The good news is that the last time we did check your bloods, everything looked fine. So there is every reason to think that once we have the new results back — which I would like to arrange as urgently as possible — we will be able to restart the methotrexate without further delay.

In the meantime, I want to help with your symptoms. You mentioned you only started ibuprofen yesterday — taking it regularly, three times a day with food, is more effective for managing inflammation than taking it only when the pain peaks. I will also prescribe omeprazole to protect your stomach lining. If you find that ibuprofen is not giving enough relief, naproxen is a stronger option and we can switch to that. If things become really difficult before we get the blood results, I could also consider a short reducing course of steroid tablets to settle the flare — I would rather hold off for now if the NSAIDs are working, but it is an option we can revisit.

I will also send a message to your rheumatology team today to let them know about the current situation and our plan. They may have additional advice or want to see you sooner, and it is important they are kept in the loop.

Looking ahead, I''d like us to think together about how to prevent this situation from happening again. Setting a recurring reminder on your phone a month or two before your next blood test is due can really help. We can also send you a reminder from the practice well in advance. What do you think would work best for your schedule?

Finally, please do contact us urgently if your symptoms deteriorate significantly before your blood results are back — particularly if any joint becomes very hot, extremely swollen, or impossible to move, or if you develop a temperature or start to feel generally unwell. Those features would need same-day assessment to rule out infection in the joint.',
  ARRAY[
    'Methotrexate is a DMARD (disease-modifying anti-rheumatic drug) that requires regular blood monitoring — typically every 2 to 3 months — to detect potentially serious adverse effects including hepatotoxicity, renal impairment, and bone marrow suppression.',
    'If a patient on methotrexate misses their monitoring, the medication must be withheld until updated blood results confirm it is safe to resume; restarting without current monitoring risks severe and potentially life-threatening complications.',
    'During an RA flare while awaiting safe resumption of methotrexate, NSAIDs (ibuprofen or naproxen) with gastroprotection (omeprazole) are first-line; a short reducing course of oral prednisolone can be considered for severe or refractory symptoms.',
    'Septic arthritis should always be considered and excluded when assessing a patient with a joint flare — it should be suspected if a single joint is hot, swollen, immobile, and accompanied by systemic features such as fever.',
    'Patients on immunosuppressive therapy are at increased risk of infection and should be offered pneumococcal vaccination and annual influenza vaccination.',
    'Supporting patients in developing practical strategies to maintain monitoring compliance — such as phone reminders or advance booking — is an important part of long-term DMARD management and can prevent avoidable medication interruptions.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  169,
  'Struggling with Sex After Past Trauma',
  'General Practice',
  'Video Consultation',
  false,
  'Rachel Osei',
  '34-year-old female',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No known drug allergy'],
  NULL,
  'The patient booked a routine video consultation to discuss a personal and sensitive concern.',
  'Hi doctor, I need to bring up something quite private. I haven''t been able to have sex with my husband for months now, and it''s really worrying me.',
  'About 8 months ago, you were raped after your drink was spiked at a party. You reported it to the police and an investigation is still ongoing. You had STI screening afterwards and everything came back negative. Since the assault, you have been unable to have penetrative sex. When you try to be intimate with your husband, the muscles around your vagina tighten up automatically, and penetration becomes painful or impossible. You become anxious and tense, even though you love your husband and want to be close to him. You did not have this problem before the assault. Your sexual relationship with your husband was normal beforehand, but since the incident your body seems to shut down whenever intercourse is attempted. You feel frustrated and embarrassed because you want things to go back to how they were. You love your husband very much but have not been able to tell him about the rape, as you feel guilty and keep thinking that if you had stayed home that night, none of this would have happened. You have not received any counselling or therapy so far.',
  ARRAY['Your mood is not particularly low, but you are worried about the impact this is having on your relationship. You are not experiencing nightmares or flashbacks at the moment.'],
  '',
  'You believe the rape has affected your ability to have sex and that your body is reacting against penetration.',
  'You worry that you may never be able to have sex again and that your marriage might suffer as a result.',
  'You would like help, support, and guidance on how to overcome this so you can feel normal again.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor.',
  ARRAY[
    'Acknowledge that the patient has brought a very personal and difficult issue and thank her for trusting you. For example: "Thank you for sharing something so personal with me today. I can only imagine how difficult this must be to talk about. Please be assured that we will do our best to support you. Are you comfortable talking about what happened 8 months ago?"',
    'Show respect and sensitivity by informing her that you will be asking a number of personal questions regarding her sexual history. This demonstrates good interpersonal skills and helps prepare the patient for the discussion.',
    'Ask how long she has been experiencing difficulties with intimacy.',
    'Ask what happens during attempted intimacy — for example, whether she experiences fear, anxiety, physical pain, or involuntary tightness. This helps differentiate an emotional trauma response from secondary vaginismus.',
    'Ask if sexual intercourse was comfortable prior to the traumatic event.',
    'Ask if she has had any medical review, STI screening, or forensic examination after the incident.',
    'Screen for symptoms of PTSD by asking about nightmares, flashbacks, intrusive thoughts, feeling constantly on edge (hypervigilance), or feeling emotionally numb or detached.',
    'Ask about her mood, sleep, appetite, concentration, and general day-to-day functioning.',
    'Ask about suicidal thoughts or self-harm ideation.',
    'Ask how her symptoms have impacted her relationship, emotional wellbeing, ability to work, and daily life.',
    'Ask about her social history, including smoking, alcohol use, and any use of illicit substances. Enquire about her occupation, who she lives with, and what support network she has around her.',
    'Ask about her ideas, concerns, and expectations regarding what might be going on and what kind of help or outcome she is hoping for from the consultation.',
    'Give a working diagnosis of secondary vaginismus, likely triggered by the sexual assault.'
  ],
  ARRAY[
    'Acknowledge the trauma and validate the patient''s feelings; reassure her that her reactions are understandable and that help is available.',
    'Explain that her symptoms are consistent with secondary vaginismus, which can develop following traumatic sexual experiences such as rape.',
    'Offer referral to a pelvic floor physiotherapist experienced in vaginismus. Explain that they will guide her through gentle pelvic floor exercises that help her regain control of the vaginal muscles and reduce involuntary tightening.',
    'Inform her that another helpful treatment option is the use of vaginal dilators (also called vaginal trainers). These are smooth devices that come in gradually increasing sizes and can be used at her own pace to help desensitise the area and reduce pain or muscle spasm during penetration. They can be purchased over the counter.',
    'Offer referral to psychosexual therapy with a focus on sexual trauma. Explain that this helps address the fear, anxiety, and emotional impact associated with penetration, and works alongside physical therapy to improve symptoms.',
    'Acknowledge that it may feel very difficult to tell her husband about the rape, but gently explain that sharing this with him might help him understand what she is going through and allow him to support her. If she does not feel ready to have that conversation herself, reassure her that the psychosexual therapy team can help guide and support this discussion when the time feels right.',
    'Offer referral to sexual violence victim support charities, where she can also access counselling and support tailored to survivors of sexual assault.',
    'Safety net: Advise her to seek urgent help through the GP urgent line or 111 if she develops thoughts of suicide, self-harm, or feels unable to cope.'
  ],
  'Thank you for feeling able to share something so personal today, Rachel. I want to start by saying that what you''ve told me takes real courage, and I want to make absolutely sure you feel supported throughout our conversation.

What you''re describing — the involuntary tightening of the vaginal muscles during attempted intercourse, the anxiety and tension you feel even though you want to be close to your husband — fits a pattern we call secondary vaginismus. This is where the pelvic floor muscles contract automatically in response to the idea or attempt of penetration. It''s not something you are doing consciously, and it is certainly not your fault. This kind of physical response can develop after a traumatic sexual experience, and it is actually a well-recognised condition that we know how to support.

In terms of next steps, I''d like to refer you to a pelvic floor physiotherapist who specialises in vaginismus. They work very gently and at your own pace, guiding you through exercises that help you gradually regain control over those muscles and reduce the involuntary tightening. Some women also find vaginal dilators — smooth devices available over the counter that come in a range of gradually increasing sizes — very helpful for desensitising the area over time. There is no rush with any of this, and everything would be entirely at your own pace.

I''d also like to refer you to a psychosexual therapist who has experience working with survivors of sexual trauma. This kind of therapy addresses the fear, anxiety, and emotional response that has built up around intimacy, and works hand in hand with the physical treatment. Many women find that this combination approach makes a really meaningful difference.

I understand how difficult it must feel knowing that your husband doesn''t yet know what happened to you. You mentioned feeling guilty, and I want to gently say that what happened was not your fault in any way — not then, and not now. Sharing what happened with your husband might help him better understand what you are going through and allow him to support you. When the time feels right, the psychosexual therapy team can also help to facilitate and support that conversation if you''d like that.

I can also refer you to a specialist support charity for survivors of sexual assault, where you can access confidential counselling and peer support from people who truly understand what you''re going through.

Finally, on safety: if you ever find yourself feeling overwhelmed, unable to cope, or having thoughts of harming yourself, please don''t hesitate to contact us urgently or call 111. You don''t have to manage this alone, and we are here for you every step of the way.',
  ARRAY[
    'Secondary vaginismus is an involuntary tightening of the pelvic floor muscles during attempted penetration; it can develop following sexual trauma and is clinically distinct from primary vaginismus.',
    'Key management includes referral to a pelvic floor physiotherapist experienced in vaginismus, use of vaginal dilators, and referral to psychosexual therapy with a trauma focus.',
    'Always screen for PTSD symptoms (flashbacks, nightmares, hypervigilance, emotional numbing) and assess mood, including suicidal ideation, when a patient discloses sexual assault.',
    'Patients may not have disclosed the assault to close family members; approach this sensitively and avoid pressuring disclosure — psychosexual therapy can support this process when the patient is ready.',
    'Safety-net by advising patients to seek urgent review via GP urgent line or 111 if they develop thoughts of self-harm or feel unable to cope.',
    'Referral to sexual violence victim support charities provides additional counselling and tailored survivor support alongside NHS pathways.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  170,
  'Flight Anxiety',
  'Mental Health',
  'Telephone Consultation',
  false,
  'Simon Hartley',
  '42-year-old male',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No known drug allergy'],
  'Patient booked an urgent telephone appointment to discuss some concerns. You are Simon Hartley, a 42-year-old male. You are calling today because you are due to fly back to the UK from Belgium tomorrow and you are very anxious about the flight. You have a long-standing fear of flying, and in the past you have taken diazepam before flights, which helped you remain calm during the journey. This was prescribed by your previous GP. You have one tablet left, which you are planning to use for the flight home tomorrow. However, you also have an upcoming long-haul flight to Canada in five days, and you are calling to request a prescription for diazepam to help manage your anxiety for that flight. Your fear of flying began after experiencing severe turbulence during a flight to Australia six years ago. During take-off, landing, or turbulence, you feel very panicky. Your heart races, you begin to sweat, and you often notice a tingling sensation in your lips and fingers. You have not been formally diagnosed with anxiety and have never had therapy or counselling. You have tried breathing exercises and listening to calming music on flights but they do not help much.',
  'The patient booked an urgent telephone consultation to request a repeat prescription for flight anxiety.',
  'Hi doctor, I don''t want to take up too much of your time. I just need some diazepam for my flight anxiety if that''s okay. I have one tablet left and I''m about to run out. I have a couple of flights coming up and I''d really appreciate a few more, please.',
  '',
  ARRAY[]::text[],
  'You don''t smoke or drink, and you''re not on any regular medication. You have never had any issues with addiction or misusing medications. You work as a financial analyst. You are currently abroad on a short work trip and live in the UK with your partner.',
  'You believe diazepam helps you fly safely and manage your anxiety. You consider it the only effective solution for your flight-related symptoms.',
  'You are worried that you will panic during the long-haul flight to Canada and will be unable to cope without diazepam.',
  'You would like the doctor to prescribe 2 to 3 tablets of diazepam 5 mg for your upcoming flight to Canada. You plan for your partner to collect the medication and bring it to the airport.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor.',
  ARRAY[
    'Ask about the onset of the flying anxiety, when it started, and whether anything specific triggered it.',
    'Ask what typically happens during flights — for example, panic attacks, inability to board, or physical symptoms such as a racing heart, sweating, or tingling.',
    'Ask if the patient experiences anxiety in other situations apart from flying.',
    'Ask how long he has been using diazepam for flights and where he usually obtained the prescription.',
    'Ask about mood, sleep, and appetite.',
    'Ask about any history of substance misuse, alcohol intake, and smoking.',
    'Ask about his occupation.',
    'Clarify his current location, the date of his return flight, and details of the upcoming long-haul flight.',
    'Ask if he has tried or considered non-drug approaches such as CBT, breathing techniques, or exposure therapy.',
    'Ask about his ideas, concerns, and expectations.',
    'Give a working diagnosis of flight anxiety.'
  ],
  ARRAY[
    'Explain that diazepam is no longer prescribed for flight anxiety, as it carries significant risks including sedation, confusion, increased risk of deep vein thrombosis (DVT), respiratory depression, and a reduced ability to respond in emergencies.',
    'In addition, diazepam is illegal in some countries, which creates additional legal and safety risks when flying internationally.',
    'Offer safer and evidence-based alternatives for managing flight anxiety, including breathing exercises, distraction techniques such as listening to music or podcasts, watching a film or TV show, reading, or doing puzzles, and using calming and mindfulness apps like Headspace.',
    'If the patient still insists and explains that he has already tried breathing and distraction techniques without improvement, you may offer a very short course of diazepam — for example, two tablets of diazepam 2 mg only. Make it clear that this is a one-off prescription and will not be repeated in the future.',
    'Explain that a long-term approach is also important. Options such as talking therapy and structured fear-of-flying courses, like those offered by British Airways or EasyJet, are helpful long-term strategies to overcome flight anxiety.',
    'Offer a follow-up appointment after his return to the UK to review his symptoms and create a personalised care plan for ongoing anxiety management.'
  ],
  'Thank you for calling today, Simon, and for being so open about how difficult flying has become for you. I completely understand why you have relied on diazepam in the past — if it helped you stay calm during a flight, it makes total sense that you would want to use it again.

I do need to be honest with you about something, though, and I hope you will bear with me. Current medical guidance no longer supports prescribing diazepam for flight anxiety. The reasons come down to safety. Diazepam can cause sedation and confusion, and at altitude this effect can be amplified. It also raises the risk of blood clots forming in the legs — deep vein thrombosis — which can be particularly dangerous on long-haul flights. On top of that, it can impair your ability to react quickly in an emergency situation onboard. Are you following me so far?

There is also a practical issue: diazepam is classed as an illegal substance in some countries, so carrying it on an international flight could put you in a very difficult legal position.

I would love to talk you through some alternatives that are safe and that many people find genuinely helpful. Structured breathing exercises — particularly slow, diaphragmatic breathing — can reduce the physical symptoms of anxiety quite significantly. Distraction techniques like watching a film, listening to a podcast, reading, or working through puzzles are also well worth trying. Apps such as Headspace offer guided relaxation that you can use mid-flight.

If after trying those approaches you still find that the anxiety is overwhelming and truly unmanageable, I can consider prescribing a very small, one-off supply — no more than two tablets of diazepam at the lower 2 mg dose. This would not be something I could repeat in future, and I want to be clear about that from the outset.

When you are back in the UK, I would really like to see you for a proper follow-up. There are some excellent longer-term options, including talking therapy and structured fear-of-flying programmes run by airlines such as British Airways and EasyJet. These programmes have helped a lot of people feel genuinely confident about flying again. Would that be something you would consider?',
  ARRAY[
    'Diazepam is no longer recommended for flight anxiety due to risks of sedation, DVT, respiratory depression, impaired emergency response, and legal issues in certain countries.',
    'First-line non-pharmacological management includes breathing exercises, distraction techniques (music, films, reading, puzzles), and mindfulness apps such as Headspace.',
    'If a patient has genuinely exhausted non-pharmacological options and insists, a one-off very low-dose prescription (e.g. diazepam 2 mg, two tablets) may be considered, with clear communication that it will not be repeated.',
    'Long-term management of flight anxiety should include talking therapy and structured fear-of-flying courses offered by airlines such as British Airways and EasyJet.',
    'Always explore triggers, duration, and prior treatment history, and screen for generalised anxiety disorder when a patient presents with flight-specific anxiety.',
    'A follow-up appointment on return to the UK allows creation of a personalised, ongoing anxiety management plan.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  171,
  'Abnormal HbA1c Result',
  'Endocrine & Nephrology',
  'Telephone Consultation',
  false,
  'Martin Calloway',
  '40-year-old male',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No known drug allergy'],
  'Note entry 3 days ago by Dr Andrew Ashburn (Clinical Practitioner access role): arrange blood test with HCA — Ms. Joanne Badley. Seen yesterday by Ms Joanne Badley (Health Care Assistant role). Blood samples taken as requested. Blood pressure: 130/80 mmHg. BMI: 30. Blood test results: Urea and Electrolytes, eGFR, Full Blood Count, Liver Function Test, Thyroid Function Test, and CRP all reviewed and filed as normal by Dr Andrew Ashburn. The below blood results are still awaiting review and filing. Test | Result | Reference Range. HbA1c: 46 mmol/mol | <42 mmol/mol = Normal. Total Cholesterol: 5.8 mmol/L | <5.0 mmol/L (desirable). LDL Cholesterol: 3.9 mmol/L | <3.0 mmol/L. HDL Cholesterol: 1.3 mmol/L | >1.0 mmol/L. Triglycerides: 1.4 mmol/L | <1.7 mmol/L. QRISK3 Score (10-year risk): 5.5%. Patient was sent a text message inviting them to book an appointment to discuss blood test results. Patient booked a telephone consultation to discuss recent blood test results.',
  'The patient booked a telephone consultation to discuss the results of a recent NHS Health Check blood test.',
  'Hi Doctor, I had some blood tests done a few days ago as part of my NHS check-up, and I got a message asking me to call in. I wasn''t sure if there was something to worry about.',
  '',
  ARRAY[]::text[],
  'You work as a warehouse supervisor and spend most of your shift on your feet, though you do not do structured exercise outside of work. Your diet is not great — you tend to rely on convenience food and ready meals during the week. You live alone and rarely cook from scratch.',
  'You are not sure what the results will show.',
  'You have no specific concerns at this point.',
  'You would like to go through your results and understand what they mean.',
  ARRAY[]::text[],
  'If the doctor explains that you are at risk of developing diabetes or fall within the pre-diabetic range, ask whether there is any medication that could help reduce your risk of progressing to type 2 diabetes.',
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor.',
  ARRAY[
    'Confirm the reason for having the blood test — whether this was part of a routine NHS Health Check or arranged for another reason.',
    'Ask about symptoms to rule out undiagnosed diabetes, including blurred vision (diabetic retinopathy), increased thirst, frequent urination, increased appetite, unexplained weight loss or gain, non-healing wounds, and tingling in the hands or legs (diabetic neuropathy).',
    'Ask about any chest pain or shortness of breath, which may indicate cardiovascular complications.',
    'Ask about social and lifestyle factors, including smoking, alcohol intake, diet, weight, physical activity level, and occupation.',
    'Ask about family history of diabetes or other relevant medical conditions.',
    'Explore the patient''s ideas, concerns, and expectations (ICE).',
    'Explain that the blood test shows pre-diabetes and raised cholesterol, with a low QRISK3 score. Also inform the patient of his raised BMI.'
  ],
  ARRAY[
    'Offer lifestyle advice, including adopting a healthier diet by reducing saturated fat intake and increasing dietary fibre, alongside improving physical activity levels.',
    'Encourage at least 150 minutes of moderate-intensity exercise per week, such as brisk walking or cycling.',
    'Reassure the patient that medication is not routinely recommended for pre-diabetes, as most people can reverse it through sustained lifestyle changes.',
    'Refer to the NHS National Diabetes Prevention Programme — a nine-month, evidence-based lifestyle intervention that can be attended digitally, face-to-face, individually, or in a group.',
    'Offer further tests including a full lipid profile, BMI measurement, and QRISK3 calculation to assess cardiovascular risk.',
    'Inform the patient that HbA1c will be monitored annually to track long-term progress.',
    'Arrange a follow-up in 3 months to review lifestyle changes and assess whether additional interventions, such as weight management support or medication for obesity (e.g. orlistat), are required.',
    'Advise the patient to seek medical review if he develops symptoms suggestive of diabetes, such as increased thirst, frequent urination, unexplained weight loss, or persistent fatigue.'
  ],
  'Thanks for calling in today, Martin. I''m really glad you booked this appointment so we can go through your results together and make sure you leave with a clear picture of where things stand.

I''ll start with the good news. The majority of your blood tests — including your kidney function, liver function, thyroid, full blood count, and inflammation markers — all came back completely within the normal range. So there is a lot to feel reassured about there.

That said, there are two results I do want to talk through with you. Your blood sugar level is sitting in a range we call pre-diabetes. This means it is higher than the ideal level, but not yet high enough to be classified as full diabetes. Think of it as an early warning sign — your body is giving us a chance to act now, before things progress further. Does that make sense so far?

We also checked your cholesterol. Your total cholesterol and LDL — that''s the type we sometimes call the less helpful cholesterol — are both slightly above the healthy range. This means there is a little more fat circulating in the blood than we would ideally like, which over time can place some additional strain on the heart and blood vessels. I should also mention that your BMI, which is a measure of weight relative to height, is a little above the recommended range. This is relevant because excess weight can contribute to both raised blood sugar and raised cholesterol. I want to say that in a way that''s helpful rather than critical — many of my patients are in a similar position, and these are things we can genuinely work on together.

When we put all of this together into a risk calculator called QRISK3, your overall 10-year risk of having a heart attack or stroke comes out at 5.5%. To put that in context, if 100 people had the same results and risk factors as you, around 5 or 6 of them might experience a heart-related event over the next decade. So while the risk is low, these results are a real opportunity to make some changes now and keep it that way.

You asked whether medication might help reduce the risk of progressing to diabetes, which is a really sensible question. In most cases at this stage, we hold off on medication and focus on lifestyle first — and the research shows this can be very effective. Things like eating a little more fibre, cutting back on processed foods and ready meals where possible, and building in some regular movement can genuinely bring those blood sugar and cholesterol levels down.

I would also like to refer you to the NHS National Diabetes Prevention Programme. It is a nine-month structured programme, available online or face-to-face, which supports people in exactly your position to make sustainable lifestyle changes. It is evidence-based and completely free. We will also repeat your HbA1c every year to keep a close eye on things, and I would like to see you again in three months to review how you are getting on. If at that point we feel additional support is needed, such as a formal weight management programme, we can look at that together.',
  ARRAY[
    'An HbA1c of 42–47 mmol/mol indicates pre-diabetes (non-diabetic hyperglycaemia); values below 42 are normal, and 48 or above on two occasions diagnoses type 2 diabetes.',
    'Pre-diabetes is often reversible through sustained lifestyle changes including a healthier diet, increased physical activity, and weight reduction; medication is not routinely recommended at this stage.',
    'The NHS National Diabetes Prevention Programme is the recommended structured intervention for patients with pre-diabetes: a nine-month evidence-based course available digitally, face-to-face, individually, or in a group.',
    'HbA1c should be monitored annually in patients with pre-diabetes; arrange a clinical review at 3 months to assess lifestyle progress and consider additional interventions such as orlistat if needed.',
    'Raised BMI alongside pre-diabetes and dyslipidaemia should prompt calculation of QRISK3 to assess overall cardiovascular risk and guide shared decision-making.',
    'When discussing weight, diet, and activity levels, use non-judgemental, patient-centred language; patients are more likely to engage with lifestyle advice when they feel supported rather than criticised.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  172,
  'Fibroids on Ultrasound Scan',
  'Gynaecology & Women''s Health',
  'Telephone Consultation',
  false,
  'Donna Okafor',
  '36-year-old female',
  ARRAY[]::text[],
  ARRAY[]::text[],
  'Seen 2 weeks ago by Dr Lucy Aldershot (Clinical Practitioner role). Presenting complaint: The patient reported experiencing heavy menstrual bleeding since stopping Microgynon 9 months ago, which she discontinued to begin trying for pregnancy. Recent blood tests revealed microcytic anaemia, with a haemoglobin level of 109 g/L. LMP: 2 weeks ago, not currently bleeding. Examination: No pelvic tenderness or masses felt. Speculum examination was unremarkable with no abnormalities noted. Blood pressure: 121/65 mmHg. Pulse: 70 bpm. Plan: Ultrasound scan requested. Initiated treatment with ferrous sulfate. Provided safety netting and advice on when to seek further medical attention if symptoms worsen. Pelvic Ultrasound Scan Report: A combined transabdominal and transvaginal pelvic ultrasound scan was performed. A chaperone was present throughout the examination. The uterus is enlarged with a heterogeneous echotexture. Multiple fibroids are identified, consistent with intramural and subserosal locations. The largest fibroid is seen posteriorly and measures 4.2 cm in diameter. The endometrial thickness appears within normal limits for the reported phase of the menstrual cycle. Both ovaries are visualised and are normal in size and morphology. No adnexal masses or free fluid are observed. Conclusion: Ultrasound findings are consistent with multiple uterine fibroids, the largest measuring 4.2 cm. Clinical correlation is advised. Reported by: Chinyere Okonkwo, Advanced Reporting Ultrasonographer. Patient booked a telephone consultation to discuss her scan results.',
  'The patient booked a telephone consultation to discuss the results of her recent pelvic ultrasound scan.',
  'Hi Doctor, I''m calling to go through my scan results. I had it done after seeing your colleague a couple of weeks ago.',
  '',
  ARRAY[]::text[],
  'You do not smoke or drink alcohol. You work full-time as a solicitor and live with your husband.',
  'You are not sure what the underlying cause of the heavy bleeding is.',
  'You want the heavy bleeding to stop and are worried it might affect your ability to get pregnant.',
  'You would like the doctor to explain the scan results, clarify what is causing the heavy bleeding, and recommend treatment. You also stopped taking the iron tablets (ferrous sulfate) recently because they were causing constipation, and you would like advice on what to do next.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor.',
  ARRAY[
    'Acknowledge the previous consultation and reason for the scan: "I can see you were seen by my colleague recently because of heavy menstrual bleeding and were sent for an ultrasound scan — is that right? How have things been since then?"',
    'Ask about the duration and pattern of heavy menstrual bleeding and whether it has changed recently.',
    'Ask if the bleeding is associated with pain.',
    'Ask about her last menstrual period and whether her cycles are regular.',
    'Ask about any intermenstrual bleeding (bleeding between periods).',
    'Ask about pressure symptoms of fibroids such as urinary urgency, urinary frequency, bloating, constipation, or painful defecation.',
    'Ask if the patient is sexually active.',
    'Ask about the number of sexual partners if clinically relevant.',
    'Ask about any bleeding during or after sex (postcoital bleeding).',
    'Ask about pain during sex (dyspareunia).',
    'Ask if she has had any difficulty conceiving and how long she and her partner have been trying for pregnancy.',
    'Ask about family history of fibroids.',
    'Ask if the patient is currently using any form of contraception.',
    'Screen for symptoms of anaemia using the "3 head and 3 chest" approach: light-headedness, dizziness, headache; palpitations, shortness of breath, chest pain.',
    'Ask about how the heavy bleeding is affecting her daily life, including impact on work, mood, relationships, and quality of life.',
    'Ask whether she has tried any previous treatments or medications to manage the heavy bleeding.',
    'Ask about iron tablet side effects and current use.',
    'Ask about smoking, alcohol use, occupation, and home support.',
    'Explain the scan results showing multiple uterine fibroids, the largest measuring 4.2 cm.'
  ],
  ARRAY[
    'Offer a referral to Gynaecology due to the presence of fibroids larger than 3 cm and the patient''s concerns regarding fertility.',
    'Offer a trial of tranexamic acid to help manage menorrhagia.',
    'Inform the patient about potential side effects of tranexamic acid, such as an increased risk of blood clots in the legs or lungs. Reassure her that this is uncommon and does not affect everyone.',
    'Encourage the patient to restart her iron tablets (ferrous sulfate), but to take them on alternate days, ideally with orange juice or with or after food to reduce gastrointestinal side effects. Alternatively, if she prefers, a laxative can be prescribed to help manage the constipation.',
    'Provide safety netting advice: advise the patient to seek urgent medical attention if she develops dizziness, light-headedness, palpitations, or chest pain, as these may be signs of worsening anaemia.'
  ],
  'Thank you for calling in today, Donna. I''ve had a chance to review your scan results and I''m glad we can go through them together, because I want to make sure you have a clear understanding of what''s been found and what we plan to do about it.

Your ultrasound has shown that you have something called fibroids. Have you come across that term before? Fibroids are non-cancerous growths that develop in or around the wall of the womb. They are actually very common and are a well-recognised cause of heavy periods. The scan found several fibroids, and the largest one measures 4.2 centimetres in diameter. That''s roughly the size of a small plum. I want to reassure you straight away that fibroids are not cancer, and the vast majority of women with fibroids go on to lead completely normal lives.

Because of the size of the fibroids and the fact that you and your husband are actively trying for a baby, I think the most appropriate next step is to refer you to a gynaecologist — a specialist in women''s reproductive health. They will be able to discuss the options available to you in much more detail, including treatments that could help shrink or remove the fibroids, while also taking your fertility goals into account. Some of those options might include medication to help reduce fibroid size, or in some cases a minor procedure to remove them. The specialist is best placed to advise you on what is right for your particular situation.

In the meantime, I would like to prescribe you a medication called tranexamic acid to help reduce the amount of bleeding during your periods. It works by helping the blood clot more effectively at the lining of the womb. Like any medication, it does carry some potential side effects — in particular, there is a small and uncommon risk of blood clots forming in the legs or lungs. I want to make you aware of that, but please be reassured that it is not common. If you ever notice calf pain, chest pain, or difficulty breathing, please seek help promptly.

Regarding your iron tablets — I completely understand why you stopped them if they were causing constipation. The good news is there are ways to make them much more tolerable. Taking ferrous sulfate on alternate days rather than every day tends to reduce the stomach side effects significantly, and taking them with a glass of orange juice or alongside food can also help. If you still find them difficult to manage, I can add a laxative to make things more comfortable. Keeping your iron levels up is really important given how much bleeding you have been having.

Finally, on the safety side: if at any point you feel dizzy, light-headed, notice your heart racing, or experience any chest discomfort, please contact us straight away or call 111. These could be signs that your anaemia is getting worse and would need to be assessed promptly.',
  ARRAY[
    'Uterine fibroids are the most common cause of heavy menstrual bleeding in women of reproductive age and can contribute to iron deficiency anaemia; they are benign but can significantly impact quality of life and fertility.',
    'Refer to gynaecology if fibroids are larger than 3 cm, if the patient has fertility concerns, if there are pressure symptoms, or if there are features suspicious for malignancy.',
    'Tranexamic acid is an effective treatment option for menorrhagia; counsel patients about the uncommon but important risk of venous thromboembolism.',
    'Ferrous sulfate (iron replacement) tolerability can be improved by taking it on alternate days, with orange juice or with food; a laxative can be co-prescribed if constipation is problematic.',
    'Screen for symptoms of worsening anaemia using the "3 head and 3 chest" approach: light-headedness, dizziness, headache; palpitations, shortness of breath, chest pain — and safety-net accordingly.',
    'Always acknowledge a patient''s fertility concerns when managing fibroids, as this will guide the choice of treatment options discussed with the gynaecology team.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  173,
  'Paget''s Disease',
  'Rheumatology & Musculoskeletal',
  'Video Consultation',
  false,
  'George Hartfield',
  '70-year-old male',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No known drug allergy'],
  'Seen 2 days ago by Dr Charles Lewis (Clinical Practitioner Role). Presenting complaint: Patient reported worsening pain in the left knee, ongoing for 4 weeks. Described the pain as waking him up at night and worse on movement. No red flag symptoms reported. He is currently managing the pain with over-the-counter ibuprofen, which he reports is helping. Examination findings: No swelling, tenderness, or visible deformity noted in left knee. No lumps or bumps palpated. Other joints are unremarkable. Temperature: 36.0°C. Blood pressure: 130/88 mmHg. Impression: Likely worsening osteoarthritis; however, in view of night pain, needs an X-ray to rule out possible underlying pathology, including tumour. Plan: X-ray of the left knee requested. Continue analgesia. Safety netting and worsening advice given. Imaging Report — Left Knee X-ray. George Hartfield | 70 years old | Male. Clinical History: Left knee pain for 4 weeks. Worsening with movement. Night pain. Query tumour or underlying pathology. Findings: There is coarsening of trabecular bone, cortical thickening, and bone expansion involving the distal femur and proximal tibia, with preservation of joint space. No evidence of fracture or lytic lesion is seen. Soft tissues appear unremarkable. These radiographic findings are in keeping with Paget''s disease of bone, involving the distal femur and proximal tibia. No aggressive features to suggest malignancy. Conclusion: Radiographic features are consistent with Paget''s disease of bone. Reported by: Chinedu Okonkwo, BSc (Hons), PgCert (Med Imaging), HCPC Registered Reporting Radiographer. Patient booked a follow-up appointment to discuss X-ray results.',
  'The patient booked a follow-up video consultation to discuss his recent knee X-ray results.',
  '"Doctor, I''m calling to find out what my X-ray showed."',
  'You were seen two days ago by a doctor after experiencing pain in your left knee for the past four weeks. The pain sometimes wakes you up at night and can also be triggered by movement during the day. You first tried paracetamol but it did not help, so you switched to ibuprofen, which has given you some relief. You have never had this kind of pain before.',
  ARRAY[]::text[],
  'You are a non-smoker and do not drink alcohol. You live with your wife, who uses a wheelchair following a serious hip fracture. You are her main carer, helping her with most of her daily needs.',
  'You suspect that the knee pain might be due to osteoarthritis.',
  'You are worried about how this condition will affect your ability to look after your wife. You want to get better so you can continue caring for her properly.',
  'You would like the doctor to explain what the X-ray has shown and tell you what is going on.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor.',
  ARRAY[
    'Begin by acknowledging the previous consultation and the reason for imaging: "I can see you were seen by my colleague recently because of knee pain and were sent for an X-ray. Am I right? Could you tell me in your own words how the pain has been — has it been getting better, worse, or staying the same?"',
    'Ask about any swelling, stiffness, or noticeable lumps or bumps over the affected knee.',
    'Ask specifically about night pain and whether the symptoms wake him from sleep.',
    'Ask about current mobility — whether the patient is able to walk, bear weight, and whether pain limits his daily movement.',
    'Ask whether any other joints or bones are affected or painful.',
    'Ask about systemic symptoms such as fever, night sweats, unexplained weight loss, or loss of appetite, to rule out underlying malignancy (e.g. osteosarcoma as a rare complication of Paget''s disease).',
    'Ask about hearing changes, such as hearing loss or tinnitus, which may indicate skull involvement in Paget''s disease.',
    'Ask about family history of any bone conditions.',
    'Ask about social history, including occupation and living arrangements, and how the knee pain has impacted daily activities or caregiving responsibilities at home.',
    'Acknowledge the patient''s role as a sole carer for his wife and explore how his knee pain is affecting his ability to provide care.',
    'Explain that the X-ray findings are suggestive of Paget''s disease of bone.'
  ],
  ARRAY[
    'Offer blood tests including serum total alkaline phosphatase (ALP), liver function tests, calcium, vitamin D, and parathyroid hormone (PTH) to assess metabolic bone activity and rule out other causes.',
    'Offer a referral to rheumatology for further evaluation, diagnosis confirmation, and consideration of treatment.',
    'Advise the patient that the specialist may recommend bisphosphonate therapy, which is commonly used to reduce bone turnover and help manage symptoms.',
    'As ibuprofen is providing some relief, advise the patient that he can continue using it, but offer a proton pump inhibitor (PPI) to protect the gastrointestinal tract, particularly given his age.',
    'Offer a referral to a social prescriber to discuss community support services and any potential eligibility for carer benefits or practical assistance with care for his wife.',
    'Provide clear safety netting and advise the patient about the risk of fractures and the rare but serious risk of osteosarcoma associated with Paget''s disease.',
    'Instruct the patient to seek urgent medical review if he develops sudden or worsening bone pain, becomes unable to walk or use a limb, or notices any new lumps, swelling, or systemic symptoms such as weight loss or fever.',
    'Advise the patient to report any hearing loss or tinnitus, as these may indicate involvement of the skull in Paget''s disease.'
  ],
  'Thank you for joining me today, George. I''ve had a good look at your X-ray results, and I want to take you through what has been found in a way that makes sense. I can reassure you straight away that the X-ray does not show osteoarthritis — I know that''s what you were thinking it might be — and there are no features that suggest anything sinister such as cancer. That is genuinely good news.

What the X-ray does show are some changes in the bone around your knee — specifically at the lower end of the thigh bone and the upper end of the shin bone. These changes are consistent with a condition called Paget''s disease of bone. Is that something you have heard of before? Paget''s disease affects the normal cycle by which our bodies constantly break down and rebuild bone. In this condition, that process becomes disrupted, and bone can be rebuilt in a way that is denser but less well-structured than normal. This is what is causing the pain you have been experiencing. We know that the condition tends to run in families, though it is not clear exactly what causes it.

I can see that one of your biggest concerns is how this is going to affect your ability to care for your wife at home — and that is completely understandable. You are clearly doing a remarkable job, and I want to make sure you have the support you need too. While we are getting things under control with your knee, I would like to refer you to our social prescriber, who can explore what additional help might be available for both of you at home — whether that is temporary carers, equipment, or any financial support you may be entitled to. Would that be helpful?

In terms of next steps for your knee, I would like to arrange some blood tests. These will check a marker called alkaline phosphatase, which reflects how active the bone changes are, as well as your calcium, vitamin D, and parathyroid hormone levels. I am also going to refer you to a rheumatologist — a specialist in bone and joint conditions — who will be able to give you more detailed advice and discuss treatment options. The most widely used treatment for Paget''s disease is a group of medications called bisphosphonates, which work by slowing down the overactive bone turnover and can significantly reduce pain.

In the meantime, please carry on with the ibuprofen as it is giving you some relief. I would like to add a tablet called a proton pump inhibitor — a stomach-protecting tablet — to take alongside it, as ibuprofen can sometimes irritate the stomach lining, especially with regular use.

On the safety side: if you develop any sudden worsening of pain, notice any new lumps or swelling, feel unwell with a fever or unexplained weight loss, or find you are unable to put weight through your leg, please seek urgent medical review straight away. These could indicate a complication and would need prompt attention. I would also ask you to let us know if you notice any changes in your hearing or develop ringing in your ears, as Paget''s disease can occasionally affect the skull and impact hearing.',
  ARRAY[
    'Paget''s disease of bone is the second most common metabolic bone condition after osteoporosis; it typically presents in patients over 50 and may be found incidentally on X-ray or through a raised alkaline phosphatase (ALP).',
    'Radiological features of Paget''s disease include coarsening of trabecular bone, cortical thickening, and bone expansion; joint space is typically preserved, which helps distinguish it from osteoarthritis.',
    'Initial blood tests should include serum ALP, liver function tests, calcium, vitamin D, and PTH to assess metabolic bone activity and exclude other causes of bone pathology.',
    'Bisphosphonate therapy is the first-line treatment to reduce bone turnover in symptomatic Paget''s disease; refer to rheumatology for specialist assessment and treatment planning.',
    'Osteosarcoma is a rare but serious complication of Paget''s disease; safety-net patients to report sudden worsening bone pain, new lumps or swelling, inability to weight-bear, or systemic symptoms such as fever and weight loss.',
    'Skull involvement in Paget''s disease can cause hearing loss or tinnitus; always ask about these symptoms and advise patients to report any new changes.',
    'NSAIDs used for analgesia in older patients should be co-prescribed with a proton pump inhibitor (PPI) to reduce the risk of gastrointestinal side effects.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  174,
  'Snoring in Young Adult',
  'ENT & Eye',
  'Video Consultation',
  false,
  'Gary Pendleton',
  '39-year-old male',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No known drug allergy'],
  'Patient booked a routine video consultation to discuss concerns.',
  'The patient booked a routine video consultation because he has been feeling extremely tired and is having ongoing problems with his sleep.',
  '"Doctor, I''ve not been sleeping well at all and I feel exhausted pretty much every day."',
  '',
  ARRAY[
    'These problems have been going on for around 7 months and are starting to have a real impact on day-to-day life. There are occasional early morning headaches, though these normally ease off as the day goes on. Daytime napping has become common because night-time sleep is so poor.'],
  'You drink quite a lot of alcohol — around 2 cans of beer a day, which adds up to roughly 30 units per week. You do not smoke. You feel your weight is on the higher side and your diet is not great. You tend to eat a lot of takeaways or fast food, mainly because your job leaves little time to cook. You live with your partner. You work as a delivery lorry driver.',
  'You are not sure what is causing the problem.',
  'You are worried about your job performance because you have occasionally dozed off during the day, including at times when you were supposed to be working.',
  'You would like the doctor to work out what is going on and suggest something to help.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor.',
  ARRAY[
    'Ask the patient to clarify what he means by "not sleeping well" and "feeling exhausted every day".',
    'Ask when the symptoms started and whether they have got worse over time.',
    'Ask about snoring and whether his partner has described it as loud or disruptive.',
    'Ask about possible episodes of apnoea — such as choking or gasping during sleep, or whether his partner has noticed any pauses in his breathing during the night.',
    'Ask about restless sleep or waking frequently during the night.',
    'Ask if he experiences early morning headaches.',
    'Ask whether he wakes up feeling unrefreshed despite what seems like a full night''s sleep.',
    'Ask about daytime sleepiness or fatigue throughout the day.',
    'Ask if he has noticed any lumps or swelling in the neck area.',
    'Ask how these symptoms are affecting his daily life, mood, and overall functioning.',
    'Ask about his job and whether symptoms are affecting his performance, particularly given that he operates a large vehicle.',
    'Ask directly whether his daytime sleepiness affects his ability to drive safely.',
    'Ask about any recent weight changes, particularly weight gain.',
    'Ask about social lifestyle including smoking and alcohol intake; explore how much he drinks, how often, whether he has ever tried to cut down, and what happened when he did, in order to assess for possible alcohol dependence and whether he may need support to stop.',
    'Make a working diagnosis of obstructive sleep apnoea.'
  ],
  ARRAY[
    'Offer a face-to-face assessment to examine the neck, mouth (including the back of the throat), and nostrils, and to check blood pressure.',
    'Inform the patient that you will send him a questionnaire called the Epworth Sleepiness Score to help assess the severity of his symptoms; advise that this can also be completed during the face-to-face appointment if he prefers.',
    'Offer to refer him to the sleep clinic for further assessment. Explain that, as he is a Group 2 driver and his livelihood depends on this, you will request that he is seen within four weeks to avoid any unnecessary delay in diagnosis and treatment.',
    'Inform the patient that at the sleep clinic he will undergo a sleep study, which is usually carried out at home but can sometimes be done in hospital.',
    'Inform the patient that he will be given a lightweight device to take home and wear overnight, with sensors attached to monitor his breathing, oxygen levels, heart rate, sleep position, and movement.',
    'Advise the patient that if sleep apnoea is confirmed, he will be offered a CPAP device — a machine that gently pumps air through a mask into the nose and mouth to keep the airway open during sleep.',
    'Advise the patient to stop driving immediately due to the possibility of sleep apnoea and excessive daytime sleepiness.',
    'Issue a fit note to cover time off work and offer a referral to a social prescriber or welfare advisor to explore possible financial support or benefits while he is not working.',
    'Provide lifestyle advice including reducing alcohol intake, improving diet, and engaging in regular physical activity.',
    'Advise the patient to avoid sleeping on his back and instead try sleeping on his side to reduce snoring and breathing interruptions.',
    'Offer a follow-up appointment after he has been seen at the sleep clinic to discuss what has been recommended, review progress with lifestyle changes, and provide any further support needed.'
  ],
  'Thanks for getting in touch today, Gary. From everything you have described — the poor sleep, the loud snoring, the exhaustion during the day, and the fact that you have been nodding off — I am quite concerned that you may have a condition called obstructive sleep apnoea. Have you come across that term before?

Obstructive sleep apnoea is a condition where the soft tissues at the back of the throat relax and partially block the airway during sleep. This causes the breathing to become disrupted — sometimes pausing completely for a few seconds before starting again with a gasp or a snore. Because the brain picks up on these interruptions, even if you are not fully aware of them, your sleep quality is very poor, which explains the exhaustion, the morning headaches, and the need to nap during the day.

I want to be straightforward with you about something, Gary. Given that your job involves driving a large lorry, the daytime sleepiness you are describing is a serious safety concern — not just for you, but for other people on the road too. I know that is not easy to hear, and I am not saying this to alarm you, but I do need to advise you to stop driving for the time being, until we have had you properly assessed and you have been given the all-clear to drive again. I will write a fit note to cover your time off work, and I would also like to refer you to a social prescriber who can help you explore any financial support or benefits that might be available to you while you are not working.

I am going to refer you to the sleep clinic for a proper assessment. Because you are a professional driver — what we call a Group 2 licence holder — I will specifically request that you are seen within four weeks to avoid any unnecessary delay. At the clinic, they will likely arrange a sleep study, which is usually done at home. You will be given a small device to wear overnight that monitors your breathing, oxygen levels, heart rate, and movement. If sleep apnoea is confirmed, the standard treatment is a CPAP machine. This is a device that sits on your bedside table and gently delivers air through a mask while you sleep, keeping the airway open and allowing you to breathe normally throughout the night. Most people notice a dramatic improvement in energy levels and daytime alertness once they start using it regularly.

In the meantime, there are some lifestyle changes that can genuinely make a difference. You mentioned drinking around two cans of beer a day — that adds up to about 30 units a week, which is above the recommended limit. Alcohol relaxes the muscles in the airway, which can make sleep apnoea significantly worse. Gradually cutting back would likely improve your symptoms. Similarly, even modest improvements in diet and a bit of regular physical activity can help. Trying to sleep on your side rather than on your back can also reduce snoring and breathing interruptions.

I will also send you a short questionnaire called the Epworth Sleepiness Score, which helps us measure how severely the sleepiness is affecting you. You can fill it in at home or when you come in to see me face-to-face. I would like to arrange a follow-up appointment after your sleep clinic review so we can go through the results together, check in on how the lifestyle changes are going, and make sure you have all the support you need going forward.',
  ARRAY[
    'Obstructive sleep apnoea (OSA) should be suspected in patients presenting with loud snoring, excessive daytime sleepiness, witnessed apnoeic episodes, and unrefreshing sleep, particularly in those who are overweight or have high alcohol intake.',
    'Any patient with suspected OSA and excessive daytime sleepiness that is likely to impair driving must be advised to stop driving immediately; Group 2 drivers (e.g. HGV, lorry, bus) carry a higher level of responsibility and should be referred to the sleep clinic urgently, within four weeks.',
    'The Epworth Sleepiness Score is a validated questionnaire used to assess the severity of daytime sleepiness and can be completed at home or in clinic.',
    'Sleep studies (polysomnography or home oximetry) are used to confirm OSA; they are usually performed at home but can be hospital-based, and monitor breathing, oxygen levels, heart rate, sleep position, and movement.',
    'CPAP (continuous positive airway pressure) is the first-line treatment for confirmed OSA; it keeps the airway open during sleep and typically leads to significant improvement in daytime alertness and quality of life.',
    'Alcohol relaxes upper airway muscles and worsens OSA; assess alcohol intake carefully and encourage reduction as part of lifestyle management, alongside weight loss, improved diet, and side sleeping.',
    'Issue a fit note to cover time off work and refer to a social prescriber or welfare advisor to explore financial support options for patients unable to work while awaiting OSA assessment and treatment.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  175,
  'Gout Flare Requesting Medication',
  'Rheumatology & Musculoskeletal',
  'Telephone Consultation',
  false,
  'Gary Thornton',
  '64-year-old male',
  ARRAY['Hypertension'],
  ARRAY['Amlodipine 10mg OD','No Known Drug Allergy'],
  'Letter from Bristol Urgent Care Service (3 days ago)
To: General Practitioner
Re: Mr. Gary Thornton | 64 years old | Male

Dear Colleague,

Mr. Gary Thornton presented to the Urgent Care Centre with a rapid-onset swelling and severe pain affecting the right first metatarsophalangeal (MTP) joint, which developed overnight. Clinical examination revealed redness, swelling, and tenderness consistent with an acute gout flare. He was systemically well with no fever or constitutional symptoms, and there were no features to suggest septic arthritis at the time of review. A blood test showed an elevated serum uric acid level of 350 µmol/L. A diagnosis of acute gout was made. He was commenced on colchicine 500 micrograms four times daily for 3 days. He was safety-netted appropriately, including advice regarding signs of septic arthritis and when to seek urgent medical attention. Mr. Thornton was advised to follow up with his GP once the acute flare has resolved to discuss the possibility of initiating urate-lowering therapy to reduce the risk of future attacks.

Kind regards,
Dr Kelechi Onwudiwe, MBBS, MRCGP, MRCEM
Urgent Care Physician

Patient booked an urgent telephone appointment to discuss concerns.',
  'Patient calling to request further colchicine following an acute gout flare treated at urgent care.',
  '"Hi doctor, I''d like to request a prescription for the medication I was given at the out-of-hours service — colchicine. Could you arrange that for me please?"',
  'You are calling because your right big toe is still painful even after finishing the 3-day course of colchicine from urgent care. The swelling has reduced slightly and you can now put some weight through it, but it still hurts when walking. You have no fever and feel well in yourself overall. You had diarrhoea over the last couple of days, which you later found out is a recognised side effect of colchicine — this has now settled. You have never had a gout attack before. You are wondering whether you need more colchicine and would also like to know what can be done to stop future attacks.',
  ARRAY[]::text[],
  'You do not smoke or use recreational drugs. You drink alcohol occasionally, usually a pint or two of beer at weekends, though not every week. You regularly eat red meat. You live with your wife and work as a delivery driver. You have been off sick for the past 3 days because of the pain but are keen to get back to work soon as you enjoy it.',
  'You suspect the gout flare has not fully settled and may need more treatment.',
  'You have been off work for 3 days and are anxious to return as soon as possible.',
  'You are hoping for more colchicine or a stronger painkiller to fully clear the current discomfort, and you would also like to know about something that could prevent future flares.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions outside of the details already provided.',
  ARRAY[
    'Ask about current symptoms including level of pain, ongoing swelling or redness, and whether mobility is gradually improving',
    'Confirm whether this is the patient''s first episode of gout',
    'Ask about systemic symptoms such as fever, chills, or feeling generally unwell to exclude septic arthritis',
    'Ask about the impact on daily functioning, including whether the patient can bear weight or walk',
    'Ask about side effects from colchicine including diarrhoea, abdominal pain, nausea, or vomiting',
    'Ask about lifestyle factors including diet (particularly how often the patient consumes red meat), alcohol intake, and whether he smokes',
    'Ask about any family history of gout or similar joint conditions',
    'Ask about the patient''s occupation and how symptoms have affected his ability to work',
    'Ask about any previous joint problems or similar episodes in the past',
    'Explore the patient''s ideas, concerns, and expectations',
    'Provide a working diagnosis of a resolving acute gout flare'
  ],
  ARRAY[
    'Do not offer a repeat course of colchicine. It should not be taken for more than 3 days due to the risk of toxicity. According to the BNF, the recommended dose is 500 micrograms two to four times daily until symptoms improve, with a maximum total dose of 6 mg per course. The course should not be repeated within three days. This is because colchicine has a narrow therapeutic window, meaning the difference between an effective dose and a toxic dose is small, so small differences can lead to toxicity or adverse drug reactions',
    'If there are no contraindications, offer an NSAID such as naproxen or ibuprofen for ongoing pain. Alternatively, consider short-course oral prednisolone (30 mg once daily for 3 to 5 days), which is an off-label option',
    'Prescribe a proton pump inhibitor (PPI) for gastric protection if an NSAID is used, especially in patients over the age of 55',
    'Reassure the patient that a face-to-face review is not required at this time, as symptoms are already improving and he was assessed recently',
    'Provide simple self-care advice including resting and elevating the affected foot, keeping the joint uncovered in a cool environment, and applying an ice pack to reduce pain and swelling',
    'Advise that the patient can self-certify for up to 7 days. If symptoms persist beyond this period, offer a fit note to support further time off work',
    'Discuss lifestyle modifications including reducing alcohol intake, limiting consumption of red meat and seafood, and maintaining good hydration to reduce uric acid levels',
    'Explain that once this flare settles, there is an option to start a preventative medication called allopurinol to reduce the risk of future gout attacks. This can be discussed at a follow-up if the patient is interested',
    'Safety-net by advising the patient to seek urgent medical attention if the joint becomes hot, red, and swollen again, or if systemic symptoms such as fever or feeling unwell develop',
    'Arrange a follow-up in 2 to 3 weeks to review blood tests and discuss long-term management options, including preventative treatment'
  ],
  'Thank you for calling today, Gary. It sounds from what you''ve described as though your gout flare is beginning to settle, which is reassuring, even though I understand you''re still experiencing some discomfort. Before we go ahead, may I ask what you already know about gout?

Gout is a condition that tends to come and go in episodes. It happens when a chemical in the blood called uric acid builds up and forms tiny crystals inside the joints. These crystals trigger inflammation, which causes the intense swelling and pain you''ve been experiencing in your big toe.

I can see from the urgent care letter that you completed the full course of colchicine at the maximum recommended dose. The reason I''m not able to prescribe another course is that colchicine has what we call a narrow therapeutic window — this means the gap between a safe and effective dose and a harmful one is very small. Repeating the course too soon significantly increases the risk of side effects, including the diarrhoea you experienced. It also shouldn''t be repeated within three days of completing a course.

Since you''re still in some pain, I can prescribe an anti-inflammatory medication called naproxen to help ease the remaining discomfort. I would also prescribe something to protect your stomach alongside it — particularly because you''re in the age group where we take that extra precaution. Before I prescribe, I just want to check: do you have any history of stomach problems such as ulcers or indigestion? Good. That sounds straightforward.

In the meantime, a few simple measures can also help. Resting the foot, keeping it elevated, and placing a cool ice pack on the joint can all reduce the swelling and ease discomfort. It also helps to keep the toe uncovered if it''s very sore to touch.

Looking ahead, it''s worth thinking about reducing the chances of this happening again. The things most likely to raise uric acid levels include regular red meat and seafood, alcohol — particularly beer — and not drinking enough water. Making some gradual adjustments there can make a real difference.

Once this flare has completely settled, we can also talk about a preventative medication called allopurinol. This works by lowering the amount of uric acid your body produces and is very effective at reducing the frequency of future attacks. We wouldn''t start it during an active flare, but it''s definitely something worth considering at a follow-up.

Regarding work, you can self-certify for up to seven days in total. If you''re still not able to return after that, please let us know and we can arrange a fit note for you. Do watch out for any signs that things are getting worse — if the joint becomes very hot, red, and swollen again, or if you develop a fever or start feeling generally unwell, please seek urgent attention as we would want to rule out an infection in the joint.',
  ARRAY[
    'Colchicine should not be repeated within three days of completing a full course; the maximum total dose per course is 6 mg, and its narrow therapeutic index makes exceeding recommended doses dangerous',
    'When colchicine is contraindicated or a course has been completed, an NSAID (e.g. naproxen) or short-course prednisolone 30 mg once daily for 3–5 days are appropriate alternatives for ongoing gout pain',
    'Always co-prescribe a proton pump inhibitor when prescribing an NSAID, especially in patients aged over 55',
    'Key lifestyle advice in gout includes reducing alcohol (particularly beer), limiting red meat and seafood intake, and maintaining good hydration to lower uric acid levels',
    'Allopurinol is the first-line urate-lowering therapy for preventing recurrent gout but should only be initiated once the acute flare has fully resolved',
    'Patients should be safety-netted to seek urgent review if symptoms worsen or systemic features such as fever develop, as septic arthritis must always be excluded'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  176,
  'Unexplained Hyperglycaemia in Adult',
  'Endocrine & Nephrology',
  'Telephone Consultation',
  false,
  'Tariq Hassan',
  '42-year-old male',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No Known Drug Allergy'],
  'Letter from Accident & Emergency – Dated Yesterday

Dear GP,
Re: Mr Tariq Hassan | 42 years old | Male

Mr Hassan presented to our Emergency Department last night complaining of feeling unusually tired, passing urine more frequently than normal, and increased thirst over the past several days. A urine dipstick test was performed and showed glucose 2+, with no nitrates, no leucocytes, and no ketones. Unfortunately, Mr Hassan left the department before he could be fully assessed or reviewed by the clinical team. We have been unable to make contact with him since, and we hope he is well. Given the concerning nature of his presenting symptoms and the glycosuria on urinalysis, we recommend that he be followed up promptly in primary care to rule out underlying pathology such as new-onset diabetes mellitus.

Thank you for your continued support in ensuring patient safety.

Yours sincerely,
Dr Youssef El-Gohary MB ChB, MRCEM
Emergency Medicine Registrar

Patient booked urgent telephone appointment to discuss some concerns.',
  'Patient calling following an A&E attendance yesterday where he left before being seen; A&E letter reports glycosuria and symptoms consistent with possible diabetes.',
  '"Doctor, I''ve been feeling really tired lately and I keep needing to go to the toilet and drink loads of water. I went to A&E last night but the wait was about eight hours so I left after the nurse did a urine test. I just want to feel better."',
  'You have booked this telephone consultation because over the past 2 to 3 weeks you have been needing to urinate more often than usual, drinking much more water, and feeling exhausted all the time. You went to A&E last night out of concern, but after the nurse collected your urine sample you were told the wait would be around eight hours, so you left before seeing a doctor. When you got home, your wife — who has diabetes herself — said your symptoms sounded familiar. She used her glucose meter to check your blood sugar and the result was 11.9 mmol/L. She told you that reading might mean you have diabetes. Your symptoms have been getting worse and you now feel weak.',
  ARRAY['You have noticed you have lost approximately 4 kg over the past three weeks without changing your diet or exercise habits'],
  'You do not smoke or drink alcohol. You live with your wife and children and run a small convenience store, which keeps you busy most days. Your diet is not particularly healthy — you tend to eat a lot of carbohydrates such as rice, roti, curry, and similar dishes.',
  'You think this might be diabetes.',
  'You just want to get well so you can keep the shop running and continue to look after your family. Your wife helps with the store but cannot manage it alone.',
  'You would like the GP to prescribe something to make you feel better.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor.',
  ARRAY[
    'Ask about the onset and duration of increased urination and thirst',
    'Ask about associated urinary symptoms to rule out a UTI, including pain when passing urine, blood in the urine, lower abdominal or suprapubic pain, and fever',
    'Ask about any weight changes, including unintentional weight loss, and quantify how much weight has been lost and over what period',
    'Ask about symptoms suggestive of diabetic complications, including blurred vision, tingling or numbness in the hands or feet, and any history of slow-healing wounds or frequent infections',
    'Ask whether he has experienced any symptoms that could indicate diabetic ketoacidosis (DKA), such as abdominal pain, nausea or vomiting, diarrhoea, deep or rapid breathing, or a fruity smell on his breath',
    'Ask about family history of diabetes, including age at diagnosis and type if known',
    'Ask about social and lifestyle factors, including diet, physical activity, smoking, alcohol intake, and occupation',
    'Ask how his symptoms have affected his daily life, including mood, energy levels, sleep, and ability to manage work and family responsibilities',
    'Explore his ideas, concerns, and expectations',
    'Give a diagnosis of suspected Type 1 diabetes'
  ],
  ARRAY[
    'Offer to arrange immediate same-day hospital admission via the Acute Medical Unit (AMU) for suspected type 1 diabetes',
    'Instruct the patient not to drive and advise that he should ask his wife or someone else to take him safely to hospital',
    'Advise the patient that if diabetes is confirmed, he will be started on intravenous fluids and insulin in hospital to bring his blood sugar levels under control and prevent complications',
    'Explain that if his symptoms worsen on the way to hospital — such as vomiting, severe tiredness, confusion, or breathing difficulty — he or the person with him should call 999 immediately',
    'Advise the patient that once he is discharged from hospital, he should book a follow-up appointment to discuss what happened during his admission and to receive further support, including lifestyle changes, diet, and long-term management of his blood sugar'
  ],
  'Thank you for explaining all of that so clearly, Tariq. I can completely understand why you and your wife have been worried, and I think her instinct was right to be concerned. Based on everything you''ve described — the exhaustion, drinking more than usual, going to the toilet so frequently, the weight loss, and the blood sugar reading of 11.9 mmol/L on her meter — this is a picture that needs urgent attention today.

Before I explain what I think is happening, can I just check what you already know about diabetes? Diabetes is a condition where the level of sugar in the blood becomes too high because the body isn''t producing enough of a hormone called insulin, which normally controls blood sugar. There are different types of diabetes. Based on your symptoms coming on quite quickly, your weight loss, and how unwell you''re feeling, I''m concerned this could be type 1 diabetes — the kind where the body has stopped making insulin almost completely. When that happens, sugar builds up in the blood and the body starts to struggle, which is why you''ve been feeling so weak and exhausted.

I know you want to get back to the shop and keep things running, and I completely respect that. However, the fact that your symptoms are worsening is a sign that your body is under real strain right now, and it wouldn''t be safe to wait. The most important thing for you today is to go to hospital — specifically to the Acute Medical Unit — so that the team there can do the tests to confirm the diagnosis and, if needed, start treatment straight away.

Treatment will likely involve fluids through a drip and insulin injections, which will bring your blood sugar down safely, help you feel significantly better, and stop things from deteriorating further. The sooner we act, the better.

Please do not drive yourself to hospital. It would be safest if your wife or another person you trust takes you. If at any point on the way you start to feel much worse — very dizzy, sick to your stomach, confused, or if your breathing feels laboured or unusual — please ask whoever is with you to call 999 immediately rather than continuing to drive.

Once you''ve been discharged and are back home and recovering, I would like you to book a follow-up appointment with me. We can go through everything that happened in hospital together, talk about what the diagnosis means for day-to-day life, and I can support you with diet, lifestyle, and longer-term blood sugar management. We''re here to support you through this.',
  ARRAY[
    'Type 1 diabetes can present at any age with a rapid onset of polyuria, polydipsia, fatigue, and significant unintentional weight loss; a random plasma glucose above 11 mmol/L with symptoms warrants same-day hospital admission',
    'Suspected new type 1 diabetes in an adult requires urgent same-day referral to the Acute Medical Unit due to the risk of rapid progression to diabetic ketoacidosis (DKA), a life-threatening emergency',
    'Key features that raise the suspicion of type 1 rather than type 2 diabetes include rapid symptom onset, significant weight loss, and a younger or middle-aged patient with no prior metabolic history',
    'Patients should be advised not to drive themselves to hospital when symptomatic hyperglycaemia is suspected, and should be warned to call 999 if they develop vomiting, confusion, or breathing difficulty en route',
    'A post-discharge follow-up is essential to provide education, lifestyle support, and ongoing coordination of diabetic care in primary care'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  177,
  'Abnormal Random Blood Glucose Result',
  'Endocrine & Nephrology',
  'Telephone Consultation',
  false,
  'Nasrin Begum',
  '44-year-old female',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No Known Drug Allergy'],
  'Letter from City Walk Urgent Treatment Centre – 4 weeks ago

Dear GP,
Re: Nasrin Begum | 44 years old | Female

Ms Begum attended our centre today following a laceration to her right lower leg, sustained while moving boxes into her new flat this morning. On examination, a 3 cm superficial linear laceration was noted on the anterior aspect of the right shin, with no signs of active bleeding, foreign bodies, or underlying neurovascular compromise. The wound was cleaned and sutured using 3.0 nylon interrupted sutures. A sterile dressing was applied. She was advised to keep the wound clean and dry and to arrange suture removal in 7–10 days at her GP surgery. Routine blood tests were carried out including FBC, U&Es, and CRP, which were all within normal limits. However, her random blood glucose was noted to be raised at 12.0 mmol/L. Urinalysis was performed due to her report of occasional urinary frequency. The results showed glucose 2+ with no blood, nitrates, or ketones present. This result may warrant further investigation in primary care, and we are attaching the blood results for your review and action.

Kind regards,
Laura McKenzie, BSc (Hons), ANP
Advanced Nurse Practitioner

Attached blood test results from City Walk Urgent Treatment Centre:

Test | Result | Reference Range
Sodium (Na⁺) | 139 mmol/L | 135–145 mmol/L
Potassium (K⁺) | 4.2 mmol/L | 3.5–5.3 mmol/L
Urea | 5.1 mmol/L | 2.5–7.8 mmol/L
Creatinine | 72 µmol/L | 59–104 µmol/L
eGFR | >90 mL/min/1.73m² | >90 mL/min/1.73m²
Random Blood Glucose | 12.0 mmol/L | <11.1 mmol/L

Note entry – 3 weeks ago by Dr Sanjida Rahman (Clinical Practitioner Role):
Urgent care letter and blood results reviewed. Results filed as normal. No further action required.

Patient booked routine telephone appointment to discuss some concerns.',
  'Patient calling after noticing on the NHS App that her blood sugar was elevated but recorded as normal; she has also had symptoms of urinary frequency for several weeks.',
  '"Doctor, I was looking at my NHS App and I noticed that my blood sugar result was high, but it had been marked as normal. I''m a bit confused and worried about that."',
  'You explain that over the past 6 to 7 weeks you have been passing urine more frequently and feeling more thirsty than usual. Your symptoms have remained stable and have not got any worse, and you otherwise feel well. The wound on your leg seems to be healing without any problems.',
  ARRAY[]::text[],
  'You do not smoke or drink alcohol. You are a full-time homemaker and live with your husband and three children. You describe your home life as calm and settled. You do not do much regular physical activity. Your diet is not particularly healthy — you eat a lot of carbohydrates including rice, curry, and lentil dishes. You think you have put on some weight recently.',
  'You think you might have diabetes.',
  'You are worried about developing complications. Your older sister was diagnosed with type 2 diabetes at the age of 48 and was admitted to hospital with a wound on her foot that would not heal properly. She was told the poor healing was linked to her diabetes.',
  'You want the GP to start you on medication to treat the high blood sugar and prevent complications from developing.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor.',
  ARRAY[
    'Begin by apologising sincerely for the error. Acknowledge that the blood test from the urgent treatment centre showed a raised blood glucose level and was mistakenly filed as normal',
    'Reassure the patient that the practice takes such incidents very seriously and that this will be formally reported as a clinical incident. Explain that it will be reviewed to understand how it occurred and to prevent similar mistakes in the future',
    'Ask about the onset and duration of increased thirst (polydipsia) and frequent urination (polyuria)',
    'Ask about other urinary symptoms including nocturia, pain when passing urine, or visible blood in the urine',
    'Ask about symptoms suggestive of diabetic complications, such as blurred vision (diabetic retinopathy), tingling or numbness in the hands or feet (peripheral neuropathy), and delayed wound healing or recurrent infections — in her case, ask whether the leg wound she sustained and attended the urgent treatment centre for is healing properly',
    'Ask about any recent weight changes, including weight loss or weight gain — rapid weight loss may suggest type 1 diabetes, whereas type 2 diabetes is often associated with weight gain or more gradual weight changes',
    'Ask about symptoms suggestive of diabetic ketoacidosis (DKA), such as abdominal pain, persistent vomiting or diarrhoea, and difficulty breathing or deep, rapid breathing',
    'Ask about family history of diabetes',
    'Ask about social and lifestyle factors, including diet, physical activity levels, smoking, alcohol use, and occupation',
    'Ask if her symptoms have affected her daily life in any way, such as her energy levels, mood, sleep, or ability to carry out routine activities',
    'Ask about her ideas, concerns, and expectations',
    'Explain that the symptoms and findings are suggestive of possible type 2 diabetes, but that further confirmatory testing is needed urgently to make a clear diagnosis'
  ],
  ARRAY[
    'Offer a face-to-face appointment for further assessment, including urine dipstick testing for ketones, blood pressure measurement, and BMI check',
    'Arrange an urgent blood test to check HbA1c on the same day, if possible',
    'Advise that if the HbA1c confirms diabetes, she will be started on medication to help control her blood sugar',
    'Offer lifestyle advice including healthy dietary changes, weight management, and regular physical activity, as these are important for controlling blood sugar and improving overall health',
    'Explain that once diabetes is confirmed, she will be referred to a structured group education programme known as DESMOND (Diabetes Education for Self-Management for Ongoing and Newly Diagnosed), which will support her in understanding and managing her condition',
    'Advise her to monitor the wound on her leg and to contact the practice if she notices any discharge, redness, swelling, or other signs of infection',
    'Reassure her that an incident form will be completed regarding the misfiling of her previous blood result, to ensure this is investigated properly and to help prevent similar errors in the future',
    'Arrange follow-up contact within 48 hours once the blood test results are available',
    'Provide safety netting advice: if she develops new or worsening symptoms such as nausea, vomiting, abdominal pain, rapid or deep breathing, or feeling generally unwell or weak, she should contact the practice immediately or seek urgent medical attention'
  ],
  'Thank you so much for raising this today, Nasrin, and I completely understand why you are concerned. Having looked at your records, I can confirm that you are absolutely right — your blood sugar result from the urgent treatment centre was elevated, and I am very sorry that it was mistakenly filed as normal. That should not have happened, and I want to apologise for the worry this has caused you. I want to be transparent with you: I will be completing an incident report so that we can investigate exactly how this error occurred and put measures in place to make sure it does not happen to anyone else.

Now, turning to how you have been feeling — the increased thirst and passing urine more often that you have noticed over the past several weeks are symptoms we commonly see when blood sugar levels are running high, so it is understandable that you are worried, especially given what your sister went through.

Based on the information we have, including the blood test result and your symptoms, you may well have diabetes. However, before we make any firm decisions about treatment, we need to confirm the diagnosis properly. A one-off elevated blood sugar reading, while concerning, is not always enough on its own to make a definitive diagnosis — blood sugar can sometimes rise temporarily due to things like stress or illness. The test we use to confirm diabetes is called an HbA1c. This measures your average blood sugar level over roughly the past three months and gives us a much clearer picture. Before I explain more, what do you already know about diabetes?

Diabetes is a long-term condition where the body struggles to regulate the level of sugar in the blood. Over time, if blood sugar stays too high, it can affect the eyes, kidneys, nerves, and the blood vessels supplying the feet and legs — which is what caused the wound problem your sister experienced. That is exactly why it is so important we confirm this promptly and start supporting you early.

I would like to arrange for you to come in for a face-to-face appointment as soon as possible. When you come in, I will check your blood pressure, weigh you, and test a urine sample for something called ketones, which tells us how your body is coping with the high sugar level. We will also arrange the HbA1c blood test today if possible and aim to have the results reviewed within 48 hours.

If the HbA1c does confirm diabetes, we will discuss starting a medication to help control your blood sugar levels. We would also refer you to a structured education programme called DESMOND, which is specifically designed to help people newly diagnosed with diabetes understand the condition and how to manage it day-to-day. Alongside that, small dietary changes — reducing high-carbohydrate foods and increasing vegetables and fibre — and building in some gentle regular activity can make a meaningful difference, even before medication begins.

In the meantime, please keep an eye on the wound on your leg. If you notice any redness, swelling, discharge, or if it starts to look or feel as though it is not healing, please get in touch with us straight away. And if at any point you develop new symptoms such as feeling sick, tummy pain, or your breathing feels unusual, please call us or seek urgent medical attention without delay.',
  ARRAY[
    'A single elevated random blood glucose, even in the presence of symptoms, is not sufficient alone to diagnose diabetes; confirmatory testing with HbA1c or fasting plasma glucose is required per NICE guidance',
    'Duty of candour requires the GP to openly acknowledge clinical errors, apologise sincerely, and explain the steps being taken to prevent recurrence, including completing a formal incident report',
    'Features favouring type 2 over type 1 diabetes include gradual symptom onset, weight gain, absence of DKA features, and older age at presentation; however, both types require formal confirmatory testing before treatment is initiated',
    'Patients newly diagnosed with type 2 diabetes should be referred to a structured education programme such as DESMOND to support self-management',
    'Lifestyle modification — including dietary improvement, weight management, and increased physical activity — is a cornerstone of early type 2 diabetes management alongside or prior to medication',
    'Always provide safety-netting advice regarding DKA symptoms (nausea, vomiting, abdominal pain, rapid breathing) and advise prompt review if the patient deteriorates'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  178,
  'Concern About Cousin at Risk of FGM',
  'Ethics',
  'Telephone Consultation',
  false,
  'Hodan Warsame',
  '34-year-old female',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No Known Drug Allergy'],
  'Patient booked an urgent telephone appointment to discuss some private concerns.',
  'Patient calling to raise safeguarding concerns about her niece who she believes may be at risk of female genital mutilation.',
  '"Doctor, I have some concerns about my sister''s daughter, Amina Ali. She isn''t registered with this practice, but I''m hoping you might still be able to help."',
  'You and your sister both underwent female circumcision as children. You personally experienced complications from it, including problems with urination and during sexual intercourse. Around six years ago you had corrective surgery in London to help with these complications and you are doing better now. Your sister''s daughter is 8 years old. Your sister recently mentioned that her husband is planning to take the child to Eritrea for three months "to have a ceremony done." You strongly suspect this means female circumcision. They are due to travel in 3 weeks'' time.',
  ARRAY[]::text[],
  'Your sister and her daughter live in Leeds, while you are based in Sheffield. The daughter is their only child and currently attends school. She is registered with a local GP. There are no known concerns about domestic violence in the home. Your sister is a full-time mother and her husband is the main earner.',
  'You believe the child is at risk of undergoing female circumcision abroad.',
  'You are deeply worried because you know first-hand the lifelong physical and emotional harm this procedure causes.',
  'You want the doctor to advise you on the steps you can take to protect the child.',
  ARRAY[]::text[],
  'Ask whether the doctor can take action even though the child is not registered at this practice. If the doctor agrees to make the referral themselves, ask whether you need to tell your sister so she knows what is happening.',
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor.',
  ARRAY[
    'Thank the caller for opening up and acknowledge that this can be a difficult and distressing matter to raise',
    'Ask about her relationship to the child to establish her safeguarding role and the closeness of her connection to the family',
    'Ask about her ideas, concerns, and expectations regarding the situation',
    'Ask if the child is registered at your GP surgery. If not, ask whether she is registered with a GP elsewhere',
    'Ask where the child and her mother currently live, and whether they live locally, to help assess how quickly intervention can be arranged',
    'Ask when the planned travel is meant to take place and how soon the family are due to depart',
    'Ask if she knows whether any travel arrangements such as tickets or passports have already been organised, to assess the urgency and timeline',
    'Ask what the child''s mother thinks about the planned procedure — whether she agrees with it, is resisting it, or may be being pressured',
    'Ask whether the child is aware of the planned trip and if she has expressed any concerns or distress',
    'Ask if there are other female children in the family, and if so, whether any of them have already undergone female genital mutilation — if FGM has occurred and the child is under 18, this must be reported directly to the police',
    'Ask about the home environment — whether the caller feels her sister and niece are safe at home, whether there are other children in the household, and whether there are any concerns about domestic violence or coercion'
  ],
  ARRAY[
    'Thank the caller again for speaking up and acknowledge how difficult and courageous it is to raise this kind of concern',
    'Explain that female circumcision, also known as female genital mutilation (FGM), is a harmful practice that can cause permanent physical and emotional damage',
    'Inform her that FGM is illegal in the UK and it is also a criminal offence to take a child abroad for the purpose of having it carried out',
    'Emphasise that any risk of FGM is treated as a serious safeguarding concern and must be acted upon without delay',
    'Reassure the caller that even though the child is not registered at this practice, the GP still has a professional duty to act on the concern',
    'Ask the caller to provide further details including the child''s full name, the parents'' names, and their home address. Explain that this information is needed to make an urgent referral to the safeguarding team and child protection services in Leeds, where the child resides, to ensure the child''s safety',
    'Reassure her that the referral will be handled promptly and confidentially, and that the priority is to protect the child from harm',
    'Advise that if the father proceeds with the plan, this could result in serious legal consequences including a prison sentence of up to 14 years',
    'Reassure the caller that she has done exactly the right thing by speaking up, and that both her sister and niece will be offered appropriate support and protection',
    'Advise her to share any updates or further concerns with the practice, and to contact the police directly if she believes the child is at immediate risk of harm'
  ],
  'Thank you so much for finding the courage to call today. I can only imagine how difficult this has been to bring up, and I want you to know that you have absolutely done the right thing. What you have described raises a very serious safeguarding concern, and I want to talk you through what happens next.

Female circumcision — which is formally known as Female Genital Mutilation, or FGM — is illegal in the United Kingdom. It is also a criminal offence to take a child abroad specifically to have the procedure carried out in another country. The law recognises this as a form of child abuse because it causes significant and lasting physical and emotional harm, as you yourself have experienced first-hand.

You asked whether we can act even though your niece is not registered at our practice. The answer is yes. As healthcare professionals, we have a duty to act whenever we believe a child is at risk of serious harm, regardless of where they are registered. The fact that she is not our patient does not reduce our responsibility to respond.

What I will do is make an urgent referral to the safeguarding team and children''s social care services in Leeds, where your sister and niece are living. They have the authority and the expertise to assess the situation, contact the appropriate people, and take the necessary steps to ensure the child''s safety before the planned travel takes place. Given that the family is due to travel in three weeks, it is important that this referral goes in as soon as possible today.

You also asked whether you need to tell your sister about the referral. You are not required to do so. In situations like this, where advance warning could increase the risk to the child — for example, by prompting the family to bring the travel plans forward — it is often safer not to inform the family beforehand. The safeguarding team will handle communications with the family carefully and sensitively, and they will ensure the right people are involved.

To complete the referral, I will need a few pieces of information from you — the child''s full name, her parents'' names, and their home address in Leeds. Could you share those with me?

If at any point you become aware of any changes — for example, that the travel has been brought forward, or that you believe the child is in immediate danger — please do not hesitate to contact us again or to call the police directly. You can do that at any time. What you have done today is incredibly important, and it may well prevent serious harm from coming to your niece.',
  ARRAY[
    'FGM is illegal in the UK under the Female Genital Mutilation Act 2003; it is also a criminal offence to take a child abroad for the purpose of carrying out FGM, carrying a sentence of up to 14 years imprisonment',
    'There is a mandatory duty for healthcare professionals to report all confirmed cases of FGM in girls under 18 directly to the police; where FGM has not yet occurred but is at risk, an urgent safeguarding referral to children''s social care is required',
    'A GP has a professional duty to act on safeguarding concerns even if the child at risk is not registered with their practice',
    'Informing the family of a safeguarding referral before it is made may increase the risk to the child — the decision about whether to disclose should be made in consultation with the safeguarding team',
    'Key information needed for a safeguarding referral includes the child''s full name, the parents'' names, and their current address, and the referral should be made to the local authority where the child resides',
    'Clinicians should acknowledge the difficulty and bravery involved in a caller raising FGM concerns, particularly when they are family members, and provide clear and empathetic guidance throughout'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  179,
  'HIV Test Request In A Teenager',
  'Travel Health & Infectious Disease',
  'Telephone Consultation',
  false,
  'Elliot Chambers',
  '16-year-old male',
  ARRAY['None recorded'],
  ARRAY['Not currently on any medication','No Known Drug Allergy'],
  'Patient booked an urgent telephone consultation to discuss some concerns.',
  'Patient calling to request an HIV test.',
  '"Hi doctor, I''d like to get an HIV test please."',
  'You have recently started a relationship with another male and the two of you have begun having anal intercourse. After reading online that gay men face a higher risk of HIV, you became worried — especially because you had flu-like symptoms last week. You read online that flu-like symptoms can sometimes be an early sign of HIV infection. If asked about your partner: he is also 16 and in the same school year as you. He mentioned he had two previous partners before your relationship and had one casual encounter before that. He has never been tested for HIV and does not know his status.',
  ARRAY[]::text[],
  'You live at home with your parents and two younger siblings. You are in Year 11 and working towards your GCSEs. You do not smoke, drink alcohol, or take drugs. Things are going well at school.',
  'You know that HIV can be transmitted through sex between men.',
  'You are worried you might have HIV.',
  'You want to have an HIV test but you do not want your parents to know that you are getting tested.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor. If the doctor advises attending a sexual health clinic, firmly decline and say you are not comfortable with that, and ask if the test can be done at the GP surgery instead.',
  ARRAY[
    'Ask about the reason for requesting an HIV test',
    'Signpost that you need to ask some personal and sexual health questions to understand the situation properly and offer the right support. For example: "Elliot, I''d like to ask you a few personal questions, including about your sexual activity, just so I can understand things properly and support you in the best way. Would that be okay?"',
    'Ask if this is his first sexual encounter, when it took place, and when his most recent sexual contact was — to assess the window for post-exposure prophylaxis',
    'Ask whether sexual intercourse was protected or unprotected',
    'Ask about any history of previous sexual partners and whether he currently has more than one partner',
    'Ask if he has ever been diagnosed with a sexually transmitted infection (STI)',
    'Ask for the age of his partner and whether he knows his partner''s HIV status',
    'Ask if he has ever felt pressured, forced, or coerced into any sexual activity to confirm consent',
    'Ask about the onset and nature of his recent flu-like symptoms',
    'Ask about other early symptoms of HIV, such as fever, sore throat, rashes, mouth ulcers, weight loss, or diarrhoea',
    'Ask about other STI symptoms, including penile discharge, genital ulcers, pain when passing urine, and urinary frequency',
    'Ask about lifestyle factors including smoking, alcohol intake, and recreational drug use',
    'Ask about his home situation and who he lives with',
    'Ask how things are going at school and whether he has been experiencing any difficulties',
    'Ask about his understanding of HIV, how the test is done, and what a positive or negative result would mean'
  ],
  ARRAY[
    'Briefly explain that HIV is a virus that weakens the immune system, which helps the body fight off infections. It can be transmitted through unprotected sex, sharing needles, blood transfusions (in rare cases), and from mother to baby during pregnancy, birth, or breastfeeding. HIV is diagnosed with a blood test',
    'Explain that a negative test result usually means there is no HIV infection, but if the exposure was recent, the virus might not show up yet, so a repeat test may be needed at 12 weeks. If the test is positive, it will be confirmed with a second test',
    'Reassure that if confirmed positive, effective treatment is available to manage the condition and prevent HIV-related illness',
    'Emphasise the importance of safe sexual practices, including consistent condom use, to reduce the risk of HIV and other STIs',
    'Advise referral to a sexual health clinic, explaining the benefits: comprehensive STI screening, expert advice, and access to treatments if needed',
    'If the patient declines referral to a sexual health clinic, offer HIV testing in general practice and include screening for other STIs (chlamydia, gonorrhoea, syphilis, hepatitis B and C)',
    'Provide information about Pre-Exposure Prophylaxis (PrEP) — a tablet available through sexual health clinics that significantly reduces the risk of HIV infection in high-risk individuals. Let the patient know this is something that could be considered to help protect him going forward',
    'Arrange follow-up to discuss test results within one week',
    'Safety-net: advise the patient to contact the practice if he develops symptoms such as diarrhoea, weight loss, or persistent fever, or if he has any further questions or worries'
  ],
  'Thank you so much for reaching out today, Elliot — it genuinely takes courage to make this call, and I want you to feel completely at ease. What we talk about today is confidential, just between us, and I''m here to support you, not to judge you.

Before we go any further, I''d like to ask — what do you already know about HIV? That way I''ll know where to start and won''t repeat anything you already know. Is that okay?

HIV is a virus that affects the immune system — the part of the body that fights off infections. When someone has HIV and it goes untreated, the immune system gradually becomes weaker. It is most commonly passed on through unprotected sex, but it can also be transmitted through sharing needles, and very rarely through blood transfusions or from a mother to her baby during pregnancy or breastfeeding. The good news is that it is diagnosed with a simple blood test, and I can help arrange that for you.

I want to explain what the test results can mean. If the test comes back negative, that usually means you do not have HIV. However — and this is important — if the sexual contact happened recently, within the last few weeks, the virus might not yet show up in the blood. That is what we call the window period. For that reason, we would sometimes recommend repeating the test at 12 weeks to be completely certain. If the test were to come back positive, we would always repeat it to confirm the result before drawing any conclusions.

I also want to reassure you that even if a positive result were confirmed, HIV treatment today is extremely effective. People living with HIV who take their medication consistently can live long, healthy lives, and the virus can be suppressed to a level where it cannot be passed on to anyone else. So while I understand it''s worrying, a positive result is no longer the life-changing diagnosis it once was.

I know I mentioned a sexual health clinic earlier, and I completely understand if that feels like a step you''re not ready for. We can absolutely arrange the HIV test here at the surgery, and we can also check for other infections at the same time — such as chlamydia, gonorrhoea, syphilis, and hepatitis B and C. These are all important to screen for whenever someone is sexually active.

I also want to mention something called PrEP — Pre-Exposure Prophylaxis. It''s a tablet that can be taken to significantly reduce the risk of getting HIV, and it''s something available through sexual health clinics when you feel ready to explore that. It might be worth thinking about for the future.

Going forward, using condoms consistently with all sexual partners is one of the most effective ways of protecting yourself from HIV and other sexually transmitted infections. That''s something worth keeping in mind.

We''ll arrange a follow-up to go through the test results with you, usually within about a week. In the meantime, if you start to feel unwell — particularly things like persistent diarrhoea, unexplained weight loss, or a high temperature that doesn''t go away — please don''t hesitate to get in touch.',
  ARRAY[
    'HIV testing can be offered in general practice; if a patient declines referral to a sexual health clinic, the GP can arrange an HIV blood test and screen for other STIs including chlamydia, gonorrhoea, syphilis, and hepatitis B and C',
    'A negative HIV test does not exclude infection if the exposure was recent — a repeat test at 12 weeks is recommended due to the window period during which the virus may not yet be detectable',
    'Post-Exposure Prophylaxis following Sexual Exposure (PEPSE) can reduce the risk of HIV if started within 72 hours of potential exposure (ideally within 24 hours); eligible patients should be referred urgently to a sexual health clinic or emergency department',
    'Pre-Exposure Prophylaxis (PrEP) is a highly effective daily or on-demand tablet available through sexual health services that significantly reduces HIV risk in high-risk individuals such as men who have sex with men',
    'Adolescents aged 16 and above are presumed competent to consent to sexual health care; confidentiality must be maintained and parents should not be informed without the patient''s consent unless there is a safeguarding concern',
    'Always assess for consent and potential coercion when taking a sexual history in a young person, and ensure a non-judgemental, empathetic approach throughout the consultation'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  180,
  'Teenage Pregnancy',
  'Gynaecology & Women''s Health',
  'Telephone Consultation',
  false,
  'Chloe Daley',
  '16-year-old female',
  ARRAY['None recorded','Newly registered at the practice'],
  ARRAY['Not currently on any medication','No Known Drug Allergy'],
  'Patient booked an urgent telephone consultation to discuss some concerns.',
  'Patient calling after discovering she is pregnant; she wishes to continue with the pregnancy but has significant social vulnerabilities and a previous child taken into care.',
  '"Hi doctor, I''ve just found out I''m pregnant. I really want to keep the baby but I don''t know where to start."',
  'You found out you were pregnant around 4 weeks ago, and your last period was approximately 12 weeks ago. The pregnancy was not planned, but you very much want to continue with it. You are feeling anxious that social services might take this baby away, as happened with your first child. If asked about your previous pregnancy: You had a baby when you were 14. At the time you were living with your aunt, who became your guardian after your mum died. The pregnancy was with a 15-year-old neighbour and it was not consensual, though you did not tell anyone at the time as you did not know how to. Social services became involved and decided you were too young to care for a baby, and the child was placed with a foster family for adoption. You are currently well in yourself with no symptoms. You have not yet seen a midwife or had any blood tests or scans. You feel supported by your current boyfriend and you feel safe in the relationship.',
  ARRAY[]::text[],
  'You are currently living in a social hostel with your partner, who is 17 years old and supportive. Neither of you is working and you are both relying on Universal Credit. You do not smoke, drink alcohol, or take drugs. If asked about education: you were at school but stopped when you found out you were pregnant. You hope to return to studying after the baby is born.',
  'You believe that being young does not mean you cannot be a good mother.',
  'You are worried that this baby will be taken away just like the last time.',
  'You want reassurance and practical support to help you keep your baby.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered to you by the doctor.',
  ARRAY[
    'Ask when she found out she was pregnant, how the pregnancy was confirmed (for example, a home urine test or a scan), and the date of her last menstrual period to help establish gestational age',
    'Ask whether the pregnancy was planned and whether she wishes to continue with it',
    'Ask about any current pregnancy-related symptoms, including nausea, vomiting, abdominal pain, bleeding, or vaginal discharge',
    'Ask if she has seen a midwife or accessed any antenatal care so far',
    'Ask about any current medications or supplements she is taking, including folic acid or over-the-counter preparations',
    'Ask if she has been pregnant before. If so, explore the details of that pregnancy — including how old she was, who the father was, whether the relationship was consensual, what happened to the baby, and whether social services were involved',
    'Ask about her current partner, including his age, whether the relationship feels safe and supportive, and whether it was consensual. Also ask about his employment status and whether he is involved in and able to support the pregnancy',
    'Ask about her social history and lifestyle factors, including her current living arrangements, whether she smokes, drinks alcohol, or uses any drugs',
    'Explore her education and employment status, and how she is managing financially',
    'Ask about her mental health, emotional wellbeing, and whether she has any family, friends, or professionals currently supporting her',
    'Explore her ideas, concerns, and expectations'
  ],
  ARRAY[
    'Reassure the patient that just because social services were involved in the past does not mean the same outcome will happen again. Each situation is assessed individually based on current circumstances and needs',
    'Advise that a referral will be made to the safeguarding team — not because she is in trouble, but as a proactive step to ensure her safety and the safety of her unborn child',
    'Note: the safeguarding referral is appropriate in this case due to several contributing factors, including residence in temporary accommodation (a hostel), her background as a previously looked-after child, limited financial resources, and her young age, all of which may increase the risk of her being under-supported in parenting. The referral is intended to ensure early access to appropriate multi-agency support',
    'Offer to liaise with the social prescriber, who can help her access housing support, financial resources, and community-based services for young parents',
    'Encourage her to register with antenatal care by booking in with a midwife. Explain that the midwife will carry out initial blood tests and arrange a dating scan to help plan a safe and healthy pregnancy',
    'Advise that folic acid is recommended until 12 weeks of pregnancy, but as she is likely around 12 weeks, it is sensible to continue until the dating scan confirms gestational age, after which the midwife may advise whether she can stop',
    'Advise the patient to take a vitamin D supplement (10 micrograms of vitamin D per day) throughout pregnancy',
    'Both folic acid and vitamin D supplements are available over the counter; however, given this patient''s financial circumstances, it would be reasonable to offer a prescription to ensure access',
    'Arrange a follow-up in two weeks to review how things are going and ensure she is receiving the right support throughout her pregnancy',
    'Safety-net: advise the patient to contact the surgery or the out-of-hours service if she develops any symptoms such as vaginal bleeding, abdominal pain, fever, or any other concerns during the pregnancy'
  ],
  'Thank you for calling today, Chloe, and for being so open with me. I can hear how much this pregnancy means to you, and I want you to know that I am here to support you, not to judge you. Can I start by saying — the fact that you have called straight away, and that you are already thinking carefully about doing the right thing for your baby, says a lot.

I want to address your biggest worry first. I understand you are frightened that what happened last time might happen again, and that is completely understandable given everything you went through. But I want to reassure you clearly: the fact that social services were involved before does not automatically mean the same will happen this time. Every situation is looked at individually, on its own merits, based on what is happening right now. The most important thing is that you have support around you, and that is exactly what we are going to help put in place.

I do want to be honest with you about something. Because of everything you have shared — the fact that you are living in a hostel, that finances are tight, that you are still very young — I would like to make a referral to a safeguarding team. I want to be very clear: this is not because you are in any trouble, and it is not because we think you cannot be a good mother. It is a way of making sure you and your baby have the right people around you from as early as possible — things like housing support, parenting support, financial guidance, and local groups for young parents. Think of it as building your team before the baby arrives. Does that make sense?

I would also like to put you in touch with our social prescriber, who is brilliant at helping people find practical support in the community — things like benefit entitlements, housing advice, and local parent and baby groups.

The next really important step is getting registered with a midwife. I can help point you in the right direction for that today. Once you are registered, the midwife will get in touch to arrange your first antenatal appointment, where they will do some blood tests and arrange a dating scan. The scan will tell us exactly how many weeks along you are, which helps us plan the rest of your pregnancy properly.

On the topic of vitamins — folic acid is recommended in early pregnancy, usually up to 12 weeks. Since you are likely around that point but have not had a scan yet to confirm the dates, it is safest to keep taking it for now. The midwife will advise you after the scan whether you need to continue. I would also recommend you take vitamin D — 10 micrograms a day — throughout your entire pregnancy. Both of these are available at a pharmacy, but given your current situation, I am happy to prescribe them for you so there is no cost to worry about.

I would like to speak with you again in about two weeks to see how everything is progressing and make sure the right services are in place. In the meantime, if anything worries you at all — any bleeding, stomach pain, a fever, or anything that just does not feel right — please call us or the out-of-hours line straight away. We are here for you, and you do not have to do this alone.',
  ARRAY[
    'Teenage pregnancy is associated with significant social and health inequalities; a non-judgemental, empathetic approach is essential to building trust and ensuring the young person engages with antenatal care',
    'A proactive safeguarding referral is appropriate when a young pregnant person has multiple vulnerabilities — such as temporary accommodation, financial insecurity, being a previously looked-after child, and limited support networks — even in the absence of immediate abuse or neglect',
    'Folic acid is recommended until 12 weeks of pregnancy; when gestational age is uncertain, it is sensible to continue until confirmed by a dating scan. Vitamin D 10 micrograms daily is recommended throughout the entire pregnancy',
    'Given financial hardship, prescribing folic acid and vitamin D rather than directing the patient to purchase supplements over the counter is a reasonable and compassionate clinical decision',
    'Reassurance that a previous child being placed in care does not predetermine the outcome of the current pregnancy is important — each situation is assessed individually and the focus of safeguarding is empowerment and early support, not punishment',
    'The GP has a key role in coordinating early multi-agency support including midwifery, social prescribing, safeguarding, and housing services for vulnerable young pregnant patients'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  181,
  'Poorly Controlled COPD',
  'Respiratory',
  'Telephone Consultation',
  false,
  'Roy Pemberton',
  '69-year-old male',
  ARRAY['COPD (Chronic Obstructive Pulmonary Disease)','Hypertension','Hypercholesterolaemia'],
  ARRAY['Ultibro Breezhaler 85microgram/43microgram dry powder inhaler - 1 inhalation once daily','Ventolin Evohaler 100 micrograms - Two puffs up to 4 times a day when needed for relief of symptoms','Amlodipine 10 mg once daily','Atorvastatin 20 mg once daily','No Known Drug Allergy'],
  'Two months ago – Seen by Dr Patricia Simmons (Clinical Practitioner Role). Presenting complaint: Known COPD, presenting with cough producing yellowish sputum and associated shortness of breath. No haemoptysis. Patient felt that his inhalers were not working effectively. Examination findings: Widespread wheeze and left lower zone crackles. Oxygen saturations 95% on room air, BP 128/76 mmHg, pulse 91 bpm. Impression: Likely infective exacerbation of COPD (IECOPD). Plan: Doxycycline 200 mg stat, followed by 100 mg once daily for 4 days (5-day course in total). Prednisolone 30 mg once daily for 5 days. Safety-netting and worsening advice provided. Telephone Consultation (2 weeks ago) with Dr Helen Barker (Clinical Practitioner Role). Presenting complaint: Ongoing and worsening shortness of breath. No orthopnoea, paroxysmal nocturnal dyspnoea (PND), or leg swelling. No other cardiac symptoms. Patient noted that his blue inhaler provides short-term relief but is now required daily, and symptoms are increasingly affecting his quality of life. Plan: Chest X-ray requested. Follow-up appointment arranged post-imaging. Worsening advice provided. Chest X-ray Result. Roy Pemberton | 69 years old | Male. Referral Reason: Worsening dyspnoea in a patient with known COPD. Report: The lungs appear hyperinflated with flattened hemidiaphragms and increased retrosternal airspace, consistent with chronic obstructive pulmonary disease. No focal consolidation is seen. There is no evidence of pleural effusion or pneumothorax. The cardiac silhouette is within normal limits, and the mediastinal and hilar contours are unremarkable. No suspicious masses or pulmonary nodules are identified. The bony thorax shows no acute abnormalities. Conclusion: Features in keeping with COPD. No radiological evidence of malignancy or acute pulmonary pathology. Reported by: Thomas J. Cartwright, BSc (Hons) Diagnostic Radiography, PgCert Radiographic Reporting (Chest), Reporting Radiographer. Patient booked a follow-up telephone consultation to discuss the X-ray report and his ongoing concerns.',
  'Patient calling to discuss chest X-ray results and worsening breathlessness.',
  '"Hi doctor, I wanted to talk about my chest X-ray and my breathing — it''s really been getting worse lately."',
  'His chest X-ray was arranged because his breathing has been gradually worsening over the past couple of months. He now needs to use his blue inhaler every day to manage his symptoms. It provides some short-term relief, but the breathlessness keeps returning. He has noticed a significant impact on his daily life — he used to enjoy going to the bowls club with his friends but now avoids it because he becomes too breathless. He also finds it hard to spend time in the garden with his grandchildren as he used to. He feels embarrassed walking with others, as he gets short of breath after around 80 metres and often has to stop. He has a regular productive cough that brings up white phlegm, but no chest pain, no weight loss, and no coughing up blood (haemoptysis). He has never been admitted to hospital due to his COPD, but he has had more than three episodes of flare-up requiring steroids.',
  ARRAY[]::text[],
  'He lives with his wife. He is a retired lorry driver. He has smoked heavily for most of his adult life — around 40 cigarettes a day for 20 years — but cut down about 4 months ago to approximately 7 cigarettes per day.',
  'He thinks his COPD is getting worse.',
  'He is worried about losing his independence — he is already avoiding social activities and finding it difficult to keep up with his grandchildren.',
  'He is hoping the doctor can offer some treatment or a solution to help improve his breathing and quality of life.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY[
    'Ask about the shortness of breath — when it started getting worse and whether the onset was gradual or sudden (gradual worsening may suggest COPD progression, while sudden onset could indicate an infective exacerbation or cardiac cause)',
    'Ask what makes the breathlessness worse and what helps relieve it',
    'Ask how far the patient can walk before becoming breathless (e.g. MRC Dyspnoea Scale — stopping after around 80 metres suggests MRC grade 4)',
    'Ask about orthopnoea (breathlessness when lying flat), paroxysmal nocturnal dyspnoea (waking at night gasping for air), or leg swelling, to screen for heart failure',
    'Ask about associated cough, whether it is productive, and the nature of the sputum',
    'Ask about haemoptysis',
    'Ask about associated wheeze, palpitations, or chest pain',
    'Ask about red flag symptoms including unexplained weight loss or night sweats, noting that a normal chest X-ray does not fully exclude malignancy',
    'Ask how many exacerbations requiring oral steroids the patient has had in the past year',
    'Ask whether the patient has ever been hospitalised due to his COPD. Note: According to NICE, for patients with COPD who have experienced more than three exacerbations requiring oral corticosteroids (four or more exacerbations) and at least one hospital admission in the past year, referral to a respiratory specialist should be considered to assess suitability for prophylactic oral macrolide therapy (e.g. azithromycin)',
    'Ask how the breathlessness and symptoms are affecting his daily life and usual activities',
    'Ask whether the patient is taking his inhalers regularly as prescribed, and whether anyone has recently reviewed his inhaler technique',
    'Ask about mood — it is important to screen for low mood or depression in patients with chronic conditions',
    'Ask about social history including smoking, alcohol intake, home situation, and occupation',
    'Elicit ideas, concerns, and expectations (ICE)',
    'Give a working diagnosis of worsening COPD'
  ],
  ARRAY[
    'Explain that the chest X-ray confirms changes consistent with COPD and shows no evidence of infection, cancer, or any other acute abnormality',
    'Advise that his worsening symptoms are likely due to progression of his COPD',
    'Offer a face-to-face appointment to assess chest sounds, heart rate, blood pressure, and oxygen saturation levels',
    'Offer blood tests, including eosinophil count, to assess whether adding an inhaled corticosteroid (ICS) to his current treatment would be beneficial',
    'Explain that if his eosinophil levels are raised, he will need to switch to a new inhaler that contains a steroid (inhaled corticosteroid, ICS), and he will need to stop using his current inhaler as the new one will combine all the necessary medications',
    'If eosinophil levels are less than 100, consider a tablet called roflumilast to reduce the risk of future exacerbations; this medication must be initiated by a respiratory specialist, so a referral should be made for further assessment',
    'Offer referral to a physiotherapist for pulmonary rehabilitation, explaining that this can improve breathlessness and quality of life',
    'Offer and arrange vaccinations including pneumococcal, influenza, and COVID-19 to reduce the risk of exacerbations',
    'Advise on the importance of smoking cessation and offer referral to local smoking cessation services',
    'Offer referral to the COPD nurse for regular review and a personalised self-management plan',
    'Advise the patient that, as he has experienced more than one exacerbation this year, a rescue pack to keep at home — containing oral corticosteroids and antibiotics — will be offered for use during future flare-ups. Clear instructions on when and how to use the pack will be provided. This will be discussed in more detail during his face-to-face review or with the COPD nurse as part of his personalised care plan'
  ],
  'Thank you for calling in today, Roy. I can hear that your breathing has been making things quite difficult recently — not being able to get out to your usual activities or spend time in the garden with your grandchildren must be really frustrating. I want to go through the X-ray results and what we can do next, if that''s all right with you.

First, the good news from the X-ray: it does show changes that are consistent with your COPD, but there is no sign of any infection, cancer, or anything new or unexpected. That is genuinely reassuring. However, the fact that your breathing is continuing to worsen and you''re needing your blue inhaler every single day tells us that your COPD needs some further attention.

Because of that, I''d like to see you in person so we can listen to your chest, check your heart rate, blood pressure, and oxygen levels properly. I''d also like to arrange a blood test — specifically checking a type of cell called eosinophils — which will help us decide whether adding a steroid inhaler to your treatment might make a real difference to your breathing. Would you be happy to have that test done?

If the blood test shows elevated eosinophil levels, we would switch you to a new combined inhaler that includes a steroid. It would replace your current inhaler, so you''d only need the one device. If the levels are low, we would consider a tablet called roflumilast, which helps prevent flare-ups — though that would need to be started by a specialist at the hospital, so we would refer you for that.

Because your symptoms are limiting your day-to-day life, I''d also like to refer you to physiotherapy for something called pulmonary rehabilitation. It''s a structured programme of gentle exercise and breathing techniques, specifically designed for people with COPD. Patients often find it really helps them feel more in control and able to do more.

You mentioned you''ve cut your smoking down, and that is a genuinely positive step. Stopping completely, though, would make the single biggest difference to your lung health. When you feel ready, our stop smoking service can offer you real support and treatments to help. There''s no pressure — just know the option is there.

I''d also like to refer you to our COPD nurse for regular reviews. They''ll help you put together a personalised management plan, check your inhaler technique, and make sure you know the early signs of a flare-up and what to do about them.

Finally, because you''ve had more than one flare-up this year, we''ll put together a rescue pack for you to keep at home — a short course of steroids and antibiotics to use if your symptoms suddenly worsen. This means you can act early rather than waiting. The nurse will go through exactly when and how to use it when you come in. We''ll also make sure you''re up to date with your flu, pneumococcal, and COVID vaccinations. Does all of that make sense, Roy?',
  ARRAY[
    'In COPD, worsening breathlessness with daily use of a reliever inhaler despite maintenance therapy strongly suggests disease progression and warrants structured review including face-to-face assessment, eosinophil count, and spirometry',
    'COPD patients are classified as Group A, B, or E based on exacerbation history and symptom burden; Group E (two or more moderate exacerbations or at least one hospital admission in the past year) should be started on LAMA + LABA, with triple therapy (LAMA + LABA + ICS) if eosinophils are 300 cells/μL or above',
    'Roflumilast, a phosphodiesterase-4 inhibitor used to reduce exacerbation risk, must be initiated by a respiratory specialist and is considered when eosinophil counts are low (below 100 cells/μL)',
    'According to NICE, patients with more than three exacerbations requiring steroids per year AND at least one hospital admission should be referred to a respiratory specialist to assess suitability for prophylactic azithromycin',
    'Non-pharmacological management of COPD includes smoking cessation, pulmonary rehabilitation, rescue packs for patients with recurrent exacerbations, and up-to-date vaccinations (influenza, pneumococcal, COVID-19)',
    'Inhaler technique should be reviewed at every consultation, as poor technique is a common and correctable cause of inadequate symptom control'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  182,
  'Joint Pain After Recent Diarrhoeal Illness',
  'Rheumatology & Musculoskeletal',
  'Telephone Consultation',
  false,
  'Ryan Fletcher',
  '26-year-old male',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No Known Drug Allergy'],
  'Seen 4 weeks ago by Dr Moira Campbell (Clinical Practitioner Role). Presenting Complaint: Diarrhoea and crampy abdominal pain ongoing for 7 days after returning from holiday in Spain where he ate street food. Passing 4–5 episodes per day. Reported some episodes with blood. No weight loss, no night sweats, no family history of inflammatory bowel disease or cancer. Examination: Abdomen soft and non-tender. BP 118/72 mmHg, pulse 80 bpm, temperature 36.4°C. PR examination performed with verbal consent and chaperone present: no masses felt and no blood on examination glove. Impression: Traveller''s diarrhoea. Plan: Stool culture sent, advice given on hygiene measures, review with results. Stool Culture Result (Department of Microbiology). Appearance: Watery stool. Culture Result: Campylobacter species identified. Comment: Campylobacter enteritis is usually self-limiting. Antimicrobial therapy is not routinely indicated. Consider azithromycin if severe, prolonged, or in immunocompromised patients. Public Health notification may be required. Note Entry (Dr Moira Campbell, 4 weeks ago): Text message left advising patient to get back in touch if symptoms persisted.',
  'Patient calling to discuss new onset of joint pain and swelling since his recent gastrointestinal illness.',
  '"Hi doctor, my joints have become swollen and painful, and it''s really starting to affect me."',
  'He has noticed generalised joint pain, mainly affecting his left knee and right ankle. The joints feel stiff, swollen, and painful, particularly in the mornings, and sometimes ease a little as the day goes on. This started approximately 6 days ago. Symptoms have been getting progressively worse, and the pain has now spread to involve his lower back. Two days ago, he developed pain in his back and right buttock. He is not sure what is causing this, but it has started to interfere with his work as a landscape gardener. His back and buttocks feel very stiff in the mornings and only begin to ease by lunchtime. As a result, he has had to miss work for the past 2 days. He has tried paracetamol for pain relief, but it has not helped much. He has had no fever and no trauma to his joints. He had diarrhoea about 4 weeks ago after returning from Spain, but this has now fully resolved and he otherwise feels well.',
  ARRAY[]::text[],
  'He does not smoke and does not drink alcohol. He lives with his long-term partner of 2 years. He has no family history of joint or muscle disease.',
  'He is not sure what might be causing his symptoms.',
  'He is worried because this is affecting his ability to work, and as a self-employed landscaper he does not receive sick pay when he cannot work.',
  'He would like the GP to prescribe something to help relieve his symptoms.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Ask about the onset of symptoms',
    'Ask which joints are affected. Note: Reactive arthritis typically presents as an asymmetrical oligoarthritis, most often involving lower limb joints such as the knees, ankles, and sometimes the sacroiliac joints. Oligoarthritis means 2–4 joints are involved. Asymmetrical means different joints on each side are affected. This is important to distinguish from rheumatoid arthritis, which causes symmetrical arthritis affecting the same joints on both sides',
    'Ask about redness, swelling, or stiffness of the affected joints',
    'Ask about swelling of the fingers or toes (dactylitis)',
    'Ask whether he is able to move the affected joints and whether he can comfortably bear weight on them',
    'Ask about the diarrhoeal illness 4 weeks ago and whether symptoms have fully resolved',
    'Ask about factors that make symptoms better or worse',
    'Ask whether symptoms are worsening, improving, or staying the same',
    'Ask about constitutional symptoms such as fatigue, fever, and malaise',
    'Ask about other features of Reiter''s triad to rule out sexually acquired reactive arthritis: conjunctivitis (red or itchy eyes) and urethritis (burning on passing urine or urethral discharge)',
    'Ask about painful or red eyes to rule out uveitis — if present, this requires same-day ophthalmology referral',
    'Ask about skin rash or nail changes (to rule out psoriatic arthritis). Note that erythema nodosum and keratoderma blennorrhagica may also occur with reactive arthritis',
    'Ask about mouth ulcers',
    'Ask what the patient has already tried for pain relief',
    'Ask about social history including occupation, smoking, and alcohol',
    'Ask how symptoms are affecting his daily activities and work',
    'Explore ideas, concerns, and expectations',
    'Make a diagnosis of reactive arthritis'
  ],
  ARRAY[
    'Offer a face-to-face consultation to assess and examine the affected joints',
    'Arrange blood tests including FBC, ESR, CRP, rheumatoid factor, antinuclear antibodies, and HLA-B27',
    'Offer non-steroidal anti-inflammatory drugs (NSAIDs) together with a proton pump inhibitor (PPI). Explain that NSAIDs help reduce both pain and inflammation, but can cause side effects such as indigestion, stomach irritation, and bleeding, which is why a PPI is prescribed alongside to protect the stomach',
    'If the patient has already tried over-the-counter NSAIDs such as ibuprofen without benefit, offer naproxen. If NSAIDs are not tolerated, offer paracetamol with or without codeine, but explain this will only control pain and not inflammation. Steroids such as prednisolone may also be used but should only be prescribed under rheumatology guidance',
    'Offer referral to physiotherapy, explaining that physiotherapists can teach exercises to improve symptoms and support early return to work',
    'Offer referral to a social prescriber who can provide information about financial support and benefits, such as Employment and Support Allowance (ESA) or Access to Work',
    'Reassure the patient that reactive arthritis is usually self-limiting, with symptoms typically resolving within 3–6 months',
    'If symptoms have not resolved after three months, consider referral to Rheumatology, as this may suggest progression to chronic reactive arthritis',
    'Arrange follow-up in 4 weeks to review progress and discuss the outcome of any investigations',
    'Safety net: advise the patient to seek urgent medical attention if symptoms worsen, if he is unable to move the joint, or if he develops a fever'
  ],
  'Thank you for calling today. I can hear that this has come on quite suddenly and is already having a real impact on your work and day-to-day life, so I''m glad you got in touch.

From what you''ve described — swollen, stiff, painful joints mainly in your knee and ankle, with more recent involvement of your lower back and buttock — and taking into account the diarrhoeal illness you had about four weeks ago after your holiday, I think I have a good idea of what might be causing this. This pattern is consistent with a condition called reactive arthritis. This is where the body''s immune system, having fought off an infection in the gut, continues to react and causes inflammation in the joints. It is a recognised complication of gut infections caused by bacteria such as Campylobacter, which was what we found in your stool sample.

The important thing to know, Ryan, is that reactive arthritis is usually a self-limiting condition — meaning that in the majority of cases it settles down on its own over a period of around three to six months, without causing any lasting damage to the joints.

That said, I''d like to see you in person so we can properly examine your joints and assess how things are. At that appointment, I''ll arrange some blood tests — including markers of inflammation and a test called HLA-B27 — which help us confirm the diagnosis and rule out other causes of joint inflammation such as rheumatoid arthritis.

In the meantime, I want to help you manage your pain and inflammation. I''d like to start you on an anti-inflammatory tablet called naproxen. This works differently from paracetamol — rather than just dulling the pain, it actively reduces the inflammation in the joints. Because anti-inflammatories can sometimes irritate the stomach, we always prescribe a stomach-protecting tablet alongside it. You should notice some improvement within a few days.

I''d also like to refer you to a physiotherapist who specialises in joint problems. They can work with you on exercises to keep the joints moving, reduce stiffness, and help you get back to work as quickly as possible.

I know the financial side of things is a real concern for you as a self-employed person. I''d like to connect you with our social prescriber, who can help you look into any financial support you may be entitled to while you''re unable to work — such as Employment and Support Allowance.

We''ll arrange a follow-up in four weeks to see how you''re getting on. If things aren''t improving after three months, we would refer you to a specialist at the hospital called a rheumatologist for further review. In the meantime, please seek urgent help if any joint becomes completely impossible to move, if you develop a high temperature, or if your symptoms deteriorate quickly.',
  ARRAY[
    'Reactive arthritis is a sterile, asymmetrical oligoarthritis of the lower limbs that typically develops 1–4 weeks after a gastrointestinal or genitourinary infection; common triggers include Campylobacter, Salmonella, Shigella, and Chlamydia trachomatis',
    'Reiter''s triad (arthritis, conjunctivitis, urethritis) should be actively screened for; uveitis, if present, requires same-day ophthalmology referral',
    'First-line blood tests include FBC, ESR, CRP, rheumatoid factor, antinuclear antibodies, and HLA-B27 (positive in up to 80% of cases)',
    'NSAIDs are the mainstay of symptom management and should be co-prescribed with a PPI; steroids should only be used under rheumatology guidance',
    'Reactive arthritis is usually self-limiting and resolves within 3–6 months; persistence beyond three months warrants referral to rheumatology to consider chronic reactive arthritis',
    'Social prescribing is a useful resource for self-employed patients unable to work due to a musculoskeletal condition, to help them access benefits such as ESA or Access to Work'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  183,
  'Persistent Back Pain in Young Female',
  'Rheumatology & Musculoskeletal',
  'Video Consultation',
  false,
  'Priya Sharma',
  '32-year-old female',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No Known Drug Allergy'],
  'Seen 6 weeks ago by Karen Bailey (Physiotherapist). Presenting Complaint: Patient self-referred to physiotherapy reporting low back pain persisting for 4 weeks, worsened at night and disrupting sleep. She describes occasional tingling to the right posterior thigh. No history of trauma. Patient works as a healthcare support worker in a residential care setting, requiring prolonged periods of standing. She denies lower limb weakness or changes in bladder and bowel function. Examination findings: Features consistent with non-specific mechanical low back pain. No clinical evidence of nerve root compression or serious spinal pathology. Plan: Exercises prescribed; review if no improvement. Telephone Consultation (3 weeks ago – Dr Alan Whitfield, Clinical Practitioner Role). Presenting Complaint: Recurrent low back pain with tingling in the right posterior thigh. Patient had previously been seen by a physiotherapist and advised on exercises, with no significant improvement since. Ibuprofen had not provided adequate pain relief. Plan: Face-to-face review not required as symptoms were stable with no red flags. Prescribed Naproxen 500 mg twice daily and Omeprazole 20 mg daily for gastric protection. Patient advised to continue physiotherapy exercises. Educated on cauda equina red flags and given safety-netting guidance.',
  'Patient has booked a routine video consultation to discuss ongoing back pain and review her symptoms.',
  '"Hi doctor, I wanted to speak to you about my back pain, which has been going on for about 10 weeks now. It''s been getting worse, and I''m also getting tingling at the back of my right thigh. The naproxen helps a little, but the pain is still really troubling me, especially at night."',
  'Her back pain has been present for around 10 weeks and has been gradually worsening. She has already seen a physiotherapist, who gave her exercises to do, but these have not made much difference. She also spoke to a GP three weeks ago who prescribed naproxen. This has taken the edge off slightly, but the pain is still worse at night. She has not experienced any weakness in her legs and has had no bladder or bowel symptoms.',
  ARRAY[
    'She has also noticed unintentional weight loss of about 8 kg over the past 10 weeks. In addition, she has been experiencing heavy night sweats and alternating feelings of being hot and cold, although she is not certain whether she has had a fever.',
    'Say NO to any other symptoms asked.'
  ],
  'She is a non-smoker and does not drink alcohol. She lives with her husband. She works as a healthcare support worker in a residential care home. Travel History: She has not travelled recently, but she was born in India and moved to the UK at the age of 19. Family History: No known family history of cancer or any other medical conditions.',
  'She is not sure what is causing her back pain.',
  'She has had to take 2 weeks off work because of the pain, and her manager is putting pressure on her to return. She does not feel any better.',
  'She would like the doctor to find a solution and help her get back to normal.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other symptoms asked.',
  ARRAY[
    'Ask about the onset of back pain',
    'Ask about the nature of the pain, aggravating and relieving factors, and whether the pain radiates',
    'Ask whether there is any weakness in one or both legs',
    'Ask about early morning back stiffness and, if present, how long it lasts. Note: Inflammatory back pain (e.g. axial spondyloarthritis, ankylosing spondylitis) typically causes early morning stiffness lasting more than 30 minutes, worse with rest and improving with movement. Mechanical back pain may also cause stiffness, but this usually resolves within 30 minutes',
    'Ask about any history of trauma or falls',
    'Ask about cauda equina red flags: urinary incontinence, urinary retention, faecal incontinence, perianal or perineal sensory loss (saddle paraesthesia)',
    'Ask about systemic symptoms such as weight loss, night sweats, and fever, to rule out malignancy and serious conditions such as spinal tuberculosis, discitis, or epidural abscess',
    'Ask about lumps or swellings around the neck (lymphadenopathy, which may be seen in TB or lymphoma)',
    'Ask about cough or shortness of breath',
    'Ask about recent travel or contact with anyone with a prolonged cough',
    'Ask about BCG vaccination status, for example by checking for a scar on the upper arm (BCG status does not rule TB in or out but provides useful background information)',
    'Ask about family history of cancers such as multiple myeloma, sarcoma, or lymphoma',
    'Ask about symptoms of hypercalcaemia, which may be associated with multiple myeloma: bone pain, abdominal pain, confusion, muscle weakness, constipation, thirst, and polyuria',
    'Ask about the impact of symptoms on daily activities and mood',
    'Ask about social history including occupation, smoking, and alcohol',
    'Ask about the patient''s ideas, concerns, and expectations',
    'Make a diagnosis of suspected Pott''s disease (tuberculosis of the spine), while also considering malignancy as an important differential to be ruled out'
  ],
  ARRAY[
    'Arrange a same-day face-to-face review to examine the back and carry out a full neurological assessment',
    'Offer urgent investigations: chest X-ray (to assess for possible pulmonary TB), lumbosacral spine X-ray, full blood count, urea and electrolytes, C-reactive protein (CRP), and erythrocyte sedimentation rate (ESR)',
    'Refer urgently to an infectious diseases specialist without waiting for investigation results — she should be seen within 1 week',
    'Explain to the patient that the specialist may arrange further investigations such as MRI of the spine and initiate treatment with antibiotics, and may involve spinal specialists if required',
    'Advise that, because she works in a care home, she should temporarily stay away from work until she has been fully assessed and pulmonary TB has been excluded by the specialist team, in order to protect vulnerable patients from potential transmission',
    'Provide a fit note for work',
    'Continue current analgesia for pain relief',
    'Safety net: advise the patient to seek urgent medical attention if she develops worsening pain, leg weakness, loss of bladder or bowel control, or numbness in the perineal region (possible cauda equina syndrome). Also advise her to contact the GP if she develops a cough, feels more unwell, or notices any new concerning symptoms',
    'Arrange follow-up in 1 week to confirm she has been seen by the specialist and that treatment has been initiated'
  ],
  'Thank you for coming on today. I can hear how much this back pain has been affecting you — not being able to work, the disrupted sleep, and now the pressure from your manager on top of everything. I want to make sure we get to the bottom of what''s going on, and I need to be honest with you about what I think might be happening.

Your back pain has now been going on for ten weeks, it''s getting worse rather than better, it''s particularly bad at night, and it hasn''t responded well to physiotherapy or naproxen. On its own, that picture might still suggest a muscular or mechanical problem — but you''ve also mentioned losing around 8 kilograms in weight over those same ten weeks without trying to, along with heavy night sweats and feeling feverish. These symptoms alongside persistent back pain in someone with your background do raise concern for a more serious underlying cause, and I need to take that seriously today.

One possibility I have to consider is a condition called spinal tuberculosis — sometimes referred to as Pott''s disease — which is an infection caused by the same bacterium that causes tuberculosis in the lungs, but affecting the spine. It can cause exactly the type of symptoms you''ve been describing. Priya, I want to be clear that this is something we need to rule out urgently, and I don''t want to wait any longer before acting.

What I''d like to do today is arrange for you to be seen face to face straight away so we can examine your back and check your neurological function — things like your sensation, reflexes, and muscle strength. I''d also like to arrange some urgent blood tests and X-rays, including a chest X-ray to look at the lungs, and I''m going to refer you to a specialist in infectious diseases who should see you within the week.

Because you work in a care home with vulnerable residents, I''m going to advise that you stay off work temporarily until the specialist has assessed you and we can be confident that you don''t pose a risk of infection to others. I know that adds to the pressure you''re already under, but it''s the right thing to do while we''re investigating. I''ll provide you with a fit note to cover this period.

Please continue taking the naproxen in the meantime for pain relief. However, I want you to seek urgent medical attention immediately if you notice any weakness developing in your legs, if you lose control of your bladder or bowels, or if you develop any numbness around your back passage or inner thighs — those symptoms would require emergency assessment. Also contact us if you develop a new cough or feel significantly more unwell. We''ll speak again in one week to make sure the specialist has seen you and that everything is in motion.',
  ARRAY[
    'Persistent back pain with systemic red flags (unintentional weight loss, drenching night sweats, fever) in a patient from a TB-endemic country should raise strong suspicion for spinal tuberculosis (Pott''s disease) until proven otherwise',
    'Urgent investigations include chest X-ray, lumbosacral spine X-ray, FBC, CRP, and ESR; the specialist will arrange MRI spine and microbiological sampling',
    'Urgent referral to an infectious diseases specialist should be made without waiting for results — the patient should be seen within 1 week',
    'Healthcare workers in care settings with suspected infectious TB should be advised to stay off work temporarily to protect vulnerable patients, and a fit note should be provided',
    'Cauda equina syndrome must be safety-netted explicitly: bladder or bowel dysfunction or perianal numbness requires emergency same-day assessment',
    'Malignancy (e.g. multiple myeloma, lymphoma, spinal metastases) must remain on the differential alongside spinal TB, and should be excluded through investigation'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  184,
  'Neonatal Eye Infection',
  'Paediatrics',
  'Video Consultation',
  false,
  'Alfie Stone',
  '12-day-old male',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No Known Drug Allergy. Mother: Sophie Grant (17 years old)'],
  'Seen 2 days ago by Karen Moss (Paediatric Nurse Practitioner). Presenting complaint: Mother reports yellowish discharge from both eyes for 2 days, with no associated fever or eye swelling. The infant is otherwise well. Examination: Mild conjunctival redness with mucopurulent discharge from both eyes. Normal vitals. Eye swabs taken. Plan: Eye swabs sent for culture. Review with culture results. Safety-netting and worsening advice provided. Laboratory Report. Specimen: Eye swab. Clinical details provided: Conjunctivitis, query chlamydial infection. Interpretation / Comment: Chlamydia trachomatis detected in eye swab, consistent with chlamydial conjunctivitis. Please treat as per national guidelines.',
  'Patient''s mother (Sophie Grant, 17 years old) has booked a video appointment to discuss the baby''s swab results.',
  '"Hi doctor, I was asked to book this appointment to go over my baby''s swab results."',
  'Four days ago, her son developed red eyes with sticky yellowish discharge from both eyes, which also became swollen. The nurse took eye swabs and asked her to book this appointment to discuss the results. He is otherwise feeding well and appears comfortable in himself. PBIND (Pregnancy, Birth, Immunisation, Nutrition, Development): Alfie was born at term by vaginal delivery with no complications. He is having all his immunisations as scheduled. He is growing well and is currently bottle fed.',
  ARRAY[]::text[],
  'She currently lives with her foster parents, who are looking after both her and Alfie. He is formula fed. She left school during pregnancy but plans to return to complete her GCSEs. She does not smoke or drink alcohol. If asked about her own health or symptoms: She is not currently sexually active. Her ex-boyfriend, who is 17 years old and the father of Alfie, ended the relationship approximately 6 months ago. She has had no contact with him since. Her last sexual encounter was around 6 months ago, and she has had no other partners. She has no abdominal pain, vaginal discharge, bleeding, urinary symptoms, or fever.',
  'The nurse mentioned it might be an eye infection, but she does not understand what type it is or how her baby caught it.',
  'She has no other concerns — she just wants her baby to be okay.',
  'She wants the doctor to explain the swab results and make sure Alfie receives the right treatment.',
  ARRAY['If told the baby has chlamydia, express shock and say: "How did my baby get chlamydia? I thought that was a sexually transmitted infection."'],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario.',
  ARRAY[
    'Check with the mother whether she understands why the swab was taken',
    'Ask about the baby''s current symptoms, including any discharge, swelling, or redness in the eyes',
    'Ask about the colour of the discharge',
    'Ask whether one or both eyes are affected',
    'Ask about red flag features of serious infection, including fever, persistent irritability with high-pitched or inconsolable crying, excessive sleepiness or floppiness, reduced responsiveness, poor feeding or refusal of feeds, neck stiffness, and reduced wet nappies',
    'Ask about PBIND history: pregnancy, birth, immunisation, nutrition (feeding method), and development',
    'Ask about social history, including home situation, who lives at home, the father of the child, financial support, and whether she is in education or working',
    'Ask about her mood and how she is coping',
    'Break the news sensitively, explaining that the swab confirmed chlamydia infection in the baby''s eyes',
    'Explain the likely mode of transmission: from mother to baby during vaginal delivery',
    'Signpost before asking personal questions, then ask about the mother''s health including sexual partners, vaginal discharge, abdominal or pelvic pain, fever, abnormal vaginal bleeding, and dysuria'
  ],
  ARRAY[
    'Arrange urgent same-day referral of the baby to paediatrics or ophthalmology for systemic antibiotic treatment and monitoring',
    'Offer sexual health screening and treatment to the mother',
    'Explain that the most appropriate setting for her to receive sexual health screening and treatment is a genitourinary medicine (GUM) clinic, which will also arrange contact tracing to ensure her ex-partner is tested and treated. If she does not feel able to inform her ex-partner directly, reassure her that the GUM clinic can carry out partner notification anonymously',
    'If she declines to attend a sexual health clinic, offer testing and treatment in primary care',
    'If screening is done in primary care, offer a self-taken vulvovaginal swab or a first-catch urine sample for diagnosis',
    'Do not wait for test results before offering treatment',
    'Antibiotics of choice: if not breastfeeding, prescribe doxycycline 100 mg twice daily for 7 days. If breastfeeding, prescribe erythromycin 500 mg twice daily for 14 days. Note that azithromycin is another option, but as it is present in breast milk, the BNF advises it should only be used if no suitable alternative is available',
    'Advise the mother that as she is taking Alfie straight to hospital today, the doctors will monitor him closely. However, if before arrival he develops a high fever, becomes floppy, feeds poorly, or shows any worrying changes, she should call 999 or seek urgent help immediately',
    'Provide safety-netting advice for the mother: advise her to seek urgent medical attention if she develops abdominal pain, fever, abnormal vaginal discharge, or any new concerning symptoms',
    'Arrange follow-up in 1–2 weeks to review how both mother and baby are doing'
  ],
  'Thank you for coming on today, and thank you for bringing Alfie in to be seen earlier this week. I know it''s been a worrying couple of days, and I want to go through the results carefully and make sure we have a clear plan for both Alfie and for you.

The swab taken from Alfie''s eyes has come back with a result. I want to explain this as clearly as I can, because I know it might come as a surprise. The swab has shown a germ called Chlamydia trachomatis, which means Alfie has a type of eye infection called chlamydial conjunctivitis. I completely understand that hearing the word "chlamydia" can be alarming — it is most commonly known as a sexually transmitted infection, which is why what I''m about to explain is so important.

Chlamydia can be passed from a mother to her baby during vaginal birth, without anyone knowing it was there beforehand. It often causes no symptoms in adults, particularly in women, which is why it can go undetected. This is not anyone''s fault. The most important thing right now is that Alfie is treated promptly, and he will be.

I am going to refer Alfie to the hospital today — he needs to be seen by a paediatrician straight away so that he can be given the right antibiotic treatment. This is a systemic treatment, meaning it works throughout the body, not just in the eyes. The team there will monitor him closely and make sure he is responding well. On your way to hospital, if at any point Alfie seems floppy, is struggling to feed, develops a high temperature, or anything feels wrong, please stop and call 999 straight away.

Sophie, because chlamydia can be passed on in the way I''ve described, it''s really important that you are also tested and treated. The best place for this is a sexual health clinic called a GUM clinic. They are experienced, completely confidential, and non-judgmental. They will test you and, if needed, treat you there. They will also arrange for your ex-partner to be informed and offered testing — and if you''d prefer not to contact him directly, the clinic can do this anonymously on your behalf.

If for any reason you''d prefer not to go to the GUM clinic, we can also arrange testing and treatment here in the practice. Because we act before results come back, the treatment would start straight away. If you are bottle-feeding Alfie — which you''ve told me you are — the antibiotic we would prescribe for you is doxycycline 100 mg twice daily for 7 days.

I also want to check in with you about how you are doing. You''re a young mum in a new situation, and this has been a lot to take in today. Please know that we are here to support both you and Alfie. We''ll arrange a follow-up in one to two weeks to make sure Alfie is responding to treatment and that your own results and any treatment needed are in place. Is there anything you''d like to ask me before we finish today?',
  ARRAY[
    'Neonatal chlamydial conjunctivitis (ophthalmia neonatorum caused by Chlamydia trachomatis) typically presents in the first 2 weeks of life with bilateral mucopurulent eye discharge and is acquired during vaginal delivery from an infected mother',
    'The baby requires urgent same-day referral to paediatrics or ophthalmology for systemic antibiotic therapy — topical treatment alone is insufficient',
    'The mother should be offered testing and treatment for chlamydia; GUM clinic referral is preferred for contact tracing and partner notification, which can be done anonymously if needed',
    'If treating the mother in primary care: doxycycline 100 mg twice daily for 7 days if not breastfeeding; erythromycin 500 mg twice daily for 14 days if breastfeeding. Azithromycin should only be used in breastfeeding women if no suitable alternative is available (BNF guidance)',
    'Treatment should not be delayed pending test results — offer treatment on clinical grounds',
    'A sensitive, non-judgmental approach is essential; safeguarding considerations must be held in mind when the mother is a minor living in foster care'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  185,
  'Abnormal Blood Test in Blood Donor',
  'General Practice',
  'Telephone Consultation',
  false,
  'Daniel Marsh',
  '39-year-old male',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No Known Drug Allergy'],
  'Letter from NHS Blood and Transplant Unit (1 week ago). Re: Daniel Marsh | 39 years old | Male. Dear GP, Mr Daniel Marsh attended our blood donation clinic to donate blood. As part of our routine pre-donation screening, a blood test was performed. The results demonstrated a raised mean corpuscular volume (MCV) with haemoglobin at the lower limit of normal. In view of this finding, Mr Marsh has been advised that he is not currently eligible to donate blood and has been referred to you for further assessment, investigation, and management as appropriate. Please see the attached full blood count results below. We would be grateful if you could kindly review this patient. Thank you for your attention. Yours sincerely, Heather Harrison, Senior Nurse, NHS Blood and Transplant. Full Blood Count Result. Test | Result | Reference Range. Haemoglobin (Hb) | 135 g/L | 135–175 g/L. Haematocrit (Hct) | 0.40 | 0.38–0.50. Red Blood Cell Count (RBC) | 3.9 × 10¹²/L | 4.3–5.7 × 10¹²/L. Mean Corpuscular Volume (MCV) | 107 fL | 83–101 fL. Mean Corpuscular Haemoglobin (MCH) | 34 pg | 27–32 pg. Mean Corpuscular Haemoglobin Concentration (MCHC) | 330 g/L | 320–360 g/L. White Blood Cell Count (WBC) | 6.2 × 10⁹/L | 4.0–11.0 × 10⁹/L. Platelet Count | 250 × 10⁹/L | 150–400 × 10⁹/L. Patient has booked a routine telephone appointment to discuss the letter from the blood donor clinic.',
  'Patient calling to discuss a letter received from the blood donation clinic following an abnormal blood test result.',
  '"Doctor, I went to the blood donor clinic and they told me I couldn''t donate blood because something came back abnormal in my blood test. I''m not entirely sure what it means, but they said they''d written to my GP, so I booked this appointment."',
  '',
  ARRAY[]::text[],
  'He lives alone and works as a delivery driver. He drinks approximately 8 cans of beer per day, which has been his pattern for the past 3 months following the breakdown of a long-term relationship. He does not smoke or use illicit drugs. His mood is fine and he does not feel depressed. If asked about driving: he confirms he drives for work. If asked CAGE alcohol screening questions, he answers No to all four. If the doctor offers help to cut down on alcohol, he accepts. If asked whether he has ever tried to cut down on his drinking and whether he experienced any symptoms, he responds that he has never tried to cut down — in fact his intake has increased from 7 to 8 cans per day.',
  'He is not sure what the blood test result means.',
  'He is worried about why the clinic suddenly told him he cannot donate blood, as he normally donates every year.',
  'He would like the GP to explain the blood results clearly.',
  ARRAY[
    'If the doctor offers help to cut down on alcohol, he accepts.',
    'If asked whether he has ever tried to cut down and whether he experienced any symptoms, he responds that he has never tried to cut down — in fact his intake has increased from 7 to 8 cans per day.'
  ],
  'When will I be able to donate blood again?',
  NULL,
  ARRAY[
    'Start by acknowledging that you can see from his records that he attended the blood donor clinic and was referred to the GP to discuss his results',
    'Ask whether he is currently experiencing any symptoms',
    'Ask specifically about neurological symptoms that may occur with vitamin B12 deficiency, such as blurred vision, tingling or numbness in the hands or feet, difficulty with balance or coordination (ataxia), muscle weakness, memory problems, or confusion',
    'Ask about general symptoms of B12 deficiency including persistent tiredness, headaches, mouth ulcers, loss of appetite, diarrhoea, and unintentional weight loss',
    'Ask about diet, particularly whether he is vegan or vegetarian, as B12 and folate deficiency is more common in these groups',
    'Ask about alcohol intake and establish a clear history',
    'Ask CAGE questions to screen for alcohol misuse: ask if he has ever felt he should Cut down on his drinking, if people have ever Annoyed him by criticising his drinking, if he has ever felt Guilty about his drinking, or if he has ever needed a drink first thing in the morning (Eye-opener) to steady his nerves or get rid of a hangover. Note: A score of two or more on the CAGE questions suggests a significant likelihood of an alcohol problem. Even a single "yes" response should prompt further assessment using a tool such as the AUDIT questionnaire',
    'Ask whether he has ever tried to reduce his alcohol intake and what happened, including whether he experienced any withdrawal symptoms (important for assessing severity of dependence and potential need for medical support)',
    'Ask whether he drives, as individuals with significant alcohol problems should not drive and must inform the DVLA',
    'Ask about other social history including smoking, illicit drug use (noting that nitrous oxide can cause vitamin B12 deficiency), and occupation',
    'Make a diagnosis of macrocytosis without anaemia, most likely related to excess alcohol intake'
  ],
  ARRAY[
    'Offer blood tests to investigate possible causes of macrocytosis, including repeat full blood count, vitamin B12, folate, thyroid function, and liver function tests',
    'Offer the patient the AUDIT questionnaire, explaining that it helps assess the extent of his alcohol intake and determine what level of support or intervention may be needed',
    'Advise reducing alcohol intake, explaining that excessive alcohol can cause the current blood picture and may also damage the liver and other organs in the long term',
    'Inform him that support services are available if he would like help reducing his alcohol intake',
    'Refer the patient to local community alcohol withdrawal services, explaining that cutting down suddenly on his own may cause withdrawal effects, and the community team can support him to do so safely',
    'Advise on maintaining a healthy, balanced diet',
    'Explain that if vitamin B12 or folate deficiency is identified, replacement therapy will be offered',
    'Advise him not to drive and to inform the DVLA, as driving is not permitted in the context of harmful or excessive alcohol use',
    'Inform the patient that he will only be able to donate blood again once any underlying cause of his blood results has been identified and treated, and once his alcohol intake is at a safe and stable level — blood donation services do not accept donations from people with ongoing harmful alcohol use',
    'Safety net: advise the patient to seek medical help if he develops symptoms of acute alcohol withdrawal such as tremors, agitation, palpitations, confusion, or restlessness',
    'Arrange follow-up in 2–3 days to review and discuss the blood test results'
  ],
  'Thank you for calling in today. It''s good to speak with you, and I''m glad you got in touch after receiving that letter from the donor clinic. Let me go through what the results show and what we can do to help.

When you went to donate blood, the clinic ran a routine blood test as part of their standard checks. What they found is that the size of your red blood cells is larger than normal — we call this macrocytosis. The red blood cells themselves look bigger under the microscope, even though the level of haemoglobin in your blood is just within the normal range. Does that make sense so far?

There are several things that can cause this. One common reason is low levels of certain vitamins — particularly vitamin B12 or folate — which the body needs to make red blood cells properly. Another cause can be the thyroid gland not working as it should; the thyroid is a small gland in the neck that regulates the body''s energy, and when it''s underactive it can produce this kind of result. Liver problems can also cause this pattern. And alcohol, when consumed regularly in significant amounts, is a well-recognised cause of enlarged red blood cells — even in people who feel completely well.

Daniel, from what you''ve told me about your drinking over the past three months, I think this may well be playing a role in your blood result. Drinking at that level can affect the blood and the liver, even without you noticing any obvious symptoms. I want to help you with that, and I''ll come back to it in a moment.

What I''d like to do first is arrange some blood tests — to check your vitamin B12, folate, thyroid function, and liver health. This will give us a full picture of what''s going on. Would you be happy to have those done?

Now, in terms of the alcohol — I''m not here to judge you at all. It sounds like the past few months have been a really difficult time personally, and it makes complete sense that you''ve been looking for ways to get through it. But I do want to be straight with you: drinking at 8 cans a day puts quite a significant strain on your body, and it''s likely contributing to this blood result. Cutting back would make a real difference to your health.

I''d suggest we send you a short questionnaire called the AUDIT — it''s designed to help us work out what level of support might be most useful for you. I can also put you in touch with a local community alcohol service who can help you reduce your intake safely. I want to make that clear: cutting down suddenly and on your own can sometimes trigger withdrawal symptoms — things like shakiness, restlessness, a racing heartbeat, or confusion. If you ever notice any of those symptoms, please seek medical help straight away.

There is also one important practical matter I need to raise. Because of the level of drinking you''ve described, the DVLA requires you to let them know, and for your own safety and the safety of other road users, you should stop driving for now. I understand that''s a significant thing, especially given your work — but it is a legal requirement, and the most important thing is that you and others are kept safe while we work on getting things under control.

You asked when you''ll be able to donate blood again. Once we''ve found out what''s causing this blood result and addressed it — whether that''s vitamins, thyroid, or getting your alcohol intake to a safer level — the donation service can look at your eligibility again. But we need to sort things out first. Does that all make sense? Let''s arrange those blood tests, and I''ll speak to you again in a couple of days when the results are back.',
  ARRAY[
    'Macrocytosis (raised MCV) without anaemia is a common incidental finding; key causes include alcohol misuse, hypothyroidism, liver disease, vitamin B12 or folate deficiency, and drugs such as methotrexate or hydroxycarbamide',
    'Investigations should include repeat FBC, vitamin B12, folate, thyroid function tests, and liver function tests; a blood film and reticulocyte count are also helpful',
    'The CAGE questionnaire is a rapid screening tool for alcohol misuse — a score of two or more warrants full assessment with the AUDIT questionnaire; even one "yes" should prompt further enquiry',
    'Patients with harmful or dependent alcohol use must be advised to stop driving and inform the DVLA — this is a legal requirement as well as a safety issue',
    'Sudden alcohol cessation can precipitate withdrawal (tremors, agitation, palpitations, seizures); patients should be supported to reduce gradually via community alcohol withdrawal services rather than stopping abruptly at home',
    'Blood donation eligibility cannot be reinstated until the underlying cause is identified and treated, and alcohol intake is at a safe and stable level'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  186,
  'Insomnia in Elderly Woman with Dementia',
  'Elderly Medicine & Palliative Care',
  'Telephone Consultation',
  false,
  'Margery Collins',
  '84-year-old female',
  ARRAY[]::text[],
  ARRAY['Memantine hydrochloride 10 mg once daily','Amlodipine 10 mg once daily','Atorvastatin 20 mg once daily','No Known Drug Allergy','Lives in a care home'],
  'Caller: Carer from care home, Janet Pearce, phoning to discuss concerns about the patient.',
  'Carer from the care home calling on behalf of the patient to discuss sleep disturbance and request sleeping tablets.',
  '"Hi doctor, I''m calling on behalf of one of our residents, Margery Collins, who I understand is one of your patients. I''d like to request some sleeping tablets for her."',
  'She has been having difficulty sleeping and is wandering around at night, which is disturbing other residents and sometimes keeping them awake. This has been going on for the past 4 days. There has been no worsening of her memory, and she has not shown any signs of aggression. She appears otherwise stable, with no fever and no cough.',
  ARRAY[
    'She has not opened her bowels for 5 days.',
    'She has long-standing urinary incontinence and uses pads.',
    'She has no urinary symptoms and has not complained of any abdominal pain.',
    'She does not appear to be in pain and has not had any falls.',
    'She has been living in the care home for the past 9 months.',
    'She is eating and drinking well.',
    'Recent observations: BP 120/85 mmHg, Pulse 78 bpm, Respiratory rate 17 breaths per minute, Temperature 36.5°C.',
    'If asked about a urine sample: She is incontinent and uses pads, so it may be difficult to obtain a clean urine sample.'
  ],
  'She lives in the care home. Her son is her next of kin and holds lasting power of attorney for health and finance. He visits twice a month and has been made aware of the current situation. The patient does not smoke or drink alcohol.',
  'The carer suspects she has insomnia.',
  'The carer is worried that she is disturbing other residents at night and that she might have a fall.',
  'The carer would like the GP to prescribe sleeping tablets.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY[
    'Ask about the onset and duration of the sleep disturbance',
    'Ask whether her sleep was previously normal before this episode',
    'Ask about any recent changes in her environment, regular carers, or daily routine',
    'Ask whether she experiences daytime sleepiness and what activities she engages in during the day (being active during the day promotes natural tiredness at bedtime and may reduce anxiety and restlessness; avoiding long daytime naps helps maintain a normal sleep–wake cycle)',
    'Ask whether she has been unwell recently, for example cough, fever, sore throat, or any reported pain or discomfort',
    'Ask whether she is eating and drinking adequately',
    'Ask whether she appears more confused than usual',
    'Ask whether she has been aggressive or has attempted to harm herself, other residents, or staff',
    'Ask about bowel habits, including constipation or diarrhoea (constipation is a common and reversible cause of sleep disturbance, agitation, and confusion in older adults; if constipation is present, ask about symptoms suggestive of faecal impaction such as hard lumps, abdominal pain, bloating, or overflow incontinence)',
    'Ask about urinary symptoms such as frequency, smelly urine, abdominal pain, or haematuria',
    'Ask whether she has recently started any new medication',
    'Ask about her mood and whether she appears more withdrawn than usual',
    'Make a working diagnosis of insomnia, likely secondary to constipation'
  ],
  ARRAY[
    'Explain to the carer that constipation is likely contributing to the sleep disturbance, and that treating the constipation may restore normal sleep',
    'Offer laxatives to help relieve constipation. Begin with a first-line bulk-forming agent such as ispaghula husk (Fybogel). If Fybogel is offered, emphasise the importance of adequate fluid intake to avoid worsening constipation or risk of intestinal obstruction',
    'If Fybogel has been tried without improvement, consider macrogol, lactulose, or senna (particularly if stools are soft but difficult to pass)',
    'If faecal impaction is suspected, offer a suppository such as bisacodyl for soft stools, glycerol alone or glycerol with bisacodyl for hard stools, or a mini enema such as docusate. Confirm whether a district nurse or carer is able to administer the enema. If not, offer a high-dose oral macrogol',
    'Encourage non-pharmacological sleep hygiene measures, including exposure to natural daylight, increased daytime activity, engagement in personalised activities, keeping the bedroom quiet, dark, and at a comfortable temperature, and minimising caffeine or stimulating drinks in the evening',
    'Explain that being active during the day promotes tiredness at bedtime and reduces anxiety and restlessness',
    'Ask whether one-to-one carer supervision can be arranged temporarily at night to reduce the risk of falls and ensure her safety during restless periods',
    'Recommend anti-fall measures including anti-fall stockings, properly fitting footwear, and personal alarms. Ensure the environment is dementia-friendly, free from hazards, and has good lighting throughout the night',
    'Offer to contact the care home in 3–4 days to review progress; if there is no improvement, a home visit can be arranged for further assessment',
    'Provide safety-netting advice: if symptoms do not improve, or if Margery becomes aggressive or poses a risk of harm to herself or others, urgent medical attention should be sought immediately'
  ],
  'Thank you, Janet, for calling and for explaining what''s been happening with Margery. From what you''ve described, she has been restless and wandering at night for the past four days, with increased daytime drowsiness. I can understand why that''s concerning for you, for the other residents, and especially for her safety.

You''ve mentioned asking about sleeping tablets, and I completely understand why that seems like a logical solution. However, I''d ask you to bear with me, because in older adults — and particularly in someone with Margery''s condition — sleeping tablets such as zopiclone can actually make things worse. They increase the risk of falls, cause daytime drowsiness, and can further impair thinking and coordination. They can also lead to dependence and reduced effectiveness over time. So before we go down that route, I''d like us to look at what might actually be causing this change.

Something that struck me from what you''ve shared is that Margery hasn''t opened her bowels in five days. This is really important, because constipation is one of the most common — and very treatable — causes of sleep disturbance, agitation, and restlessness in older adults with dementia. People who cannot communicate their discomfort clearly will often become unsettled in other ways, and I think this may well be what''s driving her nighttime restlessness.

I''d like to start by treating the constipation. I''ll prescribe a laxative — something like ispaghula husk, which is gentle and works by adding bulk to the stool. It''s important that she drinks enough fluids alongside it, as it won''t work without adequate hydration and can actually worsen things without it. If that doesn''t help within a couple of days, we can step up to something stronger.

In parallel, there are some practical things that can really help with sleep. Encouraging Margery to be active and engaged during the day — even with gentle activities she enjoys — helps promote natural tiredness at bedtime. Exposure to natural daylight during the day is also beneficial. In the evenings, keeping her room quiet, dark, and at a comfortable temperature, and avoiding caffeinated drinks after lunchtime, can all make a meaningful difference.

On the subject of falls — I''m glad you raised this. Is there any possibility of arranging one-to-one carer supervision for Margery during the night, at least temporarily, until things settle? It would significantly reduce the risk of her having a fall while wandering. In the meantime, please make sure she is wearing properly fitting footwear, that her personal alarm is within reach, and that the corridors and her room have adequate lighting overnight.

I''ll ring you in three to four days to see how she is getting on. If there is no improvement by then, I will arrange to come and see her in person so we can assess things further. In the meantime, if her behaviour changes significantly — if she becomes aggressive, distressed, or poses any risk of harm to herself or others — please seek urgent medical attention straight away.',
  ARRAY[
    'Sleep disturbance and nocturnal agitation in patients with Alzheimer''s dementia often have reversible causes — constipation, pain, infection, and environmental changes should all be actively sought before considering pharmacological treatment',
    'Constipation is a frequently overlooked cause of restlessness and sleep disruption in elderly patients with dementia who may be unable to articulate their discomfort; first-line treatment is a bulk-forming laxative such as ispaghula husk (Fybogel), prescribed with adequate fluid intake',
    'Zopiclone and other hypnotics carry significant risks in elderly patients with dementia, including increased falls, daytime sedation, cognitive impairment, and long-term dependence — they should only be considered after non-pharmacological measures have been optimised',
    'According to NICE guidance, melatonin should not be offered to manage insomnia in people with Alzheimer''s disease, as evidence does not support its effectiveness in this population',
    'Non-pharmacological sleep interventions include natural daylight exposure, structured daytime activity, avoiding daytime naps, a calm and comfortable sleep environment, and reducing evening caffeine',
    'If agitation or aggression leads to a risk of harm, a short course of lorazepam may be appropriate pending old age psychiatry review; antipsychotic therapy should only be initiated under specialist guidance'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  187,
  'Aggression in Patient with Pick''s Disease',
  'Mental Health',
  'Telephone consultation',
  false,
  'Margaret Haynes',
  '71-year-old female',
  ARRAY[]::text[],
  ARRAY['Donepezil 5mg once daily','No Known Drug Allergy'],
  'Letter from the Department of Old Age Psychiatry (2 months ago) Dear Colleague, RE: Margaret Haynes | 71-year-old | female Thank you for referring this lady for assessment of cognitive and behavioural changes. On review in clinic today, clinical examination, cognitive testing and neuroimaging were all consistent with a diagnosis of frontotemporal dementia (Pick''s disease variant). Blood investigations including full blood count, erythrocyte sedimentation rate (ESR), C-reactive protein (CRP), urea and electrolytes, calcium, HbA1c, liver function tests, thyroid function tests, serum B12 and folate levels were unremarkable. We have commenced Mrs Haynes on donepezil 5mg once daily. We will review her progress in our department in 6 months'' time. In the interim, please do not hesitate to contact us if any concerns arise. Thank you for your ongoing care. Yours sincerely, Dr Philip Cosgrove MBChB FRCPsych Consultant Old Age Psychiatrist Caller: Susan Haynes, the patient''s daughter and next of kin. She holds Lasting Power of Attorney (LPA) for both health and finance.',
  'The patient''s daughter has arranged a telephone consultation to speak with the GP about her mother''s worsening behaviour and increasing aggression at home.',
  'Hi doctor, I''m calling about my mum. She has been getting really aggressive over the past couple of months and things don''t seem to be improving at all.',
  'My mum was diagnosed with Pick''s disease a few months ago and was started on a medication that was supposed to slow down how the condition progresses. My dad has been finding it very hard to cope because she''s become increasingly irritable and argumentative. She shouts at him regularly, and on two occasions she actually locked him out of the house until I arrived and managed to calm her down. She doesn''t seem to remember any of it afterwards. She''s also become very rigid about her routines — she insists on watching the same TV programmes every evening, even if she''s already seen them. If anything disrupts that routine she becomes extremely distressed and starts shouting. She has never hurt herself or anyone else, including my dad.',
  ARRAY[]::text[],
  'She lives at home with my dad. She doesn''t smoke or drink. She used to be a primary school teacher before she retired. There are no professional carers involved at the moment — my dad is her main carer. We would both prefer she stays at home because my dad is devoted to her. She no longer drives. I live about ten minutes away and visit every two to three days.',
  'I think her condition is getting worse.',
  'My dad is struggling more and more, but he really doesn''t want her to go into a nursing home.',
  'I''d like some guidance on what I should do and how best to handle the situation.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything the doctor offers.',
  ARRAY['Confirm consent to discuss the patient with her daughter and verify her Lasting Power of Attorney (LPA) status.','Ask about the onset of the aggressive and concerning behaviours.','Establish whether there are any immediate safety concerns for the patient or her husband, including any risk of harm or history of physical violence towards herself or her husband.','Ask specifically what behaviours or symptoms the patient is displaying.','Ask whether there are particular times of day when behaviour worsens, and if there are identifiable triggers such as changes in routine, hunger, thirst, or conflict.','Ask whether the symptoms are improving, worsening, or staying the same.','Ask whether the behavioural symptoms started around the time donepezil was initiated by the psychiatrist. (People with frontotemporal dementia should not be offered memantine or acetylcholinesterase inhibitors such as donepezil, as these can worsen behavioural and cognitive symptoms by affecting cholinergic systems that are not the primary issue in frontotemporal dementia.)','Ask about the patient''s mood and whether she seems more withdrawn than usual.','Ask about symptoms that may indicate delirium or other reversible causes, such as fever, cough, breathlessness, urinary symptoms, constipation, diarrhoea, abdominal pain, or any recent fall or head injury.','Ask about diet and fluid intake to assess for possible dehydration or nutritional triggers.','Ask about the home situation, including who lives with the patient, who her main carer is, and what level of support is currently in place.','Ask about smoking and alcohol use.','Ask about driving status, and if still driving, advise that she must stop and notify the DVLA of her diagnosis.','Ask about the daughter''s ideas, concerns, and expectations.','Make a working diagnosis of behavioural and psychological symptoms of Pick''s disease (frontotemporal dementia), with donepezil likely contributing to the worsening of these symptoms.'],
  ARRAY['Explain that her mother''s symptoms are consistent with what can occur in people with frontotemporal dementia (Pick''s disease), as this condition affects the parts of the brain responsible for behaviour, personality, and emotional control.','Inform her that the medication donepezil may also be contributing to these behavioural changes.','Offer to discuss the case with the Old Age Psychiatry team to review the medication and determine whether donepezil should be discontinued.','Explain that the psychiatry team may consider other medications, such as antipsychotics or selective serotonin reuptake inhibitors (SSRIs), to help manage agitation or behavioural symptoms if required.','Advise her to remove potential hazards from the home or keep them out of her mother''s reach — such as knives, sharp objects, cleaning products, or other dangerous items — to maintain safety.','Advise the use of verbal and non-verbal de-escalation techniques, including active listening, calm and reassuring responses, and the use of pictures or symbols to aid communication and reduce agitation.','Offer to make a referral to the safeguarding team for a home situation and care needs assessment, as her father may be struggling to cope and carers or additional support may be needed.','Offer respite care (temporary accommodation in a care home) as an alternative option while the psychiatry team reviews and adjusts her medication. This can provide a period of stability, particularly if the daughter is concerned about her father''s safety or if he is finding the situation very difficult to manage.','Provide safety-net advice to seek urgent medical attention if her mother becomes violent, poses a risk to herself or others, or if her father is no longer able to manage safely at home.'],
  'Thank you so much for reaching out today — it sounds like things have been really difficult at home, and I can hear how worried you are about both your mum and your dad. What you''re describing, with your mum becoming increasingly irritable, argumentative, and resistant to any change in her routine, can happen in people with her type of dementia, which is called frontotemporal dementia or Pick''s disease. This condition affects the parts of the brain that control behaviour, personality, and emotional regulation, which is why people can become very rigid in their habits and react strongly when things don''t go as expected.

I do want to be open with you about something important, Susan. It is possible that the medication your mum is currently taking, donepezil, may actually be making things worse rather than better. Donepezil is useful in some types of dementia, but in frontotemporal dementia it can sometimes worsen behaviour and thinking because it works on a part of the brain that isn''t the main area affected in this condition. I think this is something we urgently need to review.

My plan would be to contact the Old Age Psychiatry team today to discuss your mum''s case. They will be able to advise on whether donepezil should be stopped and whether a different medication — such as an antidepressant called an SSRI or a low-dose antipsychotic — might help to reduce her agitation and stabilise her mood. I wouldn''t want to stop the donepezil without specialist guidance first, but I will make sure this is flagged as a priority.

In the meantime, there are some practical things that can help at home. It would be important to make the environment as safe as possible by keeping potentially dangerous items — such as knives, sharp objects, or cleaning products — well out of your mum''s reach or locked away. When she becomes distressed, try to use calm, gentle communication. Speak quietly, avoid getting into arguments, and use reassuring body language. If words are becoming difficult, simple pictures or visual cues can sometimes help reduce her anxiety.

I would also like to refer your family to the safeguarding and social care team for a full care needs assessment. Your dad is clearly doing a wonderful job, but it sounds as though he may need more support, and we want to make sure the right help is in place for both of them. This could include arranging professional carers to come in during the day or at other times when the situation is more challenging.

Another option I want to mention is respite care. This would involve your mum staying temporarily in a care home while the psychiatry team adjusts her treatment and gets her symptoms more under control. It doesn''t mean a permanent move — it is simply a way of giving everyone a chance to stabilise and recover. I understand your dad''s wish to continue caring for her at home, and we absolutely respect that. But it is worth knowing this option exists, especially if things become harder to manage.

Please do not hesitate to call us or NHS 111 if your mum becomes violent, causes harm to herself or your dad, or if your dad reaches a point where he can no longer keep her safe at home. Your family''s safety is the priority, and we are here to support you through this.',
  ARRAY['Frontotemporal dementia (Pick''s disease) causes behavioural and psychological symptoms including agitation, aggression, and rigid routines, which are distinct from other dementia types.','Acetylcholinesterase inhibitors such as donepezil and memantine are contraindicated in frontotemporal dementia as they can worsen behavioural and cognitive symptoms — always review medications in this context.','Management of challenging behaviour in dementia should combine non-pharmacological strategies (calm communication, de-escalation, routine, safe environment) with pharmacological review in collaboration with the Old Age Psychiatry team.','Carer burden must be assessed proactively — a referral for care needs assessment and consideration of respite care are important management steps when the home situation is at risk of breaking down.','Driving must cease and the DVLA must be notified once a diagnosis of dementia is established.','Safety-netting is essential: families must know when to seek urgent help, particularly if the patient poses a risk of harm to herself or others.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  188,
  'HRT Use and Breast Cancer Risk',
  'Gynaecology & Women''s Health',
  'Video consultation',
  false,
  'Rachel Hughes',
  '53-year-old female',
  ARRAY[]::text[],
  ARRAY['Evorel Conti (Estradiol with norethisterone) Patches — apply one patch twice weekly continuously','No Known Drug Allergy'],
  'Patient booked a routine video consultation to discuss some concerns.',
  'The patient has booked a routine video consultation to discuss concerns about her hormone replacement therapy in the context of a close family member''s recent breast cancer diagnosis.',
  'Hi doctor, I''d like to talk about whether I should stop my hormone replacement therapy.',
  'I''ve been on HRT for about two years, which I started when I went through the menopause. It really helped with my hot flushes and my mood improved a lot. However, my sister was diagnosed with breast cancer six weeks ago and is waiting for surgery and further treatment. She''s 55 and was told that her HRT might have contributed to her developing breast cancer. The cancer was in her left breast only. There''s no other family history of breast, ovarian, prostate, or any other cancer in our family, and we don''t have any Jewish ancestry. I feel well at the moment and haven''t noticed any lumps or changes in my breasts. My mood is stable and all my menopausal symptoms are well controlled. I''ve had no abnormal vaginal bleeding. I do regular breast self-examinations. My last NHS breast screening was two years ago and came back normal — I think I''m due the next one next year.',
  ARRAY[]::text[],
  'I don''t smoke and I don''t drink alcohol. I work as an estate agent. I live with my husband and two children. My diet isn''t great and I don''t exercise much.',
  'I believe that HRT increases the risk of breast cancer.',
  'I''m worried that I might develop cancer because of the HRT I''m taking.',
  'I''d like the GP to explain my personal risk and advise me on whether it would be sensible to stop the HRT.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything the doctor offers.',
  ARRAY['Ask why she is considering stopping HRT.','Acknowledge and empathise with her about her sister''s breast cancer diagnosis, and ask how her sister is coping at the moment.','Ask how old her sister is and whether the diagnosis involved one breast or both. (One first-degree relative with bilateral breast cancer diagnosed before the age of 50 is considered high risk and warrants referral to secondary care breast services for genetic testing.)','Ask how long she has been on HRT.','Ask about the original reason for starting HRT and whether her menopausal symptoms have now resolved. (This will guide management by helping determine suitable alternatives if she decides to stop HRT — for example, non-hormonal vaginal moisturisers or lubricants for vaginal dryness, and cognitive behavioural therapy (CBT) or SSRIs for hot flushes and mood symptoms.)','Ask whether she performs regular breast self-examinations and whether she has noticed any changes such as lumps, nipple discharge, skin dimpling, or pain.','Ask about any vaginal bleeding, spotting, or discharge, as postmenopausal bleeding always requires urgent investigation.','Ask whether she has noticed any other systemic symptoms such as weight loss, fatigue, or loss of appetite.','Ask about her mood and how she is coping emotionally with her sister''s diagnosis.','Ask about any other family history of breast cancer (including male breast cancer), ovarian, prostate, pancreatic, sarcoma, or any other type of cancer beyond her sister.','Ask if her sister''s cancer is known to be hormone receptor positive, and whether any genetic testing such as BRCA testing has been discussed or offered to the family.','Ask about Jewish ancestry. (Certain ethnic backgrounds, particularly Jewish heritage, are associated with a higher risk of BRCA gene mutations.)','Ask about lifestyle and social history including smoking, alcohol intake, occupation, home situation, diet, and level of physical activity.','Explore her ideas, concerns, and expectations.'],
  ARRAY['Acknowledge her concern and empathise with her about her sister''s recent breast cancer diagnosis, recognising how worrying this must be.','Explain that she is right that HRT does increase the risk of breast cancer, and that this risk rises with the duration of use. The risk gradually declines after stopping HRT but can persist for up to 10 years after discontinuation.','Reassure her that, based on her history and current information, her personal risk remains low, and that the benefits of HRT for up to five years of use are likely to outweigh any potential harm.','Emphasise the importance of following up on her sister''s case, particularly to find out whether any genetic testing such as BRCA testing has been carried out, as a positive result could alter her own risk assessment.','Inform her that aside from HRT, other factors can influence breast cancer risk. Research has shown that being overweight and having a low level of physical activity can increase the risk. Sensitively explain that adopting a healthier lifestyle — increasing physical activity, eating a balanced diet, and working towards gradual weight reduction — can help lower her risk and improve her overall wellbeing.','Advise that if she chooses to stop HRT, non-hormonal options are available to manage symptoms: for vaginal dryness, recommend non-hormonal vaginal moisturisers or lubricants; for hot flushes or mood changes, suggest cognitive behavioural therapy (CBT) as first-line, or SSRIs/SNRIs such as venlafaxine as alternatives.','Advise her to keep in touch with her sister''s progress, particularly to find out whether genetic testing has been done. Explain that this information will help determine whether she also needs genetic counselling or a referral to a genetic clinic. Reassure her that, for now, based on her family history, there is no immediate need for a genetic referral.','Offer to send her patient information leaflets about HRT and breast cancer risk for her understanding and reassurance.','Encourage her to continue regular breast self-examinations and to report any new lumps, pain, nipple changes, discharge, or swelling around the armpit urgently.','Offer a follow-up appointment in 2–3 weeks to check whether her sister has had any genetic testing, as the results may influence the decision about whether to stop HRT and whether a referral to a genetic clinic is needed.'],
  'Thank you for bringing this to me today, Rachel — and I''m really sorry to hear about your sister. A breast cancer diagnosis in someone you''re close to is understandably frightening, and it makes complete sense that you''ve been thinking about your own situation. Let me try to help you make sense of things.

You''re right that HRT does carry a slightly increased risk of breast cancer, and that risk does tend to go up the longer it''s used. However, it''s equally important to know that this risk begins to fall again after stopping HRT, although it can take up to around ten years to return to baseline. That''s worth bearing in mind when weighing up your options.

Based on everything you''ve told me today, your personal risk of breast cancer currently appears to be low. Your sister''s cancer was in one breast only, she is 55, and as far as you''re aware there is no other family history of breast, ovarian, or related cancers. For most women in a similar situation to yours, the benefits of HRT for up to around five years of use — in terms of managing hot flushes, protecting mood and quality of life — are likely to outweigh the potential risks. That said, this is absolutely your decision, and I want to make sure you feel fully informed.

One important thing we should keep an eye on is whether your sister''s doctors decide to carry out genetic testing, for example testing for a BRCA gene mutation. If that result comes back positive, it could change how we assess your own risk, and we would want to refer you to a genetics clinic at that point. For now, based on what we know, there is no reason to refer you urgently, but it''s something worth revisiting once her results are available.

Alongside HRT, there are a few lifestyle factors that can also affect breast cancer risk. Research suggests that being overweight and doing little physical activity can both modestly increase the risk. I appreciate that making changes isn''t always easy, but even small and gradual steps — like building more movement into your day, eating a more balanced diet, and working towards a healthier weight — can make a meaningful difference to your overall health and wellbeing.

If you do decide you''d prefer to stop HRT, that is absolutely fine and we can support you with that. There are non-hormonal alternatives that can help manage symptoms. For any vaginal dryness, we can recommend vaginal moisturisers or lubricants. If hot flushes or mood changes become a problem, the first option we''d suggest is cognitive behavioural therapy (CBT), which has good evidence behind it. Medications such as venlafaxine or other SSRIs can also be considered as alternatives.

Whatever you decide, please do continue with your regular breast self-examinations — at least once a month — and keep attending your NHS breast screening when it''s due. If you ever notice a new lump, any nipple changes, discharge, skin dimpling, or swelling under the arm, please contact us straight away rather than waiting. I''d also like to offer you a follow-up in a couple of weeks once you''ve had a chance to digest all of this, and ideally once you know more about your sister''s situation.',
  ARRAY['HRT does increase the risk of breast cancer, and the risk rises with duration of use; it begins to fall after stopping but can persist for up to 10 years.','A woman with one first-degree relative with unilateral breast cancer diagnosed over the age of 50 is generally at low to population-level risk and does not automatically require referral for genetic testing.','Referral to secondary care breast services for genetic assessment is indicated if, for example, a first-degree relative had bilateral breast cancer diagnosed under the age of 50, or if multiple family members are affected.','If a woman wishes to stop HRT, non-hormonal alternatives include vaginal moisturisers/lubricants for vaginal dryness, and CBT or SSRIs/SNRIs such as venlafaxine for hot flushes and mood symptoms.','Following up on whether a family member has undergone BRCA genetic testing is clinically important, as a positive result could alter the patient''s own risk classification and trigger a genetics referral.','Lifestyle factors including obesity and physical inactivity independently increase breast cancer risk — addressing these should form part of the management conversation.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  189,
  'Intermittent Diplopia in Young Adult',
  'ENT & Eye',
  'Video consultation',
  false,
  'Ryan Fletcher',
  '23-year-old male',
  ARRAY[]::text[],
  ARRAY['Not currently on any medication','No Known Drug Allergy'],
  'Letter from Private GP (5 weeks ago) Dear Colleague, Re: Mr Ryan Fletcher | 23 years old | Male Mr Ryan Fletcher attended my private practice for assessment of intermittent double vision, which he reports has been present for approximately two years. The diplopia occurs mainly when he turns his eyes to the side and worsens with prolonged computer use, including gaming. Symptoms resolve when he looks straight ahead. He denies any headaches, blurred vision, eye pain, weakness, or other neurological symptoms and otherwise feels well. On examination, cranial nerves were intact and a full neurological assessment revealed no focal neurological deficits. General health appeared good. Mr Fletcher would like his ongoing care to continue under the NHS. I advised him to attend an optician for a comprehensive eye examination including refraction and assessment for binocular vision or ocular alignment problems. I would be grateful if you could reassess him in around four weeks, or sooner if his symptoms change or worsen. Yours sincerely, Dr Emily Graham MBBS MRCGP Private General Practitioner Letter from Vision Care High Street Opticians (3 weeks ago) Eye Examination Report Reason for Visit: Routine sight test with reported double vision (diplopia), ongoing for 2 years. No headaches, trauma, or systemic symptoms. Family history: None relevant. Medical history: None. Visual acuity: Right eye 6/6, Left eye 6/6, Both eyes 6/6. Intraocular pressure: Right eye 15 mmHg, Left eye 14 mmHg (within normal range 10–21 mmHg). Posterior Segment (Fundus Biomicroscopy) Optical Coherence Tomography (OCT) Scan — Macular and RNFL thickness: RE 265 μm, LE 260 μm (normal <300 μm). No cystoid spaces, epiretinal membrane, or subretinal fluid. 100 μm, LE 98 μm (normal 90–120 μm). Quadrants symmetrical; no optic nerve head swelling or pallor or optic neuropathy. Assessment: Normal visual acuity, intraocular pressures, and OCT findings. No ocular pathology identified. Optometrist: Sarah Archbold MCOptom (GOC Registration 123456). Patient has booked a routine video consultation to discuss his results.',
  'The patient has booked a routine video consultation to follow up on a two-year history of intermittent double vision, following recent review by a private GP and optician.',
  'Hi doctor, I''ve been having double vision on and off for the past two years and my mum felt it was time I got it properly looked into.',
  'The double vision started about two years ago and hasn''t really changed since then. I mainly notice it when I move my eyes to the side — it goes away completely when I look straight ahead. It''s not there all the time; it comes and goes. It tends to get worse when I''ve been staring at a screen for a long time. I spend a lot of time gaming and I''m also teaching myself game development, so I''m in front of a screen for roughly 10 to 14 hours a day. I don''t have any headaches, blurred vision, eye redness, weakness, or any other physical symptoms and I feel well in myself. I''ve already been seen by the optician and a private GP, and both said everything looked normal.',
  ARRAY['If the doctor asks you to close one eye, say that the double vision disappears when you do so. Family History: No family history of eye disease or any other medical condition.'],
  'I don''t smoke, drink alcohol, or use any recreational drugs. I live with my parents, I''m not currently working, and I receive Universal Credit. My parents also help support me financially. I''m an only child. I don''t drive.',
  'I''m not really sure what''s causing the double vision.',
  'My mum is worried it could be something serious, which is why she encouraged me to come. Personally I''ve got used to it and it doesn''t worry me much.',
  'I''d like the GP to explain what might be going on and sort it out if possible.',
  ARRAY['If the doctor asks you to close one eye, say that the double vision disappears when you do so. Family History: No family history of eye disease or any other medical condition.'],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything the doctor offers.',
  ARRAY['Ask about the onset and duration of the double vision.','Ask if the double vision occurs when looking in specific directions — for example, when looking to the side or up and down.','Ask whether the double vision only occurs when both eyes are open and disappears when one eye is closed. If the double vision resolves when one eye is closed, this suggests binocular double vision — a problem with how the two eyes work together — which can be caused by cranial nerve palsy affecting the eye muscles due to issues such as a stroke, tumour, or inflammation. If the double vision persists when one eye is closed, this suggests monocular double vision, indicating a problem within that eye itself, such as a cataract or issue with the lens or cornea.','Ask whether the images appear side by side or one above the other, as this can help identify which eye muscles may be affected.','Ask if the symptoms are constant or intermittent.','Ask about specific triggers such as tiredness or prolonged screen time.','Ask about associated symptoms such as headache, nausea, or vomiting (which may suggest raised intracranial pressure or a brain tumour), drooping eyelids or difficulty swallowing (which may suggest myasthenia gravis or cranial nerve involvement), or limb weakness or facial numbness (which can occur with stroke, multiple sclerosis, or a brain tumour).','Ask about other visual symptoms such as blurred vision, red eyes, or painful eyes. (Painful eyes may suggest optic neuritis, which can occur in multiple sclerosis.)','Ask about any recent eye trauma.','Ask whether he has ever worn glasses or had a squint in childhood, as decompensating strabismus is a common benign cause of diplopia in young adults.','Ask about any muscle weakness, particularly in the upper or lower limbs, that worsens with activity and improves with rest, as this pattern may suggest myasthenia gravis.','Ask about the impact on daily life and activities, including whether the double vision interferes with reading, driving, or work. Note that people with diplopia must not drive and must notify the DVLA, as driving with double vision is unsafe and a legal requirement to report.','Ask about social history including smoking, alcohol, and illicit drug use.','Explore the patient''s ideas, concerns, and expectations.','Make a diagnosis of diplopia likely due to convergence insufficiency, contributed to by prolonged screen use.'],
  ARRAY['Offer a routine referral to the Ophthalmology team for a comprehensive assessment, given the two-year history of double vision. This will help confirm the diagnosis, rule out any other underlying causes, and allow the orthoptist — a specialist in eye movement and coordination — to provide guided eye exercises if needed.','Advise on screen use and lifestyle. Explain that staring at screens for prolonged periods can strain the eye muscles and contribute to double vision. Encourage him to take regular breaks using the 20-20-20 rule: every 20 minutes, look away from the screen and focus on an object about 20 feet away for 20 seconds to reduce eye fatigue.','Encourage him to limit overall screen time where possible and to ensure good lighting and correct posture when using computers or gaming devices.','Offer a blood test to rule out myasthenia gravis — specifically a serum anti-acetylcholine receptor (AChR) antibody test — as ocular myasthenia can present in this manner.','Safety-net: Advise him to seek urgent medical attention if his symptoms suddenly worsen, or if he develops a headache, eye pain, drooping of one eyelid, weakness in any part of the body, or numbness, as these could indicate a neurological problem.','Offer follow-up in 4–6 weeks to review progress and discuss any findings from the ophthalmology referral.'],
  'Thank you for coming in today, Ryan, and it''s good to hear that you''ve already had your eyes checked by the optician and been seen by a private GP. The fact that both assessments came back normal is genuinely reassuring, and I want to make sure we get to the bottom of what''s been going on.

What you''re describing is called diplopia — double vision. The first important thing I can tell you is that when you close one eye, the double vision disappears. That tells us that both eyes are working fine individually, but they''re struggling a little when they try to work together as a pair. We call this binocular diplopia.

Based on everything you''ve told me — the pattern of symptoms, the fact it happens mainly when you move your eyes to the side and gets worse after long periods of screen use — I think the most likely explanation is something called convergence insufficiency. It simply means that the muscles that help your eyes focus together, especially on things close up, are having to work a bit harder than they should. When you''re spending 10 to 14 hours a day in front of a screen, those muscles are being pushed to their limits, and the double vision is essentially a sign that they''re fatigued.

One very practical thing that can help is something called the 20-20-20 rule. Every 20 minutes, look away from your screen and focus on something about 20 feet away for around 20 seconds. This gives your eye muscles a genuine chance to rest and recover. Good lighting and having your screen at a comfortable distance and height will also help.

There is another condition worth knowing about — it''s rare, but I want to be thorough. It''s called myasthenia gravis, and it can cause double vision that worsens with prolonged use of the eye muscles and then improves with rest. It affects the way nerves and muscles communicate. It''s quite unlikely in your case, but to be completely thorough I''d like to arrange a blood test specifically to check for this, so we can rule it out. Would you be happy with that?

I''d also like to refer you to the ophthalmology team at the hospital — the eye specialists — for a more detailed assessment. They can confirm the diagnosis and may also refer you to an orthoptist, who is a specialist in how the eyes move and work together. They can teach you specific exercises to help strengthen the coordination between your eyes. Are you happy for me to arrange that?

In the meantime, if your symptoms suddenly get worse, or if you develop headaches, a drooping eyelid, eye pain, weakness, or numbness anywhere in your body, please don''t wait — seek medical attention straight away. We''ll plan to follow you up in around four to six weeks to see how things are going.',
  ARRAY['Diplopia should be classified as monocular or binocular as the first diagnostic step — if double vision resolves when one eye is closed, it is binocular, indicating a problem with ocular alignment or cranial nerve/muscle function.','Convergence insufficiency is a common benign cause of binocular diplopia in young adults, particularly those spending long hours on screens — the 20-20-20 rule (every 20 minutes, look 20 feet away for 20 seconds) is a simple and effective intervention.','Myasthenia gravis is an important differential for binocular diplopia — it causes fatigable weakness, worsening with sustained use and improving with rest; a serum anti-AChR antibody test should be offered to exclude it.','Decompensating strabismus (childhood squint) is another common benign cause of diplopia in young adults and should be asked about.','All patients with diplopia must be advised not to drive and must notify the DVLA — this is a legal requirement.','Routine referral to ophthalmology is appropriate for persistent diplopia of uncertain cause, as orthoptists can guide targeted eye exercises in addition to confirming the diagnosis.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  190,
  'Abnormal Thyroid Function in Patient Taking Carbimazole',
  'Endocrine & Nephrology',
  'Telephone consultation',
  false,
  'Claire Watts',
  '40-year-old female',
  ARRAY[]::text[],
  ARRAY['Carbimazole 20mg once daily','No Known Drug Allergy'],
  'Letter from Endocrine (12 weeks ago) Re: Claire Watts | 40 years old | Female Dear GP, Thank you for your ongoing shared care of Mrs Watts, whom I reviewed today for follow-up of her Graves'' disease. Claire is feeling much improved overall. On examination, her pulse is 78 bpm and regular, there are no eye signs, and her thyroid is non-tender. Her most recent thyroid function tests show stable biochemical and clinical euthyroidism. Plan: If she develops symptoms of hyperthyroidism (such as palpitations, tremor, anxiety, or heat intolerance) or if future blood results show suppressed TSH (<0.1 mU/L), please increase carbimazole to 20 mg once daily and arrange repeat TFTs in 6 weeks. Thank you for your continued support with her care. Kind regards, Dr Alex Burnham MBBS, FACE, FRCP Consultant Endocrinologist Note entry by Dr Helen Morris (Clinical Practitioner) — 6 weeks ago: Test Result Reference Range TSH 12.8 mU/L 0.4–4.0, Free T4 6.5 pmol/L 10–23, Free T3 2.7 pmol/L 3.5–6.5. Bloods seen and filed as abnormal — picture consistent with worsening hyperthyroidism. Plan: Increase carbimazole to 20 mg once daily as per endocrine advice. Patient called and informed of dose change. Safety-netting advice given. Repeat bloods arranged in 6 weeks. Most recent blood test results (taken yesterday at the GP surgery as part of the patient''s follow-up for Graves'' disease): Test Result Reference Range TSH 15.8 mU/L 0.4–4.0, Free T4 3.5 pmol/L 10–23, Free T3 1.0 pmol/L 3.5–6.5.',
  'The patient has booked a telephone appointment to discuss her recent thyroid blood test results.',
  'Hi doctor, I''d like to go over my blood test results if that''s all right.',
  'I had this thyroid blood test done as part of the monitoring for my overactive thyroid. I''ve noticed that things have felt a bit off lately. I''ve been unusually tired, feeling cold when everyone else seems warm, my skin has been very dry, and I''ve been constipated despite eating normally. These symptoms started about five weeks ago but got noticeably worse around four weeks ago — around the same time I got a text from the surgery telling me to increase my tablet dose, which I did. My periods are regular and unchanged.',
  ARRAY[]::text[],
  'I work as a nursery nurse. I live on my own, haven''t been in a relationship for several years, and I don''t smoke, drink alcohol, or use recreational drugs.',
  'I''m not entirely sure what''s going on, but I suspect it might be related to my thyroid medication.',
  'I''ve had to take time off work because of the tiredness and my manager is becoming concerned about my absences. I''m worried about my job.',
  'I want the doctor to explain what''s happening and what can be done to help me feel better.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything the doctor offers.',
  ARRAY['Clarify that the recent blood test was done to monitor thyroid function as part of her ongoing Graves'' disease management.','Ask whether she has been experiencing any symptoms, particularly tiredness, feeling unusually cold when others feel warm, dry skin, hair loss, swelling around the eyelids, constipation, weight gain, or any swelling or pain in the neck.','Ask about her menstrual history, especially whether she has noticed any heavy or prolonged periods.','Confirm the current dose of carbimazole she is taking and whether she has been taking it regularly.','Ask how her symptoms are affecting her daily activities and work life.','Ask about her home situation, occupation, smoking, and alcohol use.','Explore her ideas, concerns, and expectations regarding the results and her current symptoms.','Duty of Candour: Acknowledge that there appears to have been an error in interpreting her blood test result, leading to an incorrect instruction to increase the carbimazole dose. Explain this openly and sincerely, apologise for the mistake, and outline how the issue will be rectified to restore trust and ensure her safety.','Make a working diagnosis of carbimazole-induced hypothyroidism.'],
  ARRAY['Begin by offering a sincere apology for the error in her blood test management. Explain that the incident will be reported through the practice''s clinical incident reporting system, fully investigated, and that steps will be taken to prevent similar mistakes in the future.','Offer to support her if she wishes to make a formal complaint, and reassure her that her concerns will be taken seriously.','Advise her to stop carbimazole immediately, as her results show an underactive thyroid resulting from overtreatment.','Arrange a face-to-face assessment to check for clinical signs of hypothyroidism such as bradycardia, dry skin, facial puffiness, delayed reflexes, or goitre, and to ensure she is clinically stable.','Offer to contact the endocrinology team urgently today for specialist advice on the next steps and to determine whether she needs to start thyroid hormone replacement with levothyroxine.','Offer to provide a letter to her employer explaining her medical condition to help them support her, or a fit note recommending amended duties or a short period of absence, depending on her preference.','Provide safety-net advice: Ask her to contact the surgery or call NHS 111 if she feels increasingly unwell, excessively tired, confused, or develops neck pain or swelling.','Arrange follow-up: Inform her that you will call once the endocrinology team has responded, to update her and plan the next steps accordingly.'],
  'Thank you for calling in today and for having those blood tests done promptly. I want to talk you through the results, but first I need to say something important and I want to be completely open with you about it.

When we look at your results from six weeks ago, the pattern shows a very high TSH with very low Free T4 and Free T3 levels. A high TSH with low thyroid hormones actually indicates an underactive thyroid, not an overactive one. Unfortunately, it appears that when those results were reviewed six weeks ago, they were interpreted incorrectly and you were advised to increase your carbimazole dose. I am truly sorry, Claire — this was a mistake, and I want to be honest with you about that. Your most recent results, taken yesterday, show that your thyroid is now significantly underactive as a result of too much carbimazole. The symptoms you''ve been describing — the tiredness, feeling cold, dry skin, and constipation — are all consistent with this.

I want to be clear: this is something the practice takes seriously. The incident will be formally reported through our clinical incident system, carefully investigated, and we will be putting steps in place to make sure this kind of error does not happen again. If you would like to make a formal complaint, I will fully support you in doing so and ensure your concerns are given the attention they deserve.

In terms of what we need to do right now: the first step is for you to stop taking carbimazole completely. Do not take any more doses. I would like to arrange for you to come in for a face-to-face appointment as soon as possible so we can examine you properly — checking your heart rate, reflexes, skin, and thyroid gland — to make sure you are clinically stable.

I am also going to contact the endocrinology team today, urgently, to let them know what has happened and to ask for their guidance on the next steps. It is possible that they may want to start you on thyroid hormone replacement — a medication called levothyroxine — to bring your thyroid levels back up to normal and help you feel better more quickly. I will not make that decision without their input.

Regarding your work situation — I completely understand how stressful it must be to be worrying about your job on top of everything else. I can write a letter to your employer explaining that you are dealing with a medical condition that has required time off, or I can issue a fit note recommending reduced duties or a period of absence, whichever would be more helpful for your circumstances. Just let me know.

Please keep a close eye on how you feel over the next few days. If you feel significantly worse — very confused, very fatigued, or develop any swelling or pain in your neck — please call us straight away or contact NHS 111. I will call you back once I''ve spoken to the endocrinology team, usually the same day, to update you and let you know the plan going forward.',
  ARRAY['Carbimazole-induced hypothyroidism occurs when overtreatment with carbimazole suppresses thyroid hormone production; blood results will show a raised TSH with low Free T4 and Free T3.','A raised TSH with low Free T4 and Free T3 indicates hypothyroidism — not hyperthyroidism — and requires a dose reduction or cessation of carbimazole, not an increase. Misinterpreting this pattern is a patient safety risk.','The Duty of Candour requires clinicians to be open and honest with patients when something has gone wrong, offer a sincere apology, and explain what will be done to investigate and prevent recurrence.','When carbimazole-induced hypothyroidism is identified, stop carbimazole immediately, arrange urgent clinical review, and contact the endocrinology team for advice on whether levothyroxine replacement is needed.','A fit note or employer letter should be offered when a medical condition is affecting a patient''s ability to work, particularly when the illness has arisen from a clinical error.','Safety-netting in thyroid disorders should include advising patients to seek urgent review if they develop worsening fatigue, confusion, neck swelling, or pain — features that may indicate myxoedema or other complications.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  191,
  'Abnormal Semen Analysis',
  'Men''s Health',
  'Video consultation',
  false,
  'Simon Hartley',
  '40-year-old male',
  ARRAY[]::text[],
  ARRAY['No Known Drug Allergy'],
  'Telephone consultation — 2 weeks ago with Dr Krish Patel (Clinical Practitioner) Presenting Complaint: Patient reports he and his wife have been trying to conceive for 2 years without success. His wife is currently undergoing fertility investigations with her GP, who advised that he should also have a semen analysis done. Plan: Semen analysis requested. Patient advised to contact the laboratory for instructions regarding the sample collection process to ensure accuracy of results. Review to be arranged once results are available. Semen Analysis Result (performed 1 week ago) Parameter Result Reference Range (WHO 2021): Volume 2.0 mL ≥ 1.4 mL; Sperm concentration 8 million/mL ≥ 16 million/mL; Total sperm count 16 million ≥ 39 million/ejaculate; Progressive motility (PR) 20% ≥ 32%; Non-progressive motility (NP) 10% —; Immotile sperm 70% —; Total motility (PR + NP) 30% ≥ 42%; Vitality (live sperm) 55% ≥ 54%; Morphology (normal forms) 5% ≥ 4%; pH 7.6 ≥ 7.2; White blood cells <1 million/mL <1 million/mL; Agglutination None —.',
  'Patient has booked a video consultation to discuss his semen analysis results.',
  'Hi doctor, I''ve booked this appointment to go through my semen analysis results. If Asked Why You Did the Test: My wife and I have been trying to start a family for the past two years without any luck. My wife''s GP has been looking into things on her side, and we were told I should have a semen analysis done as well.',
  '',
  ARRAY['You followed all the laboratory instructions carefully. You abstained from sex for three days before the test, collected the sample close to the laboratory, and handed it in immediately. You feel well in yourself and have no symptoms.','You have a ten-year-old son from a previous relationship. You and your ex-partner are no longer in contact.','You have never had a sexually transmitted infection (STI) or received treatment for one. Your last STI screen was about two years ago, before your marriage, and it was completely clear. You have no other sexual partners besides your wife.'],
  'I work as a long-distance lorry driver and spend many hours sitting, often using heated seats to stay comfortable on long journeys. I don''t smoke or drink alcohol. I live at home with my wife, who doesn''t have any children from a previous relationship. I''ve been feeling quite stressed lately because we haven''t been able to conceive, and I''ve been taking on extra shifts to keep myself occupied. I don''t exercise regularly, my diet isn''t great, and I know my weight is on the higher side.',
  'I wasn''t sure what the results would show, but I was hoping they''d come back normal.',
  'My main concern is not being able to have a baby with my wife.',
  'I''d like the doctor to explain the results and tell me what happens next.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything the doctor offers.',
  ARRAY['Confirm with him that, according to the notes, he and his wife have been trying to conceive for the past two years and that a semen analysis was arranged for this reason.','Ask whether he followed the laboratory instructions correctly before providing the sample — for example, maintaining sexual abstinence for at least two days and no longer than seven days beforehand, and ensuring the sample was transported to the laboratory promptly under the correct conditions.','Ask if he has any children or has ever fathered a pregnancy from his current or any previous relationship.','Signpost sensitively before asking personal questions: "I''m going to ask you some personal questions now — is that all right?"','Ask if he is sexually active and, if so, the frequency of sexual intercourse.','Ask whether he has multiple sexual partners.','Ask if he has ever been diagnosed with or treated for a sexually transmitted infection (STI).','Ask if he has any problems with erection or ejaculation.','Ask whether he has noticed any bending or curvature of the penis.','Ask whether he has noticed any lumps, swelling, or changes in the testicles.','Ask if he has noticed any enlargement of breast tissue (gynaecomastia).','Ask whether he had mumps during childhood or adolescence.','Ask if he has had any operations or injuries involving the genital area.','Ask about his occupation and specifically whether he drives long distances, uses heated seats, or wears tight underwear, as these factors can affect sperm production and quality.','Ask about current stress levels and whether this has had any effect on his relationship or sexual performance.','Ask whether he has had any recent illness, as this can temporarily affect semen quality.','Ask about social and lifestyle factors including exercise, diet, weight, smoking, alcohol consumption, and recreational drug use.','Ask whether he has any other medical conditions or is taking any prescribed, over-the-counter, or herbal medications that the practice may not be aware of.','Inform the patient that the results show low sperm concentration and reduced motility, findings consistent with oligoasthenozoospermia.'],
  ARRAY['Offer a repeat semen analysis in 3 months and explain that this is because it takes approximately three months for a full new cycle of sperm production (spermatogenesis) to complete. This repeat test helps confirm whether the initial findings are consistent and rules out temporary factors that can affect semen quality, such as stress or recent illness.','Offer general lifestyle advice including maintaining a healthy weight, taking regular exercise, eating a balanced diet rich in fruits and vegetables, and managing stress effectively.','As he drives long distances, advise him to take regular breaks during journeys and to avoid using heated seats, as prolonged heat exposure to the scrotal area can reduce sperm quality.','Offer stress management strategies such as talking therapy, relaxation and breathing exercises, yoga, and resources such as the Headspace app, which provides guided meditations and mindfulness techniques to help reduce stress.','If fertility concerns are affecting his relationship, offer relationship counselling or referral to a couples'' support service.','Arrange follow-up in 3 months to review his progress and discuss the results of the repeat semen analysis.'],
  'Thank you for coming in today, Simon, and for being so open about what you and your wife have been going through. Trying to conceive for two years without success is an emotionally difficult experience, and I want to make sure you leave today with a clear understanding of what the results mean and what we can do.

The semen analysis shows two main findings that are outside the normal range. Firstly, the sperm concentration — that is, the number of sperm per millilitre — is lower than expected at 8 million per millilitre, compared with the normal reference of at least 16 million. Secondly, the motility — the percentage of sperm that are actively moving in the right direction — is lower than it should be, at 20% progressive motility compared to a normal of at least 32%. When we see a combination of low sperm count and low motility like this, it is described with a medical term called oligoasthenozoospermia. The good news is that the shape of the sperm (morphology) and other parameters are within normal range, which is reassuring.

Before we draw firm conclusions, I would like to arrange a repeat semen analysis in around three months'' time. The reason for waiting is that it takes approximately three months for the body to complete a full new cycle of sperm production. Temporary factors — such as a recent illness, high stress levels, or heat exposure — can all affect a test result. A second sample will help us confirm whether these findings are consistent.

There are also some positive lifestyle changes that can make a real difference to sperm quality. One thing that stands out from what you''ve told me is the use of heated seats during your long drives. Prolonged heat around the scrotal area can reduce sperm production, so it would be worth switching those off if you can, and taking regular breaks to reduce sustained sitting. Trying to manage stress is equally important, and I appreciate that''s easier said than done when you''re in this situation. Techniques like breathing exercises, mindfulness apps such as Headspace, or speaking to a counsellor can all help. If you feel that the fertility concerns are putting a strain on your relationship with your wife, we can also arrange couples'' counselling.

In terms of general health, working towards a healthier weight, eating more fruit and vegetables, and building some regular exercise into your week are all things that can support sperm health alongside overall wellbeing.

I''d like to arrange a follow-up in three months once we have the repeat results back, and at that point we can plan the next steps together. If things haven''t improved or if there are new concerns before then, please don''t hesitate to get back in touch.',
  ARRAY['Oligoasthenozoospermia describes a combination of low sperm concentration (<16 million/mL) and reduced progressive motility (<32%), as defined by WHO 2021 reference values.','A repeat semen analysis should be offered 3 months after the initial result, as spermatogenesis takes approximately 3 months — temporary factors such as illness or stress can affect a single sample.','Lifestyle factors that can reduce sperm quality include obesity, a poor diet, smoking, excessive alcohol, recreational drug use, prolonged scrotal heat exposure (e.g. heated car seats, tight underwear), and high stress levels — all should be addressed.','When discussing semen analysis results, sensitively ask about previous pregnancies from any relationship, as confirmed previous fertility changes the clinical picture.','Offer stress management and relationship support when fertility concerns are affecting wellbeing or the couple''s relationship.','Follow-up in 3 months allows reassessment of semen quality and planning of further investigation or referral if results remain abnormal.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  192,
  'Recurrent Nasal Symptoms in Young Man',
  'ENT & Eye',
  'Telephone consultation',
  false,
  'Bradley Moore',
  '29-year-old male',
  ARRAY[]::text[],
  ARRAY['Mometasone intranasal spray 50 micrograms — two sprays once daily (one into each nostril)','No Known Drug Allergy'],
  'Telephone consultation — 4 weeks ago with Dr Indira Khan (Clinical Practitioner) Presenting Complaint: Patient reported nasal congestion and a persistent runny nose for approximately 7–8 months. He denied any known allergies, reported no family history of atopy, and had no red flag symptoms such as epistaxis, facial pain, visual disturbance, or unilateral nasal obstruction. Impression: Rhinitis. Plan: Started on mometasone nasal spray and advised to return if symptoms persisted or worsened.',
  'Patient has booked a routine telephone appointment to discuss ongoing nasal symptoms that have not improved with the prescribed nasal spray.',
  'Hi doctor, I really need some help with my blocked and runny nose — I''ve got a big work event in two weeks where I''m giving a talk and I really can''t have this affecting me on the day.',
  'About eight months ago I had a really bad flu that lasted nearly three weeks. During that time I used an over-the-counter nasal decongestant spray called Otrivine to help with the congestion. The flu eventually cleared up, but I noticed my nose kept feeling blocked or runny every few days. The discharge is clear and watery. Over time it''s got worse, and now my nose feels blocked almost every single day. The only thing that seems to give me any relief is the decongestant spray, but I''m worried about depending on it and I want a proper solution. I was prescribed a steroid nasal spray recently, but I stopped after three days because I wasn''t noticing any difference. Since then I''ve gone back to using the decongestant spray regularly.',
  ARRAY[]::text[],
  'I don''t smoke and I don''t drink alcohol. I live by myself and work as a public speaker, presenting regularly at corporate events and conferences.',
  'The doctor I saw before mentioned something called rhinitis.',
  'I''m worried my symptoms will get in the way of my presentation at the event in two weeks — it would be really embarrassing.',
  'I''d like the doctor to prescribe a short course of oral steroids. I looked it up online and read they can clear rhinitis up quickly.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything the doctor offers.',
  ARRAY['Ask about the onset and duration of symptoms.','Ask how long he has been using the nasal decongestant spray (Otrivine) and how frequently he is currently using it.','Ask whether the nasal blockage and discharge affect one nostril or both. (Unilateral symptoms are more likely to suggest another cause such as nasal polyps, a foreign body, carcinoma, or a cerebrospinal fluid leak.)','Ask about the colour of the nasal discharge. (Discoloured or purulent discharge may indicate infection such as acute bacterial sinusitis.)','Ask about any particular triggers or irritants that worsen the symptoms, such as exposure to dust, pollen, perfumes, or animal dander. (Allergic rhinitis is often triggered by exposure to allergens such as grass, trees, pets, or household dust.)','Ask about associated symptoms such as nasal itching, sneezing, sore throat, cough, fever, ear pain, facial pain, postnasal drip (a sensation of mucus at the back of the throat), or loss of smell.','Ask about associated eye symptoms such as itching, redness, or watering, as these may indicate allergic rhinitis.','Ask whether he has had any recent cold or flu-like illness.','Ask about red flag symptoms that may suggest malignancy, such as nosebleeds, crusting, blood-stained discharge, facial swelling, or visual symptoms.','Ask about any personal or family history of atopy such as eczema or asthma, which may raise suspicion of allergic rhinitis.','Ask about the impact of symptoms on sleep, daily activities, and confidence with public speaking.','Ask about social history including smoking, alcohol use, occupation, and home environment.','Explore his ideas, concerns, and expectations.','Give a diagnosis of rhinitis medicamentosa.'],
  ARRAY['Explain the diagnosis of rhinitis medicamentosa, clarifying that this is a rebound nasal congestion caused by prolonged use of nasal decongestant sprays such as Otrivine (xylometazoline).','Offer a face-to-face review to examine the nasal passages and check for any nasal polyps, masses, or other concerning findings.','Advise that the main treatment is to stop using the nasal decongestant spray, as continuing it will perpetuate or worsen the symptoms.','Advise the patient to restart the steroid nasal spray (mometasone) daily and use it consistently for at least 4–6 weeks to help reduce inflammation and congestion. Explain that symptom relief may not be immediate and can take several weeks to become noticeable.','Offer saline nasal sprays or drops as a safe, non-medicated option to help relieve congestion and dryness while symptoms settle.','Demonstrate or explain the correct nasal spray technique: remove the cap, hold the spray in the opposite hand to the nostril being used, tilt the head slightly forward, place the nozzle just inside the nostril, and aim it slightly outwards away from the centre of the nose before spraying.','Offer a follow-up appointment in 4–6 weeks to review progress and symptom improvement.','Provide safety-netting advice to seek review if symptoms persist despite treatment, worsen, or if he develops new symptoms such as facial pain, swelling, or blood-stained discharge.'],
  'Thank you for getting in touch, and I completely understand why you''re keen to get this sorted before your presentation — it sounds like an important occasion and I want to help you feel as prepared as possible.

Having listened to everything you''ve described, I think I can explain what''s been happening. What you have is something called rhinitis medicamentosa — which is a type of nasal congestion that is actually caused by prolonged use of the decongestant spray itself. Otrivine works by narrowing the blood vessels inside the nose, which gives you temporary relief. However, if it''s used regularly for more than a week or so, the blood vessels begin to ''rebound'' and dilate even more once the spray wears off, making the congestion feel worse than before. This creates a cycle where the spray seems to be the only thing that helps, but using it is actually keeping the problem going.

The most important step in getting better is to stop using the Otrivine. I know that might feel daunting when you''re worried about the event in two weeks, but continuing to use it will keep this cycle going and your symptoms will not improve.

The steroid nasal spray — mometasone — that was prescribed for you is the right treatment, but it does need time to work. Three days is far too short a time to judge whether it''s helping; it typically takes four to six weeks of consistent daily use before you notice a significant improvement. It works by reducing the underlying inflammation in your nasal lining, which is the root cause of the congestion. I''d encourage you to restart it today and use it every day without stopping.

One thing that makes a real difference is the technique used to apply the spray. Rather than aiming it straight up the nostril, hold the spray in the hand opposite to the nostril you''re treating, tilt your head slightly forward, and aim the nozzle gently outwards away from the middle of your nose. This helps the spray reach the right area and reduces the chance of it hitting the central partition of the nose, which can cause irritation.

Alongside the steroid spray, saline nasal drops or a saline rinse can also be really helpful — they are completely safe to use daily and can gently soothe and clear the nasal passages while things settle down.

I''d also like to arrange for you to come in for a face-to-face appointment so I can have a look inside your nose and make sure there isn''t anything else going on, such as nasal polyps, that might be contributing. And we''ll arrange a follow-up call or appointment in around four to six weeks to check how things are progressing. If your symptoms worsen, you develop facial pain, swelling, or notice any blood in the discharge before then, please contact us sooner.',
  ARRAY['Rhinitis medicamentosa is a rebound nasal congestion caused by prolonged use of topical nasal decongestants (e.g. xylometazoline/Otrivine); the primary treatment is cessation of the decongestant spray.','Topical nasal decongestant sprays should not be used for more than 5–7 consecutive days, as prolonged use leads to rebound congestion and dependency.','Intranasal corticosteroids such as mometasone 50 micrograms are the mainstay of treatment for rhinitis medicamentosa, but must be used consistently for at least 4–6 weeks before symptom improvement is expected — patients should not discontinue early.','Correct intranasal spray technique is important: hold the spray in the hand opposite to the nostril, tilt the head slightly forward, and aim outwards away from the nasal septum to maximise drug delivery and minimise irritation.','Unilateral nasal symptoms should always prompt consideration of alternative diagnoses such as nasal polyps, foreign body, malignancy, or CSF leak — red flag symptoms include blood-stained discharge, facial swelling, or visual disturbance.','Saline nasal rinses or drops are a safe adjunct that can relieve congestion and dryness while recovery progresses.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  193,
  'Painful Rash on Back in Middle-Aged Man',
  'Dermatology',
  'Telephone consultation',
  false,
  'George Osei',
  '62-year-old male',
  ARRAY[]::text[],
  ARRAY['Amlodipine 5mg daily','No Known Drug Allergy'],
  'No significant recent consultations',
  'Patient has sent in a photograph and booked an urgent telephone appointment to discuss a painful rash on his back.',
  'Hi doctor, I''ve sent through a photo of the rash on my back. I wasn''t sure if you''d had a chance to look at it yet. It''s been really painful and I''d like something to help, please.',
  'You first noticed a burning sensation in your back about seven days ago. Two days after that — so around five days ago — a rash appeared in the same area. The rash is painful, burning, and throbbing, and the pain has been getting progressively worse, now disturbing your sleep. You have tried paracetamol and ibuprofen without much relief. You have not been in contact with anyone with a similar rash. You returned from Nigeria about a week ago, where you were doing volunteer work and visited some people who were unwell. You are now worried you may have picked up an infection from them.',
  ARRAY[]::text[],
  'You live alone and run your own business — an African food import and wholesale company with a small team of staff. You do not smoke or drink alcohol.',
  'You are not certain what the rash is, but you are wondering if you may have caught something infectious during your recent trip.',
  'The pain is quite severe and has been waking you up at night.',
  'You would like the doctor to identify what the rash is and prescribe something to help manage the pain.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Ask about the onset of symptoms — when the pain started and when the rash appeared, and whether the pain preceded the rash.',
    'Clarify whether the pain came before the rash, as this sequence is characteristic of shingles.',
    'Ask whether the rash is present anywhere else on the body. Note: shingles affecting the head, neck, or eye area requires same-day hospital assessment.',
    'Ask about systemic symptoms such as fever, headache, fatigue, or general malaise.',
    'Ask whether new blisters (vesicles) are still forming. Even if the patient presents beyond the initial 72-hour window for antivirals, treatment can still be considered if new blisters continue to appear within 7 days of rash onset.',
    'Ask about any discharge or oozing from the rash, which may suggest secondary bacterial infection.',
    'Ask whether the patient has had any contact with anyone with a similar rash.',
    'Explore how the symptoms have affected daily life, including sleep quality, ability to work, and general comfort.',
    'Ask about social history including smoking, alcohol use, and living situation.',
    'Ask about any other medical conditions or medications, including over-the-counter remedies, not already recorded.',
    'Explore the patient''s ideas, concerns, and expectations.',
    'Make a working diagnosis of shingles.'
  ],
  ARRAY[
    'No face-to-face appointment is necessary at this stage, as the photograph and clinical history are consistent with a typical presentation of shingles.',
    'Offer a neuropathic pain agent for analgesia — options include amitriptyline, duloxetine, gabapentin, or pregabalin — selected based on suitability and patient preference.',
    'Advise the patient that antiviral medication is unlikely to be beneficial at this stage, as he has presented beyond the 72-hour window during which antivirals are most effective.',
    'Advise on skin care: wear loose-fitting clothing to minimise irritation, keep the rash clean and dry to reduce the risk of secondary infection, and keep any weeping areas covered.',
    'Explain that shingles cannot be caught from another person — it is caused by reactivation of the varicella-zoster virus, which lies dormant in the nervous system after a previous chickenpox infection. However, someone with an active shingles rash can transmit chickenpox to individuals who have never had chickenpox or the vaccine, through direct contact with the rash.',
    'Advise him to avoid skin-to-skin contact with people at higher risk of complications, such as immunocompromised individuals, newborn babies, elderly people, and pregnant women who have not had chickenpox, until all lesions have fully crusted over.',
    'Reassure him that if his daughter had chickenpox as a child, she is unlikely to catch it from him. However, as a precaution, he should avoid direct contact with her until the rash has fully crusted. Also advise caution around other people who may be present — such as pregnant women, young children, or those with weakened immunity.',
    'Explain that he will be eligible to receive the shingles vaccine from age 65, even having already had shingles, as it can help reduce the risk of future recurrence.',
    'Advise him to contact the practice or NHS 111 if the pain worsens significantly, if he develops any eye symptoms (such as rash near the eyes, forehead, or tip of the nose), or if the rash shows signs of secondary infection — including spreading redness, swelling, warmth, yellow discharge or pus, or increased tenderness.'
  ],
  'Thank you for sending through that photograph, George — it has been really helpful. I can see why you''ve been struggling, and I want to reassure you that we''re going to get to the bottom of this today.

Having looked at the image and listened carefully to everything you''ve described — the burning pain that started first, followed a couple of days later by a rash appearing in the same area — I''m confident that what you have is called shingles. It can sound alarming, but I want to explain what that means and what we''re going to do about it.

Shingles is caused by a virus called varicella-zoster — the same virus that causes chickenpox. After you had chickenpox, likely many years ago, the virus went to sleep in the nerves in your body. Now, for various reasons, it has woken up and is causing this painful rash along the path of one of the nerves in your back. It is not something you have caught from anyone during your trip — it has come from within your own body. That is very important to understand, so I hope that puts your mind at rest.

In terms of treatment, I want to be honest with you. There are antiviral tablets that can be used for shingles, but they work best if taken within 72 hours of the rash first appearing. As you are now around five days into the rash, we are past that window, so I do not think antivirals would be beneficial at this stage.

What I do want to focus on is your pain, because I can hear how much it is affecting you — particularly your sleep. The standard pain relief you have been using — paracetamol and ibuprofen — is not really designed for this type of nerve pain. Instead, I would like to prescribe you a medication specifically aimed at nerve pain. There are several options, such as amitriptyline, gabapentin, pregabalin, or duloxetine. We can discuss which might suit you best. These can take a little time to build up in your system, but many people find significant relief within a few days.

In terms of looking after the rash itself — please try to wear loose-fitting clothing over the area, as tight fabric can make the discomfort worse. Keep the rash as clean and dry as possible to reduce the risk of any secondary infection setting in, and if any of the blisters are weeping, try to keep them covered when you are around others.

Shingles itself is not contagious in the sense that you cannot give someone else shingles. However, the virus in the rash can cause chickenpox in someone who has never had it — particularly those who are pregnant, have a weakened immune system, are very elderly, or are young children who have not yet been vaccinated. So it would be wise to avoid direct skin contact with those groups until the rash has fully crusted over.

Finally, I want to mention that once you reach 65, you will be eligible for the shingles vaccine on the NHS. Even though you have had shingles now, having the vaccine in the future can help reduce the chance of it coming back. Do please seek medical advice if the pain significantly worsens, if you notice any rash appearing near your eye or on your forehead, or if the skin around the rash starts to look infected — signs of that would include spreading redness, swelling, warmth, or any yellow discharge. In that case, contact us or call NHS 111 if it is out of hours.',
  ARRAY[
    'Shingles (herpes zoster) is caused by reactivation of the varicella-zoster virus lying dormant in the dorsal root ganglia after a prior chickenpox infection — it cannot be caught from another person.',
    'The characteristic clinical sequence is neuropathic pain preceding the dermatomal rash by several days; this history alone is highly suggestive of the diagnosis.',
    'Antivirals (e.g. aciclovir) are most effective within 72 hours of rash onset but can still be considered up to 7 days if new vesicles are still forming.',
    'Standard analgesics have limited effect on neuropathic pain in shingles; preferred options include amitriptyline, duloxetine, gabapentin, or pregabalin.',
    'Patients with shingles involving the ophthalmic division of the trigeminal nerve (rash near eye, forehead, or tip of nose — Hutchinson''s sign) require same-day ophthalmology review.',
    'Shingles vaccine (Shingrix) is offered on the NHS from age 65 and can be given even after a previous episode of shingles to reduce recurrence risk.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  194,
  'Preoperative ECG Showing Incidental Bradycardia',
  'Cardiology',
  'Video Consultation',
  false,
  'Graham Whitfield',
  '74-year-old male',
  ARRAY['Hypertension','Severe left knee osteoarthritis'],
  ARRAY[]::text[],
  'Letter from Perioperative Team (1 week ago)

Dear GP,

Re: Mr Graham Whitfield | 74 years old | Male

I am writing following a recent pre-operative assessment for Mr Graham Whitfield, who is scheduled to undergo an elective total knee replacement. During his assessment, he was found to have a resting heart rate of 45 beats per minute. His ECG demonstrated sinus bradycardia with no other abnormalities noted. He was otherwise asymptomatic, with no history of syncope, chest pain, or dizziness at the time of review. Routine pre-operative blood tests, including full blood count, urea and electrolytes, liver function tests, and bone profile, were all within normal range. Given these findings, I have advised him to contact his general practitioner for further assessment and investigation to ensure it is safe to proceed with surgery. Please do not hesitate to contact me should you require further details or wish to discuss management prior to surgery.

Yours sincerely,
Donald Robertson, MBChB FRCA
Consultant Anaesthetist

Drug History: Amlodipine 10 mg once daily | Ramipril 5 mg once daily',
  'The patient has booked a video consultation to discuss a letter received from the perioperative team regarding an incidental finding of bradycardia at his pre-operative assessment.',
  'Hi doctor, they would not go ahead with my operation because the doctor at the hospital said my heart rate was too slow, and that I should come and speak to my GP about it.',
  'You are due to have a left knee replacement in four weeks due to severe arthritis. You attended the hospital for your pre-operative assessment, where they did an ECG, blood tests, and a chest examination. You were told your heart rate was slow and were asked to see your GP before they could confirm it is safe to proceed with surgery.',
  ARRAY[
    'You feel well in yourself and have not experienced any dizziness, collapse, or chest pain. You go for an evening walk with your dogs most days and have never had any difficulties doing so.'
  ],
  'You live with your wife and are a retired plumber. You do not smoke, drink alcohol, or use recreational drugs. There is no family history of heart problems or sudden cardiac death.',
  'You are not sure why your heart rate is slow or what might have caused it.',
  'You are worried that your knee operation might be cancelled and that you will have to keep living with the pain and reduced mobility.',
  'You would like the GP to explain what is going on and advise on what needs to happen next so that your surgery can still proceed as planned.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY[
    'Demonstrate that you have reviewed the patient''s notes before starting the consultation. For example: "Graham, I can see from the hospital letter that during your pre-operative assessment they found your heart rate to be slower than normal — is that right?"',
    'Ask if he has ever been told before that his heart rate is slow.',
    'Ask if he has felt generally unwell recently, to identify any underlying or acute illness — such as a viral infection with vomiting or diarrhoea — that might cause electrolyte disturbances and contribute to bradycardia.',
    'Ask about dizziness or light-headedness.',
    'Ask about fatigue or unusual tiredness.',
    'Ask about any history of fainting or blackouts.',
    'Ask about chest pain, which could indicate underlying cardiac pathology.',
    'Ask about shortness of breath, particularly on exertion. Assessing exercise tolerance is important, as people with physiological bradycardia typically maintain good exercise capacity — if the patient can carry out moderate activity without distress, the bradycardia is less likely to be pathological.',
    'Ask about palpitations or any awareness of the heart beating fast or irregularly, as this may indicate intermittent tachyarrhythmias such as sick sinus syndrome or tachy-brady syndrome.',
    'Ask about any family history of heart disease or sudden cardiac death.',
    'Ask about smoking, alcohol, and recreational drug use (e.g. cocaine, which can cause arrhythmias).',
    'Ask about over-the-counter medications or herbal supplements, as some may affect heart rate.',
    'Ask about physical activity levels and whether he has ever been a competitive or endurance athlete, to help distinguish physiological from pathological bradycardia.',
    'Make a working diagnosis of bradycardia.'
  ],
  ARRAY[
    'Offer the patient a repeat 12-lead ECG in the practice to confirm sinus bradycardia and to check for any conduction abnormalities such as heart block.',
    'Arrange blood tests including thyroid function tests, as hypothyroidism is a recognised cause of bradycardia.',
    'Explain that if the repeat ECG continues to show bradycardia, you will arrange a 24-hour ambulatory ECG monitor (or longer if indicated) to assess for associated rhythm abnormalities such as intermittent heart block.',
    'Explain that as he is due to have an operation, you will seek advice from the cardiology team if further investigations are required or if they feel he should be reviewed in their clinic before surgery.',
    'Safety-net advice: advise him to seek urgent medical attention if he develops fainting or blackouts, severe dizziness, chest pain, shortness of breath, confusion, or new or irregular palpitations.',
    'Inform him that you will arrange a follow-up appointment once the test results are available and after receiving advice from the cardiology team.'
  ],
  'Thank you for coming in today, Graham, and I completely understand why this has been worrying — especially with the operation only a few weeks away. Let me take you through what we know and what we plan to do.

When you attended the hospital for your pre-operative assessment, they found that your heart rate was sitting at around 45 beats per minute. For most people, a normal resting heart rate falls somewhere between 60 and 100. When the heart rate is below 60, we call that bradycardia — it simply means a slower heart rate than average. The anaesthetist wanted you to see us before proceeding, which is entirely the right approach, and I''m glad you''ve come in.

Now, there are several reasons why someone might have a slow heart rate. In some people — particularly those who are physically active or have been throughout their lives — a slower rate is completely normal and nothing to worry about. In others, it can occasionally be related to the electrical system of the heart slowing down, an effect of medication, or a condition such as an underactive thyroid gland. What is very reassuring in your case is that you feel well, you''re still going on your evening walks without any trouble, and you haven''t had any dizziness, chest pain, or episodes of blacking out.

However, because of the planned surgery, we do need to make sure everything is as it should be before giving the green light to go ahead. What I''d like to do first is repeat your heart tracing here at the practice — this will confirm what the hospital found and allow us to look closely for any changes in the electrical pattern of your heart. I''d also like to examine you and listen to your heart today.

Alongside that, I''d like to arrange a blood test to check your thyroid function. The thyroid is a small gland in the front of the neck that helps regulate your body''s energy. If it is slightly underactive, it can sometimes cause the heart to slow down. That is a very straightforward thing to identify and, if found, can be treated effectively. Is that alright with you?

If the heart tracing continues to show a slow rate, the next step would be for you to wear a small heart monitor for 24 hours — or possibly a little longer. It''s a compact device that records every heartbeat while you go about your normal daily activities. It helps us identify whether the rhythm is consistently slow or whether anything else is happening in between.

Because of the upcoming surgery, I will also be consulting with the cardiology team. They can advise on whether you need any further tests or whether they would like to see you before the operation goes ahead. My aim is to make sure we have all the information we need to get your knee replacement back on track as safely as possible.

In the meantime, please do get in touch with us or seek urgent help if you develop any new symptoms — particularly dizziness, fainting, chest pain, palpitations, or breathlessness. We will be in touch as soon as we have the results, and I''ll make sure you have a follow-up appointment arranged promptly.',
  ARRAY[
    'Bradycardia is defined as a resting heart rate below 60 bpm; most individuals are asymptomatic unless the rate falls below 50 bpm.',
    'Common pathological causes include hypothyroidism, negative chronotropic drugs (beta-blockers, rate-limiting calcium-channel blockers, digoxin, amiodarone), sick sinus syndrome, and acute myocardial infarction.',
    'Physiological bradycardia is common in endurance athletes and fit individuals — preserved exercise tolerance is a reassuring feature distinguishing it from pathological causes.',
    'Initial investigation includes a repeat 12-lead ECG and thyroid function tests; a 24-hour ambulatory ECG monitor is indicated if bradycardia is confirmed or if intermittent rhythm abnormalities are suspected.',
    'Pre-operative bradycardia should prompt cardiology input before surgery proceeds, particularly if the rate is below 50 bpm or the patient is symptomatic.',
    'Safety-netting is essential: urgent review is needed if the patient develops syncope, chest pain, severe dizziness, or new palpitations.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  195,
  'Post-Hospitalisation Diarrhoea in Older Adult',
  'Gastroenterology & Haematology',
  'Telephone Consultation',
  false,
  'Thomas Hartley',
  '72-year-old male',
  ARRAY['Hypertension','Type 2 Diabetes'],
  ARRAY[]::text[],
  'Respiratory Unit – Hospital Discharge Summary (1 week ago)

Thomas Hartley | 72 years old | Male

Dear GP,

Mr Hartley was admitted to the Respiratory Unit with cough, fever, and shortness of breath. On assessment, his chest X-ray showed evidence of pneumonia, and blood tests revealed raised inflammatory markers with acute kidney injury (AKI). He was diagnosed with community-acquired pneumonia. He was treated with intravenous antibiotics and intravenous fluids during his hospital stay. After two days of treatment, his condition improved, and he was discharged home to continue oral antibiotics (co-amoxiclav 625 mg three times daily) for a further three days, completing a total five-day course. His regular medications, including Metformin and Ramipril, were withheld during admission due to the acute kidney injury. The Hospital at Home service has been informed and will repeat blood tests one week after discharge to monitor kidney function. We kindly request that his GP review the post-discharge blood results and consider restarting his Metformin and Ramipril once renal function has recovered and it is clinically appropriate.

Drug History: Amlodipine 10 mg once daily | Ramipril 5 mg once daily | Metformin 1g twice daily | No Known Drug Allergy

Kidney Function Results — 1 week ago (on Admission):

Sodium (Na⁺): 138 mmol/L (ref 135–145 mmol/L) | Previous (6 months ago): 139 mmol/L
Potassium (K⁺): 5.4 mmol/L (ref 3.5–5.0 mmol/L) | Previous: 4.5 mmol/L
Urea: 14.8 mmol/L (ref 2.5–7.8 mmol/L) | Previous: 6.2 mmol/L
Creatinine: 210 µmol/L (ref 60–110 µmol/L) | Previous: 92 µmol/L
eGFR: 40 mL/min/1.73m² (ref >90 mL/min/1.73m²) | Previous: >90 mL/min/1.73m²

Interpretation: Acute Kidney Injury (AKI) Stage 2.',
  'Patient has booked an urgent telephone appointment to discuss ongoing diarrhoea following a recent hospital discharge.',
  'Doctor, I''ve been having diarrhoea for the past five days. The nurse came in today to take my blood test and she said I should speak to you about it.',
  'The diarrhoea has been going on for five to six days now, beginning the day after you returned home from hospital. You initially thought it might be related to an out-of-date chicken sandwich you ate on the day you got home — you only noticed the expiry date after finishing it. Although the diarrhoea did not start the same day, it began the following day. The stools are loose and watery, occurring around four to five times per day. There is no blood or mucus in the stool. You have not had a fever, but you are experiencing generalised crampy abdominal pain.',
  ARRAY[
    'If asked about Metformin and Ramipril: explain that you restarted both medications yourself. The hospital did not explain why they had been stopped, and as you were feeling better you assumed it was safe to do so.'
  ],
  'You live with your wife. You are a retired lorry driver. You do not smoke and do not drink alcohol.',
  'You think the diarrhoea might be related to the out-of-date chicken sandwich you ate the day you came home from hospital.',
  'You have not been going out or socialising because you are worried about urgently needing the toilet when you are away from home.',
  'You would like the GP to explain what is causing the diarrhoea and advise on what to do to help it settle.',
  ARRAY[
    'If the doctor asks about Metformin and Ramipril, explain that you restarted both medications on your own. The hospital did not tell you why they had been stopped, and as you were feeling better you assumed it was safe to resume them.'
  ],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY[
    'Ask about the onset and duration of the diarrhoea.',
    'Ask the patient to describe the stool consistency — whether it is loose or watery.',
    'Ask whether there is any blood or mucus in the stool.',
    'Ask how many episodes of diarrhoea are occurring per day.',
    'Ask about associated symptoms such as fever, abdominal pain, bloating, nausea, or vomiting.',
    'Explore the timeline in relation to eating the expired food — food poisoning typically causes symptoms within one to two hours of ingesting contaminated food, though in some cases onset can be delayed by a day or more.',
    'Ask about red flag symptoms that might indicate the need for hospital admission — such as dizziness, palpitations, reduced urine output, or inability to tolerate oral fluids.',
    'Ask about cancer red flags including unintentional weight loss, an abdominal or rectal mass.',
    'Ask whether anyone the patient has been in contact with has had similar symptoms.',
    'Ask about any recent travel abroad.',
    'Ask whether any meals from restaurants or takeaways were consumed recently.',
    'Ask about social history including alcohol use, smoking, occupation, home environment, and whether anyone else in the household is unwell.',
    'Explore how the diarrhoea has affected his daily activities and quality of life.',
    'Ask whether he has restarted his regular medications — particularly Metformin and Ramipril — and explore his understanding of sick day rules.',
    'Ask whether he completed the full course of antibiotics prescribed on discharge from hospital.',
    'Explore the patient''s ideas, concerns, and expectations.',
    'Make a working diagnosis of likely antibiotic-associated diarrhoea, while acknowledging that food poisoning from the expired food is a possibility. Explain that C. difficile infection is more likely given the timing, recent hospital admission, and recent use of broad-spectrum antibiotics.'
  ],
  ARRAY[
    'Offer to send a stool sample pot for collection — ask whether the patient can collect one from reception, or whether someone can collect it on his behalf.',
    'Explain that the reason for sending a stool sample is to check for a bacterium called Clostridioides difficile (C. difficile), which can sometimes cause diarrhoea following recent antibiotic treatment.',
    'Advise the patient to stop Metformin and Ramipril temporarily in line with sick day rules, due to the risk of dehydration and further worsening of kidney function.',
    'Advise that Amlodipine can generally be continued, as it does not affect kidney function in the same way as Ramipril or Metformin. However, it should be stopped if he is unable to maintain adequate fluid intake or develops symptoms such as dizziness or low blood pressure.',
    'Advise against taking loperamide, as there is concern about possible C. difficile. Explain that loperamide slows gut motility and can be dangerous in this context by trapping harmful toxins within the bowel.',
    'Encourage regular fluid intake to prevent dehydration, and suggest oral rehydration salts (ORS) if available.',
    'Advise on methods to reduce the risk of spreading infection, including thorough handwashing with liquid soap and warm running water, followed by complete drying of the hands.',
    'Advise that he should avoid attending social or public gatherings until at least 48 hours after the last episode of diarrhoea.',
    'Reassure the patient that in most cases diarrhoea should settle within one to two weeks.',
    'Provide safety-netting advice: instruct him to seek urgent medical attention if he is unable to keep fluids down, feels dizzy or light-headed, experiences palpitations, notices reduced urine output, sees blood in the stool, or develops severe abdominal pain.',
    'Arrange a follow-up appointment once stool culture results are available and after obtaining microbiology advice to guide further management.'
  ],
  'Thank you for getting in touch today, Thomas, and I''m glad the nurse suggested you called. It sounds like you''ve had a really uncomfortable week, and I want to make sure we sort this out properly.

Having listened to everything you''ve described — diarrhoea starting shortly after you were discharged from hospital, following a course of antibiotics for your pneumonia — I think it''s important we consider a specific cause. You mentioned the out-of-date chicken sandwich, and I understand why that came to mind. However, food poisoning typically causes symptoms within an hour or two of eating contaminated food, sometimes a little longer but usually quite promptly. In your case, given that the diarrhoea started a day later and has continued for nearly a week, and given that you were recently in hospital and were given a broad-spectrum antibiotic called co-amoxiclav, I think it''s more likely this is what we call antibiotic-associated diarrhoea.

Antibiotics are fantastic medicines, but they can also disturb the natural balance of bacteria in the gut. In some cases — particularly after hospital stays and the use of broad-spectrum antibiotics — a bacterium called Clostridioides difficile, or C. difficile, can take hold and cause ongoing diarrhoea. This is not uncommon and is entirely treatable, but we do need to confirm it. I''d like to arrange a stool sample to check for this. A nurse or receptionist can give you a pot to collect a sample — please could someone collect one from us, or could you call in?

Now, I also need to talk about your regular medications. I can see from your hospital notes that Ramipril and Metformin were deliberately stopped while you were admitted because your kidneys were under some strain at the time — what we call an acute kidney injury. I understand the hospital may not have explained this clearly, but these tablets need to be stopped temporarily when the kidneys are under stress, and they should only be restarted once the kidneys have recovered. Given that you''re now also dealing with diarrhoea — which can cause dehydration and put further strain on the kidneys — I''d like you to pause these two tablets for now. Your Amlodipine, however, is fine to continue as normal.

I also want to advise against taking loperamide at this stage. I know you mentioned you have it at home, and ordinarily it would be reasonable to try. However, if this is C. difficile, slowing the bowel down can prevent the body from clearing the toxins produced by the bacteria and can actually make things worse. So please hold off on that for now.

In the meantime, the most important thing is to keep your fluids up. Aim to drink regularly throughout the day — water is fine, but oral rehydration sachets are even better if you have them. Please wash your hands thoroughly with soap and water after each episode of diarrhoea and before eating or preparing food. Until you have been free of diarrhoea for at least 48 hours, it would be best to avoid going to social gatherings or public settings.

The good news is that in the vast majority of cases this settles within one to two weeks, and once we have the stool result back we can make sure we have the right plan in place. I''ll arrange a follow-up once the microbiology results are available. In the meantime, please do contact us urgently — or call 111 if we are closed — if you feel unable to keep fluids down, feel faint or lightheaded, notice your heart racing, are passing very little urine, or see any blood in the stool.',
  ARRAY[
    'Antibiotic-associated diarrhoea — including C. difficile infection — should be the leading diagnosis in a patient with diarrhoea following a recent hospital admission and broad-spectrum antibiotic use, even when an alternative explanation (such as food poisoning) is suggested.',
    'Sick day rules require temporary cessation of Metformin (risk of lactic acidosis) and ACE inhibitors such as Ramipril (risk of AKI) during episodes of diarrhoea, vomiting, or dehydration.',
    'Loperamide is contraindicated in suspected C. difficile infection as it may prevent clearance of toxins and worsen the clinical course.',
    'A stool sample should be sent to check for C. difficile toxin; results guide further management including whether antibiotic treatment such as oral vancomycin or fidaxomicin is required.',
    'Amlodipine (a calcium-channel blocker) does not carry the same renal risk as ACE inhibitors or Metformin and can generally be continued during mild illness, provided the patient is maintaining adequate fluid intake.',
    'Safety-netting is essential: inability to tolerate fluids, dizziness, reduced urine output, blood in stool, or haemodynamic instability should prompt urgent review or hospital assessment.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  196,
  'Palliative Care in a Patient with Advanced Motor Neuron Disease',
  'Elderly Medicine & Palliative Care',
  'Telephone Consultation',
  false,
  'Peter Sullivan',
  '49-year-old male',
  ARRAY['Motor Neuron Disease'],
  ARRAY['Not currently on any regular medication.','No Known Drug Allergy'],
  'Neurology Discharge Summary – Received 1 day ago

Dear GP,

RE: Discharge Summary – Peter Sullivan (49-year-old male)

Mr Peter Sullivan has been under our care in the Neurology Department following a confirmed diagnosis of motor neuron disease (MND). He has shown progressive bulbar dysfunction and is now established on enteral feeding via a percutaneous endoscopic gastrostomy (PEG) tube due to significant risk of aspiration. He is nil by mouth (NBM) and will require all medications and nutrition via the PEG tube. He has been assessed by the hospital dietitian and commenced on pump-assisted PEG feeding over a 10-hour period overnight to meet his nutritional needs. His wife, Karen Sullivan, who holds Lasting Power of Attorney (LPA) for both Health and Welfare, and Property and Financial Affairs, has been trained in the use of the feeding pump and is acting as his primary carer. She has been actively involved in all discussions regarding his care.

Given the progression of his condition, Mr Sullivan has been deemed palliative. He is now being discharged to the community, and we would be grateful if you could arrange an urgent referral to the community palliative care team for multidisciplinary input and end-of-life care support.

Medications on Discharge (all to be given via PEG tube or subcutaneous injection as appropriate):
Oramorph (oral morphine solution) — for pain or breathlessness when needed, maximum 60 mg in 24 hours.
Hyoscine butylbromide — for respiratory secretions, maximum 25 mg in 24 hours.
Levomepromazine — for nausea or agitation, maximum 60 mg per day.
Midazolam — for anxiety or restlessness as needed.

DNACPR is in place.
Lasting Power of Attorney (LPA) for Health and Welfare and Property and Financial Affairs is held by Karen Sullivan (wife and next of kin).

Yours sincerely,
Dr Chukwuma Obi, MBBS, MRCP, PhD
Consultant Neurologist',
  'Caller is the patient''s wife, Karen Sullivan, who holds Lasting Power of Attorney. She is telephoning to discuss ongoing care and medication management following her husband''s discharge from the neurology ward.',
  'Hi doctor, I''m not sure how to give my husband his medications — he can''t swallow. I don''t really understand what the tablets are for or how to use them.',
  'Your husband has just been discharged from hospital, and you were told he is now receiving palliative care, as nothing further can be done to treat his condition. He is unable to eat by mouth or speak. You were sent home with several medications intended to keep him comfortable, but no one clearly explained what each one is for or how to administer them. You feel unsure and overwhelmed. At the moment, he is doing well with the morphine for pain. You give him 2.5 ml of Oramorph twice a day via his PEG tube — this was the only medication you were shown how to use, and it seems to be controlling his pain well.',
  ARRAY[
    'He wears a pad and is opening his bowels normally with no signs of constipation. There are no secretions from his mouth, he does not appear agitated or confused, and he has no other symptoms of concern at present. His mood seems settled and he has been sleeping reasonably well.'
  ],
  'You live at home with your husband and two children — a 7-year-old son and a 9-year-old daughter. You have a private carer who assists with your husband''s care. You do not have financial difficulties at present. If asked about your own mood: you are coping as well as you can and trying to stay strong for your husband and the children during this very difficult time. Your children are not yet fully aware of the situation, as you are not sure how to explain it to them.',
  'You understand that your husband is dying and has only a few weeks left to live.',
  'Your husband has said he wants to die at home. You want to honour his wishes, but you are deeply worried about the impact on your children — particularly the thought that one of them might find him at home after he has passed away.',
  'You would like the GP to explain what each medication is for, how and when to give them, and to advise on whether a hospice might be a better option given your concerns about the children.',
  ARRAY[]::text[],
  'Doctor, do you think it would be better to move him to a hospice so the children don''t have to be there when he dies — or should we try to keep him at home as he wishes? I''m finding this decision very hard and would really value your advice.',
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY[
    'Acknowledge that you have read the neurology discharge summary and express genuine empathy for the situation before proceeding.',
    'Ask which medications she is currently administering, how she is giving them, and how frequently.',
    'Ask whether the patient is currently experiencing any common palliative symptoms, including pain, breathlessness, respiratory secretions, agitation, confusion, nausea, or vomiting.',
    'Ask whether he is opening his bowels normally and passing urine without difficulty.',
    'Ask how his mood has been and whether he has been sleeping.',
    'Ask whether he is currently bedbound.',
    'Ask if there are any difficulties with the PEG feeding pump or with administering feeds.',
    'Ask about the home environment — who else is in the household and what support is available.',
    'Ask whether there are any financial pressures as a result of his illness and whether she would like help accessing available support.',
    'Ask if she has received any information about what to expect in the final days of life.',
    'Ask about her understanding of palliative care and whether any community palliative care services have already been in contact.',
    'Ask about her own emotional wellbeing and how she is coping, particularly with two young children at home.',
    'Ask whether there have been any previous conversations with her husband about his preferred place of care and death.',
    'Explore her current concerns and what she feels would be most helpful at this stage.',
    'Ask if she has any questions about what to expect as his condition progresses.'
  ],
  ARRAY[
    'Provide a clear and compassionate explanation of each anticipatory medication — often called ''just in case'' medications. Explain that morphine is used to relieve pain and breathlessness and can be given via the PEG tube; in future it can also be delivered continuously via a syringe driver if needed.',
    'Explain that the other medications are given by subcutaneous injection: hyoscine butylbromide helps manage respiratory secretions that may cause noisy or wet-sounding breathing; levomepromazine is used for nausea and vomiting; and midazolam is used for anxiety, restlessness, or agitation.',
    'Inform her that you will refer to the district nursing team, who can administer the injectable medications and can also teach her how to give them if she feels comfortable. The district nurses will also support with ongoing PEG tube care.',
    'Explain that in the future, a syringe driver may be used — a small battery-operated pump that delivers continuous medication under the skin, used when swallowing is no longer possible or when symptoms require more consistent control.',
    'Acknowledge her husband''s expressed wish to die at home and offer to arrange a best interests meeting involving the GP, the community palliative care team, the district nurses, and herself as his Lasting Power of Attorney. This will allow a shared care plan to be developed that takes his wishes into account while ensuring the plan is safe and manageable for the family.',
    'Offer to refer the family to the Macmillan service, who can provide experienced palliative care nurses and bereavement counsellors. They can also support the children by helping prepare them for what is happening in a sensitive and age-appropriate way, and can guide the family through the possibility of a death at home.',
    'Inform her about the SR1 form, which supports benefit claims under the Special Rules for End-of-Life Care for people with a terminal illness. Completing this form enables fast-tracked access to financial support from the Department for Work and Pensions (DWP). Offer to complete and submit the form on her behalf.',
    'Offer a referral to Occupational Therapy, who can visit the home to assess for practical modifications or equipment — such as a hospital bed, hoist, commode, or pressure-relieving mattress — to help keep her husband safe and comfortable.',
    'Provide her with the dedicated contact numbers used for palliative care patients, ensuring she has direct and timely access to the GP and district nursing team during working hours for any concerns related to his care.',
    'Arrange a follow-up appointment or home visit within the next few days to confirm that the relevant teams have been in contact and that she feels supported.'
  ],
  'Thank you so much for calling today, Karen. I want you to know that I have read through the letter from the neurology team and I understand a little of what you and your family are going through right now. This is an incredibly difficult time, and I want you to know that we are here to support you and Peter every step of the way.

I''m glad to hear that the Oramorph is helping with Peter''s pain — you are doing a wonderful job managing his care at home. Let me take you through the other medications so that you feel confident about what each one is for and when it might be needed.

These medications are what we sometimes call ''anticipatory'' or ''just in case'' medications. They are prescribed in advance for people being cared for at home in the later stages of life, so that if any distressing symptoms arise, they can be treated quickly without delay. The morphine you are already giving via the PEG tube is used for pain and breathlessness. If it is ever needed in the future and the PEG tube is no longer being used, it can also be given as a continuous small injection under the skin through a device called a syringe driver.

The other three medications are given as small injections under the skin when needed. Hyoscine butylbromide helps to reduce and manage secretions that can build up in the throat and airways, sometimes causing a noisy or wet-sounding breathing — it is not painful, but it can be distressing for families to hear, so it is reassuring to know we have something to help. Levomepromazine can be used if Peter ever experiences nausea or vomiting. Midazolam is for anxiety, restlessness, or agitation — again, I understand he is not experiencing any of these symptoms right now, which is very good news, but it is important that we are prepared.

I will arrange for the district nursing team to visit you at home. They will be able to give these injections if and when they are ever needed, and they can also show you how to give them yourself if you ever feel comfortable doing so. They will also be on hand to support you with the PEG tube and any other nursing needs.

I want to come back to the question you asked about whether Peter should remain at home or consider moving to a hospice. This is one of the most important and most personal decisions a family can face, and I want you to know there is no right or wrong answer. What I would suggest is that we arrange what is called a best interests meeting — bringing together yourself as his Lasting Power of Attorney, the district nurses, the community palliative care team, and myself — to talk through the options together and develop a plan that honours Peter''s wishes while also taking into account what is realistic and emotionally manageable for you and the children.

I would also like to refer you to the Macmillan service. Their nurses are very experienced in situations like this. They can offer emotional support and counselling for you, and they are also very skilled at helping parents find the right words to talk to young children about serious illness and what is happening. You should not have to navigate that conversation alone.

Finally, I want to let you know about a form called an SR1, which I can complete on your behalf. It helps to fast-track access to financial support from the government for families in Peter''s situation, and I want to make sure that is in place for you. I will also arrange for an occupational therapist to visit, as there may be equipment or adjustments to the home that could make things easier and more comfortable for Peter day to day.

I will follow up with you in the next few days to make sure the right teams are in place and that you are feeling supported. Please do not hesitate to reach out to us at any time.',
  ARRAY[
    'Anticipatory medications — often called ''just in case'' medications — are prescribed in advance in palliative care to manage symptoms that may arise in the final stages of life: morphine for pain and breathlessness, hyoscine butylbromide for secretions, levomepromazine for nausea and agitation, and midazolam for anxiety and restlessness.',
    'A syringe driver (continuous subcutaneous infusion) is used when a patient can no longer tolerate oral medication or when symptom control requires continuous delivery rather than intermittent doses.',
    'Where a Lasting Power of Attorney (LPA) for Health and Welfare is in place, the LPA holder can formally represent the patient''s wishes and participate in best interests meetings as part of shared decision-making.',
    'A best interests meeting involving the GP, community palliative care team, district nurses, and family is the appropriate framework for resolving complex decisions about preferred place of death.',
    'The SR1 form enables fast-tracked access to benefits under the Special Rules for End-of-Life Care and should be completed proactively by the GP for patients with a terminal illness.',
    'Macmillan nurses and specialist counsellors can provide psychological support for both carers and children, including age-appropriate preparation for bereavement.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  197,
  'UTI in a Patient with Poorly Controlled Type 2 Diabetes',
  'Travel Health & Infectious Disease',
  'Video Consultation',
  false,
  'Rachel Okafor',
  '47-year-old female',
  ARRAY['Type 2 Diabetes'],
  ARRAY[]::text[],
  'Seen by Healthcare Assistant (Debbie Burton) – 1 Week Ago

Presenting Complaint: Patient attended for a routine diabetes review.

Examination Findings:
Blood pressure: 120/80 mmHg | Pulse: 72 bpm | BMI: 30
Urinalysis: positive for leucocytes and nitrites. Patient also reported urinary symptoms.
A mid-stream urine (MSU) sample was sent for culture.

Plan: To follow up with GP once results are available.

Blood Test Results:
HbA1c — Previous (3 months ago): 63 mmol/mol | Current: 73 mmol/mol (ref 20–42 mmol/mol)
Sodium (Na): 139 mmol/L (ref 135–145 mmol/L)
Potassium (K): 4.2 mmol/L (ref 3.5–5.0 mmol/L)
Urea: 5.2 mmol/L (ref 2.5–7.8 mmol/L)
Creatinine: 79 µmol/L (ref 60–110 µmol/L)
eGFR: >90 mL/min/1.73m² (ref ≥90 mL/min/1.73m²)

Urine Culture Report:
Specimen: Mid-stream urine (MSU)
Culture Result: Heavy pure growth of Escherichia coli (>10⁸ CFU/L). No other organisms isolated.
Antimicrobial Sensitivity: Please see attached sensitivity report.
Interpretation: Significant bacteriuria consistent with urinary tract infection.

Drug History: Metformin 1g twice daily | Gliclazide 160 mg twice daily | No Known Drug Allergy',
  'The patient has booked a video consultation to discuss recent blood and urine test results from her routine diabetes review.',
  '',
  'You attended your routine diabetic check-up last week and were told that blood and urine samples would be taken. Over the past week, you have noticed that you need to pass urine more frequently than usual, including waking up at night to use the toilet. You also experience a stinging or burning sensation when passing urine.',
  ARRAY[]::text[],
  'You do not smoke or drink alcohol. You live with your husband of twelve years and your two sons. You work as a practice manager and spend much of your working day at a desk. You rarely exercise, though you have recently started cooking more at home and trying to include more vegetables in your diet. Gynaecology history (if asked): your last menstrual period was one week ago. You are not using any contraception, as your husband has had a vasectomy. You do not have any other sexual partners. This is your first episode of urinary symptoms.',
  'You suspect you might have a urinary tract infection.',
  'You are concerned because this is the first time you have experienced these symptoms and you are not sure why it has happened.',
  'You would like the doctor to explain what is going on and whether any treatment is needed.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY[
    'Begin by explaining that you have reviewed her recent test results and check that they match her understanding. For example: "I can see you had your routine diabetes blood tests last week, and a urine sample was also sent because there were signs suggesting a possible infection. Is that right?"',
    'Ask about symptoms suggestive of diabetic complications — including increased thirst, blurred vision, tingling in the hands or feet, and any non-healing wounds, particularly on the feet.',
    'Ask about the presence and onset of urinary symptoms, including frequency, urgency, stinging or burning, nocturia, suprapubic discomfort, or visible blood in the urine.',
    'Ask about systemic symptoms that may suggest a more severe or upper urinary tract infection, such as fever, rigors, or loin pain.',
    'Ask whether she has had previous urinary tract infections and, if so, how frequently — to identify whether this may represent a pattern of recurrent UTIs.',
    'Ask about her adherence to diabetic medications and whether she is experiencing any side effects.',
    'Ask about lifestyle factors including occupation, diet, exercise habits, smoking, and alcohol use.',
    'Explore the patient''s ideas, concerns, and expectations.',
    'Make a diagnosis of urinary tract infection in the context of poorly controlled type 2 diabetes.'
  ],
  ARRAY[
    'Offer an SGLT2 inhibitor (e.g. dapagliflozin or empagliflozin) to help improve blood glucose control and reduce the risk of cardiovascular and renal complications.',
    'Inform the patient of potential side effects of SGLT2 inhibitors, including increased risk of urinary tract infections, genital thrush, and, very rarely, a serious condition called Fournier''s gangrene. Reassure her that not everyone experiences these effects and that SGLT2 inhibitors are generally safe and effective. Advise her to contact the surgery or call 111 out of hours if she notices any concerning symptoms.',
    'Explain the sick day rules associated with SGLT2 inhibitors — advise her to stop the medication temporarily if she becomes unwell with vomiting, diarrhoea, reduced fluid intake, or any acute illness, to reduce the risk of dehydration or diabetic ketoacidosis. She should only restart once she has fully recovered and is eating and drinking normally.',
    'Prescribe antibiotics for the confirmed urinary tract infection based on culture sensitivity results. For example: nitrofurantoin 100 mg modified-release twice daily for 3 days, or trimethoprim 200 mg twice daily for 3 days.',
    'Advise self-care measures including maintaining good hydration.',
    'Explain that high blood glucose levels increase susceptibility to urinary tract infections, and that improving blood sugar control will help reduce the likelihood of future infections.',
    'Advise on lifestyle measures including a healthy balanced diet and regular physical activity, as these will help improve blood sugar control.',
    'Offer health promotion interventions including routine vaccinations (pneumococcal, influenza, and COVID-19), and ensure she is up to date with her annual diabetic foot and eye checks.',
    'Arrange follow-up in 3 months for a repeat HbA1c and full diabetic review.',
    'Safety-net: advise that if urinary symptoms persist or worsen, or if she develops a fever, loin pain, haematuria, abdominal pain, nausea, or vomiting, she should contact the GP urgently during working hours or call 111 out of hours.'
  ],
  'Thank you for booking in today, Rachel, and for attending your diabetes review last week — it was really important that we had those tests done. I''ve now had a chance to look through your results carefully, and there are a couple of things I''d like to go through with you.

The urine sample we sent off has confirmed a urinary tract infection — a UTI. The test shows a significant growth of a bacterium called Escherichia coli, which is the most common cause of urinary infections. That explains the symptoms you''ve been noticing over the past week — the burning on passing urine and needing to go more frequently, including at night. I''m going to prescribe you a short course of antibiotics today, selected based on what the urine culture shows the bacteria to be sensitive to. The most likely option will be nitrofurantoin 100 mg modified-release twice daily for three days, though I''ll confirm this based on the full sensitivity report. Do please make sure you drink plenty of fluids over the coming days as well, as that helps to flush the infection through.

I also want to talk about your blood sugar result, because it is relevant to why this infection has occurred. Your HbA1c — which is the measure we use to track your average blood sugar over the past three months — has come back at 73 mmol/mol. This is higher than three months ago when it was 63, and higher than we would like. When blood sugar levels are elevated, the body passes more glucose in the urine, and this creates an environment where bacteria can more easily take hold. So the UTI and the blood sugar result are closely connected. Getting your blood sugar better controlled will genuinely reduce the likelihood of infections like this happening again in the future.

I''d like to discuss adding a new type of medication to your current tablets. It''s called an SGLT2 inhibitor — examples include dapagliflozin and empagliflozin. These tablets work by helping the kidneys remove excess sugar from the blood into the urine, which lowers blood sugar levels. They also have proven benefits for the heart and kidneys, which is particularly important for people with type 2 diabetes. I do want to be transparent with you: because they work by passing sugar in the urine, they can slightly increase the risk of UTIs and genital thrush in some people. They are generally very safe and well tolerated, and not everyone experiences these side effects — but I want you to be aware. If you notice any unusual or worrying symptoms after starting them, please do get in touch.

One important thing to know about this type of medication: if you ever become unwell — with sickness, diarrhoea, or if you''re unable to eat and drink normally — you should stop taking it temporarily until you have fully recovered. This is called the sick day rule and it helps prevent a rare but serious complication. You would restart it once you are eating and drinking normally again.

I''d also like to make sure you are up to date with your annual diabetic foot check and eye screening, and that you have had your flu, pneumococcal, and COVID-19 vaccinations. These are all an important part of looking after yourself with diabetes.

I''ll book you in for a follow-up appointment in three months for a repeat blood test to check your HbA1c. In the meantime, if your urinary symptoms don''t settle with the antibiotics, or if at any point you develop a fever, pain in your back or sides, blood in your urine, or feel generally unwell, please contact us promptly or call 111 if we are closed.',
  ARRAY[
    'Poorly controlled type 2 diabetes (elevated HbA1c) is a significant risk factor for urinary tract infections, as glycosuria creates a growth medium for bacteria in the urinary tract.',
    'A confirmed UTI with positive urine culture should be treated with antibiotics guided by sensitivity results — common first-line options include nitrofurantoin 100 mg MR twice daily for 3 days or trimethoprim 200 mg twice daily for 3 days in uncomplicated lower UTIs.',
    'SGLT2 inhibitors (e.g. dapagliflozin, empagliflozin) are an effective second-line addition in type 2 diabetes and offer additional cardiovascular and renal protection; known side effects include increased risk of UTIs and genital thrush.',
    'Sick day rules for SGLT2 inhibitors: the medication should be stopped temporarily during acute illness with vomiting, diarrhoea, or reduced oral intake due to the risk of euglycaemic diabetic ketoacidosis.',
    'Systemic symptoms such as fever, loin pain, or rigors in a patient with UTI suggest upper urinary tract involvement (pyelonephritis) and require escalated management.',
    'Annual diabetic health checks — including HbA1c, foot examination, retinal screening, and vaccinations — should be reinforced at every relevant consultation.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  198,
  'Unvaccinated Child with Suspected Whooping Cough',
  'Paediatrics',
  'Telephone Consultation',
  false,
  'Ryan Fletcher',
  '8-year-old male',
  ARRAY['None Recorded'],
  ARRAY['Not currently on any regular medication.','No Known Drug Allergy'],
  'No significant recent consultations. Caller: Sandra Fletcher (Patient''s Mum).',
  'Mother has telephoned requesting advice about her son, who she believes may have whooping cough.',
  'Hi doctor, I think my son has whooping cough and I need you to give him something for it.',
  'Ryan, your son, has had a dry cough for the past two to three days. The cough is dry with no phlegm. It can happen at any time during the day. There is no whooping sound, no gasping for breath between coughing fits, and he does not seem to struggle to breathe. He has not been sick after coughing. He is otherwise well and is currently attending school. You believe he has whooping cough because there has been a coughing illness going around his class — parents were sent a letter about it. It has not been officially confirmed as whooping cough, but you know it can spread easily between children.',
  ARRAY[]::text[],
  'He lives with you, his father, and his younger brother. No one else at home has a cough. No one smokes at home. He attends school in year four and there have been no issues at school. He was born at full term with no complications during pregnancy or delivery. He has not received any vaccinations because you read an article online suggesting that vaccines are linked with autism and mental health conditions in children. You therefore believe it is better to build natural immunity through a healthy diet with plenty of fruit and vegetables. Your husband shares this view. He is developing well in all areas.',
  'You believe your son has whooping cough.',
  'You want to know whether he needs antibiotics and whether he should be kept off school.',
  'You want the GP to prescribe antibiotics for your son. If you are offered a face-to-face appointment today, say that you are unable to attend because he is at school and you are at work, but that you would be able to bring him in tomorrow.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY[
    'Ask about the onset, duration, and nature of the cough — whether it came on gradually or suddenly.',
    'Ask whether the cough is dry or producing any phlegm.',
    'Ask about classic features of whooping cough: whether there is a whooping sound at the end of coughing fits, prolonged bouts of coughing that are difficult to stop, and whether Ryan vomits after coughing episodes (post-tussive vomiting).',
    'Ask about associated symptoms such as runny nose, sore throat, fever, difficulty breathing, or chest pain.',
    'Ask whether Ryan has been in contact with anyone who has been diagnosed with whooping cough or who has a similar cough.',
    'Ask whether he is eating and drinking normally and passing urine as usual.',
    'Ask whether the cough is disturbing his sleep or affecting his daily activities.',
    'Ask about PBIND: pregnancy and birth history, immunisation status, nutrition, and development.',
    'Sensitively explore the reasons behind the decision not to vaccinate.',
    'Ask about the home and social environment: who lives at home, whether anyone else is unwell, and whether Ryan is currently attending school.',
    'Ask whether the school has issued any public health communications or notifications about a cough illness.',
    'Explore the mother''s ideas, concerns, and expectations.',
    'Give a working diagnosis of likely viral upper respiratory tract infection.'
  ],
  ARRAY[
    'Reassure the mother that, based on the history, this does not currently sound like typical whooping cough — there is no whooping sound, no prolonged coughing fits, no post-tussive vomiting, and no confirmed contact with a diagnosed case.',
    'Explain that the symptoms are more consistent with a mild viral upper respiratory tract infection, which is very common in school-age children.',
    'Advise that antibiotics are not needed at this stage, as they are only effective against bacterial infections and this presentation does not suggest one.',
    'Offer a face-to-face appointment to assess Ryan further, or if symptoms worsen.',
    'Provide self-care advice: rest, adequate fluid intake, and paracetamol or ibuprofen if he is uncomfortable.',
    'Discuss the importance of routine childhood immunisations in a non-judgemental way, and explain that there is no reliable scientific evidence linking vaccines to autism or mental health conditions.',
    'Inform her that vaccines protect children from serious diseases such as whooping cough, and that vaccinated children who do catch it tend to have a much milder illness and recover more quickly.',
    'Offer to send information leaflets from reputable sources such as the NHS and the World Health Organization (WHO), so that she can read further at her own pace.',
    'Advise that there is no need to keep Ryan off school at present, as he is well enough to attend.',
    'Encourage good hand hygiene to help reduce the spread of infection in the household and at school.',
    'Provide safety-netting advice: advise the mother to contact the GP promptly — or call 111 if out of hours — if the cough becomes significantly worse, Ryan develops a high fever, has difficulty breathing, appears drowsy, is not drinking well, or is not passing urine as normal.'
  ],
  'Thank you for calling in today, Sandra, and I can hear that you are concerned — and rightly so for keeping an eye on things. Let me share with you what I think is going on based on everything you''ve told me.

From what you''ve described, Ryan has had a dry cough for the past two to three days. I want to be thorough here, so I asked you about the features that we specifically associate with whooping cough — the prolonged coughing fits that are hard to stop, the distinctive whooping sound at the end of a cough, and vomiting after coughing. None of those are present. He is also otherwise well in himself and still attending school, which is very reassuring. At this stage, what you''re describing sounds much more like a common viral cough, which is extremely frequent in school-age children — especially when a cough is circulating in the class.

I do understand why the school letter made you think of whooping cough, and it was absolutely right to call and check. Viral coughs spread very easily in schools, and it''s quite possible that Ryan and several of his classmates have all picked up the same common cold virus. Without the specific features I mentioned, whooping cough is unlikely.

Because antibiotics only work against bacterial infections, they wouldn''t help with a viral cough and could actually cause unnecessary side effects such as stomach upset or diarrhoea. So I wouldn''t want to prescribe them without a good reason. In the meantime, please make sure Ryan is drinking plenty of fluids and is resting when he needs to. You can give him paracetamol or ibuprofen if he''s uncomfortable. There''s no need to keep him off school for now, as he is well enough to go — but do continue to encourage good handwashing to help stop any infection spreading.

I would like to see Ryan face to face so I can listen to his chest and give him a proper examination. Since you can''t make it today, let''s arrange for tomorrow — does that work for you?

You mentioned that Ryan hasn''t been vaccinated. I want to say first and foremost that I completely respect that you made this decision based on what you felt was best for your son, and I understand you read something that caused concern. The suggestion that vaccines cause autism or mental health problems has been studied very extensively, and the scientific evidence does not support that link. The original study that started that claim was found to be deeply flawed and was retracted.

What vaccines do is protect children from illnesses that, while rare thanks to vaccination programmes, can be very serious. Whooping cough is a good example — vaccinated children are far better protected, and if they do catch it, they tend to have a much milder illness. I don''t want to pressure you at all, and this is entirely your decision. What I can do is send you some information from the NHS and the World Health Organization so you can read through it in your own time and we can talk about it again whenever you feel ready.

Please do get back in touch with us — or call 111 if we are closed — if Ryan''s cough gets worse, if he develops a high temperature, has any difficulty breathing, seems very drowsy, is not drinking well, or is not passing urine as he normally would.',
  ARRAY[
    'Whooping cough (pertussis, caused by Bordetella pertussis) is a notifiable disease characterised by prolonged paroxysmal coughing, an inspiratory whoop, and post-tussive vomiting — the absence of these features makes the diagnosis unlikely.',
    'A dry cough without these classic features in a well child attending school is more consistent with a viral upper respiratory tract infection; antibiotics are not indicated.',
    'Macrolide antibiotics (azithromycin, clarithromycin, or erythromycin) should be offered for whooping cough if the cough began within the past 14 days, to reduce transmission and severity; treatment may be considered up to 21 days in cases with high-risk household contacts.',
    'Children with confirmed or suspected whooping cough should be excluded from school until 48 hours of appropriate antibiotic treatment have been completed, or for 14 days from symptom onset if not treated.',
    'Vaccine hesitancy should be approached with empathy and without judgement — explore concerns, share accurate evidence-based information, and offer written resources (NHS, WHO); avoid confrontation and leave the door open for future discussion.',
    'There is no credible scientific evidence linking childhood vaccines to autism or mental health conditions; the original paper making this claim was retracted due to serious methodological flaws and ethical violations.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  199,
  'Medication Review Following Recent Myocardial',
  'Cardiology',
  'Video Consultation',
  false,
  'Dorothy Simmons',
  '79-year-old female',
  ARRAY['None Recorded'],
  ARRAY['Not currently on any regular medication','No Known Drug Allergy'],
  'Discharge summary received from Cardiology two days ago RE: Dorothy Simmons | 79 years old | Female Summary of Admission: Mrs Simmons was admitted via A&E following a 2-hour history of sudden central chest pain radiating to the left arm, associated with shortness of breath and sweating. On admission, initial bloods revealed elevated high-sensitivity troponin T (peak 1,200 ng/L), consistent with myocardial injury. Serial ECGs showed ST-segment elevation in leads V2-V4, indicative of an anterior wall myocardial infarction. Urgent coronary angiography was performed, which demonstrated a 95% occlusion in the proximal left anterior descending (LAD) coronary artery, with good distal vessel flow preserved. She subsequently underwent urgent percutaneous coronary intervention (PCI) with balloon angioplasty and deployment of a drug-eluting stent to the proximal LAD, achieving TIMI 3 flow with no residual stenosis. She was monitored in the coronary care unit for 48 hours post-procedure, with no complications. Medications Initiated During This Admission: PCI) chest pain relief admission anxiety). Follow-up and Ongoing Plan: will contact her within 2 weeks to arrange outpatient sessions focusing on exercise, education, and lifestyle modification. GP Actions: initiation. persists. Kind regards, Dr Ashley Saunders Senior House Officer Cardiology Consultant in Charge: Dr Alex Kanu, MBBS, MRCP(UK), FESC, FRCP (Edin)',
  'The patient has booked a routine video consultation to discuss her recent hospital admission and newly prescribed medications.',
  'Hello doctor, I''ve been feeling quite lightheaded and I''m having real difficulty moving around the house. I was also given a lot of new medicines in hospital. I''ve never been on tablets before and I''m not entirely sure what they''re all for.',
  'About a week ago you had a very frightening episode of central chest pain and called for an ambulance. The paramedics told you that you were having a heart attack, which was confirmed when you arrived at hospital. You were admitted for five days and discharged two days ago with a number of new tablets that you do not fully understand. You remember being told to take one tablet at bedtime called temazepam, which is the only one you know the purpose of. While you were in hospital, the constant noise and beeping from the monitors left you feeling anxious and unable to sleep, so this medication was given to help you rest. You feel better now that you are back home in a quiet environment. During the day you often feel lightheaded, which makes it hard to get around the house. The dizziness tends to be worse in the mornings and early afternoons and can come on whether you are seated or standing. It feels like light-headedness and a general sense of exhaustion — almost like a hangover — although you have not had any alcohol.',
  ARRAY[]::text[],
  'You live on your own. Your husband passed away seven years ago from prostate cancer. You do not smoke or drink alcohol. Your son, who lives about five miles away, does your grocery shopping. You usually manage the cooking and housework yourself, but since feeling dizzy and tired you have been unable to cope and have been relying on ready-made meals. You do not drive.',
  'You are not entirely sure what is causing the dizziness but suspect it could be related to one or more of your new tablets.',
  'You are concerned that you might fall if the dizziness carries on.',
  'You would like the doctor to go through what each of the medications is for and whether it might be possible to stop some or all of them.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided.',
  ARRAY[
    'Begin by acknowledging that you can see from the discharge letter that she was recently admitted to hospital, and ask how she is getting on. For example: "Mrs Simmons, I can see from your discharge paperwork that you were admitted after having chest pain and were found to have had a heart attack, which was treated. How are you feeling now?"',
    'Ask about the onset, frequency, duration, and severity of the dizziness.',
    'Clarify what she means by dizziness — whether it feels like light-headedness or a spinning sensation.',
    'Ask whether the dizziness occurs in a particular position, such as on standing or sitting, or whether there are any specific triggers.',
    'Ask about associated symptoms such as syncope (fainting or collapse), chest pain, palpitations, shortness of breath, visual changes, headache, nausea, or vomiting.',
    'Ask about ankle swelling, breathlessness when lying flat (orthopnoea), or waking at night gasping for breath (paroxysmal nocturnal dyspnoea), to help rule out heart failure as a post-MI complication.',
    'Ask about any falls, near-falls, or unsteadiness when walking.',
    'Ask whether she has been taking all of the newly prescribed medications as directed.',
    'Ask whether she has been eating and drinking normally since discharge, to rule out dehydration or poor oral intake.',
    'Ask about her sleep quality and whether she continues to take temazepam each night.',
    'Ask about her mood and whether she has been feeling anxious or low, as depression and anxiety are common following a hospital admission and a heart attack.',
    'Ask whether she has checked her blood pressure at home and, if so, whether she has noticed it being lower than usual.',
    'Ask about her social history, including smoking, alcohol use, who she lives with, and how she is managing daily activities such as cooking, cleaning, and shopping.',
    'Ask whether she currently drives (important given the dizziness; she should not drive when feeling dizzy. Post-MI, Group 1 drivers should check with their insurers but do not need to inform the DVLA; Group 2 drivers must stop driving for a set period and must notify the DVLA).',
    'Explore her ideas, concerns, and expectations about the medications and the dizziness.',
    'Make a diagnosis of medication-induced dizziness, possibly related to next-day sedative effects of temazepam or low blood pressure from new cardiac medications.'
  ],
  ARRAY[
    'Advise that her dizziness may be caused by her new medications. Explain that temazepam can cause next-day sedative effects and, as her sleep has improved since leaving hospital, it would be reasonable to consider stopping it.',
    'Explain that having never taken regular medication before and now being started on several new tablets all at once can feel overwhelming. Offer a referral to the pharmacist for a full medication review and consider arranging a dosette box or blister pack to help her take the right tablets at the right time and reduce the risk of missed or double doses.',
    'Offer a face-to-face appointment to examine her heart and chest and to measure her blood pressure both lying and standing, to rule out postural hypotension or low blood pressure from her new cardiac medications. Advise her that if low blood pressure is confirmed, the dose of her medication may need adjusting.',
    'Advise her to rise from sitting or lying slowly, stay well hydrated, and move carefully to reduce the risk of falls.',
    'Offer to arrange a blood test with the phlebotomist or healthcare assistant in 3 to 5 days to recheck her kidney function following commencement of the ACE inhibitor.',
    'Offer appropriate vaccinations, including the annual influenza vaccine.',
    'Check whether she has been contacted by the cardiac rehabilitation team and encourage her to attend, as this supports recovery and reduces the risk of a further heart attack.',
    'Provide safety-net advice: if she develops chest pain, she should stop what she is doing, sit down, and use her GTN spray as instructed. If the pain has not settled 5 minutes after the second dose of GTN, or if the pain worsens at any point, she must call 999 immediately. If her dizziness worsens, she collapses, or she develops palpitations, shortness of breath, or any other concerning symptoms, she should contact the surgery urgently or call 111 if out of hours.'
  ],
  'It''s really good to speak with you today, Dorothy, and I want to start by saying how sorry I am that you''ve been through such a frightening experience. Having a heart attack is an enormous shock, and it is completely understandable that things feel overwhelming right now, especially when you have never had to take regular medication before.

What happened to you is called a myocardial infarction — a heart attack — which occurred because one of the main arteries supplying blood to your heart became very narrowed and was almost completely blocked. The hospital team acted quickly and opened that artery using a procedure called a PCI, or percutaneous coronary intervention, where a tiny tube called a stent was placed to keep the artery open. You were in the best possible hands, and that treatment has been life-saving.

The tablets you were sent home with are not optional extras — they are an essential part of your recovery and are there to protect your heart going forward. They work in different ways: some reduce the risk of the stent becoming blocked again, others lower your cholesterol, manage your blood pressure, and protect your heart muscle. I do understand it feels like a lot, and I''d like to arrange for our pharmacist to sit down with you and go through each one individually so you know exactly what each tablet does and when to take it.

The dizziness you''ve been experiencing is something we need to take seriously and investigate properly. There are two likely explanations. The first is that the temazepam — the sleeping tablet you were given in hospital to help with the noise and anxiety — can linger in your system and cause a hangover-like feeling of lightheadedness and tiredness the following day. Now that your sleep has improved at home, it would be very reasonable to stop the temazepam, and I''d like to do that gradually and safely with you.

The second possibility is that one or more of the heart tablets is lowering your blood pressure a little too much, particularly when you move from lying or sitting to standing. This is called postural hypotension, and it is a well-recognised side effect, especially in the early weeks after starting these medications. I would like to bring you in for a face-to-face appointment so I can examine you and check your blood pressure in both positions. If we find your blood pressure is on the lower side, we may be able to adjust one of your doses to help you feel more comfortable.

In the meantime, there are a few practical things that will help keep you safe. Please take your time when getting up from a chair or from bed — do it slowly and in stages. Make sure you are drinking enough fluids each day, and eat regular meals. If you feel dizzy, sit or lie down immediately rather than risk a fall.

I also want to make sure we arrange a blood test in the next few days to check how your kidneys are responding to one of the new heart medications, which is routine and nothing to worry about. And please do attend cardiac rehabilitation when the team contacts you — it is a very supportive programme that will help you build your strength back up safely and understand your condition better.

Finally, and very importantly: if you ever develop chest pain again, please stop what you are doing, sit down, and use your GTN spray under the tongue. If the pain has not gone away five minutes after a second dose, or if it gets worse at any point, you must call 999 straight away. Please do not hesitate to call us or 111 out of hours if anything else worries you.',
  ARRAY[
    'Following a myocardial infarction treated with PCI, patients are typically discharged on dual antiplatelet therapy, a statin, an ACE inhibitor, and a beta-blocker — it is important to recognise these and understand their individual roles.',
    'Temazepam commonly causes next-day sedative effects in elderly patients; once the indication (in-hospital insomnia) has resolved, it should be reviewed and stopped if no longer needed.',
    'Post-MI dizziness may reflect postural hypotension from new antihypertensive or heart failure medications; a lying-and-standing blood pressure measurement at a face-to-face appointment is essential.',
    'Renal function should be rechecked within one week of starting an ACE inhibitor, particularly in elderly patients.',
    'Post-MI driving advice differs by licence group: Group 1 drivers do not need to notify the DVLA but should check with their insurer; Group 2 drivers must notify the DVLA and are subject to a specified period off the road.',
    'Cardiac rehabilitation reduces the risk of a further cardiac event and improves recovery outcomes — all eligible patients should be actively encouraged to attend.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  200,
  'Fatigue and Microcytic Anaemia in a Middle-',
  'Gastroenterology & Haematology',
  'Telephone Consultation',
  false,
  'Rachel Foster',
  '45-year-old female',
  ARRAY['None Recorded'],
  ARRAY['Desogestrel 75 micrograms once daily for contraception','No Known Drug Allergy'],
  'Telephone consultation with Dr Giuseppe Mancini (Clinical Practitioner) - 3 days ago. Presenting complaint: The patient reported feeling tired all the time, which is now affecting her daily life. She requested a general blood test. She stated that her mood is fine, her periods are regular, and there is no possibility of pregnancy. Plan: Blood tests arranged. Follow up with blood test results. Blood Test Results Parameter Result Reference Range Haemoglobin 108 g/L 115–165 g/L Haematocrit (Hct) 0.28 0.36–0.47 Mean Corpuscular Volume (MCV) 77 fL 80–100 fL Mean Corpuscular Haemoglobin (MCH) 22 pg 27–32 pg Mean Corpuscular Hb Concentration (MCHC) 290 g/L 310–360 g/L White Cell Count (WCC) 6.2 ×10⁹/L 4–11 ×10⁹/L Neutrophils 3.5 ×10⁹/L 2–7.5 ×10⁹/L Lymphocytes 1.8 ×10⁹/L 1.0–3.5 ×10⁹/L Platelets 320 ×10⁹/L 150–450 ×10⁹/L Ferritin 8 µg/L 15–300 µg/L Vitamin B12 110 ng/L 180–900 ng/L Folate 6.5 µg/L 3.0–20.0 µg/L Liver Function Test (LFT), Bone Profile (including calcium), Thyroid Function Test, HbA1c Normal All within reference range',
  'The patient has booked a follow-up telephone consultation to discuss her recent blood test results.',
  'Hello doctor, I''m calling to go through my blood test results.',
  'You have been feeling tired for the past three months and it is steadily getting worse. Despite sleeping well at night, you still feel exhausted during the day and simply want to rest. The fatigue is constant and is beginning to affect your ability to carry out your job. You work as an estate agent.',
  ARRAY[
    'You have also lost around 5 kg over the past two to three months, but this has been deliberate as you have been trying to eat more healthily and get more exercise.',
    'You have had no abdominal pain and no change in your bowel habits, and you have not experienced any nausea or vomiting.',
    'You eat what you consider to be a healthy diet. You are vegetarian and eat vegetables, fruit, grains, nuts, and seeds, but do not eat meat, fish, or seafood. You do consume dairy products and eggs. You have been vegetarian your whole life.',
    'You are unsure about your family medical history as you are adopted.',
    'Gynaecology History: You have not had a period for the past 18 months since starting desogestrel. You took a pregnancy test three days ago, which was negative.',
    'If asked about hot flushes, night sweats, irritability, or other symptoms of menopause, say that you have not experienced any of these.'
  ],
  'You live with your partner and teenage daughter. Everything is well at home. You do not smoke, drink alcohol, or use recreational drugs.',
  'You are not sure what is causing your symptoms.',
  'The tiredness is affecting your work and you have had to call in sick on several occasions. You have been off work for the past six days.',
  'You would like the doctor to explain what the blood tests show and whether the results could account for how tired you have been feeling.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided.',
  ARRAY[
    'Acknowledge the recent consultation and confirm the purpose of today''s call. For example: "Rachel, I can see from your records that you spoke with my colleague three days ago because you were feeling exhausted, and they arranged some blood tests. Is that right?"',
    'Ask about the onset and progression of the fatigue.',
    'Ask whether the tiredness is constant or varies throughout the day, and whether it is getting worse, improving, or staying the same.',
    'Ask about the impact of the tiredness on her daily activities, work, and quality of life.',
    'Ask about her periods, including her last menstrual period, whether her cycles are regular, whether she has experienced heavy bleeding, and whether there is any possibility of pregnancy.',
    'Ask whether she has noticed bleeding from any site, including blood in her stools, dark or tarry stools, abnormal vaginal bleeding, nosebleeds, bleeding gums, blood in her urine, or vomiting blood.',
    'Ask whether she has developed any new abdominal pain or noticed any lumps or masses.',
    'Ask about associated gastrointestinal symptoms such as nausea, vomiting, fever, diarrhoea, constipation, bloating, early satiety, or heartburn.',
    'Ask about symptoms of anaemia, including dizziness, breathlessness on exertion, palpitations, or chest pain.',
    'Ask about symptoms of vitamin B12 deficiency, including blurred vision, tingling or numbness anywhere in the body, and any difficulties with balance or walking.',
    'Ask about unintentional weight loss and night sweats.',
    'Ask about any known family history of bowel cancer or other malignancies.',
    'Ask about her diet, particularly her intake of iron-rich foods, and whether she has made any recent dietary changes.',
    'Ask about mood, sleep quality, and appetite.',
    'Ask about social history including smoking, alcohol use, occupation, and any sources of stress.',
    'Explore her ideas, concerns, and expectations about her symptoms and results.',
    'Make a diagnosis of microcytic anaemia, most likely iron deficiency anaemia, with possible gastrointestinal blood loss or bowel cancer as an underlying cause.'
  ],
  ARRAY[
    'Offer a face-to-face appointment to examine her abdomen and assess her observations.',
    'Arrange a FIT test and further blood tests including a coeliac screen.',
    'Offer a urine dip to check for haematuria.',
    'Start iron replacement therapy with ferrous sulfate 200 mg once daily for three months.',
    'Offer vitamin B12 replacement, either oral or intramuscular depending on symptoms and clinical judgement.',
    'Explain that if her urine test does not show blood, she will be referred to a gastroenterologist for further investigation, including bidirectional endoscopy such as gastroscopy with or without colonoscopy, as iron deficiency in this context may indicate gastrointestinal blood loss, including serious causes such as cancer.',
    'Offer a fit note for amended duties or time off work if her symptoms are affecting her ability to work.',
    'Advise a diet rich in iron, including green leafy vegetables, beans, lentils, nuts, and fortified cereals.',
    'Advise on vitamin B12 sources, including fortified breakfast cereals, eggs, milk, and cheese.',
    'Provide safety-net advice to seek medical attention if symptoms worsen or if she develops dizziness, fainting, palpitations, tingling sensations, blurred vision, problems with balance, shortness of breath, or any new concerns. Advise contacting the surgery or calling NHS 111 if out of hours.',
    'Arrange follow-up to review investigation results including the FIT test and blood tests, and to reassess her response to treatment.'
  ],
  'Thank you so much for calling in today, Rachel. I have your blood test results in front of me and I want to go through everything clearly so you understand what we have found and what we are going to do about it.

The results show that you have anaemia, which means the level of haemoglobin — the protein in your red blood cells that carries oxygen around your body — is lower than it should be. Your reading is 108 g/L, and for a woman your age the lower end of normal is 115 g/L. When we look at the additional red cell measurements, the cells are smaller than average and contain less haemoglobin than normal. This pattern is called microcytic anaemia, and it most commonly points to iron deficiency, which your results confirm — your ferritin level, which is the body''s iron store, is only 8 µg/L when it should be at least 15 µg/L.

We have also noticed that your vitamin B12 is on the low side, coming in at 110 ng/L against a normal range of 180 to 900 ng/L. B12 deficiency can cause tiredness and, in some cases, sensations of tingling or numbness, although your pattern of anaemia is predominantly iron-related. It is still important that we address both.

The key question now is: why are you iron deficient? You have told me you eat a vegetarian diet, which can sometimes make it harder to absorb iron as plant-based sources are not as readily absorbed as meat-based iron. However, given your age and the degree of deficiency, we cannot assume diet alone explains this. Iron deficiency can sometimes be caused by blood loss from the gut, even if you haven''t noticed it. This is something we take seriously and need to investigate properly.

To start with, I would like you to do a FIT test — this stands for faecal immunochemical test — which checks for tiny amounts of blood in the stool that you would not be able to see with the naked eye. I also want to run a blood test to check for coeliac disease, which is a condition affecting the gut''s ability to absorb nutrients including iron. We will also ask you to provide a urine sample to check whether there is any blood there.

In the meantime, I am going to start you on iron replacement: ferrous sulfate 200 mg once a day, which you should take with a glass of orange juice if possible as the vitamin C helps with absorption. We will also address the B12 deficiency and discuss whether oral supplements or an injection would be most appropriate for you.

If the urine sample is clear and the FIT test is positive, or if symptoms continue to progress, I will arrange a referral to a gastroenterologist for a more detailed look at your digestive system — this may involve a camera test of the stomach and bowel. I know that can sound daunting but it is a routine procedure and the best way to make sure nothing is being missed.

Please do contact us sooner if your symptoms worsen significantly, or if you develop any dizziness, fainting, palpitations, difficulty with your balance, or any new concerns. We will arrange a follow-up call to go through all the results together once they are back.',
  ARRAY[
    'Microcytic anaemia with low ferritin (ferritin 8 µg/L, ref 15–300 µg/L) in a middle-aged woman is iron deficiency anaemia until proven otherwise; gastrointestinal blood loss including malignancy must be excluded regardless of dietary history.',
    'A FIT test and coeliac screen are first-line investigations in iron deficiency anaemia where an obvious dietary cause is not sufficient to explain the degree of deficiency.',
    'Iron replacement with ferrous sulfate 200 mg once daily for three months is standard treatment; patients should be advised to take it with vitamin C to enhance absorption.',
    'Vitamin B12 deficiency (B12 110 ng/L, ref 180–900 ng/L) must be identified and treated alongside iron deficiency; route of replacement (oral vs intramuscular) depends on clinical presentation and severity of deficiency.',
    'A vegetarian diet reduces iron bioavailability but should not be accepted as the sole explanation for iron deficiency anaemia in the absence of adequate investigation.',
    'Bidirectional endoscopy (gastroscopy and/or colonoscopy) is indicated when iron deficiency anaemia cannot be explained by dietary factors and initial investigations are inconclusive or concerning.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  201,
  'Opioid-Induced Constipation',
  'General Practice',
  'Video Consultation',
  false,
  'Adam Fletcher',
  '34-year-old male',
  ARRAY['Meniscal tear'],
  ARRAY['Co-codamol 30/500 1–2 tablets every 6 hours as required for pain (Maximum 8 tablets a day)','No Known Drug Allergy'],
  'Letter from Fracture Clinic, Department of Trauma and Orthopaedics – 6 weeks ago. Dear GP, RE: Adam Fletcher | 34-year-old | male Mr Fletcher was referred to our Fracture Clinic today by the Urgent Treatment Centre with a 3-day history of right knee pain. He reports twisting his right knee during a football match. Immediately following the injury, he experienced significant swelling, associated with intermittent pain. He also reports episodes where the knee intermittently catches and locks. On examination today, the right knee was swollen, with tenderness along the medial joint line. Range of movement was slightly reduced due to discomfort. An ultrasound scan has shown a small meniscal tear measuring approximately 0.3 cm. There is no evidence of significant ligamentous injury. We have advised conservative management at this stage, including rest, ice, compression with an elastic knee bandage, and elevation as tolerated. For analgesia, he has been prescribed co-codamol. He has also been advised to self-refer to Community MSK Physiotherapy for ongoing rehabilitation and strengthening exercises. Mr Fletcher has been informed that if his symptoms fail to improve, worsen, or if he develops increased locking or instability, he should contact our service for reassessment. Please do not hesitate to get in touch if you require any further information. Yours sincerely, Mr Jonathan Clarke MBBS, FRCS (Tr&Orth) Consultant Orthopaedic Surgeon',
  'The patient has booked a video consultation to discuss a bowel problem he has been experiencing.',
  'Hi doctor, I''m having trouble opening my bowels.',
  'You have been struggling to open your bowels for the past three to four weeks. Your stools are hard and you sometimes go as long as three days without having a bowel movement, whereas before this was regular for you.',
  ARRAY[
    'You have not noticed any blood in your stools, but you have felt a lump near your back passage, which is what prompted you to book this appointment. You first noticed it about five days ago. It feels firm and painful, particularly when sitting, and you are unable to push it back inside. Your partner has looked at it and says it appears purplish in colour. You have not had any nausea or vomiting. You get some mild tummy discomfort but no significant pain. You have had no fever and no weight loss.',
    'You are currently taking co-codamol for your right knee pain, which you injured during sport. You were told you could take up to eight tablets a day. Initially you were taking eight tablets daily, but you have now reduced this to about four tablets a day, which helps to relieve the pain. You have recently started physiotherapy for the knee and this has also been helping.',
    'You try to maintain a healthy diet as someone who is physically active, including a reasonable amount of fibre, and you keep yourself well hydrated.'
  ],
  'You do not smoke or drink alcohol. You work as a personal trainer, although you have not been able to work since your knee injury six weeks ago. You live with your partner.',
  'You are not sure what has caused your symptoms.',
  'You are concerned about the lump near your back passage because you have always been told that any new lump should be checked to rule out something serious.',
  'You would like the doctor to explain what is happening and tell you what you should do.',
  ARRAY['If the doctor asks whether you can stop taking co-codamol, agree and say that you are happy to switch to something else and try paracetamol instead.'],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided.',
  ARRAY[
    'Ask the patient to clarify what he means by having trouble opening his bowels — whether he is going less often than usual or passing harder stools.',
    'Ask about the onset and progression of the constipation.',
    'Ask about stool consistency, for example whether stools are hard, small and pebble-like, or large and difficult to pass.',
    'Ask about his usual bowel habits and whether this problem is new for him or has occurred in the past.',
    'Ask about associated symptoms such as pain when passing stool (which may suggest an anal fissure), abdominal pain, nausea, vomiting, bloating, urinary symptoms, abdominal masses, or anal lumps.',
    'Ask about the lump, including whether it feels hard, firm, or soft (hard lumps may raise concern for malignancy, whereas haemorrhoids are usually soft), whether it is painful (which may indicate a thrombosed haemorrhoid or anal fissure), and whether it can be pushed back in (if it can be reduced, this may suggest a rectal prolapse or prolapsed internal haemorrhoid).',
    'Ask about the colour of the lump, as thrombosed external haemorrhoids typically appear purplish, while prolapsed internal haemorrhoids may appear bluish.',
    'Ask about features of faecal impaction such as overflow diarrhoea or soiling of underwear, a feeling of incomplete evacuation, or the need to use fingers to assist defecation.',
    'Ask about red flag symptoms including visible blood in stools, unintentional weight loss, fever, loss of appetite, night sweats, or a family history of bowel cancer.',
    'Ask how the constipation and lump are affecting his daily life and function.',
    'Ask about his knee injury recovery, and specifically about the dose, frequency, and duration of co-codamol use.',
    'Ask about his social history including smoking, alcohol use, occupation, and home situation.',
    'Explore his ideas, concerns, and expectations.',
    'Make a diagnosis of constipation most likely secondary to co-codamol use, with the lump likely representing a haemorrhoid.'
  ],
  ARRAY[
    'Offer a face-to-face appointment to examine his abdomen and perform a rectal examination with a chaperone present to fully assess the lump and exclude red flags.',
    'Advise reducing or stopping co-codamol if possible, and using alternative analgesia such as paracetamol or NSAIDs if there are no contraindications.',
    'Offer laxatives, including an osmotic laxative or a stimulant laxative. Examples of osmotic laxatives include macrogol or lactulose. Examples of stimulant laxatives include senna, bisacodyl, and docusate. Note: lactulose may cause gas and bloating and is not suitable for opioid-induced constipation. NICE recommends that for constipation caused by opioid medicines, patients should normally be offered both an osmotic laxative and a stimulant laxative — for example macrogol and senna together. However, if he agrees to stop the opioid medication (co-codamol), it is reasonable to start with just an osmotic laxative and see how he responds. If things do not improve, a stimulant laxative can then be added. If he continues taking the opioid, both types of laxative should be offered from the outset.',
    'Advise him that laxatives should not be stopped abruptly. They can be gradually reduced and discontinued once he is passing soft, formed stools without straining at least three times per week.',
    'Recommend increasing dietary fibre and maintaining good hydration.',
    'Explain that if the lump is confirmed to be a haemorrhoid, this can be managed with haemorrhoid creams available over the counter. If there are any concerns about the nature of the lump, referral to a colorectal specialist may be needed.',
    'Provide safety-net advice: although he will be assessed in person, if he develops severe abdominal pain, abdominal distension, vomiting, blood in stools, weight loss, or worsening symptoms, he should seek urgent medical advice by calling the surgery''s urgent line or 111 out of hours.',
    'Offer follow-up in two weeks to review his symptoms.'
  ],
  'Thank you for getting in touch and for describing what has been going on. I can see from your records that you injured your knee six weeks ago and were prescribed co-codamol for pain relief, and I think this is almost certainly connected to what you''re experiencing now.

Co-codamol contains codeine, which is an opioid painkiller. One of the most well-known and common side effects of opioids is that they slow down the movement of the bowel, which is exactly what causes the constipation you''ve been describing — the hard stools, the infrequent bowel movements, and the general difficulty you''ve been having. This is not a reflection of your diet or hydration; it is a direct pharmacological effect of the medication itself.

Regarding the lump you''ve noticed near your back passage, Adam — I want to reassure you that what you are describing sounds very consistent with a haemorrhoid, sometimes known as a pile. The purplish discolouration, the firmness, and the fact that it is painful and cannot be pushed back in are all features of what we call a thrombosed external haemorrhoid, which is essentially a small blood vessel that has become engorged and clotted just beneath the skin. While this is uncomfortable, it is not sinister. However, I do want to examine you properly to be certain, and I''d like to bring you in for a face-to-face appointment so I can check your abdomen and perform a rectal examination — I will ensure a chaperone is available for that.

In terms of what we can do right now to help, I''d like to discuss your pain relief. Now that you''ve started physiotherapy and your knee is improving, you''ve already reduced your co-codamol to four tablets a day, which is great. If you''re comfortable switching to regular paracetamol instead, that would be a very sensible step — removing the opioid component should help your bowel return to normal within a week or two.

I would also like to start you on a laxative to help in the short term. Because the constipation has been caused by an opioid, the current guidance recommends using both an osmotic laxative — such as macrogol, which draws water into the bowel — and a stimulant laxative such as senna, which helps the bowel contract and move stool along. Since you''re happy to stop the co-codamol, we can begin with just the osmotic laxative and see how you get on; if things don''t improve we can add a stimulant alongside it. These should be reduced gradually once your stools are soft and regular — typically three or more times a week without straining.

Once the haemorrhoid is confirmed, you can also pick up an over-the-counter haemorrhoid cream such as Anusol or Preparation H, which can soothe the discomfort in the meantime. Please do get in touch urgently — or call 111 if we are closed — if you develop severe abdominal pain, significant swelling of the tummy, vomiting, visible blood in your stools, or if you lose weight unexpectedly. We will arrange a follow-up in two weeks to see how you are progressing.',
  ARRAY[
    'Constipation is a predictable and common side effect of opioid analgesics, including co-codamol; the mechanism is direct inhibition of bowel motility and should be anticipated and managed proactively.',
    'NICE guidance recommends prescribing both an osmotic laxative (e.g. macrogol) and a stimulant laxative (e.g. senna) for opioid-induced constipation; lactulose should be avoided as it can worsen bloating and is not effective in this context.',
    'A thrombosed external haemorrhoid typically presents as a painful, non-reducible purplish lump near the anal margin; a face-to-face examination with a chaperone is essential to confirm the diagnosis and exclude malignancy.',
    'Red flag symptoms for colorectal cancer — visible rectal bleeding, unintentional weight loss, change in bowel habit, family history — must be actively screened for and documented even when a benign cause is suspected.',
    'Stopping or reducing the causative opioid is the most effective single intervention for opioid-induced constipation; laxatives should be weaned gradually once normal bowel habit is restored.',
    'A rectal examination with a chaperone is a mandatory part of assessing any anorectal lump in primary care.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  202,
  'Eye Lump in a Middle-Aged Woman',
  'ENT & Eye',
  'Telephone Consultation',
  false,
  'Joanna Sutton',
  '47-year-old female',
  ARRAY['None Recorded','Newly registered at the practice'],
  ARRAY['Not on any regular medication','No Known Drug Allergy'],
  'No significant recent consultations',
  'The patient has sent a photograph of her eye and booked a telephone consultation to discuss a growth she has noticed.',
  'Hello doctor, I sent through a photo of my left eye because I''ve got a lump on it. Were you able to have a look at it?',
  'You first noticed this whitish growth on your left eye around three years ago and it has gradually got slightly larger over time. It has knocked your confidence, as you feel that people stare at it whenever they look at you. You have no blurred vision, no redness, and no visual symptoms. Your eyesight is perfectly normal. You occasionally experience some dryness in the eye, but it is mild and has not been getting worse.',
  ARRAY[]::text[],
  'You work as a landscape architect and have spent the past five years based in Abu Dhabi, where you were regularly outdoors in a hot and sunny environment. You returned to the UK two months ago. You do not smoke or drink alcohol. You live with your husband. There is no family history of eye conditions.',
  'You are not entirely sure what the lump is.',
  'You are worried about how it looks; it has affected your confidence and you want to make sure it is not something serious.',
  'You would like the doctor to refer you to have it removed.',
  ARRAY['If the doctor offers a referral to an eye specialist: Ask whether this would be an urgent referral and how long it would take before you are seen.'],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided.',
  ARRAY[
    'Acknowledge that you have reviewed the photograph she sent and ask her to describe the lump in her own words.',
    'Ask when she first noticed the growth and whether it has changed in size or appearance over time.',
    'Confirm which eye is affected and that it is the same eye shown in the photograph she sent.',
    'Ask whether there are any associated symptoms such as irritation, discharge, dryness, grittiness, redness, pain, or discomfort.',
    'Ask whether she has any visual symptoms such as blurred vision, double vision, or reduced visual acuity.',
    'Ask about any history of eye trauma, foreign bodies, or previous eye infections.',
    'Ask about her occupation and lifestyle factors such as outdoor work, sun exposure, dust exposure, and wind exposure.',
    'Ask about the psychosocial impact, including how the appearance of the lump is affecting her daily life, work, or confidence.',
    'Ask about her social history including smoking, alcohol use, occupation, and home situation.',
    'Explore her ideas, concerns, and expectations.',
    'Make a diagnosis of pterygium.'
  ],
  ARRAY[
    'Reassure her that the appearance is consistent with a pterygium, which is a benign and non-cancerous growth.',
    'Explain that pterygium commonly develops in people who spend prolonged periods outdoors in sunny, dusty, or windy environments.',
    'Inform her that because the pterygium has increased in size, is affecting her confidence, and has started to encroach onto the cornea — the transparent surface covering the iris (the coloured part of the eye) and pupil (the black centre) — a routine referral to Ophthalmology is appropriate. The specialist will assess it in clinic and discuss whether surgical removal would be suitable. Explain that this is a non-urgent referral, as her vision is unaffected and there are no red flags.',
    'Advise regular use of sunglasses outdoors to protect the eyes from UV light and help prevent further progression.',
    'Offer ocular lubricants for her dry eyes, such as artificial tears — for example, Hylo-Forte containing sodium hyaluronate.',
    'Safety-net by advising her to seek urgent care if she develops sudden visual changes, eye pain, significant redness, or rapid growth of the lesion.'
  ],
  'Thank you for getting in touch and for sending through that photograph — that was really helpful. Having looked at it carefully, I can see the growth you are describing on the white part of your left eye, and I want to reassure you straight away that what I can see is very consistent with something called a pterygium.

A pterygium — pronounced ter-IDJ-ee-um — is a benign, non-cancerous fleshy growth that develops on the surface of the eye, specifically on the conjunctiva, which is the thin transparent membrane covering the white part. It is not a tumour and it is not contagious; it is simply an overgrowth of tissue that has been triggered by long-term exposure to UV light, wind, and dust. Given that you have spent the past five years working outdoors in Abu Dhabi, Joanna, the environment there is one of the most well-recognised risk factors for developing this condition, so the timeline fits very well.

The good news is that this is not causing any threat to your sight at present, your vision is unaffected, and there are no features that concern me clinically. That said, I do take seriously the impact it is having on your confidence and your day-to-day life, and since you mentioned it has grown slightly over the years and is now beginning to creep across the coloured part of your eye — the area we call the cornea — it is entirely appropriate to refer you to see an eye specialist, an ophthalmologist, for a formal assessment.

The referral I will make is a routine, non-urgent one, because as I said, your vision is fine and there are no warning signs. The ophthalmologist will examine it in detail and have a conversation with you about the options, which typically include monitoring it or, if you wish, a minor surgical procedure to remove it. Surgery for pterygium is generally very effective and has a good cosmetic result. The waiting time for a routine outpatient appointment can vary, but you will receive a letter or message with the details once the referral has been sent.

In the meantime, I would recommend wearing good quality UV-blocking sunglasses whenever you are outside — this is the single most effective thing you can do to prevent the pterygium from growing any further. I would also like to prescribe you some lubricating eye drops, such as sodium hyaluronate drops, to help with the mild dryness you mentioned. These are safe to use regularly and should make your eye feel more comfortable.

Please do get back in touch sooner if you notice any sudden change in your vision, significant pain in the eye, marked redness, or if the growth seems to be increasing in size quite rapidly. Otherwise, keep an eye out for your ophthalmology appointment letter.',
  ARRAY[
    'Pterygium is a benign fibrovascular growth arising from the conjunctiva; it is strongly associated with chronic UV, wind, and dust exposure, and is more common in people who have lived in tropical or subtropical climates.',
    'The key clinical concern with an enlarging pterygium is encroachment onto the cornea, which can eventually distort the corneal surface and impair vision; this is the main indication for surgical referral.',
    'Ophthalmology referral for pterygium is routine and non-urgent unless there is rapid growth, significant visual impairment, or other red flag features such as sudden visual loss or severe pain.',
    'UV-blocking sunglasses are the most important preventive measure to slow pterygium progression and should be recommended to all affected patients.',
    'Ocular lubricants such as sodium hyaluronate (e.g. Hylo-Forte) can help manage the associated dryness and grittiness that frequently accompanies pterygium.',
    'Red flags requiring urgent ophthalmology review include sudden or significant visual deterioration, severe pain, or rapid change in the size or appearance of the lesion.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  203,
  'Incidental High BP and Abnormal Urinalysis',
  'Cardiology',
  'Telephone Consultation',
  false,
  'Priya Chandrasekaran',
  '39-year-old female',
  ARRAY['Primary infertility (two unsuccessful IVF cycles)'],
  ARRAY['Not currently on any regular medication.','No Known Drug Allergy'],
  'Seen today by Vimbai Dube – Nurse Access Role. Presenting complaint: The patient attended for child adoption medical assessments. She reported no current medical problems. She and her husband have been trying to conceive for over four years and have been reviewed by the fertility clinic. They underwent NHS-funded IVF, which has been unsuccessful on two occasions. Examination: Blood pressure: 154/100 mmHg (measured three times; this was the lowest reading). Pulse: 78 bpm. BMI: 28 kg/m². Urinalysis: Blood 1+, Protein 1+, all other parameters negative. Plan: Discussed with the duty GP, who advised arranging a GP appointment today due to the raised blood pressure and abnormal urinalysis before proceeding with the child adoption medical blood tests.',
  'The patient was booked for this telephone appointment following an assessment by the practice nurse earlier today.',
  'Hello doctor, the nurse asked me to speak with you about my blood pressure reading and what she found in my urine sample.',
  'You and your husband are in the process of applying to adopt a child, and you were advised to attend for routine medical assessments and examinations as part of that process, which is why you came in today. The nurse checked your blood pressure on three separate occasions and told you it was raised. She also tested your urine and said it showed blood and protein, even though you have not noticed any blood yourself. You have no symptoms at all and you feel completely well, with no urinary symptoms. You and your husband have been trying for a baby for four years. You underwent thorough investigations and were referred to the fertility clinic. No specific cause was identified to explain why you were unable to conceive naturally. You underwent IVF on two occasions, both of which were unsuccessful. You are now proceeding with adoption. If asked about your periods: your periods are regular. Your last menstrual period was one week ago. You performed a pregnancy test two weeks ago, which was negative. Family History: You are adopted and do not know your biological family medical history.',
  ARRAY[]::text[],
  'You do not smoke or drink alcohol. You work as an accountant for a law firm. You live with your husband.',
  'You are not sure what the raised blood pressure and the urine findings mean.',
  'You are worried that these results might affect your ability to proceed with the adoption.',
  'You want the doctor to explain what these results mean and what needs to happen next.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided.',
  ARRAY[
    'Acknowledge the nurse''s findings and invite the patient to describe what happened earlier today.',
    'Ask about symptoms that may suggest complications of high blood pressure, including headaches, visual changes, chest pain, shortness of breath, palpitations, weakness, tingling in any part of the body, or slurred speech, to screen for hypertensive emergency or stroke.',
    'Ask about urinary symptoms such as pain or burning when passing urine, increased frequency, urgency, cloudy urine, foul-smelling urine, or visible blood, to rule out urinary tract infection.',
    'Ask about systemic symptoms such as fever or flank pain (to consider renal calculi) and swelling of the legs or face (to consider nephrotic syndrome or glomerulonephritis).',
    'Ask about any use of over-the-counter medications, particularly NSAIDs, or herbal supplements that may affect renal function.',
    'Ask about any family history of kidney disease, for example polycystic kidney disease.',
    'Ask about fluid intake and hydration.',
    'Ask about diet, salt intake, caffeine intake, exercise levels, weight changes, and stress levels.',
    'Ask about her last menstrual period, whether she is currently menstruating, and whether there is any possibility of pregnancy. This is important as menstruation can contaminate a urine sample and cause a false positive for haematuria on dipstick testing, and pregnancy is a key consideration in the context of raised blood pressure.',
    'Explore her ideas, concerns, and expectations.',
    'Make a diagnosis of suspected hypertension with asymptomatic microscopic haematuria and proteinuria, requiring further investigation to confirm true hypertension and to exclude renal target organ damage.'
  ],
  ARRAY[
    'Offer a face-to-face appointment for clinical assessment, including cardiovascular examination and fundoscopy.',
    'Offer urgent further investigations to assess for target organ damage, including ECG, urine ACR (albumin to creatinine ratio), HbA1c, lipid profile, and renal function.',
    'Offer either ambulatory blood pressure monitoring (ABPM) or home blood pressure monitoring (HBPM) to confirm a diagnosis of hypertension.',
    'If ambulatory blood pressure monitoring (ABPM) is offered, advise the patient that the monitor will be worn for 24 hours. During this time, she should avoid driving, exercising, and bathing or showering while the equipment is attached.',
    'If home blood pressure monitoring (HBPM) is offered, advise the patient to record two blood pressure readings at least one minute apart, every morning (between 06:00 and 12:00) and every evening (between 18:00 and 00:00), for at least four days and ideally for seven days.',
    'Offer to repeat urinalysis in 3 to 5 days to reassess the haematuria. Advise the patient that if this persists, further investigations will be arranged, including an ultrasound scan of the kidneys.',
    'Provide lifestyle advice, including reducing salt intake, maintaining regular physical activity, weight management, and stress reduction.',
    'Explain that these isolated findings do not automatically affect adoption eligibility. Reassure her that even if high blood pressure is confirmed, many people adopt successfully with well-controlled medical conditions. What matters most is how well the condition is managed, whether it affects day-to-day functioning, and whether it could interfere with parenting responsibilities.',
    'Provide safety-net advice to seek urgent medical attention by contacting the GP urgent line, or calling 111 if out of hours, if she develops severe headache, visual changes, chest pain, shortness of breath, or visible blood in her urine.',
    'Offer follow-up to review blood pressure readings and investigation results.'
  ],
  'Thank you for speaking with me today, and I''m glad the nurse was thorough in her assessment this morning. I want to go through what was found and explain clearly what it means for you.

The nurse measured your blood pressure on three separate occasions and obtained readings of 154/100 mmHg. A normal blood pressure is below 140/90 mmHg, so the reading taken today is elevated. However — and this is important — a single set of readings taken in a clinical setting is not enough on its own to diagnose high blood pressure, or hypertension. Many people have temporarily raised blood pressure when they are at an appointment, due to stress or anxiety, which is perfectly understandable given the significance of today''s visit for you and your husband. To be sure that this is a genuine and sustained elevation, we use a monitoring process either at home or with a portable monitor you wear for 24 hours.

The urine test showed a small amount of blood and protein. You told me you have not noticed any blood yourself, and you have no urinary symptoms such as pain or burning, which is reassuring. It is also worth noting that your last period was a week ago, so contamination from menstruation is less likely but still possible. We will repeat the urine test in three to five days to check whether those findings persist. If blood or protein is still present on the repeat test, we will arrange a kidney ultrasound scan to look more carefully at your renal tract.

Priya, I can hear that your main concern is what this means for the adoption process, and I want to address that directly. These findings do not automatically disqualify you from adopting. Many prospective parents adopt successfully while living with well-managed medical conditions. What the adoption medical is assessing is whether any health condition affects your day-to-day ability to parent, and whether it is properly managed. We are at a very early stage of investigation — we do not yet even have a confirmed diagnosis — so please try not to let this cause you undue anxiety.

In terms of next steps, I would like to bring you in for a face-to-face appointment so that I can listen to your heart and check your eyes, which we can do with a simple light examination called fundoscopy. This helps us look for any signs that blood pressure has been affecting the body over time. I will also arrange a small panel of blood tests including kidney function, a cholesterol level, a blood sugar test, and a trace of protein in the urine measured in a specific way called a urine ACR.

For the blood pressure monitoring, I would like to give you a home monitor and ask you to take two readings every morning and every evening for seven days, following a specific routine which I will explain to you. If that isn''t possible, we can arrange for you to wear a portable monitor that takes readings automatically over 24 hours. Both methods are equally valid and give us a much more accurate picture than clinic readings alone.

In the meantime, please do get in touch urgently, or call 111 if we are closed, if you develop a severe headache, any changes to your vision, chest pain, breathlessness, or if you notice blood in your urine. We will follow up once all the results are back and take things one step at a time.',
  ARRAY[
    'A single elevated blood pressure reading in a clinical setting is not sufficient to diagnose hypertension; ambulatory blood pressure monitoring (ABPM) over 24 hours or home blood pressure monitoring (HBPM) over at least four days is required to confirm the diagnosis per NICE guidance.',
    'Asymptomatic microscopic haematuria and proteinuria on dipstick testing should be repeated in 3 to 5 days to exclude contamination (e.g. from menstruation) before further investigation such as renal ultrasound is arranged.',
    'Target organ damage investigations in suspected hypertension include ECG, urine ACR, renal function, HbA1c, lipid profile, and fundoscopy — these should be arranged promptly alongside confirmatory blood pressure monitoring.',
    'Menstruation can cause a false positive result for haematuria on urine dipstick; timing of the test in relation to the menstrual cycle should always be considered.',
    'A diagnosis of hypertension does not automatically disqualify a person from adoption; what matters is effective management and the absence of functional impairment — this should be communicated sensitively to the patient.',
    'Lifestyle modifications for hypertension include reducing dietary salt, maintaining a healthy weight, regular aerobic exercise, limiting caffeine, and managing stress — these should be offered at first presentation regardless of whether pharmacological treatment is started.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  204,
  'Bisphosphonate-Related Oesophagitis',
  'General Practice',
  'Video Consultation',
  false,
  'Margaret Hollis',
  '74-year-old female',
  ARRAY['Hypertension'],
  ARRAY['Amlodipine 5 mg once daily','Alendronic acid 70 mg once weekly (every Monday)','Adcal D3 chewable tablets, one tablet twice daily'],
  'Seen by Dr Harry Evans (Clinical Practitioner Access Role) - 8 months ago. Presenting Complaint: The patient requested treatment for osteoporosis due to personal concerns about fracture risk. These concerns were triggered after a close friend sustained a fracture and subsequently died following hospital admission. Assessment: FRAX score - Green zone, indicating low fracture risk. Plan: Discussion held regarding low fracture risk; however, the patient preferred to commence treatment. Alendronic acid 70 mg once weekly was started alongside Adcal D3 chewable tablets twice daily. She was counselled on correct administration of alendronic acid, potential side effects, and advised to have a dental check prior to treatment. Seen by Dr Chizoba Diwe (Clinical Practitioner Access Role) – 3 weeks ago. Presenting Complaint: Retrosternal chest pain described as a burning sensation for six weeks, worsening in nature. She is currently on alendronic acid 70 mg once a week. Examination: epigastric tenderness, no rigidity or signs of peritonitis. BP 120/70 mmHg, Pulse 76 bpm, Temp 36.2 °C, BMI 24.5 kg/m². Impression: Suspected oesophagitis, likely related to bisphosphonate use. Plan: Referral for upper gastrointestinal endoscopy due to ongoing symptoms and alendronic acid use. Follow-up planned with results. Upper Gastrointestinal Endoscopy Report (OGD) - 3 days ago. Margaret Hollis | 74 years old | Female. Indication: Reflux symptoms in the context of oral alendronic acid use. Findings: Oesophagus: Distal oesophagitis with erythema and superficial erosions, consistent with Los Angeles Grade B oesophagitis. No stricture or Barrett''s change seen. Stomach: Normal. Duodenum: Normal. Recommendations: administration. Impression: Moderate erosive oesophagitis (Los Angeles Classification Grade B), likely secondary to alendronic acid ingestion. Endoscopist: Dr James Harrington, MBBS, FRCP, Consultant Gastroenterologist',
  'The patient has booked this video consultation to discuss the results of her recent camera test.',
  'Hello doctor, I had a camera test done recently and I''d like to go over the results with you.',
  'You were referred for a camera test because you developed significant chest pain that felt like a burning sensation. This had been going on for about six weeks before you attended the surgery. You tried Gaviscon but it did not help. The doctor who saw you at that appointment arranged the camera test to find out what was causing your symptoms. If asked about the pain: it is burning in nature, worse after meals, when you lie down, and particularly at night. It sometimes wakes you from sleep and is affecting your rest. If asked why you are on alendronic acid: you asked to start alendronic acid because you are very frightened of having a fracture. Your closest friend had a fracture, was admitted to hospital, developed a blood clot in her chest, and passed away. That experience had a profound effect on you. You discussed your concerns with a GP about eight months ago and were started on alendronic acid. You have never had a fracture yourself. If asked about menopause: your periods stopped at the age of 53. You did not take hormone replacement therapy.',
  ARRAY[]::text[],
  'You live alone. You do not smoke or drink alcohol. You eat a healthy diet with plenty of calcium-containing foods, including yoghurt, cheese, and milk. You go out every day for a walk and try to get some sunlight when the weather allows. You are a retired florist. There is no family history of osteoporosis.',
  'You are not entirely sure what the camera test showed, although the doctor mentioned something about reflux.',
  'You want the symptoms to stop as they are distressing and affecting your sleep.',
  'You would like the doctor to explain what the camera test found and what can be done next.',
  ARRAY['If the Doctor Asks You to Stop Alendronic Acid: Be slightly hesitant. Say that you are worried about having a fracture. Ask the doctor what else can be done to reduce your fracture risk if alendronic acid is stopped.'],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided.',
  ARRAY[
    'Acknowledge that you can see from her records that she recently had an endoscopy and ask what symptoms led to the referral.',
    'Ask whether her chest or epigastric pain has improved, worsened, or remained the same since she last saw the doctor.',
    'Ask about triggering or aggravating factors for the pain, such as food (large meals, late meals, or spicy foods), caffeine, or lying flat.',
    'Ask about associated symptoms such as black tarry stools, bloating, feeling full too quickly after eating (early satiety), nausea, and vomiting; if vomiting is present, ask whether there has been any blood in it.',
    'Ask about red flag symptoms including difficulty swallowing, pain on swallowing, unintentional weight loss, reduced appetite, or an abdominal mass.',
    'Ask how she takes her alendronic acid, including whether she sits upright when taking it, avoids lying down for at least 30 minutes afterwards, the amount of fluid she uses to swallow it, and whether she had any symptoms before starting the medication. Note: alendronic acid should be taken first thing in the morning, before any food or drink, with a full glass of plain water (at least 200 mL).',
    'Ask why she wanted to start alendronic acid despite having a low fracture risk and explore her understanding of osteoporosis.',
    'Ask about other potential side effects of alendronic acid, including jaw pain, to exclude osteonecrosis of the jaw.',
    'Ask about osteoporosis risk factors, including family history of osteoporosis, smoking, alcohol intake, previous fractures, falls, early menopause, poor calcium or vitamin D intake, and low levels of physical activity.',
    'Ask about her home situation, including who lives with her and what support she has with activities of daily living.',
    'Explore her ideas, concerns, and expectations.',
    'Make a diagnosis of oesophagitis likely secondary to oral alendronic acid use, with low underlying osteoporotic fracture risk.'
  ],
  ARRAY[
    'Offer full-dose proton pump inhibitor (PPI) therapy for four weeks. For example, omeprazole 20 mg once daily for 4 weeks.',
    'Explain that her current fracture risk is low, and reinforce that her good dietary calcium intake, vitamin D supplementation, and regular walking are all positive protective measures. Advise that, in her case, the risks of continuing alendronic acid currently outweigh the benefits, and therefore it should be stopped.',
    'Reassure her that her FRAX score remains low, and that stopping alendronic acid does not significantly increase fracture risk at present.',
    'Provide lifestyle advice to help improve oesophagitis symptoms, including avoiding late meals, spicy foods, and other known triggers, reducing caffeine intake, and remaining upright for at least one hour after eating.',
    'Offer to assess dietary calcium intake using a calcium calculator. Explain that if her intake is adequate, she may not need to continue Adcal, and instead could remain on low-dose vitamin D alone.',
    'Encourage her to continue lifestyle measures, including regular weight-bearing exercise such as walking, and a balanced diet, to help maintain bone strength.',
    'Advise that her fracture risk will be reassessed every five years, or sooner if her clinical situation changes.',
    'Provide safety-net advice to seek urgent medical attention by contacting the GP urgent line, or calling 111 if out of hours, if she develops difficulty swallowing, vomiting blood, black stools, severe chest or abdominal pain, or unintentional weight loss.',
    'Offer follow-up in four weeks to review symptom resolution and response to treatment.'
  ],
  'Thank you for joining me today, and I can see you''ve been having a difficult few weeks with this burning chest pain. I want to go through the results of your camera test carefully and make sure you understand exactly what was found and what we are going to do next.

The endoscopy — the camera test — was arranged because you had been experiencing that persistent burning sensation in your chest for around six weeks, and it was not responding to antacid medication. The results have come back and they show that you have something called oesophagitis. The oesophagus is the food pipe that connects your mouth to your stomach, and the report describes inflammation with some superficial erosions in the lower part of it. The gastroenterologist who performed the test has graded this as Los Angeles Grade B, which means moderate erosive oesophagitis. There is no narrowing of the food pipe and no Barrett''s change, which is the type of change we particularly want to rule out, so that is reassuring news.

The camera test also looked at your stomach and the first part of your small bowel, both of which were completely normal.

Now, the most likely cause of this oesophagitis, Margaret, is the alendronic acid you have been taking for the past eight months. Alendronic acid is a type of medication called a bisphosphonate, and it is well known that if it is not taken in exactly the right way — with a full glass of water, first thing in the morning, sitting or standing upright, and remaining upright for at least 30 minutes afterwards — it can linger in the oesophagus and cause irritation and damage to the lining. Even when taken correctly, some people still develop this reaction. This is almost certainly what has happened in your case.

I know this raises a worry for you about your bones, and I want to take that very seriously. The reason you asked to start this medication was because you were frightened after your dear friend''s experience, and that was completely understandable. However, I want to share something important with you: when we assessed your fracture risk score eight months ago using a tool called the FRAX score, your risk was in the green zone, meaning it was low. That score has not changed. Stopping alendronic acid in someone with a low baseline fracture risk does not significantly increase the likelihood of a fracture. Your bones are being protected in other very meaningful ways — the calcium you get from your diet of cheese, yoghurt, and milk is excellent; the Adcal D3 tablets give you supplemental vitamin D; and the daily walking you do is one of the most beneficial things you can do for bone strength, as weight-bearing exercise directly stimulates bone density.

To treat the oesophagitis, I am going to prescribe you a medication called a proton pump inhibitor, or PPI. We will use omeprazole 20 mg once a day for four weeks, which reduces the amount of acid the stomach produces and allows the inflamed lining of the food pipe to heal. In the meantime, some lifestyle adjustments will also help: try to avoid eating late in the evening, reduce spicy foods and caffeine, and make sure you sit or stand upright for at least an hour after meals.

Regarding the Adcal D3 — I would like to use a calcium calculator to check how much calcium you are getting from your diet, because if your food alone is providing enough, you may not need to continue the Adcal tablets and could take a lower-dose vitamin D supplement instead. We can look at that together at your follow-up.

We will arrange a review in four weeks to make sure your symptoms have settled. Your fracture risk will be formally reassessed every five years, or sooner if anything changes in your health. Please do contact us urgently, or call 111 if we are closed, if you develop any difficulty swallowing, vomiting with blood, black or tarry stools, severe pain in your chest or tummy, or any unexplained weight loss.',
  ARRAY[
    'Alendronic acid is a well-recognised cause of oesophagitis and oesophageal erosions, particularly if administration instructions are not followed precisely; it must be taken fasting with at least 200 mL of plain water, and the patient must remain upright for a minimum of 30 minutes afterwards.',
    'Bisphosphonate-related oesophagitis should prompt a clinical review of the indication for the drug; if the patient''s FRAX score was already in the low-risk category, the risks of continuing treatment are likely to outweigh the benefits.',
    'Stopping alendronic acid in a patient with a low baseline FRAX score does not significantly increase fracture risk and is the appropriate course of action when symptomatic oesophagitis has been confirmed on endoscopy.',
    'A four-week course of full-dose PPI (e.g. omeprazole 20 mg once daily) is the standard treatment for bisphosphonate-induced oesophagitis.',
    'Non-pharmacological bone protection measures — weight-bearing exercise, adequate dietary calcium, and vitamin D supplementation — should be emphasised as effective alternatives when bisphosphonates are stopped in low-risk patients.',
    'Fracture risk should be formally reassessed using FRAX every five years, or sooner if the patient''s clinical circumstances change, such as a new fragility fracture, significant weight loss, or new comorbidity.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  205,
  'Request for Cervical Screening',
  'Gynaecology & Women''s Health',
  'Telephone Consultation',
  false,
  'Natasha Kovalenko',
  '31-year-old female',
  ARRAY['Newly Registered at the Practice'],
  ARRAY['Not currently on any regular medication.'],
  'No significant recent consultations',
  'The patient has booked a routine telephone consultation to discuss cervical screening.',
  'Hello doctor, I would like to arrange a cervical screening test please.',
  'You recently moved to the UK from Poland due to difficult circumstances back home. In Poland, it is routine for women to have cervical screening every year. Your last cervical screening test was just over a year ago and the result was completely normal. You are keen to keep on top of your health and would like to continue having regular smear tests.',
  ARRAY['You do not have any vaginal discharge, bleeding between periods, or pelvic pain.','Your periods are regular, coming every 28 days. You are not using any contraception as your husband is still in Poland and you have not been sexually active for over six months. There is no chance you could be pregnant.','You feel well in yourself overall.'],
  'You do not smoke or drink alcohol. You work as a cleaner and are staying with a family friend while you get settled. Your mood is generally okay, though you miss your husband very much and stay in contact with him by video call.',
  'You believe cervical screening should be carried out every year, as that was the standard practice in your home country.',
  'You have no specific concerns but want to make sure your health is being properly looked after here in the UK.',
  'You would like the GP to arrange for you to have a cervical screening test.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided.',
  ARRAY['Ask about the reason for requesting cervical screening at this time.','Ask about cervical screening history, including the date and result of her most recent test.','Before proceeding, signpost the sensitive nature of the discussion and obtain consent. For example: "Natasha, I''ll need to ask you some personal questions, including about your sexual health, as this helps me understand the situation properly. Is that okay?"','Ask whether she has any abnormal vaginal discharge or bleeding.','Ask for the date of her last menstrual period and whether her cycles are regular.','Ask whether she has experienced any bleeding between periods, as intermenstrual bleeding can be a symptom of cervical cancer.','Ask whether she is currently sexually active. If yes, ask about the number of sexual partners, any history of sexually transmitted infections, and whether she experiences pain or bleeding during or after intercourse.','Ask whether there is any possibility she could be pregnant.','Ask about other gynaecological symptoms including lower abdominal or pelvic pain.','Ask about any unexplained weight loss or night sweats.','Ask whether she takes any contraceptive pills, noting that the combined oral contraceptive pill slightly increases the risk of cervical cancer, particularly with use of more than five years.','Ask about social history including smoking status (smoking increases cervical cancer risk), alcohol use, occupation, and living situation.','Ask about her mood and how she is adjusting to life in the UK following her recent move.','Explore her ideas, concerns, and expectations regarding cervical screening in the UK.'],
  ARRAY['Explain that in the UK, cervical screening is offered routinely from the age of 25, and the interval between tests depends on previous results. For people aged 25 to 64, screening is repeated every 5 years if results are normal.','Reassure her that, based on her history of a normal cervical screen just over a year ago, she is currently up to date and does not require another test at this time.','Explain that her records will now be updated and she will be automatically invited for her next cervical screening when it is due. Invitations are usually sent via the NHS App, text message, or letter, with clear instructions on how to book.','Offer written information or NHS leaflets about how cervical screening works in the UK to provide further reassurance.','Offer a referral to the practice social prescriber, who can support her in settling into life in the UK and help her understand how NHS services are organised. They can also connect her with local community or social groups to help build a sense of belonging.','Provide clear safety-net advice: advise her to seek urgent review by calling the GP urgent line or booking an urgent appointment if she develops symptoms such as abnormal vaginal bleeding, bleeding after sex, unusual vaginal discharge, or pelvic pain, as these would need assessment regardless of screening dates.'],
  'It is wonderful that you are being so proactive about your health, Natasha, and I completely understand why you have come in today. Moving to a new country with a different healthcare system can be confusing, and it is very natural to want to carry on with the health checks you were used to back home.

In Poland, cervical screening is done every year, and that is perfectly reasonable practice. Here in the UK, the NHS Cervical Screening Programme works slightly differently. Cervical screening is offered from the age of 25, and once you have a normal result, you are invited again every five years. This interval is based on strong research showing that in most women, any changes that could develop between normal screens take several years to progress, making five-yearly checks both safe and effective.

Because your last smear test was just over a year ago and the result was completely normal, the good news is that you are fully up to date. You do not need to have another test right now. Your details will be added to our register, and you will receive an automatic reminder when your next test is due, usually by letter, text, or through the NHS App.

I do want to make sure you know what symptoms to look out for in the meantime. If you ever notice bleeding between your periods, bleeding after sex, any unusual vaginal discharge, or pelvic pain, please do not wait for your next routine screen. Contact us promptly for an appointment, as those symptoms would need to be assessed straight away, regardless of when your last smear was.

I would also like to offer you a referral to our social prescriber, a member of our team who specialises in helping people settle into life in the UK. They can help you find out how local NHS services work and can put you in touch with community groups and social activities in the area. It can make a real difference to have those connections, especially when you are far from home and missing your husband.',
  ARRAY['In the UK, cervical screening is offered from age 25 and repeated every 5 years after a normal result; this interval is evidence-based and differs from many other countries where annual screening is standard.','A patient who is up to date with normal cervical screening does not require a repeat test; reassurance and explanation of the UK recall system is the appropriate response.','Red flag symptoms such as intermenstrual bleeding, post-coital bleeding, unusual vaginal discharge, or pelvic pain require prompt clinical assessment regardless of the date of the last cervical screen.','Smoking increases the risk of cervical cancer and should be addressed opportunistically; the combined oral contraceptive pill also slightly increases risk with long-term use over five years.','For newly registered patients from overseas, offering a social prescriber referral supports adjustment to the UK healthcare system and builds community connections.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  206,
  'Suspected Condom Allergy',
  'General Practice',
  'Telephone Consultation',
  false,
  'Lucia Ferreira',
  '29-year-old female',
  ARRAY['None recorded'],
  ARRAY['Mirena® 20micrograms/24hours intrauterine device in situ (inserted 2 years ago)','Not currently on any regular medication.','No Known Drug Allergy'],
  'No significant recent consultations',
  'The patient has booked a routine telephone consultation regarding itching in the vaginal area.',
  'Hello doctor. This is quite embarrassing to bring up, but I have been getting itching around my vagina for the past six months.',
  'You have noticed that the itching happens every single time a male partner uses a condom during sex. The itching starts shortly afterwards. When a condom is not used, you do not get any itching at all. You work as a sex worker and have regular clients. You are not sure what to do because you know condoms protect against sexually transmitted infections, but the itching is becoming a real problem.',
  ARRAY['The itching starts shortly after condom use and is associated with redness, though there are no visible rashes or broken skin. It can last for over 24 hours before settling.','You do not have any abnormal vaginal discharge, pain, sores, or bleeding.','Your periods are regular and you have a Mirena intrauterine device in place. You had a full sexually transmitted infection screen two months ago which was completely normal. You routinely have STI screening every three months.','You usually use condoms with clients, although occasionally you do not if a client pays more.','You are not sure whether the condoms used are latex or non-latex, but most of your clients use the Durex brand. You have no urinary symptoms and no personal history of allergies or eczema.','If asked whether this happened before six months ago: you explain that you only started sex work six months ago, which is when you began having regular sex using condoms.'],
  'You do not smoke or drink alcohol. You live on your own and work as a sex worker.',
  'You wonder whether you might be allergic to condoms.',
  'You have an important client booked from tomorrow for a full week. You are worried that if he uses condoms, the itching will return and make it difficult to continue working. You are anxious about letting him down.',
  'You would like the GP to advise you on what you should do.',
  ARRAY['If the doctor offers a face-to-face appointment: ask why the doctor wants you to come in, as you do not currently have any symptoms. If the doctor still suggests it, explain that you cannot attend right now as you are preparing to travel for work tomorrow and will be away for several days.'],
  'Do you think I should stop using condoms?',
  'Say NO to any other questions or symptoms asked outside of the details already provided.',
  ARRAY['Acknowledge her concern sensitively and thank her for raising a personal and difficult issue.','Ask about the onset, duration, and timing of the itching in relation to condom use.','Clarify whether the itching occurs only after condom use and whether it happens every time.','Ask what type of condoms are used, for example whether they are latex or non-latex.','Ask whether she has noticed redness, swelling, rash, burning, or soreness following condom use.','Ask whether the symptoms resolve on their own and how long they typically last.','Ask about any abnormal vaginal discharge, ulcerations, pain, or bleeding.','Ask about any urinary symptoms such as stinging or increased frequency.','Ask about sexual history, including episodes of unprotected intercourse and any history of sexually transmitted infections.','Ask about use of vaginal products such as douches, soaps, wipes, lubricants, or topical creams.','Ask about any personal or family history of allergies, eczema, asthma, or hay fever.','Ask about symptoms suggestive of anaphylaxis, such as tongue swelling, wheeze, or difficulty breathing.','Ask about social history including smoking, alcohol use, occupation, and living situation.','Explore her ideas, concerns, and expectations.','Make a diagnosis of suspected contact dermatitis to latex condoms.'],
  ARRAY['Reassure her that, based on the history, this is most likely contact dermatitis, commonly caused by latex or chemicals in condoms or lubricants, rather than an infection.','Strongly advise against stopping condom use, as condoms remain essential for protection against sexually transmitted infections, particularly given the nature of her work.','Advise switching to non-latex condoms such as polyurethane or polyisoprene condoms, which are suitable for people with latex sensitivity. SKYN is a popular brand that specialises in latex-free condoms.','Advise attending a sexual health clinic to discuss HIV pre-exposure prophylaxis (PrEP), which can provide additional protection against HIV alongside condom use.','Offer non-sedating antihistamines and 1% hydrocortisone cream for short-term use if symptoms recur in future.','Safety-net by advising her to seek review if symptoms worsen, do not improve after switching condoms, or if she develops discharge, pain, ulcers, or bleeding.','Advise that although rare, some people can develop a severe allergic reaction presenting with difficulty breathing, swelling of the tongue or throat, or dizziness, and that if this occurs she should call 999 immediately.','Offer follow-up in four weeks to review symptoms and response to the change in condom type.'],
  'Thank you for having the courage to bring this up today, Lucia, because I know it was not easy to talk about. You have given me a very clear picture of what is happening, and I want to explain what I think is going on.

Based on everything you have described, the most likely explanation is something called contact dermatitis. This is a skin reaction caused by coming into contact with a substance your body is sensitive to. In your case, the timing strongly suggests a reaction to latex, which is the material most condoms — including many Durex products — are made from. It can also sometimes be a reaction to lubricants or other chemicals in the condom rather than the latex itself. This is not an infection and it is not related to your Mirena coil.

I want to be very clear about one thing: I would strongly advise against stopping condom use. Condoms are one of the most important forms of protection against sexually transmitted infections including HIV, and this remains just as important regardless of what other precautions are in place. What I would recommend instead is switching to non-latex condoms. These are made from alternative materials such as polyurethane or polyisoprene and are just as effective for STI prevention. A popular brand called SKYN specialises in latex-free condoms and is widely available in pharmacies and supermarkets.

To help manage the itching if it does occur, I can prescribe a non-sedating antihistamine and a short course of 1% hydrocortisone cream, which can reduce the inflammation and discomfort. These should only be used short term and are not a long-term solution on their own — switching the condom type is the main step.

I would also strongly encourage you to visit a sexual health clinic. They offer free, confidential support including HIV pre-exposure prophylaxis, known as PrEP, which is a daily medication that provides additional protection against HIV on top of condom use. For someone in your line of work, it is well worth discussing this with a specialist there.

Finally, I want you to know what to look out for in terms of warning signs. If you ever experience difficulty breathing, swelling of your tongue or throat, or feel faint or dizzy after condom use, these could be signs of a serious allergic reaction and you should call 999 straight away. Otherwise, if the itching does not settle after switching to non-latex condoms, or if you develop discharge, pain, or any sores, please come back and we will reassess. Let''s arrange a follow-up call in about four weeks to see how things are going.',
  ARRAY['Contact dermatitis to latex or condom lubricants is a common cause of post-coital genital itching and should be distinguished from infectious causes; key features are the close temporal relationship to condom use and absence of discharge or systemic symptoms.','The correct management is to switch to non-latex condoms (polyurethane or polyisoprene) rather than to stop condom use, as condoms remain essential for STI protection.','Non-sedating antihistamines and 1% hydrocortisone cream can be used short term for symptom relief during future episodes.','Anaphylaxis to latex, though uncommon, can occur and patients should be warned to call 999 if they develop difficulty breathing, throat swelling, or collapse.','Sexual health clinic referral should be offered for PrEP counselling in patients at high risk of HIV exposure.','Always explore ICE sensitively in consultations involving sex workers, particularly concerns about financial or relationship pressures that might influence the patient''s willingness to use protection.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  207,
  'New Back Pain and Urinary Symptoms',
  'General Practice',
  'Telephone Consultation',
  false,
  'Graham Fletcher',
  '54-year-old male',
  ARRAY['None recorded'],
  ARRAY['Not currently on any regular medication.'],
  'No significant recent consultations',
  'Patient booked a routine consultation to discuss back pain that has not settled.',
  'Hi doctor, I have had this low back pain for about a week now and it just isn''t getting any better.',
  'The back pain started after you lifted some heavy boxes when helping a friend move house. Not long after that, you developed pain in your lower back. The pain has remained much the same since it started. You have tried paracetamol, but it has not helped at all. You have not found anything that clearly makes the pain better or worse. You have no tingling, numbness, or weakness in your legs. You have full control of your bladder and bowels. You have no weight loss, night sweats, or fever, and you feel generally well. If asked about your bladder or urine symptoms: over the past six months or so, you have noticed that you are waking up more often at night to pass urine. You have also noticed that when you feel the urge to go, you sometimes have to get there quickly or feel you might leak. You have no pain passing urine, no blood in the urine, and no other urinary symptoms. If asked whether you have had back pain before: yes, you had back pain about three years ago which was caused by your desk chair and poor posture at work. Once that was sorted, the pain went away completely and you have been fine since.',
  ARRAY[]::text[],
  'You do not smoke and you do not drink alcohol. You work from home as a financial analyst. You live with your partner and your two teenage children.',
  'You think the pain is probably from lifting the heavy boxes.',
  'You just want to get rid of this pain so you can get back to normal.',
  'You would like to know what the best treatment would be for the pain.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided.',
  ARRAY['Ask about the onset, nature, and precise location of the back pain, noting that spinal fracture often presents with sudden onset of severe central spinal pain relieved by lying down.','Ask whether the pain radiates into the lower limbs and whether there are any relieving or aggravating factors.','Ask about any history of trauma or heavy lifting.','Ask about previous episodes of back pain and whether this feels similar to or different from before.','Ask about red flag symptoms suggestive of cauda equina syndrome, including numbness or tingling in the lower limbs, leg weakness, saddle anaesthesia, or any loss of bladder or bowel control.','Ask about other red flag features that might suggest systemic disease or malignancy, such as fever, unexplained weight loss, or night sweats.','Ask about his urinary symptoms in more detail, including onset, frequency, urgency, nocturia, haematuria, weak stream, hesitancy, dribbling, a feeling of incomplete emptying, or dysuria.','Ask about social history including smoking, alcohol use, and occupation.','Ask how the symptoms are affecting his daily activities and quality of life.','Ask about his ideas, concerns, and expectations.','Make a working diagnosis of probable low back muscle strain from heavy lifting; however, in view of his urinary symptoms, it is important to rule out prostate cancer metastases, as spread from prostate cancer can cause pathological vertebral fracture.'],
  ARRAY['Offer a face-to-face appointment to examine his back, carry out a neurological examination, and perform a prostate examination.','Offer further analgesia, starting with an NSAID such as ibuprofen together with a gastric-protective agent like omeprazole. If NSAIDs are not appropriate, consider a short course of co-codamol instead.','Arrange a urine dipstick and urine culture to screen for infection, and a PSA (Prostate-Specific Antigen) blood test to assess the prostate.','Advise that if the PSA is raised or the prostate feels abnormal on examination, he will need an urgent referral to urology on the suspected cancer pathway.','Reassure him that simple muscular strains commonly improve gradually with time.','Advise gentle movement and maintaining normal activity levels, avoiding prolonged bed rest, as staying mobile supports recovery.','Provide safety-netting advice: advise him to seek urgent help if he develops new leg weakness, numbness in the saddle area, difficulty passing urine or controlling his bladder or bowels, or if the pain becomes significantly worse. He should call the urgent GP line or NHS 111 if any of these symptoms arise.','Arrange follow-up once his results are available to plan the next steps together.'],
  'Thank you for calling in today, Graham, and I''m glad you did, because while what you''ve described does sound like it could be a muscle strain from all that heavy lifting, there are a couple of things in what you''ve told me that I want to make sure we look into properly.

First, regarding the back pain itself: lifting something heavy and then developing low back pain immediately afterwards is a very common pattern we see, and in the majority of cases it is caused by a muscle or ligament strain. The good news is that this type of back pain usually improves gradually with time and gentle movement. What I would suggest rather than resting completely is keeping as active as you comfortably can, as staying mobile actually helps the muscles recover more quickly than lying still. I would also like to offer you something a bit more effective for the pain — a short course of an anti-inflammatory like ibuprofen, taken with a tablet called omeprazole to protect your stomach. Paracetamol alone often is not enough for this type of pain.

However, the reason I want to see you in person is not just the back pain. You mentioned that over the past six months you have been getting up more at night to pass urine and sometimes feel you have to rush to the toilet. These urinary symptoms in a man of your age are something we always take seriously. They could simply be due to the prostate gland, which tends to enlarge naturally as men get older, but they can also occasionally be the first sign of something we need to rule out, including prostate cancer.

I want to arrange some tests for you, including a urine test to check for infection and a blood test called a PSA, which gives us information about the prostate. I will also examine your back and carry out a prostate examination when I see you, which I know is not the most comfortable test but is an important one. If the blood test or examination raises any concerns, I would refer you to a urology specialist as a priority.

In the meantime, please keep an eye out for any new symptoms that would need you to act straight away: if you develop weakness in your legs, loss of feeling in the area between your legs and bottom, or if you suddenly lose control of your bladder or bowels, please call NHS 111 or the urgent GP line immediately without waiting for your appointment. These would need urgent assessment that same day.',
  ARRAY['New back pain following heavy lifting is likely muscular, but the co-presence of lower urinary tract symptoms in a man over 50 raises the possibility of prostate cancer with spinal metastases and should not be dismissed.','Red flag symptoms for cauda equina syndrome — saddle anaesthesia, bilateral leg weakness, and loss of bladder or bowel control — require same-day emergency assessment and must be screened for in all back pain consultations.','A PSA blood test and digital rectal examination are the initial investigations for suspected prostate pathology; an elevated PSA or abnormal prostate on examination should trigger an urgent suspected cancer pathway referral to urology.','NSAIDs such as ibuprofen should be co-prescribed with a proton pump inhibitor (e.g. omeprazole) for gastric protection when used for musculoskeletal pain.','Advice to maintain gentle activity and avoid bed rest is evidence-based for acute non-specific low back pain and should be communicated clearly to the patient.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  208,
  'Persistent Fatigue After Chemotherapy',
  'General Practice',
  'Telephone Consultation',
  false,
  'Helen Chung',
  '50-year-old female',
  ARRAY['Acute Myeloid Leukaemia'],
  ARRAY['Co-codamol 30/500 mg, one to two tablets every four to six hours as required for pain (maximum eight tablets per day)','No Known Drug Allergy'],
  'Clinic Letter from Haematology Department – 4 weeks ago

Dear Colleague,

RE: Helen Chung | 50 years old | Female

I am writing to update you on the management of Mrs Chung, a 50-year-old female diagnosed with acute myeloid leukaemia (AML).

Mrs Chung has now completed her planned course of chemotherapy. I am pleased to report that she has achieved complete remission, based on post-treatment bone marrow assessment and peripheral blood monitoring. She is currently clinically well, with no features suggestive of disease relapse. She will continue to be followed up in the Haematology outpatient clinic on a three-monthly basis.

Please continue routine primary care surveillance and refer back to us urgently if there are any concerns. We appreciate your ongoing collaboration in her care. Should you require further information, do not hesitate to contact us.

Yours sincerely,
Dr Harriet Hargreaves, MRCP(UK), FRCPath
Consultant Haematologist',
  'Patient booked a routine consultation to discuss persistent tiredness since completing chemotherapy.',
  'Hi doctor, I just feel exhausted all the time.',
  'You have been experiencing extreme tiredness for the past four weeks and it is not getting any better. Even the smallest tasks leave you feeling drained, and you are worried about how you will cope when you eventually go back to work, as you cannot imagine managing your usual responsibilities feeling like this. Alongside the tiredness, you have noticed a tingling sensation in both your hands and feet for the past four weeks. You have no weakness, no problems with your balance, no headaches, and no blurred vision. You sleep well enough at night but still wake up feeling completely unrefreshed. Your mood is fine and you do not feel low.',
  ARRAY['You were given opioids for pain relief during treatment but have not taken them for the past four weeks as you are no longer in any pain.','Your periods stopped two years ago. You are not on HRT. You are not sexually active.'],
  'You live alone. You do not smoke or drink alcohol. You have a son who visits twice a week to help with shopping, cooking, and other household tasks. You work as a secondary school librarian and love your job. You are very keen to return to work but your colleagues have encouraged you to wait until you are well enough. You are not in financial difficulty, but you find being at home makes the tiredness feel worse and you miss the routine.',
  'You are not sure what is causing your symptoms.',
  'You desperately want to return to work soon but are worried you will not cope given how exhausted you feel.',
  'You would like the GP to explain what might be causing your symptoms and whether you need any further tests or treatment.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided.',
  ARRAY['Ask about the onset of the symptoms.','Ask what the patient means by feeling tired — whether this is physical fatigue, mental exhaustion, or a general sense of being unwell.','Ask whether the tiredness is improving, worsening, or staying the same.','Ask whether minimal activity makes the tiredness significantly worse, as this may suggest post-exertional malaise and raise the possibility of chronic fatigue syndrome.','Ask about sleep quality, whether she feels refreshed after sleep, whether she is sleeping more than usual, and whether she has ever woken gasping for air or been told she snores, to help rule out obstructive sleep apnoea.','Ask about difficulty concentrating or brain fog.','Ask about any generalised body aches or joint pains.','Ask about any recent flu-like symptoms to help rule out post-viral fatigue.','Ask about red flag symptoms that may suggest leukaemia relapse, including fever, night sweats, unexplained weight loss, easy bruising or bleeding, recurrent infections, bone pain, or breathlessness.','Ask about her last menstrual period.','Ask whether she has experienced any constipation, which could be related to previous codeine use.','Ask whether she is bleeding from anywhere, to screen for anaemia.','Ask about the onset and nature of the tingling in both hands and feet.','Ask whether the tingling is associated with weakness, unsteadiness, blurred vision, or headaches, to help rule out vitamin B12 deficiency.','Ask about appetite, dietary intake, or any restrictive diet that might predispose to nutritional deficiency.','Ask about her mood and whether she feels low, anxious, or has lost interest in activities she normally enjoys.','Ask about social history including smoking, alcohol use, home situation, occupation, who she lives with, and what support she has at home.','Ask how she is managing financially while not working.','Ask how these symptoms are affecting her day-to-day life and routine.','Ask about her ideas, concerns, and expectations.','Make a working diagnosis of post-chemotherapy fatigue and chemotherapy-induced peripheral neuropathy.'],
  ARRAY['Offer a face-to-face appointment to carry out a full neurological examination and general physical examination.','Arrange urgent blood tests including full blood count, thyroid function tests, vitamin B12 and folate, HbA1c, renal and liver profile, vitamin D level, and inflammatory markers.','Encourage her to keep a daily symptom diary to identify any patterns or triggers for her fatigue, which can help guide pacing and activity planning.','Advise on energy management and pacing techniques: encourage her to balance activity with adequate rest, avoid overexertion, and gradually increase her activity levels in small and manageable steps.','If she wishes to return to work, offer a Fit Note recommending amended duties or a phased return. For example, if she normally works eight hours per day, she could begin with one to two hours per day and increase gradually as tolerated.','Provide general wellbeing advice including maintaining good hydration, eating a balanced diet, taking short low-intensity walks as tolerated, and keeping a regular sleep routine.','Advise her to seek urgent medical attention if she develops fever, night sweats, unexplained bruising or bleeding, breathlessness, or bone pain, as these may suggest relapse of leukaemia. She should contact the urgent GP line or NHS 111 if these occur.'],
  'I am really glad you called today, and I want to start by saying what an enormous thing you have been through. Completing chemotherapy for acute myeloid leukaemia is a major achievement, and reaching remission is genuinely wonderful news. But I also completely understand that it does not feel wonderful right now, Helen, because your body has been through an extraordinary amount and it takes real time to recover.

What you are describing — this deep, persistent exhaustion that does not lift even after a good night''s sleep — is something we call post-chemotherapy fatigue. It is one of the most common and most difficult things that patients experience after cancer treatment, and it is very real. It is not just tiredness in the ordinary sense; it is a whole-body fatigue caused by the cumulative effect of chemotherapy on your system. The important thing I want to reassure you about is that this does not mean the leukaemia is coming back. Based on the letter from your haematologist, you are in complete remission, and that is what we would expect to see.

The tingling in your hands and feet is something I also want to take seriously. This is a recognised side effect of certain chemotherapy agents called chemotherapy-induced peripheral neuropathy. It happens because chemotherapy can affect the nerves in the extremities. It often improves over time, but I want to examine you in person and arrange some blood tests to make sure there is nothing else contributing, such as a deficiency in vitamin B12 or vitamin D, or a thyroid problem, which can all cause similar symptoms.

For the fatigue itself, I would encourage you to think about pacing. Rather than pushing through and trying to do everything at once, the aim is to balance activity with rest and build things up slowly in small steps. I know it feels counterintuitive when you want to get back to normal, but this approach actually tends to lead to a better and faster recovery than trying to do too much too soon. I would also like to help you plan your return to work when the time is right. I can write you a Fit Note that recommends a phased return, so for example you might start with just an hour or two a day and build up gradually from there.

Please do keep a close watch for certain symptoms that would need urgent attention: if you develop a fever, night sweats, unexpected bruising or bleeding, bone pain, or breathlessness, please contact us urgently or call NHS 111, as those symptoms would need to be assessed promptly to rule out any change in your condition. Otherwise, let''s get you booked in to see me in person and we will go from there together.',
  ARRAY['Post-chemotherapy fatigue is a recognised and common syndrome following cancer treatment; it is distinct from relapse and requires a specific management approach involving pacing, graded activity, and exclusion of treatable contributing causes.','Chemotherapy-induced peripheral neuropathy typically presents as tingling or numbness in a glove-and-stocking distribution and is a known complication of several chemotherapy agents; it often improves over time but requires clinical assessment and investigation to exclude other causes such as vitamin B12 deficiency.','Blood tests following chemotherapy fatigue should include full blood count, thyroid function, vitamin B12 and folate, HbA1c, renal and liver profile, vitamin D, and inflammatory markers.','Red flag symptoms suggesting leukaemia relapse — fever, night sweats, unexplained weight loss, easy bruising or bleeding, bone pain, and recurrent infections — must be screened for and trigger urgent haematology review if present.','A Fit Note recommending phased return to work is an appropriate supportive measure for patients recovering from cancer treatment who are keen to return but not yet able to work full hours.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  209,
  'Incidental Hypercalcaemia on Routine Blood Tests',
  'Endocrine & Nephrology',
  'Telephone Consultation',
  false,
  'Claire Sutton',
  '58-year-old female',
  ARRAY['None recorded'],
  ARRAY['Not currently on any regular medication.'],
  'Seen by Dr Quincy Eze (Clinical Practitioner Access Role) – one week ago

Presenting Complaint: Patient reports feeling tired all the time for approximately one year. She is concerned about diabetes following her sister''s recent diagnosis. No red flag symptoms reported.

Examination: BP 122/74 mmHg, Pulse 76 bpm, no lumps or bumps noted.

Plan: Blood tests requested. Follow up with blood test results.

Blood Test Results
Test                            Result         Reference Range
Corrected calcium               2.9 mmol/L     2.20–2.60
Phosphate                       1.1 mmol/L     0.8–1.5
Alkaline phosphatase (ALP)      92 U/L         30–130
Albumin                         42 g/L         35–50
Sodium                          139 mmol/L     135–145
Potassium                       4.3 mmol/L     3.5–5.3
Urea                            6.1 mmol/L     2.5–7.8
Creatinine                      78 µmol/L      45–84
eGFR                            >90 mL/min/1.73 m²  >60
HbA1c                           38 mmol/mol    <42 mmol/mol
Thyroid function test, Liver function test, Full blood count, CRP, ESR: Normal',
  'Patient booked a follow-up appointment to discuss her blood test results.',
  'Hello doctor, I am calling to go over my blood test results.',
  'You have been feeling tired all the time for over a year now. Although you have been getting on with things, you became more worried recently when your sister was diagnosed with type 2 diabetes. Her GP told her that close family members could also be at higher risk, and that is what prompted you to go and get the blood tests done.',
  ARRAY['You do not have any other symptoms. You went through the menopause at the age of 50.','If asked about your diet and lifestyle: you eat a healthy, balanced diet and exercise regularly.','The tiredness has not stopped you from doing your job as you have adapted to it over time. Your mood is fine and you are not depressed.'],
  'You work as a project manager for the local council. You do not smoke or drink alcohol. You live with your husband.',
  'You think your symptoms might be related to diabetes, following your sister''s diagnosis.',
  'You are worried about developing diabetes because of the risk of complications you have heard about.',
  'You would like the GP to explain what your blood test results mean.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided.',
  ARRAY['Acknowledge that you can see she was reviewed one week ago for tiredness, that blood tests were arranged at that time, and confirm she is calling today to discuss those results.','Ask her to describe in her own words what led her to have the blood tests done.','Ask about the tiredness: onset, duration, and whether it is getting worse, better, or staying the same.','Ask if there are any triggers for the tiredness or anything that makes it better or worse.','Ask about cancer red flag symptoms including unexplained weight loss, night sweats, loss of appetite, or any lumps or bumps noticed anywhere.','Ask about symptoms of hypercalcaemia, for example whether the patient or anyone around her has noticed confusion, feeling muddled, drowsiness, increased thirst (polydipsia), palpitations, chest pain, abdominal pain, constipation, increased urination (polyuria), or blood in the urine (haematuria).','Ask about cough, shortness of breath, or coughing up blood to help exclude possible lung cancer.','Ask about use of any over-the-counter supplements, particularly vitamin D, as excessive intake can cause hypercalcaemia.','Ask about her general mood and sleep quality.','Ask about social history including smoking, alcohol use, and occupation.','Ask about her ideas, concerns, and expectations.','Explain that her blood tests show a raised calcium level, with primary hyperparathyroidism being the most likely cause.'],
  ARRAY['Arrange further blood tests including parathyroid hormone level, vitamin D level, and a repeat adjusted calcium level.','Explain that if the parathyroid hormone level is raised, this would suggest primary hyperparathyroidism, and she would then be referred to an endocrinologist to discuss treatment options, which may include monitoring, medication, or surgery depending on the results and her symptoms.','Advise her to maintain good hydration and ensure she is drinking adequate fluid, as this can help reduce calcium levels.','Reassure her that she does not need to avoid dairy products or other dietary sources of calcium, as normal dietary intake does not cause this degree of hypercalcaemia.','Safety net: advise her to seek urgent medical help through the GP urgent line or NHS 111/999 if she develops increasing drowsiness or confusion, severe abdominal pain, vomiting, muscle weakness, or palpitations, as these can indicate worsening hypercalcaemia.','Arrange follow-up once the further blood test results are available to discuss the next steps.'],
  'Thank you for calling in today, Claire, and I can see you have been waiting for these results with a good deal of anticipation. I want to go through them carefully with you so you have a clear picture of what they show.

First, I can reassure you about the thing you were most worried about. Your HbA1c, which is the main test we use to screen for diabetes, has come back completely normal at 38 mmol/mol. That means you do not have diabetes, and you are well within the normal range. That is good news.

However, there is one result that I do want to discuss with you today, and that is your calcium level. The normal range for calcium is 2.20 to 2.60 mmol/L, and yours has come back at 2.9 mmol/L, which is above the upper limit of normal. This is something called hypercalcaemia, which simply means there is more calcium in your blood than there should be. On its own this does not necessarily cause obvious symptoms, which is why it has been picked up incidentally, but it is something we always take seriously and investigate further.

The most common cause of a raised calcium in someone who is otherwise well is a condition called primary hyperparathyroidism. This happens when one or more of the small glands in the neck, called the parathyroid glands, become overactive and release too much parathyroid hormone, which in turn raises the calcium level. It is usually not dangerous and is often managed very well once identified. To find out whether this is what is happening in your case, I would like to arrange a specific blood test to measure your parathyroid hormone level alongside a vitamin D level and a repeat calcium check.

If that parathyroid hormone test comes back elevated, I would arrange a referral for you to see a specialist doctor called an endocrinologist, who focuses on hormone conditions. They would advise on the best management, which could range from careful monitoring through to medication or even a small procedure to treat the overactive gland, depending on the results and how you are feeling.

In the meantime, I would encourage you to make sure you are drinking plenty of fluids — good hydration is helpful when calcium is raised. You do not need to change your diet or cut out dairy foods, as the amount of calcium in a normal diet does not cause this kind of result. Please do keep an eye out for certain symptoms that would need you to seek help urgently: if you develop increasing confusion, severe abdominal pain, vomiting, significant muscle weakness, or palpitations, please contact the urgent GP line or call 111 straight away.',
  ARRAY['An incidental finding of raised corrected calcium above 2.60 mmol/L requires further investigation; the most common cause in an otherwise well patient is primary hyperparathyroidism.','Initial investigations for hypercalcaemia should include parathyroid hormone level, vitamin D level, and a repeat adjusted calcium; a raised PTH alongside a raised calcium confirms primary hyperparathyroidism.','Symptoms of hypercalcaemia include fatigue, polydipsia, polyuria, constipation, abdominal pain, confusion, and palpitations — remembered by the mnemonic "bones, stones, groans, and psychic moans".','Normal dietary calcium intake does not cause pathological hypercalcaemia; patients should not restrict dairy intake.','Patients should be safety-netted about symptoms of severe or worsening hypercalcaemia, which include confusion, severe abdominal pain, vomiting, muscle weakness, and palpitations, requiring urgent medical review.','If primary hyperparathyroidism is confirmed, referral to endocrinology is appropriate to discuss monitoring, medical management, or parathyroid surgery.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  210,
  'Safeguarding Concerns in a Female Child',
  'Ethics',
  'Telephone Consultation',
  false,
  'Millie Harper',
  '9-year-old female',
  ARRAY[]::text[],
  ARRAY['Not on any current medication','No Known Drug Allergy'],
  'No significant consultation recorded',
  'Patient''s mother, Sandra Ashworth, booked an urgent appointment to discuss a concern about her daughter.',
  'Hi doctor, I''m not quite sure how to start saying this, but my daughter Millie came home from her father''s house two days ago and she told me that one of her dad''s friends — a male friend — had hugged her from behind and touched her down below in a way that felt wrong. Since then she has been quiet and withdrawn and not herself at all. I didn''t know what to do, so I booked this appointment to talk to you.',
  'You and Millie''s father, Daniel Harper, separated around seven months ago and you have joint custody. Millie has been going to his house most weekends for the past five months while you work your weekend shifts. She came home two days ago behaving strangely and seeming unhappy, and when you gently asked her what was wrong she told you that Daddy''s friend had touched her in an inappropriate way. You had a look at her vaginal area and did not see any marks, bleeding, or discharge. She has not started her periods. She says she is not in any pain. She is attending school at the moment and seems all right in herself when she is at home with you. This has never happened before.',
  ARRAY[]::text[],
  'Millie spends weekdays at your home and goes to her dad''s house on Saturdays and Sundays, usually returning Monday mornings. Nobody else lives with you. You work as a waitress at a restaurant and your shifts fall mainly on weekends.',
  'You think Millie may have been touched inappropriately by one of her father''s friends.',
  'You and your ex-partner have been on better terms lately and there is a chance you might get back together. You are worried that if you tell him about this, he won''t believe you and it will destroy any chance of reconciliation.',
  'You want the GP to tell you what steps you should take.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided.',
  ARRAY['Ask exactly what words the child used to describe the incident, including what she meant by being hugged from behind and touched down below.','Ask about the timing of the incident and whether this was a single event or whether similar things may have happened before.','Ask whether the child gave any further details about the father''s friend, such as his name, what he looks like, whether he has been present before, or whether anything like this has happened on previous visits.','Ask about any changes in the child''s behaviour since she came home, such as withdrawal, disturbed sleep, nightmares, clinginess, increased anxiety, or avoidance of certain people or places.','Ask whether the child has reported or shown any physical signs such as marks around the vaginal area, vaginal bleeding or discharge, itching, soreness, bedwetting, or changes in appetite or bowel habits.','Ask about the child''s previous relationship with her father and with this friend, and whether any concerns had been raised before.','Ask about the child''s school attendance and recent behaviour at school, including whether any teachers have raised concerns.','Ask about immediate safety: ask whether Millie is expected to return to her father''s house soon.','Ask about the child''s home arrangements, including where she stays during the week and at weekends, and ask whether the mother has any trusted family or friends who could care for Millie at weekends while this concern is being investigated.','Ask how this situation has affected the mother emotionally and whether she is coping.','Ask about the mother''s ideas, concerns, and expectations.','Make a working diagnosis of potential child sexual abuse.'],
  ARRAY['Thank the mother for coming forward with something so distressing and acknowledge how difficult and upsetting this must be for her and for Millie.','Offer an urgent referral to the safeguarding team, explaining that any concern about potential abuse of a child is taken extremely seriously because of the potential physical and emotional impact on the child.','Explain that the safeguarding team will begin an investigation immediately, and depending on their findings, the police may become involved. Inform her that as part of the investigation process, her ex-partner may also be made aware of the concern.','Explain that you understand she does not want to damage her chances of reconciliation, but that Millie''s safety must remain the priority. Reassure her that the safeguarding process is designed to protect the child while supporting the family, and that the team will involve the father in a sensitive and appropriate way.','Advise her that any communication with the father can be guided or facilitated by safeguarding professionals, which can help prevent misunderstanding and reduce conflict.','Explain that the safeguarding team may offer psychological support or counselling for Millie depending on the impact this incident has had on her.','Advise that Millie should not visit her father until the investigation has been completed and it has been assessed as safe for her to do so.','Advise that if at any point she feels that she or Millie is in immediate danger, she should call 999 without delay. She should also contact the urgent GP line or call 111 out of hours if she has further concerns about Millie.','Offer to follow up with her within 24 to 48 hours to check that the safeguarding team has made contact and to provide ongoing support.'],
  'I want to start by saying how courageous it was to ring us today, and I want you to know that you have absolutely done the right thing. This is an incredibly difficult situation, and the fact that you came to us so quickly shows how much you love your daughter and want to protect her.

What you have told me is something that I, as a GP, am required to take very seriously. Whenever a child tells us that they have been touched in an inappropriate way, we have a duty of care to act. This is not about making assumptions or rushing to conclusions — it is about making sure Millie is safe and that she gets the support she needs. Everything you have told me today will be passed to our safeguarding team, who are specialists trained to handle exactly these kinds of concerns with care and sensitivity.

I also need to address something you mentioned, Sandra — about your feelings towards your ex-partner and the possibility of getting back together. I completely understand how complicated that is, and I can see this is not a straightforward situation for you emotionally. But I want to gently say that Millie''s safety has to come first right now. The safeguarding process is not designed to punish anyone or to take sides. It is designed to protect children and to support families through difficult circumstances. The team will approach your ex-partner in a careful and measured way, and they will work to gather the facts properly.

One of the most important things I need to ask you to do right now is to make sure Millie does not return to her father''s home until this investigation has been completed and the safeguarding team has advised that it is safe for her to do so. I understand that may create practical difficulties with your weekend work shifts, and I would encourage you to think about whether there is a trusted family member or friend who could help with childcare during that time.

The safeguarding team will be in touch with you very soon, and they will guide you through what happens next step by step. They can also access support for Millie — including talking therapies and counselling — if it is felt she would benefit from that. I will also give you a call myself in the next day or two to check that the team has been in contact and to see how you both are doing. In the meantime, if at any point you feel that either you or Millie is in immediate danger, please do not hesitate to call 999.',
  ARRAY['Any disclosure by a child of inappropriate touching must be taken seriously and triggers a mandatory safeguarding referral; the GP has a legal and professional duty to refer to the safeguarding team without delay.','The child''s exact words describing the incident should be documented carefully; clinicians should avoid leading questions and should not conduct their own investigative interview.','Immediate safety planning is essential: the child should not return to an environment where the alleged abuser may be present until the safeguarding investigation is complete.','It is common for parents in these situations to have conflicting loyalties or concerns about family relationships; the GP should acknowledge these sensitively while being clear that the child''s safety is the primary consideration.','The safeguarding referral should include the multi-agency safeguarding hub (MASH) or local equivalent, and the police may become involved as part of the investigation process.','Ongoing GP support and a follow-up contact within 24 to 48 hours are appropriate to ensure the referral has been acted on and to provide continuity of care for the family.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  211,
  'Abnormal Liver Function Tests in a Young male',
  'General Practice',
  'Telephone Consultation',
  false,
  'Oliver Webb',
  '24-year-old male',
  ARRAY['None Recorded','BMI - 23.5 kg/m²'],
  ARRAY['Not currently on any regular medication.','No Known Drug Allergy'],
  'Telephone consultation with Dr Patel (Clinical Practitioner Access Role) – 1 week ago Presenting Complaint: Patient booked an appointment to discuss having blood tests, including liver function tests and a full blood count. He has a history of driving under the influence of alcohol, which resulted in a one-year driving licence suspension. He has reapplied for his driving licence and is due to undergo a DVLA medical assessment in two weeks. He would like to check that his blood test results are satisfactory prior to the assessment. Plan: Full blood count and liver function tests requested. Follow-up to be arranged to discuss results once available. Blood test results Full Blood Count Test Result Reference Range Haemoglobin (Hb) 145 g/L 130–180 g/L White Blood Cells (WBC) 6.2 ×10⁹/L 4.0–11.0 ×10⁹/L Platelets 250 ×10⁹/L 150–400 ×10⁹/L Mean Cell Volume (MCV) 89 fL 80–100 fL Mean Cell Haemoglobin (MCH) 30 pg 27–33 pg Mean Cell Haemoglobin Concentration (MCHC) 335 g/L 320–360 g/L Liver Function Tests Test Result Reference Range Alanine Transaminase (ALT) 54 IU/L 10–40 IU/L Alkaline Phosphatase (ALP) 136 IU/L 30–130 IU/L Albumin 56 g/L 35–50 g/L Gamma-GT (GGT) 32 IU/L 10–60 IU/L Bilirubin 14 µmol/L 3–21 µmol/L',
  'Patient booked appointment to discuss blood test results',
  'Hello doctor, I booked this appointment to go over my blood test results, if that''s okay.',
  'You requested the blood tests because you are due to attend a DVLA medical assessment in one week. You were caught driving while over the alcohol limit a year ago and received a twelve-month driving ban. The ban has now ended and you are eligible to reapply for your licence. You have already submitted your application and your DVLA appointment is in one week. You asked the GP to arrange blood tests to make sure everything looked normal before your assessment. You stopped drinking alcohol completely a year ago and have not had any since. You feel well and have no symptoms. You do not have a history of alcohol dependence. On the evening you were caught, you had been celebrating after securing over 50 property completions at work. It was a lapse in judgement and a one-off incident.',
  ARRAY[]::text[],
  'You do not smoke, drink alcohol, or use illicit drugs. You work in property development. You follow a healthy, balanced diet and exercise regularly. You are not overweight. You live with your long-term partner of over four years and have had no other partners.',
  'You hope that the blood test results will come back as normal.',
  'You are worried that the results might affect your chances of getting your driving licence reinstated. Having your licence back is important for your career.',
  'You would like a clear explanation of what the results mean. You want to know whether they will affect your DVLA assessment and what you need to do next.',
  ARRAY[]::text[],
  'Do these results mean I won''t be able to get my licence back? What should I do from here?',
  'Decline to answer any questions or discuss symptoms beyond what has already been provided in the scenario.',
  ARRAY[
    'Open by acknowledging that you can see from his records that blood tests were arranged ahead of a DVLA assessment, and invite him to tell you more about the background.',
    'Ask about alcohol history in detail, including previous intake, how long he has been abstinent, and whether there has been any relapse.',
    'Ask about symptoms that could point to liver disease, including yellowing of the eyes or skin, itching, dark urine, pale stools, fever, unintentional weight loss, right-sided abdominal pain, and fatigue.',
    'Ask whether he has been unwell recently with symptoms such as a sore throat, cough, fever, runny nose, or flu-like illness, as a recent viral illness can transiently raise liver enzymes.',
    'Ask about use of over-the-counter medications, herbal remedies, or dietary supplements.',
    'Ask about recent travel abroad, to assess for risk of hepatitis A, which is acquired through contaminated food or water in endemic regions.',
    'Ask about family history of liver disease.',
    'Explore social history including smoking, illicit drug use, occupation, and who he lives with.',
    'Ask about sexual history, including any new or recent partners.',
    'Ask about previous blood transfusions or tattoos.',
    'Explore the patient''s ideas, concerns, and expectations.',
    'Arrive at a working diagnosis of abnormal liver function tests, most likely related to supplement use.'
  ],
  ARRAY[
    'Advise the patient to stop taking the supplement straight away, as it may be contributing to the abnormal liver function test results.',
    'Ask him to check the contents of the supplement after the call and send a photograph of the packaging or ingredient list, so this can be recorded and may assist with further management.',
    'Arrange repeat liver function tests in 2–4 weeks to see whether results improve after stopping the supplement.',
    'Explain that if liver function tests remain abnormal, further investigations will be organised, including a full liver panel, hepatitis screen, and an ultrasound scan of the liver.',
    'Reassure him that he can attend his DVLA medical assessment, as the current pattern of results is not consistent with ongoing alcohol use.',
    'Explain that the DVLA may also request additional tests such as carbohydrate-deficient transferrin (CDT), which is more specific for detecting alcohol misuse and is typically negative in those who are not drinking.',
    'Provide safety-netting advice to seek urgent medical attention by contacting the GP urgent line during working hours or NHS 111 out of hours if he develops yellowing of the skin or eyes, itching, fatigue, abdominal pain, or a change in urine or stool colour.',
    'Arrange a follow-up in 2–4 weeks to review the repeat liver function test results and plan the next steps.'
  ],
  'Thank you for calling in today, Oliver — I''m glad you got in touch before your DVLA appointment so we can make sense of these results together. I have had a look at the blood tests that were arranged for you last week, and I want to walk you through what they show and what we''re going to do about it.

The good news is that most of the results are normal. Your full blood count, which checks your red cells, white cells, and platelets, looks completely fine. Within the liver function tests, most markers are also within normal limits. However, there are two values that are slightly outside the expected range. Your ALT, which is one of the main liver enzymes, has come back at 54 IU/L when the normal range is 10–40 IU/L. Your alkaline phosphatase, another liver marker, is 136 IU/L, just nudging above the upper limit of 130 IU/L. Your albumin is also slightly above the upper reference range at 56 g/L, though in isolation this is not usually a cause for concern.

Now, the pattern of these results does not suggest any alcohol-related liver damage. I want to be clear about that, because I know that is what you are most worried about ahead of your DVLA assessment. The GGT, which is the enzyme most sensitive to alcohol use, is entirely normal at 32 IU/L. This is genuinely reassuring.

What is more likely to explain the mild rise in ALT and ALP is the supplement you mentioned taking. Certain gym supplements, protein powders, herbal products, and pre-workout formulas can place a strain on the liver, even when they appear natural or are bought over the counter. I would ask you to stop taking the supplement today, if you haven''t already, and after our call if you could take a photograph of the packaging and send it through to the surgery, that would be really helpful. Having a record of the ingredients will help us understand the picture better.

What I would like to do is arrange a repeat set of liver function tests in two to four weeks. In most cases, when a supplement is the cause, the levels return to normal once it is stopped. If the results are back to normal at that stage, that will be very reassuring and there should be nothing further to worry about.

Regarding your DVLA appointment — I would encourage you to go ahead with it as planned. The pattern of your results is not one that indicates current alcohol use, and the test the DVLA often use, called carbohydrate-deficient transferrin or CDT, is specifically designed to detect recent sustained alcohol intake. As you have not been drinking, this test should be negative.

Finally, I want to give you some safety-netting advice. If at any point before your follow-up you develop yellowing of your eyes or skin, itching, very dark urine, pale stools, significant fatigue, or pain under your right ribs, please contact us urgently during working hours or call NHS 111 out of hours. Otherwise, I will be in touch once we have the repeat results, and we can take it from there.',
  ARRAY[
    'Mildly elevated ALT and ALP in a young man with no symptoms and no alcohol use should prompt enquiry about supplement or over-the-counter product use before pursuing complex investigations.',
    'A normal GGT in the context of mildly elevated ALT and ALP makes an alcohol-related cause less likely, as GGT is the enzyme most sensitive to alcohol-related liver damage.',
    'The DVLA may use carbohydrate-deficient transferrin (CDT) as part of a medical assessment for alcohol-related driving offences; this marker is more specific for detecting sustained heavy drinking than standard liver function tests.',
    'Repeat liver function tests in 2–4 weeks after stopping a potential causative agent (such as a supplement) is appropriate first-line management for mild, isolated LFT abnormalities.',
    'If liver function tests remain abnormal despite stopping the supplement, further investigation including a full liver panel, hepatitis screen, and liver ultrasound should be arranged.',
    'Safety-netting for liver disease should cover jaundice, dark urine, pale stools, right upper quadrant pain, and fatigue, with advice to seek urgent review if these develop.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  212,
  'Flare of Ankylosing Spondylitis',
  'Rheumatology & Musculoskeletal',
  'Video Consultation',
  false,
  'Adam Fletcher',
  '28-year-old male',
  ARRAY['Ankylosing spondylitis'],
  ARRAY['Not currently on any regular medication.','No Known Drug Allergy'],
  'Letter from Rheumatology – 5 years ago Dear GP, Thank you for referring Mr Adam Fletcher, whom I reviewed recently in the rheumatology clinic. Mr Fletcher presented with a history of chronic lower back pain and stiffness, particularly worse in the mornings and improving with activity. Following a thorough clinical assessment, including review of his symptoms, examination findings, and HLA-B27 positivity, a diagnosis of ankylosing spondylitis has been confirmed. His symptoms are currently well controlled with regular ibuprofen 400mg three times daily as required. No additional disease-modifying antirheumatic drugs (DMARDs) are indicated at this stage, given the good response to simple analgesia. I have advised Mr Fletcher to engage with a structured physiotherapy programme, focusing on spinal mobility exercises, posture correction, and aerobic activity. He has been referred to the local physiotherapy service for ongoing support. Mr Fletcher has been fully educated on the importance of monitoring for red flag symptoms, including those suggestive of spinal fracture (such as sudden severe back pain following minor trauma) and cauda equina syndrome (including saddle anaesthesia, bladder or bowel dysfunction, and bilateral leg weakness). He is aware of the need to seek urgent medical attention, including presentation to A&E, should any of these occur. In view of the stability of his condition and good response to conservative management, Mr Fletcher is now discharged from our Rheumatology Clinic. Should any concerns arise or his symptoms deteriorate, please do not hesitate to re-refer him for further review. Thank you for your ongoing care of this patient. Yours sincerely, Dr Helen Ashworth, MBBS, MRCP (Rheumatology) Consultant Rheumatologist',
  'Patient booked a routine consultation to discuss ongoing back pain',
  'Hello doctor, I''ve been struggling with my back pain and it''s just not improving despite taking ibuprofen and paracetamol.',
  'You developed lower back pain about two weeks ago, which came on gradually and feels like a dull, achy discomfort. It is worse first thing in the morning and accompanied by stiffness, but walking around and moving tends to ease it. You have been taking both paracetamol and ibuprofen, but neither is giving you adequate relief.',
  ARRAY[
    'You have not had any recent falls or injuries. You do not have any tingling, numbness, or weakness in your legs. You have no problems with your bladder or bowel.',
    'If asked about physiotherapy, explain that you did not attend the physiotherapy appointment because your symptoms improved with ibuprofen at the time and you did not feel it was necessary.'
  ],
  'You do not smoke, drink alcohol, or use illicit drugs. You live with your girlfriend. You work as a self-employed plumber. Your symptoms are affecting your work, as your job involves prolonged periods of bending and kneeling.',
  'You think this is likely a flare-up of your ankylosing spondylitis.',
  'You are worried because the pain is interfering with your work. You are unable to take on as many jobs as usual, and if things do not improve, it could start to affect your income.',
  'You would like the GP to help manage your symptoms and prescribe something to bring the pain under control so you can return to your normal workload. If offered a sick note or a referral to a social prescriber, explain that you do not want this. You want to keep working and just need treatment to relieve the pain.',
  ARRAY['If the doctor offers you a sick note or referral to a social prescriber for benefits, explain that you do not want this. You want to continue working and would like treatment to relieve your pain so that you can carry on as normal.'],
  NULL,
  'Decline to answer any questions or discuss symptoms beyond what has already been provided in the scenario.',
  ARRAY[
    'Ask about the onset of the pain and whether it came on gradually or suddenly. A gradual onset is more in keeping with a flare of ankylosing spondylitis, whereas a sudden onset raises concern for an alternative cause such as a fracture.',
    'Ask about the character of the pain, including its location, severity, and whether it improves with movement or worsens with rest.',
    'Ask about associated symptoms such as early morning stiffness, which is a hallmark feature of ankylosing spondylitis.',
    'Ask about neurological symptoms including tingling, numbness, or weakness in the legs.',
    'Screen for red flag symptoms, including recent trauma (raising concern for fracture), saddle paraesthesia, loss of bladder or bowel control, and bilateral radicular pain or leg weakness (suggesting cauda equina syndrome), as well as unexplained weight loss, fever, or night pain (which may point to malignancy or systemic disease).',
    'Ask about extra-articular features of ankylosing spondylitis, including anterior uveitis (red, painful eyes with blurred vision or photophobia), enthesitis (pain at tendon insertion sites such as the Achilles tendon or plantar fascia), skin changes suggestive of psoriasis, and gastrointestinal symptoms such as diarrhoea or abdominal cramping that might indicate inflammatory bowel disease.',
    'Explore social history including occupation, smoking status, and alcohol use.',
    'Assess the impact of symptoms on daily activities, work, and overall function.',
    'Ask what he has tried for pain relief and whether he has attended physiotherapy.',
    'Explore the patient''s ideas, concerns, and expectations.',
    'Make a working diagnosis of a flare of ankylosing spondylitis.'
  ],
  ARRAY[
    'Offer a face-to-face appointment to examine the back and perform a full neurological examination.',
    'Offer an alternative NSAID such as naproxen for pain relief, alongside a proton pump inhibitor for gastroprotection.',
    'Offer referral to physiotherapy and explain that it can help improve pain, mobility, and function, which may support his ability to continue working.',
    'Offer to seek advice from the rheumatology team regarding his current flare, to determine whether any additional or alternative treatments may be appropriate.',
    'Provide advice on workplace adjustments, including taking regular breaks from prolonged bending or kneeling and doing gentle stretches during the working day.',
    'Offer referral to a social prescriber, who can discuss any financial support he may be entitled to, particularly relevant given that he is self-employed.',
    'Provide safety-netting advice to call 999 or attend A&E immediately if red flag symptoms develop, including weakness in the lower limbs, loss of bladder or bowel control, numbness around the back passage, or sudden severe back pain. Advise contacting NHS 111 urgently if he is unsure.',
    'Arrange follow-up in 2–4 weeks to review symptoms, or sooner if new advice is received from rheumatology.'
  ],
  'Thank you for getting in touch today — it sounds like things have really been getting on top of you with this flare, and I can completely understand how frustrating it is when the pain is affecting your livelihood. Let''s go through what''s happening and what we can do to help.

From what you''ve described, this sounds very much like a flare of your ankylosing spondylitis. The gradual onset, the dull aching quality, the fact that it is worse first thing in the morning with stiffness that eases once you start moving — all of that is very typical of this condition. Importantly, you haven''t had any falls or injuries, no weakness in your legs, and no bladder or bowel problems, which is reassuring and tells us this is not something more urgent.

The first thing I would like to do is arrange for you to be seen in person so I can examine your back and do a proper neurological check. It is always helpful to assess things directly during a flare, and it means I can also make sure everything is as expected.

In the meantime, I want to help with your pain. Rather than continuing with ibuprofen, which does not seem to be giving you enough relief on its own, I would like to switch you over to naproxen, which is a similar type of anti-inflammatory but can sometimes work better for inflammatory back conditions. I would also prescribe a tablet to protect your stomach while you are taking it, as these medications can occasionally irritate the stomach lining.

I would also like to refer you to physiotherapy. I know that feels like a step you''ve put off before, but for ankylosing spondylitis, physiotherapy is genuinely one of the most effective things we can offer. A structured exercise programme focusing on spinal mobility can make a real difference to your symptoms and your ability to keep working, which I know is your priority.

I will also contact the rheumatology team to share an update on your current situation and ask whether there is anything additional they would recommend at this stage — for example, whether stronger treatments might be appropriate given the flare.

In terms of safety-netting, I want to flag that if at any point you develop sudden severe back pain, any weakness in your legs, numbness around your back passage, or any problems controlling your bladder or bowel, you should call 999 or go straight to A&E — do not wait for an appointment. These would be signs of a more serious problem requiring urgent attention. I will arrange a follow-up for you in two to four weeks, or sooner if you hear anything back from the rheumatology team in the meantime.',
  ARRAY[
    'A flare of ankylosing spondylitis typically presents with gradual-onset inflammatory back pain, worse in the mornings with stiffness that improves with movement — distinguishing it from mechanical back pain, which worsens with activity.',
    'Red flag symptoms including saddle paraesthesia, bilateral leg weakness, and loss of bladder or bowel control must be actively screened for to exclude cauda equina syndrome, which requires immediate A&E attendance.',
    'Extra-articular features of ankylosing spondylitis include anterior uveitis, enthesitis, psoriasis, and inflammatory bowel disease — asking about these is part of a thorough assessment.',
    'When NSAIDs are prescribed for inflammatory conditions, a proton pump inhibitor should be co-prescribed for gastroprotection.',
    'Physiotherapy focusing on spinal mobility and posture is a cornerstone of long-term management in ankylosing spondylitis and should be offered even when initial symptoms improve, as it reduces flare frequency and maintains function.',
    'Self-employed patients may benefit from referral to a social prescriber if symptoms affect income, as they may be entitled to support that a standard sick note does not address.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  213,
  'Recurrent Abscesses in a Patient',
  'Dermatology',
  'Video Consultation',
  false,
  'Donna Howell',
  '35-year-old female',
  ARRAY['Polycystic Ovary Syndrome','BMI - 33.5 kg/m²'],
  ARRAY['Not currently on any regular medication.','No Known Drug Allergy'],
  'Seen by Dr Kelechi Phillips (Clinical Practitioner Access Role) – 6 months ago Presenting Complaint: Patient reported ongoing episodes of multiple painful boils in her right armpit. She was treated with co-amoxiclav one month ago for a similar episode, but the symptoms did not fully resolve. On examination: Multiple erythematous, tender nodules measuring 1-2 cm in diameter, clustered in the intertriginous folds of right axilla. Two nodules show central fluctuance, consistent with early abscess formation. No evidence of sinus tract formation. Impression: Recurrent axillary boils. Plan: Commenced on clarithromycin 500 mg twice daily for 7 days. Blood tests including HbA1c requested to rule out diabetes as a contributing factor Blood test results 6 months ago HbA1c: 38 mmol/mol (Normal) Full blood count, ferritin, liver function tests, thyroid function tests, urea and electrolytes – all within normal limits',
  'Patient sent a photograph and booked a routine appointment to discuss recurrent lumps',
  'Hi doctor, I''ve got another painful lump under my arm and now there''s one in my groin as well. I''m a bit concerned it''s starting to spread.',
  'You first noticed a painful lump in your right armpit roughly two weeks ago, and over the past five days it has become increasingly red and sore. Two days ago you also noticed a similar lump appearing in your left armpit and another one in your left groin. This is the first time anything like this has appeared in the groin or left armpit — the lumps have always been in the right armpit before.',
  ARRAY[
    'At the moment, you have around three painful red lumps in the right armpit and one lump in the left armpit and groin that are not currently painful. None of the lumps are discharging pus.',
    'You feel generally well in yourself and have not had any fever. You have been taking paracetamol to manage the pain.',
    'You have had two previous episodes affecting the right armpit and were given antibiotics on both occasions. During the last episode, you were first treated with co-amoxiclav and then switched to clarithromycin, and your symptoms only resolved after completing the second course of antibiotics.'
  ],
  'You work as a healthcare assistant in a care home and live with your partner. You smoke 10 cigarettes per day and have been smoking for the past ten years. You do not drink alcohol or use illicit drugs. You try to eat healthily by including fruit and vegetables, choosing lower-fat options, and cooking most of your meals at home.',
  'You are wondering whether this might be connected to your PCOS.',
  'You are worried that the lumps seem to be spreading, as they have now appeared in more than one area for the first time.',
  'You would like something to help with the pain and to get rid of the lumps.',
  ARRAY[]::text[],
  NULL,
  'Decline to answer any questions or discuss symptoms beyond what has already been provided in the scenario.',
  ARRAY[
    'Ask about the onset and how the lumps visible in the photograph have developed over time.',
    'Ask whether similar lumps are present in other areas, including the other armpit, the groin, or the perineal region.',
    'Ask about associated features such as redness, pain, itchiness, discharge of pus, fever, or generalised malaise.',
    'Ask whether she has noticed any scarring or skin changes around the armpits or groin from previous episodes.',
    'Ask about possible triggers or aggravating factors, including shaving, use of deodorants or topical products, stress, tight clothing, sweating, friction, and hormonal influences such as flares related to the menstrual cycle or premenstrual symptoms.',
    'Ask about previous episodes, including what treatments were prescribed and how effective they were.',
    'Ask whether the symptoms are affecting daily activities, sleep, or her ability to work.',
    'Ask whether the symptoms have had any psychological impact, such as low mood, anxiety, or reduced self-esteem.',
    'Screen for red flag symptoms to exclude malignancy, including unintentional weight loss, night sweats, or loss of appetite.',
    'Ask about family history of similar skin conditions, noting that a significant proportion of patients with hidradenitis suppurativa have an affected first-degree relative.',
    'Ask about social history including smoking status, alcohol intake, diet, and physical activity levels, as smoking and obesity are recognised risk factors for hidradenitis suppurativa.',
    'Explore the patient''s ideas, concerns, and expectations.',
    'Make a working diagnosis of hidradenitis suppurativa.'
  ],
  ARRAY[
    'Offer a face-to-face appointment to examine the lesions in the armpits and groin, to assess severity and exclude any other abnormalities.',
    'As there are features consistent with acute infection, including redness and pain, offer treatment with either oral flucloxacillin 500 mg four times daily for 5 to 7 days or clarithromycin 500 mg twice daily for 5 to 7 days, depending on suitability and tolerance.',
    'Advise regular simple analgesia such as paracetamol or ibuprofen to help manage pain.',
    'Offer the use of topical antiseptic washes such as Octenisan antimicrobial wash or a 4% chlorhexidine solution, to be used regularly, as these can help reduce flares.',
    'Advise the patient to keep a symptom diary to help identify potential triggers such as stress, certain foods, hormonal changes, or other recurring factors around flare episodes, as this may help reduce future flares.',
    'Acknowledge her ideas and explain that hormonal factors are linked to hidradenitis suppurativa and that people with polycystic ovary syndrome are at increased risk of developing this condition.',
    'Reassure the patient that hidradenitis suppurativa is not caused by poor hygiene.',
    'Acknowledge that she already eats healthily and encourage gradual increases in physical activity where possible, as this can support weight management and help reduce flares.',
    'Offer smoking cessation advice and explain that stopping smoking can improve her overall health and help reduce the frequency of flares.',
    'Advise avoiding tight clothing and tight underwear, as friction and irritation can act as triggers for flares.',
    'Advise against squeezing or manipulating the lumps, as this can worsen inflammation and increase the risk of scarring.',
    'Safety-net by advising her to seek urgent medical review by contacting the practice urgent line during working hours or NHS 111 out of hours if the lesions become increasingly painful, develop spreading redness, start discharging significant pus, are associated with fever, or if she feels generally unwell.',
    'Arrange follow-up in five days to assess whether the symptoms have improved.'
  ],
  'Thank you for getting in touch and for sending through the photograph — that is really helpful and has given me a much clearer picture of what''s going on. I can hear that you''re concerned about these lumps appearing in new areas, so let me explain what I think is happening and what we''re going to do about it.

Based on what you''ve described and the image you sent, along with the history of recurrent painful lumps in your armpits — which have now also appeared in your groin — I think you may have a skin condition called hidradenitis suppurativa. I know that sounds like quite a formal name, so let me explain it in plain terms. Hidradenitis suppurativa is a chronic inflammatory skin condition that affects areas where skin rubs together and where there are sweat glands, such as the armpits, groin, and inner thighs. It causes recurring painful nodules and lumps, which can sometimes become infected.

You mentioned you were wondering whether this could be linked to your PCOS — and that is actually a really astute observation, Donna. There is a well-recognised association between polycystic ovary syndrome and hidradenitis suppurativa, and hormonal factors are thought to play a role. So your instinct was right.

I also want to reassure you that this condition is not caused by poor hygiene. I mention this because many people worry about that, and I want to be clear that it is not the case.

Because some of the lumps look red and sore, which suggests there may be some active infection, I would like to prescribe you a course of antibiotics — either flucloxacillin or clarithromycin — to help settle the acute inflammation. I would also recommend regular paracetamol or ibuprofen to help with the pain in the meantime.

There are also some helpful things you can do at home to reduce flares. Using an antiseptic wash such as Octenisan or a chlorhexidine 4% solution regularly in affected areas can be beneficial. It is also worth keeping a diary of when the lumps appear and whether there are patterns — for example, around your periods, times of stress, or after wearing tighter clothing — as identifying triggers can make a real difference. I would also advise wearing looser clothing and avoiding tight waistbands or underwear where possible, and please do not squeeze or interfere with the lumps, as this can worsen things and increase the chance of scarring.

I also want to raise the topic of smoking, because stopping smoking is one of the most beneficial steps you can take for this condition — it has been shown to reduce the frequency of flares significantly, as well as improving your general health. If you''d like support with quitting, I can arrange a referral to our smoking cessation service.

I would like to see you in person within the next five days to examine the areas properly and review how you are getting on. In the meantime, please contact us urgently or call NHS 111 out of hours if the lumps become much more painful, the redness spreads, pus starts discharging, you develop a fever, or you feel generally unwell.',
  ARRAY[
    'Recurrent painful nodules in the axillae, groin, or intertriginous areas in the context of PCOS and obesity should raise suspicion for hidradenitis suppurativa rather than simple recurrent abscesses.',
    'Hidradenitis suppurativa is not caused by poor hygiene — reassuring the patient on this point is important as it is a common misconception and can cause significant distress.',
    'There is a recognised association between hidradenitis suppurativa and polycystic ovary syndrome; hormonal factors are thought to contribute to the pathogenesis.',
    'Acute infections in hidradenitis suppurativa are managed with antibiotics such as flucloxacillin 500 mg four times daily or clarithromycin 500 mg twice daily for 5 to 7 days.',
    'Topical antiseptic washes (Octenisan or 4% chlorhexidine) and avoidance of tight clothing are useful adjuncts to reduce flare frequency.',
    'Smoking cessation is a key lifestyle modification in hidradenitis suppurativa, as smoking is a recognised risk factor for the condition and cessation can reduce flare frequency.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  214,
  'Parental Request for Contraception in an Adolescent with Down''s Syndrome',
  'Ethics',
  'Telephone Consultation',
  false,
  'Emily Hargreaves',
  '15-year-old female',
  ARRAY['Down''s Syndrome','BMI – 22.3kg/m²'],
  ARRAY['Not currently on any regular medication.','No Known Drug Allergy'],
  'No significant recent consultations. Caller: Patient''s mother, Sandra Hargreaves, booked a routine telephone consultation to discuss concerns.',
  'Mother calling to discuss contraception options for her daughter',
  'Hello doctor, I am calling on behalf of my daughter. I would like to discuss getting her started on contraception and find out what the best option might be.',
  'Emily has recently started a new relationship with a boyfriend, and you are worried that she could become pregnant. You feel it is important to get contraception in place to prevent this until she is older and better emotionally and mentally prepared to cope with having a baby.',
  ARRAY[
    'Her boyfriend is also 15 years old, and they met through a learning disability group. He also has Down''s syndrome.',
    'Emily has not had sex with him yet. You know this because Emily always confides in you and has told you they have never had sex but are thinking about it. You or another responsible adult is always present when they are together, and they are never left alone. You are now considering allowing them some privacy in the future, as he seems to genuinely care for her.',
    'Emily does not know that you are making this call on her behalf.',
    'Her menstrual cycle is regular, occurring every 28 days, and she usually bleeds for five days. Her last period started three days ago and she is still currently on her period. You have not yet spoken to her about contraception, but she does understand that sex can lead to pregnancy.',
    'Emily is currently at school and is not available to come to the phone.',
    'Emily has no other medical problems besides Down''s syndrome, and there is no relevant family history.'
  ],
  'Emily attends a secondary school, is in Year 11, and is doing well academically with no concerns raised by her teachers. She does not smoke or drink alcohol. She lives at home with you, her father, and her older brother.',
  'You understand that if Emily were to have sex without contraception, she could become pregnant.',
  'You are worried that a pregnancy would be extremely difficult for Emily to cope with at her current age.',
  'You would like to discuss the most suitable form of contraception for Emily and would like her to be started on this. If the doctor explains the different contraceptive options, say that you would prefer the injectable method for her, as she might forget to take a daily pill and you do not want to take any chances.',
  ARRAY[]::text[],
  NULL,
  'Decline to answer any questions or discuss topics beyond what has already been provided in the scenario. Accept anything offered by the doctor.',
  ARRAY[
    'Ask where Emily is at the moment and whether she is aware of this call or conversation.',
    'Ask why the mother is requesting contraception for Emily at this time.',
    'Ask whether Emily is sexually active or is considering becoming sexually active.',
    'Ask about the partner, including where Emily met him, his age, and whether Emily feels safe in the relationship, and ask whether the mother is aware of any coercion, pressure, or force from the boyfriend in relation to sexual activity.',
    'Ask whether the mother believes Emily understands the implications of sex and the use of contraception, noting that this helps inform a preliminary assessment of competence, although this must be formally assessed directly with Emily.',
    'Ask about menstrual history, including the date of her last menstrual period, the length of her cycle, whether her periods are regular, and whether there are any menstrual problems.',
    'Ask about any medical contraindications to contraception, including migraines, personal or family history of thromboembolism, and personal or family history of breast cancer.',
    'Ask whether Emily is taking any regular or over-the-counter medications not listed in her records and confirm no known drug allergies as documented in her notes.',
    'Ask about lifestyle factors including smoking, alcohol use, and illicit drug use.',
    'Ask about social history, including who Emily lives with, whether she is currently attending school, which year group she is in, and whether there are any concerns at school.',
    'Explore the mother''s ideas, concerns, and expectations regarding contraception and Emily''s wellbeing.'
  ],
  ARRAY[
    'Thank the mother for raising her concerns and for the care and support she provides for Emily.',
    'Provide a brief overview of the different types of contraception, including their main advantages and disadvantages, and offer an information leaflet to read through together with Emily to support an informed decision.',
    'Explain that only condoms protect against sexually transmitted infections and that sexual health screening is recommended for anyone who is or becomes sexually active.',
    'Explain clearly that contraception cannot be prescribed without seeing and speaking to Emily directly, as she is the patient and her understanding, views, and consent must be assessed.',
    'Offer to arrange a separate face-to-face or telephone consultation with Emily present, ideally without a parent in the room initially, to allow a confidential discussion.',
    'Explain that during this consultation, Emily''s capacity and competence to make decisions about contraception will be assessed, including her understanding of sex, pregnancy, and contraception.',
    'Reassure the mother that young people are usually encouraged to involve their parents in these discussions, but that this decision ultimately rests with Emily unless she is assessed as lacking capacity.',
    'Explain that if Emily is found not to have capacity, any decision would need to be made in her best interests, with appropriate involvement of parents and relevant professionals.',
    'Arrange a follow-up appointment within one to two weeks with Emily present to complete the assessment and discuss contraception in detail. In the meantime, if sexual activity were to occur, advise that condoms should be used.'
  ],
  'Thank you, Sandra, for calling today and for being so open about your concerns. It is clear you are acting out of genuine care for Emily, and I want you to know that this is exactly the kind of thing we are here to help with. Let me take you through how we can approach this together.

First of all, I want to say that it is entirely appropriate to be thinking about contraception at this stage, given that Emily is in a relationship. We can absolutely discuss the options available today. However, I do need to be clear from the outset that we cannot start Emily on any form of contraception without first seeing and speaking with her directly. She is the patient, and her own understanding, views, and consent are central to this process. I hope that makes sense.

There are several different types of contraception available, and I am happy to give you a broad overview. There is the combined oral contraceptive pill, which is taken every day. There is also the patch, which is changed once a week, and the vaginal ring, which is replaced every three weeks. Then there are longer-acting options that do not require daily attention — for example, the injection, which is given every twelve weeks; the implant, which is placed under the skin of the upper arm and lasts for up to three years; and the coil, which is inserted into the womb and can provide contraception for between five and ten years. All of these methods have different advantages and disadvantages, and some may suit Emily better than others depending on her needs and preferences. I will arrange for an information leaflet to be sent to you, and it might be helpful to look through it together with Emily beforehand so she can start forming her own thoughts.

One important point worth mentioning is that none of these methods protect against sexually transmitted infections — only condoms do. So if Emily does become sexually active, using condoms alongside any other method of contraception would also be recommended. We would also advise sexual health screening for anyone entering a new sexual relationship.

In terms of the next steps, I would like to arrange an appointment with Emily present — ideally face to face — within the next one to two weeks. During that appointment, I would speak with her privately to assess her understanding, her capacity to make informed decisions about contraception, and her own wishes. Young people with Down''s syndrome do not automatically lack capacity — the law requires us to assess each person individually, and capacity is decision-specific. If Emily is found to have capacity, she would have the right to make her own decision about contraception, including whether to involve you in that decision. If she were found not to have capacity, then any decision would be made in her best interests, with appropriate involvement from you and, where needed, other professionals.

In the meantime, the most important safety measure would be to ensure that if any sexual activity were to happen before we have had a chance to see Emily, condoms are used. Please do keep me updated if your circumstances change before the appointment.',
  ARRAY[
    'Having Down''s syndrome or being under 16 does not automatically mean a young person lacks capacity — capacity must be assessed individually and is decision-specific, using the principles of the Mental Capacity Act 2005.',
    'Gillick competence applies to young people under 16: if a child has sufficient understanding, intelligence, and maturity to fully appreciate what a proposed treatment involves, they can consent to it independently of their parents.',
    'Contraception cannot be prescribed based solely on parental request — the young person must be seen directly, and their understanding, views, and consent must be formally assessed.',
    'If a young person under 16 is found to lack capacity, any decision regarding contraception must be made in their best interests, with appropriate parental involvement and, where necessary, input from relevant professionals.',
    'Only condoms protect against sexually transmitted infections — this must be communicated when discussing contraception, alongside advice that sexual health screening is recommended for anyone who is or becomes sexually active.',
    'Young people should generally be given the opportunity to be seen without a parent present initially, to allow a confidential discussion and to assess their wishes independently.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  215,
  'Type 2 Diabetes with Microalbuminuria',
  'Endocrine & Nephrology',
  'Video Consultation',
  false,
  'Tariq Saleem',
  '50-year-old male',
  ARRAY['Type 2 Diabetes','Hypertension'],
  ARRAY['Metformin 500 mg three times daily','Ramipril 10 mg once daily','No Known Drug Allergy'],
  'Seen by Katie Beckham (Nurse practitioner role) - Yesterday Presenting complaint: Patient attended for a routine diabetic review. He reported no symptoms or concerns. Examination: Blood pressure 150/100 mmHg. Pulse 76 bpm. BMI: 32.5kg/m². Diabetic foot examination was satisfactory. Urinalysis was negative for all parameters. Plan: Blood samples taken for routine HbA1c and renal function. Patient provided with a urine specimen bottle to return a sample for urine albumin to creatinine ratio (ACR) testing. Blood Test Results Test Current Result Previous Result Reference Range Sodium (Na⁺) 139 mmol/L 140 mmol/L 135–145 mmol/L Potassium (K⁺) 4.4 mmol/L 4.3 mmol/L 3.5–5.0 mmol/L Urea 7.8 mmol/L 7.2 mmol/L 2.5–7.8 mmol/L Creatinine 108 µmol/L 104 µmol/L 64–104 µmol/L eGFR 59 mL/min/1.73 m² 62 mL/min/1.73 m² ≥ 90 mL/min/1.73 m² HbA1c 64 mmol/mol 60 mmol/mol < 42 mmol/mol Urine Test Results Test Result Reference Range Urine Albumin:Creatinine Ratio (ACR) 7 mg/mmol < 3 mg/mmol',
  'Patient booked a routine consultation to discuss recent blood and urine test results from his diabetes review',
  'Doctor, I''ve booked this appointment to go over my blood test results and my urine test from my routine diabetes check.',
  'You have type 2 diabetes and usually have blood tests every three months to keep an eye on your blood sugar levels.',
  ARRAY[
    'You do not have any symptoms. You struggle to take your afternoon dose of metformin because of your work. You work as a delivery driver and are very busy during the day, which means you often forget the lunchtime dose and usually only take the morning and evening doses.'
  ],
  'You do not smoke, drink alcohol, or use illicit drugs. You work as a delivery driver. You live at home with your wife and two children. You are aware that your diet is not ideal, as you tend to eat a lot of carbohydrate-heavy meals and snack frequently due to the nature of your job.',
  'You suspect that your blood sugar results may be high because you regularly forget to take your afternoon dose of medication.',
  'You want to get your diabetes under better control but find it hard to remember the afternoon dose because of work commitments.',
  'You would like the GP to advise you on what you can do to better manage your blood sugar levels.',
  ARRAY[]::text[],
  NULL,
  'Decline to answer any questions or discuss symptoms beyond what has already been provided in the scenario.',
  ARRAY[
    'Open by acknowledging that he has come to discuss the results of his recent blood and urine tests from his routine diabetes review.',
    'Ask about symptoms suggestive of diabetic complications, including blurred vision (diabetic retinopathy), excessive thirst and frequent urination (osmotic symptoms of poorly controlled diabetes), chest pain, shortness of breath, or palpitations (cardiovascular complications), pins and needles or numbness in the hands or feet (diabetic neuropathy), blood in the urine, reduced urine output, or leg swelling (diabetic kidney disease), and non-healing ulcers or wounds on the feet or legs (diabetic foot disease).',
    'Ask about adherence to his prescribed medications.',
    'Ask whether he experiences any side effects from his medications, for example gastrointestinal side effects such as diarrhoea, abdominal pain, or vomiting from metformin.',
    'Ask about social history and lifestyle factors, including smoking status, alcohol intake, occupation, diet, and physical activity levels.',
    'Explore his ideas, concerns, and expectations regarding his diabetes management and treatment.',
    'Make a working diagnosis of poorly controlled type 2 diabetes, uncontrolled hypertension, and suspected chronic kidney disease.'
  ],
  ARRAY[
    'Offer modified release metformin 1 g daily and add dapagliflozin 10 mg once daily.',
    'Explain that modified release metformin will be started first, and after approximately two weeks, once he is tolerating it well, dapagliflozin will then be introduced.',
    'Inform him of side effects. Metformin can cause gastrointestinal upset including diarrhoea and nausea. Dapagliflozin can increase the risk of urinary tract infections and, in rare cases, a serious infection called Fournier''s gangrene, which affects the genital and perineal area.',
    'Explain sick day rules for both medications. If he develops vomiting or diarrhoea, he should temporarily stop these medications and restart them 24 to 48 hours after he is able to eat and drink normally again.',
    'Advise adding another medication to improve blood pressure control and offer amlodipine 5 mg daily. Inform him about possible side effects including ankle swelling and dizziness.',
    'Inform him that the blood tests show his kidney function is not within the expected range and that the urine test has detected some protein leakage, which suggests his kidneys may be under some strain. Explain that these tests will need to be repeated in three months to confirm whether this is a one-off finding or a persistent issue, as factors such as recent exercise, acute illness, or dehydration can temporarily affect the results.',
    'Offer further blood tests to check cholesterol levels and calculate his QRISK score.',
    'Provide lifestyle advice including increasing physical activity, eating healthily, and aiming for gradual weight loss.',
    'Offer vaccinations including influenza, pneumococcal, and COVID vaccination.',
    'Advise him to attend his annual diabetic eye screening appointment.',
    'Provide safety-netting advice, including seeking urgent medical attention by contacting the GP urgent line during working hours or NHS 111 out of hours if he becomes unwell or develops symptoms such as abdominal pain, vomiting, excessive thirst, or confusion, as these may indicate diabetic ketoacidosis.',
    'Offer follow-up in 3 months with repeat HbA1c, renal function tests, and urine ACR.'
  ],
  'Thank you for coming to discuss your results today — there are a few things I would like to go through with you carefully, but I also want to reassure you that we have picked these up at a good stage and there is plenty we can do. Let me take you through each part of the results and then explain what the plan is.

Starting with your blood sugar levels, your HbA1c — which gives us an average picture of your blood sugar control over the past two to three months — has come back at 64 mmol/mol. The target we aim for is below 42 mmol/mol, so this tells us that your diabetes is not as well controlled as we would like at the moment. You mentioned that you often miss the lunchtime dose of metformin because of work, and that is certainly likely to be contributing. We can make a change there that should help significantly — I would like to switch you to a modified-release form of metformin, taken once daily, which means you will not need to worry about the lunchtime dose at all. That should make things much easier to manage around your work schedule.

I also want to introduce an additional medication called dapagliflozin, 10 mg once daily. This belongs to a group of drugs called SGLT2 inhibitors, and it works in a different way to metformin — it helps the kidneys remove excess sugar from the body. It also has some additional benefits for the heart and kidneys, which is particularly relevant given your other results. I will start the modified-release metformin first, and once you have been taking it for around two weeks and we know you are tolerating it well, we will add the dapagliflozin. Both of these medications have sick day rules — if you ever develop vomiting or diarrhoea, you should temporarily stop taking them and restart 24 to 48 hours after you are back to eating and drinking normally.

Moving on to your blood pressure — the reading yesterday was 150/100 mmHg, which is higher than we would like, especially with diabetes and the kidney findings I am about to explain. I would like to add a blood pressure tablet called amlodipine 5 mg once daily. The main side effects to be aware of are ankle swelling and occasionally dizziness, particularly when you first start taking it.

Regarding the kidney results — your creatinine and eGFR, which are measures of how well your kidneys are filtering, are slightly outside the normal range. Your eGFR is 59, and the normal range starts above 90. Your urine test also showed a small amount of protein leaking into the urine, with an ACR of 7 mg/mmol when the normal is below 3. This pattern can be a sign that the kidneys are under some strain, which can happen with long-standing diabetes and high blood pressure. I want to be clear that this does not mean your kidneys are failing — these are early findings, and by addressing your blood sugar and blood pressure control, we can slow or halt any progression. We will repeat both the blood tests and the urine test in three months to see how things have changed, and we will also check your cholesterol and calculate your overall cardiovascular risk score.

In terms of lifestyle, I know your job makes eating well and exercising regularly more difficult, but where you can make small, sustainable changes — reducing carbohydrate-heavy snacks, increasing activity on days off — that will all help. I would also like to make sure you are up to date with your vaccinations, including the flu, pneumococcal, and COVID jabs, as these are recommended for people with diabetes. And please do not forget your annual eye screening appointment, as we want to monitor for any early changes to the retina.

Finally, as a safety-netting point — if at any time you feel very unwell with abdominal pain, vomiting, excessive thirst, or confusion, please contact us urgently or call NHS 111, as these can occasionally be signs of a serious complication of diabetes. I will arrange a follow-up appointment in three months to review everything.',
  ARRAY[
    'An HbA1c of 64 mmol/mol with suboptimal medication adherence should prompt a review of the medication regimen — switching to modified-release metformin reduces the dosing frequency and can significantly improve adherence.',
    'Dapagliflozin 10 mg once daily (an SGLT2 inhibitor) is indicated in type 2 diabetes with suboptimal glycaemic control and offers additional cardiorenal protective benefits beyond glucose lowering.',
    'A urine ACR of 7 mg/mmol (normal < 3 mg/mmol) with a declining eGFR in a patient with type 2 diabetes and hypertension should be investigated further; repeat testing in 3 months is required to confirm persistence before diagnosing chronic kidney disease.',
    'Uncontrolled hypertension in type 2 diabetes with microalbuminuria should be managed aggressively — amlodipine 5 mg daily is an appropriate add-on when an ACE inhibitor alone is insufficient.',
    'Sick day rules for metformin and SGLT2 inhibitors must be clearly explained: both should be temporarily stopped during vomiting or diarrhoea and restarted 24–48 hours after normal eating and drinking resumes.',
    'Patients with type 2 diabetes should be offered annual influenza, pneumococcal, and COVID vaccinations, and reminded to attend their annual diabetic eye screening.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  216,
  'Recurrent Hypoglycaemia in a Patient with Chronic Kidney Disease',
  'Endocrine & Nephrology',
  'Telephone Consultation',
  false,
  'Patricia Mullins',
  '59-year-old female',
  ARRAY['Type 2 diabetes','Chronic kidney disease stage 4'],
  ARRAY['Gliclazide 80 mg once daily','Lantus SoloStar (insulin glargine) 100 units/mL pre-filled pen, 6 units subcutaneously once daily at night.','Ramipril 10 mg once daily','Atorvastatin 20 mg once daily','No Known Drug Allergy'],
  'Letter from Nephrology - 4 weeks ago Dear GP, I reviewed Patricia in the renal outpatient clinic today for follow-up of her chronic kidney disease (CKD stage G4, A3). Recent bloods confirm an eGFR of 23 ml/min/1.73 m² (previously similar trend), with a urine ACR of 72 mg/mmol. Using the four-variable Kidney Failure Risk Equation (KFRE), her estimated risk of progression to kidney replacement therapy is 10.8% at 2 years and 33.6% at 5 years. Her most recent HbA1c is 69 mmol/mol, indicating suboptimal glycaemic control. In view of her renal function, I have advised discontinuation of metformin due to the increased risk of lactic acidosis. To maintain glycaemic control, I have initiated insulin glargine (Lantus) at a dose of 6 units subcutaneously once daily at night, with advice regarding hypoglycaemia awareness and glucose monitoring. I have also started atorvastatin 20 mg once daily for cardiovascular risk reduction. She should continue ramipril 10 mg once daily, with the aim of maintaining her blood pressure below 130/80 mmHg, provided this is tolerated. We discussed dietary advice, focusing on salt restriction and moderation of protein intake. I have also referred her to the diabetes specialist nurses for ongoing follow-up, education, and optimisation of her diabetes management. We will continue to follow her up closely in the nephrology clinic. If there are any concerns in the interim, please do not hesitate to contact us. Yours sincerely, Dr Anna Rutherford MBChB, MRCP (UK), PhD, FRCP Consultant Nephrologist',
  'Patient has booked a routine telephone appointment to discuss stopping her insulin due to morning symptoms',
  'Hello doctor. I would like to stop the insulin because it''s making me feel dizzy every morning.',
  'You were prescribed insulin four weeks ago by the kidney specialists. They stopped your metformin because they explained that, given your level of kidney function, it could cause problems. Insulin was started as a result, and you were told to take it every evening. A nurse at the clinic showed you how to use the insulin pen and also sent you a video to watch at home. Since starting insulin, you wake up most mornings feeling dizzy — by which you mean light-headed, with difficulty concentrating and headaches. When this happens, you usually need to have something sugary to feel better. You read that these symptoms could be a side effect of insulin, and this has made you want to stop taking it.',
  ARRAY[
    'Your other symptoms include excessive sweating and shaking of your hands.',
    'You have a blood sugar machine (glucometer) and you check your blood sugars regularly. Your morning readings are often low, usually between 3.0 and 3.2 mmol/L.',
    'You do not enjoy having to prick your fingers frequently.',
    'You have never needed help from anyone during these dizzy episodes. When symptoms occur, you take apple juice and some chocolates, and you feel better.',
    'You check your blood pressure at home regularly. It was 120/75 mmHg this morning and is usually around the 120s for the top number and the 70s for the bottom number.',
    'These symptoms are affecting your daily routine, as you often end up going to work late in the mornings because you do not feel well.',
    'You do not have chest pain, shortness of breath, palpitations, or visual changes.',
    'You take your gliclazide in the morning after breakfast and you take your insulin at night. Your symptoms occur early in the morning after waking, before eating breakfast or taking your medication.',
    'If asked about driving: You do drive, but you have never driven when feeling dizzy.'
  ],
  'You do not smoke and you do not drink alcohol. You work as a checkout assistant in a supermarket. You drive, but you avoid driving when you feel dizzy or light-headed. You live with your husband. If asked about your periods: you went through the menopause six years ago and no longer have periods.',
  'You think you are experiencing episodes of low blood sugar brought on by the insulin.',
  'You are worried about these episodes as they are affecting your ability to get to work on time. You are also concerned about having to check your blood sugars so frequently.',
  'You would like the GP to stop the insulin and discuss alternative ways to manage your blood sugar safely.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY[
    'Ask why the patient wants to stop taking insulin.',
    'Ask whether symptoms occur at specific times — for example, only in the mornings, or also during the day or evening — and how frequently they happen.',
    'Ask about other symptoms of hypoglycaemia including sweating, tremor, palpitations, confusion, headache, or visual disturbance.',
    'Ask about red flag or severe features of hypoglycaemia including loss of consciousness, seizures, falls, or injuries related to low blood sugar.',
    'Ask whether she checks her blood glucose levels during these episodes and what the recorded readings are.',
    'Ask whether she is aware of early warning symptoms of hypoglycaemia and what she does to relieve symptoms. Also ask whether she has ever needed help from another person during an episode, as this would have implications for driving and the need to inform the DVLA.',
    'Ask whether insulin is being taken alongside gliclazide and confirm the timing of gliclazide dosing, as taking both agents concurrently can cause early-morning hypoglycaemia.',
    'Ask about missed meals, reduced appetite, or reduced evening food intake, as eating very little in the evening increases the risk of overnight and early-morning hypoglycaemia.',
    'Ask whether she was taught how to use her insulin pen and check whether she has any injection site problems such as pain or swelling, as lipohypertrophy can alter insulin absorption and contribute to hypoglycaemia.',
    'Ask whether she monitors her blood pressure at home and when it was last checked, to help rule out postural hypotension as an alternative cause of dizziness.',
    'Ask about lifestyle and social history including occupation, alcohol use, smoking, and prolonged exercise, noting that hypoglycaemia can occur several hours after sustained exercise or alcohol ingestion.',
    'Ask how the symptoms have been affecting her daily life.',
    'Ask about her home situation and whether she has support at home.',
    'Explore the patient''s ideas, concerns, and expectations.',
    'Make a working diagnosis of medication-induced hypoglycaemia, most likely due to the combined use of insulin and a sulfonylurea.'
  ],
  ARRAY[
    'Explain to the patient that the combination of insulin and gliclazide is causing recurrent hypoglycaemia. Explain that in advanced chronic kidney disease, the body''s normal counter-regulatory response to low blood sugar is impaired, making hypoglycaemia more frequent and prolonged.',
    'Offer a continuous glucose monitoring device such as FreeStyle Libre. Explain that this is worn on the arm, reduces the need for finger-prick testing, provides real-time glucose readings on a smart device, and helps identify patterns of low blood sugar.',
    'Reassure her that insulin is an effective medication for controlling blood sugar but requires careful titration, especially in people with reduced kidney function. If she agrees to continue insulin: stop gliclazide (sulfonylureas are known to cause hypoglycaemia in severe renal impairment); advise a consistent evening meal and a bedtime snack to reduce nocturnal hypoglycaemia and early-morning symptoms; refer urgently to the diabetes specialist nurse for close monitoring and insulin dose titration to reduce hypoglycaemia risk; offer SGLT2 inhibitors (gliflozins) such as dapagliflozin or DPP-4 inhibitors (gliptins) such as linagliptin, in addition to insulin; explain sick day rules for dapagliflozin — if she develops vomiting or diarrhoea, she should temporarily stop the medication and restart it 24 to 48 hours after she is able to eat and drink normally again.',
    'If she refuses to continue insulin: stop insulin in line with her wishes and also stop gliclazide; offer SGLT2 inhibitors (gliflozins) such as dapagliflozin and DPP-4 inhibitors (gliptins) such as linagliptin; note that when eGFR is less than 45 mL/min/1.73 m², SGLT2 inhibitors lose their effectiveness in controlling blood sugar, so they are not suitable as monotherapy and an additional agent is often required.',
    'Advise that she must not drive if she develops impaired hypoglycaemia awareness or experiences severe hypoglycaemia requiring help from another person, and that in this situation she would need to inform the DVLA. If she decides to continue with insulin, advise that she needs to inform the DVLA, and the DVLA will determine whether it is safe for her to continue driving (for Group 1 drivers this applies if insulin treatment lasts, or is expected to last, more than 3 months).',
    'Advise keeping fast-acting carbohydrates readily available, such as 150 to 200 mL of fresh juice or a regular fizzy drink (not sugar-free or reduced sugar), and to take this if symptoms occur. Advise avoiding biscuits or chocolate due to their high fat content, which slows sugar absorption.',
    'Encourage informing and educating close family members or household contacts about her hypoglycaemia risk so that help can be provided if needed.',
    'Encourage her to receive recommended vaccinations, including pneumococcal and COVID vaccines.',
    'Advise that if she experiences further hypoglycaemic episodes, she should let the practice know. Safety-net clearly and advise her to let loved ones know about her condition, and to call 999 if she develops severe symptoms including confusion, blackouts, or seizures, or if mild to moderate symptoms do not improve or worsen after taking sugary drinks.',
    'Arrange follow-up with the diabetes specialist nurses.'
  ],
  'Thank you for calling in today — I am really glad you reached out rather than just stopping the insulin on your own, because I want to make sure we handle this safely together. What you are experiencing in the mornings sounds very much like episodes of low blood sugar, and I want to explain why this is happening and what we are going to do about it.

The insulin you were started on by the kidney specialists is called insulin glargine, and it is a long-acting insulin designed to give a steady level of background coverage overnight and into the morning. The problem is that you are also still taking gliclazide — a tablet that stimulates your pancreas to produce more insulin. Taking both together means there is quite a lot of insulin working in your body overnight, and because your kidneys are not working at full capacity, your body''s normal mechanism for raising blood sugar when it drops too low is not as effective as it would be in someone with healthy kidneys. This is why you are waking up with readings of 3.0 to 3.2 mmol/L and feeling dizzy, shaky, and light-headed.

Patricia, the key change I would like to make today is to stop the gliclazide. The gliclazide is actually the main driver of the problem here, and in people with advanced kidney disease, sulfonylureas like gliclazide are known to cause exactly this kind of prolonged hypoglycaemia. Stopping it should reduce the frequency of these morning episodes significantly. I would also like to discuss with you whether you are willing to continue with the insulin or whether you would prefer to stop it — either is a valid choice and I will support you whichever way you decide. I will talk through what each option would mean for managing your blood sugar going forward.

I would also like to offer you a continuous glucose monitoring device called FreeStyle Libre. This is a small sensor worn on the upper arm that monitors your glucose levels continuously throughout the day and night, and you can check the reading at any time using your phone or a small reader. It would significantly reduce the amount of finger-prick testing you need to do, which I know you find difficult, and it will help us spot any patterns in your glucose levels so we can fine-tune your treatment more safely.

In terms of what to do if you feel dizzy in the mornings, I want to make sure you are treating these episodes correctly. The best thing to take is around 150 to 200 mL of full-sugar fruit juice or a regular fizzy drink — not diet or reduced-sugar versions. Please avoid chocolate or biscuits for treating hypos, as the fat in them actually slows down how quickly the sugar is absorbed. Once you have taken something sweet, sit quietly and check your glucose again after fifteen minutes.

I also want to mention driving. You told me you drive but avoid doing so when you feel dizzy — which is absolutely the right thing to do. However, I need to advise you that if you are on insulin, DVLA guidance for Group 1 drivers requires you to notify the DVLA if the insulin treatment is expected to last more than three months. The DVLA will then assess whether it is safe for you to continue driving. Additionally, if you ever had a severe episode where you needed help from someone else — for example, if you became confused or lost consciousness — you would need to stop driving and inform the DVLA immediately.

I will refer you urgently to the diabetes specialist nurses, who will be able to work closely with you to adjust your insulin dose and provide more detailed education and support. Please also let your husband know about these episodes so that he knows what to do if you ever need help. If at any point you develop confusion, seizures, or lose consciousness, or if your symptoms do not improve after taking sugary drinks, please call 999 immediately.',
  ARRAY[
    'Recurrent morning hypoglycaemia in a patient with CKD stage 4 taking both insulin and a sulfonylurea (gliclazide) should prompt immediate review — the combination is a common cause of prolonged hypoglycaemia in renal impairment, as counter-regulatory responses are blunted.',
    'Sulfonylureas such as gliclazide are renally cleared and are known to cause hypoglycaemia in severe renal impairment — they should be stopped in patients with advanced CKD.',
    'SGLT2 inhibitors (e.g. dapagliflozin) lose their glucose-lowering efficacy when eGFR falls below 45 mL/min/1.73 m² and are therefore not appropriate as monotherapy for glycaemic control in advanced CKD; a DPP-4 inhibitor such as linagliptin may be a safer adjunct.',
    'Patients on insulin who are Group 1 drivers must inform the DVLA if insulin treatment lasts or is expected to last more than 3 months; driving must cease if impaired hypoglycaemia awareness or severe hypoglycaemia requiring third-party assistance occurs.',
    'Fast-acting carbohydrates for treating hypoglycaemia should be 150–200 mL of full-sugar juice or fizzy drink (not diet); biscuits and chocolate should be avoided as their fat content slows sugar absorption.',
    'FreeStyle Libre continuous glucose monitoring reduces the need for frequent finger-prick testing and helps identify nocturnal hypoglycaemia patterns — it is particularly useful in patients who find self-monitoring burdensome or who have complex insulin regimens.'
  ],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  217,
  'Chronic Widespread Pain in a Military Veteran',
  'Mental Health',
  'Telephone Consultation',
  false,
  'Simon Hartley',
  '40-year-old male',
  ARRAY['None Recorded','Military veteran, previously served in the British Army'],
  ARRAY['Not currently on any regular medication.','No Known Drug Allergy'],
  'Seen by Dr Karen Patel (Clinical Practitioner Access Role) – 1 week ago. Presenting Complaint: Patient presents with generalised body pain, primarily across the back and shoulders, ongoing for nine months without improvement. No red flag symptoms were reported. Examination: Mild tenderness noted across both shoulders and throughout all spinal segments, including the cervical, thoracic, and lumbar regions. No lumps or swellings identified. Range of movement was full with no restriction. Neurological examination was normal. Impression: Suspected rheumatoid arthritis; polymyositis to be excluded. Plan: Blood tests arranged including inflammatory markers and autoimmune screen. Follow-up booked to discuss results. Blood Test Results: Full blood count, thyroid function tests, liver function tests, urea and electrolytes, bone profile, coeliac screen, HbA1c, vitamin B12, folate, calcium, vitamin D, C-reactive protein, erythrocyte sedimentation rate, and creatine kinase were all within normal limits. Autoimmune and rheumatology screen: all normal.',
  'Patient has booked a telephone appointment to discuss his blood test results.',
  'Hello doctor. I''d like to go over my blood test results if that''s alright with you.',
  'You had these blood tests done because you''ve been having pain all over your body, mainly in your shoulders and back. The pain has been going on for about nine months.',
  ARRAY['The pain is a dull, constant ache, though it can feel better or worse at different times. You''ve tried ibuprofen and paracetamol, but neither has helped much.','You feel tired most of the time and you''re not sure why. Even small tasks leave you feeling exhausted. For example, getting your daughter ready for nursery wipes you out for the rest of the day.','Even after a full night''s sleep, you still wake up feeling unrefreshed.','You don''t have any joint stiffness. Your sleep is okay and your mood isn''t low.','You haven''t noticed any particular triggers, and nothing clearly makes the pain better. Your symptoms have stayed much the same since you were seen by the doctor a week ago.'],
  'You don''t smoke, drink alcohol, or use illicit drugs. You live with your wife and daughter. You are currently unemployed and looking for work. You previously served in the British Army but were medically discharged because of this ongoing pain.',
  'You think this could be rheumatoid arthritis because a friend from the forces was recently diagnosed with it and had similar pain in both shoulders.',
  'The pain has had a significant impact on your ability to work. You were medically discharged from the Army and have been unable to find work since. You''re worried that if this doesn''t get resolved, you''ll struggle to find another job and will run out of savings.',
  'You would like the GP to explain what the blood test results mean and advise you on what should happen next.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided.',
  ARRAY['Clarify with the patient why the blood tests were performed.','Ask about the onset, duration, nature, location, and exact distribution of the pain.','Ask if there are any relieving or aggravating factors, for example whether stress or anxiety triggers or worsens symptoms.','Ask about morning stiffness. Note that in fibromyalgia, stiffness is usually brief and lasts less than 30 minutes, and occasionally up to one hour, whereas in ankylosing spondylitis and other inflammatory joint conditions, stiffness typically lasts longer than 30 minutes.','Ask if there is any swelling in any of the joints.','Ask if there is associated fatigue or a persistent feeling of tiredness (this is common in fibromyalgia).','If tiredness is present, ask whether it is disproportionate to the level of activity (this is a feature of chronic fatigue syndrome and fibromyalgia).','Ask about other symptoms associated with fibromyalgia, including headaches, paraesthesia, and impaired memory or concentration.','Ask about red flag symptoms including unexplained weight loss, night sweats, fevers, weakness in the lower limbs, tingling in both legs, perianal or perineal paraesthesia, or bowel or bladder dysfunction.','Ask about the impact of symptoms on daily functioning, employment, family life, and physical activity.','Ask about sleep, appetite, low mood, anxiety, and post-traumatic stress symptoms, for example flashbacks, nightmares, feeling detached or emotionally numb, or avoidance, particularly given his military background.','Ask whether he has tried any treatments for his symptoms and whether they were helpful.','Ask about social history including smoking, alcohol use, occupation, and home situation.','Ask about his ideas, concerns, and expectations.','Make a working diagnosis of possible fibromyalgia.'],
  ARRAY['No need for a face-to-face review, as he has already been examined by a colleague and there are no new red flag symptoms.','Advise him to keep a symptom diary, as this can help identify potential triggers for worsening pain and support better self-management.','Provide advice on pacing. Explain that pacing is an energy management technique designed to balance activity and rest to avoid symptom flares. This involves identifying current limits and staying within them rather than pushing through fatigue — for example, breaking large tasks into smaller manageable activities with rest in between, resting before feeling exhausted, and gradually increasing activity levels over time.','Offer referral to physiotherapy, as they can provide a tailored graded exercise programme to help improve symptoms and physical function.','Offer cognitive behavioural therapy (CBT). Explain that talking therapy can help change how the brain processes pain, improve coping strategies, reduce psychological distress, and lead to an overall improvement in quality of life.','For pain management, explain that as paracetamol and ibuprofen have not been effective, medication can be considered alongside non-pharmacological approaches. Offer low-dose amitriptyline, starting at 10 mg taken 2 to 4 hours before bedtime. Inform him about common side effects such as drowsiness and dry mouth, and reassure him that most people tolerate this medication well. Explain that this is an off-label use of the medication.','Offer referral to the social prescriber to provide advice on financial support and benefits eligibility, help with applications such as Universal Credit or other employment-related benefits, and signposting to local support services.','Offer written information and leaflets about fibromyalgia for further reading.','Safety-net clearly and advise him to seek urgent medical advice if he develops red flag symptoms such as thoughts of suicide or self-harm, progressive weakness, numbness, bowel or bladder dysfunction, unexplained weight loss, or night sweats.','Arrange follow-up in four weeks to assess response to treatment and consider dose titration if required.'],
  'Thank you for calling today, Simon, and for being so open about everything you''ve been going through. I can hear how much this pain has been affecting your life, and I want to take the time to explain what your blood test results mean and what I think is going on.

The good news is that all of your blood tests have come back completely normal. This means there is no sign of rheumatoid arthritis, thyroid problems, anaemia, vitamin deficiencies, or any other condition that might explain your pain through a blood test. While that might feel frustrating — because the pain is very real — I want to reassure you that this actually helps us work out the diagnosis.

Based on everything you''ve described — the widespread pain across your back and shoulders lasting nine months, the exhaustion that feels out of proportion to what you''re doing, the fact that even getting your daughter ready in the morning wipes you out for the day, and the fact that you sleep but still don''t feel rested — I think the most likely explanation is a condition called fibromyalgia. This is a recognised medical condition that causes real, chronic widespread pain and fatigue. It isn''t something that shows up on blood tests or scans, and it doesn''t mean the pain is imaginary — it reflects the way the nervous system is processing pain signals.

In terms of what we can do, I''d like to suggest a few things. First, I''d encourage you to start keeping a symptom diary — this can help you and your care team spot patterns and identify whether certain activities or stressors make things better or worse. I''d also like to explain something called pacing, which is a technique for managing your energy levels. Rather than pushing through until you''re exhausted, the idea is to break tasks into smaller chunks with rest in between, and to rest before you feel depleted rather than after. Over time, this approach can help you do more without triggering flares.

I''d also like to refer you to physiotherapy, as they can put together a graded exercise programme tailored to you, which has been shown to help with fibromyalgia. Alongside that, I''d like to offer you a referral for cognitive behavioural therapy — often called CBT — which is a type of talking therapy that can help change the way the brain responds to pain signals and improve your ability to cope. Many people find this very beneficial over time.

Regarding medication — since paracetamol and ibuprofen haven''t helped, I''d like to offer you a low-dose tablet called amitriptyline, 10 mg, taken two to four hours before bed. I want to be upfront that this is being used off-label here — it''s not being used as an antidepressant, but rather for its effect on pain pathways and sleep quality. Common side effects can include drowsiness and a dry mouth, but most people tolerate it well at this low dose.

I also want to make sure you get the right support around your situation at home. Given that you''re currently out of work and worried about your savings, I''d like to refer you to our social prescriber, who can help with things like benefits advice, Universal Credit applications, and connecting you with local support services. You shouldn''t have to navigate all of that on your own.

Finally, please do get in touch urgently if you develop any new or worrying symptoms — things like thoughts of harming yourself, progressive weakness or numbness in your legs, any changes in your bladder or bowel function, unexplained weight loss, or night sweats. I''d like to catch up with you again in four weeks to see how things are going and to review whether the amitriptyline needs adjusting. Does that all make sense?',
  ARRAY['Fibromyalgia is a clinical diagnosis characterised by chronic widespread pain, fatigue disproportionate to activity, and unrefreshing sleep, with normal blood tests and examination findings.','Key screening questions include morning stiffness duration (less than 30 minutes in fibromyalgia), disproportionate fatigue, and absence of joint swelling or neurological signs.','Military veterans are at higher risk of fibromyalgia and related conditions; always screen for post-traumatic stress symptoms, including flashbacks, emotional numbing, and avoidance.','First-line management includes non-pharmacological approaches: pacing, graded exercise via physiotherapy, and cognitive behavioural therapy (CBT).','Low-dose amitriptyline 10 mg, taken 2 to 4 hours before bedtime, is an off-label option for fibromyalgia when simple analgesia has failed; common side effects include drowsiness and dry mouth.','Social prescribing referral is an important component of holistic management, particularly where chronic illness has led to unemployment or financial hardship.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  218,
  'Haematemesis Following Acute Alcohol Binge',
  'Gastroenterology & Haematology',
  'Video Consultation',
  false,
  'Ryan Fletcher',
  '20-year-old male',
  ARRAY['None Recorded'],
  ARRAY['Not currently on any regular medication.','No Known Drug Allergy'],
  'No significant recent consultations.',
  'Patient booked an urgent appointment to discuss a health concern.',
  'Hi doctor, I was sick yesterday and noticed some blood when I vomited.',
  'You were out with friends yesterday and drank more than usual. You had around six cans of lager over about two hours, followed by roughly five shots of vodka. About 30 to 40 minutes later, you started vomiting. You had three episodes in total. During the last episode, you noticed small specks of blood in the vomit. This hasn''t happened again since. You''re feeling better now, but you were worried about seeing blood and wanted to get it checked.',
  ARRAY['You don''t currently have any other symptoms and you feel well in yourself.'],
  'You live in student accommodation with flatmates. You are studying computer science at university. You drink alcohol every day, usually around four cans of lager, and have been doing this for the last year. You don''t smoke and you don''t use illicit drugs.',
  'You''re not sure what caused the blood in your vomit.',
  'You were worried when you saw blood after vomiting and want to make sure it''s nothing serious.',
  'You would like the GP to explain what happened and let you know what needs to happen next.',
  ARRAY['If the doctor offers a face-to-face consultation: Decline and explain that you have an important assignment due, but you can come in tomorrow.'],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided.',
  ARRAY['Ask about the onset and number of vomiting episodes.','Ask whether the blood in the vomit was a large volume or small streaks or specks.','Ask about associated symptoms including epigastric pain, heartburn, chest pain, difficulty swallowing, black stools, or diarrhoea.','Ask about red flag symptoms of anaemia including dizziness, syncope, shortness of breath, or palpitations.','Ask about use of over-the-counter medications such as NSAIDs, for example ibuprofen or aspirin, that may contribute to symptoms.','Ask about any past history of similar episodes.','Ask about social history including alcohol intake, smoking, illicit drug use, occupation, and home situation.','Ask CAGE questions to assess alcohol dependence: have you ever felt the need to cut down on your drinking? Do you get annoyed when people comment on your drinking? Have you ever felt guilty about your drinking? Have you ever had a drink first thing in the morning to steady your nerves?','Ask whether he experiences any withdrawal symptoms when he does not drink.','Ask about the patient''s ideas, concerns, and expectations.','Make a working diagnosis of a likely Mallory-Weiss tear or alcohol-induced gastritis.'],
  ARRAY['Offer a face-to-face appointment to assess the abdomen and check observations. If he declines to attend today, this can be arranged for the following day, as there is no immediate clinical urgency.','Offer blood tests including liver function tests to assess for alcohol-related liver injury given his one-year history of heavy daily alcohol intake.','Advise him that he needs to reduce his alcohol intake, as ongoing heavy drinking is harmful to his health.','Offer referral to local alcohol support services to help him cut down safely and reduce the risk of withdrawal symptoms.','Offer omeprazole 20 mg once daily for four weeks to support mucosal healing and reduce gastric acid irritation.','Safety-net clearly. Advise him to seek urgent medical advice by contacting the urgent GP service or NHS 111 if out of hours if vomiting blood recurs, stools become black, or he develops dizziness, abdominal pain, fainting, or palpitations.','Arrange follow-up in four weeks to review symptoms.'],
  'Thanks for getting in touch today, Ryan, and for not ignoring this — seeing blood when you''ve been sick is understandably frightening, and it was the right thing to do to get it checked.

Let me explain what I think happened. When you drink a large amount of alcohol in a short space of time and then vomit forcefully and repeatedly, this can cause small tears in the lining of the oesophagus — the tube that connects your mouth to your stomach. These tears are called a Mallory-Weiss tear, and they''re actually one of the most common causes of small amounts of blood appearing in vomit after a heavy drinking episode. Another possibility is that the alcohol caused inflammation of the stomach lining, which we call gastritis. Both of these are much more likely than something more serious, particularly given that the bleeding appears to have stopped and you''re feeling well now.

The reassuring signs are that you only noticed small specks of blood rather than a large amount, you haven''t vomited blood again since, and you''re feeling okay in yourself. That said, I do want to review you in person so I can examine your abdomen and check some basic observations. I appreciate you''ve got an assignment on today — that''s absolutely fine, we can arrange that for tomorrow.

I''d also like to arrange some blood tests, in particular liver function tests. The reason for this is that you''ve mentioned you''ve been drinking around four cans of lager every day for the past year — that level of alcohol intake over a prolonged period can start to put strain on the liver, and I want to make sure there are no early signs of any damage.

I''d also like to offer you a referral to a local alcohol support service. I say this not to alarm you or to judge you, but because drinking daily at that level does carry real health risks over time, and there are services specifically set up to help people cut down safely. Stopping abruptly after drinking heavily every day can actually cause withdrawal symptoms, so doing this with support is much safer.

In the meantime, I''d like to start you on a medication called omeprazole, 20 mg once a day for four weeks. This reduces the acid in your stomach and helps the lining heal.

Please do get in touch urgently — via the out-of-hours service or NHS 111 if we''re closed — if you vomit blood again, if your stools turn black or tarry, or if you develop dizziness, abdominal pain, or feel faint. Those would be signs that the bleeding has restarted and you''d need to be seen straight away. Otherwise, we''ll review how you''re doing in four weeks. Any questions?',
  ARRAY['Small specks of blood in vomit following forceful vomiting after heavy alcohol intake most likely represent a Mallory-Weiss tear or alcohol-induced gastritis; large-volume haematemesis requires urgent same-day assessment.','CAGE questions are a validated screening tool for alcohol dependence; any positive answer warrants further assessment and referral to alcohol support services.','Daily alcohol intake of four cans or more over a year constitutes hazardous drinking; liver function tests are indicated to screen for alcohol-related liver injury.','Omeprazole 20 mg once daily for four weeks is appropriate to support mucosal healing in alcohol-induced gastritis or Mallory-Weiss tear.','Patients with heavy daily alcohol use should not be advised to stop abruptly without support, due to the risk of withdrawal symptoms; referral to local alcohol services ensures safe supervised reduction.','Safety-netting is essential: advise patients to seek urgent care if haematemesis recurs, stools turn black, or symptoms of haemodynamic compromise develop.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  219,
  'Exertional Chest Pain in a Middle-Aged Adult',
  'Cardiology',
  'Telephone Consultation',
  false,
  'Carol Pemberton',
  '55-year-old female',
  ARRAY['None Recorded'],
  ARRAY['Not currently on any regular medication.','No Known Drug Allergy'],
  'No significant recent consultations.',
  'Patient booked an urgent telephone appointment to discuss a concern following a recent A&E attendance.',
  'Hello doctor. Could you prescribe me something for gastritis?',
  'You were seen in A&E yesterday because of chest pain. You had a heart tracing (ECG) and blood tests done, and you were told that the results were normal. A nurse explained that because your ECG and blood tests were normal, it could take several hours before a doctor could see you. She suggested your symptoms might be due to gastritis and recommended that you see your GP for treatment.',
  ARRAY['The chest pain is in the centre of your chest and feels like a dull, squeezing ache. The first episode happened four weeks ago while you were climbing the stairs at work. The second episode occurred yesterday afternoon while you were carrying heavy shopping bags.','On both occasions, you had to stop what you were doing for the pain to settle. The pain went away after about 5 to 6 minutes of rest.','You don''t have chest pain right now, and you haven''t had any other associated symptoms.','You have only had two episodes of chest pain so far.'],
  'You smoke 20 cigarettes per day and have done so for around 30 years. You don''t drink alcohol and don''t use illicit drugs. You work as an insurance adviser. You live with your husband and two children. Your father died from a heart attack at the age of 62. Your periods stopped 3 years ago.',
  'You think this is gastritis because the nurse in A&E suggested it.',
  'You don''t have any particular concerns at the moment.',
  'You would like the GP to prescribe medication for gastritis.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided. Accept anything offered by the doctor.',
  ARRAY['Ask about the location, onset, and nature or character of the chest pain.','Ask about aggravating and relieving factors for the pain — stable angina is typically precipitated by physical exertion and relieved by rest.','Ask whether the chest pain occurs only with exertion or also at rest, as pain at rest suggests acute coronary syndrome and requires urgent hospital assessment.','Ask whether the chest pain radiates anywhere, for example to the neck, shoulders, jaw, or arms.','Ask how long the pain lasts before resolving — stable angina pain usually lasts less than 15 minutes.','Ask whether she currently has chest pain.','Ask about associated symptoms including shortness of breath, palpitations, dizziness, nausea, or sweating.','Ask about any past cardiac history or previous similar episodes.','Ask about respiratory symptoms such as cough or recent flu-like illness.','Ask about gastrointestinal symptoms including heartburn, vomiting, regurgitation, and whether the pain is related to meals, to help rule out gastritis as suggested in A&E.','Ask about social and lifestyle factors including smoking, alcohol use, illicit drug use, physical activity level, occupation, and diet.','Ask about family history of heart attack or stroke.','Ask about the patient''s ideas, concerns, and expectations.','Make a working diagnosis of stable angina.'],
  ARRAY['Offer a face-to-face appointment for a cardiovascular examination and repeat ECG.','Arrange blood tests including lipid profile, full blood count, urea and electrolytes, and liver function tests.','Start aspirin 75 mg once daily, unless contraindicated, and prescribe glyceryl trinitrate (GTN) spray.','Advise that if chest pain occurs, she should stop what she is doing and rest, then use one spray of GTN. If the pain has not eased after five minutes, she should use a second spray. If the pain has still not eased five minutes after the second dose, she should call 999 for an ambulance.','Offer an urgent referral to the rapid access chest pain clinic (RACPC). Explain that she should be seen within two weeks and that further investigations, such as scans and tests, will be carried out to confirm the diagnosis.','Advise on smoking cessation and offer referral to smoking cessation services.','Advise on maintaining a healthy lifestyle, including regular physical activity within tolerance and a balanced diet.','Safety-net clearly. Advise her to seek urgent medical help by calling 999 if she develops chest pain at rest, worsening or more frequent pain, pain lasting more than 15 minutes, or associated symptoms such as breathlessness, dizziness, or collapse.','Arrange follow-up after she has been seen at the rapid access chest pain clinic to review the outcome and plan ongoing management.'],
  'Thank you for calling today. I completely understand why you came away from A&E thinking this might be gastritis — that''s what you were told, and it''s a very reasonable thing to follow up on. However, having listened carefully to your symptoms, I''m concerned that what you''re experiencing is actually coming from your heart rather than your stomach, and I want to explain my thinking.

Carol, the pattern of your chest pain is really the key here. Both episodes happened during physical activity — climbing stairs at work and carrying heavy shopping bags — and on both occasions the pain settled after you stopped and rested for about five or six minutes. That particular pattern — pain brought on by exertion and relieved by rest — is very characteristic of a condition called stable angina. Gastritis, by contrast, tends to be related to meals and doesn''t typically behave that way.

Angina occurs when the arteries supplying the heart muscle become narrowed. During activity, the heart needs more blood and oxygen, but the narrowed vessels can''t meet that demand, which causes the pain. When you stop and rest, the demand drops and the pain settles. This doesn''t mean you''re about to have a heart attack, but it does mean we need to take it seriously and investigate it properly.

Given that you''ve smoked 20 cigarettes a day for the past 30 years and that your father had a fatal heart attack at 62, your overall risk of cardiovascular disease is higher than average, and that makes it all the more important that we get this checked out thoroughly.

What I''d like to do is arrange for you to be seen face to face so I can examine you and repeat an ECG. I''d also like to arrange some blood tests, including your cholesterol levels, to give us a fuller picture of your cardiovascular risk. Today I''m going to start you on two treatments. The first is aspirin 75 mg once a day, which helps reduce the risk of blood clots forming in the arteries. The second is a spray called glyceryl trinitrate, or GTN. If you get chest pain again, stop what you''re doing and rest, then use one spray under your tongue. If the pain hasn''t settled after five minutes, use a second spray. If it still hasn''t gone five minutes after that, please call 999 immediately — do not wait.

I''m also going to make an urgent referral to what''s called the rapid access chest pain clinic. You should be seen there within two weeks, and they''ll carry out further tests and scans to confirm the diagnosis and decide on the best long-term treatment plan.

One more important thing — and I say this because I genuinely want to help you protect your heart — smoking is one of the biggest risk factors for heart disease, and stopping is the single most effective thing you can do to reduce your risk. I know it''s not easy, and I''m not expecting you to do it alone. If you''re willing, I can refer you to our smoking cessation service, who provide real support to help people quit safely.

Please do call 999 straight away if you develop chest pain at rest, pain that lasts more than 15 minutes, or if you feel breathless, dizzy, or faint. Otherwise I''ll be in touch after your appointment at the chest pain clinic to review what was found.',
  ARRAY['Stable angina characteristically presents as central chest tightness or pressure brought on by exertion and relieved by rest within 15 minutes; pain at rest suggests acute coronary syndrome and requires urgent same-day assessment.','Key risk factors for coronary artery disease include smoking, family history of premature cardiac death, hypertension, hyperlipidaemia, diabetes, and post-menopausal status in women.','Initial management of suspected stable angina includes aspirin 75 mg once daily and glyceryl trinitrate (GTN) spray with clear instructions: one spray at rest, repeat after 5 minutes if no relief, call 999 if no relief after the second dose.','All patients with suspected stable angina should be referred urgently to the rapid access chest pain clinic (RACPC), with a target of assessment within two weeks.','Blood tests including lipid profile, full blood count, urea and electrolytes, and liver function tests are indicated as part of cardiovascular risk assessment.','Smoking cessation is the most impactful lifestyle intervention for reducing cardiovascular risk; referral to cessation services should always be offered.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  220,
  'Parental Anxiety Following Safeguarding Referral',
  'Ethics',
  'Video Consultation',
  false,
  'Donna Ashworth',
  '32-year-old female',
  ARRAY['History of substance misuse (cannabis)','History of alcohol misuse','Completed drug and alcohol misuse rehabilitation programme one year ago.'],
  ARRAY['Not currently on any regular medication.','No Known Drug Allergy'],
  'No significant recent consultations.',
  'Patient booked an urgent appointment to discuss a concern.',
  'Hello doctor. Has anyone from the safeguarding team been in touch with you?',
  'Your son, Tyler, who is 4 years old, was brought to A&E two weeks ago after he developed a bruise on his arm. This happened while he was playing with your partner, Marcus. X-rays were done and everything came back fine. However, the doctors in A&E said they would be making a safeguarding referral. Since then, you''ve been very anxious because you don''t want your child to be taken away from you.',
  ARRAY['Marcus is not the biological father of your son, Tyler. You weren''t present when the incident happened. Your partner told you he was playing with Tyler in the back garden when Tyler fell and bruised his arm. He said it was an accident and that he hadn''t caused the injury. You were indoors at the time, and when you heard Tyler crying you went outside, saw he was in pain, and took him straight to A&E.','When you arrived at A&E, X-rays were done. The doctors said they were concerned about the nature of the injury and certain X-ray findings, and explained they would be making a safeguarding referral. Tyler is well in himself now.','If Asked About Your Partner: Your partner is Marcus, who is 42 years old. He drinks alcohol excessively, including in front of your child. He can be hot-tempered at times, but you love him and feel you understand him. He has been physically rough with you once in the past, but you don''t consider it serious, as he looks after you. He is currently not working, helps out with childcare, and is on Universal Credit.'],
  'You live with your partner and your son. There are no other children at home. You work as a receptionist at a hotel. You don''t smoke or use illicit drugs currently. You previously completed alcohol and drug misuse rehabilitation and no longer drink excessively or use cannabis. You occasionally have a drink when socialising or at celebrations, and you stay within recommended limits.',
  'You''re worried that the safeguarding team may take your child away from you.',
  'You have a history of cannabis and alcohol misuse in your records, and you''re frightened that this will lead to the safeguarding team removing your child from your care.',
  'You would like the GP to delete the cannabis and alcohol misuse history from your medical records.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided.',
  ARRAY['Clarify the patient''s understanding of why a safeguarding referral was made and what concerns were identified in A&E.','Ask about the events leading to the child''s injury, including when it happened, who was present, and what steps were taken afterwards.','Ask about the child''s current condition, including whether the injury has healed, whether the child is still in pain, and where the child is now, for example at home or at nursery.','Ask about the child''s behaviour, including whether he seems withdrawn, fearful, or less engaged than usual.','Ask whether the child is eating and drinking normally, is up to date with immunisations, and whether there are any concerns about his development.','Ask whether there has been any previous history of injuries, accidents, or hospital attendances involving the child.','Ask about the home situation, including who lives at home and whether there are any other children in the household.','Ask about the partner, including his role in the household, alcohol use, smoking, or illicit drug use, and whether there has been any abusive behaviour towards the patient or the child.','Ask whether the patient feels safe at home.','Ask about the patient herself, including occupation, financial situation, smoking, alcohol use, and illicit drug use.','Ask about her ideas, concerns, and expectations.','Consider safeguarding concerns relating to a child with an unexplained injury, and potential domestic abuse risk.'],
  ARRAY['Inform her that past histories of cannabis and alcohol misuse cannot be removed from her medical records, as medical records must be accurate, factual, and reflect relevant past health information.','Inform her that there is an ethical and professional responsibility to keep medical records accurate. Explain that if she were to see a doctor in the future, knowledge of her past medical history could be important in guiding safe and appropriate care, and that removing this information could affect the management of her condition.','Explain that safeguarding teams usually seek consent to access medical records where possible. However, information may be shared without consent if there are concerns about a child''s safety, in line with safeguarding legislation.','Offer to make an urgent referral to children''s safeguarding regardless of whether a referral was made by the hospital. Note that safeguarding is everyone''s responsibility, and hospital referrals can occasionally be delayed, missed, or misdirected. Given that two weeks have passed since the incident without contact, this raises a concern that the safeguarding referral may not have been processed.','Inform her that the child safeguarding team is likely to contact her within the next 24 to 48 hours to gather further information and assess the situation. Reassure her that their aim is to support families and to keep children with their parents wherever it is safe to do so.','Encourage her to engage openly and honestly with safeguarding professionals and to attend any appointments or assessments arranged.','Safety-net clearly. Advise her to seek urgent help by calling 999 if she feels unsafe at home or if she becomes concerned about her partner''s behaviour towards her or her child.','Advise her to seek urgent medical attention if she has any immediate concerns about her child''s health or safety.','Offer follow-up with a telephone or video review within 24 to 48 hours to check whether safeguarding services have made contact and to provide further support if needed.'],
  'Thank you for coming to speak with me today. I can hear how frightened and anxious you are, and I want to take the time to address everything properly. This is clearly an extremely stressful situation for you, and I want to be as honest and supportive as I can be.

I do need to address the request about your medical records first. I understand why you''re worried, Donna — you''re concerned that your past history of cannabis and alcohol misuse might count against you. However, I''m not able to remove that information from your records, and I want to explain why. Medical records have to be accurate and complete. If you ever see a doctor in the future — whether here or somewhere else — that background information could genuinely matter in keeping you safe and making the right decisions about your care. Removing it would go against my professional and ethical responsibilities. I hope that makes sense, even if it''s not what you were hoping to hear.

I also want to explain how safeguarding information-sharing works. Safeguarding teams will usually ask for your consent before accessing your medical records. However, if there are concerns about a child''s safety, information can be shared without consent under safeguarding legislation — and that is there to protect children, not to punish parents.

Now, I''m concerned that two weeks have passed since the A&E attendance and, to your knowledge, you haven''t yet been contacted by a safeguarding team. That''s something I need to take seriously. Safeguarding is everyone''s responsibility — not just the hospital''s — and referrals can sometimes be delayed or misdirected. I''m going to make my own safeguarding referral today to make sure the right people are aware and can follow up.

I want to reassure you about what safeguarding teams are actually there to do. Their primary goal is to support families and to keep children with their parents wherever it is safe to do so. They are not looking to take Tyler away from you without good reason, and they will want to hear your account of what happened. I would encourage you to engage with them openly and attend any appointments or assessments they arrange — that will help them understand the full picture.

Please do contact us urgently, or call 999, if you feel unsafe at home or if you have any concerns about Tyler''s safety or wellbeing. I''d like to follow up with you in the next day or two to check that the safeguarding team has been in touch and to see how you''re doing.',
  ARRAY['GPs have an independent safeguarding duty: if two weeks have elapsed since a hospital attendance without confirmed safeguarding contact, the GP should make their own referral to children''s services rather than assuming the hospital referral was processed.','Medical records must remain accurate and complete; requests to delete historical information — even historical substance misuse — must be declined on ethical and professional grounds, with a clear explanation given to the patient.','Information in medical records may be shared with safeguarding services without patient consent when there is a concern about a child''s safety, in line with safeguarding legislation.','Safeguarding assessments should always include enquiry about the home environment, the role and behaviour of all adults in the household, any history of domestic abuse, and whether the patient feels safe.','The presence of an adult in the household with excessive alcohol use, a history of physical aggression, and unsupervised access to a young child represents a significant safeguarding risk that must be documented and acted upon.','Follow-up within 24 to 48 hours after a safeguarding referral is good practice to confirm that services have made contact and to provide ongoing support to the family.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  221,
  'New-Onset Anxiety Symptoms After Prostate Cancer',
  'Mental Health',
  'Video Consultation',
  false,
  'George Whitmore',
  '84-year-old male',
  ARRAY['Prostate cancer','Hypertension'],
  ARRAY['Amlodipine 5mg once daily','No Known Drug Allergy'],
  'Urology Letter to GP – 5 months ago. Dear GP, Re: George Whitmore, 84-year-old male. Mr Whitmore completed radical radiotherapy for prostate cancer 6 weeks ago. His disease is currently well controlled. His most recent PSA is 0.4 ng/mL, which is consistent with a good post-treatment response. He will continue to be followed up in the urology clinic, with PSA monitoring every 6 months in line with standard UK post-radiotherapy surveillance. Further assessment will be arranged if there is any concerning rise in PSA or new symptoms. Thank you for your ongoing care of this patient. Yours sincerely, Dr Andrew Whitfield, Consultant Urological Surgeon MBBS, FRCS (Urol). Ambulance Attendance Record – 2 days ago. Patient: George Whitmore | Age: 84 years. Reason for attendance: 999 call for shortness of breath, palpitations, and feeling of impending doom. Second ambulance attendance for similar symptoms. On scene findings: Symptoms resolved on crew arrival. No chest pain reported. Clinical assessment: SpO2 97 percent on air, Temperature 36.6°C. Outcome: Hospital conveyance offered but patient declined. Patient assessed to have capacity. Safety-net advice given. Plan / advice: Advised urgent GP review due to recurrent symptoms to exclude underlying cardiac cause. Attending Paramedics: James Holloway, Sarah Whitfield.',
  'Patient booked a routine video appointment to discuss a concern following a recent ambulance attendance.',
  'Hello doctor, the ambulance crew asked me to come and see you.',
  'You''ve been experiencing shortness of breath that comes on whenever you think about going outside. The symptoms started gradually and have been getting worse. They began after you finished radiotherapy for prostate cancer about six to seven months ago.',
  ARRAY['When you feel breathless, your heart starts racing. You don''t experience any chest pain. The symptoms only happen when you think about going outside and don''t occur at other times.','Your wife has become frustrated and upset because you''re no longer able to help with the shopping, go out with her, or visit your grandchildren.','Your mood, sleep, and appetite are generally fine. You don''t have any thoughts of suicide or self-harm.'],
  'You don''t smoke and you don''t drink alcohol. You live with your wife. You are a retired secondary school teacher. Your wife currently does the shopping and cooking. You can manage activities around the house but are unable to leave the house.',
  'You''re not sure why this is happening.',
  'You''re concerned because these symptoms are having a big impact on your life.',
  'You would like the GP to help you get back to normal.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided.',
  ARRAY['Ask about the onset, duration, and progression of the shortness of breath.','Ask what triggers the symptoms and confirm whether they are situational, for example occurring only when thinking about or attempting to leave the house.','Ask about associated symptoms during episodes, including palpitations, sweating, trembling, dizziness, a choking sensation, fear of losing control, fear of dying, or avoidance of situations that may provoke breathlessness.','Ask about the frequency of episodes and whether symptoms resolve spontaneously.','Ask about chest pain, orthopnoea, paroxysmal nocturnal dyspnoea, wheeze, cough, fever, recent flu-like symptoms, leg swelling, or reduced exercise tolerance, to help exclude cardiac or respiratory disease.','Ask whether there was any specific incident that triggered the onset of symptoms, for example being attacked, robbed, or experiencing a distressing event while outside, or whether the symptoms started spontaneously.','Ask about mood, sleep, and appetite.','Ask directly about thoughts of suicide or self-harm.','Ask about common symptoms associated with cancer or cancer treatment, including pain, constipation, or vomiting.','Ask about the impact of symptoms on daily activities, independence, and relationships.','Ask about social and lifestyle history including smoking, alcohol use, illicit drug use, and home situation.','Ask about the patient''s ideas, concerns, and expectations.','Make a working diagnosis of panic attacks with agoraphobia.'],
  ARRAY['Acknowledge his symptoms and validate how distressing and limiting this has been for him.','Explain that his symptoms are most consistent with panic attacks, which can cause very real physical symptoms such as breathlessness, palpitations, dizziness, and a fear response.','Offer referral for cognitive behavioural therapy (CBT) as first-line treatment, focusing on graded exposure and anxiety management techniques.','Advise avoiding anxiety-provoking substances, for example caffeine, as these can worsen panic symptoms.','Reassure him that many people respond well to CBT. Explain that while he is waiting for therapy, medication is an option if symptoms are significantly affecting his quality of life.','If he is open to medication, offer an SSRI such as sertraline, escitalopram, or paroxetine, which are licensed treatments for panic disorder.','If medication is started, explain that symptoms can sometimes worsen in the first one to two weeks before improving, and advise close monitoring.','Safety-net clearly. Advise him to seek urgent medical help if his symptoms change in nature, occur without anxiety triggers, are associated with chest pain, collapse, or other new concerning symptoms, or if he develops thoughts of suicide or self-harm.','Arrange follow-up in two weeks if medication is started, or in four weeks if CBT alone is pursued.'],
  'Thank you for coming to see me today, and I''m really glad the ambulance crew pointed you in our direction. What you''ve been experiencing sounds very frightening and I can understand why it''s been so distressing, particularly given everything you''ve been through with your cancer treatment.

I want to start by saying that I have reviewed the ambulance records and the letter from your urology team. The good news from the urology side is that your prostate cancer is responding well to the radiotherapy — your PSA level of 0.4 ng/mL is consistent with a very good treatment response, and you''ll continue to be monitored by the urology team.

Now, regarding these episodes of breathlessness and racing heart — I want to explain what I think is happening. George, what you''re describing sounds very much like panic attacks. I know the word ''panic'' might sound dismissive, but I want to be clear: panic attacks cause very real, physical symptoms. The breathlessness, the racing heart, the feeling of dread or impending doom — these are all genuine physiological responses that your body produces. They can feel frightening and overwhelming, and they are not imagined.

What strikes me about your situation is that the symptoms seem to be triggered specifically by the thought of going outside. You''re fine in the house, but as soon as you think about leaving, the anxiety builds and the physical symptoms follow. This pattern — where someone starts to avoid certain situations because of fear of symptoms occurring — is something we recognise as agoraphobia linked to panic disorder. It''s not uncommon for something like this to develop after a significant illness or stressful medical experience, such as completing cancer treatment.

The first thing I''d like to offer you is a referral for a type of talking therapy called cognitive behavioural therapy, or CBT. This is the most effective treatment for panic disorder and agoraphobia. It works by helping you gradually face the situations that trigger your symptoms, in a structured and supported way, while also changing the thought patterns that feed the anxiety. Many people find significant improvement with CBT.

While you''re waiting for therapy to start — and I appreciate that can take some time — I want to offer you the option of medication if your symptoms are continuing to affect your quality of life significantly. The type of medication I''d suggest is called an SSRI — selective serotonin reuptake inhibitor. Examples include sertraline, escitalopram, and paroxetine. I do want to mention that for the first one to two weeks after starting, some people notice their anxiety feels slightly worse before it improves. That''s temporary, and I''d want to check in with you closely during that period. It would also be worth avoiding stimulants like caffeine during this time, as these can make anxiety and palpitations worse.

Please do contact us urgently if your symptoms change in nature — for instance, if you develop chest pain alongside the breathlessness, or if you feel faint or collapse. Those symptoms would need prompt medical assessment to rule out a heart or lung cause. Similarly, if you ever develop thoughts of harming yourself, please reach out immediately. I''d like to follow up with you in two to four weeks, depending on whether we start medication today. Is there anything you''d like to ask me?',
  ARRAY['Panic attacks cause genuine physical symptoms including breathlessness, palpitations, dizziness, and a sense of impending doom; these can be misinterpreted by patients and paramedics as cardiac events.','Panic disorder with agoraphobia may develop following a major stressful life event such as a cancer diagnosis or treatment; always consider psychological causes when physical investigations are unremarkable.','Cognitive behavioural therapy (CBT) with graded exposure is the first-line treatment for panic disorder and agoraphobia; medication with an SSRI (sertraline, escitalopram, or paroxetine) is an appropriate adjunct or alternative if symptoms are significantly impairing quality of life.','When starting an SSRI for anxiety or panic disorder, warn patients that symptoms may worsen in the first one to two weeks before improving and arrange close follow-up during this period.','Cardiac and respiratory causes must be excluded before attributing symptoms to panic disorder, particularly in older patients with comorbidities; review ambulance observations and consider ECG.','Advise patients to avoid caffeine and other stimulants, which can exacerbate anxiety and trigger palpitations.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  222,
  'Mental Capacity Assessment in a Patient with Schizophrenia',
  'Mental Health',
  'Video Consultation',
  false,
  'Daniel Sherwood',
  '25-year-old male',
  ARRAY['Autism spectrum disorder','Schizophrenia','Depression','History of attempted suicide'],
  ARRAY['Aripiprazole 30 mg once daily','Sertraline 100mg once daily','No Known Drug Allergy'],
  'Letter from Adult Psychiatry – 1 year ago. Dear GP, Re: Daniel Sherwood, 25-year-old male. Thank you for your ongoing care of Mr Daniel Sherwood. I am writing to provide an update following his recent compulsory psychiatric admission and subsequent discharge into the community. Mr Sherwood has a background of high-functioning autism, schizophrenia, and recurrent depressive disorder. He has a significant history of severe psychotic episodes associated with both suicidal and violent ideation. During his most recent relapse, he experienced distressing command auditory hallucinations instructing him to harm himself and others, including voices telling him to go to railway tracks to sabotage them and hurt people because he believed the world was evil. During this period, Mr Sherwood made a serious suicide attempt by jumping from a bridge into a canal. Fortunately, he was rescued without fatal injury. Owing to the severity of his psychotic symptoms, lack of insight at the time, and the high perceived risk to himself and others, he was detained under the Mental Health Act and remained an inpatient for approximately one month. During his admission, his mental state stabilised with antipsychotic and antidepressant treatment. On discharge, a robust risk management and support plan was put in place. Mr Sherwood has now been discharged to supported living accommodation in the community. Given the ongoing perceived risks, he has been allocated a dedicated mental health support worker who remains with him at all times to provide supervision, structure, and early identification of relapse. Mr Sherwood will continue to be followed up closely by the Community Mental Health Team, with regular psychiatric reviews and ongoing multidisciplinary input. Yours sincerely, Dr Eleanor White, Consultant Psychiatrist MBBS, MRCPsych, General Adult Psychiatry.',
  'Patient booked a routine video consultation to discuss several requests.',
  'Hello doctor, I want you to write a letter saying that I have capacity so that my mental health support worker can stop following me everywhere and telling me what to do. I also want to increase my working hours from 10 hours per week to full-time work — 40 hours a week — and I''d like to stop my medications as I feel better.',
  'You had a severe relapse of your schizophrenia about one year ago. During that time, you nearly harmed yourself and others and were admitted to hospital under the Mental Health Act. After discharge, you were given a mental health support worker who supervises you closely, makes sure you take your medication, and goes out with you when you leave the accommodation. You feel much better now and believe you no longer need this level of supervision. You want more independence and freedom to go places on your own without being monitored. You also want to stop your medication, as you no longer have thoughts of suicide or self-harm. You currently work in a coffee shop for around 10 hours a week, but you feel ready to work up to 40 hours a week and want the GP to support this. You believe all of this can be resolved if the GP writes a letter confirming that you have capacity and no longer need monitoring.',
  ARRAY['There is no bullying or mistreatment from the mental health support workers. They are kind and supportive, but you feel restricted by their constant presence and monitoring.','You have not experienced any side effects from your medications.'],
  'You live in supported living accommodation. You get on well with staff and other residents and have friends there. You don''t smoke, drink alcohol, or use illicit drugs.',
  'You believe the support workers were necessary in the past to keep you safe, but you feel well now and think they are no longer needed.',
  'You don''t have any particular concerns at the moment.',
  'You want the GP to write a letter stating that you have capacity, allowing you to stop being supervised, increase your working hours, and stop your medications.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided.',
  ARRAY['Ask why the patient wants a letter stating that he has capacity.','Ask why he wants to stop his medication and whether he has experienced any side effects, such as weight gain, nausea, or vomiting.','Ask what he understands about his diagnoses and why the mental health support worker was put in place after his last admission.','Ask about his current mental state, including mood, thought disorder, hallucinations — especially whether he is still hearing voices or seeing things — or delusional beliefs.','Confirm when his last relapse or psychotic episode occurred and whether it was approximately one year ago.','Ask directly about any current or recent thoughts of suicide, self-harm, or harm to others.','Ask about any safeguarding concerns, including whether he has felt bullied, verbally abused, physically abused, or mistreated by his mental health support workers or carers.','Ask about his current employment, what his role involves, and why he wishes to increase his working hours, including whether there are any financial pressures.','Ask about social and lifestyle factors, including where he lives, smoking status, alcohol intake, and use of illicit drugs.','Ask whether he has discussed his concerns or wishes with the Community Mental Health Team.','Ask about the patient''s ideas, concerns, and expectations.'],
  ARRAY['Explain that the GP cannot provide a letter declaring capacity to stop supervision, stop medication, or change care arrangements, as these decisions sit with the Community Mental Health Team and Consultant Psychiatrist.','Explain that everyone is assumed to have capacity unless proven otherwise and that capacity is decision-specific and time-specific. Everyday decisions such as what clothes to wear are usually within capacity, but higher-risk decisions such as stopping medication or reducing supervision require specialist assessment to ensure decisions are made safely.','Reassure him that this is not about taking control away from him, but about ensuring changes are made with him in a safe and supported way.','Advise strongly against stopping medication abruptly, explaining that sudden discontinuation of antipsychotic or antidepressant medication significantly increases the risk of relapse, with potential risk to himself and others.','Offer to contact and inform the Community Mental Health Team about his concerns. Explain that they may arrange a multidisciplinary review involving his psychiatrist, mental health support workers, and care coordinators to assess whether it is safe to reduce supervision, increase working hours, or consider any changes to medication.','Advise that any increase in working hours should be gradual and agreed with the mental health team, rather than an immediate move to full-time work, as increased stress can trigger a relapse.','Safety-net clearly: advise him to seek urgent help from mental health services, the local crisis team, or emergency services if he experiences a return of hallucinations, suicidal thoughts, thoughts of harming others, worsening mood, or loss of control.','Reassure him that you will update him as soon as you hear back from the Community Mental Health Team and arrange follow-up to review the outcome.'],
  'Thank you for coming to speak with me today, and I want to say straight away that I can hear how much better you''re feeling and how much you''re looking forward to having more independence. That''s genuinely positive progress, and I don''t want you to feel that your wishes aren''t being taken seriously — because they are.

However, I do need to be honest with you about what I can and can''t do. I''m not in a position to write a letter declaring that you have capacity and no longer need supervision, and I want to explain why. Firstly, Daniel, the legal principle around capacity is that everyone is assumed to have capacity unless there''s reason to assess otherwise — so in that sense, capacity isn''t something a GP can simply ''grant'' via a letter. More importantly, capacity is decision-specific. For everyday choices — what to wear, what to eat — there''s no question. But for higher-risk decisions, such as stopping your medication or reducing the level of supervision that was put in place after a very serious episode, those decisions need to be reviewed by the team that knows your care in the most detail — your Community Mental Health Team and your Consultant Psychiatrist.

I want to be very clear: this isn''t about taking control away from you, and it isn''t a sign that people don''t believe you''re doing well. It''s about making sure that any changes happen with you, in a safe and supported way, with the right people involved in the decision.

Regarding your medication — I would strongly advise against stopping your aripiprazole or your sertraline without specialist guidance. Stopping antipsychotic or antidepressant medication abruptly significantly increases the risk of relapse, sometimes very quickly. Given what happened during your last episode — the intensity of the symptoms and the serious risks involved — that''s something we all want to avoid. If reducing your medication is something you want to explore, that''s a conversation worth having, but it needs to happen with your psychiatrist.

What I can do — and will do today — is contact your Community Mental Health Team to let them know about your concerns and what you''ve asked for. They may well arrange a multidisciplinary review involving your psychiatrist, support workers, and care coordinator to look at whether it''s safe and appropriate to gradually increase your independence, step up your working hours, or consider any adjustments to your care plan. Any increase in hours should be gradual rather than jumping straight to full-time work, as a sudden increase in pressure and stress can sometimes be a trigger for relapse.

Please do reach out urgently to your mental health team, the crisis line, or emergency services if you notice any return of voices, thoughts of harming yourself or others, worsening mood, or any sense of losing control. I''ll be in touch with you again as soon as I''ve heard back from the Community Mental Health Team.',
  ARRAY['Capacity is presumed under the Mental Health Capacity Act 2005 and is decision-specific and time-specific; GPs cannot issue letters "granting" capacity, and high-risk decisions such as stopping antipsychotics or reducing supervision require specialist multidisciplinary assessment.','Abrupt discontinuation of antipsychotic medication — such as aripiprazole — significantly increases the risk of psychotic relapse; any changes to medication in patients with a history of severe psychosis must be supervised by the responsible psychiatrist.','In patients with complex psychiatric histories managed under a Community Mental Health Team, major changes to care — including reducing supervision or increasing work demands — should be coordinated through a multidisciplinary review rather than actioned unilaterally by the GP.','Increased psychosocial stress, such as a sudden shift to full-time employment, can precipitate relapse in schizophrenia; any increase in working hours should be gradual and agreed with the mental health team.','Always screen for safeguarding concerns when a patient with severe mental illness is living in supported accommodation with carers, including asking about mistreatment, bullying, or coercion.','Safety-netting in patients with a history of suicidal ideation and command hallucinations must include clear advice to contact crisis services or emergency services if hallucinations, suicidal thoughts, or thoughts of harming others return.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  223,
  'Recurrent Vomiting in a Young Adult',
  'Gastroenterology & Haematology',
  'Telephone Consultation',
  false,
  'Zoe Hartley',
  '27-year-old female',
  ARRAY['None Recorded'],
  ARRAY['Microgynon 30 combined oral contraceptive pill','No Known Drug Allergy'],
  'A and E Discharge Summary (Two Weeks Ago) Zoe Hartley | 27-year-old female Triage Notes: 2 months history of recurrent vomiting. The patient reported ongoing vomiting on the day of attendance with approximately six episodes. Vomiting was non-bloody. Assessment: Urine pregnancy test was negative. Blood tests and medical review were planned; however, the patient left the department before these could be completed. Outcome: The patient left the department prior to full clinical assessment and investigations. Kind regards, Dr James Patel ST5 Emergency Medicine Registrar Reason for appointment: Patient booked a routine telephone appointment to discuss some concerns.',
  'Patient booked a routine telephone appointment to discuss ongoing vomiting episodes.',
  'Hi doctor, I''ve been feeling sick and bringing up my food on and off for about two months now and it''s starting to worry me.',
  'It began about two months ago — I started getting these sudden bouts of vomiting. They come on out of nowhere. When they happen I can''t stop being sick, roughly four or five times in the space of half an hour to an hour. Sometimes it carries on later in the same day too. It tends to flare up around once a week and it''s beginning to take its toll — I''ve had to call in sick to work because of it.',
  ARRAY['You have noticed that the episodes tend to happen when you are most stressed.','You sometimes feel bloated and your stools can be hard and pellet-like, but this is not new — your bowels have always been like this.','There is no blood in your vomit or stools. You have not lost any weight and you can generally keep fluids down between episodes.','You are not pregnant and you completed a pregnancy test recently, which came back negative.','You use cannabis most days and have been doing so for the past six to seven months.','You have no abdominal pain, fever, night sweats, or difficulty swallowing.','Your last period started 7 days ago.'],
  'You work as a receptionist at a letting agency. You do not smoke cigarettes. You use cannabis regularly. You do not drink alcohol. You live with your boyfriend.',
  'You think it might be stress-related. You recently took on a new position at work with more responsibility and are still finding your feet, though your colleagues have been supportive.',
  'You are worried that if this carries on it will affect your job, as you''ve already needed to take time off when the vomiting flares up.',
  'You''d like either medication or advice on how to stop it happening.',
  ARRAY[]::text[],
  'If the doctor advises you to stop using cannabis, ask whether cutting down rather than stopping completely would be enough to make the symptoms go away.',
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Ask when the vomiting episodes started and how symptoms have progressed over time','Ask how many episodes of vomiting occur in a typical day and during a flare','Ask about the contents of the vomit, specifically whether there is any blood or bile','Ask whether the patient is able to keep fluids down between episodes','Ask about any known triggers, including emotional stress or anxiety, infections, certain foods, prolonged periods without food, dehydration, hot weather, menstrual periods, excessive exercise, or sleep deprivation','Ask about associated symptoms such as nausea, abdominal pain, diarrhoea, constipation, bloating, or unintentional weight loss','Ask how the vomiting is affecting the patient''s day-to-day activities, work, and quality of life','Ask about symptoms of dehydration, including headache, dry mouth or lips, dizziness, increased thirst, lethargy, and reduced urine output','Ask about the date of her last menstrual period and acknowledge the recent negative pregnancy test performed in the emergency department','Ask about social and lifestyle history, including smoking, alcohol intake, illicit drug use, particularly cannabis use, occupation, and home situation','Explore the patient''s ideas, concerns, and expectations','Make a diagnosis of cannabinoid hyperemesis syndrome'],
  ARRAY['Offer a face-to-face appointment to perform an abdominal examination and arrange blood tests, including urea and electrolytes, full blood count, liver function tests, and HbA1c, to ensure there are no other contributing causes and no electrolyte abnormalities','Advise the patient to keep a symptom diary to help track the frequency and severity of symptoms and to identify any additional triggers other than stress that may help with prevention','Offer antiemetic treatment for symptomatic relief, for example prochlorperazine 10 mg three times daily to be used when required','Advise that stopping cannabis use completely is the most effective way to prevent further episodes of vomiting','Explain that anti-sickness medication may provide short-term relief but will not fully resolve symptoms if cannabis use continues','Offer support for stopping cannabis use and explain that local drug misuse services are available if she would like additional help','Discuss strategies to manage stress, including breathing and relaxation exercises, regular physical activity, yoga, and talking therapies','Provide safety net advice to seek urgent medical review (by calling the GP urgent line or 111 if out of hours) if vomiting becomes persistent, if she is unable to keep fluids down, if there is blood in vomit or stools, if severe abdominal pain develops, if there is unintentional weight loss, or if there are signs of dehydration such as dizziness or palpitations'],
  'Thank you for calling today and for being so open about everything — I can hear how much this has been affecting you. Based on what you''ve told me, Zoe, I think the most likely explanation for your recurrent vomiting is something called cannabinoid hyperemesis syndrome. This is a condition that can develop in people who use cannabis regularly over a prolonged period. It causes repeated, sudden-onset episodes of severe nausea and vomiting, often coming in intense waves lasting anywhere from minutes to hours — which sounds exactly like what you''ve been experiencing.

The way cannabis works in the body is quite complex. While it has well-known effects on the brain, it also affects the gut directly — slowing down stomach emptying and interfering with normal digestion. In some people who use it regularly, this eventually leads to the pattern of cyclical vomiting you''ve described. Stress can act as an additional trigger, which fits with what you''ve noticed.

I want to be honest with you about the most important part of treatment: stopping cannabis completely is the key step. I know that might not be what you were hoping to hear, and I appreciate it''s not easy. Cutting down rather than stopping fully is unlikely to be enough to resolve the symptoms — the vomiting tends to continue as long as cannabis is present in the system regularly. That said, I don''t want you to feel alone in this. There are local support services that can help if you''d like some guidance with stopping, and we can look into those together.

In the shorter term, I can prescribe you some anti-sickness tablets — prochlorperazine 10 mg three times daily, taken as needed — to help manage the episodes while you work towards stopping cannabis. These should take the edge off during flares, though they won''t cure the underlying cause on their own.

I''d also like to bring you in face to face so I can examine your abdomen and check some blood tests, including kidney salts, a full blood count, liver function, and blood sugar levels. This is just to make sure nothing else is contributing and that your body hasn''t been depleted by the repeated vomiting.

Keeping a symptom diary in the meantime would also be really useful — noting when episodes occur, how long they last, and whether anything else seems to trigger them beyond stress. This will help us build a clearer picture going forward.

You mentioned stress has been a big factor lately. It''s worth thinking about ways to protect your wellbeing alongside stopping cannabis — things like breathing or relaxation techniques, regular gentle exercise, or even speaking to a therapist. Some people find structured talking therapy particularly helpful when both stress and substance use are involved.

Finally, please do seek urgent help if the vomiting becomes constant, you can''t keep any fluids down, you notice blood in your vomit or stools, develop severe abdominal pain, unexplained weight loss, or feel dizzy and unwell in a way that worries you. In that case, please call our urgent GP line or NHS 111 if it''s out of hours, or call 999 if things feel very serious.',
  ARRAY['Cannabinoid hyperemesis syndrome presents with recurrent cyclical vomiting in the context of regular, long-term cannabis use — always take a thorough drug history in unexplained vomiting.','Complete cessation of cannabis is the definitive treatment; dose reduction alone is insufficient and symptoms typically persist while use continues.','Prochlorperazine 10 mg three times daily as required can be used for symptomatic relief while the patient works towards stopping cannabis.','If standard antiemetics are ineffective, topical capsaicin 0.1% cream (approximately 5 g applied to the abdomen) may be considered as an alternative.','Amitriptyline may be considered for prevention of recurrent flares, though evidence supporting its use remains limited.','Safety-netting should cover persistent vomiting, inability to tolerate fluids, blood in vomit or stools, signs of dehydration, or severe abdominal pain.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  224,
  'Persistent Headache in a Middle-Aged Adult',
  'Neurology',
  'Telephone Consultation',
  false,
  'Helen Forsythe',
  '38-year-old female',
  ARRAY['Copper IUCD inserted 2 years ago'],
  ARRAY['Not currently on any regular medication','No Known Drug Allergy'],
  'Seen by Dr James McDonnell (Clinical Practitioner Access Role) – 3 weeks ago Presenting complaint: Headache ongoing for two months, described as a tight band around the head. Associated nausea but no vomiting. No red flag features reported. Examination: Fundoscopy satisfactory in both eyes with no concerning features. Blood pressure 120/70 mmHg. Neurological examination normal. Impression: Tension-type headache Plan: Patient was reassured. Advised on stress management techniques and use of simple analgesia such as paracetamol and ibuprofen. Safety-net advice given regarding red flag symptoms.',
  'Patient booked a routine telephone consultation to discuss headaches that have not improved since her last appointment.',
  'Doctor, I''m ringing back because my headaches are still just as bad — they haven''t got any better since I was last seen.',
  'I''ve had this headache for nearly three months now. It''s there almost every day. The pain spreads across the whole front of my head and feels like a tight band pressing round it. I feel queasy with it, though I haven''t actually been sick.',
  ARRAY['The headache gets worse when you tilt your head back, particularly when you look upwards.','You take paracetamol and ibuprofen, which help for a short while but the headache keeps coming back. You use these medications roughly five to six times a month and try not to rely on them too much.','You don''t experience any other symptoms.','Your last period was seven days ago. You currently have a copper coil in place.'],
  'You work as a customer services team leader at an insurance company, and your role involves long periods sitting at a desk. You don''t smoke and don''t drink alcohol. You live with your husband and two children. You eat healthily and keep reasonably active. You are not under any particular stress at the moment.',
  'You think your headaches might be migraines rather than tension-type headaches.',
  'You are worried it could be something more serious, as the headaches have been going on for so long without resolving.',
  'Your husband thinks you should be referred for a head scan or to see a specialist about it.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario.',
  ARRAY['Ask about the location, onset, character, frequency, and duration of the headaches, and whether the pain radiates','Ask about relieving and aggravating factors','Ask about associated symptoms, including nausea, vomiting, blurred vision, lacrimation, nasal congestion, aura, photophobia, and neck pain','Ask about trauma to the head or neck','Screen for red flag symptoms, including rash, fever, neck stiffness, slurred speech, weakness or paraesthesia in any part of the body, and unintentional weight loss','Ask about features of raised intracranial pressure, such as early morning headaches, vomiting, or headache worsened by coughing or straining','Ask about analgesic use and frequency to exclude medication overuse headache (if she takes ibuprofen on 15 or more days per month, or codeine or triptans on 10 or more days per month, consider medication overuse headache)','Ask how the symptoms have affected daily functioning and quality of life','Ask about mood and sleep','Ask about social history, including smoking, alcohol intake, illicit drug use, occupation, stress, caffeine intake, and hydration','Explore the patient''s ideas, concerns, and expectations','Make a diagnosis of chronic tension-type headache coexisting with a cervicogenic headache'],
  ARRAY['No need for a face-to-face review at present, as she has already been examined and red flag features have been excluded','Offer a headache diary to help monitor triggers, frequency, severity, and response to treatment','Offer amitriptyline 10 mg at night as preventive treatment, given the chronic nature of her headaches and the risk of medication overuse headache','Explain the risk of medication overuse headache and advise limiting simple analgesia for acute attacks to fewer than 15 days per month','Reassure her that brain imaging is not routinely indicated in the absence of red flag symptoms or abnormal neurological findings','Advise optimising posture and workplace ergonomics, including regular breaks from prolonged sitting and screen use','Offer a referral to physiotherapy to help improve neck range of motion, strength, and posture','Provide clear safety-net advice to seek urgent medical review if she develops new neurological symptoms, a sudden severe headache, visual disturbance, or systemic symptoms','Arrange follow-up in 4 to 6 weeks to review symptom control and response to treatment'],
  'Thank you for calling back, and I''m sorry to hear the headaches haven''t improved — that must be really frustrating, especially when you were hoping to see some progress. Let me try to explain what I think is going on and what we can do about it.

Based on everything you''ve described, Helen, I believe you''re experiencing what we call chronic tension-type headache, which is a headache that has been present on most days for more than three months. This fits with the tight band sensation across the front of your head and the fact that it tends to be there almost daily. Alongside this, the fact that the pain is worse when you tilt your head back suggests there may also be a component coming from the neck — something called cervicogenic headache, where tension or stiffness in the neck structures contributes to the head pain. Given that you spend long periods sitting at a desk, this is quite a common finding.

I understand your husband feels a brain scan would be reassuring, and I want to explain why we don''t routinely recommend one in your situation. You''ve already been examined thoroughly, your neurological examination was completely normal, and there were no red flag features to suggest anything more serious. Guidelines are clear that brain imaging isn''t indicated when the examination is normal and there are no concerning features — and in fact it can sometimes cause unnecessary worry if it picks up things that turn out to be entirely harmless. I do want to reassure you that there is nothing in what you''ve told me that suggests something sinister.

What I''d like to do is start a preventive medication called amitriptyline at a low dose of 10 mg taken at night. This is used specifically to reduce the frequency and severity of tension-type headaches — it''s different from using a painkiller each time a headache comes on. It tends to build up its effect gradually over several weeks, so please don''t be disheartened if you don''t notice a difference straight away.

One thing I''d also like to flag is the risk of something called medication overuse headache. If painkillers like ibuprofen are taken on 15 or more days per month, they can paradoxically make headaches worse over time. You''re currently well within that threshold, which is reassuring, but it''s worth keeping in mind as we go forward.

I''d also like to refer you to physiotherapy, as a physiotherapist can work on your neck posture, range of movement, and muscle tension — all of which can make a real difference to cervicogenic headaches. In the meantime, it would be worth making sure you''re taking regular breaks from your desk and being mindful of your posture, particularly how you hold your head when looking at a screen.

It would also be helpful to keep a headache diary — just a simple note each day of whether you had a headache, how bad it was, what you took for it, and anything that seemed to trigger or relieve it. This will help us see whether the amitriptyline is working and identify any patterns.

Please do get in touch urgently if you develop any new symptoms, such as sudden severe headache, changes to your vision, weakness or numbness, difficulty speaking, or a headache accompanied by fever or neck stiffness. Otherwise, let''s plan to speak again in four to six weeks to see how you''re getting on.',
  ARRAY['Chronic tension-type headache is diagnosed when headache is present on 15 or more days per month for more than three months — amitriptyline 10 mg at night is appropriate first-line preventive treatment.','Cervicogenic headache should be considered when head pain is aggravated by neck movements or posture; physiotherapy referral is a key management step.','Medication overuse headache occurs when simple analgesia (e.g. ibuprofen) is used on 15 or more days per month, or triptans/codeine on 10 or more days per month — always assess analgesic frequency.','Brain imaging is not routinely indicated for chronic headache in the absence of red flag features or abnormal neurological findings — providing this explanation clearly helps manage patient expectations.','A headache diary is a useful tool to track triggers, frequency, and treatment response, and should be offered alongside any new preventive therapy.','Safety-netting must include advice to seek urgent review for sudden severe headache, new neurological symptoms, visual disturbance, or systemic features such as fever or neck stiffness.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  225,
  'Young Adult with Intermittent Chest Tightness',
  'Cardiology',
  'Telephone Consultation',
  false,
  'Ryan Saunders',
  '19-year-old male',
  ARRAY['None Recorded'],
  ARRAY['Not currently on any medication','No Known Drug Allergy'],
  NULL,
  'Patient booked a routine telephone consultation to discuss recurring episodes of chest tightness.',
  '"Hi doctor, I''ve been getting this tightness in my chest and I''m not sure if it''s asthma or whether I could be having a heart attack."',
  'It''s been happening on and off for the past three to four months. The episodes come on randomly — sometimes when I''m revising, sometimes when I''m just lying in bed, or even when I''m out with mates. The most recent one happened last night while I was watching something on TV and it lasted about 25 minutes before going away on its own. A guy at work who''s about 45 said it sounds like a heart attack because he had something similar. Another colleague my age thought it might be asthma. I honestly don''t know what to think.',
  ARRAY['Each episode usually lasts somewhere between 15 and 25 minutes. If you hold your breath or take a really deep breath, the tightness tends to ease off or disappear altogether.','You don''t have any chest pain or shortness of breath as such. Occasionally there''s a racing heartbeat that comes with it.','You''re under a lot of pressure at the moment — you''re working shifts while also revising for your A-levels. You often stay up late and barely sleep because you rely on energy drinks and strong coffee to keep going.','You''re working to help your mum cover the bills at home. Your parents separated recently and your dad has moved out, leaving you and your mum to manage on your own.'],
  'You don''t smoke, drink alcohol, or take any drugs. You work as a barista at a coffee shop and live with your mum.',
  'You think it might be asthma or possibly a heart attack, based on what your colleagues have suggested.',
  'You''re worried about both possibilities because of what the people at work told you.',
  'You''d like the GP to give you some medication to make the episodes stop. If the doctor asks you to come in for an appointment, explain that you can''t miss work today but you''re free tomorrow.',
  ARRAY['If the GP asks you to attend for an in-person review: Decline and explain that you cannot miss work today, but you are happy to attend tomorrow.'],
  NULL,
  'Say NO to any questions outside of the details already provided in this scenario.',
  ARRAY['Ask about the onset, duration, frequency, and pattern of chest tightness','Ask about whether the symptoms are intermittent or constant, and if intermittent, how long each episode lasts','Ask about triggers and relieving factors','Ask about whether symptoms are improving, worsening, or unchanged','Ask about cardiac-associated symptoms, including chest pain, shortness of breath, palpitations, dizziness, or syncope','Ask about respiratory symptoms, including cough, wheeze, nocturnal symptoms, exercise-induced symptoms, or recent viral illness','Ask about panic or anxiety features, including sweating, trembling, fear of dying, tingling around the lips, and nausea','Ask about mood and sleep','Ask about family history of sudden cardiac death or heart disease','Ask about social and lifestyle factors, including recent stress, caffeine or energy drink consumption, smoking, alcohol intake, illicit drug use, and occupation','Ask about the impact of symptoms on his daily activities','Explore the patient''s ideas, concerns, and expectations','Make a diagnosis of possible anxiety-related episodes or panic attacks'],
  ARRAY['Offer a face-to-face review for cardiovascular and respiratory examination','Offer an ECG and baseline blood tests to exclude other abnormalities and provide reassurance','Advise reducing caffeine and energy drink intake, as these can contribute to chest tightness and palpitations','Advise establishing regular sleeping patterns and good sleep hygiene','Discuss stress-relief strategies, including regular physical activity, relaxation and breathing techniques, yoga, and talking therapies','Discuss ways to balance A-level preparation with work commitments, including taking regular breaks and setting realistic study schedules','Offer referral to talking therapies to help manage anxiety-related symptoms','Provide clear safety-net advice to seek urgent medical attention if he develops chest pain, persistent shortness of breath, collapse, or worsening symptoms — advise contacting the urgent GP line, NHS 111 if out of hours, or 999 if symptoms are severe','Arrange follow-up in four weeks to review progress and symptom improvement'],
  'Thank you for getting in touch — those kinds of episodes must be quite alarming, especially when people around you start suggesting it could be your heart. I want to reassure you that based on everything you''ve described, this doesn''t sound like a heart attack or asthma. Let me explain what I think is actually happening.

The pattern you''re describing — chest tightness that comes on randomly, lasts 15 to 25 minutes, often at rest, and gets better when you take a deep breath or hold your breath — is actually very typical of anxiety-related episodes, sometimes called panic attacks. This might not be what you expected to hear, but I want to be clear that panic attacks are a real physical experience. They can cause genuine tightness in the chest, a racing heart, and real discomfort. They''re not imagined, and they don''t mean there''s something wrong with your heart.

Ryan, I can also hear how much pressure you''re under right now. Working shifts while revising for your A-levels, staying up late on energy drinks, and taking on responsibility at home after a really difficult change in your family situation — that''s a lot to carry. High levels of stress and sleep deprivation are well-known triggers for anxiety symptoms and palpitations. Caffeine and energy drinks specifically can make chest tightness and a racing heart much more likely, so cutting back on those is one of the most practical things you can do right now.

I would like to see you in person tomorrow as you suggested, so I can listen to your heart and lungs, check your breathing, and arrange an ECG and some blood tests. The ECG records the electrical activity of your heart and will help us make sure everything is fine structurally. This isn''t because I''m worried — it''s good practice to check these things, and the results will also give you peace of mind.

In the meantime, it''s worth trying some simple breathing techniques when episodes come on — slow, controlled breaths in through the nose and out through the mouth can help your nervous system calm down quite quickly. Regular physical activity, even just going for a walk, can also make a meaningful difference to anxiety over time.

I''d also like to refer you to a talking therapies service — this is a free NHS service where you can speak to someone trained in helping people manage stress and anxiety. Many people find it makes a real difference, and it doesn''t mean anything is seriously wrong with you mentally.

Please do seek urgent help if you develop true chest pain (not just tightness), you feel like you might faint or collapse, you can''t catch your breath, or symptoms become much more frequent or severe. In that case, call 999 rather than waiting. Otherwise, I''ll look forward to seeing you tomorrow and we''ll take it from there.',
  ARRAY['Panic attacks and anxiety-related chest tightness are common in young adults under significant psychosocial stress — always explore mood, sleep, and life stressors in unexplained chest symptoms.','Key features favouring anxiety over cardiac or respiratory cause include: episodic nature at rest, relief with breath-holding or deep breathing, and absence of exertional symptoms, wheeze, or cough.','High caffeine and energy drink intake is a modifiable trigger for palpitations and chest tightness — dietary advice should form part of the management plan.','Despite a likely functional cause, an ECG and baseline blood tests should be offered to exclude structural abnormality and provide patient reassurance.','Referral to NHS talking therapies (e.g. IAPT) is appropriate for anxiety-related symptoms and should be offered alongside lifestyle advice.','Safety-netting must clearly distinguish between seeking urgent help for true chest pain, syncope, or collapse versus routine follow-up for ongoing episodic tightness.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  226,
  'Tiredness in a Young Adult Male',
  'Gastroenterology & Haematology',
  'Video Consultation',
  false,
  'Lucas Adeyemi',
  '21-year-old male',
  ARRAY['None Recorded'],
  ARRAY['Not currently on any regular medication','No Known Drug Allergy'],
  NULL,
  'Patient booked a routine video consultation to discuss ongoing tiredness.',
  'Hi doctor, I''ve been feeling exhausted all the time and it''s been going on for about six to seven months now.',
  'I''ve been feeling worn out constantly for the past six or seven months. I''m not really sure what''s causing it. My mum kept telling me to get it checked out, so here I am.',
  ARRAY['You changed your diet about a year ago and now follow a vegan diet. You mainly eat rice, pasta, and leafy green vegetables. You chose this lifestyle because you believe in animal rights and feel strongly that animals should not be harmed or exploited.','You sometimes get cramping in your stomach and episodes of loose stools. The diarrhoea can last for about a week before settling, and this has been happening on and off for the past six to seven months. There is no blood or mucus in your stools. You have not lost weight and your appetite is fine. You also notice some bloating from time to time. You have no other symptoms.','Your sleep, mood, and appetite are generally good.','You are a second-year university student studying sports coaching and hope to work in professional football development.','The tiredness is manageable most of the time but occasionally stops you from attending your football training sessions, although you are mostly coping.'],
  'You don''t smoke, drink alcohol, or use drugs. You live with your parents. There is no family history of bowel problems that you know of. Things at university are going well overall.',
  'You''re not entirely sure what''s causing your tiredness.',
  'You don''t have any particular worries about it.',
  'You''d like the GP to find out what is causing the tiredness.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario.',
  ARRAY['Ask what the patient means by feeling tired all the time, whether it is physical tiredness, mental tiredness, or both','Ask how long it has been ongoing and whether it started gradually or suddenly','Ask if there is anything that makes the tiredness better or worse, for example whether it improves with rest or worsens with minimal activity','Ask about mood, sleep, and appetite to screen for psychological causes','Ask about symptoms of obstructive sleep apnoea, including snoring, witnessed apnoeic episodes, waking up gasping for breath, and daytime sleepiness','Ask about any recent flu-like illness or infection','Explore dietary history to assess for poor nutritional intake or vitamin deficiencies such as vitamin B12, folate, and iron','Ask about symptoms suggestive of vitamin deficiency, particularly in the context of a vegan diet, including poor concentration, tingling, numbness, or glossitis','Ask about gastrointestinal symptoms including abdominal pain, change in bowel habits such as diarrhoea, and any blood in the stool','Ask about endocrine causes including diabetes with polyuria and polydipsia, and thyroid disease with heat or cold intolerance and palpitations','Screen for red flag symptoms of malignancy or tuberculosis, including weight loss, night sweats, new lumps or masses, or a persistent cough, especially if from or born in a TB endemic area','Ask how the symptoms have affected the patient''s daily life, studies, and functioning','Explore social history including smoking, alcohol intake, illicit drug use, and any recent stressors','Ask about family history of medical conditions, particularly bowel conditions such as coeliac disease','Explore the patient''s ideas, concerns, and expectations','Make a diagnosis of possible nutritional deficiency (vitamin B12 or folate) in the context of a vegan diet, or coeliac disease or inflammatory bowel disease, given intermittent diarrhoea episodes'],
  ARRAY['Offer a face-to-face examination to assess for lymphadenopathy and perform an abdominal examination','Offer blood tests including vitamin B12, folate, ferritin, vitamin D, coeliac screen, thyroid function tests, full blood count, CRP, HbA1c, liver function tests, and faecal calprotectin','Advise the patient that if any vitamin deficiency is confirmed, this will be treated with appropriate replacement, and if coeliac disease is suspected, he will be referred to a specialist for confirmatory testing. Explain that management of coeliac disease involves a gluten-free diet','Advise that in the meantime, he can optimise his vegan diet to ensure adequate intake of essential nutrients, particularly vitamin B12. Suggest options such as breakfast cereals fortified with vitamin B12, unsweetened soya drinks fortified with vitamin B12, yeast extract such as Marmite, and nutritional yeast flakes. Offer to send him written information','Advise that for his tiredness, he can keep a symptom diary to understand his energy levels, pace his activities, prioritise tasks, and plan rest periods to conserve energy','Offer follow-up to review his results once available','Provide safety netting that, although not expected, if he develops worsening symptoms or new symptoms such as tingling in his arms or legs, blurred vision, or confusion, he should seek urgent medical advice by contacting the GP surgery urgently or NHS 111 if out of hours, as this may indicate significant vitamin deficiency affecting the nerves'],
  'Thank you for coming along today, and well done for getting this looked into — six to seven months is quite a long time to be feeling this drained and it absolutely warrants investigation. Let me share my thoughts on what might be causing it.

The most likely explanation, particularly given that you switched to a vegan diet about a year ago and the tiredness started around that time, is a nutritional deficiency. The nutrient I''m most focused on is vitamin B12. Vitamin B12 is found almost exclusively in animal products — meat, fish, dairy, and eggs — so people following a fully vegan diet are at real risk of becoming deficient over time unless they actively replace it. B12 is essential for producing red blood cells and keeping the nervous system working properly, so when levels fall, fatigue is one of the first things people notice.

Folate, iron, and vitamin D are other nutrients worth checking too, as they can all cause tiredness if they''re running low. Alongside this, I''d also like to check your thyroid function and run a screen for coeliac disease, because the episodes of diarrhoea and bloating you''ve been having could point towards coeliac disease or possibly inflammatory bowel disease — both of which can contribute to tiredness through poor absorption of nutrients.

I''d like to bring you in for a face-to-face appointment so I can examine your tummy and check your glands, and at the same visit we can take some blood and arrange a stool test called faecal calprotectin, which helps us look for inflammation in the bowel.

While we''re waiting for those results, there are some practical things you can do straight away to improve your nutrient intake on a vegan diet. Fortified breakfast cereals, unsweetened soya milk, yeast extract like Marmite, and nutritional yeast flakes are all good sources of B12 that don''t involve animal products. I''ll send you some written information about this that you can refer back to.

For the tiredness itself, keeping a simple energy diary — noting when you feel most fatigued and what you''ve been doing — can help you manage your day better. Pacing your activities, prioritising the most important things, and building in rest periods can all help you stay on top of your studies and training while we get to the bottom of what''s going on.

Once the results are back, we''ll go through them together and decide on the next steps. If a vitamin deficiency is found, we''ll start replacement treatment. If coeliac disease is suspected, I''ll refer you to a specialist who can confirm it and advise on a gluten-free diet.

Please do get in touch urgently if you develop any new symptoms, particularly tingling or numbness in your hands or feet, blurred vision, or confusion — these can occasionally be signs of more significant B12 deficiency affecting the nervous system and would need prompt attention. Otherwise, let''s get those tests done and speak again once we have the results.',
  ARRAY['Vitamin B12 deficiency is a common cause of fatigue in individuals following a vegan diet and should be specifically screened for, alongside folate, ferritin, and vitamin D.','A comprehensive blood panel for unexplained fatigue should include vitamin B12, folate, ferritin, vitamin D, coeliac screen, thyroid function tests, full blood count, CRP, HbA1c, and liver function tests.','Coeliac disease and inflammatory bowel disease should be considered in young adults with fatigue alongside intermittent diarrhoea and bloating — faecal calprotectin is a useful non-invasive screening tool.','Dietary advice for vegan patients low in B12 should include fortified cereals, soya milk, yeast extract (e.g. Marmite), and nutritional yeast flakes as practical plant-based sources.','If coeliac disease is confirmed on specialist testing, a strict gluten-free diet is the cornerstone of management.','Safety-netting for suspected vitamin B12 deficiency should specifically include tingling or numbness in the limbs, blurred vision, or confusion as indicators requiring urgent review.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  227,
  'Medication Safety Concern in a Post-MI Patient',
  'Cardiology',
  'Telephone Consultation',
  false,
  'Rajiv Mehta',
  '64-year-old male',
  ARRAY['Myocardial infarction (6 months ago)'],
  ARRAY['Aspirin 75 mg once daily','Ticagrelor 90 mg twice daily','Atorvastatin 80 mg once daily','Ramipril 5 mg once daily','Bisoprolol 5 mg once daily','Lansoprazole 30 mg once daily','No Known Drug Allergy'],
  'Cardiology Letter – 6 months ago Re: Rajiv Mehta, 64-year-old male Dear GP, Mr Rajiv Mehta was admitted to our unit with an acute ST-elevation myocardial infarction. He underwent successful primary percutaneous coronary intervention with stenting to the proximal left anterior descending artery. Echocardiography demonstrated a left ventricular ejection fraction of 55% with mild anterior wall hypokinesia. He was commenced on secondary prevention therapy including Aspirin 75 mg once daily, Ticagrelor 90 mg twice daily for 12 months, Atorvastatin 80 mg at night, Bisoprolol 5 mg once daily, Ramipril 5 mg once daily, and Lansoprazole 30 mg once daily. He was referred to a cardiac rehabilitation programme and provided with lifestyle advice. Please arrange monitoring of blood pressure, renal function, and lipid profile in 4 to 6 weeks. We will review him in clinic in 6 to 8 weeks. Yours sincerely, Dr Alexander Harrington, MBBS, MRCP (UK), FRCP Consultant Cardiologist Seen by Dr Chika Eze (Clinical Practitioner Role) – 3 weeks ago Presenting complaint: One week history of palpitations. Palpitations were described as regular. No red flag symptoms including syncope, dizziness, chest pain, shortness of breath, or exertional symptoms. Examination: Blood pressure 130/70 mmHg, Pulse 67 bpm, SpO2 99% on air, Temperature 36.5°C, RR 18cpm Heart sounds: S1, S2, no added sounds. Chest clear. ECG showed sinus rhythm with no abnormalities. Plan: 3-day Holter monitor arranged and referral to cardiology due to recent myocardial infarction. Safety netting advice given. Cardiology Letter – 2 days ago Dear GP, Thank you for referring Mr Rajiv Mehta, who presented with a four-week history of palpitations. I reviewed him in the cardiology clinic. His ECG and 3-day Holter monitoring demonstrated ventricular ectopic beats and two short runs of non-sustained ventricular tachycardia. Echocardiography showed no evidence of structural heart disease, with a preserved ejection fraction of 55%. I have explained the diagnosis to him and commenced Verapamil 40 mg three times daily. I will review him again in six weeks to assess his symptom response. In the meantime, please continue Verapamil 40 mg three times daily on repeat prescription. Please do not hesitate to contact me if his symptoms worsen or if you have any concerns. Yours sincerely, Dr Patrick Hughes MBChB, FRCP Consultant Cardiologist',
  'Patient booked an urgent telephone consultation after the pharmacist declined to dispense a newly prescribed medication.',
  'Hi doctor, the pharmacist wouldn''t give me the new tablets the heart specialist prescribed. She said I needed to speak to you first.',
  'I''d been having these palpitations so I saw a GP, who sent me on to the heart specialist. The specialist did some tests on my heart and started me on a new tablet to help with the palpitations. I''m still getting them — they happen roughly every two to three days — but they haven''t got any worse. I don''t have any other symptoms.',
  ARRAY[]::text[],
  'You don''t smoke or drink alcohol. You live with your wife. You run a small catering business and own a restaurant. You look after your diet and try to stay active.',
  'You''re not sure why the pharmacist refused to give you the medication.',
  'You''re worried that the medication might be important for your heart and that not having it could put you at risk.',
  'You''d like the GP to explain why you can''t have the medication and what will happen next.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario.',
  ARRAY['Start by acknowledging that you can see the patient has recently seen a cardiologist for palpitations and ask him to explain in his own words what has happened','Ask about current palpitations, including whether he is still experiencing them and whether they have worsened, improved, or remained the same','Ask about associated symptoms including syncope, dizziness, shortness of breath, chest pain, and exertional symptoms','Ask whether he is still taking all his current medications, particularly bisoprolol','Ask how the symptoms have affected his daily life','Explore social history including smoking, alcohol intake, diet, and exercise level','Ask about family history of heart disease or sudden cardiac death','Ask whether the pharmacist explained why the medication was not dispensed','Recognise a potential drug interaction between verapamil and bisoprolol, which may increase the risk of bradycardia and heart block'],
  ARRAY['Explain that verapamil and bisoprolol should generally not be taken together as they can both slow the heart rate and may increase the risk of bradycardia or heart block, which can be dangerous','Explain that this may be a prescribing oversight; however, you do not have enough information at this stage to determine why it was prescribed in this way, and you will clarify this with the cardiology team','Offer to contact the cardiology team to inform them about possible concerns and interaction between verapamil and bisoprolol and to seek further advice','Advise the patient to continue his current medications, including bisoprolol, until further specialist advice is obtained','If the patient wishes to make a complaint, advise that this can be done through the hospital Patient Advice and Liaison Service (PALS), as the issue relates to secondary care. The complaint can be made by writing (sending an email or letter), or raising it verbally','Offer to follow up with the patient once you have heard back from the cardiology team','Provide safety netting that if he develops worsening palpitations, chest pain, shortness of breath, dizziness, or syncope, he should seek urgent medical attention by calling 999'],
  'Thank you for calling in — I''m glad the pharmacist asked you to get in touch, and I want to explain exactly what has happened and why. This is something I can help to sort out for you.

I''ve looked through your notes and I can see that following your heart attack six months ago, you were started on several important medications including bisoprolol, which is a tablet that helps to control your heart rate and protect your heart. You''ve also recently been seen by the cardiologist for palpitations, and he has prescribed you a new medication called verapamil to help with that.

The reason the pharmacist was concerned — and rightly so — is that verapamil and bisoprolol both slow the heart rate down, and taking them together can sometimes slow the heart too much, leading to a condition called bradycardia or even heart block, where the electrical signals in the heart are disrupted. This combination is generally something we avoid in cardiology because of that risk.

I want to be clear that I''m not suggesting the cardiologist made a mistake — there may be a clinical reason for this prescription that I''m not fully aware of, or it may be an oversight that simply needs reviewing. Either way, I don''t think it''s right to start the verapamil without checking with the cardiology team first. I will contact them directly today to explain the situation and ask for their guidance on how best to proceed.

In the meantime, please continue taking all your existing medications as normal, including the bisoprolol. Do not stop any of your current tablets. I know it may be frustrating not to have the new medication yet, but it''s important we get specialist advice before adding it.

I will follow up with you once I''ve spoken to the cardiology team and we''ll work out the safest next step together. If at any point before then you feel your palpitations have worsened significantly, or you experience chest pain, shortness of breath, dizziness, or feel like you might faint, please call 999 straight away rather than waiting.

If you feel this situation has caused you distress and you would like to raise it formally, you have every right to do so. You can contact the hospital''s Patient Advice and Liaison Service — known as PALS — either by phone, email, or in writing. They are there to help with exactly these kinds of concerns relating to hospital care.',
  ARRAY['Verapamil and bisoprolol should not generally be prescribed together due to the risk of additive bradycardia and heart block — this is a recognised drug interaction that must be identified in patients on beta-blockers.','When a potential prescribing error is identified from a secondary care letter, the GP should contact the specialist team directly to clarify and seek advice, rather than acting unilaterally.','Advise the patient to continue all existing medications, including bisoprolol, until specialist clarification is received — do not stop medications without guidance.','Patients who wish to raise a concern about secondary care prescribing should be directed to the hospital Patient Advice and Liaison Service (PALS), which accepts complaints verbally, by email, or in writing.','Safety-netting in post-MI patients with arrhythmia concerns should cover worsening palpitations, chest pain, shortness of breath, dizziness, and syncope as indications for immediate 999 call.','Pharmacists play an important safety role in identifying drug interactions at the point of dispensing — the GP should acknowledge and act on their concern rather than override it.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  228,
  'Medication-Induced Urinary Symptoms',
  'Neurology',
  'Video Consultation',
  false,
  'George Hartmann',
  '72-year-old male',
  ARRAY['Migraine','Hypertension','Asthma'],
  ARRAY['Symbicort 200/6 Turbohaler, one puff twice daily and one puff as required for symptom relief','Amlodipine 10 mg once daily','Amitriptyline 25 mg at night','No Known Drug Allergy'],
  'Letter from Neurology – 6 weeks ago Dear GP, Re: George Hartmann | 72-year-old male Thank you for referring this patient to the neurology clinic for assessment of recurrent headaches. He describes a history consistent with migraine. An MRI scan of the brain has been performed and is normal, with no evidence of intracranial pathology. He was previously treated with pizotifen 1.5 mg once daily, which was initially effective but has since lost its benefit. This has now been discontinued. We have commenced amitriptyline 25 mg at night as prophylaxis. This dose can be gradually increased, if required and tolerated, up to 75 mg at night to achieve optimal symptom control. We have advised on lifestyle measures and trigger avoidance, including maintaining regular sleep, adequate hydration, and reducing stress where possible. I have now discharged him from the neurology clinic. If his symptoms do not improve or if there are any concerns, please feel free to contact us for further advice. Yours sincerely, Dr David Brown Consultant Neurologist Seen by Dr Clinton Diwe (Clinical Practitioner role) - 1 week ago. Presenting complaint: Patient reports urinary symptoms including hesitancy, nocturia, and frequency. No red flag symptoms reported. Examination: Blood pressure 130/78 mmHg, pulse 68 bpm, temperature 36.5°C, oxygen saturation 98% on air. PR examination: Mildly enlarged prostate. Otherwise normal examination. Urinalysis: Negative for all parameters. Plan: Blood tests sent for PSA and U&Es. Urine sent for culture. Follow up arranged with results. Blood test results: Sodium 140 mmol/L (ref 135–145 mmol/L); Potassium 4.2 mmol/L (ref 3.5–5.0 mmol/L); Urea 5.0 mmol/L (ref 2.5–7.8 mmol/L); Creatinine 80 µmol/L (ref 60–110 µmol/L); eGFR 85 mL/min/1.73m² (ref >90 mL/min/1.73m²); PSA 1.2 ng/mL (ref <4.0 ng/mL age-dependent: 40–49 years <2.5 ng/mL; 50–59 years <3.5 ng/mL; 60–69 years <4.5 ng/mL; 70–79 years <6.5 ng/mL). Urine Culture Report: Specimen: Midstream urine. Microscopy: Culture: No significant growth. Bacterial count below the laboratory threshold for urinary tract infection (<10³ CFU/mL).',
  'Patient booked a video consultation to discuss his blood test and urine results.',
  'Hi doctor, I''d like to go over my blood test and urine results if that''s all right.',
  'Those tests were done because I''ve been having trouble with my waterworks. I''m going to the toilet much more often than usual, particularly in the night, and when I try to start it takes a while to get going — sometimes I have to stand there for a minute before anything happens. It''s started to affect my life a fair bit. I don''t go out in the evenings as much anymore and I''ve stopped meeting my friends for a drink because I''m constantly needing the toilet. My friends have begun asking questions about why I keep disappearing to the bathroom, and I find it quite embarrassing. And waking up several times a night is exhausting.',
  ARRAY['You have noticed that these symptoms started after you began taking amitriptyline. The medication has helped with your headaches, but shortly afterwards you started having these problems with passing urine.'],
  'You don''t smoke or drink alcohol. You are a retired bus driver. You live with your wife. You enjoy playing bowls and meeting friends at the social club most days.',
  'You''re not entirely sure what''s causing the symptoms, but you have a feeling it might be connected to the new medication, amitriptyline.',
  'It''s affecting your day-to-day life — you''ve been avoiding evenings out with friends because of the toilet problems.',
  'You''d like the doctor to help you sort out these urinary symptoms.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario.',
  ARRAY['Start by acknowledging that you can see he was reviewed for urinary symptoms and was sent for blood and urine tests','Ask him to describe the symptoms that led to these investigations','Ask about the onset of symptoms','Ask about other lower urinary tract symptoms including urgency, straining, intermittency, terminal dribbling (dribbling after passing urine), feeling of incomplete bladder emptying, and poor stream','Ask about symptoms of urinary retention including inability to pass urine, abdominal pain, or suprapubic discomfort','Ask about bowel symptoms such as constipation, which may worsen urinary symptoms','Ask about red flag symptoms for prostate cancer including new onset back pain, bone pain, haematuria, weight loss, and night sweats','Ask about family history of prostate cancer','Ask whether the symptoms started after initiating amitriptyline and whether the medication has helped his headaches','Ask how the symptoms have affected his daily life and mood','Ask about social history including smoking, alcohol intake, occupation, and home situation','Ask about intake of caffeine or caffeinated drinks','Explore the patient''s ideas, concerns, and expectations','Make a diagnosis of amitriptyline-induced urinary symptoms'],
  ARRAY['Explain to the patient that amitriptyline is the most likely cause of his urinary symptoms due to its side effects','Offer options including reducing the dose of amitriptyline to 10 mg. Explain that urinary symptoms may still persist, and his headache control may be less effective. However, it is a reasonable option to try','Alternatively, offer switching to another migraine prophylaxis such as topiramate 25 mg once daily, with gradual dose increase if needed, or candesartan 16 mg once daily. Please note that candesartan (an angiotensin receptor blocker — ARB) should not be offered in patients who are already taking an angiotensin converting enzyme (ACE) inhibitor, as ACE inhibitors and ARBs should not be used together','Inform the patient about potential side effects. Topiramate can cause gastrointestinal upset and increase the risk of kidney stones, so advise maintaining good fluid intake. Candesartan can cause dizziness and cough','Arrange follow-up in 4 weeks to assess both migraine control and whether urinary symptoms have improved','Provide safety netting that if urinary symptoms persist, worsen, or if he develops weight loss, haematuria, or new back pain, he should seek medical advice promptly. Advise seeking earlier review if his migraine symptoms worsen'],
  'Thank you for joining me today, and let''s go through those results together and talk about what I think is going on with your waterworks. I want to reassure you first that the results are largely very encouraging. Your kidney function tests are all within normal limits, there are no signs of infection in the urine, and most importantly, your PSA level — which is the prostate blood test — came back at 1.2, which is well within the expected range for a man of your age. So there is nothing in these results to suggest prostate cancer or a urinary infection.

The mild enlargement of the prostate that was found on examination is extremely common in men in their seventies and, given the normal PSA result, is not something we need to be concerned about at this stage.

So if it''s not an infection and the prostate isn''t the main culprit, what is causing these symptoms? George, based on everything you''ve told me — particularly that the urinary problems started shortly after you began amitriptyline — I think the medication is the most likely explanation. Amitriptyline has what we call anticholinergic effects, which means it can relax the muscles involved in bladder emptying. This can cause exactly the kind of symptoms you''re describing: difficulty starting to pass urine, needing to go more often, and waking up at night. It''s a recognised side effect, and you were right to make that connection.

The good news is that there are options for managing this. One approach would be to lower the dose of amitriptyline from 25 mg down to 10 mg at night. This might reduce the urinary side effects, though they may not disappear completely, and there is a chance your headache control won''t be quite as effective at the lower dose. It''s still a reasonable option to try first.

If you''d rather move away from amitriptyline altogether, there are two alternatives worth considering for migraine prevention. The first is topiramate, starting at 25 mg once daily and gradually increasing the dose if needed. The main things to be aware of with topiramate are that it can sometimes cause an upset stomach and it slightly increases the risk of kidney stones, so it''s important to drink plenty of water. The second option is candesartan 16 mg once daily. This is a blood pressure tablet that also happens to be effective for migraine prevention. However, I should mention that candesartan cannot be used alongside ACE inhibitors — that''s a group of blood pressure tablets ending in "pril" — so we''d need to check whether any of your current medications fall into that category before prescribing it.

I''d like to give you a moment to take that in and think about which approach feels right for you. There''s no single perfect answer here — it''s a balance between headache control and managing the urinary symptoms, and your preferences matter.

Let''s plan to speak again in four weeks. By then we''ll have a clearer picture of whether any adjustments have made a difference. If the urinary symptoms get worse, you notice any blood in your urine, develop new back or bone pain, or lose weight unexpectedly, please don''t wait for that appointment — get in touch sooner. And if your migraines become significantly worse after any change, come back to us promptly.',
  ARRAY['Amitriptyline has anticholinergic properties that can cause urinary hesitancy, frequency, nocturia, and poor stream — these side effects should be proactively discussed when initiating the drug, particularly in older men.','A mildly enlarged prostate on PR examination with a normal PSA (below 6.5 ng/mL for age 70–79 years) and negative urine culture makes amitriptyline the most likely diagnosis in this context rather than benign prostatic hyperplasia or prostate cancer.','Alternative migraine prophylaxis options when amitriptyline is not tolerated include topiramate 25 mg once daily (titrated upward) and candesartan 16 mg once daily — candesartan is an ARB and must not be co-prescribed with ACE inhibitors.','Topiramate can increase the risk of nephrolithiasis (kidney stones) — advise patients to maintain good fluid intake when starting this medication.','Interpreting PSA results requires age-adjusted reference ranges: the upper limit of normal for men aged 70–79 years is 6.5 ng/mL.','Safety-netting for lower urinary tract symptoms should specifically include haematuria, unexplained weight loss, and new bone or back pain as red flag features warranting prompt reassessment.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  229,
  'Exertional Calf Pain in a Smoker',
  'Cardiology',
  'Video Consultation',
  false,
  'Mark Holloway',
  '58-year-old male',
  ARRAY['None Recorded'],
  ARRAY['Not currently on any regular medication.','No Known Drug Allergy'],
  'Letter from Community Podiatry Service Dear GP, Re: Mark Holloway, 58-year-old male Mark self-referred to our service with a history of cramp-like pain in both calves on walking. An Ankle Brachial Pressure Index (ABPI) assessment was performed using a handheld Doppler and appropriately sized blood pressure cuffs following a period of rest in the supine position. ABPI Results: Doppler Waveform Analysis Findings: Right Lower Limb: Interpretation: Mild to moderate reduction in arterial flow Left Lower Limb: Interpretation: Moderate reduction in arterial flow Mark has been advised to arrange follow up with his GP for further assessment and ongoing management. Yours sincerely, Mr Daniel Mansfield BSc (Hons) Podiatry, HCPC Registered Podiatrist Community Podiatry Service',
  'Patient booked a routine consultation to discuss the results of a leg assessment performed by the podiatrist.',
  'Hi doctor, the podiatrist asked me to come and see you. He mentioned he would be sending you a letter about a test he carried out on my legs.',
  'You have been getting cramping pains in both calves for the past 5 months. The pain comes on after walking for around 15 minutes and settles with rest after about 6 to 10 minutes. This is starting to affect your work as a delivery driver, as you have to stop frequently. You have not noticed any pain at rest or overnight. You have not noticed any ulcers or colour changes in your feet. You have not taken any painkillers as the pain goes away on its own once you stop.',
  ARRAY[]::text[],
  'You smoke 20 cigarettes per day and have done so for 30 years. You do not drink alcohol or use illicit drugs. You work as a delivery driver. You live with your wife.',
  'You are not entirely sure what is causing the pain in your legs.',
  'You are concerned because the pain is affecting your ability to do your job and walk any reasonable distance.',
  'You would like the GP to find a way to stop the pain so you can get back to normal.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario.',
  ARRAY['Acknowledge that you have reviewed the podiatry letter regarding the leg assessment and invite the patient to describe, in his own words, the symptoms he has been experiencing','Ask about the pain, including when it started, its character, and what makes it better or worse','Ask whether the pain affects one leg or both','Ask about the walking distance before pain begins, how long it takes to settle with rest, and whether things have changed over time','Ask about red flag symptoms of acute limb ischaemia, including pain at rest or at night, weakness in the lower limbs, numbness or tingling, a perishingly cold limb, and changes in colour of the limb','Ask about other related symptoms such as non-healing wounds or ulcers on the legs and loss of hair on the legs or feet','Ask about leg swelling or redness to help exclude deep vein thrombosis','Ask about chest pain, breathlessness, and palpitations to screen for coexisting cardiovascular disease, which is common alongside peripheral arterial disease','Ask about the impact of symptoms on daily life and his occupation','Ask about smoking, alcohol use, diet, and lifestyle','Ask about the patient''s ideas, concerns, and expectations','Make a diagnosis of intermittent claudication secondary to peripheral arterial disease, supported by the reduced ABPI values'],
  ARRAY['Explain to the patient that his symptoms and test results point towards peripheral arterial disease, a condition in which narrowing of the arteries reduces blood flow to the legs','Offer blood tests to check for associated conditions, including HbA1c, cholesterol, lipid profile, liver function tests, renal function tests, and full blood count','Advise that his blood pressure will be checked by the healthcare assistant or nurse when his blood tests are taken, to ensure it is not raised','Offer a statin such as atorvastatin 80 mg once daily for cardiovascular risk reduction','Offer antiplatelet therapy such as clopidogrel 75 mg once daily to reduce cardiovascular risk','Offer referral to physiotherapy for a supervised exercise programme, encouraging him to walk to the point of pain, rest, and then continue walking, as this approach helps improve symptoms over time','Advise that stopping smoking is the single most important step to slow the progression of the disease, and offer referral to a smoking cessation service if he is willing','Advise on broader lifestyle changes including a healthy diet, maintaining a healthy weight, and regular physical activity','Offer support in relation to his work, as the condition is affecting his ability to carry out his duties, including providing a fit note with amended duties if appropriate','Give safety-netting advice regarding signs of acute limb ischaemia, including sudden severe pain, pallor, numbness, weakness, or a perishingly cold leg, and advise him to call 999 immediately if any of these occur','Offer follow-up in 4 to 6 weeks to review symptoms and response to treatment'],
  'Thank you for making this appointment today, Mark. I have had a look at the letter from the podiatrist, and I want to go through everything with you so it all makes sense. The test that was done on your legs — called an Ankle Brachial Pressure Index — checks how well blood is flowing through the arteries in your legs. Your results showed a reduced blood flow in both legs, with the left side showing a slightly greater reduction than the right.

What you are describing — cramping pain in both calves that comes on when you walk and settles with rest — fits very well with a condition called peripheral arterial disease, or PAD for short. This happens when the arteries that carry blood to the legs become narrowed, usually because of a build-up of fatty deposits inside the artery walls. When you walk and your muscles need more oxygen, the narrowed arteries cannot deliver enough blood, which causes the cramping. Once you rest, the demand drops and the pain eases.

The good news is that there is quite a lot we can do. To begin with, I would like to arrange some blood tests to check your cholesterol, blood sugar, kidney function, liver function, and a full blood count. We will also check your blood pressure at the same time. Based on the results, I will want to start you on two medications. The first is atorvastatin 80 mg, taken once a day — this is a cholesterol-lowering tablet that also helps to protect the arteries and reduce the risk of heart attack and stroke. The second is clopidogrel 75 mg, taken once a day — this is a blood-thinning tablet that reduces the risk of a clot forming in the narrowed arteries.

I would also like to refer you to physiotherapy for what is called a supervised exercise programme. I know that might sound counterintuitive when walking causes you pain, but the evidence shows that walking to the point of pain, resting, and then carrying on again actually helps improve the circulation over time. Many patients find real benefit from this.

One of the most important things you can do to slow this condition down is to stop smoking. Smoking is a major cause of peripheral arterial disease and continuing to smoke will cause it to worsen more quickly. I can refer you to a smoking cessation service where you will get a lot of practical support to help you quit — would that be something you would be open to?

I also want to make sure you know what to watch out for. If you ever develop sudden severe pain in your leg that does not ease with rest, or if the leg becomes very pale, cold, numb, or weak, that would be an emergency requiring an ambulance — please call 999 straightaway in that situation.

Let us arrange a follow-up in about four to six weeks to see how you are getting on with the blood tests and to check how things are going more generally. Do you have any questions about anything I have covered today?',
  ARRAY['Intermittent claudication caused by peripheral arterial disease presents as reproducible exertional calf pain that is relieved by rest, and is confirmed by a reduced Ankle Brachial Pressure Index on Doppler assessment','All patients with peripheral arterial disease should be offered antiplatelet therapy (clopidogrel 75 mg once daily) and a high-dose statin (atorvastatin 80 mg once daily) for cardiovascular risk reduction','Smoking cessation is the single most important intervention to slow progression of peripheral arterial disease','A supervised exercise programme is first-line treatment for intermittent claudication and has good evidence for improving walking distance and symptoms','Red flag features of acute limb ischaemia — the 6 Ps: pain, pallor, pulselessness, paraesthesia, paralysis, and perishingly cold — require emergency assessment and 999 advice','Baseline investigations should include HbA1c, lipid profile, renal and liver function, full blood count, and blood pressure measurement to identify and manage cardiovascular risk factors'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  230,
  'Diagnosis of COPD Following Spirometry',
  'Respiratory',
  'Video Consultation',
  false,
  'George Whitfield',
  '62-year-old male',
  ARRAY['None Recorded'],
  ARRAY['Not currently on any regular medication.','No Known Drug Allergy'],
  'Accident and Emergency Discharge Summary – 3 weeks ago Patient''s Name: George Whitfield | Age: 62-year-old male Dear GP, George Whitfield attended the Accident and Emergency department with a history of productive cough with yellowish sputum and progressively worsening breathlessness. He has a significant smoking history of approximately 30 cigarettes daily for 30 years. On assessment, he was haemodynamically stable. Clinical examination of the chest revealed widespread wheeze. There were also widespread rhonchi which improved on coughing. A chest X-ray was performed and reported as satisfactory, with no acute abnormalities identified. Based on the clinical presentation, this was treated as a likely lower respiratory tract infection. Treatment Provided: a total of 5 days He was given safety-netting advice and told to seek urgent medical attention if he develops worsening breathlessness, chest pain, haemoptysis, fever, or feels systemically unwell. He has been advised to follow up with his GP for further assessment, including consideration of spirometry. Assessed by: Sarah Hawkins, Emergency Nurse Practitioner. Seen by Julie Hull (Advanced Nurse Practitioner) – 1 week ago Presenting complaint: Patient reports a 3-month history of progressively worsening shortness of breath and cough. Patient is a smoker. Examination: Minimal wheeze on auscultation. BP 135/75 mmHg, Pulse 70 bpm, RR 18 cpm, SpO2 95% on air, Temperature 36.5°C Plan: Referred for in-house spirometry. Added to waiting list for respiratory nurses. Safety-netting advice given. Seen by Debbie Burton (Respiratory Nurse Specialist) – 2 days ago Spirometry Results (Post-Bronchodilator): Parameter Measured Predicted % Predicted FEV₁ 2.40 L 3.20 L 75% FVC 3.70 L 4.30 L 86% FEV₁/FVC 0.65 0.75 — Bronchodilator Reversibility: FEV₁ increase: +100 mL (5%), No significant reversibility. Flow-Volume Loop: Concave expiratory limb demonstrated. Volume-Time Curve: Prolonged expiratory phase. Quality: Test quality good and reproducible. Plan: Patient advised to follow up with GP to discuss results.',
  'Patient booked a routine consultation to discuss the results of a recent breathing test and his ongoing respiratory symptoms.',
  'Hello doctor, I was asked to book this appointment to go over the results of the breathing test I had done for my breathing problems.',
  'You have been getting more and more short of breath over the past 3 months, and it has been gradually worsening.',
  ARRAY['You become breathless doing things like walking 200 to 300 metres, walking quickly, or trying to keep up with your grandchildren, and you often have to stop to catch your breath. You also have a cough that goes on throughout the day. The cough brings up clear sputum and has been present for the same 3 months.','You are not breathless at rest. You do not have chest pain, you are not waking up breathless at night, and you can lie flat without difficulty.','You were treated for a chest infection about 3 weeks ago. You feel better in yourself and the sputum has gone from yellow to clear, but the cough and breathlessness are still there.'],
  'You smoke 30 cigarettes per day and have done so for 30 years. You do not drink alcohol. You live with your wife. Your grandchildren come over every weekend. You are a retired electrician.',
  'You are not sure what is causing your breathing problems.',
  'You are worried because you are finding it harder to spend time with your grandchildren and do the things you used to enjoy.',
  'You would like the GP to explain the test results and help you breathe more easily.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario.',
  ARRAY['Acknowledge that you have reviewed the spirometry results and invite the patient to describe, in his own words, the symptoms he has been experiencing','Ask about the shortness of breath, including when it started, how it has changed over time, and how severe it is','Ask about functional limitations, including how far he can walk and which activities bring on breathlessness','Ask whether he is breathless at rest or only on exertion','Ask about associated respiratory symptoms including cough, sputum production, and wheeze','Ask about features suggestive of heart failure, including breathlessness when lying flat, waking at night feeling breathless, and ankle swelling','Ask about chest pain and palpitations to help exclude angina','Ask about red flag symptoms that might suggest malignancy, including unexplained weight loss, night sweats, and coughing up blood','Ask about previous chest infections and whether he has needed steroids, antibiotics, or hospital admission due to chest problems in the past year, as this helps classify disease severity and guide management','Ask about social history including smoking, alcohol intake, home situation, occupation, diet, and the impact of his condition on daily life','Ask about the patient''s ideas, concerns, and expectations','Make a diagnosis of chronic obstructive pulmonary disease'],
  ARRAY['Offer to start a LAMA and LABA combination inhaler, for example Anoro Ellipta or Ultibro Breezhaler, as the patient is in Group B','Note: Patients who are newly diagnosed are classified into Group A, B, or E based on exacerbation history and breathlessness level. Group A and B patients have 0 or 1 exacerbation per year without hospital admission. Group A patients are not troubled by breathlessness except during strenuous exercise (mMRC scale 0–1), while Group B patients have an mMRC score of 2 or more, meaning they are breathless when hurrying or on minimal exertion. Group E patients have 2 or more exacerbations per year or at least one hospital admission due to COPD or chest infection','Offer a short-acting bronchodilator such as salbutamol with a spacer device for relief of breakthrough breathlessness as required','Advise that stopping smoking is the single most important step to slow the progression of COPD, and offer referral to a smoking cessation service','Offer referral to pulmonary rehabilitation to improve breathlessness, exercise capacity, and quality of life','Offer vaccinations including the annual influenza vaccine and pneumococcal vaccine','Offer baseline blood tests including a full blood count to check for anaemia or polycythaemia','Offer referral to a COPD nurse specialist, who will provide inhaler technique training and help develop a personalised COPD self-management plan','Provide safety-netting advice that if he develops worsening breathlessness, chest pain, haemoptysis, or becomes systemically unwell, he should seek urgent medical attention by contacting the GP or calling NHS 111 if out of hours','Offer follow-up in 4 to 6 weeks to review symptoms, inhaler technique, and response to treatment'],
  'Thank you for coming in today to go through these results, George. I want to make sure everything is explained clearly so you know exactly what is going on and what we are going to do about it.

The breathing test — called spirometry — measures how well your lungs are working by looking at how much air you can breathe out and how quickly. Your results show a pattern where there is an obstruction to airflow, meaning air is not moving in and out of your lungs as freely as it should be. Alongside your symptoms of cough, bringing up phlegm, and worsening breathlessness over the past three months, and your long smoking history, this fits with a diagnosis of chronic obstructive pulmonary disease, which is usually referred to as COPD.

COPD is a condition in which the airways and air sacs in the lungs become damaged over time, usually from years of smoking. This makes it harder to breathe air out fully, which leads to the breathlessness and cough you have been experiencing. The encouraging thing is that we caught this at a stage where we can really make a difference.

To start with, I would like to get you on an inhaler that combines two types of medication in one device — one helps to relax the muscles around the airways to open them up, and the other keeps them open for longer. This type of inhaler, called a LAMA and LABA combination, such as Anoro Ellipta, is the recommended starting treatment for people with your level of symptoms. I will also prescribe a salbutamol inhaler — a blue reliever — which you can use if you feel breathless between your regular doses.

I would also like to refer you to a specialist respiratory nurse who will show you exactly how to use the inhalers correctly and work with you on a personalised self-management plan. In addition, I would like to refer you to pulmonary rehabilitation — this is a group-based programme of guided exercise and education that has very good evidence for helping people with COPD breathe more easily and feel more in control.

I also need to raise the subject of smoking. I appreciate this may be difficult to hear, but stopping smoking is the single most important thing you can do to slow COPD from getting worse. I can refer you to a smoking cessation service where you will get plenty of support — would you be open to exploring that?

We should also make sure you are up to date with your flu jab and pneumococcal vaccine, as chest infections can cause significant setbacks with COPD. I will arrange some blood tests at the same time to make sure there are no other issues contributing to your symptoms.

Please do keep an eye out for any worsening breathlessness, chest pain, or coughing up blood — if any of those occur, please contact us urgently or call NHS 111 if we are closed. Let us plan a review in four to six weeks to see how you are responding to the inhaler and go from there.',
  ARRAY['COPD is confirmed by post-bronchodilator spirometry showing FEV₁/FVC below 0.70 with no significant reversibility (less than 12% or 200 mL improvement); a concave expiratory flow-volume loop and prolonged expiratory phase are characteristic findings','Newly diagnosed COPD patients are classified into Group A, B, or E; Group B patients (mMRC score 2 or more, 0–1 exacerbations per year) should be started on a LAMA plus LABA combination inhaler as first-line treatment','Smoking cessation is the single most effective intervention to slow COPD progression and should be offered to all patients who smoke','Pulmonary rehabilitation improves exercise tolerance, breathlessness, and quality of life in COPD and should be offered as part of initial management','Annual influenza and pneumococcal vaccination are recommended for all patients with COPD to reduce the risk of infective exacerbations','A COPD nurse referral for inhaler technique training and a personalised self-management plan is an important component of ongoing care'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  231,
  'Infected Eczema with Possible Head Lice',
  'Dermatology',
  'Video Consultation',
  false,
  'Chloe Patterson',
  '7-year-old female',
  ARRAY['Eczema (diagnosed aged 6 months)'],
  ARRAY['Topical hydrocortisone cream 1% (acute prescription)','Topical Clobetasone butyrate cream 0.05% (acute prescription)','E45 cream','No Known Drug Allergy'],
  'No significant recent consultations',
  'Patient''s mother, Anna Patterson, is calling to discuss concerns about her daughter''s skin and scalp.',
  'Hello doctor, I think my daughter''s eczema has flared up again and I was hoping to get something a bit stronger to sort it out.',
  'Your daughter has had a flare of eczema on the back of her neck and scalp for the last 3 days. She has been scratching both areas constantly. You have been applying her steroid cream, Eumovate, and E45 cream to her neck, but the rash does not seem to be getting better — if anything it looks worse. You have noticed some yellowish crusting at the back of her neck. You have also seen some white flakes on her scalp when combing her hair. Your ex-husband''s partner noticed your daughter scratching her head, did wet combing, and found a live louse, which she believes she removed.',
  ARRAY['The rash on her neck is dry rather than oozing or bleeding.','She is otherwise well — eating, drinking, and passing urine normally.','There has been no known contact with anyone else known to have head lice or an itchy scalp.'],
  'She lives with you but spends time with her father from time to time. She attends primary school. Pregnancy and Birth History: Unremarkable. Immunisation History: Up to date with all vaccinations. Development: Growing and developing well with no concerns.',
  'You think this might be related to head lice because the symptoms started when she was staying with her father, and his partner spotted a louse during wet combing. You tried wet combing yourself but did not find any lice, though you did notice white flakes on her scalp.',
  'You are worried because her eczema usually improves with steroid cream, but this time the treatment does not seem to be working.',
  'You would like something stronger to clear the rash up.',
  ARRAY['If the doctor asks you to bring her in for a face-to-face appointment: Say that you cannot come in today or tomorrow due to work commitments but could bring her in the following day. If the doctor suggests sending a photograph: Agree to take and send a picture.','If the doctor suggests sending a photograph: Agree to send a photograph.'],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario.',
  ARRAY['Ask about the rash, including when it started, where it is, and whether it is getting better, worse, or staying the same','Ask about the appearance of the rash, including redness, crusting, discharge, oozing, and itching','Ask about associated systemic symptoms such as fever, lethargy, poor oral intake, or reduced urine output','Ask about scalp symptoms, including itching, rash, and whether any lice or eggs have been seen. Note that a live louse must be found to confirm active head lice infestation — an itchy scalp alone is not sufficient to make the diagnosis','Ask whether there has been any known contact with others who have head lice','Ask about previous eczema flares and how often they occur','Ask what treatments have been tried and whether they have helped','Ask about symptoms that might prompt safeguarding considerations, including whether the child appears withdrawn or has any unexplained marks, injuries, or wounds on the body','Ask about the impact of the rash on the child''s sleep and daily activities','Ask about social history, including school attendance and home circumstances','Ask about the parent''s ideas, concerns, and expectations','Make a diagnosis of possible secondary bacterial infection (impetigo) arising from itching secondary to head lice or eczema'],
  ARRAY['Explain to the mother that head lice, on a background of eczema, may have caused increased itching which has broken the skin and allowed bacteria to enter, leading to the yellowish crusting — this is consistent with a secondary skin infection','Offer a face-to-face assessment to examine the scalp and the back of the neck more closely. If this is not possible today, advise sending a clear photograph for review','Advise that if the appearance is consistent with infection, treatment can be started with a topical antiseptic such as hydrogen peroxide 1% cream or a topical antibiotic such as fusidic acid 2%, applied three times daily for 5 days','Advise keeping the child''s nails short and encouraging her not to scratch, to reduce further skin damage and the risk of spreading infection','Advise continued regular use of emollients such as E45 cream multiple times throughout the day to keep the skin moisturised. Advise avoiding topical steroids on the affected infected area as this may worsen the infection','Reassure the mother that as she did not find any lice herself, it is possible that the wet combing performed by her ex-husband''s partner was effective in removing them. However, if she remains concerned, she can repeat wet combing, as it is an effective method for both diagnosing and treating head lice','Advise that the child can generally continue to attend school if the issue is head lice alone. However, as impetigo is suspected, she should remain off school until 48 hours after starting treatment, as it is contagious. Advise that once you have reviewed the photographs, you will provide further guidance on school attendance','Reassure the mother that head lice are not a sign of poor hygiene. They spread through direct head to head contact and can occur in clean hair','Provide safety-netting advice that if the child develops a fever, spreading redness, worsening pain, or becomes systemically unwell, she should seek urgent medical attention by contacting the GP or calling NHS 111 if out of hours'],
  'Thank you for getting in touch today. I can hear how worried you are, and I want to help you make sense of what might be going on with Chloe.

From what you have described — the yellowish crusting at the back of her neck, the fact that the rash is not settling with her usual steroid cream, and the history of a live louse being found during wet combing — it sounds as though there may be two things happening at once. It is possible that head lice caused increased itching, and with Chloe''s sensitive skin and eczema in the background, all that scratching has created small breaks in the skin. Bacteria can then get into those breaks and cause what we call a secondary skin infection, which would explain the yellowish crusting you have noticed. That type of infection is called impetigo.

The reason the steroid cream has not been working as well as usual is actually very important here. Steroid creams help with the eczema itself, but if there is a bacterial infection on top, steroids can sometimes make the infection worse by dampening down the immune response. So I would advise pausing the steroid cream on the affected crusted area for now.

What I would really like to do is have a proper look at her skin. I understand you cannot come in today or tomorrow, so in the meantime, if you could take a clear photograph of the back of her neck and the scalp and send it through to us, that would be really helpful. Once I have seen the picture, I can advise more specifically, but it is very likely that we will want to start a short course of an antibiotic or antiseptic cream — for example, something like hydrogen peroxide 1% cream or fusidic acid 2% cream, applied three times a day for five days.

In the meantime, please keep Chloe''s nails short to discourage scratching, and carry on using the E45 cream regularly across her skin — several times a day if you can. Keeping the skin well moisturised is still really important for managing the eczema.

On the question of head lice — you mentioned that you did wet combing yourself and did not find any lice, which is reassuring. It is possible the louse found by your ex-husband''s partner was the only one and was removed at that point. If you remain concerned, you are very welcome to repeat wet combing at home. It is an effective way of both checking for and removing lice, and does not require any special treatment.

Regarding nursery or school — because impetigo can be spread to other children, she should stay home until 48 hours after starting the antibiotic cream. Once I have reviewed your photographs and confirmed the picture, I will be able to give you clearer guidance on when she can go back.

Finally, please keep an eye out for any signs of the infection spreading — things like a temperature, worsening redness creeping further across the skin, or Chloe seeming generally unwell. If any of that happens, please contact us or call NHS 111 if we are closed.',
  ARRAY['A secondary bacterial infection (impetigo) should be suspected when eczema appears to be worsening despite standard steroid treatment and yellowish crusting is present, particularly if there is a history of scratching','Topical steroids should be avoided on infected skin as they can suppress the immune response and worsen the infection; treat the infection first with a topical antiseptic (hydrogen peroxide 1%) or antibiotic (fusidic acid 2%) three times daily for 5 days','Diagnosing active head lice requires finding a live louse — an itchy scalp or the presence of nits (eggs) alone is not sufficient for diagnosis','Children with suspected impetigo should be excluded from school or nursery until 48 hours after starting antibiotic treatment due to the risk of transmission','Head lice are not related to hygiene standards and spread through direct head to head contact; wet combing is both a diagnostic and treatment method','Regular emollient use is the cornerstone of eczema management and should be continued even during flares, applied multiple times daily'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  232,
  'Paramedic Query on Palpitations Management',
  'Cardiology',
  'Telephone Consultation',
  false,
  'Stuart Barlow',
  '49-year-old male',
  ARRAY['Hearing Impaired'],
  ARRAY['Not currently on any regular medication.','No Known Drug Allergy'],
  'No significant recent notes or consultations. Caller: Michelle Carver (Paramedic), on the phone to speak with you.',
  'Telephone call from a paramedic attending a patient with palpitations, seeking advice on further management.',
  'Good morning doctor, I am calling for some advice regarding Stuart Barlow, a 49-year-old male who I believe is registered at your practice.',
  'You attended a 999 call made by Stuart''s wife. Stuart has been having palpitations on and off for the past three months. Today''s episode felt particularly alarming to him, which is what prompted his wife to call for an ambulance. You are not sure whether he needs to go to Accident and Emergency or whether he can be looked after safely in the community.',
  ARRAY['He occasionally gets a bit short of breath during episodes of palpitations, though this does not happen every time. The palpitations can happen at any time — both at rest and when he is active.','There is no associated chest pain, dizziness, or collapse, and the palpitations are not brought on by exercise.','There is no family history of sudden cardiac death.','Previously he was having around one episode every two to three days. However, he is now having at least one episode every day.','He describes the palpitations as feeling regular. Each episode typically lasts around 10 minutes and then stops on its own, although today''s episode went on for about 15 minutes.','He has recently started a new role as a kitchen manager, which has been very stressful. To cope with the stress he has been drinking up to ten cups of coffee per day.','You have carried out an ECG, which shows normal sinus rhythm with no abnormalities and a rate of 89 beats per minute. His observations are stable: pulse rate 84 bpm, blood pressure 130/70 mmHg, temperature 36.1°C, respiratory rate 18 breaths per minute. You have listened to his chest and there are no murmurs. His chest is otherwise clear.'],
  'Stuart is a non-smoker and does not drink alcohol. He lives with his wife and works as a kitchen manager. He is hearing impaired.',
  'You are not sure what is causing his palpitations.',
  'You are concerned because his episodes are becoming more frequent, and you are not sure whether he needs to go to hospital. This is also Stuart''s own concern, which is why he called for an ambulance.',
  'You would like clear advice from the GP on whether to take him to hospital or manage him at home.',
  ARRAY['If the doctor asks to speak directly to the patient, explain that he is hearing impaired and struggles to communicate over the phone. Say NO to any other questions or symptoms asked outside of the details already provided in the scenario.'],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario.',
  ARRAY['Thank the paramedic for attending the patient and for calling to discuss the case','Ask about the onset and progression of the palpitations, including how frequently they are occurring and whether symptoms are getting worse or staying the same over time','Ask about the character of the palpitations — whether they feel fast, regular, or irregular','Ask about the duration of each episode','Ask about red flag features, including chest pain, shortness of breath, dizziness, syncope, palpitations brought on by exercise, and any family history of sudden cardiac death or cardiac disease','Ask about potential triggers such as stress, anxiety, caffeine intake, or use of energy drinks','Ask about sleep, mood, and any symptoms of anxiety','Ask whether an ECG and a full set of observations have been performed, and request the results','Ask about social history, including smoking, alcohol, recreational drug use, occupation, and home situation','Ask about the paramedic''s ideas, concerns, and expectations, as well as those of the patient','Make a diagnosis of likely benign palpitations related to excessive caffeine intake and work-related stress'],
  ARRAY['Thank the paramedic for the thorough assessment provided','Advise that there are no red flag features to suggest an immediately life-threatening cause, and that hospital conveyance is not required at this stage','Explain that the most likely cause of his palpitations is a combination of excessive caffeine intake and the stress related to his new role','Advise the paramedic to encourage the patient to significantly reduce his caffeine intake, ideally to no more than one to two cups per day, and to avoid energy drinks and other stimulants','Encourage stress management strategies including adequate rest, regular sleep, and relaxation techniques. Advise that he may also wish to speak with his employer to explore whether any reasonable adjustments to his workload are possible','Advise the patient to keep a symptom diary, noting the timing, duration, and any potential triggers of each episode of palpitations','Offer to arrange baseline blood tests including thyroid function tests, full blood count, HbA1c, urea and electrolytes, liver function tests, and lipid profile. Advise the paramedic that these will be booked with the healthcare assistant or practice nurse, and confirmation will be sent to the patient by text message','Advise that if his palpitations persist, worsen, or do not improve with lifestyle changes, he should come back to be reviewed and further investigations such as a 3-day Holter monitor can then be considered','Ask the paramedic to give the patient clear safety-netting advice to call 999 if symptoms change, including chest pain, collapse, severe dizziness, worsening breathlessness, or prolonged episodes','Advise the paramedic that a text message will be sent to the patient summarising the management plan, red flag symptoms to look out for, and how to seek urgent help','Advise that if any abnormalities are found on the blood tests, the patient will be offered a follow-up appointment'],
  'Thank you so much, Michelle, for attending Stuart and for calling to talk this through. That is really appreciated, and the assessment you have done is very helpful.

Based on everything you have described, Stuart is currently stable. His observations are within normal limits, his ECG shows a normal sinus rhythm with no concerning features, and there are no red flag symptoms such as chest pain, collapse, or palpitations brought on by exercise to suggest a serious cardiac cause at this stage. That is all very reassuring.

Putting the picture together, the most likely explanation for Stuart''s palpitations is benign in nature and related to two main factors: the significant amount of caffeine he is drinking — up to ten cups a day is a considerable amount — and the stress he has been under since taking on his new role as kitchen manager. Both of these are well-recognised triggers for palpitations, and the fact that they have been worsening since these changes occurred fits well with that explanation.

With that in mind, I do not think he needs to go to hospital today. I think we can safely manage him in the community, provided you are comfortable with that assessment too. The first things to tackle are the caffeine and the stress. It would be very helpful to advise him to bring his coffee intake right down — ideally to no more than one or two cups a day — and to avoid energy drinks or any other stimulants. On the stress side, things like better sleep, building in rest time, and exploring whether his employer can make any adjustments to help him manage the pressure would all be worth trying.

It would also be useful for Stuart to keep a symptom diary — jotting down when the episodes happen, how long they last, and what he was doing at the time. This can help identify any patterns or triggers we might not have spotted yet.

I will arrange some baseline blood tests for him, including thyroid function, blood sugar, full blood count, kidney and liver function, and cholesterol. An overactive thyroid can sometimes cause palpitations, so it is important we rule that out. I will book him in with the practice nurse and send him a text confirmation.

If things do not settle with these changes, we can look at further investigations such as a 3-day Holter monitor, which records his heart rhythm continuously and can capture any abnormalities during an episode.

Could you please make sure Stuart is aware of the warning signs to look out for? He should call 999 straightaway if he experiences chest pain, feels faint or collapses, has severe dizziness, significant worsening of his breathlessness, or a prolonged episode that is not settling. I will also send him a text message summarising everything we have discussed, including the safety-netting advice and what to do next.',
  ARRAY['When assessing palpitations, always screen for red flag features including chest pain, syncope, exertional onset, and family history of sudden cardiac death, as these may indicate a serious underlying arrhythmia requiring urgent investigation','In a clinically stable patient with no red flag features, benign palpitations related to excess caffeine and stress are a common and safe diagnosis to make in primary care, with lifestyle advice as first-line management','Baseline blood tests including thyroid function tests, HbA1c, full blood count, lipid profile, urea and electrolytes, and liver function tests should be arranged to exclude reversible causes','If palpitations persist or do not improve with lifestyle modification, a 3-day Holter monitor is an appropriate next step to capture any rhythm abnormality during symptomatic episodes','Effective telephone consultations with paramedics involve collaborative decision-making — acknowledge their assessment, provide clear guidance, and confirm the management plan including safety-netting instructions','Caffeine is a well-recognised and common trigger for palpitations; patients should be advised to limit intake to no more than one to two cups of coffee per day and avoid energy drinks'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  233,
  'Parental Request for Antidepressants',
  'Paediatrics',
  'Video Consultation',
  false,
  'Melissa Harding',
  '14-year-old female',
  ARRAY['None Recorded'],
  ARRAY['Not currently on any regular medication.','No Known Drug Allergy'],
  'Seen by Dr Aisha Abdul (Clinical Practitioner role) – 2 months ago Presenting complaint: Seen with mum. Mum reports that the patient is anxious, withdrawn, and has been in low mood for one month. No known triggers identified. Attending school and managing. No thoughts of self-harm or suicide. Examination: Vitals stable. Maintaining eye contact. No pressure of speech. No delusions or signs of psychosis. Impression: Depression Plan: Referred to CAMHS. Safety-netting advice given.',
  'Patient''s mother, Laura Harding, is calling to discuss her daughter''s mental health and a medication recommendation from a private psychiatrist.',
  'Hello doctor, we recently had a consultation with a private psychiatrist who has recommended that my daughter should be started on antidepressants. They suggested fluoxetine 10 mg. Would you be able to prescribe this for her?',
  'Your daughter was seen by the GP two months ago and was felt to have depression. She was referred to CAMHS, but you were told the waiting time is around six months. You felt that was too long to wait, so your husband arranged a private appointment with a psychiatrist through your health insurance. The psychiatrist assessed her, confirmed depression, and recommended antidepressant medication. You were told that if prescribed privately there would be a cost, but that the GP could prescribe it on the NHS, and as she is under 16 it would be free. The psychiatrist suggested fluoxetine 10 mg.',
  ARRAY['Melissa has been feeling low and is anxious about going to school. She has become withdrawn at home and has lost interest in the things she used to enjoy. There are no clear triggers. Her sleep and appetite are normal but she is much less engaged than she used to be.','She is still going to school and there have been no concerns raised by her teachers. She has not mentioned any bullying.','She started her periods at age 12. She is not in any romantic relationship. She has friends but has been less interested in spending time with them.'],
  'Melissa is a non-smoker, does not drink alcohol, and has never used illicit drugs. She lives with both parents and her younger sister. Family life is stable.',
  'You believe your daughter is depressed.',
  'You are worried that her symptoms will get worse while she is waiting to be seen by CAMHS.',
  'You would like the GP to prescribe the medication that was recommended. If asked about your daughter''s whereabouts, say that she is currently at school.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario.',
  ARRAY['Ask about the onset and progression of her low mood, including whether it is getting better, worse, or staying the same, and whether it is persistent or comes and goes','Ask about associated features of depression, including changes to sleep or appetite, weight changes, and loss of interest in activities she previously enjoyed','Ask about possible triggers, including stress at school, changes in circumstances such as a new school year or change in teachers, or any recent loss or significant life event','Screen for risk by asking about any thoughts of self-harm, suicidal ideas, plans, or previous attempts','Ask if she has had any physical illness recently','Ask about her social relationships, including whether she has friends and whether she is in any romantic relationship','Explore anxiety symptoms, including what she feels anxious about, whether it is linked to school or other situations, and any physical symptoms such as palpitations, chest tightness, tingling, or avoidance behaviours','Ask about school functioning, including attendance, performance, relationships with peers and teachers, and any concerns about bullying','Ask about any family history of depression or other mental health conditions','Ask about social history, including the home situation and any history of substance use','Confirm the details of the private psychiatric assessment, including diagnosis, recommendations, and whether any written documentation is available','Assess the mother''s ideas, concerns, and expectations, particularly regarding the request to start medication','Make a diagnosis of depression in a young person'],
  ARRAY['Acknowledge the mother''s concerns and thank her for acting promptly to get support for her daughter','Explain that depression in young people is best managed with a combination of psychological support and, where appropriate, medication, but that this should usually involve specialist input such as CAMHS','Advise that GPs do not usually initiate antidepressants in young people under the age of 18, and that this is typically done under specialist guidance due to the need for close monitoring','Explain that cognitive behavioural therapy, also known as talking therapy, is a very effective treatment for depression in young people, and offer referral to appropriate services','Offer to write to CAMHS to request that the appointment be brought forward if possible, given the ongoing symptoms','Offer blood tests to check for other conditions that can present with similar symptoms, including vitamin B12, folate, and iron deficiency, as well as thyroid function tests','Encourage supportive measures at home, including maintaining a regular routine, good sleep habits, regular physical activity, and keeping communication open','Discuss whether it would be helpful to involve the school so that additional pastoral support can be arranged','Provide safety-netting by advising the mother to seek urgent help if there are any concerns about self-harm, suicidal thoughts, or a significant deterioration in mood, including contacting local mental health crisis services, NHS 111, or the GP practice during working hours','Offer a follow-up in 4 to 6 weeks, ideally with Melissa present, to review how she is getting on and to decide on next steps together'],
  'Thank you for getting in touch today, and I want to start by saying that it is clear how much you care about Melissa and how hard this has been for your family. You have done absolutely the right thing by seeking help and exploring all the options available.

From everything you have described, it does sound as though Melissa has been struggling with depression — the low mood, the withdrawal from friends and activities she used to love, and the anxiety around school all fit with that picture. I completely understand why the private psychiatrist has suggested starting medication, and I also understand how worrying it must feel to be told there is a six-month wait for CAMHS when your daughter needs help now.

I do want to be transparent with you about something, though. In the UK, when it comes to young people under the age of 18, we do not usually start antidepressants without specialist involvement. This is not because the medication is not helpful — fluoxetine is in fact the first-line antidepressant we use in young people when medication is needed — but because starting it safely in this age group requires closer monitoring and specialist oversight than a GP consultation alone can provide. So at this stage, it would not be appropriate for me to prescribe it without CAMHS being involved. I hope that makes sense, and I want you to know this is about making sure Melissa has the right support around her when treatment starts.

What I can do straight away is write to CAMHS to let them know that her symptoms are ongoing and ask whether there is any possibility of bringing her appointment forward given the circumstances. I cannot guarantee that, but it is worth requesting.

In the meantime, there are things that can genuinely help. Cognitive behavioural therapy — or CBT — is a talking therapy that helps young people identify and challenge unhelpful thought patterns and gradually re-engage with activities and situations they have been avoiding. It is very effective for both depression and anxiety, and I can refer Melissa to a service for this now.

At home, simple but important things make a real difference — keeping a regular daily routine, encouraging gentle physical activity, and making sure she knows she can talk openly to you about how she is feeling. If you feel it would be helpful and she is comfortable with it, involving her school so that her form tutor or a school counsellor is aware can also provide a layer of additional support.

I would also like to arrange some blood tests to check that there are no physical causes contributing to how she feels — things like low iron, B12, folate, or an underactive thyroid can all affect mood and energy levels, and it is straightforward to check for these.

Finally, I want to make sure you know what to do if things feel more urgent. If at any point you are worried that Melissa is talking about harming herself or expressing suicidal thoughts, or if her mood deteriorates significantly, please do not wait for an appointment — contact NHS 111 straightaway, or the local mental health crisis team, whose contact details I will share with you. You can also call us during working hours.

Let us book a review in about four to six weeks. It would be great if Melissa could join us for that appointment so we can hear from her directly and think together about the next steps.',
  ARRAY['GPs should not initiate antidepressants in young people under the age of 18 without specialist involvement from CAMHS, as this requires closer monitoring and is outside routine GP prescribing competence','Fluoxetine is the first-line antidepressant for depression in young people when medication is indicated, but must be started under specialist guidance','Cognitive behavioural therapy is an effective evidence-based first-line treatment for depression and anxiety in young people and should be offered while awaiting specialist review','When a GP receives a prescription recommendation from a private specialist, they must be satisfied that the prescription is appropriate, safe, and within their own competence before proceeding — prescribing solely on the basis of another clinician''s recommendation is not sufficient','Safety-netting for depression in young people must specifically cover self-harm and suicidal ideation, with clear signposting to NHS 111, local crisis services, and the GP practice','Blood tests including thyroid function, iron, B12, and folate should be checked to exclude treatable physical causes that can mimic or worsen depressive symptoms in young people'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  234,
  'Incidental Pulmonary Fibrosis on CT Scan',
  'Respiratory',
  'Telephone Consultation',
  false,
  'Caroline Lawson',
  '51-year-old female',
  ARRAY['Recurrent UTI'],
  ARRAY['Nitrofurantoin 50mg at night (started 18 months ago)','No Known Drug Allergy'],
  'CT Chest Report Referrer: Private GP Clinical Indication: General health check-up (private insurance screening) Technique: CT scan of the chest performed without intravenous contrast. Multiplanar reformats reviewed. Findings: There are bilateral, predominantly basal and subpleural reticular opacities. Areas of interlobular septal thickening are noted, with early honeycombing seen in the posterior lower lobes. Mild traction bronchiectasis is present. No focal consolidation identified. No suspicious pulmonary nodules or masses. No pleural effusion or pneumothorax. No significant mediastinal or hilar lymphadenopathy. Cardiac size within normal limits. No pericardial effusion. Great vessels appear unremarkable. Upper Abdomen (limited views): No significant abnormality identified. Bones: No acute or suspicious bony abnormality. Impression: Imaging features are in keeping with early pulmonary fibrosis, with a basal and subpleural predominance, early honeycombing, and traction bronchiectasis. Clinical correlation is advised. Referral to a respiratory specialist and consideration of pulmonary function testing is recommended. Radiologist: Dr James Whitaker, MBBS, FRCR, Consultant Radiologist, GMC no: 12345',
  'Patient booked a routine telephone consultation to discuss the results of a CT scan performed as part of a private health check.',
  'Hello doctor, I recently had a full health check arranged through my private health insurance as part of a routine screen, and they included a CT scan. I was told that they found something in my lungs and that I should speak to my GP about it.',
  'You feel completely well in yourself. This was a routine head-to-toe health check arranged through your private insurance. You were told something had been found in your lungs but you are not entirely sure what it means or whether it is serious.',
  ARRAY['You do not have any symptoms at all and feel perfectly well in yourself.','If asked about nitrofurantoin, you have been taking it for the past 18 months. It was prescribed by a urologist because of recurrent urinary tract infections. It has worked very well and you have not had a UTI for approximately 12 months.'],
  'You do not smoke, drink alcohol, or use illicit drugs. You live with your husband and work as a project manager at a property development company.',
  'You are not sure what this finding means or what it could indicate.',
  'You are worried because something has shown up on the scan even though you feel completely well.',
  'You would like the GP to explain the results clearly and tell you what happens next. Questions for the GP: What is pulmonary fibrosis? Is it curable? What might have caused it? If the doctor suggests a specialist referral, ask what the specialist is likely to do.',
  ARRAY['If the doctor suggests referral to a specialist, ask what the specialist is likely to do. Say NO to any other questions or symptoms asked outside of the details already provided in the scenario.'],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario.',
  ARRAY['Ask why the CT scan was arranged in the first place','Ask whether she has any respiratory symptoms such as cough, shortness of breath, reduced exercise tolerance, wheeze, or chest pain','Ask whether she has had any constitutional symptoms such as unexplained weight loss, fatigue, fevers, or night sweats','Ask about any previous history of tuberculosis, pneumonia, or recurrent chest infections, as fibrosis can develop following severe or repeated infections','Ask about symptoms that might suggest an underlying connective tissue disease, including joint pains, skin rashes, dry eyes, dry mouth, Raynaud''s phenomenon, or muscle weakness','Ask about social history, including smoking, alcohol use, and home environment','Ask about her occupation and work history, as certain jobs carry increased risk — for example, livestock farming or bird keeping (organic dust exposure), hairdressing (prolonged exposure to sprays or dyes), construction, plumbing, mining, or demolition work (possible exposure to asbestos, silica, or coal dust)','Ask about any family history of lung disease','Explore the patient''s ideas, concerns, and expectations','Make a diagnosis of pulmonary fibrosis and consider nitrofurantoin-induced lung toxicity as an important possible underlying cause'],
  ARRAY['Offer an urgent referral to a respiratory specialist. Explain that they may arrange further investigations such as spirometry and, in some cases, a lung biopsy if needed to establish the underlying cause','Inform the patient that pulmonary fibrosis is a recognised but uncommon side effect of long-term use of nitrofurantoin','Advise the patient to stop nitrofurantoin and discuss alternative approaches to managing her recurrent urinary tract infections, including lifestyle measures such as maintaining good fluid intake, not delaying urination, voiding after sexual activity, and wiping front to back as first-line options. If symptoms remain well controlled, no further medication may be needed; if infections recur, alternatives such as trimethoprim can be considered','Explain that if the fibrosis has been caused by the medication, stopping nitrofurantoin can prevent further worsening and may lead to some improvement, particularly as it has been identified at an early stage. However, any scarring already present in the lungs may not fully reverse','Offer baseline blood tests including ESR, CRP, full blood count, and an autoimmune screen to help exclude other possible underlying causes','Provide safety-netting by advising her to contact the GP practice if she develops any new respiratory symptoms such as shortness of breath, a persistent cough, chest pain, or reduced exercise tolerance'],
  'Thank you for calling in today, Caroline, and I am glad you got in touch. I can imagine it must feel quite unsettling to be told something has shown up on a scan when you feel completely well, so I want to go through the results carefully and make sure you understand what they mean and what we are going to do.

The CT scan looked at your lungs in detail. The report describes a pattern of changes that is consistent with something called pulmonary fibrosis. Fibrosis essentially means scarring — in this case, scarring within the lung tissue itself. The pattern seen on your scan appears mainly at the bases of the lungs and around the outer edges, which is a recognised distribution. The radiologist has noted early changes, which means this has been picked up at a relatively early stage, and that is actually important — the earlier we identify it, the more we can do.

I want to raise something that could be very relevant here. You have been taking nitrofurantoin for the past 18 months for your recurrent urinary tract infections. Pulmonary fibrosis is a recognised, though uncommon, side effect of long-term nitrofurantoin use, and given the timing of your treatment and the changes on the scan, this is something we need to take seriously as a possible cause. I would like to advise you to stop taking the nitrofurantoin for now. For your urinary tract infections, we can discuss alternatives. Simple measures like keeping well hydrated, not holding on when you need to go, and wiping front to back can all reduce the risk of infections. If infections do return, we can consider a different antibiotic such as trimethoprim.

If the nitrofurantoin is indeed responsible, stopping the medication now can prevent the scarring from getting any worse, and in some cases there can be some improvement, particularly when the changes have been caught early as in your case. That said, any scarring that has already formed may not completely disappear.

I would like to refer you urgently to a respiratory specialist — a lung doctor — who will be best placed to assess you in full, interpret the scan in the clinical context, and arrange further tests such as breathing tests and, if needed, more detailed investigations. They will also be able to give you a clearer picture of what to expect going forward.

I will also arrange some blood tests at our end, including markers of inflammation and an autoimmune screen, to help rule out other possible causes of the changes seen.

I do want to reassure you that because you feel well and this has been picked up incidentally at an early stage, we are in a good position to manage this proactively. Please do get in touch with us if you develop any new symptoms — particularly breathlessness, a new persistent cough, chest discomfort, or finding that you cannot do the things you normally do without getting out of breath. In that situation, please contact us promptly rather than waiting.',
  ARRAY['Nitrofurantoin is a well-recognised cause of pulmonary fibrosis when used long-term, and this diagnosis should always be considered when a patient on nitrofurantoin presents with incidental CT findings consistent with fibrosis','Pulmonary fibrosis on CT typically appears as bilateral basal and subpleural reticular opacities, interlobular septal thickening, early honeycombing, and traction bronchiectasis','Stopping nitrofurantoin promptly when drug-induced fibrosis is suspected can prevent progression and may allow partial improvement, particularly when identified early; established scarring may not fully reverse','All patients with CT findings suggestive of pulmonary fibrosis require urgent referral to a respiratory specialist for further assessment, which may include spirometry, further imaging, or lung biopsy','Baseline blood tests including ESR, CRP, full blood count, and autoimmune screen help to exclude connective tissue diseases and other systemic causes of pulmonary fibrosis','Occupational history is an important part of assessing pulmonary fibrosis — exposure to organic dusts (farming, bird keeping), asbestos, silica, or chemical agents can all cause or contribute to fibrotic lung disease'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  235,
  'Recurrent Epistaxis',
  'ENT & Eye',
  'Video Consultation',
  false,
  'Helen Bradshaw',
  '62-year-old female',
  ARRAY['Bilateral knee osteoarthritis','Hypertension','Epistaxis'],
  ARRAY['Amlodipine 5mg once daily','Co-codamol 30/500 mg, 1 to 2 tablets every 4 to 6 hours as required','Ibuprofen gel as required','No Known Drug Allergy'],
  'A&E Discharge letter – 1 week ago Dear GP, Helen attended the Accident and Emergency Department with a nosebleed. The bleeding was identified as anterior epistaxis and was successfully cauterised, with good haemostasis achieved. Her observations were stable. Blood pressure 130/78 mmHg, pulse 89 bpm, respiratory rate 18 breaths per minute, oxygen saturation 97% on air, temperature 36.3°C. She was prescribed Naseptin cream to be applied to both nostrils twice daily. She was advised to avoid nasal trauma, including nose picking, and to avoid strenuous activity for a few days. She was also advised to seek urgent medical attention if the bleeding recurs or becomes heavy. GP review is advised if symptoms persist or recur. Dr Emily Carter Emergency Medicine Registrar',
  'Patient booked an urgent video consultation to discuss recurrent nosebleeds.',
  'Hello doctor, I have had another nosebleed again.',
  'You have been getting recurrent nosebleeds for the past 6 months. You were seen in A&E 1 week ago where the bleeding was treated and you were given a cream to apply twice daily. Today you had another episode around 30 minutes ago.',
  ARRAY['The most recent episode came from your left nostril, which is the same side it usually bleeds from. You typically have at least one episode every 2 weeks, but it has been getting more frequent — now around 2 episodes every 2 weeks.','You do not have any other symptoms apart from the nosebleeds. When they happen, you lean backwards and pinch the hard part of your nose to try to stop the bleeding. Please demonstrate this during the video consultation if asked.','You have hypertension and osteoarthritis and take your prescribed medications regularly. For your osteoarthritis, you have been using over-the-counter ibuprofen tablets, which you started around 6 to 7 months ago as they helped with your knee pain. You do not take co-codamol regularly because ibuprofen works better for your pain, and you do not use the ibuprofen gel.'],
  'You do not smoke, drink alcohol, or use illicit drugs. You work as a retail store manager and live with your husband.',
  'You think your high blood pressure may be causing the nosebleeds.',
  'You are worried because the episodes are becoming more frequent.',
  'You would like the doctor to advise you on what to do. Questions for the Doctor: Can you please show me what to do when I have a nosebleed? I am not sure if I am doing it correctly because it never seems to work. I usually lean backwards and pinch the hard part of my nose. Is that right?',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Ask about the onset and progression of the nosebleeds.','Ask if she is currently having an episode and when the last episode occurred.','Ask whether the bleeding is from one nostril or both. Note that bleeding from one nostril is more suggestive of an anterior bleed, which is usually easier to control, whereas bleeding from both nostrils may suggest a posterior source, which can be more difficult to manage.','Ask about the severity of the bleeding and whether there are any clots.','Ask what she does during an episode to stop the bleeding.','Ask about local nasal causes such as nose picking, trauma, recent upper respiratory tract infection, chronic rhinosinusitis, nasal dryness, or use of nasal sprays.','Ask about symptoms of anaemia such as fatigue, dizziness, palpitations, chest pain, or shortness of breath.','Ask if she has experienced bleeding from other sites, such as gum bleeding, easy bruising, or blood in the stool or urine, to exclude a bleeding disorder.','Ask about red flag symptoms that may suggest malignancy, including weight loss, night sweats, unilateral nasal obstruction, persistent nasal discharge, facial pain, hearing loss, persistent lymphadenopathy, facial numbness, or double vision.','Ask about medication use, including anticoagulants and over-the-counter medications such as aspirin or NSAIDs.','Ask about any family history of bleeding disorders.','Ask about smoking, alcohol use, occupation, and home situation.','Explore the patient''s ideas, concerns, and expectations.','Make a diagnosis of recurrent epistaxis, likely worsened by regular use of over-the-counter ibuprofen tablets.'],
  ARRAY['Offer a face-to-face appointment to examine the nostrils and look for any local causes such as polyps or masses that may be contributing.','Offer blood tests, including full blood count to check for anaemia, liver function tests, and a coagulation profile to assess for clotting abnormalities.','Advise that she can continue using Naseptin and increase application to four times daily.','Advise discontinuation of ibuprofen tablets, as these can contribute to bleeding and worsen nosebleeds.','Offer alternative pain relief such as paracetamol with or without codeine or topical ibuprofen gel. If symptoms are not controlled, arrange a follow-up to discuss further options for osteoarthritis management, including physiotherapy or joint injections.','Advise avoiding nose blowing or picking to reduce further trauma.','Reassure her that her blood pressure was well controlled at her recent A&E visit and is unlikely to be the cause of her nosebleeds. Offer to recheck her blood pressure at the face-to-face appointment.','Reinforce correct first aid for epistaxis by advising her to sit upright, lean forward, and pinch the soft part of the nose firmly for 10 to 15 minutes without releasing pressure.','Provide safety-netting by advising her to seek urgent medical attention by contacting the GP urgently, NHS 111, or attending A&E if bleeding lasts longer than 20 minutes despite applying pressure, becomes heavy, or is associated with symptoms such as dizziness, shortness of breath, palpitations, or weakness.','Offer follow-up to discuss the blood test results once they are available.'],
  'Thank you for joining me on the video today, Helen. I can hear that you''re quite worried, especially after attending A&E just last week and now having another episode this morning — that must feel very frustrating and unsettling.

From what you''ve described, the nosebleeds are coming from the same nostril each time and seem to be happening more often over recent months. The good news is that based on the A&E letter and what you''ve told me today, this is most likely what we call anterior epistaxis — bleeding from a small blood vessel near the front of the nose. This is the most common type and is generally manageable. However, I do want to look into this a little further.

One important thing that has come up in our conversation is that you''ve been taking ibuprofen tablets regularly for your knee pain over the past six to seven months — and this timing lines up closely with when the nosebleeds started. Ibuprofen and similar anti-inflammatory medications can affect how the blood clots and make the lining of the nose more fragile, which can contribute to nosebleeds. I would strongly advise stopping the ibuprofen tablets for now. You could try paracetamol as an alternative, or use the ibuprofen gel that is already prescribed, as topical use is much less likely to have this effect. We can also look at other options for your knee pain at a follow-up.

I''d also like to increase your Naseptin cream to four times a day rather than twice, as this can help keep the nasal lining moist and reduce the likelihood of further bleeds.

Regarding your blood pressure — I want to reassure you that it was recorded as well controlled during your A&E visit, so that is unlikely to be the cause. That said, I''d like to recheck it when I see you in person.

I''d like to arrange a face-to-face appointment to have a proper look inside your nostrils to check for any local causes such as visible blood vessels, polyps, or any other changes. I''ll also arrange some blood tests, including a full blood count to check for anaemia, liver function tests, and a clotting profile, just to make sure there isn''t anything else going on in the background.

I also want to address your question about what to do when a nosebleed happens. Rather than leaning back and pinching the hard part of the nose, the correct technique is to sit upright and lean slightly forward, then pinch the soft, fleshy part of the nose — just below the bony bridge — firmly and continuously for ten to fifteen minutes without releasing. Leaning back can cause blood to run down the throat, which can cause nausea. Pinching the soft part is where most bleeds originate from.

For safety, if you have a nosebleed that lasts longer than twenty minutes despite applying firm pressure, becomes very heavy, or is accompanied by symptoms such as dizziness, palpitations, shortness of breath, or weakness, please call NHS 111 or attend your nearest A&E straight away. Otherwise, please do book in to see me for the face-to-face appointment and we''ll take it from there.',
  ARRAY['Recurrent unilateral epistaxis in a patient taking regular NSAIDs should prompt advice to stop the NSAID, as ibuprofen impairs platelet function and can worsen mucosal fragility, contributing to nosebleeds.','Correct first aid for epistaxis is to sit upright, lean forward, and pinch the soft (fleshy) part of the nose firmly for 10–15 minutes continuously — not the bony bridge, and not leaning back.','Naseptin cream can be increased to four times daily for recurrent epistaxis to keep nasal mucosa moist and reduce further bleeds.','Investigations for recurrent epistaxis should include full blood count, liver function tests, and a coagulation profile to exclude anaemia and clotting disorders.','Although hypertension is often assumed to cause nosebleeds, well-controlled blood pressure is unlikely to be the primary cause — address this misconception clearly with patients.','Safety-netting for epistaxis: advise urgent review or A&E attendance if bleeding exceeds 20 minutes, is very heavy, or is associated with dizziness, palpitations, or shortness of breath.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  236,
  'Sexual Health Advice in a Lesbian Patient',
  'Gynaecology & Women''s Health',
  'Video Consultation',
  false,
  'Gemma Holloway',
  '29-year-old female',
  ARRAY['None Recorded Alerts','Missed cervical screening for the second time. Numerous text messages and letters sent to home address.'],
  ARRAY['Not currently on any regular medication','No Known Drug Allergy'],
  NULL,
  'Patient booked a video consultation to discuss sexual health concerns and STI risk.',
  'Hello doctor, I read an article saying that lesbians can get sexually transmitted infections, including HIV, and I would like to understand how that is possible and whether I should be tested.',
  'You recently came across an article about STIs in women who have sex with women, and it has made you worried about your own risk. About 3 months ago, you went out with friends and had a sexual encounter with a woman who is bisexual. You currently have no symptoms but are worried about possible exposure.',
  ARRAY['You shared sex toys with the bisexual partner. You do not have a regular partner and have occasional sexual encounters. Your last sexual contact was 3 months ago.','You usually have sex with women, and your last partner was a bisexual female.','If asked about cervical screening, explain that you did not feel it was necessary as you believed cervical cancer mainly affects women who have sex with men. Then ask the doctor whether you are at risk of getting the virus that causes cervical cancer even if you do not have sex with men.'],
  'You do not smoke, drink alcohol, or use illicit drugs. You live alone and work as a software developer.',
  'You believe that lesbians are not at risk of sexually transmitted infections.',
  'You are worried after reading the article and feel you may now be at risk.',
  'You would like the GP to explain your level of risk and advise whether you need testing. Questions for the Doctor: Can I get sexually transmitted infections as a lesbian? Can women who have sex with women be at risk of HIV? Do I need cervical screening as a lesbian — I thought that was only for women who have sex with men? What percentage of lesbians get sexually transmitted infections? What are safer ways to have sex as a lesbian to reduce my risk?',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Acknowledge her concerns and explore what she has understood from the article.','Signpost that you will be asking some personal questions to better understand her risk.','Ask about her sexual lifestyle, including number of sexual partners, gender of partners, and whether partners are female or bisexual, as well as practices such as use of sex toys and oral sex.','Ask whether protection was used during sexual activity, including use of dental dams for oral sex or condoms on sex toys.','Ask about any past history of sexually transmitted infections and whether she has ever been tested before.','Screen for symptoms of sexually transmitted infections, including vaginal discharge, itching, pelvic pain, dysuria, bleeding after sex, or genital lesions.','Ask about her menstrual history, including any abnormal bleeding or intermenstrual bleeding.','Acknowledge that she has missed two cervical screening appointments and explore her reasons for this.','Ask about social history, including smoking, alcohol use, illicit drug use, occupation, and home situation.','Explore her ideas, concerns, and expectations regarding STI risk and testing.'],
  ARRAY['Explain that women who have sex with women can still get and pass on sexually transmitted infections, including HIV, HPV, herpes, and bacterial infections, particularly through sharing sex toys, oral sex especially if there are cuts or sores in the mouth, and contact with bodily fluids.','Offer referral to a sexual health clinic and explain that they can provide a full sexual health screen, including tests for HIV, chlamydia, gonorrhoea, syphilis, and other relevant infections. If she prefers not to attend, offer to arrange testing in primary care.','Address her misconception regarding cervical screening and explain that HPV can be transmitted between women, so cervical screening remains important regardless of sexual orientation. Explain that most cases of cervical cancer are linked to HPV, which is spread through skin-to-skin contact during any form of sexual activity.','Strongly encourage her to book a cervical smear and explain its role in preventing cervical cancer.','Discuss safer sex practices, including using condoms on sex toys, avoiding sharing them or cleaning them thoroughly between use (washed with soap and water), and considering the use of dental dams for oral sex.','Advise that sex toys should be washed with soap and water between uses.','Offer written information or leaflets about STI risk and safer sex practices.','Provide safety-netting by advising her to seek medical attention if she develops symptoms such as abnormal vaginal discharge, painful urination, lower abdominal pain, genital ulcers, or any other concerns.'],
  'Thank you for getting in touch today and for being so open about what has been worrying you. Reading that article clearly prompted some real concern, and it is genuinely good that you have come forward to discuss it rather than just wondering.

I want to start by addressing your main question directly, Gemma. Women who have sex with women can still get and pass on sexually transmitted infections — including HIV. The risk is real, even if it may differ in some ways compared to sexual activity with men. Infections can be passed on through sharing sex toys without protection, through oral sex particularly if there are any cuts or sores present, and through contact with bodily fluids. So while the risk profile is different, it is definitely not zero. I hope that helps to clarify things.

Given that your last sexual contact was around three months ago and involved sharing sex toys, it would be appropriate to arrange a full sexual health screen for you. This would include tests for HIV, chlamydia, gonorrhoea, syphilis, and other relevant infections. The best place for this is usually a sexual health clinic, as they specialise in this area and can offer a comprehensive screen. However, if you would prefer to have the tests arranged through the practice, we can do that too. How do you feel about that?

I also want to talk about cervical screening, because you have missed two invitations now. I completely understand the thinking that it might not apply to you as a woman who has sex with women — but this is actually a common misconception that is really important to address. The virus responsible for the vast majority of cervical cancer cases is HPV, which is spread through skin-to-skin contact during sexual activity. This means it can be passed between women, regardless of whether penetrative sex with men is involved. Cervical screening is just as important for you as for anyone else, and it exists to pick up early cell changes before they ever develop into cancer. I would really encourage you to book that appointment.

In terms of reducing your risk going forward, there are some straightforward steps you can take. Avoid sharing sex toys where possible, or if you do share them, use condoms on them and wash them thoroughly with soap and water between uses. You might also consider using dental dams during oral sex to reduce the risk of infection.

You asked what percentage of lesbians get sexually transmitted infections — that is a really thoughtful question. There is no single exact figure, because risk depends much more on individual sexual practices than on sexual orientation alone. What matters most is understanding your own situation and what steps you can take to reduce risk, which is exactly what we''ve been talking about today.

If you develop any symptoms such as unusual vaginal discharge, pain when passing urine, lower abdominal pain, or any sores or ulcers, please do get in touch with us straight away. Otherwise, the next step is to arrange that sexual health screen and to book your cervical smear.',
  ARRAY['Women who have sex with women are not immune to STIs — infections including HIV, HPV, herpes, and chlamydia can all be transmitted through oral sex, shared sex toys, and contact with bodily fluids.','HPV is transmitted through skin-to-skin contact during sexual activity, not only through penetrative sex — women who have sex with women remain at risk of HPV and therefore cervical cancer.','Cervical screening is recommended for all eligible individuals regardless of sexual orientation; this must be communicated clearly and non-judgementally.','Safer sex practices for women who have sex with women include using condoms on sex toys, cleaning toys thoroughly with soap and water between uses, and using dental dams for oral sex.','Sexual health screening after a potential exposure should include HIV, chlamydia, gonorrhoea, syphilis, and other relevant infections — this is most comprehensively done at a sexual health clinic.','Addressing misconceptions sensitively and without judgement is central to effective sexual health consultations, particularly in patients from marginalised or less-represented groups.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  237,
  'Rectal Bleeding in Young Male',
  'Gastroenterology & Haematology',
  'Telephone Consultation',
  false,
  'Daniel Forsyth',
  '39-year-old male',
  ARRAY['None Recorded'],
  ARRAY['Not currently on any regular medication','No Known Drug Allergy'],
  'Seen by Dr Peter Bexley (Clinical Practitioner role) 3 months ago Presenting complaint: Patient was concerned about the risk of prostate cancer as his uncle was recently diagnosed. No weight loss, new back pain or urinary symptoms reported Examination: Prostate examination performed with verbal consent. Chaperone declined. Prostate felt smooth with no masses. Some external haemorrhoids noted, non-bleeding and non-tender Observations: Blood pressure 120/80 mmHg, respiratory rate 16 breaths per minute, oxygen saturation 100% on air, pulse 82 bpm Impression: Normal findings Plan: Counselled regarding PSA testing. PSA test offered Note entry by Dr Peter Bexley (Clinical Practitioner role) 2 months ago: PSA: 1.2 (0 to 4 ng/L) – normal. Patient informed via text and reassured. Warning signs of prostate cancer discussed',
  'Patient booked an urgent telephone consultation to discuss rectal bleeding.',
  'Hello doctor, I have had bleeding from my back passage for the last 2 days.',
  'You noticed fresh red blood when wiping after opening your bowels yesterday, and it happened again today. This has made you worried, which is why you booked this appointment.',
  ARRAY['The blood is not mixed with the stool. You notice it on the tissue after opening your bowels. Your stools are normal and you do not have constipation or diarrhoea.','You do not have any pain, weight loss, or night sweats.','There is a family history of bowel cancer in your father at age 75 and prostate cancer in your uncle on your father''s side at age 80.','If asked about sexual history, you are bisexual and have sex with both men and women. You engage in anal sex and are both the receptive and insertive partner.'],
  'You do not smoke, drink alcohol, or use illicit drugs. You live alone and work as a tattoo artist, running your own shop.',
  'You are not sure what is causing the bleeding.',
  'You are worried that the bleeding could be cancer or related to your sexual activity.',
  'You would like the GP to explain what might be going on.',
  ARRAY[]::text[],
  NULL,
  NULL,
  ARRAY['Ask about the onset of PR bleeding, including duration, frequency, and whether it is increasing or resolving.','Ask about the colour of the blood, including whether it is dark red or fresh bright red.','Ask whether the blood is mixed with the stool, on the surface of the stool, or only seen on wiping. (PR bleeding with haemorrhoids is usually seen on wiping and not mixed with the stool. If mixed, consider other causes such as malignancy).','Ask about any associated anal pain during or after passing stool (haemorrhoids are usually painless unless thrombosed; if painful, consider anal fissures).','Ask about associated abdominal pain, constipation, or diarrhoea.','Ask about symptoms suggestive of colorectal cancer, including weight loss, fatigue, loss of appetite, or night sweats.','Ask about symptoms of anaemia such as dizziness, palpitations, chest pain, or shortness of breath.','Ask about any history of haemorrhoids, anal fissures, or previous similar episodes.','Ask about recent sexual history, including anal intercourse, any trauma, pain, or bleeding associated with it, and use of protection.','Ask about risk of sexually transmitted infections, including discharge, ulcers, or rectal pain.','Ask about medication use, including anticoagulants, antiplatelets, or NSAIDs.','Ask about family history of bowel cancer and clarify the age of diagnosis.','Ask about social history, including smoking, alcohol use, and occupation.','Explore the patient''s ideas, concerns, and expectations.','Make a diagnosis of rectal bleeding, likely due to haemorrhoids.'],
  ARRAY['Offer a face-to-face appointment for examination, including abdominal examination and digital rectal examination to confirm the diagnosis.','Advise on conservative management, including increasing dietary fibre intake, maintaining adequate hydration, and avoiding straining during bowel movements.','Advise on the importance of good anal hygiene. The anal area should be kept clean and dry to promote healing and reduce irritation and itching.','Advise avoiding prolonged sitting on the toilet.','Advise that he can purchase over-the-counter haemorrhoid treatments such as creams or suppositories, for example Anusol cream, to be used morning and night and after bowel movements for up to 7 days.','Reassure him that his symptoms are more likely due to haemorrhoids and are less likely to be due to cancer or his sexual orientation. Encourage him to continue safe sex practices.','Provide safety-netting by advising him to seek medical attention if bleeding becomes heavy, persists, is mixed with stool, or if he develops weight loss, a change in bowel habit, or symptoms of anaemia such as dizziness, palpitations, or shortness of breath.','Offer follow-up in 4 weeks to review symptoms and ensure improvement.'],
  'Thank you for calling in today. I can hear that this has been worrying you, and I want to reassure you that you did the right thing by getting in touch.

From what you have described, the blood you are noticing is fresh and bright red, appearing on the tissue after wiping rather than being mixed in with the stool itself. This pattern is actually quite reassuring, because blood that is mixed into the stool tends to suggest a source higher up in the bowel, whereas blood seen only on wiping is much more commonly coming from the area around the back passage — most often from haemorrhoids.

You mentioned that haemorrhoids were actually found on examination at your last appointment here a few months ago. Although they were not bleeding at the time, it is quite likely that these are now causing the bleeding you are experiencing. This is a very common and treatable condition, and I want to be clear that there is nothing in what you have described that suggests this is related to your sexual activity or to cancer.

That said, I do want to examine you properly to confirm this. I would like to arrange a face-to-face appointment where we can carry out an abdominal examination and a digital rectal examination to have a proper look and feel.

In the meantime, there are some things that can really help. Try to increase the amount of fibre in your diet — things like fruit, vegetables, wholegrains, and pulses — and make sure you are drinking plenty of fluids. Avoid straining when you open your bowels, and try not to spend too long sitting on the toilet. Keeping the area clean and dry will also help to reduce irritation. You can also pick up an over-the-counter cream or suppository from the pharmacy — something like Anusol — and use it morning and night and after each bowel movement for up to 7 days.

In terms of your concerns about cancer: your father was diagnosed with bowel cancer at the age of 75, and your uncle with prostate cancer at 80. These are relatively late-onset diagnoses and do not place you in a high-risk category at this stage, though it is always worth keeping track of family history.

Please do come back to us urgently — or contact NHS 111 if we are closed — if the bleeding becomes heavier, does not settle, starts appearing mixed in with the stool, or if you develop any weight loss, a change in your usual bowel habit, or symptoms such as dizziness, palpitations, or breathlessness.',
  ARRAY['PR bleeding that is fresh, bright red, and seen only on wiping (not mixed with stool) is most consistent with a low rectal or anal source such as haemorrhoids or a fissure.','Haemorrhoids are typically painless unless thrombosed; associated pain suggests an anal fissure or thrombosed haemorrhoid.','A face-to-face appointment with abdominal and digital rectal examination is essential to confirm the diagnosis before assuming haemorrhoidal cause.','Conservative management of haemorrhoids includes dietary fibre, adequate hydration, avoiding straining, good anal hygiene, and short-term use of over-the-counter preparations such as Anusol cream.','Family history of colorectal cancer should be assessed; a first-degree relative diagnosed after age 60 does not generally qualify for early surveillance under NICE guidelines.','Safety-netting for rectal bleeding: advise urgent review if bleeding persists, becomes heavy, is mixed with stool, or is accompanied by weight loss, change in bowel habit, or anaemia symptoms.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  238,
  'Iron Deficiency and Low Folate',
  'Gastroenterology & Haematology',
  'Telephone Consultation',
  false,
  'Roy Cunningham',
  '72-year-old male',
  ARRAY['None Recorded'],
  ARRAY['Not currently on any regular medication','No Known Drug Allergy'],
  'Seen by Mary Preston (Advanced Nurse Practitioner) 2 weeks ago Presenting complaint: Feeling tired all the time and reports back pain. No red flag symptoms Examination: Blood pressure 130/70 mmHg, pulse 78 bpm, temperature 36.1°C, oxygen saturation 98 percent on air, respiratory rate 18 breaths per minute. No tenderness on examination of lower back and straight leg raise normal bilaterally Impression: Tired all the time with mechanical back pain Plan: For TATT blood tests and review with results Blood Test Results: Test Result Reference Range Haemoglobin (Hb) 132 g/L 130–160 g/L White Cell Count (WCC) 6.5 ×10⁹/L 4.0–11.0 ×10⁹/L Platelets 280 ×10⁹/L 150–400 ×10⁹/L Mean Cell Volume (MCV) 88 fL 80–100 fL Mean Cell Haemoglobin (MCH) 29 pg 27–33 pg Serum Folate 2.0 µg/L 3.0–20.0 µg/L Ferritin 10 µg/L 30–400 µg/L B12, U+E''s, Bone profile, CRP, ESR, TSH, and Liver function test Normal',
  'Patient booked a follow-up telephone consultation to discuss blood test results.',
  'Hello doctor, I am here to go through my blood test results, if that is alright.',
  'You have been feeling tired all the time for over 3 months and have also had some back pain. You saw a nurse practitioner who arranged blood tests to look for a cause of your symptoms.',
  ARRAY['Your back pain has now resolved. It was in your lower back, a dull ache that came and went, but it is now better. You do not have any urinary or bowel symptoms, no weight loss, and no bleeding from anywhere.','You are still able to manage your daily activities such as shopping and cleaning despite the tiredness.','Your sleep and mood are okay.','Your diet has not been very good since your wife, who used to cook, passed away one year ago from breast cancer. You miss her a lot. You usually have toast in the morning and rely on processed or packaged foods for lunch and dinner as you do not know how to cook.'],
  'You live alone and are a retired bus driver. You do not smoke, drink alcohol, or use illicit drugs.',
  'You are not sure what is causing your symptoms.',
  'You do not have any specific concerns.',
  'You would like to discuss your blood test results.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Acknowledge that you have reviewed the previous consultation notes, but ask the patient to explain in his own words what led to the blood tests.','Ask about the onset and progression of his tiredness, including whether it is getting worse, improving, or staying the same.','Ask if there are any factors that make the tiredness better or worse.','Ask about his back pain, including location, onset, character, and whether it radiates.','Ask about bleeding from any part of the body, including blood in urine, blood in stool, or vomiting blood.','Ask about symptoms suggestive of anaemia, including headache, shortness of breath, dizziness, palpitations, or reduced exercise tolerance.','Ask about gastrointestinal symptoms such as abdominal pain, vomiting, difficulty swallowing, heartburn, change in bowel habit, or any abdominal or rectal lumps.','Ask about lower urinary tract symptoms, including frequency or nocturia, to exclude possible prostate pathology.','Ask about cancer red flag symptoms, including weight loss, night sweats, or loss of appetite.','Ask about dietary intake.','Ask about family history of cancer.','Ask about social history, including smoking, alcohol use, and home situation.','Explore the patient''s ideas, concerns, and expectations.','Explain that the blood results show low ferritin and low folate, suggesting iron deficiency and folate deficiency, which are likely contributing to his tiredness.'],
  ARRAY['Offer further investigations, including a FIT test and coeliac screening, to rule out other causes of iron and folate deficiency.','Start iron supplementation with ferrous sulfate 200 mg once daily for 3 months, and folic acid 5 mg daily for 4 months.','Advise dietary modification, including increasing intake of iron-rich foods such as red meat, green leafy vegetables, and fortified cereals, as well as folate-rich foods such as broccoli and peas.','If meal preparation is a struggle, offer referral to a social prescriber who can support access to local community meal services such as "Meals on Wheels".','Explain that if any investigations return abnormal results, further referral for specialist assessment, including possible endoscopy, may be required.','Arrange repeat blood tests, including full blood count, in 4 weeks to assess response to treatment.','Provide safety-netting by advising him to seek medical attention by contacting the GP surgery if he develops symptoms such as difficulty swallowing, new-onset heartburn, change in bowel habit, blood in the stool, vomiting blood, unintentional weight loss, or worsening symptoms of anaemia such as dizziness, light-headedness, palpitations, or shortness of breath.'],
  'Thank you for calling in today, and thank you for sharing a little of what has been going on at home. I can only imagine how difficult the past year has been since losing your wife, and I want you to know that what you have been through matters, and we are here to support you.

Looking at your blood test results, Roy, there are two things that have come back slightly outside the normal range. Your ferritin level — which is a measure of your iron stores — is 10 µg/L, and the normal range is 30 to 400 µg/L, so it is lower than we would like. Your folate level, which is a B vitamin that the body needs for various important functions, is 2.0 µg/L against a normal range of 3.0 to 20.0 µg/L — again, lower than normal. Everything else in your blood tests has come back as normal, which is reassuring.

These two deficiencies are very likely to be contributing to the tiredness you have been experiencing. One of the most common reasons for low iron and folate in someone your age is diet — and from what you have shared, relying mainly on toast and packaged foods since your wife passed away would certainly make it harder to get enough of these nutrients. Iron-rich foods include things like red meat, green leafy vegetables, and fortified breakfast cereals. Folate is found in foods like broccoli, peas, and other green vegetables. I appreciate that cooking for yourself is new and not easy, and I would like to help with that.

I am going to prescribe ferrous sulfate 200 mg once daily for 3 months to top up your iron stores, and folic acid 5 mg daily for 4 months to address the low folate. I would also like to arrange a FIT test, which checks for tiny amounts of blood in the stool, and a test for coeliac disease, just to make sure there is not an underlying cause of these deficiencies that we need to investigate further. If either of those tests comes back with anything of concern, we may need to refer you for a further assessment such as an endoscopy.

I would also like to refer you to our social prescriber, who is brilliant at connecting people with local community support. There are services such as Meals on Wheels that can help make sure you are getting nutritious hot meals without the burden of cooking, especially while you are finding your feet.

We will arrange a repeat full blood count in around 4 weeks to see how you are responding to the supplements. In the meantime, please do get in touch with us if you notice any difficulty swallowing, new heartburn, a change in your bowel habit, any blood in the stool or vomiting blood, unexplained weight loss, or if the tiredness becomes significantly worse with symptoms like dizziness, palpitations, or breathlessness — any of those would need to be assessed promptly.',
  ARRAY['Low ferritin (10 µg/L; ref 30–400 µg/L) and low serum folate (2.0 µg/L; ref 3.0–20.0 µg/L) indicate iron deficiency and folate deficiency — both require supplementation and investigation for an underlying cause.','Treatment: ferrous sulfate 200 mg once daily for 3 months, and folic acid 5 mg daily for 4 months; arrange repeat full blood count in 4 weeks to assess response.','Further investigations for iron and folate deficiency should include a FIT test and coeliac screening to exclude malignancy and malabsorption.','Poor dietary intake is a common and often overlooked cause of nutritional deficiencies, particularly in older adults living alone — a holistic social history is essential.','Social prescribing and community meal services (e.g. Meals on Wheels) can address nutritional deficiency in vulnerable patients where cooking is not feasible.','Safety-netting for iron deficiency: advise urgent review if the patient develops dysphagia, change in bowel habit, rectal bleeding, haematemesis, or symptoms of significant anaemia.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  239,
  'Heavy and Painful Periods in an Adolescent',
  'Gynaecology & Women''s Health',
  'Telephone Consultation',
  false,
  'Chloe Barrington',
  '14-year-old female',
  ARRAY['None Recorded'],
  ARRAY['Not currently on any regular medication','No Known Drug Allergy'],
  NULL,
  'Caller: Karen Barrington (Patient''s stepmother) on the phone to speak with you.',
  'Hello doctor, Chloe has been having really heavy periods and I would like to get some help for her.',
  'Chloe has been having heavy and painful periods since she first started her periods at the age of 10, and it has not improved.',
  ARRAY['Chloe knows that I am calling the GP today, and her father is aware too.','She is not currently on her period. Her last period was about 1 week ago, and the bleeding usually lasts around 4 days with a regular 28-day cycle. During her periods she uses Tampax Super Plus and Ultra absorbency products — the highest absorbency available — but despite this she goes through them very quickly, sometimes using up to 5 to 6 per day.','You are not sure whether she passes clots.','She always has significant crampy pain in her lower tummy during her periods. She has tried ibuprofen and paracetamol, but these have not helped.','Sometimes the pain is so severe that she misses school during the first 2 days of her periods.','She is not in a romantic relationship and is not sexually active as far as you are aware. She tends to confide in you.','Her biological mother passed away 6 years ago following a road traffic accident. She is currently in school. Her diet is reasonable. She enjoys playing netball and attends training every weekend.'],
  'She does not smoke, drink alcohol, or use illicit drugs. She lives at home with you, her biological father, and her half-brother and half-sister.',
  'You think she has heavy and painful periods.',
  'You are worried because her symptoms seem to be getting worse and you want help for her.',
  'You would like the GP to offer treatment and support.',
  ARRAY['If the doctor suggests contraception, explain that you had similar symptoms when you were younger and found contraception helpful, but you are unsure whether this would be appropriate for Chloe as she is not sexually active.'],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Clarify consent or parental responsibility to discuss the patient (for example: "Thank you for taking the time to call. Just to check — is Chloe aware you are calling today and happy for us to discuss her symptoms? And could you confirm your relationship to her and whether you have parental responsibility?")','Ask about the history of heavy periods, including onset, duration, and whether symptoms are worsening.','Ask about menarche, last menstrual period, cycle length, duration of bleeding, and whether there is any bleeding between periods.','Ask about how heavy the flow is, including number of pads or tampons used and presence of clots.','Ask about associated lower abdominal or pelvic pain.','Ask about any abnormal vaginal discharge or urinary symptoms.','Ask about symptoms of anaemia, including dizziness, palpitations, shortness of breath, or tiredness.','Ask about sexual history sensitively, including whether she is sexually active.','Ask about social history, including smoking, alcohol use, illicit drug use, home situation, and school attendance.','Ask about family history of heavy periods or bleeding disorders.','Ask about the impact on quality of life, including school attendance, sports, and social activities.','Ask what she has tried so far to manage her symptoms.','Explore the stepmother''s ideas, concerns, and expectations.','Make a working diagnosis of primary dysmenorrhoea with menorrhagia.'],
  ARRAY['Offer a face-to-face appointment to assess the patient, including observations and abdominal examination. Note: As the patient has never been sexually active, a bimanual or speculum examination is not indicated at this stage. The likelihood of pelvic inflammatory disease or cervical pathology is low, and findings are unlikely to alter management. Additionally, these examinations can be uncomfortable and invasive in this group. If there is concern regarding underlying pathology such as fibroids, a transabdominal pelvic ultrasound scan should be considered as a first-line, non-invasive investigation.','Offer blood tests, including full blood count, to check for anaemia.','Offer medical management, including tranexamic acid with or without mefenamic acid or other NSAIDs during periods.','Discuss hormonal options if symptoms are not controlled, including the combined oral contraceptive pill, explaining that this is commonly used for regulating periods and reducing pain and bleeding, not just for contraception.','Offer written information or leaflets for both the patient and her stepmother to review before the appointment, so they can consider which options may suit her best.','Advise lifestyle measures, including maintaining a healthy diet, adequate hydration, and regular exercise.','Provide safety-netting by advising that if she develops symptoms such as dizziness, palpitations, shortness of breath, or extreme tiredness, she should contact the GP urgently or NHS 111 if out of hours, as this may indicate significant blood loss.'],
  'Thank you so much for calling today, and thank you for looking out for Chloe in this way. I can hear how concerned you are, and it is really important that you have reached out. This sounds like it has been going on for a long time and is having a real impact on her life — missing school during her periods is something we absolutely want to address.

From what you have described, Chloe''s symptoms — heavy, painful periods since she first started menstruating at the age of 10 — sound like what we call primary dysmenorrhoea with heavy menstrual bleeding. This is actually quite common in young people, particularly in the years after periods first begin. It happens because of the way the body produces certain hormones called prostaglandins during the menstrual cycle, which cause the womb to contract strongly and can lead to significant cramping and heavier bleeding. It does not mean anything is seriously wrong, but it is something that can and should be treated.

The next step I would like to take is to arrange a face-to-face appointment for Chloe so we can assess her properly — check her observations and carry out a gentle abdominal examination. At this stage, because she has not been sexually active, we would not need to perform any internal examinations, and a simple transabdominal ultrasound scan could be considered if we wanted to look at the womb from the outside. I would also like to take some blood tests to check whether the heavy periods have caused any anaemia, as that could be adding to her tiredness.

In terms of treatment, there are some very helpful options available. We can start with medications taken during her period, such as tranexamic acid, which reduces the amount of bleeding, and mefenamic acid, which is an anti-inflammatory that can help with both the pain and the heaviness. These are taken only during the days of her period. If these are not enough, there is also the option of the combined oral contraceptive pill — I want to be clear that this is used very commonly for regulating periods and reducing pain and bleeding, and is not only for contraception. I can provide some information leaflets for both you and Chloe to read through before the appointment so you can both think about what feels right.

If at any point Chloe becomes very tired, dizzy, short of breath, or notices her heart racing, please do not wait — contact us urgently or call NHS 111 if we are closed, as these symptoms could indicate she has lost a significant amount of blood and needs prompt attention.',
  ARRAY['Primary dysmenorrhoea is the most likely diagnosis when painful, heavy periods begin within the first few years after menarche without an identifiable cause — it is mediated by prostaglandin-driven uterine contractions.','In adolescents who have never been sexually active, bimanual and speculum examination are not indicated as first-line assessment; transabdominal pelvic ultrasound is the appropriate investigation if structural pathology is suspected.','First-line medical management includes tranexamic acid (to reduce blood loss) and mefenamic acid or other NSAIDs (for pain and bleeding), taken during menstruation.','The combined oral contraceptive pill is an effective hormonal option for regulating periods and reducing pain and bleeding in adolescents — its use is not confined to contraception.','Always confirm parental responsibility or the patient''s awareness of a third-party consultation before disclosing medical information.','Safety-netting: advise urgent contact with GP or NHS 111 if the patient develops dizziness, palpitations, breathlessness, or extreme fatigue, as these may indicate significant blood loss.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  240,
  'Persistent Menorrhagia Despite Treatment',
  'Gynaecology & Women''s Health',
  'Video Consultation',
  false,
  'Fiona Gallagher',
  '43-year-old female',
  ARRAY['Menorrhagia','Up to date with cervical smear'],
  ARRAY['Tranexamic acid 1 g three times a day for up to 4 days, to be started when menstruation begins','Mefenamic acid 500 mg three times a day','No Known Drug Allergy'],
  'Seen by Dr Chioma Philip (Clinical Practitioner role) - 6 months ago Presenting complaints: Patient reports recurrent heavy menstrual periods for the past year. The periods are slightly painful, but the pain is manageable and not a major concern to her. Recent investigations: Ultrasound scan done 1 week ago was normal with no identified cause. Cervical smear up to date and negative Sexually transmitted infection screen done through a sexual health clinic – negative Full blood count showed haemoglobin 122 g/L (normal). Normal thyroid function tests. Examination: Blood pressure 110/70 mmHg, pulse 75 bpm Pregnancy test negative. Urinalysis negative Speculum examination: No abnormalities seen Pelvic and bimanual examination: Normal Impression: Menorrhagia Plan: Trial of tranexamic acid and mefenamic acid. Safety-netting advice given',
  'Patient has booked an urgent video consultation to discuss ongoing heavy periods.',
  'Hello doctor, my periods are very heavy and I really need something to stop them.',
  'Your periods have been heavy for the past 18 months. You have had scans, an STI screen, and a cervical smear, all of which were normal. You were told this can sometimes happen without a clear cause, but your symptoms are not improving.',
  ARRAY['You are currently on your period, which started yesterday, and it is heavy.','You have been taking tranexamic acid and mefenamic acid as prescribed, but they do not seem to be helping. Your periods last 5 to 6 days and occur every 30 days. They are regular. They can be painful at times, but the pain is manageable and not a concern for you.','You do not have any bleeding between periods. You are sexually active with your husband of 10 years.','You are not on any contraception. Your husband has had a vasectomy. You also took a pregnancy test 2 weeks ago, which was negative.','Your sister has also had similar symptoms, with heavy periods, and she is now 47 years old and still experiencing them.'],
  'You work as a theatre nurse. You do not smoke or drink alcohol. You live with your husband and 2 children.',
  'You are not sure what is causing this.',
  'You are travelling to Spain to attend a close friend''s wedding in 3 days'' time. You were planning to wear a cream dress and are worried about staining. You would like something to stop your period.',
  'You would like the GP to prescribe something to stop your periods.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Ask about the history of heavy periods, including onset, duration, and whether symptoms are worsening.','Ask about her menstrual history, including last menstrual period, cycle length, duration of bleeding, any intermenstrual bleeding, and possibility of pregnancy.','Ask about how heavy the flow is, including number of pads or tampons used and presence of clots.','Ask if she is using any contraception.','Ask about sexual history sensitively, including whether she is sexually active, any new partners, number of partners, history of sexually transmitted infections, and whether there is any postcoital bleeding.','Ask about associated lower abdominal or pelvic pain.','Ask about any abnormal vaginal discharge or urinary symptoms.','Ask about symptoms suggestive of perimenopause, including hot flushes, night sweats, or mood changes.','Ask about red flag symptoms, including unintentional weight loss, loss of appetite, and night sweats, to exclude possible malignancy.','Ask about symptoms of anaemia, including dizziness, palpitations, shortness of breath, or tiredness.','Ask about social history, including smoking, alcohol use, illicit drug use, and home situation.','Ask about family history of heavy periods, bleeding disorders, or gynaecological cancers.','Ask about the impact on quality of life, including work, social activities, and daily functioning.','Ask what she has tried so far to manage her symptoms and response to treatment.','Explore her ideas, concerns, and expectations.','Make a working diagnosis of heavy menstrual bleeding, likely dysfunctional uterine bleeding.'],
  ARRAY['Offer repeat blood tests, including full blood count, to reassess for anaemia given ongoing bleeding.','Offer short-term treatment with norethisterone 5 mg three times a day for 10 days to help stop the bleeding. Explain that it may take up to 48 hours to reduce the bleeding.','Inform her about the rare risk of blood clots with norethisterone. Advise her to stay well hydrated and keep mobile, especially during travel, to reduce this risk.','Advise her on red flag symptoms of blood clots, including leg pain or swelling, chest pain, palpitations, shortness of breath, or coughing up blood, and to seek urgent medical attention if these occur.','Explain that once she returns from the wedding, it would be important to review long-term management options, including the levonorgestrel intrauterine system such as the Mirena coil, which can help control heavy periods.','Provide safety-netting by advising her to seek medical attention by contacting the GP practice urgently or NHS 111 if she develops symptoms such as dizziness, palpitations, shortness of breath, or extreme tiredness, which may indicate significant blood loss.','Offer follow-up after she returns from her trip to review symptoms and discuss ongoing management options.'],
  'Thank you for joining me on the video today. I can see from your notes that you have been dealing with very heavy periods for quite some time now, and I really do understand how distressing this must be — particularly with an important event coming up so soon.

You have already had a very thorough workup over the past six months: your pelvic ultrasound was normal, your cervical smear is up to date and clear, your STI screen was negative, and your thyroid function and initial blood count were both satisfactory. So we have ruled out many of the structural and hormonal causes of heavy bleeding. What you are most likely experiencing is what we call dysfunctional uterine bleeding — heavy periods that occur without an identifiable structural cause. This is actually one of the most common gynaecological presentations we see, and importantly, it is something we can manage.

Given that you are currently on your period and travelling to Spain in three days, I can understand why you need something to act quickly. I would like to offer you a short course of norethisterone 5 mg three times a day for 10 days. This is a progesterone-type tablet that works by temporarily stopping the period. I should mention that it may take up to 48 hours to fully reduce the bleeding, so starting it as soon as possible is important. It should then see you through your trip comfortably.

There is one thing I want to make you aware of: norethisterone carries a small but rare risk of blood clots. To reduce this risk, I would advise you to keep well hydrated and stay as mobile as possible during your flight and while travelling. If at any point you develop leg pain or swelling, chest pain, palpitations, shortness of breath, or cough up any blood, please seek urgent medical attention straight away.

I also want to arrange an updated full blood count, as ongoing heavy bleeding can sometimes cause anaemia over time, and it would be good to know where your haemoglobin levels are now.

When you return from your trip, Fiona, I would really like to sit down with you and talk through the longer-term options. One of the most effective treatments we have for heavy periods is the levonorgestrel intrauterine system — commonly known as the Mirena coil. It is a small device placed inside the womb and it can dramatically reduce or even stop periods altogether in most women. It is well tolerated, lasts for several years, and is considered one of the most effective long-term treatments for heavy menstrual bleeding. We can discuss this properly when you are back.

In the meantime, if your bleeding becomes very heavy, you feel dizzy, breathless, notice your heart racing, or feel extremely tired, please contact us urgently or call NHS 111 rather than waiting.',
  ARRAY['Norethisterone 5 mg three times a day for 10 days is an appropriate short-term option to stop heavy menstrual bleeding before an important event; patients should be warned it may take up to 48 hours to take effect.','Norethisterone carries a rare but recognised risk of venous thromboembolism — counsel patients to stay mobile and well hydrated during travel and to seek urgent help if symptoms of VTE develop.','The levonorgestrel intrauterine system (Mirena coil) is first-line long-term management for heavy menstrual bleeding and should be discussed as part of follow-up planning after short-term measures.','Heavy menstrual bleeding that persists despite tranexamic acid and mefenamic acid warrants reassessment, including a repeat full blood count to check for anaemia and reconsideration of management options.','Dysfunctional uterine bleeding is a diagnosis of exclusion — confirmed after structural causes (fibroids, polyps, malignancy), infection, thyroid disease, and coagulopathy have been ruled out.','Safety-netting for menorrhagia: advise urgent review if dizziness, palpitations, breathlessness, or extreme fatigue develop, as these may indicate haemodynamically significant blood loss.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  241,
  'Post-Partum Breast Pain',
  'Gynaecology & Women''s Health',
  'Video Consultation',
  false,
  'Rachel Hodgson',
  '27-year-old female',
  ARRAY['Vaginal delivery 6 days ago'],
  ARRAY['Not on any regular medication','No Known Drug Allergy'],
  NULL,
  'Patient has booked an urgent video consultation to discuss breast pain that has been worsening over the past couple of days.',
  'Hello doctor, I''ve got pain in my right breast and it''s been getting worse.',
  'Your right breast has been painful for the past 2 days. It feels warm to touch and the pain keeps getting worse.',
  ARRAY['The breast pain is a constant dull ache affecting only your right breast. The left breast feels completely fine.','You had a temperature last night of 38 degrees Celsius. You''ve noticed a red patch on your right breast, starting near the nipple and spreading towards the upper part of the breast.','You haven''t noticed any lumps or rashes. You have been taking paracetamol but it hasn''t helped much.','You gave birth 6 days ago via vaginal delivery and everything went smoothly. Your baby, Sophie, is well and has no problems feeding or with her mouth. You are both breastfeeding and topping up with formula.'],
  'You live with your partner and your mum, who has been helping out since the birth. You feel very well supported at home. You are currently on maternity leave. You do not smoke, drink alcohol, or use illicit drugs.',
  'You''re not sure what''s causing it, but your mum mentioned it might be something that happens after having a baby.',
  'You''re worried about whether it''s safe to carry on breastfeeding.',
  'You''d like the doctor to tell you what''s going on and what to do next.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Ask if the symptoms are affecting one breast or both breasts.','Ask about the onset and progression of the breast pain, including whether it is getting better, worse, or staying the same.','Ask her to describe the pain and specifically ask about deep burning pain, as this may suggest ductal infection and may require milk culture.','Ask about the location of the pain and whether it is in one area or the whole breast.','Ask about associated symptoms such as redness, warmth, swelling, areas of hardness, or any lumps.','Ask about nipple discharge or nipple changes, including cracks or bleeding.','Ask about systemic symptoms including fever, chills, or feeling generally unwell.','Ask if she is breastfeeding. If yes, ask about any difficulties such as poor infant attachment or latching problems.','Ask about predisposing factors such as eczema, trauma, use of tight bras, feeding from one breast only, or mixed feeding.','Ask about red flag symptoms for breast cancer, including lumps in the armpit, unintentional weight loss, or night sweats.','Ask about medication use, including what analgesia has been taken so far.','Ask about social history, including smoking, alcohol use, illicit drug use, how she is coping at home, how the baby is doing, whether the baby is feeding and growing well, any fever in the baby, and any whitish coating on the baby''s tongue suggestive of oral thrush.','Explore her ideas, concerns, and expectations.','Make a diagnosis of lactational mastitis.'],
  ARRAY['Offer a face-to-face appointment to examine the breast and rule out an abscess that may require drainage.','Advise her that as her symptoms have worsened over the last 24 hours, antibiotics are indicated. Prescribe flucloxacillin 500 mg four times daily for 10 days. Reassure her that this is safe during breastfeeding and check for any allergies.','Advise that she can use ibuprofen for pain relief if there are no contraindications.','Advise her to continue breastfeeding from the affected breast if she is able, as this helps with recovery. If breastfeeding is too painful or the baby refuses to feed, advise her to hand express milk to maintain supply until she can resume breastfeeding.','If the nipple is cracked or painful, advise expressing milk from that breast until it heals.','Reassure her that it is safe to continue breastfeeding. The infection does not pass to the baby through breast milk, and breast milk contains protective factors that help the baby fight infections.','Advise her to rest and wear a well-fitting, supportive bra.','Offer to send leaflets and videos on breastfeeding techniques. If she continues to have difficulty, offer referral to a midwife or breastfeeding specialist for further support.','Provide safety-netting by advising her to seek urgent medical attention by contacting the GP surgery or NHS 111 out of hours if symptoms worsen, if she develops rigors, chills, a fast heart rate, feels increasingly unwell, or if there is no improvement within 48 hours of starting antibiotics.','Follow up in 10 days after completion of antibiotics.'],
  'It sounds like you''ve had quite an uncomfortable few days, Rachel, and I''m really glad you called in today. Breast pain in the first week or two after giving birth is something we take seriously, and based on what you''ve described — the redness spreading from around the nipple, the warmth, the worsening pain, and the fever you had overnight — this is looking very much like lactational mastitis. This is an infection of the breast tissue that can happen in breastfeeding mothers, usually when milk becomes blocked or bacteria enter through a cracked nipple.\n\nThe good news is that this is very treatable, and catching it early is exactly what we want to do. Because your symptoms have been getting worse over the past day or so, I do want to start you on a course of antibiotics. I''m going to prescribe flucloxacillin 500 mg, taken four times a day for 10 days. This antibiotic is safe to take while breastfeeding, so there''s no need to stop feeding Sophie. Before I send it through, can I just double-check whether you have any known allergies to antibiotics?\n\nI''d also like to see you in person — ideally today or tomorrow — so that we can examine the breast properly and make sure there isn''t a collection of fluid called an abscess forming underneath. An abscess sometimes needs to be drained and is something we''d want to pick up quickly.\n\nIn the meantime, please do continue feeding from the affected breast if you''re able to. I know that might sound counterintuitive when it''s painful, but keeping the milk moving is one of the most important things you can do to help the infection settle. The infection doesn''t pass to Sophie through your breast milk, and your milk actually contains antibodies that help protect her. If feeding becomes too painful or Sophie won''t latch on that side, hand expressing is a great alternative to keep the milk flowing until things improve.\n\nFor pain relief, paracetamol hasn''t been doing much for you, so I''d suggest trying ibuprofen as well — provided there''s no reason you can''t take it. It works as both a painkiller and an anti-inflammatory, which should help with the heat and swelling. Wearing a well-fitting, supportive bra and resting as much as you can — easier said than done with a newborn, I know — will also help.\n\nIf at any point over the next 48 hours things get worse rather than better — if you start shivering uncontrollably, develop a racing heart, feel very unwell, or there''s still no improvement after two days on the antibiotics — I''d like you to contact us again or call NHS 111 out of hours straight away. We''ll check in with you once you''ve finished the course of antibiotics in 10 days, but please don''t hesitate to get in touch sooner if you need to. You''re doing a brilliant job.',
  ARRAY['Lactational mastitis presents with unilateral breast pain, redness, warmth, and systemic symptoms such as fever in the postpartum period — it is the most likely diagnosis when these features occur within the first few weeks of breastfeeding.','Flucloxacillin 500 mg four times daily for 10 days is the first-line antibiotic for lactational mastitis; always check for penicillin allergy before prescribing.','Mothers should be advised to continue breastfeeding from the affected breast where possible — cessation of feeding can worsen milk stasis and increase the risk of abscess formation.','A face-to-face appointment is important to examine the breast and exclude an abscess, which would require surgical drainage.','Ibuprofen is a useful adjunct for pain relief and has anti-inflammatory properties particularly suited to mastitis; paracetamol alone is often insufficient.','Safety-netting is essential: advise the patient to seek urgent review if symptoms worsen, she develops rigors or feels very unwell, or there is no improvement within 48 hours of starting antibiotics.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  242,
  'Confidentiality in a Third-Party Query',
  'Ethics',
  'Telephone Consultation',
  false,
  'Dorothy Ashworth',
  '72-year-old female',
  ARRAY['Chronic Glaucoma','Hypertension'],
  ARRAY['Amlodipine 5 mg once daily','Latanoprost one drop once daily in both eyes','Allergic to penicillin'],
  'Letter from St. James''s Eye Unit – 4 weeks ago Re: Mrs Dorothy Ashworth | Age: 72-year-old female Dear Colleague, Mrs Dorothy Ashworth was seen in our clinic for assessment following an optometry referral due to raised intraocular pressure and suspected glaucoma. She remains asymptomatic in both eyes, with no reported visual disturbance, pain, or reduction in vision. On examination: (left eye) glaucomatous optic neuropathy. Based on the above findings, a diagnosis of chronic open-angle glaucoma has been made. She has been commenced on Latanoprost eye drops, to be used once daily at night. She has been advised to inform the Driver and Vehicle Licensing Agency (DVLA) of her diagnosis, and they will determine whether it is safe for her to continue driving. We will review her again in three months'' time to monitor her intraocular pressure and disease progression. Please do not hesitate to contact us if there are any concerns. Yours sincerely, Dr Priya Mehta, MBBS, FRCOphth, Consultant Ophthalmologist',
  'A telephone appointment has been booked by the patient''s daughter to discuss concerns about her mother.',
  'Hello doctor, I''d like to discuss some worries I have about my mum, if that''s alright.',
  'You noticed that your mum was given new eye drops. She used them for about 4 or 5 days and then stopped. You want to know what the drops are for, whether they are important, and if she has glaucoma, because she is no longer using them. You came across the medication online and think it might be used for glaucoma.',
  ARRAY['Your mum doesn''t know you''re calling, and she would be upset if she found out. She hasn''t given you permission to talk about her health, and you don''t have lasting power of attorney.','She told you the drops caused a stinging sensation in both eyes, which is why she stopped. You know the drops might be important for her eyes.','She hasn''t mentioned any problems with her vision and still seems to see well. However, you''ve noticed she hasn''t been driving recently. She mentioned she is waiting to hear back from the DVLA — ask the doctor whether this could be connected to the glaucoma.'],
  'She lives alone and manages all her daily activities independently, including shopping, cooking, and keeping the house. She doesn''t smoke or drink alcohol.',
  'You think she may have glaucoma based on what you found when you looked it up online.',
  'You''re worried that she has stopped taking her medication.',
  'You''d like the GP to tell you what condition she has and what you can do to help her take her medication.',
  ARRAY['If the doctor offers to contact your mother and let her know you called, say you''d prefer she didn''t know you discussed this. However, you''re happy to speak to her yourself and encourage her to contact the GP about her eye drops.'],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered to you by the doctor.',
  ARRAY['Clarify whether she has consent to discuss her mother''s medical information or has lasting power of attorney.','Acknowledge the daughter''s concern and explain confidentiality, including that you may not be able to share specific medical details without her mother''s consent.','Ask what she already understands about her mother''s condition.','Ask what she has noticed about her mother''s symptoms, including any changes in vision, eye pain, itching, swelling, photophobia, redness, headache, or difficulty carrying out daily activities.','Ask if she knows the reason her mother stopped using the eye drops.','Ask about any side effects from the eye drops, such as stinging, dry eyes, or eye colour changes.','Ask about any concerns regarding her mother''s memory or changes in behaviour that may affect her ability to manage medications independently.','Ask about the mother''s social history, including home situation, who she lives with, level of independence, smoking, alcohol use, and whether she is currently driving.','Explore the daughter''s ideas, concerns, and expectations.'],
  ARRAY['Acknowledge the daughter''s concerns and thank her for raising them.','Explain that as she does not have consent from her mother, you are unable to disclose the diagnosis or specific reasons for the prescribed eye drops.','Provide general information, explaining that eye drops like these are important in managing eye conditions and preventing long-term complications, and that stopping them without an alternative treatment may lead to worsening of the condition.','Encourage her to speak with her mother to book an appointment with the GP to discuss her concerns and side effects. Explain that you can liaise with the ophthalmology team through advice and guidance if needed.','Reassure her that if her mother is experiencing side effects, there may be alternative treatments available, and this can be reviewed.','Inform the daughter that, if she is happy for you to do so, you can contact her mother directly to share the concerns she has raised and speak with her about this.','Provide safety-netting by advising her to inform her mother that if she develops symptoms such as red eye, headache, or blurred vision, she should seek urgent medical attention by contacting the GP or NHS 111 if out of hours.'],
  'Thank you for calling today — it''s clear that you care a great deal about your mum''s health and wellbeing, and I really appreciate you raising these concerns. Before we go any further, I need to explain something important about how we handle patient information. As your mother''s GP, I have a duty of confidentiality to her, which means I''m not able to share specific details about her diagnosis or treatment without her permission. I hope you understand that this rule exists to protect all of our patients, including your mum.\n\nWhat I can tell you in general terms is that eye drops of the type you''ve described are often prescribed to manage conditions affecting the pressure inside the eye, and they play an important role in preventing long-term damage to vision. Stopping them without discussing an alternative with a doctor can sometimes allow the underlying condition to worsen over time. I can hear that this is something you''re understandably worried about.\n\nIt''s also worth knowing that stinging or discomfort when first starting eye drops is quite common, and in many cases it does settle after a few weeks. If it doesn''t, there are usually alternatives that can be tried. The important thing is that your mum is able to have that conversation with us directly so we can find a solution that works for her.\n\nThe most helpful next step would be for your mum to get in touch with us and book an appointment. We could then review the drops together with her, talk through any side effects she''s been experiencing, and make sure she has a treatment plan she''s comfortable with. If you''re able to encourage her to do that, it would be really valuable.\n\nIf you''re happy for me to do so, I could also contact your mum directly — I could let her know that someone close to her is concerned and invite her to come in and speak with us. That way, I wouldn''t need to mention who called. Would that feel like a helpful option, or would you prefer to speak to her yourself first?\n\nFinally, if at any point you notice that your mum develops any new symptoms — such as a red eye, a headache, or any change in her vision — please encourage her to contact us promptly, or call NHS 111 if it''s outside of normal surgery hours. We want to make sure she stays well.',
  ARRAY['When a third party contacts the GP about a patient, confidentiality must be maintained — specific clinical information cannot be disclosed without the patient''s consent or a legal authority such as lasting power of attorney.','General information can be shared (e.g. the importance of eye drops for managing eye conditions) without breaching confidentiality, as long as no specific diagnosis or treatment details are revealed.','The GP can offer to contact the patient directly to raise concerns without revealing who called, which balances confidentiality with patient safety.','Always clarify early in the consultation whether the caller has consent or lasting power of attorney, as this determines how much information can be shared.','Medication side effects (such as stinging with Latanoprost) are a common reason for non-adherence — alternatives should be explored rather than simply advising the patient to persevere.','Safety-netting is still relevant in third-party calls — advise the caller to encourage the patient to seek urgent help if symptoms such as red eye, headache, or visual disturbance develop.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  243,
  'Headache and Request for Antibiotics',
  'Neurology',
  'Video Consultation',
  false,
  'Gemma Sutton',
  '28-year-old female',
  ARRAY['None recorded'],
  ARRAY['Nexplanon (inserted 1 year ago)','No Known Drug Allergy'],
  NULL,
  'Patient has booked an urgent video consultation to discuss persistent headaches and is requesting antibiotics.',
  'Hello doctor, I think I''ve got sinusitis and I''d like some antibiotics please.',
  'You''ve been getting headaches at the front of your head for the past 10 days. A colleague at work had exactly the same thing and was told it was sinusitis and given antibiotics, so you think that''s probably what this is.',
  ARRAY['You had a runny nose about 2 weeks ago, which has now completely cleared up. But the headaches have carried on. The pain goes across your whole forehead, feels like a tight band around your head, and comes and goes throughout the day. There''s no nausea or vomiting.','You don''t have any facial pain, blocked nose, runny nose, or fever. No blurred vision either.','You''ve tried paracetamol but it hasn''t really helped.','Your last menstrual period was about a week ago.'],
  'You work as an estate agent and started a new job about 2 months ago. It''s been quite demanding getting to grips with everything but you''re enjoying it. You live with your boyfriend. You don''t smoke, drink alcohol, or use illicit drugs.',
  'You think you have sinusitis.',
  'You''re worried about sinusitis.',
  'You''d like the doctor to prescribe antibiotics. If the doctor asks about time off work, explain that you can''t really take any time off at the moment as you''re still settling in to your new role.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Ask about the onset, location, character, and progression of the headache.','Ask about associated symptoms including nausea, vomiting, and photophobia.','Ask about symptoms of sinusitis, including nasal congestion, facial pain or pressure, reduced sense of smell, fever, recent flu-like illness, or purulent nasal discharge.','Ask about triggers for the headache, including recent stress, caffeine intake, missed meals, or dehydration.','Ask about red flag symptoms, including visual changes, neck stiffness, confusion, rash, recent head trauma, or focal neurological symptoms such as weakness, tingling, or slurred speech.','Ask about medication use, including analgesia taken, frequency, and response.','Ask about menstrual history and any relation of headaches to the menstrual cycle.','Ask about any past history of similar headaches.','Ask about the severity of pain and its impact on daily activities.','Ask about social history, including alcohol use, smoking, and illicit drug use.','Explore the patient''s ideas, concerns, and expectations.','Make a working diagnosis of tension-type headache.'],
  ARRAY['Acknowledge her symptoms and explain that her symptoms are not typical of sinusitis and are more in keeping with a tension-type headache.','Advise her to keep a symptom diary to help identify potential triggers.','Advise that she can take ibuprofen 400 mg three times daily for pain relief, which can be taken alongside paracetamol if needed. Inform her that it is available over the counter, and advise her about possible side effects such as stomach upset, recommending that she takes it with or after food.','Discuss the role of stress as a contributing factor and advise strategies to manage this, such as regular exercise, yoga, and mindfulness.','Advise reducing screen time where possible, as eye strain can contribute to headaches.','Encourage her to speak with her workplace about workload and support, and discuss the possibility of adjustments or time off if needed.','Provide safety-netting by advising her to seek medical attention by contacting the GP surgery or NHS 111 if out of hours if headaches worsen, become persistent, or if she develops red flag symptoms such as visual changes, vomiting, neurological symptoms, or fever.','Arrange follow-up in 4 weeks to review her symptoms and progress.'],
  'I can hear that these headaches have been really persistent and frustrating, especially when you''re trying to get settled into a new job. I''m glad you came in today so we can get to the bottom of what''s going on, Gemma. Having looked at everything you''ve described, I don''t think this is actually sinusitis. The symptoms that would point towards sinusitis — things like facial pain or pressure, a blocked nose, thick nasal discharge, or a fever — aren''t really present here. The runny nose you had a fortnight ago sounds more like a viral cold that has since cleared up.\n\nWhat your headaches are actually sounding more like is something called a tension-type headache. This is one of the most common types of headache, and the way you''ve described it — a tight band across the whole forehead, coming and going, without nausea or visual changes — fits this pattern really well. Tension headaches are often triggered or made worse by stress, tiredness, too much screen time, or changes to your routine, all of which can come with starting a new job.\n\nBecause of this, antibiotics wouldn''t actually be the right treatment here — they work against bacterial infections, and a tension headache isn''t caused by an infection. What I''d suggest instead is trying ibuprofen 400 mg three times a day with or after food, as this can be more effective for this type of headache than paracetamol alone, and the two can be taken together if needed. You can pick this up over the counter. Just be aware it can occasionally cause some stomach discomfort, so taking it with food is a good idea.\n\nI''d also encourage you to keep a simple headache diary — just jotting down when the headaches happen, how long they last, and what you were doing beforehand. This can be really useful for spotting patterns and identifying any triggers. Things like staying well hydrated, eating regular meals, taking proper breaks from screens, and getting some fresh air and exercise can all make a real difference.\n\nI understand that taking time off isn''t an option right now, but it might be worth having a quiet word with your manager about workload — not necessarily about taking leave, but just to make sure you have enough support while you''re finding your feet. Stress is a very real factor in tension headaches.\n\nIf the headaches get worse rather than better, become very severe, or you develop anything new — such as visual changes, vomiting, neck stiffness, or any neurological symptoms like tingling or weakness — please don''t wait: contact us straight away or call NHS 111 if it''s outside hours. Otherwise, let''s arrange a follow-up in about four weeks to see how you''re getting on.',
  ARRAY['Tension-type headache is characterised by a bilateral, band-like pressure or tightening sensation without nausea or photophobia — it is the most common headache type and should not be confused with sinusitis.','Sinusitis requires features such as facial pain or pressure, purulent nasal discharge, nasal congestion, and often fever — a preceding cold without these ongoing features does not indicate bacterial sinusitis.','Antibiotics are not indicated for tension-type headache; ibuprofen 400 mg three times daily (taken with food) is an appropriate first-line analgesic, and can be combined with paracetamol.','Red flag headache features requiring urgent review include sudden-onset severe headache, progressive worsening, focal neurological symptoms, neck stiffness, fever, or headache with visual disturbance.','Stress, poor sleep, dehydration, and excessive screen time are common modifiable triggers for tension-type headache and should be explored and addressed.','A headache diary is a useful tool to identify triggers and monitor progression, and follow-up should be arranged to reassess if symptoms do not improve.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  244,
  'Suspected Drug Reaction in a Patient with Gout',
  'Dermatology',
  'Telephone Consultation',
  false,
  'Philip Hartley',
  '58-year-old male',
  ARRAY['Gout'],
  ARRAY['Allopurinol 100 mg once daily','No Known Drug Allergy'],
  'Telephone consultation with Dr Sarah Whitmore (Clinical Practitioner role) - 10 days ago. Presenting complaint: Patient booked this appointment to discuss urate-lowering therapy. Last urate level 1 week ago: 392 micromol/L. We discussed the benefits of starting allopurinol, and the patient is willing to proceed. He understands the potential side effects, including the risk of allopurinol precipitating a gout flare. Colchicine prophylaxis was offered, but the patient prefers not to take additional medication and is happy to start allopurinol, with a plan to use acute treatment if a flare occurs. Plan: Start allopurinol 100 mg once daily. Repeat urate levels in 4 weeks time.',
  'Patient has booked an urgent telephone consultation and has sent a photograph of a rash to be reviewed.',
  'Hello doctor, have you had a chance to look at the photo of the rash I sent through?',
  'You noticed the rash started about 2 days ago. It began on your stomach and has spread to your neck, both arms and your back. It''s very itchy and is disturbing your sleep.',
  ARRAY['The rashes are flat and red.','You haven''t been in contact with anyone with a similar rash. You don''t have a fever, and there are no rashes on your palms, mouth, face, genitals, or legs.','You don''t have any shortness of breath or facial swelling.','You''re still taking the allopurinol and took it again this morning.','You are not taking any other medications.'],
  'You don''t smoke, don''t drink alcohol, and don''t use illicit drugs. You work as a financial adviser and live with your wife.',
  'You think the rash might be caused by allopurinol, as you read about this in the information leaflet that came with the medication.',
  'The rash is extremely itchy and is stopping you from sleeping properly.',
  'You''d like the GP to prescribe something to help.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Ask about the onset and progression of the rash, including when it started and how quickly it has spread.','Ask about the appearance of the rash, including whether it is raised, flat, blotchy, or blistering.','Ask if the skin is dry and whether there is any discharge from the rash.','Ask about associated symptoms such as itching, pain, or burning.','Ask about symptoms suggestive of anaphylaxis or angioedema, including facial swelling, lip or tongue swelling, shortness of breath, or wheeze.','Ask about symptoms suggestive of Stevens-Johnson syndrome, including mouth ulcers, genital sores, blisters, skin peeling, fever, palpitations, or feeling generally unwell.','Ask whether the rash involves the palms or soles.','Ask about any recent flu-like illness, sore throat, or diarrhoea to rule out a viral rash such as measles.','Ask if the rash started after initiating allopurinol and whether he is taking any over-the-counter medications.','Ask about any new soaps, creams, detergents, foods, or other possible allergens.','Ask about contact with anyone with a similar rash.','Ask about the impact on sleep and daily activities.','Ask about social history, including smoking, alcohol use, and illicit drug use.','Explore the patient''s ideas, concerns, and expectations.','Make a working diagnosis of likely allopurinol-induced maculopapular drug rash.'],
  ARRAY['Advise the patient to stop allopurinol immediately.','Offer a non-sedating antihistamine such as cetirizine. Inform him that although it is generally non-drowsy, it can occasionally cause mild drowsiness, and advise him not to drive or operate machinery if he feels drowsy.','Offer a topical emollient to soothe the skin (for example, Epimax or Oilatum cream for moist skin, or Cetraben or Diprobase ointment for dry skin).','Consider adding a topical steroid, such as a mild to moderate potency steroid, if symptoms are not controlled with emollients alone.','Advise that once the rash has settled, alternative urate-lowering therapy can be considered, such as febuxostat.','Inform him that you will document allopurinol as a drug allergy in his records and advise him to avoid it in the future.','Provide safety-netting and advise that if the rash worsens, or if he develops blistering, fever, mouth ulcers, facial or tongue swelling, or difficulty breathing, he should call 999 or attend A&E urgently.','Arrange follow-up in 2 weeks to ensure the rash has settled and to discuss alternative urate-lowering therapy.'],
  'Thank you for sending that photograph through — it''s been really helpful to see. Based on what you''ve described, with the rash starting on your stomach and spreading to your neck, arms, and back over the past two days, and given the timing in relation to when you started allopurinol, this does look very much like a drug rash caused by allopurinol. This is a known side effect and something we take seriously, so I''m glad you got in touch promptly.\n\nThe most important thing right now is that you stop taking allopurinol straight away — please don''t take any more doses. I''ll be adding allopurinol to your medical records as a drug allergy, so that it is flagged in future and you won''t be prescribed it again. You mentioned in the leaflet that you''d read about this possibility, and you were absolutely right to make that connection.\n\nTo help with the itching, I''m going to prescribe cetirizine, which is a non-sedating antihistamine. It shouldn''t make you drowsy, though in a small number of people it can cause mild sleepiness, so please avoid driving or using machinery if you feel any of that. For the skin itself, I''d also like to suggest a moisturising emollient — something like Oilatum or Epimax cream — which can help soothe and settle the irritation. If the itching isn''t controlled with those alone, we may consider adding a mild to moderate topical steroid cream as well.\n\nOnce the rash has fully settled down, we''ll need to revisit the question of managing your gout. There is an alternative urate-lowering medication called febuxostat, which works in a similar way to allopurinol but through a different mechanism, and this would be something we can discuss at your follow-up. We''ll aim to bring you back in about two weeks to check that the rash has cleared.\n\nFinally, and this is very important: if at any point the rash gets significantly worse, you develop any blistering, peeling of the skin, ulcers in your mouth, swelling of your face, lips, or tongue, or you have any difficulty breathing, please do not wait — call 999 or go straight to A&E. These could be signs of a more serious reaction that requires emergency treatment. I don''t expect that to happen, but I want to make sure you know what to watch out for.',
  ARRAY['A maculopapular rash appearing within weeks of starting allopurinol should be treated as an allopurinol-induced drug reaction until proven otherwise — allopurinol must be stopped immediately.','Always ask specifically about features of Stevens-Johnson syndrome (mouth ulcers, genital sores, blistering, skin peeling, fever) and anaphylaxis (facial swelling, breathing difficulty) when assessing a drug rash, as these require emergency management.','Cetirizine is a suitable non-sedating antihistamine for drug rash; topical emollients and mild to moderate topical steroids can also be used for symptom control.','Allopurinol should be documented as a drug allergy in the patient''s medical record and the patient advised to avoid it permanently.','Febuxostat is an appropriate alternative urate-lowering therapy for patients who cannot tolerate allopurinol.','Safety-netting is critical: patients must be advised to call 999 or attend A&E immediately if they develop blistering, peeling, mouth ulcers, facial swelling, or difficulty breathing.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  245,
  'Anxiety About Dying in a Palliative Patient',
  'Elderly Medicine & Palliative Care',
  'Telephone Consultation',
  false,
  'Carolyn Barrett',
  '62-year-old female',
  ARRAY['Metastatic Breast Cancer','Has DNACPR in place'],
  ARRAY['Oramorph 10 mg/5 ml, 2.5 ml (5 mg) every 4 hours as required for pain','Senna 15 mg once daily','Laxido 2 sachets once daily','No Known Drug Allergy'],
  'Oncology letter – 4 weeks ago. Dear GP, Re: Carolyn Barrett, 62-year-old female. Thank you for your ongoing care of this patient. Mrs Barrett has a diagnosis of advanced breast cancer, which has now progressed with metastatic spread to the liver, bones, and brain. Despite receiving palliative chemotherapy and radiotherapy, unfortunately her disease has not responded to treatment and has continued to progress. Following careful discussion with Mrs Barrett, she is now considered to be in the palliative phase of her illness. She has been informed of her prognosis, which is estimated to be in the region of weeks to months, and she demonstrates a clear understanding of this. I would be grateful if you could liaise with the community palliative care team to ensure that appropriate support is in place. If you have any concerns or queries regarding her care, please do not hesitate to contact me. Yours sincerely, Dr Aisha Patel, Consultant Clinical Oncologist.',
  'Patient has booked a routine telephone consultation to discuss her emotional wellbeing following a recent visit from the district nursing team.',
  'Hello doctor, the district nurse suggested I give you a call.',
  'You recently had a visit from the district nurses as part of your community palliative care. During that visit, you mentioned that you''ve been feeling low and very anxious about dying, because you''re not sure when it will happen. You were told your prognosis is weeks to months, and the uncertainty is really getting to you. The nurse thought it would be helpful for you to speak with your GP.',
  ARRAY['Your mood has been low, and your mind keeps dwelling on thoughts about dying. This makes you feel very anxious and sometimes affects your sleep. These feelings started about 4 weeks ago after your last appointment with the oncologist.','What worries you most about dying is feeling out of control — particularly the fear of going to sleep one night and not waking up.','You are still managing to eat and drink. You do have generalised bone pain, but the Oramorph helps keep it under control. Your bowels are regular and you are passing urine normally.','You are not struggling to look after yourself, you have no financial difficulties, and you are managing well at home.'],
  'You live with your husband, who has been wonderfully supportive throughout everything. You don''t smoke, drink alcohol, or use illicit drugs.',
  'You''re not really sure why you feel this way — you thought you''d come to terms with your diagnosis, but lately the anxiety has crept back.',
  'You''re scared about dying.',
  'You''d like the GP to help you find ways to cope with how you''re feeling.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Acknowledge her concerns and explore her mood, including the onset, duration, and progression of low mood.','Ask about symptoms of depression, including poor sleep, low energy, reduced appetite, loss of interest, or reduced concentration.','Ask about symptoms of anxiety, including constant worry, restlessness, panic episodes, or physical symptoms such as palpitations.','Explore her thoughts about dying, including what specifically worries her and any fears about the process of dying. Note: common fears include loss of control, dying suddenly in their sleep, experiencing pain, becoming a burden to others, anxiety about leaving loved ones behind, or uncertainty about what happens during the dying process.','Ask sensitively about suicidal thoughts or thoughts of self-harm.','Ask about the impact of symptoms on daily functioning and quality of life.','Ask about other common palliative symptoms, including pain, constipation, nausea, vomiting, difficulty breathing, dry mouth, or headache.','Ask about support systems, including her husband, family, and community or palliative care team involvement.','Ask about social history, including home situation, finances, support at home, smoking, alcohol use, and illicit drug use.','Ask about any previous history of mental health problems.','Explore her ideas, concerns, and expectations.','Make a working diagnosis of adjustment disorder with low mood and anxiety.'],
  ARRAY['Acknowledge her feelings with empathy and validate her fears about dying.','Reassure her that what she is experiencing is understandable given her situation.','Offer clear explanation of the dying process to reduce uncertainty and fear. Inform her that as her condition progresses, people typically become gradually more tired and sleepy, and that this is usually a gentle and progressive process rather than something sudden or frightening.','Explain that to help her feel more in control, we can carry out advance care planning, which allows her to document her wishes and preferences for future care in case she is unable to make decisions later, ensuring that all care provided is in line with her preferences.','Offer referral for talking therapy with a psychologist experienced in palliative care. Explain that this can help her explore her thoughts, feel more in control, and manage her anxiety and low mood.','Explain that many people do well with talking therapy alone, but if her symptoms begin to significantly affect her, medication can be considered. Options include mirtazapine, which may help with sleep and mood, or an SSRI such as sertraline.','Offer another telephone consultation or home visit to discuss advance care planning. Also explain that we can prescribe "just in case" medications, which are used to manage common symptoms that may arise as her condition progresses.','Inform her that she may be eligible for additional support, including benefits. Explain that an SR1 form can be completed, and offer to liaise with a social prescriber to assist with this.','Provide her with the local palliative care emergency contact number for easy access to the district nurse or GP in case she has any concerns or worsening symptoms.','Provide safety-netting by advising her to seek help if her mood worsens, she develops thoughts of self-harm, or if her symptoms become overwhelming.','Arrange follow-up in 2 weeks to ensure she has appropriate support in place and to review any ongoing concerns.'],
  'Thank you so much for calling today. I can hear how much courage it takes to talk about these feelings, and I want you to know that everything you''re describing makes complete sense given what you''ve been through. Feeling anxious and low in the context of a life-limiting illness is not a sign of weakness — it is a very natural human response, and you are absolutely not alone in feeling this way.\n\nWhat you''ve described — the low mood, the difficulty sleeping, the mind returning again and again to thoughts about dying and what that will look like — sounds very much like what we call an adjustment disorder. This is where the emotional weight of a difficult situation begins to affect how we feel day to day. It does not mean you are not coping; it means that what you are facing is genuinely very hard.\n\nOne of the things that many people find most frightening is exactly what you''ve described — the uncertainty, and particularly the fear of losing control over what happens. I want to try and offer you a little reassurance about that. For most people, as their illness progresses, the process of dying is a gradual one. People tend to become more sleepy and tired over time, and it is generally a gentle, progressive process rather than something that happens suddenly and without warning. I hope that is a little comforting, even if it doesn''t take the fear away entirely.\n\nOne thing that can really help with that sense of control is something called advance care planning. This is where we sit down together — or I can arrange a home visit if that would be easier — and we write down your wishes for how you''d like to be cared for as things progress. This means that whatever happens, your preferences will be known and respected. We can also discuss prescribing what are called "just in case" medications in advance, which are kept at home so that if you develop any distressing symptoms, the district nurses can administer them quickly without any delay.\n\nI''d also very much like to refer you to a psychologist who specialises in working with people in your situation. Talking therapy of this kind has been shown to be really helpful for managing anxiety and low mood, and it can also give you more tools to feel in control of your thoughts. If at any point you feel that talking therapy alone isn''t enough, there are medications we can consider as well — for example, mirtazapine, which can help with both sleep and mood, or an SSRI such as sertraline.\n\nPlease do make use of the palliative care emergency contact number — the district nurses and the team around you are there precisely for moments like this. And I''d like to speak with you again in about two weeks to see how you''re getting on and make sure everything is in place. In the meantime, if your mood gets much worse or you have any thoughts of harming yourself, please reach out straight away.',
  ARRAY['Anxiety and low mood are common in palliative patients and most often represent an adjustment disorder — this should be explored with empathy and not dismissed as an inevitable part of dying.','Exploring specific fears about the dying process (e.g. loss of control, dying suddenly in sleep, pain) allows the GP to address these with targeted reassurance and practical information.','Advance care planning empowers patients by allowing them to document their wishes for future care, increasing their sense of control.','Talking therapy with a palliative care psychologist is the preferred first-line treatment for adjustment disorder; pharmacological options such as mirtazapine or sertraline can be added if symptoms are not controlled.','"Just in case" medications should be discussed proactively with palliative patients to allow rapid symptom management at home without delays.','The SR1 form can be completed for patients with a terminal diagnosis to enable access to benefits, and social prescribers can assist with this process.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  246,
  'Severe Unilateral Facial Pain',
  'Neurology',
  'Video Consultation',
  false,
  'Simon Warwick',
  '44-year-old male',
  ARRAY['None recorded'],
  ARRAY['Not on any current medication','No Known Drug Allergy'],
  NULL,
  'Patient has booked an urgent video consultation to discuss severe facial pain that has been ongoing for several weeks.',
  'Hello doctor, I''ve been having these headaches for about 4 weeks now and they''re really starting to get me down.',
  'The pain is on the left side of your face, around the temple area, and it''s not improving.',
  ARRAY['The pain is sharp and lasts about 2 minutes at a time, then goes away. You can have up to 15 or more of these attacks in a single day.','The pain spreads to your left cheek.','It''s noticeably worse in the morning, particularly when you''re washing your face, brushing your teeth, or sometimes when you''re eating. That''s what made you go to the dentist — but they checked your teeth thoroughly and said everything looked fine.','The pain is very severe. You''ve tried both paracetamol and ibuprofen but neither has made any difference.','You don''t have nausea or vomiting.'],
  'You don''t smoke, drink alcohol, or use illicit drugs. You live with your wife and three children. You work in finance and your job is fairly steady — not especially stressful.',
  'You think it might be some kind of migraine.',
  'The pain is making you anxious about eating, because you''re worried that chewing might set off another attack.',
  'You''d like the GP to help you get on top of this.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Ask about the onset, location, duration, character, and progression of the pain, including whether it is getting better, worse, or staying the same.','Ask if the pain radiates anywhere.','Ask about triggers such as touching the face, brushing teeth, chewing, speaking, or exposure to cold air.','Ask about any relieving factors.','Ask about associated neurological symptoms such as facial numbness, weakness, visual changes, or hearing problems.','Ask about sinus-related symptoms such as nasal congestion, runny nose, nasal discharge, facial pressure, or fever.','Ask about symptoms of migraine, including nausea, vomiting, photophobia, or aura.','Ask about dental symptoms or recent dental procedures.','Ask about any history of trauma or infection affecting the face.','Ask about red flag symptoms such as unintentional weight loss, night sweats, or loss of appetite to rule out malignancy.','Ask about social history, including smoking, alcohol use, and illicit drug use.','Ask about the impact of the pain on daily activities.','Explore the patient''s ideas, concerns, and expectations.','Make a working diagnosis of trigeminal neuralgia.'],
  ARRAY['Offer a face-to-face appointment to examine the cranial nerves of the face.','Offer treatment with carbamazepine, starting at 100 mg twice daily and titrating up as needed for symptom control.','Explain that carbamazepine is a medication commonly used for seizures but is also effective in treating nerve-related pain such as trigeminal neuralgia.','Arrange baseline blood tests before starting treatment, including full blood count and liver function tests.','Inform the patient about common side effects such as dizziness, drowsiness, dry mouth, and gastrointestinal upset.','Explain rare but important side effects, including a drop in white blood cells (agranulocytosis). Advise the patient that if they develop symptoms such as a sore throat, fever, or feel generally unwell, they should seek medical attention promptly.','Provide safety-netting by advising the patient to seek urgent help by contacting the GP surgery or NHS 111 if symptoms worsen or if they develop red flag symptoms such as visual disturbance, hearing changes, or facial weakness.','Arrange follow-up in 2 weeks to assess symptom control and response to treatment.'],
  'Thank you for getting in touch — four weeks of pain like this must have been really wearing, and I can see why it''s getting you down. Based on what you''ve described, Simon, I think what you''re experiencing is actually something called trigeminal neuralgia rather than migraine. Let me explain what that means.\n\nThe trigeminal nerve is the main nerve responsible for sensation across the face. When this nerve becomes irritated or compressed, it can cause very sudden, severe, sharp pain — often described as electric-shock-like — that typically lasts a matter of seconds to a couple of minutes and then stops, before returning again. The fact that your pain is on one side of your face, radiates to your cheek, is triggered by everyday things like washing your face, brushing your teeth, or chewing, and that your dentist found nothing wrong with your teeth — all of this fits very well with trigeminal neuralgia.\n\nI''d like to arrange for you to come in to see me in person so that I can examine the nerves in your face properly — this helps to confirm the diagnosis and make sure there''s nothing else we need to look into. I''d also like to arrange some baseline blood tests before we start any treatment, specifically a full blood count and liver function tests.\n\nIn terms of treatment, the medication we use for trigeminal neuralgia is called carbamazepine. It''s actually a drug that is more commonly known for treating epilepsy, but it is highly effective for nerve pain of this kind. We would start you at 100 mg twice a day and adjust the dose gradually until we find the level that gives you the best symptom control. Common side effects can include dizziness, drowsiness, dry mouth, and some stomach upset, particularly when you first start taking it, so it''s worth being aware of those.\n\nThere is also a rare but important side effect I want to make sure you know about: carbamazepine can in very rare cases reduce your white blood cell count, which are the cells that help fight infection. If at any point you develop a sore throat, a fever, or simply feel very unwell, please contact us promptly rather than waiting — it''s something we would want to check.\n\nI''ll book you in for a review in two weeks to see how you''re responding to the medication. If in the meantime your symptoms worsen significantly, or you develop anything new such as visual disturbance, hearing changes, or weakness in the face, please get in touch with us straight away or call NHS 111 if it''s out of hours.',
  ARRAY['Trigeminal neuralgia presents with brief, severe, lancinating unilateral facial pain triggered by light touch or everyday activities such as chewing, washing, or brushing teeth — it is frequently misdiagnosed as dental pain.','Carbamazepine 100 mg twice daily (titrated as needed) is the first-line treatment for trigeminal neuralgia; it acts on voltage-gated sodium channels to reduce nerve excitability.','Baseline full blood count and liver function tests should be arranged before starting carbamazepine, and the patient should be counselled about common side effects (dizziness, drowsiness, GI upset) and the rare but serious risk of agranulocytosis.','Patients should be advised to seek prompt medical attention if they develop signs of infection (sore throat, fever, feeling unwell) while on carbamazepine, as this may indicate a drop in white blood cells.','A face-to-face appointment to examine the cranial nerves is essential in suspected trigeminal neuralgia to confirm the diagnosis and exclude sinister causes such as a mass lesion.','Red flag features requiring urgent review include progressive neurological symptoms, hearing changes, visual disturbance, or facial weakness, which may indicate an underlying structural cause.'],
  NULL
);

